  ["magni bronzebeard"] = { 5, "former reigning king of the dwarven kingdom of Khaz Modan", "\"I am still the dwarf I was before, but now me purpose transcends any throne or kingdom.\" Magni Bronzebeard is the former reigning king of the dwarven kingdom of Khaz Modan, Thane of Ironforge and head of the Bronzebeard clan. During the Second Wa..." },
