  ["baine bloodhoof"] = { 4, "High Chieftain of the united tauren tribes of Mulgore", "Baine Bloodhoof is the High Chieftain of the united tauren tribes of Mulgore and leader of Thunder Bluff. He is the son of the late tauren leader, Cairne Bloodhoof, whom he looked up to as a role model." },
  ["cairne bloodhoof"] = { 4, "High Chieftain of the united tauren tribes of Mulgore", "Cairne Bloodhoof was the High Chieftain of the united tauren tribes of Mulgore, chieftain of the Bloodhoof, leader of Thunder Bluff, and the final wielder of the Bloodhoof Runespear. Allying with the Horde upon its arrival on the shores of Kalimdo..." },
  ["genn greymane"] = { 4, "former reigning King of Gilneas", "Genn Greymane (sometimes spelled as 'Graymane') is the former reigning King of Gilneas, and one of the original founders of the Alliance of Lordaeron. He is a large bearish man, a brawny warrior with thick features, a heavy beard, and black and gr..." },
