  ["queen azshara"] = { 4, "queen of the naga", "Azshara is the queen of the naga, ruling from the underwater city of Nazjatar. Once the ruler of the Kaldorei Empire over ten thousand years ago, she was entrancingly beautiful and beloved by her people." },
  ["uther the lightbringer"] = { 4, "first of the five paladins of the Knights of the Silver H...", "Lord Uther the Lightbringer, or Sire Uther Lightbringer, was the first of the five paladins of the Knights of the Silver Hand along with Turalyon, Saidan Dathrohan, Tirion Fordring, and Gavinrad the Dire. Once a knight of Lordaeron and a follower ..." },
  ["advisor belgrum"] = { 3, "dwarf located in Old Ironforge", "Advisor Belgrum is a dwarf located in Old Ironforge. He was previously standing in the Library of the Hall of Explorers in Ironforge." },
  ["bezok"] = { 3, "brick maker", "Bezok was a brick maker who lived on Copper Street in Bilgewater Port and he watched Jastor Gallywix trick Skezzo and his gang. Soon after the battle, Jastor made a deal with Bezok to give him his business in return for yearly compensation." },
  ["dras"] = { 3, "orc assassin", "Dras was an orc assassin who helped escort carts loaded with supplies of water for the Horde in Mulgore shortly after the Cataclysm. He was slain by a group of quilboar along with Izwix and Grotz." },
  ["greyhoof farwanderer"] = { 3, "apparent leader of the Farwanderers tauren tribe", "Greyhoof Farwanderer is the apparent leader of the Farwanderers tauren tribe, and an elderly tauren who had served Cairne Bloodhoof faithfully prior to his death. Though he is loyal to his son and successor, Baine, he has become disheartened with ..." },
  ["lyani shadestalker"] = { 3, "Darkfallen warden located in the Underhold during  [60] S...", "Lyani Shadestalker is a Darkfallen warden located in the Underhold during  [60] Stay of Execution, where she is initially seen training. Later, Magister Hathorel calls her to kill Thrall, Varok Saurfang, and Jaina Proudmoore as they try to release..." },
  ["nalmeena darkfollow"] = { 3, "night elf warden", "Nalmeena Darkfollow is a night elf warden. A tower in Val'sharah is probably named after her: Darkfollow's Spire." },
  ["sky-reaver korm blackscar"] = { 3, "orc quest giver", "Sky-Reaver Korm Blackscar is an orc quest giver and the captain of the Horde gunship Orgrim's Hammer in Icecrown. During the assault on Icecrown he sent soldiers to ambush soldiers of the Alliance while they were battling the Scourge at the Broken..." },
  ["vindicator boros"] = { 3, "draenei vindicator", "Vindicator Boros is a draenei vindicator and a member of the Triumvirate of the Hand, the leaders of the Hand of Argus. He is initially found as a quest giver at Blood Watch on Bloodmyst Isle, and later moved in the Sanctum of Light beneath Light'..." },
  ["'ambassador' dagg'thol"] = { 2, "ogre quest giver located in the Eastern wing of Dire Maul", "'Ambassador' Dagg'thol is an ogre quest giver located in the Eastern wing of Dire Maul." },
  ["'bad news' brin"] = { 2, "dwarven member of the Bloodsail Buccaneers", "'Bad News' Brin is a dwarven member of the Bloodsail Buccaneers who appears at the Buccaneers' beach party on the Cape of Stranglethorn's Wild Shore during Pirates' Day. She offers to tell a number of pirate-themed jokes." },
  ["'calmest' gobbu"] = { 2, "nerubian vendor located in the Skeins in the City of Thre...", "'Calmest' Gobbu is a nerubian vendor located in the Skeins in the City of Threads in Azj-Kahet." },
  ["'captain' cookie"] = { 2, "elite murloc", "'Captain' Cookie is an elite murloc, captain of the Defias juggernaught, and the last boss of Deadmines in normal mode. In Heroic mode, there is one more boss after him." },
  ["'captain' cookie (azmerloth)"] = { 2, "murloc located in Azmerloth", "'Captain' Cookie is a murloc located in Azmerloth." },
  ["'captain' kaftiz"] = { 2, "ethereal self-proclaimed captain of the Consortium locate...", "'Captain' Kaftiz is an ethereal self-proclaimed captain of the Consortium located at the Mana Tombs in Terokkar Forest." },
  ["'commander' nazrim"] = { 2, "kobold located south of Algaz Station", "'Commander' Nazrim is a kobold located south of Algaz Station, inside a cave. He is part of the Tunnel Rat and appears to be the leader of the kobolds west of Thelsamar." },
  ["'conspiracy theory' binni"] = { 2, "goblin located in a cave in Gutterville in the Ringing Deeps", "'Conspiracy Theory' Binni is a goblin located in a cave in Gutterville in the Ringing Deeps." },
  ["'creepjack'"] = { 2, "', "'Creepjack' can be found in Shattrath City. He's involved in the quest  [15-30G3] What Book?" },
