  ["'dusty' brandom"] = { 2, "gnome of the Darkmoon Faire", "'Dusty' Brandom is a gnome of the Darkmoon Faire, located at Darkmoon Island, which is only available during the monthly Darkmoon Faire event. He is located right next to the entrance portal, advertising the use of the Faire's Darkmoon Strider mou..." },
