  ["'good-boy' bruce"] = { 2, "human member of the Blackwater Raiders", "Bruce Callows was a human member of the Blackwater Raiders that was in Gilneas before the ports were closed. His ship, Brashtide, and his crew were held prisoner there and when the worgen curse swept through the land they were changed along with t..." },
  ["'grizzly' d. adams"] = { 2, "human PvP rewards vendor located in Venture Bay in the Gr...", "'Grizzly' D. Adams is a human PvP rewards vendor located in Venture Bay in the Grizzly Hills. He is only available when the Alliance owns the Lighthouse." },
