  ["'pokey' thornmantle"] = { 2, "rare quilboar found near the battleboar pens south of Cam...", "'Pokey' Thornmantle is a rare quilboar found near the battleboar pens south of Camp Narache. He wields a fish as a weapon and it is possible that he is a relative of 'Squealer' Thornmantle." },
