  ["'tiny' jimb"] = { 2, "ogre located near Kamagua in the Howling Fjord", "'Tiny' Jimb is an ogre located near Kamagua in the Howling Fjord. He seems to have formed a group with Grezzix Spindlesnap of whom he is first mate, Lou the Cabin Boy and Grezzix's parrot Molly." },
  ["\"yen\" malone"] = { 2, "worgen located at Breakwater Bight on Founder's Point", "\"Yen\" Malone is a worgen located at Breakwater Bight on Founder's Point and outside the Hull on Razorwind Shores. She sells plant-based housing decor with with a theme opposite to her location: On Founder's Point, she sells Horde-themed plants, an..." },
