  ["7th legion tinkerblade"] = { 2, "', "7th Legion Tinkerblades are gnomes located in Vol'dun and Nazmir during Faction Assaults." },
  ["7th legion vicar"] = { 2, "', "7th Legion Vicars are humans located in Tiragarde Sound, Drustvar, Stormsong Valley, and Nazmir during Faction Assaults." },
  ["7th legion windfinder"] = { 2, "', "7th Legion Windfinders are humans located in Talanji's Rebuke in Zuldazar." },
  ["7th legion wyrm hunter"] = { 2, "', "7th Legion Wyrm Hunters are with the 7th Legion, stationed at the 7th Legion Front in the Dragonblight. They fight the frostwyrm Icestorm in the quest  [15-30] Chasing Icestorm: Thel'zan's Phylactery." },
  ["a tormented voice"] = { 2, "voice when doing the quest  [54] The Smoldering Ruins of ...", "A tormented voice is a voice when doing the quest  [54] The Smoldering Ruins of Thaurissan, you will receive a whisper whenever you open a relic. The messages depict Dark Iron dwarves and lead to insight into what happened there." },
  ["a.c.e. beamgunner"] = { 2, "', "A.C.E. Beamgunners are gnomes located at Domination Point in the Domination Point scenario." },
  ["a.c.e. medic"] = { 2, "', "A.C.E. Medics are gnomes located at Domination Point in the Domination Point scenario." },
  ["a.c.e. saboteur"] = { 2, "', "A.C.E. Saboteurs are gnomes located at Domination Point in the Domination Point scenario." },
  ["aq small set"] = { 2, "human located in the Trade District in Stormwind City", "AQ Small Set is a human located in the Trade District in Stormwind City and in the Valley of Strength in Orgrimmar. He provides the Cenarion Circle sets for free." },
  ["awol grunt"] = { 2, "', "AWOL Grunts are orcs located in Bilgewater Harbor in Azshara." },
  ["aalun"] = { 2, "draenei elekk riding trainer located at the stables north...", "Aalun is a draenei elekk riding trainer located at the stables north of the entrance to the Exodar on Azuremyst Isle." },
  ["aarko"] = { 2, "draenei found at Aarko's Estate on Talador's southern shore", "Aarko is a draenei found at Aarko's Estate on Talador's southern shore." },
  ["aaron"] = { 2, "human child located in second floor of the northernmost h...", "Aaron is a human child located in second floor of the northernmost house of Goldshire in Elwynn Forest." },
  ["ab'xal"] = { 2, "nerubian located in City of Threads", "Ab'xal is a nerubian located in City of Threads." },
  ["abandoned acolyte"] = { 2, "', "Abandoned Acolytes are found in the Season of Discovery Karazhan Crypts dungeon." },
  ["abandoned outcast"] = { 2, "', "Abandoned Outcasts are venthyr located in cages in Ember Ward in Revendreth." },
  ["abatha"] = { 2, "draenei located near Verdant Mire in Shadowmoon Valley", "Abatha is a draenei located near Verdant Mire in Shadowmoon Valley. As a young girl, she learned the ways of alchemy from her mother, before she passed away." },
  ["abbot of northshire abbey"] = { 2, "character mentioned in Warcraft: Orcs & Humans", "The Abbot of Northshire Abbey was a character mentioned in Warcraft: Orcs & Humans. Prior to the First War, on his fourteenth birthday Medivh fell into coma and the Abbot and the King agreed that the future Guardian be taken into Northshire Abbey." },
  ["abby"] = { 2, "human located in Boralus", "Abby is a human located in Boralus." },
  ["abdul the insane"] = { 2, "human located on a ship at Iskaal in the Howling Fjord", "Abdul the Insane is a human located on a ship at Iskaal in the Howling Fjord. He went mad after  [The Staff of Storm's Fury] was brought on board the ship." },
  ["abe the cabin boy"] = { 2, "boat", "Abe the Cabin Boy is - as his name suggests - the cabin boy of the Lady Mehley, the boat that runs between Theramore Isle and Menethil Harbor. He swabs the decks." },
  ["abel"] = { 2, "', "Abel is human member of the Undermarket found in the Burning Steppes." },
  ["abel camhorn"] = { 2, "gnome located in Mechagon City", "Abel Camhorn is a gnome located in Mechagon City." },
  ["abercrombie"] = { 2, "human quest giver located at Beggar's Haunt", "Abercrombie is a human quest giver located at Beggar's Haunt, northwest up the road from Darkshire in Duskwood. Originally, he was just northeast of Raven Hill Cemetery." },
  ["aberee"] = { 2, "goblin located in the Verdant Gutters in the Ringing Deeps", "Aberee is a goblin located in the Verdant Gutters in the Ringing Deeps." },
  ["abereth"] = { 2, "dracthyr", "Abereth is a dracthyr." },
  ["aberrus watcher"] = { 2, "Shadowed Crucible", "Aberrus Watchers are ethereals located throughout Aberrus, the Shadowed Crucible." },
  ["abigail the huntress"] = { 2, "worgen hunter of the Gilneas Brigade participating in the...", "Abigail the Huntress is a worgen hunter of the Gilneas Brigade participating in the battle against the Horde in the Cove of Nashal." },
  ["abner fizzletorque"] = { 2, "gnome located in Fizzcrank Airstrip in the Borean Tundra", "Abner Fizzletorque is a gnome located in Fizzcrank Airstrip in the Borean Tundra." },
  ["aboda"] = { 2, "tauren stable master located in Shadowprey Village in Des...", "Aboda is a tauren stable master located in Shadowprey Village in Desolace." },
  ["abrakkar the wretched"] = { 2, "orc lich of the Scourge", "Abrakkar the Wretched is an orc lich of the Scourge. He is also a sorcerer and necromancer." },
  ["abrogar dusthoof"] = { 2, "tauren located in Shrine of Two Moons of Vale of Eternal ...", "Abrogar Dusthoof is a tauren located in Shrine of Two Moons of Vale of Eternal Blossoms. He was sent there by Baine, with whom he has been friends for a long time." },
  ["absalan the pious"] = { 2, "dwarf quest giver roaming the deck of the Skybreaker in I...", "Absalan the Pious is a dwarf quest giver roaming the deck of the Skybreaker in Icecrown. He is a member of the Argent Crusade who has been ordered to stay on the gunship and serve as an ambassador to the Valiance Expedition." },
  ["abyssal acolyte"] = { 2, "', "The Abyssal Acolytes are three humans located in the Sepulcher of the Abyss in Stormsong Valley. They sit in front of the Altar of the Abyss." },
  ["abyssal lieutenant"] = { 2, "', "Abyssal Lieutenants were naga found in the Great Sea off the shores of Val'sharah. Two of them were escorting Abyssal Queen Sha'rathra." },
  ["abyssal queen sha'rathra"] = { 2, "naga found in the Great Sea off the shores of Val'sharah", "Abyssal Queen Sha'rathra is a naga found in the Great Sea off the shores of Val'sharah. She deceived the druids of the Dreamgrove and stole the  [Pendant of Starlight]." },
  ["academy marine"] = { 2, "', "Academy Marines are humans located at the Proudmoore Academy in Boralus." },
  ["academy squallrunner"] = { 2, "', "Academy Squallrunners are humans located at the Proudmoore Academy in Boralus." },
  ["acadia chistlestone"] = { 2, "dwarf of the Explorer's League", "Acadia Chistlestone is a dwarf of the Explorer's League. Elementalist Taiyang describes her as vibrant and fiery." },
  ["accessories vendor"] = { 2, "goblin", "The Accessories Vendor is a goblin that sells necklaces, capes, rings, trinkets and item-based enchants for players on the Arena Tournament and Mythic Dungeon International realms. On the Public Test Realm for patch 7.2.5, he sold items from the T..." },
  ["accursed slitherblade"] = { 2, "rare mob naga in Desolace", "The Accursed Slitherblade is a rare mob naga in Desolace. Aggro will be friendly whilst under the effects of  [Slitherblade Charm]." },
  ["ace"] = { 2, "goblin first found on the isle of Kezan", "Ace is a goblin first found on the isle of Kezan, then the Lost Isles, and finally ends up in Azshara like most of the Bilgewater Cartel goblins. This section concerns content related to The War Within." },
  ["achellios the banished"] = { 2, "rare centaur", "Achellios the Banished is a rare centaur who patrols the plateau west of the Splithoof Heights in eastern Thousand Needles alongside three Galak Packhounds. He is on a 5-8 hour respawn timer." },
  ["achelus"] = { 2, "quest giver located at Blood Watch in the draenei territo...", "Achelus is a quest giver located at Blood Watch in the draenei territory of Bloodmyst Isle." },
  ["acherus necromancer"] = { 2, "', "Acherus Necromancers are humans found on the second floor of Acherus: The Ebon Hold raising Death Knight Initiates for Instructor Razuvious. In phase two, after completing   [8-30] Victory At Death's Breach!, they can also be found on the beach at..." },
  ["achilles"] = { 2, "', "Achilles tells Arthas someone destroyed the bridge in Brill, Alterac and that there is another, but unsafe, route." },
  ["achillon"] = { 2, "ascended kyrian located in Bastion", "Achillon is an ascended kyrian located in Bastion. He is Pallessa's soulbind." },
  ["acolyte (netherlight temple)"] = { 2, "', "Acolytes are human, Forsaken, gnome, and draenei priests located in the Netherlight Temple." },
  ["acolyte (warcraft iii)"] = { 2, "', "Acolytes are human beings who have given themselves over to the power of Ner'zhul and the Scourge. These bitter, fanatical men and women will stop at nothing to promote the Lich King's will and maintain the secrecy and dominance of the Cult of the..." },
  ["acolyte (mob)"] = { 2, "', "Acolytes can be found in the Culling of Stratholme." },
  ["acolyte amalthina"] = { 2, "kyrian located in Bastion", "Acolyte Amalthina is a kyrian located in Bastion." },
  ["acolyte danysia"] = { 2, "kyrian located in Bastion", "Acolyte Danysia is a kyrian located in Bastion. It is revealed that in life she was a human who served as a member of the Stormwind forces and died a great hero." },
  ["acolyte galistos"] = { 2, "kyrian located in Bastion", "Acolyte Galistos is a kyrian located in Bastion. It is revealed that in life he was a tauren, and as a member of the Horde, experienced combat against Alliance soldiers." },
  ["acolyte in hiding"] = { 2, "', "Many Acolytes In Hiding lived masquerading as normal villagers in Vandermar until the death knight Arthas Menethil came to regroup them. Arthas came just in time, as several acolytes fell under suspicion of the local town guard." },
  ["acolyte inquisitor"] = { 2, "human", "Acolyte Inquisitor is a human." },
  ["acolyte kitkar"] = { 2, "arakkoa found in Warspear on Ashran", "Acolyte Kitkar is an arakkoa found in Warspear on Ashran. He is found inside Warspear Hold, accompanying Ravenspeaker Skeega." },
  ["acolyte reegis"] = { 2, "arakkoa found in Warspear on Ashran", "Acolyte Reegis is an arakkoa found in Warspear on Ashran. He is found inside Warspear Hold, accompanying Ravenspeaker Skeega." },
  ["acolyte of agony"] = { 2, "', "Acolytes of Agony are human acolytes located in Zul'Drak." },
  ["acolyte of n'zoth"] = { 2, "', "Acolytes of N'Zoth are humans and orcs located in Uldum, Vale of Eternal Blossoms, and the Vision of the Twisting Sands. Some are riding Writhing Horrors." },
  ["acolyte of pain"] = { 2, "', "Acolytes of Pain are humans located in Zul'Drak." },
  ["acolyte of pain (legion assaults)"] = { 2, "', "Acolytes of Pain are warlocks located in Azsuna during the Legion Assaults. After being rescued from demons, they accompany the Class order leader for several minutes." },
  ["acolyte of pain (legion invasion)"] = { 2, "', "Acolytes of Pain are friendly warlocks that are at the Legion Invasion locations. Once saved, they can help the adventurers." },
  ["acolyte of purity"] = { 2, "', "Acolytes of Purity are kyrian located at the Temple of Purity in Bastion. Some of them are being recruited by the Forsworn." },
  ["acolyte of wisdom"] = { 2, "', "Acolytes of Wisdom are kyrian located in Bastion." },
  ["acquirer ba'theom"] = { 2, "broker located at Shadow Point on K'aresh", "Acquirer Ba'theom is a broker located at Shadow Point on K'aresh. He sells tier 34 equipment tokens in exchange for  [Hungering Void Curios]." },
  ["acquirer ta'est"] = { 2, "broker located in Castle Nathria on beta for testing purp...", "Acquirer Ta'est is a broker located in Castle Nathria on beta for testing purposes." },
  ["acquirer ta'gosh"] = { 2, "broker located in the Hall of Curiosities in Oribos", "Acquirer Ta'gosh is a broker located in the Hall of Curiosities in Oribos." },
  ["acquirer ta'wah"] = { 2, "broker located in the Hall of Curiosities in Oribos", "Acquirer Ta'wah is a broker located in the Hall of Curiosities in Oribos." },
  ["acquisitioner xy'gui"] = { 2, "broker located in Fracture of Laacuna", "Acquisitioner Xy'gui is a broker located in Fracture of Laacuna and Serrated Peaks in K'aresh." },
  ["acquisitionist xy'rahn"] = { 2, "broker", "Acquisitionist Xy'rahn is a broker. Sharing the title with Tracker Zo'korss, they were likely planned to appear in Tazavesh, the Veiled Market." },
  ["acquistion hauler"] = { 2, "', "Acquistion[sic] Haulers are brokers sitting on barges in Ephemeral Plains in the Sepulcher of the First Ones." },
  ["acrypha"] = { 2, "orc mage trainer located in the Valley of Trials in Durotar", "Acrypha is an orc mage trainer located in the Valley of Trials in Durotar. She spent several years in Undercity studying the arcane." },
  ["acteon"] = { 2, "draenei hunter trainer", "Acteon is a draenei hunter trainer and quest giver located at Azure Watch in Azuremyst Isle. He is the camp's resident tracker, and the skins he wears are a testament to his skill." },
  ["adalar"] = { 2, "member of the Stormriders", "Adalar is a member of the Stormriders. He was first encountered in Dornogal where he could be found relaxing in the Keepers Terrace." },
  ["adam"] = { 2, "human boy", "Adam is a human boy who hangs around the Stormwind City Canals with Billy." },
  ["adamman the trader"] = { 2, "human found in the Underbelly of Dalaran", "Adamman the Trader is a human found in the Underbelly of Dalaran. Apparently, he once had it all, including fame, fortune and good gear, but when the 'Cartel' caught him rigging fights, they took away everything." },
  ["adarrah"] = { 2, "human woman", "Adarrah is a human woman who has been seen by adventurers all across Azeroth and even beyond. She appears in quest lines in several different zones." },
  ["adaru"] = { 2, "ankoan located in Nazjatar", "Adaru is an ankoan located in Nazjatar." },
  ["adashe flintwill"] = { 2, "the oldest son of Captain Marjani Flintwill raised aboard...", "Adashe Flintwill was a the oldest son of Captain Marjani Flintwill raised aboard the Makemba of the Blackwater Raiders to the life of a pirate along with his other siblings who had different fathers. He was handsome and smart and Makasa admired hi..." },
  ["adday"] = { 2, "furbolg located on Longclaw Island in the Azure Span", "Adday is a furbolg located on Longclaw Island in the Azure Span. He also attended the gathering in Amirdrassil when it bloomed on the Dragon Isles after Fyrakk's death." },
  ["addie fizzlebog"] = { 2, "', "Addie Fizzlebog is Hemet Nesingwary's gnomish ghost writer, found at Nesingwary's Retreat in Highmountain. She has accompanied Hemet on all his expeditions from Stranglethorn to Nagrand, to Nagrand again, taking notes on his adventures and turning..." },
  ["addius the tormentor"] = { 2, "venthyr located in Old Gate in Revendreth", "Addius the Tormentor is a venthyr located in Old Gate in Revendreth." },
  ["addled arcanomancer"] = { 2, "', "Addled Arcanomancers are gnome arcane mages found at the Violet Bluff in the Everbloom." },
  ["addysen wildbanner"] = { 2, "Arathi located in Fungal Fields in Hallowfall", "Addysen Wildbanner is an Arathi located in Fungal Fields in Hallowfall." },
  ["adelgonn"] = { 2, "Stoneward of Dornogal", "Adelgonn is the Stoneward of Dornogal. She served as the head and representative of the Stonebound in the Council of Dornogal." },
  ["adella"] = { 2, "worgen located in Shadebough in Feralas", "Adella is a worgen located in Shadebough in Feralas. A member of the Sentinels, she is skilled in marksmanship and serves as the camp's leader." },
  ["adena"] = { 2, "widowed wife of Dougan", "Adena is the widowed wife of Dougan and the mother of Lieren and Loania. After hearing the sad news of Dougan’s demise from his friends Kardan and Voldana, Adena's grief was so immense that her mind snapped and she became unfit to raise her own tw..." },
  ["adept of the dawn"] = { 2, "', "Adepts of the Dawn are high arakkoa located in Skyreach." },
  ["adjunct ek'vem"] = { 2, "mantid located outside the Heart of Fear in Dread Wastes", "Adjunct Ek'vem is a mantid located outside the Heart of Fear in Dread Wastes." },
  ["adjunct g'kkal"] = { 2, "mantid found at the Amber Hibernal in the Dread Wastes", "Adjunct G'kkal is a mantid found at the Amber Hibernal in the Dread Wastes." },
  ["adjunct ikkess"] = { 2, "mantid located outside the Heart of Fear in the Dread Wastes", "Adjunct Ikkess is a mantid located outside the Heart of Fear in the Dread Wastes." },
  ["adjunct kree'zot"] = { 2, "mantid found facing down Klaxxi'va Tik at the Terrace of ...", "Adjunct Kree'zot is a mantid found facing down Klaxxi'va Tik at the Terrace of Gurthan in the Dread Wastes." },
  ["adjunct okzyk"] = { 2, "mantid located in the Amber Hibernal in the Dread Wastes", "Adjunct Okzyk is a mantid located in the Amber Hibernal in the Dread Wastes." },
  ["adjunct pivvika"] = { 2, "mantid located in the Amber Hibernal in the Dread Wastes", "Adjunct Pivvika is a mantid located in the Amber Hibernal in the Dread Wastes." },
  ["adjunct sek'ot"] = { 2, "mantid found at Zan'vess of Dread Wastes", "Adjunct Sek'ot is a mantid found at Zan'vess of Dread Wastes. He maintains communication with the empress at the Whispering Stones." },
  ["adjunct suruz"] = { 2, "mantid located outside the Heart of Fear in the Dread Wastes", "Adjunct Suruz is a mantid located outside the Heart of Fear in the Dread Wastes." },
  ["adjunct tzikzi"] = { 2, "mantid located outside the Heart of Fear in the Dread Wastes", "Adjunct Tzikzi is a mantid located outside the Heart of Fear in the Dread Wastes." },
  ["adjunct zet'uk"] = { 2, "mantid located at Kypari Ik in the Dread Wastes", "Adjunct Zet'uk is a mantid located at Kypari Ik in the Dread Wastes." },
  ["adjutant dekaris"] = { 2, "Mawsworn kyrian located in the Maw", "Adjutant Dekaris is a Mawsworn kyrian located in the Maw." },
  ["adjutant felipos"] = { 2, "kyrian found in Torghast", "Adjutant Felipos is a kyrian found in Torghast, Tower of the Damned. He was originally only found in the Coldheart Interstitia wing." },
  ["adland"] = { 2, "earthen located in the Royal Library in Stormwind City", "Adland is an earthen located in the Royal Library in Stormwind City. He can be found listening to the stories of Shauna Strattonmeier." },
  ["admiral copeland"] = { 2, "human of Kul Tiras", "Admiral Copeland is a human of Kul Tiras. After the third invasion of the Burning Legion, during a remembrance day in Boralus commemorating Daelin Proudmoore, Copeland tried to persuade Katherine Proudmoore to rejoin the Alliance." },
  ["admiral ripsnarl"] = { 2, "worgen employed by the Defias Brotherhood", "Admiral Ripsnarl, formerly known as James Harrington, is a worgen employed by the Defias Brotherhood. He had a family and a successful naval career until he was infected with the worgen curse." },
  ["admiral's elite guard (npc)"] = { 2, "Proudmoore Academy", "Admiral's Elite Guards are human guards located in Proudmoore Keep, the Proudmoore Academy, and their surrounding areas in Boralus." },
  ["admiral's elite guard (warcraft iii)"] = { 2, "', "The Admiral's Elite Guards were an elite unit that served as the royal guard of Admiral Proudmoore of Kul Tiras. Some survived to stand down after the Admiral's death." },
  ["admiralty marine"] = { 2, "', "Admiralty Marines are humans located in Tiragarde Sound and Boralus." },
  ["admirer"] = { 2, "', "Admirers are summoned by  [Letter from an Admirer]." },
  ["admirer (murloc)"] = { 2, "', "Admirers are murlocs that will spawn and follow a player who is transformed into a murloc from a  [Magical Murkmorpher]." },
  ["adolphus blastwidget"] = { 2, "gnome demolitions expert", "Adolphus Blastwidget was a gnome demolitions expert who planted a series of remote-controlled explosives to use against the Horde during their attack on Theramore Isle. When the fighting at Sentry Point began to go badly, Captain Wymor lured as ma..." },
  ["adonas"] = { 2, "Ascended kyrian located in Bastion", "Adonas is an Ascended kyrian located in Bastion." },
  ["adonias"] = { 2, "Forsworn kyrian encountered at the Temple of Loyalty in B...", "Adonias is a Forsworn kyrian encountered at the Temple of Loyalty in Bastion during  [60] The Greater Good." },
  ["adoring freebooter"] = { 2, "', "Adoring Freebooters are humans located at the Ring of Booty in Tiragarde Sound. They can be found near Reed 'The Flirt' Fisc." },
  ["adorned bladetalon"] = { 2, "', "Adorned Bladetalons are high arakkoa located in the Grand Spire in Skyreach." },
  ["adorned starseer"] = { 2, "Veiled Market", "Adorned Starseers are brokers located in Tazavesh, the Veiled Market." },
  ["adrestes"] = { 2, "Ascended kyrian located at the Seat of Eternal Hymns in B...", "Adrestes, previously Polemarch of Bastion and now Paragon of Devotion, is an Ascended kyrian located at the Seat of Eternal Hymns in Bastion. After the events of  [60] The New Path, the Archon elevates him as the new Paragon of Devotion, overseein..." },
  ["adrew the free man"] = { 2, "vrykul located on the cliffs in southern Stormheim", "Adrew the Free Man is a vrykul located on the cliffs in southern Stormheim." },
  ["adrianos"] = { 2, "ascended kyrian located in Ascension Coliseum", "Adrianos is an ascended kyrian located in Ascension Coliseum." },
  ["adric"] = { 2, "undead human crossbow archer", "Adric is an undead human crossbow archer and an old friend of Garrick. While it appears he has gained his independence, he does not seem to be allied to the Forsaken and was able to infect his former friend with the Plague." },
  ["adrihi"] = { 2, "Broken shaman trainer located at Blood Watch in Bloodmyst...", "Adrihi is a Broken shaman trainer located at Blood Watch in Bloodmyst Isle." },
  ["adrina"] = { 2, "Ascended kyrian located at the Eonian Archives in Bastion", "Adrina is an Ascended kyrian located at the Eonian Archives in Bastion." },
  ["adsila darkmane"] = { 2, "tauren located in Stormsong Valley", "Adsila Darkmane is a tauren located in Stormsong Valley." },
  ["adugos"] = { 2, "blue drake", "Adugos is a blue drake and one of Lailastrasza's companions, who fought alongside her against the djaradin. He is usually indifferent and withdrawn but tried to get Lailastrasza to celebrate their victory against the djaradin in the Roasted Ram in..." },
  ["advance scout"] = { 2, "', "Advance Scouts are humans located in Nazmir." },
  ["advanced flying machine"] = { 2, "', "The Advanced Flying Machines were strong flying machines in the Kul Tiras army, they served under Admiral Proudmoore." },
  ["adventurer (npc)"] = { 2, "', "Adventurers are humans located in Lunarfall. They toss coins into the fountain." },
  ["adventurer rugan"] = { 2, "worgen located in Apex Observatory in the Waking Shores", "Adventurer Rugan is a worgen located in Apex Observatory in the Waking Shores, speaking with his adventuring friends. He also appears in Artisan's Market in Valdrakken, talking to Gohfyrr." },
  ["adventuring desii"] = { 2, "draenei from Azeroth located at Elodor in Shadowmoon Valley", "Adventuring Desii is a draenei from Azeroth located at Elodor in Shadowmoon Valley.  She ends up showing her pug, Percy, to a local girl, and doing tricks." },
  ["adventurous dwarf"] = { 2, "', "Adventurous Dwarves are dwarves located in the Wildgrowth Mangal in Sholazar Basin. They are sometimes found when pulling Sturdy Vines during  [20-30] Some Make Lemonade, Some Make Liquor." },
  ["adyen the lightwarden"] = { 2, "draenei quest giver located on the Aldor Rise at the base...", "The Aldor are keepers of the Light and servants of the naaru. Adyen the Lightwarden is a draenei quest giver located on the Aldor Rise at the base of the steps leading up to the Shrine of Unending Light in Shattrath City." },
  ["aedelas blackmoore"] = { 2, "master of Durnholde Keep", "Aedelas Blackmoore was the master of Durnholde Keep and head of the orcish internment camp system shortly after the Second War, and the man who found Thrall lost in the wilds. He was a subject of King Terenas Menethil." },
  ["aedelas blackmoore (alternate universe)"] = { 2, "', "In an alternate timeline, Thrall died as an infant. Aedelas Blackmoore was robbed of his ultimate weapon and most efficient method of taking over the Alliance, so he did the unexpected - instead of going further down his drunken path, he sobered u..." },
  ["aedelyn blackmoore"] = { 2, "general", "Aedelyn Blackmoore was a general and the father of Aedelas Blackmoore. When Aedelas was a child, many years before the foundation of the Alliance of Lordaeron, Aedelyn was tried and convicted of selling state secrets (to whom, it was not mentioned..." },
  ["aeden braesmeld"] = { 2, "Arathi located in Mereldar in Hallowfall", "Aeden Braesmeld is an Arathi located in Mereldar in Hallowfall." },
  ["aedis brom"] = { 2, "wandering dwarf found wandering between Old Town", "Aedis Brom is a wandering dwarf found wandering between Old Town and the Canals in Stormwind City. He walks with a human named Christoph Faral, the two having extensive conversations." },
  ["aeedrei"] = { 2, "draenei located in Eventide Landing in Shadowmoon Valley", "Aeedrei is a draenei located in Eventide Landing in Shadowmoon Valley. During  [10-40] Pale Moonlight, she can be seen cowering in fear." },
  ["aeeshna"] = { 2, "ethereal located in any neighborhood where Consortium Con...", "Aeeshna is an ethereal located in any neighborhood where Consortium Consternation is the active endeavor. She appears in the Town Center in Founder's Point or the Common in Razorwind Shores." },
  ["aegira"] = { 2, "vrykul located at Aegira's Meadery in Stormheim", "Aegira is a vrykul located at Aegira's Meadery in Stormheim. In her youth, Aegira had a master named Melba." },
  ["aegor irynbawnd"] = { 2, "Arathi located at Lorel's Crossing in Hallowfall", "Aegor Irynbawnd is an Arathi located at Lorel's Crossing in Hallowfall. He tries to keep tabs on Lamplighters in the field and assess what areas of Hallowfall may be in need of their aid." },
  ["aegrim bronzebeard"] = { 2, "ancient dwarf of the Bronzebeard clan", "Aegrim Bronzebeard was an ancient dwarf of the Bronzebeard clan. Long ago, the Bronzebeard clan was small, and it was under his lead as thane that it began to flourish and command respect." },
  ["aellaana"] = { 2, "draenei located at the Shattrath Port Authority in Talador", "Aellaana is a draenei located at the Shattrath Port Authority in Talador. She is the owner of Tiny the elekk." },
  ["aellia"] = { 2, "Arathi child located on the Siren Isle", "Aellia is an Arathi child located on the Siren Isle. Spots follows her around the camp." },
  ["aelneth"] = { 2, "sayaad", "Aelneth is a sayaad whose master has been spending more time with her than his wife." },
  ["aelric leid"] = { 2, "founder", "Aelric Leid is the founder and leader of the Order of Night, a cult of the Hallowfall Arathi that serves the Void and has allied with Xal'atath. He is the main antagonist of the Hallowfall storyline." },
  ["aemyra acton"] = { 2, "Arathi located in Velhan's Claim in Hallowfall", "Aemyra Acton is an Arathi located in Velhan's Claim in Hallowfall. She and Taenar Strongoth were sent to investigate Velhan's Claim after its Dawntower went out." },
  ["aenir"] = { 2, "draenei quest giver located at the Lunarfall in Shadowmoo...", "Aenir is a draenei quest giver located at the Lunarfall in Shadowmoon Valley." },
  ["aeonas"] = { 2, "human paladin found in the chamber at the back of the Sca...", "Aeonas is a human paladin found in the chamber at the back of the Scarlet Monastery Cathedral after defeating Scarlet Commander Mograine and High Inquisitor Whitemane. Upon returning to Stormwind City, he becomes Aeonas the Vindicated." },
  ["aeqinus"] = { 2, "draenei paladin", "Aeqinus is a draenei paladin and a member of the Light's Chosen." },
  ["aerie ace"] = { 2, "', "Aerie Aces are wyvern riders of the Twilight's Hammer located in Twilight Aerie in Thousand Needles." },
  ["aerik matthews"] = { 2, "worgen located at the Lunarfall in Shadowmoon Valley", "Aerik Matthews is a worgen located at the Lunarfall in Shadowmoon Valley. He can only be recruited using the Headhunter's Harvest from Lunarfall Inn." },
  ["aeris landing nexus-guard"] = { 2, "ethereal", "The Aeris Landing Nexus-Guard is an ethereal who would be found at Aeris Landing in Nagrand." },
  ["aertin brighthand"] = { 2, "', "Aertin Brighthand served as the Spearhead of the Council of Tirisfal (a prototype of the Guardian of Tirisfal) during the battle with Kathra'natir at Dalaran. He also used to serve as a mage in the court of the father of Prince Nallorath." },
  ["aerun"] = { 2, "draenei quest giver located in Lunarfall in Shadowmoon Va...", "Aerun is a draenei quest giver located in Lunarfall in Shadowmoon Valley." },
  ["aethanel"] = { 2, "naga located in the Last Prison in the Eternal Palace", "Aethanel is a naga located in the Last Prison in the Eternal Palace. She is one of the cursed lovers summoned by Queen Azshara." },
  ["aether-tech adept"] = { 2, "dwarf found at Bash'ir Landing in the Blade's Edge Mountains", "Aether-tech Adept is a dwarf found at Bash'ir Landing in the Blade's Edge Mountains. He is spawned by the Bash'ir Landing Raid event." },
  ["aether-tech apprentice"] = { 2, "Broken quest ender located at Skyguard Outpost in the Bla...", "Aether-tech Apprentice is a Broken quest ender located at Skyguard Outpost in the Blade's Edge Mountains." },
  ["aether-tech assistant"] = { 2, "Broken found at Bash'ir Landing in the Blade's Edge Mount...", "Aether-tech Assistant is a Broken found at Bash'ir Landing in the Blade's Edge Mountains after the Bash'ir Landing Raid stage one is completed." },
  ["aethril-crazed murloc"] = { 2, "', "Aethril-Crazed Murlocs are murlocs found guarding the Aethril Cluster at the Hatecoil Warcamp in Azsuna when  [45WQ] Aethril Cluster is up." },
  ["aeun"] = { 2, "draenei quest giver located on a hill above Ammen Ford on...", "Aeun is a draenei quest giver located on a hill above Ammen Ford on Azuremyst Isle. After Technician Zhanaa contacted Azure Watch via holographic emitter, Aeun was sent to scout Ammen Vale to see how many people Azure Watch could expect to receive." },
  ["aeun (alternate universe)"] = { 2, "draenei located at the Exarch's Refuge in Talador", "Aeun is a draenei located at the Exarch's Refuge in Talador." },
  ["aevery flamestonge"] = { 2, "Arathi located in Light's Blooming in Hallowfall", "Aevery Flamestonge is an Arathi located in Light's Blooming in Hallowfall." },
  ["afflicted gilnean"] = { 2, "', "Afflicted Gilneans are Gilneans afflicted with the worgen curse found in the Military District in Gilneas City." },
  ["affray challenger"] = { 2, "', "Affray Challengers are a group of five humans (three female, two male) and one male dwarf located under the Maiden's Dagger's gangplank on Fray Island in the Northern Barrens. Before Cataclysm, these challengers were involved in   [30] The Affray ..." },
  ["affray spectator"] = { 2, "', "Affray Spectators were humans, orcs, dwarves, and night elves located on Fray Island in the Barrens." },
  ["afha"] = { 2, "orc general goods vendor located at Agmar's Hammer in the...", "Afha is an orc general goods vendor located at Agmar's Hammer in the Dragonblight." },
  ["ag'cha the feltongue"] = { 2, "orc warlock", "Ag'cha the Feltongue is an orc warlock." },
  ["ag'tor bloodfist"] = { 2, "orc quest giver located in Azshara at the Orgrimmar Rear ...", "Ag'tor Bloodfist is an orc quest giver located in Azshara at the Orgrimmar Rear Gate. He used to be located in Valormok before the Cataclysm." },
  ["agadai"] = { 2, "orc found at Thunderlord Stronghold in the Blade's Edge M...", "Agadai is an orc found at Thunderlord Stronghold in the Blade's Edge Mountains." },
  ["agal"] = { 2, "rare furbolg located in Ban'ethil Hollow in Teldrassil", "Agal is a rare furbolg located in Ban'ethil Hollow in Teldrassil." },
  ["agari dotur"] = { 2, "centaur located in Maruukai in the Ohn'ahran Plains", "Agari Dotur is a centaur located in Maruukai in the Ohn'ahran Plains." },
  ["agasham"] = { 2, "unknown figure within the Grimtotem", "Agasham is an unknown figure within the Grimtotem who was to receive three Secret Notes from agents of unknown origin." },
  ["agashem"] = { 2, "one", "Agashem appears to be a leader among the Grimtotem tauren, as he or she was the one who ordered the destruction of the Shady Rest Inn. From the Grimtotem Battle Plans, the Horde learned that Agashem had instructed the Grimtotem to halt the Allianc..." },
  ["aged dalaran wizard"] = { 2, "', "The Aged Dalaran Wizard can be found wandering on the road next to a Dalaran Sorceress in the Caverns of Time instance Old Hillsbrad Foothills. He sells the limited supply item  [Formula: Enchant Shield - Intellect] for 6." },
  ["ageilaa"] = { 2, "draenei female", "Ageilaa is a draenei female that works at the Jorune Mine. She is a good friend of Aeun, and sent him for extra help when the spare Auchenai vindicators sent by Exarch Maladaar weren't enough." },
  ["agent araxes"] = { 2, "ethereal quest giver located just west of Access Shaft Ze...", "Agent Araxes is an ethereal quest giver located just west of Access Shaft Zeon in the Netherstorm." },
  ["agent connelly"] = { 2, "retired SI:7 agent", "Agent Connelly is a retired SI:7 agent and master of disguise. He comes out of retirement, after the player completes  [15-35] Stirred, Not Shaken to help the Alliance in Operation: Shieldwall." },
  ["agent keanna"] = { 2, "human found at Ariden's Camp in Deadwind Pass", "Agent Keanna is a human found at Ariden's Camp in Deadwind Pass. An agent of the Violet Eye, she eventually managed to infiltrate Karazhan where she stayed in the guest chambers and kept an encoded log of her observations." },
  ["agent ya-six"] = { 2, "ethereal quest giver located in the deepest part of Acces...", "Agent Ya-six is an ethereal quest giver located in the deepest part of Access Shaft Zeon in the Netherstorm." },
  ["aggartha"] = { 2, "earthen located on the Isle of Dorn", "Aggartha is an earthen located on the Isle of Dorn." },
  ["aggem thorncurse"] = { 2, "quilboar ghost found in Razorfen Kraul as part of the War...", "Aggem Thorncurse is a quilboar ghost found in Razorfen Kraul as part of the Warlord Ramtusk encounter." },
  ["aggem thorncurse (classic)"] = { 2, "named quilboar found in Razorfen Kraul", "Aggem Thorncurse was a named quilboar found in Razorfen Kraul." },
  ["aggressive assailant"] = { 2, "', "Aggressive Assailants are venthyr located in Revendreth." },
  ["aggressor zo'dash"] = { 2, "broker located in the Enclave in Oribos", "Aggressor Zo'dash is a broker located in the Enclave in Oribos. He serves as an item upgrader, typically for PvP gear with  [Honor]." },
  ["aggron"] = { 2, "orc found in the Siegeworks during the Siege of Orgrimmar", "Aggron is an orc found in the Siegeworks during the Siege of Orgrimmar." },
  ["aggu"] = { 2, "orc child training to be a shaman under the Earthen Ring", "Aggu is an orc child training to be a shaman under the Earthen Ring. When Zekhan arrived at the Western Earthshrine, the child and his friends took advantage of the situation to ask him about the assassination attempt on Talanji only for Lorlidrel..." },
  ["agitated initiate"] = { 2, "', "Agitated Initiates are centaur located in Windsong Rise in the Ohn'ahran Plains." },
  ["agitated stratholme citizen"] = { 2, "grain supplier", "Agitated Stratholme Citizens are humans found throughout King's Square and Festival Lane in Old Stratholme. They can be seen harassing food vendors, the grain supplier, and trying to get into the town hall to speak to the magistrate for leadership." },
  ["agitated stratholme resident"] = { 2, "grain supplier", "Agitated Stratholme Residents are humans found throughout King's Square and Festival Lane in Old Stratholme. They can be seen harassing food vendors, the grain supplier, and trying to get into the town hall to speak to the magistrate for leadership." },
  ["aglaya"] = { 2, "', "Aglaya possessed wrist armor crafted from an ancient bull that had been graced with a disposition of eternal happiness." },
  ["agloolik"] = { 2, "tuskarr dockmaster located in Unu'pe in the Borean Tundra", "Agloolik is a tuskarr dockmaster located in Unu'pe in the Borean Tundra. He'll inform you about Walker of Waves, the giant sea turtle that takes you from Unu'pe to Moa'ki Harbor in Dragonblight." },
  ["agmar's siegesmith"] = { 2, "', "Agmar's Siegesmiths are a group of blacksmiths located at Agmar's Hammer in the Dragonblight. They appear to be under the command of Grand Master Blacksmith Borus Ironbender." },
  ["agmera"] = { 2, "earthen located in Challenger's Rest in Dornogal", "Agmera is an earthen located in Challenger's Rest in Dornogal and in the Bazaar in Silvermoon City. At or above 1,000 Mythic+ Rating, she sells warbound Champion 1 loot tokens for that season." },
  ["agmond (human)"] = { 2, "human of the Stromgarde Militia", "Agmond was a human of the Stromgarde Militia who fought against the Syndicate in Arathi Highlands. He fell and his badge was taken by his killer, kept as a trophy until its retrieval by hired adventurers." },
  ["agnes"] = { 2, "human located at Nastrondir in Stormheim", "Agnes is a human located at Nastrondir in Stormheim. She is the mother of Seymour." },
  ["agnes farwithers"] = { 2, "cheese vendor available to Horde players during the activ...", "Agnes Farwithers is a cheese vendor available to Horde players during the activities of Brewfest." },
  ["agni blazehoof"] = { 2, "tauren located in the Forbidden Reach", "Agni Blazehoof is a tauren located in the Forbidden Reach." },
  ["agrox gand"] = { 2, "tauren first seen in the Darkmoon Faire on the Darkmoon I...", "Agrox Gand is a tauren first seen in the Darkmoon Faire on the Darkmoon Island. His family had always wanted Gand to become a shaman, but he had troubles with the elements." },
  ["agrul"] = { 2, "drogbar located in Zaralek Cavern", "Agrul is a drogbar located in Zaralek Cavern." },
  ["agthia"] = { 2, "Paragon of Courage before Xandria", "Agthia was the Paragon of Courage before Xandria. Eons ago, the powers of the Void launched a massive attack against the Shadowlands, trying to shift the balance of the cosmos." },
  ["agthian defender"] = { 2, "Paragon of Courage at the time", "Agthian Defender are Ascended kyrian. They were in service of Agthia, the Paragon of Courage at the time, and were helping her fend of the invasion of the Void when it came to Bastion at the place that would come to be known as Agthia's Repose." },
  ["agurahl the butcher"] = { 2, "centaur located at Timberstep Outpost in the Ohn'ahran Pl...", "Agurahl the Butcher is a centaur located at Timberstep Outpost in the Ohn'ahran Plains." },
  ["ah'tusa"] = { 2, "', "Ah'tusa is one of the main characters of  [A Steamy Romance Novel: Forbidden Love]. The only things known about her is that she had an intimate relationship with Marcus, and met him in one of the tunnels of the Deeprun Tram." },
  ["ah'wara"] = { 2, "haranir drink", "Ah'wara is a haranir drink and alcohol vendor located in the Den in Harandar." },
  ["ahanu"] = { 2, "tauren leather armor vendor located in Hewa's Armory on t...", "Ahanu is a tauren leather armor vendor located in Hewa's Armory on the lower rise in Thunder Bluff. He is friends with Jahan Hawkwing and Varg Windwhisper." },
  ["ahemen"] = { 2, "draenei staff vendor located on the Aldor Rise in Shattra...", "Ahemen is a draenei staff vendor located on the Aldor Rise in Shattrath City." },
  ["ahjani excavator"] = { 2, "', "Ahjani Excavators are vulpera located around Zul'Ahjin in Vol'dun. Most are in  [Stealth], sneaking in and out of the ruins to pillage various artifacts." },
  ["ahlurglgr"] = { 2, "friendly murloc clam vendor stationed in Winterfin Retrea...", "Ahlurglgr is a friendly murloc clam vendor stationed in Winterfin Retreat in the Borean Tundra. He could be considered the quartermaster of the Winterfin tribe of murlocs as he sells items for Winterfin Clams." },
  ["ahm"] = { 2, "draenei quest giver located at Archenon Siegeyard in Talador", "Ahm is a draenei quest giver located at Archenon Siegeyard in Talador. Ahm was captured by Blademaster Bralok who left Ahm mortally wounded and starved." },
  ["ahn'izik the old soul"] = { 2, "nerubian spiderling located in the City of Threads", "Ahn'izik the Old Soul is a nerubian spiderling located in the City of Threads." },
  ["ahna"] = { 2, "vulpera singer resting in the back of a caravan wagon at ...", "Ahna is a vulpera singer resting in the back of a caravan wagon at Camp Lastwind in Vol'dun." },
  ["ahnko"] = { 2, "deckhand on the Wavestrider", "Ahnko was a deckhand on the Wavestrider. He died defending the ship against Captain Malus and his Hidden." },
  ["ahonan"] = { 2, "draenei warrior trainer located at the Ring of Arms in th...", "Ahonan is a draenei warrior trainer located at the Ring of Arms in the Trader's Tier in the Exodar. This section concerns content related to Legion." },
  ["ahoo'ru"] = { 2, "final Rank 3 encounter in the Brawler's Guild", "Ahoo'ru is the final Rank 3 encounter in the Brawler's Guild." },
  ["ahote"] = { 2, "tauren follower located at Frostwall in Frostfire Ridge", "Ahote is a tauren follower located at Frostwall in Frostfire Ridge. He can only be recruited using the Headhunter's Harvest from Frostwall Tavern." },
  ["ai"] = { 2, "resident of", "Ai was a resident of Andorhal when Arthas, having just killed his father and betrayed his own people, came through and slaughtered Uther the Lightbringer and the other paladins who were protecting Terenas Menethil II's urn." },
  ["ailenda hedgemyr"] = { 2, "Arathi vendor located in Flotsam Shoal on the Siren Isle", "Ailenda Hedgemyr is an Arathi vendor located in Flotsam Shoal on the Siren Isle." },
  ["ailgrha splittusk"] = { 2, "quilboar located in Thousand Needles", "Ailgrha Splittusk is a quilboar located in Thousand Needles." },
  ["ailsa bronzebeard"] = { 2, "dwarf", "Ailsa Bronzebeard is a dwarf and ancestor of the three Bronzebeard brothers, Magni, Muradin, and Brann. Her name is inscribed in Mina Stormsmith's runes in Mithrios, Bronzebeard's Legacy." },
  ["aimele"] = { 2, "draenei located at Lamplighter Inn in Shadowmoon Valley", "Aimele is a draenei located at Lamplighter Inn in Shadowmoon Valley. She is playing on a harp." },
  ["aimi"] = { 2, "', "Aimi can be found at the Refugee Caravan in Terokkar Forest." },
  ["aioluus"] = { 2, "draenei located at the Gala of Gifts by the Stormwind Gat...", "Aioluus is a draenei located at the Gala of Gifts by the Stormwind Gate in Elwynn Forest during Love is in the Air." },
  ["airborne goblin priest"] = { 2, "goblin priest summoned to the Orgrimmar Rocketway Exchang...", "The Airborne Goblin Priest is a goblin priest summoned to the Orgrimmar Rocketway Exchange in Azshara using the  [Blessed Flaregun] to inspect Clubnik's Dozer during  [5-30] Dozercism. He performs an exorcism on the dozer by jumping atop it and ba..." },
  ["airborne priest"] = { 2, "', "Airborne Priests are goblin priests located in Azshara. They were called by Horde adventurers to heal wounded soldiers." },
  ["airfield guard"] = { 2, "', "Airfield Guards are dwarves located at the Ironforge Airfield of Dun Morogh. They are combating the Dark Iron Invaders." },
  ["airhorn"] = { 2, "tauren warrior", "Airhorn is a tauren warrior that is a part of the Uber Town group. He can be briefly seen during the flashback of the confrontation with Illidan Stormrage atop the Black Temple, as well as during the fall of Deathwing in the Maelstrom." },
  ["airship crewman"] = { 2, "', "Airship Crewmen are goblins located on Theramore Isle during the Theramore's Fall scenario." },
  ["airship crewman (faction assaults)"] = { 2, "', "Airship Crewmen are humans located on the Alliance Airship attacking Zandalar during the Faction Assaults." },
  ["airship engineer (gnome)"] = { 2, "', "Airship Engineers are gnomes located on the Alliance Airship attacking the areas of Zandalar during the Faction Assaults." },
  ["airship engineer (goblin)"] = { 2, "', "Airship Engineers are goblins located on the airship attacking Kul Tiras during the Faction Assaults." },
  ["airship marine"] = { 2, "', "Airship Marines are goblins located on Theramore Isle during the Theramore's Fall scenario." },
  ["airship worker"] = { 2, "', "Airship Workers are goblins and Forsaken located on the Defiant Dragonscale in Durotar." },
  ["airwyn bantamflax"] = { 2, "gnome located at Booty Bay in the Cape of Stranglethorn", "Airwyn Bantamflax is a gnome located at Booty Bay in the Cape of Stranglethorn. She is a high ranking member of the Explorers' League who enjoys drinking on the job." },
  ["aisha"] = { 2, "vulpera located at the Artisan's Market in Valdrakken", "Aisha is a vulpera located at the Artisan's Market in Valdrakken. She is the founder of the Artisan's Consortium." },
  ["aiyell"] = { 2, "night elf of the Sentinels", "Aiyell is a night elf of the Sentinels and owns a brown owl. She accompanied Llaran and Iyneath when they rescued Makasa Flintwill from a black drake in the Charred Vale in the Stonetalon Mountains." },
  ["aizra dawnchaser"] = { 2, "innkeeper at Thunder Cleft", "Aizra Dawnchaser is a innkeeper at Thunder Cleft and Dawnchaser Retreat in the Krasarang Wilds. She is a member of the Dawnchaser tribe, which traveled to Pandaria in search of a dreamed paradise." },
  ["aja"] = { 2, "goblin located on the Darkmoon Island", "Aja is a goblin located on the Darkmoon Island." },
  ["ajaye"] = { 2, "ogre stable master located Stonemaul Hold in Feralas", "Ajaye is an ogre stable master located Stonemaul Hold in Feralas." },
  ["ak'zeloth"] = { 2, "orc located at Far Watch Post in the Northern Barrens", "Ak'Zeloth is an orc located at Far Watch Post in the Northern Barrens. He is the assistant of Neeru Fireblade and Arnak Fireblade." },
  ["ak'ox the slaughterer"] = { 2, "orc located at the Iron Siegeworks in Frostfire Ridge", "Ak'ox the Slaughterer is an orc located at the Iron Siegeworks in Frostfire Ridge. She is inspecting supplies in a building." },
  ["akainu"] = { 2, "shaman", "Akainu was a shaman whose molten powers could shape an entire landscape." },
  ["akama"] = { 2, "elder sage", "Akama is the elder sage and leader of both the Ashtongue tribe and the elite of said tribe, the Ashtongue Deathsworn, a faction of Broken in Outland. Prior to the destruction of Draenor and the genocide of the draenei, Akama was chosen by Prophet ..." },
  ["akama (brawler's guild)"] = { 2, "broken serving as a Challenge Card encounter in the Brawl...", "Akama is a broken serving as a Challenge Card encounter in the Brawler's Guild during The War Within. To fight Akama, purchase  [Challenge Card: Akama] at Rank 8 with the guild." },
  ["akama (warcraft iii)"] = { 2, "elder draenei", "Akama is an elder draenei and leader of a group of draenei fighting against the army of the Pit Lord Magtheridon in order to survive on the devastated world of Draenor. When Illidan, Kael, and Vashj arrived in Outland, Akama and his forces joined ..." },
  ["akan"] = { 2, "tortollan located in Anyport in Drustvar", "Akan is a tortollan located in Anyport in Drustvar." },
  ["akana"] = { 2, "arakkoa vendor located at the Sethekk Hollow in the Spire...", "Akana is an arakkoa vendor located at the Sethekk Hollow in the Spires of Arak." },
  ["akanaka the cowled"] = { 2, "ankoan located in Mezzamere in Nazjatar", "Akanaka the Cowled is an ankoan located in Mezzamere in Nazjatar." },
  ["akarek"] = { 2, "leader of the House of Eyes", "Margrave Akarek was the leader of the House of Eyes, one of the five Necrolord houses of Maldraxxus, until he was killed in a plot by the traitor House of Rituals." },
  ["akashinga flintwill"] = { 2, "son of Captain Marjani Flintwill raised aboard the Makemb...", "Akashinga Flintwill was a son of Captain Marjani Flintwill raised aboard the Makemba of the Blackwater Raiders to the life of a pirate along with his other siblings who had different fathers. Akashinga was Makasa's favorite brother." },
  ["akatha blazeburn"] = { 2, "Burning Blade orc", "Akatha Blazeburn is a Burning Blade orc that attacks the garrison in order to retrieve the  [Heart of Gorgorek]." },
  ["akdan"] = { 2, "earthen located in the Forgegrounds in Dornogal", "Akdan is an earthen located in the Forgegrounds in Dornogal." },
  ["akeeta"] = { 2, "arakkoa located at the Akeeta's Hovel‎ in Spires of Arak", "Akeeta is an arakkoa located at the Akeeta's Hovel‎ in Spires of Arak." },
  ["akham"] = { 2, "draenei leatherworking trainer located at the Trader's Ti...", "Akham is a draenei leatherworking trainer located at the Trader's Tier in the Exodar. This section concerns content related to Legion." },
  ["akhan"] = { 2, "draenei quest giver located at the Pilgrim's Road in Talador", "Akhan is a draenei quest giver located at the Pilgrim's Road in Talador. He is a survivor of the arakkoa attack on Aruuna." },
  ["akiaruk"] = { 2, "tuskarr located at Kamagua in the Howling Fjord", "Akiaruk is a tuskarr located at Kamagua in the Howling Fjord." },
  ["akil'darah"] = { 2, "eagle loa known as 'the eagle spirit of the Hinterlands'", "Akil'darah is an eagle loa known as 'the eagle spirit of the Hinterlands'. Her totem can be found in Jintha'Alor and was initially controlled by the Vilebranch trolls." },
  ["akinos"] = { 2, "orc quest giver located at the Sunreaver Pavilion in the ...", "Akinos is an orc quest giver located at the Sunreaver Pavilion in the Argent Tournament Grounds in Icecrown. He sends Horde adventurers seeking to champion Orgrimmar in the tournament to kill 10 members of the Scourge." },
  ["akiun"] = { 2, "tuskarr located in a camp east of Brackenhide Hollow in t...", "Akiun is a tuskarr located in a camp east of Brackenhide Hollow in the Azure Span. He was ambushed and injured by gnolls." },
  ["ako"] = { 2, "draenei located on the Isle of Thunder", "Ako is a draenei located on the Isle of Thunder. Initially found on the Seabolt, he can appear in Za'Tual." },
  ["akoru the apprentice"] = { 2, "draenei located in Rangari Refuge", "Akoru the Apprentice is a draenei located in Rangari Refuge. He is standing with the kids Morod and Aylaan." },
  ["akoru the firecaller"] = { 2, "Broken quest giver located at the Ruins of Sha'naar in th...", "Akoru the Firecaller is a Broken quest giver located at the Ruins of Sha'naar in the Hellfire Peninsula." },
  ["akota"] = { 2, "tortollan", "Akota is a tortollan." },
  ["akrittok"] = { 2, "tuskarr food vendor", "Akrittok is a tuskarr food vendor and member of the Argent Crusade located at the Argent Tournament Grounds in Icecrown. This section concerns content related to Shadowlands." },
  ["akrosh"] = { 2, "orc quest giver located at the Mar'gok's Overwatch in Nag...", "Akrosh is an orc quest giver located at the Mar'gok's Overwatch in Nagrand." },
  ["akru"] = { 2, "tortollan located in Zuldazar", "Akru is a tortollan located in Zuldazar. At first, she is found in a Nazeshi Cage in the Dreadpearl Shallows." },
  ["aktar"] = { 2, "arakkoa located at Aktar's Post in Tanaan Jungle  His fri...", "Aktar is an arakkoa located at Aktar's Post in Tanaan Jungle  His friend Reshad of the Arakkoa Outcasts asked him to set up the camp in the first place." },
  ["akua"] = { 2, "tortollan located at Tradewinds Market in Boralus", "Akua is a tortollan located at Tradewinds Market in Boralus. He runs Akuatik Delights." },
  ["akuno"] = { 2, "Broken quest giver located in the Shadow Tomb in Terokkar...", "Akuno is a Broken quest giver located in the Shadow Tomb in Terokkar Forest. He has been kidnapped by members of the Shadow Council known as the Cabal and is under guard within the tomb." },
  ["akuta"] = { 2, "vulpera located at the Bloom in Razorwind Shores", "Akuta is a vulpera located at the Bloom in Razorwind Shores. He is sitting around a campfire with Seniku, Itsero, and Taiyata." },
  ["al'ara"] = { 2, "broker of Cartel Al", "Al'Ara (or Al'ara) is a broker of Cartel Al. She is initially encountered as Elder Ara, one of the three elders who lead the Enlightened of Haven in Zereth Mortis." },
  ["al'dalil"] = { 2, "broker from Cartel Al", "Al'dalil (/æl.dəˈliːl/ al-də-LEEL) is a broker from Cartel Al and the self-proclaimed foremost expert on broker culture. He is involved in the story of Tazavesh, the Veiled Market and in a side questline in Zereth Mortis." },
  ["alamo"] = { 2, "level 80 tauren druid from the Thunderhorn server", "Alamo, a level 80 tauren druid from the Thunderhorn server, had grown in notoriety for a post he made titled 'Alamo teechs u 2 play DURID!' on the official WoW druid boards. The topic itself is filled with poorly edited MSpaint images, horrible sp..." },
  ["alana the hopebringer"] = { 2, "ally card from the Reign of Fire set", "Alana the Hopebringer is an ally card from the Reign of Fire set." },
  ["alana the woebringer"] = { 2, "ally card from the Throne of the Tides set", "Alana the Woebringer is an ally card from the Throne of the Tides set." },
  ["alanatheth"] = { 2, "dracthyr located on the Rugged Dragonscale in Stormwind City", "Alanatheth is a dracthyr located on the Rugged Dragonscale in Stormwind City." },
  ["alanya"] = { 2, "', "Alanya is 'Silvermoon' Harry's companion at Scalawag Point. She lets the player use Harry's Bomber for the quest  [10-30] The Ancient Armor of the Kvaldir." },
  ["alaria"] = { 2, "draenei shaman found in the Exile's Reach", "Alaria is a draenei shaman found in the Exile's Reach. She was part of the first expedition to the island." },
  ["alaric"] = { 2, "', "Alaric was once Thule Ravenclaw's head servant and bodyguard. Thule used his magic to 'protect' him from the Plague of Undeath giving him an undead form." },
  ["alastair the savage"] = { 2, "gnome located in Gadgetzan in Tanaris", "Alastair the Savage is a gnome located in Gadgetzan in Tanaris." },
  ["albert henson"] = { 2, "Forsaken located in the Waking Shores", "Albert Henson is a Forsaken located in the Waking Shores and Azj-Kahet. He first appeared at the Dragonscale Basecamp in the Waking Shores as Pathfinder Henson, looking through a telescope from the main camp." },
  ["albetha"] = { 2, "earthen innkeeper located in Freywold Village on the Isle...", "Albetha is an earthen innkeeper located in Freywold Village on the Isle of Dorn." },
  ["albrech"] = { 2, "', "Albrech was one of the dwarves under Rom's command. He accompanied Rom to a mission to capture a skardyn." },
  ["albrecht 'full metal' finklestein"] = { 2, "gnome", "Albrecht 'Full Metal' Finklestein is a gnome." },
  ["alchemist (warcraft iii)"] = { 2, "Neutral Hero in The Frozen Throne", "The Alchemist is a Neutral Hero in The Frozen Throne and was added in patch 1.17 on August, 2004. While named simply as the Alchemist in-game, in other official material he is also known as the Goblin Alchemist." },
  ["alchemist adrianna"] = { 2, "human alchemist", "Alchemist Adrianna was a human alchemist that had a chance to appear inside the Icecrown Citadel, near the Scourge Transporter in the Upper Spire." },
  ["alchemist arbington"] = { 2, "human quest giver located at Chillwind Camp in the Wester...", "Alchemist Arbington is a human quest giver located at Chillwind Camp in the Western Plaguelands. He is well versed on Scholomance as he spent a fair portion of his life studying it." },
  ["alchemist finklestein"] = { 2, "undead alchemist", "Alchemist Finklestein is an undead alchemist and member of the Argent Crusade found by his Cauldron at Heb'Valok in Zul'Drak. He later becomes a part of the Ashen Verdict providing his skills for the Icecrown Citadel assault." },
  ["alchemist funen"] = { 2, "Broken located in Krokul Hovel in Krokuun", "Alchemist Funen is a Broken located in Krokul Hovel in Krokuun. He supplied the camp with necessary potions to deal with the demons, including tracking potions for the camp's scouts." },
  ["alchemist karloff"] = { 2, "undead reagent vendor at Acherus: The Ebon Hold", "Alchemist Karloff is an undead reagent vendor at Acherus: The Ebon Hold." },
  ["alchemist korlya"] = { 2, "vrykul located at the Garrison of the Fel on the Broken S...", "Alchemist Korlya is a vrykul located at the Garrison of the Fel on the Broken Shore. Korlya is the one responsible for poisoning the brew that was distributed during the Storm Brew celebration on the Wandering Isle." },
  ["alchemist leticia"] = { 2, "venthyr located at the Catacombs of Regret in Revendreth", "Alchemist Leticia is a venthyr located at the Catacombs of Regret in Revendreth." },
  ["alchemist talbax"] = { 2, "nerubian found in the Silken Ward in Azj-Kahet", "Alchemist Talbax is a nerubian found in the Silken Ward in Azj-Kahet." },
  ["aldor acolyte"] = { 2, "', "Aldor Acolytes are draenei located throughout the Aldor section of Shattrath City." },
  ["aldor anchorite"] = { 2, "', "Aldor Anchorites are draenei located on the Aldor Rise in Shattrath City. They can also be found inside the Shrine of Unending Light." },
  ["aldor marksman"] = { 2, "', "Aldor Marksmen are Aldor draenei located at Aldor Rise in Shattrath City, taking orders from Harbinger Erothem who sends them to Nagrand. They are so dedicated, they bring their own cooking pot to avoid taking long breaks for lunch." },
  ["aldor neophyte"] = { 2, "', "Aldor Neophytes are draenei located in the Aldor section of Shattrath City. Since the launching of the Battle for Quel'Danas they wear Shattered Sun Offensive tabards instead of Aldor ones." },
  ["aldor reveler"] = { 2, "', "Aldor Revelers are draenei located at Shattrath City. They celebrate the New Year and Midsummer Fire Festival fireworks on the Aldor Rise." },
  ["aldor vindicator"] = { 2, "', "Aldor Vindicators are draenei guards located on the Aldor Rise in Shattrath City. They give directions to various locations within the city." },
  ["aldorei"] = { 2, "female night elf killed by Ralaar", "Aldorei was a female night elf killed by Ralaar and Arvell while they had lost their minds to the Pack Form." },
  ["aldra"] = { 2, "earthen located at the Stoneshaper's Atrium in Dornogal", "Aldra is an earthen located at the Stoneshaper's Atrium in Dornogal. She can be found speaking to an Oathsworn Dignitary." },
  ["aldraan"] = { 2, "draenei weapon vendor located at Halaa in Nagrand", "Aldraan is a draenei weapon vendor located at Halaa in Nagrand. He is only present when the Alliance controls Halaa." },
  ["aldrek"] = { 2, "captain of the Warchief's Fist which was stationed off th...", "Aldrek was the captain of the Warchief's Fist which was stationed off the coast of Tanaris." },
  ["aldren cordon"] = { 2, "dwarf cloth armor vendor located at Ironband's Excavation...", "Aldren Cordon is a dwarf cloth armor vendor located at Ironband's Excavation Site in Loch Modan." },
  ["alekaa"] = { 2, "draenei quest giver located at the Lunarfall in Shadowmoo...", "Alekaa was a draenei quest giver located at the Lunarfall in Shadowmoon Valley." },
  ["alerted goliath"] = { 2, "', "Alerted Goliaths are centaur located in Windsong Rise in the Ohn'ahran Plains." },
  ["alerted stormsmith"] = { 2, "', "Alerted Stormsmiths are tauren and jungle trolls located in Windsong Rise in the Ohn'ahran Plains." },
  ["alesha"] = { 2, "blood elf in service to Illidan Stormrage", "Alesha was a blood elf in service to Illidan Stormrage and was close with Luzen. While it is unknown what happened to her, she may have died during the assault on the Black Temple." },
  ["alessia d'nara"] = { 2, "draenei located at the Lunarfall in Shadowmoon Valley", "Alessia D'Nara is a draenei located at the Lunarfall in Shadowmoon Valley. She can only be recruited using the Headhunter's Harvest from Lunarfall Inn." },
  ["alestos"] = { 2, "draenei located in Valiance Keep in the Borean Tundra", "Alestos is a draenei located in Valiance Keep in the Borean Tundra." },
  ["alex"] = { 2, "', "Alex  can be found in the Caverns of Time instance, Escape from Durnholde Keep. He is standing in a group of kids east side of Southshore." },
  ["alex (warcraft iii)"] = { 2, "son of Alric", "Alex is the son of Alric and Daunell Barton. Alric told Arthas that there was a healing fountain up ahead in Alterac." },
  ["alexei the beastlord"] = { 2, "fifth boss in the Scarlet Enclave", "Alexei the Beastlord is the fifth boss in the Scarlet Enclave." },
  ["alexi silenthowl"] = { 2, "worgen found on the Lost Isles", "Alexi Silenthowl is a worgen found on the Lost Isles." },
  ["alexie"] = { 2, "draenei fishing supply vendor located at Elodor in Shadow...", "Alexie is a draenei fishing supply vendor located at Elodor in Shadowmoon Valley." },
  ["alexius"] = { 2, "Broken innkeeper of the Crystal Goblet within Shattrath City", "Alexius is a Broken innkeeper of the Crystal Goblet within Shattrath City and the cousin of Arechron. He hosted Maiev Shadowsong and informed her of the various factions that resided within the city." },
  ["alforila"] = { 2, "earthen Archivist located in the Library in Ironforge", "Alforila is an earthen Archivist located in the Library in Ironforge. She is being interviewed by three Dwarven Historians." },
  ["alfred"] = { 2, "Arathi located in Mereldar in Hallowfall", "Alfred is an Arathi located in Mereldar in Hallowfall. He, Dolores, and Chay are observing Arathi Reserves." },
  ["alfritha"] = { 2, "stasis-locked earthen located in the Living Grotto in the...", "Alfritha is a stasis-locked earthen located in the Living Grotto in the Ringing Deeps. Next to her is her plaque." },
  ["alfryd"] = { 2, "venthyr located in Redelav Tower at Revendreth", "Alfryd is a venthyr located in Redelav Tower at Revendreth. He is the personal butler of The Countess." },
  ["algerson lumberjack"] = { 2, "', "Algerson Lumberjacks are humans located at Algerson Lumber Yard in Tiragarde Sound. Some of them are trapped in web cocoons." },
  ["algeth'ar freshscale"] = { 2, "', "Algeth'ar Freshscales are dracthyr located at Algeth'ar Academy in Thaldraszus." },
  ["ali buntblaster"] = { 2, "goblin located at The Overgrowth in the Southern Barrens", "Ali Buntblaster is a goblin located at The Overgrowth in the Southern Barrens. She sends adventurers to the Northern Barrens." },
  ["alia irongear"] = { 2, "Arathi located in the Whirring Field in Hallowfall", "Alia Irongear is an Arathi located in the Whirring Field in Hallowfall." },
  ["alice"] = { 2, "human girl located at Windshear Hold in Stonetalon Mountains", "Alice is a human girl located at Windshear Hold in Stonetalon Mountains. She skips around the machine Big Papa, hoping to get him fixed." },
  ["alicia"] = { 2, "human child quest giver located in Stormwind Keep in Stor...", "Alicia is a human child quest giver located in Stormwind Keep in Stormwind City." },
  ["alicia (warcraft iii)"] = { 2, "villager", "Alicia was a villager and with her family lived in a farmhouse just outside Strahnbrad." },
  ["aligar the tormentor"] = { 2, "satyr found in southeastern Darkshore", "Aligar the Tormentor is a satyr found in southeastern Darkshore. He used to spawn at the end of the escort quest  [24] Supplies to Auberdine received from Feero Ironhand at Maestra's Post in Ashenvale." },
  ["alina"] = { 2, "Forsaken", "Alina is a Forsaken. Magus Wordeen Voidglare wanted the Bloodstone Shard that Alina had, a relic that Alina had taken as part of her attempt to defect from her people." },
  ["alisius"] = { 2, "kyrian located in Elysian Hold in Bastion", "Alisius is a kyrian located in Elysian Hold in Bastion." },
  ["alithea"] = { 2, "kyrian spirit healer located outside Lakeshire in the Red...", "Alithea is a kyrian spirit healer located outside Lakeshire in the Redridge Mountains during the Kyrian Campaign. She also appears in the Font of Fealty in the Seat of the Archon during  [60] The Grand Reception." },
  ["alius"] = { 2, "father of Leena", "Alius was the father of Leena. During the war between the orcs and draenei, Alius, his wife and daughter Leena had to once hide before orcs in a cavern." },
  ["aliya hillhelm"] = { 2, "Arathi located in Hillhelm Stead in Hallowfall", "Aliya Hillhelm is an Arathi located in Hillhelm Stead in Hallowfall." },
  ["alizabeth"] = { 2, "daughter of Alric", "Alizabeth is the daughter of Alric and Daunell Barton. Alric told Arthas that there was a healing fountain up ahead in Alterac." },
  ["allabas"] = { 2, "tauren flight master located at Windfall Cavern in Storms...", "Allabas is a tauren flight master located at Windfall Cavern in Stormsong Valley." },
  ["allan darksteel"] = { 2, "gnome found in Stormshield", "Allan Darksteel is a gnome found in Stormshield. He is found just down the road from Ernst ten Bosch, the flightmaster." },
  ["allash"] = { 2, "technomancer of Ma'nussa", "Allash was a technomancer of Ma'nussa who held membership in the Ravel." },
  ["allavan"] = { 2, "tinker mage", "Allavan was a tinker mage. Allavan was well-known for his use of technological devices to aid his arcane casting abilities." },
  ["allerian defender"] = { 2, "', "Allerian Defenders are human guards for the Allerian Stronghold in Terokkar Forest." },
  ["allerian horseman"] = { 2, "knight serving to protect the Allerian Stronghold in Tero...", "The Allerian Horseman is a knight serving to protect the Allerian Stronghold in Terokkar Forest." },
  ["allerian peasant"] = { 2, "', "Allerian Peasants are humans found walking within the Allerian Stronghold in Terokkar Forest." },
  ["alliance adventurer"] = { 2, "', "You can see these NPCs at the end of the quest  [10-90] Auchindoun and the Ring of Observance (Children's Week). They are a parody of instance party members." },
  ["alliance arbalest"] = { 2, "', "Alliance Arbalests are human archers located in the Arathi Highlands during the Battle for Stromgarde." },
  ["alliance assault volunteer"] = { 2, "', "Alliance Assault Volunteers are Alliance footmen that shipwrecked in the Kelp'thar Forest and were brought to an abandoned warehouse in Ruins of Vashj'ir. There they are trained to battle." },
  ["alliance axeman"] = { 2, "', "Alliance Axemen are humans located in Odesyus' Landing in Azuremyst Isle. They are members of the crew of Admiral Odesyus and cooperate with the Alliance Loggers in the area." },
  ["alliance battlemage"] = { 2, "', "Alliance Battlemagi are humans located in the Jade Forest during  [10-35] Unleash Hell. Each battlemage maintains a Gunship Portal, allowing an adventurer to get back up to the Skyfire in case they've fallen and don't have flying yet." },
  ["alliance berserker"] = { 2, "', "Alliance Berserkers are draenei warriors who participated in the Alliance expedition into the Nexus, under the leadership of Commander Stoutbeard. The Berserkers, alongside their compatriots were frozen in ice for a time by the Nexus' denizens, on..." },
  ["alliance bodyguard"] = { 2, "', "The Alliance Bodyguard was Anduin Wrynn's bodyguard. When the Horde attacked the ship, he was one of the casualties." },
  ["alliance bomber pilot"] = { 2, "dwarf located at the Alliance camp at Aldur'thar: The Des...", "Alliance Bomber Pilot is a dwarf located at the Alliance camp at Aldur'thar: The Desolation Gate in Icecrown." },
  ["alliance brigadier general"] = { 2, "', "Alliance Brigadier Generals were quest givers located in the Alliance capital cities and originally at the Alliance entrance subzones for the battlegrounds." },
  ["alliance cannoneer"] = { 2, "', "Alliance Cannoneers are humans and dwarves aboard the ships during the Battle on the High Seas scenario." },
  ["alliance cannoneer (siege of orgrimmar)"] = { 2, "', "Alliance Cannoneers are humans located aboard Turalyon's Might in Bladefist Bay during the Siege of Orgrimmar." },
  ["alliance captain"] = { 2, "', "Alliance Captains are human captains of the Alliance navy, commanding ships during the Battle on the High Seas scenario." },
  ["alliance captain (lost isles)"] = { 2, "', "Alliance Captains are humans located on the Vengeance Wake in the Lost Isles." },
  ["alliance captain (pandaria)"] = { 2, "human", "The nameless Alliance Captain is a human who was one of the first to rediscover Pandaria. When his ship and a Horde one engaged in a seafare combat, both ships sunk, and he was one of the survivors who made his way to an unknown shore nearby." },
  ["alliance citizen"] = { 2, "', "Alliance Citizens are NPCs of various races found throughout the Darkmoon Faire on Darkmoon Island." },
  ["alliance cleric"] = { 2, "', "Alliance Clerics are the human priests captured in the Hall of Stasis in the Nexus. They are encountered by the Horde." },
  ["alliance commander"] = { 2, "high commander of the Alliance forces invading the Nexus", "Alliance Commander is the high commander of the Alliance forces invading the Nexus." },
  ["alliance conjuror"] = { 2, "', "Alliance Conjurors are humans located in the Dawn of the Infinite." },
  ["alliance conscript"] = { 2, "', "Alliance Conscripts are humans and night elves located in Dragonblight, preventing the Scourge from leaving the Ruby Dragonshrine." },
  ["alliance deckhand"] = { 2, "', "Alliance Deckhands are humans aboard the ships during the Battle on the High Seas scenario." },
  ["alliance defender"] = { 2, "', "Alliance Defenders are humans located in Andorhal during The Deaths of Chromie scenario." },
  ["alliance deserter"] = { 2, "', "The Alliance Deserters are deserters of several races who threw down their weapons and surrendered to the Horde forces at Warsong Hold, under the impression that they would be sent home for being captured by the enemy. They are held at the pigsty ..." },
  ["alliance druid"] = { 2, "', "Alliance Druids are worgen and night elves located in Krasarang Cove in the Krasarang Wilds." },
  ["alliance emissary"] = { 2, "special emissary sent by King Terenas Menethil II to have...", "Alliance Emissary was a special emissary sent by King Terenas Menethil II to have his son Prince Arthas Menethil come back to Lordaeron with his forces and to have them give up the hunt for the dreadlord Mal'Ganis, after Lord Uther persuaded the k..." },
  ["alliance emmissary"] = { 2, "', "Alliance Emmissaries[sic] are located in the Alliance Embassy in Dornogal. They show up with Kurdran Wildhammer and a pair of Stromgarde Footmen, carrying crates after the completion of  [80] Embassies and Envoys." },
  ["alliance field defender"] = { 2, "', "Alliance Field Defenders are humans and dwarves that spawn in Fields of Blood in Southern Barrens. Four of them appear during  [10-30] A Line in the Dirt when an adventurer attempts to capture a point." },
  ["alliance field scout"] = { 2, "human PvP rewards vendor located at a small camp just nor...", "Alliance Field Scout is a human PvP rewards vendor located at a small camp just northwest of Telredor in Zangarmarsh." },
  ["alliance footman (battle for stromgarde)"] = { 2, "', "Alliance Footmen are humans located in Arathi Highlands during the Battle for Stromgarde." },
  ["alliance footman (boralus)"] = { 2, "', "Alliance Footmen are humans located in Boralus." },
  ["alliance footman (dawn of the infinite)"] = { 2, "', "Alliance Footmen are humans located in the Dawn of the Infinite." },
  ["alliance footman (deepwind gorge)"] = { 2, "human located in Deepwind Gorge", "Alliance Footman is a human located in Deepwind Gorge." },
  ["alliance footman (hyjal summit)"] = { 2, "', "Alliance Footmen are footmen who appear at the Battle for Mount Hyjal in the Caverns of Time." },
  ["alliance footman (krasarang wilds)"] = { 2, "', "Alliance Footmen are humans located in Krasarang Cove in the Krasarang Wilds. Some are also found attacking Domination Point." },
  ["alliance footman (nazjatar)"] = { 2, "', "Alliance Footmen are humans located in Nazjatar." },
  ["alliance footman (shadowmoon valley)"] = { 2, "', "Alliance Footmen are deceased human footmen located in Shadowmoon Valley." },
  ["alliance footman (character boost)"] = { 2, "', "Alliance Footmen are level 110 footmen being airdropped on the Tempest's Roar prior to the Battle for Lordaeron." },
  ["alliance footsoldier"] = { 2, "', "Alliance Footsoldiers are humans located at the Norwington Estate in Tiragarde Sound." },
  ["alliance footsoldier (azmerloth)"] = { 2, "', "Alliance Footsoldiers are murlocs located in Azmerloth. They come in two variants." },
  ["alliance force-commander"] = { 2, "human located at", "Alliance Force-Commander is a human located at Andorhal in The Deaths of Chromie scenario." },
  ["alliance fox hunter"] = { 2, "', "Alliance Fox Hunters are human hunters located at Felstone Field in the Western Plaguelands." },
  ["alliance gryphon rider"] = { 2, "', "Alliance Gryphon Riders are human and dwarf gryphon riders escorting the Sword of Dawn prior to the Battle for the Broken Shore. They are equipped with stormhammers." },
  ["alliance guard"] = { 2, "', "Alliance Guards are humans located in Staghelm Point in Silithus: The Wound." },
  ["alliance guard (durotar)"] = { 2, "', "Alliance Guards are humans located in Razor Hill and the Dranosh'ar Blockade in Durotar during the last stage of the War Campaign." },
  ["alliance guard (hillsbrad foothills)"] = { 2, "', "Alliance Guards are humans defending the Alterac Valley entrance in the Hillsbrad Foothills. Prior to the Shattering and the destruction of Southshore they were merely called Southshore Guards and defended the town." },
  ["alliance gunship captain"] = { 2, "dwarf located aboard the Alliance airship", "The Alliance Gunship Captain is a dwarf located aboard the Alliance airship, controlled from the Hangar in Isle of Conquest." },
  ["alliance halaani guard"] = { 2, "', "Alliance Halaani Guards are the guards that come to protect the town of Halaa in Nagrand when it is under control of the Alliance. There are 15 of them, men and women, stationed throughout the town at various buildings, on patrols and keeping wat..." },
  ["alliance hostage"] = { 2, "', "Alliance Hostages are human, dwarf, draenei, and gnome prisoners located in Tol Dagor." },
  ["alliance hunter infantry"] = { 2, "Warden's Vigil", "Alliance Hunter Infantries are dwarves located in the Slagworks, the Warden's Vigil, and the Ironclad Garrison in Tol Barad." },
  ["alliance infantry"] = { 2, "', "Alliance Infantries are human footmen located on the Sword of Dawn prior to the battle for the Broken Shore. They helped train the novice adventurers transported by the gunship by fighting against them." },
  ["alliance infiltrator"] = { 2, "', "Alliance Infiltrators are humans located at the Dookin' Grounds in the Jade Forest." },
  ["alliance infra-green engineer"] = { 2, "', "Alliance Infra-green Engineer are gnomes located at the Alliance camp at Aldur'thar: The Desolation Gate in Icecrown." },
  ["alliance knight"] = { 2, "', "Alliance Knights are humans located in the Arathi Highlands during the Battle for Stromgarde." },
  ["alliance knight (dawn of the infinite)"] = { 2, "', "Alliance Knights are humans located in the Dawn of the Infinite." },
  ["alliance knight (hyjal summit)"] = { 2, "', "Alliance Knights are knights who appear at the Battle for Mount Hyjal in the Caverns of Time." },
  ["alliance laborer"] = { 2, "', "Alliance Laborers are humans located in Felstone Field in Western Plaguelands. They get killed and transformed into Forsaken Troopers." },
  ["alliance laborer (bfa)"] = { 2, "', "Alliance Laborers are humans located in Boralus Harbor in Boralus and in Shatterstone Harbor in Vol'dun." },
  ["alliance logger"] = { 2, "', "Alliance Loggers are humans located in Odesyus' Landing in Azuremyst Isle. They are members of the crew of Admiral Odesyus and cooperate with the Alliance Axemen in the area." },
  ["alliance lookout"] = { 2, "', "Alliance Lookouts are humans located on the Sword of Dawn prior to the battle for the Broken Shore. They spotted the ambush of the Burning Legion against the gunship." },
  ["alliance lookout (shimmering expanse)"] = { 2, "', "Alliance Lookouts are humans and night elves located in Shimmering Expanse. They might be the survivors of the shipwreck from the Kelp'thar Forest." },
  ["alliance mage"] = { 2, "', "Alliance Mages are gnome and human mages located in the Ruins of Lordaeron during the Battle for Lordaeron. Alleria Windrunner and Gelbin Mekkatorque arrived with Ren'dorei Rangers and additional Alliance mages with them near the end of the confli..." },
  ["alliance priest (wandering isle)"] = { 2, "', "Alliance Priests are humans and dwarves found at Wreck of the Skyseeker on the Wandering Isle. They are tending to Injured Sailors, and later help heal Shen-zin Su's wound." },
  ["alliance prisoner"] = { 2, "', "The Alliance Prisoners are the captured crewman of the Vanguard. They survived their encounter with the Horde, but have been trapped by the local hozen and put into cages in the Slingtail Pits in the Jade Forest." },
  ["alliance prisoner (abyssal depths)"] = { 2, "', "Alliance Prisoners are dwarf and human prisoners located in Abyssal Depths." },
  ["alliance prisoner (faction assaults)"] = { 2, "', "Alliance Prisoners are humans and gnomes located on the Horde Airship in Stormsong Valley during Faction Assaults. Some of them are members of the Storm's Wake." },
  ["alliance recruit"] = { 2, "', "Alliance Recruits are Alliance soldiers located inside the Stormwind Harbor prior to the battle for the Broken Shore. They can be seen engaging in a variety of things, like sleeping, training, reading scrolls about the demons of the Burning Legion..." },
  ["alliance recruit (character boost)"] = { 2, "', "Alliance Recruits are soldiers located on the Sword of Dawn prior to the battle for the Broken Shore. They seem equipped with armors of a lesser quality compared to more experienced Alliance footmen." },
  ["alliance rifleman"] = { 2, "', "Alliance Riflemen are dwarves located in the Arathi Highlands during the Battle for Stromgarde." },
  ["alliance rifleman (hyjal summit)"] = { 2, "', "Alliance Riflemen are dwarf riflemen who appear at the Battle for Mount Hyjal in the Caverns of Time." },
  ["alliance rifleman (shadowmoon valley)"] = { 2, "', "Alliance Riflemen are deceased dwarves located in Shadowmoon Valley." },
  ["alliance rogue"] = { 2, "dwarf located in the Deadmines", "Alliance Rogue is a dwarf located in the Deadmines." },
  ["alliance rogue (radiant echoes)"] = { 2, "', "Alliance Rogues are gnome projections located in Pyrox Flats in the Searing Gorge during the Radiant Echoes event. During the inactive phase, they also appear at the Sea of Cinders and Grimesilt Dig Site." },
  ["alliance rootshaper"] = { 2, "', "Alliance Rootshapers are night elves and worgen who land on Krasarang Cove alongside the other forces to establish Lion's Landing." },
  ["alliance sailor"] = { 2, "', "Alliance Sailors are humans located in Stormwind City and Boralus." },
  ["alliance sailor (lost isles)"] = { 2, "', "Alliance Sailors are humans located aboard Vengeance Wake near the Lost Isles." },
  ["alliance sailor (lunarfall)"] = { 2, "', "Alliance Sailors are sailors of the Alliance found on the ships in the harbor, and at the Fleet Command Table in Lunarfall's Town Hall upon reaching Tier 3 Lunarfall Shipyard." },
  ["alliance scout"] = { 2, "human located in the Fox Grove in the Jade Forest", "Alliance Scout is a human located in the Fox Grove in the Jade Forest." },
  ["alliance sea-scout"] = { 2, "', "Alliance Sea-Scouts are spies of the Alliance located at Seabrush in the Abyssal Depths. They are trying to learn some important information about Tenebrous Cavern." },
  ["alliance silithyst sentinel"] = { 2, "', "Alliance Silithyst Sentinels are dwarves found at the Alliance camp in Silithus. This section concerns content related to Legion." },
  ["alliance skirmisher"] = { 2, "', "Alliance Skirmishers are humans located in Nazjatar." },
  ["alliance slave"] = { 2, "', "Alliance Slaves have been captured by the Scourge and forced to work inside the Pit of Saron. Alliance adventurers need to free fifteen slaves and kill Scourgelord Tyrannus to complete the progression quest  [25-30D] The Path to the Citadel to gai..." },
  ["alliance soldier (drustvar)"] = { 2, "', "Alliance Soldiers are humans located at Western Watch in Drustvar." },
  ["alliance soldier (hellfire peninsula)"] = { 2, "', "Alliance Soldiers are draenei, dwarf, night elf, and gnome soldiers located in Stair of Destiny in Hellfire Peninsula. They appear during the Children's Week." },
  ["alliance soldier (isle of dorn)"] = { 2, "', "Alliance Soldiers are humans, draenei, night elves, dwarves, and worgen located at the factions' landing site and at Tranquil Strand on the Isle of Dorn.  They are being transported from ships to the mainland via Alliance Landing Skiffs." },
  ["alliance soldier (nagrand)"] = { 2, "', "Alliance Soldiers are humans and draenei located in Grommashar during its attack, and in Lok-rath and Telaari Station, in Nagrand." },
  ["alliance soldier (pit of saron)"] = { 2, "', "Alliance Soldier are humans located in the Pit of Saron." },
  ["alliance sorcerer"] = { 2, "', "Alliance Sorcerers are humans located in the Arathi Highlands during the Battle for Stromgarde." },
  ["alliance spectator"] = { 2, "', "Alliance Spectators are humans located at the Boneyard in the Twilight Highlands." },
  ["alliance spirit guide"] = { 2, "', "Alliance Spirit Guides are spirit healers who can be found at the graveyards of the various battlegrounds." },
  ["alliance squallshaper"] = { 2, "', "Alliance Squallshapers are humans aboard the ships during the Battle on the High Seas scenario." },
  ["alliance swashbuckler"] = { 2, "', "Alliance Swashbucklers are humans aboard the ships during the Battle on the High Seas scenario." },
  ["alliance truce enforcer"] = { 2, "', "Alliance Truce Enforcers are humans." },
  ["alliance vanguard (siege of orgrimmar)"] = { 2, "', "Alliance Vanguards are humans, dwarves, and gnomes that accompany Alliance leaders on ships from Bladefist Bay into Dranosh'ar Landing where they take part in the Galakras encounter. They also accompany the leaders into the Kor'kron Barracks in th..." },
  ["alliance vanguard (valley of the four winds)"] = { 2, "', "Alliance Vanguards are humans located at the Alliance encampment on the Serpent's Spine in the Valley of the Four Winds. They appear when a Horde player approaches the encampment." },
  ["alliance wargryphoner"] = { 2, "human", "Alliance Wargryphoner is a human." },
  ["alliance warrior"] = { 2, "human located in the Deadmines", "Alliance Warrior is a human located in the Deadmines." },
  ["alliance warrior infantry"] = { 2, "Warden's Vigil", "Alliance Warrior Infantries are draenei located in the Slagworks, the Warden's Vigil, and the Ironclad Garrison in Tol Barad." },
  ["alliance wizard"] = { 2, "', "Alliance Wizards are humans located on the Vengeance Wake in the Lost Isles." },
  ["alliance worker"] = { 2, "', "Alliance Workers are humans and dwarves located in Silithus: The Wound." },
  ["alliance worker (isle of dorn)"] = { 2, "', "Alliance Workers are humans located at the factions' landing site on the Isle of Dorn." },
  ["allurana"] = { 2, "wife of Dethorin", "Allurana was the wife of Dethorin, whose unfaithfulness to him motivated his lamentations and, consequently, the appearance of the Killmaim axe. With this weapon, Allurana and her lover were slain by Dethorin, who then cast the weapon into the sea." },
  ["alrin the agile"] = { 2, "human rogue", "Alrin the Agile was a human rogue who had a chance to appear inside Icecrown Citadel. He waited outside the Crimson Hall to inform adventurers that Infiltrator Minchar has been captured by Blood-Queen Lana'thel, who will execute him if he is not r..." },
  ["alshirr banebreath"] = { 2, "rare mob satyr at Jadefire Glen in Felwood", "Alshirr Banebreath is a rare mob satyr at Jadefire Glen in Felwood." },
  ["alsiaszar"] = { 2, "dracthyr located in the Valley of Honor in Orgrimmar", "Alsiaszar is a dracthyr located in the Valley of Honor in Orgrimmar." },
  ["alta"] = { 2, "earthen", "Alta is an earthen who traveled from Dornogal to Flotsam Shoal on the Siren Isle." },
  ["altaa"] = { 2, "draenei alchemy vendor located in Alchemy & Herbalism in ...", "Altaa is a draenei alchemy vendor located in Alchemy & Herbalism in the Vault of Lights in the Exodar. This section concerns content related to Legion." },
  ["altar defender"] = { 2, "', "Altar Defenders are draenei located in Shadowmoon Valley." },
  ["altar of sha'tar vindicator"] = { 2, "', "The Altar of Sha'tar Vindicators are draenei located at the Altar of Sha'tar in Shadowmoon Valley." },
  ["altauur"] = { 2, "draenei assassin of the Rangari located at the Dionor's D...", "Altauur is a draenei assassin of the Rangari located at the Dionor's Demise in Gorgrond. Altauur was sent by Rangari D'kaan on a dangerous mission." },
  ["altformu"] = { 2, "dracthyr", "Altformu is a dracthyr." },
  ["alton redding"] = { 2, "worgen quest giver located in Irontree Clearing in Felwood", "Alton Redding is a worgen quest giver located in Irontree Clearing in Felwood, on a hill above the entrance to Irontree Cavern. He is Denmother Ulrica's most trusted protector and was sent to disrupt the goblins' mining and logging operation." },
  ["alulgultasza de urgl-blalul"] = { 2, "murloc located in Azmerloth", "Alulgultasza de Urgl-Blalul is a murloc located in Azmerloth. During  [70] A Murloc and a Dragon Walk into a Time Rift..., one of the criteria of  [Temporal Acquisitions Specialist], she briefly appears in the Tyrhold Reservoir in Thaldraszus with..." },
  ["alumeth the ascended"] = { 2, "elite mob located at Aldur'thar in Icecrown", "Alumeth the Ascended is an elite mob located at Aldur'thar in Icecrown. His heart, skull, scepter and robes must be collected from around the chamber and combined to make his remains." },
  ["aluneth (entity)"] = { 2, "strange", "Aluneth is a strange, fickle and powerful entity of pure arcane energy hailing from another plane of existence. It was eventually defeated by the Guardian Aegwynn and bound to an enchanted greatstaff that would come to bear its name, where it rema..." },
  ["aluyen"] = { 2, "Broken reagent vendor found in the Black Temple", "Aluyen is a Broken reagent vendor found in the Black Temple." },
  ["aluyk the peddler"] = { 2, "tuskarr located in Camp Antonidas in the Azure Span", "Aluyk the Peddler is a tuskarr located in Camp Antonidas in the Azure Span." },
  ["alvegar"] = { 2, "earthen located in the Opalcreg on the Isle of Dorn", "Alvegar is an earthen located in the Opalcreg on the Isle of Dorn." },
  ["alya"] = { 2, "draenei fighting Iron Horde Grunts alongside many others ...", "Alya is a draenei fighting Iron Horde Grunts alongside many others at the Dark Portal in Blasted Lands and Tanaan Jungle. She died after the portal was destroyed." },
  ["alyza bowblaze"] = { 2, "Arathi located in Mereldar in Hallowfall", "Alyza Bowblaze is an Arathi located in Mereldar in Hallowfall. She is also appears in the Sinkhole." },
  ["alzinathel"] = { 2, "dracthyr walking with Emishalan in Stormwind Harbor in St...", "Alzinathel is a dracthyr walking with Emishalan in Stormwind Harbor in Stormwind City." },
  ["alzzin the wildshaper"] = { 2, "satyr found in the Warpwood Quarter of Dire Maul", "Alzzin the Wildshaper is a satyr found in the Warpwood Quarter of Dire Maul. He is the final boss of the wing." },
  ["amaan the wise"] = { 2, "', "Amaan the Wise is draenei located at the Temple of Telhamat in the Hellfire Peninsula. He is blind and gives council to the draenei around him." },
  ["amaan the younger"] = { 2, "leader of the Aldori forces", "Amaan the Younger was the leader of the Aldori forces that reinforced the Alliance's army when it first crossed to Outland." },
  ["amaguq"] = { 2, "taunka of Taunka'le village", "Amaguq was a taunka of Taunka'le village. After Trag told him what happened to him, Amaguq allowed him to stay in the village." },
  ["amahle flintwill"] = { 2, "son of Captain Marjani Flintwill raised aboard the Makemb...", "Amahle Flintwill was a son of Captain Marjani Flintwill raised aboard the Makemba of the Blackwater Raiders to the life of a pirate along with his other siblings who had different fathers. He was only two years older than Makasa with whom he often..." },
  ["amakkar"] = { 2, "orc rogue", "Amakkar is an orc rogue and a member of the Bad Dogs, a mercenary trio at New Kargath in the Badlands. He is not as strong as Gargal and Jurrix and instead uses a 'jack-of-all-trades' combat style with stuns and healing potions." },
  ["amalia"] = { 2, "draenei located at the Dalaran Pet Tournament in Dalaran", "Amalia is a draenei located at the Dalaran Pet Tournament in Dalaran. She has a litter of corgi puppies." },
  ["amalia (shadows rising)"] = { 2, "plump", "Amalia is a plump, dark-skinned, and beautiful barmaid working at the Lion's Pride Inn in Goldshire. She exchanged flirts with Jerek when he visited the inn." },
  ["amano, herald of the sun"] = { 2, "card from the Throne of the Tides set", "Amano, Herald of the Sun is a card from the Throne of the Tides set." },
  ["amarakk"] = { 2, "haranir located in Harandar", "Amarakk is a haranir located in Harandar. After the Battle of the Bridge, he aided the assault on the Darkwell." },
  ["amarehz"] = { 2, "daughter of Go'el (Thrall)", "Amarehz, more commonly known as Rehze, is the daughter of Go'el (Thrall) and Aggralan (Aggra), and the younger sister of Durak. She takes after her mother, both in appearance and in her fierce and thoughtful manners." },
  ["amaryllis webb"] = { 2, "undead found in the Swamp of Sorrows", "Amaryllis Webb is an undead found in the Swamp of Sorrows. She sells  [Entomology Starter Kit] to druids and hunters for 50." },
  ["amateur hunter"] = { 2, "', "Amateur Hunters are, as the name suggests, inexperienced and incompetent hunters who have recently arrived at Pinerock Basin in Highmountain, seemingly in the hopes of joining the Unseen Path at the nearby Trueshot Lodge. Since they're scaring awa..." },
  ["amateur photographer"] = { 2, "', "Amateur Photographers are located in Eastwind Shore in Grizzly Hills and throughout Nagrand during Love is in the Air. They come in all playable races." },
  ["ambassador bloodrage"] = { 2, "undead rare mob Scourge agent found in Razorfen Downs wit...", "Ambassador Bloodrage is an undead rare mob Scourge agent found in Razorfen Downs within the Barrens. He was on a 10.5-16 hour respawn timer." },
  ["ambassador jerrikar"] = { 2, "', "Ambassador Jerrikar is rare mob satyr found in Shadowmoon Valley. He can spawn at Coilskar Point, Illidari Point, Eclipse Point, Ruins of Baa'ri or Dragonmaw Fortress." },
  ["ambassador lonn'mog"] = { 2, "ogre located at the Highmaul Harbor in Nagrand", "Ambassador Lonn'mog was an ogre located at the Highmaul Harbor in Nagrand. He was negotiating with Admiral Kronnor and Midshipman Nawrog." },
  ["ambassador malcin"] = { 2, "undead found near Razorfen Downs in the Barrens", "Ambassador Malcin is an undead found near Razorfen Downs in the Barrens. He was a representative from the Scourge to the Death's Head tribe, the ruling body of the quilboars of Kalimdor, offering aid in the quilboars' attempts to take control of t..." },
  ["ambassador pax'ivi"] = { 2, "ethereal trapped within the Mana-Tombs Stasis Chamber in ...", "Ambassador Pax'ivi is an ethereal trapped within the Mana-Tombs Stasis Chamber in the Mana-Tombs. Freeing him is the objective of  [25-30H] Stasis Chambers of the Mana-Tombs." },
  ["ambassador saylaton gravehoof"] = { 2, "tauren", "Ambassador Saylaton Gravehoof is a tauren." },
  ["amber ledge warmage"] = { 2, "', "Amber Ledge Warmages are human guards." },
  ["amber-shaper esh'ri"] = { 2, "mantid located in the Vale of Eternal Blossoms", "Amber-Shaper Esh'ri is a mantid located in the Vale of Eternal Blossoms." },
  ["amber-shaper un'sok"] = { 2, "fifth boss of Heart of Fear", "Amber-Shaper Un'sok is the fifth boss of Heart of Fear. The last boss between the players and Grand Empress Shek'zeer provides an unorthodox battle which requires high raid awareness of both the boss' abilities and the abilities the players receiv..." },
  ["amber-shaper gokilak"] = { 2, "mantid located at Mogu'shan Terrace in Kun-Lai Summit", "Amber-shaper Gokilak is a mantid located at Mogu'shan Terrace in Kun-Lai Summit." },
  ["ambermill brewmaster"] = { 2, "human brewmaster located in Ambermill in the Forsaken zon...", "The Ambermill Brewmaster is a human brewmaster located in Ambermill in the Forsaken zone of Silverpine Forest." },
  ["ambermill mage"] = { 2, "', "Ambermill Mages are the corpses of various Ambermill mages in Silverpine Forest slain by the Forsaken adventurer. Daschla raised them into undeath." },
  ["ambermill magister"] = { 2, "', "Ambermill Magisters are human mages that can be found in Ambermill of Silverpine Forest." },
  ["ambermill miner"] = { 2, "human located in Ambermill in the Forsaken zone of Silver...", "The Ambermill Miner is a human located in Ambermill in the Forsaken zone of Silverpine Forest." },
  ["ambermill portal guardian"] = { 2, "', "Ambermill Portal Guardians are human forces who keep watch outside the portal at Beren's Peril that leads to the dimensionally shifted town of Ambermill in Silverpine Forest. Though they are standard mobs for the most part, they will cast a type o..." },
  ["ambermill spellscribe"] = { 2, "rare human found in Ambermill in Silverpine Forest", "The Ambermill Spellscribe is a rare human found in Ambermill in Silverpine Forest." },
  ["ambermill warder"] = { 2, "', "Ambermill Warders are human guards found in Ambermill of Silverpine Forest." },
  ["ambermill watcher"] = { 2, "', "Ambermill Watchers are human priests found in Ambermill of Silverpine Forest." },
  ["ambermill witchalok"] = { 2, "', "Ambermill Witchaloks are humans found in Ambermill of Silverpine Forest. These casters are capable of summoning Wolfoids, which are friendly to players, or the powerfully elite Doomskull." },
  ["amberpine footman"] = { 2, "', "Amberpine Footmen are human guards for the Alliance outpost of Amberpine Lodge in the Grizzly Hills." },
  ["amberpine hunter"] = { 2, "', "The Amberpine Hunters are two human woodsmen who appear at Amberpine Lodge in Grizzly Hills when the Alliance player and the Freed Alliance Scout arrive at the end of  [15-30] Escape from Silverbrook. They despawn shortly after." },
  ["amberpine scout"] = { 2, "', "Amberpine Scout are human scouts of the Alliance. They can be found at the Blackriver Logging Camp in the Grizzly Hills." },
  ["amberpine woodsman"] = { 2, "', "Amberpine Woodsmen are humans located at Amberpine Lodge in the Grizzly Hills. They stand in pairs, butchering dead Tallhorn Stags." },
  ["ambersmith zikk"] = { 2, "quartermaster for the Klaxxi", "Ambersmith Zikk is the quartermaster for the Klaxxi. He is located at Klaxxi'vess in the Dread Wastes." },
  ["amberstill mountaineer"] = { 2, "', "Amberstill Mountaineers are dwarves located in Amberstill Ranch in Dun Morogh. This section concerns content related to Legion." },
  ["amberwinged mindsinger"] = { 2, "mantid", "Amberwinged Mindsinger is a mantid that can be encountered during Island Expeditions." },
  ["ambitious aspirant"] = { 2, "', "Ambitious Aspirants are kyrian located in Bastion." },
  ["ambitious duelist"] = { 2, "', "Ambitious Duelists are venthyr located in the Menagerie of the Master in Revendreth." },
  ["ambrose"] = { 2, "human warrior", "Ambrose was a human warrior and a member of the Night Watch militia. He assisted Karlain and Revil Kost as they fought off the feral worgen at Manor Mistmantle in Duskwood." },
  ["ambrose boltspark"] = { 2, "gnome mage serving as the Grand Champion of Gnomeregan in...", "Ambrose Boltspark is a gnome mage serving as the Grand Champion of Gnomeregan in the Silver Covenant Pavilion in the Argent Tournament Grounds in Icecrown as part of the Argent Tournament. He participates in the Trial of the Champion." },
  ["ambrose boltspark (tactics)"] = { 2, "boss of the Trial of the Champion in the Crusaders' Coliseum", "Ambrose Boltspark is a boss of the Trial of the Champion in the Crusaders' Coliseum. Like every Alliance champion, he is only encountered by Horde players." },
  ["ambusher"] = { 2, "', "Ambushers are human bandits that may appear when Clara Charles visits the well near her house in Elwynn Forest, just south of Stormwind City." },
  ["ambusher daggerfang"] = { 2, "worgen located in Stormheim", "Ambusher Daggerfang is a worgen located in Stormheim." },
  ["ambushing shaman"] = { 2, "', "Ambushing Shaman are gnolls located in the Azure Span." },
  ["ambushing warrior"] = { 2, "', "Ambushing Warriors are gnolls located in the Azure Span." },
  ["ameeka"] = { 2, "draenei tailor quest giver located at Elodor in Shadowmoo...", "Ameeka is a draenei tailor quest giver located at Elodor in Shadowmoon Valley.  She lives in Embaari Village." },
  ["ameer"] = { 2, "ethereal quest giver", "Ameer is an ethereal quest giver, first appearing as Commander Ameer at the Protectorate Watch Post in the Netherstorm. After the initial quest, he interacts through a projection of himself." },
  ["amelia calder"] = { 2, "deceased sister of Alexander Calder", "Amelia Calder is the deceased sister of Alexander Calder and the cousin of Deze Snowbane. She is referred to in the Sealed Research Report which can be obtained by turning in  [A Careworn Note] from the quest Note from the Front which can be acqui..." },
  ["amethia"] = { 2, "kyrian located in Torghast", "Amethia is a kyrian located in Torghast, Tower of the Damned." },
  ["amethil"] = { 2, "earthen located in Freywold Village on the Isle of Dorn", "Amethil is an earthen located in Freywold Village on the Isle of Dorn." },
  ["amilya airheart"] = { 2, "tauren flight master located at Spinebreaker Post in the ...", "Amilya Airheart is a tauren flight master located at Spinebreaker Post in the Hellfire Peninsula." },
  ["ammen vale guardian"] = { 2, "', "Ammen Vale Guardians are draenei guards located in Ammen Vale. These guards are here to prevent Horde players from interfering with low level players." },
  ["amnumi"] = { 2, "draenei located at the Pilgrim's Road‎ in Talador", "Amnumi is a draenei located at the Pilgrim's Road‎ in Talador." },
  ["amokarok"] = { 2, "worgen leader located in the Rotting Orchard in Duskwood ...", "Amokarok is a worgen leader located in the Rotting Orchard in Duskwood during Nightmare Incursions." },
  ["amphitheater spectator"] = { 2, "', "Amphitheater Spectators are the patrons of the Amphitheater of Anguish in Zul'Drak, watching the fights below. They appear as various different races and factions, with some being generic orcs and humans, to taunka, Winterax trolls, Zandalari trol..." },
  ["amphitheater vendor"] = { 2, "', "Amphitheater Vendors are goblin snacks vendor found at the Amphitheater of Anguish in Zul'Drak." },
  ["amre"] = { 2, "vulpera quest giver located at Zul'Ahjin in Vol'dun", "Amre is a vulpera quest giver located at Zul'Ahjin in Vol'dun." },
  ["amrrgla grglllhrrt"] = { 2, "murloc found in Azmerloth", "Amrrgla Grglllhrrt is a murloc found in Azmerloth. She pilots the Murloc Hopper." },
  ["amwa'ana"] = { 2, "haranir located in the Den in Harandar", "Amwa'ana is a haranir located in the Den in Harandar." },
  ["amy lychenstone"] = { 2, "Arathi located in Mereldar in Hallowfall", "Amy Lychenstone is an Arathi located in Mereldar in Hallowfall. She picks flowers near Klayn Thysthand and brings them to a memorial in the northeastern part of town." },
  ["amythora"] = { 2, "dracthyr located in Zaralek Cavern", "Amythora is a dracthyr located in Zaralek Cavern. She, Marithos, and Winglord Dezran accompanied Scalecommander Sarkareth to Nal ks'kol in his quest to secure Neltharion's legacy for the Sundered Flame." },
  ["an'dorvel"] = { 2, "child living in Silvermoon City when the Scourge attacked...", "An'dorvel was a child living in Silvermoon City when the Scourge attacked during the Third War. When it became clear that the city could not stand, An'dorvel and other civilians boarded a trio of ships bound for the Hinterlands, seeking safe harbo..." },
  ["an'she"] = { 2, "sun god", "An'she (/ˈɔːn.ʃeɪ/ AHN shay) or simply Sun is the sun god, the right eye of the Earth Mother, and the twin brother of Mu'sha in tauren mythology." },
  ["anabelle"] = { 2, "human", "Anabelle is a human." },
  ["anaeli"] = { 2, "draenei located at the Lunarfall in Shadowmoon Valley", "Anaeli is a draenei located at the Lunarfall in Shadowmoon Valley. She can only be recruited using the Headhunter's Harvest from Lunarfall Inn." },
  ["anaka the light's bulwark"] = { 2, "hero card from the Throne of the Tides set", "Anaka the Light's Bulwark is a hero card from the Throne of the Tides set." },
  ["anakron"] = { 2, "human first spotted at certain Infinite Bazaars in Pandar...", "Anakron is a human first spotted at certain Infinite Bazaars in Pandaria Remix. In most of his appearances, he is simply called Hooded Supplier." },
  ["anap"] = { 2, "broker innkeeper", "Anap is a broker innkeeper and vendor located in Haven in Zereth Mortis." },
  ["anara"] = { 2, "kyrian spirit healer located  at the Bear's Head", "Anara is a kyrian spirit healer located  at the Bear's Head, Azshara. She is met by players during the quest  [5-30] Easy is Boring." },
  ["anaryth"] = { 2, "member of the Farstriders before the Second War", "Anaryth was a member of the Farstriders before the Second War. She and Rendevan were sent to scout the Amani territory but did not return." },
  ["anastaria"] = { 2, "Arathi located by a small lake south of Mereldar in Hallo...", "Anastaria is an Arathi located by a small lake south of Mereldar in Hallowfall." },
  ["anastasia"] = { 2, "human girl found in the Trade District of Stormwind City", "Anastasia is a human girl found in the Trade District of Stormwind City, outside of her mother's barbershop. She can be found in front of her mother, Genevieve, who often calls her Ana for short." },
  ["anastei"] = { 2, "draenei located at the Embaari Village in Shadowmoon Valley", "Anastei is a draenei located at the Embaari Village in Shadowmoon Valley." },
  ["anatoly"] = { 2, "human trapper", "Anatoly is a human trapper and Wolfcult member being held hostage by Sasha at the White Pine Trading Post in Grizzly Hills. When he refuses to reveal the location of Sasha's captive sister, Anya, Sasha has adventurers capture Anatoly's wife, Tatja..." },
  ["ancestral sage"] = { 2, "tauren", "Ancestral Sage is a tauren who was to appear outside the Crossroads in the Barrens." },
  ["anchorite ahura"] = { 2, "draenei", "Anchorite Ahura is a draenei that would accompany Akama, Cleric Maluuf, and Vindicator Hogo during the Iron March invasion of Karabor in Shadowmoon Valley." },
  ["anchorite ahuurn"] = { 2, "draenei located at Telredor in Zangarmarsh", "Anchorite Ahuurn is a draenei located at Telredor in Zangarmarsh. Originally, the resident priests seldom received visitors, but when the orcs started to attack draenei settlements, refugees began to arrive in larger numbers." },
  ["anchorite alendar"] = { 2, "draenei located at the Temple of Telhamat in Hellfire Pen...", "Anchorite Alendar is a draenei located at the Temple of Telhamat in Hellfire Peninsula." },
  ["anchorite attendant"] = { 2, "', "Anchorite Attendants are draenei located in the Shrine of Unending Light in Shattrath City." },
  ["anchorite avuun"] = { 2, "draenei quest giver located at the Harborage in the Swamp...", "Anchorite Avuun is a draenei quest giver located at the Harborage in the Swamp of Sorrows. After coming to the Harborage, he encouraged its residents to make it an Alliance-only settlement." },
  ["anchorite ayuri"] = { 2, "draenei quest giver located between the Sun's Reach Sanctum", "Anchorite Ayuri is a draenei quest giver located between the Sun's Reach Sanctum and the Sun's Reach Armory of the Isle of Quel'Danas. She spawns when players retake the harbor." },
  ["anchorite barada"] = { 2, "draenei kneeling next to Colonel Jules' bed on the second...", "Anchorite Barada is a draenei kneeling next to Colonel Jules' bed on the second floor of the Honor Hold inn in Hellfire Peninsula. His assistant is Klatu." },
  ["anchorite buurq"] = { 2, "draenei located in Forest Song in Ashenvale", "Anchorite Buurq is a draenei located in Forest Song in Ashenvale." },
  ["anchorite caalen"] = { 2, "draenei of the Aldor", "Anchorite Caalen is a draenei of the Aldor, found at the Black Temple in Shadowmoon Valley." },
  ["anchorite ceyla"] = { 2, "draenei quest giver located at the Altar of Sha'tar in Sh...", "Anchorite Ceyla is a draenei quest giver located at the Altar of Sha'tar in Shadowmoon Valley." },
  ["anchorite delan"] = { 2, "draenei anchorite located in the Darkshire Town Hall in D...", "Anchorite Delan is a draenei anchorite located in the Darkshire Town Hall in Duskwood. When the draenei learned that Duskwood was a place filled with evil and undeath, Delan came to Darkshire's town hall in order to help its inhabitants in pushing..." },
  ["anchors down patron"] = { 2, "', "Anchors Down Patrons are located at Anchors Down in Stormsong Valley." },
  ["ancient citizen"] = { 2, "', "Ancient Citizens are visions of eredar located at Kil'jaeden's Terrace in Eredath during  [45WQ] Bully Pulpit." },
  ["ancient citizen of nifflevar"] = { 2, "', "The Ancient Citizens of Nifflevar are a crowd of Dragonflayer vrykul gathered in front of King Ymiron in a vision of the ancient past in Nifflevar in the Howling Fjord during  [10-30] Anguish of Nifflevar." },
  ["ancient female vrykul"] = { 2, "Dragonflayer vrykul seen in a vision of the ancient past ...", "The Ancient Female Vrykul is a Dragonflayer vrykul seen in a vision of the ancient past during the quest  [10-30] The Echo of Ymiron, in which she and her husband discuss what to do with their malformed offspring." },
  ["ancient male vrykul"] = { 2, "Dragonflayer vrykul seen in a vision of the ancient past ...", "The Ancient Male Vrykul is a Dragonflayer vrykul seen in a vision of the ancient past during the quest  [10-30] The Echo of Ymiron, in which he and his wife discuss what to do with their malformed offspring." },
  ["ancient mogu defender"] = { 2, "mogu located in the cut Defense of the Alehouse battleground", "Ancient Mogu Defender was a mogu located in the cut Defense of the Alehouse battleground." },
  ["ancient primalist"] = { 2, "', "Ancient Primalists were blood elves, jungle trolls, tauren, dwarves, and orcs found in the Waking Shores." },
  ["ancient raven-priest"] = { 2, "', "Ancient Raven-Priests are arakkoa priests found at the Vortex Pinnacle in the Blade's Edge Mountains. Together with Sai'kkal the Elder, they are part of a cult that worships the raven god Anzu." },
  ["andari"] = { 2, "Lamplighter of the Hallowfall Arathi", "Andari was a Lamplighter of the Hallowfall Arathi and the best friend of Faerin Lothar. They convinced the young Faerin, who'd lost her eye and arm during the expedition's arrival to Hallowfall, to play Light's Gambit to learn strategy, as a way t..." },
  ["andarl"] = { 2, "human quest giver located at Allerian Stronghold in Terok...", "Andarl is a human quest giver located at Allerian Stronghold in Terokkar Forest." },
  ["andegel"] = { 2, "draenei located in the Snug Harbor Inn in Boralus", "Andegel is a draenei located in the Snug Harbor Inn in Boralus." },
  ["ander the monk"] = { 2, "human", "Ander the Monk is a human." },
  ["andesigos"] = { 2, "blue dragon", "Andesigos is a blue dragon who was tasked by Malygos to guard the dracthyr in the Forbidden Reach. He wrote  [Report: Infestation]." },
  ["andi (human)"] = { 2, "human child walking with Miss Danna all around Stormwind ...", "Andi is a human child walking with Miss Danna all around Stormwind City." },
  ["andjor dragontamer"] = { 2, "vrykul located in Pit of Saron", "Andjor Dragontamer is a vrykul located in Pit of Saron. He is the leader of the Sveldrek group of vrykul and rides the Sveldrek Broodmother." },
  ["ando blastenheimer"] = { 2, "teenage gnome found by the wreckage of his father's gyroc...", "Ando Blastenheimer is a teenage gnome found by the wreckage of his father's gyrocopter in Loch Modan. He's run away from his father for some unknown reason." },
  ["ando the gat"] = { 2, "goblin vendor located upstairs in the Incontinental Hotel...", "Ando the Gat is a goblin vendor located upstairs in the Incontinental Hotel during Liberation of Undermine. He sells mounts gated by the Gallagio Loyalty Rewards Club." },
  ["andorhal citizen"] = { 2, "', "Andorhal Citizens are humans located in Andorhal in the Western Plaguelands during  [60] I Intend to Live Forever." },
  ["andorhal defender"] = { 2, "', "Andorhal Defenders are humans located in Andorhal in Western Plaguelands." },
  ["andorhal force-commander"] = { 2, "', "Andorhal Force-Commanders are humans located in Andorhal in Western Plaguelands." },
  ["andorhal resident"] = { 2, "', "Andorhal Residents are humans and dwarves located in the Burning of Andorhal." },
  ["andoris"] = { 2, "dracthyr located at the Artisan's Market in Valdrakken", "Andoris is a dracthyr located at the Artisan's Market in Valdrakken." },
  ["andrahn"] = { 2, "dracthyr item upgrader located in the Eye of Ysera in the...", "Andrahn is a dracthyr item upgrader located in the Eye of Ysera in the Emerald Dream." },
  ["andras"] = { 2, "human located in Boralus", "Andras is a human located in Boralus." },
  ["andrenatol"] = { 2, "draenei priest trainer located at Blood Watch in Bloodmys...", "Andrenatol is a draenei priest trainer located at Blood Watch in Bloodmyst Isle." },
  ["andrew"] = { 2, "human child located in Stormwind City Outskirts in Stormwind", "Andrew is a human child located in Stormwind City Outskirts in Stormwind. He can be seen playing with a Playful Critter." },
  ["andrew (warcraft iii)"] = { 2, "villager", "Andrew was a villager and son of Alicia. The family lived in a farmhouse in a village between the Silver Hand encampment and Strahnbrad." },
  ["andrew clementine"] = { 2, "unknown person", "Andrew Clementine is an unknown person whose drunken exploits are written in Nolkai's battered journal." },
  ["androk"] = { 2, "orc located in Warfang Hold in Stormsong Valley", "Androk is an orc located in Warfang Hold in Stormsong Valley." },
  ["andromede, herald of the forsworn"] = { 2, "Forsworn kyrian located in Bastion", "Andromede, Herald of the Forsworn is a Forsworn kyrian located in Bastion." },
  ["andruk"] = { 2, "orc flight master located at Zoram'gar Outpost in Ashenvale", "Andruk is an orc flight master located at Zoram'gar Outpost in Ashenvale." },
  ["andryck carltyn"] = { 2, "Arathi stationed at Beledar's Bounty in Hallowfall", "Andryck Carltyn is an Arathi stationed at Beledar's Bounty in Hallowfall. When Hallowfall once again came under threat by the Sureki and the army was stretched thin, a call to arms was issued to those with the strength to wield a weapon." },
  ["anduin wrynn (tactics)"] = { 2, "eighth boss of the Sepulcher of the First Ones", "Anduin Wrynn is the eighth boss of the Sepulcher of the First Ones." },
  ["andurg slatechest"] = { 2, "stable master located at Bouldercrag's Refuge in the Stor...", "Andurg Slatechest is a stable master located at Bouldercrag's Refuge in the Storm Peaks. He is an Ulduar earthen and as such is friendly to both the Alliance and the Horde." },
  ["andurs"] = { 2, "vrykul located at Valdisdall in Stormheim", "Andurs is a vrykul located at Valdisdall in Stormheim. Alongside Rydyr, he is pet battle master and his pet is a Mini Musken." },
  ["anduur"] = { 2, "draenei", "Anduur is a draenei who gathered wild berries on the hills of Shadowmoon Valley, when he was attacked and injured by Maa'run, an aggressive talbuk. Anduur's brother, Orrin, put a bounty on the beast and asked for the talbuk's hoof as proof of its ..." },
  ["anessa"] = { 2, "daughter of Broll Bearmantle", "Anessa was the daughter of Broll Bearmantle. She fought beside her father during the Battle of Mount Hyjal." },
  ["ang'kra"] = { 2, "orc located at Boneslag in Frostfire Ridge", "Ang'kra is an orc located at Boneslag in Frostfire Ridge. Angkra is the adopted daughter of Kadar." },
  ["angelista"] = { 2, "character referenced many times in the game", "Angelista is a character referenced many times in the game. With such items as: [Angelista's Touch] [Angelista's Charm] [Angelista's Sash] [Angelista's Grasp] [Angelista's Revenge] The majority of the items suggest that Angelista is a priest." },
  ["anglepoint dockworker"] = { 2, "', "Anglepoint Dockworkers are humans located at Anglepoint Wharf in Tiragarde Sound. They can be seen discussing between themselves or asking the Diligent Tidesage for advice, prompting conversations." },
  ["anglepoint fisherman"] = { 2, "', "Anglepoint Fishermen are humans located at Anglepoint Wharf in Tiragarde Sound." },
  ["anglepoint fishmonger"] = { 2, "', "Anglepoint Fishmongers are humans located in Stormsong Valley." },
  ["anglepoint fishpacker"] = { 2, "', "Anglepoint Fishpackers are humans located at Anglepoint Wharf in Tiragarde Sound." },
  ["anglepoint guard"] = { 2, "', "Anglepoint Guards are humans located in Tiragarde Sound." },
  ["angler danica"] = { 2, "kyrian located in Bastion", "Angler Danica is a kyrian located in Bastion." },
  ["angler etuun"] = { 2, "centaur vendor located in Teerakai in the Ohn'ahran Plains", "Angler Etuun is a centaur vendor located in Teerakai in the Ohn'ahran Plains." },
  ["angler johnny rotten"] = { 2, "Forsaken with the Anglers located throughout Pandaria", "Angler Johnny Rotten is a Forsaken with the Anglers located throughout Pandaria. His location changes daily with the location of special fishing pools noted by Ben of the Booming Voice." },
  ["angler taimu"] = { 2, "centaur fishing trainer standing next to a fishing Iskaar...", "Angler Taimu is a centaur fishing trainer standing next to a fishing Iskaara Trader by the river in northeastern Teerakai in the Ohn'ahran Plains." },
  ["ango'rosh brute"] = { 2, "', "Ango'rosh Brutes are ogres located at the Ango'rosh Grounds in Zangarmarsh." },
  ["ango'rosh mauler"] = { 2, "', "Ango'rosh Maulers are ogres located at the Ango'rosh Stronghold in Zangarmarsh. Looting a  [Box of Mushrooms] causes an Ango'rosh Mauler to appear." },
  ["ango'rosh ogre"] = { 2, "', "Ango'rosh Ogres are ogres located at the Hewn Bog in Zangarmarsh." },
  ["ango'rosh sentry"] = { 2, "', "Ango'rosh Sentries are ogres found at the Ango'rosh Grounds in Zangarmarsh." },
  ["angorla"] = { 2, "earthen located in Flotsam Shoal on the Siren Isle", "Angorla is an earthen located in Flotsam Shoal on the Siren Isle. She was first seen tending to Helpful Haulbot." },
  ["angrathar necrolord"] = { 2, "', "Angrathar Necrolords are humans located in the Court of Skulls in Dragonblight. After a player completes  [15-30] Return To Angrathar, Angrathar Necrolord will phase out of existence for that player and will no longer be available." },
  ["angrun"] = { 2, "orc herbalism trainer located in Grom'gol Base Camp in No...", "Angrun is an orc herbalism trainer located in Grom'gol Base Camp in Northern Stranglethorn." },
  ["angry citizen"] = { 2, "', "Angry Citizens are humans located in Stormwind City." },
  ["angry crowd"] = { 2, "', "Angry Crowds are drogbar located in Path of the Worm in Neltharion's Lair. They watch Naraxas." },
  ["angry merchant"] = { 2, "', "Angry Merchants are humans that would be located around Stormwind Harbor in Stormwind City prior to the discovery of Pandaria." },
  ["angry murloc"] = { 2, "', "Angry Murlocs are murlocs located on Azuremyst Isle. They may spawn when using the  [Draenei Fishing Net] on the Schools of Red Snapper during  [1-30] Red Snapper - Very Tasty!." },
  ["angry trader (orgrimmar)"] = { 2, "goblin located in the Valley of Strength in Orgrimmar", "The Angry Trader is a goblin located in the Valley of Strength in Orgrimmar. They appear during the Auction House Dance Party micro-holiday and the New Year event." },
  ["angry trader (stormwind city)"] = { 2, "gnome located outside the Trader's Hall in the Trade Dist...", "The Angry Trader is a gnome located outside the Trader's Hall in the Trade District in Stormwind City. They appear during the Auction House Dance Party micro-holiday and the New Year event." },
  ["angus"] = { 2, "dwarf found in Dun Morogh", "Angus is a dwarf found in Dun Morogh. He is a part of a dwarven mortar team consisting of himself and Shorty." },
  ["anima smuggler"] = { 2, "', "Anima Smugglers are venthyr encountered by adventure companions in Darkhaven in Revendreth." },
  ["animated guardian (human)"] = { 2, "', "Animated Guardians are humans located in Drustvar." },
  ["anje noon"] = { 2, "Arathi located in Mereldar in Hallowfall", "Anje Noon is an Arathi located in Mereldar in Hallowfall." },
  ["anka clawhoof"] = { 2, "tauren quest giver located at the Sunreaver Pavilion in t...", "Anka Clawhoof is a tauren quest giver located at the Sunreaver Pavilion in the Argent Tournament Grounds in Icecrown. This section concerns content related to Shadowlands." },
  ["ankaa"] = { 2, "draenei found inside Deathweb Hollow alongside Isaari", "Ankaa is a draenei found inside Deathweb Hollow alongside Isaari, Mardaar, and Doruun." },
  ["ankoan champion utaari"] = { 2, "worldsoul memory of an ankoan located in Velhan's Claim i...", "Ankoan Champion Utaari is the worldsoul memory of an ankoan located in Velhan's Claim in Hallowfall during  [80] Worldsoul Memory: Descendant of Distant Waters event." },
  ["antonidas (warcraft iii)"] = { 2, "head of the Kirin Tor", "Antonidas is the head of the Kirin Tor, the conclave of wizards that rules over the magical kingdom of Dalaran. This venerable Archmage is reputedly one of the most powerful wizards in the world." },
  ["antonidas (alternate universe)"] = { 2, "', "In the alternate timeline where Thrall died as an infant, Antonidas was still ruling Dalaran and its Kirin Tor during the reign of the King Aedelas Blackmoore after the Battle of Blackrock Spire. Antonidas and the Kirin Tor severed all ties with K..." },
  ["antonidas (film universe)"] = { 2, "', "Antonidas is leader of the Kirin Tor, de facto ruler of Dalaran and one-time mentor to Medivh and Khadgar." },
  ["antonius"] = { 2, "', "Antonius was one of the One Hundred magi of Arathor. He, Decindra, and their apprentices chose to accompany Thoradin on his quest to find the origins of humanity, which ended in disaster when they broke the seals on the Tomb of Tyr and were killed..." },
  ["antoran drudge"] = { 2, "', "Antoran Drudges are fel-corrupted Broken located in the Arinor Gardens in Eredath." },
  ["antur fallow"] = { 2, "tauren quest giver located at the exit from Red Cloud Mes...", "Antur Fallow is a tauren quest giver located at the exit from Red Cloud Mesa in Mulgore. She was a young tauren on her Rite of Strength quest." },
  ["anub'ar cultist"] = { 2, "', "Anub'ar Cultists are found in Icemist Village in the Dragonblight." },
  ["anuniaq"] = { 2, "tuskarr found in Kamagua in Howling Fjord", "Anuniaq is a tuskarr found in Kamagua in Howling Fjord." },
  ["anuur"] = { 2, "draenei jewelcrafting vendor located at the Argent Tourna...", "Anuur is a draenei jewelcrafting vendor located at the Argent Tournament Grounds in Icecrown. Anuur holds the same stock as Tiffany Cartier in Dalaran." },
  ["anwehu"] = { 2, "draenei armor vendor located behind Exarch Nasuun", "Anwehu is a draenei armor vendor located behind Exarch Nasuun and the Shattrath Portal to Isle of Quel'Danas on the Terrace of Light of Shattrath City. He duplicates Smith Hauthaa's Justice point wares." },
  ["anxious villager"] = { 2, "', "Anxious Villagers are humans located at Anglepoint Wharf in Tiragarde Sound." },
  ["anya"] = { 2, "human trapper girl found in Grizzly Hills", "Anya is a human trapper girl found in Grizzly Hills." },
  ["anya eversong"] = { 2, "dark ranger in the Forsaken forces", "Anya Eversong is a dark ranger in the Forsaken forces. She is an unsettling undead figure wearing a long, shadowladen cloak, obscuring most of her features and causing her to fade into the darkness." },
  ["anyndra"] = { 2, "night elven member of the Watchers", "Anyndra was a night elven member of the Watchers and Maiev Shadowsong's second-in-command. She accompanied her to Outland to hunt Illidan Stormrage and Sarius was in love with her." },
  ["aodhan falamar"] = { 2, "young human mage", "Aodhan Falamar is a young human mage and a student under Master Simeon. At the start of the Nexus War, Dalaran was attacked by blue dragons and Aodhan was tricked into freeing his uncle from the Violet Hold." },
  ["aoewyn"] = { 2, "draenei located in the Molten Fields of the Molten Front", "Aoewyn is a draenei located in the Molten Fields of the Molten Front." },
  ["aonar"] = { 2, "draenei quest giver located at Kessel's Crossing on Blood...", "Aonar is a draenei quest giver located at Kessel's Crossing on Bloodmyst Isle." },
  ["apari"] = { 2, "Zandalari witch", "Apari is a Zandalari witch and the leader of the Widow's Bite, a faction of Zandalari rebels who oppose the rule of Queen Talanji. She had white hair, walked with a noticeable limp, and was always accompanied by her lieutenant and bodyguard Tayo a..." },
  ["apathetic guard"] = { 2, "human located at Hook Point in Boralus", "The Apathetic Guard is a human located at Hook Point in Boralus." },
  ["apek the unkillable"] = { 2, "tortollan located outside the Hall of Beasts in Dazar'alor", "Apek the Unkillable is a tortollan located outside the Hall of Beasts in Dazar'alor. He is doing a pet battle with Rina the Traveler." },
  ["apex blackpowder"] = { 2, "goblin", "Apex Blackpowder is a goblin." },
  ["apoko"] = { 2, "shaman", "Apoko is one of the 8 different NPCs that can be with Priestess Delrissa, the third boss in Magisters' Terrace. He is a shaman, drops Totems (Windfury, Fire Nova), and heals the Priestess and the three other random NPC spawns." },
  ["apolon"] = { 2, "Ascended kyrian located in Bastion", "Apolon is an Ascended kyrian located in Bastion and one of the Hands of Courage, alongside his sister Artemede, serving as seconds in command to Xandria the Paragon of Courage. He and Artemede also organize the Path of Ascension, the eternal train..." },
  ["aponi brightmane"] = { 2, "tauren paladin", "Aponi Brightmane is a tauren paladin and the chieftain of the Sunwalkers. The order was founded by Aponi after theological discussions with Tahu Sagewind about the importance of balancing out the night elven focus on moon-worship through reverence..." },
  ["apothecary baxter"] = { 2, "boss found in Shadowfang Keep during the Love is in the A...", "Apothecary Baxter is a boss found in Shadowfang Keep during the Love is in the Air event." },
  ["apothecary berard"] = { 2, "worgen found in Pyrewood Village in Silverpine Forest", "Apothecary Berard is a worgen found in Pyrewood Village in Silverpine Forest. Before he was transformed into a worgen when Arugal cast his wretched magic on the forest, he was a Forsaken of the Royal Apothecary Society." },
  ["apothecary caolas"] = { 2, "venthyr located in Redelav Tower in Revendreth", "Apothecary Caolas is a venthyr located in Redelav Tower in Revendreth." },
  ["apothecary chemist"] = { 2, "', "Apothecary Chemists were Forsaken located in the Undercity during the Battle for the Undercity." },
  ["apothecary collaborator"] = { 2, "', "Apothecary Collaborators were Forsaken located in the Undercity during the Battle for the Undercity." },
  ["apothecary eli"] = { 2, "member of the Royal Apothecary Society", "Apothecary Eli was a member of the Royal Apothecary Society. She was killed by Citizen Wilkes." },
  ["apothecary frye"] = { 2, "boss found in Shadowfang Keep during the Love is in the A...", "Apothecary Frye is a boss found in Shadowfang Keep during the Love is in the Air event." },
  ["apothecary hummel"] = { 2, "boss found in Shadowfang Keep", "Apothecary Hummel is a boss found in Shadowfang Keep, during the Love is in the Air event. He fights along with Apothecary Baxter and Apothecary Frye." },
  ["apothecary staffron lerent"] = { 2, "Forsaken apothecary hidden away behind Ravenholdt Manor i...", "Apothecary Staffron Lerent was a Forsaken apothecary hidden away behind Ravenholdt Manor in the Alterac Mountains during the Love is in the Air event. He created several special fragrances in order to lull unsuspecting users into a state of misgui..." },
  ["appraiser au'vesk"] = { 2, "broker located in the Hall of Shapes in Oribos", "Appraiser Au'vesk is a broker located in the Hall of Shapes in Oribos. He teaches Maw Walkers about Shadowlands Jewelcrafting crafts." },
  ["apprehensive worker"] = { 2, "', "Apprehensive Workers are gnomes and humans located in Tol Barad Peninsula." },
  ["apprentice alena"] = { 2, "human vendor located in Eye of Eternity during the quest ...", "Apprentice Alena is a human vendor located in Eye of Eternity during the quest   [45] Dispersion of the Discs. For a few resources, she helps the Archmage defuse the excess energy from the three pieces by selling several orbs." },
  ["apprentice anako"] = { 2, "ankoan located in Nazjatar", "Apprentice Anako is an ankoan located in Nazjatar." },
  ["apprentice aonari"] = { 2, "ankoan located at Zin-Azshari in Nazjatar", "Apprentice Aonari is an ankoan located at Zin-Azshari in Nazjatar." },
  ["apprentice argoly"] = { 2, "apprentice under Ansirem Runeweaver", "Apprentice Argoly was an apprentice under Ansirem Runeweaver. After being swiftly trained by Archmage Ataeric, he was sent to Runeweaver as an apprentice." },
  ["apprentice artificer andren"] = { 2, "draenei Arms warrior from Elodor", "Apprentice Artificer Andren is a draenei Arms warrior from Elodor who joined the Alliance champion as a follower after the defeat of Socrethar at Exarch's Rise. He is ultimately seen assisting the Alliance forces in the Gates of Tanaan in Talador." },
  ["apprentice beruun"] = { 2, "draenei artificer located in Aldor Rise in Shattrath City...", "Apprentice Beruun is a draenei artificer located in Aldor Rise in Shattrath City prior to the Tishamaat. Azeek is running around him or is perched atop his shoulder." },
  ["apprentice boulian"] = { 2, "draenei helping to raise the new settlement at Forest Son...", "Apprentice Boulian is a draenei helping to raise the new settlement at Forest Song in Ashenvale." },
  ["apprentice chef"] = { 2, "', "Apprentice Chefs are humans located at Tradewinds Market in Boralus and at Anglepoint Wharf in Tiragarde Sound." },
  ["apprentice ehri"] = { 2, "centaur tending the forge at Timberstep Outpost in the Oh...", "Apprentice Ehri is a centaur tending the forge at Timberstep Outpost in the Ohn'ahran Plains alongside Farrier Roscha." },
  ["apprentice gatherer"] = { 2, "gnome vendor located at the Artisan's Market in Valdrakken", "Apprentice Gatherer is a gnome vendor located at the Artisan's Market in Valdrakken." },
  ["apprentice gekiruun"] = { 2, "centaur mining trainer located Maruukai in the Ohn'ahran ...", "Apprentice Gekiruun is a centaur mining trainer located Maruukai in the Ohn'ahran Plains." },
  ["apprentice inari"] = { 2, "ankoan located at the Ashen Strand in Nazjatar", "Apprentice Inari is an ankoan located at the Ashen Strand in Nazjatar." },
  ["apprentice jewelcrafter"] = { 2, "', "Apprentice Jewelcrafters are orcs and pandaren located in the Hall of Glimmers in Dazar'alor." },
  ["apprentice jeweler eliani"] = { 2, "vulpera jewelcrafting vendor located in Emberwatch in the...", "Apprentice Jeweler Eliani is a vulpera jewelcrafting vendor located in Emberwatch in the Ohn'ahran Plains." },
  ["apprentice mage"] = { 2, "', "Apprentice Mages are mages located in the Wizard's Sanctum within the Mage Quarter of Stormwind City, comprised of various Alliance races. They appear to be taking lessons from the mage trainer Elsharin." },
  ["apprentice mage (children's week)"] = { 2, "', "The Apprentice Mages are located at the Cone of Cold shop in Stormwind City's Mage Quarter during Children's Week. Together with the Ice Elementals, they are creating more ice cream for the children." },
  ["apprentice odari"] = { 2, "ankoan located in Nazjatar", "Apprentice Odari is an ankoan located in Nazjatar." },
  ["apprentice pataana"] = { 2, "tuskarr located at Uktulut Backwater in the Waking Shores", "Apprentice Pataana is a tuskarr located at Uktulut Backwater in the Waking Shores. She can be seen working with wood." },
  ["apprentice pyromage"] = { 2, "', "Apprentice Pyromages are magi located in Azsuna." },
  ["apprentice scrumpy"] = { 2, "vulpera located in Camp Antonidas in the Azure Span", "Apprentice Scrumpy is a vulpera located in Camp Antonidas in the Azure Span. He also attended the gathering in Amirdrassil when it bloomed on the Dragon Isles." },
  ["apprentice shipbuilder"] = { 2, "', "Apprentice Shipbuilders are Arathi located in Silkwood Grotto on the Isle of Dorn." },
  ["apprentice tanmar"] = { 2, "Arathi located in Flotsam Shoal on the Siren Isle", "Apprentice Tanmar is an Arathi located in Flotsam Shoal on the Siren Isle. In the Priory of the Sacred Flame, Tanmar spent most of his adult years among the Sacredites studying the properties of fragments found in Hallowfall." },
  ["apprentice tucky"] = { 2, "vulpera located in Camp Antonidas in the Azure Span", "Apprentice Tucky is a vulpera located in Camp Antonidas in the Azure Span. He also attended the gathering in Amirdrassil when it bloomed on the Dragon Isles." },
  ["apprentice uataro"] = { 2, "ankoan located in Zanj'ir Wash in Nazjatar", "Apprentice Uataro is an ankoan located in Zanj'ir Wash in Nazjatar." },
  ["apprentice ukaro"] = { 2, "ankoan located in Nazjatar", "Apprentice Ukaro is an ankoan located in Nazjatar." },
  ["apprentice unato"] = { 2, "ankoan located at the Spears of Azshara in Nazjatar", "Apprentice Unato is an ankoan located at the Spears of Azshara in Nazjatar." },
  ["apprentice utapo"] = { 2, "ankoan located in the Coral Forest in Nazjatar", "Apprentice Utapo is an ankoan located in the Coral Forest in Nazjatar." },
  ["apprentice wizard"] = { 2, "', "\"This poor guy has to walk =[ He doesn't have a horse! He doesn't know any spells so that is probably why.\" -classic.battle.net entry Apprentice Wizards are human renegade wizard creeps that can be encountered in the Cityscape, Dalaran, Dalaran Ru..." },
  ["april cameraflash"] = { 2, "goblin located at Slam Central Station in the Undermine", "April Cameraflash is a goblin located at Slam Central Station in the Undermine." },
  ["aquatic technician"] = { 2, "', "Aquatic Technicians are orcs located in Blackrock Foundry." },
  ["ar'gorok defender"] = { 2, "', "Ar'gorok Defenders are orcs located in Ar'gorok in the Arathi Highlands." },
  ["ar'gorok grunt"] = { 2, "', "Ar'gorok Grunts are orcs located in Ar'gorok in the Arathi Highlands. They are also present during the Battle for Stromgarde." },
  ["ar'gorok shaman"] = { 2, "', "Ar'gorok Shaman are orcs located in the Arathi Highlands during the Battle for Stromgarde." },
  ["ar'gorok wind rider"] = { 2, "', "Ar'gorok Wind Riders are orcs located in the Arathi Highlands during the Battle for Stromgarde." },
  ["ar'kali the dervish"] = { 2, "human located in the Ruins of Ammon in Uldum during the A...", "Ar'kali the Dervish is a human located in the Ruins of Ammon in Uldum during the Assault in Uldum." },
  ["ar'tor, son of oronok"] = { 2, "dead orc quest giver located at Illidari Point in Shadowm...", "Ar'tor, Son of Oronok is a dead orc quest giver located at Illidari Point in Shadowmoon Valley." },
  ["araac"] = { 2, "arakkoa located at the Lower City in Shattrath City", "Araac is an arakkoa located at the Lower City in Shattrath City." },
  ["araazi"] = { 2, "draenei flight master found at the Shattered Beachhead in...", "Araazi is a draenei flight master found at the Shattered Beachhead in Blasted Lands." },
  ["arachni bloodseeker"] = { 2, "Darkfallen death knight follower located at the Frostwall...", "Arachni Bloodseeker is a Darkfallen death knight follower located at the Frostwall in Frostfire Ridge. She can only be recruited using the Headhunter's Harvest from Frostwall Tavern." },
  ["aradria cloudflyer"] = { 2, "night elven expert hippogryph rider", "Aradria Cloudflyer was a night elven expert hippogryph rider, one of the best in Ashenvale. She was tasked by Commander Haldrissa Woodshaper to send a missive to Darnassus and inform Tyrande Whisperwind that the Horde have infiltrated Ashenvale." },
  ["araka"] = { 2, "orc located in the Hall of Ancient Paths in the Great Seal", "Araka is an orc located in the Hall of Ancient Paths in the Great Seal." },
  ["arakkoa (skyreach)"] = { 2, "', "Arakkoa are arakkoa flying around the Skyreach." },
  ["arakkoa outcast"] = { 2, "', "Arakkoa Outcasts are arakkoa located in the Spires of Arak. Some of them are held prisoner in Skettis." },
  ["arakkoa outcast warrior"] = { 2, "arakkoa", "Arakkoa Outcast Warrior is an arakkoa." },
  ["arakkoa raider"] = { 2, "', "Arakkoa Raiders are arakkoa found attacking Anchorite's Sojourn in Talador during the Saving Anchorite's Sojourn event. They drop no loot." },
  ["arakkoa stinger"] = { 2, "', "Arakkoa Stingers are arakkoa found attacking Anchorite's Sojourn in Talador during the Saving Anchorite's Sojourn event. They drop no loot." },
  ["arakkoa suntalon"] = { 2, "', "Arakkoa Suntalons are arakkoa found attacking Anchorite's Sojourn in Talador during the Saving Anchorite's Sojourn event. They drop no loot." },
  ["arakkoa talon guard"] = { 2, "', "Arakkoa Talon Guards are arakkoa found in the Violet Hold replacing Erekem Guards after wipes. They drop no loot." },
  ["arakkoa visitor"] = { 2, "', "Arakkoa Visitors are visitors that occasionally appear in the VIP section of the Darkmoon Faire Zoo." },
  ["arakkoa windwalker"] = { 2, "arakkoa located in the Violet Hold replacing Erekem after...", "Arakkoa Windwalker is an arakkoa located in the Violet Hold replacing Erekem after wipes." },
  ["aramil"] = { 2, "former guard at Stormwind Keep", "Aramil was a former guard at Stormwind Keep who now served as Turalyon's assistant in all things nonmilitary. He was mentioned when Gelbin Mekkatorque asked Turalyon for aid against a rat infestation in the Deeprun Tram." },
  ["aranda"] = { 2, "female human Guardian of Tirisfal", "Aranda was a female human Guardian of Tirisfal who served the wizards of Dalaran long ago." },
  ["ararat"] = { 2, "warrior", "Ararat was a warrior. His blood was infused with glimmering steel, spilled by dragons, gods, and demons." },
  ["araspeth"] = { 2, "human located at the Lunarfall in Shadowmoon Valley", "Araspeth is a human located at the Lunarfall in Shadowmoon Valley. She can only be recruited using the Headhunter's Harvest from Lunarfall Inn." },
  ["aratas"] = { 2, "ruler of the perfect ones", "High Khan Aratas was the ruler of the perfect ones, a race of centaur created by a powerful earth elemental after the Cataclysm. He united all of the centaur tribes of Kalimdor into a massive army, with the goal of destroying the 'mongrel' races o..." },
  ["aratas' father"] = { 2, "huge", "The unnamed father of Aratas was a huge and powerful earth elemental who appeared in Maraudon after the Cataclysm. He created a new race of centaur known as the perfect ones, led by Aratas, with the intent of conquering Azeroth and purging it of i..." },
  ["arathi aeroknight"] = { 2, "', "Arathi Aeroknights are Arathi located in Azj-Kahet. Later, some of them joined the Flame's Radiance and are found at Lothar's Landing and outside Mereldar." },
  ["arathi ardent"] = { 2, "', "Arathi Ardents are Arathi located in Dunelle's Kindness and Dunelle's Rest in Hallowfall." },
  ["arathi blacksmith"] = { 2, "', "Arathi Blacksmiths are humans located in Arathi Basin." },
  ["arathi bodyguard"] = { 2, "', "Arathi Bodyguards are humans summoned by Arathi Lords in Alliance farms in the Arathi Highlands during Plunderstorm." },
  ["arathi bulwark"] = { 2, "', "Arathi Bulwarks are Arathi located in Hallowfall." },
  ["arathi child"] = { 2, "', "Arathi Children are Arathi children being tutored by Izaeh Strongiron in Lorel's Crossing in Hallowfall." },
  ["arathi citizen"] = { 2, "', "Arathi Citizens are Arathi located in Mereldar in Hallowfall." },
  ["arathi cleric"] = { 2, "', "Arathi Clerics are Arathi located in Lothar's Landing, Dunelle's Kindness, around Morgaen's Tears, and outside Mereldar in Hallowfall." },
  ["arathi crusader"] = { 2, "', "Arathi Crusaders are Arathi located in Lothar's Landing, around Morgaen's Tears, and outside Mereldar in Hallowfall." },
  ["arathi farmer"] = { 2, "', "Arathi Farmers are humans located in Arathi Basin." },
  ["arathi footman"] = { 2, "', "Arathi Footmen are Arathi located in the Priory of the Sacred Flame." },
  ["arathi knight"] = { 2, "', "Arathi Knights are Arathi located in Sina's Yearning in Hallowfall. Others later became members of the Flame's Radiance and are stationed at Lothar's Landing, Dunelle's Kindness, near Morgaen's Tears, and in Faerin's Advance in Azj-Kahet." },
  ["arathi knight (priory of the sacred flame)"] = { 2, "', "Arathi Knights are Arathi located at the Sanctified Grounds in the Priory of the Sacred Flame." },
  ["arathi laborer"] = { 2, "', "Arathi Laborers are Arathi located in Dunelle's Kindness, Lorel's Crossing, Fjord Tavern, Mereldar, and Dayspring Fields in Hallowfall. Some also joined Flame's Radiance and are found in Lothar's Landing." },
  ["arathi laborer (plunderstorm)"] = { 2, "', "Arathi Laborers are humans located in Alliance farms in the Arathi Highlands during Plunderstorm." },
  ["arathi lamplighter"] = { 2, "', "Arathi Lamplighters are lamplighters located in the Dawnbreaker." },
  ["arathi lord"] = { 2, "', "Arathi Lords are humans located in Alliance farms in the Arathi Highlands during Plunderstorm." },
  ["arathi lumberjack"] = { 2, "', "Arathi Lumberjacks are humans located in Arathi Basin." },
  ["arathi militia"] = { 2, "', "Arathi Militias are humans located in Alliance farms in the Arathi Highlands during Plunderstorm." },
  ["arathi miner"] = { 2, "', "Arathi Miners are humans located in Arathi Basin." },
  ["arathi neophyte"] = { 2, "', "Arathi Neophytes are Arathi located in the Priory of the Sacred Flame." },
  ["arathi orphan"] = { 2, "', "Arathi Orphans are Arathi children located in Mereldar in Hallowfall." },
  ["arathi recruit"] = { 2, "', "Arathi Recruits are Arathi located in Lothar's Landing, near Morgaen's Tears, and outside Mereldar in Hallowfall." },
  ["arathi recruit (priory of the sacred flame)"] = { 2, "', "Arathi Recruits are Arathi located in Priory of the Sacred Flame in Hallowfall." },
  ["arathi refugee"] = { 2, "', "Arathi Refugees are humans located in Hammerfall in the Arathi Highlands. Pretending to be refugees from Stromgarde, they are in fact agents of the Syndicate serving the Red Dawn to spy on the Horde." },
  ["arathi reserve"] = { 2, "', "Arathi Reserves are Arathi located in Mereldar and Livia's Patience in Hallowfall." },
  ["arathi scout"] = { 2, "', "Arathi Scouts are dead Arathi located in Shadowmire in Hallowfall. Later, more scouts appeared near Morgaen's Tears as members of Flame's Radiance." },
  ["arathi sentry"] = { 2, "', "Arathi Sentries are Arathi located at most of their settlements and camps in Hallowfall. Later, some of them joined the Flame's Radiance and could be found at Lothar's Landing and in Azj-Kahet." },
  ["arathi shipwright"] = { 2, "', "Arathi Shipwrights are Arathi located in Fjord Tavern in Hallowfall." },
  ["arathi stablehand"] = { 2, "', "Arathi Stablehands are humans located in the Stables of Arathi Basin." },
  ["arathi stalwart"] = { 2, "', "Arathi Stalwarts are Arathi located in Hallowfall." },
  ["arathi villager"] = { 2, "', "Arathi Villagers are humans located in Stromgarde Keep in the Arathi Highlands." },
  ["arathi volunteer"] = { 2, "', "Arathi Volunteers are Arathi located in Lothar's Landing in Hallowfall." },
  ["arathor arbalest"] = { 2, "', "Arathor Arbalests are humans located at Dabyrie's Farmstead in the Arathi Highlands. They also participate in the Battle for Stromgarde fighting against the Horde." },
  ["arathor cavalry"] = { 2, "', "Arathor Cavalries are humans located at Dabyrie's Farmstead in the Arathi Highlands when the Horde controls Ar'gorok." },
  ["arathor defender"] = { 2, "', "Arathor Defenders are humans located in Dabyrie's Farmstead in the Arathi Highlands. They also participate in the Battle for Stromgarde." },
  ["arathor faithful"] = { 2, "', "Arathor Faithfuls are human priests located at Dabyrie's Farmstead in the Arathi Highlands. They also participate in the Battle for Stromgarde fighting against the Horde." },
  ["arathor scout"] = { 2, "', "Arathor Scouts are Arathi located in Deadfin Mire on the Siren Isle while  [80EWQ] Tides of Greed is active. They have been charmed by the island's sirens and now fight for them." },
  ["arathor watchman"] = { 2, "', "Arathor Watchmen are humans located in Trollbane Hall in Arathi Basin. Two are found dead at the Defiler's Den." },
  ["arax'ne"] = { 2, "nerubian located in the Umbral Bazaar in City of Threads", "Arax'ne is a nerubian located in the Umbral Bazaar in City of Threads." },
  ["arc-consul velara"] = { 2, "eredar located at the Conservatory of the Arcane in Eredath", "Arc-Consul Velara is an eredar located at the Conservatory of the Arcane in Eredath. As one of Archimonde's greatest pupils, Velara held such power in her own disciplines that the Conservatory remembers her even centuries later." },
  ["arcane manipulator tharohn"] = { 2, "dracthyr located in the Azure Span", "Arcane Manipulator Tharohn is a dracthyr located in the Azure Span." },
  ["arcane prisoner"] = { 2, "', "Arcane Prisoners can be found inside Arcane Prisons at the Beryl Point in the Borean Tundra. They are abducted mages." },
  ["arcanist alec"] = { 2, "gnome located at Krasus' Landing in Dalaran", "Arcanist Alec is a gnome located at Krasus' Landing in Dalaran. He can provide directions to various locations in Dalaran." },
  ["arcanist delath"] = { 2, "arakkoa quest giver for adventurers with enchanting found...", "Arcanist Delath is an arakkoa quest giver for adventurers with enchanting found in Frostfire Ridge and Shadowmoon Valley." },
  ["arcanist earthsmasher"] = { 2, "', "Arcanist Earthsmashers are ogres located in Broken Precipice of Nagrand." },
  ["arcanist oumana"] = { 2, "ankoan located in Mezzamere in Nazjatar", "Arcanist Oumana is an ankoan located in Mezzamere in Nazjatar." },
  ["arcanist owara"] = { 2, "ankoan located at the Ashen Strand in Nazjatar", "Arcanist Owara is an ankoan located at the Ashen Strand in Nazjatar." },
  ["arcanist uzumu"] = { 2, "ankoan located in Mezzamere in Nazjatar", "Arcanist Uzumu is an ankoan located in Mezzamere in Nazjatar." },
  ["archaeo-tinkologist"] = { 2, "', "Archaeo-Tinkologists are gnomes, dwarves, night elves, and humans who accompany Tinkmaster Overspark to the Forgotten Vault at the Abandoned Junkheap in Tiragarde Sound. All of the non-gnome tinkologists who entered the vault were deemed unworthy ..." },
  ["archaeologist andorin"] = { 2, "dwarf found in Frosthold in Storm Peaks", "Archaeologist Andorin is a dwarf found in Frosthold in Storm Peaks." },
  ["archaeology consultant"] = { 2, "goblin located in a camp with Rohan Sunveil", "Archaeology Consultant is a goblin located in a camp with Rohan Sunveil and Clarya Sunveil near Kal'delar in Val'sharah. He tinkers with a tank." },
  ["archdruid of hyjal"] = { 2, "', "Archdruids of Hyjal are druids located in the Circle of Cinders in Mount Hyjal." },
  ["archenon vindicator"] = { 2, "', "Archenon Vindicators are draenei located in Redemption Rise in Talador." },
  ["archer (trueshot lodge)"] = { 2, "', "Archers are goblins, humans and gnomes located in Trueshot Lodge." },
  ["archer (warcraft i)"] = { 2, "lighter armor they must wear", "Archers use their skill in the crossbow to deal death from a distance. They are slightly more maneuverable than Footmen, but the cost is the lighter armor they must wear." },
  ["archetus the mad designer"] = { 2, "', "The sinstone of Archetus the Mad Designer is found in Revendreth in the Endmire between the Edge of Sin and Death's End." },
  ["architect brokfor"] = { 2, "earthen architect located in the Proscenium on the Isle o...", "Architect Brokfor is an earthen architect located in the Proscenium on the Isle of Dorn. Adventurers help him tidy up the Proscenium." },
  ["archivam assassin"] = { 2, "', "Archivam Assassins are venthyr located in Revendreth." },
  ["archivam ransacker"] = { 2, "', "Archivam Ransackers are venthyr located at Archivam in Revendreth." },
  ["archive investigator"] = { 2, "', "Archive Investigator is venthyr encountered by adventure companions in Revendreth." },
  ["archivist coppermoss"] = { 2, "earthen Archivist located on the beach behind Thunderhead...", "Archivist Coppermoss is an earthen Archivist located on the beach behind Thunderhead Peak on the Isle of Dorn during the Lunar Festival event." },
  ["archivist fane"] = { 2, "venthyr located in the Halls of Atonement in Revendreth", "Archivist Fane is a venthyr located in the Halls of Atonement in Revendreth." },
  ["archivist farolt"] = { 2, "earthen Archivist in the Living Grotto in the Ringing Dee...", "Archivist Farolt is an earthen Archivist in the Living Grotto in the Ringing Deeps during the Lunar Festival event. She can be found beside the waterfall that leads down into Azj-Kahet." },
  ["archivist frithrun"] = { 2, "earthen Archivist located in Dornogal", "Archivist Frithrun is an earthen Archivist located in Dornogal." },
  ["archivist frunhil"] = { 2, "earthen Archivist located in Old Ironforge", "Archivist Frunhil is an earthen Archivist located in Old Ironforge." },
  ["archivist grollund"] = { 2, "earthen Archivist located in the Procedural Forum in the ...", "Archivist Grollund is an earthen Archivist located in the Procedural Forum in the Hall of Awakening." },
  ["archivist ionaa"] = { 2, "Broken located in Krokul Hovel in Krokuun", "Archivist Ionaa is a Broken located in Krokul Hovel in Krokuun. He knew of the Armor of the Triumvirate from before the fall of the eredar." },
  ["archivist ionata"] = { 2, "venthyr encountered by adventure companions in Revendreth", "Archivist Ionata is a venthyr encountered by adventure companions in Revendreth." },
  ["archivist janeera"] = { 2, "venthyr located in the Halls of Atonement in Revendreth", "Archivist Janeera is a venthyr located in the Halls of Atonement in Revendreth." },
  ["archivist karbrima"] = { 2, "earthen Archivist located in Thraegar Rest in Dornogal", "Archivist Karbrima is an earthen Archivist located in Thraegar Rest in Dornogal. There she can be found among the crowd of earthen gathered around Magni Bronzebeard." },
  ["archivist leonara"] = { 2, "venthyr located in the Enclave in Oribos", "Archivist Leonara is a venthyr located in the Enclave in Oribos." },
  ["archivist mokrand"] = { 2, "', "Archivist Mokrand are earthen Archivist located in the Foundation Hall in Dornogal." },
  ["archivist rohlnar"] = { 2, "earthen Archivist located in Freywold Village on the Isle...", "Archivist Rohlnar is an earthen Archivist located in Freywold Village on the Isle of Dorn." },
  ["archivist rubbleglint"] = { 2, "earthen Archivist located on the beach behind Freywold Vi...", "Archivist Rubbleglint is an earthen Archivist located on the beach behind Freywold Village on the Isle of Dorn during the Lunar Festival event." },
  ["archivist silsigra"] = { 2, "earthen Archivist located at the Obsidian Hollow in the R...", "Archivist Silsigra is an earthen Archivist located at the Obsidian Hollow in the Ringing Deeps during the Lunar Festival event." },
  ["archmage (warcraft iii)"] = { 2, "Archmagi represent the pinnacle of magical power", "Hailing from the magical kingdom of Dalaran, the Archmagi represent the pinnacle of magical power. Weaving their intricate enchantments, these crotchety old wizards are called upon to defend humanity with all the magical powers at their disposal." },
  ["archmage allistarj"] = { 2, "demonic human archmage found in Serpent's Coil in the Bla...", "Archmage Allistarj was a demonic human archmage found in Serpent's Coil in the Blasted Lands. Although once human, Allistarj was now in fact demonic." },
  ["archmage alturus"] = { 2, "human located at the entrance to the Master's Cellar guar...", "Archmage Alturus is a human located at the entrance to the Master's Cellar guarding it from demons. Before the Burning Legion's third invasion, he was located just outside of Karazhan in Deadwind Pass." },
  ["archmage alvareaux"] = { 2, "human quartermaster for the Kirin Tor found in the Violet...", "Archmage Alvareaux is a human quartermaster for the Kirin Tor found in the Violet Citadel in Dalaran." },
  ["archmage brixton"] = { 2, "worgen located in either Stormheim", "Archmage Brixton is a worgen located in either Stormheim, Val'sharah or Highmountain." },
  ["archmage cleary"] = { 2, "gnome located in the Upper Frostlands in the Azure Span", "Archmage Cleary is a gnome located in the Upper Frostlands in the Azure Span." },
  ["archmagus nilas arcanister"] = { 2, "human located in the Scarlet Enclave", "Archmagus Nilas Arcanister is a human located in the Scarlet Enclave." },
  ["archritualist kelada"] = { 2, "rare elite mogu", "Archritualist Kelada is a rare elite mogu and the one responsible for the Dark Animus. Occasionally the weekly quest will allow players to kill this mogu, which will start after killing the Dark Animus." },
  ["arcti"] = { 2, "draenei located in the Brewfest grounds in Dun Morogh dur...", "Arcti is a draenei located in the Brewfest grounds in Dun Morogh during Brewfest." },
  ["arcweaver reinforcements"] = { 2, "', "Arcweaver Reinforcements are orcs seen in the Siege of Orgrimmar." },
  ["ardaan the solemn"] = { 2, "apparent draenei located around the Exodar", "Ardaan the Solemn is an apparent draenei located around the Exodar. In truth, he is a homunculus created by the Burning Legion to infiltrate their enemies." },
  ["ardan blastbarrel"] = { 2, "dwarf", "Ardan Blastbarrel is a dwarf that would be located in the Military Ward in Ironforge." },
  ["arden"] = { 2, "captain of the guard of Mardenholde Keep", "Arden was the captain of the guard of Mardenholde Keep and one of the closest friends of governor Tirion Fordring of the principality of Hearthglen. However, prior to the Third War, when Tirion fell from grace as a result of trying to save the orc..." },
  ["ardent champion"] = { 2, "', "Ardent Champions are kyrian located in Bastion." },
  ["ardent defender (npc)"] = { 2, "', "Ardent Defenders are kyrian located in Bastion." },
  ["ardent legionnaire"] = { 2, "', "Ardent Legionnaires are Forsworn kyrian fighting Kyrian Defender above Elysian Hold during  [60] The Greater Good." },
  ["ardent loyalist"] = { 2, "', "Ardent Loyalists are venthyr located at Briar Gate in Revendreth." },
  ["ardent paladin"] = { 2, "', "Ardent Paladins are Arathi located in the Priory of the Sacred Flame." },
  ["ardent warrior"] = { 2, "', "Ardent Warriors are Forsworn kyrian located at the Citadel of Loyalty in Bastion." },
  ["ardgaz"] = { 2, "earthen located in the Council's Treasury in Dornogal", "Ardgaz is an earthen located in the Council's Treasury in Dornogal. He is the Token of Merit exchange for The War Within, trading  [Algari Token of Merit] from the Great Vault for other, hopefully more useful items." },
  ["ardo dirtpaw"] = { 2, "gnoll found in the Rethban Caverns of the Redridge Mountains", "Ardo Dirtpaw is a gnoll found in the Rethban Caverns of the Redridge Mountains." },
  ["ardogan"] = { 2, "Arathorian mage", "Ardogan was an Arathorian mage and an early ruler of the city of Dalaran." },
  ["ardra"] = { 2, "earthen located at the Councilward's Rise in Dornogal", "Ardra is an earthen located at the Councilward's Rise in Dornogal." },
  ["ardule d'na"] = { 2, "draenei vendor located at Elodor in Shadowmoon Valley", "Ardule D'na is a draenei vendor located at Elodor in Shadowmoon Valley." },
  ["ardwynn"] = { 2, "human", "Ardwynn is a human who guarded the Dark Portal in the Hellfire Peninsula when the forces of Azeroth first emerged on Outland. He and his companions blocked the path for Jorad Mace, citing that he was proclaimed deserter." },
  ["area 52 big bruiser"] = { 2, "', "Area 52 Big Bruisers are ogres guarding the goblin city of Area 52 in the Netherstorm." },
  ["area 52 bruiser"] = { 2, "', "Area 52 Bruiser are goblins guarding Area 52 in the Netherstorm." },
  ["arebia wintercall"] = { 2, "Darkfallen death knight located at the Lunarfall in Shado...", "Arebia Wintercall is a Darkfallen death knight located at the Lunarfall in Shadowmoon Valley. She can only be recruited using the Headhunter's Harvest from Lunarfall Inn." },
  ["arechron"] = { 2, "Broken located at Telaar in Nagrand", "Arechron is a Broken located at Telaar in Nagrand. He is the leader of the settlement as well as the Kurenai." },
  ["aredhel"] = { 2, "wife of Karlain", "Aredhel was the wife of Karlain who was accidentally killed by her husband when a man seeking to be Karlain's apprentice attempted to rape her. An image of her appeared before Karlain in Karazhan years later due to the tower's mysterious ability t..." },
  ["aredi"] = { 2, "earthen located in the Lapidarium in the Fissure in Dornogal", "Aredi is an earthen located in the Lapidarium in the Fissure in Dornogal. She is working on an Oathsworn Worker." },
  ["areg bloodrune"] = { 2, "vrykul located in Stormheim", "Areg Bloodrune is a vrykul located in Stormheim." },
  ["arekk"] = { 2, "draenei located at the Bloodthorn Cave in Shadowmoon Valley", "Arekk is a draenei located at the Bloodthorn Cave in Shadowmoon Valley. Along with his friends Roona, Jorril, Diaani, and Zuulo, he went to Bloodthorn Hill to collect the bounty on Kliaa." },
  ["arellas fireleaf"] = { 2, "', "Arellas Fireleaf has a large statue erected in his honor in the Hall of Champions, located in the Scarlet Monastery in the Tirisfal Glades.  A citizen of Quel'Thalas, Fireleaf became the High Wizard of the Scarlet Crusade." },
  ["arena battlemaster (arena tournament)"] = { 2, "', "The Arena Battlemasters for the Arena Tournament realms were Arena battlemasters riding a  [Swift Nether Drake], and could be found in all races' starting areas. In later years, they are instead riding a frost wyrm." },
  ["arena organizer (arena tournament)"] = { 2, "goblin", "The Arena Organizer is a goblin that sells Arena Team Charters for players on the Arena Tournament realms." },
  ["arena promoter"] = { 2, "', "Arena Promoters can be found in various near or in various cities throughout Azeroth on the Arena Tournament realm." },
  ["arena spectator"] = { 2, "', "Arena Spectators are humans and Dark Iron dwarves found observing the Ring of the Law in Blackrock Depths." },
  ["arena spectator (frostfire ridge)"] = { 2, "deceased ogre located in the Circle of Blood in Frostfire...", "Arena Spectator is a deceased ogre located in the Circle of Blood in Frostfire Ridge." },
  ["arena spectator (nagrand)"] = { 2, "', "Arena Spectators are orcs, draenei and goblins located in the Ring of Trials and ogres at the Ring of Blood in Nagrand. They surround the ring, watching the fights that take place there." },
  ["ares the oathbound"] = { 2, "human member of the Argent Crusade", "Ares the Oathbound is a human member of the Argent Crusade and an envoy of the Silver Hand. He ventured into the Utgarde Catacombs in the Howling Fjord to get the  [Sacred Artifact] inside of it." },
  ["arfur"] = { 2, "kobold located in Campalot in the Ringing Deeps", "Arfur is a kobold located in Campalot in the Ringing Deeps." },
  ["argah"] = { 2, "orc located at the Warsong Hold in the Borean Tundra", "Argah is an orc located at the Warsong Hold in the Borean Tundra." },
  ["argaleus"] = { 2, "powerful mage", "Argaleus was a powerful mage. He created a book containing magically enchanted symbols, which, upon touch would activate powerful spells." },
  ["argan hammerfist"] = { 2, "earthen decor vendor located at the Town Center in Founde...", "Argan is an earthen decor vendor located at the Town Center in Founder's Point." },
  ["arganax"] = { 2, "satyr", "Arganax is a satyr who infiltrated Lorlathil in Val'sharah. He took up the form of Nymia Shadesong." },
  ["argarom"] = { 2, "earthen vendor located in Flotsam Shoal on the Siren Isle", "Argarom is an earthen vendor located in Flotsam Shoal on the Siren Isle." },
  ["argent apothecary judkins"] = { 2, "undead quest giver located at the Plaguewood Tower in the...", "Argent Apothecary Judkins is an undead quest giver located at the Plaguewood Tower in the Eastern Plaguelands." },
  ["argent battle-priest"] = { 2, "', "Argent Battle-priests are dwarves and blood elves trying to stop the Scourge from preventing the sanctifing of Crusaders' Pinnacle during  [25-30] The Battle For Crusaders' Pinnacle." },
  ["argent bowman"] = { 2, "', "Argent Bowmen were humans participating in the Dark Portal Opens event at the Dark Portal in the Blasted Lands. They fire Ice Arrows." },
  ["argent centurion"] = { 2, "', "Argent Centurions are members of the Argent Crusade located in Tyr's Hand in Eastern Plaguelands. They can be seen fighting Scarlet Warders and Scarlet Clerics after lighting the Crusader's Flare." },
  ["argent champion"] = { 2, "', "Argent Champions are guards found in various parts of the Valley of Echoes in Icecrown. They are also found at the Argent Tournament riding chargers and in Icecrown Citadel." },
  ["argent commander"] = { 2, "', "Argent Commanders are humans found guarding the Frozen Halls of Icecrown Citadel alongside Ebon Blade Commanders. This section concerns content related to Shadowlands." },
  ["argent crusade engineer"] = { 2, "', "Argent Crusade Engineers are humans located in Light's Hope Chapel in Eastern Plaguelands." },
  ["argent crusade rifleman"] = { 2, "', "The Argent Crusade Riflemen keep Tilda Darathan and Orik Trueheart at Dawn's Reach safe from the Hungering Dead attacking from The Carrion Fields" },
  ["argent crusade spectator"] = { 2, "', "Argent Crusade Spectators are located in the Trial of the Champion and the Trial of the Crusader." },
  ["argent crusader (icecrown)"] = { 2, "', "Argent Crusaders are humans, dwarves, and blood elves located in Icecrown. They are on foot or mounted on horses." },
  ["argent crusader (npc)"] = { 2, "', "Were you looking for the  [Argent Crusader]? Argent Crusaders are soldiers that serve the Argent Crusade found in Light's Trust in Dragonblight and the Argent Stand in Zul'Drak." },
  ["argent crusader (stratholme)"] = { 2, "', "Argent Crusaders are humans, dwarves, blood elves located in Stratholme." },
  ["argent dawn (anniversary)"] = { 2, "', "Argent Dawn are projections of humans, dwarves, and orcs that appear during Story Time in Tanaris. In The Tragedy of Thassarian, they were depicted as being faced off by Thassarian and Death Knights." },
  ["argent dawn cleric"] = { 2, "', "Argent Dawn Clerics were Forsaken of the Argent Dawn available during the first and second Scourge Invasion events in capital cities and Light's Hope Chapel in the Eastern Plaguelands. They gave Marks of the Dawn." },
  ["argent dawn infantry"] = { 2, "', "Argent Dawn Infantry are humans, dwarves, and orcs located at an unnamed camp near Blackwood Lake in the Eastern Plaguelands." },
  ["argent dawn initiate"] = { 2, "', "Argent Dawn Initiates were Forsaken of the Argent Dawn available during the first and second Scourge Invasions in capital cities and Light's Hope Chapel in the Eastern Plaguelands. They gave Lesser Marks of the Dawn." },
  ["argent dawn priest"] = { 2, "', "Argent Dawn Priests were Forsaken of the Argent Dawn available during the first and second Scourge Invasions. They gave Greater Marks of the Dawn." },
  ["argent dawn prisoner"] = { 2, "', "Argent Dawn Prisoners are members of the Argent Dawn who were captured by the Scourge and then transported to the Scourge citadel of Acherus: The Ebon Hold in the Scarlet Enclave. Following the Battle for Light's Hope Chapel and the creation of th..." },
  ["argent dawnbringer"] = { 2, "trail of their dessicated bodies even leading to Fordring", "Argent Dawnbringers are troops that followed Tirion Fordring alongside Argent Lightbringers on a failed assault to the Broken Shore. During the Battle for Broken Shore, many of them can be seen dead or dying, a trail of their dessicated bodies eve..." },
  ["argent defender (npc)"] = { 2, "', "Argent Defenders are human, dwarf, and orc footsoldiers of the Argent Crusade found protecting both Chillwind Camp and the Menders' Stead in the Western Plaguelands, and the Bulwark in Tirisfal Glades." },
  ["argent footman"] = { 2, "', "Argent Footmen are tauren, draenei, human, and orcs located in a small Argent Crusade camp in Drak'Sotra in Zul'Drak. Some of them are withered, Scourged, and dead." },
  ["argent gruntling"] = { 2, "sound like", "The Argent Gruntling is acquired when you become a Champion of your race during the Argent Tournament. Upon summoning, a sound like that of a hunting horn can be heard." },
  ["argent guard"] = { 2, "', "Argent Guards are Argent Dawn guards found guarding Light's Hope Chapel in the Eastern Plaguelands." },
  ["argent guard (naxxramas)"] = { 2, "', "Argent Guards are protecting the Argent Dawn expedition in Naxxramas." },
  ["argent guard (season of discovery)"] = { 2, "', "Argent Guards are humans, night elves, and dwarves located in the Scarlet Enclave." },
  ["argent guardian"] = { 2, "', "Argent Guardians were orc members of the Argent Dawn participating in the Dark Portal Opens event." },
  ["argent healer"] = { 2, "', "Argent Healers were located in all capital cities and they were able to cleanse a \"zombie debuff\" during the Zombie Infestation world event. The said debuff turned you into a zombie, infecting with it every player you attack, that allowed you to k..." },
  ["argent healer (death rising)"] = { 2, "', "Argent Healers are members of the Argent Crusade located in all major cities." },
  ["argent hippogryph rider"] = { 2, "', "Argent Hippogryph Riders are draenei, humans, dwarves and blood elves located in the Ironwall Rampart in Icecrown. Some have been captured by the Cult of the Damned at Aldur'thar: The Desolation Gate." },
  ["argent lightbringer"] = { 2, "', "Argent Lightbringers are troops that followed Tirion Fordring alongside Argent Dawnbringers on a failed assault to the Broken Shore. During  [10-45] The Battle for Broken Shore, many of them can be seen dead or dying." },
  ["argent mage"] = { 2, "', "The Argent Mages are two Forsaken of the Argent Crusade maintaining a portal to Dalaran (Northrend) in the Pathfinder's Den in Orgrimmar. Although members of the Argent Crusade, they are wearing Argent Dawn tabards." },
  ["argent mage (trial of the crusader)"] = { 2, "gnome located in the Trial of the Crusader", "Argent Mage is a gnome located in the Trial of the Crusader." },
  ["argent medic"] = { 2, "', "Argent Medics are dwarves of the Argent Dawn in Eastern Plaguelands. The Medics will cure players of  [Maggot Slime] and  [Ghoul Rot] once the player is honored with the Argent Dawn." },
  ["argent medic (naxxramas)"] = { 2, "', "Argent Medics are dwarf and orc medics helping Injured Soldiers in Naxxramas. One of them is also inspecting Archmage Tarsis Kir-Moldir." },
  ["argent messenger"] = { 2, "', "Argent Messengers were orcs located in capital cities and Light's Hope Chapel in the Eastern Plaguelands." },
  ["argent paladin"] = { 2, "', "Argent Paladins are paladins assaulting the Fleshwerks in Icecrown after its storyline's completion." },
  ["argent peacekeeper"] = { 2, "', "Argent Peacekeepers can be found at the Court of Bones and the Argent Tournament Grounds in Icecrown and in Dalaran. When found in Dalaran, they follow/guard either Arelas Brightstar or Jaeren Sunsworn." },
  ["argent phalanx"] = { 2, "', "Argent Phalanxes are paladins of the Argent Crusade first seen in Krasus' Landing in Dalaran accompanying the paladin leaders. Afterward, some were seen at the Light's Hope Chapel in the Eastern Plaguelands." },
  ["argent priest"] = { 2, "', "Argent Priests are Forsaken located in the Crossroads in the Northern Barrens. Some of them are also confronting Nathanos Blightcaller at Marris Stead in the Eastern Plaguelands." },
  ["argent scout"] = { 2, "', "Argent Scouts could be found in Horde capital cities." },
  ["argent sentry"] = { 2, "', "Argent Sentries are Argent Crusade guards found guarding their towers and Light's Hope Chapel in the Eastern Plaguelands. They participated to the defense of the chapel during the Ebon Blade's assault on Light's Hope Chapel." },
  ["argent sentry (death rising)"] = { 2, "Crossroads in the Northern Barrens", "Argent Sentries are located in Stormwind City, Orgrimmar, the Crossroads in the Northern Barrens, Marris Stead in the Eastern Plaguelands, Darkshire in Duskwood, and in Ironwall Rampart and Court of Bones in Icecrown." },
  ["argent shieldman"] = { 2, "', "Argent Shieldmen are humans, night elves, orcs, and tauren located at the Argent Stand in Zul'Drak." },
  ["argent soldier"] = { 2, "', "Argent Soldiers are humans, night elves, tauren, and orcs located near and at the Altar of Sseratus in Zul'Drak." },
  ["argent watchman"] = { 2, "', "Argent Watchmen are guards found around the Argent Tournament Grounds in Icecrown. They are riding on hippogryphs similar to the  [Argent Hippogryph]." },
  ["argus purifier"] = { 2, "', "Argus Purifiers are draenei located in Sanctum of Light and Deliverance Point on the Broken Shore." },
  ["argus watcher"] = { 2, "Burning Throne", "Argus Watchers were ethereals located throughout Antorus, the Burning Throne." },
  ["ariaana"] = { 2, "draenei located at Arbor Glen in Shadowmoon Valley", "Ariaana is a draenei located at Arbor Glen in Shadowmoon Valley. When the Shadowmoon clan attacked, Ariaana stayed behind to save her pet Squiggy." },
  ["ariana mckinnon"] = { 2, "worgen located in Deliverance Point on the Broken Shore", "Ariana McKinnon is a worgen located in Deliverance Point on the Broken Shore." },
  ["ariel"] = { 2, "murloc located at the Winterfin Retreat in the Borean Tundra", "Ariel is a murloc located at the Winterfin Retreat in the Borean Tundra." },
  ["arietta"] = { 2, "daughter of Elyrion Fogsong", "Arietta was the daughter of Elyrion Fogsong and Ellaene. She was determined to become a Sentinel alongside her mother, but the two of them were killed in a battle." },
  ["arif"] = { 2, "human", "Arif was a human that followed Maddox to Andorhal looking for the defeat of the Scourge. During the battle he lighted a house and discovered it was full of undead ghouls." },
  ["ariia"] = { 2, "tauren follower located at Frostwall in Frostfire Ridge", "Ariia' is a tauren follower located at Frostwall in Frostfire Ridge. She can only be recruited using the Headhunter's Harvest from Frostwall Tavern." },
  ["ariok"] = { 2, "Blackrock orc initially encountered at Flamestar Post (on...", "Ariok is a Blackrock orc initially encountered at Flamestar Post (only visible to Horde players) in the Burning Steppes. He later moves to Chiselgrip and finally Flame Crest." },
  ["arios riftbearer"] = { 2, "Ascended kyrian located in Bastion", "Arios Riftbearer is an Ascended kyrian located in Bastion. He is the Hand of Wisdom serving as second in command to Thenios, the Paragon of Wisdom." },
  ["aris voldin"] = { 2, "dracthyr located in the Common in Razorwind Shores", "Aris Voldin is a dracthyr located in the Common in Razorwind Shores and Town Center in Founder's Point when the Reaching Beyond the Possible endeavor is active." },
  ["ariuun"] = { 2, "draenei located at Light's Rest in Talador", "Ariuun is a draenei located at Light's Rest in Talador." },
  ["arkhaan"] = { 2, "Broken located in the Oronaar Collapse in Eredath", "Arkhaan is a Broken located in the Oronaar Collapse in Eredath. He tried to keep the other Broken in Eredath from falling to the Void, reminding them that salvation was out there among the stars." },
  ["arkkoran muckdweller"] = { 2, "', "Arkkoran Muckdwellers are murlocs found in Azshara." },
  ["arkkoran oracle"] = { 2, "', "Arkkoran Oracles are murlocs found in Azshara." },
  ["arko"] = { 2, "inexperienced mage", "Arko is an inexperienced mage that was assigned to Ziya's plundersquad, which was tasked to raid Pandaren treasuries, temples, and armories for valuables and weapons to fuel the Horde war machine. Spending the night on the chilly northern shore of..." },
  ["arkus"] = { 2, "ogre of the Dire Maul Gordunni clan", "Arkus was an ogre of the Dire Maul Gordunni clan. He guarded Dire Maul and was sent by King Gordok to the gate when the Hidden attacked." },
  ["arlen brighthammer"] = { 2, "dwarf blacksmithing vendor found at the Argent Stand in Z...", "Arlen Brighthammer is a dwarf blacksmithing vendor found at the Argent Stand in Zul'Drak." },
  ["armandei"] = { 2, "venthyr located in Revendreth", "Armandei is a venthyr located in Revendreth." },
  ["armed blackrock peon"] = { 2, "orc", "Armed Blackrock Peon is an orc." },
  ["armored overseer"] = { 2, "Veiled Market", "Armored Overseers are brokers located in Tazavesh, the Veiled Market." },
  ["armored skullsmasher"] = { 2, "fel orc located at the Pits of Mannoroth in Hellfire Citadel", "The Armored Skullsmasher is a fel orc located at the Pits of Mannoroth in Hellfire Citadel." },
  ["armored tunneler"] = { 2, "', "Armored Tunnelers are nerubians located in Silkwood Grotto on the Isle of Dorn." },
  ["armormaster darha"] = { 2, "centaur vendor located in Broadhoof Outpost in the Ohn'ah...", "Armormaster Darha is a centaur vendor located in Broadhoof Outpost in the Ohn'ahran Plains." },
  ["arnaal"] = { 2, "draenei vendor located at the Retribution Point in Talador", "Arnaal is a draenei vendor located at the Retribution Point in Talador." },
  ["arnaera"] = { 2, "night elf buried at Tel'anor in Suramar", "Arnaera is a night elf buried at Tel'anor in Suramar." },
  ["arnbourda"] = { 2, "earthen located in Tradewinds Market in Boralus", "Arnbourda is an earthen located in Tradewinds Market in Boralus." },
  ["arne broadshot"] = { 2, "dwarf located at Forkriver Crossing in the Ohn'ahran Plains", "Arne Broadshot is a dwarf located at Forkriver Crossing in the Ohn'ahran Plains." },
  ["arneu"] = { 2, "draenei located at the Cliffside in Founder's Point", "Arneu is a draenei located at the Cliffside in Founder's Point." },
  ["arngrin"] = { 2, "vrykul located at the Grand Bazaar in Dazar'alor", "Arngrin is a vrykul located at the Grand Bazaar in Dazar'alor." },
  ["arnie doublebutton"] = { 2, "gnome", "Arnie Doublebutton is a gnome who appeared at the Gates of Ironforge in Dun Morogh during Legion Invasions." },
  ["arnok"] = { 2, "orc first aid trainer located at his shop Survival of the...", "Arnok is an orc first aid trainer located at his shop Survival of the Fittest in the Valley of Spirits in Orgrimmar." },
  ["arnokk the burner"] = { 2, "', "Arnokk the Burner is Commander Vorka's pyromaniacal lieutenant and a member of the Iron Horde. He is first seen discussing supply shipments with Sadana Bloodfury in Shaz'gul, flanked by a pair Warsong Ragemongers, and later participates in the Iro..." },
  ["aronen"] = { 2, "draenei found in Light's Hammer of Icecrown Citadel", "Aronen is a draenei found in Light's Hammer of Icecrown Citadel. This section concerns content related to Dragonflight." },
  ["arras"] = { 2, "draenei blacksmithing vendor located at the Trader's Tier...", "Arras is a draenei blacksmithing vendor located at the Trader's Tier in the Exodar. This section concerns content related to Legion." },
  ["arred"] = { 2, "draenei jewelcrafting vendor located at the Crystal Hall ...", "Arred is a draenei jewelcrafting vendor located at the Crystal Hall in the Exodar. This section concerns content related to Legion." },
  ["arrested cultist"] = { 2, "', "Arrested Cultists were humans and orcs located in Stormwind City and Orgrimmar during the Elemental Unrest. They originally were Cultist Incanters and Cultist Infiltrators and became Detained Cultists." },
  ["arrexis"] = { 2, "powerful", "Arrexis was a powerful and well known archmage of the Violet Citadel before the First War. He was also secretly a member of the Council of Tirisfal and wielded  [Ebonchill], the staff of Alodi, the first Guardian." },
  ["arrluk"] = { 2, "tuskarr poison", "Arrluk is a tuskarr poison and reagents vendor located in Kamagua in the Howling Fjord." },
  ["arrogant intruder"] = { 2, "', "Arrogant Intruders are goblins located in the Hovel Hill in the Undermine." },
  ["arrowflight"] = { 2, "white quel'dorei mare steed", "Arrowflight was a white quel'dorei mare steed and the mount of Lireesa Windrunner before the Great Wars, gifted by King Anasterian. At the onset of the Second War, Verath and Lireesa were sent to Lordaeron City, so they set out on their horses." },
  ["artemede"] = { 2, "Ascended kyrian located in Bastion", "Artemede is an Ascended kyrian located in Bastion and one of the Hands of Courage, alongside her brother Apolon, serving as seconds in command to Xandria the Paragon of Courage. She and Apolon also organize the Path of Ascension, the eternal train..." },
  ["artesh"] = { 2, "Dragonmaw orc quest giver", "Artesh is a Dragonmaw orc quest giver who appears briefly within Dragonmaw Port after Warchief Mor'ghor is slain and before the Horde rebuild the site. She and the shaman are instrumental in activating the portal that leads from the Port to Orgrim..." },
  ["arthaid"] = { 2, "draenei stable master located in the Seat of the Naaru in...", "Arthaid is a draenei stable master located in the Seat of the Naaru in the Exodar. This section concerns content related to Legion." },
  ["artificer (npc)"] = { 2, "', "Artificers are draenei artificers who are currently working on the project of raising a new settlement at Forest Song in Ashenvale." },
  ["artificer andren"] = { 2, "draenei located southeast of the Seat of the Naaru in the...", "Artificer Andren is a draenei located southeast of the Seat of the Naaru in the Exodar. This section concerns content related to Legion." },
  ["artificer baleera"] = { 2, "draenei jewelcrafting vendor located at the Embaari Villa...", "Artificer Baleera is a draenei jewelcrafting vendor located at the Embaari Village in Shadowmoon Valley." },
  ["artificer daelo"] = { 2, "draenei engineering trainer located at Azure Watch in Azu...", "Artificer Daelo is a draenei engineering trainer located at Azure Watch in Azuremyst Isle." },
  ["artificer drenin"] = { 2, "draenei located southeast of the Seat of the Naaru in the...", "Artificer Drenin is a draenei located southeast of the Seat of the Naaru in the Exodar. This section concerns content related to Legion." },
  ["artificer ligiea"] = { 2, "Forsworn kyrian located at Kalliope's Rest in Bastion", "Artificer Ligiea is a Forsworn kyrian located at Kalliope's Rest in Bastion." },
  ["artificer morphalius"] = { 2, "ethereal quest giver located inside the entrance of the M...", "Artificer Morphalius is an ethereal quest giver located inside the entrance of the Mana-Tombs in Auchindoun. He and Mamdy the \"Ologist\" are the only two ethereals so far who have passed through Nexus-Prince Shaffar's ward and lived, although Morph..." },
  ["artificer xy'desh"] = { 2, "broker located in Tazarest in Tazavesh", "Artificer Xy'desh is a broker located in Tazarest in Tazavesh, the Veiled Market in K'aresh." },
  ["artificer xy'mox"] = { 2, "broker boss in Castle Nathria", "Artificer Xy'mox is a broker boss in Castle Nathria. Having broken into the vault of Sire Denathrius, Xy'mox wishes to steal away and test the authenticity of the Sire's prized relics on the raid." },
  ["artificer xy'mox (sepulcher of the first ones)"] = { 2, "third boss of the Sepulcher of the First Ones", "Artificer Xy'mox is the third boss of the Sepulcher of the First Ones." },
  ["artillery guard"] = { 2, "dwarf", "Artillery Guard is a dwarf." },
  ["artillery loader"] = { 2, "dwarf", "Artillery Loader is a dwarf." },
  ["artillery loader (orc)"] = { 2, "orc", "Artillery Loader is an orc." },
  ["artillery technician"] = { 2, "', "Artillery Technicians are goblins located in Bilgewater Harbor in Azshara." },
  ["artisan itanu"] = { 2, "ankoan located in Mezzamere in Nazjatar", "Artisan Itanu is an ankoan located in Mezzamere in Nazjatar." },
  ["artisan okata"] = { 2, "ankoan located at Mezzamere in Nazjatar", "Artisan Okata is an ankoan located at Mezzamere in Nazjatar." },
  ["artisan ta'bone"] = { 2, "broker located in the Hall of Curiosities in Oribos", "Artisan Ta'bone is a broker located in the Hall of Curiosities in Oribos." },
  ["artisan's consortium representative"] = { 2, "', "Artisan's Consortium Representatives were located at Forkriver Crossing in the Ohn'ahran Plains. Their IDs were repurposed for Clerk Galesong, Clerk Weaver, and Clerk Goldspark." },
  ["artorius the doombringer"] = { 2, "doomguard disguised as a tauren named Artorius the Amiable", "Artorius the Doombringer is a doomguard disguised as a tauren named Artorius the Amiable, located in Winterspring. He was one of four vile agents of the Burning Legion which Vartrus the Ancient, a tree spirit from Irontree Woods in Felwood, wishes..." },
  ["aru"] = { 2, "young centaur hunter of Clan Shikaar encountered througho...", "Aru is a young centaur hunter of Clan Shikaar encountered throughout the Ohn'ahran Plains. He is locked in a friendly rivalry with Belika over who is the better hunter; Aru believes that precision is more important than speed, while Belika believe..." },
  ["arugi"] = { 2, "orc cooking trainer located in the Drag in Orgrimmar", "Arugi is an orc cooking trainer located in the Drag in Orgrimmar. This section concerns content related to Legion." },
  ["arugoo of the stillpine"] = { 2, "furbolg quest giver located at Azure Watch in Azuremyst Isle", "Arugoo of the Stillpine is a furbolg quest giver located at Azure Watch in Azuremyst Isle." },
  ["aruuna (npc)"] = { 2, "draenei located at Embaari Village in Shadowmoon Valley", "Aruuna was a draenei located at Embaari Village in Shadowmoon Valley." },
  ["aruuna miner"] = { 2, "', "Aruuna Miners are draenei located in Aruuna Crystal Mine in Talador." },
  ["aruuna refugee"] = { 2, "', "Aruuna Refugees are draenei located in areas of Talador." },
  ["arv"] = { 2, "tuskarr located in Iskaara in the Azure Span", "Arv is a tuskarr located in Iskaara in the Azure Span. She is part of the Community Feast." },
  ["arva"] = { 2, "one-eyed", "Arva was a one-eyed, four-toothed goblin first mate of Flynn Fairwind. She was allegedly killed in a tragic harpooning accident." },
  ["arvell"] = { 2, "night elf druid", "Arvell was a night elf druid and the best friend of Ralaar Fangfire. He fought alongside Malfurion Stormrage and the rest of the druids, during the War of the Satyr." },
  ["arvik"] = { 2, "tuskarr located in Iskaara in the Azure Span", "Arvik is a tuskarr located in Iskaara in the Azure Span. He hammers on an anvil, while Arv stands at the forge next to him." },
  ["arwan beastheart"] = { 2, "vrykul located on the expedition isles", "Arwan Beastheart is a vrykul located on the expedition isles." },
  ["arwis blackstone"] = { 2, "dwarf", "Arwis Blackstone is a dwarf that was part of an Alliance expedition sent to Silithus to study Azerite and survey the Horde forces alongside Sentinel Cordressa Briarbow, Sapphronetta Flivvers, Gavvin Stoutarm and Inge Ironfist. After the Horde atta..." },
  ["asarin"] = { 2, "centaur enchanting trainer", "Asarin is a centaur enchanting trainer and vendor located in Teerakai in the Ohn'ahran Plains." },
  ["asarnan"] = { 2, "ethereal enchanting trainer", "Asarnan is an ethereal enchanting trainer and vendor located at the Stormspire in the Netherstorm." },
  ["asbjorn the bloodsoaked"] = { 2, "vrykul located in Stormtide Dregs on the Siren Isle", "Asbjorn the Bloodsoaked is a vrykul located in Stormtide Dregs on the Siren Isle." },
  ["ascended bearer"] = { 2, "kyrian", "Ascended Bearer is a kyrian who rescues the falling Maw Walker of the edges of Bastion." },
  ["ascended champion"] = { 2, "', "Ascended Champions are kyrian located in Bastion." },
  ["ascended defender"] = { 2, "', "Ascended Defenders are Ascended kyrian located in Bastion." },
  ["asger jarlborn"] = { 2, "vrykul located in Stormheim", "Asger Jarlborn is a vrykul located in Stormheim." },
  ["asgrim the dreadkiller"] = { 2, "vrykul", "Asgrim the Dreadkiller was a vrykul whose hatred for the kvaldir was unmatched. He made it his life's work to slay as many of Helya's minions as possible, and his deeds were so great that Helya sent the Naglfar for him." },
  ["ash'katzuum"] = { 2, "', "Ash'katzuum is an draenei serving as the second encounter at Rank 4 in the Brawler's Guild during The War Within" },
  ["ashar ghosthoof"] = { 2, "tauren spiritwalker", "Ashar Ghosthoof was a tauren spiritwalker, who left Theramore with his companions the goblin engineer, Jocas Irongear, and the night elf warden, Blackhawk, aboard Jocas' zeppelin. A mysterious merchant hired them to transport a cargo of spices out..." },
  ["ashbeard"] = { 2, "dwarf", "Ashbeard is a dwarf." },
  ["ashbinder tornecha"] = { 2, "djaradin located in the Waking Shores", "Ashbinder Tornecha is a djaradin located in the Waking Shores." },
  ["ashen enforcer"] = { 2, "', "Ashen Enforcers are orcs located in the Withering Thicket in Darkshore during  [50] In Darkest Night." },
  ["ashen raider"] = { 2, "', "Ashen Raiders are orcs located in Bashal'Aran in Darkshore during  [50] In Darkest Night." },
  ["ashigos"] = { 2, "blue dragon", "Ashigos was a blue dragon who was slain by the black dragonflight. His name is on a Fresh Gravestone at the Veiled Ossuary." },
  ["ashildir"] = { 2, "vrykul located in Stormheim", "Ashildir  is a vrykul located in Stormheim and is the queen of the Valkyra." },
  ["ashka"] = { 2, "Frostwolf orc found in Heartblood of Tanaan Jungle", "Ashka is a Frostwolf orc found in Heartblood of Tanaan Jungle." },
  ["ashkaz"] = { 2, "arakkoa found at Veil Reskk in Terokkar Forest", "Ashkaz is an arakkoa found at Veil Reskk in Terokkar Forest." },
  ["ashlei"] = { 2, "draenei located outside Embaari Village in Saraah's Vale ...", "Ashlei is a draenei located outside Embaari Village in Saraah's Vale in Shadowmoon Valley." },
  ["ashli (gnome)"] = { 2, "', "Ashli was one of the NPCs that players saved while doing the Timed Event in Zul'Aman. Players saved her by killing the Lynx aspect boss, Halazzi, before the timer ran out." },
  ["ashmaul bruiser"] = { 2, "', "Ashmaul Bruisers are ogres located in the Ring of Conquest on Ashran." },
  ["ashmaul destroyer"] = { 2, "', "Ashmaul Destroyers are ogres located in the Ring of Conquest on Ashran." },
  ["ashmaul enforcer"] = { 2, "', "Ashmaul Enforcers are ogres located in Brute's Rise on Ashran." },
  ["ashmaul flamespeaker"] = { 2, "', "Ashmaul Flamespeakers are ogres found in Brute's Rise in Ashran." },
  ["ashmaul forager"] = { 2, "', "Ashmaul Foragers are ogres located in Brute's Rise on Ashran." },
  ["ashmaul magma caster"] = { 2, "ogre riding Oraggro in the Ring of Conquest in Ashran", "Ashmaul Magma Caster is an ogre riding Oraggro in the Ring of Conquest in Ashran." },
  ["ashmaul pyromancer"] = { 2, "', "Ashmaul Pyromancers are ogres located in the Ring of Conquest in Ashran. Four are channeling the Ancient Inferno." },
  ["ashmaul stoneshaper"] = { 2, "', "Ashmaul Stoneshapers are ogres located in the Ring of Conquest on Ashran." },
  ["ashmaul warden"] = { 2, "', "Ashmaul Wardens are ogres located in Ashran." },
  ["ashtar"] = { 2, "orc located at the Valley of Strength in Orgrimmar", "Ashtar is an orc located at the Valley of Strength in Orgrimmar. During the Auction House Dance Party event, Ashtar hijacks the auction house." },
  ["ashtongue battlelord"] = { 2, "Broken found in the Sanctuary of Shadows in the Black Temple", "Ashtongue Battlelord is a Broken found in the Sanctuary of Shadows in the Black Temple and is not polymorphable. Killing him will result in +15 reputation with Ashtongue Deathsworn." },
  ["ashtongue broken"] = { 2, "', "Ashtongue Broken are Broken located in the Refectory in the Black Temple." },
  ["ashtongue channeler"] = { 2, "', "Ashtongue Channelers are Broken found in Black Temple during the Shade of Akama encounter." },
  ["ashtongue defender"] = { 2, "', "Ashtongue Defenders are Broken found in Black Temple during the Shade of Akama encounter." },
