  ["ashtongue handler"] = { 2, "', "Ashtongue Handlers are Broken found in Shadowmoon Valley, handling Elekk Demolishers." },
  ["ashtongue mystic"] = { 2, "', "Ashtongue Mystics are Ashtongue Broken who came from the Black Temple into Mardum with Battlelord Gaardoun. They are seen in the Fel Hammer, Niskara, and Deliverance Point on the Broken Shore." },
  ["ashtongue mystic (black temple)"] = { 2, "', "Ashtongue Mystics are Broken found in the Black Temple. They can be polymorphed." },
