  ["ashtongue stalker"] = { 2, "', "Ashtongue Stalkers are Ashtongue Broken who came from the Black Temple into Mardum with Battlelord Gaardoun. They are seen in the Fel Hammer, Niskara, and Deliverance Point on the Broken Shore." },
