  ["ashtongue warrior"] = { 2, "', "Ashtongue Warriors are Ashtongue Broken who came from the Black Temple into Mardum with Battlelord Gaardoun. They are seen in the Fel Hammer, Niskara, and Deliverance Point on the Broken Shore." },
  ["ashtongue warrior (shadowmoon valley)"] = { 2, "', "Ashtongue Warriors are Broken found in Shadowmoon Valley." },
