  ["ashtongue worker (scenario)"] = { 2, "', "Ashtongue Workers are Broken found in the Illidari Training Grounds in the Pursuing the Black Harvest scenario." },
  ["asithra diresong"] = { 2, "naga located in Darkshore during the Battle for Darkshore", "Asithra Diresong is a naga located in Darkshore during the Battle for Darkshore." },
  ["askara"] = { 2, "skilled draenei priestess", "\"It is true that the Legion is vast and mighty, but they do not stand in the Light as we do. No matter how strong our enemy is, if they walk in darkness, they will always stumble and fall.\" Askara was a skilled draenei priestess and one of the gre..." },
  ["asoran"] = { 2, "orc general goods vendor located in the Valley of Wisdom'...", "Asoran is an orc general goods vendor located in the Valley of Wisdom's Asoran's Market in Orgrimmar. This section concerns content related to Legion." },
  ["aspirant akimos"] = { 2, "kyrian located in Aspirant's Crucible in Bastion", "Aspirant Akimos is a kyrian located in Aspirant's Crucible in Bastion. He asks for three tomes to return to their proper places for everyone to enjoy." },
  ["aspirant defender"] = { 2, "', "Kyrian Aspirants are kyrian guards located at Aspirant's Rest and Aspirant's Crucible in Bastion." },
  ["aspirant eolis"] = { 2, "kyrian located  at the Court of Elation in Bastion", "Aspirant Eolis is a kyrian located  at the Court of Elation in Bastion. To start the encounter, a  [Fragile Humility Scroll] is needed." },
  ["aspirant ikaran"] = { 2, "kyrian located in Aspirant's Crucible in Bastion", "Aspirant Ikaran is a kyrian located in Aspirant's Crucible in Bastion." },
  ["aspirant kiipka"] = { 2, "nerubian located in Weaver's Lair in Azj-Kahet", "Aspirant Kiipka is a nerubian located in Weaver's Lair in Azj-Kahet. After Anub'okki's demise, Aspirant Kiipka was assigned to the former's duties within the Widow's Lair." },
  ["aspirant leda"] = { 2, "kyrian located at the Aspirant's Crucible in Bastion", "Aspirant Leda is a kyrian located at the Aspirant's Crucible in Bastion. She is first encountered when a Maw Walker, having arrived in Bastion to seek an audience with the Archon, accepted a task from Aspirant Akimos to collect some tomes to learn..." },
  ["aspirant thales"] = { 2, "kyrian from the Temple of Courage", "Aspirant Thales is a kyrian from the Temple of Courage who was taken captive by the House of Constructs and brought to their stronghold in Maldraxxus. He was blinded while in captivity, but he and his surviving friends were later freed by Maw Walk..." },
  ["aspirant thete"] = { 2, "kyrian aspirant located in Bastion", "Aspirant Thete is a kyrian aspirant located in Bastion. She was part of the reception the Archon arranged for a Maw Walker, who decided to join the Kyrian Covenant, in honor of their efforts against the Maldraxxus incursion in Bastion." },
  ["aspirant thetes"] = { 2, "kyrian located in Bastion", "Aspirant Thetes is a kyrian located in Bastion." },
  ["aspirant thyri"] = { 2, "vrykul located in Halls of Valor", "Aspirant Thyri is a vrykul located in Halls of Valor." },
  ["aspiring anchorite"] = { 2, "', "Aspiring Anchorites are draenei located at the Stormwind Embassy in Stormwind City." },
  ["aspiring duelist"] = { 2, "', "Aspiring Duelists are Zandalari trolls, blood elves, jungle trolls, goblins, and orcs located in Zuldazar." },
  ["aspiring farseer"] = { 2, "', "Aspiring Farseers are Broken shaman located in the Trader's Tier in the Exodar during the draenei heritage questline." },
  ["aspiring forgehand"] = { 2, "', "Aspiring Forgehands are earthen located in the Stonevault." },
  ["aspiring goblin engineer"] = { 2, "goblin located in the Obsidian Enclave in Valdrakken", "The Aspiring Goblin Engineer is a goblin located in the Obsidian Enclave in Valdrakken." },
  ["aspiring scoundrel"] = { 2, "', "Aspiring Scoundrel are goblins located in Hovel Hill in Undermine." },
  ["aspiring shadow council enforcer"] = { 2, "magic from the portals killed the enforcers", "Aspiring Shadow Council Enforcers are humans, orcs, blood elves located in Wrynnfall on the Broken Shore during   [10-45] Ritual Ruination. After the adventurer warlock overloaded the ritual portals, the magic from the portals killed the enforcers." },
  ["aspiring vrykul hero"] = { 2, "', "Aspiring Vrykul Heroes are vrykul located on the Broken Shore during   [10-45] Return to the Broken Shore." },
  ["aspiring wolfrider"] = { 2, "', "Aspiring Wolfriders are deceased orcs of the Warsong clan found in various locations across Nagrand. It appears that they were all attempting to complete the various steps of the trials of a Warsong wolfrider, but failed and suffered various grues..." },
  ["assault recruit (kyrian)"] = { 2, "', "Assault Recruits are Forsworn kyrian located in Elysian Hold and in Cocyrus in the Maw when the  [60B] Kyrian Assault is active." },
  ["assault recruit (venthyr)"] = { 2, "', "Assault Recruits are venthyr located in Sinfall and the Maw." },
  ["asset manager"] = { 2, "', "Asset Managers are goblins located in Rocketzan in the MOTHERLODE!!" },
  ["assistant artificer"] = { 2, "', "Assistant Artificers are draenei located in the Trader's Tier in the Exodar during the draenei heritage questline." },
  ["assistant au'dul"] = { 2, "broker located in the Hall of Shapes in Oribos", "Assistant Au'dul was a broker located in the Hall of Shapes in Oribos." },
  ["assistant dilya"] = { 2, "draenei located at T&W Trading Post in the Canals in Stor...", "Assistant Dilya is a draenei located at T&W Trading Post in the Canals in Stormwind City. She tends to the mannequins." },
  ["assistant gwinnd"] = { 2, "earthen located at the Oath Gate in Dornogal", "Assistant Gwinnd is an earthen located at the Oath Gate in Dornogal." },
  ["assistant haraald"] = { 2, "earthen located at the Oath Gate in Dornogal", "Assistant Haraald is an earthen located at the Oath Gate in Dornogal." },
  ["assistant subame"] = { 2, "centaur located next to her father Quartermaster Gensai's...", "Assistant Subame is a centaur located next to her father Quartermaster Gensai's tent next to the river in northeastern Teerakai in the Ohn'ahran Plains." },
  ["assistant tik"] = { 2, "nerubian located in the High Hollows in City of Threads", "Assistant Tik is a nerubian located in the High Hollows in City of Threads. They are an agent of the Weaver." },
  ["assistant tourrma"] = { 2, "earthen located with Gertwaald at Councilward's Rise in D...", "Assistant Tourrma is an earthen located with Gertwaald at Councilward's Rise in Dornogal." },
  ["assistant wrangler"] = { 2, "', "Assistant Wranglers are draenei located in Eredath." },
  ["associate xy'gav"] = { 2, "broker located in Tazavesh", "Associate Xy'gav is a broker located in Tazavesh, the Veiled Market in K'aresh." },
  ["associate xy'got"] = { 2, "broker located in K'aresh at Shadow Point within the Unte...", "Associate Xy'got is a broker located in K'aresh at Shadow Point within the Untethered Space." },
  ["assuming scholar"] = { 2, "', "Assuming Scholars are Forsworn kyrian located at the Citadel of Loyalty in Bastion." },
  ["astralan arcanist"] = { 2, "ethereal", "Astralan Arcanist is an ethereal." },
  ["astralan bandit"] = { 2, "ethereal", "Astralan Bandit is an ethereal." },
  ["astralan raider"] = { 2, "ethereal", "Astralan Raider is an ethereal." },
  ["astralan spell-thief"] = { 2, "ethereal", "Astralan Spell-Thief is an ethereal." },
  ["astronos"] = { 2, "kyrian located in Spires of Ascension", "Astronos is a kyrian located in Spires of Ascension." },
  ["astry fallenbough"] = { 2, "satyr disguised as a night elf wandering near the Temple ...", "Astry Fallenbough is a satyr disguised as a night elf wandering near the Temple of Elune in Val'sharah. He can be exposed by paladins wielding the  [Truthguard] or by abilities to reveal demons." },
  ["astur"] = { 2, "draenei stable master located at Blood Watch in Bloodmyst...", "Astur is a draenei stable master located at Blood Watch in Bloodmyst Isle." },
  ["astute watcher"] = { 2, "', "Astute Watcher is located in the Waking Shores. They can spawn as a dwarf or a gnome." },
  ["asuur"] = { 2, "draenei Sha'tari artifacts vendor located in the Shrine o...", "Asuur is a draenei Sha'tari artifacts vendor located in the Shrine of Unending Light in Shattrath City. He is tasked with trading \"Fallen\" tokens for Tier 4 armor pieces." },
  ["aszune"] = { 2, "night elf princess", "Aszune was a night elf princess who, long ago, mocked the Oracle's wisdom. As punishment, she was transformed into living stone." },
  ["ata'gar warrior"] = { 2, "', "Ata'gar Warriors are orcs located in Ruins of Ata'gar in Frostfire Ridge." },
  ["atai'natha"] = { 2, "leader of the Amani forest trolls", "Atai'natha was a leader of the Amani forest trolls who used a powerful magical claw to enforce his rule. The  [Lost Codex of the Amani] spends a particularly long time describing him." },
  ["ataika"] = { 2, "tuskarr standing next to Utaik on the west end of the bes...", "Ataika is a tuskarr standing next to Utaik on the west end of the besieged Kaskala in the Borean Tundra." },
  ["atepa"] = { 2, "tauren banker located on the lower rise in Thunder Bluff", "Atepa is a tauren banker located on the lower rise in Thunder Bluff." },
  ["atheeru palestar"] = { 2, "ethereal available with Spirit Lodge / Mage Tower", "Atheeru Palestar is an ethereal available with Spirit Lodge / Mage Tower. He lets the player set up two Amperial Constructs with portals in the Garrison area." },
  ["athissa"] = { 2, "general of Queen Azshara", "Tidemistress Athissa is a general of Queen Azshara and Tidemistress of the Hatecoil naga. Queen Azshara, former leader of the ancient night elves, rules the naga with supreme authority." },
  ["athodas"] = { 2, "earthen cooking trainer located in Stonelight Rest in Dor...", "Athodas is an earthen cooking trainer located in Stonelight Rest in Dornogal." },
  ["athysios"] = { 2, "dracthyr", "Athysios is a dracthyr." },
  ["atik"] = { 2, "nerubian located in Ara-Kara", "Atik is a nerubian located in Ara-Kara, City of Echoes." },
  ["atomik"] = { 2, "Horde shaman leader of Warspear Outpost", "Atomik is the Horde shaman leader of Warspear Outpost, Ashran. With the aid of adventurers, he works to empower the Underpowered Earth Fury, transforming it into the Earth Fury Kronus, who will do battle for the Horde." },
  ["atoph the bloodcursed"] = { 2, "leader of the Bloodcursed naga", "Atoph the Bloodcursed is the leader of the Bloodcursed naga and defends the shrine of Queen Azshara on the Bloodcurse Isle from any who would seek to destroy it. Captain Edward Hanes on Wyrmscar Island wants both the shrine and Atoph killed in  [1..." },
  ["atropa"] = { 2, "', "Atropa was stationed aboard the Elwynn which was stationed off of the coast Tanaris due to the Horde presence in the area." },
  ["attendant gebberd"] = { 2, "earthen located in Boulder Springs on the Isle of Dorn", "Attendant Gebberd is an earthen located in Boulder Springs on the Isle of Dorn." },
  ["attentive pupil"] = { 2, "', "Attentive Pupils are four orcish children standing in The Den watching Thrall and a fire totem." },
  ["attentive waiter"] = { 2, "Veiled Market", "Attentive Waiters are brokers located in Tazarest in Tazavesh, the Veiled Market." },
  ["attentive waitstaff"] = { 2, "Veiled Market", "Attentive Waitstaffs are brokers located in Tazavesh, the Veiled Market." },
  ["attica whiskervale"] = { 2, "Arathi located in Torchlight Mine in Hallowfall", "Attica Whiskervale is an Arathi located in Torchlight Mine in Hallowfall. He was once a member of Sky-Captain Elaena Lancekat's crew on the Dauntless." },
  ["attwogaz"] = { 2, "stasis-locked earthen located in the Warrens in the Ringi...", "Attwogaz is a stasis-locked earthen located in the Warrens in the Ringing Deeps. Next to him is his plaque." },
  ["atulhet"] = { 2, "tol'vir buried within the Tombs of the Precursors in Uldum", "Atulhet was a tol'vir buried within the Tombs of the Precursors in Uldum. He was a prophet who held off a troves of enemies by channeling the power of the sun." },
  ["aturk the anvil"] = { 2, "orc quest giver located in the Valley of Honor in the orc...", "Aturk the Anvil is an orc quest giver located in the Valley of Honor in the orcish city of Orgrimmar. He is a grumpy blacksmith who is particularly fond of the old days of war and bloodshed." },
  ["atyrannus"] = { 2, "green drake", "Atyrannus is a green drake and one of Lailastrasza's closest companions. Atyrannus' egg was among the primal dragon eggs that were stolen from their nests by the titan-forged under the orders of the dragonflights." },
  ["au'dara"] = { 2, "broker located next to Pathscribe Roh-Avonavi at the Ring...", "Au'Dara is a broker located next to Pathscribe Roh-Avonavi at the Ring of Transference in Oribos." },
  ["au'larrynar"] = { 2, "broker located at the Challenger's Promenade in Maldraxxus", "Au'larrynar is a broker located at the Challenger's Promenade in Maldraxxus." },
  ["au'manal"] = { 2, "broker located in Myza's Oasis in Tazavesh", "Au'manal is a broker located in Myza's Oasis in Tazavesh, the Veiled Market. His business associate is Fe'tajid, and they tried to deceive Cartel Zo." },
  ["au'mba"] = { 2, "broker located just before the Bazaar of Tangible Delight...", "Au'mba is a broker located just before the Bazaar of Tangible Delights in Tazavesh, the Veiled Market." },
  ["au'myza"] = { 2, "broker", "Au'myza is a broker who owns Myza's Oasis in Tazavesh, the Veiled Market." },
  ["au'narim"] = { 2, "broker located at the Challenger's Promenade in Maldraxxus", "Au'narim is a broker located at the Challenger's Promenade in Maldraxxus. She is the top broker in the Challenger's Promenade in Maldraxxus." },
  ["au'ri"] = { 2, "broker located in Tazavesh", "Au'ri is a broker located in Tazavesh, the Veiled Market." },
  ["auchenai arbiter"] = { 2, "', "Auchenai Arbiters are draenei located in Auchindoun." },
  ["auchenai artificer"] = { 2, "', "Auchenai Artificers are draenei located outside Auchindoun in Talador." },
  ["auchenai cleric"] = { 2, "', "Auchenai Clerics are draenei located in Auchindoun." },
  ["auchenai crystalsmith"] = { 2, "', "Auchenai Crystalsmiths are draenei located in Talador." },
  ["auchenai death-speaker"] = { 2, "', "Auchenai Death-Speakers are draenei found at the Bone Wastes in Terokkar Forest, specifically at the Writhing Mound and the southeast part of Auchindoun. They also occasionally spawn from the cocoons at Netherweb Ridge." },
  ["auchenai defender"] = { 2, "', "Auchenai Defenders are draenei located in Talador and in Auchindoun. Several are found being trained by Vindicator Caelus." },
  ["auchenai doomsayer"] = { 2, "', "Auchenai Doomsayers are draenei found at the Bone Wastes in Terokkar Forest, specifically at the Writhing Mound and just south of Auchindoun. At the latter location they can be found animating the spirits of Slain Auchenai Warriors into Unliving I..." },
  ["auchenai guardian"] = { 2, "', "Auchenai Guardians are draenei located in Talador." },
  ["auchenai initiate"] = { 2, "', "Auchenai Initiates are draenei found directly southeast of Auchindoun at the Bone Wastes in Terokkar Forest." },
  ["auchenai magus"] = { 2, "', "Auchenai Magi are draenei located in Auchindoun." },
  ["auchenai monk"] = { 2, "', "Auchenai Monks are draenei of the Auchenai found in the Auchenai Crypts." },
  ["auchenai necromancer"] = { 2, "', "Auchenai Necromancers are draenei of the Auchenai found in Auchenai Crypts." },
  ["auchenai ritualist"] = { 2, "', "Auchenai Ritualists are draenei located in Auchindoun." },
  ["auchenai soulpriest"] = { 2, "', "Auchenai Soulpriests are members of the Auchenai. They can be found in Auchenai Crypts." },
  ["auchenai soulpriest (talador)"] = { 2, "', "Auchenai Soulpriests are draenei located in Talador and Auchindoun." },
  ["auchenai soulpriest (heritage)"] = { 2, "', "Auchenai Soulpriests are draenei located in the Ring of Observance and Auchindoun in Terokkar Forest and in the Trader's Tier in the Exodar during the draenei heritage questline. Some of them are channeling Draenei Spirits into Vacant Vigilants, o..." },
  ["auchenai vindicator"] = { 2, "', "Auchenai Vindicators are Auchenai draenei found in Auchenai Crypts." },
  ["auchenai vindicator (talador)"] = { 2, "', "Auchenai Vindicators are draenei located in Jorune Mine in Talador. Under the command of Vindicator Doruu, they are fighting against the rampaging elementals." },
  ["auchenai vindicator (heritage)"] = { 2, "', "Auchenai Vindicators are draenei located in the Ring of Observance in Terokkar Forest and the Trader's Tier in the Exodar during the draenei heritage questline." },
  ["auchenai warden"] = { 2, "', "Auchenai Wardens are draenei located in Auchindoun." },
  ["auchenai warrior"] = { 2, "', "Auchenai Warriors are draenei found at the Bone Wastes south of Auchindoun in Terokkar Forest. They are found fighting Sha'tar Vindicators." },
  ["auchenai zealot"] = { 2, "', "Auchenai Zealots are draenei located in Auchindoun." },
  ["auctioneer beardo"] = { 2, "goblin auctioneer located in the Gadgetzan auction house ...", "Auctioneer Beardo is a goblin auctioneer located in the Gadgetzan auction house in Tanaris. This section concerns content related to Legion." },
  ["auctioneer braku"] = { 2, "draenei Aldor located at the Aldor bank in Shattrath City", "Auctioneer Braku is a draenei Aldor located at the Aldor bank in Shattrath City. He aids Horde adventurers who have taken up the Aldor's cause by acting as the Horde Auctioneer." },
  ["auctioneer buckler"] = { 2, "dwarf auctioneer located in the Commons in Ironforge", "Auctioneer Buckler is a dwarf auctioneer located in the Commons in Ironforge." },
  ["auctioneer durzin"] = { 2, "earthen located in the Gilded Exchange in Dornogal", "Auctioneer Durzin is an earthen located in the Gilded Exchange in Dornogal." },
  ["auctioneer hesse"] = { 2, "worgen auctioneer located in Stormwind City", "Auctioneer Hesse is a worgen auctioneer located in Stormwind City. At night Hesse changes into a worgen." },
  ["auctioneer prana"] = { 2, "earthen located in the Gilded Exchange in Dornogal", "Auctioneer Prana is an earthen located in the Gilded Exchange in Dornogal." },
  ["audacious artisan"] = { 2, "orc located at Forkriver Crossing in the Ohn'ahran Plains", "The Audacious Artisan is an orc located at Forkriver Crossing in the Ohn'ahran Plains." },
  ["audi the needle"] = { 2, "goblin quest giver located at the Stormspire in the Nethe...", "Audi the Needle is a goblin quest giver located at the Stormspire in the Netherstorm." },
  ["auditor balwurz"] = { 2, "earthen located in the Foundation Hall in Dornogal", "Auditor Balwurz is an earthen located in the Foundation Hall in Dornogal." },
  ["audrid"] = { 2, "draenei found walking among a small group viewing the Exo...", "Audrid is a draenei found walking among a small group viewing the Exodar Holographic Emitters within the Vault of Lights in the Exodar. This section concerns content related to Legion." },
  ["audwin alston"] = { 2, "human located in Stormwind Keep in Stormwind City", "Audwin Alston is a human located in Stormwind Keep in Stormwind City." },
  ["auebry irongear"] = { 2, "Arathi located in the Whirring Field in Hallowfall", "Auebry Irongear is an Arathi located in the Whirring Field in Hallowfall." },
  ["aufta"] = { 2, "earthen located at the Steam Vent in Dornogal", "Aufta is an earthen located at the Steam Vent in Dornogal." },
  ["augari consul"] = { 2, "', "Augari Consuls are eredar located at the Conservatory of the Arcane in Eredath. They are followed by Manabound Familiars." },
  ["augari novitiate"] = { 2, "', "Augari Novitiates are eredar located at the Conservatory of the Arcane in Eredath." },
  ["augari summoner"] = { 2, "', "Augari Summoners are eredar located at the Wakener's Enclave in Eredath." },
  ["augari wakener"] = { 2, "', "Augari Wakeners are eredar located at the Wakener's Enclave and the Praetorium in Eredath. They can be seen powering up Soulbonded Constructs." },
  ["aughild the bitter"] = { 2, "vrykul located in Stormheim", "Aughild the Bitter was a vrykul located in Stormheim. She was a fallen Valkyra who found a  [Arcane Vessel Fragment]." },
  ["augustus the touched"] = { 2, "undead fungus vendor", "Augustus the Touched is an undead fungus vendor and quest giver located in Terrordale in the Eastern Plaguelands. He is insane, and so are his prices." },
  ["auhula"] = { 2, "draenei Apprentice Hippogryph Master located at Forest So...", "Auhula is a draenei Apprentice Hippogryph Master located at Forest Song in Ashenvale. She is being taught by Suralais Farwind." },
  ["aumana"] = { 2, "tauren quest giver stationed at Blue Sky Logging Grounds ...", "Aumana is a tauren quest giver stationed at Blue Sky Logging Grounds in the Grizzly Hills." },
  ["aumanil"] = { 2, "tuskarr", "Aumanil is a tuskarr that steers the Walker of Waves, a giant turtle, between Moa'ki Harbor and Unu'pe. This section concerns content related to Dragonflight." },
  ["aundro"] = { 2, "draenei blacksmithing vendor located at the Sha'tari Base...", "Aundro is a draenei blacksmithing vendor located at the Sha'tari Base Camp in Terokkar Forest." },
  ["auntie kaunnie"] = { 2, "tuskarr located in the Azure Span", "Auntie Kaunnie is a tuskarr located in the Azure Span." },
  ["auralia steelstrike"] = { 2, "Arathi Quartermaster", "Auralia Steelstrike is the Arathi Quartermaster and the daughter of General Steelstrike. She is described as the backbone of the Arathi Army." },
  ["aurelon"] = { 2, "draenei paladin trainer located at the Crash Site on Azur...", "Aurelon is a draenei paladin trainer located at the Crash Site on Azuremyst Isle. He converses with Zalduun." },
  ["auric spiritguide"] = { 2, "Ascended kyrian located in Valiant's Path in Bastion", "Auric Spiritguide is an Ascended kyrian located in Valiant's Path in Bastion." },
  ["auro flitter"] = { 2, "Arathi flight master located at Dunelle's Kindness in Hal...", "Auro Flitter is an Arathi flight master located at Dunelle's Kindness in Hallowfall." },
  ["aurok"] = { 2, "draenei armor vendor located at the Crash Site in Azuremy...", "Aurok is a draenei armor vendor located at the Crash Site in Azuremyst Isle." },
  ["ausgazur"] = { 2, "shutdown earthen located in Shimmermist Falls in the Ring...", "Ausgazur is a shutdown earthen located in Shimmermist Falls in the Ringing Deeps." },
  ["austin huxworth"] = { 2, "worgen hunter found in Exile's Reach", "Austin Huxworth is a worgen hunter found in Exile's Reach. He is responsible for helping new hunters learn some of their talents and abilities." },
  ["avelii"] = { 2, "draenei bow vendor located at the Hunters' Sanctum in the...", "Avelii is a draenei bow vendor located at the Hunters' Sanctum in the Trader's Tier in the Exodar. This section concerns content related to Legion." },
  ["avenger oni"] = { 2, "ankoan of the Waveblade clan 'Who took ten lives for each...", "Avenger Oni was an ankoan of the Waveblade clan 'Who took ten lives for each one we lost.' When Oni died, the ankoan kill a hundred in return.' They lie buried at an Ankoan Burial Shrine in Kal'methir Citadel in Nazjatar." },
  ["avinal"] = { 2, "weathered human captain of a convoy ship affiliated to th...", "Avinal was the weathered human captain of a convoy ship affiliated to the Theramore military. Usually stationed at Northwatch Hold, he regularly patrolled the waters between there and Ratchet." },
  ["avna"] = { 2, "broker located in Haven in Zereth Mortis", "Avna is a broker located in Haven in Zereth Mortis." },
  ["avowed caregiver"] = { 2, "', "Avowed Caregivers are venthyr located at the Absolution Crypt in Revendreth." },
  ["avowed caretaker"] = { 2, "', "Avowed Caretakers are venthyr located in Revendreth." },
  ["avowed confessor"] = { 2, "venthyr located at the Halls of Atonement in Revendreth", "The Avowed Confessor is a venthyr located at the Halls of Atonement in Revendreth." },
  ["avowed cryptkeeper"] = { 2, "', "Avowed Cryptkeepers are venthyr located in Revendreth." },
  ["avowed guarantor"] = { 2, "', "Avowed Guarantors are venthyr located at the Absolution Crypt in Revendreth." },
  ["avowed inquisitor"] = { 2, "', "Avowed Inquisitors are venthyr located at the Absolution Crypt in Revendreth." },
  ["avowed notary"] = { 2, "venthyr located at the Halls of Atonement in Revendreth", "The Avowed Notary is a venthyr located at the Halls of Atonement in Revendreth. she can be found near the Bell of Repentance along with a group of chained soul." },
  ["avowed ritualist"] = { 2, "', "Avowed Ritualists are venthyr located in Revendreth." },
  ["avowed soulbreaker"] = { 2, "', "Avowed Soulbreakers are kyrian located in Helgarde Keep in the Maw." },
  ["avowed stalker"] = { 2, "', "Avowed Stalkers are venthyr located in Revendreth." },
  ["avowed tormentor"] = { 2, "', "Avowed Tormentors are venthyr located at the Absolution Crypt in Revendreth." },
  ["avowed usher"] = { 2, "', "Avowed Ushers are venthyr located in Revendreth." },
  ["avowed witness"] = { 2, "', "Avowed Witnesses are venthyr located in Revendreth." },
  ["avrus illwhisper"] = { 2, "satyr in Ashenvale", "Avrus Illwhisper is a satyr in Ashenvale who has fled his clan to seek out the forgiveness of Elune and, ultimately, his redemption. Aware that his intentions are pure, the goddess herself guides an Alliance adventurer into giving him the opportun..." },
  ["avruu"] = { 2, "arakkoa found in the Den of Haal'esh in Hellfire Peninsula", "Avruu is an arakkoa found in the Den of Haal'esh in Hellfire Peninsula. He has trapped Aeranas inside his orb." },
  ["awakened archivist"] = { 2, "', "Awakened Archivists are earthen Archivists located in the Sacred Hollow and at Ghoststone Diggings on the Siren Isle." },
  ["awakened dead"] = { 2, "', "Awakened Dead are Drust skeletons located in Drustvar." },
  ["awakened magus"] = { 2, "', "Awakened Magi are dracthyr." },
  ["awakened warder"] = { 2, "', "Awakened Warders are arakkoa guards found in Stormshield, Warspear and Tanaan Jungle, guarding the other members of the Order of the Awakened." },
  ["awakening caretaker"] = { 2, "', "Awakening Caretakers are earthen located in the Awakening Machine in the Hall of Awakening." },
  ["awakening technician"] = { 2, "', "Awakening Technicians are earthen located in the Awakening Machine in the Hall of Awakening." },
  ["awarri blazecall"] = { 2, "orc follower located at Frostwall in Frostfire Ridge", "Awarri Blazecall is an orc follower located at Frostwall in Frostfire Ridge. She can only be recruited using the Headhunter's Harvest from Frostwall Tavern." },
  ["awenasa"] = { 2, "tauren stable master located in Freewind Post in Thousand...", "Awenasa is a tauren stable master located in Freewind Post in Thousand Needles. She has been missing since the Cataclysm, presumably having been killed in the Thousand Needles disaster." },
  ["awkward gangly orc"] = { 2, "orc wandering around Desolation Hold in the Southern Barrens", "Awkward Gangly Orc is an orc wandering around Desolation Hold in the Southern Barrens. After interrogating him during  [10-30] Intelligence Warfare he will turn into a Revealed SI:7 Spy — a human wearing an orc mask." },
  ["axebite defender"] = { 2, "', "Axebite Defenders are orcs located in the Twilight Highlands." },
  ["axebite grunt"] = { 2, "', "Axebite Grunts are orcs located in the Twilight Highlands." },
  ["axebite infantry"] = { 2, "', "Axebite Infantries are orcs located in Highbank in the Twilight Highlands." },
  ["axebite marine"] = { 2, "', "Axebite Marines are orcs located in Twilight Shores in the Twilight Highlands." },
  ["axebite soldier"] = { 2, "', "Axebite Soldiers are orcs located on the road to Grim Batol in the Twilight Highlands." },
  ["axebite warrior"] = { 2, "', "Axebite Warriors are orcs found lined up in Bilgewater  Harbor near Warlord Krogg. They will cheer when he gives his speech about going to the Twilight Highlands." },
  ["axefall grunt"] = { 2, "', "Axefall Grunts are orcs located in Axefall in Spires of Arak." },
  ["axle"] = { 2, "goblin innkeeper located in Mudsprocket in Dustwallow Marsh", "Axle is a goblin innkeeper located in Mudsprocket in Dustwallow Marsh." },
  ["axxarien fleshrender"] = { 2, "', "Axxarien Fleshrenders are satyrs located in Axxarien on Bloodmyst Isle before the Tishamaat." },
  ["axxarien hellcaller"] = { 2, "', "Axxarien Hellcallers are satyrs located in Bloodmyst Isle." },
  ["axxarien ragehide"] = { 2, "', "Axxarien Ragehides are satyrs located in Axxarien on Bloodmyst Isle before the Tishamaat." },
  ["axxarien shadowstalker"] = { 2, "', "Axxarien Shadowstalkers are satyrs found on Bloodmyst Isle." },
  ["axxarien trickster"] = { 2, "', "Axxarien Tricksters are satyrs found at Axxarien on Bloodmyst Isle." },
  ["ayala the relentless"] = { 2, "warrior", "Ayala the Relentless is a warrior who cut down foe after foe in the pits of Valhalas on his way to legend. Becoming more lethal as his opponents weakened, he was truly terrifying to spectate." },
  ["ayit"] = { 2, "arakkoa found at Veil Shienor in Terokkar Forest", "Ayit is an arakkoa found at Veil Shienor in Terokkar Forest." },
  ["aylaan"] = { 2, "draenei located in Rangari Refuge", "Aylaan is a draenei located in Rangari Refuge. He is standing with Akoru the Apprentice and Morod." },
  ["aylaan the waterwaker"] = { 2, "Broken quest giver located at the Ruins of Sha'naar in He...", "Aylaan the Waterwaker is a Broken quest giver located at the Ruins of Sha'naar in Hellfire Peninsula." },
  ["aymestrasz"] = { 2, "red drake", "Aymestrasz is a red drake and one of Lailastrasza's companions, whom she considers to be her second-in-command. The duo and their friends fought against the djaradin, and he helped her to lead a devastating assault against Scalecracker Keep." },
  ["azal the fangnifiscent"] = { 2, "nerubian depicted by a statue in the Skeins in the City o...", "Azal the Fangnifiscent is a nerubian depicted by a statue in the Skeins in the City of Threads, on the northwestern side of the Royal Preservatorium. The statue's plaque can only be understood while under the effects of  [Potion of Polymorphic Tra..." },
  ["azarian"] = { 2, "member of the black dragonflight", "Azarian was a member of the black dragonflight who defected to the Primalist cause, an act for which Azarian was brought to the dungeons of the Obsidian Citadel for questioning." },
  ["azereki ashenblade"] = { 2, "Darkfallen death knight located at the Axefall in Spires ...", "Azereki Ashenblade is a Darkfallen death knight located at the Axefall in Spires of Arak. He can be recruited as a follower for Frostwall." },
  ["azerite recovery specialist"] = { 2, "', "Azerite Recovery Specialists are goblins seeking Azerite powder kegs in the waters of Mist's Edge in Darkshore during the War of the Thorns." },
  ["azerite researcher"] = { 2, "', "Azerite Researchers are goblins located in the Underhold during  [60] Stay of Execution." },
  ["azerothian archivist"] = { 2, "', "Azerothian Archivists are archaeologists located in Traitor's Rest in the Azure Span." },
  ["azgoth"] = { 2, "annihilan", "The Doom Lord Azgoth was an annihilan who dwelled in a citadel on a Burning Legion-controlled world, inhabited by felguards and felbats. At some point, Margrave Akarek and Baroness Draka of the House of Eyes traveled to Azgoth's planet and stole a..." },
  ["azik"] = { 2, "arakkoa located at Terokkar Pass in the Spires of Arak", "Azik is an arakkoa located at Terokkar Pass in the Spires of Arak. A trinket vendor, he greats adventurers outside of Skettis and sends them to Reshad." },
  ["azika the frostwitch"] = { 2, "orc frost mage found at the Dreadmaul Post in the Blasted...", "Azika the Frostwitch was an orc frost mage found at the Dreadmaul Post in the Blasted Lands during the World of Warcraft: Warlords of Draenor beta." },
  ["azj'aqir (tol'vir)"] = { 2, "tol'vir sorcerer", "Azj'Aqir was a tol'vir sorcerer. He was said to possess a scepter that would allow him to control a Qiraji battle tank outside of its Silithus home." },
  ["azjol-anak battleguard"] = { 2, "', "Guardians bred for a single purpose: protect Kilix the Unraveler, no matter the cost. The Azjol-Anak Battleguards are still-living nerubians that guard Kilix the Unraveler." },
  ["azjol-anak sorcerer"] = { 2, "', "Azjol-anak Sorcerers are nerubians that spawn in the Fallen Temple of Ahn'kahet in Ahn'kahet: The Old Kingdom after Herald Volazj's defeat. On Seer Ixit's orders, two of them are located in the center of the room, channeling fire spells on the two..." },
  ["azjol-anak warrior"] = { 2, "', "Azjol-anak Warriors are nerubians located in Azjol-Nerub and Ahn'kahet: The Old Kingdom. In Azjol-Nerub, two Warriors—one alive and one dead—are initially located at the entrance to the Gilded Gate alongside Reclaimer A'zak and a Nerubian Flyer." },
  ["azley"] = { 2, "goblin located in Forkriver Crossing in the Ohn'ahran Plains", "Azley is a goblin located in Forkriver Crossing in the Ohn'ahran Plains and at the Artisan's Market in Valdrakken." },
  ["azmerloth bubblemancer"] = { 2, "', "Azmerloth Bubblemancers are murlocs located in Tyrhold Reservoir in Thaldraszus during Time Rifts." },
  ["azmerloth stinktender"] = { 2, "', "Azmerloth Stinktenders are murlocs located in Tyrhold Reservoir in Thaldraszus during Time Rifts." },
  ["azora"] = { 2, "unknown entity", "Azora is an unknown entity. Evidence of Azora is uncommon." },
  ["azore aldamort"] = { 2, "human quest giver located at Ethel Rethor in Desolace", "Azore Aldamort is a human quest giver located at Ethel Rethor in Desolace. Azore was an agent of the Argent Dawn, and had come into possession of the Sceptre of Light after engaging the services of adventurers." },
  ["azra ironstrike"] = { 2, "Arathi located in Hallowfall", "Azra Ironstrike is an Arathi located in Hallowfall." },
  ["azsh'ari channeler"] = { 2, "', "Azsh'ari Channelers are naga located in the Eternal Palace." },
  ["azsh'ari deepstalker"] = { 2, "', "Azsh'ari Deepstalkers are naga located in Nazjatar." },
  ["azsh'ari elementalist"] = { 2, "', "Azsh'ari Elementalists are naga located in Nazjatar." },
  ["azsh'ari frostbinder"] = { 2, "', "Azsh'ari Frostbinders are naga located in the Eternal Palace." },
  ["azsh'ari galeblade"] = { 2, "', "Azsh'ari Galeblades are naga located in the Eternal Palace." },
  ["azsh'ari invoker"] = { 2, "', "Azsh'ari Invokers are naga located in Nazjatar." },
  ["azsh'ari neophyte"] = { 2, "', "Azsh'ari Neophytes are naga located in Nazjatar." },
  ["azsh'ari oracle"] = { 2, "', "Azsh'ari Oracles are naga located in Nazjatar." },
  ["azsh'ari oracle (eternal palace)"] = { 2, "', "Azsh'ari Oracles are naga located in the Eternal Palace." },
  ["azsh'ari siegemistress"] = { 2, "', "Azsh'ari Siegemistresses are naga located in Nazjatar." },
  ["azsh'ari stormbinder"] = { 2, "', "Azsh'ari Stormbinders are naga located in the Eternal Palace." },
  ["azsh'ari stormcaller"] = { 2, "', "Azsh'ari Stormcallers are naga located in the Eternal Palace." },
  ["azsh'ari stormsurger"] = { 2, "', "Azsh'ari Stormsurgers are naga located in Nazjatar." },
  ["azsh'ari stormwitch"] = { 2, "', "Azsh'ari Stormwitches are naga located in Nazjatar." },
  ["azsh'ari summoner"] = { 2, "', "Azsh'ari Summoners are naga located in Nazjatar." },
  ["azsh'ari tempest"] = { 2, "', "Azsh'ari Tempests are naga located in Nazjatar." },
  ["azsh'ari venomwatcher"] = { 2, "', "Azsh'ari Venomwatchers are naga located in the Eternal Palace." },
  ["azsh'ari wavebreaker"] = { 2, "', "Azsh'ari Wavebreakers are naga located in Nazjatar." },
  ["azsh'ari witch"] = { 2, "', "Azsh'ari Witches are naga located in the Eternal Palace as part of the Orgozoa encounter." },
  ["azsh'ir abductor"] = { 2, "naga appearing during  [30-35] Defending the Rift in Abys...", "Azsh'ir Abductor is a naga appearing during  [30-35] Defending the Rift in Abyssal Depths. He knocks the adventurers out if they are away from the main group and swim towards the group only to be killed by Erunak Stonespeaker." },
  ["azsh'ir abyss priestess"] = { 2, "', "Azsh'ir Abyss Priestesses are naga priests located at the Ruins of Vashj'ir in the Shimmering Expanse. They are fighting invaders such as the Alliance Lookouts." },
  ["azsh'ir assailant"] = { 2, "', "Azsh'ir Assailants are naga located in Abyssal Depths." },
  ["azsh'ir depthseeker"] = { 2, "', "Azsh'ir Depthseekers are naga located in Abyssal Depths." },
  ["azsh'ir infantry"] = { 2, "', "Azsh'ir Infantries are naga located at the Ruins of Vashj'ir in the Shimmering Expanse. They are guarding the ruins and trying to fight off the Alliance, killing Alliance Lookouts on sight." },
  ["azsh'ir manhunter"] = { 2, "', "Azsh'ir Manhunters are deceased naga located in Shimmering Expanse." },
  ["azsh'ir patroller"] = { 2, "', "Azsh'ir Patrollers are naga found in a phased part of the southwestern Shimmering Expanse. They are required to be slained for  [30-35] Caught Off-Guard to lower the risk of the refugees' cave to be found out." },
  ["azsh'ir raider"] = { 2, "', "Azsh'ir Raiders are visions of naga seen in the Ruins of Vashj'ir in Shimmering Expanse during  [Visions of Vashj'ir Past], killing the kvaldir raiders off." },
  ["azsh'ir scout"] = { 2, "', "Azsh'ir Scouts are naga located in Shimmering Expanse." },
  ["azsh'ir sentry"] = { 2, "', "Azsh'ir Sentries are naga located at the Ruins of Vashj'ir in Shimmering Expanse. They appear during  [30-35] Swift Approach." },
  ["azsh'ir soldier"] = { 2, "', "Azsh'ir Soldiers are naga located at the Nar'shola Terrace in the Shimmering Expanse during the visions of the Battlemaiden. They are commanded by the Naz'jar Serpent Guards." },
  ["azsh'ir warrior"] = { 2, "', "Azsh'ir Warriors are naga located in Abyssal Depths." },
  ["azsh'ir wave screamer"] = { 2, "', "Azsh'ir Wave Screamers are naga located in Shimmering Expanse. They also appear during  [30-35] Gauging Success." },
  ["azsh'ir wavebreaker"] = { 2, "', "Azsh'ir Wavebreakers are naga located in Shimmering Expanse." },
  ["azshara bombardier"] = { 2, "', "Azshara Bombardiers are found circling an elven tower at Talrendis Point in Azshara. They are riding a Warsong Assault Wind Rider and being shot at by Talrendis Marksman." },
  ["azshara watcher"] = { 2, "', "Azshara Watchers are ethereals located in the Eternal Palace." },
  ["azshara's devoted"] = { 2, "', "Azshara's Devoted are naga located in the Eternal Palace." },
  ["azuka bladefury"] = { 2, "daughter of Dharl of the Thrice-Bloodied Blade", "Azuka Bladefury is the daughter of Dharl of the Thrice-Bloodied Blade and becomes the Warlord of the Burning Blade clan after Dharl's death." },
  ["azuku"] = { 2, "ankoan flight master located at the Ashen Strand in Nazjatar", "Azuku is an ankoan flight master located at the Ashen Strand in Nazjatar." },
  ["azunla"] = { 2, "draenei portal trainer located in the Training Hall in St...", "Azunla is a draenei portal trainer located in the Training Hall in Stormwind City." },
  ["azure gob collective"] = { 2, "', "The Azure Gob Collective are goblins located at the Blackwater Marina in the Undermine." },
  ["azuremyst anchorite"] = { 2, "draenei tending to an Injured Traveler with  Healing Ligh...", "Azuremyst Anchorite is a draenei tending to an Injured Traveler with  Healing Light in the Trader's Tier in the Exodar during the draenei heritage questline." },
  ["azuremyst peacekeeper"] = { 2, "', "Azuremyst Peacekeepers are draenei guards located in Azure Watch, and patrolling the road south to Odesyus' Landing, north to Stillpine Hold, and west to the Exodar in Azuremyst Isle. They give directions to various locales within Azuremyst as wel..." },
  ["azuremyst vindicator"] = { 2, "', "Azuremyst Vindicators were draenei paladins of the Argent Dawn participating in the attack on the Dark Portal. They accompanied Justinius the Harbinger." },
  ["azzinoth"] = { 2, "powerful doomguard commander of the Burning Legion slain ...", "Azzinoth was a powerful doomguard commander of the Burning Legion slain by Illidan Stormrage during the War of the Ancients, 10,000 years ago. He was the original wielder of Illidan's warglaives, which the demon hunter claimed after slaying his foe." },
  ["azzix k'tai"] = { 2, "mantid located in the Amber Vault in the Dread Wastes", "Azzix K'tai is a mantid located in the Amber Vault in the Dread Wastes." },
  ["azzleby"] = { 2, "goblin stable master located by the gates of Everlook in ...", "Azzleby is a goblin stable master located by the gates of Everlook in Winterspring." },
  ["b.e barechus"] = { 2, "gnome", "B.E Barechus is a gnome and member of the G-Team, a small group within S.A.F.E.. He is found in Gnomeregan." },
  ["ba'choso"] = { 2, "broker located in Shadow Point in northwestern K'aresh", "Ba'choso is an broker located in Shadow Point in northwestern K'aresh. He trades  [Loombeast Silk] for cosmetic ensembles." },
  ["ba'dibla"] = { 2, "broker located in Astral Getaways in Tazavesh", "Ba'dibla is a broker located in Astral Getaways in Tazavesh, the Veiled Market. Behind her is Ba'key's Aromatic Broker Cookies Recipes." },
  ["ba'eth"] = { 2, "broker located in Tazavesh", "Ba'eth is a broker located in Tazavesh, the Veiled Market in K'aresh." },
  ["ba'jatem"] = { 2, "broker located in Tazavesh", "Ba'jatem is a broker located in Tazavesh, the Veiled Market in K'aresh." },
  ["ba'kajanai"] = { 2, "broker located in Tazavesh", "Ba'kajanai is a broker located in Tazavesh, the Veiled Market in K'aresh." },
  ["ba'kel"] = { 2, "broker located in Astral Getaways in Tazavesh", "Ba'kel is a broker located in Astral Getaways in Tazavesh, the Veiled Market." },
  ["ba'kerei"] = { 2, "broker located in Tazavesh", "Ba'kerei is a broker located in Tazavesh, the Veiled Market in K'aresh." },
  ["ba'key"] = { 2, "broker located in Tazavesh", "Ba'key is a broker located in Tazavesh, the Veiled Market in K'aresh." },
  ["ba'mua"] = { 2, "broker located in Tazavesh", "Ba'mua is a broker located in Tazavesh, the Veiled Market in K'aresh." },
  ["ba'orr"] = { 2, "broker innkeeper located in Tazarest of Tazavesh in K'aresh", "Ba'orr is a broker innkeeper located in Tazarest of Tazavesh in K'aresh." },
  ["ba'rak"] = { 2, "', "Ba'rak was one of the few orcs that survived the Alliance assault on Hellfire Citadel. He followed Kargath Bladefist to Nagrand to gather some warriors for the Horde." },
  ["ba'reesta"] = { 2, "broker located in Tazavesh", "Ba'reesta is a broker located in Tazavesh, the Veiled Market in K'aresh." },
  ["ba'sim"] = { 2, "broker belonging to Cartel Ba", "Ba'sim is a broker belonging to Cartel Ba. He works at the P.O.S.T. in Tazavesh and is a friend of Al'dalil." },
  ["ba'simtal"] = { 2, "broker located in Astral Getaways in Tazavesh", "Ba'simtal is a broker located in Astral Getaways in Tazavesh, the Veiled Market." },
  ["ba'ver"] = { 2, "broker located in Tazavesh", "Ba'ver is a broker located in Tazavesh, the Veiled Market." },
  ["ba'vol"] = { 2, "broker located by the Guild Vault in the Hall of Holding ...", "Ba'vol is a broker located by the Guild Vault in the Hall of Holding in Oribos." },
  ["baaros"] = { 2, "draenei located at Auchindoun in Talador", "Baaros is a draenei located at Auchindoun in Talador." },
  ["baatun"] = { 2, "draenei paladin trainer located in the Vindicators' Sanct...", "Baatun is a draenei paladin trainer located in the Vindicators' Sanctum in the Vault of Lights in the Exodar." },
  ["baba bogbrew"] = { 2, "elderly goblin alchemist in Stagalbog in Swamp of Sorrows", "Baba Bogbrew is an elderly goblin alchemist in Stagalbog in Swamp of Sorrows. She has been settled in Swamp of Sorrows since before Bogpaddle was founded, enjoying the peace and quiet." },
  ["babagahnoosh the grumpy"] = { 2, "gnome located near the Violet Hold in Dalaran", "\"Out of my way — I have important matters to attend to!\" Babagahnoosh the Grumpy is a gnome located near the Violet Hold in Dalaran. Unlike other mages positioned around Dalaran while in Northrend, he would not provide directions to various locati..." },
  ["babbling brawler"] = { 2, "', "Babbling Brawlers are dwarves and gnomes located in Dornogal and Stormwind City." },
  ["babs fizzletorque"] = { 2, "gnome quest giver located on the lighthouse island just e...", "Babs Fizzletorque is a gnome quest giver located on the lighthouse island just east of Theramore Isle in Dustwallow Marsh. She also appears during the Fall of Theramore cowering at the lighthouse." },
  ["babunituk"] = { 2, "tuskarr located in Camp Antonidas in the Azure Span", "Babunituk is a tuskarr located in Camp Antonidas in the Azure Span." },
  ["baby bluegill murloc"] = { 2, "', "Baby Bluegill Murlocs are murlocs found at the Loch in Loch Modan and the Bluegill Marsh in the Wetlands. They can also appear when opening Monstrous Clams in northeastern Durotar or Jagged Abalones near the Angler's Wharf in the Krasarang Wilds." },
  ["baby murloc"] = { 2, "murloc", "For general information on baby murlocs, see Murloc#Young Baby Murloc is a murloc that was brought to Zangarmarsh by Witch Doctor Tor'gash, since the murlocs don't exist in Outland. Tor'gash wants to give the Lost Ones a gift by sending these bab..." },
  ["baby murloc (deadmines)"] = { 2, "murloc located in the Deadmines", "Baby Murloc is a murloc located in the Deadmines." },
  ["baby murloc (thousand needles)"] = { 2, "murloc", "Baby Murloc is a murloc that is in a chest when engaging Tony Two-Tusk in the Admiral's Den in Thousand Needles. It and its brethren are released by a Confused Murloc who then all swim into the cave's lake, disappearing into a small cavern." },
  ["back-alley mugger"] = { 2, "', "Back-alley Muggers are orcs who appear when opening a Dusty Chest in Orgrimmar." },
  ["backalley schemer"] = { 2, "Veiled Market", "Backalley Schemers are brokers located at the Bazaar of Tangible Delights in Tazavesh, the Veiled Market." },
  ["backbreaker bahaha"] = { 2, "ogre", "Backbreaker Bahaha is an ogre who can be encountered during Island Expeditions." },
  ["backbreaker uru"] = { 2, "mogu located in the Lightning Vein Mine on the Isle of Th...", "Backbreaker Uru is a mogu located in the Lightning Vein Mine on the Isle of Thunder." },
  ["backbreaker zukan"] = { 2, "mogu located on the expedition isles", "Backbreaker Zukan is a mogu located on the expedition isles." },
  ["backup assassin"] = { 2, "', "Backup Assassins are goblins located at the Bilgewater Flats in the Undermine who attempt to kill Monte Gazlowe." },
  ["bad zed"] = { 2, "undead located in Thalassian Pass in Eversong Woods", "Bad Zed is an undead located in Thalassian Pass in Eversong Woods. Behind him is a Demonic Gateway." },
  ["badly wounded mystic"] = { 2, "', "The Badly Wounded Mystics are two centaur of Clan Ohn'ir located with Tigari Khan and the Wounded Initiate on the road north of Ridgewater Retreat in the Ohn'ahran Plains during  [20-70] Mystic Mystery,  [20-70] Toting Totems, and  [20-70] Taken B..." },
  ["badur"] = { 2, "earthen located in the Forgegrounds in Dornogal", "Badur is an earthen located in the Forgegrounds in Dornogal." },
  ["bael'dun appraiser"] = { 2, "', "Bael'dun Appraisers are dwarves found in Mulgore at the Bael'dun Digsite. They were once alive but as of Cataclysm, they are now corpses killed by the land in revenge." },
  ["bael'dun digger"] = { 2, "', "Bael'dun Diggers are dwarves found in Mulgore at the Bael'dun Digsite. They were once alive but as of Cataclysm, they are now corpses killed by the land in revenge." },
  ["bael'dun excavator"] = { 2, "', "Bael'dun Excavators are dwarves located in Bael Modan Excavation in Bael Modan in the Southern Barrens." },
  ["bael'dun foreman"] = { 2, "', "Bael'dun Foremen are dwarves located in Bael Modan in the Southern Barrens. One aids in the attack on Feegly the Exiled, but is transformed into a trogg." },
  ["bael'dun officer"] = { 2, "', "Bael'dun Officers are dwarves located in Bael Modan in the Southern Barrens." },
  ["bael'dun rifleman"] = { 2, "', "Bael'dun Riflemen are dwarves found at Bael Modan in the Southern Barrens. Many of them perished in the explosion of Bael Modan Keep." },
  ["bael'dun soldier"] = { 2, "', "Bael'dun Soldiers are dwarves found at Bael Modan in the Southern Barrens. Many of them perished in the explosion of Bael Modan Keep." },
  ["bael'dun survivor"] = { 2, "', "Bael'dun Survivors are dwarves in Bael'dun Keep in the Southern Barrens. Some are found under Burning Debris." },
  ["baelgi 'one-shot' flintbeard"] = { 2, "dwarf", "Baelgi 'One-Shot' Flintbeard is a dwarf." },
  ["baelgrim"] = { 2, "former Stormward of Khaz Algar", "Baelgrim was the former Stormward of Khaz Algar, the leader of the Stormriders in charge of defending the earthen on the Isle of Dorn. He was the very embodiment of the Stormriders and the foremost expert on stormrooks." },
  ["baelgun (warcraft iii)"] = { 2, "mountain king", "Baelgun was a mountain king who led the remnants of the Dwarven Expedition into Northrend after the disappearance of Muradin Bronzebeard settling in the Shadow Web Caverns of Azjol-Nerub." },
  ["baelgun (orc)"] = { 2, "historian of the Frostwolf clan in the canceled Warcraft ...", "Baelgun, Tribal Elder, was the historian of the Frostwolf clan in the canceled Warcraft Adventures: Lord of the Clans." },
  ["baelog"] = { 2, "muscle of the trio", "Baelog is one of the Lost Dwarves. He is the muscle of the trio, favoring combat with his sword and bow, and can send his brothers into a frenzy with his battlecries, but wears down quickly and can't take as much punishment as Eric and Olaf." },
  ["baelok"] = { 2, "vrykul death knight found in Malykriss: The Vile Hold in ...", "Baelok is a vrykul death knight found in Malykriss: The Vile Hold in Icecrown. He reached his rank only through sheer brutality." },
  ["baenan"] = { 2, "dwarf paladin", "Baenan is a dwarf paladin who was stationed aboard the Elwynn which was stationed off of the coast Tanaris due to the Horde presence in the area." },
  ["baergar blackpaw"] = { 2, "leader of the furbolgs in Grizzlemaw", "Baergar Blackpaw is the leader of the furbolgs in Grizzlemaw. It is unknown if Blackpaw was leader of all the tribes/clans located in Grizzlemaw, or the leader of the Frost Paw tribe which was first to live in Grizzlemaw." },
  ["bahat"] = { 2, "arakkoa located in Shadowmoon Village in Shadowmoon Valley", "Bahat was an arakkoa located in Shadowmoon Village in Shadowmoon Valley." },
  ["bai-jin the butcher"] = { 2, "rare mogu in Vale of Eternal Blossoms", "Bai-Jin the Butcher is a rare mogu in Vale of Eternal Blossoms." },
  ["bailey"] = { 2, "dwarf located near Bellinger at the Snowblind Hills in th...", "Bailey is a dwarf located near Bellinger at the Snowblind Hills in the Storm Peaks." },
  ["baine bloodhoof (warcraft iii)"] = { 2, "', "Baine Bloodhoof first appears when Rexxar travels to Mulgore to enlist the help of Cairne Bloodhoof, Rexxar soon found out that the chieftain was unwilling to honor his alliance with Thrall due to grief over the loss of his son. In order to secure..." },
  ["baker"] = { 2, "goblin located at Hovel Hill in the Undermine", "Baker is a goblin located at Hovel Hill in the Undermine." },
  ["bakhushek"] = { 2, "centaur located in Maruukai in the Ohn'ahran Plains", "Bakhushek is a centaur located in Maruukai in the Ohn'ahran Plains. This section concerns content related to The War Within." },
  ["bakor the gangly"] = { 2, "gnome located at the Circle of Wills in Underbelly", "Bakor the Gangly is a gnome located at the Circle of Wills in Underbelly." },
  ["bakra the bully"] = { 2, "gnoll located in Big Tree Hills in the Azure Span", "Bakra the Bully is a gnoll located in Big Tree Hills in the Azure Span." },
  ["baku"] = { 2, "tortollan located at Scaletrader Post in Zuldazar", "Baku is a tortollan located at Scaletrader Post in Zuldazar." },
  ["bakuta hardshell"] = { 2, "tortollan located at the Seekers' Vista in Stormsong Valley", "Bakuta Hardshell is a tortollan located at the Seekers' Vista in Stormsong Valley." },
  ["balaak the twice-exiled"] = { 2, "ethereal vendor located in a building in Shenzar Refinery...", "Balaak the Twice-Exiled is an ethereal vendor located in a building in Shenzar Refinery in the very center of Slayer's Rise." },
  ["balacgos"] = { 2, "elder offspring of the great Aspect Malygos", "Balacgos was an elder offspring of the great Aspect Malygos. He was especially gifted even among dragons who wielded the powers of the arcane with natural ease." },
  ["balakar khan"] = { 2, "khan of the Nokhud centaur", "Balakar Khan is the khan of the Nokhud centaur and one of the two main antagonists in the Ohn'ahran Plains storyline (the other being Koroleth). After allying with the Primalists, he declared war on the other Maruuk clans and tried to claim Ohn'ah..." },
  ["balakar khan (tactics)"] = { 2, "final boss of the Nokhud Offensive", "Balakar Khan is the final boss of the Nokhud Offensive, accessible after all other bosses have been defeated." },
  ["balambor"] = { 2, "elf", "Balambor was an elf that was training to become a demon hunter. While he survived the first part of the ritual, he was driven mad, attacked his fellow trainees and died while fighting them." },
  ["balara"] = { 2, "centaur mini-boss guarding the way to Balakar Khan in Nok...", "Balara is a centaur mini-boss guarding the way to Balakar Khan in Nokhudon Hold in the Nokhud Offensive. She is accompanied by her brother Batak." },
  ["balcephoth"] = { 2, "unknown being", "Balcephoth of the felshadows is an unknown being who telepathically communicated with Vitus Darkwalker, a Gilnean warlock, and taught him the forbidden secrets of corruption. He is presumably a demon." },
  ["baldruc"] = { 2, "dwarf gryphon flight master located on Theramore Isle in ...", "Baldruc is a dwarf gryphon flight master located on Theramore Isle in Dustwallow Marsh. Cassa Crimsonwing is his apprentice." },
  ["bale"] = { 2, "tauren general goods vendor located at Bloodvenom Post in...", "Bale is a tauren general goods vendor located at Bloodvenom Post in Felwood. After the Cataclysm, Winna Hazzard transformed all the inhabitants of Bloodvenom Post into Bloodvenom Slimeslaves." },
  ["bale bleakstare"] = { 2, "farseer in service of the Horde", "Bale Bleakstare is a farseer in service of the Horde. He is one individual who stands out among his forces: an old orc with white hair that frames his wizened face and keen eyes, and that flows in the wind." },
  ["baleful anchorite"] = { 2, "draenei", "Baleful Anchorite is a draenei." },
  ["baleful soulpriest"] = { 2, "draenei", "Baleful Soulpriest is a draenei." },
  ["balfour blackblade"] = { 2, "dwarf reagents", "Balfour Blackblade is a dwarf reagents and poisons vendor located in the Grizzly Hills." },
  ["balinda darkstone"] = { 2, "dwarf located in Stromgarde Keep in the Arathi Highlands", "Balinda Darkstone is a dwarf located in Stromgarde Keep in the Arathi Highlands. She is working on an anvil and forge." },
  ["balizar the umbrage"] = { 2, "', "Balizar the Umbrage is satyr found in Darkshore. He used to spawn at the end of the escort quest  [24] Supplies to Auberdine received from Feero Ironhand at Maestra's Post in Ashenvale." },
  ["banagos"] = { 2, "blue dragon using human visage", "Banagos is a blue dragon using human visage. He was sent with Kirygosa to discover what had happened to the blue dragons sent to move the Focusing Iris to a secure location." },
  ["banalash"] = { 2, "orc trade goods vendor located in Stonard in the Swamp of...", "Banalash is an orc trade goods vendor located in Stonard in the Swamp of Sorrows." },
  ["band groupie"] = { 2, "', "Band Groupies are venthyr located in the Ember Court." },
  ["band member"] = { 2, "', "Band Members are goblins located at the Plunder Party in the Undermine." },
  ["bandit (hall of shadows)"] = { 2, "', "Bandits are humans and orcs located in the Hall of Shadows." },
  ["banehoof"] = { 2, "satyr leader", "Banehoof was the satyr leader who drove off the druids of Shala'nir. He was killed by the druids of Val'sharah." },
  ["banewood harvester"] = { 2, "venthyr", "Banewood Harvester is a venthyr." },
  ["bang"] = { 2, "personal bruiser of Klaxz Boompowder", "Bang was the personal bruiser of Klaxz Boompowder, a trade prince of the Steamwheedle Cartel. Like Klaxz's wife Slixi, Bang noticed and was unsettled by the strange behavior his boss displayed after he fell victim to the Uninvited Guest, which cau..." },
  ["banit"] = { 2, "broker located in Haven in Zereth Mortis", "Banit is a broker located in Haven in Zereth Mortis. Assorted Scrolls are on his counter." },
  ["bank attendant"] = { 2, "', "Bank Attendants are goblins located in Last Choice Bank in the Undermine." },
  ["banner-bearer koral"] = { 2, "quilboar", "Banner-Bearer Koral is a quilboar who can be encountered on Island Expeditions." },
  ["banro"] = { 2, "draenei located at Halaa in Nagrand", "Banro is a draenei located at Halaa in Nagrand. He is only available when the Alliance controls Halaa." },
  ["banshee loyalist"] = { 2, "', "Banshee Loyalists are Horde prisoners located in Orgrimmar after the War Campaign. They are in chains, being pulled by Orgrimmar Grunts." },
  ["baoka"] = { 2, "tortollan located in the Drunk Tank in Drustvar", "Baoka is a tortollan located in the Drunk Tank in Drustvar." },
  ["baolai the immolator"] = { 2, "mogu located in the Ruins of Guo-Lai in the Vale of Etern...", "Baolai the Immolator is a mogu located in the Ruins of Guo-Lai in the Vale of Eternal Blossoms." },
  ["baqir"] = { 2, "centaur flight master located at Timberstep Outpost in th...", "Baqir is a centaur flight master located at Timberstep Outpost in the Ohn'ahran Plains, as well as on the north side of the Battle of Spears in the Nokhud Offensive." },
  ["baradin grunt"] = { 2, "', "Two Baradin Grunts are accompanying Zugra Flamefist in the Western Earthshrine in Orgrimmar. Several can also be found near Baradin Hold when the island is controlled by the Horde." },
  ["barahl lynflayme"] = { 2, "Arathi stable worker found at Dunelle's Kindness stables ...", "Barahl Lynflayme is an Arathi stable worker found at Dunelle's Kindness stables in Hallowfall. He sends adventurers to check on his cousin Sophietta Lynflayme in Lightspark." },
  ["barak kodobane"] = { 2, "Kolkar centaur found in the Northern Barrens", "Barak Kodobane is a Kolkar centaur found in the Northern Barrens. Telar Highstrider wants his head." },
  ["barblefink"] = { 2, "gnome quest giver found at Venture Bay in the Grizzly Hills", "Barblefink is a gnome quest giver found at Venture Bay in the Grizzly Hills. He desires  [Element 115], so he may use it as a solvent." },
  ["barbrul the brewbrul"] = { 2, "drogbar located in Highmountain", "Barbrul the Brewbrul  is a drogbar located in Highmountain." },
  ["barda"] = { 2, "draenei innkeeper located in Talador", "Barda is a draenei innkeeper located in Talador." },
  ["barduun"] = { 2, "draenei food", "Barduun is a draenei food and drink vendor located outside the Bloodmaul Slag Mines in Frostfire Ridge." },
  ["barg"] = { 2, "general goods vendor located at the Crossroads in the Nor...", "Barg is a general goods vendor located at the Crossroads in the Northern Barrens. This section concerns content related to Legion." },
  ["barg-gol"] = { 2, "', "Barg-gol the orcish warrior and felsworn was once a good orc, although chaotic. However, as he embraced his servitude of demons, his alignment shifted to neutral and finally he became evil and twisted as his chaotic soul became corrupted." },
  ["bargrogg"] = { 2, "drogbar general goods vendor located in the Stonedark Gro...", "Bargrogg is a drogbar general goods vendor located in the Stonedark Grotto in Highmountain." },
  ["bargus"] = { 2, "earthen Ordinant", "Bargus is an earthen Ordinant." },
  ["barkpaw"] = { 2, "gnoll located in Westfall", "Barkpaw is a gnoll located in Westfall." },
  ["barley (tauren)"] = { 2, "tauren flight master located at Thrallmar in Hellfire Pen...", "Barley is a tauren flight master located at Thrallmar in Hellfire Peninsula." },
  ["barleybrew apprentice"] = { 2, "', "Barleybrew Apprentices are dwarves found during Brewfest, wherever Alliance brew kegs are located." },
  ["barnabas"] = { 2, "brother of Burrian Coalpart", "Barnabas was the brother of Burrian Coalpart. Legend has it that he was eaten by Margol the Rager." },
  ["barnak of the reeds"] = { 2, "centaur located at the Aylaag Camp stops in the Ohn'ahran...", "Barnak of the Reeds is a centaur located at the Aylaag Camp stops in the Ohn'ahran Plains." },
  ["barnes (cycle of hatred)"] = { 2, "human killed by an orc", "Corporal Barnes was a human killed by an orc. Davin saw his body falling to water." },
  ["barrens guard"] = { 2, "', "Barrens Guards are tauren and orcs found in the Mor'shan Rampart and Camp Taurajo in the Barrens. As of the Cataclysm and the destruction of Taurajo, their bodies can be seen on the ground in the Ruins of Taurajo in the Southern Barrens." },
  ["barrus"] = { 2, "dwarf quest giver located in the Commons in Ironforge", "Barrus is a dwarf quest giver located in the Commons in Ironforge. He is only available before and during the Stranglethorn Fishing Extravaganza." },
  ["barst"] = { 2, "furbolg located on Longclaw Island in the Azure Span", "Barst is a furbolg located on Longclaw Island in the Azure Span." },
  ["bartholemew"] = { 2, "human of the Stromgarde Militia", "Bartholemew was a human of the Stromgarde Militia who fought against the Syndicate in Arathi Highlands. He fell and his badge was taken by his killer, kept as a trophy until its retrieval by hired adventurers." },
  ["bartleby armorfist"] = { 2, "dwarf located in Valgarde in Howling Fjord", "Bartleby Armorfist is a dwarf located in Valgarde in Howling Fjord." },
  ["bartolo ginsetti"] = { 2, "worgen", "Bartolo Ginsetti was a worgen and world-class cloak maker located in Fenris Keep in Silverpine Forest." },
  ["baruk stone defender"] = { 2, "mogu located in the Vale of Eternal Blossoms", "Baruk Stone Defender is a mogu located in the Vale of Eternal Blossoms." },
  ["baruk stoneshaper"] = { 2, "', "Baruk Stoneshapers are mogu located in the Yaungol Advance and Mogujia in Kun-Lai Summit and the Vale of Eternal Blossoms during Assaults." },
  ["barzelin"] = { 2, "earthen located at the Forgegrounds in Dornogal", "Barzelin is an earthen located at the Forgegrounds in Dornogal." },
  ["barzvitz"] = { 2, "earthen located at the Forgegrounds in Dornogal", "Barzvitz is an earthen located at the Forgegrounds in Dornogal." },
  ["basaan"] = { 2, "centaur skinning trainer located at Pinewood Post in the ...", "Basaan is a centaur skinning trainer located at Pinewood Post in the Ohn'ahran Plains." },
  ["base cap'n crankshot"] = { 2, "goblin in a mini-gunship located in Ashwood Depot in Dark...", "Base Cap'n Crankshot is a goblin in a mini-gunship located in Ashwood Depot in Darkshore during the Battle for Darkshore." },
  ["bash'ir (mob)"] = { 2, "ethereal", "Bash'ir is an ethereal that can be summoned at Bash'ir Landing in the Blade's Edge Mountains. He is most likely the namesake for the area and the leader of the subgroup of the Ethereum that shares his name." },
  ["bash'ir arcanist"] = { 2, "', "Bash'ir Arcanists are located at Bash'ir Landing in the Blade's Edge Mountains." },
  ["bash'ir controller"] = { 2, "', "Bash'ir Controllers are ethereals located in Blade's Edge Mountains." },
  ["bash'ir inquisitor"] = { 2, "', "Bash'ir Inquisitors are ethereals located in Bash'ir Landing in Blade's Edge Mountains." },
  ["bash'ir raider"] = { 2, "', "Bash'ir Raiders are ethereals located in Bash'ir Landing in the Blade's Edge Mountains." },
  ["bash'ir reckoner"] = { 2, "', "Bash'ir Reckoners are ethereals located at Bash'ir Landing in Blade's Edge Mountains." },
  ["bash'ir spell-thief"] = { 2, "', "Bash'ir Spell-Thief can be found in Blade's Edge Mountains." },
  ["bash'ir subprimal"] = { 2, "', "Bash'ir Subprimals are ethereals located in Blade's Edge Mountains." },
  ["bash'ir surveyor"] = { 2, "ethereal", "The Bash'ir Surveyor is an ethereal who wanders around the Crystal Spine in the Blade's Edge Mountains, along with 2 Mana-Debt Slaves. Upon getting close to the various creatures that live there, he will put them into a stasis field for a short time." },
  ["bash'ir's harbinger"] = { 2, "ethereal", "Bash'ir's Harbinger is an ethereal that can be summoned at Bash'ir Landing in the Blade's Edge Mountains.  The Harbinger appears to be a high-level lieutenant in Bash'ir's organization, and is sent in place of his master to spoil players' attempts..." },
  ["basir the hammer"] = { 2, "Arathi found reparing a Broken Harvestbot in the Whirring...", "Basir the Hammer is an Arathi found reparing a Broken Harvestbot in the Whirring Field in Hallowfall. He later joined the Flame's Radiance and is seen outside Mereldar working on a barricade." },
  ["bastian wynfall"] = { 2, "Arathi flight master located at Lorel's Crossing in Hallo...", "Bastian Wynfall is an Arathi flight master located at Lorel's Crossing in Hallowfall." },
  ["bastiana moran"] = { 2, "worgen located at the Lunarfall in Shadowmoon Valley", "Bastiana Moran is a worgen located at the Lunarfall in Shadowmoon Valley. She can only be recruited using the Headhunter's Harvest from Lunarfall Inn." },
  ["bastion ambassador"] = { 2, "', "Bastion Ambassadors are venthyr located in the Ember Court." },
  ["bastion defender"] = { 2, "', "Bastion Defenders are draenei." },
  ["batak"] = { 2, "centaur mini-boss guarding the way to Balakar Khan in Nok...", "Batak is a centaur mini-boss guarding the way to Balakar Khan in Nokhudon Hold in the Nokhud Offensive. He is accompanied by his sister Balara." },
  ["batgob"] = { 2, "goblin located in the Undermine", "Batgob is a goblin located in the Undermine." },
  ["bathet"] = { 2, "', "Bathet was among a number of the Neferset who joined the vast majority of his people in siding with Deathwing in order to reverse the curse of flesh. Though after learning about Bathet from Menrim, Li Li Stormstout theorizes that Bathet was less f..." },
  ["bati"] = { 2, "draenei mage trainer located at the Hall of the Mystics i...", "Bati is a draenei mage trainer located at the Hall of the Mystics in the Vault of Lights in the Exodar." },
  ["battered brewer"] = { 2, "', "Battered Brewers are goblins found in all four Horde cities as well as Shattrath City and Dalaran. Talking to them allows you to queue up to fight Coren Direbrew." },
  ["battered brewmaster"] = { 2, "dwarf found in all four Alliance cities as well as Shattr...", "The Battered Brewmaster is a dwarf found in all four Alliance cities as well as Shattrath City, Dalaran, and Boralus. Talking to him allows you to queue up to fight Coren Direbrew." },
  ["battered draenei prisoner"] = { 2, "', "Battered Draenei Prisoners are draenei located in Tanaan Jungle during the Assault on the Dark Portal." },
  ["battered frostwolf prisoner"] = { 2, "', "Battered Frostwolf Prisoners are orcs located in Tanaan Jungle during the Assault on the Dark Portal. The living ones are tortured in the Kargathar Proving Grounds." },
  ["battered karabor prisoner"] = { 2, "', "Battered Karabor Prisoners are draenei prisoners located in Tanaan Jungle during the Assault on the Dark Portal. The living ones are tortured in the Kargathar Proving Grounds." },
  ["battle pilot"] = { 2, "', "Battle Pilots are gnomes located at Kharanos during the Legion Invasions. They are ordered by Briz Blastbolt to use their flying machines to go support the Ironforge Airfield." },
  ["battle-maiden salaria"] = { 2, "naga located in Island Expeditions", "Battle-Maiden Salaria is a naga located in Island Expeditions." },
  ["battle-mender ka'vaz"] = { 2, "mantid", "Battle-Mender Ka'vaz is a mantid that can be encountered during Island Expeditions." },
  ["battle-priest arynthia"] = { 2, "draenei located at Karabor in Shadowmoon Valley", "Battle-Priest Arynthia is a draenei located at Karabor in Shadowmoon Valley." },
  ["battlecryer blackeye"] = { 2, "orc PvP rewards vendor located in Thrallmar in Hellfire P...", "Battlecryer Blackeye is an orc PvP rewards vendor located in Thrallmar in Hellfire Peninsula. She works tirelessly to recruit adventurers to aid in the capture of three strategic forts near Hellfire Citadel." },
  ["battlefield mechanic"] = { 2, "', "Battlefield Mechanics are gnomes located in the Sundered Span in Nazmir and Vol'dun during Faction Assaults." },
  ["battlelord gaardoun"] = { 2, "Broken warrior", "Battlelord Gaardoun is a Broken warrior and a captain of the Ashtongue and the Servants of Illidan. He is accompanied by mystics, warriors, and stalkers." },
  ["battlemaster bröng"] = { 2, "leader of the Garad'kra", "Battlemaster Bröng is the leader of the Garad'kra, a group of elite Horde militias. Just after the militia's founding following the Cataclysm, Bröng assembled the Garad'kra in Orgrimmar's Ring of Valor to give them their first orders: ending the n..." },
  ["battleworn paratrooper"] = { 2, "', "Battleworn Paratroopers are humans, dwarves, gnomes, and night elves located in Tigers' Wood in the Jade Forest. Occasionally, they paratroop to Slicky Stream, Grookin Hill, Dookin' Grounds, and the Path of Enlightenment." },
  ["batu (tortollan)"] = { 2, "tortollan located at the Seekers' Outpost in Zuldazar", "Batu is a tortollan located at the Seekers' Outpost in Zuldazar." },
  ["batzvara"] = { 2, "earthen Caretaker located in the Ringing Deeps", "Batzvara is an earthen Caretaker located in the Ringing Deeps." },
  ["bax freeseeker"] = { 2, "tauren sleeping next to Tanda Freeseeker in a hut just ea...", "Bax Freeseeker is a tauren sleeping next to Tanda Freeseeker in a hut just east of the upper level of Thunder Totem in Highmountain. Marcus the paladin can be found sleeping next to them, though upon approach he wakes up and walks out of the hut, ..." },
  ["baxel brassbombs"] = { 2, "goblin commander attacking Lion's Landing during the Lion...", "Baxel Brassbombs is a goblin commander attacking Lion's Landing during the Lion's Landing scenario. He rides a rocket." },
  ["baxtan"] = { 2, "great goblin mage", "Baxtan is a great goblin mage. He is the author of  [Baxtan: On Destructive Magics]." },
  ["baxx the purveyor"] = { 2, "goblin located at the Bilgewater Flats in the Undermine", "Baxx the Purveyor is a goblin located at the Bilgewater Flats in the Undermine." },
  ["baygumn"] = { 2, "nerubian located in the City of Threads", "Baygumn is a nerubian located in the City of Threads." },
  ["bazaar browser"] = { 2, "Veiled Market", "Bazaar Browsers are brokers located in Tazavesh, the Veiled Market." },
  ["bazaar overseer (tazavesh)"] = { 2, "Veiled Market", "Bazaar Overseers are brokers located in Tazavesh, the Veiled Market." },
  ["bazaar shopper"] = { 2, "Veiled Market", "Bazaar Shoppers are brokers located at the Bazaar of Tangible Delights in Tazavesh, the Veiled Market." },
  ["bazaar strongarm"] = { 2, "Veiled Market", "Bazaar Strongarms are brokers located in Tazavesh, the Veiled Market." },
  ["bazaar vagabond"] = { 2, "Veiled Market", "Bazaar Vagabonds are brokers located at the Bazaar of Tangible Delights in Tazavesh, the Veiled Market." },
  ["bazwix"] = { 2, "goblin quest giver", "Bazwix is a goblin quest giver who appears and begins following the player around when they enter Sabermaw in Nagrand, asking them to help retrieve his 'treasure', which got stolen by the saberon when they attacked the trade wagon he was on (the w..." },
  ["bazzalan"] = { 2, "satyr found in Ragefire Chasm", "Bazzalan is a satyr found in Ragefire Chasm." },
  ["beach enjoyer"] = { 2, "', "Beach Enjoyers are located at the Plunder Party in the Undermine." },
  ["bearer thedrin"] = { 2, "kyrian Bearer held captive by Kel'Thuzad in the Vault of ...", "Bearer Thedrin is a kyrian Bearer held captive by Kel'Thuzad in the Vault of Souls in Maldraxxus. He was captured during the attack on the Temple of Courage and delivered to Kel'Thuzad as the lich's 'personal prize'." },
  ["beast of lyquokk strait"] = { 2, "', "A large, unnamed sea monster inhabited Lyquokk Strait on the western coast of the Howling Fjord until it was killed by the tuskarr Taruka, who subsequently became known as 'Beastkiller'." },
  ["beastblast babblesnaff"] = { 2, "goblin stable master found in Bilgewater Port", "Beastblast Babblesnaff is a goblin stable master found in Bilgewater Port and Lost Isles. He has a Crawler." },
  ["beastkeeper gaelus"] = { 2, "kyrian stable master located at Sagehaven in Bastion", "Beastkeeper Gaelus is a kyrian stable master located at Sagehaven in Bastion." },
  ["beastkeeper ismene"] = { 2, "kyrian stable master located at Terrace of the Collectors...", "Beastkeeper Ismene is a kyrian stable master located at Terrace of the Collectors in Bastion." },
  ["beastkeeper krista"] = { 2, "Ascended kyrian stable master located in Elysian Hold in ...", "Beastkeeper Krista is an Ascended kyrian stable master located in Elysian Hold in Bastion." },
  ["beastmaster (arena)"] = { 2, "goblin hunter providing free pets to players", "The Beastmaster is a goblin hunter providing free pets to players and acting as a Pet Trainer and stable master. He can be found in all races' starting areas on the Arena Tournament realms." },
  ["beastmaster hilaire"] = { 2, "vrykul hunter with the Unseen Path located in Stormheim", "Beastmaster Hilaire is a vrykul hunter with the Unseen Path located in Stormheim.  Long ago she abandoned her clan to join the organization, and for that she is shunned by the clan." },
  ["beastmaster nuqut"] = { 2, "centaur stable master located on the southwestern outskir...", "Beastmaster Nuqut is a centaur stable master located on the southwestern outskirts of Timberstep Outpost in the Ohn'ahran Plains. Along with Halu, Gentara and another Loyal Bakar, he is keeping watch over a few Pack Musken and Domesticated Argali." },
  ["beastmaster oken"] = { 2, "centaur stable master located at Broadhoof Outpost in the...", "Beastmaster Oken is a centaur stable master located at Broadhoof Outpost in the Ohn'ahran Plains." },
  ["beastmaster thalmaa"] = { 2, "centaur stable master located in Teerakai in the Ohn'ahra...", "Beastmaster Thalmaa is a centaur stable master located in Teerakai in the Ohn'ahran Plains." },
  ["beastmaster tirren"] = { 2, "centaur stable master located Maruukai in the Ohn'ahran P...", "Beastmaster Tirren is a centaur stable master located Maruukai in the Ohn'ahran Plains." },
  ["beastmaster tung"] = { 2, "mogu", "Beastmaster Tung is a mogu." },
  ["beastmaster zira"] = { 2, "centaur located on the Shikaar rise in Maruukai in the Oh...", "Beastmaster Zira is a centaur located on the Shikaar rise in Maruukai in the Ohn'ahran Plains." },
  ["beatface"] = { 2, "ogre in Gorgrond", "Beatface is an ogre in Gorgrond." },
  ["beathan"] = { 2, "Wildhammer dwarf during the Second War", "Beathan was a Wildhammer dwarf during the Second War. He was the one who reported Kurdran that Moray and Seaghdh died and Alpin and Lachtin were knocked from their gryphons because of the forest trolls helping the orcs." },
  ["bebri coifcurl"] = { 2, "goblin in charge of the Barbershop in Orgrimmar", "Bebri Coifcurl is the goblin in charge of the Barbershop in Orgrimmar. She was originally found in the Cleft of Shadow." },
  ["becan barleybrew"] = { 2, "dwarf quest giver located in Dun Morogh during Brewfest", "Becan Barleybrew is a dwarf quest giver located in Dun Morogh during Brewfest. He asks adventurers to promote the Barleybrews in Ironforge by giving them a ram." },
  ["beck"] = { 2, "orc", "Beck is an orc who can be found at the Windrunner's Sanctuary in Dalaran. It is currently unknown if he survived Dalaran's destruction." },
  ["bedfear"] = { 2, "kobold located in Campalot in the Ringing Deeps", "Bedfear is a kobold located in Campalot in the Ringing Deeps." },
  ["bee wrangler"] = { 2, "', "Bee Wranglers are goblins located in the Buzz Barns in Cinderbrew Meadery." },
  ["beega"] = { 2, "draenei bow vendor located at Blood Watch on Bloodmyst Isle", "Beega is a draenei bow vendor located at Blood Watch on Bloodmyst Isle." },
  ["beegle blastfuse"] = { 2, "gnome master Pet Tamer located on the cliff opposite West...", "Beegle Blastfuse is a gnome master Pet Tamer located on the cliff opposite Westguard Keep in Howling Fjord. His three level 25 battle pets are staring out to sea nearby: Gobbles, Warble, and Dinner." },
  ["beeoka"] = { 2, "tortollan", "Beeoka is a tortollan." },
  ["beezle boomsticks"] = { 2, "goblin follower located at Frostwall in Frostfire Ridge", "Beezle Boomsticks is a goblin follower located at Frostwall in Frostfire Ridge. He can only be recruited using the Headhunter's Harvest from Frostwall Tavern." },
  ["befuddled relic-seeker"] = { 2, "', "Befuddled Relic-Seekers are ogres located in the Spires of Arak. They are fighting Highmaul Skullcrushers and Highmaul Relic-Seekers at Lost Veil Anzu." },
  ["beh'tor"] = { 2, "orc reagents", "Beh'tor is an orc reagents and poison vendor located in Zoram'gar Outpost in Ashenvale." },
  ["behomat"] = { 2, "draenei warrior trainer located at the Ring of Arms in th...", "Behomat is a draenei warrior trainer located at the Ring of Arms in the Trader's Tier in the Exodar. This section concerns content related to Legion." },
  ["bek"] = { 2, "Theramore soldier under Colonel Lorena", "Major Bek was a Theramore soldier under Colonel Lorena. When Lorena received an order from Kristoff to lead Northwatch Hold's forces, Bek was amongst those whom Lorena chose as her senior staff." },
  ["beks"] = { 2, "tuskarr located on the Young Belvo", "Beks is a tuskarr located on the Young Belvo that travels around Azeroth." },
  ["beksa"] = { 2, "goblin located in the Verdant Gutters in the Ringing Deeps", "Beksa is a goblin located in the Verdant Gutters in the Ringing Deeps." },
  ["bektal the firebinder"] = { 2, "furbolg", "Bektal the Firebinder is a furbolg." },
  ["bela"] = { 2, "venthyr located in Darkhaven in Revendreth", "Bela is a venthyr located in Darkhaven in Revendreth. He can also be seen walking inside Sinfall." },
  ["beldos"] = { 2, "draenei flight master located at the Retribution Point in...", "Beldos is a draenei flight master located at the Retribution Point in Talador." },
  ["beleaguered explorer"] = { 2, "', "Beleaguered Explorers are members of the Dragonscale Expedition located in the Waking Shores." },
  ["beleagurered engineer"] = { 2, "', "Beleagurered Engineers are dwarves located in the Twilight Shore in the Twilight Highlands." },
  ["belga"] = { 2, "earthen located in the Forgegrounds in Dornogal", "Belga is an earthen located in the Forgegrounds in Dornogal." },
  ["belgork"] = { 2, "Grom'kar officer attempting to keep Ironmonger's Hold in ...", "Belgork is a Grom'kar officer attempting to keep Ironmonger's Hold in Tanaan Jungle clear of Thromma the Gutslicer's Pale orcs. He is guarded by two Grom'kar Bulwarks." },
  ["belika"] = { 2, "young centaur hunter of Clan Shikaar encountered througho...", "Belika is a young centaur hunter of Clan Shikaar encountered throughout the Ohn'ahran Plains. She is locked in a friendly rivalry with Aru over who is the better hunter; Belika believes that speed is more important than precision, while Aru believ..." },
  ["bellhop boots"] = { 2, "goblin located at the Incontinental Hotel in the Undermine", "Bellhop Boots is a goblin located at the Incontinental Hotel in the Undermine." },
  ["belligerent supporter"] = { 2, "', "Belligerent Supporters are goblins located in Crapopolis in the MOTHERLODE!! As their name indicates, they are footbomb supporters." },
  ["bellthazor"] = { 2, "human rogue", "Bellthazor of Darkshire is a human rogue. After buying Miles Corebender a couple of drinks in a Gadgetzan inn, Miles revealed to Bellthazor his and Kova’s quest for the reclusive orc seer Dhambeela." },
  ["belosh"] = { 2, "draenei found in", "Belosh is a draenei found in Andromath's Rise in Stormshield." },
  ["belouran"] = { 2, "draenei located at Lunarfall in Shadowmoon Valley", "Belouran is a draenei located at Lunarfall in Shadowmoon Valley. He can only be recruited using the Headhunter's Harvest from Lunarfall Inn." },
  ["bemora"] = { 2, "draenei Holy paladin", "Bemora is a draenei Holy paladin. Her Horde counterpart is Seleria Dawncaller." },
  ["benatauk"] = { 2, "tuskarr found outside the Caverns of Time in Tanaris duri...", "Benatauk is a tuskarr found outside the Caverns of Time in Tanaris during the Bronze Celebration, alongside Enzo and Maru. He is part of the Guest Relations storyline and provides  [Benatauk's Clue Book] for  [10-90] Thoughtful Pursuits." },
  ["benge"] = { 2, "young orc killed by the hydra Trigore the Lasher in the W...", "Benge was a young orc killed by the hydra Trigore the Lasher in the Wailing Caverns during his om'gora. His body, torn and cold, was found by a party of warriors and brought to Orgrimmar, where his father turned away from his corpse out of grief." },
  ["bengor"] = { 2, "orc quest giver located in Stonard in the Swamp of Sorrows", "Bengor is an orc quest giver located in Stonard in the Swamp of Sorrows. He has been missing since the Cataclysm." },
  ["bengus deepforge"] = { 2, "dwarf blacksmithing trainer located at the center of the ...", "Bengus Deepforge is a dwarf blacksmithing trainer located at the center of the Great Forge in Ironforge." },
  ["benik boltshear"] = { 2, "gnome locksmith located in the Dwarven District in Stormw...", "Benik Boltshear is a gnome locksmith located in the Dwarven District in Stormwind City, near the Forge.  With the removal of keys from the game, Benik finds himself without a job." },
  ["benjamin algerson"] = { 2, "human located at Algerson Lumber Yard in Tiragarde Sound", "Benjamin Algerson is a human located at Algerson Lumber Yard in Tiragarde Sound." },
  ["benk buzzbee"] = { 2, "boss in Cinderbrew Meadery", "Benk Buzzbee is a boss in Cinderbrew Meadery." },
  ["beogoka"] = { 2, "furbolg located in the Upper Frostlands in the Azure Span", "Beogoka is a furbolg located in the Upper Frostlands in the Azure Span." },
  ["berard the moon-crazed"] = { 2, "rare worgen found in a camp in Olsen's Farthing in Silver...", "Berard the Moon-Crazed is a rare worgen found in a camp in Olsen's Farthing in Silverpine Forest." },
  ["berbert"] = { 2, "murloc located at the Winterfin Retreat in the Borean Tundra", "Berbert is a murloc located at the Winterfin Retreat in the Borean Tundra." },
  ["beregos"] = { 2, "member of the blue dragonflight", "Beregos was a member of the blue dragonflight who served as the archlibrarian of the Azure Archives. Beregos worked with Sindragosa to create an army of illusions to make the borders of the Broodlands appear far more defended than they were, and l..." },
  ["berg the spellfist"] = { 2, "ogre located in Highland Forest in the Twilight Highlands", "Berg the Spellfist was an ogre located in Highland Forest in the Twilight Highlands." },
  ["bergrisst"] = { 2, "Forsaken lead guitarist of the thrash metal band Elite Ta...", "Bergrisst is the Forsaken lead guitarist of the thrash metal band Elite Tauren Chieftain. He replaced Arthas Menethil in the band following the events of Warcraft III: The Frozen Throne." },
  ["berhild the fierce"] = { 2, "vrykul located in Island Expeditions", "Berhild the Fierce is a vrykul located in Island Expeditions." },
  ["berian"] = { 2, "member of the black dragonflight", "Berian was a member of the black dragonflight and one of the swiftest fliers available to them. He was sent to Umbrenion with a fulgurite produced by Raszageth during her attack upon a mortal village." },
  ["bernadette florence"] = { 2, "worgen", "Bernadette Florence is a worgen." },
  ["bernaisez"] = { 2, "dracthyr located in Iskaara in the Azure Span", "Bernaisez is a dracthyr located in Iskaara in the Azure Span." },
  ["bernard"] = { 2, "most famous of all Alterac brewhounds", "Bernard is the most famous of all Alterac brewhounds. He is credited with saving upwards of 50 lives — many of them dwarf and orc soldiers dragged out of the snow beneath the treacherous bridges of Alterac Valley." },
  ["bero"] = { 2, "draenei located in the Shrine of Seven Stars", "Bero is a draenei located in the Shrine of Seven Stars. This section concerns content related to Battle for Azeroth." },
  ["berred"] = { 2, "earthen located in the Forgegrounds in Dornogal", "Berred is an earthen located in the Forgegrounds in Dornogal." },
  ["berrt"] = { 2, "earthen located at the Keepers Terrace in Dornogal", "Berrt is an earthen located at the Keepers Terrace in Dornogal." },
  ["berrund the gleaming"] = { 2, "earthen located in the Ringing Deeps", "Berrund the Gleaming is an earthen located in the Ringing Deeps." },
  ["berserker danpolcari"] = { 2, "vrykul located in Stormheim", "Berserker Danpolcari is a vrykul located in Stormheim." },
  ["bert coinsplitter"] = { 2, "gnome banker located at Bronzebeard's Vault in Stormshield", "Bert Coinsplitter is a gnome banker located at Bronzebeard's Vault in Stormshield." },
  ["berta bryckbreaker"] = { 2, "Arathi located alongside a number of Arathi Laborers in n...", "Berta Bryckbreaker is an Arathi located alongside a number of Arathi Laborers in northwestern Mereldar in Hallowfall. During shadow curfew, they all take shelter at the inn." },
  ["bertha"] = { 2, "fisherman by the lake", "Bertha was a human located at Tarren Mill in Old Hillsbrad Foothills. Her husband is a fisherman by the lake." },
  ["bertinuat"] = { 2, "tuskarr located in Iskaara in the Azure Span", "Bertinuat is a tuskarr located in Iskaara in the Azure Span and inside Brackenhide Hollow." },
  ["bertola"] = { 2, "earthen located on the Isle of Dorn", "Bertola is an earthen located on the Isle of Dorn." },
  ["bertram barleybeard"] = { 2, "dwarf located in Stromgarde Keep in the Arathi Highlands", "Bertram Barleybeard is a dwarf located in Stromgarde Keep in the Arathi Highlands. He is an Alliance ambassador." },
  ["beryl reclaimer"] = { 2, "', "Beryl Reclaimers are gnomes located in Coldrock Quarry in the Borean Tundra." },
  ["besora galefeather"] = { 2, "Tauren Druid", "Besora Galefeather is a Tauren Druid that appears on the following World of Warcraft: Trading Card Game cards." },
  ["beth'amara"] = { 2, "', "Beth'Amara was one of the Highborne's most influential alchemists. The wizard alone was said to have mastered transmuting metals among other things." },
  ["bethany aldire"] = { 2, "elite Strand of the Ancients battlemaster located in Stor...", "Bethany Aldire was an elite Strand of the Ancients battlemaster located in Stormwind City only during the Call to Arms: Strand of the Ancients." },
  ["betina bigglezink"] = { 2, "gnome quest giver located at Light's Shield Tower in the ...", "Betina Bigglezink is a gnome quest giver located at Light's Shield Tower in the Eastern Plaguelands. She used to located at Light's Hope Chapel until the Argent Crusade captured the towers." },
  ["betsi boombasket"] = { 2, "goblin located in the northern part of Pinchwhistle Point", "Betsi Boombasket is a goblin located in the northern part of Pinchwhistle Point, she has a small camp with an impressive amount of explosives." },
  ["betta"] = { 2, "earthen located in Freywold Village on the Isle of Dorn", "Betta is an earthen located in Freywold Village on the Isle of Dorn." },
  ["bevrusi"] = { 2, "earthen located in Dornogal", "Bevrusi is an earthen located in Dornogal." },
  ["beyvel"] = { 2, "goblin participating in the Darkmoon Dance Competition in...", "Beyvel is a goblin participating in the Darkmoon Dance Competition in South Pavilion on Darkmoon Island." },
  ["bezime"] = { 2, "Zandalari troll noble", "Bezime was a Zandalari troll noble whose family was among those punished for their ties to the traitor Yazma, though the Zanchuli Council found the family cleared of any wrongdoing. When his daughter, Nav'rae, petitioned aid from the crown in bein..." },
  ["bezzil"] = { 2, "goblin located at Orgrimmar Rocketway Exchange in Azshara", "Bezzil is a goblin located at Orgrimmar Rocketway Exchange in Azshara. He used to be a stable master of Goblin Slums in Orgrimmar, but was relocated to Azshara following the construction of Orgrimmar Embassy." },
  ["bezzle blastbolt"] = { 2, "', "Bezzle Blastbolt and his brother Bozzle were a couple of the goblins hired to help construct the Crusaders' Coliseum in Icecrown. After it was completed, they no longer had a job and now hang around the bar drinking." },
  ["bhyshyp"] = { 2, "nerubian spiderling located in Umbral Bazaar in the City ...", "Bhyshyp is a nerubian spiderling located in Umbral Bazaar in the City of Threads." },
  ["bibilfaz featherwhistle"] = { 2, "gnome gryphon flight master located at Chillwind Camp in ...", "Bibilfaz Featherwhistle is a gnome gryphon flight master located at Chillwind Camp in the Western Plaguelands." },
  ["biergoth"] = { 2, "earthen located in Dornogal", "Biergoth is an earthen located in Dornogal." },
  ["big blossom digger"] = { 2, "', "Big Blossom Diggers are goblins located at Big Blossom Excavation of Vale of Eternal Blossoms. Their corpses can be seen in the Siege of Orgrimmar instance." },
  ["big bruiser"] = { 2, "ogre located in Shattrath City", "Big Bruiser is an ogre located in Shattrath City." },
  ["big game hunter (mob)"] = { 2, "', "Big Game Hunters are located east of Halaa in Nagrand during Love is in the Air. They are trying to take down Toothy the clefthoof." },
  ["big kinook"] = { 2, "tuskarr located in Iskaara in the Azure Span", "Big Kinook is a tuskarr located in Iskaara in the Azure Span. He manages the Communal Pot and the Community Feast." },
  ["bigzo blastbang"] = { 2, "goblin located in Apex Observatory in the Waking Shores", "Bigzo Blastbang is a goblin located in Apex Observatory in the Waking Shores." },
  ["bijou"] = { 2, "goblin found in Tazz'Alor in Lower Blackrock Spire", "Bijou is a goblin found in Tazz'Alor in Lower Blackrock Spire. She was hired by the Kargath Expeditionary Force as an operative to investigate the Blackrock orcs." },
  ["bildine"] = { 2, "draenei reagent vendor located at the Crystal Hall in the...", "Bildine is a draenei reagent vendor located at the Crystal Hall in the Exodar. This section concerns content related to Legion." },
  ["bilebloat juggernaut"] = { 2, "', "Bilebloat Juggernauts are enormous abominations of kyrian flesh located in the House of Constructs in Maldraxxus during  Righteous Retribution/ A Golden Dawn. Margrave Gharmal proclaims that they will be used to vanquish all who oppose the Constru..." },
  ["bilge rat cutthroat"] = { 2, "', "Bilge Rat Cutthroats are vulpera located in Upton Borough in the Siege of Boralus." },
  ["bilge rat grog jerk"] = { 2, "', "Bilge Rat Grog Jerks are vulpera located in Freehold." },
  ["bilge rat looter"] = { 2, "', "Bilge Rat Looters are vulpera located in Tol Dagor." },
  ["bilge rat mixologist"] = { 2, "vulpera", "Bilge Rat Mixologist is a vulpera." },
  ["bilge rat padfoot"] = { 2, "', "Bilge Rat Padfeet are vulpera located in the Rum Quarter in Freehold." },
  ["bilgefin defender"] = { 2, "', "Bilgefin Defenders are three murlocs found guarding the Fjarnskaggl Cluster at the Bilgefin Shore in Stormheim when  [45WQ] Fjarnskaggl Cluster is up." },
  ["bilgefin invader"] = { 2, "', "Bilgefin Invaders are murlocs located in Morheim if Stormheim." },
  ["bilgefin scavenger"] = { 2, "', "Bilgefin Scavengers are murlocs located in Morheim in Stormheim." },
  ["bilgefin tideseer"] = { 2, "', "Bilgefin Tideseers are murlocs located in Morheim in Stormheim." },
  ["bilgerat"] = { 2, "kobold located in a cave in Dead Man's Bay in Azsuna", "Bilgerat is a kobold located in a cave in Dead Man's Bay in Azsuna." },
  ["bilgewater azerite drudge"] = { 2, "', "Bilgewater Azerite Drudges are goblin scouts encountered throughout  [35-60] Profit and Reconnaissance in Drustvar. One is found dead." },
  ["bilgewater battlebruiser"] = { 2, "', "Bilgewater Battlebruisers are goblins located at Lost Rigger Cove in Tanaris." },
  ["bilgewater beastrider"] = { 2, "', "Bilgewater Beastriders are goblins located in Zuldazar." },
  ["bilgewater blastgineer"] = { 2, "', "Bilgewater Blastgineers are goblins located in the Horde Landing Site in the Krasarang Wilds." },
  ["bilgewater blastmaster"] = { 2, "', "Bilgewater Blastmasters are goblins located at the Dranosh'ar Blockade in Durotar. Prior to the battle for the Broken Shore, they were working on Megaton alongside Underpaid Engineers." },
  ["bilgewater blastmasters"] = { 2, "', "Bilgewater Blastmasters are goblins located in the Undercity during the Battle for Lordaeron." },
  ["bilgewater boomer"] = { 2, "', "Bilgewater Boomers are goblins located in the Bilgewater Bonanza in Zuldazar." },
  ["bilgewater bruiser (azshara)"] = { 2, "', "Bilgewater Bruisers are goblins located in Bilgewater Harbor in Azshara." },
  ["bilgewater bruiser (krasarang wilds)"] = { 2, "', "Bilgewater Bruisers are goblins that would appear in Krasarang Wilds." },
  ["bilgewater dockworker"] = { 2, "', "Bilgewater Dockworkers are goblins located in Bilgewater Harbor in Azshara." },
  ["bilgewater dockworker (crapopolis)"] = { 2, "', "Bilgewater Dockworkers are goblins located in Crapopolis during the Heritage of Kezan questline." },
  ["bilgewater driller"] = { 2, "goblin located in Bilgewater Bonanza in Zuldazar", "Bilgewater Driller is a goblin located in Bilgewater Bonanza in Zuldazar." },
  ["bilgewater emmissary"] = { 2, "', "Bilgewater Emmissaries[sic] are goblins located in the Horde Embassy or roaming the streets in Dornogal." },
  ["bilgewater enforcer"] = { 2, "', "Bilgewater Enforcers are goblins in the Blazing Strand in Darkshore during the War of the Thorns." },
  ["bilgewater field medic"] = { 2, "', "Bilgewater Field Medics are goblins located at Lion's Landing in the Lion's Landing scenario." },
  ["bilgewater foreman"] = { 2, "', "Bilgewater Foremen are goblins found throughout the goblin settlement in Bilgewater Harbor. Their gossip text reveals a typical goblin attitude towards business, and in  [30-35] Beating the Market, it seems this was correct." },
  ["bilgewater goblin"] = { 2, "', "Bilgewater Goblins are goblins located in Xibala and Bilgewater Bonanza in Zuldazar." },
  ["bilgewater grenadier"] = { 2, "', "Bilgewater Grenadiers are goblins located at Lion's Landing in the Lion's Landing scenario." },
  ["bilgewater gunman"] = { 2, "', "Bilgewater Gunmen are goblins and orcs located in Twilight Highlands." },
  ["bilgewater hauler"] = { 2, "', "Bilgewater Haulers are goblins located in the Bilgewater Bonanza in Zuldazar." },
  ["bilgewater incinerator"] = { 2, "', "Bilgewater Incinerators are goblins located in Arom's Crossing in Drustvar." },
  ["bilgewater incinerator (war of the thorns)"] = { 2, "', "Bilgewater Incinerators are goblins located in Lor'danel and Mist's Edge in Darkshore following the Burning of Teldrassil. They are burning everything and using jetpacks to jump from target to target." },
  ["bilgewater incinerator (zuldazar)"] = { 2, "', "Bilgewater Incinerators are goblins located in Zuldazar." },
  ["bilgewater laborer"] = { 2, "', "Bilgewater Laborers are goblins located in Silithus: The Wound." },
  ["bilgewater laborer (azshara)"] = { 2, "', "Bilgewater Laborers are captured goblins located in Sable Ridge in Azshara." },
  ["bilgewater laborer (war of the thorns)"] = { 2, "', "Bilgewater Laborers are goblins located in Nazj'vel in Darkshore during the stalemate phase of the War of the Thorns." },
  ["bilgewater logger"] = { 2, "', "Bilgewater Loggers are goblins found at Quickchop's Lumber Farm in Krasarang Wilds." },
  ["bilgewater marksman"] = { 2, "', "Bilgewater Marksmen are goblins located in the Twilight Highlands." },
  ["bilgewater mechanic"] = { 2, "', "Bilgewater Mechanics are goblins located in Southwind Village in Silithus: The Wound." },
  ["bilgewater mechanic (azshara)"] = { 2, "', "Bilgewater Mechanics are goblins found throughout Bilgewater Harbor in Azshara." },
  ["bilgewater miner"] = { 2, "', "Bilgewater Miners are goblin miners mainly located on the southern end of the Cracked Coast in Vol'dun. During  [30-60] Calldown: Cleaner, they spawn to harvest Azerite from Dense Stones around the coast after Abrasive Reconfigulators 8000 expose ..." },
  ["bilgewater muscle"] = { 2, "', "Bilgewater Muscles were goblins found defending Megs Dreadshredder's camp in Tanaris during the Legion Invasions." },
  ["bilgewater poacher"] = { 2, "', "Bilgewater Poachers are goblins located in Gorilla Gorge in Zuldazar during the Alliance War Campaign. Some ride direhorns." },
  ["bilgewater prisoner"] = { 2, "', "Bilgewater Prisoners are goblins located in Highbank in the Twilight Highlands." },
  ["bilgewater prospector"] = { 2, "', "Bilgewater Prospectors are goblins located in Silithus: The Wound." },
  ["bilgewater rigger"] = { 2, "', "Bilgewater Riggers are goblins located in the Blazing Strand in Darkshore." },
  ["bilgewater rocket-jockey"] = { 2, "', "Bilgewater Rocket-jockeys are goblins located at each of the five stations of the Rocketway in Azshara. To travel along the Rocketway, you must speak to one of these goblins and select which station you wish to go to." },
  ["bilgewater salvage expert"] = { 2, "', "Bilgewater Salvage Experts are goblins located in the Twilight Highlands." },
  ["bilgewater sapper"] = { 2, "', "Bilgewater Sappers are goblins found in Lion's Landing in Krasarang Wilds." },
  ["bilgewater socialite"] = { 2, "goblin found on the second floor of the inn in Bilgewater...", "A Bilgewater Socialite is a goblin found on the second floor of the inn in Bilgewater Harbor in Azshara. She appears to flirt with the Bilgewater Foreman standing next to her from time to time." },
  ["bilgewater soldier"] = { 2, "', "Bilgewater Soldiers are Bilgewater goblins and orcs found fighting naga in central Azshara. This section concerns content related to Legion." },
  ["bilgewater speculator"] = { 2, "goblin located in the Drunken Drummer in Dazar'alor", "The Bilgewater Speculator is a goblin located in the Drunken Drummer in Dazar'alor. He can be found pounding a Goblin Drum." },
  ["bilgewater surveyor"] = { 2, "', "Bilgewater Surveyors are goblins located in the Horde Landing Site in the Krasarang Wilds." },
  ["bilgewater treasure thief"] = { 2, "', "Bilgewater Treasure Thieves are goblins located in Atal'Dazar in Zuldazar." },
