  ["black harvest acolyte"] = { 2, "', "Black Harvest Acolytes are warlocks of the Council of the Black Harvest found at Dreadscar Rift. They can also be found in the Assault on Broken Shore scenario, where they summon the portal to attack the Legion ship alongside Ritssyn Flamescowl." },
