  ["blackhand"] = { 2, "chieftain of the mighty Blackrock clan", "Blackhand was the chieftain of the mighty Blackrock clan and the first Warchief of the Old Horde until he was killed by Orgrim Doomhammer near the end of the First War. He was known throughout Draenor and Azeroth alike as a brutal tyrant." },
  ["blackhand (alternate universe)"] = { 2, "warlord of the Blackrock clan", "\"My legacy is shaped by my power and nothing else.\" Blackhand is the warlord of the Blackrock clan and the ruler of Gorgrond. He was second in the structure of the Iron Horde." },
  ["blackhand (film universe)"] = { 2, "Warchief of the Horde", "Blackhand was the Warchief of the Horde, and the mightiest warrior the Horde had ever known. Although a ruthless war leader, he still held respect for tradition, placing honor above victory or even his own survival." },
  ["blackhand (tactics)"] = { 2, "final boss of Blackrock Foundry in Gorgrond", "Blackhand is the final boss of Blackrock Foundry in Gorgrond." },
  ["blackhand assassin"] = { 2, "', "Blackhand Assassins were orcs found in Upper Blackrock Spire." },
