  ["blademaster (warcraft iii)"] = { 2, "seasoned Blademasters represent an elite fighting force w...", "Though their numbers are few, the seasoned Blademasters represent an elite fighting force within the Horde. These skilled swordsmen were once part of the ill-fated Burning Blade Clan which consumed itself in the throes of Demonic corruption." },
