  ["bladesman enokou"] = { 2, "ankoan located in Mezzamere in Nazjatar", "Bladesman Enokou is an ankoan located in Mezzamere in Nazjatar. Under the guidance of Instructor Amano, he can be found sparring with Bladesman Atuki." },
