  ["bladesman inowari"] = { 2, "ankoan located in Nazjatar", "Bladesman Inowari is an ankoan located in Nazjatar and is one of the most skilled warriors of the Waveblade. He is a stalwart defender and does not flinch in battle, even against overwhelming odds." },
  ["bladesman ubano"] = { 2, "ankoan located in Mezzamere in Nazjatar", "Bladesman Ubano is an ankoan located in Mezzamere in Nazjatar. He can be found sparring with Bladesman Inaza." },
