  ["blimore vidala"] = { 2, "Arathi located in Mereldar in Hallowfall", "Blimore Vidala is an Arathi located in Mereldar in Hallowfall. He can be found dancing with Soran Vidala and appears to be  Drunk." },
  ["blind blademaster"] = { 2, "', "Blind Blademasters are orcs in the Siege of Orgrimmar. Known among players for being a close range bane like Gastropod from Throne of Thunder." },
  ["blind hero"] = { 2, "undead serving as a Challenge Card encounter in the Brawl...", "Blind Hero is an undead serving as a Challenge Card encounter in the Brawler's Guild during The War Within. To fight him, purchase  [Challenge Card: Blind Hero] after reaching Rank 8 with the guild." },
  ["blinding sun priestess"] = { 2, "', "Blinding Sun Priestesses are arakkoa located in Skyreach." },
  ["blindlight muckdweller"] = { 2, "', "Blindlight Muckdwellers are murlocs that can be found in the Pool of Ask'ar of Blackfathom Deeps." },
  ["blindlight murloc"] = { 2, "', "Blindlight Murlocs are deep sea murlocs found in the Drowned Sacellum in Blackfathom Deeps." },
  ["blindlight oracle"] = { 2, "', "Blindlight Oracles are murlocs found in the Pool of Ask'ar of Blackfathom Deeps." },
  ["blistering outcast"] = { 2, "', "Blistering Outcasts are venthyr located in Revendreth." },
  ["blitz blastospazz"] = { 2, "flight master located at Northern Rocketway Terminus in A...", "Blitz Blastospazz is the flight master located at Northern Rocketway Terminus in Azshara." },
  ["blixthraz blastcharge"] = { 2, "goblin quest giver found at Frostwall's mine in Frostfire...", "Blixthraz Blastcharge is a goblin quest giver found at Frostwall's mine in Frostfire Ridge. If the Engineering Works building is built, he relocates there." },
  ["blixxrak"] = { 2, "goblin light armor vendor located in Everlook in Wintersp...", "Blixxrak is a goblin light armor vendor located in Everlook in Winterspring." },
  ["blizrik buckshot"] = { 2, "goblin vendor located in Gadgetzan in Tanaris", "Blizrik Buckshot is a goblin vendor located in Gadgetzan in Tanaris. This section concerns content related to Legion." },
  ["bliztik"] = { 2, "goblin alchemy vendor located in a house in Raven Hill in...", "Bliztik is a goblin alchemy vendor located in a house in Raven Hill in Duskwood." },
  ["blokk"] = { 2, "simpleminded ogre", "Blokk is a simpleminded ogre who served as the mount of the goblin alchemist Rumblefitz and was hired by Zhahara Darksquall to find the Pearl of Pandaria." },
  ["blondy"] = { 2, "rare blonde orc", "Blondy was a rare blonde orc that participated in the First War." },
  ["blood font (vale of eternal blossoms)"] = { 2, "', "Blood Fonts are deceased creatures located in the Setting Sun Garrison and Tu Shen Burial Ground in the Vale of Eternal Blossoms. They are having their blood drained by the mogu of the Dokani clan." },
  ["blood guard (ptr)"] = { 2, "orc", "Blood Guard is an orc." },
  ["blood guard axelash"] = { 2, "orc located in Warspear", "Blood Guard Axelash is an orc located in Warspear. She sells Warlords Season 1 equipment." },
  ["blood horde bomber"] = { 2, "', "Blood Horde Bombers are goblins located in Tyrhold Reservoir in Thaldraszus during Time Rifts." },
  ["blood horde engineer"] = { 2, "', "Blood Horde Engineers are goblins located in Tyrhold Reservoir in Thaldraszus during Time Rifts." },
  ["blood horde grunt"] = { 2, "', "Blood Horde Grunts are orcs located in Tyrhold Reservoir in Thaldraszus and in the Warlands during Time Rifts." },
  ["blood horde reaver"] = { 2, "', "Blood Horde Reavers are orcs located in Tyrhold Reservoir in Thaldraszus and in the Warlands during Time Rifts." },
  ["blood horde shaman"] = { 2, "', "Blood Horde Shaman are orcs located in Tyrhold Reservoir in Thaldraszus and in the Warlands during Time Rifts." },
  ["blood marquess"] = { 2, "', "Blood Marquesses are Darkfallen of the San'layn located in Nazmir." },
  ["blood marquis"] = { 2, "', "Blood Marquises are Darkfallen of the San'layn located in Nazmir." },
  ["blood prince dreven"] = { 2, "Darkfallen of the San'layn", "Blood Prince Dreven is a Darkfallen of the San'layn who sought to join the Horde. In order for Warchief Windrunner to accept the San'layn among them, they had to complete a mission." },
  ["blood watch peacekeeper"] = { 2, "', "Blood Watch Peacekeepers are draenei guards located in Blood Watch and Kessel's Crossing on Bloodmyst Isle." },
  ["blood-branded razorfen"] = { 2, "', "Blood-Branded Razorfens are quilboar located in Razorfen Kraul. They can spawn after triggering a Rope Trap." },
  ["blood-princess thal'ena"] = { 2, "daughter of Blood-Queen Lana'thel", "Blood-Princess Thal'ena is Darkfallen of the San'layn and a boss in Assault on Violet Hold. She is the daughter of Blood-Queen Lana'thel." },
  ["blood-queen lana'thel"] = { 2, "leader of the San'layn", "\"Lana'thel shed tears for the lives of the elven kin she expected to lose during their war march to Northrend. She had no idea at the time that she would be the cause of many more.\" Blood-Queen Lana'thel (/ˈlanəˌθɛl/ LAH-nə-thel) was the leader of..." },
  ["blood-queen lana'thel (tactics)"] = { 2, "leader of the San'layn", "Blood-Queen Lana'thel is the leader of the San'layn and a boss of the Icecrown Citadel raid. The fight is a cross between a very intense DPS race and a hellish battle for survival." },
  ["blood-thane lucard"] = { 2, "ancient vrykul vampyr", "Blood-Thane Lucard is an ancient vrykul vampyr who was buried by the Bonespeakers in the tomb of Dreyrgrot in Stormheim. He was interred alongside a number of cursed artifacts and stones of warning were put up to keep anyone from disturbing him." },
  ["bloodarmed tester"] = { 2, "', "Bloodarmed Testers are goblins located in the Venturewood in the Undermine." },
  ["bloodaxe evoker"] = { 2, "', "Bloodaxe Evokers are orcs found in Hordemar City in Lower Blackrock Spire. They are part of the Bloodaxe Legion and specialize in damage-dealing fire and arcane spells." },
  ["bloodaxe raider"] = { 2, "', "Bloodaxe Raiders are orcs located in Hordemar City and the Chamber of Battle in Lower Blackrock Spire." },
  ["bloodaxe summoner"] = { 2, "', "Bloodaxe Summoners are orcs located in Hordemar City in Blackrock Spire." },
  ["bloodaxe veteran"] = { 2, "', "Bloodaxe Veterans are orcs located in Hordemar City and the Chamber of Battle in Lower Blackrock Spire." },
  ["bloodaxe warmonger"] = { 2, "', "Bloodaxe Warmongers are orcs found in Hordemar City and the Storehouse in Lower Blackrock Spire." },
  ["bloodblade foreman"] = { 2, "', "Bloodblade Foremen are goblins located at Axefall in the Spires of Arak. They operate shredders." },
  ["bloodblade guard"] = { 2, "orc serving Azuka Bladefury", "Bloodblade Guard is an orc serving Azuka Bladefury." },
  ["bloodclaw (gnoll)"] = { 2, "gnoll located in Brackenhide Waterhole in the Azure Span", "Bloodclaw is a gnoll located in Brackenhide Waterhole in the Azure Span. He became a warboss right after a previous one was killed by an adventurer sent by Detry Hornswald." },
  ["bloodcleave"] = { 2, "orc located in Gorgrond", "Bloodcleave was an orc located in Gorgrond." },
  ["bloodcursed naga"] = { 2, "', "Bloodcursed Naga are naga found at Bloodcurse Isle and Wyrmscar Island in Bloodmyst Isle." },
  ["blooded bladefeather"] = { 2, "', "Blooded Bladefeathers are arakkoa located in the Lower Quarter in Skyreach." },
  ["bloodeye brute"] = { 2, "', "Bloodeye Brutes are ogres found at the Twilight Gate in the Twilight Highlands." },
  ["bloodeyes"] = { 2, "worgen located in Duskwood", "Bloodeyes is a worgen located in Duskwood. During the Fourth War, the residents of Duskwood had been plagued by this particularly ferocious member of the Nightbane pack." },
  ["bloodfang berserker"] = { 2, "', "Bloodfang Berserkers are members of the Bloodfang pack, who can be found at the Battlefront, constantly rushing the Forsaken forces located there during the Silverpine Forest storyline. Bloodfang Berserkers can be found in Shadowfang Keep as well." },
  ["bloodfang bloodletter"] = { 2, "', "Bloodfang Bloodletters are worgen located at the Military District in Gilneas. They share the same model as the Bloodfang Lurkers." },
  ["bloodfang forsaken hunter"] = { 2, "', "Bloodfang Forsaken Hunters are worgen found around the Ruins of Southshore in the Hillsbrad Foothills, attacking the Forsaken's dark rangers in packs. Helcular orders Horde players to aid the dark rangers by slaying Bloodfang Forsaken Hunters." },
  ["bloodfang lurker"] = { 2, "', "Bloodfang Lurkers are stealthed worgen that appear in the streets of the Military District in Gilneas City after the quest   [1-20] The Rebel Lord's Arsenal. They tend to be difficult to see, but thankfully players are given a mastiff for the ques..." },
  ["bloodfang mauler"] = { 2, "', "Bloodfang Maulers are worgen." },
  ["bloodfang ripper"] = { 2, "', "Bloodfang Rippers are worgen that show up in the second phase of the Military District of Gilneas City, after players complete the quest   [1-20] The Rebel Lord's Arsenal. They will chase you during the quest   [1-20] Save Krennan Aranas." },
  ["bloodfang scavenger"] = { 2, "', "Bloodfang Scavengers are worgen members of the Bloodfang pack located in North Tide's Beachhead in the Silverpine Forest. They are responsible for destroying two Orc battleships that arrived from Kalimdor to aid the Forsaken." },
  ["bloodfang scout"] = { 2, "', "Bloodfang Scouts are Bloodfang worgen located in the Ruins of Gilneas." },
  ["bloodfang sentry"] = { 2, "', "Bloodfang Sentries are Bloodfang worgen located on the Purgation Isle in Hillsbrad Foothills." },
  ["bloodfang stalker"] = { 2, "', "Bloodfang Stalkers are worgen stalkers of the Bloodfang pack in Silverpine Forest. They are part of the worgen force that ambushed a group of Forsaken troopers and catapults crossing Olsen's Farthing, destroying it." },
  ["bloodfang stalker (gilneas)"] = { 2, "', "Bloodfang Stalkers are worgen that can be found at the Cathedral Quarter and Greymane Court in Gilneas City during the starting questline for worgen players." },
  ["bloodfang stalkers"] = { 2, "', "Bloodfang Stalkers are worgen War Campaign troop units." },
  ["bloodfang worgen"] = { 2, "', "Bloodfang Worgen are worgen found around Stoneward Prison inside Gilneas City during the worgen invasion phase." },
  ["bloodfin forager"] = { 2, "', "Bloodfin Foragers are murlocs located in Nazjatar." },
  ["bloodfin hydromancer"] = { 2, "', "Bloodfin Hydromancers are murlocs located in the Bloodfin Village in Nazjatar. They will hunt those who bring about the Anger of the Bloodfin." },
  ["bloodfin murloc"] = { 2, "', "Bloodfin Murlocs are murlocs located in Nazjatar." },
  ["bloodfin oracle"] = { 2, "', "Bloodfin Oracles are murlocs located in Nazjatar." },
  ["bloodfin raider"] = { 2, "', "Bloodfin Raiders are murlocs located in Nazjatar." },
  ["bloodfin sentry"] = { 2, "', "Bloodfin Sentries are murlocs located in the Bloodfin Village in Nazjatar. They will hunt those who bring about the Anger of the Bloodfin." },
  ["bloodfin tadpole"] = { 2, "', "Bloodfin Tadpoles are murlocs located in the Bloodfin Village in Nazjatar. Bullying the tadpoles will bring about the Anger of the Bloodfin, which will cause Bloodfin Sentries and Bloodfin Hydromancers to hunt you for ten minutes." },
  ["bloodfin tidecaller"] = { 2, "', "Bloodfin Tidecallers are murlocs located in Nazjatar." },
  ["bloodfist basher"] = { 2, "', "Bloodfist Bashers are ogres located on Molten Cay." },
  ["bloodfist battlemaster"] = { 2, "', "Bloodfist Battlemasters are ogres located on Molten Cay." },
  ["bloodfist elementalist"] = { 2, "', "Bloodfist Elementalists are ogres located on Molten Cay." },
  ["bloodfist enforcer"] = { 2, "', "Bloodfist Enforcers are ogres located on Molten Cay." },
  ["bloodfist geomancer"] = { 2, "', "Bloodfist Geomancers are ogres located on Molten Cay." },
  ["bloodfist ogre"] = { 2, "', "Bloodfist Ogres are ogres located on Molten Cay." },
  ["bloodfist rockbinder"] = { 2, "', "Bloodfist Rockbinders are ogres located on Molten Cay." },
  ["bloodhilt earth-singer"] = { 2, "', "Bloodhilt Earth-Singers are orcs located at Lion's Landing in the Lion's Landing scenario." },
  ["bloodhilt grunt"] = { 2, "', "Bloodhilt Grunts are orcs located at Lion's Landing in the Lion's Landing scenario." },
  ["bloodhilt honor guard"] = { 2, "', "Bloodhilt Honor Guards are level 90 orcs found at Domination Point of Krasarang Wilds." },
  ["bloodhilt mauler"] = { 2, "', "Bloodhilt Maulers are tauren druids located at Lion's Landing in the Lion's Landing scenario." },
  ["bloodhilt raider"] = { 2, "', "Bloodhilt Raiders are orcs located at Lion's Landing in the Lion's Landing scenario." },
  ["bloodhilt wolf-sister"] = { 2, "', "Bloodhilt Wolf-Sisters are orcs located at Lion's Landing in the Lion's Landing scenario." },
  ["bloodhilt's rearguard"] = { 2, "orc mounted on wolf", "Bloodhilt's Rearguard is an orc mounted on wolf who accompanied the adventurer on Bloodhilt's Riding Wolf during in  [10-30] Desolation Hold Inspection." },
  ["bloodhoof villager"] = { 2, "', "Bloodhoof Villagers are tauren located in Bloodhoof Village in Mulgore during the Heritage of the Shu'halo." },
  ["bloodhorn"] = { 2, "tauren vendor located in Flayers' Point of Desolace", "Bloodhorn is a tauren vendor located in Flayers' Point of Desolace. She is an acquaintance of the captain of the Wavestrider, Greydon Thorne." },
  ["bloodied brave"] = { 2, "', "Bloodied Braves are tauren located in Toghusuq Village in the Ohn'ahran Plains." },
  ["bloodied slayer"] = { 2, "', "Bloodied Slayers are ogres found at the Gorian Proving Grounds in Nagrand." },
  ["bloodletter"] = { 2, "', "Bloodletters are undead that appear during  [15-30] The Battle of Darrowshire at Darrowshire in Eastern Plaguelands." },
  ["bloodmaul agent"] = { 2, "ogre located in the Circle of Blood in the Blade's Edge M...", "Bloodmaul Agent is an ogre located in the Circle of Blood in the Blade's Edge Mountains. He can sometimes be found talking to Mog'dorg the Wizened, after which he will run in the general direction of Grulloc before despawning." },
  ["bloodmaul brewmaster"] = { 2, "', "Bloodmaul Brewmasters are ogres found in most Bloodmaul holdings in the central canyon in the Blade's Edge Mountains. They become neutral once becoming neutral with Ogri'la." },
  ["bloodmaul brute"] = { 2, "', "Bloodmaul Brutes are ogres located in Frostfire Ridge. Some are found dead in Iceblister Den." },
  ["bloodmaul brute (blade's edge mountains)"] = { 2, "', "Bloodmaul Brutes are ogres located in Bloodmaul Ravine and Bloodmaul Outpost in the Blade's Edge Mountains. They become neutral once becoming neutral with Ogri'la." },
  ["bloodmaul drudger"] = { 2, "', "Bloodmaul Drudgers are ogres found in Draenethyst Mine in the Blade's Edge Mountains. They become neutral once becoming neutral with Ogri'la." },
  ["bloodmaul earthbreaker"] = { 2, "', "Bloodmaul Earthbreakers are ogres located in Bloodmaul Slag Mines." },
  ["bloodmaul enforcer"] = { 2, "', "Bloodmaul Enforcers are ogres located in Bloodmaul Slag Mines." },
  ["bloodmaul flamespeaker"] = { 2, "', "Bloodmaul Flamespeakers are ogres located in Bloodmaul Slag Mines." },
  ["bloodmaul forge-tender"] = { 2, "ogre", "Bloodmaul Forge-Tender was an ogre." },
  ["bloodmaul frostbender"] = { 2, "Lesser Icelings", "Bloodmaul Frostbenders are ogres located at the Stonefury Cliffs in Frostfire Ridge. They are utilizing frost magic, and are followed around by their elemental minions, the Lesser Icelings." },
  ["bloodmaul geomancer (bloodmaul slag mines)"] = { 2, "', "Bloodmaul Geomancers are ogres located in Bloodmaul Slag Mines." },
  ["bloodmaul geomancer (frostfire ridge)"] = { 2, "', "Bloodmaul Geomancers are ogres located at the Stonefury Cliffs in Frostfire Ridge. They are calling up Tamed Rockworms from the frozen earth." },
  ["bloodmaul gladiator"] = { 2, "', "Bloodmaul Gladiators are ogres located at the Stonefury Cliffs in Frostfire Ridge. They fight each other under the watchful eye of Rugrum the Pit Boss." },
  ["bloodmaul goon"] = { 2, "', "Bloodmaul Goons are Bloodmaul ogres that run up the tower to attack the player, after  [Bladespire Clan Banner] is placed, in Bloodmaul Outpost in Blade's Edge Mountains." },
  ["bloodmaul lookout"] = { 2, "', "Bloodmaul Lookouts are ogres located in the Blade's Edge Mountains." },
  ["bloodmaul magma binder"] = { 2, "', "Bloodmaul Magma Binders are ogres located in Bloodmaul Slag Mines." },
  ["bloodmaul magma shaper"] = { 2, "', "Bloodmaul Magma Shapers are ogres located at the Stonefury Cliffs in Frostfire Ridge. They are located just by the huge stream of lava flowing through the area." },
  ["bloodmaul mauler"] = { 2, "', "Bloodmaul Maulers are ogres found in Daggermaw Canyon and Bloodmaul Camp in the Blade's Edge Mountains. They become neutral once becoming neutral with Ogri'la." },
  ["bloodmaul ogre mage"] = { 2, "', "Bloodmaul Ogre Mages are ogres located in Bloodmaul Slag Mines." },
  ["bloodmaul overseer"] = { 2, "', "Bloodmaul Overseers are ogres located in Bloodmaul Slag Mines." },
  ["bloodmaul pit boss"] = { 2, "ogre located in Frostfire Ridge", "Bloodmaul Pit Boss is an ogre located in Frostfire Ridge." },
  ["bloodmaul shaman"] = { 2, "', "Bloodmaul Shaman are ogres located in Bloodmaul Ravine in the Blade's Edge Mountains. They become neutral once becoming neutral with Ogri'la." },
  ["bloodmaul skirmisher"] = { 2, "', "Bloodmaul Skirmishers are ogres located in Bloodmaul Ravine and Bloodmaul Outpost in the Blade's Edge Mountains. They become neutral once becoming neutral with Ogri'la." },
  ["bloodmaul slaver"] = { 2, "', "Bloodmaul Slavers are ogres located in Bloodmaul Slag Mines." },
  ["bloodmaul supplicant"] = { 2, "', "Bloodmaul Supplicants are ogres who appear outside the Circle of Blood when you become the King/Queen of the Ogres." },
  ["bloodmaul taskmaster"] = { 2, "', "Bloodmaul Taskmasters are ogres found in Daggermaw Canyon in Blade's Edge Mountains. They become neutral once becoming neutral with Ogri'la." },
  ["bloodmaul taskmaster (frostfire ridge)"] = { 2, "', "Bloodmaul Taskmasters are ogres located at the Stonefury Cliffs in Frostfire Ridge. They are abusing the Bloodmaul clan's slaves in the area." },
  ["bloodmaul warder"] = { 2, "', "Bloodmaul Warders are ogres located in Bloodmaul Slag Mines." },
  ["bloodmoon cultist"] = { 2, "', "Bloodmoon Cultists can be found on Bloodmoon Isle in the Grizzly Hills. Initially humans trappers of Silverbrook, they are now members of the Wolfcult." },
  ["bloodmoon servant"] = { 2, "', "Bloodmoon Servants are summoned during the battle with the Shade of Arugal. He first summons 3 of them, then 9, forcing his assailants to fight them while he waits patiently." },
  ["bloodmoon worgen"] = { 2, "', "Bloodmoon Worgen can be found on Bloodmoon Isle in the Grizzly Hills." },
  ["bloodring slaver"] = { 2, "', "Bloodring Slavers are ogres found at the Gorian Proving Grounds in Nagrand." },
  ["bloodrose"] = { 2, "gnome located at the Lunarfall in Shadowmoon Valley", "Bloodrose is a gnome located at the Lunarfall in Shadowmoon Valley. She can only be recruited using the Headhunter's Harvest from Lunarfall Inn." },
  ["bloodrose datura"] = { 2, "Darkfallen death knight", "Bloodrose Datura is a Darkfallen death knight and a quest giver located at Ebon Watch in Zul'Drak. The Knights of the Ebon Blade, of which she is a part, ordered her to stay put at the Ebon Watch." },
  ["bloodsail corsair (legion)"] = { 2, "', "Bloodsail Corsairs are pirates located in the Hall of Shadows, Booty Bay in the Cape of Stranglethorn, Azsuna, Deliverance Point on the Broken Shore, and on the Vindicaar." },
  ["bloodsail deckhand (legion)"] = { 2, "draenei located in the Hall of Shadows", "The Bloodsail Deckhand is a draenei located in the Hall of Shadows." },
  ["bloodsail pony plunderer"] = { 2, "', "Bloodsail Pony Plunderers are members of the Bloodsail Buccaneers who float around the southwestern edge of the Cape of Stranglethorn's Wild Shore atop inflatable pool ponies during Pirates' Day. Occasionally, two of the plunderers will start spla..." },
  ["bloodscale enchantress"] = { 2, "', "Bloodscale Enchantresses are naga located at the Bloodscale Enclave in Zangarmarsh." },
  ["bloodscale overseer"] = { 2, "', "Bloodscale Overseers are naga found at the Bloodscale Grounds in Zangarmarsh. If you aggro one of them, they will call a Wrekt Slave for help, which will attack you until the Bloodscale Overseer is killed." },
  ["bloodscale slavedriver"] = { 2, "', "Bloodscale Slavedrivers are naga located at the Bloodscale Enclave in Zangarmarsh. When aggroed, they call a Wrekt Slave to attack the attacker until the Slavedriver is killed." },
  ["bloodscale wavecaller"] = { 2, "', "Bloodscale Wavecallers are naga found at the Bloodscale Grounds in Zangarmarsh." },
  ["bloodseeker kilthix"] = { 2, "nerubian located in Skittering Hollow during Island Exped...", "Bloodseeker Kilthix is a nerubian located in Skittering Hollow during Island Expeditions." },
  ["bloodstained assistant"] = { 2, "', "Bloodstained Assistants are nerubians located at the Echoing Overlook in Ara-Kara, City of Echoes." },
  ["bloodstained webmage"] = { 2, "', "Bloodstained Webmages are nerubians located at the Echoing Overlook in Ara-Kara, City of Echoes. They also participate in the fight alongside Anub'zekt." },
  ["bloodstone (troll)"] = { 2, "jungle troll (or forest troll) fighter", "Bloodstone is a jungle troll (or forest troll) fighter and the head of the stables of the Arena in Stranglethorn Vale. Although his stables are full of mature teens and young adults ready to fight as well as several captured unwilling fighters, at..." },
  ["bloodthirsty adventurer"] = { 2, "', "Bloodthirsty Adventurer is located in Zaralek Cavern." },
  ["bloodthirsty crewman"] = { 2, "', "Bloodthirsty Crewmen are orcs found on Horde Airships in the Kul Tiras zones during Faction Assaults." },
  ["bloodthirsty worgen"] = { 2, "worgen", "Bloodthirsty Worgen is a worgen." },
  ["bloodtooth guard"] = { 2, "', "Bloodtooth Guards are furbolgs found in Bloodtooth Camp in Ashenvale." },
  ["bloodvenom post brave"] = { 2, "', "Bloodvenom Post Braves could be found at Bloodvenom Post in Felwood. After the Cataclysm, Winna Hazzard managed to transform all the inhabitants of Bloodvenom Post in Bloodvenom Slimeslaves, included all the Bloodvenom Post Braves." },
  ["bloodvenom slimeslave"] = { 2, "', "Bloodvenom Slimeslaves can be found at Bloodvenom Post in Felwood. They were the former inhabitants and guards of the Post, mutated by the experiments of Winna Hazzard." },
  ["bloodwake brawler"] = { 2, "', "Bloodwake Brawlers are vrykul located on Siren Isle." },
  ["bloodwake deathdealer"] = { 2, "', "Bloodwake Deathdealers are vrykul located on Siren Isle." },
  ["bloodwake harpooner"] = { 2, "', "Bloodwake Harpooners are vrykul located on the expedition isles." },
  ["bloodwake marauder"] = { 2, "', "Bloodwake Marauders are vrykul located on the expedition isles." },
  ["bloodwake mystic"] = { 2, "', "Bloodwake Mystics are vrykul located on the expedition isles." },
  ["bloodwake soothsayer"] = { 2, "', "Bloodwake Soothsayers are vrykul located on the expedition isles." },
  ["bloodwake spellslinger"] = { 2, "', "Bloodwake Spellslingers are vrykul located on Siren Isle." },
  ["bloodwake vrykul"] = { 2, "', "Bloodwake Vrykul are vrykul located on the expedition isles." },
  ["bloodwake warbringer"] = { 2, "', "Bloodwake Warbringers are vrykul located on the expedition isles." },
  ["bloodwake warmaiden"] = { 2, "', "Bloodwake Warmaidens are vrykul located on the expedition isles." },
  ["bloodwake wayfinder"] = { 2, "', "Bloodwake Wayfinders are vrykul located on the expedition isles." },
  ["bloodwash acolyte"] = { 2, "', "Bloodwash Acolytes are naga found in the Blasted Lands." },
  ["bloodwash barbarian"] = { 2, "', "Bloodwash Barbarians are naga found in the Red Reaches and Bloodwash Cavern in the Blasted Lands." },
  ["bloodwash enchantress"] = { 2, "', "Bloodwash Enchantresses are naga found in the Blasted Lands. They use blood magic." },
  ["bloodwash gambler"] = { 2, "', "Bloodwash Gamblers are level 56 - 57 naga found in the Blasted Lands." },
  ["bloodwash idolater"] = { 2, "', "Bloodwash Idolaters are level 56 - 57 naga found in the Blasted Lands." },
  ["bloodwash zealot"] = { 2, "', "Bloodwash Zealots are level 57 naga found in the Blasted Lands." },
  ["bloody war-singer"] = { 2, "orc", "Bloody War-Singer is an orc." },
  ["bloop"] = { 2, "murloc located at the Winterfin Retreat in the Borean Tundra", "Bloop is a murloc located at the Winterfin Retreat in the Borean Tundra." },
  ["blossom"] = { 2, "ram", "Blossom is a ram that was briefly befriended and named by Taryndrella south of Cliffwalker Post in the Stonetalon Mountains. Taryndralla asked him to get her and Aramar Thorne to Northwatch Expedition Base Camp." },
  ["bludsmirk"] = { 2, "Laughing Skull orc located at Trading Post in Frostwall", "Bludsmirk is a Laughing Skull orc located at Trading Post in Frostwall. He may travel to Barracks if they are built." },
  ["blue (dracthyr)"] = { 2, "dracthyr located in the Mage Quarter in Stormwind City", "Blue is a dracthyr located in the Mage Quarter in Stormwind City. She is found with Krenzen and Berkeley." },
  ["blue murloc egg"] = { 2, "blue baby murloc Companion", "The Blue Murloc Egg item teaches you to summon Murky, a blue baby murloc Companion. During BlizzCon 2005, cards with special codes were given out to attendees to obtain the Blue Murloc Egg in-game." },
  ["blue and gold murloc egg"] = { 2, "murloc companion", "The Blue and Gold Murloc Egg summons Flurky, a murloc companion. This pet is not available in retail World of Warcraft." },
  ["bluebell"] = { 2, "human stationed in Westguard Keep in Howling Fjord", "Bluebell is a human stationed in Westguard Keep in Howling Fjord. She has blue eyes." },
  ["bluegill copperblade"] = { 2, "', "Bluegill Copperblades are murlocs located in Loch Modan." },
  ["bluegill forager"] = { 2, "', "Bluegill Foragers are murlocs located in Bluegill Marsh in the Wetlands." },
  ["bluegill muckdweller"] = { 2, "', "Bluegill Muckdwellers are murlocs located in Bluegill Marsh in the Wetlands." },
