  ["bluewax cavewhisker"] = { 2, "', "Bluewax Cavewhiskers are Bluewax kobold miners and guards found around Candle Rock in Highmountain. Like the rest of the Bluewax, they are normally hostile but turn friendly while the player is wearing the  [Skull of Bossing Around], and neutral w..." },
  ["bluewax drumtaker"] = { 2, "', "Bluewax Drumtakers are kobolds located in Thunder Totem in Highmountain." },
  ["bluewax fishmonger"] = { 2, "kobold", "Bluewax Fishmonger is a kobold." },
  ["bluewax flamewick"] = { 2, "', "Bluewax Flamewicks are Bluewax kobolds found in Candle Rock in Highmountain. Like the rest of the Bluewax, they are normally hostile but turn friendly while the player is wearing the  [Skull of Bossing Around], and neutral while they have the 'Fri..." },
  ["bluewax gatekeeper"] = { 2, "Bluewax kobold guarding the entrance into the Candleking'...", "The Bluewax Gatekeeper is a Bluewax kobold guarding the entrance into the Candleking's inner sanctum in Candle Rock in Highmountain. He forces the adventurer to perform several minor tasks for the kobolds in the cavern before he allows them entran..." },
  ["bluewax graverobber"] = { 2, "', "Bluewax Graverobbersare Bluewax kobolds found around the Sepulcher of the Sky in Highmountain. Like the rest of the Bluewax, they are normally hostile but turn friendly while the player is wearing the  [Skull of Bossing Around], and neutral while ..." },
  ["bluewax guardian"] = { 2, "', "Bluewax Guardians are kobolds located in Highmountain." },
  ["bluewax ratcatcher"] = { 2, "', "Bluewax Ratcatchers are Bluewax kobolds wandering around inside Candle Rock in Highmountain accompanied by rat pets. Like the rest of the Bluewax, they are normally hostile but turn friendly while the player is wearing the  [Skull of Bossing Aroun..." },
  ["bluewax skullcaptain"] = { 2, "leader of the Bluewax kobolds raiding the Sepulcher of th...", "The Bluewax Skullcaptain is the leader of the Bluewax kobolds raiding the Sepulcher of the Sky in Highmountain. He is found inside a hut in the eastern part of the sepulcher." },
  ["bluff scout"] = { 2, "tauren", "Bluff Scout is a tauren." },
  ["bluffwatcher"] = { 2, "', "Those who visit the capital city of the tauren know better than to misbehave. Bluffwatchers are guards located throughout the tauren city of Thunder Bluff." },
  ["blythe (stromgarde)"] = { 2, "human of the Stromgarde Militia", "Blythe was a human of the Stromgarde Militia who fought against the Syndicate in Arathi Highlands. He fell and his badge was taken by his killer, kept as a trophy until its retrieval by hired adventurers." },
  ["bo (tuskarr)"] = { 2, "tuskarr child located in Iskaara in the Azure Span", "Bo is a tuskarr child located in Iskaara in the Azure Span." },
  ["bo bobble"] = { 2, "gnome", "Bo Bobble is a gnome who runs G.G. Engineering together with Max Megablast." },
  ["bo farplain"] = { 2, "tauren", "Bo Farplain is a tauren." },
  ["boarguts the impaler"] = { 2, "TCG character", "Boarguts the Impaler is a TCG character that appears on the following cards:" },
  ["boarmaster bragh"] = { 2, "dwarf", "Boarmaster Bragh is a dwarf and the stable master for Frosthold in the Storm Peaks." },
  ["bob bigheart"] = { 2, "dwarf character in Smokywood Pastures Presents: A Winter ...", "Bob Bigheart is a dwarf character in Smokywood Pastures Presents: A Winter Veil Carol. He is a scribe working at Scrounge's counting house." },
  ["boba"] = { 2, "tortollan located in Little Tortolla in Dazar'alor", "Boba is a tortollan located in Little Tortolla in Dazar'alor." },
  ["bobbin"] = { 2, "nerubian spiderling located in the Weaver's Lair in Azj-K...", "Bobbin is a nerubian spiderling located in the Weaver's Lair in Azj-Kahet." },
  ["bobby howlis"] = { 2, "brother of Jes Howlis", "Bobby Howlis is the brother of Jes Howlis that assists him in the heroic version of the encounter." },
  ["bobzle dinkbelt"] = { 2, "gnome located in Camp Nowhere in the Azure Span", "Bobzle Dinkbelt is a gnome located in Camp Nowhere in the Azure Span." },
  ["bodalf the strong"] = { 2, "vrykul", "Bodalf the Strong is a vrykul who can be encountered during Island Expeditions." },
  ["bodrin bloodhowl"] = { 2, "worgen death knight located at the Lunarfall in Shadowmoo...", "Bodrin Bloodhowl is a worgen death knight located at the Lunarfall in Shadowmoon Valley. He can only be recruited using the Headhunter's Harvest from Lunarfall Inn." },
  ["boduro the seeker"] = { 2, "Broken archaeology trainer located in the Lower City of S...", "Boduro the Seeker is a Broken archaeology trainer located in the Lower City of Shattrath City." },
  ["bog"] = { 2, "orc child", "Bog is an orc child." },
  ["bogdan"] = { 2, "venthyr located in Revendreth", "Bogdan is a venthyr located in Revendreth." },
  ["bogpaddle beach bum"] = { 2, "', "Bogpaddle Beach Bums can be found partying on the beach outside Bogpaddle in the Swamp of Sorrows, surrounding Brono Goodgroove." },
  ["bogpaddle beach bunny"] = { 2, "', "Bogpaddle Beach Bunnies are goblins found partying on the beach outside Bogpaddle in the Swamp of Sorrows, surrounding Brono Goodgroove." },
  ["bogpaddle bruiser"] = { 2, "', "Bogpaddle Bruisers are the guard NPCs at Trade Baron Silversnap's beachside resort, Bogpaddle in the Swamp of Sorrows. Like other Steamwheedle Cartel guards, they enforce the city's neutrality with their guns and their nets." },
  ["bogpaddle entertainer"] = { 2, "', "Bogpaddle Entertainers are goblins dancing on the bar in Bogpaddle in the Swamp of Sorrows." },
  ["bogpaddle privateer"] = { 2, "', "Bogpaddle Privateers are goblins located at Sorrowmurk and other goblin settlements in the Swamp of Sorrows." },
  ["bogpaddle worker"] = { 2, "', "Bogpaddle Workers are the goblin laborers of Bogpaddle in the Swamp of Sorrows." },
  ["bogrogg the stonescreamer"] = { 2, "drogbar", "Bogrogg the Stonescreamer is a drogbar and member of the Stonedark clan who appears in the Hall of Chieftains in Thunder Totem after completing  [10-45] Unexpected Allies. He offers instant transportation to the Stonedark Grotto in northern Highmo..." },
  ["bogruk"] = { 2, "ogre vendor located at the Highmaul in Nagrand", "Bogruk is an ogre vendor located at the Highmaul in Nagrand." },
  ["bohein"] = { 2, "tauren", "Bohein is a tauren that appeared in a short story of Magic & Mayhem." },
  ["bojsanz"] = { 2, "leader of the Heart's Guard during the War of the Scaleborn", "Bojsanz was the leader of the Heart's Guard during the War of the Scaleborn and a favored champion of Alexstrasza. Bojsanz slew Vyranoth's lieutenant Vitelenoth at Icewing Rift with the help of Stoltria, and alongside Levarian engaged in combat wi..." },
  ["boktar bloodfury"] = { 2, "orc quest giver of the Warsong Offensive located at Grom'...", "Boktar Bloodfury is an orc quest giver of the Warsong Offensive located at Grom'arsh Crash-Site in the Storm Peaks. Using Scout Vor'takh's information on Brann Bronzebeard he sends Horde adventurers to discover Brann's location in the Storm Peaks." },
  ["boku"] = { 2, "anxious centaur mystic of Clan Ohn'ir", "Boku, initially called Initiate Boku, is an anxious centaur mystic of Clan Ohn'ir and a quest giver in the Ohn'ahran Plains, first seen at the Ohn'ahran shrine in Teerakai." },
  ["bol'dar"] = { 2, "ogre located in the Grand Bazaar in Dazar'alor", "Bol'dar is an ogre located in the Grand Bazaar in Dazar'alor." },
  ["bolgaff"] = { 2, "rare dwarf found wandering outside the Forsaken Rear Guar...", "Bolgaff  is a rare dwarf found wandering outside the Forsaken Rear Guard in Silverpine Forest." },
  ["bolgar"] = { 2, "follower of the Twilight's Hammer", "Bolgar was a follower of the Twilight's Hammer who had purchased a copy of the book The Powers Below from Gerrig Bonegrip of Bonegrip's Runes and Dooms in Ironforge. He seems to have studied the book thoroughly in the year he owned it, writing not..." },
  ["bolgor"] = { 2, "gnome located in the Golden Keg in the Dwarven District o...", "Bolgor is a gnome located in the Golden Keg in the Dwarven District of Stormwind City." },
  ["bolik"] = { 2, "Captain of the Horde trading ship Orgath'ar", "Bolik was the Captain of the Horde trading ship Orgath'ar. A young orc, born in the human internment camp system, he felt that it was important to look as little like the slaves of old as possible, and groomed himself in a way very unusual for the..." },
  ["bolkar the cruel"] = { 2, "orc found torturing the caged Goldmane the Skinner at the...", "Bolkar the Cruel is an orc found torturing the caged Goldmane the Skinner at the top of the tower in Ironfist Harbor in Nagrand." },
  ["bolts"] = { 2, "pet mechanical squirrel of Fala Fizzlesprocket in the Smo...", "Bolts is the pet mechanical squirrel of Fala Fizzlesprocket in the Smokywood Storytime episode 'A Very Smokywood Winter Veil'. Fala's father Fritz made the squirrel for her as a birthday present." },
  ["bolvar fordragon (time rifts)"] = { 2, "alternate version of Bolvar Fordragon located in Tyrhold ...", "Bolvar Fordragon is an alternate version of Bolvar Fordragon located in Tyrhold Reservoir in Thaldraszus during Time Rifts. Held by ice chains, he needs to be freed from them." },
  ["bombardier gu'gok"] = { 2, "ogre located at Shattrath City in Talador", "Bombardier Gu'gok is an ogre located at Shattrath City in Talador." },
  ["bombus finespindle"] = { 2, "gnome leatherworking vendor located in the Great Forge in...", "Bombus Finespindle is a gnome leatherworking vendor located in the Great Forge in Ironforge." },
  ["bondaz"] = { 2, "earthen located at the Crossroads Plaza on the Isle of Dorn", "Bondaz is an earthen located at the Crossroads Plaza on the Isle of Dorn." },
  ["bone flayer"] = { 2, "orc", "Bone Flayer is an orc." },
  ["bonebolt hunter"] = { 2, "', "Bonebolt Hunters are gnolls located in the Azure Span." },
  ["bonebolt hunter (brackenhide hollow)"] = { 2, "', "Bonebolt Hunters are gnolls located at Lost Kanniak in Brackenhide Hollow." },
  ["bonechewer cannibal (wod)"] = { 2, "', "Bonechewer Cannibals are orcs." },
  ["bonechewer scavenger (wod)"] = { 2, "', "Bonechewer Scavengers are orcs." },
  ["bonegrim"] = { 2, "orc found in the Legerdemain Lounge in Dalaran", "Bonegrim is an orc found in the Legerdemain Lounge in Dalaran. When the Uncrowned secured the tavern during their search for Akaari Shadowgore, he was cowering in fear." },
  ["bonegrind the starved"] = { 2, "orc located at the Broken Horn Village in Gorgrond", "Bonegrind the Starved is an orc located at the Broken Horn Village in Gorgrond. Two Broken Horn Reavers are tending to him." },
  ["bonekeeper makiri"] = { 2, "troll", "Bonekeeper Makiri is a troll." },
  ["bonenose"] = { 2, "goblin located with two Booty Bay Buccaneers on the shore...", "Bonenose is a goblin located with two Booty Bay Buccaneers on the shore of the Waterspring Field, northwest of the Caverns of Time in eastern Tanaris. Alyx sent adventurers to check upon Bonenose and see if they need any assistance." },
  ["bonesaw"] = { 2, "orc fighting Iron Horde Grunts alongside many others at t...", "Bonesaw is an orc fighting Iron Horde Grunts alongside many others at the Dark Portal in Blasted Lands and Tanaan Jungle." },
  ["boneshaper jardak"] = { 2, "djaradin located in the Waking Shores", "Boneshaper Jardak is a djaradin located in the Waking Shores." },
  ["boneslag (ogre)"] = { 2, "ogre", "Boneslag  is an ogre that appears at Lunarfall and Frostwall. After building the level 3 Gladiator's Sanctum, you will have a quest giver come to the gates of your garrison." },
  ["bonespeaker carver"] = { 2, "', "Bonespeaker Carvers are vrykul located in Stormheim." },
  ["bonespeaker cleaver"] = { 2, "', "Bonespeaker Cleavers are vrykul found at Haustvald in Stormheim." },
  ["bonespeaker inkbinder"] = { 2, "', "Bonespeaker Inkbinders are vrykul located in Inkbinders Rise in Stormheim." },
  ["bonespeaker mystic"] = { 2, "', "Bonespeaker Mystics are vrykul found at Haustvald in Stormheim." },
  ["bonespeaker runeaxe"] = { 2, "', "Bonespeaker Runeaxes are vrykul located in Inkbinders Rise and Akstad in Stormheim." },
  ["bonespeaker soulbinder"] = { 2, "', "Bonespeaker Soulbinders are vrykul located in Trial of Valor." },
  ["boneweaver"] = { 2, "', "Six Boneweavers can be found in the Chamber of Summoning in Scholomance, summoning Woven Boneguards from the Bone Piles near them to attack Lilian Voss." },
  ["bongbong"] = { 2, "parrot of the goblin Krazzet", "Bongbong is a parrot of the goblin Krazzet, who won him in a bet against Flynn Fairwind." },
  ["bonks"] = { 2, "gnome located in Lunarfall", "Bonks was a gnome located in Lunarfall." },
  ["boog the 'gear whisperer'"] = { 2, "gnome first encountered enslaved by the Horde in Ashenval...", "Boog the 'Gear Whisperer' is a gnome first encountered enslaved by the Horde in Ashenvale near Silverwind Refuge. He is later found, after being saved, as a quest giver in Stonetalon Mountains." },
  ["bookkeeper mhewind"] = { 2, "earthen located at the Oath Gate in Dornogal", "Bookkeeper Mhewind is an earthen located at the Oath Gate in Dornogal." },
  ["boomboom brullingsworth"] = { 2, "top hat-", "Boomboom Brullingsworth is a top hat- and monocle-wearing drogbar who appears in the Stonedark Grotto in Highmountain to spectate the snail race between Zoom, Helix for Brains, Glip Gloop Haberdasher and Various and Sundry. As Boomboom's title sug..." },
  ["boomer"] = { 2, "', "Boomers are goblins playing golf at the Emerald Hills Golf Course in the Undermine." },
  ["boomhooch the lost"] = { 2, "goblin located in Thaldraszus", "Boomhooch the Lost is a goblin located in Thaldraszus. Talking to him summons The Weeping Vilomah." },
  ["booms"] = { 2, "elite Forsaken mob found on the southwestern side of Unga...", "Booms is an elite Forsaken mob found on the southwestern side of Unga Ingoo, Krasarang Wilds. Booms commands the powers of a shadow priest and is hostile to players of both factions." },
  ["boomshot specialist"] = { 2, "', "Boomshot Specialists are goblins located in Darkshore." },
  ["boomsy burnthrottle"] = { 2, "gnome located at the Gates of Ironforge in Dun Morogh", "Boomsy Burnthrottle is a gnome located at the Gates of Ironforge in Dun Morogh." },
  ["booraven"] = { 2, "Theramore soldier under Colonel Lorena", "Corporal Booraven was a Theramore soldier under Colonel Lorena. She was the rare case of a magic-sensitive human that could sniff out fel or arcane magic where the naked human eye couldn't." },
  ["bootlegger bruiser"] = { 2, "', "Bootlegger Bruisers are goblin guards located in Bootlegger Outpost in Tanaris. They appear when Alliance and Horde characters fight in the town." },
  ["boots"] = { 2, "goblin drink vendor located at Area 52 in the Netherstorm", "Boots is a goblin drink vendor located at Area 52 in the Netherstorm." },
  ["bootstrap blingbuckle"] = { 2, "goblin located at the Kelp'thar Forest in Vashj'ir", "Bootstrap Blingbuckle is a goblin located at the Kelp'thar Forest in Vashj'ir. He in one of the survivors the Horde encounters on its way." },
  ["booty bay bruiser"] = { 2, "', "Booty Bay Bruisers are goblins located in Booty Bay in the Cape of Stranglethorn. They defended the town when the Bloodsail Buccaneers attacked it." },
  ["booty bay buccaneer"] = { 2, "', "Booty Bay Buccaneers are a pair of goblins accompanying Bonenose at Waterspring Field in Tanaris." },
  ["booty bay elite"] = { 2, "', "Booty Bay Elites were goblin guards located in Booty Bay in the Cape of Stranglethorn during Stranglethorn Fishing Extravaganza." },
  ["booty bay reveler"] = { 2, "', "Booty Bay Revelers are goblins found in Booty Bay in the Cape of Stranglethorn during New Year and Midsummer Fire Festival part called Fireworks Spectacular." },
  ["boprul"] = { 2, "drogbar", "Boprul is a drogbar and a member of Hardrogg's band who occasionally appears in the Stonedark Grotto in Highmountain. As his name suggest, Boprul beats on 'Bop Rocks'." },
  ["bor"] = { 2, "mysterious entity mentioned throughout Northrend", "Bor is a mysterious entity mentioned throughout Northrend, mainly in the Storm Peaks near Frostborn territories and by the kvaldir." },
  ["bor'gorok battleguard"] = { 2, "', "Bor'gorok Battleguards are orc guards located in Bor'gorok Outpost in the Borean Tundra." },
  ["bor'gorok peon"] = { 2, "', "Bor'gorok Peons are orcs located in Bor'gorok Outpost in the Borean Tundra." },
  ["bor'zehn"] = { 2, "orc located at Ironstone Camp in Thousand Needles", "Bor'zehn is an orc located at Ironstone Camp in Thousand Needles. He seem to be member of the orcish war party led by Moktar Krin." },
  ["boraga"] = { 2, "orc under the command of Shargha", "Boraga was an orc under the command of Shargha. He discussed the world's state of affairs with his commander." },
  ["boragg"] = { 2, "drogbar located in Zaralek Cavern", "Boragg is a drogbar located in Zaralek Cavern." },
  ["boralus trader"] = { 2, "', "Boralus Trader are humans and goblins located in Boralus and in Tiragarde Sound." },
  ["borand"] = { 2, "orc bow vendor located in Sun Rock Retreat in the Stoneta...", "Borand is an orc bow vendor located in Sun Rock Retreat in the Stonetalon Mountains." },
  ["bordok"] = { 2, "ogre of the Gordunni clan", "Bordok was an ogre of the Gordunni clan and a part of Wordok's group. He was killed by Makasa Flintwill in Feralas." },
  ["bordos"] = { 2, "draenei blacksmithing supplies vendor located in Talador", "Bordos is a draenei blacksmithing supplies vendor located in Talador." },
  ["bored custodian"] = { 2, "', "Bored Custodians are goblins located at Slam Central Station in Undermine." },
  ["bored student"] = { 2, "', "Bored Students can be found in the Viewing Room of Scholomance." },
  ["bored teenager"] = { 2, "', "Bored Teenagers are goblins located in Undermine, in Less-4-More" },
  ["bored traveller"] = { 2, "goblin located at Slam Central Station in Undermine", "The Bored Traveller is a goblin located at Slam Central Station in Undermine." },
  ["borgal doomfist"] = { 2, "single-headed ogre mage serving as the Bloodmaul clan's c...", "Borgal Doomfist is a single-headed ogre mage serving as the Bloodmaul clan's chieftain in Frostfire Ridge. While he only appears during the Garrison Campaign, his minions can be found around the Bloodmaul Stronghold." },
  ["borginn darkfist"] = { 2, "rare mogu located in a Zandalari camp near the Valley of ...", "Borginn Darkfist is a rare mogu located in a Zandalari camp near the Valley of Emperors in Kun-Lai Summit. Borginn Darkfist is a pandarian champion." },
  ["borgl the seeker"] = { 2, "murloc of the Muckfin tribe ecountred in Island Expeditions", "Borgl the Seeker is a murloc of the Muckfin tribe ecountred in Island Expeditions." },
  ["borgos"] = { 2, "earthen blacksmithing vendor located in the Forgegrounds ...", "Borgos is an earthen blacksmithing vendor located in the Forgegrounds in Dornogal." },
  ["boris brightbeard"] = { 2, "dwarven priest", "Boris Brightbeard is a dwarven priest that once fought Onyxia in her lair." },
  ["boroughbreaker stik'kar"] = { 2, "nerubian spiderlord located on the Isle of Dorn", "Boroughbreaker Stik'kar is a nerubian spiderlord located on the Isle of Dorn." },
  ["borstan"] = { 2, "orc meat vendor located in the Drag in Orgrimmar", "Borstan is an orc meat vendor located in the Drag in Orgrimmar. This section concerns content related to Legion." },
  ["bort"] = { 2, "orc quest giver located on the Orgrimmar Skyway", "Bort was an orc quest giver located on the Orgrimmar Skyway. He has sent with Cromula to recruit Horde adventurers to aid in the defense of Grom'gol Base Camp in Northern Stranglethorn." },
  ["bort fizzwaggle"] = { 2, "gnome mage", "Bort Fizzwaggle is a gnome mage that was eaten by Meatball, a gnoll encounter in the Brawler's Guild. After Meatball's defeat, the gnome is freed." },
  ["bortega"] = { 2, "orc reagents", "Bortega is an orc reagents and poison vendor located in the Caverns of Time in Tanaris." },
  ["borto"] = { 2, "Broken trade goods vendor located at Telaar in Nagrand", "Borto is a Broken trade goods vendor located at Telaar in Nagrand." },
  ["borus"] = { 2, "draenei vendor located at the Twilight Glade in Shadowmoo...", "Borus is a draenei vendor located at the Twilight Glade in Shadowmoon Valley." },
  ["borya"] = { 2, "orc tailoring vendor located in Magar's Cloth Goods in th...", "Borya is an orc tailoring vendor located in Magar's Cloth Goods in the Drag in Orgrimmar. This section concerns content related to Mists of Pandaria." },
  ["boscoe"] = { 2, "goblin located at the Llothien Highlands in Azsuna", "Boscoe is a goblin located at the Llothien Highlands in Azsuna. Together with Rungle, he flies Boscoe and Rungle's Sky Chariot." },
  ["bosh"] = { 2, "earthen located in Gundargaz in the Ringing Deeps", "Bosh is an earthen located in Gundargaz in the Ringing Deeps." },
  ["boss bazzelflange"] = { 2, "goblin", "Boss Bazzelflange is a goblin who is in charge of the Brawl'gar Arena in Orgrimmar. She can also be found in Area 52." },
  ["boss blastmouth"] = { 2, "goblin located in the Bilgewater Bonanza in Zuldazar", "Boss Blastmouth is a goblin located in the Bilgewater Bonanza in Zuldazar." },
  ["boss copperplug"] = { 2, "goblin located inside the Boulder Lode Mine in Northern B...", "Boss Copperplug is a goblin located inside the Boulder Lode Mine in Northern Barrens. He was once the best engineer of the Tinkers' Union before he defected to the Venture Company and took his greatest techniques with him." },
  ["boss grog'ak"] = { 2, "overseer of the Ango'rosh mushroom-cutting operation foun...", "Boss Grog'ak is the overseer of the Ango'rosh mushroom-cutting operation found at the Hewn Bog in Zangarmarsh." },
  ["boss whalebelly"] = { 2, "tuskarr located in Azsuna", "Boss Whalebelly is a tuskarr located in Azsuna." },
  ["boss whiskerlash"] = { 2, "kobold located in the Chittering Den in the Ringing Deeps", "Boss Whiskerlash is a kobold located in the Chittering Den in the Ringing Deeps. He has three undercrawler pets, Bileweb, Rankfang, and Kriksi." },
  ["bosun moruk"] = { 2, "tuskarr located in Whaler's Nook in the Azure Span", "Bosun Moruk is a tuskarr located in Whaler's Nook in the Azure Span." },
  ["bot-specialist alley"] = { 2, "goblin located at the Ruins of Enkaat in the Netherstorm", "Bot-Specialist Alley is a goblin located at the Ruins of Enkaat in the Netherstorm." },
  ["botaan"] = { 2, "last of the three final Sporemounds faced by Grond", "Botaan was the last of the three final Sporemounds faced by Grond, the other two being Naanu and Zang. It was covered with primal forestlands." },
  ["botanist om'koi"] = { 2, "broker", "Botanist Om'koi is a broker who can be found attempting to work on a console in Eco-Dome: Primus in K'aresh." },
  ["botanist om'kork"] = { 2, "broker", "Botanist Om'kork is a broker who can be found overseeing Botanist Om'koi's attempts to work on a console in Eco-Dome: Primus in K'aresh." },
  ["botanist om'lin"] = { 2, "broker located at the Atrium on K'aresh", "Botanist Om'lin is a broker located at the Atrium on K'aresh." },
  ["bouldaz"] = { 2, "earthen located near the Thunder Bluff lift", "Bouldaz is an earthen located near the Thunder Bluff lift." },
  ["boulder'mok brute"] = { 2, "', "Boulder'mok Brutes are ogres located in Raven's Wood in Blade's Edge Mountains." },
  ["boulder'mok chieftain"] = { 2, "ogre found in the Blade's Edge Mountains", "Boulder'mok Chieftain is an ogre found in the Blade's Edge Mountains." },
  ["bouldercrag the rockshaper"] = { 2, "leader of the earthen from Ulduar", "Bouldercrag the Rockshaper is the leader of the earthen from Ulduar. He led them to safety after Loken and his iron dwarf army took over Ulduar, and forced the earthen out." },
  ["boulderfist brute"] = { 2, "', "Boulderfist Brutes are ogres of the Boulderfist clan. They can be found in the southern part of the Arathi Highlands." },
  ["boulderfist brute (plunderstorm)"] = { 2, "', "Boulderfist Brute are ogres located in Boulderfist Hall in the Arathi Highlands during Plunderstorm." },
  ["boulderfist crusher"] = { 2, "', "Boulderfist Crushers are ogres found at the Burning Blade Ruins in Nagrand. Killing these will earn you +10 to Kurenai/Mag'har faction." },
  ["boulderfist enforcer"] = { 2, "', "Boulderfist Enforcers are ogres of the Boulderfist found inside Boulder'gor in the Arathi Highlands." },
  ["boulderfist hunter"] = { 2, "', "Boulderfist Hunters are ogres found near the Alliance town of Telaar in Nagrand." },
  ["boulderfist invader"] = { 2, "', "Boulderfist Invaders are ogres found throughout the Bleeding Hollow Ruins in Terokkar Forest. A pair are found dancing for the amusement of Unkor the Ruthless." },
  ["boulderfist lord"] = { 2, "', "Boulderfist Lords are ogres of the Boulderfist tribe. They can be found inside Stromgarde Keep in the Arathi Highlands." },
  ["boulderfist magus (plunderstorm)"] = { 2, "', "Boulderfist Magi are ogres located in Boulderfist Hall in the Arathi Highlands during Plunderstorm." },
  ["boulderfist mauler"] = { 2, "', "Boulderfist Maulers are ogres found in Stromgarde Keep in the Arathi Highlands. Turn right before heading up the ramp to the keep itself, then turn left in the next passage." },
  ["boulderfist ogre"] = { 2, "', "Boulderfist Ogres are ogres of the Boulderfist clan found inside and around Boulder'gor in the Arathi Highlands." },
  ["boulderfist ogre (anniversary)"] = { 2, "', "Boulderfist Ogre is one of Whizbang's minions summoned from an Ominous Portal during Hearthstone's 10th Anniversary at the event locations in Valdrakken, Stormwind City, and Durotar." },
  ["boulderfist saboteur"] = { 2, "', "Boulderfist Saboteur are ogres located in Laughing Skull Ruins in Nagrand. Several of them spawn during  [15-30] Body of Evidence." },
  ["boulderfist shaman"] = { 2, "', "Boulderfist Shaman are ogres found in Stromgarde Keep in the Arathi Highlands. Turn right before heading up the ramp to the keep itself, then turn left in the next passage." },
  ["boulderfist warlock"] = { 2, "', "Boulderfist Warlocks are ogres located in Boulderfist Hall in the Arathi Highlands during Plunderstorm. They are accompanied by Boulderfist Imps." },
  ["boulderfist warrior"] = { 2, "', "Boulderfist Warriors can be found in the Northwind Cleft and Southwind Cleft of the Halaani Basin in Nagrand. Killing these will earn you +10 to Kurenai/Mag'har faction." },
  ["boulderslide geomancer"] = { 2, "', "Boulderslide Geomancers are kobolds found at Boulderslide Cavern in Stonetalon Mountains." },
  ["boulderslide rock keeper"] = { 2, "', "Boulderslide Rock Keepers can be found at Boulderslide Cavern in Stonetalon Mountains." },
  ["boulderslide stonepounder"] = { 2, "', "Boulderslide Stonepounders can be found at Boulderslide Cavern in Stonetalon Mountains." },
  ["bountiful feast hostess"] = { 2, "', "These hostesses can be found during the Pilgrim's Bounty seasonal event near the Bountiful Tables, not only near the main cities, but also at the villages where these tables are present. They give an explanation of how the tables work and offer a ..." },
  ["bounty hunter ta'oku"] = { 2, "broker located at Transfer Station Ta in Bastion", "Bounty Hunter Oku is a broker located at Transfer Station Ta in Bastion. Al'dalil and a Maw Walker in their quest to go to Tazavesh, the Veiled Market were directed to Ta'oku by Ta'nla the Identifier." },
  ["bowe dawnhorn"] = { 2, "tauren held in a Quilboar Cage in Mulgore", "Bowe Dawnhorn was a tauren held in a Quilboar Cage in Mulgore." },
  ["boxey boltspinner"] = { 2, "gnome found on the Brewfest Grounds outside Ironforge in ...", "Boxley Boltspinner is a gnome found on the Brewfest Grounds outside Ironforge in Dun Morogh." },
  ["boxi"] = { 2, "tortollan located at the Seekers' Vista in Stormsong Valley", "Boxi is a tortollan located at the Seekers' Vista in Stormsong Valley. He will appear to welcome the adventurer during the completion of  [30-60] Battle Victorious and  [50WQ] Turtle Tactics." },
  ["boxie"] = { 2, "goblin located in Cartelagio at the Grand Bazaar in Dazar...", "Boxie is a goblin located in Cartelagio at the Grand Bazaar in Dazar'alor. She is a bodyguard of Moxie Dealracket alongside her sister Noxie, watching over Gazrix Gearlock's Steamwheedle crew." },
  ["bozzil boomcrank"] = { 2, "goblin located at the Ruins of Na'gwa in Nagrand", "Bozzil Boomcrank is a goblin located at the Ruins of Na'gwa in Nagrand. He got his face melted off by Xelganak." },
  ["bozzle blastbolt"] = { 2, "', "Bozzle Blastbolt and his brother Bezzle were a couple of the goblins hired to help construct the Crusaders' Coliseum in Icecrown. After it was completed, they no longer had a job and now hang around the bar drinking." },
  ["bozzle blastinfuse"] = { 2, "goblin flight master located at Bozzle's Wreck at the Isl...", "Bozzle Blastinfuse is a goblin flight master located at Bozzle's Wreck at the Isle of Giants. His Alliance counterpart is Beeble Sockwrench." },
  ["bozzle blastrap"] = { 2, "goblin", "Bozzle Blastrap is a goblin." },
  ["brack"] = { 2, "rare mob murloc found patrolling the Longshore coastline ...", "Brack is a rare mob murloc found patrolling the Longshore coastline in Westfall together with Slark. He runs quickly, so catching him without pulling any of his murloc friends can be difficult." },
  ["bracken warscourge"] = { 2, "', "Bracken Warscourges are gnolls located at Lost Kanniak in Brackenhide Hollow." },
  ["brackenhide announcer"] = { 2, "gnoll located in Brackenhide Waterhole in the Azure Span", "Brackenhide Announcer is a gnoll located in Brackenhide Waterhole in the Azure Span." },
  ["brackenhide blackfeather"] = { 2, "', "Brackenhide Blackfeathers are gnolls located in the Codex of Chromie." },
  ["brackenhide carrion caller"] = { 2, "', "Brackenhide Carrion Callers are gnolls located in the Codex of Chromie." },
  ["brackenhide deadeye"] = { 2, "', "Brackenhide Deadeyes are gnolls located in Brackenhide Outskirts in the Azure Span." },
  ["brackenhide devourer"] = { 2, "', "Brackenhide Devourers are gnolls located in the Codex of Chromie." },
  ["brackenhide putrifier"] = { 2, "', "Brackenhide Putrifiers are gnolls located in Brackenhide Brambles in the Azure Span." },
  ["brackenhide rotflinger"] = { 2, "', "Brackenhide Rotflingers are gnolls located in Brackenhide Brambles in the Azure Span." },
  ["brackenhide scavenger"] = { 2, "', "Brackenhide Scavengers are gnolls located in the Codex of Chromie." },
  ["brackenhide scrapper"] = { 2, "', "Brackenhide Scrappers are gnolls located in Brackenhide Outskirts in the Azure Span." },
  ["brackenhide spectator"] = { 2, "', "Brackenhide Spectators are gnolls located in Brackenhide Waterhole in the Azure Span." },
  ["brackenwall enforcer"] = { 2, "', "Brackenwall Enforcers are ogres of the Stonemaul clan with red tattoos and clothing that guard and protect Brackenwall Village in the northeast Dustwallow Marsh. These guards are equipped with large maces." },
  ["bradok"] = { 2, "', "Bradok was one of the first dragon riders of the Dragonmaw clan during the Second War. He noticed Gul'dan's fleet sailing for the Tomb of Sargeras, and went to discover why he had abandoned his post at Quel'Thalas and set out onto the Great Sea." },
  ["bradrula"] = { 2, "earthen located in the Fissure in Dornogal", "Bradrula is an earthen located in the Fissure in Dornogal." },
  ["bradshaw"] = { 2, "old Gilnean human", "Bradshaw is an old Gilnean human who during the worgen attack on the kingdom was writing a journal about the events transpiring in Stormglen Village. While the rest of the town left for Tempest's Reach, Bradshaw stayed." },
  ["brae"] = { 2, "draenei located at Elodor in Shadowmoon Valley", "Brae is a draenei located at Elodor in Shadowmoon Valley." },
  ["bragdur battlebrew"] = { 2, "dwarf located in the Artisan's Market in Valdrakken", "Bragdur Battlebrew is a dwarf located in the Artisan's Market in Valdrakken." },
  ["bragok"] = { 2, "goblin flight master located at Ratchet in Northern Barrens", "Bragok is a goblin flight master located at Ratchet in Northern Barrens." },
  ["bragor bloodfist"] = { 2, "orc originally assigned by Thrall to guard the Undercity", "Bragor Bloodfist is an orc originally assigned by Thrall to guard the Undercity." },
  ["bragund brightlink"] = { 2, "dwarf mail armor vendor located in the Eventide in Dalara...", "Bragund Brightlink was a dwarf mail armor vendor located in the Eventide in Dalaran inside Langrom's Leather & Links. He sells the Tier 7 and Tier 8 armor pieces for shamans, death knights and hunters, as well as some other mail armor." },
  ["brahnmar"] = { 2, "dwarf armor vendor located in Menethil Harbor in the Wetl...", "Brahnmar is a dwarf armor vendor located in Menethil Harbor in the Wetlands." },
  ["brak blusterpipe"] = { 2, "goblin located at Nozzlepot's Outpost in the Northern Bar...", "Brak Blusterpipe is a goblin located at Nozzlepot's Outpost in the Northern Barrens. He seeks the  [Cats Eye Emerald] held by one of the miners in Venture Company's Boulder Lode mine located just northeast from the outpost." },
  ["brakh"] = { 2, "earthen located in the Forgegrounds in Dornogal", "Brakh is an earthen located in the Forgegrounds in Dornogal." },
  ["brakkar"] = { 2, "orc wind rider flight master located at Bloodvenom Post i...", "Brakkar is an orc wind rider flight master located at Bloodvenom Post in Felwood." },
  ["brakor"] = { 2, "legendary orc hero of the Thunderlord clan in ancient times", "Brakor was a legendary orc hero of the Thunderlord clan in ancient times, when they were still enslaved by the ogres of Frostfire. He wielded the legendary spear  [Gronnsbane], which was blessed by the elements and beasts of the land, but which lo..." },
  ["brammold deepmine"] = { 2, "dwarf heirloom vendor located in Dalaran", "Brammold Deepmine was a dwarf heirloom vendor located in Dalaran." },
  ["brandal darkbeard"] = { 2, "dwarf located in Boralus", "Brandal Darkbeard is a dwarf located in Boralus." },
  ["brandolf"] = { 2, "vrykul located at Jandvik in Suramar", "Brandolf is a vrykul located at Jandvik in Suramar. Brandolf can first be found guarding the body of Jarl Throndyr from attacking Naga." },
  ["brandon buckbeard"] = { 2, "dwarf located at the Legerdemain Lounge in Dalaran", "Brandon Buckbeard was a dwarf located at the Legerdemain Lounge in Dalaran. This section concerns content related to The War Within." },
  ["brangrimm"] = { 2, "earthen reagent & poison vendor located at Bouldercrag's ...", "Brangrimm is an earthen reagent & poison vendor located at Bouldercrag's Refuge in the Storm Peaks. He is an Ulduar earthen, and as such is friendly to both the Alliance and the Horde." },
  ["brann bronzebeard"] = { 2, "youngest of the three Bronzebeard brothers", "Brann Bronzebeard is the youngest of the three Bronzebeard brothers, with Magni and Muradin being his elders. A noted dwarven historian and veteran of the Second War, Brann is the leader and an active member of the Explorers' League, following clo..." },
  ["branor broadbraw"] = { 2, "dwarf of the Dragonscale Expedition located in the Azure ...", "Branor Broadbraw is a dwarf of the Dragonscale Expedition located in the Azure Span. He asks adventurers to find his assistant Lukh Rockrunner so that they can continue traveling to Three-Falls Lookout." },
  ["branzlit"] = { 2, "', "Branzlit is, along with Kixa, Perixa and Rilgiz one of four bankers in the Bank of Orgrimmar which is located in the Valley of Strength of Orgrimmar. This section concerns content related to Mists of Pandaria." },
  ["brashtide crewman"] = { 2, "', "Brashtide Crewmen are worgen of the Brashtide Crew that briefly attacked Booty Bay." },
  ["brashtide raider"] = { 2, "', "Brashtide Raiders are worgen pirates that attack Booty Bay during the Bloodsail Buccaneers storyline." },
  ["brashtide sot"] = { 2, "', "Brashtide Sots are worgen of the Brashtide Crew that briefly attacked Booty Bay." },
  ["bratu"] = { 2, "Aldor draenei warrior trainer located at the Terrace of L...", "Bratu is an Aldor draenei warrior trainer located at the Terrace of Light in Shattrath City." },
  ["braug dimspirit"] = { 2, "tauren shaman located just southeast of the Talondeep Pat...", "Braug Dimspirit is a tauren shaman located just southeast of the Talondeep Path in the Stonetalon Mountains." },
  ["brave chuata"] = { 2, "tauren", "Brave Chuata is a tauren." },
  ["brave cloudmane"] = { 2, "tauren guard located in Bloodhoof Village in Mulgore", "Brave Cloudmane is a tauren guard located in Bloodhoof Village in Mulgore. He can provide directions to various locations." },
  ["brave darksky"] = { 2, "tauren guard located in Bloodhoof Village in Mulgore", "Brave Darksky is a tauren guard located in Bloodhoof Village in Mulgore. He can provide directions to various locations." },
  ["brave dawneagle"] = { 2, "tauren guard located in Bloodhoof Village in Mulgore", "Brave Dawneagle is a tauren guard located in Bloodhoof Village in Mulgore. She can provide directions to various locations." },
  ["brave greathoof"] = { 2, "tauren found in Red Cloud Mesa in Mulgore", "Brave Greathoof is a tauren found in Red Cloud Mesa in Mulgore. He is one of several guards that protect the tauren starting area." },
  ["brave researcher"] = { 2, "Waking Shores", "Brave Researchers are members of the Dragonscale Expedition located at the Dranosh'ar Blockade in Durotar, Stormwind Harbor in Stormwind City, the Waking Shores, and Ohn'ahran Plains." },
  ["brawl enthusiast"] = { 2, "', "Brawl Enthusiasts are located in Brawl'gar Arena. They can get angry." },
  ["brawl'gar arena grunt"] = { 2, "orc located in Brawl'gar Arena", "Brawl'gar Arena Grunts is an orc located in Brawl'gar Arena. To start a fight in the arena, speak with them." },
  ["brawler otaka"] = { 2, "ankoan of the Waveblade clan", "Brawler Otaka was an ankoan of the Waveblade clan. Otaka's fists spoke as loud as her words and silenced the boasts of Azshara's brutes." },
  ["brawler outcast"] = { 2, "', "Brawler Outcasts are ogres found immediately south of the Gorian Proving Grounds in Nagrand." },
  ["brawn (npc)"] = { 2, "orc leatherworking trainer located in Grom'gol Base Camp ...", "Brawn is an orc leatherworking trainer located in Grom'gol Base Camp in Northern Stranglethorn." },
  ["brazie the botanist"] = { 2, "goblin quest giver located at Brazie Farmstead in Hillsbr...", "Brazie the Botanist is a goblin quest giver located at Brazie Farmstead in Hillsbrad Foothills." },
  ["breaker ritualist (fel)"] = { 2, "', "Breaker Ritualists are ogres located in Chamber of Nullification in Highmaul assisting Ko'ragh." },
  ["breaker ritualist (fire)"] = { 2, "', "Breaker Ritualists are ogres located in Chamber of Nullification in Highmaul assisting Ko'ragh." },
  ["breaker ritualist (frost)"] = { 2, "', "Breaker Ritualists are ogres located in Chamber of Nullification in Highmaul assisting Ko'ragh." },
  ["breanni"] = { 2, "neutral gnome pet supplies vendor located in the Magical ...", "Breanni, one of the world's foremost collectors of exotic pets, is a neutral gnome pet supplies vendor located in the Magical Menagerie store in Dalaran. She also mails players pets awarded by completing achievements or by purchasing pets or mount..." },
  ["breck rockbrow"] = { 2, "flight master located at Bouldercrag's Refuge in the Stor...", "Breck Rockbrow is a flight master located at Bouldercrag's Refuge in the Storm Peaks. He is an Earthen of Ulduar and as such is friendly to both the Alliance and the Horde." },
  ["breek"] = { 2, "earthen located in the Forgegrounds in Dornogal", "Breek is an earthen located in the Forgegrounds in Dornogal." },
  ["breem"] = { 2, "earthen flight master located in Dornogal", "Breem is an earthen flight master located in Dornogal." },
  ["bregg coppercast"] = { 2, "dwarf vendor located at the Stormshield in Ashran", "Bregg Coppercast is a dwarf vendor located at the Stormshield in Ashran." },
  ["brekk"] = { 2, "swolbold located in the Chittering Den in the Ringing Deeps", "Brekk is a swolbold located in the Chittering Den in the Ringing Deeps. He is a member of the Glumtooth Gang." },
  ["brelnor battlebrew"] = { 2, "dwarf located in Dun Morogh during Brewfest", "Brelnor Battlebrew is a dwarf located in Dun Morogh during Brewfest." },
  ["brena"] = { 2, "chieftain of the Iskaara tribe of tuskarr located in Iska...", "Brena is the chieftain of the Iskaara tribe of tuskarr located in Iskaara in the Azure Span. She succeeded Ponoliak as chieftain, who used to be her mentor." },
  ["brendormi"] = { 2, "dracthyr quartermaster of the Storm's Fury event in the P...", "Brendormi is a dracthyr quartermaster of the Storm's Fury event in the Primalist Future of Thaldraszus. She ends  [70] Coalesced Storm Remnants, part of the introduction quests." },
  ["brennok"] = { 2, "earthen Compiler located in the Ringing Deeps", "Brennok is an earthen Compiler located in the Ringing Deeps." },
  ["brett the bomber"] = { 2, "goblin quest giver located at the Krazzworks in the Twili...", "Brett the Bomber is a goblin quest giver located at the Krazzworks in the Twilight Highlands." },
  ["bretta the bold"] = { 2, "vrykul located at Skold-Ashil in Stormheim", "Bretta the Bold is a vrykul located at Skold-Ashil in Stormheim. Along with Silent Shale, Froijla Axebearer and Lafayla Mightblade; they wish to challenge the champion of Odyn in single combat." },
  ["breuuer"] = { 2, "draenei", "Breuuer is a draenei that roams the Lunarfall garrison." },
  ["brew master aldryr"] = { 2, "boss in Cinderbrew Meadery", "Brew Master Aldryr is a boss in Cinderbrew Meadery." },
  ["brew specialist"] = { 2, "', "Brew Specialists are dwarves and orcs located next to the Brew Barrel in Dun Morogh and Durotar during the Brewfest holiday." },
  ["brew vendor"] = { 2, "', "Brew Vendors sell the beers players get from the Brew of the Month Club. You get one sample beer mailed to you each month, and you can buy additional beers from this vendor, but only for the current month." },
  ["brewer gurta"] = { 2, "earthen located in Gundargaz in the Ringing Deeps", "Brewer Gurta is an earthen located in Gundargaz in the Ringing Deeps." },
  ["brewer kreztar"] = { 2, "earthen located in the Proscenium on the Isle of Dorn", "Brewer Kreztar is an earthen located in the Proscenium on the Isle of Dorn." },
  ["brewfest celebrant"] = { 2, "', "Brewfest Celebrants are located in various areas of Valdrakken as well as the taverns of the Dragon Isles during Brewfest." },
  ["brewfest reveler"] = { 2, "', "Brewfest Revelers are partygoers of all different races of the Brewfest that can be found at the Brewfest festival and parties in Dun Morogh, Durotar, Elwynn Forest, Eversong Woods and Undercity during the Brewfest holiday. Drunken Brewfest Revele..." },
  ["brewfest setup crew"] = { 2, "', "Brewfest Setup Crew are workers who set up Brewfest Grounds in Durotar and Dun Morogh." },
  ["brewfest setup crewman"] = { 2, "', "Brewfest Setup Crewmen are workers from several races who set up Brewfest Grounds in Durotar and Dun Morogh." },
  ["brewfest spy"] = { 2, "dwarven spy found in the Grim Guzzler of Blackrock Depths...", "The Brewfest Spy was a dwarven spy found in the Grim Guzzler of Blackrock Depths during the Brewfest holiday." },
  ["brewhunter"] = { 2, "', "Brewhunters were dwarves located near a farm on the Wandering Isle." },
  ["brewmeister bilger"] = { 2, "dwarf located in Southshore in the Hillsbrad Foothills", "Brewmeister Bilger was a dwarf located in Southshore in the Hillsbrad Foothills. He wandered around in the inn cellar, hiccupping occasionally." },
  ["breyk"] = { 2, "orc flight master located at Stonard in the Swamp of Sorrows", "Breyk is an orc flight master located at Stonard in the Swamp of Sorrows." },
  ["brgl-lrgl the basher"] = { 2, "huge murloc", "Brgl-Lrgl the Basher is a huge murloc who appears inside a cave in the center of the Forgotten Marsh in Vol'dun while the world quest  [50REWQ] Brgl-Lrgl the Basher is available. According to Princess Talanji, he is the leader of the troublesome T..." },
  ["brglmurgl"] = { 2, "murloc found in Winterfin Retreat in the Borean Tundra", "Brglmurgl is a murloc found in Winterfin Retreat in the Borean Tundra. He is very annoyed and focused on getting the contaminated murlocs out of his village." },
  ["briarback boarmaster"] = { 2, "', "Briarback Boarmasters are quilboar located in Goldfield Farmstead in Stormsong Valley." },
  ["briarback brute"] = { 2, "', "Briarback Brutes are quilboar brutes located in Stormsong Valley." },
  ["briarback crusher"] = { 2, "', "Briarback Crushers are quilboar brutes located in Stormsong Valley." },
  ["briarback enforcer"] = { 2, "', "Briarback Enforcers are quilboar brutes located in Stormsong Valley." },
  ["briarback geomancer"] = { 2, "', "Briarback Geomancers are quilboar located in Briarback Kraul in Stormsong Valley." },
  ["briarback kraulguard"] = { 2, "quilboar", "Briarback Kraulguard is a quilboar." },
  ["briarback kraultender"] = { 2, "', "Briarback Kraultenders are quilboar located in Burton Farmstead in Stormsong Valley." },
  ["briarback lookout"] = { 2, "', "Briarback Lookouts are quilboar located in Briarback Kraul in Stormsong Valley." },
  ["briarback packmaster"] = { 2, "', "Briarback Packmasters are quilboar located in Briarback Kraul in Stormsong Valley." },
  ["briarback raider"] = { 2, "', "Briarback Raiders are quilboar located in Stormsong Valley." },
  ["briarback reinforcements"] = { 2, "', "Briarback Reinforcements are quilboar summoned by Briarback Lookouts in Stormsong Valley." },
  ["briarback rider"] = { 2, "', "Briarback Riders are quilboar located in Stormsong Valley." },
  ["briarback shaper"] = { 2, "', "Briarback Shapers are quilboar located in Stormsong Valley." },
  ["briarback skirmisher"] = { 2, "', "Briarback Skirmishers are quilboar located in Burton Farmstead in Stormsong Valley." },
  ["briarback soldier"] = { 2, "', "Briarback Soldiers are quilboar located in Stormsong Valley." },
  ["briarback thorn-witch"] = { 2, "', "Briarback Thorn-Witches are quilboar located in Thornheart in Stormsong Valley." },
  ["briarback thornmatron"] = { 2, "', "Briarback Thornmatrons are quilboar located in Thornheart in Stormsong Valley. They are corrupting Bramblefist the Maddened." },
  ["briarback tunneler"] = { 2, "', "Briarback Tunnelers are quilboar located at the Amber Waves in Stormsong Valley." },
  ["briarback warcaller"] = { 2, "', "Briarback Warcallers are quilboar located in Briarback Kraul in Stormsong Valley. They carry a drum." },
  ["briarbane arbalest"] = { 2, "', "Briarbane Arbalests are venthyr located at Witherfall Ruins in Revendreth." },
  ["briarbane cavalier"] = { 2, "', "Briarbane Cavaliers are venthyr located at Witherfall Ruins in Revendreth." },
  ["briarbane footman"] = { 2, "', "Briarbane Footmen are venthyr located at Witherfall Ruins in Revendreth." },
  ["briarthorn (gnome)"] = { 2, "gnome warlock trainer located in Bonegrip's Runes", "Briarthorn is a gnome warlock trainer located in Bonegrip's Runes and Dooms within the Forlorn Cavern in Ironforge." },
  ["brick"] = { 2, "drogbar located in the Deep Roads in Highmountain", "Brick is a drogbar located in the Deep Roads in Highmountain." },
  ["brickhouse"] = { 2, "ogre located at the Tower in Ashran", "Brickhouse is an ogre located at the Tower in Ashran." },
  ["bridge worker alex"] = { 2, "human located at Lakeshire", "Bridge Worker Alex is a human located at Lakeshire. He is one of the workers who repaired Everstill Bridge and are now trying to free Foreman Oslow from under a boulder." },
  ["brigade member"] = { 2, "', "Brigade Members are summoned by  [Citizens Brigade Whistle]." },
  ["briggs"] = { 2, "member of the Argent Dawn", "Briggs was a member of the Argent Dawn. He was killed by another member of his order who had been raised from undeath by the Scourge." },
  ["briggs (worgen)"] = { 2, "worgen located at", "Briggs is a worgen located at Andorhal in The Deaths of Chromie scenario." },
  ["briggul"] = { 2, "drogbar located  at Glimmerogg in Zaralek Cavern", "Briggul is a drogbar located  at Glimmerogg in Zaralek Cavern." },
  ["brighthoof"] = { 2, "tauren paladin found in Molten Front as part of the Thral...", "Brighthoof is a tauren paladin found in Molten Front as part of the Thrall's Thrashers in the raid section of the Firelands." },
  ["brightmane"] = { 2, "', "Brightmane was one of the white horses kept by the Balnir family at their farmstead in the Tirisfal Glades. In the winter of 4 ADP, she gave birth to a colt, Invincible, with some assistance from Jorum Balnir, Jarim Balnir, and the visiting Prince..." },
  ["brightstone"] = { 2, "latest architect assistant", "Assistant Brightstone is the latest architect assistant and student of Baros Alexston. Baros notes that she does everything to the extreme." },
  ["brigitte abbendis"] = { 2, "daughter of the former High General Abbendis", "High General Brigitte Abbendis was one of the founders of the original Scarlet Crusade. She was the daughter of the former High General Abbendis." },
  ["briglar"] = { 2, "orc flight master located at Sandy Beach in the Shimmerin...", "Briglar is an orc flight master located at Sandy Beach in the Shimmering Expanse. He works as a connection with the underwater flight masters of Vashj'ir." },
  ["brigligos"] = { 2, "blue dragon", "Brigligos was a blue dragon who was killed in a magical accident. His name is on a Fresh Gravestone at the Veiled Ossuary." },
  ["brilda dopplegink"] = { 2, "gnomish recovery specialist located in Dalaran during its...", "Brilda Dopplegink is a gnomish recovery specialist located in Dalaran during its stay in Deadwind Pass. The entire city had been moved by a giant Blink spell, and some Dalaran Citizens were re-materialized at the wrong place and were stuck in wall..." },
  ["briln"] = { 2, "orc captain of the Blood", "Briln was the orc captain of the Blood and Thunder. He lost his eye in the battle against Alliance forces commanded by Admiral Proudmoore." },
  ["brimming mechano-mage"] = { 2, "gnome", "Brimming Mechano-Mage is a gnome." },
  ["brina bearclaw"] = { 2, "dwarf", "Brina Bearclaw is a dwarf who serves as the companion vendor for Brewfest for the Alliance. She is located at the camp outside Ironforge in Dun Morogh." },
  ["brine"] = { 2, "orc shaman located on a hill in the northern part of Blac...", "Brine is an orc shaman located on a hill in the northern part of Blackthorn Ridge in the Southern Barrens. She is an expert on the spirits and nature of water, and previously aided trainee shaman adventurers in their quests to gain their water totem." },
  ["brinesnout raider"] = { 2, "', "Brinesnout Raiders are gnolls located at Shipwreck Arena in Azsuna." },
  ["briney boltcutter"] = { 2, "neutral goblin within the Zul'Gurub instance", "Briney Boltcutter is a neutral goblin within the Zul'Gurub instance, sending adventurers into the Cache of Madness area. He is allied with the Blackwater Raiders of Booty Bay and is accompanied by two Blackwater Ruffians." },
  ["brinthe"] = { 2, "current leader of the Machine Speakers", "High Speaker Brinthe is the current leader of the Machine Speakers and their representative in the Council of Dornogal. In the past she held the position of Speaker, overseeing Machine Speakers for millennia." },
  ["bristleback arsonist"] = { 2, "quilboar", "Bristleback Arsonist is a quilboar." },
  ["bristleback bladewarden"] = { 2, "', "Bristleback Bladewardens are quilboar located near and at the Overgrowth in the Southern Barrens. Some are seen using drums." },
  ["bristleback clubber"] = { 2, "', "Bristleback Clubbers are quilboar located in Krakenbane Cove in Tiragarde Sound and in Stormsong Valley." },
  ["bristleback defender"] = { 2, "quilboar", "Bristleback Defender is a quilboar." },
  ["bristleback geomancer"] = { 2, "', "Bristleback Geomancers are quilboar found in the Barrens." },
  ["bristleback gun thief"] = { 2, "', "Bristleback Gun Thieves are quilboar who have stolen guns from a tauren village while the tauren were occupied with the attack on Camp Narache.  Adana Thunderhorn would like to get them back." },
  ["bristleback horker"] = { 2, "', "Bristleback Horkers are quilboar located in Freehold in Tiragarde Sound." },
  ["bristleback hunter"] = { 2, "', "Bristleback Hunters were quilboar located in the Barrens." },
  ["bristleback interloper"] = { 2, "', "Bristleback Interlopers are quilboar found in Red Rocks in Mulgore." },
  ["bristleback invader"] = { 2, "', "Bristleback Invaders are quilboar members of the Bristleback tribe. These barbarous quilboar have slaughtered many tauren and destroyed their homes." },
  ["bristleback invaders"] = { 2, "', "Bristleback Invaders are quilboar located in the Thornsnarl in Mulgore." },
  ["bristleback mystic"] = { 2, "quilboar", "Bristleback Mystic is a quilboar." },
  ["bristleback onlooker"] = { 2, "onlookers run away in fear", "Bristleback Onlookers are quilboar who enter the Bristleback Challenge Ring in the Southern Barrens to watch the duel between the adventurer and Sabersnout during  [10-30] Diplomacy By Another Means /  [10-30] Speaking Their Language. After Sabers..." },
  ["bristleback pounder"] = { 2, "', "Bristleback Pounders are quilboar located in Daelin's Gate in Tiragarde Sound." },
  ["bristleback quilboar"] = { 2, "', "Bristleback Quilboar are found in Brambleblade Ravine in Mulgore." },
  ["bristleback shaman"] = { 2, "', "Bristleback Shaman are quilboar found in Mulgore." },
  ["bristleback thorncaller"] = { 2, "', "Bristleback Thorncallers are quilboar thornweavers of the Bristleback tribe found in the Thornsnarl on Red Cloud Mesa. They are responsible for seeding and growing new thorned roots for the quilboar to live in." },
  ["bristleback thornweaver"] = { 2, "', "Bristleback Thornweavers are quilboar found near Vendetta Point and Forward Command in the Southern Barrens." },
  ["bristleback water seeker"] = { 2, "', "Bristleback Water Seekers are quilboar found in the Barrens." },
  ["bristleburr"] = { 2, "furbolg", "Bristleburr is a furbolg." },
  ["bristlefur"] = { 2, "wyvern mount of Valeera Sanguinar", "Bristlefur is the wyvern mount of Valeera Sanguinar. Valeera stole him from Tarm, when fleeing from her new gladiator master, Helka Grimtotem." },
  ["bristlelimb ambusher"] = { 2, "furbolg", "Bristlelimb Ambusher is a furbolg." },
  ["bristlelimb furbolg"] = { 2, "', "Bristlelimb Furbolgs are furbolg mobs that can be found at Bristlelimb Village near the western shore of Azuremyst Isle. They are at war with the Stillpine tribe and have kidnapped a number of Stillpine furbolgs, holding them captive in Bristlelim..." },
  ["bristlelimb pathfinder"] = { 2, "furbolg", "Bristlelimb Pathfinder is a furbolg." },
  ["bristlelimb shaman"] = { 2, "', "Bristlelimb Shaman are furbolgs found on Bloodmyst Isle." },
  ["bristlelimb ursa"] = { 2, "', "Bristlelimb Ursas are furbolg mobs that can be found at Bristlelimb Village near the western shore of Azuremyst Isle. They are at war with the Stillpine tribe and have kidnapped a number of Stillpine furbolgs, holding them captive in Bristlelimb V..." },
  ["bristlelimb warrior"] = { 2, "', "Bristlelimb Warriors are furbolgs found in Bloodmyst Isle." },
  ["bristlelimb windcaller"] = { 2, "', "Bristlelimb Windcallers are furbolg mobs that can be found at Bristlelimb Village near the western shore of Azuremyst Isle. They are at war with the Stillpine tribe and have kidnapped a number of Stillpine furbolgs, holding them captive in Bristle..." },
  ["bristlemane bramble-weaver"] = { 2, "', "Bristlemane Bramble-Weavers are quilboar located on the expedition isles." },
  ["bristlemane defender"] = { 2, "', "Bristlemane Defenders are quilboar located on the expedition isles." },
  ["bristlemane pathfinder"] = { 2, "', "Bristlemane Pathfinders are quilboar located on the expedition isles." },
  ["bristlemane quilboar"] = { 2, "', "Bristlemane Quilboar are quilboar located on the expedition isles." },
  ["bristlemane squealer"] = { 2, "', "Bristlemane Squealers are quilboar located on the expedition isles." },
  ["bristlemane thorncaller"] = { 2, "', "Bristlemane Thorncallers are quilboar located on the expedition isles." },
  ["bristlemaw"] = { 2, "quilboar", "Bristlemaw is a quilboar." },
  ["bristlethorn battleguard"] = { 2, "', "Bristlethorn Battleguards are quilboar located on the expedition isles." },
  ["brita"] = { 2, "', "Brita follows Thane Illskar at the Circle of Suffering in the Underhalls of Icecrown." },
  ["brita bramblebrush"] = { 2, "goblin alchemy vendor located at Stagalbog in the Swamp o...", "Brita Bramblebrush is a goblin alchemy vendor located at Stagalbog in the Swamp of Sorrows." },
  ["brittlebark breaker"] = { 2, "', "Brittlebark Breakers are draenei encountered by adventure companions in Ardenweald." },
  ["brivelthwerp"] = { 2, "gnome ice cream vendor", "Brivelthwerp is a gnome ice cream vendor and quest giver located on a coolant tugboat above the Sunken Dig Site in Thousand Needles. Prior to the Cataclysm, he was located at the Mirage Raceway where he sold Tigule's Strawberry Ice Cream." },
  ["briz blastbolt"] = { 2, "gnome located at Kharanos during the Legion Invasions", "Briz Blastbolt is a gnome located at Kharanos during the Legion Invasions. He orders several Battle Pilots to jump into their flying machines to go support the Ironforge Airfield." },
  ["brlee"] = { 2, "member of the Gordunni Gladiator Team of Ancient Draenor:...", "Brlee was a member of the Gordunni Gladiator Team of Ancient Draenor: the previous year's team champions of the Crimson Ring tournament. During his gladiator fight in Dire Maul against Varian 'Lo'Gosh' Wrynn, Valeera Sanguinar and Broll Bearmantle..." },
  ["bro'kin"] = { 2, "goblin alchemy vendor located on top of the northern wall...", "Bro'kin is a goblin alchemy vendor located on top of the northern wall of the Ruins of Alterac in the Alterac Mountains. He and the gnome Lotwil Veriatus are friends." },
  ["brock"] = { 2, "tortollan", "Brock is a tortollan who roams between Mezzamere, Newhome and the Azsh'ari Terrace in Nazjatar. He is the apprentice of Maedin." },
  ["brock the crazed"] = { 2, "worgen shadow priest captain of the Alliance", "Brock the Crazed is a worgen shadow priest captain of the Alliance, who served in Ashran and would later appear at Raven's Glory, the Black Rook Hold arena. In Ashran, Brock or another random Alliance Captain will spawn each time the Alliance rein..." },
  ["brod anvilbeard"] = { 2, "dwarf general goods vendor located in the small camp of G...", "Brod Anvilbeard is a dwarf general goods vendor located in the small camp of Gunstan's Dig in Tanaris." },
  ["brodog"] = { 2, "orc", "Brodog was an orc who lived on Draenor during the time of the Second War." },
  ["broff bombast"] = { 2, "dwarf located in Valiance Keep in the Borean Tundra", "Broff Bombast is a dwarf located in Valiance Keep in the Borean Tundra." },
  ["brogan falamar"] = { 2, "father of Aodhan", "Brogan Falamar was the father of Aodhan and Kedehern. He was very proud of Kedehern's choice of becoming a paladin, but he became rather disappointed when Aodhan chose to become a mage." },
  ["brogas"] = { 2, "young orc warrior in the Dragonmaw clan under the command...", "Brogas was a young orc warrior in the Dragonmaw clan under the command of Nekros at Grim Batol. He was the chief handler of dragons." },
  ["brogdul"] = { 2, "orc flight master aboard the Stygian Bounty in the Shimme...", "Brogdul is an orc flight master aboard the Stygian Bounty in the Shimmering Expanse. He works as a connection with the underwater flight masters of Vashj'ir." },
  ["brogg the beast"] = { 2, "drogbar located in Zaralek Cavern", "Brogg the Beast is a drogbar located in Zaralek Cavern." },
  ["brogor"] = { 2, "orc quest giver located east of Mor'shan Base Camp in the...", "Brogor is an orc quest giver located east of Mor'shan Base Camp in the Northern Barrens. This section concerns content related to Legion." },
  ["brogrul the mighty"] = { 2, "drogbar vignette found at a tauren watchtower in the Snow...", "Brogrul the Mighty is a drogbar vignette found at a tauren watchtower in the Snowblind Cliffs in Highmountain. He is surrounded by several dead Skyhorn Interceptors." },
  ["brohann caskbelly"] = { 2, "dwarf quest giver located in the Dwarven District of Stor...", "Brohann Caskbelly is a dwarf quest giver located in the Dwarven District of Stormwind City. He is affiliated with the Explorers' League." },
  ["brok"] = { 2, "master Pet Tamer located at the southern edge of Nordrass...", "Brok is a master Pet Tamer located at the southern edge of Nordrassil in Mount Hyjal. He is surrounded by his three level 25 battle pets: Ashtail, Kali, and Incinderous." },
  ["broken corpse"] = { 2, "Broken located next to a Strange Object in the central bu...", "Broken Corpse is a Broken located next to a Strange Object in the central building of the Cenarion Thicket in Terokkar Forest." },
  ["broken exile"] = { 2, "', "Broken Exiles can be found at the Harborage in the Swamp of Sorrows. They are part of the Broken exiles." },
  ["broken horn desecrator"] = { 2, "', "Broken Horn Desecrators are orcs located in Broken Horn Village in Gorgrond. Some of them are working the anvil." },
  ["broken horn marauder"] = { 2, "', "Broken Horn Marauders are orc guards located in Broken Horn Village in Gorgrond. They are riding ravagers." },
  ["broken horn reaver"] = { 2, "', "Broken Horn Reavers are orcs located in Broken Horn Village in Gorgrond. Two are tending to Bonegrind the Starved." },
  ["broken horn vandal"] = { 2, "', "Broken Horn Vandals are orcs located in Broken Horn Village in Gorgrond." },
  ["broken isles adventurer"] = { 2, "', "Broken Isles Adventurers are traveling to the Broken Isles by using the portal found in Pathfinder's Den of Orgrimmar and Wizard's Sanctum of Stormwind City." },
  ["broken miner"] = { 2, "', "Broken Miners are Broken located at the Crystal Hall in the Exodar. They are mining crystals in the cave attached to the Crystal Hall." },
  ["broken refugee"] = { 2, "', "Broken Refugees are Broken located in Shattrath City." },
  ["broken shaman"] = { 2, "', "Broken Shaman are Broken shaman who appear during the Battle for the Exodar. They defended the Crystal Hall from Karzak the Impaler with Farseer Nobundo." },
  ["broken skeleton"] = { 2, "', "Broken Skeletons are skeletons found at the Bone Wastes in Terokkar Forest. They also occasionally spawn from the cocoons at Netherweb Ridge." },
  ["broken slave"] = { 2, "', "Broken Slaves are Broken located in Antoran Wastes." },
  ["broken soul"] = { 2, "', "Broken Souls are Broken located in Antoran Wastes." },
  ["broken temple prisoner"] = { 2, "', "Broken Temple Prisoners are dwarves and Forsaken located in Stormheim." },
  ["broker realmwalker"] = { 2, "', "Broker Realmwalkers were brokers maintaining a portal to Oribos in the Wizard's Sanctum of Stormwind City. They were replaced by Ebon Blade Acolytes in the beta." },
  ["broker tradesman"] = { 2, "', "Broker Tradesmen are brokers of Cartel Ba who first appear during  [60] Explosive Schemes, escorting a caravan through the Scaplian Ridge tunnel in Maldraxxus alongside the Caravan Guards. After the caravan is blown up, they can be seen around the..." },
  ["broker ve'bena"] = { 2, "broker located in Tazavesh", "Broker Ve'bena is a broker located in Tazavesh, the Veiled Market in K'aresh." },
  ["broker ve'ken"] = { 2, "broker located in floor three of layers in Torghast", "Broker Ve'ken is a broker located in floor three of layers in Torghast, Tower of the Damned. Ve'ken provides Refuge of the Damned to players near him, providing a brief respite from the Jailer's attentions." },
  ["broker ve'kot"] = { 2, "broker", "Broker Ve'kot is a broker that has a chance to briefly appear from a portal during  [60] Fangcrack's Fan Club at the Tremaculum in the Maw." },
  ["broker ve'nott"] = { 2, "broker located on the boss floor", "Broker Ve'nott is a broker located on the boss floor, just before the layer boss in Torghast, Tower of the Damned. Unlike his compatriot Broker Ve'ken (on floor three), Ve'nott does not provide a refuge from the Jailer's Chains or any torments." },
  ["brokespear"] = { 2, "rare centaur", "Brokespear is a rare centaur who is found at the Stagnant Oasis in the Northern Barrens. He is on a 2-3 hour respawn timer." },
  ["brokor"] = { 2, "orc located at the Brimstone Springs in Gorgrond", "Brokor is an orc located at the Brimstone Springs in Gorgrond. Near his broken body is Brokor's Sack which contains  [Brokor's Walking Stick]." },
  ["broktar"] = { 2, "orc located in the Common in Razorwind Shores", "Broktar is an orc located in the Common in Razorwind Shores." },
  ["brolic"] = { 2, "orc blademaster", "Brolic is an orc blademaster and quest giver stationed at Domination Point in Krasarang Wilds." },
  ["bromm"] = { 2, "dwarf located at Valiance Keep in the Borean Tundra", "Bromm is a dwarf located at Valiance Keep in the Borean Tundra." },
  ["bron"] = { 2, "resident Sausage Vendor at the Brewfest grounds in Durotar", "Bron is the resident Sausage Vendor at the Brewfest grounds in Durotar. He sells the sausages needed for  [The Brewfest Diet]." },
  ["bron (mage)"] = { 2, "young human mage", "Bron is a young human mage, and, alongside Aodhan, a student under Master Simeon." },
  ["bron big-head"] = { 2, "ogre located in Frostfire Ridge", "Bron Big-Head was an ogre located in Frostfire Ridge. He found a huge supply cache, but was taken out by the followers sent from the garrisons." },
  ["bronk"] = { 2, "tauren alchemy vendor located in Camp Mojache in Feralas", "Bronk is a tauren alchemy vendor located in Camp Mojache in Feralas." },
  ["bront axecrusher"] = { 2, "orc located in the Steam Pools in Feralas during Love is ...", "Bront Axecrusher is an orc located in the Steam Pools in Feralas during Love is in the Air." },
  ["bronze brannbeard"] = { 2, "dwarf located at Krasus' Landing in Dalaran", "Bronze Brannbeard is a dwarf located at Krasus' Landing in Dalaran, as well as at the Infinite Bazaar, during Legion Remix PTR testing. He resembles and has the same on-click quotes as Brann Bronzebeard." },
  ["broodwatcher anub'akar"] = { 2, "nerubian located in Skittering Hollow in Island Expeditions", "Broodwatcher Anub'akar is a nerubian located in Skittering Hollow in Island Expeditions." },
  ["broodwatcher tal'nadix"] = { 2, "nerubian located in Skittering Hollow during Island Exped...", "Broodwatcher Tal'nadix is a nerubian located in Skittering Hollow during Island Expeditions." },
  ["broodwatcher taldim-ra"] = { 2, "nerubian located in Skittering Hollow during Island Exped...", "Broodwatcher Taldim-Ra is a nerubian located in Skittering Hollow during Island Expedition." },
  ["brookly"] = { 2, "goblin located in Gral's Grotto in Zuldazar", "Brookly is a goblin located in Gral's Grotto in Zuldazar. She was present during the funeral of King Rastakhan in Dazar'alor." },
  ["brorg bitterspite"] = { 2, "orc located in Durotar during Brewfest", "Brorg Bitterspite is an orc located in Durotar during Brewfest." },
  ["brot"] = { 2, "orc leatherworking supplies vendor at Dragonmaw Port in t...", "Brot is an orc leatherworking supplies vendor at Dragonmaw Port in the Twilight Highlands." },
  ["brote"] = { 2, "captured gnome located in Venomspite in the Dragonblight", "Brote is a captured gnome located in Venomspite in the Dragonblight. His main occupation is haranguing his fellow prisoner and brother, Skrotee, and announcing the even hours." },
  ["brother abealard"] = { 2, "Arathi located in the Priory of the Sacred Flame in Hallo...", "Brother Abealard is an Arathi located in the Priory of the Sacred Flame in Hallowfall. He is making batches of memorial wines." },
  ["brother adam"] = { 2, "', "Brother Adam and Brother David were brilliant mathematicians and monks, always blabbing about abacuses and parabolas." },
  ["brother addington"] = { 2, "human located in Stormsong Valley", "Brother Addington is a human located in Stormsong Valley. He was killed by Sister Ava and left hanging from a hook near a crossroads." },
  ["brother akil"] = { 2, "human", "Brother Akil is a human." },
  ["brother alen"] = { 2, "human located in the Monastery Archives of Boralus", "Brother Alen is a human located in the Monastery Archives of Boralus. Taelia and the Alliance emissary met him to find answers about the missing Kul Tiran fleet." },
  ["brother anton"] = { 2, "human quest giver originally located at Nijel's Point in ...", "Brother Anton was a human quest giver originally located at Nijel's Point in Desolace." },
  ["brother boshi"] = { 2, "gnome located at the Lunarfall in Shadowmoon Valley", "Brother Boshi is a gnome located at the Lunarfall in Shadowmoon Valley. He can only be recruited using the Headhunter's Harvest from Lunarfall Inn." },
  ["brother cuo"] = { 2, "general of the Thunder King", "Brother Cuo was one of the Shado-Pan agents chosen to aid Vol'jin and his companions in their attempt to thwart the resurrection of Warlord Kao, a general of the Thunder King. However, the group ended up being captured by the Zandalari and Cuo was..." },
  ["brother dao"] = { 2, "general of the Thunder King", "Brother Dao was one of the Shado-Pan agents chosen to aid Vol'jin and his companions in their attempt to thwart the resurrection of Warlord Kao, a general of the Thunder King. However the group ended up being captured by the Zandalari and Dao foun..." },
  ["brother david"] = { 2, "', "Brother David and Brother Adam were brilliant mathematicians and monks, always blabbing about abacuses and parabolas." },
  ["brother larry"] = { 2, "Forsaken priest", "Brother Larry is a Forsaken priest and bat handler standing next to a Riding Bat at Faol's Rest in the Tirisfal Glades. He offers instantaneous transportation to Dalaran for priests in the area." },
  ["broxigar"] = { 2, "veteran orc warrior", "\"I accept that I might die in battle - a glorious fate for an orc, shaman - but I am filled with dishonor for seeking it at the possible cost of those who fight against evil for their lives and those of others.\" Broxigar (a.k.a Broxigar the Red, B..." },
  ["broyk"] = { 2, "orc quest giver found at Hellscream's Watch in Ashenvale", "Broyk is an orc quest giver found at Hellscream's Watch in Ashenvale." },
  ["brrigan"] = { 2, "earthen inscription trainer located in the Forgegrounds i...", "Brrigan is an earthen inscription trainer located in the Forgegrounds in Dornogal." },
  ["brrrgl"] = { 2, "ice murloc companion", "Brrrgl is an ice murloc companion that is provided with the purchase of the Ice Murloc Funko Pop! Figure, available exclusively from the Blizzard Gear Store." },
  ["brrrgrrrl"] = { 2, "murloc planned to appear in Murloc Shoals in Suramar", "Brrrgrrrl is a murloc planned to appear in Murloc Shoals in Suramar. It would drop  [Infused Clam] for  [110] Magic Clams." },
  ["bruart"] = { 2, "drunken dwarf in the Military Ward in Ironforge", "Bruart is a drunken dwarf in the Military Ward in Ironforge. After talking to Bruuk Barleybeard, he can be challenged to a fight to get the  [Rune of Rebuke] for paladins or  [Rune of Frenzied Assault] for warriors." },
  ["bruk'tor"] = { 2, "orc located at the entrance to Darkmaul Citadel on Exile'...", "Bruk'tor is an orc located at the entrance to Darkmaul Citadel on Exile's Reach just before turning in  [7-10] Dungeon: Darkmaul Citadel." },
  ["brula brandykeg"] = { 2, "dwarf located at the Lunarfall in Shadowmoon Valley", "Brula Brandykeg is a dwarf located at the Lunarfall in Shadowmoon Valley. She can only be recruited using the Headhunter's Harvest from Lunarfall Inn." },
  ["brulf the heavy"] = { 2, "vrykul vendor located at Valdisdall in Stormheim", "Brulf the Heavy is a vrykul vendor located at Valdisdall in Stormheim." },
  ["brulla"] = { 2, "orc shaman trainer located at the Crossroads in the North...", "Brulla is an orc shaman trainer located at the Crossroads in the Northern Barrens. She is surrounded by a  [Water Shield]." },
  ["brullo the strong"] = { 2, "rare elite drogbar located in Glimmerogg in southwestern ...", "Brullo the Strong is a rare elite drogbar located in Glimmerogg in southwestern Zaralek Cavern. He spawns with the zone-wide emote: The strong are gathering in Glimmerogg to test their mettle." },
  ["bruln grainkeeper"] = { 2, "tauren", "Bruln Grainkeeper is a tauren." },
  ["brumman"] = { 2, "dwarf leatherworking trainer", "Brumman is a dwarf leatherworking trainer and vendor located at Honor Hold in the Hellfire Peninsula. He is sitting outside the inn, half way down the left wall when you are stood facing the entrance." },
  ["brunda"] = { 2, "orc herbalism vendor found in The Arboretum in the upper ...", "Brunda is an orc herbalism vendor found in The Arboretum in the upper level of the Drag in Orgrimmar. This section concerns content related to Legion." },
  ["brundall chiselgut"] = { 2, "dwarf metal trader found at Highbank in Twilight Highlands", "Brundall is a dwarf metal trader found at Highbank in Twilight Highlands." },
  ["brundia braidhammer"] = { 2, "dwarf", "Brundia Braidhammer is a dwarf who sells toys and pets during Children's Week in Stormwind City. Leial Knitterton is her Horde counterpart in Orgrimmar." },
  ["brundin the dragonbane"] = { 2, "djaradin located in the Waking Shores", "Brundin the Dragonbane is a djaradin located in the Waking Shores. He is part of a Qalashi war party seemingly heading for the Ruby Life Pools." },
  ["brunelda"] = { 2, "earthen character in 'Forget Me Not'", "Brunelda is an earthen character in 'Forget Me Not', a play performed by the theater troupe at the Proscenium on the Isle of Dorn. She was deeply in love with Clodgran, her fused." },
  ["brunhold"] = { 2, "earthen located at the Orgrimmar Embassy in Orgrimmar", "Brunhold is an earthen located at the Orgrimmar Embassy in Orgrimmar." },
  ["brunold"] = { 2, "drogbar located on the expedition isles", "Brunold is a drogbar located on the expedition isles." },
  ["bruor ironbane"] = { 2, "earthen quest giver located at Bouldercrag's Refuge in th...", "Bruor Ironbane is an earthen quest giver located at Bouldercrag's Refuge in the Storm Peaks. He is a Ulduar earthen and as such is base-line friendly for both the Alliance and the Horde." },
  ["brusier gor"] = { 2, "ogre", "Brusier[sic] Gor is an ogre who can be encountered during Island Expeditions." },
  ["brutalsnout"] = { 2, "quilboar brute encountered during Island Expeditions", "Brutalsnout is a quilboar brute encountered during Island Expeditions." },
  ["brute (ashran)"] = { 2, "ogre leader of the Ashmaul located at Brute's Rise in Ashran", "Brute is an ogre leader of the Ashmaul located at Brute's Rise in Ashran." },
  ["brute (return to karazhan)"] = { 2, "worgen located in Return to Karazhan", "Brute is a worgen located in Return to Karazhan." },
  ["bruuk barleybeard"] = { 2, "dwarf drink vendor", "Bruuk Barleybeard is a dwarf drink vendor and owner of Bruuk's Corner, a tavern located in the Military Ward of Ironforge." },
  ["bruvv tearon"] = { 2, "Arathi fishing trainer located south of Mereldar in Hallo...", "Bruvv Tearon is an Arathi fishing trainer located south of Mereldar in Hallowfall. He is teaching Anastaria to fish." },
  ["bryan schnau"] = { 2, "worgen located at the Lunarfall in Shadowmoon Valley", "Bryan Schnau is a worgen located at the Lunarfall in Shadowmoon Valley. He can only be recruited using the Headhunter's Harvest from Lunarfall Inn." },
  ["bryndaor"] = { 2, "unknown being", "Bryndaor is an unknown being, presumably vrykul, who guards the gates of Helheim for all eternity as a punishment. His  [Shackles of Bryndaor] can be looted." },
  ["brynild the brewmaster"] = { 2, "', "Brynild the Brewmaster knew the two monks named Brother Adam and Brother David." },
  ["brynjar"] = { 2, "vrykul", "Old Brynjar is a vrykul who recorded a chapter in The Legend of Odyn, 'Great Odyn and the Firelord', about Odyn and Tyr battling Ragnaros the Firelord." },
  ["brynkros"] = { 2, "Mawsworn kyrian located in the Face of Oblivion in the Maw", "Brynkros is a Mawsworn kyrian located in the Face of Oblivion in the Maw." },
  ["brytag"] = { 2, "vrykul located at Jandvik in Suramar", "Brytag is a vrykul located at Jandvik in Suramar." },
  ["bubblefilled patron"] = { 2, "', "Bubblefilled Patrons are located at the Bubble Bath in the Waking Shores." },
  ["bubbles (gnome)"] = { 2, "gnome located in Booty Bay in Stranglethorn Vale", "Bubbles is a gnome located in Booty Bay in Stranglethorn Vale." },
  ["bubbles (murloc)"] = { 2, "murloc located at the Winterfin Retreat in the Borean Tundra", "Bubbles is a murloc located at the Winterfin Retreat in the Borean Tundra." },
  ["bubulo acerbus"] = { 2, "gnome quest giver located in Tinker Town in Ironforge", "Bubulo Acerbus <Alliance Cloth Quartermaster> was a gnome quest giver located in Tinker Town in Ironforge." },
  ["buckshot bazza"] = { 2, "goblin located in Arathi Basin during Brawl: Comp Stomp f...", "Buckshot Bazza is a goblin located in Arathi Basin during Brawl: Comp Stomp for Alliance players." },
  ["buckslappy"] = { 2, "goblin engineering vendor located at Fuselight-by-the-Sea...", "Buckslappy is a goblin engineering vendor located at Fuselight-by-the-Sea in the Badlands." },
  ["budd's bodyguard"] = { 2, "', "Budd's Bodyguards could be found in the Hatchet Hills in south-eastern Ghostlands, protecting Budd Nedreck." },
  ["bugan the flesh-crusher"] = { 2, "mogu encountered during Island Expeditions", "Bugan the Flesh-Crusher is a mogu encountered during Island Expeditions. He can also spawn at the Unknown Crypt." },
  ["buh'gzaki the blasphemous"] = { 2, "mantid located at the Gate of the Setting Sun in the Vale...", "Buh'gzaki the Blasphemous is a mantid located at the Gate of the Setting Sun in the Vale of Eternal Blossoms." },
  ["buhurda"] = { 2, "draenei Strand of the Ancients battlemaster located on th...", "Buhurda was a draenei Strand of the Ancients battlemaster located on the Vault of Lights in Exodar during the Call to Arms: Strand of the Ancients." },
  ["builder bezzle"] = { 2, "goblin", "Builder Bezzle is a goblin that was present in Warsong Hold in Borean Tundra." },
  ["builder bozzle"] = { 2, "goblin", "Builder Bozzle is a goblin that was present in Warsong Hold in Borean Tundra." },
  ["bukarakikk"] = { 2, "tuskarr skinning trainer", "Bukarakikk is a tuskarr skinning trainer and fishing vendor located in Iskaara in the Azure Span." },
  ["bulgorg the wind slayer"] = { 2, "ogre located at the Mar'gok's Overwatch in Nagrand", "Bulgorg the Wind Slayer is an ogre located at the Mar'gok's Overwatch in Nagrand." },
  ["bullets bigblast"] = { 2, "engineering vendor located at Bogpaddle in the Swamp of S...", "Bullets Bigblast is an engineering vendor located at Bogpaddle in the Swamp of Sorrows. He will usually be tinkering with something outside in the eastern part of the town." },
  ["bulrug"] = { 2, "tauren stable master located on lower rise in Thunder Bluff", "Bulrug is a tauren stable master located on lower rise in Thunder Bluff. This section concerns content related to Legion." },
  ["bulwark defender"] = { 2, "', "Bulwark Defenders are orcs, Forsaken, dwarves, and humans located in the Twilight Bulwark in Thousand Needles." },
  ["bulwark prisoner"] = { 2, "', "Bulwark Prisoners are tauren, goblins, gnomes, and night elves located in the Twilight Bulwark in Thousand Needles." },
  ["bungledorf"] = { 2, "main character in the children's story The Worst Mage in ...", "Bungledorf is the main character in the children's story The Worst Mage in Dalaran: A Children's Book. His story is about a mage who didn't think he was cut out for the class." },
  ["burghy blackheart"] = { 2, "gnome located at the Lunarfall in Shadowmoon Valley", "Burghy Blackheart is a gnome located at the Lunarfall in Shadowmoon Valley. He can only be recruited using the Headhunter's Harvest from Lunarfall Inn." },
  ["burgle"] = { 2, "murloc located on the expedition isles", "Burgle is a murloc located on the expedition isles." },
  ["burgle (pet)"] = { 2, "untamable level 11 murloc battle pet owned by Bill Buckle...", "Burgle is a untamable level 11 murloc battle pet owned by Bill Buckler found at the Wild Shore in the Cape of Stranglethorn." },
  ["burgle eye"] = { 2, "rare mob murloc found in Dustwallow Marsh", "Burgle Eye is a rare mob murloc found in Dustwallow Marsh. He is part of the Mirefin tribe." },
  ["burglosh the earthbreaker"] = { 2, "ogre", "Burglosh the Earthbreaker was an ogre who took power of the Twilight's Hammer after Zeryxia's death. He was encountered by the Earthen Ring champions in Deepholm." },
  ["buried prisoner"] = { 2, "dwarf", "Buried Prisoner is a dwarf." },
  ["burigos"] = { 2, "dracthyr located in the Dragon's Hoard in Valdrakken", "Burigos is a dracthyr located in the Dragon's Hoard in Valdrakken." },
  ["burk the literate"] = { 2, "ogre", "Burk the Literate is an ogre who can be encountered during Island Expeditions." },
  ["burkhalt"] = { 2, "earthen theater troupe member located in the Proscenium i...", "Burkhalt is an earthen theater troupe member located in the Proscenium in the Isle of Dorn. He plays General Emmerich in 'The Rivals' and Clodgran in 'Forget Me Not'." },
  ["burko"] = { 2, "draenei first aid trainer", "Burko is a draenei first aid trainer and vendor located at the Temple of Telhamat in the Hellfire Peninsula. From the entrance of the temple, go forward up two flights of stairs, then take the path that goes west/left." },
  ["burkrum"] = { 2, "tauren armor vendor located at Splintertree Post in Ashen...", "Burkrum is a tauren armor vendor located at Splintertree Post in Ashenvale." },
  ["burly berta"] = { 2, "character", "Burly Berta is a character that appears on the following World of Warcraft: Trading Card Game cards." },
  ["burndl"] = { 2, "Timbermaw furbolg quest giver located next to Tanrir just...", "Burndl is a Timbermaw furbolg quest giver located next to Tanrir just outside of Winterfall Village." },
  ["burned-out remains"] = { 2, "', "The Burned-Out Remains can be found in the Alexston Farmstead in Westfall or south of Camp Taurajo in the Barrens." },
  ["burning blade adept"] = { 2, "', "Burning Blade Adepts are human, orc, and Forsaken members of the Burning Blade located in Thunder Axe Fortress in Desolace." },
  ["burning blade augur"] = { 2, "', "Burning Blade Augurs are Burning Blade orcs located in the Thunder Axe Fortress in Desolace." },
  ["burning blade felsworn"] = { 2, "', "Burning Blade Felsworns are Burning Blade orcs, humans, and Forsaken located in Thunder Axe Fortress in Desolace." },
  ["burning blade invoker"] = { 2, "', "Burning Blade Invokers are orcs, Forsaken, and humans located in Shadowbreak Ravine in Desolace." },
  ["burning blade reaver"] = { 2, "', "Burning Blade Reavers are orcs, Forsaken, and humans located in Thunder Axe Fortress in Desolace." },
  ["burning blade seer"] = { 2, "', "Burning Blade Seers are orcs, Forsaken, and humans found in Desolace." },
  ["burning blade shadowmage"] = { 2, "', "Burning Blade Shadowmages are orcs, humans, and Forsaken located in Thunder Axe Fortress in Desolace." },
  ["burning blade summoner"] = { 2, "', "Burning Blade Summoners are orcs, Forsaken, and humans found in Desolace." },
  ["burning blade warlock"] = { 2, "', "Burning Blade Warlocks are orcs, Forsaken, and humans located in Shok'Thokar and Shadowbreak Ravine in Desolace." },
  ["burning blade warlock corpse"] = { 2, "', "Burning Blade Warlock Corpses are deceased orcs, humans, and Forsaken located in Shok'Thokar and Shadowbreak Ravine in Desolace." },
  ["burr"] = { 2, "dwarf located at Thrym's End in Zul'Drak", "Burr is a dwarf located at Thrym's End in Zul'Drak. He can be found lying on a table dead, killed by the nearby Scourge." },
  ["bursar syleed"] = { 2, "ethereal likely planned to appear as part of the Trial of...", "Bursar Syleed is an ethereal likely planned to appear as part of the Trial of Style." },
  ["burth"] = { 2, "ogre bodyguard of Silas Darkmoon", "Burth is the ogre bodyguard of Silas Darkmoon. He is not a ride, does not like players, and will smash players away if they want." },
  ["buruk"] = { 2, "draenei pet trainer located at Azure Watch in Azuremyst Isle", "Buruk is a draenei pet trainer located at Azure Watch in Azuremyst Isle." },
  ["burx"] = { 2, "chief warrior in the Horde", "Burx was a chief warrior in the Horde and Thrall's closest advisor in the years after the Battle for Mount Hyjal. Burx was also secretly a member of the Burning Blade cult, not out of disrespect for his Warchief but rather out of an intense hatred..." },
  ["busy waiter"] = { 2, "', "Busy Waiters are goblins located in the Undermine." },
  ["butchie"] = { 2, "goblin located in the Motherlode", "Butchie is a goblin located in the Motherlode." },
  ["butchie (black temple)"] = { 2, "orc or draenei (depending on the race of the player) shaman", "Butchie is an orc or draenei (depending on the race of the player) shaman that is a part of the Uber Town group. She can be briefly seen during the flashback of the confrontation with Illidan Stormrage atop the Black Temple as well as during the f..." },
  ["butterfingers"] = { 2, "goblin cook from the Horde serving the Dragonscale Expedi...", "Butterfingers is a goblin cook from the Horde serving the Dragonscale Expedition on the Dragon Isles. He appears as Sous-Chef Butterfingers at Wingrest Embassy and the Dragonscale Basecamp in the Waking Shores where he assists dracthyr prepare meals." },
  ["buwei"] = { 2, "pandaren refugee", "Buwei was a pandaren refugee who entered the Vale of Eternal Blossoms after the gate to it was opened. He was soon joined with Li Li Stormstout." },
  ["buzz chopsaw"] = { 2, "goblin vendor located at the Irontree Clearing in the Fel...", "Buzz Chopsaw is a goblin vendor located at the Irontree Clearing in the Felwood." },
  ["buzz crankchug"] = { 2, "gnome flight master located in Vulture's Nest in Vol'dun", "Buzz Crankchug is a gnome flight master located in Vulture's Nest in Vol'dun. He was encountered by Horde troops at Crankchug's Overlook." },
  ["buzzek bracketswing"] = { 2, "goblin Illustrious Grand Master engineering trainer locat...", "Buzzek Bracketswing is a goblin Illustrious Grand Master engineering trainer located in Gadgetzan in Tanaris. He is in the southernmost hut." },
  ["byakko"] = { 2, "animal companion of Wotan", "Byakko was the animal companion of Wotan, the Master Hunter of the Winterskorn." },
  ["byrok"] = { 2, "orcish warrior", "Byrok was an orcish warrior. A veteran of the First and Second Wars, he spent years enslaved in the humans' internment camps before being freed by Thrall." },
  ["byron nailstew"] = { 2, "Arathi vendor located in Flotsam Shoal on the Siren Isle", "Byron Nailstew is an Arathi vendor located in Flotsam Shoal on the Siren Isle." },
  ["byula"] = { 2, "tauren former innkeeper once located in Camp Taurajo in t...", "Byula is a tauren former innkeeper once located in Camp Taurajo in the Barrens. He was one of the few tauren that managed to escape Camp Taurajo alive after the dwarves of Bael'dun Keep destroyed it." },
  ["caara"] = { 2, "draenei flight master located at Eventide Landing in Shad...", "Caara is a draenei flight master located at Eventide Landing in Shadowmoon Valley." },
  ["caas"] = { 2, "draenei located at Light's Rest in Talador", "Caas is a draenei located at Light's Rest in Talador." },
  ["cabal abjurist"] = { 2, "', "Cabal Abjurists are orcs and Broken found at the Shadow Tomb in Terokkar Forest." },
  ["cabal acolyte"] = { 2, "', "Cabal Acolytes can be found in the Shadow Labyrinth." },
  ["cabal deathsworn"] = { 2, "', "Cabal Deathsworns can be found in the Shadow Labyrinth." },
  ["cabal shadow priest"] = { 2, "', "Cabal Shadow Priests are Broken found in the Shadow Labyrinth." },
  ["cabal spell-weaver"] = { 2, "', "Cabal Spell-weavers are orcs and Broken found at the Shadow Stair in Terokkar Forest. Four of them are keeping an Enslaved Doomguard under control." },
  ["cabal spellbinder"] = { 2, "', "Cabal Spellbinders are Broken found in Shadow Labyrinth." },
  ["cackle"] = { 2, "gnoll matriarch of the Grimtail clan living in the Last F...", "Cackle is the gnoll matriarch of the Grimtail clan living in the Last Forest of Desolace. She traded with Wavestrider's Captain, Greydon Thorne." },
  ["cadi grasshoof"] = { 2, "tauren follower located at Frostwall in Frostfire Ridge", "Cadi Grasshoof is a tauren follower located at Frostwall in Frostfire Ridge. She can be recruited from the Frostwall Tavern building via Akanja." },
  ["caedakar the vicious"] = { 2, "satyr found in Darkshore", "Caedakar the Vicious is a satyr found in Darkshore. He used to spawn at the end of the escort quest  [24] Supplies to Auberdine received from Feero Ironhand at Maestra's Post in Ashenvale." },
  ["caedmos"] = { 2, "draenei priest trainer located in the Anchorites' Sanctum...", "Caedmos is a draenei priest trainer located in the Anchorites' Sanctum in the Vault of Lights in the Exodar. He used to send adventuring Alliance priests to aid Ogtinc in the plight of the Cenarion Circle." },
  ["caelus the harmonic"] = { 2, "kyrian located in the Eonian Archives in Bastion after ch...", "Caelus the Harmonic is a kyrian located in the Eonian Archives in Bastion after channeling the Anima Conductor level 3 to the area." },
  ["caerin"] = { 2, "Arathi located in Lightspark in Hallowfall", "Caerin is an Arathi located in Lightspark in Hallowfall. She and Faerley are studying with Edwyn Wyndsmithe." },
  ["caeris felwalker"] = { 2, "worgen located at the Lunarfall in Shadowmoon Valley", "Caeris Felwalker is a worgen located at the Lunarfall in Shadowmoon Valley. She can only be recruited using the Headhunter's Harvest from Lunarfall Inn." },
  ["cage head"] = { 2, "Forsaken located in the Cauldron of Rock in Darkmoon Island", "Cage Head is a Forsaken located in the Cauldron of Rock in Darkmoon Island. He also performed with his band in the Caverns of Time during WoW's Anniversary." },
  ["caged dwarf male"] = { 2, "lonely dwarf located in the Apothecarium in the Undercity", "The Caged Dwarf Male is a lonely dwarf located in the Apothecarium in the Undercity. There are two caged human males and two caged human females next to him." },
  ["cahoots fizzlebang"] = { 2, "gnome", "Cahoots Fizzlebang is a gnome." },
  ["cairne bloodhoof (rumble)"] = { 2, "melee ground unit of the Horde family in Warcraft Rumble", "Cairne Bloodhoof is a melee ground unit of the Horde family in Warcraft Rumble. Cairne is one of the tankiest leaders in the game and comes with a powerful AoE attack." },
  ["cairne bloodhoof (warcraft iii)"] = { 2, "peerless warrior", "The mighty chief of the Bloodhoof tauren, Cairne is a peerless warrior and a wise leader of his ancient people. Though slowed somewhat by the weight of age, Cairne still possesses the strength and valor of twenty men." },
  ["caladon leechblade"] = { 2, "Darkfallen death knight located in Arathi Basin during Br...", "Caladon Leechblade is a Darkfallen death knight located in Arathi Basin during Brawl: Comp Stomp for Horde players." },
  ["calcia"] = { 2, "', "Calcia was one of Neltharion's most trusted scale-crafters and the leader of the black dragonflight's scalesmiths. She and her scalesmiths worked with the blue dragonflight to stabilize the earth beneath the Broodlands during Iridikron's onslaught..." },
  ["calder (vrykul)"] = { 2, "vrykul located at Jandvik in Suramar", "Calder is a vrykul located at Jandvik in Suramar. He can be found on a ridge to the south of the entrance to Jandvik, working on a weapon rack." },
  ["caleb"] = { 2, "draenei child located in Talador", "Caleb is a draenei child located in Talador. He was trying to move a clutch of peachicks out of the way of the demons, but they were ambushed by Sher'khaan, spreading the chicks across the area." },
  ["caleb baelor"] = { 2, "dwarf flight master located in Dun Modr in the Wetlands", "Caleb Baelor is a dwarf flight master located in Dun Modr in the Wetlands." },
  ["calix"] = { 2, "kyrian located in Torghast", "Calix is a kyrian located in Torghast, Tower of the Damned." },
  ["caller of the gloom"] = { 2, "', "Callers of the Gloom are Arathi found in Hallowfall." },
  ["callie the nightmaiden"] = { 2, "Forsworn kyrian", "Callie the Nightmaiden is a Forsworn kyrian." },
  ["callum ashvow"] = { 2, "Arathi located at Sun's Reach Sanctum on the Isle of Quel...", "Callum Ashvow is an Arathi located at Sun's Reach Sanctum on the Isle of Quel'Danas during the assault by the Devouring Host. Together with Commander Koruth Mountainfist and Knight Anais, he is holding the bridge leading south-west." },
  ["cami cogwizzle"] = { 2, "gnome riding a mechano-tank in Valorcall Pass in Arathi H...", "Cami Cogwizzle is a gnome riding a mechano-tank in Valorcall Pass in Arathi Highlands during the Battle for Stromgarde." },
  ["camp ataya brave"] = { 2, "', "Camp Ataya Braves are tauren guards located in Camp Ataya of Feralas." },
  ["camp mojache brave"] = { 2, "', "Camp Mojache Braves are tauren found in Camp Mojache in Feralas." },
  ["camp narache brave"] = { 2, "', "Camp Narache Braves are elite tauren guards found protecting Camp Narache in Mulgore." },
  ["camran"] = { 2, "dwarf mail armor vendor located in Northwatch Hold in the...", "Camran is a dwarf mail armor vendor located in Northwatch Hold in the Southern Barrens. It is unknown whether he survived the Razing of Northwatch Hold or not." },
  ["candleflyer captain"] = { 2, "kobold located in the Warrens in the Ringing Deeps", "Candleflyer Captain is a kobold located in the Warrens in the Ringing Deeps. He flies around a small area atop a candlefly." },
  ["candlelit desecrator"] = { 2, "kobold located in the Mourning Rise in the Isle of Dorn", "Candlelit Desecrator is a kobold located in the Mourning Rise in the Isle of Dorn." },
  ["candlelit pebblemaker"] = { 2, "kobold located in the Mourning Rise in the Isle of Dorn", "Candlelit Pebblemaker is a kobold located in the Mourning Rise in the Isle of Dorn." },
  ["candy cane"] = { 2, "male goblin adventurer's girlfriend/ex-girlfriend", "Candy Cane is the male goblin adventurer's girlfriend/ex-girlfriend and male goblin-only quest giver at Bilgewater Port. Her counterpart for the female goblin adventurer is Chip Endale." },
  ["cannary caskshot"] = { 2, "dwarf found in Thelsamar of Loch Modan", "Cannary Caskshot is a dwarf found in Thelsamar of Loch Modan. She's the local hunter that comes up with the plan to stop the Mosshide tribe's plans in region." },
  ["cap'n copyright"] = { 2, "goblin located in Booty Bay in the Cape of Stranglethorn", "Cap'n Copyright was a goblin located in Booty Bay in the Cape of Stranglethorn." },
  ["capps carlin"] = { 2, "goblin PvP rewards vendor located at Gadgetzan in Tanaris", "Capps Carlin is a goblin PvP rewards vendor located at Gadgetzan in Tanaris. He sells older seasons' gear in exchange for  [Mark of Honor]." },
  ["captain (crawler)"] = { 2, "huge pet crawler of the goblin hunter Chikkers", "The Captain is the huge pet crawler of the goblin hunter Chikkers. She stands nearly as tall as Lorash Sunbeam's waist and has a light blue shell that is almost as big as her goblin master and probably weighs twice as much." },
  ["captain adams"] = { 2, "dwarven captain of the Valiance Expedition on the Howling...", "Captain Adams is a dwarven captain of the Valiance Expedition on the Howling Fjord. His famous temper is feared among his troops." },
  ["captain alina"] = { 2, "human", "Captain Alina is a human who is being held prisoner by Warchief Kargath Bladefist in the Hall of Blades inside the Shattered Halls. The injured Randy Whizzlesprocket tasked Alliance adventurer to find and rescue her before she could be executed." },
  ["captain alpert"] = { 2, "human quest giver stationed at Moonbrook in Westfall", "Captain Alpert is a human quest giver stationed at Moonbrook in Westfall. He is an officer of the Westfall Brigade, and one of the best soldiers under Marshal Gryan Stoutmantle." },
  ["captain andrews"] = { 2, "', "Captain Andrews used to train his team and occasionally fought against the Blue Team of Captain Thomas. It's unknown if he survived the Attack on Theramore Isle, but as a soldier, he was likely killed in combat or from the bomb." },
  ["captain angelica"] = { 2, "captain of the Alliance navy's Third Fleet; she", "Captain Angelica is a captain of the Alliance navy's Third Fleet; she and her crew, including First Mate Tidesong, have been through many a campaign. Her ship was cast ashore during the Battle for the Broken Shore, after which she could be seen tr..." },
  ["captain anton"] = { 2, "', "Captain Anton could once be found inside Stormwind Keep of Stormwind City during the Elemental Unrest. He was heavily involved in tracking down the mysterious Doomsday Cult that had started to spread throughout Stormwind." },
  ["captain ara"] = { 2, "human located in Stormsong Valley", "Captain Ara is a human located in Stormsong Valley." },
  ["captain aransas"] = { 2, "human found at Booty Bay in Stranglethorn Vale", "Captain Aransas is a human found at Booty Bay in Stranglethorn Vale. She will give rogues  [Captain Aransas' Reward] in exchange for freeing Wendel Mathers from Kurzen's Compound." },
  ["captain bashgar"] = { 2, "orc", "Captain Bashgar is an orc who would appear in Ironfist Harbor in Nagrand." },
  ["captain bilgemaul"] = { 2, "orc planned to appear in Brackish Coast in Drustvar", "Captain Bilgemaul is an orc planned to appear in Brackish Coast in Drustvar." },
  ["captain biyel"] = { 2, "centaur located at Broadhoof Outpost in the Ohn'ahran Plains", "Captain Biyel is a centaur located at Broadhoof Outpost in the Ohn'ahran Plains." },
  ["captain blackanvil"] = { 2, "dwarf quest ender located at the Hive'Zora Alliance camp ...", "Captain Blackanvil is a dwarf quest ender located at the Hive'Zora Alliance camp in Silithus." },
  ["captain blackmaw"] = { 2, "worgen captain of the Gilneas Brigade", "Captain Blackmaw is a worgen captain of the Gilneas Brigade, serving on the Broken Isles trying to take over the Warden Towers located in either Stormheim, Val'sharah or Highmountain. Horde adventurers aid the Forsaken in killing Blackmaw and the ..." },
  ["captain bloodknuckle"] = { 2, "orc located on his ship the Stygian Bounty above the Shim...", "Captain Bloodknuckle is an orc located on his ship the Stygian Bounty above the Shimmering Expanse." },
  ["captain bo'kar"] = { 2, "ogre located on a watch tower at the Ango'rosh Grounds in...", "Captain Bo'kar is an ogre located on a watch tower at the Ango'rosh Grounds in Zangarmarsh." },
  ["captain bonemaw"] = { 2, "orc captain of the Warsong Offensive found at Conquest Ho...", "Captain Bonemaw is an orc captain of the Warsong Offensive found at Conquest Hold in the Grizzly Hills." },
  ["captain boneshatter"] = { 2, "orc found in the Shattered Halls", "Captain Boneshatter is an orc found in the Shattered Halls. He was imprisoned in Kargath Bladefist's prison and is scheduled to be executed, which would be a huge blow to the Horde forces in Outland." },
  ["captain boomspark"] = { 2, "goblin mercenary located at the Ring of Trials in Nagrand", "Captain Boomspark is a goblin mercenary located at the Ring of Trials in Nagrand." },
  ["captain brak"] = { 2, "orc found at Grom'kar Gulch in Gorgrond", "Captain Brak is an orc found at Grom'kar Gulch in Gorgrond." },
  ["captain brava"] = { 2, "tuskarr located on the Lost Arvillo in the Waking Shores", "Captain Brava is a tuskarr located on the Lost Arvillo in the Waking Shores." },
  ["captain brent the black"] = { 2, "captain of The Defiant", "Captain Brent the Black is the captain of The Defiant, one of the Alliance ships attacking Domination Point in the Krasarang Wilds." },
  ["captain cracklepants"] = { 2, "goblin captain of the Horde located at [[]] in Vol'dun du...", "Captain Cracklepants is a goblin captain of the Horde located at [[]] in Vol'dun during Faction Assaults." },
  ["captain crudbeard"] = { 2, "', "Captain Crudbeard a dwarf death knight in service to the Stormpike Guard. In preparation for their assault to claim the Hillsbrad Foothills for themselves, Captain Crudbeard was stationed at the Headland." },
  ["captain cuergo"] = { 2, "pirate known for plundering", "Captain Cuergo is a pirate known for plundering and hanging around Lost Rigger Cove. Although he is supposedly the leader of the Southsea Freebooters in Lost Rigger Cove, he never makes an appearance and is only mentioned in questlines." },
  ["captain cyrii"] = { 2, "draenei located in Shadowmoon Valley", "Captain Cyrii is a draenei located in Shadowmoon Valley." },
  ["captain dailcry"] = { 2, "boss in Priory of the Sacred Flame", "Captain Dailcry is a boss in Priory of the Sacred Flame." },
  ["captain eudora"] = { 2, "vulpera leader of the Bilge Rats", "Captain Eudora is the vulpera leader of the Bilge Rats, located in Freehold. Along with Captain Jolly and Captain Raoul, she serves as one of the bosses in the Council o' Captains encounter." },
  ["captain feargus"] = { 2, "worgen pirate located in Azsuna", "Captain Feargus is a worgen pirate located in Azsuna, serving as second-in-command of the Brashtide Crew." },
  ["captain flat tusk"] = { 2, "rare Razormane quilboar captain at Razormane Grounds in D...", "Captain Flat Tusk is a rare Razormane quilboar captain at Razormane Grounds in Durotar." },
  ["captain granger"] = { 2, "worgen captain of the Alliance located on the Alliance Ai...", "Captain Granger is a worgen captain of the Alliance located on the Alliance Airship in Vol'dun during the Faction Assaults." },
  ["captain halyndor"] = { 2, "undead human aboard the sunken Intrepid frigate in the Lo...", "Captain Halyndor is an undead human aboard the sunken Intrepid frigate in the Lost Fleet area of the Wetlands. He was a captain in Kul Tiras' Third fleet when he was alive." },
  ["captain jacobs"] = { 2, "former captain of the military guarding Farshire Mine in ...", "Captain Jacobs is a former captain of the military guarding Farshire Mine in the Borean Tundra. He fell victim, along with his troops, to Plagued Grain." },
  ["captain kitt"] = { 2, "vulpera located at the Port of Zandalar in Dazar'alor", "Captain Kitt is a vulpera located at the Port of Zandalar in Dazar'alor. He sells salvage chests containing treasures from Island Expeditions." },
  ["captain kromcrush"] = { 2, "ogre mini-boss found in the Gordok Commons of Dire Maul", "Captain Kromcrush is an ogre mini-boss found in the Gordok Commons of Dire Maul. He holds the  [Gordok Shackle Key]." },
  ["captain krosh"] = { 2, "ogre captain of the Ango'rosh tribe found at the Ango'ros...", "Captain Krosh is an ogre captain of the Ango'rosh tribe found at the Ango'rosh Grounds in Zangarmarsh. Krosh guards the  [Ango'rosh Attack Plans] describing their planned siege of Zabra'jin." },
  ["captain lancer"] = { 2, "djaradin located on the southern tip of the Dragonbane Ke...", "Captain Lancer is a djaradin located on the southern tip of the Dragonbane Keep just near Apex Canopy in the Waking Shores. She always spawns immediately after the conclusion of the Siege on Dragonbane Keep." },
  ["captain longtusk"] = { 2, "tuskarr located on the Old Belfyr in the Azure Span", "Captain Longtusk is a tuskarr located on the Old Belfyr in the Azure Span." },
  ["captain manjin"] = { 2, "centaur located at Broadhoof Outpost in the Ohn'ahran Plains", "Captain Manjin is a centaur located at Broadhoof Outpost in the Ohn'ahran Plains." },
  ["captain namier"] = { 2, "undead sailor found in one of the shipwrecks of North Tid...", "Captain Namier is an undead sailor found in one of the shipwrecks of North Tide's Run in Silverpine Forest." },
  ["captain nuthals"] = { 2, "worgen captain of the King's Fang located just outside th...", "Captain Nuthals is the worgen captain of the King's Fang located just outside the Cove of Nashal in Stormheim." },
  ["captain oathmyt"] = { 2, "Arathi located at the Dayspring Fields south of Mereldar ...", "Captain Oathmyt is an Arathi located at the Dayspring Fields south of Mereldar in Hallowfall. She runs the  [70-80W] Hallowfall Fishing Derby every Saturday." },
  ["captain obvious"] = { 2, "goblin", "Captain Obvious is a goblin." },
  ["captain p. harris"] = { 2, "undead captain of the Shipwrecked Sailors", "Captain P. Harris is the undead captain of the Shipwrecked Sailors who haunt the Cape of Lost Hope in Tol Barad Peninsula." },
  ["captain razorclaw"] = { 2, "worgen druid", "Captain Razorclaw is a worgen druid and captain in the Gilneas Brigade, serving on the Broken Isles trying to take over the Warden Towers located either in Stormheim, Val'sharah, or Highmountain. Horde adventurers aid the Forsaken in attacking Raz..." },
  ["captain razorspine"] = { 2, "quilboar brute located in the Collapsed Fields in Stormso...", "Captain Razorspine is a quilboar brute located in the Collapsed Fields in Stormsong Valley." },
  ["captain ripflesh"] = { 2, "leader of an all-gnoll mercenary group", "Captain Ripflesh is the leader of an all-gnoll mercenary group, the Blackmane Mercenaries. He and his men were hired by the Zandalar tribe in their assault on the Zouchin Strand, where he callously murdered the villagers after his men were done pi..." },
  ["captain ro-gu"] = { 2, "mogu", "Captain Ro-Gu is a mogu." },
  ["captain roberts"] = { 2, "worgen PvP quartermaster in the Greyfang Enclave in Dalaran", "Captain Roberts is a worgen PvP quartermaster in the Greyfang Enclave in Dalaran who sells elite gladiator rewards. It is currently unknown if she survived Dalaran's destruction." },
  ["captain rufus hardwick"] = { 2, "worgen captain of Gilneas", "Captain Rufus Hardwick was a worgen captain of Gilneas that would appear in Stormwind City prior to the discovery of Pandaria. Jes-Tereth would try lure him to join the Alliance navy's cause by bringing him  [Diluted Lime Sulfur],  [Dogwood Extrac..." },
  ["captain rupert"] = { 2, "', "Captain Rupert can be found in Zul'Drak." },
  ["captain saeed"] = { 2, "military leader for the Protectorate", "Captain Saeed can be found in the Netherstorm. Saeed is a military leader for the Protectorate." },
  ["captain trueflame"] = { 2, "Arathi located in Dunelle's Kindness in Hallowfall", "Captain Trueflame is an Arathi located in Dunelle's Kindness in Hallowfall. She is in charge of scouts who protect and light the passageways of Hallowfall for Arathi citizens." },
  ["captain tyralius"] = { 2, "ethereal captain of the Protectorate imprisoned by the Et...", "Captain Tyralius is an ethereal captain of the Protectorate imprisoned by the Ethereum in Captain Tyralius's Prison in Netherstorm. He is guarded by Warden Icoshock whom Commander Ameer recruits adventurers to kill and retrieve  [The Warden's Key]..." },
  ["captain vor'lek"] = { 2, "mantid located in the Vale of Eternal Blossoms", "Captain Vor'lek is a mantid located in the Vale of Eternal Blossoms." },
  ["captain whumphrus"] = { 2, "tuskarr", "Captain Whumphrus is a tuskarr." },
  ["captain zovax"] = { 2, "ethereal located in Netherstorm", "Captain Zovax is an ethereal located in Netherstorm." },
  ["captive aspirant"] = { 2, "', "Captive Aspirants are gnome, human, tauren, and jungle troll prisoners found inside Black Cages all over Deathspeaker's Watch in Icecrown. Players are tasked to free several unlucky Captive Aspirants and Kul the Reckless on the daily quest  [25-30..." },
  ["captive child"] = { 2, "', "Captive Children are human and draenei children located in Veil Skith in Terokkar Forest." },
  ["captive druid of the talon"] = { 2, "', "Captive Druid of the Talons are held captive in Firelands." },
  ["captive footman"] = { 2, "', "Captive Footmen are draenei located in Zul'Drak." },
  ["captive miner"] = { 2, "', "Captive Miners are humans and dwarves located in Detention Block in Blackrock Depths." },
  ["captive sha'tari citizen"] = { 2, "', "Captive Sha'tari Citizens are draenei located in Talador." },
  ["captive sha'tari peacekeeper"] = { 2, "', "Captive Sha'tari Peacekeepers are draenei prisoners located in Talador." },
  ["captive shieldmaiden"] = { 2, "vrykul located in Stormheim during Legion Assaults", "Captive Shieldmaiden is a vrykul located in Stormheim during Legion Assaults." },
  ["captive spitescale scout"] = { 2, "', "Captive Spitescale Scouts are captured naga located in Darkspear Training Grounds on the Echo Isles in Durotar. They are guarded by a Darkspear Jailor." },
  ["captive tadpole"] = { 2, "baby murloc located in Suramar", "Captive Tadpole is a baby murloc located in Suramar." },
  ["captive tortollan"] = { 2, "', "Captive Tortollans are tortollans trapped in Naga Cages in Nazmir and at Atal'Gral and Dreadpearl Shallows in Zuldazar." },
  ["captive tuskarr"] = { 2, "', "Captive Tuskarr are tuskarr located at Lost Kanniak in Brackenhide Hollow." },
  ["captive vrykul"] = { 2, "', "Captive Vrykul are vrykul found in the Forlorn Mine behind Sifreldar Village in the Storm Peaks." },
  ["captive vrykul (stormheim)"] = { 2, "', "Captive Vrykul are vrykul found at Storm's Reach in Stormheim during the Legion Assaults when  [10-45LI WQ] Souls of the Vrykul is up." },
  ["captive worgen"] = { 2, "', "Captive Worgen can be found imprisoned in stocks within the town of Duskhaven in Gilneas. Players are initially held with them, so it may be presumed that these remaining captives are either those worgen that have yet to take the cure, or those th..." },
  ["captured argent scout"] = { 2, "', "Captured Argent Scouts are located at Mord'rethar: The Death Gate and the Court of Bones in Icecrown." },
  ["captured blackfuse engineer"] = { 2, "goblin found in Warspear of Ashran", "Captured Blackfuse Engineer is a goblin found in Warspear of Ashran. He is being interrogated by a Warspear Bruiser and Bruiser Snaptoe." },
  ["captured bloodfang worgen"] = { 2, "', "Captured Bloodfang Worgen are three captured worgen located in the Southpoint Gate in Hillsbrad Foothills. Their fate is to be decided by the Forsaken High Command." },
  ["captured brave"] = { 2, "', "Captured Braves are tauren located in the Thornsnarl in Mulgore. They have been captured by the quilboar and are being held in cages." },
  ["captured civilian"] = { 2, "', "Captured Civilians are Horde civilians captured by the Burning Legion during the Legion Invasions. By the time adventurers arrives to the Kor'kron meat camp in the Northern Barrens they are already dead, their bodies surrounded with an aura of dar..." },
  ["captured crusader"] = { 2, "', "Captured Crusaders need to be rescued in  [25-30] Into The Wild Green Yonder. It is done by the player riding one of the Argent Skytalons provided by Penumbrius in Argent Vanguard." },
  ["captured death's rise spy"] = { 2, "', "Captured Death's Rise Spies are dead death knights located in the Hidden Hollow in Icecrown. They hang suspended in the air while groups of Onslaught Darkweavers perform rituals on them." },
  ["captured demolitionist"] = { 2, "', "Captured Demolitionists are gnomes found in Frostmane Hold in Dun Morogh, where they have been imprisoned by the Rockjaw troggs who have taken over the area." },
  ["captured druid"] = { 2, "', "Captured Druids are night elf, tauren, jungle troll, and worgen druids located on the Broken Shore." },
  ["captured forsworn"] = { 2, "', "Captured Forsworn are kyrian located in Perdition Hold in the Maw." },
  ["captured freewind brave"] = { 2, "Freewind Post guard", "Captured Freewind Brave was a Freewind Post guard that was captured during the attack of the town by the Grimtotem tribe. After his rescue he becomes Freewind Brave." },
  ["captured furbolg"] = { 2, "', "Captured Furbolgs are furbolgs of the Foulweald tribe held captive at Silverwind Refuge in Ashenvale." },
  ["captured gnome"] = { 2, "gnome engineering vendor located at Zabra'jin in Zangarmarsh", "Captured Gnome is a gnome engineering vendor located at Zabra'jin in Zangarmarsh. He is watched over by Guard Untula." },
  ["captured goblin"] = { 2, "', "Captured Goblins are goblins located in Slave Pits on the Lost Isles." },
  ["captured goblin bughunter"] = { 2, "', "Captured Goblin Bughunters are goblins located in the Gaping Chasm in Tanaris. They can be freed from Hazzali Cocoons." },
  ["captured gor'vosh stoneshaper"] = { 2, "', "Captured Gor'vosh Stoneshaper are non-attackable ogres found imprisoned in Brute's Rise in Ashran. Players can interact with their prisons to free them, causing the Stoneshaper to grant the player the Boulder Shield buff." },
  ["captured grimtotem"] = { 2, "', "Captured Grimtotems are tauren imprisoned in demonic cages in Darkcloud Pinnacle in Thousand Needles during the Burning Legion's third invasion. Magatha Grimtotem tasked the Farseer of the Earthen Ring with rescuing them." },
  ["captured halaani vindicator"] = { 2, "', "Captured Halaani Vindicators are draenei prisoners located in Garadar in Nagrand." },
  ["captured hyjal druid"] = { 2, "', "Captured Hyjal Druids are night elf and tauren druids trapped in Cinderweb Cocoons in Widow's Clutch in the Molten Front. Once rescued, they transform into stormcrows." },
  ["captured krokul"] = { 2, "', "Captured Krokul are broken located in the Petrified Forest in Krokuun. They are made into Ur'zul by the local eredar." },
  ["captured leyspine murloc"] = { 2, "murloc", "Captured Leyspine Murloc is a murloc." },
  ["captured marine (twilight ascension)"] = { 2, "', "Captured Marines were humans and dwarves held in Bloodeye Cages in the Twilight Gate in the Twilight Highlands." },
  ["captured mercenary captain (alliance)"] = { 2, "draenei or dwarf located in Ulduar", "The Captured Mercenary Captain is a draenei or dwarf located in Ulduar. He is accompanied by Captured Mercenary Soldiers." },
  ["captured mercenary captain (horde)"] = { 2, "', "The Captured Mercenary Captain is located in Ulduar. He is accompanied by Captured Mercenary Soldiers." },
  ["captured mercenary soldier (alliance)"] = { 2, "', "Captured Mercenary Soldiers are located in Ulduar, accompanying Captured Mercenary Captain. They are only available to Horde players." },
  ["captured mercenary soldier (horde)"] = { 2, "', "Captured Mercenary Soldiers are located in Ulduar, accompanying Captured Mercenary Captain. They are only available to Alliance players." },
  ["captured messenger"] = { 2, "dracthyr located in Zaralek Cavern", "Captured Messenger is a dracthyr located in Zaralek Cavern." },
  ["captured miner (ashran)"] = { 2, "', "Captured Miners are deceased characters located in Ashran." },
  ["captured miner (bloodmaul slag mines)"] = { 2, "', "Captured Miners are draenei, orcs, and sporelings located in the Bloodmaul Slag Mines." },
  ["captured mosshide"] = { 2, "', "Captured Mosshides are gnolls located in central Wetlands. They have been captured by Dark Iron Trappers and placed in Gnoll Cages." },
  ["captured mountaineer"] = { 2, "', "Captured Mountaineer could be found in the basement of the Gallows' End Tavern in Tirisfal Glades. Renee Lauer retold her story to the mountaineer and he liked the story." },
  ["captured nightbane"] = { 2, "', "Captured Nightbane are a pair of worgen located in Raven Hill in Duskwood. Vassandra Stormclaw is testing a cure on them." },
  ["captured operative"] = { 2, "', "Captured Operatives are Covert Operatives that are at Frostmane Retreat in Dun Morogh during the Legion Invasions. They could be found encaged by demons." },
  ["captured prisoner"] = { 2, "', "Captured Prisoners are orc and draenei prisoners located in the Maw of Souls in Hellfire Citadel." },
  ["captured protectorate vanguard"] = { 2, "ethereal quest giver located at the Ethereum Staging Grou...", "Captured Protectorate Vanguard is an ethereal quest giver located at the Ethereum Staging Grounds in the Netherstorm." },
  ["captured rangari"] = { 2, "', "Captured Rangari are draenei located in The Pit in Gorgrond. Some are tortured by Gruesome Torturers." },
  ["captured rangari scout"] = { 2, "', "Captured Rangari Scouts are draenei located in Hellfire Citadel." },
  ["captured razormane"] = { 2, "Razormane Pillager after being captured during  [5-30] Dr...", "The Captured Razormane is a Razormane Pillager after being captured during  [5-30] Drag it Out of Them. After that, she can be found at the Grol'dom Farm in the Northern Barrens, ready to be interrogated." },
  ["captured servant of azora"] = { 2, "gnome tailoring vendor located in Render's Valley in the ...", "Captured Servant of Azora is a gnome tailoring vendor located in Render's Valley in the Redridge Mountains. He had been captured by the Blackrock orcs." },
  ["captured tadpole"] = { 2, "', "Captured Tadpoles are murlocs located in Highmountain." },
  ["captured tenant"] = { 2, "', "Captured Tenants are goblins located at Venturewood in the Undermine." },
  ["captured tortollan"] = { 2, "', "Captured Tortollans are tortollan prisoners." },
  ["captured tuskarr prisoner"] = { 2, "tuskarr located at Riplash Strand in the Borean Tundra", "The Captured Tuskarr Prisoner is a tuskarr located at Riplash Strand in the Borean Tundra. Look on the beach to the southwest of Karuk, south of the graveyard." },
  ["captured valgarde mage"] = { 2, "objective of the quest  [10-30] Prisoners of Wyrmskull", "Captured Valgarde Mages are Alliance-aligned sorcerers - usually humans and draenei - held captive by the vrykul of Wyrmskull Village. Restoring their freedom is the objective of the quest  [10-30] Prisoners of Wyrmskull." },
  ["captured valgarde paladin"] = { 2, "', "Captured Valgarde Paladins are dwarf prisoners found in Wyrmskull Village in the Howling Fjord." },
  ["captured vile fin minor oracle"] = { 2, "murloc captured with a  [Murloc Leash] by the Horde adven...", "Captured Vile Fin Minor Oracle is a murloc captured with a  [Murloc Leash] by the Horde adventurer in Whispering Shore in Tirisfal Glades. It is brought to Sedrick Calston and becomes Sparky." },
  ["captured vile fin puddlejumper"] = { 2, "murloc captured with a  [Murloc Leash] by the Horde adven...", "Captured Vile Fin Puddlejumper is a murloc captured with a  [Murloc Leash] by the Horde adventurer in Whispering Shore in Tirisfal Glades. It is brought to Sedrick Calston and becomes Speckle." },
  ["captured vrykul"] = { 2, "', "The Captured Vrykul are vrykul prisoners found in Azuregale Bay in Suramar." },
  ["captured vulpera"] = { 2, "', "Captured Vulpera are vulpera that appear around the Port of Zem'lan in Vol'dun while the Bonus Objective  [30-59B] Monsters of Zem'lan is active. Freeing them will increase the Bonus Objective progress by 4%." },
  ["captured warrior"] = { 2, "', "Captured Warriors are located in Felrage Strand on the Broken Shore." },
  ["captured wastelander"] = { 2, "', "Captured Wastelanders are ethereals located in Shadow Point in K'aresh." },
  ["captured worgen"] = { 2, "', "Captured Worgen are worgen of the Wolfheart pack." },
  ["caravan defender"] = { 2, "neutral quest hub in Terokkar Forest", "Caravan Defenders are the guards of the Refugee Caravan, a neutral quest hub in Terokkar Forest." },
  ["caravan guard (maldraxxus)"] = { 2, "', "Caravan Guards are brokers of Cartel Ba who first appear during  [60] Explosive Schemes, escorting a caravan through the Scaplian Ridge tunnel in Maldraxxus alongside the Broker Tradesmen. After the caravan is blown up, they can be seen standing g..." },
  ["caravan guardian"] = { 2, "', "Caravan Guardians are vulpera that appear in Vol'dun during Faction Assaults when the Vulpera for a Day buff is active." },
  ["cardenaas"] = { 2, "draenei found at the central square of Stormshield", "Cardenaas is a draenei found at the central square of Stormshield. He is speaking with Glenn Ramtoss." },
  ["caregiver abidaar"] = { 2, "draenei innkeeper located at Telredor in Zangarmarsh", "Caregiver Abidaar is a draenei innkeeper located at Telredor in Zangarmarsh." },
  ["caregiver breel"] = { 2, "draenei innkeeper located at the Seat of the Naaru in the...", "Caregiver Breel is a draenei innkeeper located at the Seat of the Naaru in the Exodar. He runs the caregiver center known as The Exobar." },
  ["caregiver chellan"] = { 2, "draenei innkeeper located at Azure Watch in Azuremyst Isle", "Caregiver Chellan is a draenei innkeeper located at Azure Watch in Azuremyst Isle." },
  ["caregiver iqniq"] = { 2, "tuskarr innkeeper found in Kamagua in the Howling Fjord", "Caregiver Iqniq is a tuskarr innkeeper found in Kamagua in the Howling Fjord." },
  ["caregiver mumik"] = { 2, "tuskarr innkeeper located at Moa'ki Harbor in Dragonblight", "Caregiver Mumik is a tuskarr innkeeper located at Moa'ki Harbor in Dragonblight." },
  ["caregiver poallu"] = { 2, "tuskarr innkeeper located in Kalu'ak village called Unu'p...", "Caregiver Poallu is a tuskarr innkeeper located in Kalu'ak village called Unu'pe in the Borean Tundra." },
  ["caregiver selenis"] = { 2, "Ascended kyrian located at the Cliffs of Respite in Bastion", "Caregiver Selenis is an Ascended kyrian located at the Cliffs of Respite in Bastion." },
  ["caretaker alaric"] = { 2, "human", "Caretaker Alaric is a human who appears to guard over Trollbane's Tomb with Trol'kalar, contained in the crypt of Stromgarde in the Arathi Highlands." },
  ["caretaker alen"] = { 2, "human general goods vendor located near Light's Hope Chap...", "Caretaker Alen is a human general goods vendor located near Light's Hope Chapel in the Eastern Plaguelands. He is affiliated with the Argent Dawn." },
  ["caretaker allen"] = { 2, "human located at Barrowknoll Cemetery in Drustvar", "Caretaker Allen is a human located at Barrowknoll Cemetery in Drustvar. Daisy, Wendy, and Rusty are next to him." },
  ["caretaker aluuro"] = { 2, "draenei innkeeper located at the Altar of Sha'tar in Shad...", "Caretaker Aluuro is a draenei innkeeper located at the Altar of Sha'tar in Shadowmoon Valley. He will not speak to those aligned with the Scryers." },
  ["caretaker bagdur"] = { 2, "stasis-locked earthen found in Mourning Rise in the Isle ...", "Caretaker Bagdur is a stasis-locked earthen found in Mourning Rise in the Isle of Dorn. Once a celebrated Stormrider, she was discharged from their ranks when she turned away from Oathsworn beliefs." },
  ["caretaker calisaphene"] = { 2, "kyrian innkeeper", "Caretaker Calisaphene is a kyrian innkeeper and vendor located at Sagehaven in Bastion." },
  ["caretaker caryn"] = { 2, "Ascended kyrian innkeeper", "Caretaker Caryn is an Ascended kyrian innkeeper and vendor located in Elysian Hold in Bastion." },
  ["caretaker dorgad"] = { 2, "stasis-locked earthen found in Mourning Rise in the Isle ...", "Caretaker Dorgad is a stasis-locked earthen found in Mourning Rise in the Isle of Dorn. He and his fused, Caretaker Nattar, were the ones who named Mourning Rise to commemorate and honor Kriegval." },
  ["caretaker kristina"] = { 2, "Ascended kyrian innkeeper", "Caretaker Kristina is an Ascended kyrian innkeeper and vendor located at the Terrace of the Collectors in Bastion." },
  ["caretaker mirene"] = { 2, "kyrian innkeeper", "Caretaker Mirene is a kyrian innkeeper and vendor located in Aspirant's Rest in Bastion. She was part of the reception the Archon arranged for a Maw Walker, who decided to join the Kyrian Covenant, in honor of their efforts against the Maldraxxus ..." },
  ["caretaker movra"] = { 2, "Broken quest giver", "Caretaker Movra is a Broken quest giver, innkeeper, and a vendor found at the Silver Tide Hollow in the Shimmering Expanse. He sends adventurers to kill 12 Spiketooth Eels." },
  ["caretaker nattar"] = { 2, "stasis-locked earthen found in Mourning Rise in the Isle ...", "Caretaker Nattar is a stasis-locked earthen found in Mourning Rise in the Isle of Dorn. She and her fused, Caretaker Dorgad, were the ones who named Mourning Rise in honor of Kriegval." },
  ["caretaker nuunwa"] = { 2, "Broken innkeeper of the Earthen Ring in the sanctuary of ...", "Caretaker Nuunwa is a Broken innkeeper of the Earthen Ring in the sanctuary of the Temple of Earth found in the center of Deepholm. He remains after many of the other members of the Earthen Ring leave." },
  ["caretaker okdan"] = { 2, "stasis-locked earthen found in Mourning Rise in the Isle ...", "Caretaker Okdan is a stasis-locked earthen found in Mourning Rise in the Isle of Dorn. Known by his unit of friends for striking a victorious pose when he won an argument." },
  ["caretaker pancha"] = { 2, "venthyr located in the Halls of Atonement in Revendreth", "Caretaker Pancha is a venthyr located in the Halls of Atonement in Revendreth. She is holding Werimu the Traitor-King chained." },
  ["caretaker radok"] = { 2, "stasis-locked earthen found in Mourning Rise in the Isle ...", "Caretaker Radok is a stasis-locked earthen found in Mourning Rise in the Isle of Dorn. Struck down while protecting Mourning Rise from nerubians, he was beloved by all his sector." },
  ["caretaker smithers"] = { 2, "human standing around outside the graveyard close to Sout...", "Caretaker Smithers was a human standing around outside the graveyard close to Southshore, until he fled with the others when the Forsaken destroyed the town. Smithers and the other Southshore townsfolk traveled to Fenris Keep where they were convi..." },
  ["caretaker tedo"] = { 2, "venthyr located at Chalice District in Revendreth", "Caretaker Tedo is a venthyr located at Chalice District in Revendreth. He also attends the Ember Court." },
  ["caretaker theo"] = { 2, "Ascended kyrian innkeeper", "Caretaker Theo is an Ascended kyrian innkeeper and vendor located in Elysian Hold in Bastion." },
  ["cargen fairleifen"] = { 2, "Arathi located in Mereldar in Hallowfall", "Cargen Fairleifen is an Arathi located in Mereldar in Hallowfall." },
  ["carnivous the breaker"] = { 2, "rare furbolg found roaming Twilight Vale in Darkshore", "Carnivous the Breaker is a rare furbolg found roaming Twilight Vale in Darkshore. He is on a 2-3 hour respawn timer." },
  ["carousing aristocrat"] = { 2, "', "Carousing Aristocrats are venthyr located in the Eternal Terrace in Revendreth." },
  ["carriage guard"] = { 2, "', "Carriage Guards are venthyr located in Revendreth." },
  ["carrosh"] = { 2, "satyr located at the Cleft in Teldrassil", "Carrosh was a satyr located at the Cleft in Teldrassil." },
  ["carseng"] = { 2, "centaur flight master located in southern Teerakai in the...", "Carseng is a centaur flight master located in southern Teerakai in the Ohn'ahran Plains, where he is accompanied by the Flight Master's Assistant and a couple of Messenger Ohuna, and in the Nokhud Offensive. He is the only NPC to be present in the..." },
  ["carson crazybread"] = { 2, "gnome general goods vendor located in New Tinkertown in D...", "Carson Crazybread is a gnome general goods vendor located in New Tinkertown in Dun Morogh." },
  ["cartel appropriator"] = { 2, "', "Cartel Appropriators are brokers." },
  ["cartel battlemancer"] = { 2, "', "Cartel Battlemancers are brokers." },
  ["cartel boss xy'eolm"] = { 2, "leader of Cartel Xy", "Cartel Boss Xy'eolm is the leader of Cartel Xy. She can be found lounging on a balcony above Astral Getaways in Tazavesh." },
  ["cartel brightcaster"] = { 2, "', "Cartel Brightcasters are brokers." },
  ["cartel grandcaster"] = { 2, "', "Cartel Grandcaster are brokers." },
  ["cartel manifestor"] = { 2, "', "Cartel Manifestors are brokers." },
  ["cartel negotiator"] = { 2, "Veiled Market", "Cartel Negotiators are brokers located in Myza's Oasis in Tazavesh, the Veiled Market. They are seen in a booth with Trade Prince Gallywix." },
  ["cartel neophyte"] = { 2, "', "Cartel Neophytes are brokers." },
  ["cartel om botanist"] = { 2, "', "Cartel Om Botanists are brokers located at Eco-Dome: Primus on K'aresh." },
