  ["cartel om technician"] = { 2, "', "Cartel Om Technicians are brokers located in Eco-Dome: Primus on K'aresh." },
  ["cartel overseer"] = { 2, "', "Cartel Overseers are brokers located in the Sepulcher of the First Ones." },
  ["cartel plunderer"] = { 2, "', "Cartel Plunderers are brokers located in Sepulcher of the First Ones." },
  ["cartel reinforcer"] = { 2, "', "Cartel Reinforcers are brokers located at the Broker's Sting in the Sepulcher of the First Ones." },
  ["cartel skulker"] = { 2, "Veiled Market", "Cartel Skulkers are brokers located in Tazavesh, the Veiled Market." },
  ["cartel spellfist"] = { 2, "', "Cartel Spellfists are brokers." },
  ["cartel stevedore"] = { 2, "Veiled Market in K'aresh", "Cartel Stevedores are brokers located in Tazavesh, the Veiled Market in K'aresh." },
  ["cartel substantiator"] = { 2, "', "Cartel Substantiators are brokers." },
  ["cartel ve pathfinder"] = { 2, "broker located in the Maw", "Cartel Ve Pathfinder is a broker located in the Maw." },
  ["cartel wiseguy"] = { 2, "Veiled Market", "Cartel Wiseguys are brokers located in Tazavesh, the Veiled Market." },
  ["cartel xy agent"] = { 2, "', "Cartel Xy Agents are brokers that appear periodically around adventurers who have  [Xy'rath's Signature Saber] equiped or in their bags." },
  ["cartel xy plunderer"] = { 2, "', "Cartel Xy Plunderers are brokers located in Zereth Mortis." },
  ["cartel xy researcher"] = { 2, "', "Cartel Xy Researchers are brokers located in the Felicitous Glade in Zereth Mortis." },
  ["cartel xy saboteur"] = { 2, "broker located just outside Haven in Zereth Mortis", "The Cartel Xy Saboteur is a broker located just outside Haven in Zereth Mortis. It appears when assessing the southeast Shield Conduit." },
  ["cartel zo guardian"] = { 2, "', "Consortium Arcanists are brokers located at Shadow Point, as well as Eco-Dome: Rhovan and the Oasis on K'aresh." },
  ["caruk bloodwind"] = { 2, "Highmountain tauren", "Caruk Bloodwind is a Highmountain tauren that was the first leatherworker in Highmountain. He invented tanning." },
  ["carvo blastbolt"] = { 2, "gnome quest giver", "Carvo Blastbolt is a gnome quest giver and member of S.A.F.E. who can be found in the Train Depot of Gnomeregan." },
  ["cassa crimsonwing"] = { 2, "dwarf found standing next to Baldruc", "Cassa Crimsonwing is a dwarf found standing next to Baldruc, the gryphon master of Theramore Isle and her mentor. She is involved in the quest  [15-30] Survey Alcaz Island - speaking to her while on the quest will allow you to fly around the islan..." },
  ["cassia the slitherqueen"] = { 2, "rare naga found at the Bloodwash Shrine in the Blasted Lands", "Cassia the Slitherqueen is a rare naga found at the Bloodwash Shrine in the Blasted Lands." },
  ["cassius"] = { 2, "Ascended kyrian", "Cassius is an Ascended kyrian and the Flight Master of Elysian Hold in Bastion. He was part of the grand reception the Archon arranged for a Maw Walker, who decided to join the Kyrian Covenant, in honor of their efforts against the Maldraxxus incu..." },
  ["castalia hawklans"] = { 2, "Arathi located on the road leading east from Mereldar in ...", "Castalia Hawklans is an Arathi located on the road leading east from Mereldar in Hallowfall." },
  ["castaway peacekeeper"] = { 2, "', "Castaway Peacekeepers are humans located at Castaway Point in Tiragarde Sound." },
  ["castellan niklaus"] = { 2, "venthyr located in the Feast of Arrogance in Castle Nathria", "Castellan Niklaus is a venthyr located in the Feast of Arrogance in Castle Nathria, as part of the Council of Blood encounter." },
  ["castillian"] = { 2, "mysterious mage of the Argent Dawn", "Castillian was a mysterious mage of the Argent Dawn. He never spoke, wore a mask to conceal his identity, and was among those who chose to accompany Darion Mograine into Naxxramas to rescue his father, Alexandros Mograine." },
  ["catacomb guard"] = { 2, "', "Catacomb Guards are venthyr located at the Catacombs of Regret in Revendreth." },
  ["cataloger adams"] = { 2, "human located by the river at Thunderspine Thicket", "Cataloger Adams is a human located by the river at Thunderspine Thicket and in the eastern river in the Ohn'ahran Plains. She is trying to take a photo of a Riverbend Kit at each spot." },
  ["cataloger alexia"] = { 2, "human located near the entrance of the Valdrakken Treasur...", "Cataloger Alexia is a human located near the entrance of the Valdrakken Treasury Hoard in Valdrakken. She is seen photographing a Holiday Enthusiast." },
  ["cataloger chirplet"] = { 2, "gnome located in the Forbidden Reach", "Cataloger Chirplet is a gnome located in the Forbidden Reach." },
  ["cataloger grazewell"] = { 2, "tauren located in Shady Sanctuary in the Ohn'ahran Plains", "Cataloger Grazewell is a tauren located in Shady Sanctuary in the Ohn'ahran Plains." },
  ["cataloger ryler"] = { 2, "vulpera located on a bridge in northern in the Azure Span", "Cataloger Ryler is a vulpera located on a bridge in northern in the Azure Span." },
  ["cataloguer arnsvala"] = { 2, "earthen located at the Oath Gate in Dornogal", "Cataloguer Arnsvala is an earthen located at the Oath Gate in Dornogal. Chawlay can be found sitting on a box nearby." },
  ["cataloguing enthusiast"] = { 2, "', "Cataloguing Enthusiasts are members of the Dragonscale Expedition accompanying Cataloger Wulferd in the Trade District and Stormwind Harbor in Stormwind City during  [10-70] Expeditionary Coordination." },
  ["catapult driver"] = { 2, "', "Catapult Drivers are earthen piloting Earthen Catapults in Deepholm. One of them is driving an Earthen Catapult to Needlerock Slag for  [30-35] Close Escort." },
  ["catrina"] = { 2, "', "Catrina is one of the NPCs involved with the Day of the Dead world event, appearing alongside Chapman at all capital city graveyards. She will transform all who /dance with her and award the achievement  [Dead Man's Party]." },
  ["cauldronbearer blakor"] = { 2, "djaradin located in the Waking Shores", "Cauldronbearer Blakor is a djaradin located in the Waking Shores." },
  ["cautious drakerider"] = { 2, "', "Cautious Drakeriders are draenei and humans located at the Skytop Observatory in the Waking Shores. They can also be found in the Azure Span." },
  ["cautious fisher"] = { 2, "tuskarr located in Tyrhold in the Thaldraszus", "Cautious Fisher is a tuskarr located in Tyrhold in the Thaldraszus. Next to him is the Large Lunker Sighting post." },
  ["caverns of time portal-keeper"] = { 2, "', "Caverns of Time Portal-Keepers are found outside the Caverns of Time in Tanaris during the Bronze Celebration, holding portals to areas with Chests of Props on Azeroth and beyond, as well as portals back to the Caverns of Time. Each day, a differe..." },
  ["cedric bronzeflint"] = { 2, "dwarf general goods vendor stationed at Whelgar's Retreat...", "Cedric Bronzeflint is a dwarf general goods vendor stationed at Whelgar's Retreat in the Wetlands." },
  ["cedrick fallrook"] = { 2, "ambitious", "Cedrick Fallrook was an ambitious and arrogant son of Terrence Fallrook who lived in the Fallrook Estate. His family owned a winery." },
  ["cedrik 'the raza' fixmantra"] = { 2, "gnome located in Deliverance Point in Broken Shore", "Cedrik 'The Raza' Fixmantra is a gnome located in Deliverance Point in Broken Shore." },
  ["ceeqa the peacetaker"] = { 2, "djaradin located at the Field of Ferocity in the Ohn'ahra...", "Ceeqa the Peacetaker is a djaradin located at the Field of Ferocity in the Ohn'ahran Plains." },
  ["celadine the fatekeeper"] = { 2, "tauren located at the Dreamgrove in Val'sharah", "Celadine the Fatekeeper is a tauren located at the Dreamgrove in Val'sharah. She is the lead historian of the Dreamweavers and wrote the Tome of the Ancients." },
  ["celebrating ascended"] = { 2, "', "Celebrating Ascended are kyrian located in the Seat of the Archon during  [60] The Grand Reception." },
  ["celebrating aspirant"] = { 2, "', "Celebrating Aspirants are kyrian of the Ascended and Forsworn located in the Seat of the Archon during  [60] The Grand Reception." },
  ["celestine of the harvest"] = { 2, "worgen druid of Gilneas", "Celestine of the Harvest is a worgen druid of Gilneas." },
  ["celestra brightmoon"] = { 2, "worgen", "Celestra Brightmoon is a worgen who can be encountered during Island Expeditions." },
  ["celidh aletracker"] = { 2, "dwarf stable master located at Valiance Keep in the Borea...", "Celidh Aletracker is a dwarf stable master located at Valiance Keep in the Borean Tundra." },
  ["celle wilde"] = { 2, "Arathi located in the Hungering Pool in Hallowfall", "Celle Wilde is an Arathi located in the Hungering Pool in Hallowfall. He can transport you to just outside of The Hungering Pool if asked." },
  ["cellyn"] = { 2, "female high elf mentioned in Death Knight", "Cellyn is a female high elf mentioned in Death Knight. According to Faltora, she is a show off and she was going to organize a banquet." },
  ["celosel nightgiver"] = { 2, "void elf captain", "Celosel Nightgiver is a void elf captain who worked under Alleria Windrunner and Turalyon in their mission to hunt down and capture Sylvanas Windrunner in the Arathi Highlands. He worked closely with Senn and after discovering where Visrynn (a dar..." },
  ["cemmorhan"] = { 2, "draenei herbalism trainer located in Alchemy & Herbalism ...", "Cemmorhan is a draenei herbalism trainer located in Alchemy & Herbalism in the Vault of Lights in the Exodar. This section concerns content related to Legion." },
  ["cenarion dreamwarden"] = { 2, "', "Cenarion Dreamwardens can be found in Moonglade, battling the enroaching Nightmare within the Stormrage Barrow Dens." },
  ["cenarion emissary blackhoof"] = { 2, "level 80 quest giver located in the Valley of Wisdom in t...", "Cenarion Emissary Blackhoof is a level 80 quest giver located in the Valley of Wisdom in the orcish city of Orgrimmar. He stands next to the portal which takes the adventurers to Moonglade after reaching level 80." },
  ["cenderragg"] = { 2, "earthen located in the Opalcreg on the Isle of Dorn", "Cenderragg is an earthen located in the Opalcreg on the Isle of Dorn." },
  ["cendrii"] = { 2, "draenei food", "Cendrii is a draenei food and drink vendor located at Halaa in Nagrand. She is only available when the Alliance controls Halaa." },
  ["cendvin"] = { 2, "earthen located in Cinderbrew Meadery on the Isle of Dorn", "Cendvin is an earthen located in Cinderbrew Meadery on the Isle of Dorn." },
  ["cenrrrn cirrgl mender"] = { 2, "', "Cenrrrn Cirrgl Menders are murlocs located in Tyrhold Reservoir in Thaldraszus during Time Rifts." },
  ["cenrrrn cirrgl mooncaller"] = { 2, "', "Cenrrrn Cirrgl Mooncallers are murlocs located in Tyrhold Reservoir in Thaldraszus during Time Rifts." },
  ["cenrrrn cirrgl tideshifter"] = { 2, "', "Cenrrrn Cirrgl Tideshifters are murlocs located in Tyrhold Reservoir in Thaldraszus during Time Rifts. They can shapeshift into Sharks, which suggests that murlocs can be druids, at least in this timeline." },
  ["centaur (beta)"] = { 2, "', "Centaur are unreleased centaur." },
  ["centaur archer"] = { 2, "', "Centaur Archers are centaur archer creeps that can be encountered in the Barrens tileset." },
  ["centaur champion"] = { 2, "heavy hitter melee unit", "The Centaur Champion is a heavy hitter melee unit that is generally in charge of a group of centaur attackers." },
  ["centaur commander"] = { 2, "centaur controlled during  [10-30] Into the Fray!", "The Centaur Commander is a centaur controlled during  [10-30] Into the Fray! and  [10-30] Death to Agogridon in Desolace." },
  ["centaur conqueror"] = { 2, "level 12 centaur from Warcraft III: The Frozen Throne", "The Centaur Conqueror is a level 12 centaur from Warcraft III: The Frozen Throne. He was the leader of a group of centaurs in Dustwallow Marsh during the Founding of Durotar." },
  ["centaur deathcaller"] = { 2, "centaur caster", "The Centaur Deathcaller is a centaur caster that appears in the Founding of Durotar campaign." },
  ["centaur drudge"] = { 2, "', "Centaur Drudges are centaur creeps that can be encountered in the Barrens tileset." },
  ["centaur firecaller"] = { 2, "', "Centaur Firecallers are level 6 centaur pyromancers appearing in the Founding of Durotar campaign." },
  ["centaur guardian"] = { 2, "', "Centaur Guardians are centaur located throughout Shok'Thokar in Desolace after completion of  [10-30] Death to Agogridon. They can have the appearance of any of the three newly-united centaur clans: Gelkis, Kolkar, or Magram." },
  ["centaur impaler"] = { 2, "', "Centaur Impalers are centaur archer creeps that can be encountered in the Barrens tileset." },
  ["centaur khan"] = { 2, "', "Centaur Khans are centaur khan creeps that can be encountered in the Barrens tileset. They are the most powerful centaur found in melee games." },
  ["centaur marauder"] = { 2, "', "Centaur Marauders are centaurs appearing in the Founding of Durotar campaign." },
  ["centaur mauler"] = { 2, "', "Centaur Maulers are centaur who accompany the player while they control a Centaur Commander during  [10-30] Into the Fray! and  [10-30] Death to Agogridon in Desolace." },
  ["centaur outrunner"] = { 2, "', "Centaur Outrunners are centaur creeps that can be encountered in the Barrens tileset." },
  ["centaur outrunner (beta)"] = { 2, "centaur", "Centaur Outrunner is a centaur." },
  ["centaur pariah"] = { 2, "centaur", "The Centaur Pariah is a centaur who wanders east of Gelkis Village and south of Mannoroc Coven in southern Desolace. He was exiled by the other centaur for heresy." },
  ["centaur ravager"] = { 2, "', "Centaur Ravagers are centaurs appearing in the Founding of Durotar campaign." },
  ["centaur sorcerer"] = { 2, "', "Centaur Sorcerers are centaur sorcerer creeps that can be encountered in the Barrens tileset." },
  ["centaur torturer"] = { 2, "level 9 centaur from Warcraft III: The Frozen Throne", "The Centaur Torturer was a level 9 centaur from Warcraft III: The Frozen Throne. He was a member of the Kolkar clan of centaur in Dustwallow Marsh during the Founding of Durotar." },
  ["centaur warmonger"] = { 2, "', "Centaur Warmongers are centaur seen fighting the Burning Blade forces in Shok'Thokar in Desolace during  [10-30] Time For Change,  [10-30] Into the Fray!, and  [10-30] Death to Agogridon." },
  ["centaur windchaser"] = { 2, "', "Centaur Windchasers are centaur who accompany the player while they control a Centaur Commander during  [10-30] Into the Fray! and  [10-30] Death to Agogridon in Desolace." },
  ["ceren leadland"] = { 2, "Arathi located in Hallowfall", "Ceren Leadland is an Arathi located in Hallowfall." },
  ["cerie larksong"] = { 2, "alchemy vendor at the Argent Tournament Grounds", "Cerie Larksong is the alchemy vendor at the Argent Tournament Grounds. This section concerns content related to Shadowlands." },
  ["certified explosives expert"] = { 2, "goblin flying in a hot air balloon", "The Certified Explosives Expert is a goblin flying in a hot air balloon who throws bombs on the ground in Cinderfall Grove in Darkshore. They are also present during the Battle for Darkshore." },
  ["chachi the artiste"] = { 2, "venthyr located in Sinfall", "Chachi the Artiste is a venthyr located in Sinfall." },
  ["chae-nan"] = { 2, "', "Chae-nan is one of Warlord Kao's bodyguards and as such was present when his master resurrected by the Zandalari trolls. Under his master's command, Chae-nan joined with the force of 500 Zandalari warriors ordered to destroy the Shado-Pan and thei..." },
  ["chag"] = { 2, "tortollan located in Mangrove Shore in Nazmir", "Chag is a tortollan located in Mangrove Shore in Nazmir. He summons Lucille." },
  ["chaka the ancient"] = { 2, "tortollan located in Little Tortolla in Dazar'alor", "Chaka the Ancient is a tortollan located in Little Tortolla in Dazar'alor. He also appears at Turtle Beach in the Krasarang Wilds during Wanderer's Festival." },
  ["chakaa"] = { 2, "Broken shaman found wandering the Crystal Hall of the Exo...", "Chakaa is a Broken shaman found wandering the Crystal Hall of the Exodar with his two draenei students, Drysc and Sayari, teaching them about the four elements. Drinking an  [Elemental Sapta], obtainable by talking to Seer Skaltesh, reveals that f..." },
  ["chalice resident"] = { 2, "', "Chalice Residents are venthyr located in the Chalice District in Revendreth." },
  ["challenger savina"] = { 2, "worgen", "Challenger Savina is a worgen who can be found outside the Auction House in Stormshield." },
  ["chalyx"] = { 2, "beloved cat pet of Emperor Ninjter", "Chalyx was the beloved cat pet of Emperor Ninjter. A clay statue was commissioned in his memory." },
  ["chamley"] = { 2, "human of the Stromgarde Militia", "Chamley was a human of the Stromgarde Militia who fought against the Syndicate in Arathi Highlands. He fell and his badge was taken by his killer, kept as a trophy until its retrieval by hired adventurers." },
  ["champion aelyse"] = { 2, "human located in the Hall of Champions in the Scarlet Hal...", "Champion Aelyse is a human located in the Hall of Champions in the Scarlet Halls during the quest  [83-88] Light Miswielded. After bringing her to low health, she surrenders to Arator and the adventurer and gives them her weapon." },
  ["champion choruk"] = { 2, "djaradin located in the Waking Shores", "Champion Choruk is a djaradin located in the Waking Shores." },
  ["champion coldmine explorer"] = { 2, "', "Champion Coldmine Explorers are humans and gnomes found in Coldtooth Mine in Alterac Valley when the Alliance controls it." },
  ["champion coldmine guard"] = { 2, "', "Champion Coldmine Guards are orcs and tauren found in Coldtooth Mine in Alterac Valley." },
  ["champion coldmine invader"] = { 2, "', "Champion Coldmine Invaders are dwarves, humans, and night elves found in Coldtooth Mine in Alterac Valley." },
  ["champion commando"] = { 2, "', "Champion Commandos are dwarves located in Alterac Valley. They spawn once Murgot Deepforge gets 1500  [Armor Scraps]." },
  ["champion defender (alterac valley)"] = { 2, "', "Champion Defenders are dwarves found throughout Alterac Valley." },
  ["champion elodie"] = { 2, "worgen located in Stormheim", "Champion Elodie is a worgen located in Stormheim." },
  ["champion guardian"] = { 2, "', "Champion Guardians are orcs and tauren found throughout Alterac Valley." },
  ["champion guardsman"] = { 2, "', "Champion Guardsmen are dwarves located in Alterac Valley." },
  ["champion irondeep guard"] = { 2, "', "Champion Irondeep Guards are dwarves found in the Irondeep Mine in Alterac Valley when the Alliance controls it." },
  ["champion irondeep surveyor"] = { 2, "', "Champion Irondeep Surveyors are found in the Irondeep Mine in Alterac Valley." },
  ["champion mountaineer"] = { 2, "', "Champion Mountaineers are dwarves located in the Arathi Highlands during the Battle for Stromgarde." },
  ["champion mountaineer (alterac valley)"] = { 2, "', "Champion Mountaineers are dwarves located in Alterac Valley." },
  ["champion mukcrush"] = { 2, "ogre located at the Ring of Blood in Nagrand", "Champion Mukcrush is an ogre located at the Ring of Blood in Nagrand. He was taken out by the followers sent from the Frostwall and Lunarfall garrisons." },
  ["champion priest of ironforge"] = { 2, "', "Champion Priests of Ironforge are dwarves located in the Arathi Highlands during the Battle for Stromgarde." },
  ["champion shadowcaster"] = { 2, "', "Champion Shadowcasters are dwarves and Dark Iron dwarves located in the Arathi Highlands during the Battle for Stromgarde." },
  ["champion warrior"] = { 2, "', "Champion Warriors are orcs and tauren located in Alterac Valley." },
  ["champion of ironforge"] = { 2, "', "Champions of Ironforge are dwarves located in the Arathi Highlands during the Battle for Stromgarde." },
  ["chancellor codrin"] = { 2, "venthyr located in Revendreth", "Chancellor Codrin is a venthyr located in Revendreth." },
  ["chancellor ladris"] = { 2, "venthyr located in the Eternal Terrace in Revendreth", "Chancellor Ladris is a venthyr located in the Eternal Terrace in Revendreth. He is the leader of House Primrose." },
  ["chancellor ylenia"] = { 2, "venthyr located in Revendreth", "Chancellor Ylenia is a venthyr located in Revendreth." },
  ["chancellor zelma"] = { 2, "venthyr located in Revendreth", "Chancellor Zelma is a venthyr located in Revendreth." },
  ["chantu"] = { 2, "draenei", "Chantu was a draenei whom Jaruk Bloodfyre and Leena visited at their one year anniversary. He wanted them to stay with him, but Jaruk refused, telling him that they must be on a move from his brother - J'argg Bloodfyre." },
  ["chapman"] = { 2, "', "Chapman can be found at all capital city graveyards during Day of the Dead alongside Catrina. He sells nearly all of the items associated with the event." },
  ["charfang"] = { 2, "gnoll located in the Azure Span", "Charfang is a gnoll located in the Azure Span." },
  ["charfrost looter"] = { 2, "', "Charfrost Looters are Dark Iron dwarves, jungle trolls, and tauren located in the Azure Span." },
  ["charfrost marauder"] = { 2, "', "Charfrost Marauders are dwarves and orcs located in the Azure Span." },
  ["chargath, bane of scales"] = { 2, "djaradin located in the Smoldering Barracks in Neltharus", "Chargath, Bane of Scales is a djaradin located in the Smoldering Barracks in Neltharus." },
  ["charlane"] = { 2, "worgen located in Boralus", "Charlane is a worgen located in Boralus." },
  ["charles northen"] = { 2, "Forsaken located just in front of the Temple of Five Dawn...", "Charles Northen is a Forsaken located just in front of the Temple of Five Dawns in Mandori Village on the Wandering Isle." },
  ["charlga razorflank"] = { 2, "elite quilboar boss found in Razorfen Kraul", "Charlga Razorflank <The Crone> is an elite quilboar boss found in Razorfen Kraul. She is the leader of the Razorfen tribe." },
  ["charlga razorflank (classic)"] = { 2, "quilboar boss found in Razorfen Kraul", "Charlga Razorflank is a quilboar boss found in Razorfen Kraul. She is the leader of the Death's Head and Razorfen tribes." },
  ["charlga razorflank (rumble)"] = { 2, "ranged ground unit of the Beast family in Warcraft Rumble", "Charlga Razorflank is a ranged ground unit of the Beast family in Warcraft Rumble. Charlga's ability is somewhat complicated, but ultimately mixes out the costs of your minis across one another." },
  ["charlina the wrench"] = { 2, "gnome located at the Shimmering Deep in Thousand Needles", "Charlina the Wrench is a gnome located at the Shimmering Deep in Thousand Needles." },
  ["charmonger"] = { 2, "kobold located just north of the Hallowfall Gate in the R...", "Charmonger is a kobold located just north of the Hallowfall Gate in the Ringing Deeps." },
  ["charnas"] = { 2, "goblin", "Charnas of Gadgetzan is a goblin who traveled across Azeroth and sketched its various birds. One of his books ended up with Captain Greydon Thorne and was later found by his son, Aramar Thorne." },
  ["charonus"] = { 2, "boss in the Voidscar Arena", "Charonus is a boss in the Voidscar Arena." },
  ["charred outcast"] = { 2, "', "Charred Outcasts are dead arakkoa found at Veil Zekk in the Spires of Arak." },
  ["chartographer darithel"] = { 2, "dwarf of Keg Leg's Crew located in Brew Bay in the Arathi...", "Chartographer Darithel is a dwarf of Keg Leg's Crew located in Brew Bay in the Arathi Highlands during Plunderstorm." },
  ["chatty citizen"] = { 2, "', "Chatty Citizens are members of the Horde located in Orgrimmar during the Horde War Campaign." },
  ["chatty contender"] = { 2, "', "Chatty Contender is located in the Trade District in Stormwind City. They may appear as a gnome or draenei." },
  ["chatty customer"] = { 2, "Veiled Market in K'aresh", "Chatty Customers are brokers located in Tazavesh, the Veiled Market in K'aresh." },
  ["chay"] = { 2, "Arathi located in Mereldar in Hallowfall", "Chay is an Arathi located in Mereldar in Hallowfall. He, Dolores, and Alfred are observing Arathi Reserves." },
  ["chef (broker)"] = { 2, "Veiled Market", "Chefs are brokers located in Tazavesh, the Veiled Market." },
  ["chef au'krut"] = { 2, "broker located in the Hall of Shapes in Oribos", "Chef Au'krut is a broker located in the Hall of Shapes in Oribos. He teaches Maw Walkers about Shadowlands Cooking recipes." },
  ["chef barbauu'koa"] = { 2, "draenei food", "Chef Barbauu'koa is a draenei food and drink vendor located at the Southport in Spires of Arak." },
  ["chef braf"] = { 2, "orc food", "Chef Braf is an orc food and drink vendor found in Dreadmaul Hold in the Blasted Lands. It's unknown if he survived the Ironmarch." },
  ["chef chewie"] = { 2, "ogre chef located in the Flaming Taps in Cinderbrew Meadery", "Chef Chewie is an ogre chef located in the Flaming Taps in Cinderbrew Meadery." },
  ["chef chum platter"] = { 2, "ogre located in Stormtide Dregs on the Siren Isle", "Chef Chum Platter is an ogre located in Stormtide Dregs on the Siren Isle." },
  ["chef cookie"] = { 2, "dead abomination leftover located in the House of Constru...", "Chef Cookie is a dead abomination leftover located in the House of Constructs in Maldraxxus. The soul of the late 'Captain' Cookie, he is found next to Halis's Lunch Pail." },
  ["chef dinaire"] = { 2, "Arathi located in the Fungal Fields in Hallowfall", "Chef Dinaire is an Arathi located in the Fungal Fields in Hallowfall. He may also show up in Mycomancer Cavern." },
  ["chef galai"] = { 2, "centaur vendor located in Teerakai in the Ohn'ahran Plains", "Chef Galai is a centaur vendor located in Teerakai in the Ohn'ahran Plains." },
  ["chef shikaar"] = { 2, "centaur located in the Ohn'ahran Plains", "Chef Shikaar is a centaur located in the Ohn'ahran Plains." },
  ["chef xy'zin"] = { 2, "broker located in Tazavesh", "Xy'Zin is a broker located in Tazavesh, the Veiled Market in K'aresh." },
  ["chelie coldanvil"] = { 2, "dwarf located at Arbor Glen in Shadowmoon Valley", "Chelie Coldanvil is a dwarf located at Arbor Glen in Shadowmoon Valley. She runs a menagerie of 'exotic' creatures, including a Thistle Boar, a Dun Morogh Chicken, an Alpine Hare, a Calico Cat, a Gilnean Raven, a Sea Gull, a Skunk, and a Stormwind..." },
  ["chelnen"] = { 2, "dracthyr located in the Sapphire Enclave in Valdrakken", "Chelnen is a dracthyr located in the Sapphire Enclave in Valdrakken, they sell insignias that grant renown in exchange for  [Flightstones]." },
  ["chepi"] = { 2, "tauren reagent vendor located on the lower rise in Thunde...", "Chepi is a tauren reagent vendor located on the lower rise in Thunder Bluff." },
  ["chert"] = { 2, "earthen housing decor vendor found in Gundargaz in the Ri...", "Chert is an earthen housing decor vendor found in Gundargaz in the Ringing Deeps." },
  ["chesmu"] = { 2, "tauren banker located on the lower rise in Thunder Bluff", "Chesmu is a tauren banker located on the lower rise in Thunder Bluff." },
  ["chezin dawnchaser"] = { 2, "', "Chezin Dawnchaser was part of the Dawnchaser expedition, led by Sunwalker Dezco, sent to Pandaria to follow 'dreams of a valley, golden with blossoms, filled with the hope of peace'. When the group set up camp at Thunder Cleft, Dezco sent Chezin t..." },
  ["chiang sisters"] = { 2, "', "The Chiang Sisters are two elderly pandaren women who live in Binan Village. They claim to be old enough to remember when Liu Lang had first departed from Pandaria, however Chen Stormstout doubts this, and have developed opinions of those who 'cha..." },
  ["chibo"] = { 2, "tortollan child located in Brawl'gar Arena", "Chibo is a tortollan child located in Brawl'gar Arena and Bizmo's Brawlpub as part of the Tidemistress Shellbreaker encounter along with Chubo." },
  ["chie"] = { 2, "ankoan located in Nazjatar", "Chie is an ankoan located in Nazjatar." },
  ["chief anders"] = { 2, "', "Chief Anders is one of the four big Kurzen's Expedition chiefs. He leads the commandos and jungle fighters and is responsible for maintaining the compound's militia and protecting the compound resources from rebel attacks." },
  ["chief blastgineer bombgutz"] = { 2, "level 27 goblin Horde quest giver", "Chief Blastgineer Bombgutz is a level 27 goblin Horde quest giver. She is first seen at Silverwind Refuge in Ashenvale next to Blood Guard Aldo Rockrain, and later appears at Krom'gar Fortress in Stonetalon Mountains." },
  ["chief corewright kasreth"] = { 2, "boss in the Nexus-Point Xenas", "Chief Corewright Kasreth is a boss in the Nexus-Point Xenas." },
  ["chief dead eye"] = { 2, "gnoll located in Darktooth Pond in the Azure Span", "Chief Dead Eye is a gnoll located in Darktooth Pond in the Azure Span. He is the leader of the Darktooth tribe." },
  ["chief engineer"] = { 2, "', "Chief Engineers are goblins found at the gate between Azshara and Orgrimmar. They work on Hellscream Demolishers, named after Garrosh Hellscream, which need to be inspected for the quest  [30-35] Weapons of Mass Dysfunction." },
  ["chief engineer bilgewhizzle"] = { 2, "goblin quest giver located inside Zul'Farrak of Tanaris a...", "Chief Engineer Bilgewhizzle of the Gadgetzan Water Company is a goblin quest giver located inside Zul'Farrak of Tanaris alongside Tran'rek. Prior to the Cataclysm, he was located in Gadgetzan in Tanaris." },
  ["chief engineer boltwrench"] = { 2, "gnome quest giver on board the Skybreaker above Icecrown ...", "Chief Engineer Boltwrench is a gnome quest giver on board the Skybreaker above Icecrown Glacier, located on the lowest deck at the prow of the ship. He serves as the chief engineer of the ship." },
  ["chief engineer cogwrench"] = { 2, "gnome located at the Bilgewater Beach in the Krasarang Wilds", "Chief Engineer Cogwrench is a gnome located at the Bilgewater Beach in the Krasarang Wilds." },
  ["chief engineer copperclaw"] = { 2, "goblin quest giver", "Chief Engineer Copperclaw is a goblin quest giver and vendor located on Orgrim's Hammer above Icecrown." },
  ["chief expeditionary requisitioner enkles"] = { 2, "gnome located at the Ironforge Brigade Outpost near Hive'...", "Chief Expeditionary Requisitioner Enkles is a gnome located at the Ironforge Brigade Outpost near Hive'Zora in Silithus. The subject of this section is unique to the World of Warcraft Classic: Season of Discovery." },
  ["chief murgut"] = { 2, "furbolg found at Greenpaw Village in Ashenvale", "Chief Murgut is a furbolg found at Greenpaw Village in Ashenvale. He is summoned by  [Senani's Banner]." },
  ["chief officer brassbolt"] = { 2, "member of The Iron Eagle", "Chief Officer Brassbolt is a member of The Iron Eagle, the zeppelin that runs between Orgrimmar and Grom'gol Base Camp. She is somewhat annoyed she was assigned a passenger ship, especially one named 'Iron Eagle', when it is clearly not a warbird." },
  ["chief officer coppernut"] = { 2, "zeppelin", "Chief Officer Coppernut is second-in-command of The Thundercaller, the zeppelin that runs between Orgrimmar and Brill. Sky-Captain Cloudkicker often gets her name and gender wrong when issuing orders." },
  ["chief ogg'ora"] = { 2, "female ogre mage", "Chief Ogg'ora was a female ogre mage and a leader of the Fire-Gut ogres." },
  ["chief ouchpatcher hock"] = { 2, "kobold looking after wounded earthen in the Obsidian Holl...", "Chief Ouchpatcher Hock is a kobold looking after wounded earthen in the Obsidian Hollow together with Volunteer Ouchpatcher Drendar." },
  ["chief sharptusk thornmantle"] = { 2, "quilboar", "Chief Sharptusk Thornmantle is a quilboar and the leader of the Bristleback tribe who lived in Brambleblade Ravine, near Red Cloud Mesa in Mulgore. The Bristlebacks have started invading the lands guarded by the tauren at Camp Narache." },
  ["chief softpaw"] = { 2, "gnoll held captive in a cage in Lost Kanniak in Brackenhi...", "Chief Softpaw is a gnoll held captive in a cage in Lost Kanniak in Brackenhide Hollow." },
  ["chief squealer thornmantle"] = { 2, "quilboar", "Chief Squealer Thornmantle is a quilboar and the leader of the Bristleback tribe. He was originally known simply as 'Squealer' Thornmantle and could be found in Brambleblade Ravine." },
  ["chieftain bloodmaw"] = { 2, "leader of the Felpaw Village which is located in northern...", "Chieftain Bloodmaw is the leader of the Felpaw Village which is located in northern Felwood. He appears to be the leader of the Deadwood tribe." },
  ["chieftain earthbind"] = { 2, "tauren located in the Hall of Legends in Orgrimmar", "Chieftain Earthbind is a tauren located in the Hall of Legends in Orgrimmar. This section concerns content related to Legion." },
  ["chieftain graw"] = { 2, "furbolg located in Smolderhide Thicket in Val'sharah", "Chieftain Graw is a furbolg located in Smolderhide Thicket in Val'sharah. He succumbed to the Nightmare corruption." },
  ["chieftain hatuun"] = { 2, "leader of the Krokul of Argus", "Chieftain Hatuun is the leader of the Krokul of Argus. Hatuun knows Velen from before the Burning Legion corrupted the eredar, and resents him and the draenei who fled Argus." },
  ["chieftain narla"] = { 2, "furbolg", "Chieftain Narla is a furbolg who was to be located in the Blackroot Village." },
  ["chikkers"] = { 2, "goblin hunter", "Chikkers is a goblin hunter who participated in the Horde's invasion of Ashenvale during the War of the Thorns. His pet is a crawler named the Captain." },
  ["chilled refugee"] = { 2, "', "Chilled Refugees are located at the Temporal Conflux in the Primalist Future." },
  ["chilled survivor"] = { 2, "', "Chilled Survivors are humans, orcs, jungle trolls, pandaren, tauren, vulpera, and nightborne located in Temporal Conflux in the Primalist Future." },
  ["chillmere coastrunner"] = { 2, "', "Chillmere Coastrunners are murlocs located at Chillmere Coast in the Howling Fjord." },
  ["chillmere oracle"] = { 2, "', "Chillmere Oracles are murlocs located in Chillmere Coast in the Howling Fjord." },
  ["chillmere tidehunter"] = { 2, "', "Chillmere Tidehunters are murlocs located at Chillmere Coast in Howling Fjord." },
  ["chilly explorer"] = { 2, "', "Chilly Explorers are blood elves, nightborne, and worgen located in the Azure Span." },
  ["chimei"] = { 2, "centaur located in the Ohn'ahran Plains", "Chimei is a centaur located in the Ohn'ahran Plains. They are one of the few surviving members of Clan Toghus, having been rescued from the village of Daruukhan after it was destroyed by Clan Nokhud." },
  ["chinwa"] = { 2, "son of a fisherman", "Chinwa is the son of a fisherman and as a youth would compete for Yalia Sagewhisper with his friend Yenki. However Yalia possessing wisdom beyond her young years realized that their competition would not end, even after her hand had been." },
  ["chive"] = { 2, "kobold located in the Ringing Deeps", "Chive is a kobold located in the Ringing Deeps. She asks adventurers to help her dig for history with a 'History Detector' she got from a goblin." },
  ["choa"] = { 2, "tortollan located in Zuldazar", "Choa is a tortollan located in Zuldazar. Initially found in the Jailer Cage right outside the Dreadpearl Cavern at Covescale Rise, she returns to the Seekers' Outpost after being freed." },
  ["choicertauren"] = { 2, "tauren located at Newhome in Nazjatar", "The Choicertauren is a tauren located at Newhome in Nazjatar." },
  ["chok'sul"] = { 2, "ogre found in the Mo'grosh Stronghold in Loch Modan", "Chok'sul was an ogre found in the Mo'grosh Stronghold in Loch Modan. He was the presumed leader of the Mo'grosh ogres." },
  ["choluna"] = { 2, "', "Choluna a tauren member of the Druids of the Talon and Guardians of Hyjal located at the Shrine of Aviana in Mount Hyjal. She also traveled to the alternate Draenor." },
  ["chompkeeper baggrul"] = { 2, "drogbar located in Underslog in Highmountain", "Chompkeeper Baggrul is a drogbar located in Underslog in Highmountain." },
  ["chonk"] = { 2, "ogre innkeeper located at Stonemaul Hold in Feralas", "Chonk is an ogre innkeeper located at Stonemaul Hold in Feralas." },
  ["chonon"] = { 2, "haranir located on a branch of Nordrassil at Mount Hyjal", "Chonon is a haranir located on a branch of Nordrassil at Mount Hyjal. Finding Chonon is one of the criteria of the exploration achievement  [More Than Just Their Roots]." },
  ["choral artisan"] = { 2, "broker located in the Idyllia in Oribos", "The Choral Artisan is a broker located in the Idyllia in Oribos." },
  ["choraldormi"] = { 2, "bronze dragon referenced on an Ancient Stone titled A Tim...", "Choraldormi is a bronze dragon referenced on an Ancient Stone titled A Timely Message." },
  ["choren-ka conspirator"] = { 2, "mogu", "Choren-ka Conspirator is a mogu." },
  ["chorka"] = { 2, "tortollan located in Nesingwary's Trek in Zuldazar", "Chorka is a tortollan located in Nesingwary's Trek in Zuldazar." },
  ["chort"] = { 2, "ogre of the Bloodmaul clan", "Chort is an ogre of the Bloodmaul clan, located outside the Circle of Blood in the Blade's Edge Mountains. He secretly tried to recruit mercenaries for Mog'dorg the Wizened to partake in a quest about saving their clan from annihilation by the Bla..." },
  ["chosen warrior"] = { 2, "', "Chosen Warriors are Forsaken and tauren located in the Bastion of Twilight." },
  ["christoff"] = { 2, "paladin of the Silver Hand under Duncan Senturus's command", "Christoff was a paladin of the Silver Hand under Duncan Senturus's command." },
  ["christoph"] = { 2, "human from Lordaeron", "Christoph was a human from Lordaeron who fought during the Third War. His last battle was in Andorhal alongside the Knights of the Silver Hand when Arthas invaded for the Urn of King Terenas." },
  ["chromatus"] = { 2, "first", "Chromatus is the first and only successfully formed chromatic dragon. Chromatus' five heads grant him the power of all five dragonflights." },
  ["chronicler eko"] = { 2, "ankoan of the Waveblade clan", "Chronicler Eko was an ankoan of the Waveblade clan. Eko recorded the deeds of their greatest heroes and earned her rightful place among them as well." },
  ["chronicler ken'nai"] = { 2, "troll", "Chronicler Ken'nai is a troll." },
  ["chronicler shoopa"] = { 2, "tortollan located in Little Tortolla in Dazar'alor", "Chronicler Shoopa is a tortollan located in Little Tortolla in Dazar'alor." },
  ["chronicler toopa"] = { 2, "tortollan located in the Tradewinds Market in Boralus", "Chronicler Toopa is a tortollan located in the Tradewinds Market in Boralus." },
  ["chronos"] = { 2, "Forsaken quest giver located at the Darkmoon Faire in Dar...", "Chronos is a Forsaken quest giver located at the Darkmoon Faire in Darkmoon Island." },
  ["chrovo"] = { 2, "dracthyr located at Stormwind Harbor in Stormwind City", "Chrovo is a dracthyr located at Stormwind Harbor in Stormwind City. He keeps tabs on the movement of the Rugged Dragonscale." },
  ["chrozon"] = { 2, "dracthyr located Emberwatch in the Ohn'ahran Plains", "Chrozon is a dracthyr located Emberwatch in the Ohn'ahran Plains." },
  ["chua"] = { 2, "haranir child located at the Den in Harandar", "Chua is a haranir child located at the Den in Harandar. At some point, his older brother En'liahn saved him from the Rift of Aln." },
  ["chub bass"] = { 2, "goblin located in Undermine", "Chub Bass is a goblin located in Undermine." },
  ["chubis"] = { 2, "goblin located at Area 52 in the Netherstorm", "Chubis is a goblin located at Area 52 in the Netherstorm." },
  ["chubo"] = { 2, "tortollan located in Brawl'gar Arena", "Chubo is a tortollan located in Brawl'gar Arena and Bizmo's Brawlpub as part of the Tidemistress Shellbreaker encounter along with Chibo. He is a juror during The Brawlpub Trial and The Brawl'gar Trial." },
  ["chuchu"] = { 2, "tortollan located in the Sliver in Dazar'alor", "Chuchu is a tortollan located in the Sliver in Dazar'alor." },
  ["chugara razorflank"] = { 2, "quilboar thornweaver of the Razorfen tribe", "Chugara Razorflank is a quilboar thornweaver of the Razorfen tribe. She was trained by Charlga to maintain the thorn dome of Razorfen Downs and is said to be the one who surrendered Razorfen to the Death's Head." },
  ["chuho dawnchaser"] = { 2, "tauren found at Halfhill Market in the Valley of the Four...", "Chuho Dawnchaser is a tauren found at Halfhill Market in the Valley of the Four Winds. He is a member of the Dawnchaser tribe, which traveled to Pandaria in search of a dreamed paradise." },
  ["churka"] = { 2, "tortollan quest giver located at the Tortaka Refuge in Vo...", "Churka is a tortollan quest giver located at the Tortaka Refuge in Vol'dun." },
  ["chyrus"] = { 2, "trait striven for", "Chyrus is one of the five Paragons of the kyrian Ascended in Bastion. He embodies the virtue of humility, a trait striven for and valued by Bastion's inhabitants, and personally oversees the Temple of Humility in the eastern part of the realm." },
  ["ciara deepstone"] = { 2, "dwarf found standing along the road from Gnomeregan to Kh...", "Ciara Deepstone is a dwarf found standing along the road from Gnomeregan to Kharanos in Dun Morogh near a new cog-shaped gate. She directs adventurers to Kharanos." },
  ["ciarin"] = { 2, "dwarf", "Ciarin was a dwarf that was contracted by Maddox." },
  ["cinad darksummit"] = { 2, "dwarf located at the Lunarfall in Shadowmoon Valley", "Cinad Darksummit is a dwarf located at the Lunarfall in Shadowmoon Valley. He can only be recruited using the Headhunter's Harvest from Lunarfall Inn." },
  ["cinderfoot"] = { 2, "striped moonsaber belonging to Iyneath", "Cinderfoot is a striped moonsaber belonging to Iyneath. It carried the injured Makasa Flintwill to Thal'darah Overlook." },
  ["cinnabar"] = { 2, "earthen housing decor vendor found in Freywold Village on...", "Cinnabar is an earthen housing decor vendor found in Freywold Village on the Isle of Dorn." },
  ["circle apprentice"] = { 2, "', "Circle Apprentices are human mages located in the Circle of Elements in the Arathi Highlands. They are also present during the Battle for Stromgarde." },
  ["cirio"] = { 2, "draenei located at Embaari Village in Shadowmoon Valley", "Cirio is a draenei located at Embaari Village in Shadowmoon Valley." },
  ["citadel mage"] = { 2, "', "Citadel Mages are draenei and humans located in Grommashar in Nagrand during its assault." },
  ["citizen bonoan"] = { 2, "citizen of Hillsbrad Fields", "Citizen Bonoan was a citizen of Hillsbrad Fields. It is unknown what became of him after the Forsaken took over." },
  ["citizen om'sto"] = { 2, "broker located in Tazavesh", "Citizen Om'sto is a broker located in Tazavesh, the Veiled Market in K'aresh." },
  ["citizen of kezan"] = { 2, "', "Citizens of Kezan are Kezanian citizens appearing after the Battle for Broken Shore. They are worried about the fate of their Warchief and can be seen discussing or crying with citizens from other Horde capitals." },
  ["citrinataur"] = { 2, "tauren vendor located at Flotsam Shoal on the Siren Isle", "Citrinataur is a tauren vendor located at Flotsam Shoal on the Siren Isle." },
  ["city guard enforcer"] = { 2, "Veiled Market", "City Guard Enforcers are brokers located in Tazavesh, the Veiled Market." },
  ["city invader"] = { 2, "', "City Invaders are NPCs who can come in many races and classes that attack capital cities during the Volunteer Guard Day holiday." },
  ["civil technician alena"] = { 2, "human located in Tiragarde Sound", "Civil Technician Alena is a human located in Tiragarde Sound." },
  ["civilian recruit"] = { 2, "', "Civilian Recruits are humans and dwarves found at Valiance Keep in the Borean Tundra, where they are standing in lines before the desk of Recruitment Officer Blythe and Recruitment Officer Carven." },
  ["cladd dawnstrider"] = { 2, "tauren located in Warspear", "Cladd Dawnstrider is a tauren located in Warspear. He sells Warlords Season 2 equipment." },
  ["clai"] = { 2, "soldier under Lorena", "Clai is a soldier under Lorena. He accompanied Lorena and her army out of Northwatch." },
  ["claim miner"] = { 2, "', "Claim Miners are draenei located at Kuuro's Claim in Talador. Many have been killed and can be found throughout the mine, often with Glowgullet Devourers feasting on their remains." },
  ["claims adjuster"] = { 2, "goblin", "The Claims Adjuster is a goblin who is to inspect the KTC Headquarters in Kezan insurance claim during   [1-20] 447." },
  ["claire \"the fox\"'] = { 2, "worgen located at Lunarfall in Shadowmoon Valley", "Claire \"the Fox\" is a worgen located at Lunarfall in Shadowmoon Valley. She can only be recruited using the Headhunter's Harvest from Lunarfall Inn." },
  ["clandestine operative"] = { 2, "', "Clandestine Operatives are dead brokers located in the Planes of Torment in the Maw. They were transporting the Broker Cache but were killed by Inquisitor Devaki." },
  ["clank coppernozzle"] = { 2, "goblin weapon vendor summoned by the  [Goblin Town-in-a-Box]", "Clank Coppernozzle is a goblin weapon vendor summoned by the  [Goblin Town-in-a-Box]. He has the  Toy Stability buff which lasts for 20 minutes, afterwards he'll despawn." },
  ["clara henry"] = { 2, "human located in the Shrine of Seven Stars", "Clara Henry is a human located in the Shrine of Seven Stars. She originally appeared in worgen form." },
  ["claretta (dracthyr)"] = { 2, "dracthyr found speaking with Taellyn in the Victorious Vi...", "Claretta is a dracthyr found speaking with Taellyn in the Victorious Visage in Valdrakken during  [70] Who Are You?." },
  ["clarissa (draenei)"] = { 2, "draenei located at the Auchenai Crypts in Terokkar Forest", "Clarissa is a draenei located at the Auchenai Crypts in Terokkar Forest." },
  ["claryssa paller"] = { 2, "Arathi located with her family in Dunelle's Kindness in H...", "Claryssa Paller is an Arathi located with her family in Dunelle's Kindness in Hallowfall. When Hallowfall once again came under threat by the Sureki and the army was stretched thin, a call to arms was issued to those with the strength to wield a w..." },
  ["classic larry"] = { 2, "ogre found in the stairwell leading to the rear entrance ...", "Classic Larry is an ogre found in the stairwell leading to the rear entrance of the Underbelly in Dalaran." },
  ["claudia albright"] = { 2, "human located at Lake Everstill in Redridge Mountains", "Claudia Albright is a human located at Lake Everstill in Redridge Mountains. When attacked, she teleports her pets and herself away." },
  ["claw (gnoll)"] = { 2, "Woodpaw gnoll brute", "Claw was the Woodpaw gnoll brute. He was a close friend to Gnaw." },
  ["claw fighter"] = { 2, "', "Claw Fighters are gnolls located in the Azure Span." },
  ["claw fighter (brackenhide hollow)"] = { 2, "', "Claw Fighters are gnolls located at Lost Kanniak in Brackenhide Hollow." },
  ["clawed abel"] = { 2, "worgen located in Timbertooth Trail in the Azure Span", "Clawed Abel is a worgen located in Timbertooth Trail in the Azure Span." },
  ["clay mudaxle"] = { 2, "elite earthen quest giver located at the Fractured Front ...", "Clay Mudaxle is an elite earthen quest giver located at the Fractured Front in Deepholm." },
  ["clean-up canoe"] = { 2, "tauren located at the Mirage Abyss  in Thousand Needles", "The Clean-Up Canoe is a tauren located at the Mirage Abyss  in Thousand Needles. He sails around, helping Tu-Luak clean the waters." },
  ["cleansing aspirant"] = { 2, "', "Cleansing Aspirants are kyrian located at the Temple of Purity in Bastion." },
  ["cleaver bmurglbrm"] = { 2, "murloc found cutting open a whale at Winterfin Retreat in...", "Cleaver Bmurglbrm is a murloc found cutting open a whale at Winterfin Retreat in the Borean Tundra. After you end a Quest by Mrmrglmr, he whispers to you to speak to him." },
  ["clemens"] = { 2, "human of the Stromgarde Militia", "Clemens was a human of the Stromgarde Militia who fought against the Syndicate in Arathi Highlands. He fell and his badge was taken by his killer, kept as a trophy until its retrieval by hired adventurers." },
  ["clementine darcy"] = { 2, "worgen", "Clementine Darcy is a worgen." },
  ["cleo clearmeadow"] = { 2, "Arathi innkeeper located at Wildcamp Ul'ar in Azj-Kahet", "Cleo Clearmeadow is an Arathi innkeeper located at Wildcamp Ul'ar in Azj-Kahet." },
  ["clerk ardran"] = { 2, "earthen located in the Crafter's Enclave in Dornogal", "Clerk Ardran is an earthen located in the Crafter's Enclave in Dornogal." },
  ["clerk gretal"] = { 2, "earthen located in the Crafter's Enclave in Dornogal", "Clerk Gretal is an earthen located in the Crafter's Enclave in Dornogal." },
  ["clerk pordaz"] = { 2, "earthen located in the Crafter's Enclave in Dornogal", "Clerk Pordaz is an earthen located in the Crafter's Enclave in Dornogal." },
  ["clerk scaravelle"] = { 2, "dracthyr located in the Artisan's Market in Valdrakken", "Clerk Scaravelle is a dracthyr located in the Artisan's Market in Valdrakken." },
  ["cliff"] = { 2, "worgen located at Deliverance Point in the Broken Shore", "Cliff is a worgen located at Deliverance Point in the Broken Shore." },
  ["cliffwalker brave"] = { 2, "', "Cliffwalker Braves are the guards at Cliffwalker Post in Stonetalon Mountains. They disappear from the post after the quest  [10-30] To Be Horde...." },
  ["clinkeasy"] = { 2, "goblin located outside the Caverns of Time in Tanaris", "Clinkeasy is a goblin located outside the Caverns of Time in Tanaris." },
  ["clint"] = { 2, "undead gnome found on Alcaz Island in Dustwallow Marsh", "Clint is an undead gnome found on Alcaz Island in Dustwallow Marsh. He came to the island to apply as an intern of a resurrected Dr." },
  ["clive cozen"] = { 2, "dwarf located in Dalaran", "Clive Cozen is a dwarf located in Dalaran. It is currently unknown if he survived Dalaran's destruction." },
  ["cloaked saboteur"] = { 2, "', "Cloaked Saboteurs are gnomes, Dark Iron dwarves, and humans located in Greystone Ruins in Tiragarde Sound during Faction Assaults." },
  ["cloaked shadowraider"] = { 2, "', "Cloaked Shadowraiders are arakkoa located in Tanaan Jungle." },
  ["cloaked watchman"] = { 2, "', "Cloaked Watchmen are venthyr located at the elevator in Dominance Keep in Revendreth." },
  ["clodgran"] = { 2, "earthen character in 'Forget Me Not'", "Clodgran is an earthen character in 'Forget Me Not', a play performed by the theater troupe at the Proscenium on the Isle of Dorn. He was deeply in love with Brunelda, his fused." },
  ["clomprul"] = { 2, "drogbar drummer", "Clomprul is a drogbar drummer and a member of Hardrogg's band who occasionally appears in the Stonedark Grotto in Highmountain. As his name suggests, Clomprul beats on 'Clomp Rocks'." },
  ["clora"] = { 2, "kyrian initially located in Forgelite Sophone's forge at ...", "Clora is a kyrian initially located in Forgelite Sophone's forge at the Aspirant's Crucible in Bastion. Soulbound to Sophone, the pair are among the first to be selected for ascendency since the anima drought began." },
  ["cloth armor vendor"] = { 2, "goblin", "The Cloth Armor Vendor is a goblin who sells seasonal cloth armor to players on the Arena Tournament and Mythic Dungeon International realms." },
  ["cloth trader"] = { 2, "earthen located at the Crossroads Plaza on the Isle of Dorn", "Cloth Trader is an earthen located at the Crossroads Plaza on the Isle of Dorn." },
  ["clothshaper steelspine"] = { 2, "quilboar", "Clothshaper Steelspine is a quilboar." },
  ["cloudbreaker shaman"] = { 2, "', "Cloudbreaker Shaman are tauren located in Vol'dun, Tiragarde Sound, and Stormsong Valley during Faction Assaults." },
  ["cloudhoof"] = { 2, "', "Cloudhoof was one of the twin sons of Sunwalker Dezco and Leza Dawnchaser. He and his brother, Redhorn, were born in the Krasarang Wilds, their mother dying in childbirth." },
  ["clumsy cragmaul brute"] = { 2, "ogre found dead high on a ledge on the Stonefury Cliffs o...", "The Clumsy Cragmaul Brute is an ogre found dead high on a ledge on the Stonefury Cliffs overlooking the Coldsnap Bluffs at the northern end of Frostfire Ridge. On his corpse find a  [Half-Eaten Banana], a  [Dented Ogre Skullcap], and 10-20x  [Garr..." },
  ["clumsy jaz'di"] = { 2, "dead troll located in one of the vats in Steamwheedle Lab...", "Clumsy Jaz'di is a dead troll located in one of the vats in Steamwheedle Laboratories in the Undermine." },
  ["clumsy swabbie"] = { 2, "same way one would resurrect a fallen squadmate during a ...", "Clumsy Swabbies are deceased members of Keg Leg's Crew in Brew Bay in the Arathi Highlands during Plunderstorm. They can be resurrected by standing near them for several seconds, the same way one would resurrect a fallen squadmate during a Plunder..." },
  ["cog burnwick"] = { 2, "gnomish deckhand on the Wavestrider", "Cog Burnwick was a gnomish deckhand on the Wavestrider. He died defending the ship when Captain Malus and his Hidden attacked it." },
  ["cogchewer"] = { 2, "kobold located in the Lost Mines in the Ringing Deeps", "Cogchewer is a kobold located in the Lost Mines in the Ringing Deeps. Cogchewer works as a muscle for the Candle King." },
  ["coggeye aimbot"] = { 2, "goblin follower located at Frostwall in Frostfire Ridge", "Coggeye Aimbot is a goblin follower located at Frostwall in Frostfire Ridge. She can only be recruited using the Headhunter's Harvest from Frostwall Tavern." },
  ["cogwin"] = { 2, "earthen located in the Hallowfall Gate in the Ringing Deeps", "Cogwin is an earthen located in the Hallowfall Gate in the Ringing Deeps." },
