  ["colarra the cadaverous"] = { 2, "draenei located in Arathi Basin during Brawl: Comp Stomp ...", "Colarra the Cadaverous is a draenei located in Arathi Basin during Brawl: Comp Stomp for Horde players." },
  ["cold-singer akala"] = { 2, "orc", "Cold-Singer Akala is an orc." },
  ["coldarra leyliner"] = { 2, "draenei", "The Coldarra Leyliner is a draenei." },
  ["coldheart agent"] = { 2, "', "Coldheart Agents are Mawsworn kyrian found in Torghast, Tower of the Damned. They were originally only found in the Coldheart Interstitia wing." },
  ["coldheart ambusher"] = { 2, "', "Coldheart Ambushers are Mawsworn kyrian found in the Coldheart Interstitia wing in Torghast, Tower of the Damned." },
