  ["coldmine explorer"] = { 2, "', "Coldmine Explorers are humans and gnomes of the Stormpike Guard found in Coldtooth Mine in Alterac Valley. One also appears west of the Gates of Ironforge in Dun Morogh." },
  ["coldmine guard"] = { 2, "', "Coldmine Guards are orcs and tauren found in Coldtooth Mine in Alterac Valley." },
  ["coldmine invader"] = { 2, "', "Coldmine Invaders are found in Coldtooth Mine in Alterac Valley." },
  ["coldridge citizen"] = { 2, "', "Coldridge Citizens are dwarves living in Coldridge Valley in Dun Morogh. They are being kept safe in the stronghold of Anvilmar under Jona Ironstock's watch while troggs attack outside." },
  ["coldridge defender"] = { 2, "', "Coldridge Defenders are dwarves found in Coldridge Valley in Dun Morogh. They are seen defending Coldridge from the Rockjaw Invaders and Rockjaw Goons." },
  ["coldridge mountaineer"] = { 2, "', "Coldridge Mountaineers are dwarven mountaineers who patrol the roads of Coldridge Valley in Dun Morogh." },
  ["colicky tadpole"] = { 2, "', "Colicky Tadpoles are murlocs hatched from Incubated Eggs in the Tomb of Sargeras." },
  ["coliseum champion"] = { 2, "', "A host of Coliseum Champions can be found after defeating the Devourer of Souls in the Forge of Souls, and just inside the Pit of Saron. On the faction champion's command, they charge in to attack Scourgelord Tyrannus." },
  ["collector astorestes"] = { 2, "kyrian located in the Terrace of Inner Grace in Bastion", "Collector Astorestes is a kyrian located in the Terrace of Inner Grace in Bastion." },
  ["collector dyna"] = { 2, "earthen located southwest of Freywold Village on the Isle...", "Collector Dyna is an earthen located southwest of Freywold Village on the Isle of Dorn." },
  ["collector kojo"] = { 2, "tortollan emissary of the Tortollan Seekers", "Collector Kojo is a tortollan emissary of the Tortollan Seekers. He can be found at Seekers' Vista in Stormsong Valley for the Alliance, or at Scaletrader Post in Zuldazar for the Horde and in other areas of the two isles." },
  ["collector ta'steld"] = { 2, "broker located in the Ring of Fates of Oribos during Shad...", "Collector Ta'steld is a broker located in the Ring of Fates of Oribos during Shadowlands timewalking weeks serving as the  [Timewarped Badge] vendor. Next to him are Crimson Lupine and Snowpaw Glimmerfur Prowler." },
  ["collector unta"] = { 2, "tortollan auctioneer", "Collector Unta is a tortollan auctioneer and the left-hand passenger of the Mighty Caravan Brutosaur. On the other side of the brutosaur is the vendor Merchant Maku." },
  ["collector of worth"] = { 2, "broker located in Tazavesh Customs Enforcement in Tazavesh", "The Collector of Worth is a broker located in Tazavesh Customs Enforcement in Tazavesh, the Veiled Market." },
  ["colm breakstorm"] = { 2, "dwarf located at the Lunarfall in Shadowmoon Valley", "Colm Breakstorm is a dwarf located at the Lunarfall in Shadowmoon Valley. He can only be recruited using the Headhunter's Harvest from Lunarfall Inn." },
  ["colonel mort"] = { 2, "venthyr located in the Ember Court", "Colonel Mort is a venthyr located in the Ember Court." },
  ["colosos"] = { 2, "draenei found at the Silver Covenant Pavilion in the Arge...", "Colosos is a draenei found at the Silver Covenant Pavilion in the Argent Tournament Grounds in Icecrown as part of the Argent Tournament. This section concerns content related to Shadowlands." },
  ["colosos (tactics)"] = { 2, "boss of the Trial of the Champion in the Crusaders' Coliseum", "Colosos is a boss of the Trial of the Champion in the Crusaders' Coliseum. Like every Alliance champion, he is only encountered by Horde players." },
  ["colt carbine"] = { 2, "goblin gun vendor located at Fuselight-by-the-Sea in the ...", "Colt Carbine is a goblin gun vendor located at Fuselight-by-the-Sea in the Badlands." },
  ["colton"] = { 2, "goblin located at the G", "Colton is a goblin located at the G.E.T.A. Headquarters and at Hovel Hill in the Undermine. He is a member of G.E.T.A. and helped adventurers in hunting down a radioactive rat that was chased into a nearby sewer and had become highly aggressive." },
  ["colum bootbright"] = { 2, "dwarf participating in the Darkmoon Dance Competition in ...", "Colum Bootbright is a dwarf participating in the Darkmoon Dance Competition in South Pavilion on Darkmoon Island." },
