  ["commander ag'troz"] = { 2, "Kor'kron Commander orc located in the Northern Barrens", "Commander Ag'troz was a Kor'kron Commander orc located in the Northern Barrens." },
  ["commander aggro'gosh"] = { 2, "orc quest giver located in Grom'gol Base Camp in Northern...", "Commander Aggro'gosh is an orc quest giver located in Grom'gol Base Camp in Northern Stranglethorn. Aggro'gosh is in command of all of Grom'gol and is charged with giving safe passage for members of the Horde wishing to travel with supplies to Sto..." },
  ["commander alvingham"] = { 2, "human located in Stormsong Valley", "Commander Alvingham is a human located in Stormsong Valley." },
