  ["commander ansela"] = { 2, "war veteran dwarven paladin", "Commander Ansela is a war veteran dwarven paladin and trainer located in the Sanctum of Light. She was rescued from the Broken Shore by the Silver Hand." },
  ["commander arcus"] = { 2, "draenei quest giver located at the Altar of Sha'tar in Sh...", "Commander Arcus is a draenei quest giver located at the Altar of Sha'tar in Shadowmoon Valley." },
