  ["commander deremat"] = { 2, "draenei located at Sha'tar Way Station in Talador", "Commander Deremat is a draenei located at Sha'tar Way Station in Talador. He speaks to a gathered host of draenei." },
  ["commander i'juk"] = { 2, "mantid located in the Vale of Eternal Blossoms", "Commander I'juk is a mantid located in the Vale of Eternal Blossoms." },
