  ["commander ix'vaarha"] = { 2, "ethereal", "Commander Ix'vaarha was an ethereal who spawns during the final stage of a Twilight's Call at Verrall River in the Twilight Highlands." },
  ["commander jo'vak"] = { 2, "mantid encountered during Island Expeditions", "Commander Jo'vak is a mantid encountered during Island Expeditions." },
