  ["commander kresh"] = { 2, "naga located in Gorgonian Overlook in Nazjatar", "Commander Kresh is a naga located in Gorgonian Overlook in Nazjatar." },
  ["commander largo"] = { 2, "Commander of the Largo's Overlook in Tol Barad Peninsula", "Commander Largo is the Commander of the Largo's Overlook in Tol Barad Peninsula. The poor commander is still waiting for his navy to arrive." },
  ["commander malor"] = { 2, "undead member of the Risen found in Stratholme", "Commander Malor, previously the scarlet crusader Malor the Zealous, is an undead member of the Risen found in Stratholme. When Balnazzar revealed himself, he, like the rest of the Scarlets in Stratholme, was killed and brought back as one of Balna..." },
  ["commander malt'his"] = { 2, "naga found in Azuregale Bay in Suramar", "Commander Malt'his is a naga found in Azuregale Bay in Suramar." },
