  ["commander raz'jira"] = { 2, "naga found in Azuregale Bay in Suramar", "Commander Raz'jira is a naga found in Azuregale Bay in Suramar." },
  ["commander ri'mok"] = { 2, "third boss of Gate of the Setting Sun", "Commander Ri'mok is the third boss of Gate of the Setting Sun." },
