  ["compiler gulderon"] = { 2, "earthen Compiler located in Old Ironforge", "Compiler Gulderon is an earthen Compiler located in Old Ironforge." },
  ["conceited noble"] = { 2, "', "Conceited Nobles are venthyr encountered by adventure companions in Revendreth." },
  ["concerned citizen"] = { 2, "', "Concerned Citizens are Orgrimmar citizens appearing after the battle for the Broken Shore. They are worried about the fate of their Warchief and can be seen discussing or crying with citizens from other Horde capitals." },
  ["concerned citizen (dalaran)"] = { 2, "', "Concerned Citizens are, as their name implies, concerned Dalaran Citizens after Argus appeared in the skies. They are found regrouped around the Kirin Tor Guardians, trying to get more information about the current situation, and sometimes around ..." },
  ["concerned onlooker"] = { 2, "', "Concerned Onlookers are located in the Valley of Strength in Orgrimmar and in Stormwind City during  [10-60] Shadowlands: A Chilling Summons." },
  ["concert bruiser"] = { 2, "', "Concert Bruisers are guards found in Darkmoon Island. You can find them guarding the concert being put on by The Tauren Chieftains." },
  ["conduitaur, esq."] = { 2, "tauren located in the four Covenant Sanctums", "Conduitaur, Esq. is a tauren located in the four Covenant Sanctums." },
  ["conflict assessor"] = { 2, "', "Conflict Assessors are brokers located in the Enclave in Oribos." },
  ["confused murloc"] = { 2, "murloc", "The Confused Murloc is a murloc that appears in a chest when engaging Tony Two-Tusk in the Admiral's Den in Thousand Needles. It releases a group of Baby Murlocs who then all swim into the cave's lake, disappearing into a small cavern." },
  ["confused seerspine murloc"] = { 2, "murloc summoned by 'slapping' the  [Sleeping Murloc]", "The Confused Seerspine Murloc is a murloc summoned by 'slapping' the  [Sleeping Murloc]. This item can be fished from the open water of Suramar and Runescale Koi Schools, or bought from Sha'leth for 25 ." },
  ["confused tadpole"] = { 2, "baby murloc", "Confused Tadpole is a baby murloc and one of the Beguiling Orb's pets in El'dranil Shallows in Azsuna." },
  ["conjurer of dalaran"] = { 2, "', "Conjurers of Dalaran are humans, blood elves, and draenei located in the Hall of the Guardian." },
  ["conner buzznick"] = { 2, "goblin located in the Hide or Hair shop at the Grand Baza...", "Conner Buzznick is a goblin located in the Hide or Hair shop at the Grand Bazaar in Dazar'alor." },
  ["conquest hold berserker"] = { 2, "', "Conquest Hold Berserkers are orcs and tauren found battling Westfall Brigade Marines in Venture Bay in the Grizzly Hills." },
  ["consortium arcanist"] = { 2, "', "Consortium Arcanists are ethereals located in the Wizard's Sanctum of Stormwind City and Pathfinder's Den of Orgrimmar. They maintain portals to Shattrath." },
  ["consortium arcanist (k'aresh)"] = { 2, "', "Consortium Arcanists are ethereals located at Shadow Point on K'aresh." },
  ["consortium assistant"] = { 2, "', "Consortium Assistants are ethereals located in the Lower City in Shattrath City." },
  ["consortium claviger"] = { 2, "', "Consortium Clavigers are ethereals located in Aeris Landing in Nagrand." },
  ["consortium collector"] = { 2, "Veiled Market in K'aresh", "Consortium Collectors are ethereals located in Tazavesh, the Veiled Market in K'aresh." },
  ["consortium engineer"] = { 2, "', "Consortium Engineers are members of the Consortium that can found inside and outside the Mana-Tombs." },
  ["consortium gemcutter"] = { 2, "', "Consortium Gemcutters are ethereals located in Aeris Landing in Nagrand." },
  ["consortium laborer"] = { 2, "', "Consortium Laborers are members of the Consortium that can found inside and outside the Mana-Tombs." },
  ["consortium nether runner"] = { 2, "ethereal located in Nagrand", "The Consortium Nether Runner is an ethereal located in Nagrand. He works for the Consortium." },
  ["consortium overseer"] = { 2, "ethereal located at Aeris Landing in Nagrand", "Consortium Overseer is an ethereal located at Aeris Landing in Nagrand." },
  ["consortium prospector"] = { 2, "ethereal", "Consortium Prospector is an ethereal." },
  ["consortium recruiter"] = { 2, "', "Consortium Recruiters are ethereal quest givers located outside Garadar and Telaar in Nagrand." },
  ["constable elimoore"] = { 2, "Arathi located in Light's Blooming in Hallowfall", "Constable Elimoore is an Arathi located in Light's Blooming in Hallowfall." },
  ["constable zo'ardaz"] = { 2, "broker located in Tazavesh", "Constable Zo'ardaz is a broker located in Tazavesh, the Veiled Market in K'aresh." },
  ["consumed hopebreaker"] = { 2, "', "Consumed Hopebreakers are deceased venthyr located in the Endmire in Revendreth. Their corpses are feasted upon by Invasive Mites." },
  ["contemplative student"] = { 2, "', "Contemplative Students are kyrian located at Agthia's Repose in Bastion." },
  ["contraband auctioneer"] = { 2, "Veiled Market", "Contraband Auctioneers are broker auctioneers located in Tazavesh Customs Enforcement in Tazavesh, the Veiled Market." },
  ["contracted demolitionist"] = { 2, "', "Contracted Demolitionists are goblins located in Vol'dun and Roaring Highland in Stormsong Valley during Faction Assaults. They are operating Horde Cannons." },
  ["contracted engineer"] = { 2, "', "Contracted Engineers are goblins located at The Iron Bulwark in Hellfire Citadel. They are working for Blackfuse Company which has been contracted by the Iron Horde." },
  ["converted hero"] = { 2, "', "Converted Heroes are ghosts found in around the Valley of Fallen Heroes in Icecrown. It would appear that they are created from Fallen Hero's Spirits in the Valley of Fallen Heroes by Scourge Converters via the Grip of the Scourge ability." },
  ["cook (character)"] = { 2, "tower's cook", "The servant Cook was one of Medivh's two servants at Karazhan — the other servant being Moroes. As her name/title implies, she was the tower's cook." },
  ["cookie"] = { 2, "elite murloc in the Deadmines in the service of Captain G...", "Cookie is an elite murloc in the Deadmines in the service of Captain Greenskin and Edwin VanCleef. He is the only optional boss in instance." },
  ["cookie barleybeard"] = { 2, "dwarf located in Camp Nowhere in the Azure Span", "Cookie Barleybeard is a dwarf located in Camp Nowhere in the Azure Span." },
  ["cooktholomew"] = { 2, "chef from Booty Bay", "Rufinwag nicknamed Cooktholomew is a chef from Booty Bay. He had been traveling with Bonenose and a pair of Booty Bay Buccaneers, but got lost at sea." },
  ["coordinator"] = { 2, "', "Coordinators are gnomes located along the road traveled during the Great Gnomeregan Run. They will indicate the correct way to run by pointing, though some are instead simply seen cheering at the racers." },
  ["coordinator xy'thir"] = { 2, "broker located in Tazavesh", "Coordinator Xy'thir is a broker located in Tazavesh, the Veiled Market in K'aresh." },
  ["coot 'the stranger' albertson"] = { 2, "human bartender located at Valgarde in the Howling Fjord", "Coot 'The Stranger' Albertson is a human bartender located at Valgarde in the Howling Fjord." },
  ["copper clobberbottom"] = { 2, "goblin located in the Darkmoon Faire on the Darkmoon Island", "Copper Clobberbottom is a goblin located in the Darkmoon Faire on the Darkmoon Island." },
  ["copperpot goon"] = { 2, "', "Copperpot Goons are guards located in the Ulduar area of the Storm Peaks. They protect Chester Copperpot." },
  ["coppers the kobold"] = { 2, "', "Coppers the Kobold is sold by Gnawbles at Gundargaz in the Ringing Deeps for 1 ." },
  ["cora (draenei)"] = { 2, "draenei child", "Cora was a draenei child and friend of Akama who lived in the Temple of Karabor. During the temple's fall to the Horde, Akama led Cora and other civilians to safety but was unable to save the girl's mother, who was cut down by the orcs." },
  ["coral"] = { 2, "murloc located at the Winterfin Retreat in the Borean Tundra", "Coral is a murloc located at the Winterfin Retreat in the Borean Tundra." },
  ["coraline"] = { 2, "tortollan located in the Drunk Tank in Drustvar", "Coraline is a tortollan located in the Drunk Tank in Drustvar." },
  ["coralweaver calliso"] = { 2, "naga located in Siren Isle", "Coralweaver Calliso is a naga located in Siren Isle." },
  ["corbix chaching"] = { 2, "goblin innkeeper located in the Rusty Cylinder in the Pin...", "Corbix Chaching is a goblin innkeeper located in the Rusty Cylinder in the Pinchwhistle Gearworks in the Spires of Arak." },
  ["corewarden nysarra"] = { 2, "boss in the Nexus-Point Xenas", "Corewarden Nysarra is a boss in the Nexus-Point Xenas." },
  ["coreway worker"] = { 2, "', "Coreway Workers are earthen located around the Coreway in Dornogal." },
  ["corewind"] = { 2, "tauren located in Freewind Post in Thousand Needles", "Corewind is a tauren located in Freewind Post in Thousand Needles. Some time after the Cataclysm, during one of the harpy attacks, he was swooped by one, but Thalia Amberhide threw a spear at the abductor, piercing her wing." },
  ["corey clockbonk"] = { 2, "gnome located at the Overspark Expedition Camp on Mechago...", "Corey Clockbonk is a gnome located at the Overspark Expedition Camp on Mechagon Island." },
  ["coriander"] = { 2, "draenei innkeeper of Lamplighter Inn", "Coriander is a draenei innkeeper of Lamplighter Inn, located at Embaari Village in Shadowmoon Valley." },
  ["corig the cunning"] = { 2, "dwarf poisons", "Corig the Cunning is a dwarf poisons and reagents vendor located in Frosthold in the Storm Peaks." },
  ["corka"] = { 2, "tortollan innkeeper", "Corka is a tortollan innkeeper and vendor located at Scaletrader Post in Zuldazar." },
  ["corki"] = { 2, "Broken located in cages at Burning Blade Ruins", "Corki is a Broken located in cages at Burning Blade Ruins, Northwind Cleft, and Warmaul Hill in Nagrand. He is Arechron's son who has been captured by enemies and rescued by the Alliance adventurers several times." },
  ["cormery"] = { 2, "guard in service of House Proudmoore", "Cormery is a guard in service of House Proudmoore. When Flynn Fairwind arrived in the city to inform Katherine and Jaina Proudmoore that Mathias Shaw had been captured by the Zandalari Empire, Cormery was one of his escorts." },
  ["coros"] = { 2, "proto-dragon of blue-green coloration", "Coros was a proto-dragon of blue-green coloration and an old rival of the blue-white Malygos. They had competed in the past over kills, territory, and strength." },
  ["corporal fizzwhistle"] = { 2, "gnome quest giver found in New Tinkertown", "Corporal Fizzwhistle is a gnome quest giver found in New Tinkertown." },
  ["corporal teeka bloodsnarl"] = { 2, "orc quest giver located in the Horde tunnel leading to Al...", "Corporal Teeka Bloodsnarl is an orc quest giver located in the Horde tunnel leading to Alterac Valley in the Hillsbrad Foothills. This section concerns content related to Dragonflight." },
  ["corpse harvester (mob)"] = { 2, "', "Corpse Harvesters are mad scientists located in the Grim Harvest in the Necrotic Wake." },
  ["corrigan"] = { 2, "dwarf", "Corrigan was a dwarf who, according to a song written about him, defeated a dragon." },
  ["corruptable lifeform"] = { 2, "', "Corruptable Lifeforms are critters deployed by the  [Legion Invasion Simulator]." },
  ["corrupted assassin"] = { 2, "', "Corrupted Assassins are gnomes and goblins located in Uldum. They appear after killing Black Empire Assassins." },
  ["corrupted beheader"] = { 2, "', "Corrupted Beheaders are Kul Tiran humans and tauren located in the Vale of Eternal Blossoms and Uldum. They appear after killing Black Empire Beheaders." },
  ["corrupted blackwood"] = { 2, "', "Corrupted Blackwood are Blackwood furbolgs found in the Twilight Vale in Darkshore." },
  ["corrupted blackwood (war of the thorns)"] = { 2, "', "Corrupted Blackwoods are furbolgs located in the Blackwood Den in Darkshore during the War of the Thorns. They were attacked by the Horde adventurer so that they could take the land." },
  ["corrupted elementalist"] = { 2, "', "Corrupted Elementalists are corrupted twilight dragonspawn, elven, gnome, and Forsaken elementalists in the service of Twilight's Hammer. They are located at Twilight Citadel in Twilight Highlands." },
  ["corrupted gnarlpine"] = { 2, "', "Corrupted Gnarlpines are furbolgs located in Gnarlpine Hold in Teldrassil." },
  ["corrupted rooksguard"] = { 2, "', "Corrupted Rooksguards are night elves located at Heroes' Rest in Val'sharah." },
  ["corrupted servant"] = { 2, "', "Corrupted Servants are satyrs located at Gnarlpine Hold in Teldrassil. Some are accompanied by Corrupted Minions." },
  ["corrupted soulflayer"] = { 2, "venthyr encountered by adventure companions in Revendreth", "Corrupted Soulflayer is a venthyr encountered by adventure companions in Revendreth." },
  ["corrupted squallfin"] = { 2, "', "Corrupted Squallfins are murlocs located in the Magisters' Park at the road leading to Greengill Coast on the Isle of Quel'Danas during the assault by the Devouring Host." },
  ["corrupted summoner"] = { 2, "', "Corrupted Summoners are night elves and tauren located in Uldum. They appear after killing Black Empire Summoners." },
  ["corrupted talonpriest"] = { 2, "', "Corrupted Talonpriests are arakkoa located in Iskar's Clutch in Hellfire Citadel. They are fought before and during the Shadow-Lord Iskar encounter." },
  ["corrupted thaumaturge"] = { 2, "', "Corrupted Thaumaturges are night elves and tauren located in Uldum and the Vale of Eternal Blossoms. They appear after killing Black Empire Thaumaturges." },
  ["cortello"] = { 2, "unknown person", "Cortello is an unknown person who was responsible for the cortello's riddle treasure hunt." },
  ["cosmin the illusionist"] = { 2, "venthyr located in Revendreth", "Cosmin the Illusionist is a venthyr located in Revendreth. He also attends the Ember Court." },
  ["cosmowrench bruiser"] = { 2, "', "Cosmowrench Bruisers are goblins guarding Cosmowrench in the Netherstorm." },
  ["costel"] = { 2, "venthyr located in Costel's Hideout in Revendreth", "Costel is a venthyr located in Costel's Hideout in Revendreth." },
  ["cotley"] = { 2, "Forsaken apothecary", "Cotley is a Forsaken apothecary that had come to care for a group of Horde refugees within the Arathi Highlands. One day, the refugees were approached Visrynn, a dark ranger, who joined them on the condition that they take a vow of silence." },
  ["coto"] = { 2, "tortollan located at Heyman's Hideaway in Vol'dun", "Coto is a tortollan located at Heyman's Hideaway in Vol'dun." },
  ["coulisa"] = { 2, "dracthyr located at the Ruby Feast in Valdrakken", "Coulisa is a dracthyr located at the Ruby Feast in Valdrakken. The VIP List is found on the podium in front of him." },
  ["council felcaller"] = { 2, "', "Council Felcallers are ogres located in Talador." },
  ["council flamecaller"] = { 2, "', "Council Flamecallers are tauren located in the Vault Approach in the Vault of the Incarnates." },
  ["council icecaller"] = { 2, "', "Council Icecallers are draenei located in the Vault Approach in the Vault of the Incarnates." },
  ["councilor daglat"] = { 2, "ogre located at the Throne of the Imperator in Highmaul", "Councilor Daglat is an ogre located at the Throne of the Imperator in Highmaul." },
  ["councilor gorluk"] = { 2, "ogre located at the Throne of the Imperator in Highmaul", "Councilor Gorluk is an ogre located at the Throne of the Imperator in Highmaul." },
  ["councilor magknor"] = { 2, "ogre located at the Throne of the Imperator in Highmaul", "Councilor Magknor is an ogre located at the Throne of the Imperator in Highmaul." },
  ["councilor nouk"] = { 2, "ogre located at the Throne of the Imperator in Highmaul", "Councilor Nouk is an ogre located at the Throne of the Imperator in Highmaul." },
  ["counselor ta'krag"] = { 2, "broker located at Transfer Station Ta in Bastion", "Counselor Ta'krag is a broker located at Transfer Station Ta in Bastion." },
  ["count erlgadin"] = { 2, "member of the human aristocracy", "Count Erlgadin is a member of the human aristocracy. He became renowned for his generosity, while lobbying for improved working conditions for the Stonemasons' Guild during the restoration of Stormwind after the Second War." },
  ["counter bardra"] = { 2, "earthen located in Council's Treasury in Dornogal", "Counter Bardra is an earthen located in Council's Treasury in Dornogal." },
  ["counter targrin"] = { 2, "earthen located in the Council's Treasury in Dornogal", "Counter Targrin is an earthen located in the Council's Treasury in Dornogal." },
  ["countess gloomveil"] = { 2, "venthyr located in the Gallery in Castle Nathria", "Countess Gloomveil is a venthyr located in the Gallery in Castle Nathria." },
  ["courageous"] = { 2, "mount of Terenas Menethil II", "Courageous was the mount of Terenas Menethil II." },
  ["courier aidal"] = { 2, "Arathi flight master located at Faerin's Advance in Azj-K...", "Courier Aidal is an Arathi flight master located at Faerin's Advance in Azj-Kahet." },
  ["courier claridge"] = { 2, "worgen located in Stormwind Embassy in Stormwind City dur...", "Courier Claridge is a worgen located in Stormwind Embassy in Stormwind City during   [50-90] The Shadow of Gilneas." },
  ["courier lyan"] = { 2, "Arathi flight master located at Wildcamp Ul'ar in Azj-Kahet", "Courier Lyan is an Arathi flight master located at Wildcamp Ul'ar in Azj-Kahet." },
  ["courier nailen"] = { 2, "Arathi flight master located at Wildcamp Or'lay in Azj-Kahet", "Courier Nailen is an Arathi flight master located at Wildcamp Or'lay in Azj-Kahet." },
  ["court assassin"] = { 2, "', "Court Assassins are venthyr located in Castle Nathria." },
  ["court attendant"] = { 2, "', "Court Attendants are naga located in the Eternal Palace." },
  ["court enforcer"] = { 2, "', "Court Enforcers are venthyr located in Castle Nathria." },
  ["court executor"] = { 2, "', "Court Executors are venthyr located in Castle Nathria." },
  ["court hawkeye"] = { 2, "', "Court Hawkeyes are venthyr located in Castle Nathria." },
  ["cousin ich"] = { 2, "pandaren on the Wandering Isle", "Cousin Ich is a pandaren on the Wandering Isle that creates fireworks." },
  ["covert operative"] = { 2, "', "Covert Operatives are gnomes of the Gnomeregan Covert Ops located in Kharanos, Steelgrill's Depot, and Frostmane Retreat in Dun Morogh. This section concerns content related to Legion." },
  ["covert ops agent"] = { 2, "', "Covert Ops Agents are gnomes located in Steelspark Station in Tanaris." },
  ["covert ops flying machine"] = { 2, "', "Covert Ops Flying Machines are gnomes located in Frostmane Retreat in Dun Morogh. They are piloting a flying machine and appear during  [1-30] Strike From Above." },
  ["covert ops hardsuit"] = { 2, "', "Covert Ops Hardsuits are gnomes located at Lost Rigger Cove in Tanaris. Some are seen ejected as Covert Ops Pounders are destroyed." },
  ["covert shadowclaw"] = { 2, "', "Covert Shadowclaws are worgen attacking Caravan Kodo in Scavenger's Strand in Zuldazar." },
  ["cowering citizen"] = { 2, "', "Cowering Citizens are venthyr located in Revendreth." },
  ["cowry"] = { 2, "human of the Stromgarde Militia", "Cowry was a human of the Stromgarde Militia who fought against the Syndicate in Arathi Highlands. He fell and his badge was taken by his killer, kept as a trophy until its retrieval by hired adventurers." },
  ["cox"] = { 2, "large human", "Cox is a large human and the partner of the famous detective Halford Ramsey. Together, Cox and Halford were investigating the Starlight Slasher murders; however, the two of them did not get along." },
  ["crab rider grmlrml"] = { 2, "Swamprock murloc vignette riding around the Shipwreck Cov...", "Crab Rider Grmlrml is a Swamprock murloc vignette riding around the Shipwreck Cove in Highmountain atop a Tamed Coralback." },
  ["crab-ravaged darkfuse"] = { 2, "', "Crab-Ravaged Darkfuses are dead goblins found near George at the Kaja'Coast in Zuldazar." },
  ["crabmaster daijo"] = { 2, "tortollan located at the Seekers' Vista in Stormsong Valley", "Crabmaster Daijo is a tortollan located at the Seekers' Vista in Stormsong Valley." },
  ["cracktooth"] = { 2, "gnoll located in the Brackenhide Waterhole in the Azure Span", "Cracktooth is a gnoll located in the Brackenhide Waterhole in the Azure Span." },
  ["craftataur"] = { 2, "tauren located at the Ring of Fates in Oribos", "The Craftataur is a tauren located at the Ring of Fates in Oribos. She provides recipes and reagents for new craftables for free." },
  ["crafted gearataur"] = { 2, "tauren located in Dalaran on the World of Warcraft: Wrath...", "Crafted Gearataur is a tauren located in Dalaran on the World of Warcraft: Wrath of the Lich King Classic PTR. She hands out crafted PvP gear for free." },
  ["crafter kuliqa"] = { 2, "tuskarr located at Uktulut Backwater in the Waking Shores", "Crafter Kuliqa is a tuskarr located at Uktulut Backwater in the Waking Shores." },
  ["crafter y'selfa"] = { 2, "eredar vendor located next to Kuraam at the Circle of Asp...", "Crafter Y'selfa is an eredar vendor located next to Kuraam at the Circle of Aspirants in Eredath. She sells eredar tail rings." },
  ["craftsman azama"] = { 2, "ankoan located in Mezzamere in Nazjatar", "Craftsman Azama is an ankoan located in Mezzamere in Nazjatar." },
  ["craftsman ironai"] = { 2, "ankoan located at Orise's Vigil in Nazjatar", "Craftsman Ironai is an ankoan located at Orise's Vigil in Nazjatar." },
  ["crafty the ambitious"] = { 2, "goblin in the Dark Heart of Pandaria scenario", "Crafty the Ambitious is a goblin in the Dark Heart of Pandaria scenario. Once he entered the Vault of Y'Shaarj, an echo of Y'Shaarj corrupted and possessed him, forcing the adventurers to kill him." },
  ["crag rockcrusher"] = { 2, "earthen quest giver found in Deepholm", "Crag Rockcrusher is an earthen quest giver found in Deepholm." },
  ["crags"] = { 2, "tauren located in the Road Warrior in Gadgetzan in Tanari...", "Crags is a tauren located in the Road Warrior in Gadgetzan in Tanaris along with Blue and her Warband. He fights his evil version outside the town." },
  ["cragsworn conqueror"] = { 2, "', "Cragsworn Conquerors are located in the Primalist Future." },
  ["cragsworn stoneshaper"] = { 2, "', "Cragsworn Stoneshapers are located in the Primalist Future." },
  ["craig amai (npc)"] = { 2, "human using the appearance of Varian Wrynn", "Craig Amai is a human using the appearance of Varian Wrynn." },
  ["craishae"] = { 2, "subject of many myths", "Craishae was a legendary lost queen of Arathor. She is the subject of many myths, of which one, The Ballad of Craishae the First Flame, tells of how she became the first person to wield a combination of fire and the Light (something similar to the..." },
  ["crane operator bigglefuzz"] = { 2, "goblin located in Ratchet in the Northern Barrens", "Crane Operator Bigglefuzz is a goblin located in Ratchet in the Northern Barrens. He tried unloading just a little too much cargo with his crane, and it all fell down." },
  ["crane style initiate"] = { 2, "', "Crane Style Initiates are monks of the Order of the Broken Temple located in the Shrine of Five Dawns, Temple of Five Dawns, and Mandori Village on the Wandering Isle." },
  ["crankshot blaster"] = { 2, "', "Crankshot Blasters are cannons operated by goblins located in Darkshore during the Battle for Darkshore. They are also present when the Horde is in control of the area." },
  ["cranston fizzlespit"] = { 2, "gnome alchemy supplies vendor located in Northwatch Hold ...", "Cranston Fizzlespit is a gnome alchemy supplies vendor located in Northwatch Hold in the Southern Barrens. It is unknown whether he survived the Razing of Northwatch Hold or not." },
  ["crapopolis citizen"] = { 2, "', "Crapopolis Citizens are goblins located in Crapopolis." },
  ["crapopolis laborer"] = { 2, "', "Crapopolis Laborers are goblins located in Crapopolis. Some are working on Mechanized Peacekeepers, one is working on the frozen Goblin Test Subject." },
  ["crash bigbomb"] = { 2, "goblin located at Area 52 in the Netherstorm", "Crash Bigbomb is a goblin located at Area 52 in the Netherstorm." },
  ["crashed recon pilot"] = { 2, "dead gnome", "The Crashed Recon Pilot is a dead gnome who can be found in the Borean Tundra. There are several other similar looking gnome corpses near him due to the crash of a gnomish recon wing from Fizzcrank Airstrip." },
  ["cravitz lorent"] = { 2, "Forsaken vendor found in the Underbelly of Dalaran", "Cravitz Lorent is a Forsaken vendor found in the Underbelly of Dalaran. This section concerns content related to The War Within." },
  ["crazed apothecary"] = { 2, "', "Crazed Apothecaries were Forsaken working for the Crown Chemical Co. found in Shadowfang Keep." },
  ["crazed bilgewater survivor"] = { 2, "', "Crazed Bilgewater Survivors are goblins roaming the Land's End Beach in Tanaris. They run around aimlessly, sit, dance, or stand in place cheering at nothing." },
  ["crazed crankshot engineer"] = { 2, "', "Crazed Crankshot Engineers are goblins located in Ashwood Depot in Darkshore during the Battle for Darkshore." },
  ["crazed indu'le survivor"] = { 2, "rare elite tuskarr found in the western area of the Drago...", "Crazed Indu'le Survivor is a rare elite tuskarr found in the western area of the Dragonblight." },
  ["crazed looter"] = { 2, "', "Crazed Looters are located near Shomko's Remembrance at the Coast of Echoes in the Borean Tundra." },
  ["crazed mage"] = { 2, "', "Crazed Mages are located in the Chamber of Incineration in the Blackrock Caverns." },
  ["crazed murkblood foreman"] = { 2, "', "Crazed Murkblood Foremen are Broken found in the Netherwing Mines in Shadowmoon Valley." },
  ["crazed murkblood miner"] = { 2, "', "Crazed Murkblood Miners are Broken found in the Netherwing Mines in Shadowmoon Valley." },
  ["crazed outcast"] = { 2, "', "Crazed Outcasts are arakkoa located in Sethekk Hollow in the Spires of Arak." },
  ["crazed outcast servant"] = { 2, "', "Crazed Outcast Servants are cursed arakkoa located in the Hidden Marsh Ruins in Zorammarsh. They were the servants of an expeditionary group led by Adherent Exhumers in Tanaan Jungle." },
  ["crazed soldier"] = { 2, "', "Crazed Soldiers are dwarves and humans located in Farson Hold in Tol Barad Peninsula." },
  ["crazed tushui guardian"] = { 2, "', "Crazed Tushui Guardians are pandaren, humans, and gnomes located in the Vale of Eternal Twilight." },
  ["crazy sapper"] = { 2, "', "Crazy Sappers were goblins located in Northern Barrens." },
  ["creature collector"] = { 2, "Veiled Market", "Creature Collectors are brokers located in Tazavesh, the Veiled Market." },
  ["creedy"] = { 2, "leader of gang of bounty hunters", "Creedy was the leader of gang of bounty hunters. He was captured by Hemet Nesingwary when the bounty hunters where hunting three frostsaber cubs, that Hemet was protecting." },
  ["crekori mudwater"] = { 2, "quilboar", "Crekori Mudwater is a quilboar." },
  ["crenna earth-daughter"] = { 2, "tauren located in Exile's Reach", "Crenna Earth-Daughter is a tauren located in Exile's Reach." },
  ["crevan falamar"] = { 2, "human mage", "Crevan Falamar was a human mage. He had aligned himself with Malygos during the Nexus War and was therefore placed inside the Violet Hold by the Kirin Tor." },
  ["crew chief dearii"] = { 2, "draenei located at Kuuro's Claim in Talador", "Crew Chief Dearii is a draenei located at Kuuro's Claim in Talador. She's found tending the wounds of an Injured Miner." },
  ["crewman barrowswizzle"] = { 2, "goblin crew member aboard The Mighty Wind zeppelin", "Crewman Barrowswizzle is a goblin crew member aboard The Mighty Wind zeppelin that travels between Borean Tundra and Orgrimmar." },
  ["crewman boltshine"] = { 2, "former member of The Purple Princess", "Crewman Boltshine is a former member of The Purple Princess, the zeppelin that ran between Brill and Grom'gol Base Camp. This section concerns content related to The War Within." },
  ["crewman coilspan"] = { 2, "goblin crew member aboard The Cloudkisser zeppelin", "Crewman Coilspan is a goblin crew member aboard The Cloudkisser zeppelin that travels between Tirisfal Glades and Howling Fjord." },
  ["crez"] = { 2, "tortollan located at Gloom Hollow in Nazmir", "Crez is a tortollan located at Gloom Hollow in Nazmir." },
  ["crillian"] = { 2, "honorable headmaster", "Crillian is an honorable headmaster and master of Stalvan Mistmantle. He gave Stalvan the advice to move out of Stormwind." },
  ["crimson cabalist"] = { 2, "', "Crimson Cabalists are venthyr located in Castle Nathria during the fight against Sire Denathrius." },
  ["crispin gravesbane"] = { 2, "', "Lord Crispin Gravesbane is one of the main characters of  [A Steamy Romance Novel: Nightborne of the Living Dead] and  [A Steamy Romance Novel: Waves of Desire]." },
  ["crispy nerubian"] = { 2, "dead nerubian located in Earthcrawl Mines", "Crispy Nerubian is a dead nerubian located in Earthcrawl Mines." },
  ["cristalstrasz"] = { 2, "leader of the red dragonflight's Ruby Flamebringers durin...", "Cristalstrasz was the leader of the red dragonflight's Ruby Flamebringers during the War of the Scaleborn, and was personally responsible for the deaths of countless Primalists. Fyrakk regarded him as a brute when he saw Cristalstrasz at the Battl..." },
  ["crol'ka"] = { 2, "member of the Stonemaul clan", "Crol'ka is a member of the Stonemaul clan. When Kor'gall conquered the clan Crol'ka's brothers were among the many warriors slain." },
  ["cromas the mystic"] = { 2, "Ascended kyrian located at the Eternal Watch section of t...", "Cromas the Mystic is an Ascended kyrian located at the Eternal Watch section of the Elysian Hold in Bastion. He was part of the grand reception the Archon arranged for a Maw Walker, who decided to join the Kyrian Covenant, in honor of their effort..." },
  ["crone"] = { 2, "Forsaken present during Hallow's End", "Crone is a Forsaken present during Hallow's End." },
  ["crosh"] = { 2, "tortollan located in Zuldazar", "Crosh is a tortollan located in Zuldazar. At first, he is found in a Nazeshi Cage in the Dreadpearl Shallows." },
  ["crossing greengrocer"] = { 2, "', "Crossing Greengrocers are Arathi located in Lorel's Crossing in Hallowfall." },
  ["crowmie"] = { 2, "arakkoa found in Thaldraszus during the Dawn of the Infin...", "Crowmie is an arakkoa found in Thaldraszus during the Dawn of the Infinite quest chain. She is an alternate timeline version of Chromie who was brought to the main timeline by Morchie." },
  ["crown agent"] = { 2, "', "Crown Agents are part of the Crown Chemical Company found in the Hinterlands. They were once part of the removed  [1-70 Daily] Crushing the Crown quest, but are still present during Love is in the Air." },
  ["crown alchemist"] = { 2, "', "Crown Alchemist are Forsaken located in Stormwind City and Orgrimmar during the Love is in the Air event. They are disguised as Lovely Revelers but can be revealed with  [O.D.I.E.'s Remote Control]." },
  ["crown apothecary"] = { 2, "', "Crown Apothecaries are Forsaken located in Shadowfang Keep. The subject of this section was removed from World of Warcraft in patch 4.0.3a but is present in Classic." },
  ["crown duster"] = { 2, "', "Crown Dusters are Forsaken of the Crown Chemical Company found near the Sludge Fields in the Hillsbrad Foothills and in Darkshire in Duskwood. They were originally guarding the Chemical Wagons nearby." },
  ["crown hoodlum"] = { 2, "', "Crown Hoodlums are Forsaken of the Crown Chemical Company found northeast of Theramore Isle and just east of Sentry Point in Dustwallow Marsh. They were originally guarding the Chemical Wagons nearby." },
  ["crown lackey"] = { 2, "', "Crown Lackeys are Forsaken of the Crown Chemical Company found in Durotar and Elwynn Forest. They are guarding the Chemical Wagons nearby." },
  ["crown sprayer"] = { 2, "', "Crown Sprayers are Forsaken of the Crown Chemical Company found in Forlorn Woods in Crystalsong Forest. They are guarding the Chemical Wagons nearby." },
  ["crown sprinkler"] = { 2, "', "Crown Sprinklers are Forsaken of the Crown Chemical Company found east of Everlook in Winterspring. They were originally guarding the Chemical Wagons nearby." },
  ["crown supply guard"] = { 2, "', "Crown Supply Guards are Forsaken located in Pyrewood Village in Silverpine Forest." },
  ["crown supply guard (durotar)"] = { 2, "', "Crown Supply Guards are Forsaken located in Durotar." },
  ["crown technician"] = { 2, "', "Crown Technicians are undead of the Crown Chemical Company found in Pyrewood Village in Silverpine Forest, guarding the Chemical Wagons." },
  ["crown technician (uldum)"] = { 2, "', "Crown Technicians are undead of the Crown Chemical Company found at the Gate of Unending Cycles in Uldum, guarding the Chemical Wagons." },
  ["crown thug"] = { 2, "', "Crown Thugs are Forsaken of the Crown Chemical Company found in Darkshore. They were originally guarding the Chemical Wagons nearby." },
  ["crown underling"] = { 2, "', "Crown Underlings are Forsaken of the Crown Chemical Company found at the Cenarion Thicket of Terokkar Forest. They are guarding the Chemical Wagons nearby." },
  ["croz bloodrage"] = { 2, "orc located at the Maw of the Void in Darkshore", "Croz Bloodrage is an orc located at the Maw of the Void in Darkshore. He is also present during the Battle for Darkshore, fighting Grimhorn." },
  ["cruel bonecrusher"] = { 2, "', "Cruel Bonecrushers are gnolls located at Lost Kanniak in Brackenhide Hollow." },
  ["cruelfin"] = { 2, "murloc located in Blacksilt Shore on Bloodmyst Isle", "Cruelfin is a murloc located in Blacksilt Shore on Bloodmyst Isle." },
  ["crulgorosh"] = { 2, "ogre located at the Mar'gok's Overwatch in Nagrand", "Crulgorosh is an ogre located at the Mar'gok's Overwatch in Nagrand." },
  ["crunchola"] = { 2, "modified shredder created by Grizzek Fizzwrench", "The Crunchola is a modified shredder created by Grizzek Fizzwrench, who also fondly referred to it as Crunchy. One of its mechanically operated limbs is outfitted with a grasping hand augmented by an energy beam, with the idea being that the energ..." },
  ["crusade architect silas"] = { 2, "Forsaken quest giver", "Crusade Architect Silas is a Forsaken quest giver that appears in the Valley of Echoes in Icecrown during a few quests." },
  ["crusade recruit"] = { 2, "', "Crusade Recruits are located at Drak'Sotra in Zul'Drak." },
  ["crusader ahad"] = { 2, "human located at the Argent Tournament Grounds in Icecrown", "Crusader Ahad is a human located at the Argent Tournament Grounds in Icecrown. He is patrolling the tournament grounds during Death Rising and after." },
  ["crusader alrick"] = { 2, "human of the Scarlet Crusade located in the Dawning Isles...", "Crusader Alrick is a human of the Scarlet Crusade located in the Dawning Isles in Silverpine Forest when the crusaders attacked the Ruins of Lordaeron. When the Forsaken counterattacked them, Alrick was escorting Inquisitor Fairbell to a Scarlet P..." },
  ["crusader brune"] = { 2, "orc found in Heb'Valok in Zul'Drak", "Crusader Brune is an orc found in Heb'Valok in Zul'Drak. She is protecting Alchemist Finklestein." },
  ["crusader lord dalfors"] = { 2, "dwarf member of the Argent Crusade found in Icecrown", "\"We need every able-bodied man and woman to help keep the tide of evil at bay!\" Crusader Lord Dalfors is a dwarf member of the Argent Crusade found in Icecrown. He first appears at Argent Vanguard and later moves to the Crusaders' Pinnacle." },
  ["crusader lord valdelmar"] = { 2, "undead", "Crusader Lord Valdelmar is an undead and the former ruler of Tyr's Hand as part of the Scarlet Crusade. Even in undeath, however, he still appears to be leading the city." },
  ["crusader of virtue"] = { 2, "', "Crusaders of Virtue are dwarf and blood elf paladin guards found in various parts of the Valley of Echoes in Icecrown. This section concerns content related to Shadowlands." },
  ["crushmaul"] = { 2, "ogre located at the Ring of Trials in Nagrand", "Crushmaul is an ogre located at the Ring of Trials in Nagrand." },
  ["crushridge brute"] = { 2, "', "Crushridge Brutes can be found in the Ruins of Alterac in the Hillsbrad Foothills." },
  ["crushridge enforcer"] = { 2, "', "Crushridge Enforcers can be found in the Ruins of Alterac in the Hillsbrad Foothills." },
  ["crushridge mauler"] = { 2, "', "Crushridge Maulers are ogres found in the Ruins of Alterac in the Hillsbrad Foothills." },
  ["crushridge ogre"] = { 2, "', "Crushridge Ogres are ogres found in the Ruins of Alterac in the Hillsbrad Foothills." },
  ["crushridge plunderer"] = { 2, "', "Crushridge Plunderers are ogres found in the Ruins of Alterac in the Hillsbrad Foothills." },
  ["crushridge warmonger"] = { 2, "', "Crushridge Warmongers are ogres of the Crushridge clan, who can be found in the Ruins of Alterac in Hillsbrad Foothills." },
  ["cryo-engineer sha'heen"] = { 2, "ethereal quest giver", "Cryo-Engineer Sha'heen was an ethereal quest giver. When the Ethereal Control Box Panel in the Mana-Tombs was activtated, Sha'heen appeared." },
  ["crypt guard (revendreth)"] = { 2, "', "Crypt Guards are venthyr located in Revendreth." },
  ["crypt keeper"] = { 2, "', "Crypt Keepers are venthyr located at the Crypt of the Forgotten in Revendreth. They're performing rituals on Ruined Golems." },
  ["crypt robber"] = { 2, "', "Crypt Robbers can be found near the Undercroft in the Eastern Plaguelands. They spawn when the Loose Dirt Mound is searched, and act as the escort of Mercutio Filthgorger during  [57] Of Forgotten Memories." },
  ["crypt watcher"] = { 2, "', "Crypt Watchers are two venthyr located in the Crypt of the Forgotten in Revendreth. They are guarding the Seal of the Forgotten." },
  ["cryptkeeper kassir"] = { 2, "venthyr located at the Halls of Atonement in Revendreth", "Cryptkeeper Kassir is a venthyr located at the Halls of Atonement in Revendreth. He works with the Avowed to help in the atonment of Revendreth's souls." },
  ["cryptographer aurren"] = { 2, "draenei quest giver located at Azure Watch on Azuremyst Isle", "Cryptographer Aurren is a draenei quest giver located at Azure Watch on Azuremyst Isle. He has been trying to learn the furbolg language, and translated it to draenei in the  [Stillpine Furbolg Language Primer]." },
  ["crystal brightspark"] = { 2, "gnome alchemy trainer located at the Argent Tournament Gr...", "Crystal Brightspark is a gnome alchemy trainer located at the Argent Tournament Grounds in Icecrown. This section concerns content related to Shadowlands." },
  ["crystal-shaper barum"] = { 2, "draenei artificer", "Crystal-Shaper Barum is a draenei artificer that shapes crystals and gems. He lived in Aruuna with his daughter Melani." },
  ["cuddles"] = { 2, "gnome located in the Molten Fields of the Molten Front", "Cuddles is a gnome located in the Molten Fields of the Molten Front." },
  ["culinary assembler"] = { 2, "broker located in the Idyllia", "The Culinary Assembler is a broker located in the Idyllia and near the entrance to Oribos." },
  ["culinary assistant"] = { 2, "Veiled Market", "Culinary Assistants are brokers located at food stalls in Tazavesh, the Veiled Market." },
  ["culinary curator"] = { 2, "', "Culinary Curators are brokers located in the Idyllia and near the entrance to Oribos." },
  ["culinary facilitator"] = { 2, "', "Culinary Facilitators are brokers located in the Idyllia and near the entrance to Oribos." },
  ["culinary facilitator ta'sahm"] = { 2, "broker located at Transfer Station Ta in Bastion", "Culinary Facilitator Ta'sahm is a broker located at Transfer Station Ta in Bastion." },
  ["cult adept"] = { 2, "', "Cult Adept are cultists of the Twilight's Blade located in the Shadow Enclave delve." },
  ["cultist agtar"] = { 2, "orc located south of the building at Jaggedswine Farm in ...", "Cultist Agtar is an orc located south of the building at Jaggedswine Farm in Durotar, next to the tent. He left his wife in Orgrimmar behind and joined the Doomsday Cult." },
  ["cultist shadowblade"] = { 2, "', "Cultist Shadowblades are gnomes located in the Old Town in the Vision of Stormwind." },
  ["cultist statue"] = { 2, "', "Cultist Statues are petrified arakkoa located at Apexis Excavation in the Spires of Arak. They are located near Stonespite, likely the source of their petrification." },
  ["culver the chaser"] = { 2, "vrykul located in Stormheim", "Culver the Chaser is a vrykul located in Stormheim." },
  ["curator lano"] = { 2, "kyrian located in Kalliope's Rest in Bastion", "Curator Lano is a kyrian located in Kalliope's Rest in Bastion. He was captured by the Forsworn but eventually rescued by the Maw Walker sent by Haetio, after which he relocated to Haetion's Solace." },
  ["curator ve'ka"] = { 2, "broker located in Tazavesh", "Curator Ve'ka is a broker located in Tazavesh, the Veiled Market in K'aresh." },
  ["curgle cranklehop"] = { 2, "gnome quest giver located in Gadgetzan in Tanaris", "Curgle Cranklehop  is a gnome quest giver located in Gadgetzan in Tanaris. She leads the affair of collecting hippogryphs eggs and sending them to Erelas Ambersky, who trains and cares young hippogryphs." },
  ["curigosa"] = { 2, "blue dragon", "Curigosa was a blue dragon who was killed by Neltharion's betrayal during the War of the Ancients. Her name is on a Faded Gravestone at the Veiled Ossuary." },
  ["curio dealer"] = { 2, "', "Curio Dealers were brokers located at Transfer Station Ta in Bastion. One of their IDs were renamed to Export Specialist, while the other was seemingly just removed." },
  ["curious customer"] = { 2, "Veiled Market", "Curious Customers are brokers located in Tazavesh, the Veiled Market." },
  ["curious dracthyr"] = { 2, "', "Curious Dracthyr are dracthyr located in the Wyvern's Tail in Orgrimmar." },
  ["curious lilu"] = { 2, "tuskarr located at Apex Canopy in the Waking Shores", "Curious Lilu is a tuskarr located at Apex Canopy in the Waking Shores. She and Shy Ino are found listening to the stories of Fisherman Pasqaa." },
  ["curious onlooker (tazavesh)"] = { 2, "Veiled Market", "Curious Onlookers are brokers located in Tazavesh, the Veiled Market." },
  ["cursebreaker arnon"] = { 2, "venthyr located in Revendreth", "Cursebreaker Arnon is a venthyr located in Revendreth." },
  ["cursed arakkoa"] = { 2, "', "Cursed Arakkoa are outcast arakkoa located in Spires of Arak." },
  ["cursed centaur"] = { 2, "rare centaur", "The Cursed Centaur is a rare centaur who roams the tunnels outside Maraudon in Desolace." },
  ["cursed harbinger"] = { 2, "', "Cursed Harbingers are arakkoa located in the Dark Woods in Ashran." },
  ["cursed sailor"] = { 2, "', "Cursed Sailors can be found in the wreckage of the Lost Fleet in the Wetlands." },
  ["cursed sharptalon"] = { 2, "arakkoa located in Ashran", "Cursed Sharptalon is an arakkoa located in Ashran." },
  ["curzon"] = { 2, "draenei found walking among a small group viewing the Exo...", "Curzon is a draenei found walking among a small group viewing the Exodar Holographic Emitters within the Vault of Lights in the Exodar. This section concerns content related to Legion." },
  ["custer clubnik"] = { 2, "goblin quest giver located at the Orgrimmar Rocketway Exc...", "Custer Clubnik is a goblin quest giver located at the Orgrimmar Rocketway Exchange in Azshara. He oversaw the plans to bulldoze the nearby ruins of Mennar Academy in order to make way for a fuel depot, but the local ghosts interfered." },
  ["custodian kalir"] = { 2, "broker located in Haven in Zereth Mortis", "Custodian Kalir is a broker located in Haven in Zereth Mortis." },
  ["custodian khubon"] = { 2, "earthen located next to the Matrix Catalyst in the Forgeg...", "Custodian Khubon is an earthen located next to the Matrix Catalyst in the Forgegrounds in Dornogal." },
  ["custodian lutgred"] = { 2, "earthen located at the Stoneshaper's Atrium in Dornogal", "Custodian Lutgred is an earthen located at the Stoneshaper's Atrium in Dornogal." },
  ["custodian taj"] = { 2, "broker located in Haven", "Custodian Taj is a broker located in Haven and Primal Wasteland in Zereth Mortis. He is seen speaking with Custodian Kalir." },
  ["custodian urrgha"] = { 2, "earthen located at Stoneward's Rise in Dornogal", "Custodian Urrgha is an earthen located at Stoneward's Rise in Dornogal. Blipp sits in a wheelbarrow next to her." },
  ["customs agent (broker)"] = { 2, "', "Customs Agents are brokers." },
  ["customs anklebinder"] = { 2, "', "Customs Anklebinder are brokers." },
  ["customs aurascrapper"] = { 2, "', "Customs Aurascrappers are brokers." },
  ["customs officer"] = { 2, "Veiled Market in K'aresh", "Customs Officers are brokers located in the Gilded Landing in Tazavesh, the Veiled Market in K'aresh." },
  ["customs overseer"] = { 2, "', "Customs Overseers are brokers." },
  ["customs security"] = { 2, "Veiled Market", "Customs Securities are brokers located at Tazavesh, the Veiled Market." },
  ["customs shiftdodger"] = { 2, "', "Customs Shiftdodgers are brokers encountered by adventure companions in Tazavesh." },
  ["customs specialist"] = { 2, "', "Customs Specialists are brokers." },
  ["customs spellcoil"] = { 2, "', "Customs Spellcoils are brokers." },
  ["customs trainee"] = { 2, "', "Customs Trainees are brokers." },
  ["customs watch-agent"] = { 2, "', "Customs Watch-Agents are brokers." },
  ["cutwater knife juggler"] = { 2, "', "Cutwater Knife Jugglers are gnomes located at Winterdeep Basin and in Freehold in Tiragarde Sound. Some of them can be seen playing dice." },
  ["cutwater knife juggler (freehold)"] = { 2, "', "Cutwater Knife Jugglers are gnomes located in Freehold." },
  ["cuzi"] = { 2, "draenei bag vendor located at the Seat of the Naaru in th...", "Cuzi is a draenei bag vendor located at the Seat of the Naaru in the Exodar. This section concerns content related to Legion." },
  ["cuzolth"] = { 2, "dracthyr item upgrader located with Vaskarn in Loamm in Z...", "Cuzolth is a dracthyr item upgrader located with Vaskarn in Loamm in Zaralek Cavern. They later moved to the Central Encampment under Amirdrassil in the Emerald Dream." },
  ["cygenoth"] = { 2, "ogre disguised as a black dragonspawn", "Cygenoth is an ogre disguised as a black dragonspawn, found in the Smoldering Perch in the Waking Shores. A member of the Twilight's Hammer, Cygenoth corrupted the Worldbreakers." },
  ["cyntia shieldbreaker"] = { 2, "vrykul located in Stormheim", "Cyntia Shieldbreaker is a vrykul located in Stormheim." },
  ["cyranus"] = { 2, "naga located in the Last Prison in the Eternal Palace", "Cyranus is a naga located in the Last Prison in the Eternal Palace. He is one of the cursed lovers summoned by Queen Azshara." },
  ["cyrce"] = { 2, "leader of the Sturmvyn clan of iron vrykul", "Cyrce is the leader of the Sturmvyn clan of iron vrykul. She and her clan lived in the Storm Peaks, where she was the first vrykul to tame a galeorn, Thrayir, after all else had failed." },
  ["cyrixia"] = { 2, "Mawsworn kyrian located in Ruin's Cradle in the Maw", "Cyrixia is a Mawsworn kyrian located in Ruin's Cradle in the Maw." },
  ["cysanz"] = { 2, "ancient proto-dragon", "Cysanz was an ancient proto-dragon and one of Vyranoth's supporters during the War of the Scaleborn. He had been reluctant to join the Primalist cause, but as with many of the ancient proto-dragon holdouts he was swayed when word reached him that ..." },
  ["d.e.h.t.a. enforcer"] = { 2, "', "D.E.H.T.A. Enforcers are located at the D.E.H.T.A. Encampment in the Borean Tundra." },
  ["da cabin boy"] = { 2, "undead dire troll located in the northwestern Port of Zem...", "Da Cabin Boy is an undead dire troll located in the northwestern Port of Zem'lan in Vol'dun. He holds the  [Idol of Immortality], one of the three idols that were used by Pirate-King Zem'lan to curse his crew into skeletons." },
  ["da'kesh the elementalist"] = { 2, "draenei shaman found in the Exodar when the Burning Legio...", "Da'kesh the Elementalist is a draenei shaman found in the Exodar when the Burning Legion invaded the capital. Da'kesh, Liani the Lifegiver, and Fister Rockfist helped Farseer Nobundo and the leader of class orders to defend the Crystal Hall." },
  ["daedal"] = { 2, "draenei alchemy trainer located at Azure Watch in Azuremy...", "Daedal is a draenei alchemy trainer located at Azure Watch in Azuremyst Isle. Daedal is one of the many who journey to Blood Watch to celebrate the hero of Bloodmyst and Azuremyst." },
  ["daegarn"] = { 2, "dwarf of the Explorers' League located in the Ring of Jud...", "Daegarn is a dwarf of the Explorers' League located in the Ring of Judgement in Howling Fjord." },
  ["daera brightspear"] = { 2, "dwarf hunter trainer located at the Hall of Arms in the M...", "Daera Brightspear is a dwarf hunter trainer located at the Hall of Arms in the Military Ward in Ironforge. She directs hunters to Wulf Hansreim for questing." },
  ["daerion the assassin"] = { 2, "assassin hired by Katrana Prestor through Gakca to kill t...", "Daerion the Assassin was the assassin hired by Katrana Prestor through Gakca to kill the strong-willed Varian. Daerion met with Magatha Grimtotem, who was told by the Forsaken of his arrival." },
  ["daeyana gleamgaard"] = { 2, "Arathi located in Wildcamp Or'lay in Azj-Kahet", "Daeyana Gleamgaard is an Arathi located in Wildcamp Or'lay in Azj-Kahet. She was gravely wounded, burned by nerubian poison, but the local haranir provided help to get better." },
  ["dagath"] = { 2, "', "Dagath seemed to have been a Wildhammer dwarf of some renown as Falstad Dragonreaver was known to have sworn to the phrase Dagath's Hammer." },
  ["dagg"] = { 2, "great ogre thief", "Dagg is a great ogre thief and a master of subterfuge and disguises." },
  ["daggerspine marauder"] = { 2, "', "Daggerspine Marauders are naga intent on killing Shakes O'Breen in Faldir's Cove in the Arathi Highlands. After accepting the quest  [10-30] Death From Below waves of these naga will begin to attack, coming from over the nearby hill." },
  ["daggerspine raider"] = { 2, "', "Daggerspine Raiders are naga found in the sea south of the Arathi Highlands." },
  ["daggerspine screamer"] = { 2, "', "Daggerspine Screamers are naga located at the Eastern Strand in the Hillsbrad Foothills." },
  ["daggerspine shorehunter"] = { 2, "', "Daggerspine Shorehunters are naga located at the Eastern Strand of Hillsbrad Foothills." },
  ["daggerspine shorestalker"] = { 2, "', "Daggerspine Shorestalkers are naga located at the Eastern Strand in the Hillsbrad Foothills." },
  ["daggerspine siren"] = { 2, "', "Daggerspine Sirens can be found in Hillsbrad Foothills." },
  ["daggerspine sorceress"] = { 2, "', "Daggerspine Sorceresses are naga found in the sea south of the Arathi Highlands." },
  ["daggerspine wavecaller"] = { 2, "naga", "Daggerspine Wavecaller is a naga." },
  ["daggle bombstrider"] = { 2, "goblin located in the Krasari Ruins in Krasarang Wilds", "Daggle Bombstrider is a goblin located in the Krasari Ruins in Krasarang Wilds. After being helped, she relocates to Nesingwary's Safari in the Valley of the Four Winds." },
  ["dagkar"] = { 2, "earthen caretaker found in the Cinderwold Tribute Site in...", "Dagkar is an earthen caretaker found in the Cinderwold Tribute Site in the Isle of Dorn." },
  ["daglir"] = { 2, "nightborne living in Suramar City", "Daglir is a nightborne living in Suramar City. He is a premier fruit vendor who won the favor of the high nobles." },
  ["dagmyr"] = { 2, "vrykul located in Suramar", "Dagmyr is a vrykul located in Suramar." },
  ["daisy glimmerhoof"] = { 2, "tauren located outside Godan's Runeworks in the Drag in O...", "Daisy Glimmerhoof is a tauren located outside Godan's Runeworks in the Drag in Orgrimmar." },
  ["dakaari"] = { 2, "draenei stable master located at Eventide Landing in Shad...", "Dakaari is a draenei stable master located at Eventide Landing in Shadowmoon Valley." },
  ["dakk blunderblast"] = { 2, "dwarf found in Thelsamar in Loch Modan", "Dakk Blunderblast is a dwarf found in Thelsamar in Loch Modan. He's had trouble with Forest Lurkers sneaking into his bedroom at night." },
  ["dal bloodclaw"] = { 2, "Thistlefur furbolg found in Thistlefur Hold in Ashenvale", "Dal Bloodclaw is a Thistlefur furbolg found in Thistlefur Hold in Ashenvale. Before the Cataclysm, he was wandering around Thistlefur Village, and Raene Wolfrunner wanted his skull." },
  ["dal'rend blackhand"] = { 2, "bloodthirsty son of the former Warchief of the Horde", "Dal'rend Blackhand, (or Dal'Rend) commonly known as Rend, was the bloodthirsty son of the former Warchief of the Horde, Blackhand the Destroyer, as well as the former Warchief of the Dark Horde. He believed that he was the rightful Warchief of the..." },
  ["dalana clarke"] = { 2, "dwarf located at Lunarfall", "Dalana Clarke is a dwarf located at Lunarfall. She spawns with the Level 2 Dwarven Bunker and accepts the bunker's work orders." },
  ["dalaran citizen"] = { 2, "', "Dalaran Citizens can be found walking around Dalaran." },
  ["dalaran civilian"] = { 2, "', "Dalaran Civilians are located on the Tranquil Strand on the Isle of Dorn. They can be helped either through healing abilities or interacting with them - doing so grants the character  Sense of Duty, increasing Haste and Speed by 5%, stacking up to..." },
  ["dalaran conjuror"] = { 2, "', "Dalaran Conjurors were humans found in Silverpine Forest before the Cataclysm." },
  ["dalaran mage"] = { 2, "', "Dalaran Magi were human mages that found in Ambermill and around Beren's Peril in Silverpine Forest." },
  ["dalaran survivor"] = { 2, "', "Dalaran Survivors are found sitting in Thraegar Rest, Keepers Terrace, and Stonelight Rest in Dornogal." },
  ["dalaran visitor"] = { 2, "[Armored Snowy Gryphon]", "Dalaran Visitors are player-like NPCs flying to the Krasus' Landing in Dalaran, then they dismount and run away from the platform, where they disappear. They can spawn on many different kinds of mounts, such as: the  [Argent Hippogryph], the  [Arm..." },
  ["dalaran watcher"] = { 2, "', "Dalaran Watchers were humans found in Ambermill and around Beren's Peril in Silverpine Forest." },
  ["dalaran wizard"] = { 2, "', "Dalaran Wizards are humans and gnomes found in Ambermill and around Beren's Peril in Silverpine Forest." },
  ["daleos"] = { 2, "Ascended kyrian located at the Cliffs of Respite in Bastion", "Daleos is an Ascended kyrian located at the Cliffs of Respite in Bastion." },
  ["dalgin"] = { 2, "leader of a caravan", "Dalgin was a leader of a caravan that was heading to Uldum and were accompanied by Li Li a Chen after Deathwing's death. The caravan stumbled upon a group of tol'vir who took them to the city of Ramkahen." },
  ["dalian ironlink"] = { 2, "dead Arathi located at Stillstone Pond in Hallowfall", "Dalian Ironlink is a dead Arathi located at Stillstone Pond in Hallowfall, encountered during  [80] Those Who Fell.  [Dalian Ironlink's Tinderbox] belonged to him." },
  ["damak"] = { 2, "tortollan located in Torga's Tavern in Nazmir", "Damak is a tortollan located in Torga's Tavern in Nazmir." },
  ["dame alys finnsson"] = { 2, "worgen", "Dame Alys Finnsson is a worgen, affiliated with the Twilight's Hammer, found at the Twilight Citadel in the Twilight Highlands." },
  ["damogath the tenebrous"] = { 2, "dwarf located in Arathi Basin during Brawl: Comp Stomp fo...", "Damogath the Tenebrous is a dwarf located in Arathi Basin during Brawl: Comp Stomp for Horde players." },
  ["damon baelor"] = { 2, "dwarf flight master located in Whelgar's Retreat in the W...", "Damon Baelor is a dwarf flight master located in Whelgar's Retreat in the Wetlands." },
  ["damrul the stronk"] = { 2, "drogbar quest giver carrying two weights", "Damrul the Stronk is a drogbar quest giver carrying two weights and standing in front of a campfire in Stonedark Grotto in Highmountain. He initially wishes to ascertain the player's ability to lift weights, after which he tasks them with dealing ..." },
  ["danagh"] = { 2, "earthen located in the Ringing Deeps", "Danagh is an earthen located in the Ringing Deeps." },
  ["dance enthusiast"] = { 2, "', "Dance Enthusiasts are spectators standing in front of Simon Sezdans at the Darkmoon Faire on Darkmoon Island. They are also inside the South Pavilion." },
  ["dance party patron"] = { 2, "', "Dance Party Patrons are dragons and dracthyr letting loose on the dance floor of the Dragon's Hoard in Valdrakken." },
  ["dancer"] = { 2, "', "Dancers are humans and gnomes found in Brawl'gar Arena and Bizmo's Brawlpub as part of the Thwack U encounter." },
  ["daniela darkwhisper"] = { 2, "venthyr", "Daniela Darkwhisper is a venthyr." },
  ["danir emberlight"] = { 2, "Darkfallen death knight located in Drustvar", "Danir Emberlight is a Darkfallen death knight located in Drustvar. He attempted to raise Vadekius, opposing the red dragonflight, but was slain by an Alliance adventurer." },
  ["dannie fizzwizzle"] = { 2, "gnome warlock located in Kharanos in Dun Morogh", "Dannie Fizzwizzle is a gnome warlock located in Kharanos in Dun Morogh. This section concerns content related to Legion." },
  ["dansel adams"] = { 2, "hunter", "Dansel Adams is a hunter and a member of the Scarlet Crusade. During a routine purging of heathens in the Scourge infested Plaguewood, he witnessed Naxxramas leaving." },
  ["dantiogg"] = { 2, "drogbar located in Highmountain", "Dantiogg is a drogbar located in Highmountain." },
  ["dar'khan drathir"] = { 2, "talented mage", "Dar'Khan Drathir was once an esteemed magister, who would become one of Quel'Thalas' greatest traitors. He was a talented mage, but unbridled ambition made him arrogant and vindictive." },
  ["darahir"] = { 2, "elf found at the Black Market in the Underbelly of Dalaran", "Darahir is an elf found at the Black Market in the Underbelly of Dalaran. He sells a  [Ghostly Skull] companion in unlimited supply." },
  ["darahu"] = { 2, "Broken Aldor shaman trainer located at the Terrace of Lig...", "Darahu is a Broken Aldor shaman trainer located at the Terrace of Light in Shattrath City." },
  ["darbrul"] = { 2, "drogbar repair vendor located in the Stonedark Grotto in ...", "Darbrul is a drogbar repair vendor located in the Stonedark Grotto in Highmountain." },
  ["darckli"] = { 2, "archmage with innemurable achievements", "Darckli was an archmage with innemurable achievements, among which mastering the art of breathing dragonfire directly from his mouth." },
  ["darean"] = { 2, "earthen located in the Forgegrounds in Dornogal", "Darean is an earthen located in the Forgegrounds in Dornogal." },
  ["dareer"] = { 2, "', "Dareer, at first glance, appears to be a draenei cutting wood at Nesingwary's Retreat in Highmountain. If a player has a demon-tracking ability active (such as  [Spectral Sight]), they are able to reveal him for what he truly is: a hostile man'ari..." },
  ["dareth"] = { 2, "worgen druid trainer located at the entrance of Ironforge...", "Dareth is a worgen druid trainer located at the entrance of Ironforge in Dun Morogh. He is the only druid trainer in the area." },
  ["dargal"] = { 2, "', "During the Third War, Dargal was in charge of a group of several dwarves who were fighting against skeletons of the Scourge when found by Prince Arthas and Jaina Proudmoore. Dargal and his group then aided them in destroying the plague-infested wa..." },
  ["dargo"] = { 2, "', "Dargo was one of the three Bloodsail Buccaneers that attacked the draenei priestess Iridi for gold in Ratchet." },
  ["dargonax"] = { 2, "twilight dragon created by Sintharia", "Dargonax was a twilight dragon created by Sintharia, who regarded the mighty creature as her child. He appears in the World of Warcraft novel Night of the Dragon." },
  ["dargrul"] = { 2, "leader of the drogbar", "Dargrul the Underking was the leader of the drogbar and the most powerful Underking since the age of Neltharion. Soon after the Burning Legion's arrival, Dargrul destroyed the peace between the tauren and the drogbar tribes of Highmountain by murd..." },
  ["dargrul (tactics)"] = { 2, "drogbar located in Neltharion's Lair", "Dargrul is a drogbar located in Neltharion's Lair." },
  ["dargulf the spirit-seeker"] = { 2, "vrykul located in Island Expeditions", "Dargulf the Spirit-Seeker is a vrykul located in Island Expeditions." },
  ["dargum hammerdeep"] = { 2, "earthen blacksmithing vendor located at Bouldercrag's Ref...", "Dargum Hammerdeep is an earthen blacksmithing vendor located at Bouldercrag's Refuge in the Storm Peaks." },
  ["dargun the stone"] = { 2, "tauren fighting against Harla Darkblade in Vol'dun during...", "Dargun the Stone is a tauren fighting against Harla Darkblade in Vol'dun during Faction Assaults." },
  ["daring drakerider"] = { 2, "', "Daring Drakeriders are located in Loamm and Obsidian Rest in Zaralek Cavern. Some are found near Saddled Proto-Drakes." },
  ["daring fisher"] = { 2, "tuskarr located at the Burning Ascent in the Waking Shores", "The Daring Fisher is a tuskarr located at the Burning Ascent in the Waking Shores, Roaring Dragonsprings in the Ohn'ahran Plains, Tyrhold in Thaldraszus, and Dragonskull Island in the Forbidden Reach." },
  ["darithel the insightful"] = { 2, "dwarf located in the Hall of Mysteries in Ironforge", "Darithel the Insightful is a dwarf located in the Hall of Mysteries in Ironforge." },
  ["darius crowley"] = { 2, "Gilnean nobleman", "Lord Darius Crowley is a Gilnean nobleman and the founder of the Gilneas Liberation Front. A pro-Alliance figure during the Second War, he supported the union of the Seven Kingdoms against the Old Horde." },
  ["dark acolyte (sanguine depths)"] = { 2, "', "Dark Acolytes are venthyr located in Sanguine Depths." },
  ["dark apothecary (mob)"] = { 2, "', "Dark Apothecaries are nerubians that attack Dalaran during the War Within intro experience. They're found in the Underbelly during  [68-70] Rupture." },
  ["dark ascended corrus"] = { 2, "Forsworn kyrian located in Torghast", "Dark Ascended Corrus is a Forsworn kyrian located in Torghast, Tower of the Damned." },
  ["dark bombardier"] = { 2, "', "Dark Bombardiers are Arathi located in the Nightfall Sanctum. They fly around in miniature Arathi airships, patrolling the delve." },
  ["dark eagle"] = { 2, "eagle with gold-and-brown feathers", "The Dark Eagle was an eagle with gold-and-brown feathers, tortured and cruelly warped by the Amani trolls and their dark magic, twisting it into a true monster. After a quiet time, the trolls launched a well-planned incursion with their finest war..." },
  ["dark iron prisoner"] = { 2, "', "Dark Iron Prisoners are found in cages and down the blocked hallways in the Detention Block in Blackrock Depths during the Bronze Celebration." },
  ["dark master vaalgryn"] = { 2, "kyrian encountered by adventure companions in Bastion", "Dark Master Vaalgryn is a kyrian encountered by adventure companions in Bastion." },
  ["dark prowler"] = { 2, "', "Dark Prowlers are Drust located in Ardenweald." },
  ["dark ranger (battle for lordaeron)"] = { 2, "', "Dark Ranger are Darkfallen dark rangers located in the Magic Quarter and Canals in the Undercity and the Ruins of Lordaeron during the Battle for Lordaeron." },
  ["dark ranger (brill)"] = { 2, "', "Dark Rangers are Darkfallen high elves and night elves standing guard on the walls of Brill and the Ruins of Lordaeron in Tirisfal Glades. They count both, kaldorei and Thalassian elves." },
  ["dark ranger (broken shore)"] = { 2, "', "Dark Ranger are Darkfallen troops from Undercity following Sylvanas Windrunner during  [10-45] The Battle for Broken Shore. Before that, they can be seen at the Dranosh'ar Blockade in Durotar, preparing for the assault." },
  ["dark ranger (dazar'alor)"] = { 2, "Darkfallen located in the Hall of Ritual in Dazar'alor", "Dark Ranger is a Darkfallen located in the Hall of Ritual in Dazar'alor. She is guarding the chained Derek Proudmoore after his resurrection in  [60] The Return of Derek Proudmoore." },
  ["dark ranger (durotar)"] = { 2, "', "Dark Rangers are Darkfallen briefly seen in Grommash Hold in Orgrimmar after the Battle for the Broken Shore. Then, they relocated to the Dranosh'ar Blockade in Durotar protecting the newly chosen Warchief, Sylvanas Windrunner from a demonic ambush." },
  ["dark ranger (emerald dream)"] = { 2, "', "Three Dark Rangers are accompanying Delaryn Summermoon in the Central Encampment in the Emerald Dream." },
  ["dark ranger (hillsbrad foothills)"] = { 2, "', "Dark Rangers are Darkfallen dark rangers found roaming the southern part of the Hillsbrad Foothills. They can be found camouflaged and are accompanied by Battle Creepers." },
  ["dark ranger (howling fjord)"] = { 2, "', "Dark Rangers are Darkfallen guards found at Vengeance Landing and Ghostblade Post in the Howling Fjord. One also stands in War Quarter in the Undercity next to Nathanos Blightcaller and Apolos." },
  ["dark ranger (silverpine forest)"] = { 2, "', "Dark Rangers are Darkfallen dark rangers located throughout Silverpine Forest guarding Sylvanas Windrunner." },
  ["dark ranger (stay of execution)"] = { 2, "', "Dark Rangers are Darkfallen dark rangers located in the Underhold during  [60] Stay of Execution." },
  ["dark ranger (stormheim)"] = { 2, "', "Dark Rangers are Darkfallen dark rangers that accompany Warchief Sylvanas Windrunner from Durotar to Stormheim through the Cove of Nashal." },
  ["dark ranger (stormsong valley)"] = { 2, "', "Dark Rangers are Darkfallen dark rangers that guard the Horde leadership in Warfang Hold in Stormsong Valley during the War Campaign." },
  ["dark ranger (swift vengeance)"] = { 2, "', "Dark Rangers are Darkfallen dark rangers found on the The Swift Vengeance in Tiragarde Sound during the Horde War Campaign." },
  ["dark ranger (tiragarde sound)"] = { 2, "', "Dark Rangers are Darkfallen high elves and night elves accompanying Nathanos Blightcaller in Plunder Harbor and Timberfell Outpost in Tiragarde Sound during the  [60] Breaking Kul Tiran Will questline." },
  ["dark ranger (tirisfal glades)"] = { 2, "', "Dark Rangers are Darkfallen night elves dark rangers located in Calston Estate in Tirisfal Glades during  [50] The Hidden Need." },
  ["dark ranger (tol dagor)"] = { 2, "', "Dark Rangers are Darkfallen dark rangers located in Tol Dagor." },
  ["dark ranger (war of the thorns)"] = { 2, "', "Dark Rangers are Darkfallen dark rangers participating the War of the Thorns. They were first seen when Sylvanas Windrunner led her forces into Darkshore through the wisp wall in the Twilight Vale." },
  ["dark ranger (warcraft iii)"] = { 2, "former Rangers of Quel'Thalas enjoy nothing more than sow...", "A cunning Hero, adept at manipulating opponents. Forcibly raised from the dead, the former Rangers of Quel'Thalas enjoy nothing more than sowing dissension and hatred within the enemy ranks." },
  ["dark ranger alina"] = { 2, "Darkfallen dark ranger of the Forsaken", "Dark Ranger Alina is a Darkfallen dark ranger of the Forsaken." },
  ["dark ranger allanah"] = { 2, "Darkfallen flight master located at the Shrine of the Sto...", "Dark Ranger Allanah is a Darkfallen flight master located at the Shrine of the Storm in Stormsong Valley." },
  ["dark ranger anya"] = { 2, "Darkfallen dark ranger", "Dark Ranger Anya is a Darkfallen dark ranger who wanders the Undercity. She is one of the 'Seeker' guards, which means she can see through  [Stealth] effects." },
  ["dark ranger clea"] = { 2, "Darkfallen dark ranger", "Dark Ranger Clea is a Darkfallen dark ranger who wanders the Undercity. She is a 'seeker' guard, which means that she can see through  [Stealth] effects." },
  ["dark ranger cyndia"] = { 2, "Darkfallen dark ranger", "Dark Ranger Cyndia Hawkspear is a Darkfallen dark ranger who wanders the Undercity. She has a patrol path that encompasses a large section of the city, including the Trade Quarter." },
  ["dark ranger denyelle"] = { 2, "Darkfallen dark ranger encountered by Falstad Wildhammer ...", "Dark Ranger Denyelle is a Darkfallen dark ranger encountered by Falstad Wildhammer in Boralus Harbor." },
  ["dark ranger elite"] = { 2, "', "Dark Ranger Elites are Darkfallen dark rangers located in Gilneas City in Gilneas." },
  ["dark ranger jess"] = { 2, "Darkfallen dark ranger located in Stormheim", "Dark Ranger Jess is a Darkfallen dark ranger located in Stormheim. She is part of the Forsaken Deathsquad and is butting heads with the Worgen Stalkers." },
  ["dark ranger kalira"] = { 2, "Darkfallen dark ranger under the service of Sylvanas Wind...", "Dark Ranger Kalira is a Darkfallen dark ranger under the service of Sylvanas Windrunner. She accompanied the Banshee Queen alongside fellow Dark Ranger Loralen through the Forge of Souls and Pit of Saron." },
  ["dark ranger loralen"] = { 2, "Darkfallen dark ranger", "Dark Ranger Loralen is a Darkfallen dark ranger. After the Third War, Loralen accompanied Sylvanas Windrunner to a meeting with Cairne Bloodhoof in Thunder Bluff." },
  ["dark ranger lyana"] = { 2, "Darkfallen dark ranger", "Dark Ranger Lyana was a Darkfallen dark ranger, and a member of the Hand of Vengeance and the Unseen Path." },
  ["dark ranger marrah"] = { 2, "Darkfallen dark ranger fighting against the vrykul in Nor...", "Dark Ranger Marrah is a Darkfallen dark ranger fighting against the vrykul in Northrend, located in the Utgarde Keep in Howling Fjord. She appears only for Horde groups, and runs up to the group inside the instance after the players enter and star..." },
  ["dark ranger thandel"] = { 2, "Darkfallen dark ranger located in the Underhold during  [...", "Dark Ranger Thandel is a Darkfallen dark ranger located in the Underhold during  [60] Stay of Execution. He accompanied Magister Hathorel‎ to attack the rescuers of Baine Bloodhoof, but was killed." },
  ["dark ranger thyala"] = { 2, "Darkfallen dark ranger located in Duskmist Shore", "Dark Ranger Thyala is a Darkfallen dark ranger located in Duskmist Shore and was leading the group of Forsaken that attacked Duskhaven during the invasion of Gilneas. However, the Forsaken were defeated, and Thyala herself was killed by attack mas..." },
  ["dark ranger velonara"] = { 2, "Darkfallen dark ranger", "Dark Ranger Velonara is a Darkfallen dark ranger and a member of the Desolate Council, the governing body of the Forsaken. In life, she was a Quel'dorei ranger, until she was killed by Arthas Menethil and his Scourge during the Scourge invasion of..." },
  ["dark ranger vorel"] = { 2, "Darkfallen dark ranger", "Dark Ranger Vorel is a Darkfallen dark ranger." },
  ["dark ranger zanra"] = { 2, "Darkfallen dark ranger located in the Underhold during  [...", "Dark Ranger Zanra is a Darkfallen dark ranger located in the Underhold during  [60] Stay of Execution. She accompanied Magister Hathorel‎ to attack the rescuers of Baine Bloodhoof, but was killed." },
  ["dark rider ghrave"] = { 2, "ancient Dark Rider appearing in the Realm of Shadows as a...", "Dark Rider Ghrave is an ancient Dark Rider appearing in the Realm of Shadows as an enemy during the  Fallen Steeds: Reins of Shadow death knight class hall mission. He mounts a Crimson Deathcharger." },
  ["dark ritualist (throne of thunder)"] = { 2, "', "Dark Ritualists are mogu located in Halls of Flesh-Shaping in the Throne of Thunder." },
  ["dark scout"] = { 2, "Darkfallen dark ranger shadowing the worgen player during...", "The Dark Scout is a Darkfallen dark ranger shadowing the worgen player during their journey to the Blackwald. She ambushes and attempts to slay the player during   [1-20] Losing Your Tail." },
  ["dark seer vadaash"] = { 2, "arakkoa located in the Howling Crag‎ in the Spires of Arak", "Dark Seer Vadaash is an arakkoa located in the Howling Crag‎ in the Spires of Arak." },
  ["dark talon"] = { 2, "', "Dark Talons are dracthyr located in the War Creche in the Forbidden Reach. At the Old Weyrn Grounds, some of them are being healed by Talon Menders." },
  ["dark touched warrior"] = { 2, "', "Dark Touched Warriors are orcs and humans found in Naxxramas." },
  ["dark vault-seeker"] = { 2, "', "Dark Vault-Seekers are Forsworn kyrian located at the Walk of Recollection in Bastion." },
  ["dark watcher"] = { 2, "kyrian located just outside the Citadel of Loyalty in Bas...", "The Dark Watcher is a kyrian located just outside the Citadel of Loyalty in Bastion. She can only be seen while dead." },
  ["dark zealot (netherlight temple)"] = { 2, "', "Dark Zealots are Forsaken, human, and draenei priests located in the Netherlight Temple." },
  ["dark zealots"] = { 2, "', "Dark Zealots are humans and Forsaken who briefly spawn in the Netherlight Temple. After recruiting them as troops, they run out of the temple and despawn." },
  ["dark-sworn warlock"] = { 2, "', "Dark-Sworn Warlocks are humans and Forsaken located in Caer Darrow in Western Plaguelands and in Tol Barad." },
  ["darkcrest siren"] = { 2, "', "Darkcrest Sirens are naga found at the Darkcrest Enclave in Zangarmarsh." },
  ["darkcrest slaver"] = { 2, "', "Darkcrest Slavers are naga found at the Darkcrest Shore in Zangarmarsh. When aggroed, they will call a nearby Dreghood Drudge to attack the attacker until the Slaver is killed." },
  ["darkcrest sorceress"] = { 2, "straightforward fight except when chunks of ice start to ...", "Darkcrest Sorceresses are naga found at the Darkcrest Shore in Zangarmarsh. It is a straightforward fight except when chunks of ice start to be summoned around you." },
  ["darkcrest taskmaster"] = { 2, "', "Darkcrest Taskmasters are naga found at the Darkcrest Enclave in Zangarmarsh. When aggroed, they will call a nearby Dreghood Drudge to attack the attacker until the Taskmaster is killed." },
  ["darkfallen archmage"] = { 2, "', "Darkfallen Archmages are Darkfallen of the San'layn found in the Crimson Hall of Icecrown Citadel. They are normally found spread out among the trash in the halls." },
  ["darkfallen blood knight"] = { 2, "', "Darkfallen Blood Knights are Darkfallen of the San'layn found in the Crimson Hall of Icecrown Citadel. They are normally found spread out among the trash in the halls." },
  ["darkfallen bloodbearer"] = { 2, "', "Darkfallen Bloodbearers are Darkfallen of the San'layn stationed in the Temple City of En'kilah in the Borean Tundra. They constantly wander up and down the stairs in the center of the temple." },
  ["darkfallen commander"] = { 2, "', "Darkfallen Commanders are Darkfallen of the San'layn found in the Crimson Hall of Icecrown Citadel. They are normally found spread out among the trash in the halls." },
  ["darkfallen deathblade"] = { 2, "', "Darkfallen Deathblades are Darkfallen of the San'layn who wander around the Temple City of En'kilah in the Borean Tundra." },
  ["darkfallen handmaiden"] = { 2, "Darkfallen of the San'layn", "Darkfallen Handmaiden is a Darkfallen of the San'layn." },
  ["darkfallen lieutenant"] = { 2, "', "Darkfallen Lieutenants are Darkfallen of the San'layn found in the Crimson Hall of Icecrown Citadel. They are normally found spread out among the trash in the halls." },
  ["darkfallen noble"] = { 2, "', "Darkfallen Nobles are Darkfallen of the San'layn found in the Crimson Hall of Icecrown Citadel. They are normally found spread out among the trash in the halls." },
  ["darkfallen refugee"] = { 2, "', "Darkfallen Refugees are krokul located at Krokul Hovel on Krokuun." },
  ["darkfallen slave"] = { 2, "', "Darkfallen Slaves are Broken located in Krokuun. Some are being put to work by the Legion, some are encaged or found dead." },
  ["darkfallen tactician"] = { 2, "', "Darkfallen Tacticians are Darkfallen of the San'layn found in the Crimson Hall of Icecrown Citadel. They are normally found spread out among the trash in the halls." },
  ["darkfiend assassin"] = { 2, "', "Darkfiend Assassins are satyrs that spawn at the Field of Dreamers in Val'sharah during   [10-45] Tracking the Enemy. One is also fought during  Oculus Preparations: A Nightmarish Situation." },
  ["darkfiend corruptor"] = { 2, "', "Darkfiend Corruptors are satyrs located in Moonclaw Vale in Val'sharah." },
  ["darkfiend defiler"] = { 2, "', "Darkfiend Defilers are satyrs located in Shala'nir in Val'sharah." },
  ["darkfiend despoiler"] = { 2, "', "Darkfiend Despoilers are satyrs located in Dappled Hollow in Suramar." },
  ["darkfiend dreadbringer"] = { 2, "', "Darkfiend Dreadbringers are satyrs located in the Garden of the Moon in Val'sharah." },
  ["darkfiend dreamtwister"] = { 2, "', "Darkfiend Dreamtwisters are satyrs located in the Garden of the Moon in Val'sharah." },
  ["darkfiend lieutenant"] = { 2, "satyr", "The Darkfiend Lieutenant is a satyr that spawns upon examining the Altar of Malorne at Malorne's Refuge in Val'sharah during   [10-45] Grip of Nightmare." },
  ["darkfiend raider"] = { 2, "', "Darkfiend Raiders are satyrs located in Malorne's Refuge in Val'sharah. One captured Sylendra Gladesong." },
  ["darkfiend summoner"] = { 2, "satyr located in Val'sharah", "Darkfiend Summoner is a satyr located in Val'sharah." },
  ["darkfiend tormentor"] = { 2, "', "Darkfiend Tormentors are satyrs located in Sleeper's Barrow in Val'sharah." },
  ["darkfiend trickster"] = { 2, "satyr disguised as Malfurion Stormrage near the lake at S...", "The Darkfiend Trickster is a satyr disguised as Malfurion Stormrage near the lake at Shala'nir in Val'sharah during  [10-45] Close Enough to Touch. Upon interacting with him, the Trickster will reveal himself." },
  ["darkfiend zealot"] = { 2, "satyr located in Moonclaw Vale in Val'sharah", "Darkfiend Zealot is a satyr located in Moonclaw Vale in Val'sharah." },
  ["darkfire (arakkoa)"] = { 2, "unknown entity or thing mentioned only by Sethekk arakkoa...", "Darkfire is an unknown entity or thing mentioned only by Sethekk arakkoa inside Sethekk Halls: 'Darkfire -- avenge us!' Said along with 'Protect the Veil!' and 'In Terokk's name!' There is otherwise no information or context about who or what Dark..." },
  ["darkfront crawler"] = { 2, "', "Darkfront Crawlers are Drust located at the Faraway Pools in Ardenweald." },
  ["darkfront reaver"] = { 2, "', "Darkfront Reavers are Drust located at the Faraway Pools in Ardenweald." },
  ["darkhaven debtor"] = { 2, "', "Darkhaven Debtors are venthyr located in Revendreth." },
  ["darkhaven denizen"] = { 2, "', "Darkhaven Denizens are venthyr located in the Sinposium in Revendreth." },
  ["darkhaven dweller"] = { 2, "venthyr", "Darkhaven Dweller is a venthyr." },
  ["darkhaven outcast"] = { 2, "dead venthyr located next to the Anima Stake by the Shimm...", "Darkhaven Outcast is a dead venthyr located next to the Anima Stake by the Shimmering Rift in the Endmire in Revendreth." },
  ["darkhaven villager"] = { 2, "', "Darkhaven Villagers are venthyr located in Darkhaven in Revendreth." },
  ["darklost brute"] = { 2, "', "Darklost Brutes are voidscarred located on Telogrus Rift during  [70] Defend Telogrus Rift. They are first seen at the entrance to Ulduar in the Storm Peaks during  [70] Walk a Mile in Her Shadows." },
  ["darklost krokul"] = { 2, "', "Darklost Krokuls are voidscarred Broken located at the Oronaar Collapse in Eredath." },
  ["darkmaul centurion"] = { 2, "', "Darkmaul Centurions are ogres located in the Font of Shadows at the Darkmaul Citadel." },
  ["darkmaul channeler"] = { 2, "', "Darkmaul Channelers are ogres located at the Darkmaul Citadel." },
  ["darkmaul ogre"] = { 2, "', "Darkmaul Ogres are ogres." },
  ["darkmaul shadowcaller"] = { 2, "', "Darkmaul Shadowcallers are ogres located in the Font of Shadows at the Darkmaul Citadel." },
  ["darkmist ascendant relyana"] = { 2, "Mawsworn kyrian located in the Crucible of the Damned in ...", "Darkmist Ascendant Relyana is a Mawsworn kyrian located in the Crucible of the Damned in the Maw during the  [60B] Night Fae Assault, serving as the final boss of the assault." },
  ["darkmoon carnie"] = { 2, "', "Darkmoon Carnies are carnies found in Darkmoon Island. You can find them wandering around places, usually with a broom in hand and complaining about litterbugs." },
  ["darkmoon faire greeter (gnome)"] = { 2, "gnome located in Darkmoon Faire Staging Area in Goldshire...", "Darkmoon Faire Greeter is a gnome located in Darkmoon Faire Staging Area in Goldshire in Elwynn Forest." },
  ["darkmoon fortune teller"] = { 2, "', "Darkmoon Fortune Tellers are what they are, fortune tellers affiliated with the Darkmoon Faire. They are summoned from the inscribed Darkmoon Faire decks." },
  ["darkness (character)"] = { 2, "', "References to an apparent individual called Darkness are a running joke that began in various character quotations Warcraft III: Reign of Chaos and continues in Heroes of the Storm. The joke has its origins when demon hunters said 'darkness called..." },
  ["darkreaver mor'in"] = { 2, "Darkfallen death knight located at the Axefall in Spires ...", "Darkreaver Mor'in is a Darkfallen death knight located at the Axefall in Spires of Arak." },
  ["darkrider arly"] = { 2, "gnome death knight found on a snowy mountain pinnacle ato...", "Darkrider Arly is a gnome death knight found on a snowy mountain pinnacle atop the Fleshwerks. She, along with Crusader Olakin Sainrith, is involved in a questline to destroy the fleshwerk factories from making abominations." },
  ["darkscale assassin"] = { 2, "dead naga", "The Darkscale Assassin is a dead naga that appears to have had its skull broken in a fight with the Keeper of the Grove Aros in Darkshore." },
  ["darkscale looter"] = { 2, "', "Darkscale Looters are naga located in Darkshore." },
  ["darkscale myrmidon"] = { 2, "', "Darkscale Myrmidons are naga found at Nazj'vel in Darkshore." },
  ["darkscale priestess"] = { 2, "', "Darkscale Priestess are a four naga offering the  [Horn of the Ancients] to Queen Azshara above of Nazj'vel in southern Darkshore." },
  ["darkscale raider"] = { 2, "', "Darkscale Raiders are naga located in Darkshore." },
  ["darkscale ritualist"] = { 2, "naga", "Darkscale Ritualist is a naga." },
  ["darkscale scout"] = { 2, "', "Darkscale Scouts are naga found at the Ruins of Lornesta in Darkshore." },
  ["darkscale siren"] = { 2, "', "Darkscale Sirens are naga found at Nazj'vel in Darkshore. During the Battle for Darkshore they can be found at Bashal'Aran." },
  ["darkscale supplicant"] = { 2, "naga", "Darkscale Supplicant is a naga." },
  ["darkscale taskmaster"] = { 2, "naga located in Tomb of Sargeras", "Darkscale Taskmaster is a naga located in Tomb of Sargeras. He assists Harjatan and controls several Razorjaw murlocs." },
  ["darkscale tidecaller"] = { 2, "', "Darkscale Tidecallers are naga located in Darkshore." },
  ["darkscreecher akkarai"] = { 2, "', "Darkscreecher Akkarai is one of four descendants of Terokk's ancient enemies who are being held prisoner by the Skettis talonpriests. You learn of their existence from a tome named  [Adversarial Bloodlines]." },
  ["darkscryer raastok"] = { 2, "arakkoa aligned with the Arakkoa Outcasts", "Darkscryer Raastok is an arakkoa aligned with the Arakkoa Outcasts. He considers the Adherents of Rukhmar close-minded fools for forbidding the study of shadow magic and branding all who seek answers in the dark as heretics." },
  ["darkshore prisoner"] = { 2, "', "Darkshore Prisoners were night elves and worgen that were captured in the Shatterspear War Camp in Darkshore during the War of the Thorns." },
  ["darkspear vanguard"] = { 2, "', "Darkspear Vanguards are located in the Kor'kron Barracks in Siege of Orgrimmar guarding the entrances and fighting against the Kor'kron forces." },
  ["darkspine myrmidon"] = { 2, "myrmidons are mind-controlling the resident murlocs", "Darkspine Myrmidons are male naga on the Greengill Coast of the Isle of Quel'Danas. Along with the Darkspine Sirens, the myrmidons are mind-controlling the resident murlocs, Greengill Slaves." },
  ["darkspine siren"] = { 2, "sirens are mind-controlling the resident Greengill murlocs", "Darkspine Sirens are level 70 female naga on the Greengill Coast of the Isle of Quel'Danas. Along with the Darkspine Myrmidons, the sirens are mind-controlling the resident Greengill murlocs, Greengill Slaves with arcane orbs." },
  ["darktide aggressor"] = { 2, "', "Darktide Aggressors are naga located throughout the Siren Isle while  [80EWQ] Serpent's Wrath is active." },
  ["darktide champion"] = { 2, "', "Darktide Champions are naga found at various locations throughout Kul Tiras and Zandalar that have come under naga attacks." },
  ["darktide conqueror"] = { 2, "', "Darktide Conquerors are naga located throughout the Siren Isle while  [80EWQ] Serpent's Wrath is active." },
  ["darktide marauder"] = { 2, "', "Darktide Marauders are naga located at Carver's Harbor in Drustvar." },
  ["darktide oracle"] = { 2, "', "Darktide Oracles are naga located throughout the Siren Isle while  [80EWQ] Serpent's Wrath is active." },
  ["darktide sorceress"] = { 2, "', "Darktide Sorceresses are naga located at Carver's Harbor in Drustvar." },
  ["darktide witch"] = { 2, "', "Darktide Witches are naga located at Carver's Harbor in Drustvar." },
  ["darktooth spirit-caller"] = { 2, "', "Darktooth Spirit-Callers are gnolls located in the Azure Span." },
  ["darkturned pupil"] = { 2, "', "Darkturned Pupils are Forsworn kyrian located at the Temple of Humility in Bastion." },
  ["darkvowed recruit"] = { 2, "', "Darkvowed Recruits are Forsworn kyrian located at the Court of Elation in Bastion." },
  ["darkvowed scryer"] = { 2, "', "Darkvowed Scryers are Forsworn kyrian located in Bastion." },
  ["darkwall betrayer"] = { 2, "', "Darkwall Betrayers are venthyr located at Darkwall Tower in Revendreth." },
  ["darkwall demolisher"] = { 2, "', "Darkwall Demolishers are venthyr located at Darkwall Tower in Revendreth." },
  ["darkwall vandal"] = { 2, "', "Darkwall Vandals are venthyr located at Darkwall Tower in Revendreth." },
  ["darkweaver ji'tan"] = { 2, "mogu located in Zuldazar", "Darkweaver Ji'tan is a mogu located in Zuldazar. He is a loyalist of Zul's Zanchuli Council." },
  ["darkweaver kar'dress"] = { 2, "naga located in the Eternal Palace", "Darkweaver Kar'dress is a naga located in the Eternal Palace." },
  ["darkweaver syth"] = { 2, "first Boss of Sethekk Halls in Auchindoun", "Darkweaver Syth is the first Boss of Sethekk Halls in Auchindoun." },
  ["darkwing whisperer"] = { 2, "high arakkoa", "Darkwing Whisperer was a high arakkoa that guarded some ancient artifacts containing untold knowledge in Spires of Arak. It was taken out by the followers sent from the garrisons." },
  ["darmak bloodhowl"] = { 2, "orc warlock in Razor Hill", "Darmak Bloodhowl is an orc warlock in Razor Hill. Warlocks can bring him a  [Pure Soul Shard] and a  [Tainted Soul Shard] to get the  [Rune of Soul Siphon]." },
  ["darmend"] = { 2, "draenei blacksmithing vendor located at the Altar of Sha'...", "Darmend is a draenei blacksmithing vendor located at the Altar of Sha'tar in Shadowmoon Valley." },
  ["darmeto"] = { 2, "technomancer of Ma'nussa", "Darmeto was a technomancer of Ma'nussa who held membership in the Ravel." },
  ["darnassian citizen"] = { 2, "', "Darnassian Citizens are night elves, humans, worgen, gnomes, and draenei found all over the burning Darnassus on Teldrassil. Many of them are already deceased." },
  ["darnassian sentinel (felwood)"] = { 2, "', "Darnassian Sentinels are night elves located in Shadow Hold in Felwood during the Heritage of the Kaldorei. They are being tormented by Cultist Nethus and transform into Twisted Satyrs on attack." },
  ["darrah anderson"] = { 2, "human located in Mariner's Row in Boralus", "Darrah Anderson is a human located in Mariner's Row in Boralus." },
  ["darren"] = { 2, "', "Darren was one of the best prospectors the Explorers' League had to offer, and had seen more battles than all the journeymen assigned to him combined. He led an expedition to Uldaman, where they were attacked by a Dark Iron dwarf." },
  ["darren boyle"] = { 2, "boy living in Lakeshire in Redridge Mountains", "Darren Boyle is a boy living in Lakeshire in Redridge Mountains. When Aramar Thorne was six and was playing by Lake Everstill, the nasty Darren pushed him down into the sand and took his horse." },
  ["darren clease"] = { 2, "worgen trade goods vendor located at the Talonbranch Glad...", "Darren Clease is a worgen trade goods vendor located at the Talonbranch Glade in Felwood. He can be found near the southern entrance, nearby several guards and a shack." },
  ["darrowshire betrayer"] = { 2, "', "Darrowshire Betrayers are undead ghosts located in Darrowshire in the Eastern Plaguelands during  [15-30] The Battle of Darrowshire." },
  ["dartol"] = { 2, "creator of the ever popular [Dartol's Rod of Transformation]", "Dartol was the creator of the ever popular [Dartol's Rod of Transformation]. Not much is known about Dartol, except for what Teronis has depicted in his journal." },
  ["daruk"] = { 2, "tuskarr located in Maedin's Challenge in Nazjatar", "Daruk is a tuskarr located in Maedin's Challenge in Nazjatar." },
  ["daruukhan villager"] = { 2, "', "Daruukhan Villagers are centaur located outside Daruukhan in the Ohn'ahran Plains." },
  ["daruun"] = { 2, "draenei trader located at the Arbor Glen in Shadowmoon Va...", "Daruun is a draenei trader located at the Arbor Glen in Shadowmoon Valley. His partner in trade is Gaades." },
  ["darvel the frugal"] = { 2, "venthyr located in the Enclave in Oribos", "Darvel the Frugal is a venthyr located in the Enclave in Oribos." },
  ["datein"] = { 2, "tauren techslayer", "Datein was a tauren techslayer. He was a friend of the hunter Rorgham." },
  ["dathendrash"] = { 2, "dracthyr located in Loamm in Zaralek Cavern", "Dathendrash is a dracthyr located in Loamm in Zaralek Cavern. He also appears in the Orgrimmar Skyway in Orgrimmar and in Trade District in Stormwind City during Kalimdor Cup, serving as the  [Riders of Azeroth Badge] vendor." },
  ["dathlane the herald"] = { 2, "Mawsworn kyrian located in the Maw", "Dathlane the Herald is a Mawsworn kyrian located in the Maw. He spawns as part of the Wrath of the Jailer event." },
  ["dava"] = { 2, "earthen found in a tribute site on a mountain top between...", "Dava is an earthen found in a tribute site on a mountain top between Mourning Rise and Boulder Springs in the Isle of Dorn." },
  ["davan"] = { 2, "briefly mentioned dwarf", "Davan was a briefly mentioned dwarf who was ordered by Falric to fire on Mal'Ganis's undead." },
  ["daven kessler"] = { 2, "worgen located at the Lunarfall in Shadowmoon Valley", "Daven Kessler is a worgen located at the Lunarfall in Shadowmoon Valley. He can only be recruited using the Headhunter's Harvest from Lunarfall Inn." },
  ["davin"] = { 2, "commandant of Northwatch Hold for three years by the time...", "Major Davin was the commandant of Northwatch Hold for three years by the time of the events of Cycle of Hatred." },
  ["dawn"] = { 2, "first earthen to awaken from the Hall of Awakening after ...", "Dawn was the first earthen to awaken from the Hall of Awakening after it was restored by Magni Bronzebeard. She now serves as a guide for newly awakened earthen, alongside Foreman Uzjax, helping them navigate the process of awakening and preparing..." },
  ["dawn-seeker alkset"] = { 2, "arakkoa apexis trader found in Warspear on Ashran", "Dawn-Seeker Alkset is an arakkoa apexis trader found in Warspear on Ashran." },
  ["dawn-seeker jiklar"] = { 2, "arakkoa Order of the Awakened apexis trader found in Wars...", "Dawn-Seeker Jiklar is an arakkoa Order of the Awakened apexis trader found in Warspear on Ashran." },
  ["dawn-seeker kasrek"] = { 2, "arakkoa Order of the Awakened apexis trader found in Stor...", "Dawn-Seeker Kasrek is an arakkoa Order of the Awakened apexis trader found in Stormshield on Ashran." },
  ["dawn-seeker kayrek"] = { 2, "arakkoa apexis trader found in Warspear on Ashran", "Dawn-Seeker Kayrek is an arakkoa apexis trader found in Warspear on Ashran." },
  ["dawn-seeker kirrik"] = { 2, "arakkoa found in Warspear on Ashran", "Dawn-Seeker Kirrik is an arakkoa found in Warspear on Ashran. He appears to be the ambassador for the Order of the Awakened in Warspear." },
  ["dawn-seeker krek"] = { 2, "arakkoa Order of the Awakened apexis trader found in Stor...", "Dawn-Seeker Krek is an arakkoa Order of the Awakened apexis trader found in Stormshield on Ashran." },
  ["dawn-seeker krisek"] = { 2, "arakkoa located at Lion's Watch", "Dawn-Seeker Krisek is an arakkoa located at Lion's Watch and Vol'mar in Tanaan Jungle and is a member of the Order of the Awakened. Krisek will enlist the help of Alliance and Horde players to collect fel-corrupted apexis fragments in the hope tha..." },
  ["dawn-seeker rikks"] = { 2, "Order of the Awakened arakkoa found in Warspear on Ashran", "Dawn-Seeker Rikks is an Order of the Awakened arakkoa found in Warspear on Ashran." },
  ["dawn-seeker rilak"] = { 2, "arakkoa found in Stormshield on Ashran", "Dawn-Seeker Rilak is an arakkoa found in Stormshield on Ashran. He appears to be the ambassador for the Order of the Awakened in Stormshield." },
  ["dawn-seeker skariss"] = { 2, "arakkoa apexis trader found in Warspear on Ashran", "Dawn-Seeker Skariss is an arakkoa apexis trader found in Warspear on Ashran." },
  ["dawn-seeker skelak"] = { 2, "arakkoa Order of the Awakened apexis trader found in Stor...", "Dawn-Seeker Skelak is an arakkoa Order of the Awakened apexis trader found in Stormshield on Ashran." },
  ["dawn-seeker valak"] = { 2, "arakkoa located at the Aktar's Post in Tanaan Jungle", "Dawn-Seeker Valak is an arakkoa located at the Aktar's Post in Tanaan Jungle." },
  ["dawn-seeker vallar"] = { 2, "arakkoa Order of the Awakened apexis trader found in Stor...", "Dawn-Seeker Vallar is an arakkoa Order of the Awakened apexis trader found in Stormshield on Ashran." },
  ["dawn-seeker verroak"] = { 2, "arakkoa Order of the Awakened apexis trader found in Stor...", "Dawn-Seeker Verroak is an arakkoa Order of the Awakened apexis trader found in Stormshield on Ashran." },
  ["dawnchaser brave"] = { 2, "', "Dawnchaser Braves are tauren of the Dawnchaser tribe found in Dawnchaser Retreat in the Krasarang Wilds as well as alongside Sunwalker Dezco and Nala in the Vale of Eternal Blossoms, guarding the Shrine of Two Moons against attackers." },
  ["dawnchaser captive"] = { 2, "', "Dawnchaser Captives are tauren located at the Ruins of Korja and Field of Korja in Krasarang Wilds. They are being held prisoner by Korjan Slavemasters and forced to mine artifacts and Buried Quilen." },
  ["dawnchaser hunter"] = { 2, "', "Dawnchaser Hunters are tauren located in Dawnchaser Retreat in Krasarang Wilds. They are fighting against Korjan Reavers." },
  ["dawnseeker rukaryx"] = { 2, "arakkoa located at the Lunarfall in Shadowmoon Valley", "Dawnseeker Rukaryx is an arakkoa located at the Lunarfall in Shadowmoon Valley and Frostwall in Frostfire Ridge. She can only be recruited with her contract which is purchased from Dawn-Seeker Alkset in Warspear and Dawn-Seeker Krek in Stormshield." },
  ["dawyn the rabid"] = { 2, "worgen located in Arathi Basin during Brawl: Comp Stomp f...", "Dawyn the Rabid is a worgen located in Arathi Basin during Brawl: Comp Stomp for Horde players." },
  ["dax blitzblaster"] = { 2, "goblin located in Crapopolis during   [50-90] Beat The Cr...", "Dax Blitzblaster is a goblin located in Crapopolis during   [50-90] Beat The Crapopolis Outta Him!." },
  ["daxx bombhand"] = { 2, "goblin member of the Bilgewater Cartel", "Daxx Bombhand is a goblin member of the Bilgewater Cartel and a surveyor of the Reliquary located at a small Reliquary camp on the northwest side of Atul'Aman in Vol'dun, alongside Elisa Veilsong, whom he reports to. Shandris Feathermoon and an Al..." },
  ["daz"] = { 2, "dreadtick pet of Apari", "Daz was the dreadtick pet of Apari, the leader of the Widow's Bite. After Seshi was sacrificed, Daz went to eat his corpse only to be stopped by Apari, due to the fallen troll being poisoned." },
  ["dazar"] = { 2, "founder", "Dazar was the founder and first king of Zandalar. He led an exodus of his people out of the muck and mire, united the tribes, and built a city of gold." },
  ["deacon andaal"] = { 2, "draenei quest giver outside the Eastwall Tower in the Eas...", "Deacon Andaal is a draenei quest giver outside the Eastwall Tower in the Eastern Plaguelands." },
  ["dead arathi"] = { 2, "Arathi located east of the Hungering Pool in Hallowfall", "The Dead Arathi is an Arathi located east of the Hungering Pool in Hallowfall. She lies on the ground below the Smuggler's Treasure, having presumably fallen to her death." },
  ["dead caravan guard"] = { 2, "', "Dead Caravan Guards are corpses found around Steeljaw's Caravan in the Borean Tundra." },
  ["dead collector bane"] = { 2, "undead located in the Acherus: The Ebon Hold", "Dead Collector Bane is an undead located in the Acherus: The Ebon Hold." },
  ["dead death's rise vrykul"] = { 2, "', "Dead Death's Rise Vrykul are dead vrykul located at Death's Rise in Icecrown." },
  ["dead diseased grimtotem shaman"] = { 2, "', "The Dead Diseased Grimtotem Shaman can be found near the Grimtotem Compound in Feralas, next to the Grimtotem Chest." },
  ["dead diseased woodpaw mystic"] = { 2, "', "The Dead Diseased Woodpaw Mystic can be found near the Woodpaw Den in Feralas, next to the Woodpaw Bag." },
  ["dead draenei slave"] = { 2, "', "Dead Draenei Slaves are deceased draenei located in Frostfire Ridge. They can be buried." },
  ["dead employee"] = { 2, "', "Dead Employees are gnome and goblin corpses floating above the Sunken Dig Site in the Thousand Needles. They were employees of Brivelthwerp who were killed by silithid while setting up the refrigeration vault inside the dig site." },
  ["dead frostpaw shaman"] = { 2, "', "Dead Frostpaw Shaman were furbolgs located in Grizzlemaw in Grizzly Hills. Next to them were Shaman's Pouches." },
  ["dead gnome"] = { 2, "', "Five Dead Gnomes are deceased gnomes on the Wagon of Unending Agony ridden by Painmaster Thundrak in Ashenvale." },
  ["dead miner"] = { 2, "', "Dead Miners are dead dwarves located at Gol'Bolar Quarry and inside Gol'Bolar Quarry Mine in Dun Morogh. They've been killed by troggs from the Rockjaw tribe." },
  ["dead patron"] = { 2, "Veiled Market", "Dead Patrons are brokers located in Tazavesh, the Veiled Market, slain by the Shadowguard." },
  ["dead rangari"] = { 2, "', "Dead Rangari are draenei located at the Crimson Fen in Gorgrond. Some are found in Shadowmoon Valley." },
  ["dead ritualist"] = { 2, "', "Dead Ritualists are Arathi found next to the Dark Ritual book in a cave in central Hallowfall." },
  ["dead taurajo refugee"] = { 2, "', "Dead Taurajo Refugees are tauren located east of the Overgrowth in Southern Barrens." },
  ["dead twilight cultist"] = { 2, "dead tauren artisan of the Twilight's Hammer located in t...", "The Deceased Twilight Cultist is a dead tauren artisan of the Twilight's Hammer located in the Zoram Strand. He can be spoken to using an  [Elixir of Coalesced Regret], allowing crafters of sufficient skill to find the  [Handful of Shifting Scales..." },
  ["dead zin'jatar raider"] = { 2, "', "Dead Zin'jatar Raiders are deceased naga located in the Shimmering Expanse. During  [30-35] A Distracting Scent, they are disposed of since predators can smell their scent and attract attention toward the Silver Tide Hollow." },
  ["deadwaker ghendish"] = { 2, "centaur located in the Ohn'ahran Plains", "Deadwaker Ghendish is a centaur located in the Ohn'ahran Plains." },
  ["deadwind brute"] = { 2, "', "Deadwind Brutes are ogres located in the Vice in Deadwind Pass." },
  ["deadwind mauler"] = { 2, "', "Deadwind Maulers are ogres located in the Vice in Deadwind Pass." },
  ["deadwood avenger"] = { 2, "', "Deadwood Avengers are furbolgs found in Felpaw Village in Felwood." },
  ["deadwood den watcher"] = { 2, "Watcher will call for help amongst its Deadwood brethren", "Deadwood Den Watchers are furbolgs found in Felpaw Village in Felwood. When at half health, the Watcher will call for help amongst its Deadwood brethren." },
  ["deadwood gardener"] = { 2, "', "Deadwood Gardeners are furbolgs found in Deadwood Village in Felwood." },
  ["deadwood pathfinder"] = { 2, "', "Deadwood Pathfinders are furbolgs found in Deadwood Village in Felwood." },
  ["deadwood shaman"] = { 2, "', "Deadwood Shaman are furbolgs found in Felpaw Village in Felwood." },
  ["deadwood warrior"] = { 2, "', "Deadwood Warriors are furbolgs found in Deadwood Village in Felwood." },
  ["dealer aljaan"] = { 2, "ethereal trade goods vendor located at the Stormspire in ...", "Dealer Aljaan is an ethereal trade goods vendor located at the Stormspire in the Netherstorm." },
  ["dealer digriz"] = { 2, "ethereal general goods vendor located at the Stormspire i...", "Dealer Digriz is an ethereal general goods vendor located at the Stormspire in the Netherstorm." },
  ["dealer dunar"] = { 2, "ethereal general goods", "Dealer Dunar is an ethereal general goods and poison vendor located at Midrealm Post in the Netherstorm." },
  ["dealer hazzin"] = { 2, "ethereal general goods", "Dealer Hazzin is an ethereal general goods and reagent vendor located at the Protectorate Watch Post in the Netherstorm. In actuality, he is an agent that personally works for Nexus-Prince Haramad." },
  ["dealer jadyan"] = { 2, "ethereal weapon vendor located at the Stormspire in the N...", "Dealer Jadyan is a ethereal weapon vendor located at the Stormspire in the Netherstorm." },
  ["dealer malij"] = { 2, "ethereal enchanting vendor located at the Stormspire in t...", "Dealer Malij is an ethereal enchanting vendor located at the Stormspire in the Netherstorm." },
  ["dealer najeeb"] = { 2, "ethereal vendor located at the Stormspire in the Netherstorm", "Dealer Najeeb is an ethereal vendor located at the Stormspire in the Netherstorm." },
  ["dealer rashaad"] = { 2, "ethereal small pet vendor located at the Stormspire in th...", "Dealer Rashaad is an ethereal small pet vendor located at the Stormspire in the Netherstorm." },
  ["dealer senzik"] = { 2, "ethereal jewelcrafting vendor located at the Stormspire i...", "Dealer Senzik is an ethereal jewelcrafting vendor located at the Stormspire in the Netherstorm. He sells uncommon quality gems in limited supply." },
  ["dealer tariq"] = { 2, "ethereal poison vendor located at the entrance to the Sha...", "Dealer Tariq is an ethereal poison vendor located at the entrance to the Shadow Labyrinth in Terokkar Forest." },
  ["dealer vijaad"] = { 2, "ethereal quest giver found in Darkweaver Syth's room to t...", "Dealer Vijaad is a ethereal quest giver found in Darkweaver Syth's room to the west in Sethekk Halls. Hidden from the view of the Sethekk within a barrier, he is looking to hire some help to get rare gems for a buyer: the eyes of the wind serpents..." },
  ["dealer xy'exa"] = { 2, "boss located in the Hidden Glade in the Other Side", "Dealer Xy'exa is a boss located in the Hidden Glade in the Other Side. She is a cunning aquisitionist, wielding an array of magical contrivances that she has collected over the millennia." },
  ["dealer zijaad"] = { 2, "ethereal reagent vendor located at the Stormspire in the ...", "Dealer Zijaad is an ethereal reagent vendor located at the Stormspire in the Netherstorm." },
  ["dearny"] = { 2, "draenei leatherworking vendor located at Altar of Sha'tar...", "Dearny is a draenei leatherworking vendor located at Altar of Sha'tar in Shadowmoon Valley." },
  ["death knight (npc)"] = { 2, "', "The Death Knights replace the Death Knight Initiates in Death's Breach after players complete   [8-30] Victory At Death's Breach!, advancing the storyline to phase 2. They are located in front of the newly-repositioned Prince Valanar, listening to..." },
  ["death knight (warcraft ii)"] = { 2, "', "These soldiers of darkness were created by Gul'dan to replace the slaughtered Warlock clans. Assembled from the corpses of the Knights of Azeroth slain in the last battles of the First War, these abominations were then instilled with the ethereal ..." },
  ["death knight (mob)"] = { 2, "Death Knight appears more like a normal human than most u...", "Tall, gaunt undead, the Death Knight appears more like a normal human than most undead. Heavily armored, they swing two-handed swords." },
  ["death knight adept"] = { 2, "', "Death Knight Adepts are human, undead, and orc death knights of the Host of Suffering located in Icecrown. During  [25-30G5] The Fate of Bloodbane, they can be found fighting the Knights of the Ebon Blade under Icecrown Citadel." },
  ["death knight captain"] = { 2, "', "Death Knight Captains are night elves, tauren, and blood elves found in Naxxramas." },
  ["death knight champion (ebon hold)"] = { 2, "', "Death Knight Champions are the guards of Acherus: The Ebon Hold once the Knights of the Ebon Blade are freed from the grasp of the Lich King." },
  ["death knight initiate"] = { 2, "', "Death Knight Initiates are death knights located in the Scarlet Enclave." },
  ["death knight initiate (icecrown)"] = { 2, "', "Death Knight Initiates are death knights of the Host of Suffering located in Malykriss: The Vile Hold of Icecrown." },
  ["death knight master"] = { 2, "', "Death Knight Masters are only present at the Shadow Vault before it is captured by the Knights of the Ebon Blade." },
  ["death speaker blackthorn"] = { 2, "quilboar found in the Spiral of Thorns in Razorfen Downs", "Death Speaker Blackthorn is a quilboar found in the Spiral of Thorns in Razorfen Downs. He is capable of casting arcane magic." },
  ["death speaker jargba"] = { 2, "quilboar ghost during the Warlord Ramtusk encounter", "Death Speaker Jargba is a quilboar ghost during the Warlord Ramtusk encounter." },
  ["death speaker jargba (classic)"] = { 2, "quilboar found in Razorfen Kraul", "Death Speaker Jargba is a quilboar found in Razorfen Kraul. Jargba is a Death Speaker, a prophet of the quilboar religion which preaches their fallen god Agamaggan will rise from the dead." },
  ["death touched warrior"] = { 2, "', "Death Touched Warriors are dwarves located in the death knight wing in Naxxramas." },
  ["death's head acolyte"] = { 2, "', "Death's Head Acolytes are quilboar found in Razorfen Kraul." },
  ["death's head adept"] = { 2, "', "Death's Head Adepts are quilboar located at Razorfen Kraul." },
  ["death's head arachnomancer"] = { 2, "', "Death's Head Arachnomancers are located in Razorfen Downs. They will occasionally buff nearby spiders, increasing their attack speed by 100%." },
  ["death's head cultist"] = { 2, "', "Death's Head Cultists are quilboar found outside the Razorfen Downs in the Thousand Needles." },
  ["death's head geomancer"] = { 2, "', "Death's Head Geomancers are quilboar found in Razorfen Downs." },
  ["death's head ghoul wrangler"] = { 2, "', "Death's Head Ghoul Wranglers are quilboar located in the Murder Pens in Razorfen Downs." },
  ["death's head necrolyte"] = { 2, "', "Death's Head Necrolytes are located in Razorfen Downs." },
  ["death's head necromancer"] = { 2, "quilboar located in Razorfen Downs", "Death's Head Necromancer is a quilboar located in Razorfen Downs." },
  ["death's head priest"] = { 2, "', "Death's Head Priests are quilboar located in Razorfen Kraul." },
  ["death's head sage"] = { 2, "', "Death's Head Sages are quilboar located in Razorfen Kraul." },
  ["death's head seer"] = { 2, "', "Death's Head Seers are quilboar loacted in Razorfen Kraul." },
  ["death's head shadowmender"] = { 2, "', "Death's Head Shadowmenders are located in the Spiral of Thorns in Razorfen Downs." },
  ["death's head ward keeper"] = { 2, "', "Death's Head Ward Keepers are quilboar located in Razorfen Kraul." },
  ["death's head warrior"] = { 2, "', "Death's Head Warriors are quilboar located in Thousand Needles." },
  ["deathbinder hroth"] = { 2, "Drust located in Darkreach in Ardenweald", "Deathbinder Hroth is a Drust located in Darkreach in Ardenweald. He is attempting to corrupt Starbright." },
  ["deathcaller mystic"] = { 2, "', "Deathcaller Mystics are vrykul located in Stormheim." },
  ["deathling"] = { 2, "', "Deathlings are murlocs found in Azmerloth." },
  ["deathling destroyer"] = { 2, "', "Deathling Destroyers are murlocs found in Azmerloth." },
  ["deathspeaker zealot"] = { 2, "', "Deathspeaker Zealots are tauren and draenei found in the Oratory of the Damned in Icecrown Citadel. They are members of Cult of the Damned." },
  ["deathtouched slaver"] = { 2, "', "Deathtouched Slavers are Drust located in Waycrest Manor as part of the Gorak Tul encounter. They can't be killed in normal manners." },
  ["deathwhisper shadowcaster"] = { 2, "', "Deathwhisper Shadowcasters can be found in the Pit of Saron. They are accompanied by a Deathwhisper Torturer and two Hungering Ghouls southwest of the pit." },
  ["deathwind"] = { 2, "gnoll located in the Azure Span", "Deathwind is a gnoll located in the Azure Span." },
  ["deathwingurlugull"] = { 2, "murloc found in Azmerloth", "Deathwingurlugull is a murloc found in Azmerloth. He is an alternate version of Deathwing." },
  ["debaar"] = { 2, "draenei quest giver located at Nesingwary Base Camp in Sh...", "Debaar is a draenei quest giver located at Nesingwary Base Camp in Sholazar Basin." },
  ["decatriarch wratheye"] = { 2, "final boss in Brackenhide Hollow", "Decatriarch Wratheye is the final boss in Brackenhide Hollow. She is gnoll shaman who mastered decay magic and commands the Brackenhide that wreaks havoc in the Azure Span." },
  ["decay speaker"] = { 2, "', "Decay Speakers are gnolls located in the Azure Span." },
  ["decay speaker (brackenhide hollow)"] = { 2, "', "Decay Speakers are gnolls located in Lost Kanniak in Brackenhide Hollow." },
  ["decaying corpse (stormheim)"] = { 2, "', "Decaying Corpses are dead vrykul found at Morheim in Stormheim." },
  ["deceased broker"] = { 2, "broker located in a small cave in Perdition Hold in the Maw", "The Deceased Broker is a broker located in a small cave in Perdition Hold in the Maw." },
  ["deceptia"] = { 2, "draenei located at the Orunai Coast in Talador", "Deceptia is a draenei located at the Orunai Coast in Talador. Although alive when seen some distance away, approaching her triggers the event of seeing Deceptia and the refugees exploded by Iron Horde artillery." },
  ["decimus"] = { 2, "domanaar located in Voidstorm", "Decimus is a domanaar located in Voidstorm. At first glance another minion of Xala'tath, Decimus has other ambitions for the Voidstorm and the cosmos at large, and his grand designs align little with those of his dark master." },
  ["decindra"] = { 2, "', "Decindra was one of the One Hundred magi of Arathor. She, Antonius, and their apprentices chose to accompany Thoradin on his quest to find the origins of humanity, which ended in disaster when they broke the seals on the Tomb of Tyr and were kille..." },
  ["deck boss alcorn"] = { 2, "goblin deck captain found on the Horde navy destroyer in ...", "Deck Boss Alcorn is a goblin deck captain found on the Horde navy destroyer in the Frostwall Shipyard." },
  ["decker watts"] = { 2, "worgen located at the Amphitheater of Annihilation in Ashran", "Decker Watts  is a worgen located at the Amphitheater of Annihilation in Ashran." },
  ["deckhand (lunarfall)"] = { 2, "', "Deckhands are workers located on the ships in the Lunarfall Shipyard." },
  ["deckhand (seething shore)"] = { 2, "', "Deckhands are humans and dwarves located on the Sword of Dawn during the battle for the Seething Shore and prior to the Battle for Lordaeron." },
  ["decrepit runecarver"] = { 2, "', "Decrepit Runecarvers are captured vrykul located on the Naglfar in the Maw of Souls." },
  ["dedicated patron"] = { 2, "', "Dedicated Patrons are located in Amirdrassil." },
  ["dee"] = { 2, "kobold located in Campalot in the Ringing Deeps", "Dee is a kobold located in Campalot in the Ringing Deeps." },
  ["deeb"] = { 2, "rare murloc found standing idle on the North Coast in the...", "Deeb is a rare murloc found standing idle on the North Coast in the Tirisfal Glades. It is on a 1.5-2.5 hour respawn timer." },
  ["deedree"] = { 2, "dwarf innkeeper for the Alliance garrison at Lunarfall", "Deedree is the dwarf innkeeper for the Alliance garrison at Lunarfall, in Shadowmoon Valley. She is located by the Town Hall at Tier 1 and inside it at Tiers 2 and 3." },
  ["deeg"] = { 2, "dwarf quest giver located in the Salty Sailor Tavern in B...", "Deeg is a dwarf quest giver located in the Salty Sailor Tavern in Booty Bay in the Cape of Stranglethorn. Booty Bay's latest snuff shipment has been hi-jacked by the Bloodsail Buccaneers, much to Deeg's displeasure." },
  ["deek fizzlebizz"] = { 2, "gnome engineering trainer located on the Stonewrought Dam...", "Deek Fizzlebizz is a gnome engineering trainer located on the Stonewrought Dam in Loch Modan." },
  ["deema"] = { 2, "draenei quest giver located in southern Shadowmoon Valley", "Deema is a draenei quest giver located in southern Shadowmoon Valley." },
  ["deephive chosen"] = { 2, "', "Deephive Chosen are mantid located in the Vale of Eternal Blossoms. They are also found in the Mogu'shan Vaults during  [50] The Engine of Nalak'sha." },
  ["deephive soldier"] = { 2, "', "Deephive Soldiers are mantid located in the Big Blossom Mine in the Vale of Eternal Blossoms. They are also found accompanying Depthcaller Xith'el in the Mogu'shan Vaults." },
  ["deephive summoner"] = { 2, "', "Deephive Summoners are mantid located in the Repository in Mogu'shan Vaults during  [50] The Engine of Nalak'sha." },
  ["deephive swarmborn"] = { 2, "', "Deephive Swarmborn are mantid located in the Vale of Eternal Blossoms." },
  ["deephive voidsinger"] = { 2, "', "Deephive Voidsingers are mantid located in the Vale of Eternal Blossoms." },
  ["deepmurk junkhoarder"] = { 2, "murloc", "Deepmurk Junkhoarder is a murloc." },
  ["deepmurk slave"] = { 2, "murloc", "Deepmurk Slave is a murloc." },
  ["deeprock pitfighter"] = { 2, "', "Deeprock Pitfighters are drogbar located in the Rockcrawler Chasm in Highmountain." },
  ["deeprock scrapper"] = { 2, "', "Deeprock Scrappers are drogbar located in Rockcrawler Chasm in Highmountain." },
  ["deeprock wormtamer"] = { 2, "', "Deeprock Wormtamers are drogbar located in Rockcrawler Chasm in Highmountain." },
  ["deeprun diver"] = { 2, "gnome wearing a diving helmet", "Deeprun Diver is a gnome wearing a diving helmet who sometimes wanders at the sea bottom around Deeprun Tram's underwater tunnels. He can be right-clicked, in which case it greets you in the same way as a Gnome Commoner would." },
  ["deepscale ambusher"] = { 2, "', "Deepscale Ambushers are deceased naga located at the Wreck of the Hungry Riverbeast." },
  ["deepshadow assassin"] = { 2, "', "Deepshadow Assassins are worgen." },
  ["deepsiren saffsis"] = { 2, "naga", "Deepsiren Saffsis is a naga that was taken out by the champions of the Silver Hand who arrived to southern Val'sharah to get  [Lumenstone]." },
  ["deepsurge defender"] = { 2, "', "Deepsurge Defenders are naga located in Felrage Strand and Strand's End in the Broken Shore. They were later empowered with the fel by Harrowing Corruptors." },
  ["deepsurge tidesinger"] = { 2, "', "Deepsurge Tidesingers are naga located in Felrage Strand and Strand's End on the Broken Shore. They were later empowered with the fel by Harrowing Corruptors." },
  ["deez"] = { 2, "', "Deez was one of the NPCs that could spawn by using an  [Amani Hex Stick] on one of the wandering Forest Frogs within the old version of Zul'Aman. Once spawned, he would walk to the entrance of the instance and cheer players on when they walked by." },
  ["defeated argent footman"] = { 2, "', "Defeated Argent Footmen are deceased soldiers located in Kolramas and Drak'Sotra in Zul'Drak." },
  ["defender adrielle"] = { 2, "draenei standing in Blood Watch on Bloodmyst Isle", "Defender Adrielle is a draenei standing in Blood Watch on Bloodmyst Isle. This section concerns content related to Legion." },
  ["defender akee"] = { 2, "draenei of the Hand of Argus", "Defender Akee is a draenei of the Hand of Argus. She is stationed at Blood Watch on Bloodmyst Isle." },
  ["defender artaal"] = { 2, "draenei located at Telmor in Talador", "Defender Artaal is a draenei located at Telmor in Talador." },
  ["defender ashoon"] = { 2, "draenei of the Hand of Argus", "Defender Ashoon is a draenei of the Hand of Argus. She is stationed at Blood Watch on Bloodmyst Isle." },
  ["defender auston"] = { 2, "draenei of the Hand of Argus", "Defender Auston is a draenei of the Hand of Argus. He is stationed at Blood Watch on Bloodmyst Isle." },
  ["defender barrem"] = { 2, "draenei soldier", "Defender Barrem is a draenei soldier who was grievously wounded during the battle for the Broken Shore. He was taken to the Burning Legion-controlled world of Niskara, where he shared a cell with another draenei named Alora, though the two later m..." },
  ["defender grashna"] = { 2, "arakkoa quest giver located in the Lower City of Shattrat...", "Defender Grashna is an arakkoa quest giver located in the Lower City of Shattrath City." },
  ["defender zakar"] = { 2, "nerubian located in Skittering Hollow in Island Expeditions", "Defender Zakar is a nerubian located in Skittering Hollow in Island Expeditions." },
  ["defender of argus"] = { 2, "', "Defenders of Argus are draenei paladins located in the Sanctum of Light in Eastern Plaguelands. They also appear at Deliverance Point on the Broken Shore, where they occasionally spar with Stormforged Valarjar." },
  ["defender of the crown"] = { 2, "name given to refer to the leader of the human forces of ...", "The Defender of the Crown is the name given to refer to the leader of the human forces of the Kingdom of Stormwind during the First War. As a loyal subject of King Llane, the Defender fought on multiple battlefields against the orcs and their lead..." },
  ["defenseless tadpole"] = { 2, "', "Defenseless Tadpoles are murlocs located in Rockaway Shallows in Highmountain." },
  ["defiant lookout"] = { 2, "stealthed vulpera standing on the edge of the bridge betw...", "The Defiant Lookout is a stealthed vulpera standing on the edge of the bridge between Bwoljin's Fall and the Conqueror's Path in Vol'dun." },
  ["defiant queensguard"] = { 2, "', "Defiant Queensguards are vrykul located in Stormheim." },
  ["defiant scrapper"] = { 2, "', "Defiant Scrappers are stealthed vulpera located next to dead Faithless Centurions in Bwoljin's Fall and around the entrance to Vorrik's Sanctum in Vol'dun. According to Meerah, they are hiding along the vulpera's escape route and keeping an eye ou..." },
  ["defiant vrykul"] = { 2, "', "Defiant Vrykul are vrykul found at Storm's Reach in Stormheim during the Legion Assaults when  [10-45LI WQ] Souls of the Vrykul is up. They are fighting Shadowdirge Soul Reapers." },
  ["defias drone"] = { 2, "', "Defias Drones were undead guarding Klaven Mortwake's tower in Westfall. One of them was malformed." },
  ["defiled embalmer"] = { 2, "', "Defiled Embalmers are troll mummies located at the Terrace of Sorrows in Nazmir." },
  ["defiled worshiper"] = { 2, "', "Defiled Worshipers are troll mummies found at the Terrace of Sorrows in Nazmir." },
  ["defiler hexius"] = { 2, "satyr warband leader in Val'sharah", "Defiler Hexius was a satyr warband leader in Val'sharah. He was taken out by the mage champions of the Tirisgarde when Verdisa asked for assistance with him." },
  ["degentrius"] = { 2, "boss in the Magisters' Terrace", "Degentrius is a boss in the Magisters' Terrace." },
  ["dehydrated prisoner"] = { 2, "', "Dehydrated Prisoners are night elves located in Farson Hold in Tol Barad Peninsula. They are friendly to Alliance players, but hostile to Horde players." },
  ["dejahna"] = { 2, "high priestess of Elune at the Temple of Elune in Suramar...", "Dejahna was the high priestess of Elune at the Temple of Elune in Suramar before and during the War of the Ancients." },
  ["dekin"] = { 2, "draenei fishing vendor located at the Crystal Hall in the...", "Dekin is a draenei fishing vendor located at the Crystal Hall in the Exodar. This section concerns content related to Legion." },
  ["delaryn summermoon"] = { 2, "captain of the Darnassian City Guard", "Delaryn Summermoon, nicknamed Del, was the captain of the Darnassian City Guard, and a commander of the night elven forces who fought during the War of the Thorns. Although young, she was thrust into a position of leadership and coordinated the ka..." },
  ["delber cranktoggle"] = { 2, "gnome quest giver stationed at Steelgrill's Depot in Dun ...", "Delber Cranktoggle is a gnome quest giver stationed at Steelgrill's Depot in Dun Morogh. He aids the Alliance in opening Frostmane Retreat to an attack." },
  ["delemm"] = { 2, "draenei paladin trainer located at Blood Watch in on Bloo...", "Delemm is a draenei paladin trainer located at Blood Watch in on Bloodmyst Isle." },
  ["delger"] = { 2, "centaur vendor located in Cloverwood Hollow in the Ohn'ah...", "Delger is a centaur vendor located in Cloverwood Hollow in the Ohn'ahran Plains." },
  ["delia"] = { 2, "venthyr innkeeper located in the Sanctuary of the Mad in ...", "Delia is a venthyr innkeeper located in the Sanctuary of the Mad in Revendreth." },
  ["deliah andrean"] = { 2, "wife of Raleigh", "Deliah Andrean, the wife of Raleigh Andrean, lived in Brill and was murdered by her friend Valdred Moray. She was buried in a mass grave near Brill, but her body was stolen by Rot Hide gnolls and taken to the Decrepit Ferry in Silverpine Forest." },
  ["deliria dawes"] = { 2, "', "Deliria Dawes is one of the undead Forsaken who remained loyal to Sylvanas Windrunner after the Fourth War and became the captain of the Banshee's Wail after the loyalists had acquired it through unknown means. Under Nathanos's command, she used t..." },
  ["delmanis the hated"] = { 2, "Hated is a satyr found patrolling around the Tower of Alt...", "Delmanis the Hated is a satyr found patrolling around the Tower of Althalaxx in Darkshore. Judging by his location, he was a follower of Athrikus Narassin of the Cult of the Dark Strand." },
  ["delusional zealot"] = { 2, "', "Delusional Zealots are arakkoa located at Iskar's Clutch in Hellfire Citadel." },
  ["delver mardei"] = { 2, "worgen located in the Throughway in Zaralek Cavern", "Delver Mardei is a worgen located in the Throughway in Zaralek Cavern." },
  ["demented"] = { 2, "', "Demented are voidscarred broken located in the Forge of Aeons." },
  ["demented knife-twister"] = { 2, "Waking City", "Demented Knife-Twisters are gnomes located in Ny'alotha in Ny'alotha, the Waking City. They are stealthed." },
  ["demolisher engineer blastwrench"] = { 2, "goblin located in the Expedition Base Camp in Ulduar", "Demolisher Engineer Blastwrench is a goblin located in the Expedition Base Camp in Ulduar. He is sitting on an ogre." },
  ["demolition dome custodian"] = { 2, "', "Demolition Dome Custodians are goblins located at the Demolition Dome in the Undermine." },
  ["demolitions assistant"] = { 2, "', "Demolitions Assistants are goblins and gnomes located in Bladefist Bay in the Siege of Orgrimmar." },
  ["demolitions assistant (alliance)"] = { 2, "', "Demolitions Assistants are gnomes who take part in the Galakras encounter." },
  ["demolitions expert"] = { 2, "', "Demolitions Experts are goblins and gnomes located in Bladefist Bay in the Siege of Orgrimmar." },
  ["demolitions expert (alliance)"] = { 2, "', "Demolitions Experts are gnomes that take part in the Galakras encounter." },
  ["demon conjurer"] = { 2, "', "Demon Conjurers are ogres located in Telmor in Talador." },
  ["demonia pickerin"] = { 2, "Forsaken located in Dreadscar Rift", "Demonia Pickerin is a Forsaken located in Dreadscar Rift." },
  ["den whomper"] = { 2, "', "Den Whompers are ogres located in the Admiral's Den in Thousand Needles." },
  ["denath"] = { 2, "draenei located at the Altar of Sha'tar in Shadowmoon Valley", "Denath is a draenei located at the Altar of Sha'tar in Shadowmoon Valley." },
  ["denathrius"] = { 2, "Eternal One", "Sire Denathrius (/ˌdə.ˈnæθ.ɹi.əs/ də-NATH-ree-əs), the Master, is an Eternal One and the creator and the former leader of the realm of Revendreth and its inhabitants, the venthyr people, which he ruled from Castle Nathria. Calculating and methodic..." },
  ["denbrawn"] = { 2, "novelist of Denbrawn's Treatise on the 'Song of Aegwynn'", "Denbrawn is the novelist of Denbrawn's Treatise on the 'Song of Aegwynn', a book mentioned in The Last Guardian, which the mage Guzbah was reviewing at the time of his death." },
  ["denea"] = { 2, "night elf Sentinel", "Sentinel Lieutenant Denea is an night elf Sentinel and Commander Haldrissa Woodshaper's second in command. She would often question if Haldrissa was fit to lead since her age showed signs of frailty, but after her heroic actions, such as killing a..." },
  ["deng-chon"] = { 2, "father of Deng-Tai", "Deng-Chon is the father of Deng-Tai." },
  ["deng-tai"] = { 2, "', "Deng-Tai is one of Warlord Kao's bodyguards and as such was present when his master resurrected by the Zandalari trolls. Under his master's command, Deng-Tai joined with the force of 500 Zandalari warriors ordered to destroy the Shado-Pan and thei..." },
  ["deniigi"] = { 2, "tuskarr spearcrafter located at Kamagua in the Howling Fjord", "Deniigi is a tuskarr spearcrafter located at Kamagua in the Howling Fjord." },
  ["denizen druid"] = { 2, "', "Denizen Druids are druids found in the Eye of Ysera in the Emerald Dream." },
  ["dentarg"] = { 2, "', "The ogre mage Dentarg was one of the most trusted servants of Ner'zhul prior to the destruction of Draenor." },
  ["dentarg (alternate universe)"] = { 2, "ogre found within the Den of Secrets in Shadowmoon Valley", "Dentarg is an ogre found within the Den of Secrets in Shadowmoon Valley." },
  ["deorim"] = { 2, "draenei enchanting supplier located at the sea base of Hi...", "Deorim is a draenei enchanting supplier located at the sea base of Highbank in the Twilight Highlands." },
  ["deos"] = { 2, "kyrian", "Deos is a kyrian that is one of the trainees during the quests  [60] Training Our Forces,  [60] Training in Maldraxxus,  [60] Training in Revendreth, and  [60] Training in Ardenweald. He appears again in central Korthia, nearly overcome by Mawsworn." },
  ["deplina"] = { 2, "venthyr located in the Purloined Stores in Castle Nathria", "Deplina is a venthyr located in the Purloined Stores in Castle Nathria." },
  ["depraved absolutist"] = { 2, "', "Depraved Absolutists are venthyr located at the Halls of Atonement in Revendreth." },
