  ["depraved matron"] = { 2, "venthyr encountered by adventure companions in Revendreth", "Depraved Matron is a venthyr encountered by adventure companions in Revendreth." },
  ["depraved notary"] = { 2, "', "Depraved Notaries are venthyr located at the Halls of Atonement in Revendreth." },
