  ["depraved soulcollector"] = { 2, "', "Depraved Soulcollectors are venthyr located at the Halls of Atonement in Revendreth." },
  ["depraved soulflayer"] = { 2, "', "Depraved Soulflayers are venthyr located at the Halls of Atonement in Revendreth. They can be found draining anima from Abused Souls." },
  ["depraved stalker"] = { 2, "', "Depraved Stalkers are venthyr located at the Halls of Atonement in Revendreth." },
