  ["depthcaller xith'el"] = { 2, "mantid located in the Repository in Mogu'shan Vaults duri...", "Depthcaller Xith'el is a mantid located in the Repository in Mogu'shan Vaults during  [50] The Engine of Nalak'sha. Xith'el is accompanied by two Deephive Soldiers." },
  ["depths warden"] = { 2, "', "Depths Wardens are venthyr located in Sanguine Depths." },
  ["deputy zo'ji"] = { 2, "broker located in Tazavesh", "Deputy Zo'ji is a broker located in Tazavesh, the Veiled Market in K'aresh." },
  ["deputy zo'mi"] = { 2, "broker located in Tazavesh", "Deputy Zo'mi is a broker located in Tazavesh, the Veiled Market in K'aresh." },
  ["deputy zo'om"] = { 2, "broker patroling around Constable Zo'ardaz", "Deputy Zo'om is a broker patroling around Constable Zo'ardaz and Deputy Zo'mi in Tazavesh, the Veiled Market in K'aresh." },
  ["deputy zo'zu"] = { 2, "broker located in Tazavesh", "Deputy Zo'zu is a broker located in Tazavesh, the Veiled Market in K'aresh." },
  ["der'izu arcanist"] = { 2, "ethereal", "Der'izu Arcanist is an ethereal." },
  ["der'izu bandit"] = { 2, "ethereal", "Der'izu Bandit is an ethereal." },
  ["deranged indu'le villager"] = { 2, "', "Deranged Indu'le Villagers are tuskarr located at Indu'le Village in the Dragonblight." },
  ["deranged ogre"] = { 2, "', "Deranged Ogres are ogres located at the Vul'Gol Ogre Mound within the Duskwood Nightmare Incursion, accessed through the Dream portal in the Twilight Grove." },
  ["deremiis"] = { 2, "draenei hunter trainer located at the Hunters' Sanctum in...", "Deremiis is a draenei hunter trainer located at the Hunters' Sanctum in the Trader's Tier in the Exodar. This section concerns content related to Legion." },
  ["derill fayn"] = { 2, "Arathi quest giver located in Dunelle's Kindness in Hallo...", "Derill Fayn is an Arathi quest giver located in Dunelle's Kindness in Hallowfall, next to his wife Lerrenai. When Derill and Lerrenai joined the Hallowfall Expedition, they thought they would be away from their families for only a few years." },
  ["deriz"] = { 2, "draenei located in Alchemy & Herbalism in the Vault of Li...", "Deriz is a draenei located in Alchemy & Herbalism in the Vault of Lights in the Exodar. This section concerns content related to Legion." },
  ["dermid"] = { 2, "Wildhammer dwarf during the Second War", "Dermid was a Wildhammer dwarf during the Second War. He was the first to make contact with the humans who told him they came to fight the orcs in the Hinterlands." },
  ["dermot"] = { 2, "Forsaken", "Dermot is a Forsaken. Magus Wordeen Voidglare wanted the Bloodstone Wedge that Dermot had stolen as part of his attempt to defect from his people." },
  ["dern"] = { 2, "earthen located in the Forgegrounds in Dornogal", "Dern is an earthen located in the Forgegrounds in Dornogal." },
  ["dernim brasshelm"] = { 2, "dwarf", "Dernim Brasshelm is a dwarf. The Stonefist clan suspected that he had murdered Bargrin Stonefist, when it in truth was a dark iron infiltrator." },
  ["derrick brindlebeard"] = { 2, "dwarf found at the Silver Covenant Pavilion in the Argent...", "Derrick Brindlebeard is a dwarf found at the Silver Covenant Pavilion in the Argent Tournament Grounds in Icecrown as part of the Argent Tournament." },
  ["dervishian"] = { 2, "dracthyr located atop the walls of Stormwind City", "Dervishian is a dracthyr located atop the walls of Stormwind City. She also attended the gathering in Amirdrassil when it bloomed on the Dragon Isles after Fyrakk's death." },
  ["desamir ferrar"] = { 2, "deckhand on the Wavestrider", "Desamir Ferrar was a deckhand on the Wavestrider. He defended the ship against the Hidden, and at some fought by the ogre Throgg." },
  ["desharin"] = { 2, "member of the green dragonflight", "Desharin (aka Desharin Greensong in guise) was a member of the green dragonflight and a loyal servant of Ysera, who took on his kaldorei guise in order to assist Thrall with his task to soothe a rampant fire elemental in Feralas. He subsequently t..." },
  ["desiccation refugee"] = { 2, "', "Desiccation Refugees are venthyr located at the Desiccation in Revendreth during  [10-59B] Ash You Like It. Interacting with one will give him a parasol." },
  ["deslan the torturer"] = { 2, "Mawsworn kyrian", "Deslan the Torturer is a Mawsworn kyrian who appears in the lower courtyard of Perdition Hold in the Maw during  [10-55] A Bond Beyond Death." },
  ["desmond"] = { 2, "worgen located within Greywatch in Stormheim", "Desmond is a worgen located within Greywatch in Stormheim. He is found hauling hay about the stables where the Greywatch Gryphons are being held." },
  ["desmond gravesorrow"] = { 2, "Forsaken agent of the Uncrowned stationed west of the Vio...", "Desmond Gravesorrow is a Forsaken agent of the Uncrowned stationed west of the Violet Citadel in Dalaran. Subtlety rogues in search of the Fangs of the Devourer seek him out for information about the whereabouts of Akaari Shadowgore, but by the ti..." },
  ["desperate darnassian citizen"] = { 2, "', "Desperate Darnassian Citizens were night elves, worgen, and humans found in the Temple of the Moon in Darnassus during the Burning of Teldrassil." },
  ["desperate venthyr"] = { 2, "venthyr located in Pridefall Hamlet in Revendreth", "The Desperate Venthyr is a venthyr located in Pridefall Hamlet in Revendreth. She is found draining anima from a Defiant Soul under the supervision of a Clemency Enforcer." },
  ["dessee crashcrank"] = { 2, "gnome located at the Lunarfall in Shadowmoon Valley", "Dessee Crashcrank is a gnome located at the Lunarfall in Shadowmoon Valley. She can only be recruited using the Headhunter's Harvest from Lunarfall Inn." },
  ["dessicated lightbringer"] = { 2, "undead", "Dessicated Lightbringer is an undead." },
  ["destia"] = { 2, "dracthyr located in Orgrimmar Skyway in Orgrimmar", "Destia is a dracthyr located in Orgrimmar Skyway in Orgrimmar. She is observing Kalcifer with Razmu." },
  ["destien"] = { 2, "Arathi child summoned by the  [Khaz Algar Orphan Whistle]...", "Destien is an Arathi child summoned by the  [Khaz Algar Orphan Whistle] while on  [10-90] The Wondrous Weave, part of the Children's Week questline in Dornogal." },
  ["det'rak"] = { 2, "orc", "Det'rak was an orc whose scouting party was ambushed by the Warmaul ogres. The orc perished along with Kelorr." },
  ["determined ritualist"] = { 2, "', "Determined Ritualists were members of the Twilight's Blade found just east of Kirthaven in the Twilight Highlands during  [10-80WQ] Don't Bring That Here." },
  ["deth grul"] = { 2, "', "Deth Gruls are two quilboar brutes appearing in the Caverns of Time along with their band-mates when the concert is up." },
  ["deth'ryll satyr"] = { 2, "', "Deth'ryll Satyrs are satyrs found in the ruins of Bashal'Aran in Darkshore." },
  ["deth'ryll shadowstalker"] = { 2, "', "Deth'ryll Shadowstalkers are satyrs." },
  ["dethbringer"] = { 2, "worgen located in the Molten Fields of the Molten Front", "Dethbringer is a worgen located in the Molten Fields of the Molten Front." },
  ["dethmoora darkeyes"] = { 2, "mysterious warlock", "Dethmoora Darkeyes was a mysterious warlock who met some unknown end, prompting a type of ritual implement known as a Bell of Dethmoora named after her. Mor'zul Bloodbringer was at least vaguely familiar with her, though he did not elaborate on he..." },
  ["dethorin"] = { 2, "original wielder of the Killmaim", "Dethorin was the original wielder of the Killmaim, after it appeared out of the ground in response to his cries. With it, he killed his lady Allurana and her lover for whom had been the cause of his woe and the Killmaim's appearance." },
  ["deucus valdera"] = { 2, "Forsaken alchemy trainer located at the Agronomical Apoth...", "Deucus Valdera is a Forsaken alchemy trainer located at the Agronomical Apothecary in Dalaran. He is seen working on the alchemy station that he built by spending years assembling the components for it." },
  ["devahia"] = { 2, "venthyr rescued from Skoldus Hall in Torghast", "Devahia is a venthyr rescued from Skoldus Hall in Torghast, Tower of the Damned. Afterward, she is found by the Anima Conductor in Sinfall in Revendreth." },
  ["devi"] = { 2, "high elf mage from an alternate universe", "Devi is a high elf mage from an alternate universe and the apparent apprentice of Krasus, the alias of the great red dragon Korialstrasz. She is a dark-skinned elf with raven-black hair and has both a curious and inquisitive air about her that som..." },
  ["deviant scholar"] = { 2, "', "Deviant Scholars are kyrian encountered by adventure companions in Bastion." },
  ["deviate crone"] = { 2, "', "Deviate Crones are two quilboar located in the Southern Barrens. They are accompanying Three-Tooth." },
  ["deviate thornweaver"] = { 2, "', "Deviate Thornweavers are quilboar located in the Overgrowth in the Southern Barrens." },
  ["devin"] = { 2, "', "The sinstone of Devin is found in Revendreth in the Crypt of the Forgotten." },
  ["devlynn styx"] = { 2, "Forsaken located in the Cauldron of Rock in Darkmoon Island", "Devlynn Styx is a Forsaken located in the Cauldron of Rock in Darkmoon Island." },
  ["devonix"] = { 2, "gnomish inventor", "Devonix was a gnomish inventor and explorer. He was fascinated by the legends of the great dragon Nozdormu the Timeless." },
  ["devos"] = { 2, "powerful kyrian", "Devos was a powerful kyrian that served as one of the Paragons of the Ascended under the authority of the Archon. Embodying the virtue of loyalty, she was a staunch believer in Bastion's sacred mission of ferrying souls to the Shadowlands." },
  ["devos (tactics)"] = { 2, "Forsworn kyrian", "Devos, Paragon of Doubt, is a Forsworn kyrian and the last boss located in the Spires of Ascension." },
  ["devoted accomplice"] = { 2, "Veiled Market", "Devoted Accomplices are brokers located in Tazavesh, the Veiled Market." },
  ["devoted battle-priest"] = { 2, "', "Devoted Battle-Priests are friendly priests of several races that were at the Legion Invasion locations. They could be seen doing several things, like healing injured Stormwind Guards." },
  ["devoted guardian"] = { 2, "', "Devoted Guardians are kyrian of the Ascended and Forsworn located in the Seat of the Archon during  [60] The Grand Reception." },
  ["devoted occultist"] = { 2, "', "Devoted Occultists are warlocks located in Felfire Cavern in Azsuna and on the Broken Shore." },
  ["devoted steward"] = { 2, "', "Devoted Stewards are humans found in the Den of Mortal Delights in the Black Temple." },
  ["devout pilgrim"] = { 2, "', "Devout Pilgrims are draenei located at Sunwell Ramparts on the Isle of Quel'Danas." },
  ["devout priest (priory of the sacred flame)"] = { 2, "', "Devout Priests are Arathi located at the Sanctified Grounds in the Priory of the Sacred Flame." },
  ["devout vindicator"] = { 2, "', "Devout Vindicators are draenei who attended the Tishamaat in the Trader's Tier in the Exodar." },
  ["deyon"] = { 2, "tortollan located in Zuldazar", "Deyon is a tortollan located in Zuldazar." },
  ["dhambeela"] = { 2, "reclusive orc seer", "Dhambeela is a reclusive orc seer who sought solitude in a cave by the jungles of Un'Goro Crater. Kova was sent on a quest by Magatha Grimtotem to retrieve her." },
  ["dhink"] = { 2, "kobold taskmaster", "Dhink is a kobold taskmaster who had conducted several burglaries from the Highmountain tauren with several other kobolds. Rather than going underground, Dhink stashed the goods on top of the cave entrance to Mucksnout Den." },
  ["dhurrel"] = { 2, "centaur located at the Artisan's Market in Valdrakken", "Dhurrel is a centaur located at the Artisan's Market in Valdrakken." },
  ["di chen"] = { 2, "finest fighter of his time having the ability to best any...", "Di Chen was the finest fighter of his time having the ability to best any monk who challenged him, slapping arrows out the air with ease, and even the mountains themselves were slight inconveniences for him that could be leapt over or kicked throu..." },
  ["diaani"] = { 2, "draenei found at Bloodthorn Cave in Shadowmoon Valley", "Diaani is a draenei found at Bloodthorn Cave in Shadowmoon Valley." },
  ["diabolic tauren"] = { 2, "special phased version of the Yorgen Farmstead in Duskwoo...", "Diabolic Tauren are large, aggressive tauren found in the 'Secret Cow Level', a special phased version of the Yorgen Farmstead in Duskwood available during Diablo's 20th Anniversary. They are led by the infamous Cow King." },
  ["diana battleheart"] = { 2, "dwarf", "Diana Battleheart is a dwarf." },
  ["diesalven"] = { 2, "', "The necromancer Diesalven is known to have engaged Arellas Fireleaf, High Wizard of the Scarlet Crusade, in a duel. It is not known what transpired between the two, but they were ultimately locked in eternal combat." },
  ["digsite stalwart"] = { 2, "', "Digsite Stalwarts are Arathi located in the Sacred Hollow and at Ghoststone Diggings on the Siren Isle." },
  ["diktynna"] = { 2, "draenei fishing trainer", "Diktynna is a draenei fishing trainer and vendor located at Ammen Ford on Azuremyst Isle. Diktynna is one of the many who journey to Blood Watch to celebrate the hero of Bloodmyst and Azuremyst." },
  ["dillord copperpinch"] = { 2, "goblin food", "Dillord Copperpinch is a goblin food and drink vendor located by the Horde entrance to Alterac Valley in the Hillsbrad Foothills. This section concerns content related to Legion." },
  ["dim flathoof"] = { 2, "tauren located near K3 in the Storm Peaks", "Dim Flathoof is a tauren located near K3 in the Storm Peaks. He appears to be gathering parts for the goblins of K3 at Ricket's Folly." },
  ["dink"] = { 2, "gnome mage trainer located in the Hall of Mysteries in th...", "Dink is a gnome mage trainer located in the Hall of Mysteries in the Mystic Ward in Ironforge. This section concerns content related to the Warcraft novels, novellas, or short stories." },
  ["dinn"] = { 2, "rare elite djaradin", "Dinn is a rare elite djaradin that spawns in the Zaqali Caldera in Zaralek Cavern." },
  ["dinnis"] = { 2, "gnome located near the entrance to Booty Bay in Stranglet...", "Dinnis was a gnome located near the entrance to Booty Bay in Stranglethorn Vale during the original alpha." },
  ["diodor the damned"] = { 2, "', "Formerly a decorated hero in the First War, Diodor the Damned studied necromancy and eventually became one of the first members of the Cult of the Damned.  After leading two successful assaults against the Scarlet Monastery, he was killed when the..." },
  ["dionae"] = { 2, "Forsworn kyrian located at the Small Shrine in Bastion", "Dionae is a Forsworn kyrian located at the Small Shrine in Bastion. She is harassing Stewart." },
  ["dire shaman"] = { 2, "', "Dire Shaman are furbolgs located in the Grizzly Hills in the Emerald Nightmare." },
  ["direbrook inquisitor"] = { 2, "venthyr", "Direbrook Inquisitor is a venthyr." },
  ["direclaw"] = { 2, "furbolg", "Direclaw is a furbolg." },
  ["dirt-speaker barrul"] = { 2, "quilboar", "Dirt-Speaker Barrul is a quilboar who can be encountered on Island Expeditions." },
  ["dirtscour digger"] = { 2, "', "Dirtscour Diggers are kobolds located in the Ghoststone Diggings in Siren Isle." },
  ["dirty daryl"] = { 2, "murloc located at Margoss's Retreat in Dalaran", "Dirty Daryl is a murloc located at Margoss's Retreat in Dalaran. It is currently unknown if he survived Dalaran's destruction." },
  ["dirty rat (liberation of undermine)"] = { 2, "', "Dirty Rats are kobolds located in the Tower of Spades in the Liberation of Undermine. Two groups of them stand before Mug'Zee, who proceeds to kill them all." },
  ["discerning patron"] = { 2, "Veiled Market in K'aresh", "Discerning Patrons are brokers located in Tazavesh, the Veiled Market in K'aresh." },
  ["disciple fotima"] = { 2, "kyrian located in the Temple of Purity in Bastion", "Disciple Fotima is a kyrian located in the Temple of Purity in Bastion. She was killed during the Forsworn uprising." },
  ["disciple helene"] = { 2, "Ascended located at the Temple of Purity in the Bastion", "Disciple Helene is an Ascended located at the Temple of Purity in the Bastion. She helps aspirants to let go of their past attachment and can be seen helping Acolyte Galistos just before the Forsworn attacked the Temple of Purity." },
  ["disciple kimonas"] = { 2, "kyrian quest giver located in Gorgoa: River of Souls in t...", "Disciple Kimonas is a kyrian quest giver located in Gorgoa: River of Souls in the Maw." },
  ["disciple kosmas"] = { 2, "number of people in the temple looking for purification h...", "Disciple Kosmas is one of the Ascended kyrian serving in the Temple of Purity as a disciple. After the anima drought caused by the breaking of the Arbiter, the number of people in the temple looking for purification had grown in number, stretching..." },
  ["disciple lykaste"] = { 2, "Ascended kyrian located in Bastion", "Disciple Lykaste is an Ascended kyrian located in Bastion. Lykaste could be seen in the Temple of Purity helping kyrian aspirants go through cleansing rituals where they let go of past memories holding them back." },
  ["disciple of blood"] = { 2, "', "The Disciples of Blood are the most inactive of the disciples in the Ebon Hold. Unlike the Disciples of Frost who fight Undead or the Disciples of the Unholy who witness Lady Alistra destroy undead, they merely listen to a speech given by Lord Tho..." },
  ["disciple of courage"] = { 2, "', "Disciples of Courage are Ascended kyrian located in Bastion." },
  ["disciple of frost"] = { 2, "', "Disciples of Frost are death knights who follow the teachings of the Frost. Currently, Arch-lich Amal'thazad heads the cult which is embraced by the Knights of the Ebon Blade and has established itself within Acherus: The Ebon Hold." },
  ["disciple of jade"] = { 2, "', "Disciples of Jade are mogu located in the Tomb of Conquerors in Kun-Lai Summit during  [15-35] The Monkey King." },
  ["disciple of purity"] = { 2, "', "Disciples of Purity are kyrian located in Purity's Reflection, Temple of Purity, and the Eternal Forge in Bastion." },
  ["disciple of sar'this"] = { 2, "arakkoa found with Sar'this at Lake Jorune in Terokkar Fo...", "The Disciple of Sar'this is an arakkoa found with Sar'this at Lake Jorune in Terokkar Forest." },
  ["disciple of wisdom"] = { 2, "', "Disciples of Wisdom are kyrian located at the Path of Wisdom in Bastion." },
  ["disciple of the unholy"] = { 2, "', "The Disciples of the Unholy learn from Lady Alistra as she summons in and kills undead and (in rare cases) druids. Every so often she will summon in three ghouls whom she will promptly kill with  [Death and Decay]." },
  ["discordant attendant"] = { 2, "', "Discordant Attendants are nerubians located in Ara-Kara, City of Echoes. They are dead and being feasted on by Ravenous Crawlers and Engorged Crawlers." },
  ["discreet facilitator"] = { 2, "', "Discreet Facilitators are brokers located in Oribos." },
  ["dismayed citizen"] = { 2, "', "Dismayed Citizens are Horde members located in Orgrimmar during the last stage of the Horde War Campaign." },
  ["disobedient citizen"] = { 2, "', "Disobedient Citizens are venthyr located in Revendreth." },
  ["dispatcher raluca"] = { 2, "venthyr located in Revendreth", "Dispatcher Raluca is a venthyr located in Revendreth." },
  ["displaced citizen"] = { 2, "', "Displaced Citizens are draenei located in the Sha'tari Market District in Talador." },
  ["displaced gilnean refugee"] = { 2, "', "Displaced Gilnean Refugees were humans and worgen located around Stormwind City often seen with Darnassian Refugees and Stormwind City Clerks. They were refugees from the War of the Thorns." },
  ["displaced rogue"] = { 2, "', "Displaced Rogues are located in the Fissure in Dornogal. Displaced from the Dalaran Sewers, some are seen gambling, while another is sitting in a pile of trash with a Giant Sewer Rat and a Tiny Sewer Rat." },
  ["dissenter fervormyt"] = { 2, "Arathi located in The Dawnbreaker in Hallowfall", "Dissenter Fervormyt is an Arathi located in The Dawnbreaker in Hallowfall." },
  ["dissenter fortfervor"] = { 2, "Arathi located in The Dawnbreaker in Hallowfall", "Dissenter Fortfervor is an Arathi located in The Dawnbreaker in Hallowfall." },
  ["dissenter glaivefur"] = { 2, "Arathi located in The Dawnbreaker in Hallowfall", "Dissenter Glaivefur is an Arathi located in The Dawnbreaker in Hallowfall." },
  ["dissenter oathland"] = { 2, "Arathi located in Rak-Zakaz in Azj-Kahet", "Dissenter Oathland is an Arathi located in Rak-Zakaz in Azj-Kahet." },
  ["dissenter tailtrek"] = { 2, "Arathi located in Azj-Kahet", "Dissenter Tailtrek is an Arathi located in Azj-Kahet." },
  ["dissenter troosilver"] = { 2, "Arathi located in Hallowfall", "Dissenter Troosilver is an Arathi located in Hallowfall." },
  ["distracted scholar"] = { 2, "', "Distracted Scholars are dragons, dracthyr, and humans located in Thaldraszus. One of them has a flying squirrel named Chips." },
  ["distributor au'bic"] = { 2, "broker located in the Hall of Shapes in Oribos", "Distributor Au'bic is a broker located in the Hall of Shapes in Oribos." },
  ["distributor au'burk"] = { 2, "broker located in the Hall of Shapes in Oribos", "Distributor Au'burk is a broker located in the Hall of Shapes in Oribos." },
  ["distributor au'kharn"] = { 2, "broker located in the Hall of Shapes in Oribos", "Distributor Au'kharn is a broker located in the Hall of Shapes in Oribos." },
  ["distributor au'naci"] = { 2, "broker located in the Hall of Shapes in Oribos", "Distributor Au'naci is a broker located in the Hall of Shapes in Oribos." },
  ["distributor au'nagl"] = { 2, "broker located in the Hall of Shapes in Oribos", "Distributor Au'nagl is a broker located in the Hall of Shapes in Oribos." },
  ["distributor au'resh"] = { 2, "broker located in the Hall of Shapes in Oribos", "Distributor Au'resh is a broker located in the Hall of Shapes in Oribos." },
  ["distributor au'sha"] = { 2, "broker located in the Hall of Shapes in Oribos", "Distributor Au'sha is a broker located in the Hall of Shapes in Oribos." },
  ["distributor au'tem"] = { 2, "broker located in the Hall of Shapes in Oribos", "Distributor Au'tem is a broker located in the Hall of Shapes in Oribos." },
  ["distributor au'til"] = { 2, "broker located in the Hall of Shapes in Oribos", "Distributor Au'til is a broker located in the Hall of Shapes in Oribos." },
  ["distributor au'van"] = { 2, "broker located in the Hall of Shapes in Oribos", "Distributor Au'van is a broker located in the Hall of Shapes in Oribos." },
  ["district aristocrat"] = { 2, "', "District Aristocrats are venthyr located in Revendreth." },
  ["disturbed tracker"] = { 2, "', "Disturbed Trackers are vrykul located in Stormheim." },
  ["distyia"] = { 2, "black dragon", "Distyia was a black dragon who the red dragon Veritistrasz loved and called a friend. After the black dragonflight succumbed to the corruption of the Old Gods, Veritistrasz recalled to adventurers listening to his story the horror he felt when he ..." },
  ["diu'mik"] = { 2, "nerubian located in Siegehold in Azj-Kahet", "Diu'mik is a nerubian located in Siegehold in Azj-Kahet." },
  ["diving chakram spinner"] = { 2, "', "Diving Chakram Spinners are arakkoa located in Lower Quarter in Skyreach." },
  ["divinius"] = { 2, "draenei paladin", "Divinius is a draenei paladin and a prominent member of the elite Light's Chosen. Prophet Velen is often seen to deliver orders directly to Divinius herself, implying her seniority among her comrades." },
  ["diya"] = { 2, "draenei archaeology trainer found in the Vault of Lights ...", "Diya is a draenei archaeology trainer found in the Vault of Lights in the Exodar. This section concerns content related to Legion." },
  ["dizdemona"] = { 2, "gnome warlock", "Who would believe fel magic could hide behind such a face? Dizdemona is a gnome warlock, who once attacked Onyxia in her lair." },
  ["dizzy dina"] = { 2, "gnome located at Toshley's Station in the Blade's Edge Mo...", "Dizzy Dina is a gnome located at Toshley's Station in the Blade's Edge Mountains. As part of the Roughriders, Dina and the others were hired on to accompany Toshley from Azeroth to Outland." },
  ["djaradin commander"] = { 2, "djaradin located on the Defiant Ramparts in Aberrus", "Djaradin Commander is a djaradin located on the Defiant Ramparts in Aberrus, the Shadowed Crucible." },
  ["djaradin crustshaper"] = { 2, "', "Djaradin Crustshapers are djaradin located in the Waking Shores." },
  ["djaradin dragonhunter"] = { 2, "Shadowed Crucible", "Djaradin Dragonhunters are djaradin located in Aberrus, the Shadowed Crucible." },
  ["djaradin flametamer"] = { 2, "', "Djaradin Flametamers are djaradin located in Obsidian Citadel in the Waking Shores." },
  ["djaradin lavamancer"] = { 2, "Shadowed Crucible", "Djaradin Lavamancer are djaradin located in Aberrus, the Shadowed Crucible." },
  ["djaradin magmashaper"] = { 2, "Shadowed Crucible", "Djaradin Magmashaper are djaradin located in Aberrus, the Shadowed Crucible." },
  ["djaradin magmathrower"] = { 2, "', "Djaradin Magmathrowers are djaradin located in Obsidian Citadel in the Waking Shores." },
  ["djaradin prisoner"] = { 2, "', "Djaradin Prisoners are caged djaradin located at the Obsidian Throne in the Waking Shores." },
  ["djaradin skullcrusher"] = { 2, "Shadowed Crucible", "Djaradin Skullcrushers are djaradin located in Aberrus, the Shadowed Crucible." },
  ["djaradin wallclimber"] = { 2, "Shadowed Crucible", "Djaradin Wallclimbers are djaradin located in Aberrus, the Shadowed Crucible." },
  ["djaradin warrior"] = { 2, "', "Djaradin Warriors are djaradin located in the Ohn'ahran Plains." },
  ["do'gol"] = { 2, "ogre quest giver located in Brackenwall Village in Dustwa...", "Do'gol is an ogre quest giver located in Brackenwall Village in Dustwallow Marsh." },
  ["doba"] = { 2, "Broken cooking vendor located at Orebor Harborage in Zang...", "Doba is a Broken cooking vendor located at Orebor Harborage in Zangarmarsh. Requires Neutral reputation with the Kurenai before he speaks with you." },
  ["dock enforcer"] = { 2, "Veiled Market", "Dock Enforcers are brokers located at Tazavesh, the Veiled Market." },
  ["dockey kaang (rumble)"] = { 2, "unique ranged ground unit", "Dockey Kaang is a unique ranged ground unit. It is used during the Dockmaster mission." },
  ["dockmaster appleby"] = { 2, "human", "Dockmaster Appleby is a human who would have been located by the docks in the Ruins of the Scarlet Enclave in the Eastern Plaguelands." },
  ["doctor draxlegauge"] = { 2, "gnome quest giver located in Faldir's Cove in the Arathi ...", "Doctor Draxlegauge is a gnome quest giver located in Faldir's Cove in the Arathi Highlands." },
  ["doctor gutrick"] = { 2, "', "Doctor Gutrick is found at Invasion Point: Cataclysm in Shadowmoon Valley." },
  ["doctor hivvil"] = { 2, "mad scientist of the House of Constructs located inside a...", "Doctor Hivvil is a mad scientist of the House of Constructs located inside a ziggurat in the Separation Chamber in Maldraxxus." },
  ["doctor ickus"] = { 2, "second boss of the Plaguefall", "Doctor Ickus is the second boss of the Plaguefall." },
  ["doctor kohler"] = { 2, "cultist responsible for raising The Black Knight into und...", "Doctor Kohler is the cultist responsible for raising The Black Knight into undeath after his defeat in  [25-30] The Black Knight's Fall. Players are directed to Kohler on his ledge at Deathspeaker's Watch during the quest  [25-30] The Black Knight..." },
  ["doctor maleficus"] = { 2, "', "Doctor Maleficus is located at Invasion Point: Cataclysm in Shadowmoon Valley." },
  ["doctor razorgrin"] = { 2, "undead located at Talramas in the Borean Tundra", "Doctor Razorgrin is an undead located at Talramas in the Borean Tundra." },
  ["doctor sabnok"] = { 2, "mad scientist located at the Fleshwerks in Icecrown", "Doctor Sabnok is a mad scientist located at the Fleshwerks in Icecrown. He created 'Patches'." },
  ["doctor theolen krastinov"] = { 2, "rare elite human found in Butcher's Sanctum of Scholomance", "Doctor Theolen Krastinov is a rare elite human found in Butcher's Sanctum of Scholomance. He has a slight chance to spawn after killing Rattlegore." },
  ["dogan"] = { 2, "earthen located in the Forgegrounds in Dornogal", "Dogan is an earthen located in the Forgegrounds in Dornogal." },
  ["dogmatic forgecaster"] = { 2, "', "Dogmatic Forgecasters are earthen located in the Earthenworks in the Ringing Deeps." },
  ["dogmatic soot-seer"] = { 2, "', "Dogmatic Soot-Seers are earthen located at the Earthenworks in the Ringing Deeps." },
  ["dojan firecrown"] = { 2, "emperor of the mogu", "Dojan Firecrown was an emperor of the mogu. When the saurok guards began to plunder the very people they were supposed to police Emperor Dojan responded in the traditional mogu way: the souls were ripped from every living saurok in the Vale of Ete..." },
  ["dojani dominator"] = { 2, "', "Dojani Dominators are mogu located at the Ruins of Dojan in Krasarang Wilds." },
  ["dojani enforcer"] = { 2, "', "Dojani Enforcers are mogu of Dojani clan located at Krasarang Wilds." },
  ["dojani ranger"] = { 2, "mogu", "Dojani Ranger is a mogu." },
  ["dojani reclaimer"] = { 2, "', "Dojani Reclaimers are mogu located at the Ruins of Dojan in the Krasarang Wilds. One is found dead north of the ruins, being devoured by a Canopy Screecher." },
  ["dojani surveyor"] = { 2, "', "Dojani Surveyors are mogu located in the Ruins of Dojan in the Krasarang Wilds." },
  ["dokani bloodbinder"] = { 2, "', "Dokani Bloodbinders are mogu located in Kun-Lai Summit." },
  ["dokani bloodshaper"] = { 2, "', "Dokani Bloodshapers are mogu located in the Vale of Eternal Blossoms." },
  ["dokani shadewalker"] = { 2, "', "Dokani Shadewalkers are mogu located in the Vale of Eternal Blossoms." },
  ["dokani shadowblade"] = { 2, "', "Dokani Shadowblades are mogu located in Kun-Lai Summit." },
  ["dokhan"] = { 2, "earthen located in the Forgegrounds in Dornogal", "Dokhan is an earthen located in the Forgegrounds in Dornogal." },
  ["dokhusek"] = { 2, "centaur leatherworking trainer", "Dokhusek is a centaur leatherworking trainer and vendor located at Pinewood Post in the Ohn'ahran Plains." },
  ["dokin farplain"] = { 2, "tauren located in Thunder Bluff", "Dokin Farplain is a tauren located in Thunder Bluff." },
  ["dokkuldormu"] = { 2, "', "Dokkuldormu was among the dragons taken hostage by the djaradin in Harrowsdeep as part of Iridikron's gambit to prevent Neltharion and the Aspects from collapsing the subterranean labyrinth." },
  ["dolena"] = { 2, "Arathi located in the Growling Hollow in Hallowfall", "Dolena is an Arathi located in the Growling Hollow in Hallowfall." },
  ["dolkin craghelm"] = { 2, "dwarf mail armor vendor located at the Military Ward with...", "Dolkin Craghelm is a dwarf mail armor vendor located at the Military Ward within Ironforge. He is one of the owners of Craghelm's Plate and Chain." },
  ["dolores"] = { 2, "Arathi located in Mereldar in Hallowfall", "Dolores is an Arathi located in Mereldar in Hallowfall. She, Alfred, and Chay are observing Arathi Reserves." },
  ["dolph blastus"] = { 2, "goblin quest giver located in Fuselight in the Badlands", "Dolph Blastus is a goblin quest giver located in Fuselight in the Badlands. He first greets players arriving in Fuselight before asking them to kill Dustbelcher ogres at Camp Kosh." },
  ["dolruu"] = { 2, "draenei", "Dolruu is a draenei." },
  ["domeel"] = { 2, "husband of the elderly innkeeper of Bradensbrook", "Domeel is the husband of the elderly innkeeper of Bradensbrook, Eliyah. According to Eliyah, they spent many years wandering until Domeel decided he wanted to settle." },
  ["domina"] = { 2, "elite Forsaken boss found in the Pool of Ask'ar of Blackf...", "Domina is an elite Forsaken boss found in the Pool of Ask'ar of Blackfathom Deeps." },
  ["dominance dreadblade"] = { 2, "', "Dominance Dreadblades are venthyr located in Dominance Keep in Revendreth. Some are disguised Dreadlord Infiltrators." },
  ["dominance soulbender"] = { 2, "', "Dominance Soulbenders are venthyr located at Dominance Keep in Revendreth. Some are disguised Dreadlord Infiltrators." },
  ["dominated citizen"] = { 2, "', "Dominated Citizens are venthyr located in Revendreth." },
  ["domination point elite"] = { 2, "', "Domination Point Elites are orcs, tauren jungle trolls, and pandaren located at Domination Point Graveyard, Domination Point Tower, and Blacksand Oilfield in the Krasarang Wilds." },
  ["domination point paladin"] = { 2, "tauren located in Domination Point in Krasarang Wilds", "Domination Point Paladin is a tauren located in Domination Point in Krasarang Wilds." },
  ["dominic"] = { 2, "undead rogue", "Dominic was an undead rogue who was infiltrating the Scarlet Monastery during the Cataclysm. He could be found in the Library, Armory, and Cathedral wings of the Monastery." },
  ["dominic kandor"] = { 2, "', "Template:War of the Elements TCG" },
  ["dominika the illusionist"] = { 2, "draenei mage serving as a Challenge Card encounter in the...", "Dominika the Illusionist is a draenei mage serving as a Challenge Card encounter in the Brawler's Guild during The War Within. To fight Dominika, purchase  [Challenge Card: Dominika] after reaching Rank 8 with the guild." },
  ["don adams (npc)"] = { 2, "human located in the basement of the Kelp Club in Hook Po...", "Don Adams is a human located in the basement of the Kelp Club in Hook Point in Boralus." },
  ["don alvarado"] = { 2, "human located at Deliverance Point on the Broken Shore wh...", "Don Alvarado is a human located at Deliverance Point on the Broken Shore where he can be found playing Hearthstone with Jasper Fel. This section concerns content related to Battle for Azeroth." },
  ["donna anthony"] = { 2, "skinning trainer found inside Adele Fielder's house in El...", "Donna Anthony was a skinning trainer found inside Adele Fielder's house in Elwynn Forest during the World of Warcraft beta. She was ultimately replaced by Helene Peltskinner." },
  ["donni anthania"] = { 2, "human vendor", "Donni Anthania, the Crazy Cat Lady, is a human vendor who sells house cat companions, located in a house between Northshire Valley, Goldshire, and Stormwind City in Elwynn Forest. She invites her cats to tea parties and plans to have a bombay buri..." },
  ["doofus"] = { 2, "member Creedy's gang of bounty hunters", "Doofus was a member Creedy's gang of bounty hunters. He was killed by Hemet Nesingwary when the bounty hunters where hunting three frostsaber cubs, that Hemet was protecting." },
  ["doomblood"] = { 2, "gnoll located in the Azure Span", "Doomblood is a gnoll located in the Azure Span." },
  ["doomsayer (legion)"] = { 2, "', "For the Elemental Unrest versions, see Doomsayer (Alliance) and Doomsayer (Horde). For those appearing because of Argus, see Validated Doomsayer." },
  ["doomspark starsworn"] = { 2, "', "Doomspark Starsworn are satyrs located in Hinterlands during Nightmare Incursions." },
  ["dor'garad"] = { 2, "nerubian found at various locations in Azj-Kahet while ai...", "Dor'garad is a nerubian found at various locations in Azj-Kahet while aiding the Vizier. Talking to him will spawn several Dig Spots nearby." },
  ["dorbund"] = { 2, "earthen located in the Glimmering Shore on the Isle of Dorn", "Dorbund is an earthen located in the Glimmering Shore on the Isle of Dorn." },
  ["dorfus alphamage"] = { 2, "dwarf located under the Violet Hold in the Underbelly", "Dorfus Alphamage is a dwarf located under the Violet Hold in the Underbelly. He can provide directions to various locations in the Underbelly." },
  ["dorgly"] = { 2, "murloc located at the Winterfin Retreat in the Borean Tundra", "Dorgly is a murloc located at the Winterfin Retreat in the Borean Tundra." },
  ["dorgrub the cruel"] = { 2, "Frostcrag drogbar found inside a cave at the Highmountain...", "Dorgrub the Cruel is a Frostcrag drogbar found inside a cave at the Highmountain Summit in Highmountain." },
  ["dorian"] = { 2, "venthyr located in Revendreth", "Dorian is a venthyr located in Revendreth." },
  ["dorj"] = { 2, "tortollan located at the Seekers' Expedition in Zuldazar", "Dorj is a tortollan located at the Seekers' Expedition in Zuldazar. He guards the expedition grounds against troublemakers together with Korj." },
  ["dormant vrykul"] = { 2, "', "Dormant Vrykul are vrykul sleeping in the Waking Halls beneath Gjalerbron in the Howling Fjord." },
  ["dorn"] = { 2, "tauren druid", "Dorn is a tauren druid that appears on the following World of Warcraft: Trading Card Game cards. Drums of War #179 - Lifemender Dorn Assault on Icecrown Citadel #71 - Lifemender Dorn Class Starter 2011: Horde Shaman #17 - Lifemender Dorn Blood o..." },
  ["dornaa"] = { 2, "draenei child", "Dornaa, the Draenei Orphan, is a draenei child whom Alliance characters can summon using the  [Draenei Orphan Whistle] during Children's Week. Her Horde counterpart is Salandria." },
  ["dorni"] = { 2, "draenei general goods vendor located at Altar of Sha'tar ...", "Dorni is a draenei general goods vendor located at Altar of Sha'tar in Shadowmoon Valley." },
  ["dornogal archivist"] = { 2, "', "Dornogal Archivists are earthen Archivists located in the Archive, Alliance Embassy, and Horde Embassy in Dornogal." },
  ["dornogal citizen"] = { 2, "', "Dornogal Citizens are earthen located in Dornogal." },
  ["dornogal citizen (isle of dorn)"] = { 2, "', "Dornogal Citizens are earthen located in Crossroads Plaza on the Isle of Dorn." },
  ["dornogal foreman"] = { 2, "earthen located in Dornogal", "Dornogal Foreman is an earthen located in Dornogal." },
  ["dornogal patron"] = { 2, "', "Dornogal Patrons are earthen located in Dornogal." },
  ["dornogal preserver"] = { 2, "', "Dornogal Preservers are earthen located at Thraegar Rest in Dornogal." },
  ["dornogal steward"] = { 2, "earthen located in Dornogal", "The Dornogal Steward is an earthen located in Dornogal, that assists with decorating the city." },
  ["dorogg"] = { 2, "drogbar located in Zaralek Cavern", "Dorogg is a drogbar located in Zaralek Cavern." },
  ["dorthar"] = { 2, "centaur", "Dorthar is a centaur who, after being abandoned by his kind after the Cataclysm, helped the Garad'kra defeat Aratas and his centaur army. Dorthar went on to join the Horde himself, the first of his race to do so." },
  ["dorus"] = { 2, "Lordaeronian noble", "Dorus was a Lordaeronian noble and the father of Turalyon. He and his wife died when Turalyon was an infant, leaving Turalyon to be raised by the Church of the Holy Light." },
  ["doruun"] = { 2, "draenei found at Deathweb Hollow in Talador alongside Ankaa", "Doruun is a draenei found at Deathweb Hollow in Talador alongside Ankaa, Isaari, and Mardaar. They are trapped inside Deathweb Cocoons." },
  ["dot bindermine"] = { 2, "goblin kaja'mite expert located at the Village in the Vin...", "Dot Bindermine is a goblin kaja'mite expert located at the Village in the Vines in Zuldazar." },
  ["doubtful acolyte"] = { 2, "', "Doubtful Acolytes are kyrian located at Path of Wisdom in Bastion." },
  ["dougan"] = { 2, "human paladin", "Dougan is a human paladin who fought with Kardan and Voldana during the Second War in battling the Horde. In the aftermath of the war, he settled near Grand Hamlet with his wife Adena and his twin baby girls: Loania and Lieren." },
  ["doventhal the chosen"] = { 2, "an ogre in disguise of a black drake located in a cave at...", "Doventhal the Chosen is a an ogre in disguise of a black drake located in a cave at the Smoldering Perch in the Waking Shores. He is one of the rotating 'leaders' for the Worldbreakers, alongside Aizir the Inflamed and Vyzos the Prophet, who are s..." },
  ["dowser bigspark"] = { 2, "gnome located at the Lunarfall in Shadowmoon Valley", "Dowser Bigspark is a gnome located at the Lunarfall in Shadowmoon Valley. She can only be recruited by buying her contract." },
  ["dozara"] = { 2, "centaur located in Mountainview Post in the Ohn'ahran Plains", "Dozara is a centaur located in Mountainview Post in the Ohn'ahran Plains." },
  ["dozing laborer"] = { 2, "Veiled Market", "Dozing Laborers are brokers located at Tazavesh, the Veiled Market." },
  ["dr. boom"] = { 2, "former protégé of Lead Sapper Blastfizzle at Area 52", "Dr. Boom is the former protégé of Lead Sapper Blastfizzle at Area 52." },
  ["dr. boom (anniversary)"] = { 2, "', "Dr. Boom is one of Whizbang's minions summoned from an Ominous Portal during Hearthstone's 10th Anniversary at the event locations in Valdrakken, Stormwind City, and Durotar." },
  ["dr. hieronymus blam"] = { 2, "gnome located at Agmond's End in the Badlands", "Dr. Hieronymus Blam is a gnome located at Agmond's End in the Badlands." },
  ["dr. terrible"] = { 2, "mad scientist in the Underhalls in Icecrown", "Dr. Terrible was a mad scientist in the Underhalls in Icecrown, more specific in the Hall of Horrors." },
  ["dr. whitherlimb"] = { 2, "rare mob Scourge mad scientist found in the Ghostlands", "Dr. Whitherlimb is a rare mob Scourge mad scientist found in the Ghostlands." },
  ["dra'zish"] = { 2, "dracthyr located in the Pitch in Algeth'ar Academy", "Dra'zish is a dracthyr located in the Pitch in Algeth'ar Academy." },
  ["draakon"] = { 2, "draenei located in Emberwatch in the Ohn'ahran Plains", "Draakon is a draenei located in Emberwatch in the Ohn'ahran Plains." },
  ["draakorium peacekeeper"] = { 2, "', "Draakorium Peacekeepers are draenei located in the Draakorium in Shadowmoon Valley. Some of them are riding elekks." },
  ["draakorum fey-guardian"] = { 2, "', "Draakorum[sic] Fey-Guardians are draenei located in the Draakorium in Shadowmoon Valley. Some of them are carrying buckets." },
  ["dracos"] = { 2, "individual", "Dracos is an individual who sponsored the Queen Mae during the Speedbarge Boat Race." },
  ["dracthyr belayer"] = { 2, "', "Dracthyr Belayers are dracthyr located in Orgrimmar and in Stormwind Harbor in Stormwind City." },
  ["dracthyr commando"] = { 2, "dracthyr", "Dracthyr Commando is a dracthyr." },
  ["dracthyr duskpriest"] = { 2, "', "Dracthyr Duskpriests are dracthyr located in Orgrimmar and Stormwind City." },
  ["dracthyr evoker"] = { 2, "', "Dracthyr Evokers are dracthyr located on top of the Gates of Orgrimmar in Orgrimmar, being trained by Kodethi, on the zeppelin tower at the Dranosh'ar Blockade in Durotar. They are also atop the Stockade and at Stormwind Harbor, being trained by D..." },
  ["dracthyr freshscale"] = { 2, "', "Dracthyr Freshscales are dracthyr located at Algeth'ar Academy in Thaldraszus." },
  ["dracthyr mender"] = { 2, "', "Dracthyr Menders are dracthyr located in the Forbidden Reach." },
  ["dracthyr occultist"] = { 2, "', "Dracthyr Occultists are dracthyr located in the Trade District and Mage Quarter of Stormwind City and the Gates of Orgrimmar and Valley of Strength of Orgrimmar." },
  ["dracthyr pilgrim"] = { 2, "', "Dracthyr Pilgrims are dracthyr located at Gelikyr Post in Thaldraszus. They are sleeping upstairs in the inn." },
  ["dracthyr scout"] = { 2, "', "Dracthyr Scouts are dracthyr located in the Forbidden Reach." },
  ["dracthyr shikari"] = { 2, "', "Dracthyr Shikari are dracthyr located in Orgrimmar and Stormwind City." },
  ["dracthyr smith"] = { 2, "', "Dracthyr Smiths are dracthyr located with Thaelin Darkanvil in the Dwarven District and Stormwind Harbor in Stormwind City during  [10-70] Expeditionary Coordination." },
  ["dracthyr soldier"] = { 2, "', "Dracthyr Soldiers were dracthyr located on the Defiant Dragonscale in Durotar. They were replaced by Expedition Escorts." },
  ["dracthyr stalker"] = { 2, "', "Dracthyr Stalkers are dracthyr located on towers near Magic Quarter and Old Town in Stormwind City and in Orgrimmar Skyway overlooking the Valley of Wisdom and near the Valley of Honor in Orgrimmar." },
  ["dracthyr stoneclaw"] = { 2, "', "Dracthyr Stoneclaw are dracthyr located in the Forbidden Reach." },
  ["dracthyr talon"] = { 2, "', "Dracthyr Talons are dracthyr located in Earth-Warder's Cauldron in the Forbidden Reach." },
  ["dracthyr thaumaturge"] = { 2, "dracthyr located in Wizard's Sanctum in Stormwind City", "Dracthyr Thaumaturge is a dracthyr located in Wizard's Sanctum in Stormwind City and throughout Orgrimmar." },
  ["dracthyr tinkerer"] = { 2, "dracthyr located in the Drag in Orgrimmar", "Dracthyr Tinkerer is a dracthyr located in the Drag in Orgrimmar." },
  ["dracthyr warrior"] = { 2, "', "Dracthyr Warriors are dracthyr located in Orgrimmar and Stormwind City." },
  ["draenei anchorite"] = { 2, "draenei priest", "Draenei Anchorite is a draenei priest that along with two Draenei Vindicators, is trying to cleanse the Pools of Aggonar of the corruption that inhabits it. Ryathen the Somber wants it stopped, as he doesn't want to lose his supply of felblood." },
  ["draenei anchorite (legion)"] = { 2, "', "Draenei Anchorites are draenei priests located in the Netherlight Temple, Dalaran, and later in Deliverance Point on the Broken Shore and ultimately on the Vindicaar." },
  ["draenei artificer"] = { 2, "', "Draenei Artificers are draenei located in Azure Watch of Azuremyst Isle." },
  ["draenei caretaker"] = { 2, "draenei supervising two Draenei Children in the Lightforg...", "The Draenei Caretaker is a draenei supervising two Draenei Children in the Lightforged draenei starting area version of the Vindicaar." },
  ["draenei cartographer"] = { 2, "dead draenei found on Bloodmyst Isle", "Draenei Cartographer is a dead draenei found on Bloodmyst Isle." },
  ["draenei child"] = { 2, "', "Draenei Children are draenei children located at the Steam Pools in Feralas." },
  ["draenei child (exodar)"] = { 2, "draenei located in the Trader's Tier in the Exodar before...", "Draenei Child is a draenei located in the Trader's Tier in the Exodar before the Tishamaat and is observing Tamed Marsuul. During the celebration, many more children can be found about." },
  ["draenei child (feast of winter veil)"] = { 2, "', "Draenei Children are draenei children that have been kidnapped and imprisoned by Grumpus and his Grumplings. They can be found in cages around Grumpus' lair in Frostfire Ridge during the Feast of Winter Veil." },
  ["draenei child (talador)"] = { 2, "', "Draenei Children are draenei found running around in groups in Shattrath City in Talador." },
  ["draenei child (vindicaar)"] = { 2, "', "Draenei Children are draenei children located aboard the Vindicaar. They are supervised by the Draenei Caretaker." },
  ["draenei coliseum spectator"] = { 2, "', "Draenei Coliseum Spectators are draenei located in the Trial of the Champion and the Trial of the Crusader." },
  ["draenei commoner"] = { 2, "', "Draenei Commoners are draenei found at the Exodar during any of the seasonal events. They can also be found in Violet Rise on the Isle of Thunder." },
  ["draenei delegate"] = { 2, "', "The Draenei Delegates are draenei located at Valiance Keep in the Borean Tundra." },
  ["draenei earthworker"] = { 2, "', "Draenei Earthworkers are draenei located at the Iron Docks in Gorgrond." },
  ["draenei grand anchorite"] = { 2, "', "Draenei Grand Anchorites are draenei priests located in Netherlight Temple. They later appeared in Deliverance Point on the Broken Shore." },
  ["draenei mother"] = { 2, "listed title of a caged draenei seen on Draenor", "Draenei Mother is the listed title of a caged draenei seen on Draenor, imprisoned along with numerous others to serve as fuel for the opening of the Great Gate. As Garona walked past her cage, she reached out and grabbed the half-orc's arm, pleadi..." },
  ["draenei mourner"] = { 2, "mourning draenei next to the Crash Site in Ammen Vale on ...", "Draenei Mourner is a mourning draenei next to the Crash Site in Ammen Vale on Azuremyst Isle." },
  ["draenei paladin"] = { 2, "', "Draenei Paladins are draenei located in Battlescar Valley in the Stonetalon Mountains." },
  ["draenei paladin (mission mob)"] = { 2, "', "Draenei Paladins were draenei located in Frostfire Ridge and Talador. They were taken out by the followers sent from the Frostwall garrison." },
  ["draenei pilgrim"] = { 2, "', "Draenei Pilgrims are draenei located in Anchorite's Sojourn in Talador." },
  ["draenei pilgrim (terokkar forest)"] = { 2, "', "Draenei Pilgrims are draenei located at the entrance to the Auchenai Crypts in Terokkar Forest." },
  ["draenei prisoner (hellfire peninsula)"] = { 2, "', "The Draenei Prisoner can be found in Falcon Watch of Hellfire Peninsula. He's being held as a test subject by Apothecary Azethen." },
  ["draenei prisoner (shadowmoon valley)"] = { 2, "', "Draenei Prisoners are draenei located in Anguish Fortress in Shadowmoon Valley." },
  ["draenei protector"] = { 2, "', "Draenei Protectors are found guarding Anchorite Avuun at the Harborage of Swamp of Sorrows prior to the outpost being Alliance-only. Despite being hostile to Horde, they would not attack unprovoked." },
  ["draenei quartermaster"] = { 2, "draenei", "The Draenei Quartermaster is a draenei who supplies equipment for the artificers who are building the new settlement at Forest Song in Ashenvale." },
  ["draenei reveler"] = { 2, "', "Draenei Revelers are draenei located outside the Exodar and Moonglade during the Lunar Festival. They also appear at the Exodar and Azuremyst Isle during the New Year and Midsummer Fire Festival firework events." },
  ["draenei shaman"] = { 2, "draenei located in Talador", "Draenei Shaman was a draenei located in Talador. He was taken out by the followers sent from the Frostwall garrison." },
  ["draenei slave"] = { 2, "', "Draenei Slaves are draenei located in Frostfire Ridge. Some of them are in cages." },
  ["draenei soul"] = { 2, "', "Draenei Souls are wraiths, draenei, and wisps." },
  ["draenei survivor"] = { 2, "', "Draenei Survivors were thrown from the ship as the Exodar crashed onto Azuremyst Isle. They are scattered all around Ammen Vale, wounded and badly affected by the radiation from the power crystals of the wrecked ship." },
  ["draenei vindicator"] = { 2, "', "Two Draenei Vindicators along with a Draenei Anchorite are trying to cleanse the Pools of Aggonar in Hellfire Peninsula of the corruption that inhabits it. Ryathen the Somber wants it stopped, as he doesn't want to lose his supply of felblood." },
  ["draenei youngling"] = { 2, "', "Draenei Younglings are draenei located on Azuremyst Isle. They spawn in one of four spawn areas, and wander around." },
  ["draenic ally"] = { 2, "', "Draenic Allies are draenei projections located in Aspirant's Crucible in Bastion during  [10-53] A Life of Service." },
  ["draenor adventurer"] = { 2, "', "Draenor Adventurers are goblins, orcs, blood elves, and jungle trolls located in Orgrimmar and humans, worgen, and gnomes located in Stormwind City." },
  ["dragnet"] = { 2, "kobold located in Campalot in the Ringing Deeps", "Dragnet is a kobold located in Campalot in the Ringing Deeps." },
  ["drago"] = { 2, "venthyr vendor located at the Absolution Crypt in Revendreth", "Drago is a venthyr vendor located at the Absolution Crypt in Revendreth. He is currently inaccessible as he is stuck inside a wall." },
  ["dragon isles adventurer"] = { 2, "', "Dragon Isles Adventurers are dracthyr and pandaren traveling to or from the Dragon Isles by using the portal found in Pathfinder's Den of Orgrimmar and Wizard's Sanctum of Stormwind City." },
  ["dragon rider trainee"] = { 2, "', "Dragon Rider Trainees are draenei located in the Draakorium in Shadowmoon Valley." },
  ["dragon soultaur"] = { 2, "tauren located in Stormwind City", "The Dragon Soultaur is a tauren located in Stormwind City and Orgrimmar." },
  ["dragonbane cauldron keeper"] = { 2, "', "Dragonbane Cauldron Keepers are djaradin located in Dragonbane Keep in the Waking Shores." },
  ["dragonbane earth warden"] = { 2, "', "Dragonbane Earth Wardens are djaradin located in Dragonbane Keep in the Waking Shores." },
  ["dragonbane firebinder"] = { 2, "', "Dragonbane Firebinders are djaradin located in Dragonbane Keep in the Waking Shores." },
  ["dragonbane mender"] = { 2, "', "Dragonbane Menders are djaradin located in Dragonbane Keep in the Waking Shores." },
  ["dragonbane protector"] = { 2, "', "Dragonbane Protectors are djaradin located in the Waking Shores." },
  ["dragonbane shieldcracker"] = { 2, "', "Dragonbane Shieldcrackers are djaradin located in Dragonbane Keep in the Waking Shores." },
  ["dragonbane soldier"] = { 2, "', "Dragonbane Soldiers are djaradin located in Dragonbane Keep in the Waking Shores." },
  ["dragonbane wingshredder"] = { 2, "', "Dragonbane Wingshredders are djaradin located in the Waking Shores." },
