  ["dragonflayer huscarl"] = { 2, "', "Dragonflayer Huscarls are vrykul located in Voldrune in the Grizzly Hills." },
  ["dragonflayer invader"] = { 2, "', "Dragonflayer Invaders are a group of vrykul of the Dragonflayer Clan that constantly attack Valgarde from the north. They come with their Dragonflayer Worgs." },
  ["dragonflayer ironhelm"] = { 2, "', "Dragonflayer Ironhelms are vrykul located in Utgarde Keep." },
  ["dragonflayer lieutenant"] = { 2, "vrykul of the Dragonflayer clan mounted on a proto-dragon...", "The Dragonflayer Lieutenant is a vrykul of the Dragonflayer clan mounted on a proto-dragon in the center of Wyrmskull Village. Although unique, he is not really needed for anything and does not hit too hard." },
