  ["dragonflayer vrykul prisoner"] = { 2, "vrykul located in the cells underneath Westguard Keep in ...", "Don't get too close - it explodes. The Dragonflayer Vrykul Prisoner is a vrykul located in the cells underneath Westguard Keep in the Howling Fjord." },
  ["dragonflayer warrior"] = { 2, "', "Dragonflayer Warriors are vrykul located in Nifflevar in the Howling Fjord." },
  ["dragonflayer weaponsmith"] = { 2, "', "Dragonflayer Weaponsmiths are vrykul located in Utgarde Keep." },
  ["dragonflayer worker"] = { 2, "', "Dragonflayer Workers are vrykul seen from Tyr's Terrace in Utgarde Keep." },
  ["dragonhunter gorund"] = { 2, "djaradin located in the Azure Span", "Dragonhunter Gorund is a djaradin located in the Azure Span." },
  ["dragonhunter igordan"] = { 2, "djaradin located in Scalecracker Keep in the Waking Shores", "Dragonhunter Igordan is a djaradin located in Scalecracker Keep in the Waking Shores." },
  ["dragonscale excavator"] = { 2, "draenei located in Emberwatch in the Ohn'ahran Plains", "Dragonscale Excavator is a draenei located in Emberwatch in the Ohn'ahran Plains." },
  ["dragonscale expedition explorer"] = { 2, "', "Dragonscale Expedition Explorers are located in Tyrhold Reservoir in Thaldraszus during Time Rifts." },
  ["dragost"] = { 2, "venthyr located in the Purloined Stores in Castle Nathria", "Dragost is a venthyr located in the Purloined Stores in Castle Nathria." },
  ["drained operative"] = { 2, "', "Drained Operatives are dead brokers located in the Echoing Caverns in the Maw. They have been killed by Runemaster Mavrok who is found draining their essences." },
  ["draketamer rulfgar"] = { 2, "vrykul", "Draketamer Rulfgar is a vrykul that was taken out by the Dreamgrove champions when they came to rescue Talza and his scouts." },
  ["dralad"] = { 2, "adventurous orange proto-dragon", "Dralad was an adventurous orange proto-dragon. He was the brother of Alexstrasza and Ysera, and the three of them were the only survivors of their clutch." },
  ["drampert avirex"] = { 2, "Arathi mining trainer located in Mereldar in Hallowfall", "Drampert Avirex is an Arathi mining trainer located in Mereldar in Hallowfall." },
  ["drandus the deathcaller"] = { 2, "Blood Elf Death Knight", "Drandus the Deathcaller is a Blood Elf Death Knight that appears on the following World of Warcraft: Trading Card Game cards. Scourgewar #171 - Drandus the Deathcaller Class Starter 2011: Horde Death Knight #15 - Drandus the Deathcaller Class St..." },
  ["dranh"] = { 2, "tauren skinning trainer located in Camp Taurajo in the Ba...", "Dranh was a tauren skinning trainer located in Camp Taurajo in the Barrens. This section concerns content related to Cataclysm." },
  ["drawzle keen eye"] = { 2, "furbolg", "Drawzle Keen Eye is a furbolg who was to be located in the Blackroot Village." },
  ["drayl"] = { 2, "tauren", "Drayl was a tauren who was found on the Hunter Rise in Thunder Bluff during the original beta. He was a tracking trainer." },
  ["dread admiral eliza"] = { 2, "undead pirate", "Dread Admiral Eliza Goreblade was an undead pirate and the wielder of the Dreadblades, a pair of cursed cutlasses created by the demon Talgath which corrupted her and her crew of Bloodsail Buccaneers, transforming them into the Dread Fleet: bloodt..." },
  ["dread siphonist"] = { 2, "', "Honored Siphonists are venthyr located in the Menagerie of the Master in Revendreth during  [60] The Master of Lies." },
  ["dreadcoil myrmidon"] = { 2, "', "Dreadcoil Myrmidons are naga located at Atal'Gral in Zuldazar." },
  ["dreadcoil seeker"] = { 2, "', "Dreadcoil Seekers are naga located at Atal'Gral and the Scavenger's Strand in Zuldazar." },
  ["dreadcoil spitespeaker"] = { 2, "', "Dreadcoil Spitespeakers are naga located at the Sundered Temple in Zuldazar." },
  ["dreadful huntmaster"] = { 2, "', "Dreadful Huntmasters are venthyr located in Sanguine Depths." },
  ["dreadmaul ambusher"] = { 2, "', "Dreadmaul Ambushers are ogres found at Dreadmaul Hold in Blasted Lands." },
  ["dreadmaul brute"] = { 2, "', "Dreadmaul Brutes are ogres found at Dreadmaul Hold in Blasted Lands." },
  ["dreadmaul captive"] = { 2, "', "Dreadmaul Captives are the former residents of Dreadmaul Hold in the Blasted Lands, that were captured and enslaved when the Horde took control of the fortress. They have been put to work, with various mansions, inside the Hold." },
  ["dreadmaul crusher"] = { 2, "', "Dreadmaul Crushers are ogres found at Dreadmaul Post in Blasted Lands." },
  ["dreadmaul destroyer"] = { 2, "', "Dreadmaul Destroyers are ogres found at Dreadmaul Post in Blasted Lands." },
  ["dreadmaul mauler"] = { 2, "', "Dreadmaul Maulers are ogres found at Dreadmaul Post in Blasted Lands." },
  ["dreadmaul ogre"] = { 2, "', "Dreadmaul Ogres are ogres found at Dreadmaul Hold in Blasted Lands." },
  ["dreadmaul packmaster"] = { 2, "', "Dreadmaul Packmasters are ogres found at Dreadmaul Post in the Blasted Lands. Each is followed by two Snickerfang Pups." },
  ["dreadpaw"] = { 2, "tauren druid", "Dreadpaw is a tauren druid that is a part of the Uber Town group. He can be briefly seen during the flashback of the confrontation with Illidan Stormrage atop the Black Temple as well as during the fall of Deathwing in the Maelstrom." },
  ["dream watcher"] = { 2, "Dream's Hope", "Dream Watchers are ethereals located throughout Amirdrassil, the Dream's Hope." },
  ["dreambound druid"] = { 2, "', "Dreambound Druids are druids located in the Emerald Dream after it was cleansed from the Emerald Nightmare standing next to Cenarius." },
  ["dreambreaker stonewarden"] = { 2, "', "Dreambreaker Stonewardens are tauren and jungle trolls located at the Scorching Chasm in the Emerald Dream. Some can be swayed to side with Vyranoth during the quest  [10-80] Primalist Directive." },
  ["dreamfire betrayer"] = { 2, "', "Dreamfire Betrayers are satyrs located in Satyrnaar in Ashenvale during Nightmare Incursions." },
  ["dreamfire hellcaller"] = { 2, "', "Dreamfire Hellcallers are satyrs located in Satyrnaar in Ashenvale during Nightmare Incursions." },
  ["dreaming guardian"] = { 2, "', "Dreaming Guardians are druids located in Tel'Andu Barrow Den in the Dreamgrove, and later in Deliverance Point on the Broken Shore." },
  ["dreamwalker"] = { 2, "mount wolf", "The great black wolf Dreamwalker was the mount wolf and companion of Mother Kashur. Though Kashur used Dreamwalker as a mount and she was old and decrepit, she vowed to keep walking to Oshu'gun for as long as she could walk." },
  ["dredhunter damien"] = { 2, "venthyr located at the Banewood in Revendreth", "Dredhunter Damien is a venthyr located at the Banewood in Revendreth. Along with Wingsmash and two Muckborn Craftsmen he plans to make the nearby Dredterror Ballista operational again, with the goal of taking down Harika the Horrid." },
  ["dredhunter eileena"] = { 2, "venthyr located at the Banewood in Revendreth near Dredhu...", "Dredhunter Eileena is a venthyr located at the Banewood in Revendreth near Dredhunter Damien in the structure with a fire. A Muckborn Craftsman dredger accompanies her." },
  ["dreghood brute"] = { 2, "', "Dreghood Brutes are Broken located at the Sha'naari Wastes and the Ruins of Sha'naar in the Hellfire Peninsula. When a nearby Illidari Taskmaster is killed, they turn into Fleeing Dreghood Warriors." },
  ["dreghood drudge"] = { 2, "', "Dreghood Drudges are Broken found at the Darkcrest Enclave and Darkcrest Shore in Zangarmarsh. Upon aggroing nearby Darkcrest Slavers or Darkcrest Taskmasters, these Broken will be called upon to assist." },
  ["dreghood geomancer"] = { 2, "', "Dreghood Geomancers are Broken located at the Sha'naari Wastes and the Ruins of Sha'naar in the Hellfire Peninsula. After a nearby Illidari Taskmaster is killed, they turn into Fleeing Dreghood Geomancers." },
  ["dreghood slave"] = { 2, "', "Dreghood Slaves can be found in the Steamvault. These creatures will come to the aid of nearby Coilfang Slavemasters." },
  ["dreghood wanderer"] = { 2, "Broken", "Dreghood Wanderer is a Broken." },
  ["drekirjar felblade"] = { 2, "', "Drekirjar Felblades are vrykul located in Stormheim." },
  ["drekirjar galeborn"] = { 2, "', "Drekirjar Galeborns are vrykul located in Hrydshal in Stormheim. In the past, they were led by Hakkap One-leg." },
  ["drekirjar shieldbearer"] = { 2, "', "Drekirjar Shieldbearers are vrykul located in Stormheim." },
  ["drelda"] = { 2, "earthen flight master located in Durgaz Cabin on the Isle...", "Drelda is an earthen flight master located in Durgaz Cabin on the Isle of Dorn." },
  ["drelik blastpipe"] = { 2, "goblin vendor of Season 4 items", "For the Season 4 vendor in the Scryer's Tier see Drolig Blastpipe. Drolig Blastpipe is a goblin vendor of Season 4 items." },
  ["dremm"] = { 2, "draenei skinning trainer", "Dremm is a draenei skinning trainer and vendor located on Aldor Rise in Shattrath City." },
  ["dresaelus"] = { 2, "kyrian commemorated in the Ancient Memorial in Bastion wh...", "Dresaelus is a kyrian commemorated in the Ancient Memorial in Bastion which blesses anyone who touches it. He invented single use glider." },
  ["dresh-khevan"] = { 2, "', "The sinstone of Dresh-Khevan, who was once known as Khevan al Retaresh, is found within the southwestern courtyard of the Court of the Harvesters in Revendreth." },
  ["drewdil brewerson"] = { 2, "dwarf located at Hops", "Drewdil Brewerson is a dwarf located at Hops, Line, & Sinker Brewing in Boralus." },
  ["driaan"] = { 2, "draenei jewelcrafting trainer", "Driaan is a draenei jewelcrafting trainer." },
  ["drijya"] = { 2, "ethereal quest giver located south of Eco-Dome Midrealm i...", "Drijya is an ethereal quest giver located south of Eco-Dome Midrealm in the Netherstorm." },
  ["drill sergeant bahduum"] = { 2, "draenei located at the Shattered Sun Staging Area on the ...", "Drill Sergeant Bahduum is a draenei located at the Shattered Sun Staging Area on the Isle of Quel'Danas." },
  ["drim"] = { 2, "broker innkeeper", "Drim is a broker innkeeper and vendor located at Pilgrim's Grace in Zereth Mortis." },
  ["dripear the waxy"] = { 2, "kobold located in the Hall of the Candle King in Darkflam...", "Dripear the Waxy is a kobold located in the Hall of the Candle King in Darkflame Cleft. He caries  [The Candle Keys] needed to open the nearby Discarded Loot." },
  ["drippy tadpole"] = { 2, "', "Drippy Tadpoles are murlocs hatched from Incubated Eggs in the Tomb of Sargeras." },
  ["drithen the boisterous"] = { 2, "vrykul located in the Great Mead Hall in Skyhold during  ...", "Drithen the Boisterous is a vrykul located in the Great Mead Hall in Skyhold during  [60] A Hate-Hate Relationship. He is seen facing off against Halfdan Sly-Stalker, encircled by many Valarjar Aspirants." },
  ["driving gale-caller"] = { 2, "', "Driving Gale-Callers are high arakkoa located in Skyreach." },
  ["drix bassbolter"] = { 2, "goblin found at Frostwall", "Drix Bassbolter is a goblin found at Frostwall. He is standing next to the B.O.O.M Box." },
  ["drix blackwrench"] = { 2, "Reins of the Traveler's Tundra Mammoth#Horde", "Drix Blackwrench is one of two Horde vendors that come preloaded with a three person mammoth mount, the Reins of the Traveler's Tundra Mammoth#Horde. He can repair as well as sell reagents and poisons." },
  ["drizle"] = { 2, "furbolg quest giver located in Felwood", "Drizle is a furbolg quest giver located in Felwood. He is first seen with his companion Ferli trying to convince adventurers to gather honey from inside the Totem of Ruumbo." },
  ["dro seminario"] = { 2, "undead located in the Cauldron of Rock in Darkmoon Island", "Dro Seminario is an undead located in the Cauldron of Rock in Darkmoon Island." },
  ["drog almighty"] = { 2, "drogbar", "Drog Almighty was a drogbar that attacked the Highmountain tauren of Snowblind Mesa in Highmountain along with a stampede of drogbar. He was killed by the Order of the Broken Temple in exchange for shelter from the tauren." },
  ["drogbar (npc)"] = { 2, "', "Drogbar are drogbar located in the faraway areas of upper Neltharion's Lair as well as in the Dragon's Spine. Approaching them knocks the player back." },
  ["drogbar (mission mob)"] = { 2, "', "A stampede of Drogbar was located in Highmountain and was taken out by the monk champions of the Order of the Broken Temple." },
  ["drogbar manathirster"] = { 2, "', "Drogbar Manathirsters are drogbar located in Lifespring Cavern in Highmountain. They summon Blistering Geodes." },
  ["drogbar rivertroller"] = { 2, "', "Drogbar Rivertrollers are drogbar located in Whitewater Wash in Highmountain." },
  ["drogbar trader"] = { 2, "vision of a drogbar located in Highmountain", "Drogbar Trader is a vision of a drogbar located in Highmountain. He appears upon interacting with the Ancient Spirit Drum." },
  ["drogbar wormhook"] = { 2, "', "Drogbar Wormhooks are drogbar located in Whitewater Wash in Highmountain." },
  ["drogrin alewhisker"] = { 2, "dwarf located at Thovas Base-Camp in Tiragarde Sound", "Drogrin Alewhisker is a dwarf located at Thovas Base-Camp in Tiragarde Sound." },
  ["droha"] = { 2, "draenei shaman trainer found in the Temple of the Moon in...", "Droha is a draenei shaman trainer found in the Temple of the Moon in Darnassus, next to Elissa Dumas and Rukua, busy in some kind of conversation with them. It is unknown whether he survived the Burning of Teldrassil or not." },
  ["droha (shattrath)"] = { 2, "draenei Guild Master found in the Terrace of Light in Sha...", "Droha is a draenei Guild Master found in the Terrace of Light in Shattrath City, next to Riha and Linsa." },
  ["drokar"] = { 2, "earthen fishing trainer located with Hinodin at the Keepe...", "Drokar is an earthen fishing trainer located with Hinodin at the Keepers Terrace in Dornogal." },
  ["drolfy"] = { 2, "gnome vendor located inside the inn (on the stairs betwee...", "Drolfy is a gnome vendor located inside the inn (on the stairs between the first and second floor) in Wintergarde Keep in the Dragonblight. He is one of the inhabitants of Wintergarde Village saved by the player during  [15-30] Flight of the Winte..." },
  ["drolig blastpipe"] = { 2, "goblin vendor of Season 4 items", "Drolig Blastpipe is a goblin vendor of Season 4 items. He is located in the Scryer's Tier in Shattrath City." },
  ["drone keeper ak'thet"] = { 2, "mantid located in Vale of Eternal Blossoms", "Drone Keeper Ak'thet is a mantid located in Vale of Eternal Blossoms." },
  ["drowned crewman"] = { 2, "', "Drowned Crewmen are undead located on a shipwrecked ship on the bottom of the Forgotten Cove in Stormsong Valley." },
  ["drowned defias"] = { 2, "', "Drowned Defias are dead humans, worgen, blood elves located in the Vision of Stormwind." },
  ["drowning crewman"] = { 2, "', "Drowning Crewmen are humans, dwarves, and gnomes located in Kelp'thar Forest." },
  ["drowning kyrian"] = { 2, "', "Drowning Kyrian are kyrian located in the Maw." },
  ["drugan deepdraught"] = { 2, "dwarf located at the Quel'Delar's Rest in Icecrown", "Drugan Deepdraught is a dwarf located at the Quel'Delar's Rest in Icecrown. Since the Cataclysm, Prospector Drugan is located at the Gol'Bolar Quarry in Dun Morogh." },
  ["druid of the branch (broken shore)"] = { 2, "', "Druids of the Branch are restoration druids located at Deliverance Point on the Broken Shore." },
  ["druid of the claw (broken shore)"] = { 2, "', "Druids of the Claw are night elf located in Broken Shore." },
  ["druid of the claw (moonglade)"] = { 2, "[[tauren]", "Druid of the Claw is a [[tauren],] night elf, or worgen located in Moonglade." },
  ["druid of the talon (cataclysm)"] = { 2, "', "Druids of the Talon are tauren and night elves located in the Shrine of Aviana in Mount Hyjal and the Molten Front. Several assist Thisalee Crow at Sethria's Roost in securing Aviana's Egg and killing Sethria." },
  ["druid of the talon (highmountain)"] = { 2, "', "Druids of the Talon are tauren and night elf members of the Druids of the Talon found at the Sylvan Falls in Highmountain." },
  ["druid of the talon (lunarfall)"] = { 2, "', "Druids of the Talon are tauren and night elves located in a cave in Lunarfall." },
  ["druids of the claw (dreamgrove)"] = { 2, "', "Druids of the Claw are night elf, tauren, and worgen druids who briefly appear in the Dreamgrove. After being recruited, they run out of the area and despawn." },
  ["drunk tank patron"] = { 2, "tortollan located in the Drunk Tank in Drustvar", "The Drunk Tank Patron is a tortollan located in the Drunk Tank in Drustvar." },
  ["drunken bileslinger"] = { 2, "', "Drunken Bileslingers are ogres found in the stands of the Coliseum during the Kargath Bladefist encounter in Highmaul." },
  ["drunken scrapper"] = { 2, "', "Drunken Scrappers are ogres found at and immediately south of the Gorian Proving Grounds in Nagrand." },
  ["drust aberration"] = { 2, "Drust located in Ardenweald", "Drust Aberration is a Drust located in Ardenweald." },
  ["drust behemoth"] = { 2, "Drust located in Gol Inath in Drustvar during  [60] Into ...", "Drust Behemoth is a Drust located in Gol Inath in Drustvar during  [60] Into the Flame." },
