  ["drust deathshaper"] = { 2, "Drust", "Drust Deathshaper is a Drust." },
  ["drust evoker"] = { 2, "', "Drust Evokers are Drust skeletons located at Gol Osigr in Drustvar." },
  ["drust harvester"] = { 2, "', "Drust Harvesters are Drust located in the Oaken Assembly in the Mists of Tirna Scithe." },
  ["drust lurker"] = { 2, "', "Drust Lurkers are Drust located in Darkreach in Ardenweald." },
  ["drust manifestation"] = { 2, "Drust ghost located in Drustvar", "Drust Manifestation is a Drust ghost located in Drustvar." },
  ["drust mindreaver"] = { 2, "', "Drust Mindreavers are Drust located in Blackthorn Grove in Ardenweald." },
  ["drust shadowflayer"] = { 2, "', "Drust Shadowflayers are Drust located in Darkreach in Ardenweald." },
