  ["drustfallen reaver"] = { 2, "', "Drustfallen Reavers are Drust located in Darkreach in Ardenweald." },
  ["drysc (npc)"] = { 2, "draenei shaman student wandering in the Crystal Hall in t...", "Drysc is a draenei shaman student wandering in the Crystal Hall in the Exodar, along with fellow student Sayari and their teacher Chakaa." },
  ["drywax dredger"] = { 2, "', "Drywax Dredgers are kobolds." },
  ["drywax laborer"] = { 2, "', "Drywax Laborers are kobolds." },
  ["drywhisker digger"] = { 2, "', "Drywhisker Diggers are kobolds located in the Arathi Highlands." },
  ["drywhisker kobold"] = { 2, "', "Drywhisker Kobolds are kobolds located in Drywhisker Gorge in the Arathi Highlands." },
  ["drywhisker surveyor"] = { 2, "', "Drywhisker Surveyors are kobolds located in the Arathi Highlands." },
  ["du shan"] = { 2, "mogu located in the Shado-Pan Showdown", "Du Shan is a mogu located in the Shado-Pan Showdown. He is fighting, for the purple team, against Ja Sara of the gold team." },
  ["dubin clay"] = { 2, "dwarf located in the Magus Commerce Exchange of Dalaran", "Dubin Clay is a dwarf located in the Magus Commerce Exchange of Dalaran. Accoring to Imindril Spearsong, he is stubborn." },
  ["dubra'jin (god)"] = { 2, "', "Dubra'jin is one of the forgotten gods of Zul'Drak. The Zandalari in Zul'Drak have an outpost near his statue, having established an outpost of the same name providing them with protection from the Drakkari in exchange for many Gundrak Raptor Eggs." },
  ["duchess catina"] = { 2, "venthyr located in Revendreth", "Duchess Catina is a venthyr located in Revendreth." },
  ["duchess fallensong the frigid"] = { 2, "Darkfallen death knight located in Arom's Stand in Drustv...", "Duchess Fallensong the Frigid is a Darkfallen death knight located in Arom's Stand in Drustvar during the Faction Assaults." },
  ["duchess ileana"] = { 2, "venthyr located in the Redelav District in Revendreth", "Duchess Ileana is a venthyr located in the Redelav District in Revendreth. She can be found talking with Sir Luca." },
  ["duchess ioana"] = { 2, "venthyr located in Revendreth", "Duchess Ioana is a venthyr located in Revendreth." },
  ["duchess lacrima"] = { 2, "venthyr located in the Grand Pallisade", "Duchess Lacrima is a venthyr located in the Grand Pallisade and at the Briarbane Stables in Revendreth. She may also appear in the Eternal Terrace." },
  ["duchess leona"] = { 2, "venthyr located in the Redelav Hall in Revendreth", "Duchess Leona is a venthyr located in the Redelav Hall in Revendreth." },
  ["duchess minodora"] = { 2, "venthyr located in the Primrose Residence in Revendreth", "Duchess Minodora is a venthyr located in the Primrose Residence in Revendreth." },
  ["duchess mynx"] = { 2, "quartermaster of the Knights of the Ebon Blade", "Duchess Mynx is the quartermaster of the Knights of the Ebon Blade and is located in the Shadow Vault in Icecrown. She can only be accessed after the Shadow Vault is controlled by the Knights of the Ebon Blade following completion of  [25-30] The ..." },
  ["duchess nathalie"] = { 2, "venthyr located in Redelav Tower in Revendreth", "Duchess Nathalie is a venthyr located in Redelav Tower in Revendreth." },
  ["duchess odeta"] = { 2, "venthyr located in the Eternal Terrace in Revendreth", "Duchess Odeta is a venthyr located in the Eternal Terrace in Revendreth." },
  ["duchess rodica"] = { 2, "venthyr located at the Briarbane Stables in Revendreth", "Duchess Rodica is a venthyr located at the Briarbane Stables in Revendreth. She can be found talking with Duke Avram." },
  ["duchess silviana"] = { 2, "venthyr located in the Redelav Hall in Revendreth", "Duchess Silviana is a venthyr located in the Redelav Hall in Revendreth." },
  ["duchess vanda"] = { 2, "venthyr located in the Redelav District in Revendreth", "Duchess Vanda is a venthyr located in the Redelav District in Revendreth. She can be found outside the Sourwine Estate." },
  ["duchess yetta"] = { 2, "venthyr located in the Duskmire Domain in Revendreth", "Duchess Yetta is a venthyr located in the Duskmire Domain in Revendreth." },
  ["dudebrul"] = { 2, "drogbar wandering around the Stonedark Grotto in Highmoun...", "Dudebrul is a drogbar wandering around the Stonedark Grotto in Highmountain with his right fist up. Adventurers can 'fist bump' him to receive the 1-hour 'Fist Bumped' buff, the description of which reads: 'Fist bumped a brul." },
  ["duelist (npc)"] = { 2, "', "Duelists are rogues located in the Hall of Shadows." },
  ["duelist okoro"] = { 2, "deceased ankoan buried north of Newhome in Nazjatar", "Duelist Okoro is a deceased ankoan buried north of Newhome in Nazjatar." },
  ["duelist xaheen"] = { 2, "ethereal located in North Sufaad on K'aresh", "Duelist Xaheen is an ethereal located in North Sufaad on K'aresh." },
  ["duelmaster rowyn"] = { 2, "venthyr located at Dominance Gate in Revendreth", "Duelmaster Rowyn is a venthyr located at Dominance Gate in Revendreth." },
  ["dug digger"] = { 2, "Bluewax kobold found in Candle Rock in Highmountain durin...", "Dug Digger is a Bluewax kobold found in Candle Rock in Highmountain during  [10-45] Candle of Command and  [10-45] Burn the Candle at Both Ends. He claims to be the best digger in Candle Rock, but Intern Jackie says that while he's good enough, he..." },
  ["dugiru"] = { 2, "draenei quest giver located by the tailoring trainers on ...", "Dugiru was a draenei quest giver located by the tailoring trainers on the Trader's Tier in the Exodar." },
  ["dugsley deepdelver"] = { 2, "gnome engineering supplier in the Alliance section of the...", "Dugsley Deepdelver is a gnome engineering supplier in the Alliance section of the Temple of Earth in Deepholm." },
  ["duke anton"] = { 2, "venthyr located at the Briarbane Stables in Revendreth", "Duke Anton is a venthyr located at the Briarbane Stables in Revendreth." },
  ["duke avram"] = { 2, "venthyr located at the Briarbane Stables in Revendreth", "Duke Avram is a venthyr located at the Briarbane Stables in Revendreth. He can be found talking with Duchess Rodica." },
  ["duke grigore"] = { 2, "venthyr located in the Primrose Residence in Revendreth", "Duke Grigore is a venthyr located in the Primrose Residence in Revendreth. He can be found talking with Madame Relia." },
  ["duke horas"] = { 2, "venthyr located in the Ember Court", "Duke Horas is a venthyr located in the Ember Court. Though he is only seen in the instanced Ember Court, and only if The Countess is a guest, and has no quests associated with him even within the instance, he has a unique voice and shares unique v..." },
  ["duke jeremiah"] = { 2, "venthyr located in Redelav Tower in Revendreth", "Duke Jeremiah is a venthyr located in Redelav Tower in Revendreth." },
  ["duke jonatan"] = { 2, "venthyr located in Redelav Tower in Revendreth", "Duke Jonatan is a venthyr located in Redelav Tower in Revendreth." },
  ["duke kronid"] = { 2, "venthyr located in Revendreth", "Duke Kronid is a venthyr located in Revendreth." },
  ["duke mihas"] = { 2, "venthyr located in the Redelav District in Revendreth", "Duke Mihas is a venthyr located in the Redelav District in Revendreth. He can be found talking with Madame Sorina outside the Sourwine Estate." },
  ["duke mitica"] = { 2, "venthyr located in the Eternal Terrace in Revendreth", "Duke Mitica is a venthyr located in the Eternal Terrace in Revendreth." },
  ["duke omor"] = { 2, "venthyr located in the Redelav District in Revendreth", "Duke Omor is a venthyr located in the Redelav District in Revendreth. He can be found talking to Sir Vilhelm outside the Redelav Hall." },
  ["duke reginald baradin ii"] = { 2, "founder", "Duke Reginald Baradin II was the founder and leader of Baradin's Wardens. After his death, he was succeeded by Commander Marcus Johnson." },
  ["duke simion"] = { 2, "venthyr located in the Redelav District in Revendreth", "Duke Simion is a venthyr located in the Redelav District in Revendreth. He can be found walking between the Briarbane Stables and the Darkvein Villa." },
  ["duke sithizi"] = { 2, "naga located at the Felrage Strand on the Broken Shore", "Duke Sithizi is a naga located at the Felrage Strand on the Broken Shore." },
  ["duke velhan"] = { 2, "leader of the Arathi settlement located in Velhan's Claim...", "Duke Velhan is the leader of the Arathi settlement located in Velhan's Claim in Hallowfall." },
  ["duke vielle"] = { 2, "venthyr located at the Charred Ramparts in Revendreth", "Duke Vielle is a venthyr located at the Charred Ramparts in Revendreth." },
  ["duke vlad"] = { 2, "venthyr located behind the Sinfang Parlor in the Redelav ...", "Duke Vlad is a venthyr located behind the Sinfang Parlor in the Redelav District in Revendreth. He can be found absolving an Abject Soul of its past sins, occasionally spawning various memories." },
  ["duligosa"] = { 2, "blue dragon", "Duligosa was a blue dragon who was killed by Neltharion's betrayal during the War of the Ancients. Her name is on a Faded Gravestone at the Veiled Ossuary." },
  ["dullgrom dredger"] = { 2, "', "Dullgrom Dredgers are ogres who are being controlled by the arakkoa in Trogma's Claim in the Blade's Edge Mountains." },
  ["dulox"] = { 2, "dracthyr located in the Pitch in Algeth'ar Academy", "Dulox is a dracthyr located in the Pitch in Algeth'ar Academy." },
  ["dulvi"] = { 2, "draenei mining trainer located at Azure Watch in Azuremys...", "Dulvi is a draenei mining trainer located at Azure Watch in Azuremyst Isle." },
  ["dumitra"] = { 2, "venthyr located in the Old Gate", "Dumitra is a venthyr located in the Old Gate and later inside Thornhill Manor in Revendreth." },
  ["duna"] = { 2, "draenei child located at the Embaari Village in Shadowmoo...", "Duna is a draenei child located at the Embaari Village in Shadowmoon Valley." },
  ["dunaman"] = { 2, "draenei weapon vendor located at Altar of Sha'tar in Shad...", "Dunaman is a draenei weapon vendor located at Altar of Sha'tar in Shadowmoon Valley." },
  ["dunemaul 'emissary'"] = { 2, "ogre located at the Dunemaul Recruitment Camp in Tanaris", "Dunemaul 'Emissary' is an ogre located at the Dunemaul Recruitment Camp in Tanaris. He is supposed to be the emissary for the Dunemaul clan." },
  ["dunemaul brute"] = { 2, "', "Dunemaul Brutes are ogres found at the Dunemaul Compound in Tanaris. Before the Cataclysm they could be found at the Eastmoon Ruins and Southmoon Ruins." },
  ["dunemaul enforcer"] = { 2, "', "Dunemaul Enforcers are ogres found at the Dunemaul Compound in Tanaris. Before the Cataclysm they could be found at the Eastmoon Ruins and Southmoon Ruins." },
  ["dunemaul ogre"] = { 2, "', "Dunemaul Ogres can be found in Tanaris. This section concerns content related to Legion." },
  ["dungard ironcutter"] = { 2, "spokesman for all the earthen clans gathered by Krasus to...", "Dungard Ironcutter was the spokesman for all the earthen clans gathered by Krasus to help the night elves in their fight against the Burning Legion. Dungard was later seen on the battlefield with the other members of the Kaldorei Resistance when C..." },
  ["dungeon gearataur"] = { 2, "tauren located in Dalaran on the World of Warcraft: Wrath...", "Dungeon Gearataur is a tauren located in Dalaran on the World of Warcraft: Wrath of the Lich King Classic PTR. He hands out dungeon gear for free." },
  ["dungeontaur"] = { 2, "tauren located in Stormwind City", "The Dungeontaur is a tauren located in Stormwind City and Orgrimmar." },
  ["dunkin crackjaw"] = { 2, "dwarf located on Mechagon Island", "Dunkin Crackjaw is a dwarf located on Mechagon Island." },
  ["duquan"] = { 2, "draenei located on the Darkmoon Island", "Duquan is a draenei located on the Darkmoon Island." },
  ["durael"] = { 2, "draenei located aboard the Vindicaar on Krokuun", "Durael is a draenei located aboard the Vindicaar on Krokuun. After the Lightforged draenei joined the Alliance, he became one as well." },
  ["durakh"] = { 2, "earthen located in the Forgegrounds in Dornogal", "Durakh is an earthen located in the Forgegrounds in Dornogal." },
  ["duree"] = { 2, "old human widow", "Duree was an old human widow and a secretary working for Jaina Proudmoore. She was known to wear spectacles and to frustrate her master by questioning her decisions." },
  ["durik bronzebomb"] = { 2, "', "Durik Bronzebomb supplies the Argent Crusade in Argent Vanguard with engineering supplies. This section concerns content related to Shadowlands." },
  ["durmok darkmane"] = { 2, "tauren located in Stormsong Valley", "Durmok Darkmane is a tauren located in Stormsong Valley." },
  ["durphorn the bullheaded"] = { 2, "tauren fighting Iron Horde Grunts alongside many others a...", "Durphorn the Bullheaded is a tauren fighting Iron Horde Grunts alongside many others at the Dark Portal in Blasted Lands and Tanaan Jungle. He died after the portal was destroyed." },
  ["dusk-seer irizzar"] = { 2, "outcast arakkoa located in the Spires of Arak", "Dusk-Seer Irizzar is an outcast arakkoa located in the Spires of Arak." },
  ["duskbinder zuun"] = { 2, "mogu located on the expedition isles", "Duskbinder Zuun is a mogu located on the expedition isles." },
  ["duskblaze shadowstalker"] = { 2, "', "Duskblaze Shadowstalkers are satyr located near the Dream portal in the Twilight Grove in Duskwood." },
  ["duskcaller erthix"] = { 2, "arakkoa found at the Terokkar Refuge in Talador", "Duskcaller Erthix is an arakkoa found at the Terokkar Refuge in Talador." },
  ["duskfright herald"] = { 2, "', "Duskfright Heralds are domanaar found in Nexus-Point Xenas." },
  ["duskstalker kuli"] = { 2, "troll located in Island Expeditions", "Duskstalker Kuli is a troll located in Island Expeditions." },
  ["dust (vol'dun)"] = { 2, "vulpera caravan master located in the Vulpera Hideaway in...", "Dust is a vulpera caravan master located in the Vulpera Hideaway in Vol'dun after completion of  [60] Mission Report: Vulpera Hideaway. As a reward for rescuing him from the Faithless, Horde players can speak to him to mount a very fast Vulpera Ca..." },
  ["dustbelcher brute"] = { 2, "', "Dustbelcher Brutes were ogres of the Dustbelcher group found in Camp Wurg and Camp Boff in the Badlands." },
  ["dustbelcher butcher"] = { 2, "', "Dustbelcher Butchers are Dustbelcher ogres located in the Dustbelch Grotto in the Badlands." },
  ["dustbelcher initiate"] = { 2, "', "Dustbelcher Initiates are Dustbelcher ogres located in the Badlands. They are trained by Dustbelcher Instructors." },
  ["dustbelcher lord"] = { 2, "', "Dustbelcher Lords were ogres of the Dustbelcher group. They could be found in the southwestern part of the Badlands." },
  ["dustbelcher mauler"] = { 2, "', "Dustbelcher Maulers are ogres of the Dustbelcher group located in the Badlands." },
  ["dustbelcher merchant"] = { 2, "', "Dustbelcher Merchants are Dustbelcher ogres located in Badlands." },
  ["dustbelcher mystic"] = { 2, "', "Dustbelcher Mystics were ogres of the Dustbelcher group found primarily in Camp Kosh in the Badlands, except for one mystic that follows Boss Tho'grun around. Also, mystics are shorter than the other dustbelcher ogres." },
  ["dustbelcher ogre"] = { 2, "', "Dustbelcher Ogres were ogres of the Dustbelcher group found in Camp Wurg and Camp Boff in the Badlands." },
  ["dustbelcher shaman"] = { 2, "', "Dustbelcher Shamans are ogres of the Dustbelcher group located in the Badlands." },
  ["dustbelcher trainee"] = { 2, "', "Dustbelcher Trainees are Dustbelcher ogres located in the Badlands. They are trained by Dustbelcher Instructors." },
  ["dustbelcher warrior"] = { 2, "', "Dustbelcher Warriors were ogres of the Dustbelcher group found in Camp Kosh in the Badlands." },
  ["dustbelcher wyrmhunter"] = { 2, "', "Dustbelcher Wyrmhunters were ogres of the Dustbelcher group found wandering in the Badlands." },
  ["dutiful attendant (castle nathria)"] = { 2, "', "Dutiful Attendants are venthyr located in Castle Nathria." },
  ["dutiful watcher"] = { 2, "ascended kyrian located on the Lakeshire bridge in the Re...", "Dutiful Watcher is an ascended kyrian located on the Lakeshire bridge in the Redridge Mountains." },
  ["duumehi"] = { 2, "Broken", "Duumehi is a Broken that can be found in the Crystal Hall of the Exodar; he appears to be weakened or ill: Nus is caring for him and for Ereuso, who is lying not distant from him. This section concerns content related to Legion." },
  ["duun"] = { 2, "orc warrior", "Duun was an orc warrior who fought alongside Broxigar to hold a mountain pass against the Burning Legion during the Battle of Mount Hyjal. He was beheaded by a demon, his head bouncing along the ground several seconds before his torso collapsed." },
  ["dvid skoat"] = { 2, "vrykul located in Stormheim", "Dvid Skoat is a vrykul located in Stormheim." },
  ["dwendel"] = { 2, "young redheaded gnome", "Dwendel is a young redheaded gnome who came with Gelbin Mekkatorque to the meeting in Darnassus. He is said to have a new possible weapon that may be able to fire fifty arrows in a minute." },
  ["dying captive"] = { 2, "', "Dying Captives are prisoners located in the Deadwood Landing of the Broken Shore. They are either in Legion Cages or being tortured by Vile Tormentors." },
  ["dying mage"] = { 2, "', "Dying Mages are located at Vakthros Range in the Azure Span." },
  ["dying prisoner"] = { 2, "', "Dying Prisoners are orc and draenei prisoners located in Tanaan Jungle during the Assault on the Dark Portal. They are being tortured in the Kargathar Proving Grounds." },
  ["dying rangari"] = { 2, "Rangari draenei in the Crimson Fen of Gorgrond", "The Dying Rangari is a Rangari draenei in the Crimson Fen of Gorgrond. His group was dragged into the swamps by Fungal Lurchers and most were killed." },
  ["dylan aguilar"] = { 2, "human child", "Dylan Aguilar is a human child that can be found playing with her pet Otto von Chubbs in the Stormwind City Outskirts, near a house at the southwest of the island with the portals. She's hostile to Horde players, although she obviously can't be at..." },
  ["dylan bissel"] = { 2, "dwarf", "Dylan Bissel was a dwarf who was found at Goldshire in Elwynn Forest during the original beta." },
  ["dyuna"] = { 2, "draenei located at Embaari Village in Shadowmoon Valley", "Dyuna is a draenei located at Embaari Village in Shadowmoon Valley." },
  ["e'ira"] = { 2, "naaru", "E'ira is a naaru that helped build the Exodar and designed the Crystal Hall as a calm and quiet place. There is also a mural of E'ira in the hall." },
  ["eadrik"] = { 2, "worgen", "Eadrik was a worgen that served as Genn Greymane's messenger and loyal aide. He did various tasks for Genn, such as spying on the Highborne, whom Genn didn't seem to trust due to their reputation." },
  ["eadward"] = { 2, "Arathi located in Mereldar in Hallowfall", "Eadward is an Arathi located in Mereldar in Hallowfall." },
  ["eager freshscale"] = { 2, "', "Eager Freshscales are dracthyr and dragonspawn located at Algeth'ar Academy in Thaldraszus. Some are enclosed in personalized fields, accelerating time inside, allowing for more studying." },
  ["eager trader"] = { 2, "Veiled Market", "Eager Traders are brokers located in Tazavesh, the Veiled Market." },
  ["eaglemaster niraak"] = { 2, "centaur located in the Ohn'ahran Plains", "Eaglemaster Niraak is a centaur located in the Ohn'ahran Plains." },
  ["ear-biter"] = { 2, "ogre arena battlemaster located outside the Ring of Trial...", "Ear-Biter was an ogre arena battlemaster located outside the Ring of Trials in Nagrand." },
  ["earth mother"] = { 2, "gentle", "The Earth Mother, also known as the Earthmother or Mother Earth, is a gentle, seemingly transcendent and immortal being worshiped primarily by tauren (although also acknowledged by some orc shaman, the centaur, and at least one frost nymph) as the..." },
  ["earth-speaker juwa"] = { 2, "furbolg located in Island Expedition", "Earth-Speaker Juwa is a furbolg located in Island Expedition." },
  ["earthborne charger"] = { 2, "', "Earthborne Charger are furbolgs located in the Throughway in the Zaralek Cavern." },
  ["earthbound primalist"] = { 2, "', "Earthbound Primalists are earth-infused furbolgs located the Wild Preserve in the Waking Shores. They can be seen attempting to corrupt Captured Proto-Whelps." },
  ["earthbreaker dolomite"] = { 2, "elite earthen quest giver found at Stonehearth in Deepholm", "Earthbreaker Dolomite is an elite earthen quest giver found at Stonehearth in Deepholm." },
  ["earthcaller gulgort"] = { 2, "quilboar located in the Drowned Lands in Stormsong Valley", "Earthcaller Gulgort is a quilboar located in the Drowned Lands in Stormsong Valley." },
  ["earthcaller halmgar"] = { 2, "rare mob quilboar found in Razorfen Kraul", "Earthcaller Halmgar is a rare mob quilboar found in Razorfen Kraul. Just run through the instance to find her, she is past the first wooden bridge after Overlord Ramtusk." },
  ["earthen adventurer"] = { 2, "', "Earthen Adventurers are earthen located in the Wizard's Sanctum of Stormwind City and in Pathfinder's Den in Orgrimmar." },
  ["earthen adventurer (isle of dorn)"] = { 2, "', "Earthen Adventurers are earthen located in the Proscenium on the Isle of Dorn." },
  ["earthen champion"] = { 2, "', "Earthen Champions are earthen warriors that are fighting the stone trogg invaders off at the Fractured Front in Deepholm." },
  ["earthen custodian"] = { 2, "', "Earthen Custodians are earthen found in Uldaman." },
  ["earthen custodian (uldaman: legacy of tyr)"] = { 2, "', "Earthen Custodians are earthen located in the Hall of the Keepers in Uldaman: Legacy of Tyr." },
  ["earthen denizen"] = { 2, "', "Earthen Denizens are earthen located at the Proscenium on the Isle of Dorn during  [70-73] Fire in the Hole." },
  ["earthen dwarf"] = { 2, "', "Earthen Dwarves are earthen created by the forges near Sjonnir The Ironshaper in the Halls of Stone, and aid adventurers in fighting against Sjonnir." },
  ["earthen geomancer"] = { 2, "', "Earthen Geomancers are earthen located in Stonehearth in Deepholm. They are geomancers that are occupied with sealing buildings and attacking the stone troggs." },
  ["earthen geomender"] = { 2, "', "Earthen Geomenders are earthen tending to Wounded Unbound near the Coreway in Dornogal." },
  ["earthen guardian"] = { 2, "', "Earthen Guardians are earthen found in Magni's Encampment in Silithus: The Wound, and in the Chamber of Heart. They appear to be infused with Azerite." },
  ["earthen guardian (uldaman)"] = { 2, "', "Earthen Guardians are earthen found in Uldaman." },
  ["earthen guardian (uldaman: legacy of tyr)"] = { 2, "', "Earthen Guardians are earthen located in the Earthworks in Uldaman: Legacy of Tyr." },
  ["earthen hallshaper"] = { 2, "', "Earthen Hallshapers are earthen located in Uldaman." },
  ["earthen jormungar handler"] = { 2, "', "Earthen Jormungar Handlers are earthen located in the western Snowdrift Plains in the Storm Peaks. They train jormungar into Tamed Jormungar by the use of Jormungar Control Orbs." },
  ["earthen protector"] = { 2, "', "Earthen Protectors are earthen guarding Brann Bronzebeard and his plane just outside the The Tribunal of Ages in the Halls of Stone." },
  ["earthen representative"] = { 2, "', "Earthen Representatives are earthen located in the Stormwind Embassy in Stormwind City and the Orgrimmar Embassy in Orgrimmar. The Alliance representative can be found speaking with Aysa Cloudsinger and maintaining the nearby Earthen banner." },
  ["earthen ring channeler"] = { 2, "', "Earthen Ring Channelers are Broken, Wildhammer dwarves, and orcs located in the Twilight Highlands." },
  ["earthen ring defender"] = { 2, "', "Earthen Ring Defenders are Earthen Ring agents defending the major cities. They summoned Earthen Ring Unbinding Totems." },
  ["earthen ring elder"] = { 2, "', "Earthen Ring Elders are Midsummer Fire Festival quest givers located in all capital cities. The versions in Shattrath and the Horde capitals are female jungle trolls, while the versions in Alliance capitals are male Broken." },
  ["earthen ring emissary"] = { 2, "', "Earthen Ring Emissaries were members of the Earthen Ring who appeared in all of the main cities during the Elemental Unrest." },
  ["earthen ring flamecaller"] = { 2, "Earthen Ring member located in the Slave Pens during Mids...", "Earthen Ring Flamecaller is an Earthen Ring member located in the Slave Pens during Midsummer Fire Festival." },
  ["earthen ring geomancer"] = { 2, "', "Earthen Ring Geomancers are shaman located in the Heart of Azeroth and later in Deliverance Point on the Broken Shore. This section concerns content related to Battle for Azeroth." },
  ["earthen ring shaman"] = { 2, "Firelands", "Earthen Ring Shaman are shaman of the Earthen Ring found at the Heart of Azeroth in the Maelstrom alongside other shaman heroes. Taking part in the shaman campaigns, they were present in Dalaran, Deepholm, the Firelands, and the Vortex Pinnacle." },
  ["earthen ring shaman (cataclysm)"] = { 2, "', "Earthen Ring Shaman are shaman located in Deepholm, Shimmering Expanse, and the Twilight Highlands." },
  ["earthen ring wavebinder"] = { 2, "Broken", "Two Earthen Ring Wavebinders, a Broken and a tauren, can be found at the Silver Tide Hollow in the Shimmering Expanse of Vashj'ir. They appear to be empowering a water elemental by channeling frost magic into it." },
  ["earthen rocksmasher"] = { 2, "', "Earthen Rocksmashers are earthen found outside and inside the Temple Hall in Uldaman." },
  ["earthen runeweaver"] = { 2, "', "Earthen Runeweavers are earthen located in the Wizard's Sanctum in Stormwind City and in the Pathfinder's Den in Orgrimmar. They maintain portals to Dornogal on the Isle of Dorn." },
  ["earthen sculptor"] = { 2, "', "Earthen Sculptors are earthen found outside and inside the Temple Hall in Uldaman." },
  ["earthen steward"] = { 2, "', "Earthen Stewards are earthen located in Ulduar. They are seen during  [10-45] The Diamond King, engaging in various repairs of the facility." },
  ["earthen stonebreaker"] = { 2, "', "Earthen Stonebreaker can be found in Uldaman." },
  ["earthen stonecarver"] = { 2, "', "Earthen Stonecarvers are earthen found in Uldaman." },
  ["earthen stoneguard"] = { 2, "', "Earthen Stoneguards are earthen guards located at Bouldercrag's Refuge in the Storm Peaks. Like goblin bruisers they will attack players who engage in PvP near the refuge." },
  ["earthen stonemender"] = { 2, "', "Earthen Stonemenders are earthen located near the Coreway in Dornogal. They tend to Wounded Oathsworn." },
  ["earthen stoneshaper"] = { 2, "', "Earthen Stoneshapers are earthen located in Ulduar." },
  ["earthen stormranger"] = { 2, "', "Earthen Stormrangers are members of the Stormriders located in Dornogal and in Storm's Watch on the Isle of Dorn. They later appeared on the Siren Isle." },
  ["earthen vault guard"] = { 2, "', "Earthen Vault Guards are earthen located in the Primordial Observatory near the Maelstrom during the quest   [45] The Sunken Vault." },
  ["earthen warder"] = { 2, "', "Earthen Warders are earthen located in the Terrace of the Makers in the Storm Peaks. They are fighting against Iron Sentinels and Iron Dwarf Assailants." },
  ["earthen warder (uldaman: legacy of tyr)"] = { 2, "', "Earthen Warders are earthen located in the Hall of the Keepers in Uldaman: Legacy of Tyr." },
  ["earthen warrior"] = { 2, "', "Earthen Warriors are earthen that are associated with the forces of Kurun and located in the Grizzly Hills. A Fallen Earthen Warrior in his dying breath implores adventurers to  [15-30] Find Kurun!." },
  ["earthen weaver"] = { 2, "', "Earthen Weavers are earthen located in the Earthworks in Uldaman: Legacy of Tyr." },
  ["earthenforged invader"] = { 2, "', "Earthenforged Invaders are furbolgs located in the Azure Span." },
  ["earthguard sentinel"] = { 2, "', "Earthguard Sentinels are tauren located in Deepholm. They appear during  [30-35] On Even Ground." },
  ["earthmender deepvein"] = { 2, "Earthen medic found at the Fractured Front in Deepholm", "Earthmender Deepvein is an Earthen medic found at the Fractured Front in Deepholm." },
  ["earthmender doros"] = { 2, "draenei located at the Twilight Overlook in Deepholm", "Earthmender Doros is a draenei located at the Twilight Overlook in Deepholm." },
  ["earthmender duarn"] = { 2, "tauren shaman of the Earthen Ring", "Earthmender Duarn is a tauren shaman of the Earthen Ring. He is first found in Vashj'ir, where he initially sails in with the Horde aboard the Stygian Bounty." },
  ["earthmender gorboto"] = { 2, "Broken found in Shadowmoon Valley", "Earthmender Gorboto is a Broken found in Shadowmoon Valley." },
  ["earthmender sophurus"] = { 2, "Broken shaman located at Wildhammer Stronghold in the Sha...", "Earthmender Sophurus is a Broken shaman located at Wildhammer Stronghold in the Shadowmoon Valley." },
  ["earthshaker theurgist"] = { 2, "', "Earthshaker Theurgists are tauren and jungle trolls located in Gelikyr Overlook in Thaldraszus." },
  ["earthspeaker nala"] = { 2, "Broken located at the Trade District in Stormwind City", "Earthspeaker Nala was a Broken located at the Trade District in Stormwind City." },
  ["earthwatcher shaman"] = { 2, "', "Earthwatcher Shaman are tauren, orcs, Wildhammer dwarves, and draenei located in Shimmering Expanse." },
  ["earthworker berethal"] = { 2, "draenei located at Elodor in Shadowmoon Valley", "Earthworker Berethal is a draenei located at Elodor in Shadowmoon Valley." },
  ["ebon blade acolyte"] = { 2, "', "Ebon Blade Acolytes are humans maintaining a portal to Oribos in the Wizard's Sanctum of Stormwind City and orcs in Pathfinder's Den in Orgrimmar. They also accompanied Bolvar Fordragon to Oribos and also appear in the Sanctum of Domination." },
  ["ebon blade commander"] = { 2, "', "Ebon Blade Commanders can be found guarding the Frozen Halls of Icecrown Citadel alongside Argent Commanders. This section concerns content related to Shadowlands." },
  ["ebon blade veteran"] = { 2, "', "Ebon Watch Veterans are death knights that accompany Margrave Dhakar in battling Morbidus at the Fleshwerks in Icecrown during the quest  [25-30] The Flesh Giant Champion." },
  ["ebon blade vindicator"] = { 2, "', "Ebon Watch Vindicators are death knights guarding the Shadow Vault in Icecrown. This section concerns content related to Shadowlands." },
  ["ebon knights"] = { 2, "', "Ebon Knights are human and orc death knights located at Acherus: The Ebon Hold on the Broken Shore, trained by Korgaz Deadaxe. In addition to the races above, they also appear as dwarves, night elves, blood elves, gnomes, jungle trolls, and Forsak..." },
  ["ebon ravager"] = { 2, "', "Ebon Ravagers are death knights of the Ebon Blade found at Acherus: The Ebon Hold after completing the Live by the Sword advancement." },
  ["ebon ravagers"] = { 2, "', "Ebon Ravagers are orcs and humans located at Acherus: The Ebon Hold on the Broken Shore, trained by Korgaz Deadaxe. In addition to the races above, they also appear as worgen, dwarves, Forsaken, and blood elves, serving as the troops accompanying ..." },
  ["ebon scale"] = { 2, "', "Ebon Scales are dracthyr found in the Siege Creche in the Forbidden Reach." },
  ["ebon watch guardian"] = { 2, "', "Ebon Watch Guardians are death knights guarding Ebon Watch in Zul'Drak." },
  ["ebona"] = { 2, "earthen", "Ebona is the earthen who was tended by Adelgonn in Freywold Village on the Isle of Dorn." },
  ["echo of aella"] = { 2, "Ascended kyrian located at Agthia's Repose in Bastion", "The Echo of Aella is an Ascended kyrian located at Agthia's Repose in Bastion. When defeated she will leave behind a Worthy Aspirant's Cache." },
  ["echo of archimonde"] = { 2, "', "The Echo of Archimonde appears at Kil'jaeden's Terrace in Eredath during  [45WQ] Bully Pulpit." },
  ["echo of argus (eredath)"] = { 2, "', "Echoes of Argus are echoes of eredar (children, soldiers and refugees alike) located in Eredath, forever remembering the day of the flight of the draenei. They replace the other echoes after the defenses of the arena are re-activated." },
  ["echo of arkhaan"] = { 2, "', "Echoes of Arkhaan are echoes located in Eredath appearing during  [45] Whispers from Oronaar and  [45WQ] Bully Pulpit." },
  ["echo of attenuation"] = { 2, "mantid located in the Heart of Fear", "Echo of Attenuation is a mantid located in the Heart of Fear." },
  ["echo of crystalsmith netrius"] = { 2, "echo of Netrezaar located in Kil'jaeden's Terrace in Ered...", "Echo of Crystalsmith Netrius is an echo of Netrezaar located in Kil'jaeden's Terrace in Eredath during  [45WQ] Bully Pulpit." },
  ["echo of hatuun"] = { 2, "echo located in Kil'jaeden's Terrace in Eredath during  [...", "Echo of Hatuun is an echo located in Kil'jaeden's Terrace in Eredath during  [45WQ] Bully Pulpit." },
  ["echo of kil'jaeden"] = { 2, "', "The Echo of Kil'jaeden appears at Kil'jaeden's Terrace in Eredath during  [45WQ] Bully Pulpit." },
  ["echo of maatparm"] = { 2, "', "The Echo of Maatparm appears at Kil'jaeden's Terrace in Eredath during  [45WQ] Bully Pulpit." },
  ["echo of mercia"] = { 2, "kyrian located in the Terrace of Inner Grace in Bastion", "The Echo of Mercia is a kyrian located in the Terrace of Inner Grace in Bastion. She is an echo of the first Paragon of Humility, and the mentor of Chyrus." },
  ["echo of nuuri"] = { 2, "echo of Velen's mate appearing at Kil'jaeden's Terrace in...", "The Echo of Nuuri is the echo of Velen's mate appearing at Kil'jaeden's Terrace in Eredath, with their son. She appears only during the world quest  [45WQ] Bully Pulpit." },
  ["echo of rakeesh"] = { 2, "echo located on Kil'jaeden's Terrace in Eredath during  [...", "Echo of Rakeesh is an echo located on Kil'jaeden's Terrace in Eredath during  [45WQ] Bully Pulpit alongside the Echo of Nuuri." },
  ["echo of restalaan"] = { 2, "', "The Echo of Restalaan appears at Kil'jaeden's Terrace in Eredath during  [45WQ] Bully Pulpit." },
  ["echo of talgath"] = { 2, "', "Echoes of Talgath are echoes in Eredath appearing during  [45] Flanking Maneuvers and  [45WQ] Bully Pulpit." },
  ["echo of valok"] = { 2, "', "The Echo of Valok appears at Kil'jaeden's Terrace in Eredath during  [45WQ] Bully Pulpit." },
  ["echo of velen"] = { 2, "', "The Echo of Velen appears at Kil'jaeden's Terrace in Eredath during  [45WQ] Bully Pulpit." },
  ["ecilam"] = { 2, "Alliance mage leader in Stormshield Outpost", "Ecilam is the Alliance mage leader in Stormshield Outpost, Ashran. He serves as the Mage Portal NPC for the Alliance in Ashran." },
  ["eckert"] = { 2, "gnome located at Allerian Stronghold in Terokkar Forest", "Eckert is a gnome located at Allerian Stronghold in Terokkar Forest. He describes himself as 'a skilled engineer, a brilliant inventor, the heart of any party, and the best dancer Azeroth has ever seen." },
  ["eco-dome preserver"] = { 2, "', "Eco-Dome Preservers are brokers located in Eco-Dome: Primus on K'aresh." },
  ["ecton brasstumbler"] = { 2, "goblin PvP rewards vendor located in Gadgetzan in Tanaris", "Ecton Brasstumbler was a goblin PvP rewards vendor located in Gadgetzan in Tanaris. His stock was available to both the Horde and the Alliance and included last season's gear in exchange for  [Honor Points]." },
  ["ed"] = { 2, "worgen found at the Dark Portal in the Blasted Lands", "Ed is a worgen found at the Dark Portal in the Blasted Lands and Tanaan Jungle fighting Iron Horde Grunts alongside many others at the Dark Portal. He died after the portal was destroyed." },
  ["ed floren"] = { 2, "undead death knight located at Deliverance Point in the B...", "Ed Floren is an undead death knight located at Deliverance Point in the Broken Shore." },
  ["eddie fixit"] = { 2, "gnome located at the Jeweled Coast in Stormsong Valley", "Eddie Fixit is a gnome located at the Jeweled Coast in Stormsong Valley. This section concerns content related to The War Within." },
  ["edgar balloo"] = { 2, "son of Sully", "Edgar Balloo is the son of Sully and Sara Balloo." },
  ["edgar the collector"] = { 2, "venthyr located in the Chalice District in Revendreth", "Edgar the Collector is a venthyr located in the Chalice District in Revendreth. He is holding Chip." },
  ["edgard shadeclaw"] = { 2, "worgen druid located in Darkshore during the Battle for D...", "Edgard Shadeclaw is a worgen druid located in Darkshore during the Battle for Darkshore." },
  ["edith morgan"] = { 2, "worgen located at the Central Encampment in the Emerald D...", "Edith Morgan is a worgen located at the Central Encampment in the Emerald Dream." },
  ["edmund duskrend"] = { 2, "worgen located at the Lunarfall in Shadowmoon Valley", "Edmund Duskrend is a worgen located at the Lunarfall in Shadowmoon Valley. He can only be recruited using the Headhunter's Harvest from Lunarfall Inn." },
  ["edothir"] = { 2, "earthen located in Stonelight Rest in Dornogal", "Edothir is an earthen located in Stonelight Rest in Dornogal." },
  ["edris barleybeard"] = { 2, "dwarf drink vendor located in the Military Ward in Ironforge", "Edris Barleybeard is a dwarf drink vendor located in the Military Ward in Ironforge. She works at Bruuk's Corner." },
  ["edvard"] = { 2, "venthyr located in Revendreth", "Edvard is a venthyr located in Revendreth." },
  ["edward the odd"] = { 2, "very eccentric human paladin", "Edward the Odd is a very eccentric human paladin. His nickname 'the Odd' probably stems from his abnormal sense of fashion." },
  ["edwardi"] = { 2, "venthyr located in Haven in Zereth Mortis for players in ...", "Edwardi is a venthyr located in Haven in Zereth Mortis for players in the Venthyr Covenant." },
  ["edwi copperbolt"] = { 2, "gnome found at the Bronzebeard Encampment in Silithus", "Edwi Copperbolt is a gnome found at the Bronzebeard Encampment in Silithus. He will provide  [Desert Sonar] in exchange for a  [Busted Gizmo]." },
  ["edwyn wyndsmithe"] = { 2, "Arathi located in Lightspark in Hallowfall", "Edwyn Wyndsmithe is an Arathi located in Lightspark in Hallowfall. As a student of the academy, he was aiming to become the next captain and would often talk among his peers about becoming one." },
  ["egalin"] = { 2, "first summoner of a voidwalker into Azeroth", "Egalin was the first summoner of a voidwalker into Azeroth. He detailed the process in his grimoire." },
  ["egg-tender kahasz"] = { 2, "nerubian located in Island Expeditions", "Egg-Tender Kahasz is a nerubian located in Island Expeditions." },
  ["eggtender aloron"] = { 2, "draenei located outside The Shimmer Moor in Shadowmoon Va...", "Eggtender Aloron is a draenei located outside The Shimmer Moor in Shadowmoon Valley." },
  ["egnion"] = { 2, "leader of the black dragonflight's Shadowscales", "Egnion was the leader of the black dragonflight's Shadowscales. He spent most of his time afield spying on the Primalist forces." },
  ["egrigos"] = { 2, "blue dragon", "Egrigos was a blue dragon who was killed in a magical accident. His name is on a Fresh Gravestone at the Veiled Ossuary." },
  ["eibhlin"] = { 2, "worgen located at Mear's Farm in Founder's Point", "Eibhlin is a worgen located at Mear's Farm in Founder's Point." },
  ["eidre"] = { 2, "human mage student of Dalaran", "Eidre was a human mage student of Dalaran and former fiancée of Alodi, who lived more than 2,600 years ago before the First War. Her parents owned some land by Brightwater Lake." },
  ["eiggard"] = { 2, "earthen located on the Isle of Dorn", "Eiggard is an earthen located on the Isle of Dorn." },
  ["eiin"] = { 2, "Broken tailoring vendor located at the Lower City market ...", "Eiin is a Broken tailoring vendor located at the Lower City market of the neutral Shattrath City." },
  ["eimear"] = { 2, "Queen of Ironforge", "Eimear was the Queen of Ironforge, wife of King Magni Bronzebeard and mother of Princess Moira. After Moira's birth, Magni worried that something would take their daughter away from them." },
  ["einar the runecaster"] = { 2, "vrykul of the Valarjar located in the Skyhold", "Einar the Runecaster is a vrykul of the Valarjar located in the Skyhold. He researches the class hall." },
  ["eindride scriptyrn"] = { 2, "Arathi located in Mereldar in Hallowfall", "Eindride Scriptyrn is an Arathi located in Mereldar in Hallowfall." },
  ["einris brightspear"] = { 2, "dwarf hunter trainer located in the Dwarven District with...", "Einris Brightspear is a dwarf hunter trainer located in the Dwarven District within Stormwind City." },
  ["eirana"] = { 2, "Arathi located in Flotsam Shoal on the Siren Isle", "Eirana is an Arathi located in Flotsam Shoal on the Siren Isle. She is talking to Nixx Gearkick." },
  ["eirzay"] = { 2, "nerubian found at various locations in Azj-Kahet", "Eirzay is a nerubian found at various locations in Azj-Kahet. He offers rumors that can be investigated for the Severed Threads weekly quest." },
  ["eitrigg (alternate universe)"] = { 2, "orc", "Eitrigg was an orc who dwelt on the planet of Draenor as a member of the Blackrock clan and follower of Blackhand. During his lifetime, he met with Grommash Hellscream and was considered by him an honorable orc." },
  ["eketra"] = { 2, "Mawsworn kyrian located in the Crucible of the Damned in ...", "Eketra is a Mawsworn kyrian located in the Crucible of the Damned in the Maw." },
  ["ekhi"] = { 2, "centaur leatherworking trainer", "Ekhi is a centaur leatherworking trainer and vendor located in the Ohn'ahran Plains." },
  ["elaena emberlanz"] = { 2, "Arathi located at Sanctified Grounds in the Priory of the...", "Elaena Emberlanz is an Arathi located at Sanctified Grounds in the Priory of the Sacred Flame." },
  ["elaine clayton"] = { 2, "worgen located in Bear's Head in Azshara", "Elaine Clayton is a worgen located in Bear's Head in Azshara." },
  ["elanu"] = { 2, "female night elf killed by Ralaar", "Elanu was a female night elf killed by Ralaar and Arvell while they had lost their minds to the Pack Form." },
  ["elarisiel"] = { 2, "night elf", "Elarisiel was a night elf who sought out Illidan Stormrage in Outland to fight the Burning Legion, becoming one of the first Illidari demon hunters he trained. She was wounded during the invasion of Nathreza, but was saved by Illidan and Vandel an..." },
  ["elbeg"] = { 2, "centaur located in Cloverwood Hollow in the Ohn'ahran Plains", "Elbeg is a centaur located in Cloverwood Hollow in the Ohn'ahran Plains." },
  ["elder akar'azan"] = { 2, "nerubian located in Island Expeditions", "Elder Akar'azan is a nerubian located in Island Expeditions." },
  ["elder amir"] = { 2, "broker located at Pilgrim's Grace in Zereth Mortis", "Elder Amir is a broker located at Pilgrim's Grace in Zereth Mortis." },
  ["elder artificer batos"] = { 2, "Broken located at the Exiles' Hovel at the Voidstorm", "Elder Artificer Batos is a Broken located at the Exiles' Hovel at the Voidstorm." },
  ["elder atuik"] = { 2, "chieftain of the tuskarr at Kamagua in the Howling Fjord", "Elder Atuik is the chieftain of the tuskarr at Kamagua in the Howling Fjord. One cold windy night, Elder Atuik stood in spiritual silence, remembering the storms he had witnessed within the last seven years." },
  ["elder brolg"] = { 2, "furbolg quest giver found at the Blackwood Hold in Darkshore", "Elder Brolg is a furbolg quest giver found at the Blackwood Hold in Darkshore. This section concerns content related to Battle for Azeroth." },
  ["elder bronzebeard"] = { 2, "earthen ghost located in the Mystic Ward of Ironforge", "Elder Bronzebeard is an earthen ghost located in the Mystic Ward of Ironforge." },
  ["elder brownpaw"] = { 2, "elder furbolg quest giver of the uncorrupted part of the ...", "Elder Brownpaw is an elder furbolg quest giver of the uncorrupted part of the Blackwood tribe found in central Darkshore. This section concerns content related to Battle for Azeroth." },
  ["elder clearwater"] = { 2, "tuskarr elder", "Elder Clearwater was a tuskarr elder who could be found in Dalaran during the Kalu'ak Fishing Derby. This section concerns content related to Dragonflight." },
  ["elder daftusk"] = { 2, "visitor", "Elder Daftusk is a visitor that occasionally appears in the VIP section of the Darkmoon Faire Zoo." },
  ["elder darkweaver kath"] = { 2, "arakkoa located in Dark Woods in Ashran", "Elder Darkweaver Kath is an arakkoa located in Dark Woods in Ashran." },
  ["elder eru"] = { 2, "elder of the Enlightened brokers first located in the Lex...", "Elder Eru is an elder of the Enlightened brokers first located in the Lexical Glade and then inside the Lexical Grotto in Zereth Mortis. She has dedicated herself to cataloging and organizing the First One texts stored in the area." },
  ["elder kannu"] = { 2, "tuskarr located in Kauriq Gleamlet in the Azure Span", "Elder Kannu is a tuskarr located in Kauriq Gleamlet in the Azure Span." },
  ["elder kinaa"] = { 2, "tuskarr cooking trainer located in Iskaara in the Azure Span", "Elder Kinaa is a tuskarr cooking trainer located in Iskaara in the Azure Span." },
  ["elder knythall"] = { 2, "Arathi located near the coast west of the Veneration Grou...", "Elder Knythall is an Arathi located near the coast west of the Veneration Grounds in Hallowfall during the Lunar Festival event." },
  ["elder ko'nani"] = { 2, "elder tuskarr", "Elder Ko'nani is an elder tuskarr and chieftain of the Kalu'ak found in Moa'ki Harbor in Dragonblight. Following the war against the Jailer, the brothers Bronzebeard visited Moa'ki Harbor, where they met Elder Ko'nani and asked him questions about..." },
  ["elder kreth"] = { 2, "foremost of the three elders", "Elder Kreth (formerly Executor Al'kreth) is the foremost of the three elders who lead the Enlightened brokers of Haven in Zereth Mortis. The other two are Elder Zoor and Elder Ara." },
  ["elder kuppaka"] = { 2, "tortollan quest giver located at the Tortaka Refuge in Vo...", "Elder Kuppaka is a tortollan quest giver located at the Tortaka Refuge in Vol'dun. He is the oldest and wisest member of the Tortaka tribe." },
  ["elder muahit"] = { 2, "tuskarr standing next to Hotawa in the center of the big ...", "Elder Muahit is a tuskarr standing next to Hotawa in the center of the big island in Njord's Breath Bay in the Borean Tundra." },
  ["elder murk-eye"] = { 2, "murloc located in the Lair of Harjatan in the Tomb of Sar...", "Elder Murk-Eye is a murloc located in the Lair of Harjatan in the Tomb of Sargeras. He is summoned by the  [Mrgrglhjorn] for  [Grand Fin-ale]." },
  ["elder mystic razorsnout"] = { 2, "rare quilboar found in the eastern Razormane camp at Thor...", "Elder Mystic Razorsnout is a rare quilboar found in the eastern Razormane camp at Thorn Hill in Northern Barrens. She is on a 1.5-2.5 hour respawn timer." },
  ["elder nappa"] = { 2, "tuskarr innkeeper located in the Filled Bowl in the Azure...", "Elder Nappa is a tuskarr innkeeper located in the Filled Bowl in the Azure Span." },
  ["elder nava"] = { 2, "tuskarr located in Kauriq Gleamlet in the Azure Span", "Elder Nava is a tuskarr located in Kauriq Gleamlet in the Azure Span. Her apprentice, Poko, can be found next to her." },
  ["elder nazuun"] = { 2, "centaur quest giver located outside a tent next to the ri...", "Elder Nazuun is a centaur quest giver located outside a tent next to the river in northeastern Teerakai in the Ohn'ahran Plains. She sends adventurers to learn about the revered centaur ancestors Himia, the Blessed and Rellen, The Learned." },
  ["elder nirav"] = { 2, "broker located at Pilgrim's Grace in Zereth Mortis", "Elder Nirav is a broker located at Pilgrim's Grace in Zereth Mortis." },
  ["elder oaktalon"] = { 2, "furbolg located in the Spiritpaw Backwoods in Zul'Aman", "Elder Oaktalon is a furbolg located in the Spiritpaw Backwoods in Zul'Aman." },
  ["elder odgerel"] = { 2, "centaur of Clan Teerai located at the base of the krutal ...", "Elder Odgerel is a centaur of Clan Teerai located at the base of the krutal in Maruukai in the Ohn'ahran Plains. Hunter Narman asks for her help in preparing a proposal to Windsaga Dawa." },
  ["elder ordol"] = { 2, "furbolg located in Verdant Wilds during Island Expeditions", "Elder Ordol is a furbolg located in Verdant Wilds during Island Expeditions." },
  ["elder pindlefeather"] = { 2, "high arakkoa", "Elder Pindlefeather was a high arakkoa that guarded some ancient artifacts containing untold knowledge in Spires of Arak. It was taken out by the followers sent from the garrisons." },
  ["elder poa"] = { 2, "tuskarr located in the Azure Span", "Elder Poa is a tuskarr located in the Azure Span. She initially appears in the Big Tree Hills, where the caravan she was traveling with was attacked by Shadowpaw gnolls." },
  ["elder runecarver"] = { 2, "', "Elder Runecarvers are vrykul located in Stormheim." },
  ["elder shadeweaver"] = { 2, "nerubian sage located in the Transformatory in the City o...", "Elder Shadeweaver is a nerubian sage located in the Transformatory in the City of Threads. At first, they are a regular nerubian named Honored Citizen." },
  ["elder sookh"] = { 2, "furbolg located in Val'sharah", "Elder Sookh is a furbolg located in Val'sharah. He resolved to succeed Chieftain Graw as the chieftain of his tribe." },
  ["elder swornvow"] = { 2, "Arathi located on a patch of land below Rumshackle in Hal...", "Elder Swornvow is an Arathi located on a patch of land below Rumshackle in Hallowfall during the Lunar Festival event." },
  ["elder tunipital"] = { 2, "tuskarr located in Iskaara in the Azure Span", "Elder Tunipital is a tuskarr located in Iskaara in the Azure Span." },
  ["elder unujaak"] = { 2, "tuskarr located at Uktulut Backwater in the Waking Shores", "Elder Unujaak is a tuskarr located at Uktulut Backwater in the Waking Shores." },
  ["elder yur"] = { 2, "furbolg located in the Verdant Wilds during Island Expedi...", "Elder Yur is a furbolg located in the Verdant Wilds during Island Expeditions." },
  ["elder yusa"] = { 2, "centaur working at a cooking pot in the southeastern corn...", "Elder Yusa is a centaur working at a cooking pot in the southeastern corner of Teerakai in the Ohn'ahran Plains. She is a former member of Clan Toghus, now tagged as a member of Clan Shikaar." },
  ["elder yuvari"] = { 2, "centaur quest giver of Clan Ohn'ir in southeastern Teerak...", "Elder Yuvari is a centaur quest giver of Clan Ohn'ir in southeastern Teerakai in the Ohn'ahran Plains. He sends adventurers to help Initiate Zorig to stop the Nokhud and Ukhel's efforts in the Eternal Kurgans." },
  ["elder zoor"] = { 2, "', "Elder Zoor is one of the three elders who lead the Enlightened brokers of Haven in Zereth Mortis. The other two are Elder Kreth and Elder Ara." },
  ["eldritch understudy"] = { 2, "', "Eldritch Understudies are naga located in the Eternal Palace." },
  ["electromancer ju'le"] = { 2, "mogu located on the Isle of Thunder", "Electromancer Ju'le is a mogu located on the Isle of Thunder." },
  ["elementalist avuun"] = { 2, "draenei elemental shaman", "Elementalist Avuun is a draenei elemental shaman and part of the Hodir encounter in Ulduar. He and his party of excavation team members are trapped inside icicle blocks and must be freed if the raid wants help against Hodir." },
  ["elementalist ioki"] = { 2, "Broken quest giver located at Telaar in Nagrand", "Elementalist Ioki is a Broken quest giver located at Telaar in Nagrand." },
  ["elementalist lo'ap"] = { 2, "Broken quest giver located at the Throne of the Elements ...", "Elementalist Lo'ap is a Broken quest giver located at the Throne of the Elements in Nagrand." },
  ["elementalist morgh"] = { 2, "Broken quest giver located at the Throne of the Elements ...", "Elementalist Morgh is a Broken quest giver located at the Throne of the Elements in Nagrand. He stands with three other elementalists in a small circle." },
  ["elena"] = { 2, "venthyr located in the Old Gate", "Elena is a venthyr located in the Old Gate and later inside Thornhill Manor in Revendreth." },
  ["elgin baelor"] = { 2, "dwarf gryphon flight master located at Slabchisel's Surve...", "Elgin Baelor is a dwarf gryphon flight master located at Slabchisel's Survey in the Wetlands." },
  ["elgin clickspring"] = { 2, "gnome", "Elgin Clickspring is a gnome and assistant to High Tinker Mekkatorque. She can be found around the table discussing plans to retake Gnomeregan in New Tinkertown." },
  ["eli blackfinger"] = { 2, "son of the famous blacksmith Nori Blackfinger", "Eli Blackfinger was the son of the famous blacksmith Nori Blackfinger. His mother died during his birth." },
  ["eliminator sotiros"] = { 2, "Forsworn kyrian located in the Citadel of Loyalty in Bastion", "Eliminator Sotiros is a Forsworn kyrian located in the Citadel of Loyalty in Bastion." },
  ["elinor"] = { 2, "Forsaken priestess serving the Conclave in the Netherligh...", "Elinor is a Forsaken priestess serving the Conclave in the Netherlight Temple. One night, after Calia Menethil had spoken with Saa'ra and was heading back to her room, Elinor approached her and excitedly informed her of King Anduin's plans for a G..." },
  ["elise brightletter"] = { 2, "dwarf inscription trainer found inside the shop Thistlefu...", "Elise Brightletter is a dwarf inscription trainer found inside the shop Thistlefuzz Arcanery, by the flightpath in Ironforge." },
  ["elistrasza"] = { 2, "', "Elistrasza was among the dragons taken hostage by the djaradin in Harrowsdeep as part of Iridikron's gambit to prevent Neltharion and the Aspects from collapsing the subterranean labyrinth. Lailastrasza recognized her from her work in the Ruby Lif..." },
  ["elite guard (broker)"] = { 2, "Veiled Market", "Elite Guards are brokers located at the Lap of Luxury in Tazavesh, the Veiled Market." },
  ["elixirist au'pyr"] = { 2, "broker located in the Hall of Shapes in Oribos", "Elixirist Au'pyr is a broker located in the Hall of Shapes in Oribos. He teaches Maw Walkers about Shadowlands Alchemy crafts." },
  ["eliyah"] = { 2, "elderly innkeeper of the inn in Bradensbrook", "Eliyah is the elderly innkeeper of the inn in Bradensbrook. He greeted and introduced himself to Lor'themar Theron and Thalyssra when they stopped to visit the inn there." },
  ["eliza"] = { 2, "undead rare mob found in Duskwood", "Eliza is an undead rare mob found in Duskwood. She wears a white dress and holds a Bouquet of Red Roses in her hand." },
  ["elizabeth hollingsworth"] = { 2, "Forsaken located at Light's Breach in Zul'Drak", "Elizabeth Hollingsworth is a Forsaken located at Light's Breach in Zul'Drak." },
  ["elizabeth nesworth"] = { 2, "worgen fishing supplies vendor located at the Talonbranch...", "Elizabeth Nesworth is a worgen fishing supplies vendor located at the Talonbranch Glade in Felwood. She can be found near the lake, just outside of a small shack." },
  ["elki"] = { 2, "tauren mail armor vendor located in Hewa's Armory on the ...", "Elki is a tauren mail armor vendor located in Hewa's Armory on the lower rise in Thunder Bluff. This section concerns content related to Legion." },
  ["ella (worgen)"] = { 2, "worgen reagent vendor found near Raven Hill in Duskwood", "Ella is a worgen reagent vendor found near Raven Hill in Duskwood." },
  ["ellaene"] = { 2, "night elf Sentinel", "Ellaene was a night elf Sentinel, the wife of Elyrion Fogsong, and the mother of Arietta. According to Elyrion, she was 'Funny and quick and sweeter than honey to those she loved'." },
  ["ellanoir"] = { 2, "gnome found outside the Caverns of Time in Tanaris during...", "Ellanoir is a gnome found outside the Caverns of Time in Tanaris during the Bronze Celebration. She is seen speaking with Juddson Rakes and Duryllin." },
  ["ellaria"] = { 2, "', "Ellaria was one of the high elves of Quel'lithien Lodge who succumbed to the corruption of a magical item found by Ranger-Lord Hawkspear, which transformed them into Wretched. Kirkian Dawnshield, who managed to avoid being corrupted by fleeing fro..." },
  ["ellegos"] = { 2, "member of the blue dragonflight", "Ellegos was a member of the blue dragonflight who defected to the Primalist cause. Ellegos was among those taken to the dungeons of the Obsidian Citadel for questioning." },
  ["ellegosa"] = { 2, "member of the blue dragonflight", "Ellegosa was a member of the blue dragonflight who defected to the Primalist cause. Ellegosa intended to open a passageway between the Chittering Caverns and Algeth'ar Academy for the Primalists to launch an assault on Malygos' forces through." },
  ["ellerdin"] = { 2, "earthen located on a bench just south of the Council's Tr...", "Ellerdin is an earthen located on a bench just south of the Council's Treasury in Dornogal." },
  ["ellington moonheart"] = { 2, "worgen located at the Lunarfall in Shadowmoon Valley", "Ellington Moonheart is a worgen located at the Lunarfall in Shadowmoon Valley. He can only be recruited using the Headhunter's Harvest from Lunarfall Inn." },
  ["elly fraze"] = { 2, "vulpera located at the Grand Bazaar in Dazar'alor", "Elly Fraze is a vulpera located at the Grand Bazaar in Dazar'alor." },
  ["elma"] = { 2, "member of the theater troupe located in the Proscenium in...", "Elma is a member of the theater troupe located in the Proscenium in the Isle of Dorn. She plays Sonnebrid in the 'The Thraegar's Descent' play and Overseer Roskarrag in the 'Forget Me Not' play." },
  ["elmarine"] = { 2, "high elf mage", "Elmarine is a high elf mage. At some point after the Cataclysm, she visited Flayers' Point in Desolace where she was noticed by Aramar Thorne." },
  ["elmo seedheart"] = { 2, "Arathi child located in the Fungal Fields in Hallowfall", "Elmo Seedheart is an Arathi child located in the Fungal Fields in Hallowfall." },
  ["elonia"] = { 2, "', "Elonia is one of the main characters of  [A Steamy Romance Novel: Nightborne of the Living Dead]." },
  ["elu"] = { 2, "tauren quest giver located in Freewind Post in Thousand N...", "Elu is a tauren quest giver located in Freewind Post in Thousand Needles. Elu was an aspiring Wind Rider Master and had a great love and respect for the wyverns." },
  ["elune"] = { 2, "moon goddess of the cosmic realm of Life", "Elune is a moon goddess of the cosmic realm of Life. Her sister and counterpart is the Winter Queen, one of the Eternal Ones of Death." },
  ["elynna (kyrian)"] = { 2, "kyrian located in Torghast", "Elynna is a kyrian located in Torghast." },
  ["elyrion fogsong"] = { 2, "elderly", "Elyrion Fogsong is an elderly and very skilled night elf alchemist. After suffering a great personal loss, he chose to live alone in a bog on the slopes of Mount Hyjal, but this ultimately changed as the result of his friendship with the Sentinel ..." },
  ["elyssa the flower"] = { 2, "vrykul located in Stormheim", "Elyssa the Flower is a vrykul located in Stormheim." },
  ["emaedi autoblast"] = { 2, "gnome member of G", "Emaedi Autoblast is a gnome member of G.E.A.R. who appears during the Heritage of Gnomeregan questline. She is a sharpshooter and scout for the 7th Legion, as well as an expert on explosives." },
  ["embar firepath"] = { 2, "tauren located in the Vault of the Incarnates as part of ...", "Embar Firepath is a tauren located in the Vault of the Incarnates as part of The Primal Council encounter." },
  ["ember court noble"] = { 2, "', "Ember Court Nobles are venthyr located in the Ember Court." },
  ["ember court socialite"] = { 2, "', "Ember Court Socialites are venthyr located in the Ember Court in Revendreth." },
  ["emberhusk dominator"] = { 2, "', "Emberhusk Dominators are drogbar riding amber scorpions located in Neltharion's Lair." },
  ["emberspark dreamsworn"] = { 2, "', "Emberspark Dreamsworn are found at Bough Shadow in Ashenvale." },
  ["emeline fizzlefry"] = { 2, "gnome located near the Magus Commerce Exchange in Dalaran", "Emeline Fizzlefry is a gnome located near the Magus Commerce Exchange in Dalaran. She can provide directions to various locations in Dalaran." },
  ["emerald bearkin"] = { 2, "', "Emerald Bearkin are druids in bear form located at the Ruins of Constellas in Felwood." },
  ["emigos"] = { 2, "blue dragon", "Emigos was a blue dragon who was killed by Neltharion's betrayal during the War of the Ancients. His name is on a Faded Gravestone at the Veiled Ossuary." },
  ["emily (scourge invasion)"] = { 2, "human from Lordaeron", "Emily was a human from Lordaeron who was supposed to have received a final letter from her lover." },
  ["emishalan"] = { 2, "dracthyr walking with Alzinathel in Stormwind Harbor in S...", "Emishalan is a dracthyr walking with Alzinathel in Stormwind Harbor in Stormwind City." },
  ["emissary ba'hask"] = { 2, "broker located in the Enclave in Oribos", "Emissary Ba'hask is a broker located in the Enclave in Oribos." },
  ["emissary ba'julk"] = { 2, "broker located in the Enclave in Oribos", "Emissary Ba'julk is a broker located in the Enclave in Oribos." },
  ["emissary ba'silk"] = { 2, "broker located in the Enclave in Oribos", "Emissary Ba'silk is a broker located in the Enclave in Oribos who frequently has conversations with Caretaker Kah-Vosh." },
  ["emissary ba'solo"] = { 2, "broker located in the Broker's Den in Oribos", "Emissary Ba'solo is a broker located in the Broker's Den in Oribos. Ba'solo frequently has conversations with Opulence Ba'hare." },
  ["emissary brighthoof"] = { 2, "leader of the Westwind Refugee Camp", "Emissary Brighthoof is the leader of the Westwind Refugee Camp. Horde adventurers encounter her during  [10-30] The Fall of Taunka'le Village quest chain." },
  ["emissary of the depths"] = { 2, "earthen", "Emissary of the Depths is an earthen that used to be located in the Foundation Hall in Dornogal." },
  ["emissary of the tides"] = { 2, "', "Emissary of the Tides is Queen Azshara's projection located in Battle for Azeroth instances as part of the  [Beguiling] affix." },
  ["emogg the crusher"] = { 2, "rare Mo'grosh ogre in Loch Modan", "Emogg the Crusher is a rare Mo'grosh ogre in Loch Modan." },
  ["emperor dojan ii"] = { 2, "emperor of the mogu", "Emperor Dojan II was an emperor of the mogu. Even by mogu standards, the reign of Emperor Dojan II was short and brutish." },
  ["emperor kang"] = { 2, "mogu emperor of the past", "Emperor Kang was a mogu emperor of the past whose reign was short. He wanted to bind Quilen servants in small stone statues, but this caused them to become greatly diminished in power, causing them to be deemed unworthy, and thus the project was a..." },
  ["emperor tian"] = { 2, "mogu emperor", "Emperor Tian was a mogu emperor who was considered monstrous. He is best known for using the powers of the Vale of Eternal Blossoms to mold a group of cave troggs into a new messengers and deliverymen: the grummles." },
  ["emperor tsao"] = { 2, "emperor of the mogu", "Emperor Tsao was an emperor of the mogu. Very little is known about this emperor, other than his reign was short and unremarkable by mogu standards, notable mostly for administrative reorganization." },
  ["emperor wai"] = { 2, "mogu emperor", "Emperor Wai was a mogu emperor. His snarling face was depicted on coins that were used as currency during his time." },
  ["emperor's courage"] = { 2, "', "The Emperor's Courage are mogu created from the Forge of the Endless in the Mogu'shan Vaults." },
  ["emperor's rage"] = { 2, "', "The Emperor's Rage are mogu created from the Forge of the Endless in the Mogu'shan Vaults." },
  ["emperor's strength"] = { 2, "', "The Emperor's Strength are mogu created from the Forge of the Endless in the Mogu'shan Vaults." },
  ["empoor"] = { 2, "wandering Broken merchant", "Empoor is a wandering Broken merchant and a quest giver located on the road between Shattrath City and Tuurem in Terokkar Forest. He is accompanied by his bodyguard." },
  ["empoor's bodyguard"] = { 2, "', "Empoor's Bodyguard wanders with Empoor on the road between Tuurem and Shattrath City. He will fight alongside Empoor when the player is completing  [15-30] By Any Means Necessary." },
  ["empowered coldheart agent"] = { 2, "', "Empowered Coldheart Agents are Mawsworn kyrian located in Torghast, Tower of the Damned." },
  ["empowered coldheart ascendant"] = { 2, "', "Empowered Coldheart Ascendants are kyrian found in the Coldheart Interstitia wing in Torghast, Tower of the Damned." },
  ["empowered coldheart javelineer"] = { 2, "', "Empowered Coldheart Javelineers are kyrian found in the Coldheart Interstitia wing in Torghast, Tower of the Damned." },
  ["empowered imperial consular"] = { 2, "', "Empowered Imperial Consulars are venthyr located in Torghast, Tower of the Damned." },
  ["empowered imperial curator"] = { 2, "', "Empowered Imperial Curators are venthyr located in Torghast, Tower of the Damned." },
  ["empowered imperial duelist"] = { 2, "', "Empowered Imperial Duelists are venthyr located in Torghast, Tower of the Damned." },
  ["empty recollection"] = { 2, "Shadowed Crucible", "Empty Recollections are dracthyr projections summoned by the Scalecommander Sarkareth in Aberrus, the Shadowed Crucible." },
  ["empyrean conjuror"] = { 2, "', "Empyrean Conjurors are humans, blood elves, and gnomes located in the Empyrean Society Enclave in Azsuna." },
  ["enamored fan"] = { 2, "', "Enamored Fans are located at the Serene Dreams Spa in Thaldraszus. They are admirers of Zeldis." },
  ["enchanted emissary"] = { 2, "', "Enchanted Emissary is Queen Azshara's projection located in Battle for Azeroth instances as part of the  [Beguiling] affix." },
  ["endemion"] = { 2, "', "Endemion was responsible for guarding Ikronia's prison alongside Sandesia the night that Raszageth and her forces attacked the Reach. He was sent away from his post by Ignion to join the battle." },
  ["enderman"] = { 2, "human of the Stromgarde Militia", "Enderman was a human of the Stromgarde Militia who fought against the Syndicate in Arathi Highlands. He fell and his badge was taken by his killer, kept as a trophy until its retrieval by hired adventurers." },
  ["endiri dawnsurge"] = { 2, "Arathi located in Mereldar in Hallowfall", "Endiri Dawnsurge is an Arathi located in Mereldar in Hallowfall. He noticed listlessness and snippiness in the eyes of Shinda Creedpike, one of his lieutenants." },
  ["enforcer emilgund"] = { 2, "rare mob ogre", "Enforcer Emilgund is a rare mob ogre who guards the entrance to the Venture Co. Mine in Mulgore." },
  ["enforcer kristof"] = { 2, "venthyr located in the Shrouded Asylum in Revendreth", "Enforcer Kristof is a venthyr located in the Shrouded Asylum in Revendreth." },
  ["enges"] = { 2, "vrykul Fjarnskaggl trader located at Boralus Harbor in Bo...", "Enges is a vrykul Fjarnskaggl trader located at Boralus Harbor in Boralus." },
  ["engine speaker"] = { 2, "', "Engine Speakers are earthen located in the Stonevault." },
  ["engineer bolthold"] = { 2, "goblin located in Drustvar during the Faction Assaults", "Engineer Bolthold is a goblin located in Drustvar during the Faction Assaults. He pilots the Shredatron-2000." },
  ["engineer brightbuckle"] = { 2, "member of the crew of The Bravery", "Engineer Brightbuckle is a member of the crew of The Bravery, the boat that runs between Stormwind Harbor and Teldrassil. He sells general good supplies and also does repairs." },
  ["engineer enthusiast"] = { 2, "', "Engineer Enthusiasts are gnomes located in Vol'dun during Faction Assaults." },
  ["engineer feknut"] = { 2, "gnome located at the Steel Gate in the Howling Fjord", "Engineer Feknut is a gnome located at the Steel Gate in the Howling Fjord." },
  ["engineer fizzlepickle"] = { 2, "gnome located in Fungal Folly", "Engineer Fizzlepickle is a gnome located in Fungal Folly." },
  ["engineer om'loof"] = { 2, "broker", "Engineer Om'loof is a broker who appears in Eco-Dome: Primus on K'aresh." },
  ["engineering instructor morgaen"] = { 2, "Arathi located in Lightspark in Hallowfall", "Engineering Instructor Morgaen is an Arathi located in Lightspark in Hallowfall." },
  ["engorged bloodfin murloc"] = { 2, "', "Engorged Bloodfin Murlocs are murlocs encountered by Alliance and Horde champions in Nazjatar." },
  ["enizo"] = { 2, "ankoan located in Mezzamere in Nazjatar", "Enizo is an ankoan located in Mezzamere in Nazjatar." },
  ["enlightened broker guard"] = { 2, "', "Enlightened Broker Guards are dead brokers located just outside Haven and in the Great Veldt in Zereth Mortis." },
  ["enlightened guardian"] = { 2, "', "Enlightened Guardians are brokers located in Haven and Pilgrim's Grace in Zereth Mortis." },
  ["enlightened pilgrim"] = { 2, "', "Enlightened Pilgrims are brokers located in Zereth Mortis." },
  ["enola"] = { 2, "tauren follower located at Frostwall in Frostfire Ridge", "Enola is a tauren follower located at Frostwall in Frostfire Ridge. She can only be recruited using the Headhunter's Harvest from Frostwall Tavern." },
  ["enraged worgen"] = { 2, "', "Enraged Worgen appear during the nightmare gauntlet and are attacking the Harrington family." },
  ["ensign ebbert"] = { 2, "gnome ensign aboard the Pincer X2 in the Abyssal Depths", "Ensign Ebbert is a gnome ensign aboard the Pincer X2 in the Abyssal Depths." },
  ["enslaved alliance mage"] = { 2, "', "Enslaved Alliance Mages are gnomes located inside Nespirah in Shimmering Expanse." },
  ["enslaved bluff scout"] = { 2, "tauren", "Enslaved Bluff Scout is a tauren." },
  ["enslaved horde pearl miner"] = { 2, "', "Enslaved Horde Pearl Miners are orcs, Forsaken, tauren, and jungle trolls located in Shimmering Expanse." },
  ["enslaved outcast"] = { 2, "', "Enslaved Outcasts are arakkoa located at the Apexis Excavation in the Spires of Arak." },
  ["enslaved riplash priestess"] = { 2, "naga", "Enslaved Riplash Priestess is a naga." },
  ["enslaved shieldmaiden"] = { 2, "', "Enslaved Shieldmaidens are vrykul located in Helmouth Cliffs in the Maw of Souls." },
  ["enslaved weaponsmith"] = { 2, "tauren", "Enslaved Weaponsmith is a tauren." },
  ["ensydius the defiler"] = { 2, "Mawsworn kyrian located on a small rise overlooking the S...", "Ensydius the Defiler is a Mawsworn kyrian located on a small rise overlooking the Seeker's Quorum in southern Korthia." },
  ["enthralled laborer"] = { 2, "', "Enthralled Laborers are dwarves and gnomes located in the Dwarven District in the Vision of Stormwind." },
  ["enthralled murloc"] = { 2, "', "Enthralled Murlocs are murlocs located in the Swamp of Sorrows." },
  ["enthralled siren"] = { 2, "', "Enthralled Sirens are naga located in Swamp of Sorrows." },
  ["enthralled weaponsmith"] = { 2, "', "Enthralled Weaponsmiths are Dark Iron dwarves and gnomes located in the Dwarven District in the Vision of Stormwind." },
  ["enthusiastic soul"] = { 2, "', "Enthusiastic Souls are located around the edges of the Body Banks in Maldraxxus, alongside Curious Souls. They comment on Rathan and the Maw Walker's efforts to build a new construct body for Emeni during the  [60] Rebellious Souls questline." },
  ["enthusiastic trader"] = { 2, "broker located at Tazavesh", "The Enthusiastic Trader is a broker located at Tazavesh, the Veiled Market." },
  ["entitled guest"] = { 2, "', "Entitled Guests are venthyr located in the Ember Court." },
  ["entombed venthyr"] = { 2, "', "Entombed Venthyr are venthyr located in Revendreth." },
  ["envenomated expeditionary"] = { 2, "', "Envenomated Expeditionaries are a blood elf and a gnome located in the Shiverweb Vale in the Azure Span. Lilial Dawnburst is trying to heal them." },
  ["envoy ducal"] = { 2, "human sent by the Valiance Expedition to make contact wit...", "Envoy Ducal was a human sent by the Valiance Expedition to make contact with the humans of Silverbrook. According to the Freed Alliance Scout, he eventually became a member of the local Wolfcult." },
  ["envoy habissi"] = { 2, "Harandar Banner", "Envoy Habissi was a haranir located on the south side of the Orgrimmar Embassy in Orgrimmar. Beside her is the Harandar Banner." },
  ["envoy ir'ayi"] = { 2, "haranir standing next to a banner in Orgrimmar Embassy in...", "Envoy Ir'ayi is a haranir standing next to a banner in Orgrimmar Embassy in Orgrimmar." },
  ["envoy manat"] = { 2, "haranir located at Stormwind Embassy", "Envoy Manat is a haranir located at Stormwind Embassy." },
  ["enzo"] = { 2, "tuskarr child found outside the Caverns of Time in Tanari...", "Enzo is a tuskarr child found outside the Caverns of Time in Tanaris during the Bronze Celebration, alongside Benatauk and Maru." },
  ["eoghan knatley"] = { 2, "Arathi stationed at Beledar's Bounty in Hallowfall", "Eoghan Knatley is an Arathi stationed at Beledar's Bounty in Hallowfall. When Hallowfall once again came under threat by the Sureki and the army was stretched thin, a call to arms was issued to those with the strength to wield a weapon." },
  ["epicus maximus"] = { 2, "the fourth encounter at Rank 7 in the Brawler's Guild dur...", "Epicus Maximus is a the fourth encounter at Rank 7 in the Brawler's Guild during The War Within. The party is composed of: Epicus Maximus, an elite flying shark equipped with two rockets and a laser beam." },
  ["epistasia"] = { 2, "Ascended kyrian located at the Cliffs of Respite in Bastion", "Epistasia is an Ascended kyrian located at the Cliffs of Respite in Bastion." },
  ["eppu"] = { 2, "tortollan located in the Hall of Chroniclers of the Great...", "Eppu is a tortollan located in the Hall of Chroniclers of the Great Seal in Dazar'alor." },
  ["eral"] = { 2, "Broken general goods vendor located at the Lower City mar...", "Eral is a Broken general goods vendor located at the Lower City market in Shattrath City. This section concerns content related to Dragonflight." },
  ["eraleshk"] = { 2, "dracthyr located at the Life Vault Ruins in the Waking Sh...", "Eraleshk is a dracthyr located at the Life Vault Ruins in the Waking Shores. He is unable to fly and considers his identity as a dracthyr lost." },
  ["eran droll"] = { 2, "Darkfallen death knight located at Acherus: The Ebon Hold", "Eran Droll is a Darkfallen death knight located at Acherus: The Ebon Hold. He only appears after completing the Frost and Death class hall advancement, letting you train Ebon Knight Frostreavers." },
  ["erani"] = { 2, "earthen located in Chip Off the Block in the Forgegrounds...", "Erani is an earthen located in Chip Off the Block in the Forgegrounds in Dornogal." },
  ["erbag"] = { 2, "member of the Order of Tirisfal", "Erbag, who lived some eight centuries ago, was a member of the Order of Tirisfal. Erbag supported the council's decision to make Aegwynn the new Guardian." },
  ["erden"] = { 2, "centaur located in Mountainview Post in the Ohn'ahran Plains", "Erden is a centaur located in Mountainview Post in the Ohn'ahran Plains. He is working on a Bristletooth Mauler." },
  ["erdene"] = { 2, "centaur vendor located in Cloverwood Hollow in the Ohn'ah...", "Erdene is a centaur vendor located in Cloverwood Hollow in the Ohn'ahran Plains." },
  ["erdi bloodtooth"] = { 2, "orc innkeeper located in Stormsong Valley", "Erdi Bloodtooth is an orc innkeeper located in Stormsong Valley." },
  ["erekem"] = { 2, "arakkoa mini-boss located in the Violet Hold", "Erekem is an arakkoa mini-boss located in the Violet Hold. His escape comes with two adds." },
  ["erekem guard"] = { 2, "', "Erekem Guards are arakkoa summoned by Erekem in the Violet Hold." },
  ["ereuso"] = { 2, "Broken", "Ereuso is a Broken that can be found lying in the Crystal Hall of the Exodar; he appears to be weakened or ill: Nus is caring for him and for Duumehi, who stands not distant from him. This section concerns content related to Legion." },
  ["ergh of the stillpine"] = { 2, "furbolg trade goods vendor located at Stillpine Hold in A...", "Ergh of the Stillpine is a furbolg trade goods vendor located at Stillpine Hold in Azuremyst Isle." },
  ["ergll"] = { 2, "murloc located in Azshara", "Ergll is a murloc located in Azshara. He is a friend of Azuregos, who taught him to speak." },
  ["eric davidson"] = { 2, "master Pet Tamer located in Raven Hill Cemetery in Duskwood", "Eric Davidson is a master Pet Tamer located in Raven Hill Cemetery in Duskwood. He is circling a large statue with his three level 7 battle pets: Darkwidow, Blackfang, and Webwinder." },
  ["eric of the lanhams"] = { 2, "vrykul located in Stormheim", "Eric of the Lanhams is a vrykul located in Stormheim." },
  ["eridia"] = { 2, "Ascended kyrian", "Eridia is an Ascended kyrian and the Hand of Purity, serving as the right hand of Vesiphone, the Paragon of Purity. Lysonia, once the Hand of Loyalty, later the leader of the Forsworn, used to be her soulbind." },
  ["erik"] = { 2, "gnome Little Helper", "Erik is a gnome Little Helper that appears in Lunarfall along with Lil' Helpers when the  [Little Helpers] is purchased during the Feast of Winter Veil. He is usually on his break, eating a  [Gingerbread Cookie]." },
  ["erik (human)"] = { 2, "innkeeper/bartender of Demonsbane Inn", "Erik is the innkeeper/bartender of Demonsbane Inn and Tavern located on Theramore Isle. His brother was Olaf." },
  ["erik fallrook"] = { 2, "arrogant son of Terrence Fallrook", "Erik Fallrook was an arrogant son of Terrence Fallrook who lived in the Fallrook Estate. His family owned a winery." },
  ["erling the lightningborn"] = { 2, "vrykul located on the cliffs in southern Stormheim", "Erling the Lightningborn is a vrykul located on the cliffs in southern Stormheim." },
  ["ermmglmrr"] = { 2, "murloc from Azmerloth located in Tyrhold Reservoir in Tha...", "Ermmglmrr is a murloc from Azmerloth located in Tyrhold Reservoir in Thaldraszus during Time Rifts." },
  ["ermmglmrr iii"] = { 2, "murloc from Azmerloth located in Tyrhold Reservoir in Tha...", "Ermmglmrr III is a murloc from Azmerloth located in Tyrhold Reservoir in Thaldraszus during Time Rifts." },
  ["ermmglmrr jr."] = { 2, "murloc from Azmerloth located in Tyrhold Reservoir in Tha...", "Ermmglmrr Jr. is a murloc from Azmerloth located in Tyrhold Reservoir in Thaldraszus during Time Rifts." },
  ["erna"] = { 2, "Winterpelt furbolg located at Winterpelt Hollow in the Az...", "Erna is a Winterpelt furbolg located at Winterpelt Hollow in the Azure Span. She is trying to communicate with Narn." },
  ["erol ellimoore"] = { 2, "Arathi located in Light's Blooming in Hallowfall", "Erol Ellimoore is an Arathi located in Light's Blooming in Hallowfall." },
  ["errick ryston"] = { 2, "Arathi located in the Lightspark Commissary in Hallowfall", "Errick Ryston is an Arathi located in the Lightspark Commissary in Hallowfall. There, he works as a caretaker, making sure the students are fed." },
  ["erthalif"] = { 2, "high elf mage", "Erthalif was a high elf mage that died three hundred years before the Third War. Aegwynn was given access to his redoubt after his death." },
  ["erunak stonespeaker"] = { 2, "powerful Broken shaman quest giver allied with the Earthe...", "Erunak Stonespeaker is a powerful Broken shaman quest giver allied with the Earthen Ring. He is assigned to aid the Horde and Alliance in Vashj'ir against the naga allied with Deathwing and the Old Gods' forces." },
  ["eruundi"] = { 2, "voidscarred located in Voidstorm", "Eruundi is a voidscarred located in Voidstorm." },
  ["ery"] = { 2, "Kul Tiran tidesage", "Ery was a Kul Tiran tidesage and one of the two main characters in the Kul Tiran folktale 'Why the Mermaids Left Boralus', which tells of the love between her and the mermaid Halia." },
  ["erza"] = { 2, "dracthyr item upgrader located in the Sapphire Enclave in...", "Erza is a dracthyr item upgrader located in the Sapphire Enclave in Valdrakken." },
  ["escaped cutthroat"] = { 2, "Forsaken located on the Isle of Dorn", "Escaped Cutthroat is a Forsaken located on the Isle of Dorn. A former inmate of the Violet Hold, she is sitting at a campfire on Oztan Isle." },
  ["escaped dracthyr"] = { 2, "', "The Escaped Dracthyr are dead dracthyr located at the Old Weyrn Grounds in the Forbidden Reach. After being released from stasis, they escaped their weyrns, only to be hunted down by the Spellsworn Wingcatcher." },
  ["escaped dreghood"] = { 2, "', "Escaped Dreghood are Broken located in the Temple of Telhamat in Hellfire Peninsula." },
  ["escaped horde crewman"] = { 2, "', "Escaped Horde Crewmen can be found at the Forlorn Hut on the Wandering Isle. Some of them were injured by the recent events, and some others can be seen gathering bamboos in the Pei-Wu Forest and fighting the local tigers." },
  ["esme"] = { 2, "unknown race", "Esme is an unknown race who is acquainted with Auntie Stormstout. She was mentioned by her when she accidentally mistook Chen for Zan." },
  ["esmund brightshield"] = { 2, "dwarf located at the Lunarfall in Shadowmoon Valley", "Esmund Brightshield is a dwarf located at the Lunarfall in Shadowmoon Valley. He can only be recruited using the Headhunter's Harvest from Lunarfall Inn." },
  ["estes"] = { 2, "', "Estes is one of the survivors of the battle of Shattrath City. He was affected by the red mist, and in the months following his escape, started the change into a Broken." },
  ["et'kil"] = { 2, "stationary mantid hiding in the southwest corner of one o...", "Et'kil is a stationary mantid hiding in the southwest corner of one of the nooks of the Niuzao Temple exterior in the Townlong Steppes." },
  ["etaruk"] = { 2, "tuskarr found camped just to the southeast of the entranc...", "Etaruk is a tuskarr found camped just to the southeast of the entrance of Coldrock Quarry in the Borean Tundra." },
  ["eternal watcher (kyrian)"] = { 2, "ascended kyrian located in Aspirant's Crucible in Bastion", "Eternal Watcher is an ascended kyrian located in Aspirant's Crucible in Bastion." },
  ["ethereal apprentice"] = { 2, "', "Ethereal Apprentices are ethereals that can be found in the Mana-Tombs. They are spawned if players don't kill the Ethereal Beacons summoned by Nexus-Prince Shaffar." },
  ["ethereal arcanist"] = { 2, "', "Ethereal Arcanists are ethereals found inside the Tomb of Lights in Terokkar Forest." },
  ["ethereal construct"] = { 2, "ethereal", "Ethereal Construct is an ethereal. It was to appear at the Tomb of Lights in Terokkar Forest." },
  ["ethereal crypt raider"] = { 2, "', "Ethereal Crypt Raider are ethereals that can be found in the Mana-Tombs." },
  ["ethereal darkcaster"] = { 2, "', "Ethereal Darkcasters are ethereals that can be found in the Mana-Tombs." },
  ["ethereal nethermancer"] = { 2, "', "Ethereal Nethermancers are ethereals found at and inside the Tomb of Lights in Terokkar Forest." },
  ["ethereal plunderer"] = { 2, "', "The Consortium always collects its debts. Ethereal Plunderers are ethereals found at and inside the Tomb of Lights in Terokkar Forest." },
  ["ethereal priest"] = { 2, "', "Ethereal Priests are ethereals that can be found in the Mana-Tombs." },
  ["ethereal scavenger"] = { 2, "', "Ethereal Scavengers are ethereals that can be found in the Mana-Tombs." },
  ["ethereal sorcerer"] = { 2, "', "Ethereal Sorcerers  are ethereals that can be found in the Mana-Tombs." },
  ["ethereal soul-trader"] = { 2, "ethereal companion", "Ethereal Soul-Trader is an ethereal companion who sells wares using a unique currency to players." },
  ["ethereal spellbinder"] = { 2, "', "Ethereal Spellbinders are ethereals that can be found in the Mana-Tombs." },
  ["ethereal spellfilcher"] = { 2, "', "Ethereal Spellfilchers are ethereals found in Karazhan." },
  ["ethereal theurgist"] = { 2, "', "Ethereal Theurgists are ethereals that can be found in the Mana-Tombs." },
  ["ethereal thief"] = { 2, "', "Ethereal Thieves are ethereals located in Karazhan. They can also be seen in Return to Karazhan." },
  ["ethereal warpweaver"] = { 2, "ethereal summoned by the  [Ethereal Transmogrifier]", "The Ethereal Warpweaver is an ethereal summoned by the  [Ethereal Transmogrifier]." },
  ["ethereal watcher"] = { 2, "', "Ethereal Watchers are ethereals located in the Sepulcher of the First Ones." },
  ["ethereal wind trader"] = { 2, "', "The Ethereal Wind Trader replaces Xevozz in the Violet Hold after his death." },
  ["ethereum archon"] = { 2, "', "Ethereum Archons are ethereals located in Ethereum Staging Grounds in the Netherstorm." },
  ["ethereum assassin"] = { 2, "', "Ethereum Assassins are ethereals located in the Ethereum Staging Grounds in the Netherstorm." },
  ["ethereum avenger"] = { 2, "', "Ethereum Avengers are ethereals located throughout the isle with Managorge Ultris in Netherstorm." },
  ["ethereum disruptor"] = { 2, "ethereal", "Ethereum Disruptor is an ethereal." },
  ["ethereum gladiator"] = { 2, "', "Ethereum Gladiators are ethereals located in Netherstorm. They spawn before or during  [25-30] Escape from the Staging Grounds." },
  ["ethereum jailor"] = { 2, "ethereal found in Netherstorm near Manaforge Ultris", "Ethereum Jailor is an ethereal found in Netherstorm near Manaforge Ultris. He is reported to be on a 15 minute respawn timer." },
  ["ethereum life-binder"] = { 2, "', "Ethereum Life-Binders are ethereals found inside the Arcatraz instance." },
  ["ethereum nexus-stalker"] = { 2, "', "Ethereum Nexus-Stalkers are ethereals found in the Netherstorm." },
  ["ethereum nullifier"] = { 2, "', "Ethereum Nullifiers are ethereals found around the outskirts of Manaforge Ultris in the Netherstorm." },
  ["ethereum overlord"] = { 2, "', "Ethereum Overlords are ethereals located at the Ethereum Staging Grounds in the Netherstorm." },
  ["ethereum prisoner"] = { 2, "', "Ethereum Prisoners are ethereals located in the Netherstorm." },
  ["ethereum researcher"] = { 2, "', "Ethereum Researchers are ethereals found in the Netherstorm." },
  ["ethereum shocktrooper"] = { 2, "', "Ethereum Shocktroopers are ethereals located in Ethereum Staging Grounds in the Netherstorm." },
  ["ethereum slayer"] = { 2, "', "Ethereum Slayers are ethereals found in the Arcatraz." },
  ["ethereum smuggler"] = { 2, "', "Ethereum Smugglers are elite ethereals located in the Magisters' Terrace." },
  ["ethereum wave-caster"] = { 2, "', "Ethereum Wave-Casters are ethereals found in the Arcatraz." },
  ["ethylar"] = { 2, "high elf mage at Nallorath's father court", "Ethylar was a high elf mage at Nallorath's father court and a member of the Council of Tirisfal 2,600 years before the First War. She battled against Kathra'natir who stole the Amulet of Waters." },
  ["etna blayze"] = { 2, "Arathi", "Etna Blayze is an Arathi and the current leader of the Priory of the Sacred Flame in Hallowfall." },
  ["etries"] = { 2, "member of the Council of Oracles associated with the Arch...", "Etries was a member of the Council of Oracles associated with the Architects, one of the four aspects of K'areshi society. She also held membership among the Ravel." },
  ["etubrute"] = { 2, "tauren fighting Iron Horde Grunts alongside many others a...", "Etubrute is a tauren fighting Iron Horde Grunts alongside many others at the Dark Portal in Blasted Lands and Tanaan Jungle. He died after the portal was destroyed." },
  ["eulinda"] = { 2, "Forsaken located in Zul'Aman", "Eulinda is a Forsaken located in Zul'Aman. She has been hexxed into a frog waiting to be saved via  [Amani Hex Stick]." },
  ["eumelia"] = { 2, "kyrian stable master located at Hero's Rest in Bastion", "Eumelia is a kyrian stable master located at Hero's Rest in Bastion. She put up a bounty for Darkwing, the cloudfeather matriarch in Greatwing Roost, who had fallen to a great and terrible sickness and had grown aggressive, dominating her children..." },
  ["evaelyn cavalayr"] = { 2, "Arathi located in Lorel's Crossing in Hallowfall", "Evaelyn Cavalayr is an Arathi located in Lorel's Crossing in Hallowfall." },
  ["evaile"] = { 2, "venthyr located in the Broker's Den in Oribos during  [60...", "Evaile is a venthyr located in the Broker's Den in Oribos during  [60] Report to Oribos." },
  ["evee copperspring"] = { 2, "goblin PvP rewards vendor located in Gadgetzan in Tanaris", "Evee Copperspring was a goblin PvP rewards vendor located in Gadgetzan in Tanaris. She was usable by both Horde and Alliance." },
  ["evergrove druid"] = { 2, "', "Evergrove Druids are night elf quest givers located at Death's Door in the Blade's Edge Mountains. They appear when summoned using a quest item, and are of a random gender and race (night elf or tauren)." },
  ["evie (vulpera)"] = { 2, "vulpera child sitting next to Wenha", "Evie is a vulpera child sitting next to Wenha and watching the two Playful Prowlers outside the Orgrimmar Embassy in Orgrimmar." },
  ["evil dolly"] = { 2, "draenei located at the Southsea Holdfast in Thousand Needles", "Evil Dolly is a draenei located at the Southsea Holdfast in Thousand Needles. She is a Southsea pirate and the captain of one of the three ships located there." },
  ["eviscerator"] = { 2, "elite white worgen", "Eviscerator is an elite white worgen that sometimes appears in Blackrock Depths. When a player enters the Ring of Law in the Depths, an arena event will occur where players have to face three waves of non-elite enemies and finally an elite mini-boss." },
  ["evoker of sar'this"] = { 2, "arakkoa located at Lake Jorune in Terokkar Forest", "The Evoker of Sar'this is an arakkoa located at Lake Jorune in Terokkar Forest. He shows up after Sar'this sacrifices himself in summoning the fifth elemental needed to be killed to get the  [Flawless Arcane Essence] for  [25-30] The Soul Cannon o..." },
  ["evwix bentrocket"] = { 2, "goblin located at Venturewood in the Undermine", "Evwix Bentrocket is a goblin located at Venturewood in the Undermine." },
  ["examiner boian"] = { 2, "venthyr located at Archivam in Revendreth", "Examiner Boian is a venthyr located at Archivam in Revendreth. He works for Sinkeeper Mateo." },
  ["examiner daciana"] = { 2, "venthyr located at Archivam in Revendreth", "Examiner Daciana is a venthyr located at Archivam in Revendreth. She works for Sinkeeper Mateo." },
  ["examiner ionata"] = { 2, "venthyr located at Archivam in Revendreth", "Examiner Ionata is a venthyr located at Archivam in Revendreth. She works for Sinkeeper Mateo." },
  ["exarch admetius"] = { 2, "draenei", "Exarch Admetius is a draenei and the leader of Blood Watch in Bloodmyst Isle. He and his subordinates are known to train draenei soldiers of the Hand of Argus." },
  ["exarch akama"] = { 2, "', "Akama is one of the five Exarchs, leaders of draenei society under the prophet Prophet Velen. He leads the Vindicators in alternate Draenor, serving as their high vindicator." },
  ["exasperated exporter"] = { 2, "Veiled Market in K'aresh", "Exasperated Exporters are brokers located in the Gilded Landing in Tazavesh, the Veiled Market in K'aresh." },
  ["excavation raider"] = { 2, "', "Excavation Raiders are tauren located in Southern Barrens." },
  ["excavationist au'fer"] = { 2, "broker located in the Hall of Shapes in Oribos", "Excavationist Au'fer is a broker located in the Hall of Shapes in Oribos. He teaches Maw Walkers about Shadowlands Mining techniques." },
  ["executor nizrek"] = { 2, "other two being Widow Arak'nai (the Weaver)", "Executor Nizrek, codenamed the Vizier, is one of the three leaders of the Severed Threads conspiracy, the other two being Widow Arak'nai (the Weaver) and Anub'azal (the General). He leads a titular subfaction, the Vizier, and is found in the City ..." },
  ["executrix ophelia"] = { 2, "venthyr located in the Halls of the Faithful in Castle Na...", "Executrix Ophelia is a venthyr located in the Halls of the Faithful in Castle Nathria." },
  ["exhausted earthguard sentinel"] = { 2, "', "Exhausted Earthguard Sentinels are tauren located in Deepholm." },
  ["exhausted protector"] = { 2, "', "Exhausted Protectors are kyrian located in Cocyrus and Zovaal's Cauldron of the Maw. Xandria wants the Maw Walker to rejuvenate the protectors in  [60] Encouraging Words during the  [60B] Kyrian Assault." },
  ["exhausted spiritwalker"] = { 2, "tauren located in Toghusuq Village in the Ohn'ahran Plains", "Exhausted Spiritwalker is a tauren located in Toghusuq Village in the Ohn'ahran Plains." },
  ["exhausted tutor"] = { 2, "', "Exhausted Tutors are venthyr located in the Maw." },
  ["exhausted vrykul"] = { 2, "', "Exhausted Vrykul are vrykul found in the Forlorn Mine behind Sifreldar Village in the Storm Peaks." },
  ["exotic concubine"] = { 2, "gnome found in Elisande's Secret Quarters in the Nighthold", "The Exotic Concubine is one of Grand Magistrix Elisande's Tower Concubines. It is a gnome found in Elisande's Secret Quarters in the Nighthold, dancing naked." },
  ["expedition defender (mechagon island)"] = { 2, "', "Expedition Defenders are gnomes located at the Overspark Expedition Camp on Mechagon Island." },
  ["expedition engineer"] = { 2, "', "Expedition Engineers are gnomes located in the Waking Shores." },
  ["expedition escort"] = { 2, "', "Expedition Escorts are dracthyr located on the Rugged Dragonscale in Stormwind City and on the Defiant Dragonscale in Durotar, both of which go to the Waking Shores." },
  ["expedition guardian"] = { 2, "', "Expedition Guardians are dwarves, blood elves, and gnomes located at the Wild Coast in the Waking Shores, Emberwatch in the Ohn'ahran Plains, and Theron's Watch in the Azure Span. Some are paired with Expedition Guarantors." },
  ["expedition member"] = { 2, "dialogue plays out", "Expedition Members are three gnomes gathered in front of Twizzleflux the Insane at the Starwatch Tower in Uldum. When a player approaches, a dialogue plays out that ends with Twizzleflux channeling 'Curse of the Tombs' into the gnomes, turning the..." },
  ["expedition provisioner"] = { 2, "', "Expedition Provisioners are members of the Dragonscale Expedition located in the Dranosh'ar Blockade in Durotar, Stormwind Harbor in Stormwind City, and at Wild Coast and Wingrest Embassy in the Waking Shores." },
  ["expedition scout"] = { 2, "', "Expedition Scouts are worgen, dwarves, humans, and gnomes located in Delver's Headquarters in Dornogal." },
  ["expedition scout (boralus)"] = { 2, "', "Expedition Scouts are gnomes located in Boralus. They are members of Tinkmaster Overspark's expedition to Mechagon Island." },
  ["expedition scout (waking shores)"] = { 2, "gnome located in the Waking Shores", "Expedition Scout is a gnome located in the Waking Shores." },
  ["expedition shieldhand"] = { 2, "Arathi located in Flotsam Shoal on the Siren Isle", "Expedition Shieldhand is an Arathi located in Flotsam Shoal on the Siren Isle." },
  ["expedition supplier"] = { 2, "', "Expedition Suppliers are members of the Dragonscale Expedition located in the Dranosh'ar Blockade in Durotar and in Stormwind Harbor in Stormwind City." },
  ["expedition trainee"] = { 2, "', "Expedition Trainees are members of the Dragonscale Expedition located in Stormwind Harbor in Stormwind City." },
  ["expedition warden"] = { 2, "', "Expedition Wardens are tauren and night elf guards located in Cenarion Refuge in Zangarmarsh and Evergrove in the Blade's Edge Mountains." },
  ["experienced champion"] = { 2, "', "Experienced Champions are orcs, tauren, and blood elves located in Vol'dun during the Faction Assaults." },
  ["experiment furbolg"] = { 2, "', "The Experiment Furbolg was released upon its guards by Kael'thas and Vashj in the Dungeons of Dalaran underneath the city of Dalaran. It was enhanced by the Dalaran wizards." },
  ["experiment ogre"] = { 2, "', "The Experiment Ogre was one of the Dalaran Wizard's Experiments in the Dungeons of Dalaran.  It was locked below in a cell controlled by a lever." },
  ["exploited crown intern"] = { 2, "', "Exploited Crown Interns are Forsaken located in Pyrewood Village in Silverpine Forest during the Love is in the Air event." },
  ["explorative fisher"] = { 2, "', "Explorative Fishers are tuskarr located in the Burning Ascent in the Waking Shores." },
  ["explorer abigail"] = { 2, "dwarf quest giver located at Westguard Keep in the Howlin...", "Explorer Abagail is a dwarf quest giver located at Westguard Keep in the Howling Fjord." },
  ["explorer bisbi"] = { 2, "goblin located in Nagrand", "Explorer Bisbi is a goblin located in Nagrand." },
  ["explorer ko'nali"] = { 2, "tuskarr located in Morqut Islet", "Explorer Ko'nali is a tuskarr located in Morqut Islet and the Caldera of the Menders in the Forbidden Reach. She is also seen in Morqut Village." },
  ["explorer mnyeh"] = { 2, "vulpera found with Truffles northwest of Shatterspear War...", "Explorer Mnyeh is a vulpera found with Truffles northwest of Shatterspear War Camp in Darkshore." },
  ["explorer to'noro"] = { 2, "tuskarr located in the Caldera of the Menders in the Forb...", "Explorer To'noro is a tuskarr located in the Caldera of the Menders in the Forbidden Reach. He is also seen in Morqut Village." },
  ["explorer's league surveyor (zuldazar)"] = { 2, "', "Explorer's League Surveyors are gnomes located in Zuldazar." },
  ["explorers' league archaeologist"] = { 2, "', "Explorers' League Archaeologists are dwarf and gnome members of the Explorers' League located near Prospector Murantus in Honor Hold in Hellfire Peninsula." },
  ["explorers' league excavator"] = { 2, "', "Explorers' League Excavators are dwarven and gnomish members of the Explorers' League located near Bloodwatcher Point in Badlands." },
  ["export hauler"] = { 2, "Veiled Market", "Export Haulers are brokers located in Tazavesh, the Veiled Market." },
  ["export specialist"] = { 2, "', "Export Specialists are brokers located at Transfer Station Ta in Bastion." },
  ["export supervisor"] = { 2, "Veiled Market", "Export Supervisors are brokers located in Tazavesh, the Veiled Market." },
  ["eyahn eagletalon"] = { 2, "tauren quest giver found at Camp Sungraze in Mulgore", "Eyahn Eagletalon is a tauren quest giver found at Camp Sungraze in Mulgore. Before Cataclysm he was found on the lower rise in Thunder Bluff." },
  ["eykenen"] = { 2, "Broken located at the Fel Pits in Shadowmoon Valley", "Eykenen is a Broken located at the Fel Pits in Shadowmoon Valley. He holds a medallion fragment." },
  ["eynar"] = { 2, "vrykul located at Jandvik in Suramar", "Eynar is a vrykul located at Jandvik in Suramar. He carries a large staff or polearm with a blue lightning effect on the end of it." },
  ["eyonix (npc)"] = { 2, "ethereal innkeeper located at the Stormspire in the Nethe...", "Eyonix is an ethereal innkeeper located at the Stormspire in the Netherstorm." },
  ["ez'haadosh the liminality"] = { 2, "ethereal", "Ez'Haadosh the Liminality was an ethereal who spawns during the final stage of a Twilight's Call at  in the Twilight Highlands." },
  ["ezgi irongear"] = { 2, "Arathi located in the Whirring Field in Hallowfall", "Ezgi Irongear is an Arathi located in the Whirring Field in Hallowfall." },
  ["ezra"] = { 2, "ankoan located in Deepsea Refuge in Nazjatar", "Ezra is an ankoan located in Deepsea Refuge in Nazjatar." },
  ["ezra grimm"] = { 2, "undead found in Stratholme", "Ezra Grimm is an undead found in Stratholme." },
  ["ezraw fiercefyre"] = { 2, "human located in Hallowfall", "Ezraw Fiercefyre is a human located in Hallowfall." },
  ["faala"] = { 2, "tauren follower located at Frostwall in Frostfire Ridge", "Faala is a tauren follower located at Frostwall in Frostfire Ridge. She can only be recruited using the Headhunter's Harvest from Frostwall Tavern." },
  ["face"] = { 2, "elite gnome", "Face is an elite gnome and member of the G-Team, a small group within S.A.F.E." },
  ["facebreaker"] = { 2, "gnoll located in the Azure Span", "Facebreaker is a gnoll located in the Azure Span." },
  ["facilitator ta'lek"] = { 2, "broker located in the Hall of Shapes in Oribos", "Facilitator Ta'lek was a broker located in the Hall of Shapes in Oribos." },
  ["fading vestige"] = { 2, "', "Fading Vestiges are kyrian memories located on the roads of Bastion during  [60 Daily] A Somber Melody." },
  ["faedra ambershade"] = { 2, "', "The sinstone of Faedra Ambershade is found in Revendreth in the upper level of the Catacombs of Regret, to the right of the entrance of the tower located there, belonging to a night elf who died during the War of the Shifting Sands." },
  ["faeflayer"] = { 2, "Drust located in a cave behind a waterfall in the Shroude...", "Faeflayer is a Drust located in a cave behind a waterfall in the Shrouded Mire in Ardenweald." },
  ["faerin lothar"] = { 2, "Lamplighter of the Hallowfall Arathi", "Faerin Lothar (/ˈfeɪ.rɪn/ FAY-rin) is a Lamplighter of the Hallowfall Arathi. A member of the noble Lothar family, she stowed away on the Hallowfall Expedition as a child." },
  ["faerley"] = { 2, "Arathi located in Lightspark in Hallowfall", "Faerley is an Arathi located in Lightspark in Hallowfall. He and Caerin are studying with Edwyn Wyndsmithe." },
  ["faerley kragsland"] = { 2, "Arathi located in Wildcamp Or'lay in Azj-Kahet", "Faerley Kragsland is an Arathi located in Wildcamp Or'lay in Azj-Kahet." },
  ["failed aspirant"] = { 2, "', "Failed Aspirants are ethereals located in the Archival Assault delve." },
  ["failed convert"] = { 2, "', "Failed Converts are fel-corrupted Broken located in Krokuun. Three of them lay dead by a Shademistress in the High Inquisitor's Lair, near the entrance." },
  ["failed novice"] = { 2, "', "Failed Novices are found in the Season of Discovery Karazhan Crypts dungeon." },
  ["failed scalecommander abereth"] = { 2, "dracthyr located on Dragonskull Island in the Forbidden R...", "Failed Scalecommander Abereth is a dracthyr located on Dragonskull Island in the Forbidden Reach. He was once a promising young dracthyr, but was assassinated on Neltharion's order for unknown reasons." },
  ["failed scalecommander elarthresh"] = { 2, "dracthyr located on Dragonskull Island in the Forbidden R...", "Failed Scalecommander Elarthresh is a dracthyr located on Dragonskull Island in the Forbidden Reach." },
  ["failed scalecommander haerothal"] = { 2, "dracthyr located on Dragonskull Island in the Forbidden R...", "Failed Scalecommander Haerothal is a dracthyr located on Dragonskull Island in the Forbidden Reach." },
  ["failed supplicant"] = { 2, "', "Failed Supplicants are humans, orcs, dwarves, and gnomes located at Doom's Vigil in Mount Hyjal." },
  ["faithful of zirix"] = { 2, "', "Faithful of Zirix are nerubians located in Sunrise Shadow on the Isle of Dorn. They serve Queensguard Zirix." },
  ["fala fizzlesprocket"] = { 2, "character in the story A Very Smokywood Winter Veil told ...", "Fala Fizzlesprocket is a character in the story A Very Smokywood Winter Veil told by Wulmort Jinglepocket during the Smokywood Storytime. She has a robot pet called Bolts." },
  ["falcon atherton"] = { 2, "worgen located at the Amphitheater of Annihilation in Ashran", "Falcon Atherton is a worgen located at the Amphitheater of Annihilation in Ashran." },
  ["faldir"] = { 2, "human of Strom", "Faldir was a human of Strom and one of the last members of Thoradin's line to dwell in Arathor, circa 1,200 BDP. Following the gradual fracturing of Arathor into independent kingdoms and the departure of Strom's noble families from the capital, Fa..." },
  ["fallacious aspirant"] = { 2, "', "Fallacious Aspirants are kyrian located at the Citadel of Loyalty in Bastion." },
  ["fallen acolyte erisne"] = { 2, "Forsworn kyrian located at the Temple of Purity in Bastion", "Fallen Acolyte Erisne is a Forsworn kyrian located at the Temple of Purity in Bastion. In life she was tormented by a man'ari eredar, and these memories caused her to fail the rite of passage." },
  ["fallen armsman"] = { 2, "', "Fallen Armsmen are deceased worgen located in Val'sharah, encountered during the Legion Assaults." },
  ["fallen aspirant"] = { 2, "', "Fallen Aspirants are fallen kyrians located in the Temple of Purity, in Bastion, before the quest  [10-53] Step Back From That Ledge, My Friend." },
  ["fallen champion"] = { 2, "undead rare mob found in the Graveyard wing of the Scarle...", "The Fallen Champion is an undead rare mob found in the Graveyard wing of the Scarlet Monastery. Aside from the tabard, he uses the same armor and weapon as the living Scarlet Champions." },
  ["fallen cleric"] = { 2, "', "Fallen Clerics are deceased worgen located in Val'sharah, encountered during the Legion Assaults." },
  ["fallen cultist"] = { 2, "', "Fallen Cultists are deceased members of the Twilight's Hammer located at the Gates of Sothann in Mount Hyjal." },
  ["fallen defender (drustvar)"] = { 2, "', "Fallen Defenders are Drust skeletons located in Drustvar." },
  ["fallen druid"] = { 2, "', "Fallen Druids are druids of the Cenarion Expedition killed by one of Kael'thas Sunstrider's mana bombs detonated within the Cenarion Thicket of Terokkar Forest." },
  ["fallen earthen defender"] = { 2, "', "Fallen Earthen Defenders are injured earthen who need to be healed by a  [Telluric Poultice], doing this will turn them into a Rejuvenated Defender, acting as a guardian." },
  ["fallen earthen warrior"] = { 2, "earthen", "The Fallen Earthen Warrior is a earthen who is apart of Kurun's forces and can be located at the plaza of Thor Modan in the Grizzly Hills. After being severely wounded, he is found by adventurers when he is inches away from death." },
  ["fallen feralheart"] = { 2, "', "Fallen Feralhearts are deceased worgen located in Val'sharah, encountered during the Legion Assaults." },
  ["fallen guardian of the dream"] = { 2, "', "Fallen Guardians of the Dream are druids found in Malorne's Nightmare." },
  ["fallen hero's spirit"] = { 2, "', "Fallen Hero's Spirits are ghosts found in Icecrown. They can have a variety of appearances and can be converted to the Scourge by Scourge Converters." },
  ["fallen huntmaster"] = { 2, "', "Fallen Huntmasters are deceased worgen located in Val'sharah, encountered during the Legion Assaults." },
  ["fallen iskaara tuskarr"] = { 2, "', "Fallen Iskaara Tuskarr are dead tuskarr located in Brackenhide Outskirts in the Azure Span." },
  ["fallen jarl"] = { 2, "vrykul located in Stormheim", "Fallen Jarl is a vrykul located in Stormheim." },
  ["fallen keeper"] = { 2, "', "Fallen Keepers are Drust skeletons located in Gol Thovas." },
  ["fallen knowledge-seeker"] = { 2, "', "Fallen Knowledge-Seekers are Forsworn kyrian located at the Temple of Humility in Bastion." },
  ["fallen praetorian"] = { 2, "undead found in the Pit of Criminals in the Karazhan Crypts", "The Fallen Praetorian is an undead found in the Pit of Criminals in the Karazhan Crypts." },
  ["fallen priestess (tomb of sargeras)"] = { 2, "', "Fallen Priestesses are night elves located in the Befouled Sanctum in the Tomb of Sargeras." },
  ["fallen priestess (satyr)"] = { 2, "ghost of a hateful satyr located in Felblaze Ingress She ...", "The Fallen Priestess is a ghost of a hateful satyr located in Felblaze Ingress She was originally a night elf known as Priestess Driana. After being assisted by the class order leader in killing demons, she is transformed to her original form at t..." },
  ["fallen shieldwall soldier"] = { 2, "', "Fallen Shieldwall Soldiers can be found at Bilgewater Beach in Krasarang Wilds." },
  ["fallen shotgunner"] = { 2, "', "Fallen Shotgunners are dead worgen located in Val'sharah, encountered during the Legion Assaults." },
  ["fallen zandalari"] = { 2, "', "Fallen Zandalari are undead Zandalari summoned by the tier 15 frost/unholy death knight set." },
  ["fallen-king salhadaar"] = { 2, "boss in Voidspire", "Fallen-King Salhadaar is a boss in Voidspire." },
  ["fallenroot hellcaller"] = { 2, "', "Fallenroot Hellcallers are satyrs found in the Pool of Ask'ar and Moonshrine Ruins of Blackfathom Deeps." },
  ["fallenroot poacher"] = { 2, "satyr", "Fallenroot Poacher is a satyr that spawns when casting  [Hunter's Mark] on the Rustling Bush in Teldrassil." },
  ["fallenroot rogue"] = { 2, "', "Fallenroot Rogues were satyrs that were once found in the tunnels leading to the entrance of Blackfathom Deeps." },
  ["fallenroot satyr"] = { 2, "', "Fallenroot Satyrs are satyrs found in the tunnels leading to the entrance of Blackfathom Deeps." },
  ["fallenroot shadowstalker"] = { 2, "', "Fallenroot Shadowstalkers are satyrs found in the Pool of Ask'ar and Moonshrine Ruins of Blackfathom Deeps." },
  ["falric (cycle of hatred)"] = { 2, "', "Falric was amongst the five mage students of Magna Scavell. As the others, he also was against Aegwynn becoming the next Guardian." },
  ["faltora"] = { 2, "younger brother of Koltira Deathweaver", "Faltora was the younger brother of Koltira Deathweaver. He wanted to ask Merriel to attend a banquet with him, but was a little shy." },
  ["falwulf"] = { 2, "', "Falwulf was one of the dwarves under Rom's command. He accompanied him on a mission to Grim Batol." },
  ["famished broken"] = { 2, "', "Famished Broken are voidscarred Broken located in the Seat of the Triumvirate." },
  ["fanatical conjuror"] = { 2, "', "Fanatical Conjurors are Arathi located at the Sanctified Grounds in the Priory of the Sacred Flame." },
  ["fanatical lackey"] = { 2, "Waking City", "Fanatical Lackeys are goblins and gnomes located in Ny'alotha, the Waking City." },
  ["fang'gar"] = { 2, "companion of Jaruk Bloodfyre", "Fang'gar was the companion of Jaruk Bloodfyre. When Jaruk and Leena escaped to Zangarmarsh, Fang'gar found them and remained with them." },
  ["fanghorn"] = { 2, "tauren member of the Twilight's Hammer", "Fanghorn was a tauren member of the Twilight's Hammer. He was a part of the group assisting Garona Halforcen in ruining the peace treaty between the Horde and the Alliance." },
  ["fantei"] = { 2, "Broken reagent vendor located at the Lower City market in...", "Fantei is a Broken reagent vendor located at the Lower City market in Shattrath City." },
  ["fara (castle nathria)"] = { 2, "venthyr located in the Purloined Stores in Castle Nathria", "Fara is a venthyr located in the Purloined Stores in Castle Nathria." },
  ["fara boltbreaker"] = { 2, "primary reporter for the Gadgetzan Times", "Fara Boltbreaker is a primary reporter for the Gadgetzan Times, having had stories featured in the first two issues. Little is known about her personal life or even what she looks like." },
  ["farand"] = { 2, "Wildhammer dwarf during the Second War", "Farand was a Wildhammer dwarf during the Second War. He and his thane, Kurdran Wildhammer, were the first to notice the orcs in the Hinterlands after their retreat from Hillsbrad." },
  ["farena"] = { 2, "ethereal located in Shan'dorah in K'aresh", "Farena is a ethereal located in Shan'dorah in K'aresh." },
  ["fari"] = { 2, "vulpera located at the Serene Dreams Spa in Thaldraszus", "Fari is a vulpera located at the Serene Dreams Spa in Thaldraszus." },
  ["farkigos"] = { 2, "blue dragon", "Farkigos was a blue dragon who was killed in a magical accident. His name is on a Fresh Gravestone at the Veiled Ossuary." },
  ["farmer dokaan"] = { 2, "draenei located at the Embaari Village in Shadowmoon Valley", "Farmer Dokaan is a draenei located at the Embaari Village in Shadowmoon Valley." },
  ["faronn dustwalker"] = { 2, "flightmaster in the Druids of the Talon camp in Skysea Ri...", "Faronn Dustwalker is the flightmaster in the Druids of the Talon camp in Skysea Ridge in Gorgrond." },
  ["farrier jalka"] = { 2, "centaur located at Serene Dreams Spa in the Thaldraszus", "Farrier Jalka is a centaur located at Serene Dreams Spa in the Thaldraszus. She is seen on the hooves of a centaur Spa Guest." },
  ["farrier josu"] = { 2, "centaur blacksmithing trainer", "Farrier Josu is a centaur blacksmithing trainer and vendor located in Maruukai in the Ohn'ahran Plains." },
  ["farrier nuella"] = { 2, "centaur located at Teerakai in the Ohn'ahran Plains", "Farrier Nuella is a centaur located at Teerakai in the Ohn'ahran Plains." },
  ["farrier rondare"] = { 2, "centaur vendor located in Maruukai in the Ohn'ahran Plains", "Farrier Rondare is a centaur vendor located in Maruukai in the Ohn'ahran Plains. When the dead body of an unnamed khanam dochra was discovered during an excavation in the riverbed near Maruukai, she was one of the centaur informed." },
  ["farrier roscha"] = { 2, "centaur blacksmithing vendor", "Farrier Roscha is a centaur blacksmithing vendor and quest giver tending the forge at Timberstep Outpost in the Ohn'ahran Plains. She has toiled endlessly to prepare the Shikaar caravan's journey to Maruukai, only for her supplies to be stolen by ..." },
  ["farrier tsarine"] = { 2, "centaur vendor located in the Field of Ferocity in the Oh...", "Farrier Tsarine is a centaur vendor located in the Field of Ferocity in the Ohn'ahran Plains." },
  ["farrier uugan"] = { 2, "centaur located at Teerakai in the Ohn'ahran Plains", "Farrier Uugan is a centaur located at Teerakai in the Ohn'ahran Plains." },
  ["farrol"] = { 2, "human rider", "Farrol was a human rider who Danath Trollbane chose to take with him along with half of the military in Stormwind City to the Dark Portal. He was very young for he never participated in the Second War or fought an orc in his life." },
  ["farscale ambusher"] = { 2, "', "Farscale Ambushers are naga located in the Forbidden Reach. They appear near Morqut Islet during  [70] Driftwood Derby." },
  ["farscale hunter"] = { 2, "', "Farscale Hunters are naga located in the Forbidden Reach." },
  ["farscale myrmidon"] = { 2, "', "Farscale Myrmidons are naga located in the Forbidden Reach." },
  ["farscale overseer"] = { 2, "naga located in the Forbidden Reach", "Farscale Overseer is a naga located in the Forbidden Reach." },
  ["farscale raider"] = { 2, "', "Farscale Raiders are naga located in the Forbidden Reach." },
  ["farscale siren"] = { 2, "', "Farscale Sirens are naga located in the Forbidden Reach." },
  ["farscale skirmisher"] = { 2, "', "Farscale Skirmishers are naga located in the Forbidden Reach." },
  ["farscale witch"] = { 2, "', "Farscale Witches are naga located in the Forbidden Reach." },
  ["farseer eannu"] = { 2, "shaman of Earthen Ring located on the northern side of th...", "Farseer Eannu is a  shaman of Earthen Ring located on the northern side of the Great Forge in Ironforge." },
  ["farseer nobundo"] = { 2, "Broken shaman farseer", "Farseer Nobundo is a Broken shaman farseer. One of the most tragic heroes among the Broken of Outland, Nobundo was formerly a draenei vindicator but lost the ability to call upon the Light during the fall of Shattrath City and was deformed by the ..." },
  ["farseer ori"] = { 2, "powerful ankoan shaman located in Nazjatar", "Farseer Ori is a powerful ankoan shaman located in Nazjatar. He is respected by his clan as spiritual guide and seer." },
  ["farseer tooranu"] = { 2, "Broken shaman member of the Earthen Ring located in Grim ...", "Farseer Tooranu is a Broken shaman member of the Earthen Ring located in Grim Batol. He requests that Drahga Shadowburner be killed and the  [Missive to Cho'gall] be brought to him." },
  ["farson hold prisoner"] = { 2, "', "Farson Hold Prisoners are tauren, gnomes, goblins, and night elves located in Farson Hold in Tol Barad Peninsula." },
  ["faruu"] = { 2, "broker located at Pilgrim's Grace in Zereth Mortis", "Faruu is a broker located at Pilgrim's Grace in Zereth Mortis. He is mentioned in the Unattended Books in Haven." },
  ["farwatcher guardian"] = { 2, "', "Farwatcher Guardians are the guards at Farwatcher's Glen in Stonetalon Mountains." },
  ["fata the soulflayer"] = { 2, "venthyr located at the Halls of Atonement in Revendreth", "Fata the Soulflayer is a venthyr located at the Halls of Atonement in Revendreth. He is draining anima from Abused Souls." },
  ["fate-twister seress"] = { 2, "arakkoa found in Stormshield on Ashran", "Fate-Twister Seress is an arakkoa found in Stormshield on Ashran. He sells  [Seal of Tempered Fate] for 300 golds." },
  ["fate-twister tiklal"] = { 2, "arakkoa found in Warspear in Ashran", "Fate-Twister Tiklal is an arakkoa found in Warspear in Ashran. He sells  [Seal of Tempered Fate] for 300 golds." },
  ["fathom-caller azrajar"] = { 2, "', "Fathom-Caller Azrajar is naga that first appears in the Shimmering Expanse as a memory. He was fighting the Kvaldir until his Mistress called him back." },
  ["fathom-commander eksis"] = { 2, "naga located in Eksis' Lair near the Ruins of Nar'thalas ...", "Fathom-Commander Eksis is a naga located in Eksis' Lair near the Ruins of Nar'thalas in Azsuna. He is a commander responsible for slaying many of the night elves before retreating into shadows and commanding his naga troops from the cave." },
  ["fathom-guard caribdis"] = { 2, "naga found in Serpentshrine Cavern", "Fathom-Guard Caribdis is a naga found in Serpentshrine Cavern. She is part of the Fathom-Lord Karathress encounter." },
  ["fathom-guard sharkkis"] = { 2, "', "Fathom-Guard Sharkkis can be found in Serpentshrine Cavern. He is part of the Fathom-Lord Karathress encounter." },
  ["fathom-guard tidalvess"] = { 2, "', "Fathom-Guard Tidalvess can be found in Serpentshrine Cavern. He is part of the Fathom-Lord Karathress encounter." },
  ["fathom-lord heth'jatar"] = { 2, "naga located in the Twilight Highlands north-west of the ...", "Fathom-Lord Heth'Jatar is a naga located in the Twilight Highlands north-west of the Dragonmaw Port. He is leading the attack against the Horde and is the leader of the Blackscale naga." },
  ["fathom-lord karathress"] = { 2, "battle for survival which is made much easier by high DPS", "Fathom-Lord Karathress can be found in Serpentshrine Cavern and is usually killed as the fourth boss. The fight involves several adds (similar to High King Maulgar), and is a battle for survival which is made much easier by high DPS. After killing..." },
  ["fathom-stalker azjentus"] = { 2, "naga", "Fathom-Stalker Azjentus is a naga that appears during the Naz'jar Battlemaiden vision." },
  ["favored citizen"] = { 2, "', "Favored Citizens are nerubians located at the High Hollows in the City of Threads." },
  ["favored citizen (venthyr)"] = { 2, "', "Favored Citizens are venthyr." },
  ["favra bearhide"] = { 2, "orc follower located at Frostwall in Frostfire Ridge", "Favra Bearhide is an orc follower located at Frostwall in Frostfire Ridge. She can be recruited from the Frostwall Tavern building via Akanja." },
  ["fawne"] = { 2, "tauren follower located at Frostwall in Frostfire Ridge", "Fawne is a tauren follower located at Frostwall in Frostfire Ridge. She can only be recruited using the Headhunter's Harvest from Frostwall Tavern." },
  ["fawnia landkeep"] = { 2, "dead Arathi located in Siegehold in Azj-Kahet", "Fawnia Landkeep is a dead Arathi located in Siegehold in Azj-Kahet." },
  ["fayla fairfeather"] = { 2, "tauren located at the Trading Post in Frostwall", "Fayla Fairfeather is a tauren located at the Trading Post in Frostwall. She trades 5 reagents (herb, ore or skin with specifing reagent changing each day) for 30  [Garrison Resources]." },
  ["fe'tajid"] = { 2, "broker located at the Gilded Landing in Tazavesh", "Fe'tajid is a broker located at the Gilded Landing in Tazavesh, the Veiled Market on Mythic difficulty. He is a business associate of Au'manal and claims to be the best bounty hunter in Cartel Fe." },
  ["fear-driven brute"] = { 2, "', "Fear-Driven Brutes are mantid located at Stoneplow Fields in the Valley of the Four Winds." },
  ["feasting venthyr"] = { 2, "', "Feasting Venthyr are venthyr located in Castle Nathria." },
  ["featherbeard"] = { 2, "honored Wildhammer dwarf", "Featherbeard was an honored Wildhammer dwarf who was a gryphon breeder and trainer. He lived in Featherbeard's Hovel." },
  ["fedfennel"] = { 2, "rare gnoll", "Fedfennel is a rare gnoll who can be found at the gnoll camps northwest of Stone Cairn Lake in Elwynn Forest." },
  ["fedli caskcheer"] = { 2, "dwarf food", "Fedli Caskcheer is a dwarf food and drink vendor located in the small camp of Gunstan's Dig in Tanaris." },
  ["feeboz"] = { 2, "kobold found following the mountain giant Fozruk in the A...", "Feeboz is a kobold found following the mountain giant Fozruk in the Arathi Highlands. As of Battle for Azeroth, he now follows his son, also named Fozruk." },
  ["feenix arcshine"] = { 2, "goblin mage trainer located in the Barracks in Orgrimmar", "Feenix Arcshine is a goblin mage trainer located in the Barracks in Orgrimmar." },
  ["feffick blindside"] = { 2, "goblin vendor located at Slam Central Station in the Unde...", "Feffick Blindside is a goblin vendor located at Slam Central Station in the Undermine. He can be found selling his products to a pair of Impatient Travellers." },
  ["fel cannoneer"] = { 2, "', "Fel Cannoneers are ogres located in Talador." },
  ["fel corrupter"] = { 2, "objective of  [20-30] Culling the Wild", "Fel Corrupters are servants of the Burning Legion who can be found in Blade's Edge Mountains. Killing them is the objective of  [20-30] Culling the Wild." },
  ["fel seer"] = { 2, "', "Fel Seers are ogres located in Talador." },
  ["fel-caller guloto"] = { 2, "Broken warlock trainer in the Terrace of Light in Shattra...", "Fel-Caller Guloto is a Broken warlock trainer in the Terrace of Light in Shattrath City. This section concerns content related to Dragonflight." },
