  ["fel-poisoned initiate"] = { 2, "', "Fel-Poisoned Initiates are monks located on the Wandering Isle." },
  ["fel-touched shu'halo"] = { 2, "', "Fel-Touched Shu'halo are tauren located in Tyrhold Reservoir in Thaldraszus during Time Rifts." },
