  ["felskorn zealot"] = { 2, "', "Felskorn Zealots are fel-corrupted vrykul located at the Gates of Valor and Felskorn Warcamp in Stormheim and in the Garrison of the Fel on the Broken Shore." },
  ["felsoul captive"] = { 2, "', "Felsoul Captives are nightfallen, night elves, and tauren located in Felsoul Hold in Suramar." },
  ["felsoul hold escapee"] = { 2, "', "Felsoul Hold Escapees are injured individuals located in Suramar." },
  ["felstorm corruptor"] = { 2, "', "Felstorm Corruptors were servants of the Burning Legion that used to spawn at Felstorm Point in Blade's Edge Mountains. Insidious Familiars were their minions." },
  ["felsurge defender"] = { 2, "', "Felsurge Defenders are naga located at the Felrage Strand on the Broken Shore. They were originally Deepsurge Defenders, empowered with fel by Harrowing Corruptors." },
  ["felsurge tidesinger"] = { 2, "', "Felsurge Tidesingers are naga located at the Felrage Strand on the Broken Shore. They were originally Deepsurge Tidesingers, empowered with fel by Harrowing Corruptors." },
  ["felsworn blood-talon"] = { 2, "', "Felsworn Blood-Talons are Shadow Council arakkoa located at the Ruins of Kra'nak in Tanaan Jungle." },
  ["felsworn infester"] = { 2, "', "Felsworn Infesters are satyrs located in the Chamber of Night and Warden's Court in the Vault of the Wardens." },
  ["felsworn myrmidon"] = { 2, "', "Felsworn Myrmidons are naga located in the Chamber of Night and Warden's Court in the Vault of the Wardens." },
  ["felsworn thunderer"] = { 2, "', "Felsworn Thunderers are Shadow Council arakkoa located at the Ruins of Kra'nak in Tanaan Jungle." },
  ["feltouched conjurer"] = { 2, "', "Feltouched Conjurers are satyrs located in Jaedenar in Felwood. Using  [Incanter's Tome] on their corpses frees Spectral Sentinels." },
  ["feltouched trickster"] = { 2, "', "Feltouched Tricksters are satyrs located in Jaedenar in Felwood. Using  [Incanter's Tome] on their corpses frees Spectral Sentinels." },
  ["felyae"] = { 2, "dwarf", "Felyae is a dwarf who took Li Li and Chen Stormstouts on her wagon and carried them through Tanaris. She compared the tol'vir to centaurs as they are just big cats instead of horses." },
  ["fen"] = { 2, "pandaren", "Fen is a pandaren that is either a friend or relative to Lorewalker Shuchun." },
  ["fenegan cobbler"] = { 2, "', "Fenegan Cobbler is initially a human stable master found in different places of Gilneas. This section concerns content related to Dragonflight." },
  ["fenistrasza"] = { 2, "red dragon", "Fenistrasza was a red dragon who died fighting the djaradin named Tarjin the Blind by holding her in a volcano for three days straight. Her skull would later be taken by the adventurers and given to the Dragonscale Expedition." },
  ["feno blastnoggin"] = { 2, "goblin quest giver located at the Northern Rocketway Term...", "Feno Blastnoggin is a goblin quest giver located at the Northern Rocketway Terminus in Azshara. He is the inventor of the  [Cryomatic 16]." },
  ["fenrae the cunning"] = { 2, "worgen located at Boralus Harbor in Boralus", "Fenrae the Cunning is a worgen located at Boralus Harbor in Boralus." },
  ["fenros"] = { 2, "rare mob worgen found wandering between the camps in Brig...", "Fenros is a rare mob worgen found wandering between the camps in Brightwood Grove in Duskwood. He is on a 5-8 hour respawn timer." },
  ["fenthwick"] = { 2, "gnome rogue trainer located in the Forlorn Cavern in Iron...", "Fenthwick is a gnome rogue trainer located in the Forlorn Cavern in Ironforge. This section concerns content related to Legion." },
  ["fently"] = { 2, "human", "Fently is a human who traveled with the Ashvane Trading Company expedition on the Maiden's Whisper to the Siren Isle. He was described as a brute." },
  ["fenwick thatros"] = { 2, "undead found near the Decrepit Fields in Silverpine Forest", "Fenwick Thatros is an undead found near the Decrepit Fields in Silverpine Forest. Varimathras believes Fenwick is the leader of the undead that have taken root in Silverpine Forest, although he proves to be just an underling to Thule Ravenclaw." },
  ["feral hulk"] = { 2, "', "Feral Hulks are worgen located on the Havenswood, Dread Chain, Rotting Mire, and Jorundall isles." },
  ["feral hungerer"] = { 2, "', "Feral Hungerers are worgen located on the Havenswood, Dread Chain, Rotting Mire, and Jorundall isles." },
  ["feral nightbane"] = { 2, "', "Feral Nightbanes are worgen located in Duskwood and Deadwind Pass." },
  ["feral scar (traveler)"] = { 2, "yeti", "Feral Scar is a yeti." },
  ["feral strangler"] = { 2, "', "Feral Stranglers are worgen located on the Havenswood, Dread Chain, Rotting Mire, and Jorundall isles." },
  ["feral watcher"] = { 2, "', "Feral Watchers are worgen found guarding the entrance to Tal'doren in the forest of Blackwald during the Worgen starting experience." },
  ["feral worgen"] = { 2, "', "Feral Worgen are worgen found in Tal'doren in the forest of Blackwald during the Worgen starting experience, and are standing around Lord Darius Crowley and several night elves." },
  ["feral worgen (val'sharah)"] = { 2, "', "Feral Worgen are worgen located in various parts of Val'sharah. Using the  [Scythe of Elune] will free them from their feral state." },
  ["ferdagor"] = { 2, "earthen located in the Ringing Deeps", "Ferdagor is an earthen located in the Ringing Deeps." },
  ["ferelyn bloodscorn"] = { 2, "blood elf member of the Argent Dawn", "Ferelyn Bloodscorn was a blood elf member of the Argent Dawn. He was the first to accept Darion Mograine's call for help in storming Naxxramas to rescue his father, Alexandros Mograine." },
  ["fergun"] = { 2, "Wildhammer dwarf gryphon rider", "Fergun is a Wildhammer dwarf gryphon rider. He was stationed at Allerian Stronghold, looking after Kurdran Wildhammer's gryphon after his presumed death." },
  ["ferli"] = { 2, "furbolg quest giver located in Timbermaw Hold in Felwood", "Ferli is a furbolg quest giver located in Timbermaw Hold in Felwood. She is first seen with her companion Drizle trying to convince adventurers to gather honey from inside the Totem of Ruumbo." },
  ["ferocious swiftclaw"] = { 2, "', "Ferocious Swiftclaws are worgen located in Darkshore during the Battle for Darkshore." },
  ["ferocitas the dream eater"] = { 2, "Gnarlpine furbolg found in Teldrassil", "Ferocitas the Dream Eater is a Gnarlpine furbolg found in Teldrassil, in the outskirts of Starbreeze Village. Ferocitas has an emerald stolen from Tallonkai Swiftroot's dreamcatcher." },
  ["feroz"] = { 2, "Enlightened broker from Pilgrim's Grace", "Feroz is an Enlightened broker from Pilgrim's Grace who aids in the Forging a New Path chapter of the Zereth Mortis campaign. Of the Enlightened in Pilgrim's Grace, he is the most knowledgeable about the Creation Catalyst." },
  ["fervent sharpshooter"] = { 2, "', "Fervent Sharpshooters are Arathi located at the Sanctified Grounds in the Priory of the Sacred Flame." },
  ["fervent stormcaller"] = { 2, "', "Fervent Stormcallers are vrykul attacking the Temple of Storms in the Storm Peaks with Thunderous Proto-Drakes during   [10-45] Never Hunt Alone." },
  ["festering assistant"] = { 2, "', "Festering Assistants are gnomes found on Alcaz Island in Dustwallow Marsh." },
  ["festering corpse"] = { 2, "', "Festering Corpse are dead members of the Argent Crusade located throughout the Fleshwerks in Icecrown." },
  ["festering corpse (radiant echoes)"] = { 2, "', "Festering Corpses are dead Argent Crusade member projections located in the Mirror of Dawn in the Dragonblight during the Radiant Echoes event." },
  ["festering gnoll"] = { 2, "gnoll located in the Azure Span", "Festering Gnoll is a gnoll located in the Azure Span." },
  ["festival challenger"] = { 2, "', "Festival Challengers are drogbar and niffen located in Glimmerogg in Zaralek Cavern." },
  ["festival flamekeeper"] = { 2, "', "Festival Flamekeepers were only available during the Midsummer Fire Festival. They come in male jungle troll, female tauren, female human, and male dwarf variants." },
  ["fetid bruiser"] = { 2, "', "Fetid Bruisers are gnolls located at the Fetid Encampment in Thaldraszus." },
  ["fetid muckbinder"] = { 2, "', "Fetid Muckbinders are gnolls located at the Fetid Encampment in Thaldraszus. They can be found empowering the Mucklings in the mud pools." },
  ["fetid slogger"] = { 2, "', "Fetid Sloggers are gnolls located at the Fetid Encampment in Thaldraszus. Some are found brawling with each other, while others pass the time throwing rocks at the Captured Prey." },
  ["fey-guardian baashia"] = { 2, "draenei located at the Draakorium in Shadowmoon Valley", "Fey-Guardian Baashia is a draenei located at the Draakorium in Shadowmoon Valley." },
  ["fey-guardian diunne"] = { 2, "draenei located at the Draakorium in Shadowmoon Valley", "Fey-Guardian Diunne is a draenei located at the Draakorium in Shadowmoon Valley." },
  ["fez crankblaze"] = { 2, "goblin vendor located in Hovel Hill in Undermine", "Fez Crankblaze is a goblin vendor located in Hovel Hill in Undermine." },
  ["fezhar"] = { 2, "orc warrior", "Fezhar was an orc warrior who fought alongside Broxigar to hold a mountain pass against the Burning Legion during the Battle of Mount Hyjal. His body was dissolved when a demon belched fel fire on him." },
  ["fezi cheapbucket"] = { 2, "goblin located in Proudmoore Academy in Boralus", "Fezi Cheapbucket is a goblin located in Proudmoore Academy in Boralus, south of Dead Man's Pass in Vol'dun, and the Sundered Span in Nazmir during the Faction Assaults. She is maintaining Crawler Mine Piles and is surrounded by Crawler Mines and S..." },
  ["field commander mahfuun"] = { 2, "Broken quest giver located inside Shadow Labyrinth", "Field Commander Mahfuun is a Broken quest giver located inside Shadow Labyrinth." },
  ["field marshal afrasiabi"] = { 2, "human field marshal located in the Valley of Heroes in St...", "Field Marshal Afrasiabi was a human field marshal located in the Valley of Heroes in Stormwind City. He was a ranking member of the Stormwind Army and was the quest-end NPC for the  [Head of Nefarian], after speaking to Varian Wrynn in Stormwind K..." },
  ["field marshal cogspark"] = { 2, "gnome located at Stormwind Keep in Stormwind City during ...", "Field Marshal Cogspark is a gnome located at Stormwind Keep in Stormwind City during the War of the Thorns. She holds the portal to Astranaar open during  [110] A Disturbance in Ashenvale." },
  ["field researcher alduuri"] = { 2, "draenei located in Shadowmoon Valley", "Field Researcher Alduuri is a draenei located in Shadowmoon Valley." },
  ["fieldmaster emberath"] = { 2, "dracthyr located in the Gladiator's Refuge in Valdrakken", "Fieldmaster Emberath is a dracthyr located in the Gladiator's Refuge in Valdrakken. He sells his goods in return for  [Bloody Tokens] and  [Rousing Ire]." },
  ["fiend of water"] = { 2, "', "Fiends of Water are found on the sides of the Amphitheater of Anguish in Zul'Drak. They appear during  [20-30G5] The Amphitheater of Anguish: From Beyond!" },
  ["fiery carver"] = { 2, "', "Fiery Carvers are located at Vakthros Range in the Azure Span." },
  ["fifi"] = { 2, "vulpera located at the Serene Dreams Spa in Thaldraszus", "Fifi is a vulpera located at the Serene Dreams Spa in Thaldraszus. She and Edward can be found having a good time with the members of the Untitled Band." },
  ["filigosa"] = { 2, "blue dragon", "Filigosa was a blue dragon who died from an unknown disease. Her name is on a Faded Gravestone at the Veiled Ossuary." },
  ["fillet, kneecapper extraordinaire"] = { 2, "gnomish warrior introduced in the third set of the World ...", "Fillet, Kneecapper Extraordinaire is a gnomish warrior introduced in the third set of the World of Warcraft Trading Card Game. He has yet to appear in any games." },
  ["fillius fizzlespinner"] = { 2, "gnome trade supplies vendor located in the Commons in Iro...", "Fillius Fizzlespinner is a gnome trade supplies vendor located in the Commons in Ironforge." },
  ["filliwick featherfizz"] = { 2, "gnome located in Farstrider Lodge in Loch Modan", "Filliwick Featherfizz is a gnome located in Farstrider Lodge in Loch Modan." },
  ["filora"] = { 2, "green drake", "Filora is a green drake and one of Lailastrasza's companions who fought alongside her against the djaradin." },
  ["fimble finespindle"] = { 2, "gnome leatherworking trainer located in the shop Finespin...", "Fimble Finespindle is a gnome leatherworking trainer located in the shop Finespindle's Leather Goods, on the north side of the Great Forge in Ironforge." },
  ["finder ta'sul"] = { 2, "broker located in the Broker's Den in Oribos", "Finder Ta'sul is a broker located in the Broker's Den in Oribos. He is interested in various items from Shadowlands' dangerous areas." },
  ["findorn"] = { 2, "earthen located in the Freywold Village inn", "Findorn is an earthen located in the Freywold Village inn, on the Isle of Dorn. After a nerubian attack, he was injured but then healed by Baelgrim." },
  ["finduin"] = { 2, "Alliance murloc companion given out to attendees for Bliz...", "Finduin is the Alliance murloc companion given out to attendees for BlizzCon 2019. It is modeled after Anduin Wrynn." },
  ["fingat"] = { 2, "rare mob murloc found in the Swamp of Sorrows", "Fingat is a rare mob murloc found in the Swamp of Sorrows. This murloc is much smaller than the others, about half the size." },
  ["fink fastneedle"] = { 2, "gnome located at Lunarfall in Shadowmoon Valley", "Fink Fastneedle is a gnome located at Lunarfall in Shadowmoon Valley. He can only be recruited using the Headhunter's Harvest from Lunarfall Inn." },
  ["finlay coolshot"] = { 2, "', "Finlay Coolshot runs the Tonk Challenge game at the Darkmoon Faire." },
  ["finna bjornsdottir"] = { 2, "vrykul chosen by Odyn", "Finna Bjornsdottir is a vrykul chosen by Odyn." },
  ["finning fury"] = { 2, "', "Finning Furies are murloc pilots found in Azmerloth. They pilot Murloc Hoppers and their squadron is led by Amrrgla Grglllhrrt." },
  ["fiona"] = { 2, "worgen quest giver in the Eastern Plaguelands in Lordaeron", "Fiona is a worgen quest giver in the Eastern Plaguelands in Lordaeron and later in Shadowmoon Valley on Draenor. She can be first found near the bridge to Western Plaguelands and at the entrance to the bog near the Draakorium." },
  ["fire eater"] = { 2, "', "Were you looking for the Horde's Flame Eater? Fire Eaters can be found in all zones that have an Alliance Bonfire in them during the Midsummer Fire Festival." },
  ["fire eater (darkmoon faire)"] = { 2, "', "Were you looking for the Midsummer Fire Festival NPCs by the same name, Fire Eaters? Fire Eaters are first encountered by players at the Darkmoon Faire portal in either Elwynn Forest or Mulgore, depending on your faction." },
  ["fire juggler"] = { 2, "', "Fire Jugglers are first encountered by players at the Darkmoon Faire portal in either Elwynn Forest or Mulgore, depending on your faction. Once in Darkmoon Island, they can be found throughout the Faire itself, entertaining guests by tossing fiery..." },
  ["fire golem"] = { 2, "creature created through the power of the Demon Soul", "A fire golem (aka golem of fire) was a creature created through the power of the Demon Soul. It was a humanoid figure with a flaming bone shape and burning skull for a head." },
  ["firegut brute"] = { 2, "', "Firegut Brutes are ogres that can be found in at Dreadmaul Rock in the Burning Steppes." },
  ["firegut captain"] = { 2, "ogre", "Firegut Captain is an ogre." },
  ["firegut ogre"] = { 2, "', "Firegut Ogres are ogres found at Dreadmaul Rock in the Burning Steppes." },
  ["firegut reaver"] = { 2, "', "Firegut Reavers are ogres located in Burning Steppes." },
  ["firim"] = { 2, "eccentric broker encountered in Zereth Mortis", "Firim (formerly Al'firim) is an eccentric broker encountered in Zereth Mortis. He was originally a member of Cartel Al and led an expedition to search for the Sepulcher of the First Ones, a mission that ended with his disappearance and the other b..." },
  ["firjus the soul crusher"] = { 2, "vrykul gladiator in the Ring of Judgement in the Howling ...", "Firjus the Soul Crusher is a vrykul gladiator in the Ring of Judgement in the Howling Fjord. He needs to be slain during  [10-30] Stunning Defeat at the Ring." },
  ["firmanvaar"] = { 2, "Broken shaman trainer located at the Crash Site in Azurem...", "Firmanvaar is a Broken shaman trainer located at the Crash Site in Azuremyst Isle." },
  ["first apprentice malkrex"] = { 2, "disciple of Surgeon Stitchflesh found working on the Soul...", "First Apprentice Malkrex is a disciple of Surgeon Stitchflesh found working on the Soulfused Construct with Sharrex the Fleshcrafter in the Flesh Stitchery in Maldraxxus." },
  ["first blade grimskarn"] = { 2, "worldsoul memory of a vrykul located in the Isle of Dorn ...", "First Blade Grimskarn is the worldsoul memory of a vrykul located in the Isle of Dorn during  [80] Worldsoul Memory: The Worldcarvers event." },
  ["first forgelite"] = { 2, "kyrian", "The First Forgelite was a kyrian who served as the first Forgelite Prime of Bastion. She wielded the hammer Phaestus, Genesis of Aeons, and was responsible for the creation of the first centurions and the Spires of Ascension, as well as the design..." },
  ["first mate billwix"] = { 2, "goblin located at the Shimmering Deep in Thousand Needles", "First Mate Billwix is a goblin located at the Shimmering Deep in Thousand Needles." },
  ["first mate cinderfuse"] = { 2, "dwarf located at Anyport in Drustvar", "First Mate Cinderfuse is a dwarf located at Anyport in Drustvar. She is a former pirate who hid a map in the area." },
  ["first mate hevish"] = { 2, "tuskarr located on the Old Belfyr in the Azure Span", "First Mate Hevish is a tuskarr located on the Old Belfyr in the Azure Span." },
  ["first mate shellshock"] = { 2, "tortollan located on the Siren Isle while  [80EWQ] Tides ...", "First Mate Shellshock is a tortollan located on the Siren Isle while  [80EWQ] Tides of Greed is active." },
  ["first mate snellig"] = { 2, "human ghost found in the Lost Fleet in the Wetlands", "First Mate Snellig is a human ghost found in the Lost Fleet in the Wetlands." },
  ["fish stix"] = { 2, "murloc trapped in the Gallagio during the Liberation of U...", "Fish Stix is a murloc trapped in the Gallagio during the Liberation of Undermine. Freeing him from his cement shoes is required for the  [Sleep with the Fishes] achievement." },
  ["fish-eye"] = { 2, "murloc appearing in series 4 of DC Direct's World of Warc...", "Fish-eye is a murloc appearing in series 4 of DC Direct's World of Warcraft action figures. He was part of a two-pack, also featuring Gibbergill." },
  ["fishcan"] = { 2, "kobold located in the Ringing Deeps", "Fishcan is a kobold located in the Ringing Deeps." },
  ["fisherman crow"] = { 2, "Forsaken with the Anglers located throughout Pandaria", "Fisherman Crow is a Forsaken with the Anglers located throughout Pandaria. His location changes daily with the location of special fishing pools noted by Ben of the Booming Voice." },
  ["fisherman pasqaa"] = { 2, "tuskarr located at Apex Canopy", "Fisherman Pasqaa is a tuskarr located at Apex Canopy and at the River Mouth Fishing Hole in the Waking Shores. He can be found talking to Shy Ino and Curious Lilu." },
  ["fishface"] = { 2, "gnoll located at Lost Kanniak in Brackenhide Hollow", "Fishface is a gnoll located at Lost Kanniak in Brackenhide Hollow." },
  ["fishfood"] = { 2, "gnome", "Fishfood is a gnome." },
  ["fishspeaker irtusk"] = { 2, "tuskarr summoned by  [Fishspeaker's Lucky Lure]", "Fishspeaker Irtusk is a tuskarr summoned by  [Fishspeaker's Lucky Lure]." },
  ["fix 'smallie' biggswrench"] = { 2, "gnome quest giver found at Lunarfall in Shadowmoon Valley", "Fix 'Smallie' Biggswrench is a gnome quest giver found at Lunarfall in Shadowmoon Valley. He helps the player add the Garrison Jukebox to their garrison." },
  ["fixer so'kir"] = { 2, "broker located in Dornogal during the Turbo Boost event o...", "Fixer So'kir is a broker located in Dornogal during the Turbo Boost event of patch 11.2.5. He ends the weekly quests  [80] Turbo-Boost: Trade Must Flow or  [80] Turbo-Boost: Infinite Growth and serves as the hero-track vendor." },
  ["fixer so'tho"] = { 2, "broker located in Dornogal during the Turbo Boost event o...", "Fixer So'tho is a broker located in Dornogal during the Turbo Boost event of patch 11.2.5. He serves as the Myth-track vendor." },
  ["fizim blastwrench"] = { 2, "goblin Arena battlemaster located on the Hunter Rise in T...", "Fizim Blastwrench was a goblin Arena battlemaster located on the Hunter Rise in Thunder Bluff." },
  ["fizit 'doc' clocktock"] = { 2, "gnome innkeeper located in Toshley's Station in the Blade...", "Fizit 'Doc' Clocktock is a gnome innkeeper located in Toshley's Station in the Blade's Edge Mountains." },
  ["fizzbizz coppercoil"] = { 2, "gnome located at the Mirage Raceway in Thousand Needles", "Fizzbizz Coppercoil is a gnome located at the Mirage Raceway in Thousand Needles." },
  ["fizzcrank airman"] = { 2, "', "Fizzcrank Airmen are gnome guards located at the Fizzcrank Airstrip in the Borean Tundra." },
  ["fizzcrank airstrip survivor"] = { 2, "', "Fizzcrank Airstrip Survivors are gnomes located at Fizzcrank Airstrip in the Borean Tundra." },
  ["fizzcrank anti-scourge cannon"] = { 2, "', "Fizzcrank Anti-Scourge Cannons are gnome-controlled cannons located in the Scalding Pools during the Heritage of Gnomeregan questline, fighting off Ironbound Troggs alongside Fizzcrank Airmen. Several abandoned and 'dead' cannons are also found sc..." },
  ["fizzcrank engineering crew"] = { 2, "', "Fizzcrank Engineering Crew are gnomes located at Fizzcrank Airstrip in the Borean Tundra." },
  ["fizzcrank fighter"] = { 2, "', "Fizzcrank Fighters are gnomes located at Fizzcrank Airstrip in the Borean Tundra." },
  ["fizzcrank paratrooper"] = { 2, "', "Fizzcrank Paratroopers are gnomes located at Fizzcrank Airstrip in the Borean Tundra." },
  ["fizzcrank pilot"] = { 2, "', "Fizzcrank Pilots are gnomes located at Fizzcrank Airstrip in the Borean Tundra." },
  ["fizzcrank recon pilot"] = { 2, "', "Fizzcrank Recon Pilots are deceased gnomes located in the Scalding Pools in the Borean Tundra." },
  ["fizzix blastbolt"] = { 2, "goblin engineering vendor located at the Argent Tournamen...", "Fizzix Blastbolt is a goblin engineering vendor located at the Argent Tournament Grounds in Icecrown. This section concerns content related to Shadowlands." },
  ["fizzle brassbolts"] = { 2, "gnome co-owner of the Speedbarge floating on the Shimmeri...", "Fizzle Brassbolts is a gnome co-owner of the Speedbarge floating on the Shimmering Deep of Thousand Needles. Pilot Longbeard is a friend of the Brassbolts." },
  ["fizzlebang booms"] = { 2, "gnome fireworks vendor located year-round at Tinker Town ...", "Fizzlebang Booms is a gnome fireworks vendor located year-round at Tinker Town in Ironforge. He is the owner of the Things That Go Boom!" },
  ["fizzsprings guide"] = { 2, "', "Fizzsprings Guides are gnomes located in Fizzsprings Resort in Tiragarde Sound." },
  ["fjolrik"] = { 2, "vrykul located at Jandvik in Suramar", "Fjolrik was a vrykul located at Jandvik in Suramar. When initially found inside of Muddledeep Cavern, he appears to be unconscious." },
  ["fjornson stonecarver"] = { 2, "vrykul of the Valarjar located in Skyhold", "Fjornson Stonecarver is a vrykul of the Valarjar located in Skyhold. He is the author of the Saga of the Valarjar." },
  ["flagglemurk the cruel"] = { 2, "rare mob murloc found roaming on the Mist's Edge beach in...", "Flagglemurk the Cruel is a rare mob murloc found roaming on the Mist's Edge beach in Darkshore. It is on a 2-3 hour respawn timer." },
  ["flagship sailor"] = { 2, "', "Flagship Sailors are human and worgen sailors located aboard the Stormy Pearl in Nazmir during Faction Assaults on Nazmir." },
  ["flame eater"] = { 2, "', "Were you looking for the Alliance's Fire Eater? The Flame Eater can be found in all zones that have an Horde Bonfire in them during the Midsummer Fire Festival." },
  ["flame guardian"] = { 2, "neutral NPC", "A Flame Guardian is a neutral NPC that watches over the bonfires throughout Azeroth, during the Midsummer Fire Festival. Each guardian is named after the zone they reside in (most of the time)." },
  ["flame keeper"] = { 2, "Horde NPC", "A Flame Keeper is a Horde NPC that watches over the Horde Bonfires throughout Azeroth, during the Midsummer Fire Festival. Each keeper is named after the zone they reside in (most of the time)." },
  ["flame warden"] = { 2, "Alliance NPC", "A Flame Warden is an Alliance NPC that watches over the Alliance Bonfires throughout Azeroth, during the Midsummer Fire Festival. Each warden is named after the zone they reside in (most of the time)." },
  ["flame's radiance recruiter"] = { 2, "Arathi located in Dornogal", "Flame's Radiance Recruiter is an Arathi located in Dornogal." },
  ["flamebound huntsman"] = { 2, "Shadowed Crucible", "Flamebound Huntsman are djaradin located in Aberrus, the Shadowed Crucible." },
  ["flamebreaker grella"] = { 2, "djaradin located in the Waking Shores", "Flamebreaker Grella is a djaradin located in the Waking Shores. She was part of a Qalashi war party seemingly heading for the Ruby Life Pools." },
  ["flamebringer elementalist (season of discovery)"] = { 2, "', "Flamebringer Elementalists are Twilight's Hammer cultists found in the northwest part of the Searing Gorge during the Blackrock Eruption event." },
  ["flamebringer rageblood"] = { 2, "', "Flamebringer Rageblood are tauren located in Suffusion Camp: Cinderwind in the Ohn'ahran Plains and in Suffusion Camp: Frostburn in the Azure Span during Fyrakk Assaults." },
  ["flamebringer stalker"] = { 2, "', "Flamebringer Stalkers are stealthed Twilight's Hammer cultists found around Thorium Point in the Searing Gorge during the Blackrock Eruption event. They can only be seen under the effects of  [Dreamjuice]." },
  ["flamecaller aymi"] = { 2, "dwarf located in the Intake Reservoirs in Halls of Infusion", "Flamecaller Aymi is a dwarf located in the Intake Reservoirs in Halls of Infusion." },
  ["flamekeeper graz"] = { 2, "dire swolbold located in Mourning Rise on the Isle of Dorn", "Flamekeeper Graz is a dire swolbold located in Mourning Rise on the Isle of Dorn." },
  ["flameshaper lorak"] = { 2, "djaradin located in Scalecracker Keep in the Waking Shores", "Flameshaper Lorak is a djaradin located in Scalecracker Keep in the Waking Shores. He leads an attack on the Uktulut tuskarr, and Guard Hakota asks adventurers to kill him." },
  ["flamesworn stonewarden"] = { 2, "', "Flamesworn Stonewardens are jungle trolls and tauren located at the Primalist Stronghold in the Emerald Dream. Some are followed by Dreambreaker Bedrocks." },
  ["flametender busa"] = { 2, "centaur tending the central cooking fire at Timberstep Ou...", "Flametender Busa is a centaur tending the central cooking fire at Timberstep Outpost in the Ohn'ahran Plains." },
  ["flaming bilgefin"] = { 2, "', "Flaming Bilgefins are murlocs that appear after burning Dry Timber in Morheim in Stormheim. They run around, burning, and drop dead." },
  ["flanking mogu"] = { 2, "mogu", "Flanking Mogu is a mogu." },
  ["flashback quilboar"] = { 2, "quilboar", "Flashback Quilboar is a quilboar." },
  ["flaska-torghast"] = { 2, "tauren located throughout Bastion", "The Flaska-Torghast is a tauren located throughout Bastion." },
  ["flaskantorus"] = { 2, "tauren", "Flaskantorus is a tauren that appears on the PTR. He is located in Dalaran." },
  ["flaskataur"] = { 2, "tauren", "Flaskataur is a tauren who appears on the PTR and beta realms to aid players. A female Flaskataur has also been spotted." },
  ["flaskzertauren"] = { 2, "tauren", "Flaskzertauren is a tauren that appeared on the PTR realms to aid players. He was located in the Great Seal of Dazar'alor for the Horde and Harbormaster's Office in Boralus for the Alliance to sell the new chest and shoulder pieces with the newest..." },
  ["flavor scientist"] = { 2, "', "Flavor Scientists are goblins and gnomes located in the Stills in Cinderbrew Meadery." },
  ["flayer au'khem"] = { 2, "broker located in the Hall of Shapes in Oribos", "Flayer Au'khem is a broker located in the Hall of Shapes in Oribos. He teaches Maw Walkers about Shadowlands Skinning techniques." },
  ["flayfist"] = { 2, "gnoll located in a cave in Brackenhide Waterhole in the A...", "Flayfist is a gnoll located in a cave in Brackenhide Waterhole in the Azure Span." },
  ["fledgling brave"] = { 2, "', "Fledgling Braves are tauren located in the Thornsnarl in Mulgore. They constantly fight the Bristleback Invaders to keep the quilboar from taking over the area." },
  ["fledgling druid"] = { 2, "', "Fledgling Druids are novice members of the Druids of the Talon found at the Sylvan Falls in Highmountain, listening to Instructor Allandria or spectating Alverian Valerias." },
  ["fledgling slasher"] = { 2, "', "Fledgling Slashers are gnolls located in Brackenhide Hollow." },
  ["fleeg"] = { 2, "furbolg located in Zul'Aman", "Fleeg is a furbolg located in Zul'Aman." },
  ["fleeing horde soldier"] = { 2, "', "Fleeing Horde Soldiers are orcs and tauren located in Kor'kron Vanguard in the Dragonblight." },
  ["fleeing zin'jatar fathom-stalker"] = { 2, "', "Fleeing Zin'jatar Fathom-Stalkers are naga located in the Shimmering Expanse. They are fleeing at the end of  [30-35] Fathom-Lord Zin'jatar under the orders of Fathom-Lord Zin'jatar." },
  ["fleeting memory"] = { 2, "', "Fleeting Memories are kyrian memories located on the roads of Bastion during  [60 Daily] A Somber Melody." },
  ["flesh crafter"] = { 2, "', "Flesh Crafters are undead located in the Stitchwerks in the Necrotic Wake." },
  ["flesh handler viridius"] = { 2, "ethereal quest giver found patrolling the Protectorate Wa...", "Flesh Handler Viridius is an ethereal quest giver found patrolling the Protectorate Watch Post in the Netherstorm." },
  ["fleshcrafter hoku"] = { 2, "mogu user of blood magic", "Fleshcrafter Hoku is a mogu user of blood magic." },
  ["fletcher nisekh"] = { 2, "centaur located in the Ohn'ahran Plains", "Fletcher Nisekh is a centaur located in the Ohn'ahran Plains. He is one of the few surviving members of Clan Toghus, having been rescued from the village of Daruukhan after it was destroyed by Clan Nokhud." },
  ["flickerwick"] = { 2, "kobold located on the expedition isles", "Flickerwick is a kobold located on the expedition isles." },
  ["flight captain waetson"] = { 2, "Arathi located in Lightspark in Hallowfall", "Flight Captain Waetson is an Arathi located in Lightspark in Hallowfall." },
  ["flight master's assistant"] = { 2, "centaur located next to Carseng in southern Teerakai in t...", "The Flight Master's Assistant is a centaur located next to Carseng in southern Teerakai in the Ohn'ahran Plains. Periodically, a Messenger Ohuna spawns and lands next to the assistant." },
  ["flight mechanic"] = { 2, "', "Flight Mechanics are gnomish engineers that are at the Ironforge Airfield and Kharanos during the Legion Invasions. They are working on maintaining gyrocopters and flying machines for the battle." },
  ["flight observer viktorina"] = { 2, "Arathi located in Lightspark in Hallowfall", "Flight Observer Viktorina is an Arathi located in Lightspark in Hallowfall." },
  ["flighted storm-spinner"] = { 2, "', "Flighted Storm-Spinners are arakkoa found at Skettis in the Spires of Arak." },
  ["flindersnik"] = { 2, "kobold located in the Chittering Den in the Ringing Deeps", "Flindersnik is a kobold located in the Chittering Den in the Ringing Deeps. He is a member of the Glumtooth Gang." },
  ["flint"] = { 2, "earthen located in Dornogal", "Flint is an earthen located in Dornogal and Siren Isle." },
  ["flint broadshot"] = { 2, "human hunter", "Flint Broadshot was a human hunter. One day he entered the Blue Recluse in Stormwind, seeking to buy ale for him and his friend." },
  ["flint oremantle"] = { 2, "', "Flint Oremantle, son of Stonefather Oremantle, is adventurers' first contact with the earthen of Deepholm. The quest chain that revolves around him ends with adventurers recovering the middle fragment of the World Pillar." },
  ["flizzy coilspanner"] = { 2, "goblin flight master located at Mossy Pile in the Un'Goro...", "Flizzy Coilspanner is a goblin flight master located at Mossy Pile in the Un'Goro Crater." },
  ["flllurlokkr"] = { 2, "murloc located in a cave at Stonefin Shoals on the Broken...", "Flllurlokkr is a murloc located in a cave at Stonefin Shoals on the Broken Shore." },
  ["flockmaster sergio"] = { 2, "venthyr located in the Grove of Terror in Revendreth", "Flockmaster Sergio is a venthyr located in the Grove of Terror in Revendreth." },
  ["floid mayslord"] = { 2, "Arathi located at Faerin's Advance in Azj-Kahet", "Floid Mayslord is an Arathi located at Faerin's Advance in Azj-Kahet. He's tending to the wounds of Breanni, Coira Longrifle, and Archivist Betha." },
  ["flops"] = { 2, "murloc located at the Winterfin Retreat in the Borean Tundra", "Flops is a murloc located at the Winterfin Retreat in the Borean Tundra." },
  ["flori"] = { 2, "earthen vendor located in Flotsam Shoal on the Siren Isle", "Flori is a earthen vendor located in Flotsam Shoal on the Siren Isle." },
  ["florin"] = { 2, "venthyr located in the Old Gate", "Florin is a venthyr located in the Old Gate and later in front of Thornhill Manor in Revendreth." },
  ["flrrgl's shaking shell"] = { 2, "transmog appearance for the back slot", "Flrrgl's Shaking Shell is a transmog appearance for the back slot, unlocked by purchasing or receiving the Baby Murloc Satch-Shells ensemble." },
  ["fluga the scalekeeper"] = { 2, "vrykul flight master located in Stormheim", "Fluga the Scalekeeper is a vrykul flight master located in Stormheim." },
  ["flying machine (warcraft iii)"] = { 2, "pilots of the flying machines are instead gnomes", "The ingenious dwarven engineers replaced their gyrocopters with upgraded flying machines during the events of The Frozen Throne. In Warcraft III: Reforged, the pilots of the flying machines are instead gnomes." },
  ["fobeed"] = { 2, "ogre located at the Mirage Raceway in Thousand Needles", "Fobeed was an ogre located at the Mirage Raceway in Thousand Needles. He has not been seen since the Cataclysm caused Thousand Needles to flood, so it is unknown if he moved or drowned." },
  ["focus wizard"] = { 2, "', "Focus Wizards  are mages located at the Glittering Strand in the Dragonblight. During the third invasion of the Burning Legion, they were killed." },
  ["focused ritualist"] = { 2, "Veiled Market", "Focused Ritualists are brokers located in Tazavesh, the Veiled Market." },
  ["fonkey kaang (rumble)"] = { 2, "unique ranged ground unit used during the Dockmaster miss...", "Fonkey Kaang is a unique ranged ground unit used during the Dockmaster mission on heroic difficulty. During this mission, Dockey Kaang and Fonkey Kaang spawn near the Dockmaster, one at each lane, tossing barrels down them that deal heavy AoE damage." },
  ["fontane"] = { 2, "human of the Stromgarde Militia", "Fontane was a human of the Stromgarde Militia who fought against the Syndicate in Arathi Highlands. He fell and his badge was taken by his killer, kept as a trophy until its retrieval by hired adventurers." },
  ["foosa"] = { 2, "tortollan located in Stormsong Valley", "Foosa is a tortollan located in Stormsong Valley." },
  ["fopreshin"] = { 2, "murloc", "Fopreshin is a murloc." },
  ["forager tensai"] = { 2, "centaur located in the Ohn'ahran Plains", "Forager Tensai is a centaur located in the Ohn'ahran Plains." },
  ["forbidden dissector"] = { 2, "', "Forbidden Dissectors are venthyr located in Revendreth." },
