  ["forbidden trapper"] = { 2, "', "Forbidden Trappers are venthyr located in Revendreth." },
  ["foreman arbauch"] = { 2, "deceased earthen located in the Ringing Deeps", "Foreman Arbauch is a deceased earthen located in the Ringing Deeps." },
  ["foreman au'brak"] = { 2, "broker located in the Hall of Shapes in Oribos", "Foreman Au'brak is a broker located in the Hall of Shapes in Oribos. She oversees the Cartel Au brokers in the hall." },
  ["foreman azap"] = { 2, "earthen", "Foreman Azap is an earthen that used to be located in the Foundation Hall in Dornogal." },
  ["foreman bentscale"] = { 2, "goblin located in the Abyssal Excavation in the Ringing D...", "Foreman Bentscale is a goblin located in the Abyssal Excavation in the Ringing Deeps during the  [80] Bat Versus World." },
  ["foreman biggums"] = { 2, "dwarf quest giver located at the entrance to Honor Hold M...", "Foreman Biggums is a dwarf quest giver located at the entrance to Honor Hold Mine in the Hellfire Peninsula. He was told by Danath to get back control of the mine from the gan'arg if he didn't want to lose his ale rations." },
  ["foreman brix"] = { 2, "goblin", "Foreman Brix is a goblin." },
  ["foreman bruknar"] = { 2, "earthen located in the Waterworks", "Foreman Bruknar is an earthen located in the Waterworks." },
  ["foreman bruntza"] = { 2, "orc located at the Iron Docks in Gorgrond", "Foreman Bruntza is an orc located at the Iron Docks in Gorgrond." },
  ["foreman cogbutton"] = { 2, "goblin located in Bleak Hills Mine in Drustvar", "Foreman Cogbutton is a goblin located in Bleak Hills Mine in Drustvar." },
  ["foreman cozzle"] = { 2, "Venture Company goblin found at the Venture Co", "Foreman Cozzle is a Venture Company goblin found at the Venture Co. Operations Center in Northern Stranglethorn." },
  ["foreman duinth"] = { 2, "earthen located at the Hallowfall Gate in the Ringing Deeps", "Foreman Duinth is an earthen located at the Hallowfall Gate in the Ringing Deeps and in Lothar's Landing in Hallowfall. When the problems at the gate arose and fire elementals attacked the earthen, she was concerned for her workers and asked adven..." },
  ["foreman dunaer"] = { 2, "draenei", "Foreman Dunaer is a draenei that can be found with Valon in the Crystal Hall of the Exodar, on the same platform where Farseer Nobundo stands. This section concerns content related to Legion." },
  ["foreman gesa"] = { 2, "earthen foreman located in the Earthenworks in the Ringin...", "Foreman Gesa is an earthen foreman located in the Earthenworks in the Ringing Deeps. She was approached by Speaker Brinthe for a key to the Hall of Awakening." },
  ["foreman grint"] = { 2, "earthen foreman located outside of Gundargaz in the Ringi...", "Foreman Grint is an earthen foreman located outside of Gundargaz in the Ringing Deeps. There he leads a group of Emergency Militia in the defense of the bridge east of Gundargaz against Invading Kobolds." },
  ["foreman jerris"] = { 2, "rare mob undead found south of Corin's Crossing in near L...", "Foreman Jerris is a rare mob undead found south of Corin's Crossing in near Lake Mereldar in the Eastern Plaguelands. Before the Cataclysm, he was located in Hearthglen as a human." },
  ["foreman marcrid"] = { 2, "rare undead human found near the coast of Lake Mereldar i...", "Foreman Marcrid is a rare undead human found near the coast of Lake Mereldar in the Eastern Plaguelands. Prior to the Cataclysm, Marcrid was alive and working at the Northridge Lumber Camp in the Western Plaguelands." },
  ["foreman otan"] = { 2, "earthen foreman located in the Earthenworks in the Ringin...", "Foreman Otan is an earthen foreman located in the Earthenworks in the Ringing Deeps. He was approached by Speaker Brinthe for a key to the Hall of Awakening." },
  ["foreman pernic"] = { 2, "worgen mining trainer located in the Craftsmen's Terrace ...", "Foreman Pernic is a worgen mining trainer located in the Craftsmen's Terrace in Darnassus. During the Burning of Teldrassil, he was seemingly evacuated with the civilians to Stormwind City." },
  ["foreman pivk"] = { 2, "earthen located in Earthcrawl Mines", "Foreman Pivk is an earthen located in Earthcrawl Mines." },
  ["foreman razorgnarl"] = { 2, "quilboar located at the Briarback Warrens in Stormsong Va...", "Foreman Razorgnarl is a quilboar located at the Briarback Warrens in Stormsong Valley." },
  ["foreman shalea"] = { 2, "earthen located in Gundargaz in the Ringing Deeps", "Foreman Shalea is an earthen located in Gundargaz in the Ringing Deeps. Along with the other Gundargaz Foremen, she oversees the work of nearby Gundargaz Laborers and Junction Welders." },
  ["foreman sharpsneer"] = { 2, "gnoll located at the Silver Stream Mine", "Foreman Sharpsneer is a gnoll located at the Silver Stream Mine. He is part of the Mosshide tribe and the foreman of the Silver Stream Mine." },
  ["foreman svart"] = { 2, "earthen located north of Gundargaz in the Ringing Deeps", "Foreman Svart is an earthen located north of Gundargaz in the Ringing Deeps." },
  ["foreman uzjax"] = { 2, "member of the Machine Speakers", "Foreman Uzjax is a member of the Machine Speakers. While initially a firm believer of High Speaker Eirich, he grew disillusioned with his leadership and aided Speaker Brinthe in deposing the corrupted High Speaker." },
  ["forge hand"] = { 2, "', "Forge Hands are earthen located in the Forgegrounds in Dornogal. One can be found next to the Incident Report near the stamper." },
  ["forge master damian"] = { 2, "Arathi located at Sanctified Grounds in the Priory of the...", "Forge Master Damian is an Arathi located at Sanctified Grounds in the Priory of the Sacred Flame." },
  ["forgebound mender"] = { 2, "', "Forgebound Menders are earthen located in the Stonevault." },
  ["forgegrounds machinesmith"] = { 2, "', "Forgegrounds Machinesmiths are earthen located in the Forgegrounds in Dornogal." },
  ["forgegrounds worker"] = { 2, "', "Forgegrounds Workers are earthen located in the Forgegrounds in Dornogal." },
  ["forgelite hephaesius"] = { 2, "Ascended kyrian located in the Seat of Eternal Hymns in B...", "Forgelite Hephaesius is an Ascended kyrian located in the Seat of Eternal Hymns in Bastion." },
  ["forgelite neptira"] = { 2, "Ascended kyrian located in the Sanctum of Binding in Bastion", "Forgelite Neptira is an Ascended kyrian located in the Sanctum of Binding in Bastion." },
  ["forgelite selene"] = { 2, "kyrian quest giver located in the Eternal Forge in Bastion", "Forgelite Selene is a kyrian quest giver located in the Eternal Forge in Bastion." },
  ["forgelite sophone"] = { 2, "kyrian located in Aspirant's Crucible in Bastion", "Forgelite Sophone is a kyrian located in Aspirant's Crucible in Bastion. She was the only aspirant forgelite before her ascension and had been put in charge of the Aspirant's Crucible because she had been there the longest." },
  ["forgemaster algrin"] = { 2, "djaradin located in Suffusion Camp: Frostburn in the Azur...", "Forgemaster Algrin is a djaradin located in Suffusion Camp: Frostburn in the Azure Span. A member of the Zaqali, he is subordinate to Igira, and is berated by her as the adventurers of the Alliance and Horde dismantle the Zaqali operation he leads." },
  ["forgemaster gog'duh"] = { 2, "geomancer of the Bloodmaul clan", "Forgemaster Gog'duh, alongside the elemental Magmolatus, is one of the first two bosses in Bloodmaul Slag Mines. He is a geomancer of the Bloodmaul clan." },
  ["forgemaster gorek"] = { 2, "boss in Neltharus", "Forgemaster Gorek is a boss in Neltharus." },
  ["forgemaster han"] = { 2, "Rajani mogu repairer", "Forgemaster Han is a Rajani mogu repairer and quest giver working at an anvil in the Silent Sanctuary in the Vale of Eternal Blossoms. He is their sole blacksmith." },
  ["forgemaster kraglin"] = { 2, "djaradin located in Suffusion Camp: Cinderwind in the Ohn...", "Forgemaster Kraglin is a djaradin located in Suffusion Camp: Cinderwind in the Ohn'ahran Plains.A member of the Zaqali, he is subordinate to Igira, and is berated by her as the adventurers of the Alliance and Horde dismantle the Zaqali operation h..." },
  ["forgemaster madalav"] = { 2, "venthyr located at Dominance Keep in Revendreth", "Forgemaster Madalav is a venthyr located at Dominance Keep in Revendreth. He can be summoned by members of the Venthyr Covenant after activating the Dominance Keep Anima Conductor." },
  ["forgemaster vul'kon"] = { 2, "boss of Stage 3", "Forgemaster Vul'kon appears inside a quest scenario that takes place in the Thunder Forges for the quest  [90] The Thunder Forge. He is the boss of Stage 3." },
  ["forgetful diner"] = { 2, "', "Forgetful Diners are located at the Vatworks in the Undermine." },
  ["forgeweaver araz"] = { 2, "boss in Manaforge Omega", "Forgeweaver Araz (/əˈɹɑːz/ ə-RAHZ) is a boss in Manaforge Omega." },
  ["forgol"] = { 2, "male shaman from the Krenka tribe of centaur", "Forgol is a male shaman from the Krenka tribe of centaur who live in the Barrens. After having a vision showing the final resting place of Krenka, the tribe founder, he resolved to find the remains and return them to his tribe." },
  ["forgotten crystal tender"] = { 2, "eredar located at Azurelight Square in Eredath", "The Forgotten Crystal Tender is an eredar located at Azurelight Square in Eredath. She seems to own a few Domesticated Marsuul." },
  ["forgotten dead"] = { 2, "', "Forgotten Dead are undead that have a chance to appear while raising corpses in the graveyard near Karazhan in Deadwind Pass during   [10-45] A Grisly Task." },
  ["forgotten denizen"] = { 2, "', "Forgotten Denizens are eredar located in Eredath. One of them own a Domesticated Chitinbuk." },
  ["forika the seer"] = { 2, "arakkoa located at the Aktar's Post in Tanaan Jungle", "Forika the Seer is an arakkoa located at the Aktar's Post in Tanaan Jungle." },
  ["forkriver guard"] = { 2, "', "Forkriver Guards are centaur located at Forkriver Crossing in the Ohn'ahran Plains." },
  ["forkriver trader"] = { 2, "', "Forkriver Traders are tuskarr, centaur, and drakonid located in Forkriver Crossing in the Ohn'ahran Plains and in Artisan's Market in Valdrakken." },
  ["foror"] = { 2, "person referenced in World of Warcraft by various items", "Foror was a person referenced in World of Warcraft by various items and characters." },
