  ["forsworn ascended"] = { 2, "', "Forsworn Ascended are Forsworn kyrian found in the Temple of Purity in Bastion after it is taken over by the Forsworn. Several more also appear in Purity's Pinnacle during  [10-53] The Enemy You Know." },
