  ["forsworn watcher"] = { 2, "', "Forsworn Watchers are kyrian located in Bastion." },
  ["forx"] = { 2, "seaman aboard the Horde trading ship Orath'ar serving und...", "Forx is the seaman aboard the Horde trading ship Orath'ar serving under Captain Bolik. During the attack by pirates, Forx repelled the attack and was rewarded by the captain with his full despite the lost cargo." },
  ["foul crusher"] = { 2, "', "Foul Crushers are Drust located in Darkreach in Ardenweald." },
  ["foulbelly"] = { 2, "rare ogre found standing to the right of the tower in the...", "Foulbelly is a rare ogre found standing to the right of the tower in the ogre quarter of Stromgarde Keep in the Arathi Highlands. He is on a 32 to 48 hour respawn timer." },
  ["foulweald den watcher"] = { 2, "', "Foulweald Den Watchers are furbolgs of the Foulweald tribe found in Greenpaw Village in Ashenvale." },
  ["foulweald shaman"] = { 2, "', "Foulweald Shaman are furbolgs found in Greenpaw Village in central Ashenvale. They are part of the Foulweald tribe." },
  ["foulweald ursa"] = { 2, "', "Foulweald Ursa are furbolgs of the Foulweald tribe found at Greenpaw Village in Ashenvale." },
