  ["foundry escort"] = { 2, "', "Foundry Escorts are gnomes located in Ashvane Foundry in Tiragarde Sound during Faction Assaults." },
  ["foundry guardian"] = { 2, "', "Foundry Guardians are humans, dwarves, and worgen located in and around Ashvane Foundry in Tiragarde Sound during Faction Assaults." },
  ["four-fingered fong"] = { 2, "pandaren", "Four-Fingered Fong is a pandaren who can sell items on the Black Market Auction House." },
  ["fourman grimes"] = { 2, "kobold located in Gundargaz in the Ringing Deeps", "Fourman Grimes is a kobold located in Gundargaz in the Ringing Deeps." },
