  ["fran coppervault"] = { 2, "goblin banker in Warspear Hold in Warspear on Ashran", "Fran Coppervault is a goblin banker in Warspear Hold in Warspear on Ashran." },
  ["francis morcott"] = { 2, "worgen hunter", "Francis Morcott is a worgen hunter and cook from Gilneas at Goodgrub Smoking Pit, who prefers the taste of bears, compared to Jez Goodgrub, who prefers panther meat and Jeb Guthrie, who prefers owl meat." },
  ["frandis farley"] = { 2, "Forsaken warrior", "Captain Frandis Farley was a Forsaken warrior, who in life lived in the human kingdom of Stormwind. It has been observed that when not speaking, Frandis's jaw drops into a permanent gaping expression." },
  ["fras siabi"] = { 2, "undead found in Stratholme", "Fras Siabi is an undead found in Stratholme." },
  ["frax bucketdrop"] = { 2, "goblin flight master located at Thondroril River in the E...", "Frax Bucketdrop is a goblin flight master located at Thondroril River in the Eastern Plaguelands." },
  ["fredrik"] = { 2, "venthyr located in the Ember Court", "Fredrik is a venthyr located in the Ember Court." },
  ["freed expedition member"] = { 2, "', "The Freed Expedition Members are either humans, worgen, or dwarves for the Alliance and orcs and Forsaken for the Horde, located at the Ogre Ruins in Exile's Reach." },
  ["freed horde slave"] = { 2, "', "Freed Horde Slaves are elites who have been captured by the Scourge and forced to work inside the Pit of Saron. They are Horde Slaves who equipped themselves after  [25-30D] Deliverance from the Pit." },
  ["freewind brave"] = { 2, "tauren guard captured by the Grimtotem after Freewind Pos...", "Freewind Brave is a tauren guard captured by the Grimtotem after Freewind Post fell. They once guarded the lifts and ramp that lead up to Freewind Post." },
  ["freewind post refugee"] = { 2, "', "Freewind Post Refugees are tauren that survived the destruction of Freewind Post during the Cataclysm and seek refuge in Camp Mojache. They can be found around the camp, as well as in the Lower Wilds, where they wander the road between the Thousan..." },
  ["freewind warrior"] = { 2, "', "Freewind Warriors are tauren located around Freewind Post in Thousand Needles." },
  ["freka bloodaxe"] = { 2, "orc found in the Sunreaver Pavilion of the Argent Tournam...", "Freka Bloodaxe is an orc found in the Sunreaver Pavilion of the Argent Tournament Grounds in Icecrown as part of the Argent Tournament." },
  ["frell 'fixit' fastbolt"] = { 2, "gnome engineering vendor located at the Tranquil Wash in ...", "Frell 'Fixit' Fastbolt is a gnome engineering vendor located at the Tranquil Wash in the Shimmering Expanse." },
  ["fremal doohickey"] = { 2, "gnome first aid trainer located in Deepwater Tavern in Me...", "Fremal Doohickey is a gnome first aid trainer located in Deepwater Tavern in Menethil Harbor in the Wetlands." },
  ["frenzied blackwood furbolg"] = { 2, "', "Frenzied Blackwood Furbolgs are furbolgs in the Twilight Vale in Darkshore where they were attacked by the Alliance and Horde adventurers due to their hysteria. After the Horde took control of the Blackwood Den, they attacked Horde troops statione..." },
  ["frenzied defender (worgen)"] = { 2, "worgen", "Frenzied Defender is a worgen." },
  ["frenzied stalker"] = { 2, "', "Frenzied Stalkers are worgen found in the Light's Dawn Cathedral in Gilneas City during the quest   [1-20] Last Stand." },
  ["frenzied wildheart"] = { 2, "', "Frenzied Wildhearts are worgen who can be encountered during Island Expeditions." },
  ["frenzied worgen"] = { 2, "', "The Frenzied Worgen is found in the Trophy Hall in  Utgarde Pinnacle." },
  ["fresh test subject"] = { 2, "', "Fresh Test Subjects can be found in the rooms off of the Headmaster's Study at the end of Scholomance. Players who have been assigned a Harsh Lesson by Darkmaster Gandling will be required to fight their way out of the side room back to the main c..." },
  ["fressa blastfoot"] = { 2, "goblin located near the Grudge Grotto in Mmarl in eastern...", "Fressa Blastfoot is a goblin located near the Grudge Grotto in Mmarl in eastern Azj-Kahet. She appears to be tinkering with her giant mechanical chicken, Zero Clucks Given." },
  ["frewa"] = { 2, "tauren guild tabard designer", "Frewa was a tauren guild tabard designer who was found in Thunder Bluff during the original beta." },
  ["freysworn arborist"] = { 2, "', "Freysworn Arborists are earthen located throughout Dornogal." },
  ["freysworn chalcy"] = { 2, "earthen located in the Rookery", "Freysworn Chalcy is an earthen located in the Rookery. She assisted Stormward Baelgrim and adventurers in defeating Stormguard Gorren, his skardyn followers, and the monstrosities they unleashed upon the Stormperch." },
  ["freysworn cruton"] = { 2, "earthen freysworn located in Freywold Village on the Isle...", "Freysworn Cruton is an earthen freysworn located in Freywold Village on the Isle of Dorn. He sent Woldtender Igris to Boskroot Basin in order to investigate why there hadn't been any word from Woldkeeper Freydrin in many cycles." },
  ["freysworn etterca"] = { 2, "earthen freysworn located at the Crossroads Plaza on the ...", "Freysworn Etterca is an earthen freysworn located at the Crossroads Plaza on the Isle of Dorn." },
  ["freysworn letitia"] = { 2, "earthen located in a cave at the base of Thul Medran on t...", "Freysworn Letitia is an earthen located in a cave at the base of Thul Medran on the Isle of Dorn. She is found with a stone giant stuck in the ground and a group of Pearlescent Shellcrabs." },
  ["freysworn mossbinder"] = { 2, "', "Freysworn Mossbinders are earthen located at the Contender's Gate in Dornogal. They keep Kelpfist in check, allowing it to be used as a training dummy." },
  ["freywold constable"] = { 2, "earthen located in Freywold Village on the Isle of Dorn", "Freywold Constable is an earthen located in Freywold Village on the Isle of Dorn. She stopped Peacekeeper Leif and Lamplighter Kaerter when they arrived during their search for Shipwright Isaebela." },
  ["freywold protector"] = { 2, "', "Freywold Protectors are a pair of earthen who accompanied a Freywold Constable to speak with Peacekeeper Leif and Lamplighter Kaerter in Freywold Village on the Isle of Dorn." },
  ["friar burlingham"] = { 2, "member of the Argent Crusade", "Friar Burlingham is a member of the Argent Crusade. He came to Outfitter Mendelev to stock up swimwear for his trip to Hardwrench Hideaway." },
  ["friar tuskus"] = { 2, "tuskarr found just east of Kaskala in the Borean Tundra", "Friar Tuskus is a tuskarr found just east of Kaskala in the Borean Tundra." },
  ["friendhaver grem"] = { 2, "expert pet trainer located near the Warrens in the Ringin...", "Friendhaver Grem is an expert pet trainer located near the Warrens in the Ringing Deeps. He is surrounded by his three battle pets: Rufus, Bubs, and Takey-Take." },
  ["frightened baby murloc"] = { 2, "', "Frightened Baby Murlocs are murlocs located in Tyrhold Reservoir in Thaldraszus during Time Rifts." },
  ["frightened researcher"] = { 2, "', "Frightened Researchers are located at Talonlords' Perch in the Forbidden Reach." },
  ["fritz fizzlesprocket"] = { 2, "character in the story A Very Smokywood Winter Veil told ...", "Frits Fizzlesprocket is a character in the story A Very Smokywood Winter Veil told by Wulmort Jinglepocket during the Smokywood Storytime. Professor Frits has gone missing, and his daughter's only wish is for him to come back." },
  ["frixee brasstumbler"] = { 2, "goblin Arena PvP System rewards vendor located at the Cir...", "Frixee Brasstumbler was a goblin Arena PvP System rewards vendor located at the Circle of Blood in the Blade's Edge Mountains (). The Arena Rewards were bought using arena points." },
  ["frogseeker hunter"] = { 2, "', "Frogseeker Hunters are murlocs located in Nazmir." },
  ["frogseeker slave"] = { 2, "', "Frogseeker Slaves are murlocs located in Nazmir." },
  ["froijla axebearer"] = { 2, "vrykul located in Stormheim", "Froijla Axebearer is a vrykul located in Stormheim." },
  ["frostbeard the candlekeeper"] = { 2, "kobold located on the expedition isles", "Frostbeard the Candlekeeper is a kobold located on the expedition isles." },
  ["frostbite (gnoll)"] = { 2, "gnoll located in Snowhide Camp in the Azure Span", "Frostbite is a gnoll located in Snowhide Camp in the Azure Span." },
  ["frostcrag crusher"] = { 2, "', "Frostcrag Crushers are drogbar located in Highmountain." },
  ["frostcrag stonecaller"] = { 2, "', "Frostcrag Stonecallers are drogbar located in Highmountain." },
  ["frostpaw (azure span)"] = { 2, "gnoll located in Snowhide Camp in the Azure Span", "Frostpaw is a gnoll located in Snowhide Camp in the Azure Span. He is summoned by using Wooden Hammer on three Whack a Gnolls on Tree Stump, which causes Snowball to appear who calls Frostpaw." },
  ["frostpaw shaman"] = { 2, "', "Frostpaw Shaman are furbolgs located in Grizzlemaw in the Grizzly Hills." },
  ["frostpaw trapper"] = { 2, "', "Frostpaw Trappers are furbolgs located in Grizzlemaw in Grizzly Hills." },
  ["frostpaw warrior"] = { 2, "', "Frostpaw Warriors are furbolgs located in Grizzlemaw and at Rage Fang Shrine in Grizzly Hills." },
  ["frostwall sniper"] = { 2, "', "Frostwall Snipers are goblins and tauren located in Tanaan Jungle and in Frostwall Shipyard in Frostfire Ridge." },
  ["frostwall stablehand"] = { 2, "', "Frostwall Stablehands are NPCs that appears in the Frostwall if stables are built. They act like stable masters." },
  ["frostwall watcher"] = { 2, "', "Frostwall Watchers are tauren and jungle trolls located in Frostwall. When Frostwall is festively decorated, they are renamed to Festive Watchers." },
  ["frostwolf battleguard"] = { 2, "', "Frostwolf Battleguards are orcs, tauren, and Forsaken found in Alterac Valley." },
  ["frostwolf bowman"] = { 2, "', "Frostwolf Bowmen are orcs and tauren found in Alterac Valley." },
  ["frostwolf envoy"] = { 2, "', "Frostwolf Envoys were orc Alterac Valley recruiters located at various spots throughout the largest Horde cities - Orgrimmar, Silvermoon City, Thunder Bluff, and Undercity, as well as the neutral Shattrath City and Dalaran. They were only availabl..." },
  ["frostwolf guardian"] = { 2, "', "Frostwolf Guardians are found throughout Alterac Valley." },
  ["frostwolf warrior"] = { 2, "', "Frostwolf Warriors are orcs and tauren located in Alterac Valley." },
  ["frosty footman (rumble)"] = { 2, "', "Frosty Footmen are a melee ground unit of the Alliance and Undead families in Warcraft Rumble. They are summoned as part of the entourage of Arthas Menethil, providing a constant group of guards." },
  ["frozen murloc"] = { 2, "murloc found at Stone Cairn Lake in Elwynn Forest", "The Frozen Murloc is a murloc found at Stone Cairn Lake in Elwynn Forest and Brightwater Lake in Tirisfal Glades. It is immune to all damage except Fire, which will apply a short-lasting  Apply Heat debuff upon it." },
  ["frozen tomb guardian"] = { 2, "', "Frozen Tomb Guardians are mogu located in the Tomb of Shadows in Kun-Lai Summit. The nearby Imperial Soul-Harvesters and Zandalari Shadow-Hunters are trying to activate them." },
  ["fruit vendor"] = { 2, "broker located at the Gilded Landing in Tazavesh", "The Fruit Vendor is a broker located at the Gilded Landing in Tazavesh, the Veiled Market." },
  ["frustrated frequenter"] = { 2, "Veiled Market in K'aresh", "Frustrated Frequenters are brokers located in Tazavesh, the Veiled Market in K'aresh." },
  ["fulmin"] = { 2, "', "Fulmin was one of Warlord Gurthan's advisers." },
  ["furbolg (warcraft iii)"] = { 2, "', "This article is about the Warcraft III creeps. For the races, see furbolg, pandaren and polar furbolg." },
  ["furbolg (beta)"] = { 2, "unreleased furbolg", "Furbolg is an unreleased furbolg." },
  ["furbolg bruiser"] = { 2, "furbolg", "Furbolg Bruiser is a furbolg." },
  ["furbolg champion"] = { 2, "', "Furbolg Champions are furbolg creeps that can be encountered in many tilesets, with normal and polar furbolgs appearing. They are heavy melee units." },
  ["furbolg denizen"] = { 2, "', "Furbolg Denizens are furbolgs." },
  ["furbolg elder shaman"] = { 2, "', "Furbolg Elder Shaman are furbolg shaman creeps that can be encountered in the Ashenvale and Felwood tilesets." },
  ["furbolg hermit"] = { 2, "', "The Furbolg Hermit appears in Rise of the Naga and drops Healing Wards." },
  ["furbolg leaftender"] = { 2, "furbolg", "Furbolg Leaftender is a furbolg." },
  ["furbolg shaman (warcraft iii)"] = { 2, "', "Furbolg Shaman are furbolg shaman creeps that can be encountered in the Ashenvale and Felwood tilesets." },
  ["furbolg tracker"] = { 2, "', "Furbolg Trackers are furbolg creeps that can be encountered in the Ashenvale and Felwood tilesets." },
  ["furbolg trailblazer"] = { 2, "', "Furbolg Trailblazers are weaker Furbolgs that appear in Rise of the Naga." },
  ["furbolg ursa warrior"] = { 2, "', "Furbolg Ursa Warriors are furbolg ursa totemic creeps that can be encountered in many tilesets, with normal and polar furbolgs appearing." },
  ["furbolg warlord"] = { 2, "', "The Furbolg Warlord appears in The Druids Arise. This section concerns content related to Warcraft III: Reforged." },
  ["fureng"] = { 2, "centaur of Clan Shikaar located in the center of Maruukai...", "Fureng is a centaur of Clan Shikaar located in the center of Maruukai in the Ohn'ahran Plains as a member of Storykeeper Jaru's audience." },
  ["furgh efurrg"] = { 2, "furbolg", "Furgh Efurrg is a furbolg." },
  ["furious ankoan sentry"] = { 2, "', "Furious Ankoan Sentries are ankoan guards located in Mezzamere in Nazjatar." },
  ["furmund"] = { 2, "tauren quest giver located in the Valley of Strength in O...", "Furmund is a tauren quest giver located in the Valley of Strength in Orgrimmar during the Feast of Winter Veil event. He dislikes how Smokywood Pastures have commercialized the holiday and sends adventurers to Sagorne Creststrider to learn the sea..." },
  ["furtive assassin"] = { 2, "', "Furtive Assassins are venthyr located in the Ember Court." },
  ["fusethrian"] = { 2, "dracthyr innkeeper", "Fusethrian is a dracthyr innkeeper and vendor located at the Old Weyrn Grounds in the Forbidden Reach. After the return to Forbidden Reach, he can be found by the renown envoys of Morqut Village." },
  ["fuunid"] = { 2, "haranir located on a branch above Springrain River in Ami...", "Fuunid is a haranir located on a branch above Springrain River in Amirdrassil in the open-world version of the zone, not in the Emerald Dream. Finding Fuunid is one of the criteria of the exploration achievement  [More Than Just Their Roots]." },
  ["fuzzywick"] = { 2, "worgen character in Smokywood Pastures Presents: A Winter...", "Fuzzywick is a worgen character in Smokywood Pastures Presents: A Winter Veil Carol." },
  ["fynn steelstrike"] = { 2, "Arathi located in Mereldar in Hallowfall", "Fynn Steelstrike is an Arathi located in Mereldar in Hallowfall." },
  ["g'velev"] = { 2, "vrykul located in Stormheim", "G'velev is a vrykul located in Stormheim." },
  ["gaal"] = { 2, "Broken blacksmith located in Krokul Hovel in Krokuun", "Gaal is a Broken blacksmith located in Krokul Hovel in Krokuun. As an eredar, Gaal forged the key to the Armory of the Triumvirate in the Seat of the Triumvirate for Captain Fareeya, and after obtaining fragments, he reforged it again for the adve..." },
  ["gaarn the toxic"] = { 2, "rare mogu found within the Ruins of Dojan in Krasarang Wilds", "Gaarn the Toxic is a rare mogu found within the Ruins of Dojan in Krasarang Wilds. Gaarn is a pandarian champion." },
  ["gabbo blinkwink"] = { 2, "gnome located next to a Scenic Getaway Portal at the Gala...", "Gabbo Blinkwink is a gnome located next to a Scenic Getaway Portal at the Gala of Gifts by the Stormwind Gate in Elwynn Forest during Love is in the Air. He sent his projections to capital cities." },
  ["gabbun"] = { 2, "Kobold housing decor vendor found in Gundargaz in the Rin...", "Gabbun is a Kobold housing decor vendor found in Gundargaz in the Ringing Deeps." },
  ["gabriel bybee"] = { 2, "worgen located at Lunarfall in Shadowmoon Valley", "Gabriel Bybee is a worgen located at Lunarfall in Shadowmoon Valley. He can only be recruited using the Headhunter's Harvest from Lunarfall Inn." },
  ["gaedrin moonfang"] = { 2, "', "Gaedrin Moonfang was one of the first Druids of the Pack, who kept his night elf mind longer than most of his comrades, and wrote the  [Faded Journal]." },
  ["gaffer coilspring"] = { 2, "gnome quest giver", "Carvo Blastbolt is a gnome quest giver and member of S.A.F.E. who can be found in the Loading Room of Gnomeregan." },
  ["gaho"] = { 2, "tauren follower located at Frostwall in Frostfire Ridge", "Gaho is a tauren follower located at Frostwall in Frostfire Ridge. She can only be recruited using the Headhunter's Harvest from Frostwall Tavern." },
  ["gahroot"] = { 2, "tauren meat vendor located at Camp Una'fe in the Northern...", "Gahroot is a tauren meat vendor located at Camp Una'fe in the Northern Barrens. He was one of the survivors that escaped that slaughter of Camp Taurajo." },
  ["gahruj"] = { 2, "ethereal quest giver located at Midrealm Post in the Neth...", "Gahruj is an ethereal quest giver located at Midrealm Post in the Netherstorm." },
  ["gakkiz blusterblast"] = { 2, "goblin follower", "Gakkiz Blusterblast is a goblin follower who can be recruited to Frostwall using the Headhunter's Harvest from Frostwall Tavern. There are two distinct versions of him, one a mage and the other a monk, who can be recruited separately." },
  ["gala attendee"] = { 2, "', "Gala Attendees are located at the Gala of Gifts by the Stormwind Gate in Elwynn Forest and in Durotar during Love is in the Air. They come in all playable races." },
  ["galak assassin"] = { 2, "', "Galak Assassins are centaur located in Thousand Needles." },
  ["galak centaur"] = { 2, "', "Galak Centaur are centaur who roam eastern Mulgore, near the border with the Barrens. They sometimes move two and two, other times accompanied by a Galak Outrunner." },
  ["galak flame guard"] = { 2, "', "Galak Flame Guards are two centaur located in Thousand Needles." },
  ["galak marauder"] = { 2, "', "Galak Marauders are centaur located in Thousand Needles." },
  ["galak mauler"] = { 2, "', "Galak Maulers are centaur located in Splithoof Heights in Thousand Needles." },
  ["galak messenger"] = { 2, "centaur", "The Galak Messenger is a centaur who gallops back and forth along a set route in north-west Thousand Needles, from Splithoof Crag in the east to Camp E'thok in the west, mostly along the road near Whitereach Post." },
  ["galak outrunner"] = { 2, "', "Galak Outrunners are centaur who roam eastern Mulgore, near the border with the Barrens. They sometimes move two and two, other times accompanied by a Galak Centaur." },
  ["galak pack runner"] = { 2, "', "Galak Pack Runners were centaurs found in Thousand Needles during the original beta." },
  ["galak scout"] = { 2, "', "Galak Scouts are centaurs found in Thousand Needles." },
  ["galak stormer"] = { 2, "', "Galak Stormers are centaur located in Splithoof Heights in Thousand Needles." },
  ["galak windchaser"] = { 2, "', "Galak Windchasers are centaur found in Thousand Needles." },
  ["galak wrangler"] = { 2, "', "Galak Wranglers are centaur found in Splithoof Heights in Thousand Needles." },
  ["galamav the marksman"] = { 2, "tauren quest giver located at the beginning of the Detent...", "Galamav the Marksman is a tauren quest giver located at the beginning of the Detention Block in Blackrock Depths. Before the Cataclysm, he could be found in Kargath in Badlands." },
  ["galda bronzeblade"] = { 2, "dwarf rogue trainer located in the town of Thelsamar in L...", "Galda Bronzeblade is a dwarf rogue trainer located in the town of Thelsamar in Loch Modan. She can be found inside the inn, speaking to Gindle the Green." },
  ["galen trollbane"] = { 2, "ruler of the human kingdom of Stromgarde prior to the Cat...", "Galen Trollbane was the ruler of the human kingdom of Stromgarde prior to the Cataclysm. He took leadership of Stromgarde following the ultimate demise of his father Thoras Trollbane and rejoined the Alliance." },
  ["galestrike primalist"] = { 2, "', "Galestrike Primalists are tauren night elves, jungle trolls, and vulpera located in the Flashfrost Enclave and Flashfrost Assault in the Waking Shores." },
  ["galistos' burden"] = { 2, "', "Galistos' Burdens are manifestations and projections of a male orc and a female tauren belonging to Acolyte Galistos in Bastion." },
  ["gallak"] = { 2, "Drust located in Ardenweald", "Gallak is a Drust located in Ardenweald." },
  ["gallath"] = { 2, "Ascended kyrian located in Torghast", "Gallath is an Ascended kyrian located in Torghast, Tower of the Damned." },
  ["galok wingslicer"] = { 2, "djaradin general", "Galok Wingslicer was the djaradin general, who led the siege on the Eye of Ysera in the Emerald Dream, seeking to take control of it in order to pervert the nature and stunt the growth of Amirdrassil, which was being nourished by the Eye's power. ..." },
  ["galthogran the callous"] = { 2, "centaur", "Galthogran the Callous is a centaur." },
  ["gam"] = { 2, "tauren", "Gam was a tauren who used to hunt centaurs with Baine Bloodhoof. When the Emerald Nightmare fell into Thunder Bluff, Gam, dreaming, attacked Baine as if he were a centaur." },
  ["gambler okau"] = { 2, "ankoan of the Waveblade clan", "Gambler Okau was an ankoan of the Waveblade clan who 'knew the odds of every risk he ever took. And never cared if they were against him.' They lie buried at an Ankoan Burial Shrine in Nar'anan in Nazjatar." },
  ["gamella cracklefizz"] = { 2, "goblin quest giver located near the ramp to Eastwall Towe...", "Gamella Cracklefizz is a goblin quest giver located near the ramp to Eastwall Tower in the Eastern Plaguelands." },
  ["gamon"] = { 2, "elite named tauren found in the Valley of Strength within...", "Gamon is an elite named tauren found in the Valley of Strength within Orgrimmar. He can be rescued and will then assist players in The Drag area of the Siege of Orgrimmar raid, where the  [Gamon Will Save Us!] achievement is focused on him." },
  ["gamon (vision of orgrimmar)"] = { 2, "tauren located in the Broken Tusk in the Vision of Orgrimmar", "Gamon is a tauren located in the Broken Tusk in the Vision of Orgrimmar. After defeating him, the player receives the Heroes' Bulwark buff." },
  ["gan'rul bloodeye"] = { 2, "orc located in the Cleft of Shadow in Orgrimmar", "Gan'rul Bloodeye was an orc located in the Cleft of Shadow in Orgrimmar. During the Siege of Orgrimmar, Gan'rul is found dead hanging from a rope in the tunnel leading into the Cleft of Shadow." },
  ["gandorhil"] = { 2, "earthen blacksmithing trainer located in Freywold Village...", "Gandorhil is an earthen blacksmithing trainer located in Freywold Village on the Isle of Dorn." },
  ["gangris riverpaw"] = { 2, "gnoll warlord featured in DC Direct's series 4 of World o...", "Gangris Riverpaw is a gnoll warlord featured in DC Direct's series 4 of World of Warcraft action figures. He has not yet appeared elsewhere." },
  ["gankly rottenfist"] = { 2, "Forsaken located at Nesingwary Safari in Nagrand", "Gankly Rottenfist is a Forsaken located at Nesingwary Safari in Nagrand. He attacks Kristen Dipswitch while she delivers a bundle of skins to the camp." },
  ["gaohun the soul-severer"] = { 2, "mogu located in the Guo-Lai Halls in the Vale of Eternal ...", "Gaohun the Soul-Severer is a mogu located in the Guo-Lai Halls in the Vale of Eternal Blossoms. He is holding a Golden Lotus Guard." },
  ["gar'gol"] = { 2, "ogre located at Gar'gol's Hovel in Mount Hyjal", "Gar'gol is an ogre located at Gar'gol's Hovel in Mount Hyjal. He is the leader and carries the key to Kristoff Manheim freedom." },
  ["gar'lok"] = { 2, "rare mantid found in the Dread Wastes", "Gar'lok is a rare mantid found in the Dread Wastes. He is a Pandarian champion." },
  ["gar'mak bladetwist"] = { 2, "orc found at the Dreadmaul Hold in the Blasted Lands", "Gar'mak Bladetwist is an orc found at the Dreadmaul Hold in the Blasted Lands. He is the leader of the Ironmarch there." },
  ["gara (tortollan)"] = { 2, "tortollan located at Scaletrader Post in Zuldazar", "Gara is a tortollan located at Scaletrader Post in Zuldazar." },
  ["garaxxas"] = { 2, "satyr hunter", "Garaxxas is one of the 8 different NPCs that can be with Priestess Delrissa, the third boss in Magisters' Terrace. He is a satyr hunter, and comes with a pet ravager named Sliver." },
  ["gareb"] = { 2, "earthen located in the Forgegrounds in Dornogal", "Gareb is an earthen located in the Forgegrounds in Dornogal." },
  ["garfang"] = { 2, "cunning", "Packlord Garfang was a cunning and intelligent gnoll alpha of the Redridge pack who, 75 years prior to the First War, unified the gnoll tribes and began launching bold attacks on the kingdom of Stormwind, beginning the Gnoll War." },
  ["gargantuan muckfin"] = { 2, "', "Gargantuan Muckfins are murlocs located on the expedition isles." },
  ["gargle"] = { 2, "murloc located in Zabra'jin in Zangarmarsh", "Gargle is a murloc located in Zabra'jin in Zangarmarsh." },
  ["gargoth"] = { 2, "light-skinned", "Gargoth is a light-skinned, red-clothed ogre living in the Lower City of Shattrath City. He is one of cooking master The Rokk's kitchen assistants, the other being Grisy Spicecrackle." },
  ["garhal"] = { 2, "', "Garhal is level 79-80 named vrykul in Forlorn Mine. Mildred the Cruel wants Garhal killed because he cause insurrection between vrykul workers." },
  ["garhal the scalekeeper"] = { 2, "vrykul flight master located at Valdisdall in Stormheim", "Garhal the Scalekeeper is a vrykul flight master located at Valdisdall in Stormheim." },
  ["garm bonehew"] = { 2, "orc food", "Garm Bonehew is an orc food and drink vendor located at Bloodgulch in the Twilight Highlands." },
  ["garm gladestride"] = { 2, "tauren vendor of leatherworking patterns found in Warspea...", "Garm Gladestride is a tauren vendor of leatherworking patterns found in Warspear's Tannery in Ashran." },
  ["garn blackwolf"] = { 2, "orc located at Mudfisher Cove in Drustvar", "Garn Blackwolf is an orc located at Mudfisher Cove in Drustvar." },
  ["garn cloudsong"] = { 2, "tauren shaman trainer located on the Spirit Rise in Thund...", "Garn Cloudsong  is a tauren shaman trainer located on the Spirit Rise in Thunder Bluff." },
  ["garnett"] = { 2, "earthen housing decor vendor found in Dornogal", "Garnett is an earthen housing decor vendor found in Dornogal." },
  ["garrak"] = { 2, "earthen located on the Isle of Dorn", "Garrak is an earthen located on the Isle of Dorn." },
  ["garrick"] = { 2, "wizard apprentice", "Garrick was a wizard apprentice, and old friend of Adric. Abandoning his master's research, he came looking for Adric once he heard about a dead man with a crossbow that matched a description he knew of as a child." },
  ["garrlok"] = { 2, "ogre companion available from the Trading Post for 750  [...", "Garrlok is an ogre companion available from the Trading Post for 750  [Trader's Tender]. It was first available in February 2023." },
  ["garrulous gladiator"] = { 2, "', "Garrulous Gladiators are orcs, tauren, and goblins located in Dornogal and in the Skyway in Orgrimmar." },
  ["garth beeks"] = { 2, "undead", "Garth Beeks is an undead who wrote to the Gadgetzan Times, asking them to contact Gerald Crowe and ask him if he could introduce him to his wife." },
  ["gartwin"] = { 2, "earthen located in Freywold Village on the Isle of Dorn", "Gartwin is an earthen located in Freywold Village on the Isle of Dorn." },
  ["garval the vanquisher"] = { 2, "naga located in the Eternal Palace", "Garval the Vanquisher is a naga located in the Eternal Palace." },
  ["garvan bitterstone"] = { 2, "dwarf located at the Lunarfall in Shadowmoon Valley", "Garvan Bitterstone is a dwarf located at the Lunarfall in Shadowmoon Valley. He can only be recruited using the Headhunter's Harvest from Lunarfall Inn." },
  ["garvrulg"] = { 2, "drogbar located at the back of a cave in Tel'anor in Suramar", "Garvrulg is a drogbar located at the back of a cave in Tel'anor in Suramar. He is an exile of the Slatecrusher drogbar." },
  ["garwal"] = { 2, "worgen", "Garwal is a worgen who is currently hiding in a worg form in western Rivenwood in the Howling Fjord. Managing to trick Ulfang's brothers, Garwal quickly became the alpha worg for reasons unknown." },
  ["garz"] = { 2, "furbolg located in Camp Nowhere in the Azure Span", "Garz is a furbolg located in Camp Nowhere in the Azure Span." },
  ["gashtooth"] = { 2, "gnoll located at Lost Kanniak in Brackenhide Hollow", "Gashtooth is a gnoll located at Lost Kanniak in Brackenhide Hollow." },
  ["gate-crasher sav'ah"] = { 2, "mantid located in Rough-Hewn Passage in front of the Cham...", "Gate-Crasher Sav'ah is a mantid located in Rough-Hewn Passage in front of the Chamber of the Paragons in the Siege of Orgrimmar." },
  ["gatekeeper (tauren)"] = { 2, "tauren", "Gatekeeper is a tauren." },
  ["gatekeeper rageroar"] = { 2, "rare mob furbolg found in Blackmaw Hold in Azshara", "Gatekeeper Rageroar is a rare mob furbolg found in Blackmaw Hold in Azshara. Before the Cataclysm, Gatekeeper Rageroar was a member of Timbermaw Hold in Azshara, and one of the few rare mobs in the game that would result in a reputation loss when..." },
  ["gatewarden zo'mazz"] = { 2, "broker located in Tazavesh", "Gatewarden Zo'mazz is a broker located in Tazavesh, the Veiled Market." },
  ["gathenak the subjugator"] = { 2, "satyr located in Howling Dale in Val'sharah", "Gathenak the Subjugator is a satyr located in Howling Dale in Val'sharah. He is being hunted by Marius Felbane and Tehd Shoemaker." },
  ["gaul dun firok"] = { 2, "ogre found in Seat of Kor'lok in eastern Ashran", "Gaul Dun Firok is an ogre found in Seat of Kor'lok in eastern Ashran. The Alliance Champion of the Ogre King Kor'lok, Gaul must be defeated by Horde players in order to recruit Kor'lok to aid them in battle." },
  ["gaula axefury"] = { 2, "orc meat vendor located in Southwind Village in Silithus:...", "Gaula Axefuty is an orc meat vendor located in Southwind Village in Silithus: The Wound." },
  ["gauros earthshatter"] = { 2, "tauren found in Brawl'gar Arena", "Gauros Earthshatter is a tauren found in Brawl'gar Arena." },
  ["gava'xi"] = { 2, "ethereal", "Gava'xi is an ethereal and the leader of the Vir'aani in Nagrand. He was later targeted by adventurers on the orders of Zerid, ending the threat he and his band posed in the region." },
  ["gavin marlsbury"] = { 2, "worgen located in the northeastern passageway between the...", "Gavin Marlsbury is a worgen located in the northeastern passageway between the Trade District and the Canals in Stormwind City. He is stealthed and wields two daggers." },
  ["gaz soulripper"] = { 2, "death knight of the Old Horde", "Gaz Soulripper was a death knight of the Old Horde. Like all death knights, he was originally an orc warlock of the Shadow Council who was killed by Orgrim Doomhammer's soldiers at the end of the First War, and who was resurrected when Gul'dan pla..." },
  ["gazarogg the stonespeaker"] = { 2, "drogbar located in the Deep Roads of Highmountain", "Gazarogg the Stonespeaker is a drogbar located in the Deep Roads of Highmountain. He is guarded by a Bound Elemental." },
  ["gazz the loch-hunter"] = { 2, "rare gnoll found in the Wetlands", "Gazz the Loch-Hunter is a rare gnoll found in the Wetlands." },
  ["gear flamepierce"] = { 2, "Arathi located in Lightspark in Hallowfall", "Gear Flamepierce is an Arathi located in Lightspark in Hallowfall." },
  ["gearcutter cogspinner"] = { 2, "gnome engineering vendor located at Tinker Town in Ironforge", "Gearcutter Cogspinner is a gnome engineering vendor located at Tinker Town in Ironforge." },
  ["gehl harrowtongue"] = { 2, "Forsaken member of the Twilight's Blade", "Gehl Harrowtongue is a Forsaken member of the Twilight's Blade who oversees the initiation of Twilight Blade's acolytes. He is the vice cult leader in charge of the Twilight's Blade training grounds." },
  ["gelen jord"] = { 2, "dracthyr located in the Common in Razorwind Shores", "Gelen Jord is a dracthyr located in the Common in Razorwind Shores and Town Center in Founder's Point when the Reaching Beyond the Possible endeavor is active." },
  ["gelihast"] = { 2, "murloc mini-boss in the Pool of Ask'ar of Blackfathom Deeps", "Gelihast is a murloc mini-boss in the Pool of Ask'ar of Blackfathom Deeps. He goes down quite quickly but he can interrupt and kill casters very quickly, dealing high damage as he is wielding 2 swords and has an incredible attack speed." },
  ["gelihast (season of discovery)"] = { 2, "boss in the Season of Discovery Blackfathom Deeps raid", "Gelihast is a boss in the Season of Discovery Blackfathom Deeps raid. Unlike his original appearance, he is shrouded by the Void, like a priest in  [Shadowform]." },
  ["gelk"] = { 2, "undead centaur found in Desolace", "Gelk was an undead centaur found in Desolace. In life he was the second alleged offspring of Zaetar and Theradras, and also the first Khan of the Gelkis clan, which is named after him." },
  ["gelkis earthcaller"] = { 2, "', "Gelkis Earthcallers are centaur found at the Gelkis Village in southern Desolace." },
  ["gelkis marauder"] = { 2, "', "Gelkis Marauders are centaur found at the Gelkis Village in southern Desolace." },
  ["gelkis mauler"] = { 2, "', "Gelkis Maulers are centaur found at the Gelkis Village in southern Desolace." },
  ["gelkis outrunner"] = { 2, "', "Gelkis Outrunners are centaur found at the Gelkis Village in southern Desolace." },
  ["gelkis scout"] = { 2, "', "Gelkis Scouts are centaur found at the Gelkis Village in southern Desolace." },
  ["gelkis stamper"] = { 2, "', "Gelkis Stampers are centaur found at the Gelkis Village in southern Desolace." },
  ["gelkis windchaser"] = { 2, "', "Gelkis Windchasers are centaur found at the Gelkis Village in southern Desolace." },
  ["gellhorn"] = { 2, "tauren located at the Ring of Trials in Nagrand", "Gellhorn is a tauren located at the Ring of Trials in Nagrand." },
  ["gelmogg"] = { 2, "drogbar stonecaster found on the upper level of Lifesprin...", "Gelmogg is a drogbar stonecaster found on the upper level of Lifespring Cavern in Highmountain. He aims to draw the cavern's power into himself, forcing Jale Rivermane, an adventurer and a group of Rivermane tauren to try to destroy him before he ..." },
  ["geltharis"] = { 2, "satyr located in Ashenvale", "Geltharis is a satyr located in Ashenvale. Illiyana wants the return of the branch that Geltharis possesses." },
  ["gem trader"] = { 2, "earthen located at the Crossroads Plaza on the Isle of Dorn", "Gem Trader is an earthen located at the Crossroads Plaza on the Isle of Dorn." },
  ["gen-li, twister of words"] = { 2, "mogu located in the Ruins of Ogudei in the Krasarang Wilds", "Gen-li, Twister of Words is a mogu located in the Ruins of Ogudei in the Krasarang Wilds." },
  ["genah brawnhoof"] = { 2, "tauren follower located at Frostwall in Frostfire Ridge", "Genah Brawnhoof is a tauren follower located at Frostwall in Frostfire Ridge. She can only be recruited using the Headhunter's Harvest from Frostwall Tavern." },
  ["general aevd"] = { 2, "tauren Horde general in Ashran", "General Aevd is a tauren Horde general in Ashran, found in the Warspear Keep in Warspear Outpost. He also serves as Conquest gear vendor." },
  ["general amias bellamy"] = { 2, "Arathi located in Sunwell Ramparts on the Isle of Quel'Danas", "General Amias Bellamy (/ˈbɛləmi/ BELL-ə-mee) is an Arathi located in Sunwell Ramparts on the Isle of Quel'Danas." },
  ["general dugall"] = { 2, "', "The sinstone of General Dugall is found in Revendreth in the Archivam, in the area behind the manor." },
  ["general emmerich"] = { 2, "earthen character in 'The Rivals'", "General Emmerich is an earthen character in 'The Rivals', a play performed by the theater group at the Proscenium on the Isle of Dorn. According to the play he was once one of Dornic's top generals, alongside General Ottomar, their two companies b..." },
  ["general fangferror"] = { 2, "rare naga found at the Ravencrest Monument in Azshara", "General Fangferror is a rare naga found at the Ravencrest Monument in Azshara." },
  ["general fangore"] = { 2, "Shadowhide gnoll located in the eastern Redridge Mountains", "General Fangore, formerly known as Lieutenant Fangore, is a Shadowhide gnoll located in the eastern Redridge Mountains. Back then, Magistrate Solomon wanted Fangore's cold, dead paw, for his alliance with the warlock Morganth, as he rallied his fo..." },
  ["general ottomar"] = { 2, "earthen character in 'The Rivals'", "General Ottomar is an earthen character in 'The Rivals', a play performed by the theater group at the Proscenium on the Isle of Dorn. According to the play he was once one of Dornic's top generals, alongside General Emmerich, their two companies b..." },
  ["general pa'valak"] = { 2, "third boss of Siege of Niuzao Temple", "General Pa'valak is the third boss of Siege of Niuzao Temple." },
  ["general sho lien"] = { 2, "mogu", "General Sho Lien is a mogu who appears after interacting with an Abandoned Wreckage on the road to Mount Neverest in Kun-Lai Summit." },
  ["general skessesh"] = { 2, "naga located at the Ruins of Feathermoon in Feralas", "General Skessesh is a naga located at the Ruins of Feathermoon in Feralas, and the leader of the Hatecrest. Tambre wants him killed and his head delivered to Shandris Feathermoon." },
  ["general steelstrike"] = { 2, "leader of the Hallowfall Arathi", "General Vaelisia Steelstrike is the leader of the Hallowfall Arathi and commander of their army. Having been placed in charge of the Hallowfall Expedition by the Emperor of the Arathi, her unyielding will has seen her people through the darkest of..." },
  ["general temuja"] = { 2, "mogu located in Winterbough Glade in Vale of Eternal Blos...", "General Temuja is a mogu located in Winterbough Glade in Vale of Eternal Blossoms." },
  ["general xing"] = { 2, "Rajani mogu", "General Xing is a Rajani mogu who patrols inside the Silent Sanctuary in the Vale of Eternal Blossoms." },
  ["general zhun"] = { 2, "mogu set to appear in the Temple of Kotmogu scenario", "General Zhun was a mogu set to appear in the Temple of Kotmogu scenario." },
  ["generous ascended"] = { 2, "Forsworn kyrian located in the Font of Fealty in the Seat...", "Generous Ascended is a Forsworn kyrian located in the Font of Fealty in the Seat of the Archon. She is flying with Kowalskos." },
  ["generous dan"] = { 2, "', "Generous Dan was not captain of the Dread Crew for long, but is still regarded as the best captain ever." },
  ["gentle rosh"] = { 2, "ogre innkeeper", "Gentle Rosh is an ogre innkeeper and vendor located in Shackle's Den in Azsuna. He is standing besides Mr." },
  ["geoffy"] = { 2, "Arathi located with Nynthia in Mereldar in Hallowfall", "Geoffy is an Arathi located with Nynthia in Mereldar in Hallowfall." },
  ["geofram bouldertoe"] = { 2, "dwarf mining trainer located in the shop Deepmountain Min...", "Geofram Bouldertoe is a dwarf mining trainer located in the shop Deepmountain Mining & Jewelcrafting, on the north side of the Great Forge in Ironforge." },
  ["geologist om'nayar"] = { 2, "broker located in the Atrium in K'aresh", "Geologist Om'nayar is a broker located in the Atrium in K'aresh." },
  ["geologist om'tik"] = { 2, "broker", "Geologist Om'tik is a broker and member of Cartel Om and the K'aresh Trust located in Eco-Dome: Primus." },
  ["geolord grek'og"] = { 2, "quilboar located at the Quilboar Briarpatch in Exile's Reach", "Geolord Grek'og is a quilboar located at the Quilboar Briarpatch in Exile's Reach. He is conducting a necromantic ritual on Lindie Springstock and Cork Fizzlepop." },
  ["geolord mottle"] = { 2, "rare quilboar found near in the Razormane Grounds in Durotar", "Geolord Mottle is a rare quilboar found near in the Razormane Grounds in Durotar. She patrols the Razormane camp, ready to beat back any intruders that dare threaten her comrades." },
  ["geomancer acolyte"] = { 2, "', "Geomancer Acolytes are quilboar located in Razorfen Kraul." },
  ["geomancer flintdagger"] = { 2, "rare kobold found in Drywhisker Gorge in the Arathi Highl...", "Geomancer Flintdagger is a rare kobold found in Drywhisker Gorge in the Arathi Highlands." },
  ["geopriest gukk'rok"] = { 2, "rare quilboar found guarding a Bristleback den just north...", "Geopriest Gukk'rok is a rare quilboar found guarding a Bristleback den just north of Vendetta Point in the Southern Barrens. Gukk'rok is on a 2-3 hour respawn timer." },
  ["geradran"] = { 2, "dracthyr located at Algeth'ar Academy in Thaldraszus", "Geradran is a dracthyr located at Algeth'ar Academy in Thaldraszus." },
  ["gerald crowe"] = { 2, "human", "Gerald Crowe is a human that used to live in Stratholme with his wife, Lavinia, prior to the Third War. When the Scourge came the two of them were separated and Lavinia killed." },
  ["gerath"] = { 2, "dracthyr located in the Common in Razorwind Shores", "Gerath is a dracthyr located in the Common in Razorwind Shores and Town Center in Founder's Point when the Reaching Beyond the Possible endeavor is active." },
  ["gerdus"] = { 2, "kyrian located in Firstborne's Bounty in Bastion", "Gerdus is a kyrian located in Firstborne's Bounty in Bastion." },
  ["germira"] = { 2, "earthen located in Freywold Village on the Isle of Dorn", "Germira is an earthen located in Freywold Village on the Isle of Dorn. As a foreman, she was worried when she didn't receive the daily quota from the Opalcreg." },
  ["gerred"] = { 2, "earthen located in the Forgegrounds in Dornogal", "Gerred is an earthen located in the Forgegrounds in Dornogal." },
  ["gerrig bonegrip"] = { 2, "dwarf located in the Forlorn Cavern in Ironforge", "Gerrig Bonegrip is a dwarf located in the Forlorn Cavern in Ironforge. In his position as a member of the Twilight's Hammer, he opened the shop Bonegrip's Runes and Dooms collecting and selling lore and knowledge about rituals and the Old Gods." },
  ["gerry clogcraw"] = { 2, "goblin located in the Incontinental Hotel in the Undermine", "Gerry Clogcraw is a goblin located in the Incontinental Hotel in the Undermine." },
  ["gersho"] = { 2, "tortollan located in Gral's Grotto in Zuldazar", "Gersho is a tortollan located in Gral's Grotto in Zuldazar. After Rastakhan's death in the Battle of Dazar'alor, he was present at his funeral in Dazar'alor." },
  ["gertwaald"] = { 2, "earthen located with Assistant Tourrma at Councilward's R...", "Gertwaald is an earthen located with Assistant Tourrma at Councilward's Rise in Dornogal." },
  ["gervase"] = { 2, "worgen", "Gervase was a worgen who acted as the leader of the Wolf Cult in Duskwood. At some point, Gervase retook the Scythe of Elune and has been using it in rituals to transform people into worgen." },
  ["getseng"] = { 2, "centaur of Clan Aylaag located by the western entrance to...", "Getseng is a centaur of Clan Aylaag located by the western entrance to Maruukai in the Ohn'ahran Plains." },
  ["gezhe"] = { 2, "ethereal quest giver located at Aeris Landing in Nagrand", "Gezhe is an ethereal quest giver located at Aeris Landing in Nagrand. He is a Consortium merchant responsible for locating Aeris Landing closer to Oshu'gun because he predicted a 10% increase in profits by doing so." },
  ["ghabar"] = { 2, "ethereal quest giver located at the Stormspire in the Net...", "Ghabar is an ethereal quest giver located at the Stormspire in the Netherstorm." },
  ["ghala"] = { 2, "drogbar located in Loamm in Zaralek Cavern during the PTR", "Ghala was a drogbar located in Loamm in Zaralek Cavern during the PTR." },
  ["ghanim"] = { 2, "planned ethereal", "Ghanim was a planned ethereal." },
  ["gharg"] = { 2, "arena master of the Gorian Empire", "Gharg is an arena master of the Gorian Empire. He is normally found at the entrance into Highmaul leading heroes to the arena above." },
  ["ghastly bonewarden"] = { 2, "', "Ghastly Bonewardens are undead night elves located in the Befouled Sanctum in the Tomb of Sargeras." },
  ["ghede"] = { 2, "tauren located in Elder Rise in Thunder Bluff", "Ghede is a tauren located in Elder Rise in Thunder Bluff." },
  ["ghesh"] = { 2, "nerubian leatherworking trainer located in the Umbral Baz...", "Ghesh is a nerubian leatherworking trainer located in the Umbral Bazaar in the City of Threads in Azj-Kahet." },
  ["ghislania"] = { 2, "naga loyal to Queen Azshara", "Ghislania is a naga loyal to Queen Azshara. At some point, she was captured by Spiketooth and forced to fight as a gladiator." },
  ["ghok bashguud"] = { 2, "', "Ghok Bashguud is rare mob orc found in Lower Blackrock Spire. He is located in the room before the bridge to Overlord Wyrmthalak's room, up the stairs from Halycon's lair, and can be found sleeping in a corner with two sleeping guards." },
  ["gholna"] = { 2, "djaradin located in Zaqali Caldera in Zaralek Cavern", "Gholna is a djaradin located in Zaqali Caldera in Zaralek Cavern." },
  ["ghos'opp"] = { 2, "nerubian found at various locations in Azj-Kahet", "Ghos'opp is a nerubian found at various locations in Azj-Kahet. He offers rumors that can be investigated for the Severed Threads weekly quest." },
  ["ghost walker brave"] = { 2, "Burning Legion presence in the region", "Ghost Walker Braves are level 50 Tauren men and women that protect and defend the outpost of Ghost Walker Post located on the northeaster ledge of the Kodo Graveyard in central Desolace, Kalimdor. The guards are equipped with spears and protect th..." },
  ["ghostrider of karabor"] = { 2, "', "The Ghostriders of Karabor are four ghostly beings that ride on the central road encircling the Hand of Gul'dan in Shadowmoon Valley, following a large circular route in a counter-clockwise direction. They can only be seen while under the effects ..." },
  ["giago"] = { 2, "member of the Gordunni Gladiator Team of Ancient Draenor:...", "Giago was a member of the Gordunni Gladiator Team of Ancient Draenor: the previous year's team champions of the Crimson Ring tournament. He was killed by his teammate Brlee during a battle against Varian 'Lo'Gosh' Wrynn, Valeera Sanguinar and Brol..." },
  ["giantfin"] = { 2, "murloc", "Giantfin is a murloc who appears at the Slithering Scar in Un'Goro Crater during the Un'Goro Madness micro-holiday. During his encounter, he will summon bubbles and start casting a long Lightning Nova spell." },
  ["gibbergill"] = { 2, "murloc appearing in series 4 of DC Direct's World of Warc...", "Gibbergill is a murloc appearing in series 4 of DC Direct's World of Warcraft action figures. He was part of a two-pack, also featuring Fish-eye." },
  ["gibblesnik"] = { 2, "rare kobold found near several spawn points in the vicini...", "Gibblesnik is a rare kobold found near several spawn points in the vicinity of Windbreak Canyon in the Thousand Needles. He is on a 10.5-16 hour respawn timer." },
  ["giblin clockspark"] = { 2, "gnome located in Mugamba Overlook in Zuldazar", "Giblin Clockspark is a gnome located in Mugamba Overlook in Zuldazar." },
  ["gideon rellard"] = { 2, "worgen at Wayward Landing in the Jade Forest", "Gideon Rellard is a worgen at Wayward Landing in the Jade Forest." },
  ["gila crosswires"] = { 2, "gnomish personal assistant of Tinkmaster Overspark", "Gila Crosswires is the gnomish personal assistant of Tinkmaster Overspark. According to her, working with the Tinkmaster benefited her career and can often be seen documenting the Tinkmaster's feats." },
  ["gilbertha"] = { 2, "earthen located in Stoneshaper's Atrium in Dornogal", "Gilbertha is an earthen located in Stoneshaper's Atrium in Dornogal." },
  ["gild crewneck"] = { 2, "vrykul located in Valdisdall in Stormheim", "Gild Crewneck is a vrykul located in Valdisdall in Stormheim. He provides  [Gild's Crewneck] for free." },
  ["gilderann"] = { 2, "earthen located at the Contender's Gate in Dornogal", "Gilderann is an earthen located at the Contender's Gate in Dornogal." },
  ["giles flintridge"] = { 2, "younger brother of Tilloa Flintridge", "Giles Flintridge was the younger brother of Tilloa Flintridge, the son of a human noble of Stormwind, and a student to Stalvan Mistmantle. He was murdered the same night that Stalvan took his revenge." },
  ["gill'dan"] = { 2, "companion pet sold by Sir Finley Mrrgglton in Tyrhold Res...", "Gill'dan is a companion pet sold by Sir Finley Mrrgglton in Tyrhold Reservoir for 2750 . It is a murloc version of Gul'dan." },
  ["gill'dan (time rifts)"] = { 2, "murloc warlock in Azmerloth", "Gill'dan is a murloc warlock in Azmerloth. His appearance is manifested and used by the Fractured Causality during Time Rifts." },
  ["gill'el"] = { 2, "murloc companion", "Gill'el is a murloc companion that is provided with the purchase of the Murloc Thrall 6.5' Plush, available exclusively from the Blizzard Gear Store during WoW's 20th Anniversary and again in September 2025." },
  ["gillgar"] = { 2, "murloc found west of the Solliden Farmstead in Tirisfal G...", "Gillgar is a murloc found west of the Solliden Farmstead in Tirisfal Glades." },
  ["gillidan"] = { 2, "murloc version of Illidan Stormrage from Azmerloth", "Gillidan is a murloc version of Illidan Stormrage from Azmerloth. He is found at the Tyrhold Reservoir in Thaldraszus during Time Rifts." },
  ["gillvanas"] = { 2, "Horde murloc companion given out to attendees for BlizzCo...", "Gillvanas is the Horde murloc companion given out to attendees for BlizzCon 2019. It is modeled after Sylvanas Windrunner." },
  ["gillvanas (azmerloth)"] = { 2, "murloc located in Azmerloth", "Gillvanas is a murloc located in Azmerloth." },
  ["gilmorian"] = { 2, "rare murloc found at Misty Reed Strand in the Swamp of So...", "Gilmorian is a rare murloc found at Misty Reed Strand in the Swamp of Sorrows." },
  ["gilnean ambusher"] = { 2, "', "Gilnean Ambushers are worgen located in the Far Reach in Nazmir during the War Campaign." },
  ["gilnean arcanist"] = { 2, "', "Gilnean Arcanists are worgen located at the Warden Towers on the Broken Isles." },
  ["gilnean armsman"] = { 2, "', "Gilnean Armsmen are worgen located at the Warden Towers on the Broken Isles." },
  ["gilnean battlemage"] = { 2, "', "Gilnean Battlemagi are worgen located in Stormwind City during  [10-60] The Stormwind Extraction." },
  ["gilnean citizen"] = { 2, "', "Gilnean Citizens are humans and worgen located in Gilneas City and the other settlements in the Ruins of Gilneas." },
  ["gilnean cleric"] = { 2, "', "Gilnean Clerics are worgen located at the Warden Towers on the Broken Isles." },
  ["gilnean commander"] = { 2, "worgen riding a horse in the Emerald Dream version of Gil...", "Gilnean Commander is a worgen riding a horse in the Emerald Dream version of Gilneas City during A Gilnean's Dream." },
  ["gilnean defuser"] = { 2, "', "Gilnean Defusers are worgen located in Darkshore. They also appear during the Battle for Darkshore." },
  ["gilnean druid"] = { 2, "', "Gilnean Druids are troops of Gilneas following Genn Greymane during  [10-45] The Battle for Broken Shore. After the battle they can be seen on the Skyfire, healing the wounded." },
  ["gilnean emissary"] = { 2, "', "Gilnean Emissaries were worgen Battle for Gilneas recruiters located at various spots throughout the largest Alliance cities - Stormwind City, Exodar, Darnassus, and Ironforge during the monthly Call to Arms: Battle for Gilneas." },
  ["gilnean feralheart"] = { 2, "', "Gilnean Feralhearts are worgen located at the Warden Towers on the Broken Isles." },
  ["gilnean footman"] = { 2, "', "Gilnean Footmen are troops from Gilneas found across Darkshore, aiding the kaldorei in the reclamation of their home. They were sent on orders of Genn Greymane after Stormwind informed Tyrande Whisperwind that Stormwind could not send aid to them ..." },
  ["gilnean footman (stormwind city)"] = { 2, "', "Gilnean Footmen are troops of Gilneas found on the Skyfire after  [10-45] The Battle for Broken Shore. They are ready to follow their king Genn Greymane to war." },
  ["gilnean greymage"] = { 2, "worgen standing next to Genn Greymane in the Enclave in O...", "The Gilnean Greymage is a worgen standing next to Genn Greymane in the Enclave in Oribos." },
  ["gilnean guard"] = { 2, "', "Gilnean Guards were worgen guards located in Greyfang Enclave in Dalaran. They replaced the Silver Covenant Guardian Mages." },
  ["gilnean huntmaster"] = { 2, "', "Gilnean Huntmasters are worgen located at the Warden Towers on the Broken Isles." },
  ["gilnean laborer"] = { 2, "', "Gilnean Laborers are worgen located in Darkshore and the Battle for Darkshore." },
  ["gilnean lightbearer"] = { 2, "', "Gilnean Lightbearers are worgen located at the Warden Towers on the Broken Isles." },
  ["gilnean mauler"] = { 2, "', "Gilnean Maulers are worgen located at the Warden Towers on the Broken Isles." },
  ["gilnean mauler (ruins of lordaeron)"] = { 2, "', "Gilnean Maulers are worgen located in the Ruins of Lordaeron during the Battle for Lordaeron." },
  ["gilnean mauler (stormwind city)"] = { 2, "', "Gilnean Maulers are worgen located at the Cathedral Square in Stormwind City attacking the Horde infiltrators during  [10-60] The Stormwind Extraction scenario." },
  ["gilnean mauler (beast)"] = { 2, "', "Gilnean Maulers are worgen druids in bear form located at Domination Point in the Domination Point scenario." },
  ["gilnean musketeer"] = { 2, "', "Gilnean Musketeers are troops of the Kingdom of Gilneas deployed to Darkshore. There, they are part of the campaign to aid the kaldorei in retaking their lands from the Horde." },
  ["gilnean officer"] = { 2, "', "Gilnean Officers are worgen located in Drustvar. They are members of the Gilneas Brigade, and only spawn during the quest  [50WQ] Dogged Tenacity, where they defend their camp at the Brackish Coast alongside Hunting Hounds and their leader, Marsha..." },
  ["gilnean ore thief"] = { 2, "', "Gilnean Ore Thieves are worgen located in Darkshore." },
  ["gilnean protector"] = { 2, "', "Gilnean Protectors are worgen located at the Warden Towers on the Broken Isles." },
  ["gilnean refugee"] = { 2, "', "Gilnean Refugees are citizens of Gilneas found throughout the Howling Oak of Darnassus following their exodus from Gilneas. They are welcomed to the city by the druids of Darnassus." },
  ["gilnean royal guard (broken shore)"] = { 2, "', "Gilnean Royal Guards are worgen soldiers of Gilneas fighting the Burning Legion forces and protecting King Genn Greymane during the battle for Broken Shore. After the battle, some of them could be found wounded aboard the Skyfire, being treated by..." },
  ["gilnean royal guard (darkshore)"] = { 2, "', "Gilnean Royal Guards are worgen soldiers of Gilneas located in Darkshore. They were seen protecting Princess Tess Greymane as she led the Gilnean forces to aid the night elves reclaim their land." },
  ["gilnean royal guard (stormwind city)"] = { 2, "', "Gilnean Royal Guards are worgen soldiers of Gilneas protecting King Genn Greymane while on the Skyfire right after the battle for Broken Shore." },
  ["gilnean saboteur"] = { 2, "', "Gilnean Saboteurs are worgen located in Nazj'vel in Darkshore." },
  ["gilnean shieldwall"] = { 2, "', "Gilnean Shieldwalls are worgen located in Stormwind City during  [10-60] The Stormwind Extraction." },
  ["gilnean shieldwarder"] = { 2, "', "Gilnean Shieldwarders are worgen located at the Warden Towers on the Broken Isles." },
  ["gilnean shopkeeper"] = { 2, "', "Gilnean Shopkeepers are humans and worgen located in Merchant Square in Gilneas City." },
  ["gilnean shotgunner"] = { 2, "', "Gilnean Shotgunners are worgen located at the Warden Towers on the Broken Isles." },
  ["gilnean swiftclaw"] = { 2, "', "Gilnean Swiftclaws are worgen located at the Warden Towers on the Broken Isles." },
  ["gilnean tracker"] = { 2, "', "Gilnean Trackers are worgen located in the Alliance Embassy in Dornogal. One appears in the Bazaar in Silvermoon City." },
  ["gilnean warmonger"] = { 2, "', "Gilnean Warmongers are worgen located at the Warden Towers on the Broken Isles." },
  ["gilnean wildsoul"] = { 2, "', "Gilnean Wildsouls are worgen located at the Warden Towers on the Broken Isles." },
  ["gilnean wizard"] = { 2, "', "Gilnean Wizards are worgen located at the Warden Towers on the Broken Isles." },
  ["gilnean worker"] = { 2, "', "Gilnean Workers are worgen and humans located in Gilneas City." },
  ["gilneas nobleman"] = { 2, "worgen", "Gilneas Nobleman is a worgen." },
  ["gilthares firebough"] = { 2, "elf located in Northwatch Hold in the Southern Barrens", "Gilthares Firebough is an elf located in Northwatch Hold in the Southern Barrens. He was a deckhand on a moonshine transport between Ratchet and Booty Bay." },
  ["ginger blockgear"] = { 2, "gnome", "Ginger Blockgear is a gnome who roams inside the Photonic Playground in Dalaran, occasionally stopping to comment on one of the paintings. It's unknown if she survived Dalaran's destruction." },
  ["ginnad"] = { 2, "earthen located in the Forgegrounds in Dornogal", "Ginnad is an earthen located in the Forgegrounds in Dornogal." },
  ["gizmo the pure"] = { 2, "ghost of Gizmo the raccoon pet rewarded from  [30-90] The...", "Gizmo the Pure is the ghost of Gizmo the raccoon pet rewarded from  [30-90] The Case of the Fur-Getting Wikket, part of Guest Relations." },
  ["gjalerbron rune-caster"] = { 2, "', "Gjalerbron Rune-Casters are vrykul found in Gjalerbron in the Howling Fjord." },
  ["gjalerbron sleep-watcher"] = { 2, "', "Gjalerbron Sleep-Watchers are vrykul found at Gjalerbron in the Howling Fjord." },
  ["gjalerbron warrior"] = { 2, "', "Gjalerbron Warriors are vrykul found at Gjalerbron in the Howling Fjord. Some of them are riding felsteeds." },
  ["gjonner the merciless"] = { 2, "elite vrykul death knight found in Icecrown", "Gjonner the Merciless is an elite vrykul death knight found in Icecrown. He's the arena master of Valhalas." },
  ["gladiataur"] = { 2, "tauren located in Stormwind City", "The Gladiataur is a tauren located in Stormwind City and Orgrimmar." },
  ["gladiator akaani"] = { 2, "draenei found in Brimstone Springs in Gorgrond", "Gladiator Akaani is a draenei found in Brimstone Springs in Gorgrond." },
  ["gladiator deathy"] = { 2, "murloc located in the Ring of Blood in Nagrand", "Gladiator Deathy is a murloc located in the Ring of Blood in Nagrand." },
  ["gladiator murkalot"] = { 2, "murloc located in the Ring of Blood in Nagrand", "Gladiator Murkalot is a murloc located in the Ring of Blood in Nagrand." },
