  ["glamora"] = { 2, "dracthyr located in Gladiator's Refuge in Valdrakken", "Glamora is a dracthyr located in Gladiator's Refuge in Valdrakken. She sells cosmetic gladiator gear as a reward for reaching  [Elite: Dragonflight Season 1] and  [Elite: Dragonflight Season 2]." },
  ["glaston"] = { 2, "worgen located in Veiled Grotto in Zuldazar", "Glaston is a worgen located in Veiled Grotto in Zuldazar." },
