  ["gleep chatterswitch"] = { 2, "gnome located in the Shrine of Seven Stars of the Vale of...", "Gleep Chatterswitch is a gnome located in the Shrine of Seven Stars of the Vale of Eternal Blossoms. He provides transport to Ratchet via goblin Teleportation Pad during the quest  [90] A Little Field Work and starts  [90W] The Road to War." },
  ["glengarry adams"] = { 2, "dwarf", "Glengarry Adams is a dwarf." },
