  ["glommus"] = { 2, "ogre found in the Ruins of Alterac in the Hillsbrad Footh...", "Glommus is an ogre found in the Ruins of Alterac in the Hillsbrad Foothills. He is a loyal lieutenant of Mug'thol." },
  ["glomp"] = { 2, "ogre located on Fray Island in the Northern Barrens", "Glomp is an ogre located on Fray Island in the Northern Barrens. He is the Treasurer of the Southsea Freebooters." },
