  ["gloomseeker yarga"] = { 2, "tortollan located in an underwater cave in the Hanging Re...", "Gloomseeker Yarga is a tortollan located in an underwater cave in the Hanging Reef just south of Mezzamere in Nazjatar. Cursed items like the  [Encrusted Coin], the  [Blind Eye], and the  [Skeletal Hand] can be delivered to her in exchange for a  ..." },
  ["gloowaz bonesmusher"] = { 2, "drogbar located in Loamm in Zaralek Cavern", "Gloowaz Bonesmusher is a drogbar located in Loamm in Zaralek Cavern. He was wounded during the attack of Fyrakk on Loamm but died after being found by the adventurer and Ebyssian." },
  ["glopgut basher"] = { 2, "', "Glopgut Bashers are ogres located in the Twilight Highlands." },
