  ["glrglrglr"] = { 2, "murloc locked in a cage inside the Winterfin Caverns in t...", "Glrglrglr is a murloc locked in a cage inside the Winterfin Caverns in the Borean Tundra. One must complete  [10-30] Learning to Communicate to talk to him." },
  ["glrglrr"] = { 2, "murloc located in Mist's Edge in Darkshore", "Glrglrr is a murloc located in Mist's Edge in Darkshore." },
