  ["glumdor"] = { 2, "ogre", "Glumdor is an ogre who patrols the front ramp leading to Gorr'Dim in Bladespire Hold in the Blade's Edge Mountains. He has a unique ability to steal the player's weapon and use it against them." },
  ["glumtooth rider"] = { 2, "', "Glumtooth Riders are kobolds riding undercrawlers located in the Warrens in the Ringing Deeps." },
  ["glurgl"] = { 2, "murloc located in Freehold in Tiragarde Sound", "Glurgl is a murloc located in Freehold in Tiragarde Sound. The murloc is hiding out in an outhouse, to the chagrin of the waiting Freehold Porters." },
  ["glurpy"] = { 2, "murloc located in Tyrhold Reservoir in Thaldraszus during...", "Glurpy is a murloc located in Tyrhold Reservoir in Thaldraszus during Time Rifts." },
  ["glyphataur"] = { 2, "tauren located in Stormwind City", "The Glyphataur is a tauren located in Stormwind City and Orgrimmar. He reuses the ID of the Flaskataur, Esq." },
  ["glyphataur, ph.d."] = { 2, "tauren", "The Glyphataur, Ph.D. is a tauren who appeared during the PTR for Patch 5.4.0." },
  ["glyx brewright"] = { 2, "goblin alchemy vendor located in Boucher's Cauldron in Bo...", "Glyx Brewright is a goblin alchemy vendor located in Boucher's Cauldron in Booty Bay in the Cape of Stranglethorn." },
  ["gmurgl"] = { 2, "Saltscale murloc located at Hardwrench Hideaway in the Ca...", "Gmurgl is a Saltscale murloc located at Hardwrench Hideaway in the Cape of Stranglethorn. He is being held in a tower as a temporary prison." },
  ["gnarla"] = { 2, "haranir located in Harandar", "Gnarla is a haranir located in Harandar." },
