  ["gnaw (hogger demo)"] = { 2, "card from the Hogger Demo set", "Gnaw is a card from the Hogger Demo set." },
  ["gnaw (gnoll)"] = { 2, "Woodpaw gnoll warrior trainer", "Gnaw was a Woodpaw gnoll warrior trainer who trained her pup Hackle and Jaggal. She was a close friend with Claw." },
  ["gnawbles"] = { 2, "Quickwick kobold found in Gundargaz", "Gnawbles is a Quickwick kobold found in Gundargaz, he instructs and sends adventurers on snuffling quests. He also often sends them to Speaker Kuldas to aid with his tasks." },
  ["gnawbone"] = { 2, "rare gnoll found in the Wetlands", "Gnawbone is a rare gnoll found in the Wetlands." },
  ["gnaz blunderflame"] = { 2, "gnome engineering vendor located on a hidden hill south o...", "Gnaz Blunderflame is a gnome engineering vendor located on a hidden hill south of the Mosh'Ogg Ogre Mound in Northern Stranglethorn. The camp may be hard to find, but the hillside is climbable at one point just south of the ogre camps, and this pa..." },
  ["gnoll (warcraft iii)"] = { 2, "', "Gnolls are gnoll creeps that can be encountered in the Lordaeron Summer, Fall and Winter tilesets." },
  ["gnoll assassin (warcraft iii)"] = { 2, "', "Gnoll Assassins are gnoll assassin creeps that can be encountered in the Lordaeron Summer, Fall, and Winter tilesets." },
  ["gnoll brute (warcraft iii)"] = { 2, "', "Gnoll Brutes are gnoll brute creeps that can be encountered in the Lordaeron Summer, Fall, and Winter tilesets." },
  ["gnoll gold miser"] = { 2, "ranged unit of the Underworld Minions force in the Warcra...", "The Gnoll Gold Miser is a ranged unit of the Underworld Minions force in the Warcraft III Demo campaign Exodus of the Horde." },
  ["gnoll invader"] = { 2, "', "Gnoll Invaders are gnolls found in the Gnoll War." },
  ["gnoll mon-ark"] = { 2, "gnoll located in Creektooth Den in the Azure Span", "Gnoll Mon-Ark is a gnoll located in Creektooth Den in the Azure Span." },
  ["gnoll overseer"] = { 2, "', "Gnoll Overseers are gnoll creeps that can be encountered in the Lordaeron Summer, Fall, and Winter tilesets. They are the most powerful members of the gnoll creeps family." },
  ["gnoll poacher (warcraft iii)"] = { 2, "', "Gnoll Poachers are gnoll poacher creeps that can be encountered in the Lordaeron Summer, Fall and Winter tilesets." },
  ["gnoll warden (warcraft iii)"] = { 2, "', "Gnoll Wardens are gnoll warden creeps that can be encountered in the Lordaeron Summer, Fall and Winter tilesets. They hurl bolts of lighting." },
  ["gnoll warlord"] = { 2, "', "The Gnoll Warlord appears in Misconceptions on the northwest island. He drops a Rune of Greater Healing when killed." },
  ["gnopetto bizzfuse"] = { 2, "gnome inventor", "Gnopetto Bizzfuse was a gnome inventor who created the Blingtron unit. He worked from his workshop in Tanaris until he died several years before the third invasion of the Burning Legion when the sea arose." },
  ["gnosh brognat"] = { 2, "ogre found in the Blade's Edge Mountains", "Gnosh Brognat is an ogre found in the Blade's Edge Mountains." },
  ["goahn"] = { 2, "tauren follower located at Frostwall in Frostfire Ridge", "Goahn is a tauren follower located at Frostwall in Frostfire Ridge. He can only be recruited using the Headhunter's Harvest from Frostwall Tavern." },
  ["gobbler"] = { 2, "murloc found in the Bluegill Marsh of the Wetlands", "Gobbler is a murloc found in the Bluegill Marsh of the Wetlands." },
  ["goby blastenheimer"] = { 2, "gnomish member of the Argent Dawn", "Goby Blastenheimer is a gnomish member of the Argent Dawn and was taken prisoner by the Scarlet Crusade in the Scarlet Enclave. When the death knights of Acherus invaded the Enclave, the prisoners traded owners." },
  ["gochao the ironfist"] = { 2, "mogu located at Ruins Rise in the Vale of Eternal Blossoms", "Gochao the Ironfist is a mogu located at Ruins Rise in the Vale of Eternal Blossoms." },
  ["god-king skovald"] = { 2, "ruler of the Tideskorn", "God-King Skovald was the ruler of the Tideskorn, the vrykul of Stormheim, on the Broken Isles. He allied himself with the Burning Legion during their third invasion of Azeroth, and was tasked by his demonic masters with retrieving the Aegis of Agg..." },
  ["god-king skovald (tactics)"] = { 2, "king of the vrykul on the Broken Isles", "God-King Skovald is the king of the vrykul on the Broken Isles. He rules the lands of Stormheim and has recently allied himself with the Burning Legion during their third invasion of Azeroth." },
  ["godo cloudweaver"] = { 2, "tauren Strand of the Ancients battlemaster located in Thu...", "Godo Cloudweaver was a tauren Strand of the Ancients battlemaster located in Thunder Bluff during the monthly Call to Arms: Strand of the Ancients." },
  ["goggeroc"] = { 2, "earthen summoned in the Stonetalon Mountains", "Goggeroc was an earthen summoned in the Stonetalon Mountains. He was worshipped by the Gogger kobolds." },
  ["gogo (tauren)"] = { 2, "tauren located at Frostwall's Fishing Shack", "Gogo is a tauren located at Frostwall's Fishing Shack." },
  ["goldie baronbottom"] = { 2, "Venture Company goblin located in the Cinderbrew Meadery", "Goldie Baronbottom is a Venture Company goblin located in the Cinderbrew Meadery. She seized control of the meadery after it was damaged shortly in a battle against nerubians and Wenbrandt, the owner, grew impatient waiting for the repairs and acc..." },
  ["goldrinn defender"] = { 2, "', "Goldrinn Defenders are guards located at the Shrine of Goldrinn in Mount Hyjal." },
  ["goldsniffer"] = { 2, "kobold located in Skittering Hollow during Island Expedit...", "Goldsniffer is a kobold located in Skittering Hollow during Island Expeditions." },
  ["goldsnuffle lookout"] = { 2, "', "Goldsnuffle Lookouts are kobolds located in Highmountain." },
  ["goldsnuffle scavenger"] = { 2, "', "Goldsnuffle Scavengers are kobolds located in Highmountain." },
  ["goldsnuffle taskmaster"] = { 2, "', "Goldsnuffle Taskmasters are kobolds located in Highmountain." },
  ["goldtooth"] = { 2, "big", "Goldtooth is a big, gold-toothed kobold who can be found at Goldtooth's Den in Elwynn Forest, just east of the Fargodeep Mine. He originally stayed inside the mine, but after the Cataclysm he relocated." },
  ["golgoth"] = { 2, "innkeeper in Rambleshire", "Golgoth is the innkeeper in Rambleshire, on the Isle of Dorn." },
  ["golkada"] = { 2, "tortollan located at Scaletrader Post in Zuldazar", "Golkada is a tortollan located at Scaletrader Post in Zuldazar." },
  ["golkrin"] = { 2, "centaur located in Creektooth Den in the Azure Span", "Golkrin is a centaur located in Creektooth Den in the Azure Span." },
  ["golma"] = { 2, "tortollan found in the Sliver in Dazar'alor", "Golma is a tortollan found in the Sliver in Dazar'alor. He sits on a cliff next to food and drinks: Fish Tacos, Mojo Mixer, Spicy Peppers, Ancient Nuts and Berries, Poorly Aged Juice, and Warm Tortillas." },
  ["golnir bouldertoe"] = { 2, "dwarf mining vendor located in the Great Forge in Ironforge", "Golnir Bouldertoe is a dwarf mining vendor located in the Great Forge in Ironforge. He is somehow related to Geofram Bouldertoe." },
  ["goloria allentine"] = { 2, "Arathi located in Mereldar in Hallowfall", "Goloria Allentine is an Arathi located in Mereldar in Hallowfall." },
  ["gomora the bloodletter"] = { 2, "troll located at the Sunken Temple in Swamp of Sorrows", "Gomora the Bloodletter is a troll located at the Sunken Temple in Swamp of Sorrows." },
  ["gong'tze the riverhewer"] = { 2, "worldsoul memory of a mogu located in the Isle of Dorn du...", "Gong'tze the Riverhewer is the worldsoul memory of a mogu located in the Isle of Dorn during  [80] Worldsoul Memory: The Worldcarvers event." },
  ["gor grimgut"] = { 2, "Bloodmaul ogre", "Gor Grimgut is a Bloodmaul ogre who is guarding  [The Thunderspike] in the back of the Draenethyst Mine in the Blade's Edge Mountains. When Horde players on the quest  [20-30] The Thunderspike try to pick up the Thunderspike, he will spawn and sta..." },
  ["gor'groth"] = { 2, "ogre necromancer", "Gor'groth is an ogre necromancer and the leader of the Darkmaul ogres on Exile's Reach. He plans to conduct a ritual to resurrect the dragon Ravnyr; for this purpose, the Darkmaul and their allies abduct victims for sacrifice." },
  ["gor'marok the ravager"] = { 2, "ogre located in the cave at Dunemaul Compound in Tanaris", "Gor'marok the Ravager was an ogre located in the cave at Dunemaul Compound in Tanaris. He was once the leader of the Dunemaul clan of ogres." },
  ["gor'tesh"] = { 2, "ogre", "Gor'tesh, the brute lord, is an ogre and the leader of the Firegut ogres in the Burning Steppes. He is apparently a very intelligent ogre, ruling not directly from Dreadmaul Rock, but hiding in safety among the Blackrock clan forces near the Pilla..." },
  ["gor'vosh mage"] = { 2, "ogre", "Gor'vosh Mage is an ogre." },
  ["gor'vosh necromancer"] = { 2, "', "Gor'vosh Necromancer are ogres found in the Ashmaul Burial Grounds in Ashran." },
  ["gor'vosh warrior"] = { 2, "ogre", "Gor'vosh Warrior is an ogre." },
  ["gorak tul"] = { 2, "king of the Drust", "Gorak Tul was the king of the Drust, a seafaring people that settled the island of Kul Tiras a long time ago. A savage leader and a wielder of powerful magic, Gorak Tul led the Drust in a war against the initial human settlers who had come from th..." },
  ["gorak tul (tactics)"] = { 2, "final boss of Waycrest Manor", "Gorak Tul is the final boss of Waycrest Manor." },
  ["goraluk anvilcrack"] = { 2, "Blackrock orc blacksmith found in Upper Blackrock Spire", "Goraluk Anvilcrack is a Blackrock orc blacksmith found in Upper Blackrock Spire. He sold his soul to the satyr Lorax but broke the deal and ran away with the  [Unforged Rune Covered Breastplate]." },
  ["goraluk anvilcrack (alternate universe)"] = { 2, "Blackrock clan orc found in the Dread Grotto of Blackrock...", "Goraluk Anvilcrack is a Blackrock clan orc found in the Dread Grotto of Blackrock Foundry. In order to get to him, the heroes need to kill the Iron Maidens which will open a gateway." },
  ["goramal"] = { 2, "ogre located at Bloodmaul Stronghold in Frostfire Ridge", "Goramal is an ogre located at Bloodmaul Stronghold in Frostfire Ridge." },
  ["goran steelbreaker"] = { 2, "', "Goran Steelbreaker appears to be the leader of the earthen army attacking Ulduar." },
  ["gorath stormfyr"] = { 2, "Arathi Lamplighter located in Hallowfall where he can be ...", "Gorath Stormfyr is an Arathi Lamplighter located in Hallowfall where he can be found standing guard at the Azj-Kahet side entrance to Light's Redoubt." },
  ["gordo the oracle"] = { 2, "ogre located in Island Expeditions", "Gordo the Oracle is an ogre located in Island Expeditions." },
  ["gordok brew apprentice"] = { 2, "', "Gordok Brew Apprentices are Gordok ogres located at the Gordok Brew stalls during Brewfest." },
  ["gordok brew barker"] = { 2, "Barkers will toss you another refill", "The Gordok Brew Barker stands beside the Gordok Brewery Stand advertising their particular brews at the Brewfest grounds in Durotar and Dun Morogh. If you pick up a  [Alcohol-Free Brewfest Sampler] and throw it, the Barkers will toss you another r..." },
  ["gordok brew chief"] = { 2, "Gordok ogre", "Gordok Brew Chief is a Gordok ogre that stands behind the counter for the Gordok Brew during Brewfest." },
  ["gordok brute"] = { 2, "', "Gordok Brutes are ogres residing in Dire Maul north. They are often found with packs of Gordok Hounds." },
  ["gordok bushwacker"] = { 2, "ogre", "The Gordok Bushwacker is an ogre that appears after the Ogre Tannin Basket in the Halls of Destruction in Dire Maul is opened. He runs down the ramp to the basket and if not immediately aggro'd, he will run over the platform a few times erraticall..." },
  ["gordok captain"] = { 2, "', "Gordok Captains are ogre captains of the Gordunni clan residing in northern Dire Maul." },
  ["gordok enforcer"] = { 2, "', "Gordok Enforcers are ogre warriors located in Dire Maul in Feralas." },
  ["gordok mauler"] = { 2, "', "Gordok Maulers are ogres that appear in the Broken Commons outside Dire Maul." },
  ["gordok onlooker"] = { 2, "', "Gordok Onlookers are ogres located in Feralas." },
  ["gordok reaver"] = { 2, "', "Gordok Reavers are ogres located in Dire Maul." },
  ["gordok zealot"] = { 2, "ogre", "Gordok Zealot is an ogre." },
  ["gordul razamen"] = { 2, "centaur cooking trainer located in Teerakai in the Ohn'ah...", "Gordul Razamen is a centaur cooking trainer located in Teerakai in the Ohn'ahran Plains." },
