  ["gorehoof the black"] = { 2, "Grimtotem tauren found in Grimtotem Village in the Stonet...", "Gorehoof the Black is a Grimtotem tauren found in Grimtotem Village in the Stonetalon Mountains." },
  ["gorenda"] = { 2, "earthen located in Shadestone Elixirs in the Fissure in D...", "Gorenda is an earthen located in Shadestone Elixirs in the Fissure in Dornogal." },
  ["gorfang"] = { 2, "worgen", "Gorfang was a worgen who, alongside Shagra, attacked Karlain, Revil Kost and Ambrose at the entrance of the Roland's Doom. Ambrose killed the two worgen very quickly." },
  ["gorfax angerfang"] = { 2, "orc warrior", "Gorfax Angerfang is an orc warrior and the current chieftain of the Dragonmaw clan. He is initially found in the Wetlands at the Angerfang Encampment, replacing Nek'rosh Skullcrusher's position as a leader in the area, and was described as the chi..." },
  ["gorg the subjugator"] = { 2, "ancient ogre located on Draenor", "Gorg the Subjugator is an ancient ogre located on Draenor. His idol is located at the Broken Precipice." },
