  ["gorged hollowkeeper"] = { 2, "', "Gorged Hollowkeepers are venthyr located in Revendreth." },
  ["gorgee blastscrew"] = { 2, "goblin located in Undermine", "Gorgee Blastscrew is a goblin located in Undermine." },
  ["gorgog the gronnslayer"] = { 2, "founder of the Gorian Empire", "Gorgog the Gronnslayer, born Gog, was the founder of the Gorian Empire. He broke the bodies of the gronn, opened their bones and ate their marrow to prove they were not gods, and raised up their skeletons so others could see his victory." },
  ["gorian arcanist"] = { 2, "', "Gorian Arcanists are ogres located in Mar'gok's Overwatch in Nagrand. They also attack the Lunarfall and Frostwall garrisons." },
  ["gorian battle-mage"] = { 2, "', "Gorian Battle-Magi are ogres who invade Lunarfall and Frostwall during Garrison Invasions." },
  ["gorian beast-lasher"] = { 2, "ogre located at the Mar'gok's Overwatch in Nagrand", "Gorian Beast-Lasher is an ogre located at the Mar'gok's Overwatch in Nagrand." },
  ["gorian centurion"] = { 2, "', "Gorian Centurions are ogres attacking Lunarfall and Frostwall during Garrison Invasions." },
  ["gorian cohort"] = { 2, "', "Gorian Cohorts are ogres located in Gorgrond, Mar'gok's Overwatch in Nagrand and they also attack the Lunarfall and Frostwall garrisons. One of them in Nagrand is seen fishing." },
  ["gorian elementalist"] = { 2, "', "Gorian Elementalists are ogres attacking Lunarfall and Frostwall during Garrison Invasions." },
  ["gorian enforcer"] = { 2, "', "Gorian Enforcers are ogres located in the Market District in Highmaul." },
  ["gorian gladiator"] = { 2, "', "Gorian Gladiators are ogres located in Gorgrond and in Mar'gok's Overwatch in Nagrand." },
  ["gorian guardsman"] = { 2, "', "Gorian Guardsmen are ogres located in the Path of Victors in Highmaul." },
  ["gorian high sorcerer"] = { 2, "', "Gorian High Sorcerers are ogres located at the Throne of the Imperator in Highmaul." },
  ["gorian mage-lord"] = { 2, "', "Gorian Mage-Lords are ogres attacking Lunarfall and Frostwall during Garrison Invasions." },
  ["gorian reaver"] = { 2, "', "Gorian Reavers are ogres located in the Throne of the Imperator in Highmaul." },
  ["gorian royal guardsman"] = { 2, "', "Gorian Royal Guardsmen are ogres located in the Throne of the Imperator in Highmaul." },
  ["gorian rune-mender"] = { 2, "', "Gorian Rune-Menders are ogre spellcasters protecting the Imperator's Rise within the upper section of Highmaul. They primarily function as healers." },
  ["gorian runemaster"] = { 2, "', "Gorian Runemasters are ogre runemasters located in the Path of Victors in Highmaul." },
  ["gorian sentinel"] = { 2, "', "Gorian Sentinels are ogres attacking Frostwall and Lunarfall during Garrison Invasions." },
  ["gorian sorcerer"] = { 2, "', "Gorian Sorcerers are ogres located in Highmaul. They also appear in the Nagrand version of Highmaul." },
  ["gorian spellbinder"] = { 2, "', "Gorian Spellbinders are ogres attacking Frostwall and Lunarfall during Garrison Invasions." },
  ["gorian warcaller"] = { 2, "', "Gorian Warcallers are ogres attacking Frostwall and Lunarfall during Garrison Invasions." },
  ["gorian warden"] = { 2, "', "Gorian Wardens are ogres located in Imperator's Rise in Highmaul." },
  ["gorian warmage"] = { 2, "', "Gorian Warmages are ogres located in the Throne of the Imperator in Highmaul." },
  ["gorian warmaster"] = { 2, "', "Gorian Warmasters were ogres located in Nagrand that were taken out by the followers sent from the Frostwall and Lunarfall garrisons." },
  ["gork the basher"] = { 2, "rare ogre located at the Quilboar Briarpatch on Exile's R...", "Gork the Basher is a rare ogre located at the Quilboar Briarpatch on Exile's Reach. He oversees the quilboar tribe on behalf of Gor'groth." },
  ["gorkul the unstoppable"] = { 2, "ogre located in Island Expeditions", "Gorkul the Unstoppable is an ogre located in Island Expeditions." },
  ["gorlop"] = { 2, "elite ogre", "Gorlop is an elite ogre and the leader of the Firegut ogres in the Burning Steppes." },
  ["gormali incinerator"] = { 2, "', "Gormali Incinerators are Gormali mogu who try to capture the Nectarbreeze Orchard in the Jade Forest by burning the place." },
  ["gormali raider"] = { 2, "', "Gormali Raiders are mogu who try to take over the Nectarbreeze Orchard in the Jade Forest by luring Nectarbreeze Farmers deeper from safety." },
  ["gormali slaver"] = { 2, "', "Gormali Slavers are mogu located at Camp Gormal in the Jade Forest." },
  ["gormali stalker"] = { 2, "', "Gormali Stalkers are mogu located at the Splintered Path in the Jade Forest." },
  ["gormok axefall"] = { 2, "orc located at the Mist's Edge in Darkshore", "Gormok Axefall was an orc located at the Mist's Edge in Darkshore." },
  ["gorn one eye"] = { 2, "furbolg general goods vendor located in Timbermaw Hold in...", "Gorn One Eye is a furbolg general goods vendor located in Timbermaw Hold in Felwood." },
  ["gorr'thog"] = { 2, "ogre", "Gorr'thog is an ogre, known as the Lord of Bladespire Citadel, who leads the Bladespire clan. He can be found at the Bladespire Throne inside Bladespire Citadel in Frostfire Ridge." },
  ["gorrim"] = { 2, "tauren flight master located at Emerald Sanctuary in Felwood", "Gorrim is a tauren flight master located at Emerald Sanctuary in Felwood." },
  ["gortra"] = { 2, "earthen located next to a Rostrum of Transformation in th...", "Gortra is an earthen located next to a Rostrum of Transformation in the Forgegrounds in Dornogal." },
  ["goru the shepherd"] = { 2, "centaur stable master located at Forkriver Crossing in th...", "Goru the Shepherd is a centaur stable master located at Forkriver Crossing in the Ohn'ahran Plains." },
  ["goruk steelwall"] = { 2, "sleeping djaradin located at the Burning Ascent in the Wa...", "Goruk Steelwall is a sleeping djaradin located at the Burning Ascent in the Waking Shores." },
  ["gorvold ironbrow"] = { 2, "great vrykul warrior", "Gorvold Ironbrow was a great vrykul warrior. He was buried on Shield Hill in the Howling Fjord." },
  ["gostrof"] = { 2, "earthen located in the Forgegrounds in Dornogal", "Gostrof is an earthen located in the Forgegrounds in Dornogal." },
  ["gothal"] = { 2, "tauren located at Zen'shiri Trading Post in the Valley of...", "Gothal is a tauren located at Zen'shiri Trading Post in the Valley of Strength in Orgrimmar." },
  ["gothor brumn"] = { 2, "dwarf armor vendor located at Algaz Station in Loch Modan", "Gothor Brumn is a dwarf armor vendor located at Algaz Station in Loch Modan." },
  ["gotuk"] = { 2, "tuskarr located on the Lost Arvillo in the Waking Shores", "Gotuk is a tuskarr located on the Lost Arvillo in the Waking Shores." },
  ["gotura fourwinds"] = { 2, "tauren shaman found in Grommash Hold in Orgrimmar", "Gotura Fourwinds is a tauren shaman found in Grommash Hold in Orgrimmar. At the beginning of the Elemental Unrest, he informed Horde adventurers about the situation." },
  ["goz banefury"] = { 2, "orc master Pet Tamer located south of the Devouring Breac...", "Goz Banefury is an orc master Pet Tamer located south of the Devouring Breach in the Twilight Highlands. He is surrounded by his three level 25 battle pets: Amythel, Twilight, and Helios." },
  ["gozzic cogcrane"] = { 2, "goblin overboss of the Writhing Fields", "Gozzic Cogcrane is a goblin overboss of the Writhing Fields." },
  ["graath"] = { 2, "centaur located at Nokhudon Hold in the Ohn'ahran Plains", "Graath is a centaur located at Nokhudon Hold in the Ohn'ahran Plains." },
  ["grace jacobs"] = { 2, "worgen located at the Lunarfall in Shadowmoon Valley", "Grace Jacobs is a worgen located at the Lunarfall in Shadowmoon Valley." },
  ["gracefallen tactician"] = { 2, "', "Gracefallen Tacticians are Forsworn kyrian located at the Court of Elation in Bastion." },
  ["grady bannson"] = { 2, "dwarf battle pet trainer located outside the inn of Khara...", "Grady Bannson is a dwarf battle pet trainer located outside the inn of Kharanos in Dun Morogh. He provides training for Battle Pets for 100." },
  ["gragza the dragon-breaker"] = { 2, "djaradin located in Scalecracker Keep in the Waking Shores", "Gragza the Dragon-Breaker is a djaradin located in Scalecracker Keep in the Waking Shores." },
  ["graham mcallister"] = { 2, "worgen hippogryph master for the Gilnean town of Surwich ...", "Graham McAllister is the worgen hippogryph master for the Gilnean town of Surwich in the Blasted Lands." },
  ["grahm ciderhammer"] = { 2, "dwarf at Wayward Landing in the Jade Forest", "Grahm Ciderhammer is a dwarf at Wayward Landing in the Jade Forest. He could repair gear and sold blacksmithing supplies." },
  ["grak'i"] = { 2, "tuskarr located in Whaler's Nook in the Azure Span", "Grak'i is a tuskarr located in Whaler's Nook in the Azure Span." },
  ["grakis"] = { 2, "arakkoa vendor found in Stormshield of Ashran", "Grakis is an arakkoa vendor found in Stormshield of Ashran." },
  ["grand anchorite almonen"] = { 2, "draenei priest located in the center dome of the Terrace ...", "Grand Anchorite Almonen is a draenei priest located in the center dome of the Terrace of Light in Shattrath City. He would speak to Aldor initiates about the nature of the Holy Light while his troops were seen in battle practice around the central..." },
  ["grand apothecary alchataur"] = { 2, "tauren located in various places during alpha", "Grand Apothecary Alchataur is a tauren located in various places during alpha and beta testing where he 'sells' various flasks and potions at no cost. He also appears during Mythic Dungeon International." },
  ["grand apothecary alchataur the second"] = { 2, "tauren located in various places during alpha", "Grand Apothecary Alchataur the Second is a tauren located in various places during alpha and beta testing where he 'sells' various flasks and potions at no cost." },
  ["grand apothecary putress"] = { 2, "chief apothecary of the Forsaken's Royal Apothecary Society", "Grand Apothecary Putress was the chief apothecary of the Forsaken's Royal Apothecary Society. He played a vital role in the development of the 'New Plague' the Forsaken sought to create." },
  ["grand arcanist dimitri"] = { 2, "venthyr located in a building in the Shrouded Asylum in R...", "Grand Arcanist Dimitri is a venthyr located in a building in the Shrouded Asylum in Revendreth. The four nearby Shrouded Ritualists have to be killed to make Dimitri attackable." },
  ["grand empress shek'zara"] = { 2, "current empress of the mantid", "Grand Empress Shek'zara, formerly Princess Zara, is the current empress of the mantid and a world boss in the Vale of Eternal Blossoms. Sentinel Commander Qipan describes her as hot-headed and impulsive." },
  ["grand empress shek'zeer"] = { 2, "', "'Even in my sleep, I hear her terror. Fear grips her mind and body." },
  ["grand empress zek'hara"] = { 2, "ruler of the mantid before Shek'zeer", "Grand Empress Zek'hara was a ruler of the mantid before Shek'zeer, though how long before is unknown. Obsessed with control and gripped by paranoia, she aspired to stay in power long past her time." },
  ["grand flame"] = { 2, "djaradin located in Dragonbane Keep in the Waking Shores", "Grand Flame was a djaradin located in Dragonbane Keep in the Waking Shores. They were presumably the djaradin in charge of the keep and were killed during its siege by the Obsidian Outcasts and their allies." },
  ["grand inquisitor aurica"] = { 2, "venthyr located in the Halls of Atonement in Revendreth", "Grand Inquisitor Aurica is a venthyr located in the Halls of Atonement in Revendreth. Her name in life was Jonapa the Opulent." },
  ["grand inquisitor nicu"] = { 2, "venthyr located at the Halls of Atonement in Revendreth", "Grand Inquisitor Nicu is a venthyr located at the Halls of Atonement in Revendreth. His name in life was Vortophe the Unspeakable." },
  ["grand master alchemist ki'xen"] = { 2, "mantid located at Rough-Hewn Passage in the Siege of Orgr...", "Grand Master Alchemist Ki'xen is a mantid located at Rough-Hewn Passage in the Siege of Orgrimmar." },
  ["grand necrolord antiok"] = { 2, "', "Grand Necrolord Antiok rides upon the shoulder of Thiassi the Lightning Bringer, found on top of the Wicked Coil in Dragonblight. He is in charge of the effort to raise Galakrond to undeath." },
  ["grand overseer"] = { 2, "', "Grand Overseers are venthyr located in Sanguine Depths." },
  ["grand proctor beryllia"] = { 2, "venthyr boss located in the Sanguine Depths", "Grand Proctor Beryllia is a venthyr boss located in the Sanguine Depths." },
  ["grand vizier jarasum"] = { 2, "echo of an eredar located at the Conservatory of the Arca...", "Grand Vizier Jarasum is the echo of an eredar located at the Conservatory of the Arcane in Eredath. As one of Archimonde's greatest pupils, Jarasum held such power in his own disciplines that the Conservatory remembers him even centuries later." },
  ["grand-heister bokk"] = { 2, "kobold located in a cave north of Mourning Rise on the Is...", "Grand-Heister Bokk is a kobold located in a cave north of Mourning Rise on the Isle of Dorn. He is the leader of the Candlelit kobolds who were ransacking Mourning Rise and is slain by adventurers sent by Urtago, the caretaker of the place." },
  ["grandmaster ossip"] = { 2, "Arathi located in the Lightspark Commissary in Hallowfall", "Grandmaster Ossip is an Arathi located in the Lightspark Commissary in Hallowfall. He can be found sitting with a game of Light's Gambit as well as the Light's Gambit Challenger's Handbook." },
  ["graniteclaw"] = { 2, "furbolg located in the Azure Span", "Graniteclaw is a furbolg located in the Azure Span." },
  ["granny scribbles"] = { 2, "kobold located in the Ringing Deeps", "Granny Scribbles is a kobold located in the Ringing Deeps." },
  ["grant lazarby"] = { 2, "wealthy worgen death knight located in Bizmo's Brawlpub", "Grant Lazarby is a wealthy worgen death knight located in Bizmo's Brawlpub." },
  ["graun blump"] = { 2, "good fisherman", "Graun Blump is Gubber Blump's cousin. She is a good fisherman, though not as good as Gubber." },
  ["graveborn assassin"] = { 2, "', "Graveborn Assassins are Gilnean humans turned Forsaken." },
  ["gravel longslab"] = { 2, "earthen located at the Fractured Front in Deepholm", "Gravel Longslab is an earthen located at the Fractured Front in Deepholm. He seeks to end the stone troggs and their leader Troggzor the Earthinator." },
  ["gravelord monkh"] = { 2, "centaur of Clan Ukhel trying to resurrect Teera", "Gravelord Monkh is a centaur of Clan Ukhel trying to resurrect Teera and Maruuk's spirits in the Eternal Kurgans in the Nokhud Offensive. He is protected by a 'Ritual of Desecration', which makes him immune to damage and repeatedly damages anyone ..." },
  ["gravelsnout ambusher"] = { 2, "', "Gravelsnout Ambushers are kobolds that did not make it out of the beta stages of World of Warcraft." },
  ["gravelsnout digger"] = { 2, "', "Gravelsnout Diggers are kobolds found in Thousand Needles." },
  ["gravelsnout forager"] = { 2, "', "Gravelsnout Foragers are kobolds located in Thousand Needles." },
  ["gravelsnout kobold"] = { 2, "', "Gravelsnout Kobolds are kobolds located in Thousand Needles." },
  ["gravelsnout surveyor"] = { 2, "', "Gravelsnout Surveyors are kobolds found in Thousand Needles." },
  ["gravelsnout vermin"] = { 2, "', "Gravelsnout Vermins are kobolds located in Thousand Needles." },
  ["graw cornerstone"] = { 2, "dwarf armor vendor located in a small camp just northeast...", "Graw Cornerstone is a dwarf armor vendor located in a small camp just northeast of the Blackrock Mountain entrance in the Searing Gorge. He has been missing since the Cataclysm." },
  ["grawlash the frenzied"] = { 2, "furbolg located in Island Expeditions", "Grawlash the Frenzied is a furbolg located in Island Expeditions." },
  ["grazle"] = { 2, "furbolg quest giver located by the road opposite the Emer...", "Grazle is a furbolg quest giver located by the road opposite the Emerald Sanctuary in Felwood. He is a Timbermaw furbolg and friendly to all players, unlike other members of Timbermaw Hold." },
  ["grazlin crankthrottle"] = { 2, "goblin located in Bashal'Aran in Darkshore during the Bat...", "Grazlin Crankthrottle is a goblin located in Bashal'Aran in Darkshore during the Battle for Darkshore." },
  ["greasefang"] = { 2, "gnoll matriarch of the Woodpaw clan", "Greasefang was the gnoll matriarch of the Woodpaw clan, and the mother of Jaggal. The Woodpaws shared their lands with the hyenas who later vanished, but Greasefang didn't care about them." },
  ["great granny cinderbangs"] = { 2, "goblin located in Undermine", "Great Granny Cinderbangs is a goblin located in Undermine who was in the safe." },
  ["great kyron"] = { 2, "leader of the Lamplighters of the Hallowfall Arathi", "The Great Kyron is the leader of the Lamplighters of the Hallowfall Arathi. They served as a warden in the Arathi Army for many years before accompanying the expedition to Hallowfall, where they found their calling late in life by creating the Lam..." },
  ["greeby mudwhisker"] = { 2, "kobold", "Greeby Mudwhisker is a kobold." },
  ["greedy grove-killing drust"] = { 2, "Drust located in Dominance Keep of Revendreth", "Greedy Grove-killing Drust is a Drust located in Dominance Keep of Revendreth." },
  ["greela 'the grunt' crankchain"] = { 2, "goblin found patrolling near the Orgrimmar Embassy in Org...", "Greela 'The Grunt' Crankchain is a goblin found patrolling near the Orgrimmar Embassy in Orgrimmar. She is dressed in the same attire as an Orgrimmar Grunt." },
  ["green warrior"] = { 2, "', "Green Warriors are fighters who can sometimes be seen in the un-instanced version of the Dalaran Arena in the Dalaran Underbelly. They're one of several NPCs that periodically appear and act out a 2v2 or 3v3 arena match." },
  ["greenflame candlekeeper"] = { 2, "kobold", "Greenflame Candlekeeper is a kobold." },
  ["greengill slave"] = { 2, "', "Greengill Slaves are murlocs on the Greengill Coast of the Isle of Quel'Danas. Physically, they are very small." },
  ["greenpaw"] = { 2, "furbolg found in Ban'ethil Barrow Den in Teldrassil", "Greenpaw is a furbolg found in Ban'ethil Barrow Den in Teldrassil. He protects the Chest of the Black Feather containing the  [Black Feather Quill] that is required for the quest  [1-30] The Relics of Wakening." },
  ["greenspeaker na'layro"] = { 2, "haranir quest giver located by the southeastern entrance ...", "Greenspeaker Na'layro is a haranir quest giver located by the southeastern entrance to the Wormlands in Azj-Kahet, where he asks adventurers to help him stop Wormcaller Iz'tikrine's infestation of cave borers from threatening the great roots in th..." },
  ["greexit coarsebub"] = { 2, "goblin located in the Vatworks in west-central Undermine", "Greexit Coarsebub is a goblin located in the Vatworks in west-central Undermine. He sells a number of cosmetic items based on current Cartels of Undermine alignment." },
  ["gregan brewspewer"] = { 2, "dwarf located in a small camp just west of the road south...", "Gregan Brewspewer is a dwarf located in a small camp just west of the road south of the Twin Colossals in Feralas. He is an expert in herbs and alchemy." },
  ["gregg"] = { 2, "ogre located at the Dranosh'ar Blockade in Durotar prior ...", "Gregg is an ogre located at the Dranosh'ar Blockade in Durotar prior to the Battle for the Broken Shore. This section concerns content related to Battle for Azeroth." },
  ["gregor fizzwuzz"] = { 2, "gnome", "Gregor Fizzwuzz is a gnome who was interviewed by the Gadgetzan Times, asking him about why he is helping the Brassbolts brothers building a race cart." },
  ["gregor steelshod"] = { 2, "Arathi located in Light's Blooming in Hallowfall", "Gregor Steelshod is an Arathi located in Light's Blooming in Hallowfall." },
  ["gregor the pallidblade"] = { 2, "venthyr located in Sinfall", "Gregor the Pallidblade is a venthyr located in Sinfall." },
  ["gregory"] = { 2, "undead death knight", "Sir Gregory Edmunson, also known by his paladin name of Sage Truthbearer, is an undead death knight. Once a member of the Order of the Silver Hand, he was raised into undeath after he was killed by Arthas Menethil in Andorhal." },
  ["gregory adams"] = { 2, "human mage", "Gregory Adams is a human mage. He wrote a letter to Kirin Tor Monthly, about his friends constantly asking for food, drinks and portals." },
  ["gregory ardus"] = { 2, "human located in the Cathedral Square of Stormwind City", "Gregory Ardus is a human located in the Cathedral Square of Stormwind City. He is the proprietor of the ironically-named Just Maces, in which he can be found." },
  ["grekka anvilsmash"] = { 2, "orc located at the Obsidian Bulwark in the Waking Shores", "Grekka Anvilsmash is an orc located at the Obsidian Bulwark in the Waking Shores." },
  ["gremmie"] = { 2, "tuskarr child located in the Waking Shores", "Gremmie is a tuskarr child located in the Waking Shores." },
  ["gren tornfur"] = { 2, "furbolg located in Blackwood Hold in southern Darkshore", "Gren Tornfur is a furbolg located in Blackwood Hold in southern Darkshore. This section concerns content related to Battle for Azeroth." },
  ["grendag brightbeard"] = { 2, "dwarf located in the Forlorn Cavern in Ironforge", "Grendag Brightbeard is a dwarf located in the Forlorn Cavern in Ironforge, the Valley of Strength in Orgrimmar, and Steamwheedle Port in Tanaris. He allows players to choose a second talent specialization." },
  ["grendella cogswitch"] = { 2, "gnome located near the Lunarfall garrison in Shadowmoon V...", "Grendella Cogswitch is a gnome located near the Lunarfall garrison in Shadowmoon Valley." },
  ["gresit"] = { 2, "venthyr located in the Absolution Crypt of Revendreth", "Gresit is a venthyr located in the Absolution Crypt of Revendreth. He is a new venthyr sired by the Accuser." },
  ["greta albrite"] = { 2, "human located in the Arathi Highlands", "Greta Albrite is a human located in the Arathi Highlands. She can be found in a small house, dancing with (presumed husband) Nordric Albrite." },
  ["gretta finespindle"] = { 2, "gnome located in the Great Forge in Ironforge", "Gretta Finespindle is a gnome located in the Great Forge in Ironforge." },
  ["grex brainboiler"] = { 2, "goblin vendor found in Area 52 in the Netherstorm", "Grex Brainboiler is a goblin vendor found in Area 52 in the Netherstorm. He sells vintage Level 60 PvP cloth and leather armor." },
  ["greygill drudge"] = { 2, "', "Greygill Drudges are murlocs planned to appear in Nazjatar." },
  ["greygill slave"] = { 2, "murloc", "Greygill Slave is a murloc." },
  ["greygill tidehunter"] = { 2, "murloc", "Greygill Tidehunter is a murloc." },
  ["greyguard elite"] = { 2, "', "Greyguard Elites are humans and worgen of the Gilnean military. Shortly after the war against the Primalists, King Genn Greymane was accompanied by a Greyguard Elite at the Seat of the Aspects in Valdrakken and another one was stationed in the Tra..." },
  ["greyguard watcher"] = { 2, "', "Greyguard Watchers are worgen guards located in Stormglen Village following the Reclamation of Gilneas." },
  ["greyheart nether-mage"] = { 2, "', "Greyheart Nether-Mages are Broken located in Serpentshrine Cavern." },
  ["greyheart shield-bearer"] = { 2, "', "Greyheart Shield-Bearers are Broken found in Serpentshrine Cavern." },
  ["greyheart skulker"] = { 2, "', "Greyheart Skulkers are Broken found in Serpentshrine Cavern." },
  ["greyheart spellbinder"] = { 2, "', "Greyheart Spellbinders are Broken found in Serpentshrine Cavern, using powerful magic to hold Leotheras the Blind." },
  ["greyheart technician"] = { 2, "', "Greyheart Technicians are Broken found in Serpentshrine Cavern in Coilfang Reservoir. They are vulnerable to all forms of Crowd control." },
  ["greyheart tidecaller"] = { 2, "', "Greyheart Tidecallers are Broken found in Serpentshrine Cavern." },
  ["greymist coastrunner"] = { 2, "', "Greymist Coastrunners are murlocs found in Darkshore prior to the Cataclysm." },
  ["greymist hunter"] = { 2, "', "Greymist Hunters are murlocs found in Darkshore." },
  ["greymist netter"] = { 2, "', "Greymist Netters were murlocs located in Darkshore prior to the Cataclysm." },
  ["greymist oracle"] = { 2, "', "Greymist Oracles are murlocs found at Remtravel's Excavation in Darkshore." },
  ["greymist raider"] = { 2, "', "Greymist Raiders are murlocs located in Darkshore prior to the Cataclysm." },
  ["greymist refugee"] = { 2, "', "Greymist Refugees are murlocs that can be found at Remtravel's Excavation in Darkshore." },
  ["greymist relic-keeper"] = { 2, "', "Greymist Relic-Keepers are murlocs located in Darkshore." },
  ["greymist scavenger"] = { 2, "', "Greymist Scavengers are murlocs located in Darkshore." },
  ["greymist seer"] = { 2, "', "Greymist Seers are murlocs located in Darkshore prior to the Cataclysm." },
  ["greymist tidehunter"] = { 2, "', "Greymist Tidehunters are murlocs found at Mist's Edge in Darkshore. This section concerns content related to Battle for Azeroth." },
  ["greymist warrior"] = { 2, "', "Greymist Warriors are murlocs found at Mist's Edge in Darkshore. This section concerns content related to Battle for Azeroth." },
  ["greystone chompkeeper"] = { 2, "', "Greystone Chompkeepers are drogbar located in Highmountain." },
  ["greystone fishbrul"] = { 2, "', "Greystone Fishbruls are drogbar located in Highmountain." },
  ["greystone flanker"] = { 2, "', "Greystone Flankers are drogbar attacking Thunder Totem in Highmountain." },
  ["greystone shardcaster"] = { 2, "', "Greystone Shardcasters are drogbar attacking Thunder Totem in Highmountain." },
  ["greystone shardfinder"] = { 2, "', "Greystone Shardfinders are drogbar located in Highmountain." },
