  ["gunther the gray"] = { 2, "worgen", "Gunther the Gray is a worgen who can be encountered during Island Expeditions." },
  ["gurf"] = { 2, "draenei skinning trainer located at Stillpine Hold in Azu...", "Gurf is a draenei skinning trainer located at Stillpine Hold in Azuremyst Isle. He has lost his dignity to the murloc Murgurgula." },
  ["gurgl"] = { 2, "baby murloc located in the Eye of Azshara", "Gurgl is a baby murloc located in the Eye of Azshara. Being transported by Zantini, Gurgl was captured by the Violetsails and delivered to Trainer Iris Greedsway." },
  ["gurgl (battle pet)"] = { 2, "murloc battle pet rewarded from  [1-90] Gurgl", "Gurgl is a murloc battle pet rewarded from  [1-90] Gurgl and the Bandit." },
  ["gurgle"] = { 2, "murloc located in Zabra'jin in Zangarmarsh", "Gurgle is a murloc located in Zabra'jin in Zangarmarsh." },
  ["gurgles"] = { 2, "leader of the murlocs", "Not to be confused with  Gurgle <Tor'gash's Pet>. Gurgles is the leader of the murlocs who appeared in ZoneDiscovery." },
  ["gurlack"] = { 2, "furbolg located on the expedition isles", "Gurlack is a furbolg located on the expedition isles." },
  ["gurlgrl"] = { 2, "murloc member of the Bloodsail Buccaneers", "Gurlgrl is a murloc member of the Bloodsail Buccaneers. He is found aboard The Damsel's Luck in the Cape of Stranglethorn." },
  ["gurn grubnosh"] = { 2, "', "Gurn Grubnosh can be found in Blade's Edge Mountains. He appears when a  [Bladespire Clan Banner] is planted on top of the Northmaul Tower." },
  ["gurnot"] = { 2, "member of the Stormriders", "Gurnot is a member of the Stormriders. He was first encountered patrolling in Dhar Durgaz where he served as a guard." },
  ["gurr firecaller"] = { 2, "ogre located in Bloodmaul Slag Mines where he took over a...", "Gurr Firecaller was an ogre located in Bloodmaul Slag Mines where he took over a portion of the mines containing a shipment of valuable fuel. He was taken out by the followers sent from the garrisons." },
  ["gurrag"] = { 2, "furbolg shaman trainer located in the Crystal Hall in the...", "Gurrag is a furbolg shaman trainer located in the Crystal Hall in the draenei capital of the Exodar. He is probably a member of the Stillpine tribe." },
  ["gurthan scrapper"] = { 2, "', "Gurthan Scrappers are mogu located at Mogu'shan Palace." },
  ["gurthan swiftblade"] = { 2, "', "Gurthan Swiftblades are mogu located at Mogu'shan Palace." },
  ["gurtuk hardshell"] = { 2, "tortollan located in the Jeweled Coast in Stormsong Valley", "Gurtuk Hardshell is a tortollan located in the Jeweled Coast in Stormsong Valley." },
  ["gustav"] = { 2, "venthyr located at the Old Gate in Revendreth", "Gustav is a venthyr located at the Old Gate in Revendreth." },
  ["gut'usul"] = { 2, "nerubian found in the Sureki Command in the City of Threads", "Gut'usul is a nerubian found in the Sureki Command in the City of Threads." },
  ["gutgruk the tough"] = { 2, "ogre", "Gutgruk the Tough is an ogre who patrols near the Darkmaul Bridge on Exile's Reach. He kidnapped part of the Alliance or Horde's first expedition to the island, and he intends to capture the second expedition as well." },
  ["guthrin gravehoof"] = { 2, "tauren", "Guthrin Gravehoof is a tauren." },
  ["gutshot"] = { 2, "boss in Brackenhide Hollow", "Gutshot is a boss in Brackenhide Hollow." },
  ["gutsmash the destroyer"] = { 2, "ogre located atop a tower in Frostboar Drifts in Frostfir...", "Gutsmash the Destroyer is an ogre located atop a tower in Frostboar Drifts in Frostfire Ridge." },
  ["gutspill"] = { 2, "leader of the Nightbane worgen in Duskwood", "Gutspill is the leader of the Nightbane worgen in Duskwood and is found at Roland's Doom. Grimand Elmore seeks the burning rock that Gutspill possesses." },
  ["guzrug the tiny"] = { 2, "ogre located on the Arena Floor of the Ring of Trials in ...", "Guzrug the Tiny is an ogre located on the Arena Floor of the Ring of Trials in Nagrand." },
  ["gwan'ro"] = { 2, "nerubian jewelcrafting trainer located in the Umbral Baza...", "Gwan'ro is a nerubian jewelcrafting trainer located in the Umbral Bazaar in the City of Threads in Azj-Kahet." },
  ["gwenla cragflayer"] = { 2, "dwarf", "Gwenla Cragflayer is a dwarf." },
  ["gynfeld cogswitch"] = { 2, "gnome", "Gynfeld Cogswitch is a gnome." },
  ["h'partho ardoros"] = { 2, "draenei member of the Explorer's League", "H'partho Ardoros is a draenei member of the Explorer's League. He can be found in several locations across the zone." },
  ["haaik"] = { 2, "tuskarr located in the Azure Span", "Haaik is a tuskarr located in the Azure Span." },
  ["haal'eshi talonguard"] = { 2, "', "Haal'eshi Talonguards are arakkoa found at the Den of Haal'esh and Haal'eshi Gorge in Hellfire Peninsula." },
  ["haal'eshi windwalker"] = { 2, "', "Haal'eshi Windwalkers are arakkoa found at the Den of Haal'esh and Haal'eshi Gorge in Hellfire Peninsula." },
  ["haalum"] = { 2, "Broken located at the Netherwing Pass in Shadowmoon Valley", "Haalum is a Broken located at the Netherwing Pass in Shadowmoon Valley. He holds a medallion fragment." },
  ["haardgrim"] = { 2, "vrykul located on the Broken Shore", "Haardgrim is a vrykul located on the Broken Shore, where he fell in battle. The golden Val'kyr Danica the Reclaimer deemed his and Alrik's souls worthy and brought them to the Halls of Valor to become part of the Valarjar." },
  ["haassert"] = { 2, "Drust located in Ardenweald", "Haassert is a Drust located in Ardenweald." },
  ["habdash"] = { 2, "ogre located in the Grand Bazaar in Dazar'alor", "Habdash is an ogre located in the Grand Bazaar in Dazar'alor." },
  ["hackle"] = { 2, "small gnoll warrior", "Hackle is a small gnoll warrior. He was exiled from the Woodpaw because he is runt of the litter and is not suited to be a brute." },
  ["hacklung"] = { 2, "gnoll located in the Azure Span", "Hacklung is a gnoll located in the Azure Span." },
  ["hadari khan"] = { 2, "centaur located at the Aylaag Camp stops in the Ohn'ahran...", "Hadari Khan is a centaur located at the Aylaag Camp stops in the Ohn'ahran Plains." },
  ["hadja"] = { 2, "broker located in Haven in Zereth Mortis", "Hadja is a broker located in Haven in Zereth Mortis." },
  ["haelgond"] = { 2, "vrykul mentioned by her son", "Haelgond is a vrykul mentioned by her son. The Forsaken have provoked him by speaking ill of her." },
  ["haelmut aegisaxe"] = { 2, "Arathi located in Lorel's Crossing in Hallowfall", "Haelmut Aegisaxe is an Arathi located in Lorel's Crossing in Hallowfall. He tried to convince Dolena to leave Growling Hollow but failed and sent an adventurer after her." },
  ["haephus"] = { 2, "Ascended kyrian located in Elysian Hold in Bastion", "Haephus is an Ascended kyrian located in Elysian Hold in Bastion. He was entrusted by the Archon with guarding the anima stores of the Kyrian Covenant until they were needed." },
  ["haetio"] = { 2, "Ascended kyrian located at Haetio's Solace in Bastion", "Haetio is an Ascended kyrian located at Haetio's Solace in Bastion." },
  ["hagar"] = { 2, "haranir located in Harandar", "Hagar is a haranir located in Harandar. She was once a rootwarden of Teldrassil." },
  ["hagashi"] = { 2, "vulpera innkeeper located at the Vulpera Hideaway in Vol'dun", "Hagashi is a vulpera innkeeper located at the Vulpera Hideaway in Vol'dun. After vulpera adventurers proved their people's worth to the Horde, Kiro had Hagashi put together a small memento in appreciation of their efforts." },
  ["hagenbran"] = { 2, "earthen located on the Isle of Dorn", "Hagenbran is an earthen located on the Isle of Dorn." },
  ["hagg taurenbane"] = { 2, "rare quilboar found in Blackthorn Ridge in the Southern B...", "Hagg Taurenbane is a rare quilboar found in Blackthorn Ridge in the Southern Barrens. He is on a 5-8 hour respawn timer." },
  ["haggis boatmurder"] = { 2, "dwarf found inside Bael Modan Keep at Bael Modan in the S...", "Haggis Boatmurder  is a dwarf found inside Bael Modan Keep at Bael Modan in the Southern Barrens. He sometimes guards the  [Bael'Dun Fortress Schematics]." },
  ["haggrum bloodfist"] = { 2, "orc quest giver located at the Northern Rocketway Exchang...", "Haggrum Bloodfist is an orc quest giver located at the Northern Rocketway Exchange in Azshara. He previously resided at Valormok." },
  ["hahk'zor"] = { 2, "', "Hahk'Zor is rare ogre located at Dreadmaul Rock in the Burning Steppes." },
  ["haimaz"] = { 2, "earthen located at Shadowvein Point in the Ringing Deeps", "Haimaz is an earthen located at Shadowvein Point in the Ringing Deeps." },
  ["hairless the menace"] = { 2, "kobold located in Mourning Rise on the Isle of Dorn", "Hairless the Menace is a kobold located in Mourning Rise on the Isle of Dorn." },
  ["haiyan the unstoppable"] = { 2, "leader of the Kargesh clan", "Haiyan the Unstoppable is the leader of the Kargesh clan. He and his clan have gathered at the Mogu'shan Palace, alongside clans Harthak and Gurthan to prove their worth to their king." },
  ["hakasi"] = { 2, "vulpera initially found as a captive of the Faithless set...", "Hakasi is a vulpera initially found as a captive of the Faithless sethrak at the Serpent's Maw in Vol'dun. After being rescued by the player, he can be seen in the Vulpera Hideaway, conversing with Kipp." },
  ["hakkap one-leg"] = { 2, "first vrykul to learn how to tame the storm drakes of Sto...", "Hakkap One-leg was the first vrykul to learn how to tame the storm drakes of Stormheim. He and his powerful black drake, Ruthless, were unbeatable in battle, his newly trained Galeborn the fiercest warband in Stormheim." },
  ["haklang ulfsson"] = { 2, "vrykul located in Skyhold", "Haklang Ulfsson is a vrykul located in Skyhold." },
  ["hako"] = { 2, "tortollan located in the Sand Bar in Zuldazar", "Hako is a tortollan located in the Sand Bar in Zuldazar." },
  ["hala"] = { 2, "kyrian located in Torghast", "Hala is a kyrian located in Torghast, Tower of the Damned." },
  ["haldarr felsworn"] = { 2, "', "Haldarr Felsworns were satyrs found in Azshara." },
  ["haldarr satyr"] = { 2, "', "Haldarr Satyrs are satyrs found in Azshara." },
  ["haldarr trickster"] = { 2, "', "Haldarr Tricksters are satyrs found in Azshara." },
  ["haley copperturn"] = { 2, "engineering vendor found at the Argent Stand in Zul'Drak", "Haley Copperturn is an engineering vendor found at the Argent Stand in Zul'Drak." },
  ["halfdan sly-stalker"] = { 2, "vrykul located in the Great Mead Hall in Skyhold during  ...", "Halfdan Sly-Stalker is a vrykul located in the Great Mead Hall in Skyhold during  [60] A Hate-Hate Relationship. He is seen facing off against Drithen the Boisterous, encircled by many Valarjar Aspirants." },
  ["halfdan the ice-hearted"] = { 2, "thane of the Winterskorn clan", "Halfdan the Ice-Hearted is the thane of the Winterskorn clan. He seeks 'ascension', a ritual which can grant great power to the worthy." },
  ["halfid ironeye"] = { 2, "vrykul located on the expedition isles", "Halfid Ironeye is a vrykul located on the expedition isles." },
  ["halfkan"] = { 2, "captain of a merchant crew", "Halfkan is the captain of a merchant crew, who were willing to smuggle Mathias Shaw and the imprisoned Sira Moonwarden from Dazar'alor to Stormwind City. He is noted for having a sour-face and red hair." },
  ["halford ramsey"] = { 2, "famous human special investigator from Gilneas", "Halford Ramsey is a famous human special investigator from Gilneas. Halford and his partner Cox were investigating the murders made by the so-called Starlight Slasher, but in the process, he found something he did not expect: the worgen." },
  ["halga bloodeye"] = { 2, "orc quest giver found at the Far Watch Post in the Northe...", "Halga Bloodeye is an orc quest giver found at the Far Watch Post in the Northern Barrens. This section concerns content related to Legion." },
  ["hallowfall aeroknight"] = { 2, "', "Hallowfall Aeroknights are Arathi located in Silvermoon City." },
  ["hallowfall engineer"] = { 2, "', "Hallowfall Engineers are Arathi located in Dornogal." },
  ["halsvir fjinnsonn"] = { 2, "vrykul", "Halsvir Fjinnsonn is a vrykul who recorded a chapter in The Legend of Odyn." },
  ["ham'urit"] = { 2, "tuskarr located in Morqut Village on the Forbidden Reach", "Ham'urit is a tuskarr located in Morqut Village on the Forbidden Reach. After completing  [70] Primordial Embellishment, part of the Zskera Vaults chain, Ham'urit will break down unwanted Primordial Stones for the  [Onyx Annulet] into 6x  [Dormant..." },
  ["hama brightleaf"] = { 2, "tauren reagent vendor located at Crushblow in the Twiligh...", "Digel East Nickens is a tauren reagent vendor located at Crushblow in the Twilight Highlands." },
  ["hamelda"] = { 2, "earthen located at the Keepers Terrace in Dornogal", "Hamelda is an earthen located at the Keepers Terrace in Dornogal." },
  ["hamma the butcher"] = { 2, "centaur vendor located in the Field of Ferocity in the Oh...", "Hamma the Butcher is a centaur vendor located in the Field of Ferocity in the Ohn'ahran Plains." },
  ["hammer (ogre)"] = { 2, "ogre located at Brute's Rise in Ashran", "Hammer is an ogre located at Brute's Rise in Ashran." },
  ["hammer outcast"] = { 2, "', "Hammer Outcasts are void elves and worgen located at the Western Spray on Mechagon Island." },
  ["hana breezeheart"] = { 2, "tauren vendor located at the Gala of Gifts in Durotar dur...", "Hana Breezeheart is a tauren vendor located at the Gala of Gifts in Durotar during Love is in the Air." },
  ["handler kla'vik"] = { 2, "mantid stable master located at Klaxxi'vess in the Dread ...", "Handler Kla'vik is a mantid stable master located at Klaxxi'vess in the Dread Wastes." },
  ["haniko"] = { 2, "vulpera located in the Wild Preserve in the Waking Shores", "Haniko is a vulpera located in the Wild Preserve in the Waking Shores. This section concerns content related to The War Within." },
  ["hannan"] = { 2, "haranir found in Azj-Kahet", "Hannan is a haranir found in Azj-Kahet and Harandar." },
  ["hannval the butcher"] = { 2, "vrykul located in the Jotunnwood in Stormheim", "Hannval the Butcher is a vrykul located in the Jotunnwood in Stormheim." },
  ["hansa"] = { 2, "tortollan located in Little Tortolla in Dazar'alor", "Hansa is a tortollan located in Little Tortolla in Dazar'alor. She was present in Zanchul during Talanji's coronation." },
  ["hanu"] = { 2, "tuskarr located in the Azure Span", "Hanu is a tuskarr located in the Azure Span. She sells Renown-unlocked weapon cosmetics." },
  ["hapaniut"] = { 2, "tuskarr vendor located in Uktulut Pier in the Waking Shores", "Hapaniut is a tuskarr vendor located in Uktulut Pier in the Waking Shores." },
  ["happy greymist murloc"] = { 2, "murloc located in Darkshore", "Happy Greymist Murloc is a murloc located in Darkshore." },
  ["happy greymist orphan"] = { 2, "murloc located in Darkshore", "Happy Greymist Orphan is a murloc located in Darkshore." },
  ["hara bloodfury"] = { 2, "orc located at Windreaver's Rise in Shadowmoon Valley", "Hara Bloodfury is an orc located at Windreaver's Rise in Shadowmoon Valley." },
  ["harald the scarred"] = { 2, "deceased vrykul located in Beryl Meadow in Stormsong Valley", "Harald the Scarred is a deceased vrykul located in Beryl Meadow in Stormsong Valley, having been killed by Severus the Outcast." },
  ["haranto darkstrider"] = { 2, "Tauren Death Knight", "Haranto Darkstrider is a Tauren Death Knight that appears on the following World of Warcraft: Trading Card Game cards." },
  ["harash"] = { 2, "naga shaman", "Tide Priest Harash is a naga shaman that rules the Broken Isles and the Death Hiss tribe." },
  ["harb clawhoof"] = { 2, "tauren", "Harb Clawhoof is a tauren who sells kodo mounts, located in Bloodhoof Village in Mulgore." },
  ["harb foulmountain"] = { 2, "rare tauren found patrolling across three small plateaus ...", "Harb Foulmountain is a rare tauren found patrolling across three small plateaus in the northern part of Darkcloud Pinnacle in Thousand Needles. He was on a 5-8 hour respawn timer." },
  ["harbinger argomen"] = { 2, "draenei located in the Terrace of Light in Shattrath City...", "Harbinger Argomen was a draenei located in the Terrace of Light in Shattrath City standing next to High Exarch Commodus and Veteran Vindicators." },
  ["harbinger elm"] = { 2, "agent from Lordaeron", "Harbinger Elm is an agent from Lordaeron, but unknown from what organization, that was to meet with the Grimtotem tribe. They were going to form a working relationship, so long as the Grimtotem were completely obedient to them." },
  ["harbinger il'koxik"] = { 2, "mantid located in Winterbough Glade in the Vale of Eterna...", "Harbinger Il'koxik is a mantid located in Winterbough Glade in the Vale of Eternal Blossoms." },
  ["harbinger of the raven"] = { 2, "arakkoa summoned in Veil Ruuan in the Blade's Edge Mountains", "Harbinger of the Raven is an arakkoa summoned in Veil Ruuan in the Blade's Edge Mountains, using 6 Ruuan'ok Claws at the Ruaan'ok Oracle Circle." },
  ["harborage guardian"] = { 2, "', "Harborage Guardians are Broken found guarding the Harborage of Swamp of Sorrows. A powerful top-level version appears if Horde approach the settlement." },
  ["hardboiled egg"] = { 2, "murloc pet", "The Hardboiled Egg was a murloc pet." },
  ["hardrogg"] = { 2, "drogbar singer", "Hardrogg is a drogbar singer who occasionally appears with his band of drummers — Boprul, Tinkrul and Clomprul — in the Stonedark Grotto in Highmountain." },
  ["hargrin"] = { 2, "earthen located in the Fissure in Dornogal", "Hargrin is an earthen located in the Fissure in Dornogal. He can be found talking with Relorin Lighthand." },
  ["harick boulderdrum"] = { 2, "dwarf wand vendor located in the Mystic Ward in Ironforge", "Harick Boulderdrum is a dwarf wand vendor located in the Mystic Ward in Ironforge. He works in the Fighting Wizard." },
  ["harleen chirpsnide"] = { 2, "goblin located in Bluefeather Cliffs in Thaldraszus", "Harleen Chirpsnide is a goblin located in Bluefeather Cliffs in Thaldraszus." },
  ["harlo barnaby"] = { 2, "dwarf quest giver located in Menethil Harbor in the Wetlands", "Harlo Barnaby is a dwarf quest giver located in Menethil Harbor in the Wetlands. He survived the invasion of Dun Modr by the Dark Iron dwarves, but was hit by a stray axe in the back as he was fleeing and woke up in Menethil Harbor." },
  ["harlowe"] = { 2, "venthyr located in the Ember Court", "Harlowe is a venthyr located in the Ember Court." },
  ["harmot"] = { 2, "earthen geomender located on the Isle of Dorn", "Harmot is an earthen geomender located on the Isle of Dorn. He is the author of Observational Notes: Stormrooks, Observational Notes: Ramoliths and Observational Notes: Cinderbees." },
  ["harooka"] = { 2, "', "Harooka is one of the oldest fishers from Taruka's clan of tuskarr. Her moustache is dyed blue, and her tusks are carved with marks of great deeds instead of the usual family or clan symbols worn by most of her kind." },
  ["harpo boltknuckle"] = { 2, "goblin flight master located at the Krazzworks in the Twi...", "Harpo Boltknuckle is a goblin flight master located at the Krazzworks in the Twilight Highlands." },
  ["harpoon master yavus"] = { 2, "vrykul located in Nifflevar in the Howling Fjord", "Harpoon Master Yavus is a vrykul located in Nifflevar in the Howling Fjord." },
  ["harr grayhide"] = { 2, "tauren found on the Skybag in the Brawl'gar Arena", "Harr Grayhide is a tauren found on the Skybag in the Brawl'gar Arena." },
  ["harrier nir'verash"] = { 2, "mantid located in the Vale of Eternal Blossoms", "Harrier Nir'verash is a mantid located in the Vale of Eternal Blossoms." },
  ["harry lawson"] = { 2, "worgen located at Lunarfall in Shadowmoon Valley", "Harry Lawson is a worgen located at Lunarfall in Shadowmoon Valley. He can only be recruited using the Headhunter's Harvest from Lunarfall Inn." },
  ["harthak adept"] = { 2, "', "Harthak Adepts are mogu located at Mogu'shan Palace." },
  ["harthak flameseeker"] = { 2, "', "Harthak Flameseekers are mogu located at Mogu'shan Palace." },
  ["harthak stormcaller"] = { 2, "', "Harthak Stormcallers are mogu located at Mogu'shan Palace." },
  ["haruqti"] = { 2, "tuskarr fish vendor located in Kauriq Gleamlet in the Azu...", "Haruqti is a tuskarr fish vendor located in Kauriq Gleamlet in the Azure Span." },
  ["harvester akaro"] = { 2, "ankoan located in Nazjatar", "Harvester Akaro is an ankoan located in Nazjatar." },
  ["harvester farnee"] = { 2, "earthen located at Durgaz Cabin on the Isle of Dorn", "Harvester Farnee is an earthen located at Durgaz Cabin on the Isle of Dorn. Farnee is a tender to bees." },
  ["hashim"] = { 2, "ethereal located at Overlook Zo'Shuul on K'aresh", "Hashim is an ethereal located at Overlook Zo'Shuul on K'aresh. He serves as the  [Reshii Wraps] upgrader, trading three  [Ethereal Strands] for another point on the upgrade tree." },
  ["hatecoil ambusher"] = { 2, "', "Hatecoil Ambushers are naga located in Azsuna." },
  ["hatecoil arcanist"] = { 2, "', "Hatecoil Arcanists are naga located in the Eye of Azshara." },
  ["hatecoil crestrider"] = { 2, "', "Hatecoil Crestriders are naga located at the Hatecoil Encampment of the Eye of Azshara. They are summoned by Warlord Parjesh to defend him." },
  ["hatecoil deepsinger"] = { 2, "', "Hatecoil Deepsingers are naga located in Azsuna. They accompany Golza the Iron Fin." },
  ["hatecoil enchantress"] = { 2, "', "Hatecoil Enchantresses are naga located in Azsuna." },
  ["hatecoil fathom-stalker"] = { 2, "', "Hatecoil Fathom-Stalkers are naga located in Hatecoil Warcamp in Azsuna." },
  ["hatecoil guardian"] = { 2, "', "Hatecoil Guardians are naga located on the Isle of the Watchers in Azsuna." },
  ["hatecoil harpooner"] = { 2, "', "Hatecoil Harpooners are naga located in Azsuna." },
  ["hatecoil myrmidon"] = { 2, "', "Hatecoil Myrmidons are naga located in Azsuna." },
  ["hatecoil oracle"] = { 2, "', "Hatecoil Oracles are naga located in the instanced and uninstanced versions of the Eye of Azshara." },
  ["hatecoil raider"] = { 2, "', "Hatecoil Raiders are naga located in Azsuna." },
  ["hatecoil reservist"] = { 2, "', "Hatecoil Reservists are naga located in Azsuna." },
  ["hatecoil riptail"] = { 2, "', "Hatecoil Riptails are naga located in Azsuna." },
  ["hatecoil shellbreaker"] = { 2, "', "Hatecoil Shellbreakers are hostile naga that assist Warlord Parjesh during his encounter in the Eye of Azshara." },
  ["hatecoil slavemaster"] = { 2, "', "Hatecoil Slavemasters are naga located in Azsuna." },
  ["hatecoil slaver"] = { 2, "', "Hatecoil Slavers are naga located in Azsuna." },
  ["hatecoil spirit"] = { 2, "naga spirit located in Azsuna", "Hatecoil Spirit is a naga spirit located in Azsuna. She is summoned by  [Hatecoil Spearhead]." },
  ["hatecoil spitespeaker"] = { 2, "', "Hatecoil Spitespeakers are naga located in Hatecoil Warcamp in Azsuna. Some of them can be seen corrupting the souls of Subjugated Murlocs with corrupting waters." },
  ["hatecoil stormcaller"] = { 2, "', "Hatecoil Stormcallers are naga located in Azsuna." },
  ["hatecoil stormspeaker"] = { 2, "', "Hatecoil Stormspeakers are naga located on the Isle of the Watchers of Azsuna. They use spells of lightning." },
  ["hatecoil stormweaver"] = { 2, "', "Hatecoil Stormweavers are naga located in the instanced and uninstanced versions of the Eye of Azshara." },
  ["hatecoil warrior"] = { 2, "', "Hatecoil Warriors are naga located in the instanced and uninstanced versions of the Eye of Azshara." },
  ["hatecoil wavebinder"] = { 2, "', "Hatecoil Wavebinders are naga located in the Eye of Azshara. They summon water elementals." },
  ["hatecoil wrangler"] = { 2, "', "Hatecoil Wranglers are naga located in the instanced and uninstanced versions of the Eye of Azshara. They have spears." },
  ["hatecrest myrmidon"] = { 2, "', "Hatecrest Myrmidon were naga found off the coast of Ruins of Solarsal on Sardor Isle in Feralas." },
  ["hatecrest screamer"] = { 2, "', "Hatecrest Screamers were naga found off the coast of Ruins of Solarsal on Sardor Isle in Feralas." },
  ["hatecrest serpent guard"] = { 2, "', "Hatecrest Serpent Guards were naga found in Shalzaru's Lair and off the coast of the Ruins of Solarsal on Sardor Isle in Feralas." },
  ["hatecrest siren"] = { 2, "', "Hatecrest Sirens were naga found off the coast of Ruins of Solarsal on Sardor Isle in Feralas." },
  ["hatecrest sorceress"] = { 2, "', "Hatecrest Sorceresses are naga located at the Ruins of Feathermoon and Ruins of Solarsal on Sardor Isle in Feralas. Before the Cataclysm, they could be found in Shalzaru's Lair." },
  ["hatecrest warrior"] = { 2, "', "Hatecrest Warriors are naga found off the coast of Ruins of Solarsal on Sardor Isle in Feralas." },
  ["hatecrest wave rider"] = { 2, "', "Hatecrest Wave Riders were naga found off the coast of Ruins of Solarsal on Sardor Isle in Feralas." },
  ["hatefury betrayer"] = { 2, "', "Hatefury Betrayers can be found at Sargeron in Desolace." },
  ["hatefury felsworn"] = { 2, "', "Hatefury Felsworn are satyr found at Sargeron in Desolace." },
  ["hatefury hellcaller"] = { 2, "', "Hatefury Hellcallers can be found at Sargeron in Desolace." },
  ["hatefury rogue"] = { 2, "', "Hatefury Rogues can be found at Sargeron in Desolace." },
  ["hatefury shadowstalker"] = { 2, "', "Hatefury Shadowstalkers can be found at Sargeron in Desolace." },
  ["hatefury trickster"] = { 2, "', "Hatefury Tricksters can be found at Sargeron in Desolace." },
  ["hathlaz"] = { 2, "stasis-locked earthen located in Candleslag Quarry in the...", "Hathlaz is a stasis-locked earthen located in Candleslag Quarry in the Ringing Deeps. Next to him is his plaque." },
  ["haughty rival"] = { 2, "', "Haughty Rivals are venthyr located in Revendreth." },
  ["haun fleethoof"] = { 2, "tauren", "Haun Fleethoof is a tauren that participates in the Darkmoon Dance Competition in South Pavilion on Darkmoon Island." },
  ["havak"] = { 2, "rare mogu found in Mogujia in Kun-Lai Summit", "Havak is a rare mogu found in Mogujia in Kun-Lai Summit. When first encountered, Havak is a statue, blending in easily among the other petrified mogu and quilen, but comes to life when attacked or when a player comes too close." },
  ["haverd sunhart"] = { 2, "Arathi located at the Sanctified Grounds in the Priory of...", "Haverd Sunhart is an Arathi located at the Sanctified Grounds in the Priory of the Sacred Flame in Hallowfall." },
  ["hawli"] = { 2, "haranir located in the Den in Harandar", "Hawli is a haranir located in the Den in Harandar." },
  ["hazzik"] = { 2, "arakkoa quest giver located at Blackwind Landing in Terok...", "Hazzik is an arakkoa quest giver located at Blackwind Landing in Terokkar Forest." },
  ["head custodian javlin"] = { 2, "venthyr located in Sanguine Depths", "Head Custodian Javlin is a venthyr located in Sanguine Depths." },
  ["head poacher skrathax"] = { 2, "naga", "Head Poacher Skrathax is a naga that was to appear in Nazmir. Based on the description of  [110 - 120] Orders Received, he was likely to be a member of the Vilescale." },
  ["head rancher stenspor"] = { 2, "head rancher of Rambleshire on the Isle of Dorn", "Head Rancher Stenspor is the head rancher of Rambleshire on the Isle of Dorn." },
  ["headless ghost"] = { 2, "Forsaken ghost found in all major cities as well as Shatt...", "The Headless Ghost is a Forsaken ghost found in all major cities as well as Shattrath and Dalaran. Talking to him allows players to queue up to fight the Headless Horseman using the Dungeon Finder." },
  ["headless horseman (rumble)"] = { 2, "troop of the Undead family", "The Headless Horseman is a troop of the Undead family. Known for his high speed and powerful area of effect attacks, this unit specializes in quick engagement and high-impact attacks." },
  ["headmaster fynch"] = { 2, "Arathi located in Lightspark Commissary in Hallowfall", "Headmaster Fynch is an Arathi located in Lightspark Commissary in Hallowfall. He is the headmaster of Lightspark Academy." },
  ["headshrinker gaha"] = { 2, "troll located in Island Expeditions", "Headshrinker Gaha is a troll located in Island Expeditions." },
  ["healer dalagh"] = { 2, "draenei located in Three-Falls Lookout in the Azure Span", "Healer Kalista Dalagh is a draenei located in Three-Falls Lookout in the Azure Span. Her team consists of Modurun Sixtoes, Miner Proudrock, and Excavator Silversun." },
  ["healer selbekh"] = { 2, "centaur located in Maruukai in the Ohn'ahran Plains", "Healer Selbekh is a centaur located in Maruukai in the Ohn'ahran Plains." },
  ["healing wing"] = { 2, "', "Healing Wings are dracthyr found at the Caldera of the Menders and Old Weyrn Grounds on the Forbidden Reach and in Valdrakken." },
  ["healing wing messenger"] = { 2, "dracthyr found at the Caldera of the Menders in the Forbi...", "Healing Wing Messenger is a dracthyr found at the Caldera of the Menders in the Forbidden Reach." },
  ["hearthkeeper atahl"] = { 2, "centaur innkeeper located in Teerakai in the Ohn'ahran Pl...", "Hearthkeeper Atahl is a centaur innkeeper located in Teerakai in the Ohn'ahran Plains." },
  ["hearthkeeper bayon"] = { 2, "centaur innkeeper located in Maruukai in the Ohn'ahran Pl...", "Hearthkeeper Bayon is a centaur innkeeper located in Maruukai in the Ohn'ahran Plains." },
  ["hearthkeeper berulan"] = { 2, "centaur innkeeper located on the Shikaar rise in Maruukai...", "Hearthkeeper Berulan is a centaur innkeeper located on the Shikaar rise in Maruukai in the Ohn'ahran Plains. She is also present in the Nokhud Offensive, in which she acts solely as a food vendor despite still having the title of <Innkeeper>." },
  ["hearthkeeper erden"] = { 2, "centaur innkeeper located at the Ohn'ir pools in Maruukai...", "Hearthkeeper Erden is a centaur innkeeper located at the Ohn'ir pools in Maruukai in the Ohn'ahran Plains." },
  ["hearthkeeper katari"] = { 2, "earthen located in the Hearthside Suite in Dornogal", "Hearthkeeper Katari is an earthen located in the Hearthside Suite in Dornogal." },
  ["hearthkeeper khonor"] = { 2, "centaur innkeeper located at Broadhoof Outpost in the Ohn...", "Hearthkeeper Khonor is a centaur innkeeper located at Broadhoof Outpost in the Ohn'ahran Plains." },
  ["hearthkeeper marag"] = { 2, "centaur innkeeper located at Forkriver Crossing in the Oh...", "Hearthkeeper Marag is a centaur innkeeper located at Forkriver Crossing in the Ohn'ahran Plains." },
  ["hearthkeeper nokhor"] = { 2, "centaur innkeeper located at Timberstep Outpost in the Oh...", "Hearthkeeper Nokhor is a centaur innkeeper located at Timberstep Outpost in the Ohn'ahran Plains." },
  ["hearthstone enthusiast"] = { 2, "', "The Hearthstone Enthusiasts are a pair of tortollans playing Hearthstone in Anyport in Drustvar." },
  ["heavy brewbrul"] = { 2, "', "Heavy Brewbruls are drogbar located in Highmountain." },
  ["heavy chan"] = { 2, "large pandaren from One Keg", "Heavy Chan is a large pandaren from One Keg and the son of a wealthy alchemist. He was one of the ten volunteers who decided to take The Trial of the Red Blossoms in order to join the Shado-pan." },
  ["heavy murloc egg"] = { 2, "murloc companion", "Heavy Murloc Egg teaches Grunty, a murloc companion. This baby murloc wears Terran Marine armor and wields a gauss rifle, which he'll occasionally fire around at perceived enemies." },
  ["hecht copperpinch"] = { 2, "goblin food", "Hecht Copperpinch is a goblin food and drink vendor located at Mor'shan Base Camp in the Northern Barrens." },
  ["hed'mush the rotting"] = { 2, "rare undead ogre found in the Noxious Glade of the Easter...", "Hed'mush the Rotting is a rare undead ogre found in the Noxious Glade of the Eastern Plaguelands." },
  ["hefty enforcer"] = { 2, "ogre located in Frostfire Ridge", "Hefty Enforcer was an ogre located in Frostfire Ridge. He found a huge supply cache, but was taken out by the followers sent from the garrisons." },
  ["heidirk the scalekeeper"] = { 2, "vrykul located at Aalgen Point in the Broken Shore", "Heidirk the Scalekeeper is a vrykul located at Aalgen Point in the Broken Shore." },
  ["heissanik"] = { 2, "earthen located at Shadowvein Point in the Ringing Deeps", "Heissanik is an earthen located at Shadowvein Point in the Ringing Deeps." },
  ["heixi the stonelord"] = { 2, "mogu located in the Vale of Eternal Blossoms", "Heixi the Stonelord is a mogu located in the Vale of Eternal Blossoms." },
  ["hekgarda"] = { 2, "earthen located in Hunter Rise in Thunder Bluff", "Hekgarda is an earthen located in Hunter Rise in Thunder Bluff. She is accompanied by a Saddled Cloudrook." },
  ["hel'nurathian conjuror"] = { 2, "', "Hel'nurathian Conjurors are satyrs located in Shadow Hold in Felwood during the Heritage of the Kaldorei." },
  ["hel'nurathian trickster"] = { 2, "', "Hel'nurathian Tricksters are satyrs located in Shadow Hold in Felwood during the Heritage of the Kaldorei." },
  ["helarjar soulthief"] = { 2, "', "Helarjar Soulthieves are vrykul located in Stormheim." },
  ["helen hoggins"] = { 2, "worgen located at the Town Center in Founder's Point", "Helen Hoggins is a worgen located at the Town Center in Founder's Point." },
  ["helga bonehewer"] = { 2, "orc standing next to Libbiara Blightrunner aboard the Sky...", "Helga Bonehewer is an orc standing next to Libbiara Blightrunner aboard the Skybag in the Brawl'gar Arena. She acts flirtatious to male characters, and hostile to female ones." },
  ["helgus"] = { 2, "vrykul bard", "Helgus was a vrykul bard who lived in Nifflevar and wrote three sagas: the  [Saga of the Twins], the  [Saga of the Winter Curse] and the  [Saga of the Val'kyr]." },
  ["hellak darkhorn"] = { 2, "tauren warrior in the service of the Alliance", "Hellak Darkhorn was a tauren warrior in the service of the Alliance. He mistrusts the orcs because he thinks they are to quick to fight and willing to do it dirty, because of their demon-tainted history." },
  ["hellbringer xaroth"] = { 2, "satyr located near the northern shores of Azsuna", "Hellbringer Xaroth was a satyr located near the northern shores of Azsuna. He was killed by the druid champions sent from the Dreamgrove." },
  ["helmi cooper"] = { 2, "worgen located next to the Dye Station at the Town Center...", "Helmi Cooper is a worgen located next to the Dye Station at the Town Center in Founder's Point." },
  ["helpful squireling"] = { 2, "', "Helpful Squirelings are kobolds located in Campalot in the Ringing Deeps." },
  ["helsworn beastlord"] = { 2, "', "Helsworn Beastlords are kyrian located in Desmotaeron in the Maw." },
  ["helsworn dominator"] = { 2, "', "Helsworn Dominators are Helsworn kyrian located in the Helgarde Keep of Desmotaeron in the Maw. The dominators are working on Forsworn Prisoners and must be defeated while on  [60] What Maldraxxus Does Best." },
  ["helsworn inquisitor"] = { 2, "', "Helsworn Inquisitors are kyrian located in Desmotaeron in the Maw." },
  ["helsworn soulbreaker"] = { 2, "', "Helsworn Soulbreakers are Helsworn kyrian located in the Maw. Normally unattackable, they can be pulled out of the sky with  [Mawsworn Chains] for  [60] Clip Their Wings during the Chains of Domination campaign." },
  ["hemma beringer"] = { 2, "worgen guard of Princess Tess Greymane located in Shadowm...", "Hemma Beringer is a worgen guard of Princess Tess Greymane located in Shadowmoon Valley. She is sick." },
  ["henning roest"] = { 2, "Arathi found overlooking the cliffs at northeastern Merel...", "Henning Roest is an Arathi found overlooking the cliffs at northeastern Mereldar in Hallowfall. During shadow curfew, he takes shelter at the inn." },
  ["henry gust"] = { 2, "Forsaken affiliated with the Blight Boar band located in ...", "Henry Gust is a Forsaken affiliated with the Blight Boar band located in front of the Cauldron of Rock on Darkmoon Island." },
  ["hephaesius"] = { 2, "Ascended kyrian located at the Seat of Eternal Hymns in B...", "Hephaesius is an Ascended kyrian located at the Seat of Eternal Hymns in Bastion." },
  ["hephaestus pilgrim"] = { 2, "worgen located in Astranaar in Ashenvale", "Hephaestus Pilgrim is a worgen located in Astranaar in Ashenvale." },
  ["hera fer"] = { 2, "dracthyr located in the Common in Razorwind Shores", "Hera Fer is a dracthyr located in the Common in Razorwind Shores and Town Center in Founder's Point when the Reaching Beyond the Possible endeavor is active." },
  ["herac (dracthyr)"] = { 2, "dracthyr located at the Gardens of Unity in Thaldraszus", "Herac is a dracthyr located at the Gardens of Unity in Thaldraszus. He is found chatting with Magera." },
  ["herald beluus"] = { 2, "draenei found immediately southwest of the Crusaders' Col...", "Herald Beluus is a draenei found immediately southwest of the Crusaders' Coliseum overlooking the ring of champions on the Argent Tournament Grounds in Icecrown. He announces the arrival of the Alliance and Horde leadership parties to the tourname..." },
  ["herald bran'daan"] = { 2, "draenei located in the Seat of the Naaru in the Exodar", "Herald Bran'daan is a draenei located in the Seat of the Naaru in the Exodar. He once gave players an idea of where to go next, but that job has been taken over by the new poster boards." },
  ["herald dalora"] = { 2, "Mawsworn kyrian located throughout Icecrown during Death ...", "Herald Dalora is a Mawsworn kyrian located throughout Icecrown during Death Rising." },
  ["herald fordas"] = { 2, "earthen located in Dornogal", "Herald Fordas is an earthen located in Dornogal." },
  ["herald kurden"] = { 2, "earthen located in Dornogal", "Herald Kurden is an earthen located in Dornogal." },
  ["herald of gorak tul"] = { 2, "Drust located in Stormsong Valley", "Herald of Gorak Tul is a Drust located in Stormsong Valley." },
  ["herald of sunrise"] = { 2, "arakkoa located in Lower Quarter in Skyreach", "The Herald of Sunrise is an arakkoa located in Lower Quarter in Skyreach." },
  ["herald of the crusade"] = { 2, "human located in the Trade District in Stormwind City", "The Herald of the Crusade is a human located in the Trade District in Stormwind City and a Forsaken found in Orgrimmar." },
  ["herald of the queen"] = { 2, "naga located in the Void Chamber in Nazjatar where she is...", "The Herald of the Queen is a naga located in the Void Chamber in Nazjatar where she is trying to convert Mak." },
  ["herbalist agura"] = { 2, "centaur located at his tent in western Teerakai in the Oh...", "Herbalist Agura is a centaur located at his tent in western Teerakai in the Ohn'ahran Plains. As part of Khansguard Jebotai's war orders, he tells Agura to expect to treat wounded soldiers." },
  ["herbalist corteen"] = { 2, "draenei vendor located at Elodor in Shadowmoon Valley", "Herbalist Corteen is a draenei vendor located at Elodor in Shadowmoon Valley." },
  ["herble baubbletump"] = { 2, "gnome engineering", "Herble Baubbletump is a gnome engineering and mining vendor located in Darkshire in Duskwood. He can be found inside a small house off the road between the town proper and the flight master, speaking with Cog Glitzspinner and Finbus Geargrind." },
  ["heredormu"] = { 2, "dracthyr heirloom vendor located in a building in the Bro...", "Heredormu is a dracthyr heirloom vendor located in a building in the Bronze Enclave in Valdrakken." },
  ["heretic bodyguard"] = { 2, "', "Heretic Bodyguards are naga guarding the Heretic Emissary at Zoram Strand in Ashenvale during the Midsummer Fire Festival." },
  ["heretic crystal guard"] = { 2, "', "Heretic Crystal Guards are naga located in Ethel Rethor in Desolace during the Midsummer Fire Festival." },
  ["heretic emissary"] = { 2, "naga", "The Heretic Emissary is a naga, guarded by two Heretic Bodyguards. She has a conversation with Ice Caller Briatha and is part of the Midsummer Fire Festival." },
  ["herme the wise"] = { 2, "deceased vrykul located in Beryl Meadow in Stormsong Valley", "Herme the Wise is a deceased vrykul located in Beryl Meadow in Stormsong Valley, having been killed by Severus the Outcast." },
  ["hermestes"] = { 2, "Ascended kyrian located at the Eternal Watch section of t...", "Hermestes is an Ascended kyrian located at the Eternal Watch section of the Elysian Hold in Bastion. They were present during the reception the Archon arranged for a Maw Walker, who decided to join the Kyrian Covenant, in honor of their efforts ag..." },
  ["hertha grimdottir"] = { 2, "vrykul located at the Crimson Thicket in Suramar", "Hertha Grimdottir is a vrykul located at the Crimson Thicket in Suramar." },
  ["herupitat"] = { 2, "tuskarr located in Iskaara in the Azure Span", "Herupitat is a tuskarr located in Iskaara in the Azure Span. He is flying kites with Paera Finebreeze and Terrath Windchaser." },
  ["hester blackember"] = { 2, "dwarf located at the Lunarfall in Shadowmoon Valley", "Hester Blackember is a dwarf located at the Lunarfall in Shadowmoon Valley. She can only be recruited using the Headhunter's Harvest from Lunarfall Inn." },
  ["hezrul bloodmark"] = { 2, "centaur", "Hezrul Bloodmark is a centaur who patrols the Lushwater Oasis in the Northern Barrens with two Bloodguards. He is the leader of the Kolkar forces in the Barrens, and Regthar Deathgate wants his head." },
  ["hezrul's bloodguard"] = { 2, "', "Hezrul's Bloodguards are two centaur who accompany Hezrul Bloodmark at the Lushwater Oasis in the Northern Barrens." },
  ["hidden assassin"] = { 2, "', "Hidden Assassins can be found in Stormheim. They only spawn during  [45] The Reluctant Queen, where they are sent by Odyn to assassinate Sigryn." },
  ["hidden huntress"] = { 2, "', "Hidden Huntresses can be found in Stormheim. They only spawn during  [45] The Reluctant Queen, where they are sent by Odyn to assassinate Sigryn." },
  ["hideaway patron"] = { 2, "', "Hideaway Patrons are tortollans located at Heyman's Hideaway in Vol'dun." },
  ["hideshaper koruz"] = { 2, "centaur located at the Artisan's Market in Valdrakken", "Hideshaper Koruz is a centaur located at the Artisan's Market in Valdrakken." },
  ["hierophant cenius"] = { 2, "tauren druid located at the D", "Hierophant Cenius is a tauren druid located at the D.E.H.T.A. Encampment in the Borean Tundra." },
  ["hierophant malyk"] = { 2, "worgen quest giver located at Farwatcher's Glen in the St...", "Hierophant Malyk is a worgen quest giver located at Farwatcher's Glen in the Stonetalon Mountains. Despite telling the gnome Salsbury the 'Help' multiple times that he can't teach him how to turn into a worgen, the gnome still incorrectly believes..." },
  ["high adjudicator aleez"] = { 2, "venthyr", "High Adjudicator Aleez is a venthyr and the third boss located in the Halls of Atonement." },
  ["high arakkoa"] = { 2, "arakkoa located in the Spires of Arak", "High Arakkoa is an arakkoa located in the Spires of Arak." },
  ["high artificer ataanya"] = { 2, "draenei found in Aldor Rise in Shattrath City", "High Artificer Ataanya is a draenei found in Aldor Rise in Shattrath City. She is the daughter of the late Exarch Hataaru and the High Artificer of Shattrath." },
  ["high chief bristlelimb"] = { 2, "furbolg found on Bloodmyst Isle", "High Chief Bristlelimb is a furbolg found on Bloodmyst Isle, in the northern-most camp of the Bristlelimb Enclave. He will only appear after you have killed a few of the furbolgs in that camp." },
  ["high chief stillpine"] = { 2, "furbolg quest giver located at Stillpine Hold in Azuremys...", "High Chief Stillpine is a furbolg quest giver located at Stillpine Hold in Azuremyst Isle. He is the chieftain of the Stillpine furbolgs." },
  ["high chief winterfall"] = { 2, "furbolg found in Timbermaw Post in Winterspring", "High Chief Winterfall is a furbolg found in Timbermaw Post in Winterspring. Donova Snowden sends adventurers to kill High Chief Winterfall, should they be successful, they eventually find his  [Crudely-Written Log] and hand it to Donova." },
  ["high chieftain cliffwalker"] = { 2, "leader of Cliffwalker Post in the Stonetalon Mountains", "High Chieftain Cliffwalker is the leader of Cliffwalker Post in the Stonetalon Mountains. He is vehemently opposed to the efforts of Overlord Krom'gar and General Grebo to destroy Thal'darah Grove (the two orc commanders both believe that the Alli..." },
  ["high cleric alphus"] = { 2, "gnome priest found in the townhall of Hearthglen in the W...", "High Cleric Alphus is a gnome priest found in the townhall of Hearthglen in the Western Plaguelands." },
  ["high councilor mal'gris"] = { 2, "ogre located at the Throne of the Imperator in Highmaul", "High Councilor Mal'gris is an ogre located at the Throne of the Imperator in Highmaul. He is the High Councilor of the Gorian War Council." },
  ["high courier taelica"] = { 2, "Ascended kyrian", "High Courier Taelica is an Ascended kyrian." },
  ["high crusader adelard"] = { 2, "', "High Crusader Adelard can be found in the Argent Pavilion at the Argent Tournament Grounds. He, along with Crusader Silverdawn, offers daily quests to players who have earned the title <Crusader>." },
  ["high elder ommirith"] = { 2, "murloc ghost", "High Elder Ommirith is a murloc ghost." },
  ["high exarch commodus"] = { 2, "draenei of the Aldor located at the Terrace of Light in S...", "High Exarch Commodus was a draenei of the Aldor located at the Terrace of Light in Shattrath City." },
  ["high general abbendis"] = { 2, "father of High General Brigitte Abbendis", "High General Abbendis was one of the founders of the original Scarlet Crusade. He was the father of High General Brigitte Abbendis, and once, a paladin and general of the Order of the Silver Hand." },
  ["high guard makag"] = { 2, "ogre located in Molten Cay during Island Expeditions", "High Guard Makag is an ogre located in Molten Cay during Island Expeditions." },
  ["high inquisitor dacian"] = { 2, "venthyr located in the Halls of Atonement in Revendreth", "High Inquisitor Dacian is a venthyr located in the Halls of Atonement in Revendreth. He is accompanied by Carved Catalogers." },
  ["high inquisitor fairbanks"] = { 2, "undead hidden in a secret chamber in the Cathedral of the...", "High Inquisitor Fairbanks was an undead hidden in a secret chamber in the Cathedral of the Scarlet Monastery Cathedral, where his corpse is still located in the revamped Scarlet Monastery. Once a priest and member of the Knights of the Silver Hand..." },
  ["high inquisitor gabi"] = { 2, "venthyr located at the Halls of Atonement in Revendreth", "High Inquisitor Gabi is a venthyr located at the Halls of Atonement in Revendreth. In life, her name was Trikidi the Bloody." },
  ["high inquisitor magda"] = { 2, "venthyr located at the Halls of Atonement in Revendreth", "High Inquisitor Magda is a venthyr located at the Halls of Atonement in Revendreth. In life, her name was Lilizzinnk the Obscene." },
  ["high inquisitor radu"] = { 2, "venthyr located at the Halls of Atonement in Revendreth", "High Inquisitor Radu is a venthyr located at the Halls of Atonement in Revendreth. To attack her,  [High Inquisitor Radu's Sinstone] is needed." },
  ["high inquisitor vetar"] = { 2, "venthyr located in the Ember Court", "High Inquisitor Vetar is a venthyr located in the Ember Court." },
  ["high overseer bloodmane"] = { 2, "logistics officer for the Horde", "High Overseer Bloodmane was a logistics officer for the Horde. He was once usually found at The Dranosh'ar Blockade in Durotar, standing on opposite side of the road facing Holgar Stormaxe, but was promoted to Overseer of Razor Hill where he met h..." },
  ["high priest aemya"] = { 2, "Arathi located at Sanctified Grounds in the Priory of the...", "High Priest Aemya is an Arathi located at Sanctified Grounds in the Priory of the Sacred Flame." },
  ["high priest andorath"] = { 2, "Darkfallen of the San'layn located in the Spire of Blood ...", "High Priest Andorath is a Darkfallen of the San'layn located in the Spire of Blood of the Temple City of En'kilah in the Borean Tundra. During the war against the Lich King, Andorth alongside the high priests Naferset and Talet-Kha performed dark ..." },
  ["high priest danaar"] = { 2, "draenei located at Lunarfall in Shadowmoon Valley", "High Priest Danaar is a draenei located at Lunarfall in Shadowmoon Valley." },
  ["high priest ikzan"] = { 2, "rare arakkoa found in the Ruins of Kra'nak in Tanaan Jungle", "High Priest Ikzan is a rare arakkoa found in the Ruins of Kra'nak in Tanaan Jungle." },
  ["high priestess mourn"] = { 2, "Forsaken priest located in the south-eastern alcove in Ne...", "High Priestess Mourn is a Forsaken priest located in the south-eastern alcove in Netherlight Temple. Mourn can be used to recruit Hooded Priest follower troops, but will only appear if the player has researched the Hooded Priests class hall advanc..." },
  ["high priestess navi derolan"] = { 2, "', "The sinstone of High Priestess Navi DeRolan is found in the Dredgewood in Revendreth." },
  ["high priestess silthera"] = { 2, "naga located in Azshara", "High Priestess Silthera is a naga located in Azshara. She holds Arkkoroc's heart to controls his sons." },
  ["high ravenspeaker krikka"] = { 2, "leader of the Ravenspeakers", "High Ravenspeaker Krikka is the leader of the Ravenspeakers, an arakkoa cult dedicated to the worship of Ka'alu, the consort of Anzu. He can be found at the Nest of the Ravenspeakers in Spires of Arak." },
  ["high roller"] = { 2, "Veiled Market", "High Rollers are brokers located in Myza's Oasis in Tazavesh, the Veiled Market." },
  ["high sage viryx"] = { 2, "arakkoa leader of the Adherents of Rukhmar after betrayin...", "High Sage Viryx is the arakkoa leader of the Adherents of Rukhmar after betraying her former clutch-brother Iskar." },
  ["high sage viryx (tactics)"] = { 2, "final Boss of Skyreach in Spires of Arak", "High Sage Viryx is the final Boss of Skyreach in Spires of Arak." },
  ["high sage zelkyr"] = { 2, "predecessor of High Sage Viryx", "High Sage Zelkyr was the predecessor of High Sage Viryx. He possessed the ability to see through the eyes of kaliri." },
  ["high seer jhatal"] = { 2, "djaradin located at the Zaqali Caldera in Zaralek Cavern", "High Seer Jhatal is a djaradin located at the Zaqali Caldera in Zaralek Cavern. She is accompanied by two Blazing Hounds." },
  ["high shaman morg"] = { 2, "ogre located in Island Expeditions", "High Shaman Morg is an ogre located in Island Expeditions." },
  ["high shaman rotknuckle"] = { 2, "gnoll located in the Azure Span", "High Shaman Rotknuckle is a gnoll located in the Azure Span." },
  ["high sorcerer andromath"] = { 2, "human quest giver considered as one of the finest", "High Sorcerer Andromath is a human quest giver considered as one of the finest and most powerful sorcerers not locked away in Dalaran. He is located in the Wizard's Sanctum, in the Mage Quarter of Stormwind City, and during the third invasion of t..." },
  ["high sorceress aryna"] = { 2, "gnome mage found in Ragefire Chasm", "High Sorceress Aryna is a gnome mage found in Ragefire Chasm." },
  ["high speaker eirich"] = { 2, "former High Speaker", "Eirich is the former High Speaker. He served on the Council of Dornogal as the representative of the Machine Speakers." },
  ["high thane jorfus"] = { 2, "rare elite vrykul located at either the Court of Bones", "High Thane Jorfus is a rare elite vrykul located at either the Court of Bones, Sindragosa's Fall, or the Fleshwerks in Icecrown." },
  ["high thaumaturge fural"] = { 2, "djaradin located in Ravaged Rookery in Neltharus", "High Thaumaturge Fural is a djaradin located in Ravaged Rookery in Neltharus. He throws a potion at Magmatusk, but its eruption kills Fural." },
  ["high wakener aargon"] = { 2, "eredar echo located at the Conservatory of the Arcane in ...", "High Wakener Aargon is an eredar echo located at the Conservatory of the Arcane in Eredath. As one of Archimonde's greatest pupils, Aargon held such power in his own disciplines that the Conservatory remembers him even centuries later." },
  ["highmaul arcanist"] = { 2, "', "Highmaul Arcanists are ogres located in Nagrand." },
  ["highmaul archaeologian"] = { 2, "', "Highmaul Archaeologians are ogres located in Nagrand." },
  ["highmaul conscript"] = { 2, "', "Highmaul Conscripts are ogres located in Highmaul." },
  ["highmaul emissary guard"] = { 2, "', "Highmaul Emissary Guards are ogres located in Ironfist Harbor in Nagrand." },
  ["highmaul enforcer"] = { 2, "', "Highmaul Enforcers are ogres located in Nagrand." },
  ["highmaul gladiator"] = { 2, "', "Highmaul Gladiators are ogres located in Highmaul in Nagrand." },
  ["highmaul guard"] = { 2, "', "Highmaul Guards are ogres located in Nagrand." },
  ["highmaul laborer"] = { 2, "', "Highmaul Laborers are ogres located in Nagrand." },
  ["highmaul miner"] = { 2, "', "Highmaul Miners are ogres located in Eastwind Gulch in Nagrand. Some can be found fighting the Greedy Stonemunchers and Voracious Stonemunchers in the area." },
  ["highmaul relic-seeker"] = { 2, "', "Highmaul Relic-Seekers are ogres located in the Spires of Arak." },
  ["highmaul skullcrusher"] = { 2, "', "Highmaul Skullcrushers are ogres located in the Spires of Arak. They are fighting  Befuddled Relic-Seeker and Amorphic Cognitor at Lost Veil Anzu." },
  ["highmaul sorcerer"] = { 2, "', "Highmaul Sorcerers are ogres located in Nagrand." },
  ["highmaul sweeper"] = { 2, "', "Highmaul Sweepers are ogres located in the Coliseum in Highmaul as part of the Kargath Bladefist encounter." },
  ["higs blastscorch"] = { 2, "', "Higs Blastscorch is goblin that pilots The Bogpaddle Bullet in the quest with the same name. He disappears immediately after arriving in Bogpaddle and he don't appear outside of this quest." },
  ["hilda (vulpera)"] = { 2, "vulpera", "Hilda is a vulpera that walks around the Vulpera Hideaway in Vol'dun." },
  ["hilda copperfuze"] = { 2, "gnome located at the Engineering Works in Stormshield", "Hilda Copperfuze is a gnome located at the Engineering Works in Stormshield." },
  ["hildy bufferpolish"] = { 2, "individual", "Hildy Bufferpolish is an individual who engineered the Queen Mae during the Speedbarge Boat Race." },
  ["hillevi the scalekeeper"] = { 2, "vrykul flight master located at Stormtorn Foothills in St...", "Hillevi the Scalekeeper is a vrykul flight master located at Stormtorn Foothills in Stormheim." },
  ["hillsbrad worgen"] = { 2, "', "Hillsbrad Worgen were Hillsbrad Refugees (former residents of Southshore and Hillsbrad Fields) that fled to Fenris Isle after the Forsaken attacked their towns. Realizing that the Forsaken will never stop hunting them until they become servants to..." },
  ["hinkles fastblast"] = { 2, "gnome quest giver found in New Tinkertown", "Hinkles Fastblast is a gnome quest giver found in New Tinkertown, standing around the holographic reproduction of Operation: Gnomeregan in which he participated." },
  ["hinodin"] = { 2, "earthen located with Drokar at the Keepers Terrace in Dor...", "Hinodin is an earthen located with Drokar at the Keepers Terrace in Dornogal." },
  ["hippeusti"] = { 2, "dracthyr located in Thaldraszus", "Hippeusti is a dracthyr located in Thaldraszus." },
  ["hipponius"] = { 2, "Ascended kyrian located in Haven in Zereth Mortis for pla...", "Hipponius is an Ascended kyrian located in Haven in Zereth Mortis for players in the Kyrian Covenant." },
  ["hirano"] = { 2, "ankoan flight master located in Nazjatar", "Hirano is an ankoan flight master located in Nazjatar." },
  ["hired caravan guardian"] = { 2, "', "Hired Caravan Guardians are vulpera fighting the 7th Legion soldiers in Bonetrail Gulch in Vol'dun during the Faction Assaults." },
  ["hired courier (vol'dun)"] = { 2, "', "Hired Couriers are vulpera fighting the 7th Legion soldiers in Bonetrail Gulch in Vol'dun during the Faction Assaults." },
  ["hired kithguard"] = { 2, "', "Hired Kithguards are drogbar located in Loamm in Zaralek Cavern." },
  ["hired looter"] = { 2, "', "Hired Looters are pirates found throughout Kezan during the quest   [1-20] Robbing Hoods. They were hired by Trade Prince Gallywix." },
  ["hired muscle"] = { 2, "', "Hired Muscles are brokers located in Ephemeral Plains in the Sepulcher of the First Ones." },
  ["hired runner"] = { 2, "Veiled Market", "Hired Runners are brokers located in Tazavesh, the Veiled Market." },
  ["hired stealthblade"] = { 2, "', "A Hired Stealthblade appears when you approach Watcher Emil's location in the Catacombs of Regret in Revendreth during  [60] Watcher Emil." },
  ["hirrse"] = { 2, "nerubian spiderling located in Umbral Bazaar in the City ...", "Hirrse is a nerubian spiderling located in Umbral Bazaar in the City of Threads." },
  ["hirzek"] = { 2, "quilboar shaman found near Razorfen Kraul in the Barrens", "Hirzek is a quilboar shaman found near Razorfen Kraul in the Barrens." },
  ["hisek the swarmkeeper"] = { 2, "mantid located at Klaxxi'vess", "Hisek the Swarmkeeper is a mantid located at Klaxxi'vess. Hisek is a paranoid mantid who can track scents and is an expert at rooting out corruption and spies." },
  ["hisskari"] = { 2, "naga located in Nazjatar", "Hisskari is a naga located in Nazjatar." },
  ["historian cortagosa"] = { 2, "dracthyr located in the Caverns of Time", "Historian Cortagosa is a dracthyr located in the Caverns of Time. She is found talking with Historian Gnai Woodlund as Mocha sleeps by her side." },
  ["historian tyrana"] = { 2, "kyrian located in Kalliope's Rest in Bastion", "Historian Tyrana is a kyrian located in Kalliope's Rest in Bastion. She was captured by the Forsworn but eventually rescued by the Maw Walker sent by Haetio, after which she relocated to Haetion's Solace." },
  ["hive-guard naz'ruzek"] = { 2, "mantid located in the Setting Sun Garrison in the Vale of...", "Hive-Guard Naz'ruzek is a mantid located in the Setting Sun Garrison in the Vale of Eternal Blossoms." },
  ["hivelord vix'ick"] = { 2, "mantid located in Un'gol Ruins", "Hivelord Vix'ick is a mantid located in Un'gol Ruins." },
  ["hixin"] = { 2, "', "Hixin was one of Warlord Gurthan's advisers. He used a parchment written by the Warlord that was never sent in order to trick his rival Taskmaster Xuexing into going using a tested weapon against the mantid earlier than intended." },
  ["hjalmar anvilmar"] = { 2, "brother of Thargas Anvilmar", "Hjalmar Anvilmar, nicknamed Hjal, was the brother of Thargas Anvilmar. He trained Varian Wrynn and taught him the 'Anvilmar feint', a dwarf combat stance." },
  ["hoarder jena"] = { 2, "emissary", "Hoarder Jena is the emissary and quartermaster for the Voldunai, located at the Vulpera Hideaway in Vol'dun." },
  ["hoarder moarrgl"] = { 2, "murloc located in Bloodfin Village in Nazjatar", "Hoarder Moarrgl is a murloc located in Bloodfin Village in Nazjatar." },
  ["hobahken"] = { 2, "Broken shaman trainer located at the Crystal Hall in the ...", "Hobahken is a Broken shaman trainer located at the Crystal Hall in the Exodar." },
  ["hogger"] = { 2, "gnoll found atop Hogger Hill in southwestern Elwynn Forest", "Hogger is a gnoll found atop Hogger Hill in southwestern Elwynn Forest. He was the chieftain of the Riverpaw pack." },
  ["hogger (rumble)"] = { 2, "melee ground unit of the Beast family in Warcraft Rumble", "Hogger is a melee ground unit of the Beast family in Warcraft Rumble. Hogger grows stronger the longer a match goes on." },
  ["hogger (tactics)"] = { 2, "gnoll found in Stormwind Stockade", "Hogger is a gnoll found in Stormwind Stockade." },
  ["hogral bakkan"] = { 2, "dwarf rogue trainer located in Thunderbrew Distillery in ...", "Hogral Bakkan is a dwarf rogue trainer located in Thunderbrew Distillery in Kharanos in Dun Morogh. This section concerns content related to Legion." },
  ["hogs' studded collar"] = { 2, "achievement reward from  [That's Whack!]", "Hogs' Studded Collar is an achievement reward from  [That's Whack!]. It summons Hogs, a battle pet version of the infamous Hogger." },
  ["hogtied razormane"] = { 2, "', "Hogtied Razormanes si a Razormane Pillager when captured for  [5-30] Drag it Out of Them." },
  ["hol'bruk the brewcrusher"] = { 2, "ogre located at Highmaul in Nagrand", "Hol'bruk the Brewcrusher is an ogre located at Highmaul in Nagrand. He will only turn hostile once you try to steal his booze." },
  ["holaaru"] = { 2, "Broken quest giver located at Marshtide Watch in the Swam...", "Holaaru is a Broken quest giver located at Marshtide Watch in the Swamp of Sorrows. He has been sent to the Watch by Anchorite Avuun to retrieve Draenethyst Crystals stolen by the Lost Ones." },
  ["holbruk"] = { 2, "tortollan located in Nazmir", "Holbruk is a tortollan located in Nazmir." },
  ["holiday celebrant"] = { 2, "', "Holiday Celebrants are participating the Bronze Celebration outside the Caverns of Time in Tanaris. They come in various races, including core and allied races, adult and children, demon hunters and death knights, as well as various NPC races." },
  ["holiday enthusiast (valdrakken)"] = { 2, "', "Holiday Enthusiasts are dracthyr quest givers located inside the Seat of the Aspects and in central Valdrakken. They offer breadcrumb quests to holidays and seasonal events." },
  ["hollow frostweaver"] = { 2, "', "Hollow Frostweavers are nerubians located in the Grand Rampart in Nerub-ar Palace." },
  ["honagger bradwarden"] = { 2, "dwarf warrior", "Honagger Bradwarden is a dwarf warrior.  While taking a trip near Ironforge, he was attacked by a group of wolves." },
  ["honored aspirant"] = { 2, "', "Honored Aspirants are kyrian." },
  ["honored duelist"] = { 2, "', "Honored Duelists are venthyr located in Revendreth." },
  ["honored hopebreaker"] = { 2, "', "Honored Hopebreakers are venthyr located at Wanecrypt Hill and Decrepit Depository in Revendreth." },
  ["honored raptor"] = { 2, "', "Honored Raptors are raptors located in the Hall of Honored Dead and Halls of Ash in Kings' Rest." },
  ["hooded crusader"] = { 2, "', "The mysterious Hooded Crusader guides you through the Scarlet Monastery. Believing that the Scarlet Crusade has become irrevocably corrupt, she intends to end them for good." },
  ["hooded priest"] = { 2, "', "Hooded Priests are human and Forsaken priests found at Faol's Rest in the Tirisfal Glades and in the Netherlight Temple." },
  ["hooded priestess"] = { 2, "human or Forsaken priestess (depending on the player's fa...", "The Hooded Priestess is a human or Forsaken priestess (depending on the player's faction) who appears in Dalaran after a priest player turns in  [10-45] In the Blink of an Eye. She has been sent by Alonsus Faol to recruit the priest to his cause." },
  ["hooded purveyor"] = { 2, "earthen vendor located in Flotsam Shoal on the Siren Isle", "Hooded Purveyor is an earthen vendor located in Flotsam Shoal on the Siren Isle." },
  ["hopebreaker marku"] = { 2, "venthyr located in Dredhollow in Revendreth", "Hopebreaker Marku is a venthyr located in Dredhollow in Revendreth." },
  ["hopebreaker mursa"] = { 2, "venthyr located in Dredhollow in Revendreth", "Hopebreaker Mursa is a venthyr located in Dredhollow in Revendreth." },
  ["hopebreaker vilstav"] = { 2, "venthyr located in Dredhollow in Revendreth", "Hopebreaker Vilstav is a venthyr located in Dredhollow in Revendreth." },
  ["horace alder"] = { 2, "human mage trainer located on the top floor of Jaina's To...", "Horace Alder is a human mage trainer located on the top floor of Jaina's Tower on Theramore Isle in Dustwallow Marsh. If he seems distracted it's cause he fears for the men of Northwatch, and wished he had sent some of his students to aid them." },
  ["horde footsoldier"] = { 2, "', "Horde Footsoldiers are murlocs located in Azmerloth. They come in two variants." },
  ["horde soldier (isle of dorn)"] = { 2, "', "Horde Soldiers are Forsaken, Darkfallen, tauren, jungle trolls, orcs, Mag'har orcs, and goblins located at the factions' landing site and at Tranquil Strand on the Isle of Dorn. They are being transported from ships to the mainland via Horde Landi..." },
  ["hordranin"] = { 2, "dracthyr decor vendor located in any neighborhood where R...", "Hordranin is a dracthyr decor vendor located in any neighborhood where Reaching Beyond the Possible is the active endeavor. He appears in the Town Center in Founder's Point or in the Common in Razorwind Shores." },
  ["horgak the enslaver"] = { 2, "mogu leader found in the central tower in the Diremoor on...", "Horgak the Enslaver is a mogu leader found in the central tower in the Diremoor on the Isle of Thunder that plans to mount attacks against the Kirin Tor Offensive and the Sunreaver Onslaught." },
  ["horkus"] = { 2, "mo'arg brute disguised as an ogre located in Shackle's De...", "Horkus is a mo'arg brute disguised as an ogre located in Shackle's Den in Azsuna. He can be exposed by paladins wielding the  [Truthguard] or by abilities to reveal demons." },
  ["hornizz brimbuzzle"] = { 2, "goblin quest giver located in a small camp at the southwe...", "Hornizz Brimbuzzle is a goblin quest giver located in a small camp at the southwestern end of the Kodo Graveyard in Desolace. He wants to harvest 'ghost-o-plasm' from the Valley of Bones in the hopes of selling it to the Magram centaur." },
  ["horrified echo"] = { 2, "', "Horrified Echoes are echoes of frightened eredar located at Triumvirate's End in Eredath, forever remembering the day of the flight of the draenei. Some of them are devoured by Soultwisted Echoes." },
  ["horrormaster damnik"] = { 2, "venthyr stable master located at Wanecrypt Hill in Revend...", "Horrormaster Damnik is a venthyr stable master located at Wanecrypt Hill in Revendreth." },
  ["horth frysthelm"] = { 2, "Arathi located at Mereldar in Hallowfall", "Horth Frysthelm is an Arathi located at Mereldar in Hallowfall." },
  ["horu cloudwatcher"] = { 2, "tauren located in Blackrock Depths", "Horu Cloudwatcher is a tauren located in Blackrock Depths." },
  ["horvuld oceanscythe"] = { 2, "vrykul located on the expedition isles", "Horvuld Oceanscythe is a vrykul located on the expedition isles." },
  ["host ta'rela"] = { 2, "broker innkeeper", "Host Ta'rela is a broker innkeeper and vendor located in the Idyllia in Oribos." },
  ["hot spring attendant"] = { 2, "', "Hot Spring Attendants are earthen located at the Keepers Terrace in Dornogal." },
  ["hot spring healer"] = { 2, "', "Hot Spring Healers are earthen located in Keepers Terrace in Dornogal." },
  ["hotawa"] = { 2, "tuskarr located on the big island in the middle of the Nj...", "Hotawa is a tuskarr located on the big island in the middle of the Njord's Breath Bay in the Borean Tundra. He stands next to Elder Muahit." },
  ["hotharn"] = { 2, "earthen located at the Contender's Gate in Dornogal", "Hotharn is an earthen located at the Contender's Gate in Dornogal." },
  ["hotoppik copperpinch"] = { 2, "vendor located in the Bazaar section of Silvermoon City", "Hotoppik Copperpinch is a vendor located in the Bazaar section of Silvermoon City, near the bank, during the Feast of Winter Veil event. She is affiliated with Smokywood Pastures, and sells lower value holiday-related items." },
  ["houndlord ren"] = { 2, "mogu located in Autumnshade Ridge in the Vale of Eternal ...", "Houndlord Ren is a mogu located in Autumnshade Ridge in the Vale of Eternal Blossoms. He only spawns during  [50] Assault: The Warring Clans." },
  ["houndmaster archibald"] = { 2, "human located at the Amber Waves in Stormsong Valley", "Houndmaster Archibald is a human located at the Amber Waves in Stormsong Valley. Occasionally, he can be seen going around the house to pet Humphrey." },
  ["houndmaster ely"] = { 2, "rare worgen located in Amberfall Mesa in Stormheim", "Houndmaster Ely is a rare worgen located in Amberfall Mesa in Stormheim. He caught Saboteur Aronson." },
  ["houndmaster leopold"] = { 2, "worgen located in Mangrove Shore in Nazmir", "Houndmaster Leopold is a worgen located in Mangrove Shore in Nazmir." },
  ["houndmaster payne"] = { 2, "felguard disguised as a worgen located in Greywatch in St...", "Houndmaster Payne is a felguard disguised as a worgen located in Greywatch in Stormheim. He can be exposed by paladins wielding the  [Truthguard] or by abilities to reveal demons." },
  ["house iremoore assassin"] = { 2, "', "House Iremoore Assassins are venthyr located in the Ember Court." },
  ["hovel brute"] = { 2, "', "Hovel Brutes are ogres located in Gar'gol's Hovel in Mount Hyjal." },
  ["howah deeptan"] = { 2, "tauren leatherworking vendor located at the Cenarion Wild...", "Howah Deeptan is a tauren leatherworking vendor located at the Cenarion Wildlands in Desolace." },
  ["hrandaz"] = { 2, "earthen located at Shadowvein Point in the Ringing Deeps", "Hrandaz is an earthen located at Shadowvein Point in the Ringing Deeps. He is friends with Skorthuz and became worried when he went to Chittering Den." },
  ["hreka"] = { 2, "earthen located in Freywold Village on the Isle of Dorn", "Hreka is a earthen located in Freywold Village on the Isle of Dorn." },
  ["hrglr"] = { 2, "murloc located in Torga's Tavern in Nazmir", "Hrglr is a murloc located in Torga's Tavern in Nazmir." },
  ["hrngl"] = { 2, "murloc located in Tyrhold Reservoir in Thaldraszus during...", "Hrngl is a murloc located in Tyrhold Reservoir in Thaldraszus during Time Rifts." },
  ["hruon firesinger"] = { 2, "tauren", "Hruon Firesinger is a tauren, and a shaman in his tribe. He once stood on a hill and looked east over the lands of Mulgore." },
  ["hubert lucas"] = { 2, "dead worgen warlock located at Darkmaul Bridge in Exile's...", "Hubert Lucas is a dead worgen warlock located at Darkmaul Bridge in Exile's Reach." },
  ["hudson"] = { 2, "tuskarr located with Ranpiata at Hudson's Rock in the Azu...", "Hudson is a tuskarr located with Ranpiata at Hudson's Rock in the Azure Span." },
  ["hugo lentner"] = { 2, "worgen engineering supplies vendor located in the Craftsm...", "Hugo Lentner is a worgen engineering supplies vendor located in the Craftsmen's Terrace in Darnassus. He's most likely related to fellow engineering trainer Tana Lentner." },
  ["hulfdan blackbeard"] = { 2, "dwarf rogue trainer located in the Forlorn Cavern in Iron...", "Hulfdan Blackbeard is a dwarf rogue trainer located in the Forlorn Cavern in Ironforge. When asked for the location of the rogue trainers, the Ironforge Guards will state that they often have trouble with Hulfdan." },
  ["hulking kor'thik fleshrender"] = { 2, "mantid located in the Dread Wastes", "Hulking Kor'thik Fleshrender is a mantid located in the Dread Wastes. One appears as the final encounter during  [25-35] The Taking of Dusklight Bridge." },
  ["hulking kraulguard"] = { 2, "', "Hulking Kraulguards are quilboar brutes located in Briarback Kraul in Stormsong Valley." },
  ["hulking warshell"] = { 2, "', "Hulking Warshell is nerubian spiderlord located in the Transformatory in the City of Threads. At first, they are a regular nerubian named Honored Citizen." },
  ["humbling soulwatcher"] = { 2, "', "Humbling Soulwatchers are venthyr located in the Grove of Terror in Revendreth. Some can be found talking to Demoralized Souls while others have died out in the grove." },
  ["humbolt briarblack"] = { 2, "gnome located at the Lunarfall in Shadowmoon Valley", "Humbolt Briarblack is a gnome located at the Lunarfall in Shadowmoon Valley. He can only be recruited using the Headhunter's Harvest from Lunarfall Inn." },
  ["hunaka greenhoof"] = { 2, "tauren druid", "Hunaka Greenhoof is a tauren druid who wanders around Dalaran and acts like a player (using  [Hearthstone], training professions, checking the bank, etc.). This section concerns content related to Cataclysm." },
  ["hungry aspirant"] = { 2, "', "Hungry Aspirants are kyrian located at Hero's Rest in Bastion." },
  ["hungry hauler"] = { 2, "Veiled Market", "Hungry Haulers are brokers standing in line at food stalls in Tazavesh, the Veiled Market." },
  ["hungry laborer"] = { 2, "Veiled Market", "Hungry Laborers are brokers located in Tazavesh, the Veiled Market." },
  ["hungry patron"] = { 2, "Veiled Market", "Hungry Patrons are brokers located at food stalls in Tazavesh, the Veiled Market." },
  ["hungry tidehunter"] = { 2, "murloc", "Hungry Tidehunter is a murloc." },
  ["hunt instructor basku"] = { 2, "centaur located atop the Shikaar rise in Maruukai in the ...", "Hunt Instructor Basku is a centaur located atop the Shikaar rise in Maruukai in the Ohn'ahran Plains." },
  ["hunter akana"] = { 2, "experienced ankoan hunter located in Nazjatar", "Hunter Akana is an experienced ankoan hunter located in Nazjatar. Born into a clan that was destroyed by the naga, he was forced to survive in the deep wilderness alone." },
  ["hunter bal'ra"] = { 2, "orc located at the Everbloom Wilds in Gorgrond", "Hunter Bal'ra is an orc located at the Everbloom Wilds in Gorgrond. Her pet is Spike." },
  ["hunter bonetusk"] = { 2, "quilboar found in Razorfen Kraul", "Hunter Bonetusk is a quilboar found in Razorfen Kraul." },
  ["hunter jadar"] = { 2, "centaur located at the Watering Hole in the Ohn'ahran Plains", "Hunter Jadar is a centaur located at the Watering Hole in the Ohn'ahran Plains." },
  ["hunter narman"] = { 2, "centaur quest giver located atop the Shikaar rise in Maru...", "Hunter Narman is a centaur quest giver located atop the Shikaar rise in Maruukai in the Ohn'ahran Plains. He is an accomplished hunter, but is daunted by the idea that he is not worthy of marrying the love of his life, Windsage Dawa." },
  ["hunter saikhan"] = { 2, "centaur located in Cloverwood Hollow in the Ohn'ahran Plains", "Hunter Saikhan is a centaur located in Cloverwood Hollow in the Ohn'ahran Plains." },
  ["hunter zaya"] = { 2, "centaur sitting by the campfire in Timberstep Outpost in ...", "Hunter Zaya is a centaur sitting by the campfire in Timberstep Outpost in the Ohn'ahran Plains. Her bakar, Sarnai, was killed by the Mudfin tribe." },
  ["hunting hopebreaker"] = { 2, "', "Hunting Hopebreakers are venthyr located in Revendreth." },
  ["huntmaster amaa"] = { 2, "centaur located at the Field of Ferocity in the Ohn'ahran...", "Huntmaster Amaa is a centaur located at the Field of Ferocity in the Ohn'ahran Plains." },
  ["huntmaster constantin"] = { 2, "venthyr located at Wanecrypt Hill in Revendreth", "Huntmaster Constantin is a venthyr located at Wanecrypt Hill in Revendreth." },
  ["huntmaster krakle"] = { 2, "gnoll sneaking around in Timbertooth Trail in the Azure Span", "Huntmaster Krakle is a gnoll sneaking around in Timbertooth Trail in the Azure Span." },
  ["huntmaster kroshk"] = { 2, "centaur in Nokhudon Hold in the Ohn'ahran Plains", "Huntmaster Kroshk is a centaur in Nokhudon Hold in the Ohn'ahran Plains." },
  ["huntmaster malkik"] = { 2, "centaur located at the Aylaag Camp stops in the Ohn'ahran...", "Huntmaster Malkik is a centaur located at the Aylaag Camp stops in the Ohn'ahran Plains." },
  ["huntmaster oluuk"] = { 2, "centaur located in Mountainview Post in the Ohn'ahran Plains", "Huntmaster Oluuk is a centaur located in Mountainview Post in the Ohn'ahran Plains. Occasionally, a pair of Mountainview Scouts arrives to report to him." },
  ["huntmaster petrus"] = { 2, "venthyr located at Witherfall Ruins in Revendreth", "Huntmaster Petrus is a venthyr located at Witherfall Ruins in Revendreth." },
  ["huntmaster yrgena"] = { 2, "centaur located in Nokhudon Hold in the Ohn'ahran Plains", "Huntmaster Yrgena is a centaur located in Nokhudon Hold in the Ohn'ahran Plains." },
  ["huntress bintook"] = { 2, "draenei quest giver located at Telaar in Nagrand", "Huntress Bintook is a draenei quest giver located at Telaar in Nagrand." },
  ["huntress estrid"] = { 2, "vrykul located in a camp in Hrydshal in Stormheim", "Huntress Estrid is a vrykul located in a camp in Hrydshal in Stormheim. She has a bear pet named Halfdan." },
  ["huntsman altimor"] = { 2, "boss in Castle Nathria", "Huntsman Altimor is a boss in Castle Nathria. Altimor is a hunter who fights the raid with a trio of gargon, each with a different set of abilities, but all sharing the same health pool with Altimor." },
  ["huntsman leopold"] = { 2, "undead hunter located in Tyr's Hand", "Huntsman Leopold is an undead hunter located in Tyr's Hand. He was formerly a human quest giver at Light's Hope Chapel who could build the Cryptstalker Armor for the adventurers." },
