  ["initiate kittileg"] = { 2, "centaur located in a cave accessed from the Mirror of the...", "Initiate Kittileg is a centaur located in a cave accessed from the Mirror of the Sky in the Ohn'ahran Plains." },
  ["initiate okan"] = { 2, "centaur located next to Windsage Tohr at the Ohn'ir pools...", "Initiate Okan is a centaur located next to Windsage Tohr at the Ohn'ir pools in Maruukai in the Ohn'ahran Plains. He is training at hitting Tohr's moving orb of wind magic with bolts of his own magic." },
  ["initiate radiya"] = { 2, "centaur located in Ohn'iri Springs in the Ohn'ahran Plains", "Initiate Radiya is a centaur located in Ohn'iri Springs in the Ohn'ahran Plains." },
  ["initiate zorig"] = { 2, "centaur quest giver of Clan Ohn'ir initially located in a...", "Initiate Zorig is a centaur quest giver of Clan Ohn'ir initially located in a camp east of Eternal Kurgans in the Ohn'ahran Plains. His mentor Elder Yuvari sent him to investigate the Nokhud and Ukhel's efforts in the kurgans." },
  ["initiate of the dawn"] = { 2, "', "Initiates of the Dawn were high arakkoa located in Skyreach and in Spires of Arak. They was taken out by the followers sent from the Frostwall and Lunarfall garrisons." },
  ["initiate of the rising sun"] = { 2, "', "Initiates of the Rising Sun are arakkoa located in the Lower Quarter and Grand Spire in Skyreach." },
  ["injured aspirant (zereth mortis)"] = { 2, "', "Injured Aspirants are kyrian located in Provis Terra in Zereth Mortis. After aiding them, they will assist the Maw Walker as Honored Aspirants for a time." },
  ["injured dracthyr"] = { 2, "', "Injured Dracthyr are dracthyr located in the Forbidden Reach." },
  ["injured earthen"] = { 2, "', "Injured Earthen are earthen located on the Isle of Dorn and in Dornogal." },
  ["injured earthen (deepholm)"] = { 2, "', "Injured Earthen are earthen located in the Fractured Front in Deepholm. They've been attacked by the stone troggs that are currently warring with them." },
  ["injured earthen (ringing deeps)"] = { 2, "', "Injured Earthen are earthen located in the Ringing Deeps." },
  ["injured earthen (stonevault)"] = { 2, "', "Injured Earthen are earthen located outside of the Singing Forge in the Stonevault. They are wounded and are being tended to by Forgebound Menders." },
  ["injured guardian of the dream"] = { 2, "', "Injured Guardians of the Dream are druids found in Malorne's Nightmare." },
  ["injured krokul"] = { 2, "', "Injured Krokuls are Broken located in Krokuun." },
  ["injured legionfall defender"] = { 2, "', "Injured Legionfall Defenders are located in Deliverance Point on the Broken Shore." },
  ["injured patron"] = { 2, "Veiled Market", "Injured Patrons are brokers located in Tazavesh, the Veiled Market." },
  ["injured refugee"] = { 2, "', "Injured Refugees are found resting on the upper floor of the Shattrath Infirmary in Shattrath City." },
  ["injured shieldmaiden"] = { 2, "valkyra vrykul located in Skyhold", "Injured Shieldmaiden is a valkyra vrykul located in Skyhold." },
  ["injured soldier (hallowfall)"] = { 2, "', "Injured Soldiers are Arathi located in the Arathi Infirmary in Mereldar in Hallowfall. Kaeleb Flamegard is tending to their wounds." },
  ["injured sra'thik soldier"] = { 2, "', "Injured Sra'thik Soldiers are mantid found at the Sra'thik Incursion in the Townlong Steppes." },
  ["injured talon"] = { 2, "', "Injured Talons are dracthyr of the Healing Wings found in the Caldera of the Menders and the Support Creche in the Forbidden Reach." },
  ["injured tuskarr"] = { 2, "', "Injured Tuskarr are tuskarr traveling with Brena's caravan in central Azure Span." },
  ["injured vrykul"] = { 2, "', "Injured Vrykul are vrykul located in Suramar." },
  ["injured warrior (emerald dream)"] = { 2, "', "Injured Warriors are centaur, dracthyr, and tuskarr located the Field of Flames during the quest  [10-80] The Age of Mortals. They are being healed by Prophet Velen." },
  ["inkiep"] = { 2, "kyrian innkeeper", "Inkiep is a kyrian innkeeper and vendor located at Hero's Rest in Bastion." },
  ["inkrot"] = { 2, "Forsaken found in the Circle of Wills in Dalaran", "Inkrot is a Forsaken found in the Circle of Wills in Dalaran. This section concerns content related to The War Within." },
  ["inna the cryptstalker"] = { 2, "vrykul found in Shield's Rest in Stormheim during   [10-4...", "Inna the Cryptstalker is a vrykul found in Shield's Rest in Stormheim during   [10-45] Shrine of the Truthguard." },
  ["innervus"] = { 2, "venthyr located in the Scorched Crypt in Revendreth", "Innervus is a venthyr located in the Scorched Crypt in Revendreth. Entry requires a  [Scorched Crypt Key], which drops from the Feral Ritualists outside." },
  ["innkeeper abeqwa"] = { 2, "tauren innkeeper located in Freewind Post in Thousand Nee...", "Innkeeper Abeqwa is a tauren innkeeper located in Freewind Post in Thousand Needles. This section concerns content related to Cataclysm." },
  ["innkeeper adegwa"] = { 2, "tauren innkeeper located in Hammerfall in the Arathi High...", "Innkeeper Adegwa is a tauren innkeeper located in Hammerfall in the Arathi Highlands. During the trial of Garrosh Hellscream, Adegwa informed Shokia that there was a letter for her." },
  ["innkeeper allison"] = { 2, "human innkeeper", "Innkeeper Allison is a human innkeeper who owns and runs the Gilded Rose Inn in Stormwind City's Trade District, between the bank and the auction house. She can be found just inside the inn on the ground floor." },
  ["innkeeper anderson"] = { 2, "human innkeeper located in Southshore in the Hillsbrad Fo...", "Innkeeper Anderson is a human innkeeper located in Southshore in the Hillsbrad Foothills. Since the destruction of Southshore by Forsaken plague bombing following the Cataclysm, Anderson's fate is unknown." },
  ["innkeeper atipat"] = { 2, "tuskarr innkeeper located at Uktulut Backwater in the Wak...", "Innkeeper Atipat is a tuskarr innkeeper located at Uktulut Backwater in the Waking Shores." },
  ["innkeeper belm"] = { 2, "dwarf innkeeper located in Thunderbrew Distillery in Khar...", "Innkeeper Belm is a dwarf innkeeper located in Thunderbrew Distillery in Kharanos in Dun Morogh." },
  ["innkeeper bernice"] = { 2, "worgen innkeeper located at Farwatcher's Glen in Stonetal...", "Innkeeper Bernice is a worgen innkeeper located at Farwatcher's Glen in Stonetalon Mountains." },
  ["innkeeper brax"] = { 2, "earthen located in Gundargaz in the Ringing Deeps", "Innkeeper Brax is an earthen located in Gundargaz in the Ringing Deeps. When he has rowdy patrons, he usually knocks them on the head using his brass knuckles." },
  ["innkeeper darg bloodclaw"] = { 2, "orc innkeeper located in Shadowmoon Village in Shadowmoon...", "Innkeeper Darg Bloodclaw is an orc innkeeper located in Shadowmoon Village in Shadowmoon Valley." },
  ["innkeeper daughny"] = { 2, "dwarf innkeeper located at the Swiftgear Station in the W...", "Innkeeper Daughny is a dwarf innkeeper located at the Swiftgear Station in the Wetlands." },
  ["innkeeper greul"] = { 2, "tauren innkeeper located in Camp Mojache in Feralas", "Innkeeper Greul is a tauren innkeeper located in Camp Mojache in Feralas." },
  ["innkeeper kerp"] = { 2, "Broken innkeeper located at Orebor Harborage in Zangarmarsh", "Innkeeper Kerp is a Broken innkeeper located at Orebor Harborage in Zangarmarsh." },
  ["innkeeper notuk"] = { 2, "tuskarr innkeeper located in Uktulut Pier in the Waking S...", "Innkeeper Notuk is a tuskarr innkeeper located in Uktulut Pier in the Waking Shores." },
  ["innocent jim"] = { 2, "Forsaken located at the Krasus' Landing in Dalaran", "Innocent Jim is a Forsaken located at the Krasus' Landing in Dalaran, next to the mailbox. When you speak to him, he says nothing and eyes you warily." },
  ["inquisitor darksion"] = { 2, "venthyr located in a crypt in the Halls of Atonement in R...", "Inquisitor Darksion is a venthyr located in a crypt in the Halls of Atonement in Revendreth." },
  ["inquisitor otilia"] = { 2, "venthyr located in the Halls of Atonement in Revendreth", "Inquisitor Otilia is a venthyr located in the Halls of Atonement in Revendreth. Her name in life was Khemkan the Pitiless." },
  ["inquisitor petre"] = { 2, "venthyr located at the Halls of Atonement in Revendreth", "Inquisitor Petre is a venthyr located at the Halls of Atonement in Revendreth. [Inquisitor Petre's Sinstone] is needed to attack him." },
  ["inquisitor sigar"] = { 2, "venthyr located in the Halls of Atonement", "Inquisitor Sigar is a venthyr located in the Halls of Atonement." },
  ["inquisitor sorin"] = { 2, "venthyr located within the Halls of Atonement in Revendreth", "Inquisitor Sorin is a venthyr located within the Halls of Atonement in Revendreth. His name in life was Thogro the Devourer." },
  ["inquisitor speaker"] = { 2, "', "Inquisitor Speakers are Arathi located in Nightfall Sanctum." },
  ["inquisitor stelia"] = { 2, "venthyr located in Revendreth", "Inquisitor Stelia (known as Zill'kee the World Reaper in life) is a venthyr located in Revendreth." },
  ["inquisitor traian"] = { 2, "venthyr located within the Halls of Atonement in Revendreth", "Inquisitor Traian is a venthyr located within the Halls of Atonement in Revendreth. His name in life was Pallaval the Biased." },
  ["inquisitor vilhelm"] = { 2, "venthyr located in Revendreth", "Inquisitor Vilhelm (known as Moongo the Sun King in life) is a venthyr located in Revendreth." },
  ["instructor alexander"] = { 2, "human located at the Proudmoore Academy in Boralus", "Instructor Alexander is a human located at the Proudmoore Academy in Boralus." },
  ["instructor alikana"] = { 2, "ankoan located in Mezzamere in Nazjatar", "Instructor Alikana is an ankoan located in Mezzamere in Nazjatar." },
  ["instructor amano"] = { 2, "ankoan located in Mezzamere in Nazjatar", "Instructor Amano is an ankoan located in Mezzamere in Nazjatar." },
  ["instructor galford"] = { 2, "mini-boss in Stratholme", "Instructor Galford is a mini-boss in Stratholme. Galford used to be known as Archivist Galford a mortal human adept at fire magic until Balnazzar slew the members of the Scarlet Crusade's Crimson Legion within Stratholme and raised them as the Ris..." },
  ["instructor herus"] = { 2, "Forsworn kyrian located at the Court of Elation in Bastion", "Instructor Herus is a Forsworn kyrian located at the Court of Elation in Bastion." },
  ["instructor hroegar"] = { 2, "vrykul found at the Savage Ledge in Icecrown", "Instructor Hroegar is a vrykul found at the Savage Ledge in Icecrown." },
  ["instructor kil'thak"] = { 2, "mantid located in the Heart of Fear", "Instructor Kil'thak is a mantid located in the Heart of Fear." },
  ["instructor maltik"] = { 2, "mantid located in the Heart of Fear", "Instructor Maltik is a mantid located in the Heart of Fear." },
  ["instructor okanu"] = { 2, "ankoan profession trainer located in Mezzamere in Nazjatar", "Instructor Okanu is an ankoan profession trainer located in Mezzamere in Nazjatar." },
  ["instructor severin"] = { 2, "kyrian located at the Path of Wisdom in Bastion", "Instructor Severin is a kyrian located at the Path of Wisdom in Bastion." },
  ["instructor tak'thok"] = { 2, "mantid located in the Heart of Fear", "Instructor Tak'thok is a mantid located in the Heart of Fear." },
  ["instructor tarahna"] = { 2, "eredar located at the Conservatory of the Arcane in Eredath", "Instructor Tarahna is an eredar located at the Conservatory of the Arcane in Eredath." },
  ["instructor ulooaka"] = { 2, "ankoan located in Mezzamere in Nazjatar", "Instructor Ulooaka is an ankoan located in Mezzamere in Nazjatar. During the Nazjatar Campaign, an Alliance adventurer brought him a broken power core with hopes of repairing it and using it against the naga." },
  ["instructor zarik"] = { 2, "mantid located in the Heart of Fear", "Instructor Zarik is a mantid located in the Heart of Fear." },
  ["interested citizen"] = { 2, "', "Interested Citizens were found listening to Suspicious Citizens at the Drag in Orgrimmar and Old Town in Stormwind City during  [10-80] Avoiding Blame." },
  ["intern jackie"] = { 2, "Bluewax kobold found standing next to the Throne of Order...", "Intern Jackie is a Bluewax kobold found standing next to the Throne of Ordering Around in Candle Rock in Highmountain. During  [10-45] Candle of Command, she helps the player deliver commands to the kobolds of the cavern while they're sitting in t..." },
  ["interrogation specialist"] = { 2, "Veiled Market", "Interrogation Specialists are brokers located in Tazavesh, the Veiled Market." },
  ["intrigued dracthyr"] = { 2, "dracthyr observing Cataloger Wulferd in the Trade Distric...", "Intrigued Dracthyr is a dracthyr observing Cataloger Wulferd in the Trade District in Stormwind City during  [10-70] Expeditionary Coordination." },
  ["introspective ascended"] = { 2, "', "Introspective Ascended are Ascended kyrian located at Everdawn Commons in Bastion." },
  ["invading squallcaster"] = { 2, "', "Invading Squallcasters are vulpera located at the Fields of Reverie in the Emerald Dream." },
  ["invasive creeper"] = { 2, "', "Invasive Creepers are Drust located in the Grove of Awakening in Ardenweald." },
  ["invasive lasher"] = { 2, "Drust encountered by adventure companions in Ardenweald", "Invasive Lasher is a Drust encountered by adventure companions in Ardenweald." },
  ["inventor blammo"] = { 2, "goblin located at The Pit in Gorgrond", "Inventor Blammo is a goblin located at The Pit in Gorgrond. She is riding Bomb-o." },
  ["investigator fezzen brasstacks"] = { 2, "goblin found in Shadowfang Keep during the Love is in the...", "Investigator Fezzen Brasstacks is a goblin found in Shadowfang Keep during the Love is in the Air world event. He was investigating the Apothecaries' activities there, but was unable to take them down by himself." },
  ["invoq"] = { 2, "rare elite djaradin", "Invoq is a rare elite djaradin that spawns at the Battlefield Ruins in Zaralek Cavern." },
  ["inzi charmlight"] = { 2, "gnome barmaid found inside A Hero's Welcome on the Allian...", "Inzi Charmlight is a gnome barmaid found inside A Hero's Welcome on the Alliance side of Dalaran. She serves drinks and food to the thirsty/hungry players and adventurers." },
  ["iona skyblade"] = { 2, "Ascended kyrian located in Elysian Hold", "Iona Skyblade is an Ascended kyrian located in Elysian Hold." },
  ["ip'xal"] = { 2, "nerubian located in the City of Threads", "Ip'xal is a nerubian located in the City of Threads." },
  ["iralios"] = { 2, "Ascended kyrian", "Iralios is an Ascended kyrian." },
  ["iridi (earthen)"] = { 2, "earthen flight master located in Freywold Village on the ...", "Iridi is an earthen flight master located in Freywold Village on the Isle of Dorn." },
  ["iristella"] = { 2, "dracthyr located in Iskaara in the Azure Span", "Iristella is a dracthyr located in Iskaara in the Azure Span." },
  ["iristia the unburdened"] = { 2, "kyrian located in Bastion", "Iristia the Unburdened is a kyrian located in Bastion." },
  ["iristimat"] = { 2, "dracthyr located in Iskaara in the Azure Span", "Iristimat is a dracthyr located in Iskaara in the Azure Span." },
  ["irizi the unwanted"] = { 2, "nerubian located in the City of Threads", "Irizi the Unwanted is a nerubian located in the City of Threads." },
  ["iron captain argha"] = { 2, "orc located at Ironhold Harbor in Tanaan Jungle", "Iron Captain Argha is an orc located at Ironhold Harbor in Tanaan Jungle." },
  ["iron orkas"] = { 2, "quilboar brute located on the expedition isles", "Iron Orkas is a quilboar brute located on the expedition isles." },
  ["iron qon"] = { 2, "tenth boss encounter in the Throne of Thunder", "Iron Qon is the tenth boss encounter in the Throne of Thunder. It is a tank and spank with numerous environment awareness mechanics." },
  ["ironhaul machinist"] = { 2, "', "Ironhaul Machinists are earthen located at Ironhaul Station in the Ringing Deeps." },
  ["ironmarch felbreaker"] = { 2, "ogre", "Ironmarch Felbreaker is an ogre." },
  ["ironmarch gundriver"] = { 2, "', "Ironmarch Gundrivers are ogres found north of the Dark Portal in the Blasted Lands." },
  ["ironstead guldsh"] = { 2, "earthen located in Rambleshire on the Isle of Dorn", "Ironstead Guldsh is an earthen located in Rambleshire on the Isle of Dorn." },
  ["irontide engineer"] = { 2, "naga", "Irontide Engineer is a naga." },
  ["irontide machinesmith"] = { 2, "naga", "Irontide Machinesmith is a naga." },
  ["irontide surveyor"] = { 2, "naga", "Irontide Surveyor is a naga." },
  ["irontorch commander"] = { 2, "djaradin located in the Chamber of Flames in Neltharus", "Irontorch Commander is a djaradin located in the Chamber of Flames in Neltharus." },
  ["iruk"] = { 2, "tuskarr found dead in the waters between the mainland", "Iruk is a tuskarr found dead in the waters between the mainland and the island in the center of Njord's Breath Bay in the Borean Tundra." },
  ["iryna the disciplined"] = { 2, "venthyr located in Dominance Keep in Revendreth", "Iryna the Disciplined is a venthyr located in Dominance Keep in Revendreth." },
  ["isaac 'lefteye' bentham"] = { 2, "worgen flight master located in Veiled Grotto in Zuldazar", "Isaac 'Lefteye' Bentham is a worgen flight master located in Veiled Grotto in Zuldazar." },
  ["isaac allerton"] = { 2, "human quest giver for the Pilgrim's Bounty seasonal event", "Isaac Allerton is a human quest giver for the Pilgrim's Bounty seasonal event. He is located in Darnassus and handles several quests in the Pilgrim's Supplies quest chain." },
  ["isaac blastimov"] = { 2, "gnome located at Trueshot Lodge in Highmountain", "Isaac Blastimov is a gnome located at Trueshot Lodge in Highmountain. He collaborated with the goblin Bamm Megabomb to build two mechanical wolves, possibly to be their combat pets: Bamm's Treble and Isaac's Rush." },
  ["isaac's test creature"] = { 2, "ogre located in Ironband's Excavation Site in Loch Modan ...", "Isaac's Test Creature was an ogre located in Ironband's Excavation Site in Loch Modan for the first week of patch 10.0.7. A nearby Golden Eagle could be seen flying in circles around the ogre, occasionally flying close and hovering just above him." },
  ["isabela andare"] = { 2, "human blacksmithing vendor located in Three-Falls Lookout...", "Isabela Andare is a human blacksmithing vendor located in Three-Falls Lookout in the Azure Span." },
  ["isaqa"] = { 2, "rare djaradin located inside a small cave at the Skystone...", "Isaqa is a rare djaradin located inside a small cave at the Skystone Falls within the Emerald Dream." },
  ["isel the hammer"] = { 2, "vrykul located in Stormheim", "Isel the Hammer is a vrykul located in Stormheim." },
  ["isfar"] = { 2, "arakkoa quest giver located inside the Sethekk Halls in A...", "Isfar is an arakkoa quest giver located inside the Sethekk Halls in Auchindoun. Isfar is an exile from the Sethekk, the clan who took up residence in the Sethekk Halls after the Auchindoun explosion." },
  ["isha gloomaxe"] = { 2, "', "Isha Gloomaxe is one of the Grimtotem tauren chiefs located to the north of Freewind Post and east of Darkcloud Pinnacle." },
  ["iska, outrider of ruin"] = { 2, "Mawsworn kyrian located in the Endless Sands in Zereth Mo...", "Iska, Outrider of Ruin is a Mawsworn kyrian located in the Endless Sands in Zereth Mortis. To get Iska to spawn, keep killing rares, even rares that have already been killed and no longer show up as rares." },
  ["iskaal refugee"] = { 2, "group of three Iskaal Refugees spawn at the eastern entra...", "Iskaal Refugee are tuskarr refugees located in Kamagua in the Howling Fjord, mainly in and around Caregiver Iqniq's inn. Periodically, a group of three Iskaal Refugees spawn at the eastern entrance of town, stop by Akiaruk to offer a word of thank..." },
  ["iskaara defender"] = { 2, "', "Iskaara Defenders are tuskarr guards located in Iskaara in the Azure Span." },
  ["iskaara fisher"] = { 2, "', "Iskaara Fishers are tuskarr located in Iskaara and Cobalt Assembly in the Azure Span." },
  ["iskaara trader"] = { 2, "', "Iskaara Traders are tuskarr located throughout Teerakai in the Ohn'ahran Plains. Four are found in the trading area in the southern part of town; two of them are inspecting the carpets stacked next to Weaver Opali, another is talking to Weaver Yul..." },
  ["iskaaran fishmonger"] = { 2, "tuskarr located in the Cobalt Assembly in the Azure Span", "Iskaaran Fishmonger is a tuskarr located in the Cobalt Assembly in the Azure Span." },
  ["iskaaran healer"] = { 2, "', "Iskaaran Healers are tuskarr healing wounded Cobalt Guardians in the Cobalt Assembly in the Azure Span." },
  ["iskalder"] = { 2, "mjordin vrykul hero", "Iskalder is a mjordin vrykul hero, initially slumbering in the Halls of the Ancestors in Icecrown and rumored to be the greatest vrykul hero ever. The Bone Witch directs you to wake him and use an amulet to subjugate his will and return him to her." },
  ["isla"] = { 2, "ankoan located in Mezzamere in Nazjatar", "Isla is an ankoan located in Mezzamere in Nazjatar." },
  ["issam the unraveler"] = { 2, "ethereal located in Naakroa on K'aresh", "Issam the Unraveler is an ethereal located in Naakroa on K'aresh." },
  ["itchbite"] = { 2, "nerubian companion sold in limited quantity by Clutchmoth...", "Itchbite is a nerubian companion sold in limited quantity by Clutchmother Marn'tiq, 'Calmest' Gobbu, and Tyro Uwe in the City of Threads for 500  [Polished Pet Charms]." },
  ["itoka"] = { 2, "mogu found at the Thunder Forges on the Isle of Thunder", "Itoka is a mogu found at the Thunder Forges on the Isle of Thunder." },
  ["itokka"] = { 2, "tortollan", "Itokka is a tortollan." },
  ["itsero"] = { 2, "vulpera located at the Bloom in Razorwind Shores", "Itsero is a vulpera located at the Bloom in Razorwind Shores. He is sitting around a campfire with Seniku, Akuta, and Taiyata." },
  ["ittu"] = { 2, "tuskarr child sitting with Ituikatan in the Filled Bowl i...", "Ittu is a tuskarr child sitting with Ituikatan in the Filled Bowl in the Azure Span." },
  ["itty bitty murloc"] = { 2, "baby murloc located on Jaguero Isle in Stranglethorn Vale", "Itty Bitty Murloc is a baby murloc located on Jaguero Isle in Stranglethorn Vale." },
  ["ituikatan"] = { 2, "tuskarr sitting with Ittu in the Filled Bowl in the Azure...", "Ituikatan is a tuskarr sitting with Ittu in the Filled Bowl in the Azure Span." },
  ["itupiakut"] = { 2, "tuskarr fishing trainer of Morqut Village in the Forbidde...", "Itupiakut is the tuskarr fishing trainer of Morqut Village in the Forbidden Reach." },
  ["ivagont"] = { 2, "vrykul priest", "Ivagont was a vrykul priest who laid waste to Stormscale naga villages with his friend Kakushan in Darkshore. They drank the blood of their enemies and crafted armor from their skins." },
  ["ivan the mad"] = { 2, "worgen located in Island Expeditions", "Ivan the Mad is a worgen located in Island Expeditions." },
  ["ixin"] = { 2, "nerubian located in Ara-Kara", "Ixin is a nerubian located in Ara-Kara, City of Echoes." },
  ["iyali"] = { 2, "vulpera child located in Dragonscale Basecamp in the Waki...", "Iyali is a vulpera child located in Dragonscale Basecamp in the Waking Shores. She has an alpaca and is under the tutelage of Tyrgon." },
  ["iyyokuk the lucid"] = { 2, "mantid located at Klaxxi'vess", "Iyyokuk the Lucid is a mantid located at Klaxxi'vess. Iyyokuk is considered highly intelligent among the mantid and uses arcane magic in battle." },
  ["iz'zard"] = { 2, "ethereal found in Shattrath City", "Iz'zard is an ethereal found in Shattrath City. He is speaking with Arcanist Adyria." },
  ["izaeh strongiron"] = { 2, "Arathi teacher holding a lesson for a group of five Arath...", "Izaeh Strongiron is an Arathi teacher holding a lesson for a group of five Arathi Children inside a house in Lorel's Crossing, Hallowfall.  [The Big Book of Arathi Idioms] is lying on a crate next to the group." },
  ["izan"] = { 2, "earthen located by the Cataract River east of the Waterwo...", "Izan is an earthen located by the Cataract River east of the Waterworks in the Ringing Deeps." },
  ["izzy coppergrab"] = { 2, "goblin banker located in Everlook in Winterspring", "Izzy Coppergrab is a goblin banker located in Everlook in Winterspring." },
  ["j'amogg bloodfyre"] = { 2, "father of Jaruk", "J'amogg Bloodfyre is the father of Jaruk and J'argg Bloodfyre." },
  ["j'argg bloodfyre"] = { 2, "Shadowmoon orc", "J'argg Bloodfyre was a Shadowmoon orc who lived on Draenor at the start of the genocide of the draenei. He became a leader of raids on the remaining draenei, and often urged his brother, Jaruk Bloodfyre, to drink the Blood of Mannoroth as well and..." },
  ["j.d. collie"] = { 2, "gnome quest giver located at Marshal's Stand in the Un'Go...", "J.D. Collie is a gnome quest giver located at Marshal's Stand in the Un'Goro Crater. She spends her time studying the strange crystals found throughout the crater." },
  ["ja sara"] = { 2, "mogu located in the Shado-Pan Showdown", "Ja Sara is a mogu located in the Shado-Pan Showdown. She is fighting, for the gold team, against Du Shan of the purple team." },
  ["ja'huk"] = { 2, "mantid located at the Klaxxi'vess in Dread Wastes", "Ja'Huk is a mantid located at the Klaxxi'vess in Dread Wastes." },
  ["jabrul"] = { 2, "drogbar first encountered in Thas'talah Basin in Val'shar...", "Jabrul is a drogbar first encountered in Thas'talah Basin in Val'sharah where he was attacked by Stoneblood harpies. His next stop was Nashal's Watch in Stormheim." },
  ["jack \"all-trades\" derrington"] = { 2, "worgen profession trainer found in various places through...", "Jack \"All-Trades\" Derrington is a worgen profession trainer found in various places throughout Gilneas as the player progresses through the starting zone. As his name implies, being a play on the expression \"jack of all trades\", he can train the p..." },
  ["jack adams"] = { 2, "human pirate found on Scalawag Point in the Howling Fjord", "Jack Adams is a human pirate found on Scalawag Point in the Howling Fjord. He seems to have a love for alcohol." },
  ["jackson bayne"] = { 2, "dwarf", "Jackson Bayne was a dwarf who was found at the Eastvale Logging Camp in Elwynn Forest during the original beta." },
  ["jacob anders"] = { 2, "worgen located at the Southport in Spires of Arak", "Jacob Anders is a worgen located at the Southport in Spires of Arak. He has betrayed the Alliance as he was dealing with the Horde." },
  ["jacob felstone"] = { 2, "son of Emma Felstone", "Jacob 'Jake' Felstone was a son of Emma Felstone and Jem, and the brother of James and John. All three were warriors of Lordaeron, acting as royal guards to King Terenas Menethil." },
  ["jadefire betrayer"] = { 2, "', "Jadefire Betrayers are satyrs found in Felwood." },
  ["jadefire defender"] = { 2, "', "Jadefire Defenders are satyrs that can be found just west of the Ruins of Constellas in Felwood. They drop no loot." },
  ["jadefire felsworn"] = { 2, "', "\"The hunger of the Legion will never be sated.\" Jadefire Felsworns can be found in Felwood." },
  ["jadefire hellcaller"] = { 2, "', "Jadefire Hellcallers are satyrs found in Felwood." },
  ["jadefire illusionist"] = { 2, "', "Jadefire Illusionists are satyrs located at Stormrage Barrow Dens in Moonglade." },
  ["jadefire pyromancer"] = { 2, "', "Jadefire Pyromancers are satyrs located at Stormrage Barrow Dens in Moonglade." },
  ["jadefire rogue"] = { 2, "', "Jadefire Rogues are satyrs found in Felwood." },
  ["jadefire satyr"] = { 2, "', "Jadefire Satyrs are satyrs found in Felwood." },
  ["jadefire shadowmaster"] = { 2, "', "Jadefire Shadowmasters are satyrs located at Stormrage Barrow Dens in Moonglade." },
  ["jadefire shadowstalker"] = { 2, "', "Jadefire Shadowstalkers are satyrs found in Felwood." },
  ["jadefire trickster"] = { 2, "', "Jadefire Tricksters are satyrs found in Felwood." },
  ["jaedenar adept"] = { 2, "', "Jaedenar Adepts are gnomes, Forsaken, and orcs located near Jaedenar in Felwood." },
  ["jaedenar cultist"] = { 2, "', "Jaedenar Cultists are orc, human, and Forsaken cultists located near Jaedenar in Felwood." },
  ["jaedenar darkweaver"] = { 2, "', "Jaedenar Darkweavers are orcs, Forsaken, and gnomes located in Jaedenar in Felwood." },
  ["jaedenar guardian"] = { 2, "', "Jaedenar Guardians are orcs, humans, and Forsaken located near Jaedenar in Felwood." },
  ["jaedenar warlock"] = { 2, "', "Jaedenar Warlocks are orcs, Forsaken, and gnomes located in Jaedenar in Felwood. They summon imps." },
  ["jaenet hostfyrm"] = { 2, "Arathi located in Light's Redoubt in Hallowfall", "Jaenet Hostfyrm is an Arathi located in Light's Redoubt in Hallowfall." },
  ["jaggal"] = { 2, "gnoll", "Jaggal is a gnoll and the temporal leader of the Woodpaw clan. The Gordunni ogres' actions in Feralas drove the Woodpaw into conflict with the Feral Scar yetis, who were also been driven east by the deforestation." },
  ["jahri"] = { 2, "vulpera located in Anyport in Drustvar", "Jahri is a vulpera located in Anyport in Drustvar." },
  ["jakhar"] = { 2, "troll priest", "Jakhar is a troll priest who accompanied the Horde Expedition to Northrend during the war against the Lich King and who came into possession of the staff known as Light's Wrath. Aboard a zeppelin en route to the warfront, Jakhar practiced wielding..." },
  ["jakkerittua"] = { 2, "tuskarr located in Iskaara in the Azure Span", "Jakkerittua is a tuskarr located in Iskaara in the Azure Span." },
  ["jako the collector"] = { 2, "tortollan located in Undermine", "Jako the Collector is a tortollan located in Undermine." },
  ["jame'thris razorwind"] = { 2, "', "Jame'thris Razorwind is one of the <Druid of the Scythe> that can be freed from his Feral Worgen form with the  [Scythe of Elune]." },
  ["james ashvane"] = { 2, "leader of House Ashvane", "Lord James Ashvane was the leader of House Ashvane. He served as a captain in the Kul Tiran fleets, where he died during the invasion of Durotar alongside Daelin Proudmoore." },
  ["james blackridge"] = { 2, "son of a farming family", "James Blackridge, called Jimmy in his youth, is the son of a farming family, who live and work a farm outside Goldshire. Jimmy had a problem with responsibility as he was not able to do his chores." },
  ["james crowson"] = { 2, "worgen found alongside Ryan Quinn outside Hero's Rest Inn...", "James Crowson is a worgen found alongside Ryan Quinn outside Hero's Rest Inn in Stormshield." },
  ["james felstone"] = { 2, "son of Emma Felstone", "James 'Jem' Felstone was a son of Emma Felstone and Jem. Bearing his father's name, he was the oldest of three brothers." },
  ["james hallow"] = { 2, "worgen quest giver located in Whisperwind Grove in Felwood", "James Hallow is a worgen quest giver located in Whisperwind Grove in Felwood. He's the only Alliance NPC in the Grove, opposed to Horde's one Fez Hobnob; although hostile to Horde players, he cannot be attacked." },
  ["jamoku"] = { 2, "centaur located at Nokhudon Hold in the Ohn'ahran Plains", "Jamoku is a centaur located at Nokhudon Hold in the Ohn'ahran Plains. He is part of Clan Nokhud and an ally of the Primalists." },
  ["jan-xi"] = { 2, "mogu located in the Mogu'shan Vaults as part of the Will ...", "Jan-xi is a mogu located in the Mogu'shan Vaults as part of the Will of the Emperor encounter." },
  ["janatak"] = { 2, "tuskarr flight master located at Uktulut Backwater in the...", "Janatak is a tuskarr flight master located at Uktulut Backwater in the Waking Shores." },
  ["jandaar of the mists"] = { 2, "venthyr located at the Edge of Sin in Revendreth", "Jandaar of the Mists is a venthyr located at the Edge of Sin in Revendreth." },
  ["jande"] = { 2, "tortollan following the Trained Crab at the Seekers' Vist...", "Jande is a tortollan following the Trained Crab at the Seekers' Vista in Stormsong Valley." },
  ["jandvik bonepiercer"] = { 2, "', "Jandvik Bonepiercers are vrykul located in Suramar." },
  ["jandvik metalsmith"] = { 2, "vrykul located in Suramar", "Jandvik Metalsmith is a vrykul located in Suramar." },
  ["jandvik runecaller"] = { 2, "', "Jandvik Runecallers are vrykul located in Suramar. Some are found patrolling the area, some standing guard, and others healing wounded Jandvik Splintershields." },
  ["jandvik splintershield"] = { 2, "', "Jandvik Splintershields are vrykul located in Jandvik in Suramar. Some are found dead, fed to Har'kess the Insatiable in Azuregale Cove." },
  ["jane black"] = { 2, "worgen located in Bashal'Aran in Darkshore when the Allia...", "Jane Black is a worgen located in Bashal'Aran in Darkshore when the Alliance controls the zone." },
  ["janelle"] = { 2, "elven warrior", "Janelle is an elven warrior who fought many clockwerk goblins in order to reach the enemy leader, a goblin tinker." },
  ["janey anship"] = { 2, "human mage", "Janey Anship is a human mage who sits with Lisan Pierce and Suzanne at the base of the Wizard's Sanctum in Stormwind City, having a discussion about creating a spell or potion. The three sometimes get up to walk along the canals and through the Tr..." },
  ["jango spothide"] = { 2, "gnoll found at the Dust Plains in Westfall", "Jango Spothide is a gnoll found at the Dust Plains in Westfall. He is the leader of the Riverpaw gnolls in Westfall." },
  ["janky"] = { 2, "kobold located in Gundargaz in the Ringing Deeps", "Janky is a kobold located in Gundargaz in the Ringing Deeps." },
  ["jann harnelor"] = { 2, "vrykul located in Stormheim", "Jann Harnelor is a vrykul located in Stormheim." },
  ["jano"] = { 2, "tortollan located at Scaletrader Post in Zuldazar", "Jano is a tortollan located at Scaletrader Post in Zuldazar." },
  ["janus the dragonslayer"] = { 2, "', "The sinstone of Janus the Dragonslayer is found in Revendreth in the southcentral lower level of Dominance Keep." },
  ["jao-ti the thunderous"] = { 2, "mogu located in Warport Rastari in Zuldazar", "Jao-Ti the Thunderous is a mogu located in Warport Rastari in Zuldazar. As a stormbinder, Lei Shen himself said Jao-Ti showed a great connection to the storms." },
  ["japukitat"] = { 2, "tuskarr located in Iskaara in the Azure Span", "Japukitat is a tuskarr located in Iskaara in the Azure Span, his wounds tended to by Sentiu. He also appears inside Brackenhide Hollow." },
  ["jard"] = { 2, "tortollan located in northern Exile's Reach", "Jard is a tortollan located in northern Exile's Reach. They are found in a secret underwater cave under a waterfall." },
  ["jaren holdart"] = { 2, "dracthyr located in the Common in Razorwind Shores", "Jaren Holdart is a dracthyr located in the Common in Razorwind Shores and Town Center in Founder's Point when the Reaching Beyond the Possible endeavor is active." },
  ["jarett coldstone"] = { 2, "murloc located in Azsuna", "Jarett Coldstone is a murloc located in Azsuna." },
  ["jarien and sothos"] = { 2, "', "Jarien and Sothos are a pair of ghosts summoned in the Scarlet Bastion in Stratholme." },
  ["jarii"] = { 2, "tuskarr child located in Iskaara in the Azure Span", "Jarii is a tuskarr child located in Iskaara in the Azure Span." },
  ["jarim balnir"] = { 2, "son of the horsebreeder Jorum Balnir", "Jarim Balnir was the son of the horsebreeder Jorum Balnir and his wife Vara, and a childhood friend of Prince Arthas Menethil. He was the same age as Arthas." },
  ["jarl throndyr"] = { 2, "vrykul located at", "Jarl Throndyr was a vrykul located at, and the former leader of, Jandvik in Suramar. His body can be found among several dead Naga and is guarded by Brandolf." },
  ["jarl velbrand"] = { 2, "leader of the Drekirjar", "Jarl Velbrand is the leader of the Drekirjar. Along with Runeseer Faljar and Torvald, he could challenge Sigryn's claim to the throne of the Tideskorn." },
  ["jarlath brewbelly"] = { 2, "bronzebeard dwarf paladin", "Jarlath Brewbelly is a bronzebeard dwarf paladin and a member of the Alliance. He wields a masterwork dwarven battle hammer and a heavy steel shield, and wears plate mail." },
  ["jarquia"] = { 2, "murloc found in the Misty Reed Strand within the Swamp of...", "Jarquia is a murloc found in the Misty Reed Strand within the Swamp of Sorrows. Krinkle Goodsteel wants his flamberge back from Jarquia." },
  ["jaruk bloodfyre"] = { 2, "Shadowmoon orc shaman", "Jaruk Bloodfyre was a Shadowmoon orc shaman who lived on Draenor at the start of the genocide of the draenei. Having felt the elements abandoning him, he was wary of the course of his people and refused to drink the Blood of Mannoroth from the Cha..." },
  ["jaska aeroflange"] = { 2, "gnome located on Mechagon Island", "Jaska Aeroflange is a gnome located on Mechagon Island." },
  ["jawstretcher"] = { 2, "gnoll of the Woodpaw clan", "Jawstretcher was a gnoll of the Woodpaw clan. He had a son named Hackle." },
  ["jaxin chong"] = { 2, "goblin alchemy trainer located in the shop Boucher's Caul...", "Jaxin Chong is a goblin alchemy trainer located in the shop Boucher's Cauldron in Booty Bay in the Cape of Stranglethorn. He is on the top level, on the south side of town." },
  ["jay maguire"] = { 2, "Forsaken supervising the new area in Darkmoon Island in f...", "Jay Maguire is a Forsaken supervising the new area in Darkmoon Island in front of the Cauldron of Rock cave. He's the producer of the Blight Boar death metal band." },
  ["jayaan"] = { 2, "ethereal located in Shan'dorah in K'aresh", "Jayaan is a ethereal located in Shan'dorah in K'aresh." },
  ["jaycrue copperpinch"] = { 2, "goblin vendor located in the Trade Quarter in the Underci...", "Jaycrue Copperpinch is a goblin vendor located in the Trade Quarter in the Undercity during the Feast of Winter Veil event. She is affiliated with Smokywood Pastures, and sells higher value holiday related items." },
  ["jayde"] = { 2, "highly-skilled Darkfallen death knight of the Knights of ...", "Jayde is a highly-skilled Darkfallen death knight of the Knights of the Ebon Blade. Though she was expected to decimate the Argent Dawn forces at the Battle for Light's Hope Chapel, she was instead freed from the Lich King's control by Highlord Ti..." },
  ["jazdalaad"] = { 2, "ethereal jewelcrafting trainer located at the Stormspire ...", "Jazdalaad is an ethereal jewelcrafting trainer located at the Stormspire in the Netherstorm." },
  ["jeanine amrell"] = { 2, "worgen member of SI:7", "Jeanine Amrell is a worgen member of SI:7 that was sent to Nagrand to spy on the Iron Horde. She was killed by Warlord Azuka." },
  ["jed'hin adept"] = { 2, "', "Jed'hin Adepts are eredar echoes located at the Circle of Aspirants in Eredath, mostly standing among the audiences watching the Jed'hin matches. One of them stands ready to officiate a match between two Jed'hin Novices in the area's eastern circl..." },
  ["jed'hin champion vorusk"] = { 2, "eredar echo located on the staircase leading up to the Se...", "Jed'hin Champion Vorusk is an eredar echo located on the staircase leading up to the Seat of the Triumvirate above the Circle of Aspirants in Eredath. He was a Jed'hin champion and a disciple of Kil'jaeden." },
  ["jed'hin master"] = { 2, "', "Jed'hin Masters are eredar echoes located at the Circle of Aspirants in Eredath. One of them stands ready to officiate a Jed'hin match between two Jed'hin Adepts in the western circle, while two more stand ready to enter a match themselves in the ..." },
  ["jed'hin novice"] = { 2, "', "Jed'hin Novices are eredar echoes located at the Circle of Aspirants in Eredath, mostly seated among the audience watching the Jed'hin matches. Two of the Novices in the area's eastern circle stand ready to perform a match under the watch of a Jed..." },
  ["jeffrey gregarius"] = { 2, "worgen located at Greenwarden's Grove in the Wetlands", "Jeffrey Gregarius is a worgen located at Greenwarden's Grove in the Wetlands. He has a kitten named Spaz." },
  ["jegwa the shaggy"] = { 2, "troll located in the Hide or Hair shop at the Grand Bazaa...", "Jegwa the Shaggy is a troll located in the Hide or Hair shop at the Grand Bazaar in Dazar'alor. Katnis Sniptip gives them a trim." },
  ["jen cooper"] = { 2, "worgen", "Jen Cooper is a worgen." },
  ["jena anderson"] = { 2, "human found on the road to Stratholme", "Jena Anderson is a human found on the road to Stratholme. She needs flour to make some bread and asks Martha Goslin for some." },
  ["jenae sacredpyke"] = { 2, "Arathi located in the Lightspark Commissary in Hallowfall", "Jenae Sacredpyke is an Arathi located in the Lightspark Commissary in Hallowfall. She studied at the academy and was considered for becoming the next captain." },
  ["jeni"] = { 2, "vulpera seated atop a boulder at the Vulpera Hideaway in ...", "Jeni is a vulpera seated atop a boulder at the Vulpera Hideaway in Vol'dun. Teel appears to be her pet." },
  ["jennette doyle"] = { 2, "worgen reagent vendor located at the Talonbranch Glade in...", "Jennette Doyle is a worgen reagent vendor located at the Talonbranch Glade in Felwood. She can be found within a caravan." },
  ["jenni boombuckle"] = { 2, "goblin located in Mmarl", "Jenni Boombuckle is a goblin located in Mmarl and Grudge Grotto in Azj-Kahet. She runs the Venture Company operation in Mmarl and Grudge Grotto." },
  ["jenni cogshatter"] = { 2, "goblin flight master located at the Demolition Dome in th...", "Jenni Cogshatter is a goblin flight master located at the Demolition Dome in the Undermine." },
  ["jenoh"] = { 2, "vulpera snake charmer", "Jenoh is a vulpera snake charmer, quest giver, and pet vendor located in a small camp on the Cracked Coast in Vol'dun. He is attempting to train Strand Cobra Hatchlings with his flute, but temporarily lost it." },
  ["jephet nighthowler"] = { 2, "worgen located at Lunarfall in Shadowmoon Valley", "Jephet Nighthowler is a worgen located at Lunarfall in Shadowmoon Valley. He can only be recruited using the Headhunter's Harvest from Lunarfall Inn." },
  ["jerias bloodvein"] = { 2, "undead captain of the Garrote", "Jerias Bloodvein is the undead captain of the Garrote. He is a member of the Bloodsail Buccaneers." },
  ["jerkin joe"] = { 2, "murloc located in Dalaran", "Jerkin Joe is a murloc located in Dalaran. It is currently unknown if he survived Dalaran's destruction." },
  ["jerma lithpyke"] = { 2, "Arathi located in Fjord Tavern in Hallowfall", "Jerma Lithpyke is an Arathi located in Fjord Tavern in Hallowfall." },
  ["jermaine buckey"] = { 2, "dwarf located above Gnomeregan in a tree", "Jermaine Buckey is a dwarf located above Gnomeregan in a tree, sitting under his brother Anton Buckey hiding from a Black Bear." },
  ["jerr greenriver"] = { 2, "tauren seen fishing between Warspear", "Jerr Greenriver is a tauren seen fishing between Warspear and Warspear Outpost." },
  ["jes howlis"] = { 2, "second boss of Tol Dagor", "Jes Howlis is the second boss of Tol Dagor." },
  ["jess albury"] = { 2, "human flight master located in Arom's Stand in Drustvar", "Jess Albury is a human flight master located in Arom's Stand in Drustvar." },
  ["jessie boomfist"] = { 2, "goblin monk trainer located at the KTC Headquarters on Kezan", "Jessie Boomfist is a goblin monk trainer located at the KTC Headquarters on Kezan, where she is dueling a wooden flamingo, and in Bilgewater Harbor in Azshara, where she sits atop the roof of the inn." },
  ["jeti amberhoof"] = { 2, "dead tauren located in Pillar-nest Vosh in Azj-Kahet", "Jeti Amberhoof is a dead tauren located in Pillar-nest Vosh in Azj-Kahet. He tried to escape, but a fungal spore pod popped near him and died." },
  ["jevera milani"] = { 2, "Arathi located in Mereldar in Hallowfall", "Jevera Milani is an Arathi located in Mereldar in Hallowfall." },
  ["jhara"] = { 2, "centaur innkeeper located at Pinewood Post in the Ohn'ahr...", "Jhara is a centaur innkeeper located at Pinewood Post in the Ohn'ahran Plains." },
  ["jhorn the mad"] = { 2, "ogre located in the Ring of Trials in Nagrand", "Jhorn the Mad is an ogre located in the Ring of Trials in Nagrand. He, along with Thoktar Ironskull and Vul'gor, can be found overlooking the Arena Floor." },
  ["jinkutuk"] = { 2, "tuskarr herbalism trainer", "Jinkutuk is a tuskarr herbalism trainer and fishing vendor located in Iskaara in the Azure Span." },
  ["jinson"] = { 2, "tortollan located at the Jeweled Coast in Stormsong Valley", "Jinson is a tortollan located at the Jeweled Coast in Stormsong Valley. He is bathing a turtle." },
  ["jinxy blastwheel"] = { 2, "goblin located at the Mugambala in Zuldazar", "Jinxy Blastwheel is a goblin located at the Mugambala in Zuldazar." },
  ["jiq"] = { 2, "tuskarr child located in Iskaara in the Azure Span", "Jiq is a tuskarr child located in Iskaara in the Azure Span. He is chasing a Mammoth Calf with Lili." },
  ["jix'ak the crazed"] = { 2, "nerubian located in the Maddening Deep in Azj-Kahet", "Jix'ak the Crazed is a nerubian located in the Maddening Deep in Azj-Kahet." },
  ["jlarborn the strategist"] = { 2, "vrykul gladiator in the Ring of Judgement in the Howling ...", "Jlarborn the Strategist is a vrykul gladiator in the Ring of Judgement in the Howling Fjord. He needs to be slain during  [10-30] Stunning Defeat at the Ring." },
  ["jnifer casay"] = { 2, "vrykul located in Stormheim", "Jnifer Casay is a vrykul located in Stormheim." },
  ["joe barker"] = { 2, "worgen from Gilneas", "Joe Barker, nicknamed Silent Joe, was a worgen from Gilneas and the third mate of the Wavestrider. He was originally a pirate member of the Brashtide Crew and later of the Blackwater Raiders." },
  ["joel of the cliffs"] = { 2, "vrykul located in Stormheim", "Joel of the Cliffs is a vrykul located in Stormheim." },
  ["john felstone"] = { 2, "son of Emma Felstone", "John 'Jack' Felstone was a son of Emma Felstone and Jem, and the brother of James and Jacob. All three were warriors of Lordaeron, acting as royal guards to King Terenas Menethil." },
  ["john the reanimator"] = { 2, "venthyr located in Pridefall Hamlet in Revendreth once th...", "John the Reanimator is a venthyr located in Pridefall Hamlet in Revendreth once the anima stream from Sinfall's Anima Conductor is channeled into the area." },
  ["johnathan staats (npc)"] = { 2, "worgen quest giver located at Lor'danel in Darkshore", "Johnathan Staats is a worgen quest giver located at Lor'danel in Darkshore. He gives the quests formerly given by Gubber Blump, who went missing after the destruction of Auberdine." },
  ["jokomuupat"] = { 2, "tuskarr located in Camp Antonidas in the Azure Span", "Jokomuupat is a tuskarr located in Camp Antonidas in the Azure Span." },
  ["jol the ancient"] = { 2, "tortollan located at his house in Zeb'ahari", "Jol the Ancient is a tortollan located at his house in Zeb'ahari, Zuldazar. Being over seven hundred years old, he was the original inhabitant of the village, the Zandalari trolls then building around him." },
  ["jolinth"] = { 2, "dracthyr found at Morqut Village in the Forbidden Reach", "Jolinth is a dracthyr found at Morqut Village in the Forbidden Reach." },
  ["jolta candleflash"] = { 2, "goblin", "Jolta Candleflash is a goblin who works for the Gadgetzan Times." },
  ["joma"] = { 2, "tortollan located at Norwington Estate in Tiragarde Sound", "Joma is a tortollan located at Norwington Estate in Tiragarde Sound. When he and his father Majo were traveling to the estate, Joma noticed eels." },
  ["jon graves"] = { 2, "Forsaken located in Darkmoon Island", "Jon Graves is a Forsaken located in Darkmoon Island. He was present in the Caverns of Time during the 15th to 19th Bronze Celebration." },
  ["jonas cobb"] = { 2, "cook of the Wavestrider", "Jonas Cobb, nicknamed Old Cobb, was the cook of the Wavestrider. He had an assistant, 10 year-old-boy named Keelhaul Watt‎." },
  ["jonat han"] = { 2, "Elder", "Jonat Han, the Elder, trained new shaman of the Dragonflayer clan in mastering the ways of water and healing." },
  ["jonath chainfist"] = { 2, "dwarf mining trainer found in Stormshield", "Jonath Chainfist is a dwarf mining trainer found in Stormshield." },
  ["jonn-dar"] = { 2, "rare mogu found just north of Nesingwary's Safari in the ...", "Jonn-Dar is a rare mogu found just north of Nesingwary's Safari in the Valley of the Four Winds. When first encountered, Jonn-Dar is a statue, similar to those found in Mogujia, Kun-Lai Summit, but comes to life when attacked or when a player come..." },
  ["jool"] = { 2, "tortollan located in Torga's Tavern in Nazmir", "Jool is a tortollan located in Torga's Tavern in Nazmir." },
  ["joon cloudgazer"] = { 2, "tauren innkeeper", "Joon Cloudgazer is a tauren innkeeper and vendor located at Wolf's Den in Tiragarde Sound." },
  ["jora"] = { 2, "tortollan located at Scaletrader Post in Zuldazar", "Jora is a tortollan located at Scaletrader Post in Zuldazar." },
  ["joran"] = { 2, "Broken stable master located at the Harborage in the Swam...", "Joran is a Broken stable master located at the Harborage in the Swamp of Sorrows. He is speaking with one of the Broken Exiles." },
  ["jorb"] = { 2, "ogre", "Jorb is an ogre that patrols the path between the Crossroads and Ratchet, accompanying the goblin weapon vendor Lizzarik. Should he be provoked into battle, he will attack with his fists." },
  ["jorid"] = { 2, "earthen located in the Tradelounge in the Forgegrounds in...", "Jorid is an earthen located in the Tradelounge in the Forgegrounds in Dornogal." },
  ["jorn"] = { 2, "furbolg vendor located in Shady Sanctuary in the Ohn'ahra...", "Jorn is a furbolg vendor located in Shady Sanctuary in the Ohn'ahran Plains." },
  ["jorreth"] = { 2, "centaur located at the Gelkis Village in Desolace", "Jorreth is a centaur located at the Gelkis Village in Desolace." },
  ["joruh"] = { 2, "vulpera located in the Hall of Legends in Orgrimmar", "Joruh is a vulpera located in the Hall of Legends in Orgrimmar." },
  ["jorum balnir"] = { 2, "head of the Balnir family of horse-breeders", "Jorum Balnir was the head of the Balnir family of horse-breeders, the husband of Vara, and father of Jarim. In his youth, Prince Arthas Menethil often sneaked off to the Balnir Farmstead to admire Jorum's horses and play with Jarim." },
  ["jorun"] = { 2, "vrykul raider", "Jorun is a vrykul raider and leader of the Bloodwake clan. According to Vydhar, Jorun left the shores of Stormheim long ago with a fleet of ships, which some say consists of thousands of vessels." },
  ["joseph brayvemarc"] = { 2, "Arathi located in Mereldar in Hallowfall", "Joseph Brayvemarc is an Arathi located in Mereldar in Hallowfall." },
  ["joshua fuesting"] = { 2, "worgen found in Stormshield", "Joshua Fuesting is a worgen found in Stormshield." },
  ["josiah avery"] = { 2, "human", "Josiah Avery was a human that fell to the worgen curse during the siege of Gilneas City by the Bloodfang worgen. When the player approached him to requisition an arsenal hidden in his cellar by the Northgate rebels, he turned feral, changed to his..." },
  ["jotunheim proto-drake rider"] = { 2, "', "Jotunheim Proto-Drake Riders are vrykul located in Jotunheim in Icecrown, riding Jotunheim Proto-Drakes. This section concerns content related to Shadowlands." },
  ["jotunheim sleep-watcher"] = { 2, "', "Jotunheim Sleep-Watchers are vrykul located in Halls of the Ancestors in Icecrown. This section concerns content related to Shadowlands." },
  ["jotunheim warrior"] = { 2, "', "Jotunheim Warriors are vrykul located in Jotunheim in Icecrown. Some are accompanied by Sentry Worgs." },
