  ["jugnug"] = { 2, "ogre located at the Darkmaul Citadel on Exile's Reach", "Jugnug is an ogre located at the Darkmaul Citadel on Exile's Reach. During  [7-10] Right Beneath Their Eyes, he's friendly toward the player." },
