  ["justicia baercennan"] = { 2, "Arathi located in Office of the Veneration Grounds in Mer...", "Justicia Baercennan is an Arathi located in Office of the Veneration Grounds in Mereldar in Hallowfall. Speaking with her makes the attacking kobyss disappear from Veneration Grounds." },
  ["jux burstkix"] = { 2, "goblin", "Jux Burstkix is a goblin that appeared in the Twilight Shore in Darkshore during the War of the Thorns event. He later appeared in the Battle for Darkshore." },
