  ["ka'roz the locust"] = { 2, "mantid member of the Klaxxi located at Klaxxi'vess in the...", "Ka'roz the Locust is a mantid member of the Klaxxi located at Klaxxi'vess in the Dread Wastes. Ka'roz is a speed-based fighter from the time of Lei Shen over 12,000 years ago." },
  ["kaama arrowspring"] = { 2, "tauren follower located at Frostwall in Frostfire Ridge", "Kaama Arrowspring is a tauren follower located at Frostwall in Frostfire Ridge. He can only be recruited using the Headhunter's Harvest from Frostwall Tavern." },
  ["kaasa blighthoof"] = { 2, "tauren follower located at Frostwall in Frostfire Ridge", "Kaasa Blighthoof is a tauren follower located at Frostwall in Frostfire Ridge. She can be recruited from the Frostwall Tavern building via Akanja." },
  ["kaavu the crimson claw"] = { 2, "arakkoa found attacking Anchorite's Sojourn in Talador du...", "Kaavu the Crimson Claw is an arakkoa found attacking Anchorite's Sojourn in Talador during the Saving Anchorite's Sojourn event." },
  ["kaaya"] = { 2, "tuskarr child located in Kauriq Gleamlet in the Azure Span", "Kaaya is a tuskarr child located in Kauriq Gleamlet in the Azure Span. She is riding Noorave." },
  ["kabi bottlehold"] = { 2, "goblin drink vendor located in the Vatworks in the Undermine", "Kabi Bottlehold is a goblin drink vendor located in the Vatworks in the Undermine." },
  ["kadavan"] = { 2, "ethereal mercenary hired by the death knight", "Kadavan was an ethereal mercenary hired by the death knight, Ragnok Bloodreaver, to capture nether dragons for him. Kadavan developed a device to carry out this feat, which Ragnok used to enslave a number of nether dragons." },
  ["kador cloudsong"] = { 2, "tauren of the Cloudsong tribe", "Kador Cloudsong is a tauren of the Cloudsong tribe and a shaman trainer located on Spirit Rise in Thunder Bluff. He directs shaman towards available class quests." },
  ["kadus arkadian"] = { 2, "worgen guard of Princess Tess Greymane located in Shadowm...", "Kadus Arkadian is a worgen guard of Princess Tess Greymane located in Shadowmoon Valley." },
  ["kaeleb flamegard"] = { 2, "Arathi located in the Arathi Infirmary in Mereldar in Hal...", "Kaeleb Flamegard is an Arathi located in the Arathi Infirmary in Mereldar in Hallowfall. He tends to a hall full of Injured Soldiers." },
  ["kagfritha"] = { 2, "earthen located at Shadowvein Point in the Ringing Deeps", "Kagfritha is an earthen located at Shadowvein Point in the Ringing Deeps. Before the earthen workers abandoned the Rumbling Wastes, she used to be a site supervisor for operations in the area that was threatened by beasts, including the scorpid Sm..." },
  ["kagon"] = { 2, "earthen located on the Isle of Dorn", "Kagon is an earthen located on the Isle of Dorn." },
  ["kagraxxis the corruptor"] = { 2, "Corruptor is a satyr located inside Moonclaw Cavern in Mo...", "Kagraxxis the Corruptor is a satyr located inside Moonclaw Cavern in Moonclaw Vale. He took great pleasure in corrupting the places that he once called home during the War of the Ancients." },
  ["kah'net"] = { 2, "nerubian found in the Burrows in the City of Threads", "Kah'net is a nerubian found in the Burrows in the City of Threads." },
  ["kah'teht"] = { 2, "nerubian located by some waterfalls at the northern edge ...", "Kah'teht is a nerubian located by some waterfalls at the northern edge of the lake below Rak-Ahat in Azj-Kahet. They are originally from Azjol-Nerub, having been unsuccessfully sent by King Anub'arak to ask for Azj-Kahet's aid in the War of the Sp..." },
  ["kah'tir"] = { 2, "rare mogu located at an abandoned grummle camp", "Kah'tir is a rare mogu located at an abandoned grummle camp, northwest of Fire Camp Osul, in the Townlong Steppes. Kah'tir is a pandarian champion." },
  ["kaheti preysnatcher"] = { 2, "', "Kaheti Preysnatchers are nerubians located at the Ruptured Lake in Azj-Kahet." },
  ["kaheti sentry"] = { 2, "', "Kaheti Sentries are nerubians located in the Grand Rampart in Nerub-ar Palace." },
  ["kaheti silksinger"] = { 2, "', "Kaheti Silksingers are nerubians located at the Ruptured Lake in Azj-Kahet." },
