  ["kahlfra"] = { 2, "dracthyr located at the Cascades in Thaldraszus", "Kahlfra is a dracthyr located at the Cascades in Thaldraszus. She can, at times, be found painting a Preening Dragon." },
  ["kahugos"] = { 2, "dracthyr found sitting with Chi-Sen at the Serene Dreams ...", "Kahugos was a dracthyr found sitting with Chi-Sen at the Serene Dreams Spa in Thaldraszus. He was originally named Haiku." },
