  ["kajosh"] = { 2, "tortollan located at Gloom Hollow in Nazmir", "Kajosh is a tortollan located at Gloom Hollow in Nazmir." },
  ["kakushan"] = { 2, "great vrykul warrior", "Kakushan was a great vrykul warrior who laid waste to Stormscale naga villages with his friend Ivagont in Darkshore. They drank the blood of their enemies and crafted armor from their skins." },
  ["kal smoulderbrow"] = { 2, "Arathi located in the Ruptured Lake in Azj-Kahet", "Kal Smoulderbrow is an Arathi located in the Ruptured Lake in Azj-Kahet." },
  ["kal'shin"] = { 2, "ethereal located at North Sufaad on K'aresh", "Kal'shin is an ethereal located at North Sufaad on K'aresh, in Untethered Space." },
  ["kal'tik the blight"] = { 2, "rare mantid found north-west of the Setting Sun Garrison ...", "Kal'tik the Blight is a rare mantid found north-west of the Setting Sun Garrison in the Vale of Eternal Blossoms. Kal'tik is a pandarian champion." },
  ["kal'uvin"] = { 2, "tuskarr child building snowmen on the unnamed isle west o...", "Kal'uvin is a tuskarr child building snowmen on the unnamed isle west of the Azure Archives in southern Azure Span. Nearby, Ijap and Upio are sledding down the hill." },
  ["kala clayhoof"] = { 2, "tauren located in the Crafter's Enclave in Dornogal", "Kala Clayhoof is a tauren located in the Crafter's Enclave in Dornogal." },
