  ["kamul cloudsong"] = { 2, "tauren", "Kamul Cloudsong is a tauren." },
  ["kanai"] = { 2, "Broken of the Ashtongue Deathsworn located inside the Bla...", "Seer Kanai is a Broken of the Ashtongue Deathsworn located inside the Black Temple. After killing High Warlord Naj'entus and Supremus, the Spirit of Olum will allow teleportation directly from the entrance of Black Temple to Kanai." },
  ["kanai griffith"] = { 2, "Forsaken art teacher located on the mountain ridge on the...", "Kanai Griffith is a Forsaken art teacher located on the mountain ridge on the southeastern side of Coldarra in the Borean Tundra, where he is instructing his two students, Fara and Xega. A Skeletal Mount can also be found nearby." },
  ["kanati greycloud"] = { 2, "tauren located in Westreach Summit in Thousand Needles", "Kanati Greycloud is a tauren located in Westreach Summit in Thousand Needles. Before the Cataclysm, he was located in Whitereach Post." },
  ["kang the soul thief"] = { 2, "rare mogu located north of The Five Sisters in the Vale o...", "Kang the Soul Thief is a rare mogu located north of The Five Sisters in the Vale of Eternal Blossoms. Kang is a pandarian champion." },
  ["kanosak"] = { 2, "tuskarr dockmaster located at Moa'ki Harbor in the Dragon...", "Kanosak is a tuskarr dockmaster located at Moa'ki Harbor in the Dragonblight." },
