  ["kaqiata"] = { 2, "dead tuskarr located in Brackenhide Brambles in the Azure...", "Kaqiata is a dead tuskarr located in Brackenhide Brambles in the Azure Span. She was the mother of Rowie." },
  ["kar greycloud"] = { 2, "tauren druid part of the Hodir encounter in Ulduar", "Karr Greycloud is a tauren druid part of the Hodir encounter in Ulduar. He, along with his party is trapped in blocks of ice and must be freed to help against the frost titans attacks." },
  ["kara adams"] = { 2, "human shield vendor located in Lakeshire in the Redridge ...", "Kara Adams is a human shield vendor located in Lakeshire in the Redridge Mountains. When the Scourge attacked Lakeshire, she went to fight them." },
