  ["karang amakkar"] = { 2, "orc quest giver located at the Hellscream's Watch in Ashe...", "Karang Amakkar is an orc quest giver located at the Hellscream's Watch in Ashenvale. He was formerly located in Zoram'gar Outpost." },
  ["karba blazemaw"] = { 2, "elite orc battlemaster located in the Barracks of Orgrimm...", "Karba Blazemaw is an elite orc battlemaster located in the Barracks of Orgrimmar talking to Karg Skullgore." },
