  ["kardu"] = { 2, "earthen inscription vendor located in the Forgegrounds in...", "Kardu is an earthen inscription vendor located in the Forgegrounds in Dornogal." },
  ["karen 'i don't caribou' the culler"] = { 2, "Forsaken found on the bluff above the Farshire Mine just ...", "Karen 'I Don't Caribou' the Culler is a Forsaken found on the bluff above the Farshire Mine just to the north of Farshire in southern Borean Tundra with two stealthed Loot Crazed Poachers as guards." },
  ["karg bloodfury"] = { 2, "orc warrior located in Grom'gar", "Karg Bloodfury is an orc warrior located in Grom'gar and a member of the Frostwolf Orcs. He is the captain of Stonefang Outpost." },
  ["kargal battlescar"] = { 2, "orc quest giver located at Far Watch Post in the Northern...", "Kargal Battlescar is an orc quest giver located at Far Watch Post in the Northern Barrens. This section concerns content related to Legion." },
  ["kargand"] = { 2, "earthen located in the Forgegrounds in Dornogal", "Kargand is an earthen located in the Forgegrounds in Dornogal." },
  ["kargath bladefist"] = { 2, "Warchief of the Fel Horde", "Kargath Bladefist was the Warchief of the Fel Horde and Chieftain and founder of the Shattered Hand clan. He earned the sobriquet 'Bladefist' after he cut off his left hand to escape ogre captivity, replacing it with a deadly scythe called the  [T..." },
  ["kargath bladefist (warcraft ii)"] = { 2, "', "A razor-sharp scythe setting in place of his severed left hand, Kargath is always willing to engage in frenzied combat. His ruthless tactics and single-mindedness have earned him the Chieftainship of the feared Shattered Hand clan." },
  ["kargath bladefist (alternate universe)"] = { 2, "', "'Do not fear pain. Embrace it." },
  ["kargath bladefist (film universe)"] = { 2, "', "The Warcraft movie set in a separate timeline features Kargath Bladefist as one of the characters." },
  ["kargath bladefist (tactics)"] = { 2, "first boss of Highmaul in Nagrand", "Kargath Bladefist is the first boss of Highmaul in Nagrand." },
  ["kargen ironbrow"] = { 2, "earthen flight master located in Camp Murroch in the Ring...", "Kargen Ironbrow is an earthen flight master located in Camp Murroch in the Ringing Deeps." },
  ["kargesh grunt"] = { 2, "', "Kargesh Grunts are mogu located in the Crimson Assembly Hall in Mogu'shan Palace." },
  ["kargesh highguard"] = { 2, "', "Kargesh Highguards are mogu located at the Throne of Ancient Conquerors in Mogu'shan Palace." },
  ["kargesh ribcrusher"] = { 2, "', "Kargesh Ribcrushers are mogu located in Mogu'shan Palace." },
  ["kargpaw the fetid"] = { 2, "gnoll located in the Azure Span", "Kargpaw the Fetid is a gnoll located in the Azure Span." },
  ["kari bridgeblaster"] = { 2, "goblin located in the Incontinental Hotel in the Undermine", "Kari Bridgeblaster is a goblin located in the Incontinental Hotel in the Undermine. She trades the  [Excessively Bejeweled Curio] from Chrome King Gallywix for Tier 33 tier pieces." },
  ["karl"] = { 2, "worgen found in the Forward Command in the Southern Barrens", "Karl is a worgen found in the Forward Command in the Southern Barrens. Occasionally, he can be seen working on a wheel on a ballista." },
  ["karnk"] = { 2, "earthen located in the Waterworks in the Ringing Deeps", "Karnk is an earthen located in the Waterworks in the Ringing Deeps." },
  ["karokka"] = { 2, "arakkoa poison vendor located in the Lower City of the ne...", "Karokka is an arakkoa poison vendor located in the Lower City of the neutral Shattrath City." },
  ["karon ruz"] = { 2, "Drust located in Ardenweald", "Karon Ruz is a Drust located in Ardenweald." },
  ["karosh blackwind"] = { 2, "orc located at the Mok'gol Watchpost in Nagrand", "Karosh Blackwind is an orc located at the Mok'gol Watchpost in Nagrand. He summons Spectral Savagers." },
  ["karr the darkener"] = { 2, "mogu located at the Terrace of Gurthan in the Dread Wastes", "Karr the Darkener is a mogu located at the Terrace of Gurthan in the Dread Wastes. Karr is a Pandarian champion." },
  ["karrga"] = { 2, "seven feet tall ogre with ashy blue skin", "Karrga is a seven feet tall ogre with ashy blue skin. Marjuk killed her father over a pig." },
  ["karrion"] = { 2, "elder gnoll", "Karrion is an elder gnoll. She is part of the Woodpaw clan in Feralas." },
  ["karthis darkrune"] = { 2, "Darkfallen death knight located in the Plaguewood of East...", "Karthis Darkrune is a Darkfallen death knight located in the Plaguewood of Eastern Plaguelands under the command of Aurius Rivendare. He and Omasum Blighthoof are guarding the entrance to Stratholme." },
  ["kartra bloodsnarl"] = { 2, "elite level 85 Alterac Valley battlemaster located in the...", "Kartra Bloodsnarl was an elite level 85 Alterac Valley battlemaster located in the Hall of the Brave in the Valley of Honor, in the orcish city of Orgrimmar during the Call to Arms: Alterac Valley. She was only available during the monthly (Call t..." },
  ["karuk"] = { 2, "tuskarr located just north of Riplash Strand in the Borea...", "Karuk is a tuskarr located just north of Riplash Strand in the Borean Tundra." },
  ["karutz the lancer"] = { 2, "vrykul located in Stormheim", "Karutz the Lancer is a vrykul located in Stormheim." },
  ["kaskala defender"] = { 2, "', "Kaskala Defenders are tuskarr warriors that fight the kvaldir attackers assaulting Kaskala in the Borean Tundra." },
  ["katarine"] = { 2, "vrykul located at Jandvik in Suramar", "Katarine is a vrykul located at Jandvik in Suramar. When initially found inside of Muddledeep Cavern, she is trapped in a naga cage." },
  ["kathaw the savage"] = { 2, "furbolg located in Smolderhide Thicket in Val'sharah", "Kathaw the Savage is a furbolg located in Smolderhide Thicket in Val'sharah." },
  ["katia"] = { 2, "venthyr located in Revendreth", "Katia is a venthyr located in Revendreth." },
  ["katja"] = { 2, "trapper quest giver located at Silverbrook in the Grizzly...", "Katja is a trapper quest giver located at Silverbrook in the Grizzly Hills. She asks adventurers to remove the wolfsbane growing nearby, claiming that it is destroying crops and that she herself is allergic to it, an early hint at the fact that sh..." },
  ["katrina"] = { 2, "Ascended kyrian located in Bastion", "Katrina is an Ascended kyrian located in Bastion. She is found channeling an Anima Gateway leading to Hero's Rest." },
  ["katrina lyons"] = { 2, "worgen stable master located at Dragon's Mouth in the Bad...", "Katrina Lyons is a worgen stable master located at Dragon's Mouth in the Badlands." },
  ["katrinasa"] = { 2, "dead dracthyr found in the Support Creche in the Forbidde...", "Katrinasa is a dead dracthyr found in the Support Creche in the Forbidden Reach." },
  ["katterin the blistered"] = { 2, "vrykul located in Katterin's Hideaway in Stormheim", "Katterin the Blistered is a vrykul located in Katterin's Hideaway in Stormheim." },
  ["kattigat"] = { 2, "tuskarr located in Lost Ruins in the Azure Span", "Kattigat is a tuskarr located in Lost Ruins in the Azure Span. He is tending to Alia Sunsoar." },
  ["kattik sharktasted"] = { 2, "catch master for Taruka's clan of tuskarr", "Kattik Sharktasted is the catch master for Taruka's clan of tuskarr. He retired from daily fishing when he lost his right eye, a hand, and a leg to a shark, hence his surname." },
  ["katuu"] = { 2, "tuskarr child sleeping on an Iskaara Mammoth in Iskaara i...", "Katuu is a tuskarr child sleeping on an Iskaara Mammoth in Iskaara in the Azure Span." },
  ["kauj"] = { 2, "chieftain of the tuskarr Kauriq tribe located in Kauriq G...", "Kauj is the chieftain of the tuskarr Kauriq tribe located in Kauriq Gleamlet in the Azure Span." },
  ["kauriq fisher"] = { 2, "', "Kauriq Fishers are tuskarr located outside and inside Kauriq Gleamlet in the Azure Span. Some can also be found near Imbu, helping the refugees there." },
  ["kawayn"] = { 2, "haranir located atop Vordrassil in the Grizzly Hills", "Kawayn is a haranir located atop Vordrassil in the Grizzly Hills. Finding Kawayn is one of the criteria of the exploration achievement  [More Than Just Their Roots]." },
  ["kaya flathoof"] = { 2, "tauren quest giver located at Grimtotem Post in the Stone...", "Kaya Flathoof is a tauren quest giver located at Grimtotem Post in the Stonetalon Mountains." },
  ["kaye toogie"] = { 2, "undead member of the Kirin Tor found at the bottom of a g...", "Kaye Toogie is an undead member of the Kirin Tor found at the bottom of a grate-covered well just outside of The Filthy Animal. She can only be reached by using the  [Wormhole Generator: Northrend] and selecting Underground." },
  ["kaymard copperpinch"] = { 2, "vendor located in the Valley of Strength in the orcish ci...", "Kaymard Copperpinch is a vendor located in the Valley of Strength in the orcish city of Orgrimmar during the Feast of Winter Veil event. He is affiliated with Smokywood Pastures, and sells higher value holiday related items." },
  ["kaz'rik"] = { 2, "mantid located at the Heart of Fear in the Dread Wastes", "Kaz'rik is a mantid located at the Heart of Fear in the Dread Wastes. Talk to him to remove the debuff off the raid." },
  ["kaz'tik the manipulator"] = { 2, "mantid member of The Klaxxi", "Kaz'tik the Manipulator is a mantid member of The Klaxxi that can be found in Klaxxi'vess after being freed from amber in Briny Muck. Kaz'tik is a user of sonic-based magic, particularly using it to control the minds of enemies and kunchong minions." },
  ["kazu"] = { 2, "', "Kazu is member of the Arakkoa Outcasts located at Talon Watch within the Spires of Arak. He has been experimenting with the Curse of Sethe in order to weaponize it as a weapon against the Adherents of Rukhmar as there is nothing that they fear mor..." },
  ["kazure"] = { 2, "dracthyr located in Gladiator's Refuge in Valdrakken", "Kazure is a dracthyr located in Gladiator's Refuge in Valdrakken." },
  ["kazzi"] = { 2, "furbolg quartermaster of the Winterpelt Furbolg found Win...", "Kazzi is a furbolg quartermaster of the Winterpelt Furbolg found Winterpelt Hollow in the Azure Span. Players are introduced to her during the  [70] Local Flavors quest." },
  ["ke'nath"] = { 2, "Broken located in Krokul Hovel in Krokuun", "Ke'nath is a Broken located in Krokul Hovel in Krokuun." },
  ["keda bloomblade"] = { 2, "night elf Sentinel", "Keda Bloomblade is a night elf Sentinel and the protagonist of the short story 'Stones, Moss, and Tears'." },
  ["kedehern falamar"] = { 2, "son of Brogan", "Kedehern Falamar was the son of Brogan and brother of Aodhan. He chose to become a paladin of the Silver Hand, something his father approved of, ten years before the start of the Nexus War." },
  ["kee"] = { 2, "tortollan located in northern Exile's Reach", "Kee is a tortollan located in northern Exile's Reach. She is found in a secret underwater cave under a waterfall." },
  ["keegan alby"] = { 2, "Kul Tiran human guard of House Stormsong", "Keegan Alby is a Kul Tiran human guard of House Stormsong, located at Anglepoint Wharf in Tiragarde Sound. He was protecting the young Lord Brannon Stormsong, but lost him when their town fell." },
  ["keeneye brigadier"] = { 2, "', "Keeneye Brigadiers are worgen located in Bashal'Aran in Darkshore during  [50] In Darkest Night." },
  ["keenu"] = { 2, "tuskarr formerly located in the Gladiator's Refuge in Val...", "Keenu is a tuskarr formerly located in the Gladiator's Refuge in Valdrakken." },
  ["keeper nokturne"] = { 2, "venthyr located in the Grove of Terror in Revendreth", "Keeper Nokturne is a venthyr located in the Grove of Terror in Revendreth." },
  ["keeper ta'hilt"] = { 2, "broker located in the Hall of Curiosities in Oribos", "Keeper Ta'hilt is a broker located in the Hall of Curiosities in Oribos." },
  ["keeper ta'hult"] = { 2, "broker located in the Hall of Curiosities in Oribos", "Keeper Ta'hult is a broker located in the Hall of Curiosities in Oribos." },
  ["keeper ta'saran"] = { 2, "broker stable master located in the Hall of Curiosities i...", "Keeper Ta'saran is a broker stable master located in the Hall of Curiosities in Oribos. Together with Stablehand Ta'shno they manage beasts being portaled in, stabling them in the Dimensional Storage Cube." },
  ["keeper of worth"] = { 2, "', "Keepers of Worth are broker bankers located in the Hall of Holding in Oribos." },
  ["keeper of the cistern"] = { 2, "naga located in the Coilskar Cistern in Shadowmoon Valley", "The Keeper of the Cistern is a naga located in the Coilskar Cistern in Shadowmoon Valley." },
  ["keerin"] = { 2, "vulpera found locked inside a cage at the Ashvane Encampm...", "Keerin is a vulpera found locked inside a cage at the Ashvane Encampment in Vol'dun. He's tried to bargain for his release, but the Ashvane forces have refused all of his offers." },
  ["keese featherhoof"] = { 2, "tauren located at the Serene Dreams Spa in Thaldraszus", "Keese Featherhoof is a tauren located at the Serene Dreams Spa in Thaldraszus. They are found with a few other druids: Chumbergo, Gyasi Ra'lar, and Aona Kaseldri." },
  ["keeyo"] = { 2, "vulpera pet tamer located at the Vulpera Hideaway in Vol'dun", "Keeyo is a vulpera pet tamer located at the Vulpera Hideaway in Vol'dun. His pets are Tikka, Buzzbeak, and Milo." },
  ["kegan darkmar"] = { 2, "Forsaken found in the Lordamere Internment Camp in the Al...", "Kegan Darkmar is a Forsaken found in the Lordamere Internment Camp in the Alterac Mountains. Before becoming an undead, Kegan grew up in Lordaeron and his fondness for the now lost kingdom did not go away even when he became a Forsaken." },
  ["keila warhavuk"] = { 2, "Arathi child riding Dawnflame in Lorel's Crossing in Hall...", "Keila Warhavuk is an Arathi child riding Dawnflame in Lorel's Crossing in Hallowfall." },
  ["kelaan"] = { 2, "Broken located next to Father Gavin along with Lowan Feat...", "Kelaan is a Broken located next to Father Gavin along with Lowan Featherbreeze in Misty Pine Refuge in Dun Morogh. Judging by the short conversation the three are having, Featherbreeze and Kelaan appear to have been sent by someone to survey the d..." },
  ["kelantir bloodblade"] = { 2, "blood elf Blood Knight", "Kelantir Bloodblade was a blood elf Blood Knight. She trained with Lady Liadrin and served directly under the military leader of Quel'Thalas, Ranger-General Halduron Brightwing." },
  ["keldaz"] = { 2, "earthen located in Nibelgaz Mine in the Ringing Deeps", "Keldaz is an earthen located in Nibelgaz Mine in the Ringing Deeps." },
  ["kelgruk bloodaxe"] = { 2, "orc blacksmithing trainer located in the Valley of Honor ...", "Kelgruk Bloodaxe is an orc blacksmithing trainer located in the Valley of Honor in Orgrimmar." },
  ["kell"] = { 2, "vrykul located at Jandvik in Suramar", "Kell is a vrykul located at Jandvik in Suramar." },
  ["kelly aguilar"] = { 2, "human found in Stormwind City", "Kelly Aguilar is a human found in Stormwind City. She lives in a house, near The Eastern Earthshrine, together with Dylan Aguilar, Dylan's dog Otto von Chubbs and Waffle Joe." },
  ["kelorn nightblade"] = { 2, "night elf dispatched by Captain Varo'then to assassinate ...", "Kelorn Nightblade was a night elf dispatched by Captain Varo'then to assassinate Lord Kur'talos Ravencrest on behest of Queen Azshara during the War of the Ancients." },
  ["kelpfin"] = { 2, "baby naga companion", "Kelpfin is a baby naga companion." },
  ["kelther hearthen"] = { 2, "dead Arathi found at Cliffside Beason in Hallowfall", "Kelther Hearthen is a dead Arathi found at Cliffside Beason in Hallowfall. He was ritualistically sacrificed." },
  ["kemora"] = { 2, "dracthyr located in the Azure Archives Annex in Valdrakken", "Kemora is a dracthyr located in the Azure Archives Annex in Valdrakken." },
  ["kennel overseer"] = { 2, "', "Kennel Overseers are venthyr located in Houndkeeper's Alley and the Kennels in Castle Nathria." },
  ["kenzou"] = { 2, "vulpera quest giver located on the western outskirts of t...", "Kenzou is a vulpera quest giver located on the western outskirts of the Court of Zak'rajan in Vol'dun alongside Omi and Tacha. He used to be a member of a caravan, but after they tried and failed to fight the sethrak, Kenzou instead joined up with..." },
  ["kereke"] = { 2, "arakkoa located in Tranquil Strand on the Isle of Dorn bu...", "Kereke is an arakkoa located in Tranquil Strand on the Isle of Dorn but will not be in phase until completion of  [68-70] Secure the Beach from the Isle of Dorn storyline. Before Dalaran's destruction, Kereke was a prisoner of the Violet Hold alon..." },
  ["kergul bloodaxe"] = { 2, "orc Warsong Gulch battlemaster located on the Hunter Rise...", "Kergul Bloodaxe was an orc Warsong Gulch battlemaster located on the Hunter Rise in Thunder Bluff during the monthly Call to Arms: Warsong Gulch." },
  ["keritose bloodblade"] = { 2, "Darkfallen death knight", "Keritose Bloodblade is a Darkfallen death knight and quest giver located at the Shadow Vault in Icecrown. He directs adventurers to figure the defenses at the Weeping Quarry and to fight the Scourge forces in the quarry." },
  ["kerpow blastwrench"] = { 2, "goblin weapon vendor located at Cosmowrench in the Nether...", "Kerpow Blastwrench is a goblin weapon vendor located at Cosmowrench in the Netherstorm." },
  ["kerskull"] = { 2, "ogre of the Gordunni clan", "Kerskull was an ogre of the Gordunni clan and a part of Wordok's group. He was killed by Makasa Flintwill in Feralas." },
  ["kerthunk"] = { 2, "ogre blacksmithing vendor located at Stonemaul Hold in Fe...", "Kerthunk is an ogre blacksmithing vendor located at Stonemaul Hold in Feralas." },
  ["kervo cogpipe"] = { 2, "elderly gnome explorer", "Kervo Cogpipe was an elderly gnome explorer who set out in search of the lost city of Mechagon in hopes of finding the secret of immortality before he died of old age. Ultimately, however, he got more than he bargained for." },
  ["kerzanthi"] = { 2, "dracthyr located in the Azure Span", "Kerzanthi is a dracthyr located in the Azure Span." },
  ["keshet"] = { 2, "vulpera working at an anvil next to Kark Helmbreaker (bef...", "Keshet is a vulpera working at an anvil next to Kark Helmbreaker (before allied races are unlocked) or Uros Hardhoof (after allied races are unlocked) at the Orgrimmar Embassy in Orgrimmar." },
  ["kessa"] = { 2, "dracthyr located in the Victorious Visage in Valdrakken", "Kessa is a dracthyr located in the Victorious Visage in Valdrakken." },
  ["keth wernt"] = { 2, "Arathi located in the Orphanage of Mereldar in Hallowfall", "Keth Wernt is an Arathi located in the Orphanage of Mereldar in Hallowfall." },
  ["ketholia"] = { 2, "dracthyr located in Thaldraszus", "Ketholia is a dracthyr located in Thaldraszus." },
  ["keto"] = { 2, "tortollan located in Little Tortolla in Dazar'alor", "Keto is a tortollan located in Little Tortolla in Dazar'alor. He also appears in the Krasarang Wilds." },
  ["kettara bloodthirst"] = { 2, "orc shaman of the Earthen Ring", "Kettara Bloodthirst was an orc shaman of the Earthen Ring." },
  ["keyrra flamestonge"] = { 2, "Arathi located in Shadowgrove Vineyards in Hallowfall", "Keyrra Flamestonge is an Arathi located in Shadowgrove Vineyards in Hallowfall." },
  ["keyrra pyregard"] = { 2, "Arathi located at Faerin's Advance in Azj-Kahet", "Keyrra Pyregard is an Arathi located at Faerin's Advance in Azj-Kahet." },
  ["khadin"] = { 2, "centaur located in Khadin's Cave in the Ohn'ahran Plains", "Khadin is a centaur located in Khadin's Cave in the Ohn'ahran Plains." },
  ["khak'ik"] = { 2, "nerubian", "Khak'ik is a nerubian that patrols the Silken Path in Azj-Kahet alongside Rhak'ik." },
  ["khalla"] = { 2, "centaur food", "Khalla is a centaur food and drink vendor located on the northern coast of the Ohn'ahran Plains, where she runs a bar and grill with Tuktu the tuskarr." },
  ["khamsius"] = { 2, "Ascended kyrian located in Elysian Hold", "Khamsius is an Ascended kyrian located in Elysian Hold." },
  ["khan ablinh"] = { 2, "', "Khan Ablinh is one of the Galak chieftains in Splithoof Heights. He deals with the Alliance, while Khan Blizh deals with the Horde." },
  ["khan blizh"] = { 2, "', "Khan Blizh is one of the Galak chieftains in Splithoof Heights. He deals with the Horde, while Khan Ablinh deals with the Alliance." },
  ["khan bloodhoof"] = { 2, "', "Khan Bloodhoof is seemingly the khan of the Centaur Marauders." },
  ["khan dez'hepah"] = { 2, "Kolkar centaur khan found in Desolace", "Khan Dez'hepah is a Kolkar centaur khan found in Desolace. Felgur Twocuts wanted Dez'hepah's head." },
  ["khan gragtor"] = { 2, "level 14 Kolkar clan centaur khan", "Khan Gragtor was a level 14 Kolkar clan centaur khan, who tore an orc village asunder and took several orcs as unwilling slaves to do his bidding. Rexxar found the centaur camp and orc captives locked in cages." },
  ["khan hratha"] = { 2, "khan of the Maraudine centaur", "Khan Hratha is the khan of the Maraudine centaur. He spawns to defend the Maraudine War Horn in the Valley of Spears in Desolace during the quest  [42] Khan Hratha/ [42] Khan Hratha, and is accompanied by a Maraudine Khan Guard and a Maraudine Kha..." },
  ["khan jehn"] = { 2, "leader of the Magram centaur clan found in Magram Village...", "Khan Jehn was the leader of the Magram centaur clan found in Magram Village in Desolace. He held his leadership with his raw strength, making him the biggest and toughest in the entire village." },
  ["khan kammah"] = { 2, "leader of the Magram centaur in Desolace", "Khan Kammah is the leader of the Magram centaur in Desolace. The Burning Blade pushed him and his clan out of their home (which the cult renamed Shok'Thokar) and forced them to take over the lands of the Kolkar clan, which they renamed the Magram ..." },
  ["khan leh'prah"] = { 2, "leader of the Kolkar centaur of Desolace", "Khan Leh'Prah (also written Leh'prah) is the leader of the Kolkar centaur of Desolace. During his questline, adventurers help him unite the centaur of the Kolkar, Gelkis, and Magram clans to take back Shok'Thokar from the Burning Blade cult." },
  ["khan shaka"] = { 2, "leader of the Gelkis clan centaurs", "Khan Shaka was the leader of the Gelkis clan centaurs and once found in Gelkis Village of Desolace. When Cataclysm was released, Shaka was replaced with Khan Shodo for reasons unknown." },
  ["khan shodo"] = { 2, "leader of the Gelkis centaur in Desolace", "Khan Shodo is the leader of the Gelkis centaur in Desolace. He is aging, and suffers from old war wounds." },
  ["khanam matra sarest"] = { 2, "Khanam Matra of the Maruuk centaur of the Ohn'ahran Plains", "Khanam Matra Sarest is the Khanam Matra of the Maruuk centaur of the Ohn'ahran Plains. As such, she is the leader of Clan Teerai, the cultural khan of all the Maruuk clans, and a direct descendant of Teera herself." },
  ["khansguard akato"] = { 2, "leader of Khanam Matra Sarest's khansguard", "Khansguard Akato is the leader of Khanam Matra Sarest's khansguard, located at the entrance to Sarest's chambers atop the krutal in Maruukai in the Ohn'ahran Plains. After Clan Nokhud betray the other clans, Akato sends adventurers to thin the Nok..." },
  ["khansguard hojin"] = { 2, "member of the khansguard located in northern Teerakai in ...", "Khansguard Hojin is a member of the khansguard located in northern Teerakai in the Ohn'ahran Plains, where he oversees three training Khansguard Prospects. As part of Khansguard Jebotai's war orders, he asks Hojin to mobilize the guards." },
  ["khansguard jebotai"] = { 2, "centaur quest giver", "Khansguard Jebotai is a centaur quest giver and member of the khansguard located in the main tent in eastern Teerakai in the Ohn'ahran Plains. He is Khanam Matra Sarest's lieutenant." },
  ["khansguard prospect"] = { 2, "', "The Khansguard Prospects are three khansguard members training under Khansguard Hojin's supervision in northern Teerakai in the Ohn'ahran Plains." },
  ["khansguard warrior"] = { 2, "', "Khansguard Warriors are centaur of the khansguard who help defend Maruukai in the Ohn'ahran Plains from the Nokhud during  [20-70] The Khanam Matra,  [20-70] Trucebreakers, and  [20-70] The Nokhud Threat." },
  ["kharg"] = { 2, "ogre located at the Highmaul in Nagrand", "Kharg is an ogre located at the Highmaul in Nagrand." },
  ["khargall fivefangs"] = { 2, "furbolg located in the Azure Span", "Khargall Fivefangs is a furbolg located in the Azure Span." },
  ["khasar"] = { 2, "centaur quest giver of Clan Shikaar first seen in Mudfin ...", "Khasar is a centaur quest giver of Clan Shikaar first seen in Mudfin Village in the Ohn'ahran Plains, where he's been captured by the Mudfin gorlocs after trying to reclaim the supplies that the gorlocs stole from Farrier Roscha at Timberstep Outp..." },
  ["kherrah"] = { 2, "centaur quest giver located at Maraudon in Desolace", "Kherrah is a centaur quest giver located at Maraudon in Desolace. She is being held prisoner by the Maraudine clan." },
  ["khiragg"] = { 2, "centaur khan", "Khiragg was a centaur khan who led his warband to attack the tauren of Mulgore during the invasion of Durotar. The centaur kidnapped several tauren, including Baine Bloodhoof, son of the tauren's high chieftain Cairne." },
  ["khole"] = { 2, "earthen located in the Forgegrounds in Dornogal", "Khole is an earthen located in the Forgegrounds in Dornogal." },
  ["khoraazi"] = { 2, "planned ethereal", "Khoraazi was a planned ethereal who was meant to be a chairman of the Consortium." },
  ["khuri"] = { 2, "tuskarr fishing trainer located in the Waking Shores", "Khuri is a tuskarr fishing trainer located in the Waking Shores and at Khuri's Fishing Spot in the Azure Span. He manages the fishery of the River Mouth Fishing Hole." },
  ["khuyag"] = { 2, "centaur vendor located in Cloverwood Hollow in the Ohn'ah...", "Khuyag is a centaur vendor located in Cloverwood Hollow in the Ohn'ahran Plains." },
  ["kiaranyka"] = { 2, "kyrian located in Torghast", "Kiaranyka is a kyrian located in Torghast, Tower of the Damned." },
  ["kidnapped mind slave"] = { 2, "', "Kidnapped Mind Slaves are vulpera and Zandalari trolls being mind-controlled by Sandfury Mindthieves in the Sandfury Hideout in Vol'dun. Some are being forced to fight each other for the entertainment of Sandfury Bandits, while Gozda'kun the Slave..." },
  ["kiera horth"] = { 2, "Arathi located in Communal Kitchen of Mereldar in Hallowfall", "Kiera Horth is an Arathi located in Communal Kitchen of Mereldar in Hallowfall. The book  [500 Dishes Using Cave Fish and Mushrooms] can be found on a table in her home." },
  ["kik'tik"] = { 2, "mantid flight master found in Klaxxi'vess of the Dread Wa...", "Kik'tik is a mantid flight master found in Klaxxi'vess of the Dread Wastes." },
  ["kiki"] = { 2, "tortollan located in Little Tortolla in Dazar'alor", "Kiki is a tortollan located in Little Tortolla in Dazar'alor." },
  ["kikiua"] = { 2, "tuskarr child located in the Azure Span", "Kikiua is a tuskarr child located in the Azure Span. She and Kunap are standing next to a Snowball." },
  ["kiku"] = { 2, "tortollan located in Snug Harbor Inn in Boralus", "Kiku is a tortollan located in Snug Harbor Inn in Boralus. She serves as the solo-LFR queue NPC for level 51-and-higher players." },
  ["kil'ruk the wind-reaver"] = { 2, "proud old soldier", "Kil'ruk the Wind-Reaver was one of the Klaxxi paragons. He was a proud old soldier who saw value in allowing outsiders to aid in the Klaxxi's war against Grand Empress Shek'zeer, before siding with Garrosh Hellscream during the Siege of Orgrimmar ..." },
  ["kilejo"] = { 2, "tuskarr found in the Hall of Shadows", "Kilejo is a tuskarr found in the Hall of Shadows." },
  ["kilix the unraveler"] = { 2, "nerubian quest giver located in the Pit of Narjun in the ...", "Kilix the Unraveler is a nerubian quest giver located in the Pit of Narjun in the Dragonblight, next to the entrances to Azjol-Nerub and Ahn'kahet: The Old Kingdom, alongside two Azjol-anak Battleguards. He and his kin are strongly opposed to the ..." },
  ["killm"] = { 2, "earthen located in the Forgegrounds in Dornogal", "Killm is an earthen located in the Forgegrounds in Dornogal." },
  ["kilrogg deadeye"] = { 2, "chieftain of the Bleeding Hollow clan", "Kilrogg Deadeye was the chieftain of the Bleeding Hollow clan. He is so named because he lost his left eye." },
  ["kimi"] = { 2, "tuskarr located in Mulsted's Marquee in the Azure Span", "Kimi is a tuskarr located in Mulsted's Marquee in the Azure Span." },
  ["kin-tara"] = { 2, "Forsworn kyrian", "Kin-Tara is a Forsworn kyrian and the first boss located in the Spires of Ascension." },
  ["kina cobbleflame"] = { 2, "dwarf flight master located in Verdant Hollow in Zuldazar", "Kina Cobbleflame is a dwarf flight master located in Verdant Hollow in Zuldazar." },
  ["kindle candlecrafter"] = { 2, "Bluewax kobold found in Candle Rock in Highmountain durin...", "Kindle Candlecrafter is a Bluewax kobold found in Candle Rock in Highmountain during  [10-45] Candle of Command and  [10-45] Burn the Candle at Both Ends. He appears to be an expert at creating candles and working with wax." },
  ["king bjorn"] = { 2, "great vrykul king", "King Bjorn of the Black Storm was a great vrykul king. He is laid to rest in his funeral boat located in Ymiron's Seat, Utgarde Pinnacle." },
  ["king burgrurble"] = { 2, "murloc", "King Burgrurble is a murloc. He was so named by Professor Flozz." },
  ["king gakula"] = { 2, "murloc located at Bloodfin Village in Nazjatar", "King Gakula is a murloc located at Bloodfin Village in Nazjatar. He spawns after shooing some Bloodfin Tadpoles." },
  ["king gordok"] = { 2, "title", "King Gordok is the title and name of the Gordunni king in the Gordok Commons of Dire Maul. The title of the king of the Gordunni ogres, residing inside Dire Maul." },
  ["king haldor"] = { 2, "great vrykul king", "King Haldor of the Rocky Cliffs was a great vrykul king. He is laid to rest in his funeral boat located in Ymiron's Seat, Utgarde Pinnacle." },
  ["king ranulf"] = { 2, "great vrykul king", "King Ranulf of the Screaming Abyss was a great vrykul king. He is laid to rest in his funeral boat located in Ymiron's Seat, Utgarde Pinnacle." },
  ["king tor"] = { 2, "great vrykul king", "King Tor of the Brutal Siege was a great vrykul king. He is laid to rest in his funeral boat located in Ymiron's Seat, Utgarde Pinnacle." },
  ["king ymiron"] = { 2, "king of the vrykul", "King Ymiron was the king of the vrykul and leader of the Dragonflayer clan in Northrend. Having proven himself to the Lich King, he was converted to the undead and acted as the last boss of Utgarde Pinnacle." },
  ["king ymiron (tactics)"] = { 2, "last boss of Utgarde Pinnacle", "King Ymiron is the last boss of Utgarde Pinnacle." },
  ["kinndy brightsocket"] = { 2, "gnome located at the Lunarfall in Shadowmoon Valley", "Kinndy Brightsocket is a gnome located at the Lunarfall in Shadowmoon Valley. She can only be recruited using the Headhunter's Harvest from Lunarfall Inn." },
  ["kiopo"] = { 2, "tuskarr located in the Azure Span", "Kiopo is a tuskarr located in the Azure Span." },
  ["kip"] = { 2, "tuskarr located in the Azure Span", "Kip is a tuskarr located in the Azure Span." },
  ["kipaata"] = { 2, "tuskarr located in Uktulut Pier in the Waking Shores", "Kipaata is a tuskarr located in Uktulut Pier in the Waking Shores." },
  ["kipp"] = { 2, "vulpera initially found as a captive of the Faithless set...", "Kipp is a vulpera initially found as a captive of the Faithless sethrak at the Serpent's Maw in Vol'dun. After being rescued by the player, he can be seen in the Vulpera Hideaway, conversing with Hakasi." },
  ["kipp brightwick"] = { 2, "Bluewax kobold found on the upper level of Candle Rock in...", "Kipp Brightwick is a Bluewax kobold found on the upper level of Candle Rock in Highmountain. He is busy creating new candles, but if asked he will tell the story of the Bluewax kobolds." },
  ["kirga earthguard"] = { 2, "', "She learned from her older sibling, Kulan." },
  ["kirgvald"] = { 2, "Drust located in Ardenweald", "Kirgvald is a Drust located in Ardenweald." },
  ["kirin tor augur"] = { 2, "', "Kirin Tor Augurs are unreleased elves, gnomes, and humans." },
  ["kirin tor invoker"] = { 2, "', "Kirin Tor Invokers are located in the Hall of the Guardian and later in Deliverance Point on the Broken Shore. They will replace the Tirisgarde Apprentice in the class hall and as missive board troops if the advancement Higher Learning is taken." },
  ["kirin tor invokers"] = { 2, "', "Kirin Tor Invokers are humans who briefly appear in the Hall of the Guardian. After being trained by Grand Conjurer Mimic, they run out of the hall." },
  ["kirin tor magus (stormwind city)"] = { 2, "', "Kirin Tor Magi are mages located in the Wizard's Sanctum of Stormwind City. They maintain a portal to Stormshield." },
  ["kiro"] = { 2, "caravan leader of the Voldunai vulpera", "Kiro is a caravan leader of the Voldunai vulpera, initially encountered at the Vulpera Hideaway in Vol'dun. He is slightly wary of outsiders but is a skilled healer." },
  ["kirox the wind dancer"] = { 2, "arakkoa located in Skettis‎ in the Spires of Arak", "Kirox the Wind Dancer is an arakkoa located in Skettis‎ in the Spires of Arak." },
  ["kirrawk"] = { 2, "arakkoa shaman from Terokkar Forest", "Kirrawk is an arakkoa shaman from Terokkar Forest, serving as a Challenge Card encounter in the Brawler's Guild during The War Within. To fight Kirrawk, purchase  [Challenge Card: Kirrawk] after reaching Rank 8 with the guild." },
  ["kirrik the awakened"] = { 2, "arakkoa quest giver located at the Refugee Caravan in Ter...", "Kirrik the Awakened is an arakkoa quest giver located at the Refugee Caravan in Terokkar Forest." },
  ["kirtonos the herald"] = { 2, "undead", "Kirtonos the Herald is an undead who can transform into a vampire with gargoyle appearance. Long ago, he became the master of Scholomance's Doctor Theolen Krastinov." },
  ["kisha"] = { 2, "tortollan located in Nazmir", "Kisha is a tortollan located in Nazmir. She attended the funeral of King Rastakhan in Dazar'alor and remained in the city during Talanji's coronation." },
  ["kitala starshadow"] = { 2, "Darkfallen dark ranger first seen in the Hall of Ritual i...", "Kitala Starshadow is a Darkfallen dark ranger first seen in the Hall of Ritual in Dazar'alor as 'Captain Kitala', guarding Derek Proudmoore before he was rescued. After Sylvanas Windrunner abandoned the Forsaken, Kitala briefly appeared at the Cal..." },
  ["kitkrut"] = { 2, "kobold located near Ritkin in Gundargaz in the Ringing Deeps", "Kitkrut is a kobold located near Ritkin in Gundargaz in the Ringing Deeps." },
  ["kitzie crankshot"] = { 2, "', "Kitzie Crankshot is goblin vendor that sells vintage Season 3 PvP weapons and armor for  [Mark of Honor]. She can be found in Area 52 in the Netherstorm." },
  ["kivrok"] = { 2, "tuskarr located in Iskaara in the Azure Span", "Kivrok is a tuskarr located in Iskaara in the Azure Span. He informs on the arrival of the Young Belvo." },
  ["kiz coilspanner"] = { 2, "flight master located at Hatchet Hills in the territory o...", "Kiz Coilspanner is the flight master located at Hatchet Hills in the territory of Ghostlands." },
  ["kizi copperclip"] = { 2, "goblin in charge of the Barbershop in Dalaran", "Kizi Copperclip is the goblin in charge of the Barbershop in Dalaran. This section concerns content related to The War Within." },
  ["kizz bluntstrike"] = { 2, "goblin mace vendor located in Booty Bay in the Cape of St...", "Kizz Bluntstrike is a goblin mace vendor located in Booty Bay in the Cape of Stranglethorn. He runs Cuts-N-Bruises Incorporated together with Zarena Cromwind." },
  ["kjellrun"] = { 2, "Mawsworn kyrian located in Desmotaeron of the Maw", "Kjellrun, the Harrower, is a Mawsworn kyrian located in Desmotaeron of the Maw. She drops the  [Helwrought Seal] for  [60] The Caged Bird." },
  ["klaatu"] = { 2, "tortollan located at the Dive Bar in Zuldazar", "Klaatu is a tortollan located at the Dive Bar in Zuldazar." },
  ["klarissa cartwright"] = { 2, "human", "Klarissa Cartwright is a human who wrote to Fizzle Goblinseer, as she was concerned about her husband spending more time with a succubus named Aelneth than her." },
  ["klaskin"] = { 2, "nerubian found in the Umbral Bazaar in City of Threads", "Klaskin is a nerubian found in the Umbral Bazaar in City of Threads." },
  ["klassia"] = { 2, "Ascended kyrian located at Sagehaven in Bastion", "Klassia is an Ascended kyrian located at Sagehaven in Bastion. She was part of the grand reception the Archon arranged for a Maw Walker, who decided to join the Kyrian Covenant, in honor of their efforts against the Maldraxxus incursion in Bastion." },
  ["klaxxi (time rifts)"] = { 2, "', "Klaxxi are mantid from Azq'roth located in Tyrhold Reservoir in Thaldraszus during Time Rifts." },
  ["klaxxi amber shaper"] = { 2, "', "Klaxxi Amber Shapers are mantid from Azq'roth located in Tyrhold Reservoir in Thaldraszus during Time Rifts." },
  ["klaxxi amber-guard"] = { 2, "', "Klaxxi Amber-Guards are mantid located in the Vale of Eternal Blossoms." },
  ["klaxxi amberseeker"] = { 2, "', "Klaxxi Amberseekers are mantid located in the Vale of Eternal Blossoms." },
  ["klaxxi assassin"] = { 2, "', "Klaxxi Assassins are mantid from Azq'roth located in Tyrhold Reservoir in Thaldraszus during Time Rifts." },
  ["klaxxi blade lord"] = { 2, "', "Klaxxi Blade Lords are mantid from Azq'roth located in Tyrhold Reservoir in Thaldraszus during Time Rifts." },
  ["klaxxi skirmisher"] = { 2, "', "Klaxxi Skirmishers are mantid found in the Chamber of the Paragons during the Siege of Orgrimmar." },
  ["klaxxi vess-guard"] = { 2, "', "Klaxxi Vess-Guards are mantid located at Klaxxi'vess in the Dread Wastes. This section concerns content related to Battle for Azeroth." },
  ["klaxxi wakener"] = { 2, "', "Klaxxi Wakeners are mantid located in the Vale of Eternal Blossoms." },
  ["klaxxi warrior (time rifts)"] = { 2, "', "Klaxxi Warriors are mantid from Azq'roth located in Tyrhold Reservoir in Thaldraszus during Time Rifts." },
  ["klaxxi'va ik"] = { 2, "mantid located at Klaxxi'vess in Dread Wastes", "Klaxxi'va Ik is a mantid located at Klaxxi'vess in Dread Wastes. He is killed by Grand Empress Shek'zeer." },
  ["klaxxi'va kek"] = { 2, "mantid located at Klaxxi'vess in Dread Wastes", "Klaxxi'va Kek is a mantid located at Klaxxi'vess in Dread Wastes. He's killed by Grand Empress Shek'zeer." },
  ["klaxxi'va kor"] = { 2, "member of the Klaxxi located in Klaxxi'vess of the Dread ...", "Klaxxi'va Kor is a member of the Klaxxi located in Klaxxi'vess of the Dread Wastes." },
  ["klaxxi'va krik"] = { 2, "mantid located at Klaxxi'vess in Dread Wastes", "Klaxxi'va Krik is a mantid located at Klaxxi'vess in Dread Wastes. He's killed by Grand Empress Shek'zeer." },
  ["klaxxi'va lor"] = { 2, "mantid located outside the Heart of Fear in Dread Wastes", "Klaxxi'va Lor is a mantid located outside the Heart of Fear in Dread Wastes." },
  ["klaxxi'va pok"] = { 2, "member of the Klaxxi when Kil'ruk the Wind-Reaver was fir...", "Klaxxi'va Pok was a member of the Klaxxi when Kil'ruk the Wind-Reaver was first born into the swarm. Kil'ruk would come to Klaxxi'va Pok's attention when he began showing innovations such as having flyers dive into battle, wielding swords." },
  ["klaxxi'va set"] = { 2, "mantid located at Klaxxi'vess in Dread Wastes", "Klaxxi'va Set is a mantid located at Klaxxi'vess in Dread Wastes. He's killed by Grand Empress Shek'zeer." },
  ["klaxxi'va sra"] = { 2, "elite mantid found at Klaxxi'vess in the Dread Wastes", "Klaxxi'va Sra is an elite mantid found at Klaxxi'vess in the Dread Wastes. He appears to be one of the main members of the Klaxxi." },
  ["klaxxi'va tik"] = { 2, "mantid in the Dread Wastes", "Klaxxi'va Tik is a mantid in the Dread Wastes. He's killed by Grand Empress Shek'zeer." },
  ["klaxxi'va vor"] = { 2, "Klaxxi leader found at Klaxxi'vess in the Dread Wastes", "Klaxxi'va Vor is the Klaxxi leader found at Klaxxi'vess in the Dread Wastes. He swayed his fellows to work with the adventurers." },
  ["klaxxi'va zan"] = { 2, "mantid located at Klaxxi'vess in Dread Wastes", "Klaxxi'va Zan is a mantid located at Klaxxi'vess in Dread Wastes. He's killed by Grand Empress Shek'zeer." },
  ["klaxz boompowder"] = { 2, "former trade prince of the Steamwheedle Cartel", "Klaxz Boompowder is a former trade prince of the Steamwheedle Cartel who became the first known victim of the Uninvited Guest." },
  ["klayn thysthand"] = { 2, "Arathi located in Mereldar in Hallowfall", "Klayn Thysthand is an Arathi located in Mereldar in Hallowfall." },
  ["kleia"] = { 2, "kyrian", "Kleia is a kyrian. She is the first character that players encounter in Bastion and plays a major role throughout the zone storyline and the Kyrian Covenant campaign." },
  ["klotos"] = { 2, "kyrian located in the Spires of Ascension", "Klotos is a kyrian located in the Spires of Ascension." },
  ["klozicc the ascended"] = { 2, "furbolg located in the Flashfrost Enclave in the Waking S...", "Klozicc the Ascended is a furbolg located in the Flashfrost Enclave in the Waking Shores." },
  ["kluk'kluk"] = { 2, "', "Kluk'kluk can be found in Lion's Watch and Vol'mar in Tanaan Jungle. He offers the quest  [100 Daily] Abrogator Arbitrator for players who have not yet completed  [100R] Legacy of the Sorcerer Kings." },
  ["klystere"] = { 2, "kyrian stable master located at the Aspirant's Rest in Ba...", "Klystere is a kyrian stable master located at the Aspirant's Rest in Bastion. She asked a Maw Walker to collect materials from beasts near Aspirant's Rest so she could make clothes for new arrivals." },
  ["knaz blunderflame"] = { 2, "gnome engineering vendor located on a hidden hill south o...", "Knaz Blunderflame is a gnome engineering vendor located on a hidden hill south of the Mosh'Ogg Ogre Mound in Northern Stranglethorn. The camp may be hard to find, but the hillside is climbable at one point just south of the ogre camps, and this pa..." },
  ["knicknack"] = { 2, "kobold located outside of Gundargaz in the Ringing Deeps", "Knicknack is a kobold located outside of Gundargaz in the Ringing Deeps. During her life, she collected many things." },
  ["knight of the ebon blade (death rising)"] = { 2, "', "Knights of the Ebon Blade are orcs, humans, Forsaken, and night elves located in Stormwind City and Orgrimmar." },
  ["knight of the ebon blade (icecrown citadel)"] = { 2, "', "Knights of the Ebon Blade are death knights located in the Frozen Throne in Icecrown Citadel." },
  ["knight-captain aldrin"] = { 2, "human located at Dabyrie's Farmstead in the Arathi Highlands", "Knight-Captain Aldrin is a human located at Dabyrie's Farmstead in the Arathi Highlands." },
  ["knight-captain alyrra"] = { 2, "draenei", "Knight-Captain Alyrra is a draenei." },
  ["knight-captain murky"] = { 2, "Alliance version of Murky as a soldier", "The Knight-Captain Murky is the Alliance version of Murky as a soldier. He is awarded to players who attended or purchase the virtual ticket for BlizzCon 2016." },
  ["ko'ragh"] = { 2, "leader of the magic breakers", "Ko'ragh is the leader of the magic breakers and the sixth boss of Highmaul in Nagrand." },
  ["ko'ropo"] = { 2, "broker located in the Hall of Holding in Oribos", "Ko'ropo is a broker located in the Hall of Holding in Oribos. He sells Castle Nathria equipment." },
  ["ko'tul"] = { 2, "broker located in the Hall of Holding in Oribos", "Ko'tul is a broker located in the Hall of Holding in Oribos. He traded excess  [Valor] and  [Attendant's Token of Merit] for trade goods and currencies during the Shadowlands seasons." },
  ["koatini"] = { 2, "tuskarr located at the Grand Bazaar in Dazar'alor", "Koatini is a tuskarr located at the Grand Bazaar in Dazar'alor." },
  ["koba"] = { 2, "tortollan located at the Seekers' Outpost in Zuldazar", "Koba is a tortollan located at the Seekers' Outpost in Zuldazar." },
  ["kobold (rumble)"] = { 2, "melee ground unit of the in Warcraft Rumble", "Kobold is a melee ground unit of the in Warcraft Rumble. The Kobold is included in every single army composition and does not take a slot." },
  ["kobold (warcraft iii)"] = { 2, "', "Kobolds are kobold creeps that can be encountered in many tilesets. They are the most basic kobold creep." },
  ["kobold caster"] = { 2, "', "Kobold Casters are kobolds located in Drywhisker Gorge and Drywhisker Mine in the Arathi Highlands during Plunderstorm." },
  ["kobold digger"] = { 2, "', "Kobold Diggers are kobolds found in Jangolode Mine in Westfall." },
  ["kobold digger (deadmines)"] = { 2, "', "Kobold Diggers are kobolds found within the entrance section of the Deadmines. Sometimes the candles atop their heads are used by the Ogre Henchmen to light their cannons." },
  ["kobold drawing"] = { 2, "kobold located in Azsuna", "Kobold Drawing is a kobold located in Azsuna." },
  ["kobold fighter"] = { 2, "', "Kobold Fighters are kobolds located in Drywhisker Gorge and Drywhisker Mine in the Arathi Highlands during Plunderstorm." },
  ["kobold flametender"] = { 2, "', "Kobold Flametenders are kobolds located in Darkflame Cleft." },
  ["kobold geomancer"] = { 2, "', "Kobold Geomancers are kobold mobs that can be found in and around the Jasperlode Mine in Elwynn Forest." },
  ["kobold geomancer (plunderstorm)"] = { 2, "', "Kobold Geomancers are kobolds located in Drywhisker Gorge and Drywhisker Mine in the Arathi Highlands during Plunderstorm." },
  ["kobold geomancer (warcraft iii)"] = { 2, "', "Kobold Geomancers are kobold geomancer creeps that can be encountered in many tilesets." },
  ["kobold healer"] = { 2, "kobold", "Kobold Healer is a kobold." },
  ["kobold laborer"] = { 2, "', "Kobold Laborers were kobold mobs that could be found inside the Echo Ridge Mine at the northern end of Northshire Valley. They and their kin had infested the mine and the surrounding area, causing Marshal McBride to worry for the safety of Northsh..." },
  ["kobold looter"] = { 2, "', "Kobold Looters are kobolds that were located in the Stonetalon Mountains during beta testing." },
  ["kobold mastermind"] = { 2, "large purple Kobold found in The Oracle", "The Kobold Mastermind is a large purple Kobold found in The Oracle. When killed, it drops a Claws of Attack +12." },
  ["kobold miner"] = { 2, "', "Kobold Miners are kobold mobs that can be found in the Fargodeep Mine and the Jasperlode Mine in Elwynn Forest." },
  ["kobold mystic"] = { 2, "', "Kobold Mystics are kobolds located in the Waterworks and Kriegval's Rest." },
  ["kobold overseer"] = { 2, "powerful kobold", "Kobold Overseer is a powerful kobold that can be encountered in Mulgore during Founding of Durotar campaign." },
  ["kobold skullface"] = { 2, "', "Kobold Skullfaces are kobolds located in the Waterworks and Kriegval's Rest delves." },
  ["kobold slave"] = { 2, "kobold", "Kobold Slave is a kobold." },
  ["kobold spellcaster"] = { 2, "kobold", "Kobold Spellcaster is a kobold." },
  ["kobold tank"] = { 2, "kobold", "Kobold Tank is a kobold." },
  ["kobold taskfinder"] = { 2, "', "Kobold Taskfinders are swolbolds located in the Waterworks and Kriegval's Rest." },
  ["kobold taskmaster"] = { 2, "', "Kobold Taskmasters are kobold creeps that can be encountered in many tilesets." },
  ["kobold taskworker"] = { 2, "', "Kobold Taskworkers are kobolds located in Darkflame Cleft." },
  ["kobold thief"] = { 2, "kobold located in the Mourning Rise on the Isle of Dorn", "Kobold Thief is a kobold located in the Mourning Rise on the Isle of Dorn." },
  ["kobold thwacker"] = { 2, "', "Kobold Thwackers are kobolds located in the Waterworks and Kriegval's Rest delves." },
  ["kobold tunneler"] = { 2, "', "Kobold Tunnelers are kobold mobs that can be found in and around the Fargodeep Mine in Elwynn Forest." },
  ["kobold tunneler (warcraft iii)"] = { 2, "', "Kobold Tunnelers are kobold creeps that can be encountered in many tilesets." },
  ["kobold vermin"] = { 2, "', "Kobold Vermin were kobold mobs that could be found near the Echo Ridge Mine at the northern end of Northshire Valley. They and their kin had infested the mine and the surrounding area, causing Marshal McBride to worry for the safety of Northshire." },
  ["kobold worker"] = { 2, "', "Kobold Workers were kobold mobs that could be found near the Echo Ridge Mine at the northern end of Northshire Valley. They and their kin had infested the mine and the surrounding area, causing Marshal McBride to worry for the safety of Northshire." },
  ["kobold-at-arms"] = { 2, "', "Kobolds-at-Arms are kobolds located at Campalot in the Ringing Deeps." },
  ["kodethi"] = { 2, "dracthyr located in the War Creche in the Forbidden Reach", "Kodethi is a dracthyr located in the War Creche in the Forbidden Reach. He also attended the gathering in Amirdrassil when it bloomed on the Dragon Isles after Fyrakk's death." },
  ["kodun"] = { 2, "earthen located in Freywold Village in the Isle of Dorn", "Kodun is an earthen located in Freywold Village in the Isle of Dorn." },
  ["koflo"] = { 2, "dracthyr located in the Pitch in Algeth'ar Academy", "Koflo is a dracthyr located in the Pitch in Algeth'ar Academy." },
  ["kogu"] = { 2, "tortollan located at Scaletrader Post in Zuldazar", "Kogu is a tortollan located at Scaletrader Post in Zuldazar." },
  ["koiter (npc)"] = { 2, "kyrian spirit healer", "Koiter is a kyrian spirit healer that can be seen hovering at the Shrine of the Fallen Warrior, a memorial to Michel Koiter." },
  ["koja"] = { 2, "tortollan located in the Jeweled Coast in Stormsong Valley", "Koja is a tortollan located in the Jeweled Coast in Stormsong Valley. He is rummaging through an old shipwreck." },
  ["kokorek"] = { 2, "', "Kokorek could be found in a hut at Veil Lithic in Terokkar Forest during the beta." },
  ["kokoslah"] = { 2, "dracthyr stable master located in Emberwatch in the Ohn'a...", "Kokoslah is a dracthyr stable master located in Emberwatch in the Ohn'ahran Plains." },
  ["kol brunkrag"] = { 2, "earthen foreman", "Kol Brunkrag was an earthen foreman who led the town of Taelloch and its mine. Shortly preceding the arrival of Dalaran at Khaz Algar, Brunkrag's mind was warped during an encounter with High Speaker Eirich, an experience she described as being 'a..." },
  ["kolk"] = { 2, "undead centaur found in Desolace", "Kolk was an undead centaur found in Desolace. In life he was the first alleged offspring of Zaetar and Theradras, and also the first Khan of the Kolkar clan, which is named after him." },
  ["kolkar ambusher"] = { 2, "', "Kolkar Ambushers are centaur who spawn during the quest  [35] Bodyguard for Hire along with the Kolkar Waylayer in Desolace." },
  ["kolkar battle lord"] = { 2, "', "Kolkar Battle Lords are centaur found in Desolace." },
  ["kolkar bloodcharger"] = { 2, "', "Kolkar Bloodchargers are centaur located in the Northern Barrens." },
  ["kolkar centaur"] = { 2, "centaur of the Kolkar clan", "Kolkar Centaur is a centaur of the Kolkar clan that acts as a mount, transporting the adventurer from Karnum's Glade to the new Magram village in Desolace. He was recently freed from the Magram, where he was a Kolkar Prisoner." },
  ["kolkar destroyer"] = { 2, "', "Kolkar Destroyers are centaur located in Desolace." },
  ["kolkar drudge"] = { 2, "', "Kolkar Drudges are centaur found in Durotar." },
  ["kolkar invader"] = { 2, "', "Kolkar Invaders can be found in the Northern Barrens during the  [5-30G] Counterattack! event." },
  ["kolkar marauder"] = { 2, "', "Kolkar Marauders are centaur found in Northern Barrens. They are the trusted, disciplined warriors that keep others in line for their leaders." },
  ["kolkar mauler"] = { 2, "', "Kolkar Maulers are centaur found in Desolace." },
  ["kolkar observer"] = { 2, "centaur", "Kolkar Observer is a centaur." },
  ["kolkar outrunner"] = { 2, "', "Kolkar Outrunners are centaur found in Durotar." },
  ["kolkar pack runner"] = { 2, "', "Kolkar Pack Runners are centaurs found in the Northern Barrens. They have Kolkar Packhounds as pets." },
  ["kolkar prisoner"] = { 2, "', "Kolkar Prisoners are centaur of the Kolkar clan held captive in a pen south of Magram Territory in Desolace. They immediately run out of the pen to freedom and despawn after the Magram Warden is killed." },
  ["kolkar scout"] = { 2, "', "Kolkar Scouts are centaur found in Desolace." },
  ["kolkar stormer"] = { 2, "', "Kolkar Stormers are centaurs found in the Northern Barrens." },
  ["kolkar stormseer"] = { 2, "', "Kolkar Stormseers are centaur found in the Northern Barrens during the  [5-30G] Counterattack! event." },
  ["kolkar warmonger"] = { 2, "', "Kolkar Warmongers are centaur who spawn in Magram Territory in Desolace to help the player defend the Spear of the Kolkar Khan from Magram Defenders during  [10-30] Delicate Negotiations. They run out of the village and despawn once Khan Kammah ap..." },
  ["kolkar waylayer"] = { 2, "', "Kolkar Waylayers are centaur who spawn during the quest  [35] Bodyguard for Hire along with the Kolkar Ambushers in Desolace." },
  ["kolkar windchaser"] = { 2, "', "Kolkar Windchasers are centaur found in Desolace." },
  ["kolkar wrangler"] = { 2, "', "Kolkar Wrangler are centaur found in Northern Barrens." },
  ["kolta"] = { 2, "tortollan located at Kennings Lodge in Tiragarde Sound", "Kolta is a tortollan located at Kennings Lodge in Tiragarde Sound." },
  ["koltira deathweaver"] = { 2, "Darkfallen death knight of the New Horde", "Koltira Deathweaver is a Darkfallen death knight of the New Horde, serving as the Horde counterpart to Thassarian. In life, Koltira was a valiant defender of Quel'Thalas, and took to the field during the brutal Scourge invasion." },
  ["kono"] = { 2, "tortollan located in Zuldazar", "Kono is a tortollan located in Zuldazar. At first he is found in a Nazeshi Cage in the Dreadpearl Shallows." },
  ["konraada"] = { 2, "earthen located with Matthilde", "Konraada is an earthen located with Matthilde and Reingard at the Stoneshaper's Atrium in Dornogal." },
  ["kor bloodtusk"] = { 2, "only non-tauren in the group", "Kor Bloodtusk was part of the Dawnchaser expedition, led by Sunwalker Dezco, sent to Pandaria to follow 'dreams of a valley, golden with blossoms, filled with the hope of peace'. He appears to have been sent as a representative of Garrosh Hellscre..." },
  ["kor dawnchaser"] = { 2, "', "Kor Dawnchaser is one of the twin sons of Sunwalker Dezco and Leza Dawnchaser. He and his brother, Cloudhoof, were born in the Krasarang Wilds, and their mother died in childbirth." },
  ["kor'ak bloodspike"] = { 2, "presumably orcish witness to the Cataclysm in the Souther...", "Kor'ak Bloodspike was a presumably orcish witness to the Cataclysm in the Southern Barrens that was swallowed by the earth during the chaos." },
  ["kor'dok and tinzo the emberkeeper"] = { 2, "', "Kor'dok and Tinzo the Emberkeeper are mogu located on the Isle of Thunder." },
  ["kor'gall"] = { 2, "ruthless", "Kor'gall was a ruthless and tyrannical ogre warlord and chieftain of the Stonemaul clan living in Dustwallow Marsh after the Battle for Mount Hyjal." },
  ["kor'gall (alternate universe)"] = { 2, "cruel chieftain of the Stonemaul clan", "Kor'gall is the cruel chieftain of the Stonemaul clan. He rules the clan from the Throne of Stonemaul in Kor'gall's Hovel in Gorgrond." },
  ["kor'gall agitator"] = { 2, "', "Kor'gall Agitators are ogres located in Stonemaul in Gorgrond." },
  ["kor'gall defector"] = { 2, "', "Kor'gall Defectors are ogres located in Stonemaul in Gorgrond." },
  ["kor'gall, greatson of kor'gall"] = { 2, "ogre descendant of Kor'gall", "Kor'gall, Greatson of Kor'gall is an ogre descendant of Kor'gall. During the war between the Lightbound and the Mag'har, Kor'gall was allied with the Mag'har orc clans, however over the course of the war he became convinced that the Mag'har were d..." },
  ["kor'ik"] = { 2, "Klaxxi quest giver", "Kor'ik is a Klaxxi quest giver, helping the player awaken the Paragons. During  [30-35] Corruption Runs Deep, he is exposed by Hisek the Swarmkeeper as a double agent working for Grand Empress Shek'zeer, and subsequently killed by Hisek and the pl..." },
  ["kor'lok (traveler)"] = { 2, "young hunchbacked ogre guard of the Gordunni clan in Dire...", "Kor'lok was a young hunchbacked ogre guard of the Gordunni clan in Dire Maul. He had one central eye and was often told that he is destined for greatness like the ogre lords." },
  ["kor'nas nightsavage"] = { 2, "rare mogu found pacing through Nectarbreeze Orchard in th...", "Kor'nas Nightsavage is a rare mogu found pacing through Nectarbreeze Orchard in the Jade Forest. Kor'nas Nightsavage is a pandarian champion." },
  ["kor'thik battlesinger"] = { 2, "', "Kor'thik Battlesingers are mantid located at Kor'vess in the Dread Wastes." },
  ["kor'thik bloodletter"] = { 2, "', "Kor'thik Bloodletters are mantid located in Dread Wastes. They appear in waves during  [25-35] The Taking of Dusklight Bridge." },
