  ["korjan reaver"] = { 2, "', "Korjan Reavers are mogu found at the Ruins of Korja in the Krasarang Wilds. Some are attacking Dawnchaser Retreat, fighting against Dawnchaser Hunters, and Sentinel Basecamp, fighting against Wounded Sentinels." },
  ["korjan reclaimer"] = { 2, "', "The Korjan Reclaimers are mogu of the Korjan clan found at the Ruins of Korja and Field of Korja in Krasarang Wilds. They are unearthing artifacts and using portals connected to Kun-Lai Summit to bring in supplies and reinforcements, and send thei..." },
  ["korjan slavemaster"] = { 2, "', "Korjan Slavemasters are mogu of the Korjan clan found at the Ruins of Korja and the Field of Korja in the Krasarang Wilds. They are torturing the Dawnchaser Captives and Captive Sentinels." },
