  ["korky"] = { 2, "vulpera located at the Artisan's Market in Valdrakken", "Korky is a vulpera located at the Artisan's Market in Valdrakken." },
  ["korm bonegrind"] = { 2, "notably large orc", "Korm Bonegrind is a notably large orc that appears on a Horde gunship in the worgen starting zone quest   [1-20] Endgame. He would appear to be a mechanic based on his title." },
  ["kormyr sylfverhan"] = { 2, "vrykul", "Kormyr Sylfverhan is a vrykul who recorded two chapters in The Legend of Odyn." },
