  ["kornd"] = { 2, "earthen located in the Forgegrounds in Dornogal", "Kornd is an earthen located in the Forgegrounds in Dornogal." },
  ["koros"] = { 2, "Ascended kyrian located at the Eternal Watch section of t...", "Koros is an Ascended kyrian located at the Eternal Watch section of the Elysian Hold in Bastion. He functions as the Ascended's eyes on the field, informing them of matters in the Shadowlands that need their attention." },
  ["korrag"] = { 2, "stasis-locked earthen located on Thunderhead Peak in the ...", "Korrag is a stasis-locked earthen located on Thunderhead Peak in the Isle of Dorn. On the pedestal he is standing there is a plaque that reads: 'Here stands Korrag, Watcher of the North, a Stormrider." },
