  ["korvash"] = { 2, "skeletal Drust located in Drustvar", "Korvash is a skeletal Drust located in Drustvar. He uses a fairly unique model for such a mob." },
  ["korvelnor"] = { 2, "dracthyr located in the Azure Span", "Korvelnor is a dracthyr located in the Azure Span." },
  ["korven the prime"] = { 2, "mantid located at Klaxxi'vess", "Korven the Prime is a mantid located at Klaxxi'vess. He is the first Paragon of the Klaxxi and the one who mastered the art of using amber to preserve the Mantid's greatest warriors." },
  ["korvexxis"] = { 2, "mantid located in Sik'vess in Townlong Steppes", "Korvexxis is a mantid located in Sik'vess in Townlong Steppes. He gets ambushed by Taoshi to retrieve a crystal to open a door." },
  ["korvik"] = { 2, "tuskarr located in Iskaara in the Azure Span", "Korvik is a tuskarr located in Iskaara in the Azure Span. He informs on the arrival of Old Belfyr." },
  ["kosco copperpinch"] = { 2, "goblin food", "Kosco Copperpinch is a goblin food and drink vendor located in Hammerfall in the Arathi Highlands." },
  ["koskeszaera"] = { 2, "dracthyr", "Koskeszaera is a dracthyr. She would have acted as a vendor for trading Dreaming Crests." },
  ["kosta dawnchaser"] = { 2, "tauren general goods vendor at Thunder Cleft in Krasarang...", "Kosta Dawnchaser is a tauren general goods vendor at Thunder Cleft in Krasarang Wilds. He is a member of the Dawnchaser tribe, which traveled to Pandaria in search of a dreamed paradise." },
