  ["kothani"] = { 2, "centaur vendor located in Ohn'iri Springs in the Ohn'ahra...", "Kothani is a centaur vendor located in Ohn'iri Springs in the Ohn'ahran Plains." },
  ["kotheshal"] = { 2, "dracthyr located in Stormwind City", "Kotheshal is a dracthyr located in Stormwind City. She and Krozhalan can be found enjoying ice cream near the entrance to the Stormwind Stockade where they overlook Lion's Rest." },
  ["kothilde"] = { 2, "leader of the Stormrangers", "Kothilde is the leader of the Stormrangers. She spent many centuries as a Stonebound miner and was first encountered in Freywold Village." },
  ["kottr vondyr"] = { 2, "vrykul located at Inkbinders Rise in Stormheim", "Kottr Vondyr is a vrykul located at Inkbinders Rise in Stormheim." },
  ["kova broadhorn"] = { 2, "tauren shaman", "Kova Broadhorn is a tauren shaman and novice alchemist. It seems that she once anticipated in a battle at Red Rocks." },
  ["kovork"] = { 2, "rare ogre found inside the cave at Boulder'gor in the Bou...", "Kovork is a rare ogre found inside the cave at Boulder'gor in the Boulderfist Outpost in the Arathi Highlands. He is on a 5-8 hour respawn timer and drops the mace he is armed with." },
  ["kozastran"] = { 2, "dracthyr located in the Valley of Honor in Orgrimmar", "Kozastran is a dracthyr located in the Valley of Honor in Orgrimmar. She is reading a map." },
