  ["kranac sagesnow"] = { 2, "furbolg located in Winterpelt Hollow in the Azure Span", "Kranac Sagesnow is a furbolg located in Winterpelt Hollow in the Azure Span. He also attended the gathering in Amirdrassil when it bloomed on the Dragon Isles after Fyrakk's death." },
  ["krank axeljink"] = { 2, "gnome from Tinker Town", "Krank Axeljink was a gnome from Tinker Town, chosen to be a gnomish representative to the New Council of Tirisfal. He invented a device that would draw power from the other council members into their chosen representative (which would, of course, ..." },
  ["krasari runekeeper"] = { 2, "', "Krasari Runekeepers are mogu located in Krasari Ruins in Krasarang Wilds." },
  ["krasari tormentor"] = { 2, "', "Krasari Tormentors are mogu located at Krasarang Wilds." },
  ["krastinovian carver"] = { 2, "', "Krastinovian Carvers are humans and undead, appearing after the Chamber of Summoning in Scholomance. Killing a carver within 10 yards of another carver cause their bloodthirst to spread to that carver, increasing its stack." },
  ["krattdaz"] = { 2, "stasis-locked earthen located in Shimmermist Falls in the...", "Krattdaz is a stasis-locked earthen located in Shimmermist Falls in the Ringing Deeps. Next to him is his plague." },
