  ["krax'ik"] = { 2, "rare mantid found in stealth at the top of a cliff in the...", "Krax'ik is a rare mantid found in stealth at the top of a cliff in the Thunderwood in Jade Forest. Krax'ik is a pandarian champion." },
  ["krazzel crashfuse"] = { 2, "diabolical level 62 goblin featured in the 100 or Bust! t...", "Krazzel Crashfuse is a diabolical level 62 goblin featured in the 100 or Bust! trailer." },
  ["kreenig snarlsnout"] = { 2, "Razormane quilboar found east of Thorn Hill in the Northe...", "Kreenig Snarlsnout is a Razormane quilboar found east of Thorn Hill in the Northern Barrens. Kreenig is the leader of a band of quilboar who raid Horde caravans leaving and entering Durotar." },
  ["kreg bilmn"] = { 2, "dwarf general goods vendor located in Thunderbrew Distill...", "Kreg Bilmn is a dwarf general goods vendor located in Thunderbrew Distillery in Kharanos in Dun Morogh. This section concerns content related to Legion." },
  ["krendle bigpockets"] = { 2, "goblin zeppelin master located in the Spirit Rise in Thun...", "Krendle Bigpockets is a goblin zeppelin master located in the Spirit Rise in Thunder Bluff. He gives information about The Zephyr." },
  ["krenk choplimb"] = { 2, "goblin first aid trainer located at Orgrimmar Rocketway E...", "Krenk Choplimb is a goblin first aid trainer located at Orgrimmar Rocketway Exchange in Azshara. He used to reside in Goblin Slums of Orgrimmar where he was handling a small infirmary with Brother Silverhallow." },
  ["krenka"] = { 2, "founder of the Krenka clan", "Krenka was the founder of the Krenka clan. According to ancient tales, when Krenka grew old he wandered out into the Barrens to die, but promised to return to aid his people if the need was great." },
  ["krennan aranas"] = { 2, "Royal Chemist of Gilneas", "Krennan Aranas is the Royal Chemist of Gilneas. Genn notes him as one of the most powerful chemists in Azeroth, or at least Gilneas." },
  ["krenzen"] = { 2, "dracthyr located in the Mage Quarter in Stormwind City", "Krenzen is a dracthyr located in the Mage Quarter in Stormwind City. He is found with Blue and Berkeley." },
