  ["kristen dipswitch"] = { 2, "gnome quest giver located at the Nesingwary Safari in Nag...", "Kristen Dipswitch is a gnome quest giver located at the Nesingwary Safari in Nagrand. She is only available at certain times, when she is not off hunting for skins." },
  ["krog the dominator"] = { 2, "ancient ogre located on Draenor", "Krog the Dominator is an ancient ogre located on Draenor. His hammer is located at the Broken Precipice." },
