  ["krohm dawnhammer"] = { 2, "dwarf paladin", "Krohm Dawnhammer was a dwarf paladin who helped the citizens of Lordaeron during the Scourging of Lordaeron. He forged his own armor, which was bolstered by the Light." },
  ["krokul crusher"] = { 2, "', "Krokul Crushers are krokul located at Krokul Hovel on Krokuun." },
  ["krokul guardian"] = { 2, "', "Krokul Guardians are krokul located at Krokul Hovel on Krokuun. After their alliance with the Army of the Light, some of them can also be found on the Vindicaar." },
  ["krokul peacekeeper"] = { 2, "', "Krokul Peacekeepers are Broken located in Antoran Wastes and Krokuun." },
  ["krokul ridgestalker"] = { 2, "', "Krokul Ridgestalker are stealthed Broken guards located in Krokul Hovel in Krokuun. They can also be summoned during  [45] Threat Reduction." },
  ["krokul ridgestalker (exodar)"] = { 2, "', "Krokul Ridgestalkers are Broken located in the Trader's Tier in the Exodar during the draenei heritage questline." },
  ["krokul scout"] = { 2, "', "Krokul Scouts are dead Broken located in the Grove of Naroua in Krokuun." },
  ["krokul seer"] = { 2, "', "Krokul Seers are krokul located at Krokul Hovel on Krokuun." },
  ["krokul warrior"] = { 2, "', "Krokul Warriors are Broken located at the Krokul Hovel and the Petrified Forest in Krokuun." },
  ["krokul wrangler"] = { 2, "', "Krokul Wranglers are Broken located in Krokuun. They keep watch and patrol the upper grounds of the Petrified Forest." },
  ["krol"] = { 2, "leader of the ogres initially approached by the Blackrock...", "Krol was the leader of the ogres initially approached by the Blackrock clan who were seeking to form an alliance during the forming of the Old Horde. The Blackrocks captured three members of Krol's clan and convinced them to hold council with thei..." },
  ["krol the blade"] = { 2, "rare mogu found in the Dread Wastes", "Krol the Blade is a rare mogu found in the Dread Wastes. He is a Pandarian champion." },
  ["krolg"] = { 2, "furbolg quest giver located at Krolg's Hut south of Mystr...", "Krolg is a furbolg quest giver located at Krolg's Hut south of Mystral Lake in Ashenvale. Krolg is an uncorrupted furbolg and was once part of the Foulweald tribe." },
  ["kronah"] = { 2, "tortollan located in Anyport in Drustvar", "Kronah is a tortollan located in Anyport in Drustvar." },
  ["kronk (traveler)"] = { 2, "ogre of the Gordunni clan", "Kronk was an ogre of the Gordunni clan and a part of Wordok's group. He was killed by Makasa Flintwill in Feralas." },
  ["kronzon"] = { 2, "earthen located in Stonelight Rest in Dornogal", "Kronzon is an earthen located in Stonelight Rest in Dornogal." },
  ["krowl darkmane"] = { 2, "worgen located in the Siege of Boralus", "Krowl Darkmane is a worgen located in the Siege of Boralus." },
  ["krozhalan"] = { 2, "dracthyr located in Stormwind City", "Krozhalan is a dracthyr located in Stormwind City. He and Kotheshal can be found enjoying ice cream near the entrance to the Stormwind Stockade where they overlook Lion's Rest." },
  ["krozuthar"] = { 2, "dracthyr sitting in front of Borstan's Firepit in the Dra...", "Krozuthar is a dracthyr sitting in front of Borstan's Firepit in the Drag in Orgrimmar." },
  ["krrat"] = { 2, "stasis-locked earthen located atop the tallest peak south...", "Krrat is a stasis-locked earthen located atop the tallest peak south of Freywold Village on the Isle of Dorn. On the pedestal she is standing there is a plaque that reads: 'Here stands Krrat, Watcher of the South, a Stormrider." },
  ["krrrn trr cryomancer"] = { 2, "', "Krrrn Trr Cryomancers are murlocs from Azmerloth located in Tyrhold Reservoir in Thaldraszus during Time Rifts." },
  ["krrrn trr pyromancer"] = { 2, "', "Krrrn Trr Pyromancers are murlocs from Azmerloth located in Tyrhold Reservoir in Thaldraszus during Time Rifts." },
  ["krud the eviscerator"] = { 2, "rare ogre located at the Ring of Blood in Nagrand", "Krud the Eviscerator is a rare ogre located at the Ring of Blood in Nagrand. If his tribute challenge is not completed in a certain amount of time, he will despawn." },
  ["kruggok"] = { 2, "ogre food", "Kruggok is an ogre food and drink vendor located at the Ring of Blood in Nagrand." },
  ["krullaran the prophet"] = { 2, "only permanent centaur resident in Maraudon", "Krullaran the Prophet is the only permanent centaur resident in Maraudon. The centaur of Desolace turn to the khans for protection, but they looked to him for guidance." },
  ["krulmoo fullmoon"] = { 2, "tauren leatherworking trainer in Camp Taurajo", "Krulmoo Fullmoon was a tauren leatherworking trainer in Camp Taurajo who was killed when the Alliance attacked. Winnoa Pineforest sent adventurers to summon his spirit and put it to rest for  [10-30] Honoring the Dead." },
  ["kruugall"] = { 2, "Broken", "Kruugall is a Broken." },
  ["kruwa"] = { 2, "tortollan located at the Sliver in Dazar'alor", "Kruwa is a tortollan located at the Sliver in Dazar'alor who sells fish as food. He also appears in the Krasarang Wilds." },
  ["ku'ma"] = { 2, "undead troll within a cave on the Isle of Giants", "Ku'ma is an undead troll within a cave on the Isle of Giants. It is unknown why he is undead, why he is insane, or what his motivations are, but one thing is known for sure: He loves Giant Dinosaur Bones and will exchange bones for rewards, includ..." },
  ["ku'shif the cruel"] = { 2, "mogu located in Zuldazar", "Ku'shif the Cruel is a mogu located in Zuldazar." },
  ["kua"] = { 2, "tuskarr located in Thaldraszus", "Kua is a tuskarr located in Thaldraszus." },
  ["kua'ki"] = { 2, "tuskarr located in Thaldraszus", "Kua'ki is a tuskarr located in Thaldraszus." },
  ["kuai the brute"] = { 2, "leader of the Gurthan clan", "Kuai the Brute is the leader of the Gurthan clan. He and his clan have gathered at the Mogu'shan Palace, alongside clans Harthak and Kargesh to prove their worth to their king." },
  ["kubb"] = { 2, "rare kobold located south of Algaz Station", "Kubb is a rare kobold located south of Algaz Station, by the cave where 'Commander' Nazrim dwells. He is part of the Tunnel Rats." },
  ["kubrul"] = { 2, "drogbar located in the Deep Roads in Highmountain", "Kubrul is a drogbar located in the Deep Roads in Highmountain." },
  ["kugro"] = { 2, "tortollan mentioned by Scrollsage Nola to be able to deci...", "Kugro is a tortollan mentioned by Scrollsage Nola to be able to decipher an unknown language in a scroll." },
  ["kuk'uq"] = { 2, "tuskarr spearcrafter dwelling in Moa'ki Harbor in the Dra...", "Kuk'uq is a tuskarr spearcrafter dwelling in Moa'ki Harbor in the Dragonblight." },
  ["kul'galar oracle"] = { 2, "', "Kul'galar Oracles are vrykul located in Kul'galar Keep in Icecrown. This section concerns content related to Shadowlands." },
  ["kullan"] = { 2, "venthyr located in the Purloined Stores in Castle Nathria", "Kullan is a venthyr located in the Purloined Stores in Castle Nathria." },
  ["kunap"] = { 2, "tuskarr child located in the Azure Span", "Kunap is a tuskarr child located in the Azure Span. She and Kikiua are standing next to a Snowball." },
  ["kunga"] = { 2, "tortollan located at the Mugambala in Zuldazar", "Kunga is a tortollan located at the Mugambala in Zuldazar." },
  ["kuo (tuskarr)"] = { 2, "tuskarr child found sleeping with Omaa in Kauriq Gleamlet...", "Kuo is a tuskarr child found sleeping with Omaa in Kauriq Gleamlet in the Azure Span." },
  ["kura the blind"] = { 2, "vengeful arakkoa of the Arakkoa Outcasts", "Kura the Blind is a vengeful arakkoa of the Arakkoa Outcasts that can be found at Terokkar Refuge in Talador, and later the Spires of Arak." },
  ["kuraam"] = { 2, "eredar vendor located at the Circle of Aspirants in Eredath", "Kuraam is an eredar vendor located at the Circle of Aspirants in Eredath, where he sells Jed'hin tournament gear. There are two copies of him, one standing next to Crafter Y'selfa at the southern edge of the main circle, and another a few yards to..." },
  ["kurak"] = { 2, "centaur located at the Stagnant Oasis in the Northern Bar...", "Kurak is a centaur located at the Stagnant Oasis in the Northern Barrens. He is the strongest warrior of the Kolkar centaur in the area." },
  ["kurazidaia"] = { 2, "dracthyr", "Kurazidaia is a dracthyr and envoy of the Healing Wings. She is located at the Seat of the Aspects in Valdrakken and begins the patch 10.0.7 portion of the Dragonflight campaign, sending players to the Forbidden Reach." },
  ["kurden bloodclaw"] = { 2, "orc Warsong Gulch battlemaster located in the Royal Quart...", "Kurden Bloodclaw was an orc Warsong Gulch battlemaster located in the Royal Quarter in the Undercity during the Call to Arms: Warsong Gulch." },
  ["kurdrum barleybeard"] = { 2, "dwarf vendor found in Alterac Valley", "Kurdrum Barleybeard is a dwarf vendor found in Alterac Valley." },
  ["kurenai captive"] = { 2, "Broken quest giver located at Sunspring Post in Nagrand", "Kurenai Captive is a Broken quest giver located at Sunspring Post in Nagrand." },
  ["kurenai pitfighter"] = { 2, "Broken located in Telaar in Nagrand", "Kurenai Pitfighter is a Broken located in Telaar in Nagrand. He is training on a training dummy, while a group of Telaari Citizens and Telaari Watchers is cheering him on." },
  ["kuriah"] = { 2, "earthen located in Shadowvein Point in the Ringing Deeps ...", "Kuriah is an earthen located in Shadowvein Point in the Ringing Deeps where she can be found hiding in the rubble inside a mine cart." },
  ["kuro'ak"] = { 2, "arakkoa innkeeper located at the Veil Terokk‎ in Spires o...", "Kuro'ak is an arakkoa innkeeper located at the Veil Terokk‎ in Spires of Arak." },
  ["kurron"] = { 2, "earthen located in Freywold Village on the Isle of Dorn", "Kurron is an earthen located in Freywold Village on the Isle of Dorn." },
  ["kurtu"] = { 2, "tortollan repair vendor located at the Tortaka Refuge in ...", "Kurtu is a tortollan repair vendor located at the Tortaka Refuge in Vol'dun." },
  ["kurz the revelator"] = { 2, "furbolg located at Stillpine Hold in Azuremyst Isle", "Kurz the Revelator is a furbolg located at Stillpine Hold in Azuremyst Isle." },
  ["kusa"] = { 2, "vulpera pet tamer located on the western outskirts of the...", "Kusa is a vulpera pet tamer located on the western outskirts of the Court of Zak'rajan in Vol'dun. Her pets are Beets, Rawly, and Stinger." },
  ["kuvkel"] = { 2, "earthen located in Kriegval's Rest", "Kuvkel is an earthen located in Kriegval's Rest. Brann Bronzebeard and adventurers helped him get artifacts back from attacking kobolds." },
  ["kuz"] = { 2, "quilboar with the Razormane tribe found in Blackthorn Rid...", "Kuz is a quilboar with the Razormane tribe found in Blackthorn Ridge in the Barrens. She was killed years ago, and her skull given to Mangletooth." },
  ["kvin obren"] = { 2, "vrykul located in Stormheim", "Kvin Obren is a vrykul located in Stormheim." },
  ["kwahu fiendtamer"] = { 2, "tauren follower located at Frostwall in Frostfire Ridge", "Kwahu Fiendtamer is a tauren follower located at Frostwall in Frostfire Ridge. She can only be recruited using the Headhunter's Harvest from Frostwall Tavern." },
  ["kwint"] = { 2, "undead located at the bottom of the sea in Tiragarde Sound", "Kwint is an undead located at the bottom of the sea in Tiragarde Sound. He was once owned a boat with a crew of three hundred and twenty three." },
  ["kwit"] = { 2, "kobold located near a Snuffle Pup in Gundargaz in the Rin...", "Kwit is a kobold located near a Snuffle Pup in Gundargaz in the Ringing Deeps." },
  ["kybel"] = { 2, "dracthyr evoker", "Kybel is a dracthyr evoker." },
  ["kykrolian"] = { 2, "dracthyr located at Algeth'ar Academy in Thaldraszus", "Kykrolian is a dracthyr located at Algeth'ar Academy in Thaldraszus. He can be seen Studying." },
  ["kyl heartline"] = { 2, "vrykul located in Stormheim", "Kyl Heartline is a vrykul located in Stormheim." },
  ["kynthia"] = { 2, "Ascended kyrian from the Temple of Courage", "Kynthia is an Ascended kyrian from the Temple of Courage who was taken captive by the House of Constructs and brought to their stronghold in Maldraxxus. She and her surviving friends were later freed by Maw Walkers and chose to stay in Maldraxxus ..." },
  ["kyren"] = { 2, "', "Kyren was one of the NPCs that could spawn by using an  [Amani Hex Stick] on one of the wandering Forest Frogs within the old version of Zul'Aman. Once spawned, she would sell various reagents." },
  ["kyrestia the firstborne"] = { 2, "first of the winged kyrians", "Kyrestia the Firstborne, the Archon, is the first of the winged kyrians, the most stalwart and dedicated of the Eternal Ones, and the ruler of Bastion and the Kyrian Covenant. She resides at Archon's Rise in Elysian Hold." },
  ["kyrian ascendant"] = { 2, "', "Kyrian Ascendants are kyrian located in Bastion." },
  ["kyrian ascended"] = { 2, "', "Kyrian Ascended are kyrian located in Bastion." },
  ["kyrian aspirant"] = { 2, "', "Kyrian Aspirants are kyrian located in the Vestibule of Eternity, Aspirant's Crucible, and Elysian Hold in Bastion. They also appear in the Ring of Fates in Oribos during  [60] Prisoner of Interest." },
  ["kyrian corpse"] = { 2, "deceased kyrian located at Separation Chamber in Maldraxxus", "The Kyrian Corpse is a deceased kyrian located at Separation Chamber in Maldraxxus." },
  ["kyrian courier"] = { 2, "kyrian located in Bastion", "Kyrian Courier is a kyrian located in Bastion." },
  ["kyrian defender"] = { 2, "', "Kyrian Defenders are Ascended kyrian fighting Ardent Legionnaires above Elysian Hold during  [60] The Greater Good." },
  ["kyrian halberdier"] = { 2, "', "Kyrian Halberdiers are kyrian who helps with adventures." },
  ["kyrian mender"] = { 2, "Ascended kyrian located at Haetio's Solace in Bastion", "The Kyrian Mender is an Ascended kyrian located at Haetio's Solace in Bastion. She can be found healing a Kyrian Scholar." },
  ["kyrian phalanx"] = { 2, "', "Kyrian Phalanxes are kyrian who helps with adventures." },
  ["kyrian scholar"] = { 2, "', "Kyrian Scholars are kyrian located at Haetio's Solace in Bastion." },
  ["kyros warstone"] = { 2, "Arathi lamplighter", "Kyros Warstone is an Arathi lamplighter who patrols Light's Blooming in Hallowfall alongside Nisa Cindersteel, Azra Ironstrike, and an Expedition Stalwart. This section concerns content related to Midnight." },
  ["kythekios"] = { 2, "kyrian located in Torghast", "Kythekios is a kyrian located in Torghast, Tower of the Damned." },
  ["kz'kzik"] = { 2, "mantid located at the Horrid March in the Dread Wastes", "Kz'Kzik is a mantid located at the Horrid March in the Dread Wastes." },
  ["la'range"] = { 2, "nerubian located in the City of Threads", "La'range is a nerubian located in the City of Threads." },
  ["lady aga'thar"] = { 2, "naga", "Lady Aga'thar is a naga." },
  ["lady alistra"] = { 2, "Darkfallen death knight located in Acherus: The Ebon Hold", "Lady Alistra is a Darkfallen death knight located in Acherus: The Ebon Hold." },
  ["lady andrada"] = { 2, "venthyr located in the Redelav Hall in Revendreth", "Lady Andrada is a venthyr located in the Redelav Hall in Revendreth." },
  ["lady assana"] = { 2, "naga", "Lady Assana is a naga who can be encountered during Island Expeditions." },
  ["lady audat"] = { 2, "venthyr found in Torghast", "Lady Audat is a venthyr found in Torghast, Tower of the Damned. She was originally only found in the Upper Reaches wing." },
  ["lady daniela"] = { 2, "venthyr located at the Briarbane Stables in Revendreth", "Lady Daniela is a venthyr located at the Briarbane Stables in Revendreth. She can be found talking with Lord Silviu." },
  ["lady darkscale"] = { 2, "naga sea witch", "Lady Darkscale was a naga sea witch that attacked the naval base of Kul Tiras located in Coastal Base. She was guarded by Scilla Murkshadow." },
  ["lady delth"] = { 2, "member of the Kirin Tor", "Lady Delth was a member of the Kirin Tor who studied elven history. When Khadgar was sent to Medivh, she requested that he find out all he could about elven history from Medivh's library." },
  ["lady hatecoil"] = { 2, "naga boss located at the Whispering Willows in Eye of Azs...", "Lady Hatecoil is a naga boss located at the Whispering Willows in Eye of Azshara." },
  ["lady ihrin"] = { 2, "venthyr located in Redelav District in Revendreth", "Lady Ihrin is a venthyr located in Redelav District in Revendreth. She can be seen speaking with Duchess Ioana." },
  ["lady ilinca"] = { 2, "venthyr located in Sinfall in Revendreth", "Lady Ilinca is a venthyr located in Sinfall in Revendreth." },
  ["lady inerva darkvein"] = { 2, "venthyr boss located in the Purloined Stores in Castle Na...", "Lady Inerva Darkvein is a venthyr boss located in the Purloined Stores in Castle Nathria. She is the last boss of the castle's north wing." },
  ["lady ivona"] = { 2, "venthyr located in the Sourwine Estate", "Lady Ivona is a venthyr located in the Sourwine Estate and Eternal Terrace in Revendreth." },
  ["lady janira"] = { 2, "naga found in the Ruins of Lornesta in Darkshore", "Lady Janira is a naga found in the Ruins of Lornesta in Darkshore. She leads a large group of Darkscale Scouts and seems to be searching for something within the ruins." },
  ["lady kameria"] = { 2, "venthyr located in Redelav Tower in Revendreth", "Lady Kameria is a venthyr located in Redelav Tower in Revendreth." },
  ["lady la-la"] = { 2, "rare naga sea witch", "Lady La-La is a rare naga sea witch that spawns in southern Kelp'thar Forest, around the Clutch." },
  ["lady lerae"] = { 2, "venthyr located in the Duskmire Domain in Revendreth", "Lady Lerae is a venthyr located in the Duskmire Domain in Revendreth." },
  ["lady mara fordragon"] = { 2, "High Clerist of the Kingdom of Stormwind during the First...", "Lady Mara Fordragon was the High Clerist of the Kingdom of Stormwind during the First War. She became a patron of the Stormwindian refugees who fled to Lordaeron after the war." },
  ["lady missra"] = { 2, "naga", "Lady Missra is a naga that engaged in combat with Shandris Feathermoon but was taken out by the champions of the Unseen Path." },
  ["lady naz'jar"] = { 2, "powerful naga sea witch leading the naga invasion of Vash...", "Lady Naz'jar is a powerful naga sea witch leading the naga invasion of Vashj'ir and the Abyssal Maw." },
  ["lady naz'jar (tactics)"] = { 2, "first boss of the Throne of the Tides", "Lady Naz'jar is the first boss of the Throne of the Tides. She can be found in the depths of Throne of the Tides, and needs to be killed to unlock other bosses." },
  ["lady naz'jess"] = { 2, "naga located at the Zanj'ir Terrace in Nazjatar", "Lady Naz'jess is a naga located at the Zanj'ir Terrace in Nazjatar." },
  ["lady oana"] = { 2, "venthyr located outside the Primrose Residence in the Red...", "Lady Oana is a venthyr located outside the Primrose Residence in the Redelav District in Revendreth. She can be found absolving an Abject Soul of its past sins, occasionally spawning various memories." },
  ["lady rash'iss"] = { 2, "naga summoning the Pride of Azshara at the Eventide Delta...", "Lady Rash'iss is a naga summoning the Pride of Azshara at the Eventide Delta in Stormsong Valley." },
  ["lady rodica"] = { 2, "venthyr located in the Sinfang Parlor in Revendreth", "Lady Rodica is a venthyr located in the Sinfang Parlor in Revendreth." },
  ["lady rovinette"] = { 2, "venthyr located in the Spire of the Unseen Guests in Reve...", "Lady Rovinette is a venthyr located in the Spire of the Unseen Guests in Revendreth." },
  ["lady s'theno"] = { 2, "naga", "Lady S'theno (pronounced sa-the-no) is a naga and leader of the Coilskar tribe, the last remnants of Illidan's Naga." },
  ["lady sarevess"] = { 2, "naga found in the Pool of Ask'ar of Blackfathom Deeps", "Lady Sarevess is a naga found in the Pool of Ask'ar of Blackfathom Deeps. Sarevess is a very twisted spellcaster who dabbles in the realm of magic." },
  ["lady sarevess (season of discovery)"] = { 2, "boss in the Season of Discovery Blackfathom Deeps raid", "Lady Sarevess is a boss in the Season of Discovery Blackfathom Deeps raid." },
  ["lady sedorax"] = { 2, "', "Lady Sedorax can be found in the cave behind Cliffspring Falls in Darkshore." },
  ["lady serpentra"] = { 2, "naga sea witch in the service of Illidan Stormrage", "Lady Serpentra was a naga sea witch in the service of Illidan Stormrage." },
  ["lady sesspira"] = { 2, "rare naga found in a shrine at the Shattered Strand in Az...", "Lady Sesspira is a rare naga found in a shrine at the Shattered Strand in Azshara." },
  ["lady shav'rar"] = { 2, "naga found at Coilskar Point in Shadowmoon Valley", "Lady Shav'rar is a naga found at Coilskar Point in Shadowmoon Valley." },
  ["lady shaz'ra"] = { 2, "rare elite naga located in a sea-level cave between the O...", "Lady Shaz'ra is a rare elite naga located in a sea-level cave between the Old Weyrn Grounds and the Talonlords' Perch in central Forbidden Reach." },
  ["lady silisthra"] = { 2, "', "Lady Silisthra is one of the two naga witches masterminding the assault on the Southern Rocketway Terminus. She is located near Silisthra's Power Stone at the Ravencrest Monument in Azshara." },
  ["lady sinrender"] = { 2, "venthyr located in Pridefall Hamlet in Revendreth once th...", "Lady Sinrender is a venthyr located in Pridefall Hamlet in Revendreth once the anima stream from Sinfall's Anima Conductor is channeled into the area." },
  ["lady sinsear"] = { 2, "venthyr located in Castle Nathria", "Lady Sinsear is a venthyr located in Castle Nathria." },
  ["lady sira'kess"] = { 2, "', "Lady Sira'kess is one of the key leaders of the naga in the underwater zone of Vashj'ir. She is seen in the various Battlemaiden visions, courtesy of Earthen Ring member Wavespeaker Valoren." },
  ["lady ssathara"] = { 2, "naga located at the Felrage Strand on the Broken Shore", "Lady Ssathara is a naga located at the Felrage Strand on the Broken Shore." },
  ["lady sssurine"] = { 2, "naga located in Azsuna", "Lady Sssurine is a naga located in Azsuna." },
  ["lady stefania"] = { 2, "venthyr", "Lady Stefania is a venthyr." },
  ["lady viorica"] = { 2, "venthyr located in the Redelav Hall in Revendreth", "Lady Viorica is a venthyr located in the Redelav Hall in Revendreth." },
  ["lady zina"] = { 2, "venthyr located behind the Iremoore Estate in Revendreth", "Lady Zina is a venthyr located behind the Iremoore Estate in Revendreth. She is found talking with Lord Ionel." },
  ["lafayla mightblade"] = { 2, "vrykul located in Stormheim", "Lafayla Mightblade is a vrykul located in Stormheim." },
  ["lagertha"] = { 2, "vrykul located up a small hill near a tower in Skold-Ashi...", "Lagertha is a vrykul located up a small hill near a tower in Skold-Ashil in Stormheim. She is a fallen shieldmaiden who plotted to forcefully take her place among the Valkyra." },
  ["lago blackwrench"] = { 2, "gnome located in the Forlorn Cavern in Ironforge", "Lago Blackwrench is a gnome located in the Forlorn Cavern in Ironforge." },
  ["laha farplain"] = { 2, "tauren located in Thunder Bluff", "Laha Farplain is a tauren located in Thunder Bluff. She is the only vendor that sells  [Mulgore Sweet Potato]." },
  ["lahan"] = { 2, "tortollan located in Undermine", "Lahan is a tortollan located in Undermine." },
  ["lair brute"] = { 2, "', "Lair Brutes are ogres located in Gruul's Lair." },
  ["laire brewgold"] = { 2, "dwarf brewmaiden found in the Beer Garden in Dalaran", "Laire Brewgold is a dwarf brewmaiden found in the Beer Garden in Dalaran. She sells Northrend quality food and drinks to players that are in the Beer Garden." },
  ["laith sha'ol"] = { 2, "human member of the Tirisgarde", "Laith Sha'ol was a human member of the Tirisgarde who was entrusted with the cursed blade  [Apocalypse] and charged with hunting down the renegade Guardian of Tirisfal, Aegwynn. The blade darkened his mind and caused him to commit many horrid acts..." },
  ["lajos"] = { 2, "venthyr located in Darkhaven in Revendreth", "Lajos is a venthyr located in Darkhaven in Revendreth." },
  ["lakaan"] = { 2, "Broken located just east of Coilskar Point in Shadowmoon ...", "Lakaan is a Broken located just east of Coilskar Point in Shadowmoon Valley. He holds a medallion fragment." },
  ["lakesis"] = { 2, "kyrian located in Spires of Ascension", "Lakesis is a kyrian located in Spires of Ascension." },
  ["lakka"] = { 2, "arakkoa found captured in Sethekk Halls", "Lakka is an arakkoa found captured in Sethekk Halls. Once freed, she says she is heading to Shattrath." },
  ["lakoor"] = { 2, "Broken quest giver found at Telaar of Nagrand", "Lakoor is a Broken quest giver found at Telaar of Nagrand." },
  ["lalandi"] = { 2, "earthen located at the Contender's Gate in Dornogal", "Lalandi is an earthen located at the Contender's Gate in Dornogal." },
  ["lalla"] = { 2, "murloc located at the Winterfin Retreat in the Borean Tundra", "Lalla is a murloc located at the Winterfin Retreat in the Borean Tundra." },
  ["lalla brightweave"] = { 2, "gnome tailoring vendor", "Lalla Brightweave was a gnome tailoring vendor who sells 5 different patterns found in the Talismanic Textiles shop in Magus Commerce Exchange in Dalaran. She appears to be a mage as she summoned Lyndras from Azsuna to the shop." },
  ["lalum darkmane"] = { 2, "tauren profession trainer located in Bloodhoof Village in...", "Lalum Darkmane is a tauren profession trainer located in Bloodhoof Village in Mulgore." },
  ["lama cloudsong"] = { 2, "tauren shaman trainer located on the Spirit Rise in Thund...", "Lama Cloudsong is a tauren shaman trainer located on the Spirit Rise in Thunder Bluff." },
  ["lamplighter brensk"] = { 2, "dead Arathi lamplighter located in Nightfall Sanctum", "Lamplighter Brensk is a dead Arathi lamplighter located in Nightfall Sanctum." },
  ["lamplighter davrak chavyn"] = { 2, "Arathi lamplighter located in the Skittering Breach", "Lamplighter Davrak Chavyn is an Arathi lamplighter located in the Skittering Breach." },
  ["lamplighter havrik chayvn"] = { 2, "Arathi located in the Skittering Breach", "Lamplighter Havrik Chayvn is an Arathi located in the Skittering Breach." },
  ["lamplighter kaerter"] = { 2, "Arathi lamplighter of the Hallowfall Arathi", "Lamplighter Kaerter is an Arathi lamplighter of the Hallowfall Arathi." },
  ["lamplighter rathling"] = { 2, "Arathi lamplighter encountered in the Earthcrawl Mines", "Lamplighter Rathling is an Arathi lamplighter encountered in the Earthcrawl Mines. Her squad was following nerubians through a series of tunnels and ended up in the mines." },
  ["lamplighter recruit"] = { 2, "', "Lamplighter Recruits are Arathi located in Light's Redoubt in Hallowfall and in Azj-Kahet." },
  ["lamplighter vokel"] = { 2, "dead Arathi lamplighter located in Nightfall Sanctum", "Lamplighter Vokel is a dead Arathi lamplighter located in Nightfall Sanctum." },
  ["lani"] = { 2, "tuskarr child located on a beach west of Iskaara in the A...", "Lani is a tuskarr child located on a beach west of Iskaara in the Azure Span." },
  ["lanka farshot"] = { 2, "tauren hunter trainer located at Camp Narache in Mulgore", "Lanka Farshot is a tauren hunter trainer located at Camp Narache in Mulgore." },
  ["lano"] = { 2, "tortollan located at Paw'don Bean Dumplings in Boralus Ha...", "Lano is a tortollan located at Paw'don Bean Dumplings in Boralus Harbor in Boralus." },
  ["larati"] = { 2, "tuskarr butcher from Taruka's clan", "Larati is a tuskarr butcher from Taruka's clan. She is a friend of Taruka and regularly exchanges insults with the catch master Kattik." },
  ["lard"] = { 2, "ogre innkeeper located in Revantusk Village in the Hinter...", "Lard is an ogre innkeeper located in Revantusk Village in the Hinterlands. One day, whilst on a picnic in his secret spot, Lard was waylaid by a massive group of the Vilebranch tribe kidnappers attacked, leading Lard to run home without his lunch." },
  ["large illusionary amber-weaver"] = { 2, "mantid found in the Proving Grounds", "Large Illusionary Amber-Weaver is a mantid found in the Proving Grounds." },
  ["large illusionary hive-singer"] = { 2, "mantid found in the Proving Grounds", "Large Illusionary Hive-Singer is a mantid found in the Proving Grounds." },
  ["large illusionary wind-guard"] = { 2, "mantid found in the Proving Grounds", "Large Illusionary Wind-Guard is a mantid found in the Proving Grounds." },
  ["larionrider orstus"] = { 2, "Forsworn kyrian summoned by ringing the Black Bell in the...", "Larionrider Orstus is a Forsworn kyrian summoned by ringing the Black Bell in the Citadel of Loyalty in Bastion." },
  ["larissa bussell"] = { 2, "worgen located at Lake Dumont in Feralas", "Larissa Bussell is a worgen located at Lake Dumont in Feralas." },
  ["larlda"] = { 2, "earthen located in the Golden Keg in the Dwarven District...", "Larlda is an earthen located in the Golden Keg in the Dwarven District in Stormwind City." },
  ["larn caverndeep"] = { 2, "dwarf warlock trainer located in the Forlorn Cavern in Ir...", "Larn Caverndeep is a dwarf warlock trainer located in the Forlorn Cavern in Ironforge. He is found talking with Darba the Crone in Bonegrip's Runes and Dooms." },
  ["lars bronsmaelt"] = { 2, "Arathi located in Mereldar in Hallowfall", "Lars Bronsmaelt is an Arathi located in Mereldar in Hallowfall. He later joins Flame's Radiance and relocates to Morgaen's Tears." },
  ["lash'ir"] = { 2, "ethereal located in Castigaar in K'aresh", "Lash'ir is an ethereal located in Castigaar in K'aresh." },
  ["lashh'an matriarch"] = { 2, "', "Lashh'an Matriarchs are arakkoa found at Veil Lashh in the Blade's Edge Mountains." },
  ["lashh'an talonite"] = { 2, "', "Lashh'an Talonites are arakkoa found at Veil Lashh in the Blade's Edge Mountains." },
  ["lashh'an windwalker"] = { 2, "', "Lashh'an Windwalkers are arakkoa found at Veil Lashh in the Blade's Edge Mountains." },
  ["lashh'an wing guard"] = { 2, "', "Lashh'an Wing Guards are arakkoa located at Veil Lashh in the Blade's Edge Mountains." },
  ["lashk"] = { 2, "tortollan pilgrim", "Lashk is a tortollan pilgrim who regularly journeyed to Nazmir to hear the stories of the turtle loa Torga. When Torga was killed by the blood trolls in the service of G'huun, Lashk and Kisha joined with Princess Talanji and adventurers from the H..." },
  ["lassik spinebender"] = { 2, "venthyr located in Torghast", "Lassik Spinebender is a venthyr located in Torghast, Tower of the Damned." },
  ["latif"] = { 2, "broker located at Pilgrim's Grace in Zereth Mortis", "Latif is a broker located at Pilgrim's Grace in Zereth Mortis." },
  ["latrunculon"] = { 2, "domanaar located in Dawnstar Village on the Isle of Quel'...", "Latrunculon is a domanaar located in Dawnstar Village on the Isle of Quel'Danas during the assault by the Devouring Host." },
  ["laurdare"] = { 2, "Arathi located in the Dayspring Fields in Hallowfall", "Laurdare is an Arathi located in the Dayspring Fields in Hallowfall." },
  ["laurent"] = { 2, "venthyr located in the Ember Ward", "Laurent is a venthyr located in the Ember Ward and the Shrouded Asylum in Revendreth. Simone is a dear friend to him." },
  ["layna karner"] = { 2, "worgen blacksmithing supplies vendor located in the Warri...", "Layna Karner is a worgen blacksmithing supplies vendor located in the Warrior's Terrace in Darnassus. This section concerns content related to Battle for Azeroth." },
  ["layne pontelle"] = { 2, "Arathi located in Mereldar in Hallowfall", "Layne Pontelle is an Arathi located in Mereldar in Hallowfall. She later joins the Flame's Radiance at Morgaen's Tears." },
  ["lazashi stormfury"] = { 2, "naga", "Lazashi Stormfury is a naga." },
  ["laze blasterparse"] = { 2, "goblin located with Beeg Pumpington", "Laze Blasterparse is a goblin located with Beeg Pumpington and Cheta Threatripper at the Demolition Dome in the Undermine." },
  ["lead rider jerek"] = { 2, "Broken located in Krokul Hovel in Krokuun", "Lead Rider Jerek is a Broken located in Krokul Hovel in Krokuun." },
  ["lead sapper blastfizzle"] = { 2, "goblin found just southeast of Area 52 in the Netherstorm", "Lead Sapper Blastfizzle is a goblin found just southeast of Area 52 in the Netherstorm." },
  ["leader au'llano"] = { 2, "broker located at the Lap of Luxury in Tazavesh", "Leader Au'llano is a broker located at the Lap of Luxury in Tazavesh, the Veiled Market. She is presumably the leader of Cartel Au." },
  ["leader xy'viler"] = { 2, "broker speaking with Xy'mox on the northern end of the La...", "Leader Xy'viler is a broker speaking with Xy'mox on the northern end of the Lap of Luxury. They teleport away when Al'dalil and his helpers arrive to confront So'leah and So'azmi." },
  ["leaf-weaver kulawah"] = { 2, "haranir located at the Den in Harandar", "Leaf-Weaver Kulawah is a haranir located at the Den in Harandar." },
  ["learned aspirant"] = { 2, "', "Learned Aspirants are kyrian located at Sagehaven in Bastion." },
  ["leatherworker tukhtai"] = { 2, "centaur located in the Ohn'ahran Plains", "Leatherworker Tukhtai is a centaur located in the Ohn'ahran Plains. She is one of the few surviving members of Clan Toghus, having been rescued from the village of Daruukhan after it was destroyed by Clan Nokhud." },
  ["leda"] = { 2, "vulpera located at the Grand Bazaar in Dazar'alor", "Leda is a vulpera located at the Grand Bazaar in Dazar'alor." },
  ["ledonir"] = { 2, "earthen item upgrader located at the Contender's Gate in ...", "Ledonir is an earthen item upgrader located at the Contender's Gate in Dornogal." },
  ["leena guant"] = { 2, "worgen located at the Lunarfall in Shadowmoon Valley", "Leena Guant is a worgen located at the Lunarfall in Shadowmoon Valley. She can only be recruited using the Headhunter's Harvest from Lunarfall Inn." },
  ["legashi hellcaller"] = { 2, "', "Legashi Hellcallers are satyrs found in Azshara." },
  ["legashi rogue"] = { 2, "', "Legashi Rogues are satyrs found in Azshara." },
  ["legashi satyr"] = { 2, "', "Legashi Satyr are satyrs found in Azshara." },
  ["legion cannoneer"] = { 2, "', "Legion Cannoneers are level 110 fel-corrupted Broken found at the High Inquisitor's Lair of Krokuun." },
  ["legionfall defender"] = { 2, "', "Legionfall Defenders are guards located at Deliverance Point on the Broken Shore." },
  ["legionfall enforcer"] = { 2, "', "Legionfall Enforcers are worgen rogues located at Deliverance Point in the Broken Shore." },
  ["legionfall field priest"] = { 2, "', "The Legionfall Field Priest can spawn as a worgen, jungle troll, goblin, or gnome at Deliverance Point on the Broken Shore." },
  ["legionfall mender"] = { 2, "', "Legionfall Menders are healers located at Deliverance Point on the Broken Shore." },
  ["legionfall sentry"] = { 2, "', "Legionfall Sentries are guards located at Deliverance Point in the Broken Shore." },
  ["legionfall soldier"] = { 2, "', "Legionfall Soldiers are soldiers located on the Broken Shore. They can also be found in the Cathedral of Eternal Night and Tomb of Sargeras, fighting the demons." },
  ["legionnaire murky"] = { 2, "Horde version of Murky as a soldier", "The Legionnaire Murky is the Horde version of Murky as a soldier. He is awarded to players who attended or purchase the virtual ticket for BlizzCon 2016." },
  ["lei shen"] = { 2, "first emperor of the mogu", "Emperor Lei Shen (/ˈleɪ ʃɛn/ LAY-shen), also known as the Thunder King, was the first emperor of the mogu and the most powerful warlord in mogu history. After stealing the power of storms from the titan keeper Ra, Lei Shen united the mogu clans in..." },
  ["lei shen (tactics)"] = { 2, "twelfth", "Lei Shen is the twelfth and final boss encounter in the Throne of Thunder on Looking for Raid and Normal Mode." },
  ["lei-zhi oppressor"] = { 2, "', "Lei-zhi Oppressors are mogu located on the Isle of Fangs and Tusk Isle in Zuldazar." },
  ["lei-zhi slaver"] = { 2, "', "Lei-zhi Slavers are mogu located on the Isle of Fangs and Tusk Isle in Zuldazar." },
  ["leif"] = { 2, "earthen peacekeeper located on the Isle of Dorn", "Leif is an earthen peacekeeper located on the Isle of Dorn and later a lamplighter located in Azj-Kahet." },
  ["leifar"] = { 2, "earthen vendor located in Boulder Springs on the Isle of ...", "Leifar is an earthen vendor located in Boulder Springs on the Isle of Dorn." },
  ["leikaroc"] = { 2, "earthen located in the Lightless Reaches in the Shimmerin...", "Leikaroc is an earthen located in the Lightless Reaches in the Shimmering Expanse of Vashj'ir." },
  ["leikneir the brave"] = { 2, "vrykul", "Leikneir the Brave is a vrykul that can be encountered during Island Expeditions." },
  ["lekta'cal"] = { 2, "ethereal", "Lekta'cal is an ethereal. They would deal in trades involving  [Corruptium]." },
  ["lelyias"] = { 2, "Darkfallen dark ranger", "Lelyias is a Darkfallen dark ranger who remained loyal to Sylvanas Windrunner after the Fourth War and accompanied Nathanos Blightcaller and Sira Moonwarden on their mission to kill the loa Bwonsamdi. She frequently served as a scout in the confli..." },
  ["lenara"] = { 2, "Darkfallen of the Forsaken located at Trueshot Lodge in H...", "Lenara is a Darkfallen of the Forsaken located at Trueshot Lodge in Highmountain. She is an extraordinary archer." },
  ["lenne"] = { 2, "vrykul located at the Grand Bazaar in Dazar'alor", "Lenne is a vrykul located at the Grand Bazaar in Dazar'alor." },
  ["lenusa"] = { 2, "deceased venthyr located in the Ashen Traverse in Revendreth", "Lenusa is a deceased venthyr located in the Ashen Traverse in Revendreth. She was one of Sabina's companions." },
  ["leonid barthalomew"] = { 2, "undead member of the Argent Crusade", "Leonid Barthalomew the Revered is an undead member of the Argent Crusade, formerly the Argent Dawn, who is revered by his colleagues for the sacrifices he has made. He investigated the return of the powerful lich, Ras Frostwhisper, in the Eastern ..." },
  ["leprous servant"] = { 2, "', "Leprous Servants are undead gnomes located in the Wintergarde Mausoleum in the Dragonblight." },
  ["lerrenai fayn"] = { 2, "Arathi quest giver located at Dunelle's Kindness in Hallo...", "Lerrenai Fayn is an Arathi quest giver located at Dunelle's Kindness in Hallowfall, next to her husband Derill. When Lerrenai and Derill joined the Hallowfall Expedition, they thought they would be away from their families for only a few years." },
  ["lesser sparring partner"] = { 2, "', "Lesser Sparring Partners are vrykul located in the Halls of Valor and in Skyhold." },
  ["lester scaleworth"] = { 2, "worgen fishing trainer located at the Lunarfall Shipyard ...", "Lester Scaleworth is a worgen fishing trainer located at the Lunarfall Shipyard in Shadowmoon Valley." },
  ["lethnal"] = { 2, "Forsaken", "Lethnal is a Forsaken who can be encountered in Fungal Folly." },
  ["letjia the shapp"] = { 2, "vrykul located in Stormheim", "Letjia the Shapp is a vrykul located in Stormheim." },
  ["levia laurence"] = { 2, "', "Levia Laurence was once a member of the Kirin Tor. Dabbling in shadow magic got her banned from the city of Dalaran." },
  ["lewis bartwell"] = { 2, "worgen", "Lewis Bartwell is a worgen." },
  ["leyspeaker carver"] = { 2, "vrykul located at Haustvald in Stormheim", "Leyspeaker Carver is a vrykul located at Haustvald in Stormheim. He is only found during  [45WQ] Primal Leystone Outcropping." },
  ["leyspine dredger"] = { 2, "murloc", "Leyspine Dredger is a murloc." },
  ["leyspine taskmaster"] = { 2, "naga", "Leyspine Taskmaster is a naga." },
  ["leyspine tidecaller"] = { 2, "naga", "Leyspine Tidecaller is a naga." },
  ["leyspine worker"] = { 2, "murloc", "Leyspine Worker is a murloc." },
  ["leza farwalker"] = { 2, "member of the Dawnchaser tribe", "Leza Farwalker (or Leza Dawnchaser) was a member of the Dawnchaser tribe and the wife of Sunwalker Dezco. The earth totem named Leza's Totem left behind after her death suggests she was a shaman." },
  ["li'l gill"] = { 2, "murloc located at the Winterfin Retreat in the Borean Tundra", "Li'l Gill is a murloc located at the Winterfin Retreat in the Borean Tundra." },
  ["libbiara blightrunner"] = { 2, "wealthy Darkfallen death knight standing next to Helga Bo...", "Libbiara Blightrunner is a wealthy Darkfallen death knight standing next to Helga Bonehewer aboard the Skybag in the Brawl'gar Arena." },
  ["liberated forsworn"] = { 2, "', "The Liberated Forsworn are two non-hostile Forsworn located in the main hall of the Seat of the Primus alongside Alexandros Mograine and other kyrian characters during  [60] Filling an Empty Throne and  [60] The Roads We Walk. One is standing next..." },
  ["librarian andersen"] = { 2, "human located at Amber Ledge in the Borean Tundra", "Librarian Andersen is a human located at Amber Ledge in the Borean Tundra." },
  ["librarian eratus"] = { 2, "kyrian located in Kalliope's Rest in Bastion", "Librarian Eratus is a kyrian located in Kalliope's Rest in Bastion. He was captured by the Forsworn but eventually rescued by the Maw Walker sent by Haetio, after which he relocated to Haetion's Solace." },
  ["lich king (time rifts)"] = { 2, "ruler of the Undead Scourge", "The Lich King is the ruler of the Undead Scourge and of Azmourne. His appearance is manifested and used by the Fractured Causality during Time Rifts." },
  ["lich king (tactics)"] = { 2, "final boss of Icecrown Citadel", "The Lich King is the final boss of Icecrown Citadel and the final major encounter of World of Warcraft: Wrath of the Lich King. This boss has been available since February 2, 2010 on US servers and February 3 on EU servers." },
  ["lieutenant aden"] = { 2, "human quest giver located on Theramore Isle in Dustwallow...", "Lieutenant Aden is a human quest giver located on Theramore Isle in Dustwallow Marsh. He always volunteered for gate duty." },
  ["lieutenant akaro"] = { 2, "orc located in Ar'gorok in Arathi Highlands during the Ba...", "Lieutenant Akaro is an orc located in Ar'gorok in Arathi Highlands during the Battle for Stromgarde. He wears the tabard of the Kor'kron." },
  ["lieutenant alverold"] = { 2, "', "Lieutenant Alverold was one of Daelin Proudmoore's lieutenants and made up a part of the fleet which sailed to Durotar in search of Jaina Proudmoore. While Proudmoore headed towards land, he ordered Alverold to take an exploratory fleet and scout ..." },
  ["lieutenant amadi"] = { 2, "human quest giver located in the ruined scout tower outsi...", "Lieutenant Amadi is a human quest giver located in the ruined scout tower outside Honor Hold Mine in the Hellfire Peninsula." },
  ["lieutenant beitha"] = { 2, "orc of the Argent Dawn", "Lieutenant Beitha was an orc of the Argent Dawn, stationed in Darnassus during the duration of the Scourge Invasion. She sent low-level adventurers on a trip outside the city to investigate the invading Scourge." },
  ["lieutenant blasthammer"] = { 2, "goblin located in Battle on the High Seas scenario", "Lieutenant Blasthammer is a goblin located in Battle on the High Seas scenario." },
  ["lieutenant boltblaster"] = { 2, "gnome located in Battle on the High Seas scenario", "Lieutenant Boltblaster is a gnome located in Battle on the High Seas scenario." },
  ["lieutenant bruna"] = { 2, "orc located at the Anguish Point in Nagrand", "Lieutenant Bruna is an orc located at the Anguish Point in Nagrand. She and Lieutenant Drogg serve Malroc Stonesunder." },
  ["lieutenant castle"] = { 2, "worgen located at Skold-Ashil in Stormheim", "Lieutenant Therese Castle was a worgen located at Skold-Ashil in Stormheim." },
  ["lieutenant dagel"] = { 2, "dwarf of the Argent Dawn found in the Valley of Strength ...", "Lieutenant Dagel was a dwarf of the Argent Dawn found in the Valley of Strength in Orgrimmar." },
  ["lieutenant fizzboil"] = { 2, "gnome located in Battle on the High Seas scenario", "Lieutenant Fizzboil is a gnome located in Battle on the High Seas scenario." },
  ["lieutenant general andorov"] = { 2, "human affiliated with Cenarion Circle", "Lieutenant General Andorov is a human affiliated with Cenarion Circle who, along with 4 Kaldorei Elites, spawns once Kurinnaxx, the first boss found in the Ruins of Ahn'Qiraj, is dead. These NPCs will aid you in the battle against General Rajaxx." },
  ["lieutenant narlena"] = { 2, "dracthyr located in Zaralek Cavern", "Lieutenant Narlena is a dracthyr located in Zaralek Cavern." },
  ["liftbrul"] = { 2, "greatest of all drogbar weightlifters", "Liftbrul was the greatest of all drogbar weightlifters and a champion of the Stonedark clan. He was immortalized in stone (literally) by chief Rynox, the second-strongest drogbar of his time, and to this day Liftbrul's statue remains in the Stoned..." },
  ["light's hope messenger"] = { 2, "', "Light's Hope Messengers are a human quest giver located at the Trade District in Stormwind City and a Forsaken found in the Valley of Strength in Orgrimmar." },
  ["light's vanguard"] = { 2, "', "Light's Vanguards are located on the Isle of Quel'Danas when the Devouring Host invaded it. They come in various races representing various organizations: draenei of the Hand of Argus and the Argent Crusade, dwarves of the Kingdom of Ironforge and..." },
  ["lightbreaker valeri"] = { 2, "venthyr located in Dawnkeep in Revendreth", "Lightbreaker Valeri is a venthyr located in Dawnkeep in Revendreth." },
  ["lightning guardian"] = { 2, "', "Lightning Guardians are mogu located at the Lightning Ascent in the Throne of Thunder." },
  ["lightning witch"] = { 2, "naga located in Azsuna", "Lightning Witch is an naga located in Azsuna." },
  ["lightshielder baetrix"] = { 2, "draenei located at the Lunarfall in Shadowmoon Valley", "Lightshielder Baetrix is a draenei located at the Lunarfall in Shadowmoon Valley. She can only be recruited using the Headhunter's Harvest from Lunarfall Inn." },
  ["lightspark student"] = { 2, "', "Lightspark Students are Arathi located in Lightspark in Hallowfall." },
  ["lightwarden ruia"] = { 2, "boss in the Blinding Vale", "Lightwarden Ruia is a boss in the Blinding Vale." },
  ["lil ki"] = { 2, "tuskarr child vendor located in Iskaara in the Azure Span", "Lil Ki is a tuskarr child vendor located in Iskaara in the Azure Span." },
  ["lil' bitsy"] = { 2, "goblin child located in Undermine", "Lil' Bitsy is a goblin child located in Undermine." },
  ["lil' friend"] = { 2, "vulpera", "Lil' Friend is a vulpera that can be summoned by Don Adams at the Kelp Club in Hook Point in Boralus." },
  ["lil'idan"] = { 2, "baby murloc demon hunter located in Shipwreck Cove of Hig...", "Lil'idan is a baby murloc demon hunter located in Shipwreck Cove of Highmountain." },
  ["lili"] = { 2, "tuskarr child chasing a Mammoth Calf with Jiq in Iskaara ...", "Lili is a tuskarr child chasing a Mammoth Calf with Jiq in Iskaara in the Azure Span." },
  ["lilian voss (tactics)"] = { 2, "fourth boss in Scholomance", "Lilian Voss is the fourth boss in Scholomance." },
  ["lilith the lithe"] = { 2, "Forsaken weaponsmith located in Everlook in Winterspring", "Lilith the Lithe is a Forsaken weaponsmith located in Everlook in Winterspring. She has two hobbies - dancing, and threatening to kill people who get too close to her." },
  ["lilki"] = { 2, "important shaman of the White Shark tribe", "Lilki, a female murloc, is an important shaman of the White Shark tribe. Though young for such a position, she is already admired for her wisdom, her power, and her fervent sacrifices." },
  ["lily hillhelm"] = { 2, "Arathi located in Hillhelm Stead in Hallowfall", "Lily Hillhelm is an Arathi located in Hillhelm Stead in Hallowfall." },
  ["linda meier"] = { 2, "worgen located at Lunarfall in Shadowmoon Valley", "Linda Meier is a worgen located at Lunarfall in Shadowmoon Valley. She can only be recruited using the Headhunter's Harvest from Lunarfall Inn." },
  ["line worker"] = { 2, "', "Line Workers are earthen located at the Forgegrounds in Dornogal." },
  ["lingering merchant"] = { 2, "', "Lingering Merchants are eredar located at Azurelight Square in Eredath." },
  ["lingering torment"] = { 2, "satyr located northwest of the Eye of Ysera in the Emeral...", "Lingering Torment is a satyr located northwest of the Eye of Ysera in the Emerald Dream. It is the manifestation of a memory that still haunts Gracus, and it must be defeated for him to rest peacefully." },
  ["linkaeon"] = { 2, "kyrian located in Terrace of the Collectors in Bastion", "Linkaeon is a kyrian located in Terrace of the Collectors in Bastion." },
  ["linzy blackbolt"] = { 2, "gnome alchemy trainer located in The Agronomical Apotheca...", "Linzy Blackbolt was a gnome alchemy trainer located in The Agronomical Apothecary within Dalaran. When Lyndras came to the shop and stole a ley burner, Linzy chased him as far as the sewers before he slipped away." },
  ["lio the lioness"] = { 2, "worgen", "Lio the Lioness is a worgen that runs the Menagerie in Lunarfall. She revives dead pets." },
  ["lion's landing elite"] = { 2, "', "Lion's Landing Elites are draenei, humans, worgen, and pandaren located at Lion's Landing Graveyard, Ogudei Shrine, and Lion's Landing Tower in Krasarang Wilds." },
  ["lion's landing priest"] = { 2, "', "Lion's Landing Priests are humans located in Krasarang Wilds. They can be seen resurrecting fallen soldiers." },
  ["lissaf"] = { 2, "arakkoa located in Lower City in Shattrath City", "Lissaf is an arakkoa located in Lower City in Shattrath City." },
  ["lissyphus finespindle"] = { 2, "gnome light armor vendor located in the Military Ward in ...", "Lissyphus Finespindle is a gnome light armor vendor located in the Military Ward in Ironforge." },
  ["lita"] = { 2, "', "Lita was one of the vulpera, who made their home in the reclaimed Abandoned Burrows. In Year 42 ADP, when First Arcanist Thalyssra visited the area, Lita eagerly showed her all the new construction within the burrows." },
  ["literary enthusiast"] = { 2, "', "Literary Enthusiasts are located in the Sapphire Enclave in Valdrakken. Some appear as dracthyr, and despite being tagged as humanoid and having regular eyes, some of them also have dragon eyes." },
  ["lith'ik the stalker"] = { 2, "mantid found in Sik'vess in the Townlong Steppes", "Lith'ik the Stalker is a mantid found in Sik'vess in the Townlong Steppes. Lith'ik is a Pandarian champion." },
  ["lithia costcutter"] = { 2, "Venture Company goblin located on the Jeweled Coast in St...", "Lithia Costcutter is a Venture Company goblin located on the Jeweled Coast in Stormsong Valley, operating a shredder. After it is destroyed, she engages her attacker." },
  ["lithic"] = { 2, "daughter of the great Talon King Terokk", "Lithic was the daughter of the great Talon King Terokk and the individual closest to him.  While she was a skilled huntress, she found her true passion in goldsmithing." },
  ["lithic oracle"] = { 2, "', "Lithic Oracles are arakkoa found at Veil Lithic in Terokkar Forest." },
  ["lithic talonguard"] = { 2, "', "Lithic Talonguards are arakkoa found at Veil Lithic in Terokkar Forest." },
  ["little adeline"] = { 2, "human child found at Fragrant Flowers", "Little Adeline is a human child found at Fragrant Flowers, a shop in the Canal District of Stormwind City." },
  ["little azimi"] = { 2, "', "Little Azimi is draenei vendor located at Kessel's Crossing on Bloodmyst Isle." },
  ["little ko"] = { 2, "tuskarr child located in the Lair of the Scythid in the F...", "Little Ko is a tuskarr child located in the Lair of the Scythid in the Forbidden Reach. He also attended the gathering in Amirdrassil when it bloomed on the Dragon Isles after Fyrakk's death." },
  ["littlefur"] = { 2, "furbolg of the Smolderhide tribe located in Smolderhide T...", "Littlefur is a furbolg of the Smolderhide tribe located in Smolderhide Thicket in Val'sharah. His tribe went into a frenzy, with only Littlefur and his uncle, the Elder Sookh, uncorrupted." },
  ["lixa felflinger"] = { 2, "gnome battlemaster located in the Military Ward of Ironforge", "Lixa Felflinger is a gnome battlemaster located in the Military Ward of Ironforge." },
  ["llande"] = { 2, "earthen located in the Forgegrounds in Dornogal", "Llande is an earthen located in the Forgegrounds in Dornogal." },
  ["lleanya mourningsong"] = { 2, "Darkfallen death knight located at the Lunarfall in Shado...", "Lleanya Mourningsong is a Darkfallen death knight located at the Lunarfall in Shadowmoon Valley. She can only be recruited using the Headhunter's Harvest from Lunarfall Inn." },
  ["local"] = { 2, "', "Locals are people of various Alliance and Horde races located on Founder's Point and Razorwind Shores. Those on Founder's Point are humans, dwarves, gnomes, night elves, draenei, worgen, and pandaren." },
  ["loco"] = { 2, "murloc located at the Winterfin Retreat in the Borean Tundra", "Loco is a murloc located at the Winterfin Retreat in the Borean Tundra." },
  ["logistics specialist"] = { 2, "', "Logistics Specialists are brokers located in the Hall of Curiosities in Oribos." },
  ["loh"] = { 2, "famous young tortollan", "Loh was a famous young tortollan who traveled the world and had many adventures, as chronicled in stories told to tortollan children. When telling these stories, the elders have their children navigate a turtle representing Loh through small mazes..." },
  ["loirea galerunner"] = { 2, "', "Loirea Galerunner appears only during the Lunar Festival in Silvermoon City to let players known about whats going on during that time, since Silvermoon doesn't have its own part in the festival itself." },
  ["lok orcbane"] = { 2, "quilboar found in Blackthorn Ridge in the Barrens", "Lok Orcbane is a quilboar found in Blackthorn Ridge in the Barrens. Mangletooth having told heroes of the Horde that Lok was the leader, tasked them to kill Lok and bring back his skull as proof." },
  ["lok'lira the crone"] = { 2, "vrykul quest giver initially found inside Forlorn Mine", "Lok'lira the Crone is a vrykul quest giver initially found inside Forlorn Mine, next to Sifreldar Village in the Storm Peaks. When first encountered, she tells the adventurer that she is a Yrkvinn, an illusionist, who has been imprisoned by the Hy..." },
  ["lok'nor bloodfist"] = { 2, "orc Horde  [Honor] quartermaster found inside the Serpent...", "Lok'nor Bloodfist is an orc Horde  [Honor] quartermaster found inside the Serpent's Spine Horde Tower on the Serpent's Spine." },
  ["lok'osh bortuk"] = { 2, "orc priest levitating in front of Lok'osh Nakha at the wa...", "Lok'osh Bortuk is an orc priest levitating in front of Lok'osh Nakha at the waterfall in the western Valley of Honor in Orgrimmar. His Levitate spell occasionally fails, causing him to fall into the water and roar in frustration before he recasts ..." },
  ["lok'osh brighttusk"] = { 2, "orc priest speaking with Seer Lighthoof outside Miwana's ...", "Lok'osh Brighttusk is an orc priest speaking with Seer Lighthoof outside Miwana's Longhouse in the Valley of Wisdom in Orgrimmar." },
  ["lola bleedingheart"] = { 2, "goblin located in the Vatworks in the Undermine", "Lola Bleedingheart is a goblin located in the Vatworks in the Undermine, sitting next to Ethel and Lucy." },
  ["loldren"] = { 2, "earthen located in the Forgegrounds in Dornogal", "Loldren is an earthen located in the Forgegrounds in Dornogal." },
  ["lolo the lookout"] = { 2, "ogre member of the Blackwater Raiders", "Lolo the Lookout is an ogre member of the Blackwater Raiders. He was part of an expedition, led by Captain O'Breen, who sought an elven treasure." },
  ["long fang (worgen)"] = { 2, "worgen", "Long Fang is a worgen who didn't make it into the live game." },
  ["long john copper"] = { 2, "worgen found aboard the The Damsel's Luck in the Cape of ...", "Long John Copper is a worgen found aboard the The Damsel's Luck in the Cape of Stranglethorn." },
  ["longclaw fish catcher"] = { 2, "', "The Longclaw Fish Catcher is furbolg located on Longclaw Island in the Azure Span. Tullek is teaching them how to fish." },
  ["longclaw furbolg"] = { 2, "', "Longclaw Furbolgs are furbolgs located on Longclaw Island in the Azure Span." },
  ["longclaw shellfish collector"] = { 2, "', "Longclaw Shellfish Collectors are furbolgs located on the shores of Longclaw Island in the Azure Span." },
  ["longtusk fisherman"] = { 2, "', "Longtusk Fishermen are tuskarr fishermen found in Kamagua in the Howling Fjord." },
  ["longtusk harpooner"] = { 2, "tuskarr", "Longtusk Harpooner is a tuskarr." },
  ["longtusk sea-caller"] = { 2, "tuskarr", "Longtusk Sea-caller is a tuskarr." },
  ["longtusk tribesman"] = { 2, "tuskarr", "Longtusk Tribesman is a tuskarr." },
  ["longtusk wayfinder"] = { 2, "tuskarr", "Longtusk Wayfinder is a tuskarr." },
  ["lontupit"] = { 2, "tuskarr located in Iskaara in the Azure Span", "Lontupit is a tuskarr located in Iskaara in the Azure Span." },
  ["loogie"] = { 2, "murloc located at the Winterfin Retreat in the Borean Tundra", "Loogie is a murloc located at the Winterfin Retreat in the Borean Tundra." },
  ["looper allen"] = { 2, "worgen located at Mak'rana in Azsuna", "Looper Allen is a worgen located at Mak'rana in Azsuna. He is sent by Mr." },
  ["lor'danel citizen"] = { 2, "', "Lor'danel Citizens were found in Lor'danel in Darkshore during the second chapter of the War of the Thorns." },
  ["lorash sunbeam"] = { 2, "Horde operative", "Lorash Sunbeam was a Horde operative who oversaw the assault on Astranaar in Ashenvale during the War of the Thorns. He and a Horde champion assassinated the guards of the town." },
  ["lorax"] = { 2, "satyr located at the bottom of Frostwhisper Gorge in Wint...", "Lorax is a satyr located at the bottom of Frostwhisper Gorge in Winterspring, having moved from his prior position in the ruins of a night elven temple on the southeastern ridge of Frostwhisper Gorge." },
  ["lord afanas"] = { 2, "venthyr located in Sinfall", "Lord Afanas is a venthyr located in Sinfall." },
  ["lord agrovane"] = { 2, "human", "Lord Agrovane is a human who bought Rehgar Earthfury as a gladiator from guards at an Alliance internment camp. Eventually, however, Rehgar was able to escape." },
  ["lord ander"] = { 2, "venthyr located in Redelav Tower in Revendreth", "Lord Ander is a venthyr located in Redelav Tower in Revendreth." },
  ["lord andrei"] = { 2, "venthyr located in the Iremoore Estate in Revendreth", "Lord Andrei is a venthyr located in the Iremoore Estate in Revendreth." },
  ["lord ashbury the 1st"] = { 2, "Gilnean noble", "Lord Ashbury the 1st was a Gilnean noble and the father of Baron Ashbury. Lord Ashbury helped King Archibald Greymane build Gilneas up to a nation of great power." },
  ["lord aurel"] = { 2, "venthyr located in the Darkvein Villa in Revendreth", "Lord Aurel is a venthyr located in the Darkvein Villa in Revendreth." },
  ["lord blackbale"] = { 2, "venthyr located at Chalice District in Revendreth", "Lord Blackbale is a venthyr located at Chalice District in Revendreth, standing next to Bolt. He is a treasonous leader of the Blackbale house, in league with Maldraxxi forces." },
  ["lord blackforest"] = { 2, "night elf noble", "Lord Blackforest was a night elf noble. He was one of the many nobles who looked to Jarod Shadowsong for leadership during the later battles against the Burning Legion." },
  ["lord chamberlain"] = { 2, "venthyr servant of Sire Denathrius", "Lord Chamberlain is a venthyr servant of Sire Denathrius. One of the Master's chief servants, he wielded considerable influence thanks to this station." },
  ["lord chamberlain (tactics)"] = { 2, "venthyr", "Lord Chamberlain is a venthyr and the last boss located in the Halls of Atonement." },
  ["lord coilfin"] = { 2, "naga located in Island Expeditions", "Lord Coilfin is a naga located in Island Expeditions." },
  ["lord cyrik blackforge"] = { 2, "dwarf found in Bael Modan in the Barrens", "Lord Cyrik Blackforge is a dwarf found in Bael Modan in the Barrens. As he was standing near a flying machine, he was likely its pilot." },
  ["lord darion"] = { 2, "venthyr located in the Redelav Hall in Revendreth", "Lord Darion is a venthyr located in the Redelav Hall in Revendreth." },
  ["lord del'theon"] = { 2, "night elf noble", "Lord Del'theon was a night elf noble. He was one of many leaders killed during the fight against the Burning Legion." },
  ["lord epochbrgl"] = { 2, "murloc located in a building in Temporal Conflux in Thald...", "Lord Epochbrgl is a murloc located in a building in Temporal Conflux in Thaldraszus. He appears after activating an Unstable Time Rift." },
  ["lord evershade"] = { 2, "venthyr located in Castle Nathria", "Lord Evershade is a venthyr located in Castle Nathria." },
  ["lord garridan"] = { 2, "venthyr located in Sinfall in Revendreth", "Lord Garridan is a venthyr located in Sinfall in Revendreth. He has an extensive network of contacts and humble diplomatic skills." },
  ["lord godfrey (tactics)"] = { 2, "undead former Gilnean noble", "Lord Godfrey is an undead former Gilnean noble and the last encounter in the Shadowfang Keep." },
  ["lord harford"] = { 2, "Argent Dawn prisoner of the death knights in the Scarlet ...", "Lord Harford is an Argent Dawn prisoner of the death knights in the Scarlet Enclave." },
  ["lord harris"] = { 2, "venthyr located in Pridefall Hamlet in Revendreth", "Lord Harris is a venthyr located in Pridefall Hamlet in Revendreth." },
  ["lord holscher"] = { 2, "venthyr located in the Sinposium in Revendreth", "Lord Holscher is a venthyr located in the Sinposium in Revendreth." },
  ["lord ionel"] = { 2, "venthyr located behind the Iremoore Estate in Revendreth", "Lord Ionel is a venthyr located behind the Iremoore Estate in Revendreth. He is found talking with Lady Zina." },
  ["lord kragaru"] = { 2, "naga found in Desolace", "Lord Kragaru was a naga found in Desolace. Kragaru guarded the  [Book of the Ancients]." },
  ["lord le"] = { 2, "venthyr located in Redelav Tower in Revendreth", "Lord Le is a venthyr located in Redelav Tower in Revendreth." },
  ["lord melenas"] = { 2, "satyr found deep in Fel Rock in Teldrassil", "Lord Melenas is a satyr found deep in Fel Rock in Teldrassil. He is a vicious Satyr, who managed to amass a small army of grells led by Threggil, to protect him in his chosen lair of Fel Rock, just north of Dolanaar." },
  ["lord neculai"] = { 2, "venthyr located in the Sinfang Parlor in Revendreth", "Lord Neculai is a venthyr located in the Sinfang Parlor in Revendreth." },
  ["lord razvan"] = { 2, "venthyr located in the Duskmire Domain", "Lord Razvan is a venthyr located in the Duskmire Domain and Eternal Terrace in Revendreth." },
  ["lord sakrasis"] = { 2, "rare naga found in the Cape of Stranglethorn standing in ...", "Lord Sakrasis is a rare naga found in the Cape of Stranglethorn standing in front of the Holy Spring at Nek'mani Wellspring." },
  ["lord scowl"] = { 2, "venthyr located in Ember Ward in Revendreth", "Lord Scowl is a venthyr located in Ember Ward in Revendreth." },
  ["lord shalzaru"] = { 2, "naga", "Lord Shalzaru was a naga, and was the cruel royal leader of the Hatecrest. It is rumored that he himself has uncovered an odd relic during a recent naga excavation in a cave south of the main ruins, across the water on the Isle of Dread in Feralas." },
  ["lord silviu"] = { 2, "venthyr located at the Briarbane Stables in Revendreth", "Lord Silviu is a venthyr located at the Briarbane Stables in Revendreth. He can be found talking with Lady Daniela." },
  ["lord sinslayer"] = { 2, "rare mob naga found in Nazj'vel in Darkshore", "Lord Sinslayer is a rare mob naga found in Nazj'vel in Darkshore. He is on a 2-3 hour respawn timer." },
  ["lord sorin"] = { 2, "venthyr located outside the Primrose Residence in the Red...", "Lord Sorin is a venthyr located outside the Primrose Residence in the Redelav District in Revendreth. He can be found absolving an Abject Soul of its past sins, occasionally spawning various memories." },
  ["lord stavros"] = { 2, "venthyr located in the Feast of Arrogance in Castle Nathria", "Lord Stavros is a venthyr located in the Feast of Arrogance in Castle Nathria, as part of the Council of Blood encounter." },
  ["lord stefan"] = { 2, "venthyr located in the Sourwine Estate in Revendreth", "Lord Stefan is a venthyr located in the Sourwine Estate in Revendreth." },
  ["lord vasile"] = { 2, "venthyr located in the Redelav District in Revendreth", "Lord Vasile is a venthyr located in the Redelav District in Revendreth. He can be found walking back and forth with a Redelav Dredger between the Sinfang Parlor and the Redelav Hall." },
  ["lord vincent godfrey"] = { 2, "renegade nobleman from Gilneas", "Lord Vincent Godfrey is a renegade nobleman from Gilneas who opposed his king, Genn Greymane, after discovering that Genn and many of his people had been afflicted with the worgen curse. After committing suicide rather than acknowledge a worgen as..." },
  ["lord vyletongue"] = { 2, "', "Lord Vyletongue is head of the Putridus clan of satyrs.  He has corrupted parts of Maraudon, stunting the growth of many of the plants inside." },
  ["lord walden"] = { 2, "human nobleman from eastern Gilneas", "Lord Walden was a human nobleman from eastern Gilneas." },
  ["lord walden (tactics)"] = { 2, "fourth boss of the Shadowfang Keep instance", "Lord Walden is the fourth boss of the Shadowfang Keep instance." },
  ["lord-commander arete"] = { 2, "Forsaken death knight located at Death's Rise", "Lord-Commander Arete is a Forsaken death knight located at Death's Rise and Onslaught Harbor in Icecrown. He describes himself as particularly adept at nullifying magic." },
  ["lore character"] = { 2, "character mentioned in lore", "A lore character is a character mentioned in lore, but not present in any Warcraft or World of Warcraft games." },
  ["lorel ironglen"] = { 2, "Arathi located in Lorel's Crossing in Hallowfall", "Lorel Ironglen is an Arathi located in Lorel's Crossing in Hallowfall. She is an explorer and the founder of the town." },
  ["loreli fallglade"] = { 2, "night elf", "Loreli Fallglade is a night elf. It appears that she is a caretaker for the young, but is unable to have children herself." },
  ["loremaster bret"] = { 2, "goblin vendor located at Fuselight-by-the-Sea in the Badl...", "Loremaster Bret is a goblin vendor located at Fuselight-by-the-Sea in the Badlands." },
  ["loremaster dibbs"] = { 2, "human quest giver located in Southshore in the Hillsbrad ...", "Loremaster Dibbs was a human quest giver located in Southshore in the Hillsbrad Foothills. He didn't seem impressed at what the Crushridge ogres may have done to the various books and tomes still located within the Ruins of Alterac." },
  ["lorena belle"] = { 2, "worgen found in the Uncrowned Vault in the Hall of Shadows", "Lorena Belle is a worgen found in the Uncrowned Vault in the Hall of Shadows. She is able to refund the traits in the Shadow's artifact." },
  ["lorkron the hunter"] = { 2, "Drust located in Ardenweald", "Lorkron the Hunter is a Drust located in Ardenweald. He was sent to a hunt by Hunt-Captain Korayn which led him to be turned into a Drust and to serve a new master." },
  ["loroja"] = { 2, "tortollan located in an underwater cave off the Jeweled C...", "Loroja is a tortollan located in an underwater cave off the Jeweled Coast in Stormsong Valley. When the Tortollan Seekers were fighting against the Venture Company, Scrollsage Nola requested the adventurer to ask Loroja for help with awakening the..." },
  ["lorokeem"] = { 2, "arakkoa alchemy trainer located in Lower City in Shattrat...", "Lorokeem is an arakkoa alchemy trainer located in Lower City in Shattrath City. He is located on the lower tier of the far west treehouse in the north part of the city." },
  ["loruk foreststrider"] = { 2, "tauren", "Loruk Foreststrider is a tauren that could be found at Splintertree Post in Ashenvale." },
  ["lossain"] = { 2, "ethereal flight master located in Shadow Point in K'aresh", "Lossain is an ethereal flight master located in Shadow Point in K'aresh. After reaching Renown 5 with the Manaforge Vandals and completing  [80R] Manaforge Omega: A Walking Shadow, Lossain also provides raid skips directly to Nexus-King Salhadaar." },
  ["lost aspirant"] = { 2, "', "Lost Aspirants are kyrian located at the Court of Elation in Bastion." },
  ["lost explorer"] = { 2, "', "Lost Explorers are located in the Hissing Grotto in the Waking Shores." },
  ["lost kyrian"] = { 2, "', "Lost Kyrian are dead Ascended kyrian located around the ripening pond in the center of the House of Constructs in Maldraxxus." },
  ["lost neophyte"] = { 2, "', "Lost Neophytes are found in the Season of Discovery Karazhan Crypts dungeon." },
  ["lost slickerfin tadpole"] = { 2, "murloc", "Lost Slickerfin Tadpole is a murloc." },
  ["lost son of arugal"] = { 2, "rare worgen", "The Lost Son of Arugal is a rare worgen that patrols around Silverpine Forest. With its 'father', the Archmage Arugal, and many of its brothers dead, this worgen is left to wander the forest alone." },
  ["lost spirit"] = { 2, "', "Lost Spirits are draenei and Broken ghosts found at the Bone Wastes, just west and south of Auchindoun in Terokkar Forest." },
  ["lost tadpole"] = { 2, "', "Lost Tadpoles are murlocs located on an isolated island beach in Stormsong Valley. Three of them can be found in front of Meg Morris (disguised as a murloc)." },
  ["lost trader"] = { 2, "earthen located at the Crossroads Plaza on the Isle of Dorn", "Lost Trader is an earthen located at the Crossroads Plaza on the Isle of Dorn." },
  ["lostalot"] = { 2, "kobold located in Campalot in the Ringing Deeps", "Lostalot is a kobold located in Campalot in the Ringing Deeps." },
  ["lounging patron"] = { 2, "Veiled Market", "Lounging Patrons are brokers located at the Lap of Luxury in Tazavesh, the Veiled Market." },
  ["low-born arakkoa"] = { 2, "', "Low-Born Arakkoa are arakkoa that are held in chains by the Skyreach Overlord at the Lower Quarter in Skyreach. They drop no loot." },
  ["lower city operative"] = { 2, "', "Lower City Operatives are orcs, humans, and Broken located inside Shadow Labyrinth." },
  ["lowly moleherd"] = { 2, "', "Lowly Moleherds are kobolds located in Darkflame Cleft." },
  ["loyal acolyte"] = { 2, "', "Loyal Acolytes are Forsworn kyrian located at the Court of Elation in Bastion." },
  ["loyal footman"] = { 2, "', "Loyal Footmen are venthyr encountered by adventure companions in Revendreth." },
  ["loyal inquisitor"] = { 2, "', "Loyal Inquisitors are venthyr located in Revendreth." },
  ["loyal myrmidon"] = { 2, "', "Loyal Myrmidons are naga located in the Eternal Palace." },
  ["loyalist fearleacher"] = { 2, "', "Loyalist Fearleachers are venthyr located at Stalker's Lodge in Revendreth." },
  ["lrmrgrmr"] = { 2, "murloc located at the Winterfin Retreat in the Borean Tundra", "Lrmrgrmr is a murloc located at the Winterfin Retreat in the Borean Tundra." },
  ["lu'lin"] = { 2, "mogu located in the Throne of Thunder", "Lu'lin is a mogu located in the Throne of Thunder." },
  ["lu-ban"] = { 2, "mogu located on the Isle of Thunder", "Lu-Ban is a mogu located on the Isle of Thunder." },
  ["lu-shero"] = { 2, "mogu located in Swollen Vault at Isle of Thunder", "Lu-Shero is a mogu located in Swollen Vault at Isle of Thunder." },
  ["luanga the imprisoner"] = { 2, "arakkoa", "Luanga the Imprisoner is an arakkoa that spawns at Veil Shalas in Terokkar Forest during  [15-30G2] Skywing. He has cursed Skywing into parrot form." },
  ["luch"] = { 2, "swolbold located in the Dread Pit", "Luch is a swolbold located in the Dread Pit. He and his friend Skurro were captured by the nerubians in there." },
  ["lucia"] = { 2, "venthyr innkeeper located in Sinfall in Revendreth", "Lucia is a venthyr innkeeper located in Sinfall in Revendreth." },
  ["lucretia ainsworth"] = { 2, "human located at the Lunarfall in Shadowmoon Valley", "Lucretia Ainsworth is a human located at the Lunarfall in Shadowmoon Valley. She can only be recruited using the Headhunter's Harvest from Lunarfall Inn." },
  ["lucy brokerblast"] = { 2, "goblin found in Wor'var", "Lucy Brokerblast is a goblin found in Wor'var and Telaari Station in Nagrand seen arguing with guards." },
  ["ludwig von tortollan"] = { 2, "tortollan fighting in the Ring of Booty in Freehold", "Ludwig Von Tortollan is a tortollan fighting in the Ring of Booty in Freehold. He is part of the Ring of Booty encounter." },
  ["lufsela"] = { 2, "current Stormward", "Lufsela is the current Stormward, leader of the Stormriders, having succeeded Baelgrim in the position. Before becoming the Stormward she was a rooktender." },
  ["lug'dol"] = { 2, "ogre located in Nagrand", "Lug'dol is an ogre located in Nagrand. Following his death, his severed head was presented by adventurers to gain entry into the Ring of Blood arena." },
  ["lugger aklin"] = { 2, "earthen located in Camp Murroch in the Ringing Deeps duri...", "Lugger Aklin is an earthen located in Camp Murroch in the Ringing Deeps during  [80] Ringing in the Deeps." },
  ["lugger duchan"] = { 2, "earthen located at Shadowvein Point in the Ringing Deeps", "Lugger Duchan is an earthen located at Shadowvein Point in the Ringing Deeps." },
  ["luglar the clogger"] = { 2, "kobold", "Luglar the Clogger is a kobold." },
  ["lugo the windrider"] = { 2, "flight master for Vorrik's Sanctum in Vol'dun", "Lugo the Windrider is the flight master for Vorrik's Sanctum in Vol'dun. He is technically not located in the sanctum subzone itself, but rather on the Conqueror's Path just outside it." },
  ["lui"] = { 2, "tuskarr child located in the Filled Bowl in the Azure Span", "Lui is a tuskarr child located in the Filled Bowl in the Azure Span." },
  ["lukain chillborne"] = { 2, "worgen located at the Lunarfall in Shadowmoon Valley", "Lukain Chillborne is a worgen located at the Lunarfall in Shadowmoon Valley. He can only be recruited using the Headhunter's Harvest from Lunarfall Inn." },
  ["luke catstalker"] = { 2, "tauren located in the Drag in Orgrimmar", "Luke Catstalker is a tauren located in the Drag in Orgrimmar. He is chasing Max, while Ric is watching them." },
  ["lukir"] = { 2, "Drust located in Ardenweald", "Lukir is a Drust located in Ardenweald." },
  ["luknar"] = { 2, "Broken shaman trainer located at the Terrace of Light in ...", "Luknar is a Broken shaman trainer located at the Terrace of Light in Shattrath City. This section concerns content related to Dragonflight." },
  ["lukoturukk"] = { 2, "tuskarr located in Iskaara in the Azure Span", "Lukoturukk is a tuskarr located in Iskaara in the Azure Span." },
  ["lulubelle fizzlebang"] = { 2, "gnome warlock member of the Council of the Black Harvest", "Lulubelle Fizzlebang (or Lulu) is a gnome warlock member of the Council of the Black Harvest. She is the sister of Wilfred Fizzlebang, a famous gnome warlock who was killed by Lord Jaraxxus after he inadvertently summoned him during the Trial of t..." },
  ["luminore"] = { 2, "kobold located in Return to Karazhan as a part of the Ope...", "Luminore is a kobold located in Return to Karazhan as a part of the Opera Hall: Beautiful Beast encounter." },
  ["lump"] = { 2, "sleepy ogre found in the small camp of Boulderfist Hunter...", "Lump is a sleepy ogre found in the small camp of Boulderfist Hunters east of Telaar in Nagrand. Lump seems to be the camp's leader, who enjoys feasting on the inhabitants of Telaar." },
  ["lunar guardian"] = { 2, "', "Lunar Guardians are worgen druids located in Bashal'Aran in Darkshore during  [50] In Darkest Night." },
  ["lunarfall guard"] = { 2, "', "Lunarfall Guards are human, pandaren, and worgen guards of Lunarfall. They participate in its defense during the invasions." },
  ["lunk"] = { 2, "pacifist ogre", "Lunk is a pacifist ogre, involved in quests in the Searing Gorge requesting the player to do peaceful alternatives of what other quest givers asked." },
  ["lunk-tusk"] = { 2, "', "Lunk-tusk is one of the tuskarr warriors out of Kamagua. Along with his partner Orfus, he was sent to investigate tales of the dead rising at Shield Hill." },
  ["lurgan"] = { 2, "centaur located in the Ohn'ahran Plains", "Lurgan is a centaur located in the Ohn'ahran Plains." },
  ["lurgglbr"] = { 2, "murloc located in the Borean Tundra", "Lurgglbr is a murloc located in the Borean Tundra. One must complete  [10-30] Learning to Communicate to talk to him." },
  ["lurking marauder"] = { 2, "', "Lurking Marauders are nerubians located in the Pulsing Pit in Nerub-ar Palace." },
  ["lurkmane"] = { 2, "gnoll found in Palemane Rock in Mulgore", "Lurkmane is a gnoll found in Palemane Rock in Mulgore." },
  ["lurky's egg"] = { 2, "baby murloc companion", "Lurky's Egg teaches you how to summon Lurky, a baby murloc companion." },
  ["luthion the vile"] = { 2, "Darkfallen of the San'layn", "Luthion the Vile is a Darkfallen of the San'layn. He's one of Prince Valanar's personal retainers in Naxxanar in the Borean Tundra, along with Vanthryn the Merciless." },
  ["lutokk"] = { 2, "dead tuskarr located in Brackenhide Brambles in the Azure...", "Lutokk is a dead tuskarr located in Brackenhide Brambles in the Azure Span who was supposed to get married. He went with his fellow tuskarr to a hunt, but was killed by the Brackenhide gnolls." },
  ["lux"] = { 2, "Forsaken located at Xylem's Tower in Azshara", "Lux is a Forsaken located at Xylem's Tower in Azshara. During the Burning Legion's third invasion, she became a member of Xylem's inner circle." },
  ["lyandra sunstrider"] = { 2, "Darkfallen mage", "Lyandra Sunstrider is a Darkfallen mage, once a distant relative of the Sunstrider family and the latest wielder of Felo'melorn, which she retrieved from Icecrown Citadel before being killed and raised by the Scourge. She is encountered in the are..." },
  ["lycanthoth vandal"] = { 2, "', "Lycanthoth Vandals are worgen found at the Shrine of Goldrinn in Mount Hyjal. These worgen are from Gilneas, but have been corrupted by the Twilight's Hammer and now serve them as mindless beasts." },
  ["lynnia abbendis"] = { 2, "rare spawn found in Tyr's Hand in the Eastern Plaguelands", "Lynnia Abbendis is a rare spawn found in Tyr's Hand in the Eastern Plaguelands. She is usually spotted kneeling in the Abbey's center room." },
  ["lysonia"] = { 2, "Forsworn kyrian located in Bastion", "Lysonia is a Forsworn kyrian located in Bastion. She was the second in command of Devos, later taking her place as the Paragon of Doubt and leader of the Forsworn after her master's defeat in the Spires of Ascension." },
  ["mr-7 gutcutter"] = { 2, "', "MR-7 Gutcutters are murlocs from Azmerloth located in Tyrhold Reservoir in Thaldraszus during Time Rifts." },
  ["mr-7 shadowflipper"] = { 2, "', "MR-7 Shadowflippers are murlocs from Azmerloth located in Tyrhold Reservoir in Thaldraszus during Time Rifts." },
  ["mr-7 tangler"] = { 2, "', "MR-7 Tanglers are murlocs from Azmerloth located in Tyrhold Reservoir in Thaldraszus during Time Rifts." },
  ["maaklu cloudcaller"] = { 2, "tauren shaman", "Maaklu was a tauren shaman who accompanied Cairne and Garrosh through Garrosh's Landing. There they were attacked by Kvaldir." },
  ["maara"] = { 2, "earthen located at the Contender's Gate in Dornogal", "Maara is an earthen located at the Contender's Gate in Dornogal." },
  ["maaz"] = { 2, "vulpera quest giver located at Zul'Ahjin in Vol'dun", "Maaz is a vulpera quest giver located at Zul'Ahjin in Vol'dun." },
  ["machine ordinant"] = { 2, "', "Machine Ordinants are earthen located in Lothar's Landing in Hallowfall." },
  ["machinespeaker jorx"] = { 2, "earthen located at the Keepers Terrace in Dornogal", "Machinespeaker Jorx is an earthen located at the Keepers Terrace in Dornogal." },
  ["machinist au'gur"] = { 2, "broker located in the Hall of Shapes in Oribos", "Machinist Au'gur is a broker located in the Hall of Shapes in Oribos. He teaches Maw Walkers about Shadowlands Engineering crafts." },
  ["machinist b'randt"] = { 2, "orc during the Shattrath City scenario", "Machinist B'randt is an orc during the Shattrath City scenario." },
  ["machinist clockspan"] = { 2, "gnome located at Sprocket's Garage in Stormshield where h...", "Machinist Clockspan is a gnome located at Sprocket's Garage in Stormshield where he is doing maintenance work on a steam tank." },
  ["machinist kilton"] = { 2, "earthen located at Hallowfall Gate in the Ringing Deeps", "Machinist Kilton is an earthen located at Hallowfall Gate in the Ringing Deeps. When a magma transport pipe near the gate failed, he asked adventurers to help him gather some gas samples by standing in volcanic gas vents as they erupted." },
  ["machinist kittrin"] = { 2, "earthen located in Gundargaz in the Ringing Deeps", "Machinist Kittrin is an earthen located in Gundargaz in the Ringing Deeps." },
  ["machinist kromleg"] = { 2, "earthen located in the Analysis Interface in the Hall of ...", "Machinist Kromleg is an earthen located in the Analysis Interface in the Hall of Awakening. He can be found with the Helpful Haulbot and the Dawn Interface it carries." },
  ["machinist protector"] = { 2, "', "Machinist Protectors are earthen found in the Hall of Awakening in the Ringing Deeps." },
  ["mad henryk"] = { 2, "worgen hunter", "Mad Henry is a worgen hunter who's gone mad located in Val'sharah." },
  ["mad scientist"] = { 2, "', "Mad Scientists are undead found in Naxxramas." },
  ["madam budeau"] = { 2, "venthyr", "Madam Budeau is a venthyr." },
  ["madam colada"] = { 2, "worldsoul memory of a goblin located in the Demolition Do...", "Madam Colada is the worldsoul memory of a goblin located in the Demolition Dome during  [80] Worldsoul Memory: Early Cartel Wars event." },
  ["madame elenuta"] = { 2, "venthyr located in the Eternal Terrace in Revendreth", "Madame Elenuta is a venthyr located in the Eternal Terrace in Revendreth." },
  ["madame irini"] = { 2, "venthyr located in Revendreth", "Madame Irini is a venthyr located in Revendreth." },
  ["madame iza"] = { 2, "venthyr seen entering", "Madame Iza is a venthyr seen entering and exiting Sinfall, affiliated to House Primrose, and at the Ember Court. Despite having no quests affiliated with her, she has a unique voice." },
  ["madame lenuta"] = { 2, "venthyr located in Darkvein Villa", "Madame Lenuta is a venthyr located in Darkvein Villa and Eternal Terrace in Revendreth." },
  ["madame miriana"] = { 2, "venthyr located in the Redelav District in Revendreth", "Madame Miriana is a venthyr located in the Redelav District in Revendreth. She walks between the Duskmire Domain and the Sinfang Parlor." },
  ["madame relia"] = { 2, "venthyr located in the Primrose Residence in Revendreth", "Madame Relia is a venthyr located in the Primrose Residence in Revendreth. She can be found talking with Duke Grigore." },
  ["madame sorina"] = { 2, "venthyr located in the Redelav District in Revendreth", "Madame Sorina is a venthyr located in the Redelav District in Revendreth. She can be found talking with Duke Mihas outside the Sourwine Estate." },
  ["madame tassa"] = { 2, "venthyr located in the Redelav District in Revendreth", "Madame Tassa is a venthyr located in the Redelav District in Revendreth." },
  ["madame viseta"] = { 2, "vulpera", "Madame Viseta is a vulpera." },
  ["madame viviana"] = { 2, "venthyr located in the Redelav District in Revendreth", "Madame Viviana is a venthyr located in the Redelav District in Revendreth. She is escorted by two Stone Legion Protectors." },
  ["maddened blackwood"] = { 2, "', "Maddened Blackwoods are Blackwood furbolgs found in the Twilight Vale in Darkshore." },
  ["maddened blackwood (war of the thorns)"] = { 2, "', "Maddened Blackwoods are furbolgs located in the Blackwood Den in Darkshore during the War of the Thorns. They were attacked by the Horde adventurer so that they could take the land." },
  ["maddi"] = { 2, "venthyr located in Darkhaven in Revendreth", "Maddi is a venthyr located in Darkhaven in Revendreth." },
  ["madoran bronzebeard"] = { 2, "ruling thane of Ironforge", "Madoran Bronzebeard was the ruling thane of Ironforge and the Bronzebeard clan before and during the War of the Three Hammers. The Bronzebeard clan, ruled by Thane Madoran Bronzebeard, held close ties to the High King and stood as the traditional ..." },
  ["madstitch surgeon"] = { 2, "', "Madstitch Surgeons are undead located in Maldraxxus." },
  ["maedin"] = { 2, "tortollan located in Maedin's Challenge in Nazjatar", "Maedin is a tortollan located in Maedin's Challenge in Nazjatar." },
  ["mael shelub"] = { 2, "bitter", "Mael Shelub is a bitter and cruel nerubian necromancer. He despises everyone, especially the Lich King and the Scourge, and though still alive - unlike many of his kin - he prefers the company of the dead rather than the living." },
  ["maelgwyn"] = { 2, "worgen fighting Iron Horde Grunts alongside many others a...", "Maelgwyn is a worgen fighting Iron Horde Grunts alongside many others at the Dark Portal in Blasted Lands and Tanaan Jungle. He died after the portal was destroyed." },
  ["maera ashyld"] = { 2, "Arathi lamplighter located in Hallowfall", "Maera Ashyld is an Arathi lamplighter located in Hallowfall. She and her lynx, Magpie, are generally in charge of clearing the sky in the Stagnant Mire during their Lamplighting route." },
  ["maeryl vlann"] = { 2, "Arathi located in Mereldar in Hallowfall", "Maeryl Vlann is an Arathi located in Mereldar in Hallowfall." },
  ["maetild saberkrags"] = { 2, "Arathi located at Wildcamp Ul'ar in Azj-Kahet", "Maetild Saberkrags is an Arathi located at Wildcamp Ul'ar in Azj-Kahet." },
  ["maeve barleybrew"] = { 2, "dwarf", "Maeve Barleybrew is a dwarf who stands beside the Barleybrew tent advertising their particular brews at the Brewfest Grounds in Dun Morogh. If you pick up a  [Alcohol-Free Brewfest Sampler] and throw it, the Brewmaidens will toss you another refill." },
  ["magdala copperpick"] = { 2, "dwarf general goods vendor in the Alliance held Amber Cav...", "Magdala Copperpick is a dwarf general goods vendor in the Alliance held Amber Caverns in the Temple of Earth in Deepholm." },
  ["mage lord gogg'nathog"] = { 2, "summonable Garrison raid boss using  [Arcane Highmaul Relic]", "Mage Lord Gogg'nathog is a summonable Garrison raid boss using  [Arcane Highmaul Relic] that can be obtained during a successfully-repelled Ogre invasion." },
  ["mage talon"] = { 2, "', "Mage Talons are dracthyr found in Stormsunder Crater outside the Siege Creche and outside Froststone Vault in the Forbidden Reach." },
  ["magera"] = { 2, "dracthyr located at the Gardens of Unity in Thaldraszus", "Magera is a dracthyr located at the Gardens of Unity in Thaldraszus. She is found chatting with Herac." },
  ["maggie 'slither' masterson"] = { 2, "Forsaken located at Deliverance Point in the Broken Shore", "Maggie 'Slither' Masterson is a Forsaken located at Deliverance Point in the Broken Shore. She is in charge of managing the Nether Disruptor." },
  ["maggot eye"] = { 2, "Rot Hide gnoll found in a house at Garren's Haunt in Tiri...", "Maggot Eye is a Rot Hide gnoll found in a house at Garren's Haunt in Tirisfal Glades." },
  ["maggran earthbinder"] = { 2, "tauren quest giver", "Maggran Earthbinder is a tauren quest giver and leader of Sun Rock Retreat in the Stonetalon Mountains. He once fell prey to Besseleth but escaped." },
  ["maggrul"] = { 2, "drogbar located in Cascades Column in Zaralek Cavern", "Maggrul is a drogbar located in Cascades Column in Zaralek Cavern." },
  ["magistrate bluntnose"] = { 2, "dwarf quest giver located in Thelsamar in Loch Modan", "Magistrate Bluntnose is a dwarf quest giver located in Thelsamar in Loch Modan." },
  ["magistrate henry maleb"] = { 2, "elite worgen located inside Shadowfang Keep", "Magistrate Henry Maleb is an elite worgen located inside Shadowfang Keep, in Silverpine Forest." },
  ["magma mystic"] = { 2, "Shadowed Crucible", "Magma Mystics are djaradin located in Aberrus, the Shadowed Crucible." },
  ["magmaster blastcrank"] = { 2, "goblin located at Lor'danel Landing in Darkshore during t...", "Magmaster Blastcrank is a goblin located at Lor'danel Landing in Darkshore during the Battle for Darkshore." },
  ["magni bronzebeard (film universe)"] = { 2, "King of dwarves", "Magni Bronzebeard is the King of dwarves and Ironforge." },
  ["magorn"] = { 2, "innkeeper located at Bouldercrag's Refuge in the Storm Peaks", "Magorn is an innkeeper located at Bouldercrag's Refuge in the Storm Peaks. He is an earthen of Ulduar and as such is friendly to both the Alliance and the Horde." },
  ["magra"] = { 2, "undead centaur found in Desolace", "Magra was an undead centaur found in Desolace. In life he was the third alleged offspring of Zaetar and Theradras, and also the first Khan of the Magram clan, which is named after him." },
  ["magram defender"] = { 2, "', "Magram Defenders are centaur who rapidly spawn to attack the Spear of the Kolkar Khan in Desolace's Magram Territory during  [10-30] Delicate Negotiations. The player needs to hold them off with the help of the Kolkar Warmongers to keep the spear ..." },
  ["magram marauder"] = { 2, "', "Magram Marauders are centaur found at the Magram Village in southeast Desolace." },
  ["magram mauler"] = { 2, "', "Magram Maulers are centaur found at the Magram Village in southeast Desolace." },
  ["magram outrunner"] = { 2, "', "Magram Outrunners are centaur found at Magram Village in southeast Desolace." },
  ["magram pack runner"] = { 2, "', "Magram Pack Runners are centaur found at Magram Village in southeast Desolace. They have 2 Magram Bonepaws as pets." },
  ["magram scout"] = { 2, "', "Magram Scouts are centaur found at the Magram Village in southeast Desolace." },
  ["magram stormer"] = { 2, "', "Magram Stormers are centaur found at the Magram Village in southeast Desolace." },
  ["magram warden"] = { 2, "centaur", "The Magram Warden is a centaur who guards a pen full of Kolkar Prisoners south of Magram Territory in Desolace. Aggroing him automatically aggros two nearby Magram Wranglers as well." },
  ["magram windchaser"] = { 2, "', "Magram Windchasers are centaur found at the Magram Territory in eastern Desolace. Prior to the Cataclysm they were found at the Magram Village in the southeast part of the zone." },
  ["magram wrangler"] = { 2, "', "Magram Wranglers are centaur found at the Magram Village in southeast Desolace." },
  ["magronos the unyielding"] = { 2, "rare mob ogre in the Blasted Lands", "Magronos the Unyielding is a rare mob ogre in the Blasted Lands." },
  ["magsy bootstrap"] = { 2, "goblin located at Venturewood in the Undermine", "Magsy Bootstrap is a goblin located at Venturewood in the Undermine." },
  ["magtoor"] = { 2, "Broken located at the Harborage in the Swamp of Sorrows", "Magtoor is a Broken located at the Harborage in the Swamp of Sorrows." },
  ["magtor the blind watcher"] = { 2, "furbolg located at Stillpine Hold in Azuremyst Isle", "Magtor the Blind Watcher is a furbolg located at Stillpine Hold in Azuremyst Isle. He is one of the many who journey to Blood Watch to celebrate the hero of Bloodmyst and Azuremyst." },
  ["magub"] = { 2, "ogre vendor located at the Highmaul in Nagrand", "Magub is an ogre vendor located at the Highmaul in Nagrand." },
  ["magus araana"] = { 2, "draenei located at", "Magus Araana is a draenei located at Andorhal in The Deaths of Chromie scenario." },
  ["mahaja cloudsong"] = { 2, "tauren located at the Gala of Gifts in Durotar during Lov...", "Mahaja Cloudsong is a tauren located at the Gala of Gifts in Durotar during Love is in the Air." },
  ["mahala cloudsong"] = { 2, "tauren shaman trainer of the Cloudsong tribe; she can be ...", "Mahala Cloudsong is a tauren shaman trainer of the Cloudsong tribe; she can be found alongside Mala Skywatcher in the Apothecarium of the Undercity. She's been the second Horde shaman trainer in the to be added in the Eastern Kingdoms, the first b..." },
  ["mahara goldwheat"] = { 2, "tauren cooking trainer located in Thunder Bluff during Pi...", "Mahara Goldwheat is a tauren cooking trainer located in Thunder Bluff during Pilgrim's Bounty." },
  ["maiden of shadows"] = { 2, "abode of the undead Lord Talendar", "The Maidens of Shadows were six elven spellcasters within the Tomb of the Ancients in Dustwallow Marsh, the abode of the undead Lord Talendar. They were led by the Mistress of Shadows, and defended Lord Talendar, whos tomb they resided in." },
  ["maim blackhand"] = { 2, "son of the former Warchief Blackhand the Destroyer", "Maim Blackhand was the son of the former Warchief Blackhand the Destroyer and the brother of Dal'rend and Griselda. Along with Dal'rend, Maim served as the co-leader of the Black Tooth Grin clan until his death in Blackrock Mountain." },
  ["mairinn boulderbreaker"] = { 2, "dwarf located in Olivia's Pond in Stormwind City during t...", "Mairinn Boulderbreaker is a dwarf located in Olivia's Pond in Stormwind City during the Love is in the Air event. She is surrounded by several pets - Cats, Dogs, Playful Fawn, and Pettable Critters and directs adventurers to relax during the quest..." },
  ["majo"] = { 2, "tortollan located at Norwington Estate in Tiragarde Sound", "Majo is a tortollan located at Norwington Estate in Tiragarde Sound. He also appears at Turtle Beach in the Krasarang Wilds during the Wanderer's Festival." },
  ["makaba flathoof"] = { 2, "tauren quest giver is found at Camp Una'fe in the Norther...", "Makaba Flathoof is a tauren quest giver is found at Camp Una'fe in the Northern Barrens, after having escaped the assault on Honor's Stand. He comes from Camp Aparaje." },
  ["makael bay"] = { 2, "Horde goblin found in at the unnamed Horde triage camp in...", "Makael Bay is a Horde goblin found in at the unnamed Horde triage camp in western Pei-Wu Forest on the Wandering Isle." },
  ["makasa flintwill"] = { 2, "human girl", "Makasa Flintwill is a human girl who comes from Booty Bay, with her ancestors coming from Stromgarde. She is a capable hunter and tracker." },
  ["makhul"] = { 2, "centaur located at Timberstep Outpost in the Ohn'ahran Pl...", "Makhul is a centaur located at Timberstep Outpost in the Ohn'ahran Plains." },
  ["makir"] = { 2, "earthen located in the Forgegrounds in Dornogal", "Makir is an earthen located in the Forgegrounds in Dornogal." },
  ["maktu"] = { 2, "Broken armor vendor located at Orebor Harborage in Zangar...", "Maktu is a Broken armor vendor located at Orebor Harborage in Zangarmarsh. He always refers to himself in third person." },
  ["maku"] = { 2, "haranir located in the Den in Harandar", "Maku is a haranir located in the Den in Harandar. He sells housing decor in exchange for  [Voidlight Marl]." },
  ["makuru"] = { 2, "Broken quest giver located at the Temple of Telhamat in t...", "Makuru is a Broken quest giver located at the Temple of Telhamat in the Hellfire Peninsula." },
  ["makusha"] = { 2, "mother of the tuskarr Taruka", "Makusha is the mother of the tuskarr Taruka and Unka, left to care for them after their father died at sea. The night before their clan began their journey to Kamagua, the three had a dinner which, as often happened, was not a happy occasion." },
  ["mal'aga"] = { 2, "naga representative", "Mal'aga was a naga representative that told the Gnomeregan Gnews Gnetwork that the naga's activities were not damaging to the ecology of Zangarmarsh. He was supported by the independent environmental expert Mr." },
  ["malar bravehorn"] = { 2, "tauren member of the Argent Dawn", "Malar Bravehorn is a tauren member of the Argent Dawn and was taken prisoner by the Scarlet Crusade in the Scarlet Enclave. When the death knights of Acherus invaded the Enclave, the prisoners traded owners." },
  ["malaya dawnchaser"] = { 2, "tauren innkeeper found at Thunder Cleft in Krasarang Wilds", "Malaya Dawnchaser is a tauren innkeeper found at Thunder Cleft in Krasarang Wilds. She is a member of the Dawnchaser tribe, which traveled to Pandaria in search of a dreamed paradise." },
  ["maldraxxi harvester"] = { 2, "', "Maldraxxi Harvesters are undead located in Desmotaeron in the Maw." },
  ["malevolent stonekeeper"] = { 2, "', "Malevolent Stonekeepers are venthyr located at Stalker's Lodge in Revendreth." },
  ["malformed defias drone"] = { 2, "undead guarding Klaven Mortwake's tower in Westfall", "The Malformed Defias Drone was an undead guarding Klaven Mortwake's tower in Westfall. The two Defias Tower Patrollers Jill and Raven feared ending up as drones if they slacked in their guard duties." },
  ["malgen longspear"] = { 2, "centaur hunter", "Malgen Longspear is a centaur hunter, and is part of Theldren's team of gladiators at the Blackrock Depths arena. He has a pet called Gnashjaw." },
  ["malgin barleybrew"] = { 2, "rare dwarf found in the Bael Modan Excavation", "Malgin Barleybrew is a rare dwarf found in the Bael Modan Excavation, on a platform overlooking the digsite, just east of the chasm in the Southern Barrens. He was standing behind a bar in Bael Modan before the Cataclysm." },
  ["malicia"] = { 2, "dracthyr located in the Gladiator's Refuge in Valdrakken", "Malicia is a dracthyr located in the Gladiator's Refuge in Valdrakken. She sells equipment and consumables in return for  [Bloody Tokens]." },
  ["malicious hopebreaker"] = { 2, "', "Malicious Hopebreakers are venthyr located at Stalker's Lodge in Revendreth." },
  ["malifron"] = { 2, "dracthyr located at Nelthazan Ruins in the Ohn'ahran Plains", "Malifron is a dracthyr located at Nelthazan Ruins in the Ohn'ahran Plains. He and Urazeras are clutchmates." },
  ["malik the unscathed"] = { 2, "mantid paragon found in the Dread Wastes", "\"Heroes never die.\" Malik the Unscathed is a mantid paragon found in the Dread Wastes. First found and awakened in the Clutches of Shek'zeer he proceeds to Klaxxi'vess to aid the Klaxxi." },
  ["malinor"] = { 2, "dracthyr located in the Pitch in Algeth'ar Academy", "Malinor is a dracthyr located in the Pitch in Algeth'ar Academy." },
  ["malrogg"] = { 2, "drogbar located in a cave in Cascades Column in Zaralek C...", "Malrogg is a drogbar located in a cave in Cascades Column in Zaralek Cavern. He is the former boss of Agrul." },
  ["malspawn harbinger"] = { 2, "nerubian located at Silver Landing on the Isle of Quel'Da...", "Malspawn Harbinger is a nerubian located at Silver Landing on the Isle of Quel'Danas during the assault by the Devouring Host." },
  ["maluc"] = { 2, "earthen located in Freywold Village on the Isle of Dorn", "Maluc is an earthen located in Freywold Village on the Isle of Dorn." },
  ["malukh"] = { 2, "earthen located in the Forgegrounds in Dornogal", "Malukh is an earthen located in the Forgegrounds in Dornogal." },
  ["mamdy the 'ologist'"] = { 2, "ethereal quest giver located inside the entrance of the M...", "Mamdy the 'Ologist' is an ethereal quest giver located inside the entrance of the Mana-Tombs in Auchindoun. He was originally found in Terokkar Forest." },
  ["mammoth-tamer tavok"] = { 2, "djaradin located at Emberflow in the Waking Shores", "Mammoth-Tamer Tavok is a djaradin located at Emberflow in the Waking Shores." },
  ["mana-debt slave"] = { 2, "', "Mana-Debt Slaves are slaves of the Bash'ir ethereals in the Blade's Edge Mountains. A Bash'ir Arcanist will occasionally call several of them in to realign the Bash'ir Crystalforge at Bash'ir Landing." },
  ["manape"] = { 2, "tuskarr located on the expedition isles", "Manape is a tuskarr located on the expedition isles." },
  ["manchu"] = { 2, "mogu found in the Throne of Thunder", "Manchu is a mogu found in the Throne of Thunder." },
  ["maneo"] = { 2, "venthyr located in Pridefall Hamlet in Revendreth", "Maneo is a venthyr located in Pridefall Hamlet in Revendreth." },
  ["mange the outcast"] = { 2, "gnoll located in the Azure Span", "Mange the Outcast is a gnoll located in the Azure Span." },
  ["mangletooth"] = { 2, "quilboar", "Mangletooth is a quilboar and the new leader of the Razormane tribe in the Southern Barrens. Before escaping Camp Taurajo, he was a quest giver tasking Horde adventurers with killing of the other quilboar." },
  ["manor leecher"] = { 2, "', "Manor Leechers are venthyr located at the Caretaker's Manor in Revendreth." },
  ["mantid warrior"] = { 2, "mantid ghost located in the Temple of Humility in Bastion...", "Mantid Warrior is a mantid ghost located in the Temple of Humility in Bastion during  [60WQ] Limbo. He is a commander of a battalion and was allowed to return to life, upon which he defeated a necromancer that was wreaking havoc in the warrior's h..." },
  ["maokka"] = { 2, "tortollan located at the Jeweled Coast in Stormsong Valley", "Maokka is a tortollan located at the Jeweled Coast in Stormsong Valley, seen bathing a Sandbill Piper. He later appeared in Rustbolt on Mechagon Island." },
  ["maoli"] = { 2, "tortollan located at the Wild Coast in the Waking Shores", "Maoli is a tortollan located at the Wild Coast in the Waking Shores." },
  ["mar'kag"] = { 2, "ogre located in Black Tooth Hovel in the Burning Steppes", "Mar'kag is an ogre located in Black Tooth Hovel in the Burning Steppes." },
  ["maraclozh"] = { 2, "nerubian located in the City of Threads", "Maraclozh is a nerubian located in the City of Threads." },
  ["maragor"] = { 2, "mogu in the Crypt of Forgotten Kings scenario on heroic only", "Maragor is a mogu in the Crypt of Forgotten Kings scenario on heroic only." },
  ["maraudine khan advisor"] = { 2, "centaur", "The Maraudine Khan Advisor is a centaur who spawns to defend the Maraudine War Horn in the Valley of Spears in Desolace during the quest Khan Hratha." },
  ["maraudine khan guard"] = { 2, "', "Maraudine Khan Guards are centaur who spawn to defend the Maraudine War Horn in the Valley of Spears in Desolace during the quest Khan Hratha." },
  ["maraudine marauder"] = { 2, "', "Maraudine Marauders are found in the Valley of Spears" },
  ["maraudine mauler"] = { 2, "', "Maraudine Maulers are centaur found in the Valley of Spears in Desolace." },
  ["maraudine pack runner"] = { 2, "centaur", "Maraudine Pack Runner is a centaur." },
  ["maraudine priest"] = { 2, "', "Maraudine Priests are centaurs found in the tunnels outside Maraudon in Desolace." },
  ["maraudine scout"] = { 2, "', "Maraudine Scouts are centaur found in the Valley of Spears in Desolace." },
  ["maraudine stormer"] = { 2, "', "Maraudine Stormers are centaur found in the Valley of Spears in Desolace." },
  ["maraudine windchaser"] = { 2, "', "Maraudine Stormers are centaur found in the Valley of Spears in Desolace." },
  ["maraudine wrangler"] = { 2, "', "Maraudine Wranglers are centaur found in the Valley of Spears in Desolace." },
  ["maraudos"] = { 2, "fourth alleged offspring of Zaetar", "Maraudos elite undead centaur found in Maraudon. In life he was the fourth alleged offspring of Zaetar and Theradras, and also the first Khan of the Maraudine clan, which is named after him." },
  ["marbb"] = { 2, "earthen leatherworking trainer located in the Forgeground...", "Marbb is an earthen leatherworking trainer located in the Forgegrounds in Dornogal." },
  ["marcus auralion"] = { 2, "draenei located at Crimson Watch in Shadowmoon Valley", "Marcus Auralion is a draenei located at Crimson Watch in Shadowmoon Valley. Judging by his title, Auralion was the commander of the Sha'tar forces under Xi'ri that laid siege to Illidan Stormrage's Black Temple." },
  ["marcus dominar"] = { 2, "', "Template:Worldbreaker TCG" },
  ["marcus redpath"] = { 2, "independent undead", "Marshal Marcus Redpath was an independent undead, newly raised by the Forsaken in Deathknell. In life, he was the marshal (formerly headman) of the town of Southshore." },
  ["mardigan"] = { 2, "worgen warrior", "Mardigan is a worgen warrior and the son of Karlain, a mage. He is young, ill-tempered, lacks discipline, and has on at least one occasion gotten into a bar fight." },
  ["mardin falster"] = { 2, "vrykul located in Stormheim", "Mardin Falster is a vrykul located in Stormheim." },
  ["marduk blackpool"] = { 2, "infamous death knight of the Scourge", "Marduk Blackpool, also known as Marduk the Black, was an infamous death knight of the Scourge. He was perhaps most notable for his involvement in the Battle of Darrowshire during the Third War, where he sealed the humans' defeat by corrupting the ..." },
  ["marga bearbrawn"] = { 2, "dwarf Strand of the Ancients battlemaster located in the ...", "Marga Bearbrawn was a dwarf Strand of the Ancients battlemaster located in the Hall of Arms in the Military Ward in Ironforge. She only appeared during the Call to Arms: Strand of the Ancients." },
  ["margaeret glynnpray"] = { 2, "Arathi located in Wildcamp Or'lay in Azj-Kahet", "Margaeret Glynnpray is an Arathi located in Wildcamp Or'lay in Azj-Kahet." },
  ["margul"] = { 2, "drogbar innkeeper located in the Stonedark Grotto in High...", "Margul is a drogbar innkeeper located in the Stonedark Grotto in Highmountain." },
  ["margulf blaggon"] = { 2, "dwarven miner", "Margulf Blaggon is a dwarven miner and author, who spent most his time digging for ore in the mountains of Khaz Modan a few decades before World of Warcraft. During his time there he wrote the book The Stresses of Iron, which players seeking to he..." },
  ["marie allen"] = { 2, "human general goods vendor found at various locations thr...", "Marie Allen is a human general goods vendor found at various locations throughout Gilneas, including the Allen Farmstead. She was first met in Gilneas City, then she moved to Duskhaven after the capital fell to the worgen." },
  ["marie claire antoinette"] = { 2, "', "Marie Claire Antoinette, Linda, and Jillian flirt with Prince Arthas Menethil in Brill, Alterac." },
  ["marine anderson"] = { 2, "soldier onboard the Lady Mehley", "Marine Anderson is a soldier onboard the Lady Mehley, the boat that runs between Theramore Isle and Menethil Harbor. Anderson is a member of the Theramore Marines, and was assumed to be onboard for the protection of the crew." },
  ["marisda"] = { 2, "earthen vendor located in Freywold Village on the Isle of...", "Marisda is an earthen vendor located in Freywold Village on the Isle of Dorn." },
  ["marithos"] = { 2, "dracthyr located in Zaralek Cavern", "Marithos is a dracthyr located in Zaralek Cavern. He, Amythora, and Winglord Dezran accompanied Scalecommander Sarkareth to Nal ks'kol in his quest to secure Neltharion's legacy for the Sundered Flame." },
  ["marja lenglow"] = { 2, "Arathi located in Mereldar in Hallowfall", "Marja Lenglow is an Arathi located in Mereldar in Hallowfall. She plays Light's Gambit with Faerin Lothar." },
  ["marjani flintwill"] = { 2, "human pirate captain of the Makemba of the Blackwater Rai...", "Marjani Flintwill is a human pirate captain of the Makemba of the Blackwater Raiders's fleet. She is very capable with various weapons." },
  ["marjuk"] = { 2, "ogre commander of the Dire Maul Gordunni clan", "Marjuk was an ogre commander of the Dire Maul Gordunni clan. He and Wordok had the same roles - capturing slaves for King Gordok's arena fights." },
