  ["marksman bova"] = { 2, "draenei located at the Aldor Rise in Shattrath City", "Marksman Bova is a draenei located at the Aldor Rise in Shattrath City." },
  ["markus hjolbruk"] = { 2, "vrykul innkeeper located at Jandvik in Suramar", "Markus Hjolbruk is a vrykul innkeeper located at Jandvik in Suramar. After completing  [45] Turning the Tidemistress, Recipe: Koi-Scented Stormray will be added to his inventory." },
  ["marla"] = { 2, "worgen located in the Trader's Hall in Trade District in ...", "Marla is a worgen located in the Trader's Hall in Trade District in Stormwind City. During the Auction House Dance Party event, Marla hijacks the auction house." },
  ["marla fipps"] = { 2, "human buried at Deathknell in Tirisfal Glade", "Marla Fipps is a human buried at Deathknell in Tirisfal Glade. She would be killed by her undead husband but she loved him so much that she wanted him to be buried with her as her final wish." },
  ["marleth barleybrew"] = { 2, "dwarf quest giver located in Kharanos in Dun Morogh", "Marleth Barleybrew is a dwarf quest giver located in Kharanos in Dun Morogh. Before the Cataclysm, she was located in Brewnall Village." },
  ["marline"] = { 2, "kobold located in Campalot in the Ringing Deeps", "Marline is a kobold located in Campalot in the Ringing Deeps." },
  ["marlowe algerson"] = { 2, "human located at Hatherford in Tiragarde Sound", "Marlowe Algerson is a human located at Hatherford in Tiragarde Sound. She brings flowers to the grave of her mother, Petula, who was recently killed for being the witch that caused trouble at Algerson Lumber Yard." },
  ["marootu"] = { 2, "tuskarr fish vendor located in Kauriq Gleamlet in the Azu...", "Marootu is a tuskarr fish vendor located in Kauriq Gleamlet in the Azure Span." },
  ["marosh the devious"] = { 2, "furbolg found in Twilight Vale in Darkshore", "Marosh the Devious is a furbolg found in Twilight Vale in Darkshore. Marosh is one of the furbolgs that spawns to attack Sentinel Aynasha, during the quest  [5-30] One Shot." },
  ["marquis pummeler"] = { 2, "venthyr located in the Desiccation in Revendreth", "Marquis Pummeler is a venthyr located in the Desiccation in Revendreth." },
  ["marquis shattereye"] = { 2, "venthyr located in Revendreth", "Marquis Shattereye is a venthyr located in Revendreth." },
  ["marrlok"] = { 2, "ogre companion available from the Trading Post for 500  [...", "Marrlok is an ogre companion available from the Trading Post for 500  [Trader's Tender]. He first appeared in June 2024." },
  ["marsh flesheater"] = { 2, "', "Marsh Flesheaters are murlocs located in the Swamp of Sorrows." },
  ["marsh inkspewer"] = { 2, "', "Marsh Inkspewers are murlocs located in the Swamp of Sorrows." },
  ["marsh murkdweller"] = { 2, "', "Marsh Murkdwellers are murlocs." },
