  ["marsh oracle"] = { 2, "', "Marsh Oracles are murlocs located in the Swamp of Sorrows." },
  ["marshal bluewall"] = { 2, "dwarf quest giver located at the Hive'Zora Alliance camp ...", "Marshal Bluewall is a dwarf quest giver located at the Hive'Zora Alliance camp in Silithus. This section concerns content related to Legion." },
  ["marshal jacob alerius"] = { 2, "human located in the Silver Covenant Pavilion of the Arge...", "Marshal Jacob Alerius is a human located in the Silver Covenant Pavilion of the Argent Tournament Grounds in Icecrown as part of the Argent Tournament. This section concerns content related to Shadowlands." },
  ["marshal jacob alerius (tactics)"] = { 2, "boss of the Trial of the Champion in the Crusaders' Coliseum", "Marshal Jacob Alerius is a boss of the Trial of the Champion in the Crusaders' Coliseum. Like every Alliance champion, he is only encountered by Horde players." },
  ["marshal layre"] = { 2, "worgen located at Brackish Coast in Drustvar", "Marshal Layre is a worgen located at Brackish Coast in Drustvar. She only appears when the world quest  [50WQ] Dogged Tenacity is active, during which she is initially un-attackable until the Gilnean camp has been adequately assaulted." },
  ["marshfin murkdweller"] = { 2, "', "Marshfin Murkdwellers are murlocs located in the Swamp of Sorrows." },
  ["marta finespindle"] = { 2, "gnome quest giver located in the Military Ward in Ironforge", "Marta Finespindle was a gnome quest giver located in the Military Ward in Ironforge." },
  ["martar the not-so-smart"] = { 2, "gnoll", "Martar the Not-So-Smart is a gnoll who patrols in a circle in the open area between Sri-La Village and the Arboretum in the northeastern Jade Forest. He has a chance to drop  [Martar's Magnifying Glass], which summons him to aid you, as well as se..." },
  ["maru"] = { 2, "tuskarr child found outside the Caverns of Time in Tanari...", "Maru is a tuskarr child found outside the Caverns of Time in Tanaris during the Bronze Celebration, alongside Benatauk and Enzo. Adventurers assisted her and Enzo in locating a torch that was supposedly stolen by Ratts." },
  ["maruff grandhorn"] = { 2, "tauren healer", "Maruff Grandhorn is a tauren healer. He is the friend of of the high elf Leanine Starborn." },
  ["maruk the volcano"] = { 2, "ogre located in Molten Cay", "Maruk the Volcano is an ogre located in Molten Cay." },
  ["marus"] = { 2, "rare mob worgen found patrolling around the Rotting Orchard", "Marus is a rare mob worgen found patrolling around the Rotting Orchard and a small hidden area containing his cave and a few Nightbane Shadow Weavers. He sleeps in the cave between patrols." },
  ["maruu"] = { 2, "tuskarr child located in Kauriq Gleamlet in the Azure Span", "Maruu is a tuskarr child located in Kauriq Gleamlet in the Azure Span. He occasionally stops by Marootu or can be seen riding Oon." },
  ["maruukai villager"] = { 2, "', "Maruukai Villagers are centaur located in Maruukai in the Nokhud Offensive." },
  ["mary allerton"] = { 2, "human cooking trainer found in Darnassus during Pilgrim's...", "Mary Allerton is a human cooking trainer found in Darnassus during Pilgrim's Bounty." },
  ["mary brown"] = { 2, "human deckhand on the Wavestrider", "Mary Brown was a human deckhand on the Wavestrider. She assisted Captain Greydon Thorne in the attack against the Bloodsail Buccaneers on the Sea King, personally freeing the captured crew, along with Durgan One-God." },
  ["mary oxworth"] = { 2, "worgen banker located throughout Gilneas", "Mary Oxworth is a worgen banker located throughout Gilneas. She is one of Krennan's patients." },
  ["marylis"] = { 2, "kyrian", "Marylis is a kyrian that is one of the trainees during the quests  [60] Training Our Forces,  [60] Training in Maldraxxus,  [60] Training in Revendreth, and  [60] Training in Ardenweald. Like the other covenant trainees, she appears in Korthia, lo..." },
  ["marz"] = { 2, "Maldraxxi abomination", "Marz is a Maldraxxi abomination who was created through Abominable Stitching by the Necrolord Covenant. He was once an ogre, whose soul was sent to Maldraxxus and became bound to this new abomination body that was given to him." },
  ["masat t'andr"] = { 2, "Broken leatherworking vendor located at the Harborage in ...", "Masat T'andr is a Broken leatherworking vendor located at the Harborage in the Swamp of Sorrows." },
  ["masha cliffwalker"] = { 2, "wife of High Chieftain Cliffwalker", "Masha Cliffwalker is the wife of High Chieftain Cliffwalker and mother to their son Orthus. During the questline in Stonetalon Mountains, she along with her husband and son are trying to protect Thal'darah Grove from Overlord Krom'gar's and Genera..." },
  ["masseur"] = { 2, "ogre located at the Serene Dreams Spa in Thaldraszus", "Masseur is an ogre located at the Serene Dreams Spa in Thaldraszus." },
  ["master aitokk"] = { 2, "orc quest giver formerly found in Dreadmaul Hold in the B...", "Master Aitokk is an orc quest giver formerly found in Dreadmaul Hold in the Blasted Lands. Aitokk fell during the Ironmarch attack on Nethergarde." },
  ["master angler karu"] = { 2, "representative of the Anglers sent to the Shrine of Two M...", "Master Angler Karu is a representative of the Anglers sent to the Shrine of Two Moons to recruit Horde. He can be found on the lower level of the Golden Terrace." },
  ["master assassin olric"] = { 2, "worgen", "Master Assassin Olric is a worgen." },
  ["master bier"] = { 2, "Forsaken first aid trainer located in the sanctuary area ...", "Master Bier is a Forsaken first aid trainer located in the sanctuary area of Peak of Serenity in Kun-Lai Summit. He is standing next to Master Lo, watching him fish." },
  ["master digger"] = { 2, "rare kobold", "Master Digger is a rare kobold that can be found in the innermost part of Jangolode Mine in Westfall. He is on a 1.5 - 2.5 hour respawn timer." },
  ["master engineer cogswing"] = { 2, "gnome located at the Strongarm Airstrip in the Jade Forest", "Master Engineer Cogswing is a gnome located at the Strongarm Airstrip in the Jade Forest. He's a mechanic specialized in gyrocopter upkeep." },
  ["master feardred"] = { 2, "rare satyr found in Azshara", "Master Feardred was a rare satyr found in Azshara." },
  ["master feng"] = { 2, "battle", "Discipline is not a war that is won. It is a battle, constantly fought." },
  ["master gardener dhurttig"] = { 2, "earthen located in Freywold Village on the Isle of Dorn", "Master Gardener Dhurttig is an earthen located in Freywold Village on the Isle of Dorn." },
  ["master j. capaldi"] = { 2, "deceased human buried at Barrowknoll Cemetery in Drustvar", "Master J. Capaldi is a deceased human buried at Barrowknoll Cemetery in Drustvar." },
  ["master longfang"] = { 2, "worgen rogue of the Uncrowned located in Deliverance Poin...", "Master Longfang is a worgen rogue of the Uncrowned located in Deliverance Point on the Broken Shore. He is in stealth standing next to Wiley the Black." },
  ["master machinist dunstan"] = { 2, "earthen in an ironstrider fought in the Hall of Awakening", "Master Machinist Dunstan is an earthen in an ironstrider fought in the Hall of Awakening." },
  ["master mechanic castpipe"] = { 2, "gnome quest giver located in Tinker Town in Ironforge", "Master Mechanic Castpipe is a gnome quest giver located in Tinker Town in Ironforge." },
  ["master sergeant biggins"] = { 2, "gnome PvP accessories vendor located in the Champions' Ha...", "Master Sergeant Biggins is a gnome PvP accessories vendor located in the Champions' Hall in Stormwind." },
  ["master sergeant fizzlebolt"] = { 2, "gnome located at the Scarab Dais in Silithus alongside Fi...", "Master Sergeant Fizzlebolt is a gnome located at the Scarab Dais in Silithus alongside Field Marshal Snowfall during the Call of the Scarab micro-holiday. Fizzlebolt, along with his Horde counterpart Senior Sergeant Kai'jin, is a callback to the m..." },
  ["master smith ared"] = { 2, "deceased draenei located in Fort Wrynn in Talador", "Master Smith Ared is a deceased draenei located in Fort Wrynn in Talador. Miall is his apprentice." },
  ["master woodsman anderhol"] = { 2, "human quest giver located at Amberpine Lodge in the Grizz...", "Master Woodsman Anderhol is a human quest giver located at Amberpine Lodge in the Grizzly Hills. He seems to be the leader of the lodge's woodsmen and responsible for keeping the lodge's food stores stocked." },
  ["mataus the wrathcaster"] = { 2, "undead warlock located at Tyr's Hand in the Eastern Plagu...", "Mataus the Wrathcaster is an undead warlock located at Tyr's Hand in the Eastern Plaguelands. He was formerly a human quest giver at Light's Hope Chapel." },
  ["matchmaker osila"] = { 2, "centaur of Clan Nokhud located on the eastern edge of the...", "Matchmaker Osila is a centaur of Clan Nokhud located on the eastern edge of the Field of Ferocity in the Ohn'ahran Plains. She is, apparently, responsible for matching pairs of young centaur, but has a much more flippant view of marriage tradition..." },
  ["mateos"] = { 2, "Forsworn kyrian", "Mateos is a Forsworn kyrian." },
  ["matilda brightlink"] = { 2, "dwarf woman located in the Eventide quarter of Dalaran", "Matilda Brightlink was a dwarf woman located in the Eventide quarter of Dalaran, inside the Langrom's Leather & Links. This section concerns content related to Mists of Pandaria." },
  ["matriarch bluepelt"] = { 2, "gnoll located in the Azure Span", "Matriarch Bluepelt is a gnoll located in the Azure Span. She has captured Prince Llane Wrynn." },
  ["matriarch ta'dolla"] = { 2, "broker", "Matriarch Ta'dolla is a broker. She is presumably the leader of Cartel Ta or at least someone powerful within the cartel." },
  ["matthew ackerman"] = { 2, "stable master for the Amberpine Lodge", "Matthew Ackerman is the stable master for the Amberpine Lodge, which is located in the Southwestern portion of the Grizzly Hills. He is a member of the Valiance Expedition." },
  ["matthew rabis"] = { 2, "worgen found in the Circle of Wills in Dalaran", "Matthew Rabis is a worgen found in the Circle of Wills in Dalaran. It is currently unknown if he survived Dalaran's destruction." },
  ["matthilde"] = { 2, "earthen located with Konraada", "Matthilde is an earthen located with Konraada and Reingard, on whose back she is resting a book, at the Stoneshaper's Atrium in Dornogal." },
  ["mattimeo twinstar"] = { 2, "Arathi vendor located in Wildcamp Or'lay in Azj-Kahet", "Mattimeo Twinstar is an Arathi vendor located in Wildcamp Or'lay in Azj-Kahet." },
  ["matumo brighthoof"] = { 2, "tauren located in Arathi Basin during Brawl: Comp Stomp f...", "Matumo Brighthoof is a tauren located in Arathi Basin during Brawl: Comp Stomp for Alliance players." },
  ["maul dethwidget"] = { 2, "gnome located at the Lunarfall in Shadowmoon Valley", "Maul Dethwidget is a gnome located at the Lunarfall in Shadowmoon Valley. He can only be recruited using the Headhunter's Harvest from Lunarfall Inn." },
  ["mawforged souljudge"] = { 2, "', "Mawforged Souljudges are Mawsworn kyrian located in the Sanctum of Domination during the fight against Sylvanas Windrunner." },
  ["mawsworn abductor"] = { 2, "', "Mawsworn Abductors are kyrian located in Ardenweald during  [60] The Battle of Ardenweald. If at any point the Maw Walker should stray too far from the battle, they will grab them and bring them back to the action." },
  ["mawsworn avenger"] = { 2, "Mawsworn kyrian guarding Watcher Havros in Perdition Hold...", "Mawsworn Avenger is a Mawsworn kyrian guarding Watcher Havros in Perdition Hold in the Maw." },
  ["mawsworn conqueror"] = { 2, "', "Mawsworn Conquerors are Mawsworn kyrian located at the Altar of Domination in the Maw. Maw guard versions are encountered by adventure companions in the Altar of Domination." },
  ["mawsworn darkcaster"] = { 2, "', "Mawsworn Darkcasters are Mawsworn kyrian located in the Maw." },
  ["mawsworn doubtcaller"] = { 2, "Doubtcaller will spawn alongside the layer boss on floor ...", "Mawsworn Doubtcallers are Mawsworn kyrian located in Torghast, Tower of the Damned. If the Backup torment is active, a Doubtcaller will spawn alongside the layer boss on floor five." },
  ["mawsworn gatekeeper (ardenweald)"] = { 2, "', "Mawsworn Gatekeepers are kyrian located in Ardenweald during  [60] The Battle of Ardenweald. They are found maintaining Maw Portals." },
  ["mawsworn harbinger"] = { 2, "', "Mawsworn Harbingers are Mawsworn kyrian located in the Seeker's Quorum of Korthia." },
  ["mawsworn harbinger (escape from the maw)"] = { 2, "', "Mawsworn Harbingers are located throughout the Maw during the Escape from the Maw." },
  ["mawsworn herald"] = { 2, "', "Mawsworn Heralds are Mawsworn kyrian located in Zereth Mortis." },
  ["mawsworn infuser"] = { 2, "', "Mawsworn Infusers are Mawsworn kyrian located at the Eye's Overlook in the Sanctum of Domination. They must be killed to draw the attention of the Eye of the Jailer." },
  ["mawsworn interceptor"] = { 2, "', "Mawsworn Interceptors are Maw guards located in the Tremaculum in the Maw, Skoldus Hall and the Upper Reaches of Torghast, Tower of the Damned, and the Sanctum of Domination. Mawsworn kyrian versions are encountered by adventure companions in the ..." },
  ["mawsworn kyrian"] = { 2, "', "Mawsworn Kyrian are Mawsworn kyrian located in Perdition Hold in the Maw." },
  ["mawsworn lancer"] = { 2, "', "Mawsworn Lancers are Mawsworn kyrian located at the Eye's Overlook in the Sanctum of Domination. They must be slain to draw the attention of the Eye of the Jailer." },
  ["mawsworn myrmidon"] = { 2, "', "Mawsworn Myrmidon are Mawsworn kyrian located in Cocyrus in the Maw. They are also seen swarming the airspace just before Korthia during  [60] Mysteries of the Maw." },
  ["mawsworn myrmidon (zereth mortis)"] = { 2, "', "Mawsworn Myrmidons are kyrian located in Zereth Mortis." },
  ["mawsworn overseer"] = { 2, "', "Mawsworn Overseers are Mawsworn kyrian located in the Maw." },
  ["mawsworn realmbinder"] = { 2, "', "Mawsworn Realmbinders are kyrian located in Ardenweald during  [60] The Battle of Ardenweald." },
  ["mawsworn realmbreaker"] = { 2, "', "Mawsworn Realmbreakers are kyrian located in Ardenweald during  [60] The Battle of Ardenweald. They are seen flying high above the battlefield." },
  ["mawsworn runemaster"] = { 2, "', "The Mawsworn Runemasters were two Mawsworn kyrian located at Desmotaeron in the Maw. They had come to drain Ve'brax of his essences." },
  ["mawsworn shackler (sanctum of domination)"] = { 2, "', "Mawsworn Shacklers are kyrian located at Eye's Overlook in the Sanctum of Domination. They must be slain to draw the attention of the Eye of the Jailer." },
  ["mawsworn skystrafer"] = { 2, "', "Mawsworn Skystrafers are kyrian located at the Path of Understanding in Korthia." },
  ["mawsworn soulbearer"] = { 2, "', "Mawsworn Soulbearers were Mawsworn kyrian located in Icecrown during Death Rising. Every ten minutes, they raise an undead boss from Wrath of the Lich King." },
  ["mawsworn tormentor"] = { 2, "', "Mawsworn Tormentors are Maw casters and kyrian located in the Beastwarrens in the Maw." },
  ["mawsworn vanquisher"] = { 2, "', "Mawsworn Vanquishers are Mawsworn kyrian located in the Maw." },
  ["mawsworn warden"] = { 2, "', "Mawsworn Wardens are Mawsworn kyrian located in Perdition Hold in the Maw." },
  ["mawsworn watcher"] = { 2, "', "Mawsworn Watchers are soul seekers located in the Crucible of the Damned in the Maw during the  [60B] Night Fae Assault." },
  ["mawsworn wingsoldier"] = { 2, "', "Mawsworn Wingsoldiers are Mawsworn kyrian located at Eye's Overlook in the Sanctum of Domination. They must be slain to draw the attention of the Eye of the Jailer." },
  ["max boomson"] = { 2, "goblin located at Fuselight-by-the-Sea in the Badlands", "Max Boomson is a goblin located at Fuselight-by-the-Sea in the Badlands. He appears to be working on schematics." },
  ["max catstalker"] = { 2, "tauren located in the Drag in Orgrimmar", "Max Catstalker is a tauren located in the Drag in Orgrimmar. He is being chased by Luke, while Ric is watching them." },
  ["max crits"] = { 2, "Forsaken rogue located at the Hall of Shadows in Dalaran", "Max Crits  is a Forsaken rogue located at the Hall of Shadows in Dalaran." },
  ["maxan anvol"] = { 2, "dwarf priest trainer located in Thunderbrew Distillery in...", "Maxan Anvol is a dwarf priest trainer located in Thunderbrew Distillery in Kharanos in Dun Morogh. As a priest of the Light, Maxan tests young students on their skills." },
  ["maxima blastenheimer"] = { 2, "gnome Darkmoon Faire cannoneer located at the Darkmoon Is...", "Maxima Blastenheimer is a gnome Darkmoon Faire cannoneer located at the Darkmoon Island, which is only available during the monthly Darkmoon Faire event. She operates the Blastenheimer 5000 Ultra Cannon." },
  ["maximillian velhan"] = { 2, "Arathi located at Velhan's Hall in Hallowfall", "Maximillian Velhan is an Arathi located at Velhan's Hall in Hallowfall. He is found with a few Velhanite Children upstairs in the main building as the threat of the kobyss arose." },
  ["maxwell caprina"] = { 2, "satyr disguised as a human in Bradensbrook in Val'sharah", "Maxwell Caprina is a satyr disguised as a human in Bradensbrook in Val'sharah. He can be exposed by paladins wielding the  [Truthguard] or by abilities to reveal demons." },
  ["maxx avalanche"] = { 2, "goblin shaman trainer first encountered near the KTC Head...", "Maxx Avalanche is a goblin shaman trainer first encountered near the KTC Headquarters in Kezan. He is later encountered at multiple points in the Lost Isles and finally at Bilgewater Harbor in Azshara." },
  ["maynard algerson"] = { 2, "human located at Algerson Lumber Yard in Tiragarde Sound", "Maynard Algerson is a human located at Algerson Lumber Yard in Tiragarde Sound." },
  ["mazarhai"] = { 2, "ethereal located in Tazavesh", "Mazarhai is an ethereal located in Tazavesh, the Veiled Market in K'aresh." },
  ["mazdon bizratchet"] = { 2, "goblin blacksmithing trainer", "Mazdon Bizratchet is a goblin blacksmithing trainer and vendor found behind Gallywix's Garage in Warspear of Ashran. He is sitting atop an anvil." },
  ["mead trader"] = { 2, "earthen located at the Crossroads Plaza on the Isle of Dorn", "Mead Trader is an earthen located at the Crossroads Plaza on the Isle of Dorn." },
  ["meadery patron"] = { 2, "', "Meadery Patrons are earthen located in Cinderbrew Meadery on the Isle of Dorn." },
  ["meadery representative"] = { 2, "', "Meadery Representatives are earthen located at the Councilward's Rise in Dornogal." },
  ["meat vendor"] = { 2, "broker located at the Gilded Landing in Tazavesh", "The Meat Vendor is a broker located at the Gilded Landing in Tazavesh, the Veiled Market." },
  ["meatball"] = { 2, "first encounter at Rank 4 in the Brawler's Guild during T...", "\"MEATBALL HUNGRY!!\" Meatball is the first encounter at Rank 4 in the Brawler's Guild during The War Within. He also becomes a follower as well as a champion for class orders." },
  ["meatgrinder sotok"] = { 2, "djaradin located in Scalecracker Keep in the Waking Shores", "Meatgrinder Sotok is a djaradin located in Scalecracker Keep in the Waking Shores." },
  ["meatgut"] = { 2, "ogre quest giver", "Meatgut is an ogre quest giver and vendor located at the Ring of Trials in Nagrand. He sells some food and water, but once his quest becomes unlocked his wares normally become unavailable." },
  ["meatpie"] = { 2, "ogre located at the Suntouched Pillar in Sholazar Basin", "Meatpie is an ogre located at the Suntouched Pillar in Sholazar Basin." },
  ["mebbo"] = { 2, "tortollan located at the Seekers' Vista in Stormsong Valley", "Mebbo is a tortollan located at the Seekers' Vista in Stormsong Valley. Mebbo rides a Trained Crab." },
  ["mechagon watcher"] = { 2, "ethereal located in Operation: Mechagon", "The Mechagon Watcher is an ethereal located in Operation: Mechagon." },
  ["mechanoranger cogspark"] = { 2, "gnome mounted on a mechanostrider located in Ruins of Lor...", "Mechanoranger Cogspark is a gnome mounted on a mechanostrider located in Ruins of Lordaeron during the Battle for Lordaeron." },
  ["meeki"] = { 2, "dead vulpera lying on the southernmost pier in the Port o...", "Meeki is a dead vulpera lying on the southernmost pier in the Port of Zem'lan in Vol'dun. He was a scout from Camp Lastwind who snuck into Zem'lan in order to figure out a route for Camp Lastwind's vulpera to steal the port's treasure, but he was ..." },
  ["meekoo"] = { 2, "tortollan located at the Seekers' Vista in Stormsong Valley", "Meekoo is a tortollan located at the Seekers' Vista in Stormsong Valley. He sits with a Hearthstone Board." },
  ["meela dawnstrider"] = { 2, "tauren shaman trainer located in Camp Narache in Mulgore", "Meela Dawnstrider is a tauren shaman trainer located in Camp Narache in Mulgore." },
  ["meerah"] = { 2, "vulpera initially encountered at the Vulpera Hideaway in ...", "Meerah is a vulpera initially encountered at the Vulpera Hideaway in Vol'dun. Throughout the Vol'dun storyline, she transports the adventurer and their companions through the desert using her carriage drawn by her two alpacas Dolly and Dot." },
  ["mehrdad"] = { 2, "ethereal quest giver located at Midrealm Post in the Neth...", "Mehrdad is an ethereal quest giver located at Midrealm Post in the Netherstorm." },
  ["meilosh"] = { 2, "furbolg tradeskill vendor (though accepts only  [Runecloth]", "Meilosh is a furbolg tradeskill vendor (though accepts only  [Runecloth] and  [Mooncloth] from players Friendly or above), tailoring trainer, and Cloth Quartermaster, located in the main chamber of Timbermaw Hold in Felwood. He is a member of the ..." },
  ["mekaru"] = { 2, "vulpera quest giver found next to a wagon west of the Bri...", "Mekaru is a vulpera quest giver found next to a wagon west of the Brine Basin in Vol'dun, next to Neri." },
  ["mekeda"] = { 2, "Broken quest giver located at the Refugee Caravan in Tero...", "Mekeda is a Broken quest giver located at the Refugee Caravan in Terokkar Forest. He is a Broken belonging to the Lower City faction." },
  ["melizza brimbuzzle"] = { 2, "goblin quest giver located in a cage in the northern Vall...", "Melizza Brimbuzzle is a goblin quest giver located in a cage in the northern Valley of Spears in Desolace." },
  ["melnan darkstone"] = { 2, "dwarf quest giver", "Melnan Darkstone is a dwarf quest giver who can be found patrolling around the Commons of Ironforge during the Darkmoon Faire." },
  ["melonee"] = { 2, "dracthyr located at the Serene Dreams Spa in Thaldraszus", "Melonee was a dracthyr located at the Serene Dreams Spa in Thaldraszus. She was replaced by Melonia." },
  ["melonia"] = { 2, "dracthyr located at the Serene Dreams Spa in Thaldraszus", "Melonia is a dracthyr located at the Serene Dreams Spa in Thaldraszus." },
  ["meng-do, strength of mountains"] = { 2, "mogu located in the Ruins of Ogudei in the Krasarang Wilds", "Meng-do, Strength of Mountains is a mogu located in the Ruins of Ogudei in the Krasarang Wilds." },
  ["menial laborer"] = { 2, "', "Menial Laborers are kobolds located in Darkflame Cleft." },
  ["mennu the betrayer"] = { 2, "', "After betraying his kind to the naga under Lady Vashj's rule, Mennu the Betrayer and many fellow Broken subordinates now guard the Slave Pens in Coilfang Reservoir. It is likely that many of the Broken found in cages throughout Coilfang Reservoir ..." },
  ["menov"] = { 2, "dracthyr located in the Azure Span", "Menov is a dracthyr located in the Azure Span." },
  ["meradyth lacke"] = { 2, "Arathi lamplighter located in a Flame's Radiance camp nea...", "Meradyth Lacke is an Arathi lamplighter located in a Flame's Radiance camp near Tenir's Ascent in Hallowfall." },
  ["mercatethel"] = { 2, "dracthyr located in the Parting Glass in Valdrakken", "Mercatethel is a dracthyr located in the Parting Glass in Valdrakken. This section concerns content related to The War Within." },
  ["mercenary acquisitionist"] = { 2, "broker", "Mercenary Aquisitionist is a broker that can replace the regular encounters in any delve that has the  [Nemesis Strongbox] affix during The War Within Season 3." },
  ["merchant derrook"] = { 2, "draenei vendor located outside Elodor in Shadowmoon Valley", "Merchant Derrook is a draenei vendor located outside Elodor in Shadowmoon Valley. He sells work tools to the locals." },
  ["merchant kooda"] = { 2, "tortollan located in Anyport in Drustvar", "Merchant Kooda is a tortollan located in Anyport in Drustvar. He also appears in the Krasarang Wilds." },
  ["merchant maku"] = { 2, "tortollan general goods vendor", "Merchant Maku is a tortollan general goods vendor and the right-hand passenger of the Mighty Caravan Brutosaur. On the other side of the brutosaur is the auctioneer Collector Unta." },
  ["merciless tormentor"] = { 2, "', "Merciless Tormentors are venthyr located at the Grand Palisade in Revendreth." },
  ["merd archfeld"] = { 2, "goblin quest giver located on the Cracked Coast in Vol'dun", "Merd Archfeld is a goblin quest giver located on the Cracked Coast in Vol'dun, where he is apparently in charge of a Bilgewater Cartel Azerite-extraction operation. He frequently argues with Nerin Solvis." },
  ["merea brighsteur"] = { 2, "Arathi located in Mereldar in Hallowfall", "Merea Brighsteur is an Arathi located in Mereldar in Hallowfall. Around her Mischievous Lynxes are sitting in boxes and wandering around the goods of the store." },
  ["mereldar ardent"] = { 2, "', "Mereldar Ardents are Arathi located in Mereldar in Hallowfall. One is seen fishing south of Mereldar." },
  ["mereldar bearer"] = { 2, "Arathi located in Mereldar in Hallowfall", "The Mereldar Bearer is an Arathi located in Mereldar in Hallowfall." },
  ["mereldar child"] = { 2, "Arathi", "The Mereldar Child is an Arathi who appears in Mereldar after reaching Renown level 22 with the Hallowfall Arathi. She follows the player around until they accept her quest." },
  ["mereldar citizen"] = { 2, "', "Mereldar Citizens are Arathi located throughout Mereldar in the Dawnbreaker. Some are found dead, and others appear as Webbed Victims." },
  ["mereldar gardener"] = { 2, "', "Mereldar Gardeners are Arathi located in Mereldar in Hallowfall." },
  ["mereldar sentry"] = { 2, "', "Mereldar Sentries are Arathi located in Mereldar in Hallowfall." },
  ["mereldar trader"] = { 2, "', "Mereldar Traders are Arathi located in Mereldar in Hallowfall." },
  ["meridith the mermaiden"] = { 2, "naga quest giver found in Tanaris", "Meridith the Mermaiden is a naga quest giver found in Tanaris. She was encountered during the Scepter of the Shifting Sands quest chain and could be found off the eastern part of Land's End Beach." },
  ["merla"] = { 2, "', "Merla is Murky's cousin that got lost and ended up in the Redridge Mountains and had a tadpole. Murky used this information to get the Everstill murlocs to fight the Hidden and the Burning Legion at the Hidden citadel in Hellfire Peninsula." },
  ["merra finklestorm"] = { 2, "gnome located by Waina Steelpaw in the Shrine of Seven Stars", "Merra Finklestorm is a gnome located by Waina Steelpaw in the Shrine of Seven Stars." },
  ["merrimack"] = { 2, "earthen located on the Isle of Dorn", "Merrimack is an earthen located on the Isle of Dorn." },
  ["merris deepforge"] = { 2, "dwarf located at the Alliance encampment at the outskirts...", "Merris Deepforge is a dwarf located at the Alliance encampment at the outskirts of the Ruins of Lordaeron during Battle for Lordaeron." },
  ["merrix"] = { 2, "Councilward of Dornogal", "Merrix is the Councilward of Dornogal and the leader of the Council of Dornogal, the ruling body of the earthen of Khaz Algar. Merrix's foremost responsibility is to protect all earthen, as it is the Edict he follows above all others." },
  ["merunth"] = { 2, "stasis-locked earthen located in the Abyssal Excavation i...", "Merunth is a stasis-locked earthen located in the Abyssal Excavation in the Ringing Deeps. Next to her is her plaque." },
  ["meryl felstorm"] = { 2, "ancient undead human sorcerer", "Meryl Felstorm (previously known as Meryl Winterstorm) is an ancient undead human sorcerer. He is an incredibly powerful magic user, with nearly three thousand years of experience, whose purpose has always been the protection of Azeroth." },
  ["messenger fishtail"] = { 2, "grummle", "Messenger Fishtail is a grummle who was sent by Chen Stormstout to find his niece Li Li. He found her in the Vale of Eternal Blossoms and delivered her a letter." },
  ["metal fan"] = { 2, "', "The Metal Fans are Forsaken fans of the Blight Boar band located on the Darkmoon Island." },
  ["metal lord mono-han"] = { 2, "mogu located on the Isle of Thunder", "Metal Lord Mono-Han is a mogu located on the Isle of Thunder." },
  ["mey"] = { 2, "tortollan located in northern Exile's Reach", "Mey is a tortollan located in northern Exile's Reach. He is found in a secret underwater cave under a waterfall." },
  ["mgglurky"] = { 2, "murloc located in Mrgl's Bar", "Mgglurky is a murloc located in Mrgl's Bar and Gill in Nazjatar. He is the establishment's cook." },
  ["mi'thk"] = { 2, "nerubian located in Siegehold in Azj-Kahet", "Mi'thk is a nerubian located in Siegehold in Azj-Kahet." },
  ["miblon snarltooth"] = { 2, "', "Miblon Snarltooth is gnoll guarding a nursery of  [Evoroot] plants on the eastern outskirts of the Ruins of Ravenwind in Feralas. The nursery is blocked by a door, but players can use  [Bait] (purchased from Gregan Brewspewer) to temporarily lure ..." },
  ["micah belford"] = { 2, "undead", "Micah Belford is an undead who briefly appears at Raven Hill Cemetery in Duskwood. He is a member of the Cult of Forgotten Shadows, guards the body of Natalie Seline, and assists the High Priest, sent by Alonsus Faol of the Conclave, in reviving h..." },
  ["michael bedernik"] = { 2, "worgen found in Star's Bazaar in the Shrine of Seven Stars", "Michael Bedernik is a worgen found in Star's Bazaar in the Shrine of Seven Stars. He can be seen either in his human form or in the worgen form." },
  ["michael green"] = { 2, "worgen", "Michael Green is a worgen." },
  ["michael schweitzer"] = { 2, "Forsaken", "Michael Schweitzer is a Forsaken and is the manager of The Tauren Chieftains. His friend, Steven Thomas, has come to visit him while he is in Silvermoon City with the band and organizing the band's latest tour." },
  ["mickde"] = { 2, "earthen located with Wedekind at Stoneward's Rise in Dorn...", "Mickde is an earthen located with Wedekind at Stoneward's Rise in Dornogal." },
  ["middles"] = { 2, "kobold located in Gundargaz in the Ringing Deeps", "Middles is a kobold located in Gundargaz in the Ringing Deeps." },
  ["midsummer celebrant"] = { 2, "festival reached there", "Midsummer Celebrants are celebrants of varying races found across Azeroth, Outland, and Draenor during the Midsummer Fire Festival. After the return to the Dragon Isles, the festival reached there and now drogbar at Zaralek Cavern celebrate it." },
  ["mightstone berserker"] = { 2, "', "Mightstone Berserkers are drogbar that appear in Snowmane Village in Highmountain during the attack on Snowblind Mesa." },
  ["mightstone breaker"] = { 2, "', "Mightstone Breakers are drogbar located at the Dragon's Spine, Stone Market, and Broken Teeth in Neltharion's Lair." },
  ["mightstone flanker"] = { 2, "', "Mightstone Flankers are drogbar located in Highmountain." },
  ["mightstone rockcaller"] = { 2, "', "Mightstone Rockcallers are drogbar located in Stormheim." },
  ["mightstone savage"] = { 2, "', "Mightstone Savages are drogbar located in the Valley of the Sword in Stormheim." },
  ["mightstone slinger"] = { 2, "', "Mightstone Slingers are drogbar located in Highmountain." },
  ["miglik blotstrom"] = { 2, "level 70 Arena battlemaster located in the Seat of the Na...", "Miglik Blotstrom was a level 70 Arena battlemaster located in the Seat of the Naaru in the draenei capital of the Exodar." },
  ["mihal"] = { 2, "nerubian warrior of the Sundered Monolith", "Mihal is a nerubian warrior of the Sundered Monolith. Along with Ul'Tomon the spiderlord, Mihal served as Brann Bronzebeard's guide during the latter's six-day stay in the Sundered Monolith." },
  ["miju"] = { 2, "tortollan located on a small island south-west of Xibala ...", "Miju is a tortollan located on a small island south-west of Xibala in Zuldazar. He knows how to craft special quills required for blood-scribing, having undergone the trial at the age 2372." },
  ["mikah brewbelly"] = { 2, "dwarf located in Mezzamere in Nazjatar", "Mikah Brewbelly is a dwarf located in Mezzamere in Nazjatar." },
  ["mikrin of the raging winds"] = { 2, "vulpera located in the Ohn'ahran Plains", "Mikrin of the Raging Winds is a vulpera located in the Ohn'ahran Plains." },
  ["mile raitheborne"] = { 2, "Forsaken warlock found in Dreadscar Rift", "Mile Raitheborne is a Forsaken warlock found in Dreadscar Rift. He researches the information of the artifact weapons and is both Head Researcher and Head Archivist of the Council of the Black Harvest, having authored the Tome of Blighted Implements." },
  ["miles corebender"] = { 2, "gnome warrior", "Miles Corebender is a gnome warrior who accompanied Kova Broadhorn on her quest for the reclusive orc seer Dhambeela. He accompanied Kova in the hopes that an epic song would be sung about him and his adventures." },
  ["milgrit stonefeather"] = { 2, "earthen flight master located at Shadowvein Point in the ...", "Milgrit Stonefeather is an earthen flight master located at Shadowvein Point in the Ringing Deeps." },
  ["militant stonecaller"] = { 2, "', "Militant Stonecallers are venthyr located in the Menagerie of the Master in Revendreth." },
  ["military purveyor"] = { 2, "', "Military Purveyors are brokers located in the Hall of Shapes in Oribos." },
  ["milli featherwhistle"] = { 2, "gnome", "Milli Featherwhistle is a gnome who sells mechanostrider mounts, located at Steelgrill's Depot just outside Kharanos in Dun Morogh. She builds her inventory herself." },
  ["milly brewtap"] = { 2, "goblin barmaid located at Fuselight in the Badlands", "Milly Brewtap is a goblin barmaid located at Fuselight in the Badlands." },
  ["mimmil"] = { 2, "senior tiderunner of the Dark Ray tribe", "Mimmil, a male murloc, is the senior tiderunner of the Dark Ray tribe. He is revered as the mightiest tiderunner to appear since the murlocs moved above the water, and his skills are legendary." },
  ["mina aldan"] = { 2, "worgen", "Mina Aldan is a worgen." },
  ["mina fintallas"] = { 2, "wife of Parqual Fintallas", "Mina Fintallas is the wife of Parqual Fintallas and the mother of Philia. Before the Third War, the Fintallas family lived in their modest but comfortable chambers in Capital City." },
  ["mina harken"] = { 2, "worgen follower", "Mina Harken is a worgen follower who can be posted to the Lunarfall garrison in Shadowmoon Valley. She can only be recruited using the Headhunter's Harvest from Lunarfall Inn." },
  ["mind-seeker apprentice"] = { 2, "', "Mind-Seeker Apprentices are located at the Seat of Knowledge during the  [Mind-Seeker] secret." },
  ["mind-shackled ankoan"] = { 2, "', "Mind-Shackled Ankoan are ankoan located in Deepsea Slave Pen in Nazjatar. They are actually Umai, Imara, and Adaru." },
  ["mindri dinkles"] = { 2, "gnome inscription trainer", "Mindri Dinkles is a gnome inscription trainer and vendor located at Valgarde in the Howling Fjord." },
  ["mine rat (motherlode)"] = { 2, "', "Mine Rats are kobolds located in the Motherlode." },
  ["miner fitzgerald"] = { 2, "miner of Hillsbrad Fields", "Miner Fitzgerald was a miner of Hillsbrad Fields. It is unknown what became of him after the Forsaken took over." },
  ["minerva ravensorrow"] = { 2, "undead death knight of the Knights of the Ebon Blade", "Minerva Ravensorrow is an undead death knight of the Knights of the Ebon Blade." },
  ["ming the cunning"] = { 2, "leader of the Harthak clan", "Ming the Cunning is the leader of the Harthak clan. He and his clan have gathered at the Mogu'shan Palace, alongside clans Gurthan and Kargesh to prove their worth to their king." },
  ["minion of borgal"] = { 2, "', "Minions of Borgal are ogres of the Bloodmaul clan found performing rituals at Bloodmaul Stronghold in Frostfire Ridge. They answer to Borgal Doomfist." },
  ["minion of deathwingurlugull"] = { 2, "murloc located in Tyrhold Reservoir in Thaldraszus during...", "Minion of Deathwingurlugull is a murloc located in Tyrhold Reservoir in Thaldraszus during Time Rifts." },
  ["minion of hogger"] = { 2, "', "Minions of Hogger are gnoll mobs summoned by Hogger in Elwynn Forest. Once Hogger reaches 50% health, three of these will spawn in." },
  ["minion of kaw"] = { 2, "', "Minions of Kaw can be found at Kaw's Roost in the Borean Tundra." },
  ["minion of sar'this"] = { 2, "', "Minion of Sar'this are arakkoa found with Sar'this at Lake Jorune in Terokkar Forest." },
  ["minion of sethir"] = { 2, "', "The Minions of Sethir can be found in Teldrassil. They serve Sethir the Ancient, and there are six of them total." },
  ["minister kiyuubi"] = { 2, "Broken located at Firewatch Ridge inside a cave in the Se...", "Minister Kiyuubi is a Broken located at Firewatch Ridge inside a cave in the Searing Gorge. He is one of the three ministers holding objects used to create an artifact." },
  ["miqa"] = { 2, "tuskarr child located in Camp Nowhere in the Azure Span", "Miqa is a tuskarr child located in Camp Nowhere in the Azure Span. He is chasing a Foraging Chicken." },
  ["mirabelle"] = { 2, "worgen located in the Undercity during the Battle for Lor...", "Mirabelle is a worgen located in the Undercity during the Battle for Lordaeron. She and Renzik infiltrated the city and retreated when the Horde forces led by Varok Saurfang discovered them." },
  ["mirefin ambusher"] = { 2, "', "Mirefin Ambusher are murlocs found in northeastern Dustwallow Marsh during the quest  [15-30] Recover the Cargo!. They are part of the Mirefin tribe." },
  ["mirefin coastrunner"] = { 2, "', "Mirefin Coastrunners are murlocs found in northeastern Dustwallow Marsh. They are part of the Mirefin tribe." },
  ["mirefin muckdweller"] = { 2, "', "Mirefin Muckdwellers are murlocs found in northeastern Dustwallow Marsh. They are part of the Mirefin tribe." },
  ["mirefin murloc"] = { 2, "', "Mirefin Murlocs are murlocs found in northeastern Dustwallow Marsh. They are part of the Mirefin tribe." },
  ["mirefin oracle"] = { 2, "', "Mirefin Oracles are murlocs found in northeastern Dustwallow Marsh. They are part of the Mirefin tribe." },
  ["mirefin puddlejumper"] = { 2, "', "Mirefin Puddlejumpers are murlocs located in Dustwallow Marsh." },
  ["mirefin warrior"] = { 2, "', "Mirefin Warriors are murlocs located in Dustwallow Marsh." },
  ["miri"] = { 2, "vulpera trade goods vendor", "Miri is a vulpera trade goods vendor that walks around the Vulpera Hideaway in Vol'dun." },
  ["miri fiddlewizz"] = { 2, "gnome located at Tradewinds Market in Boralus", "Miri Fiddlewizz is a gnome located at Tradewinds Market in Boralus." },
  ["miriam brassbomb"] = { 2, "dwarf stable master located at Tranquil Wash in Shimmerin...", "Miriam Brassbomb is a dwarf stable master located at Tranquil Wash in Shimmering Expanse." },
  ["mirojin"] = { 2, "centaur innkeeper", "Mirojin is a centaur innkeeper and vendor located in Ohn'iri Springs in the Ohn'ahran Plains." },
  ["miron"] = { 2, "deceased venthyr located in the Ashen Traverse in Revendreth", "Miron is a deceased venthyr located in the Ashen Traverse in Revendreth. He was one of Sabina's companions." },
  ["misfortunate pilgrim"] = { 2, "', "Misfortunate Pilgrims are three brokers located at the Ageless Shards in Zereth Mortis. They have been killed by Xy'rath the Covetous." },
  ["misguided postulant"] = { 2, "', "Misguided Postulants are Forsworn kyrian located at the Citadel of Loyalty in Bastion." },
  ["miss benzi"] = { 2, "matron of the Lil' Guys Orphanage in Undermine", "Miss Benzi is the matron of the Lil' Guys Orphanage in Undermine." },
  ["missy flamecuffs"] = { 2, "gnome mage part of the Hodir encounter in Ulduar", "Missy Flamecuffs is a gnome mage part of the Hodir encounter in Ulduar. She, along with her excavation team are trapped inside icicle blocks and must be freed if the raid wants help against Hodir." },
  ["mist seer"] = { 2, "', "Mist Seers are vrykul located in Stormheim." },
  ["mist warder"] = { 2, "', "Mist Warders are vrykul located in Stormheim." },
  ["mister knuckles"] = { 2, "ogre located next to Madam Goya in the Black Market Aucti...", "Mister Knuckles is an ogre located next to Madam Goya in the Black Market Auction House in the Ring of Blood in Nagrand. He acts as one of her bodyguards." },
  ["mistie flitterdawn"] = { 2, "gnome located in Fizzcrank Airstrip in the Borean Tundra", "Mistie Flitterdawn is a gnome located in Fizzcrank Airstrip in the Borean Tundra." },
  ["mistress celina"] = { 2, "venthyr located in Redelav Tower in Revendreth", "Mistress Celina is a venthyr located in Redelav Tower in Revendreth." },
  ["mistress mihaela"] = { 2, "venthyr located in the Sinposium in Revendreth", "Mistress Mihaela is a venthyr located in the Sinposium in Revendreth. She is the quartermaster for the Court of Harvesters." },
  ["mistress sassz'ine"] = { 2, "naga sea witch located in Tomb of Sargeras", "Mistress Sassz'ine is a naga sea witch located in Tomb of Sargeras. She has come to the tomb to take the  [Tidestone of Golganneth] for Queen Azshara and tainted the denizens of the ocean beneath the tomb." },
  ["mistress of shadows"] = { 2, "elven spellcaster within the Tomb of the Ancients in Dust...", "The Mistress of Shadows was an elven spellcaster within the Tomb of the Ancients in Dustwallow Marsh, the abode of the undead Lord Talendar. Unlike her host, the Mistress of Shadows nor her six Maidens of Shadows remained alive, and she studied wi..." },
  ["mitishka"] = { 2, "furbolg located in Val'sharah", "Mitishka is a furbolg located in Val'sharah. It was taken out by the class order forces." },
  ["mitu"] = { 2, "tortollan located at Scaletrader Post in Zuldazar", "Mitu is a tortollan located at Scaletrader Post in Zuldazar." },
  ["mix'ni"] = { 2, "nerubian located in the Umbral Bazaar in the City of Threads", "Mix'ni is a nerubian located in the Umbral Bazaar in the City of Threads." },
  ["mixmaster blix"] = { 2, "goblin located in Steamwheedle Port in Tanaris", "Mixmaster Blix is a goblin located in Steamwheedle Port in Tanaris." },
  ["miya"] = { 2, "tuskarr located at Gelikyr Post in Thaldraszus", "Miya is a tuskarr located at Gelikyr Post in Thaldraszus. She is found with Novice Plifa and Shoo upstairs in the inn." },
  ["mizli crankwheel"] = { 2, "roadie for the Level 80 Elite Tauren Chieftains found in ...", "Mizli Crankwheel is a roadie for the Level 80 Elite Tauren Chieftains found in the Grim Guzzler in Blackrock Depths." },
  ["mizzle the crafty"] = { 2, "', "Mizzle the Crafty can be found current Gordok throneroom in Dire Maul. Only if King Gordok is killed, will Cho'Rush the Observer yell that the king is dead and call for Mizzle." },
  ["mizzy bobble"] = { 2, "dwarf located at the Lunarfall in Shadowmoon Valley", "Mizzy Bobble is a dwarf located at the Lunarfall in Shadowmoon Valley. She can only be recruited using the Headhunter's Harvest from Lunarfall Inn." },
  ["mjordin combatant"] = { 2, "', "Mjordin Combatants are vrykul, challenging each other to 'ascend' into the Ymirjar." },
  ["mjordin water magus"] = { 2, "', "Mjordin Water Magi are vrykul located at Jotunheim in Icecrown. This section concerns content related to Shadowlands." },
  ["mmmrrrggglll"] = { 2, "chieftain of the Grimscale tribe of murlocs", "Mmmrrrggglll is the chieftain of the Grimscale tribe of murlocs who are situated at both the Tranquil Shore and the Golden Strand. It is possible that he was the one responsible for the theft of cargo from Captain Kelisendra's ship." },
  ["mmmrrrggglll (azmerloth)"] = { 2, "murloc located in Azmerloth", "Mmmrrrggglll is a murloc located in Azmerloth." },
  ["mo'gosh arcanist"] = { 2, "', "Mo'gosh Arcanists are ogres located in Molten Cay during Island Expeditions." },
  ["mo'gosh brute"] = { 2, "', "Mo'gosh Brutes are ogres located in Molten Cay during Island Expeditions." },
  ["mo'gosh magi"] = { 2, "', "Mo'gosh Magi are ogres located in Molten Cay during Island Expeditions." },
  ["mo'gosh mauler"] = { 2, "', "Mo'gosh Maulers are ogres located in Molten Cay during Island Expeditions." },
  ["mo'gosh mystic"] = { 2, "', "Mo'gosh Mystics are ogres located in Molten Cay during Island Expeditions." },
  ["mo'gosh ogre"] = { 2, "', "Mo'gosh Ogres are ogres located in Molten Cay during Island Expeditions." },
  ["mo'gosh warmonger"] = { 2, "', "Mo'gosh Warmongers are ogres located in Molten Cay during Island Expeditions." },
  ["mo'grosh brute"] = { 2, "', "Mo'grosh Brutes are ogres located in Loch Modan." },
  ["mo'grosh darkmauler"] = { 2, "', "Mo'grosh Darkmaulers are ogres located at Mo'grosh Stronghold in Loch Modan." },
  ["mo'grosh enforcer"] = { 2, "', "Mo'grosh Enforcers are ogres located in Loch Modan." },
  ["mo'grosh mystic"] = { 2, "', "Mo'grosh Mystics are ogres found in Loch Modan." },
  ["mo'grosh ogre"] = { 2, "', "Mo'grosh Ogres are ogres located in Loch Modan (Classic)." },
  ["mo'grosh shaman"] = { 2, "', "Mo'grosh Shaman were ogres found in Loch Modan." },
  ["mo'mor the breaker"] = { 2, "Broken quest giver located at Telaar in Nagrand", "Mo'mor the Breaker is a Broken quest giver located at Telaar in Nagrand." },
  ["mo'tow"] = { 2, "broker located in Tazavesh", "Mo'tow is a broker located in Tazavesh, the Veiled Market in K'aresh." },
  ["moa'ki fisherman"] = { 2, "', "Moa'ki Fishermen are tuskarr fishermen located at the Moa'ki Harbor in the Dragonblight." },
  ["moa'ki turtle rider"] = { 2, "', "Moa'ki Turtle Riders are tuskarr guards that patrol the Moa'ki Harbor in the Dragonblight." },
  ["moa'ki warrior"] = { 2, "', "Moa'ki Warriors are tuskarr guards for Moa'ki Harbor in the Dragonblight." },
  ["moaoto"] = { 2, "Broken found in Lower City in Shattrath City", "Moaoto is a Broken found in Lower City in Shattrath City. This pig farmer will give players, who attended the Blizzard Worldwide Invitational 2007 and provide a code, a  [Fortune Coin]." },
  ["modak flamespit"] = { 2, "djaradin located at the Burning Ascent in the Waking Shores", "Modak Flamespit is a djaradin located at the Burning Ascent in the Waking Shores." },
