  ["model (thaldraszus)"] = { 2, "', "Models are located at Algeth'ar Academy in Thaldraszus. They are painted by Dracthyr Freshscales." },
  ["modhina"] = { 2, "dead earthen located in the Orecreg on the Isle of Dorn", "Modhina is a dead earthen located in the Orecreg on the Isle of Dorn." },
  ["modimus anvilmar"] = { 2, "last High King of the united dwarves of Ironforge prior t...", "Modimus Anvilmar was the last High King of the united dwarves of Ironforge prior to the War of the Three Hammers. An immense statue of Modimus stands guard at the Gates of Ironforge." },
  ["mogu infiltrator"] = { 2, "', "Mogu Infiltrators are mogu located in the Heartland in the Valley of the Four Winds." },
  ["mogu statue (pet)"] = { 2, "mogu companion", "The Mogu Statue teaches you how to summon Baoh-Xi, a mogu companion." },
  ["mogujia soul-caller"] = { 2, "mogu spellcaster within Mogujia in Kun-Lai Summit", "Mogujia Soul-Caller is a mogu spellcaster within Mogujia in Kun-Lai Summit. He is hinted to have been behind the reanimation of the Terracotta Warriors within Mogujia." },
  ["moira bronzebeard (timewalking)"] = { 2, "dwarf located in Imperial Seat in Blackrock Depths", "Moira Bronzebeard is a dwarf located in Imperial Seat in Blackrock Depths." },
  ["mojhua"] = { 2, "tortollan located in the Filled Bowl in the Azure Span", "Mojhua is a tortollan located in the Filled Bowl in the Azure Span." },
  ["mokrik blackfingers"] = { 2, "', "Mokrik Blackfingers is one of Gar'mak Bladetwist's orcish lieutenants, located in Nethergarde Keep in the Blasted Lands." },
  ["molako"] = { 2, "Ascended kyrian located in Torghast", "Molako is an Ascended kyrian located in Torghast, Tower of the Damned." },
  ["moldfang"] = { 2, "gnoll ghost located in the Western Plaguelands", "Moldfang is a gnoll ghost located in the Western Plaguelands. There is a smaller gnoll to his left that channels a shadow spell into Moldfang's body until the player attacks Moldfang." },
  ["molka the grinder"] = { 2, "djaradin located in the Waking Shores", "Molka The Grinder is a djaradin located in the Waking Shores." },
  ["molok the crusher"] = { 2, "rare mob ogre found at the westernmost point of the cave ...", "Molok the Crusher is a rare mob ogre found at the westernmost point of the cave at Boulder'gor in the Boulderfist Outpost in the Arathi Highlands. Notably, he hits substantially harder than any other mob found in the area." },
  ["moltenbinder"] = { 2, "djaradin in the Emerald Dream first seen at Slagfell Hold", "Moltenbinder is a djaradin in the Emerald Dream first seen at Slagfell Hold. Later, she could be found at the Eye of Ysera during the quest  [10-80] Triple Threat." },
  ["moltenbinder's disciple"] = { 2, "rare djaradin located at Slagfell Hold within the Emerald...", "Moltenbinder's Disciple is a rare djaradin located at Slagfell Hold within the Emerald Dream." },
  ["molvzira"] = { 2, "earthen located at the Forgegrounds in Dornogal", "Molvzira is an earthen located at the Forgegrounds in Dornogal." },
  ["mona"] = { 2, "tortollan located at Scaletrader Post in Zuldazar", "Mona is a tortollan located at Scaletrader Post in Zuldazar." },
  ["monann coldforge"] = { 2, "dwarf general goods vendor located at Bahrum's Post in Du...", "Monann Coldforge is a dwarf general goods vendor located at Bahrum's Post in Dun Morogh." },
  ["mook"] = { 2, "', "Mook was unfortunate enough to be eaten by one of the Cliff Giants in Azshara, while searching for Azsharite. His  [Crystallized Note] can be found on his now solid  [Crystallized Azsharite] corpse." },
  ["moonclaw warrior"] = { 2, "', "Moonclaw Warriors are female worgen who join the Sentinels alongside Adella, Silvia and Tambre." },
  ["mooncrazed tidehunter"] = { 2, "', "Mooncrazed Tidehunters are murloc attacking Glimmerspine in Darkshore." },
  ["moonrage armorer"] = { 2, "worgen found in Pyrewood Village in Silverpine Forest", "The Moonrage Armorer was a worgen found in Pyrewood Village in Silverpine Forest. During the day, he appears in his human form as the Pyrewood Armorer." },
  ["moonrage bloodhowler"] = { 2, "worgen mob in Silverpine Forest", "Moonrage Bloodhowler was a worgen mob in Silverpine Forest." },
  ["moonrage darkrunner"] = { 2, "worgen mob in Silverpine Forest", "Moonrage Darkrunner was a worgen mob in Silverpine Forest." },
  ["moonrage darksoul"] = { 2, "', "Moonrage Darksouls are worgen found in Silverpine Forest." },
  ["moonrage elder"] = { 2, "', "Moonrage Elders are worgen found in Pyrewood Village in Silverpine Forest. During the day, they appear as their human form as Pyrewood Elders." },
  ["moonrage glutton"] = { 2, "', "Moonrage Gluttons are worgen mobs found in Silverpine Forest." },
  ["moonrage leatherworker"] = { 2, "worgen found in Pyrewood Village in Silverpine Forest", "The Moonrage Leatherworker was a worgen found in Pyrewood Village in Silverpine Forest. During the day, she appears in her human form as Pyrewood Leatherworker." },
  ["moonrage sentry"] = { 2, "', "Moonrage Sentries are warriors located in Pyrewood Village in Silverpine Forest during the night, appearing as worgens. During the day, they appear as their human form as Pyrewood Sentries." },
  ["moonrage tailor"] = { 2, "worgen found in Pyrewood Village in Silverpine Forest", "The Moonrage Tailor was a worgen found in Pyrewood Village in Silverpine Forest. During the day, he appears in his human form as the Pyrewood Tailor." },
  ["moonrage watcher"] = { 2, "', "Moonrage Watchers are worgen located in Pyrewood Village in Silverpine Forest during the night. During the day, they appear in their human form as Pyrewood Watchers." },
  ["moonrage whitescalp"] = { 2, "worgen mob in Silverpine Forest", "Moonrage Whitescalp was a worgen mob in Silverpine Forest." },
  ["moontalon"] = { 2, "owl located in the Tomb of Sargeras", "Moontalon is an owl located in the Tomb of Sargeras. It's the pet of Captain Yathae Moonstrike." },
  ["moonwalker betrayer"] = { 2, "', "Moonwalker Betrayers are satyrs located in Feralas during Nightmare Incursions." },
  ["moordo"] = { 2, "furbolg leatherworking trainer located at Stillpine Hold ...", "Moordo is a furbolg leatherworking trainer located at Stillpine Hold in Azuremyst Isle." },
  ["morata glowheart"] = { 2, "tauren mage found in Arcane Enclave in the Cleft of Shado...", "Morata Glowheart is a tauren mage found in Arcane Enclave in the Cleft of Shadow in Orgrimmar." },
  ["mordei the earthrender"] = { 2, "rare satyr found patrolling at the moonwell in the Twin C...", "Mordei the Earthrender is a rare satyr found patrolling at the moonwell in the Twin Colossals in Feralas." },
  ["mordle cogspinner"] = { 2, "gnome quest giver located at the Fizzcrank Airstrip in Bo...", "Mordle Cogspinner is a gnome quest giver located at the Fizzcrank Airstrip in Borean Tundra. He sends Alliance adventurers to gather  [Fizzcrank Spare Parts] from The Geyser Fields, Scalding Pools, and other mechagnome-controlled areas in the Bore..." },
  ["mordrag the tainted"] = { 2, "ogre located in Speaker's Rest in Zul'Aman", "Mordrag the Tainted is an ogre located in Speaker's Rest in Zul'Aman. He was in charge of the Twilight's Blade cultists in the area." },
  ["mordresh fire eye"] = { 2, "elite skeleton found in Razorfen Downs", "Mordresh Fire Eye is an elite skeleton found in Razorfen Downs. In life, he was an orc shaman." },
  ["mordretha, the endless empress"] = { 2, "last boss located in the Theater of Pain", "Mordretha, the Endless Empress is the last boss located in the Theater of Pain." },
  ["morek"] = { 2, "earthen located in the Forgegrounds in Dornogal", "Morek is an earthen located in the Forgegrounds in Dornogal." },
  ["morgala darksquall"] = { 2, "powerful naga siren", "Morgala Darksquall was a powerful naga siren. When Onyxia separated Varian Wrynn into two, Morgala and her naga attacked Onyxia." },
  ["morgan (venthyr)"] = { 2, "venthyr located in Revendreth", "Morgan is a venthyr located in Revendreth." },
  ["morgana dayblaze"] = { 2, "dwarf", "Morgana Dayblaze is a dwarf." },
  ["morganna"] = { 2, "venthyr located in Darkhaven in Revendreth", "Morganna is a venthyr located in Darkhaven in Revendreth." },
  ["morgl the oracle"] = { 2, "murloc", "Morgl the Oracle is a murloc who rarely appears in the Heart of Azeroth, the shaman order hall, or in Deliverance Point on the Broken Shore. Morgl first appeared in Hearthstone as a shaman hero before being introduced in World of Warcraft." },
  ["morgo kain"] = { 2, "ogre located at The Pit in Gorgrond", "Morgo Kain is an ogre located at The Pit in Gorgrond. To defeat him, his Helmet must be destroyed first." },
  ["morgu"] = { 2, "member of the Untitled Band", "Morgu was a worgen located at the Serene Dreams Spa in Thaldraszus. He is a member of the Untitled Band." },
  ["morhan coppertongue"] = { 2, "dwarf mail armor vendor located in Thelsamar in Loch Modan", "Morhan Coppertongue is a dwarf mail armor vendor located in Thelsamar in Loch Modan." },
  ["morheim (vrykul)"] = { 2, "vrykul", "Morheim was a vrykul that lived in Stormheim. He was known by Odyn and had a village named after him." },
  ["morin cloudstalker"] = { 2, "tauren quest giver located on the road from Bloodhoof Vil...", "Morin Cloudstalker is a tauren quest giver located on the road from Bloodhoof Village to the Great Gate in Mulgore." },
  ["morjirn"] = { 2, "vrykul located on the cliffs in southern Stormheim", "Morjirn is a vrykul located on the cliffs in southern Stormheim. He is the head brewer of the Tideskorn, and harboring jealousy of Melba's skill, sent a band of raiders to kill her." },
  ["morka bruggu"] = { 2, "orc soldier of the Horde", "Morka Bruggu is an orc soldier of the Horde. She participated in the war against the Burning Legion and later served as a guard in Orgrimmar before being assigned as one of Varok Saurfang's personal guards during the War of the Thorns." },
  ["morketh bladehowl"] = { 2, "former Iron Horde blacksmith dedicated to creating the fi...", "Morketh Bladehowl is a former Iron Horde blacksmith dedicated to creating the finest weaponry possible. Fed up with their lack of respect for his superior craftsmanship, he defects to Vol'jin's Horde and joins the player's garrison as a follower -..." },
  ["morlia doomwing"] = { 2, "Forsaken flight master located at The Shadow Vault in Ice...", "Morlia Doomwing is a Forsaken flight master located at The Shadow Vault in Icecrown. She will only appear once you have completed the quest  [25-30] The Shadow Vault." },
  ["morod the windstirrer"] = { 2, "Broken quest giver located at the Ruins of Sha'naar in th...", "Morod the Windstirrer is a Broken quest giver located at the Ruins of Sha'naar in the Hellfire Peninsula." },
  ["moroes"] = { 2, "butler of Medivh the Last Guardian", "Moroes is Karazhan's steward and was the butler of Medivh the Last Guardian. In life, he was a talented and loyal servant, though somber and somewhat paranoid due to the strange visions he received due to living within the walls of Karazhan." },
  ["moroes (return to karazhan tactics)"] = { 2, "third boss in Return to Karazhan", "Moroes  is the third boss in Return to Karazhan." },
  ["moroes (tactics)"] = { 2, "', "Moroes is Karazhan's steward and can be found tending to guests in the Banquet Hall in Karazhan. Along with four special invited patrons, Moroes fights any uninvited guests to the death." },
  ["moros"] = { 2, "Mawsworn kyrian located in Korthia", "Moros is a Mawsworn kyrian located in Korthia." },
  ["morphael"] = { 2, "satyr located in Sleeper's Barrow in Val'sharah", "Morphael is a satyr located in Sleeper's Barrow in Val'sharah." },
  ["morqut elder"] = { 2, "', "Morqut Elders are tuskarr located in Morqut Islet in the Forbidden Reach." },
  ["morqut guard"] = { 2, "', "Morqut Guards are tuskarr located in Morqut Village in the Forbidden Reach." },
  ["morqut homesteader"] = { 2, "', "Morqut Homesteaders are tuskarr located in Morqut Village in the Forbidden Reach." },
  ["morqut villager"] = { 2, "', "Morqut Villagers are tuskarr located at various spots in the Forbidden Reach." },
  ["morshelz copperpinch"] = { 2, "vendor located in the Bazaar section of Silvermoon City", "Morshelz Copperpinch is a vendor located in the Bazaar section of Silvermoon City, near the bank, during the Feast of Winter Veil event. He is affiliated with Smokywood Pastures, and sells higher value holiday-related items." },
  ["mort (kobold)"] = { 2, "kobold located in Campalot in the Ringing Deeps", "Mort is a kobold located in Campalot in the Ringing Deeps." },
  ["morta the wretch"] = { 2, "Forsaken located at the Xylem's Tower in Azshara", "Morta the Wretch is a Forsaken located at the Xylem's Tower in Azshara. During the Burning Legion's third invasion, he became a member of Xylem's inner circle." },
  ["mortally wounded initiate"] = { 2, "arakkoa quest giver located at the Bloodmane Valley in Sp...", "Mortally Wounded Initiate is an arakkoa quest giver located at the Bloodmane Valley in Spires of Arak." },
  ["mortar specialist baybeard"] = { 2, "dwarf", "Mortar Specialist Baybeard is a dwarf that can be found operating a mortar near Frostmane Retreat in Dun Morogh during the Legion invasions." },
  ["mortog steamhead"] = { 2, "Broken reagent vendor located inside the entrance to Coil...", "Mortog Steamhead is a Broken reagent vendor located inside the entrance to Coilfang Reservoir in Zangarmarsh. Players can only repair and buy items from Steamhead when they are exalted with Cenarion Expedition." },
  ["morton cogswald"] = { 2, "gnome located in Xibala in Zuldazar", "Morton Cogswald is a gnome located in Xibala in Zuldazar." },
  ["morulu the elder"] = { 2, "Broken master Pet Tamer in the Lower City of Shattrath City", "Morulu The Elder is a Broken master Pet Tamer in the Lower City of Shattrath City. He is surrounded by his three pet baby crocolisks, Cragmaw, Chomps, and Gnasher." },
  ["mose canton"] = { 2, "quartermaster on the Wavestrider", "Mose Canton was the quartermaster on the Wavestrider. He died defending the ship against the Hidden, killed by Reigol Valdread." },
