  ["mrrgrl the tide reaver"] = { 2, "murloc located in El'dranil Shallows in Azsuna", "Mrrgrl the Tide Reaver is a murloc located in El'dranil Shallows in Azsuna." },
  ["mrrklr"] = { 2, "Swamprock murloc", "Mrrklr is a Swamprock murloc that appears in the northern part of Shipwreck Cove in Highmountain after a player frees Sloppy 'Sloppy Joe' Joe from captivity." },
  ["mrrrgrrrl"] = { 2, "murloc planned to appear in Murloc Shoals in Suramar", "Mrrrgrrrl is a murloc planned to appear in Murloc Shoals in Suramar. It would drop  [Infused Clam] for  [110] Magic Clams." },
