  ["muffinus chromebrew"] = { 2, "gnome hunter trainer located in New Tinkertown in Dun Morogh", "Muffinus Chromebrew is a gnome hunter trainer located in New Tinkertown in Dun Morogh. He is standing atop a platform with his pet, Sculpin." },
  ["mug'zee"] = { 2, "seventh", "Mug'Zee is the seventh and penultimate boss in the Liberation of Undermine. Players are tasked with defeating Mug'Zee in  [80R] Liberation of Undermine: Splitting Pairs, the traditional raid skip quest that is unlocked at Renown 5 with the Gallagi..." },
  ["mug'gok"] = { 2, "ogre found wandering back", "Mug'gok is an ogre found wandering back and forth between the Bleeding Hollow Ruins and Veil Lithic in Terokkar Forest. He drops no loot." },
  ["mug'thol"] = { 2, "ferocious", "Mug'thol is a ferocious and crafty ogre warlord ruling over the Crushridge clan in the Alterac Mountains." },
  ["mug'thol (warcraft iii)"] = { 2, "warchief of a branch of the Stonemaul Clan", "Mug'thol is the warchief of a branch of the Stonemaul Clan that resided in Lordaeron. Unfortunately for Mug'thol, Sylvanas Windrunner, an undead elf now free from the Lich King's control, was engaged in a difficult battle against the Dreadlord Var..." },
  ["mugglefin"] = { 2, "rare mob murloc found roaming about Lake Falathim in Ashe...", "Mugglefin is a rare mob murloc found roaming about Lake Falathim in Ashenvale. It was on an 8.5-12.5 respawn timer." },
  ["muiredon battleforge"] = { 2, "dwarf located in the Hall of Mysteries in the Mystic Ward...", "Muiredon Battleforge is a dwarf located in the Hall of Mysteries in the Mystic Ward in Ironforge. Together with his friend Narm Faulk, he had an encounter with some Dark Iron dwarves at Helm's Bed Lake and noticed a commander in their ranks." },
  ["mukkral blackvein"] = { 2, "orc follower located at the Frostwall in Frostfire Ridge", "Mukkral Blackvein is an orc follower located at the Frostwall in Frostfire Ridge. He can only be recruited using the Headhunter's Harvest from Frostwall Tavern." },
  ["mulgris deepriver"] = { 2, "tauren quest giver located in the small house at the Writ...", "Mulgris Deepriver is a tauren quest giver located in the small house at the Writhing Haunt in the Western Plaguelands. He was a member of the Cenarion Circle who was on the verge of death." },
  ["muller"] = { 2, "tuskarr located in the Waking Shores", "Muller is a tuskarr located in the Waking Shores." },
  ["muln earthfury"] = { 2, "tauren shaman", "Muln Earthfury is a tauren shaman and the former leader of the Earthen Ring." },
  ["mulric boldrock"] = { 2, "dwarf shaman trainer located in the Training Hall in Stor...", "Mulric Boldrock is a dwarf shaman trainer located in the Training Hall in Stormwind City." },
  ["mummified remains"] = { 2, "', "The Mummified Remains are mummies located in the Court of Bones on the Isle of Thunder." },
  ["mumta"] = { 2, "thief of souls", "Mumta, the thief of souls, can be found atop the Hall of the Grand Imperion, the southern building of the Court of Bones on the southwestern side of the Isle of Thunder." },
  ["munderut"] = { 2, "earthen located in Nibelgaz Mine in the Ringing Deeps", "Munderut is an earthen located in Nibelgaz Mine in the Ringing Deeps." },
  ["munovuth boldcleaver"] = { 2, "orc located in Stonefist Watch in Tiragarde Sound", "Munovuth Boldcleaver is an orc located in Stonefist Watch in Tiragarde Sound." },
  ["muqur rain-touched"] = { 2, "centaur quest giver located at Timberstep Outpost in the ...", "Muqur Rain-Touched is a centaur quest giver located at Timberstep Outpost in the Ohn'ahran Plains. He was wounded by the hornstrider Nergazurai while hunting and asks adventurers to gather reagents to cleanse the infection in the wound." },
  ["mur'ghoul corrupter"] = { 2, "', "Mur'ghoul Corrupters are mur'ghouls located at Chillmere Coast in the Howling Fjord." },
  ["mur'ghoul flesheater"] = { 2, "', "Mur'ghoul Flesheaters are mur'ghouls located at Chillmere Coast in the Howling Fjord." },
  ["mur'gul blood-gill"] = { 2, "', "Mur'gul Blood-Gills are mur'gul creeps that can be encountered in the Sunken Ruins tileset." },
  ["mur'gul clam shucker"] = { 2, "slightly more powerful Mur'gul Reaver", "The Mur'gul Clam Shucker appears in Rise of the Naga. It is a slightly more powerful Mur'gul Reaver." },
  ["mur'gul clam trapper"] = { 2, "', "The Mur'gul Clam Trapper appears in Rise of the Naga and drops a Rune of Greater Healing." },
  ["mur'gul cliffrunner"] = { 2, "', "Mur'gul Cliffrunners are mur'gul creeps that can be encountered in the Sunken Ruins tileset." },
