  ["mur'gul overlord"] = { 2, "mur'gul leader appearing in Dustwallow Marsh in the Found...", "The Mur'gul Overlord is a mur'gul leader appearing in Dustwallow Marsh in the Founding of Durotar campaign." },
  ["mur'gul reaver"] = { 2, "Mur'gul unit used by the Naga as a basic soldier", "The Mur'Gul Reaver is a Mur'gul unit used by the Naga as a basic soldier. They are trained at the Temple of Tides." },
  ["mur'gul shadowcaster"] = { 2, "', "Mur'gul Shadowcasters are mur'gul shadowcaster creeps that can be encountered in the Sunken Ruins tileset." },
  ["mur'gul shell sucker"] = { 2, "much weaker version of the Mur'gul Cliffrunner", "The Mur'gul Shell Sucker appears in Rise of the Naga and drops a Ring of Protection and Runes. It is a much weaker version of the Mur'gul Cliffrunner." },
  ["mur'gul slave"] = { 2, "', "Mur'gul Slaves are mur'gul resource-gathering and builder units trained by the naga at the Temple of Tides." },
  ["mur'gul snarecaster"] = { 2, "', "Mur'gul Snarecasters are mur'gul creeps that can be encountered in the Sunken Ruins tileset." },
  ["mur'gul tidewarrior"] = { 2, "', "Mur'gul Tidewarriors are mur'gul creeps that can be encountered in the Sunken Ruins tileset." },
  ["mur'gul tyrant"] = { 2, "mur'gul leader in Echo Isles", "The Mur'gul Tyrant is the mur'gul leader in Echo Isles, appearing in the Founding of Durotar campaign. It dropped Scepter of the Sea upon death." },
  ["muradin bronzebeard (warcraft iii)"] = { 2, "brother of King Magni Bronzebeard of Ironforge", "Muradin is the brother of King Magni Bronzebeard of Ironforge. During the dark days of the Second War, Muradin served as the liaison between Lordaeron and the dwarves' realm of Khaz Modan." },
  ["murd doc"] = { 2, "elite gnome", "Murd Doc is an elite gnome and member of the G-Team, a small group within S.A.F.E." },
  ["murdered myrmidon"] = { 2, "', "Murdered Myrmidons are naga located in Desolace." },
  ["murgle"] = { 2, "Bloodfin baby murloc drops from King Gakula at Bloodfin V...", "Murgle is a Bloodfin baby murloc drops from King Gakula at Bloodfin Village of Nazjatar." },
  ["murgly"] = { 2, "murloc located in Winterfin Retreat in the Borean Tundra", "Murgly is a murloc located in Winterfin Retreat in the Borean Tundra." },
  ["murgot deepforge"] = { 2, "', "Murgot Deepforge can be found in Alterac Valley." },
  ["murgulis"] = { 2, "murloc located at Morheim in Stormheim", "Murgulis is a murloc located at Morheim in Stormheim. He appears when the demons are invading Stormheim and will assist you until you kill their leader." },
  ["murgurgula"] = { 2, "murloc found on Azuremyst Isle", "Murgurgula is a murloc found on Azuremyst Isle." },
  ["murik"] = { 2, "tuskarr located in Iskaara in the Azure Span", "Murik is a tuskarr located in Iskaara in the Azure Span." },
  ["murkalot's flail"] = { 2, "companion", "Murkalot is a companion that was given to those who attended BlizzCon 2013, or purchased a virtual ticket. He is based on the Crusader class from the Diablo series." },
  ["murkastrasza"] = { 2, "Alexstrasza-themed murloc companion", "Murkastrasza is an Alexstrasza-themed murloc companion." },
  ["murkblood brute"] = { 2, "', "Murkblood Brutes are Broken found at Sunspring Post in Nagrand. A pair of them can be found abusing a Kurenai Captive at  and another pair are abusing a Mag'har Captive at ." },
  ["murkblood healer"] = { 2, "', "Murkblood Healers are Broken found in the Underbog." },
  ["murkblood invader"] = { 2, "', "Murkblood Invaders are Broken found patrolling some of the roads in Nagrand atop their elekk mounts along the east-west roads in both northern and southern Nagrand." },
  ["murkblood miner"] = { 2, "', "Murkblood Miners are Broken found on Netherwing Ledge in Shadowmoon Valley." },
  ["murkblood oracle"] = { 2, "', "Murkblood Oracles are Broken found in the Underbog." },
  ["murkblood overseer"] = { 2, "', "Murkblood Overseers are Broken found on Netherwing Ledge in Shadowmoon Valley deep in the mines, somewhere near the flayers. His hand is needed for  [25-30] Seeker of Truth and he himself cuts it off and gives it to you to keep up your disguise." },
  ["murkblood putrifier"] = { 2, "', "Murkblood Putrifiers are Broken found at Sunspring Post in Nagrand. Killing these will earn you +10 to the Kurenai/Mag'har faction." },
  ["murkblood raider"] = { 2, "', "Murkblood Raiders are Broken found at Sunspring Post in Nagrand." },
  ["murkblood scavenger"] = { 2, "', "Murkblood Scavengers are Broken found at Sunspring Post in Nagrand usually in groups of three. They are extremely weak, however, and are easily dispatched by a solo player of a similar level." },
  ["murkblood spearman"] = { 2, "', "Murkblood Spearmen are Broken found in the Underbog." },
  ["murkblood tribesman"] = { 2, "', "Murkblood Tribesmen are Broken found in the Underbog." },
  ["murkblood twin"] = { 2, "', "The Murkblood Twins are Broken encountered in the Ring of Blood in Nagrand." },
  ["murkbrine fishmancer"] = { 2, "Veiled Market dungeon", "Murkbrine Fishmancers are murlocs located in Stormheim during the Tazavesh, the Veiled Market dungeon." },
  ["murkbrine scalebinder"] = { 2, "Veiled Market dungeon", "Murkbrine Scalebinders are murlocs located in Stormheim during the Tazavesh, the Veiled Market dungeon." },
  ["murkbrine shellcrusher"] = { 2, "Veiled Market dungeon", "Murkbrine Shellcrushers are murlocs located in Stormheim during the Tazavesh, the Veiled Market dungeon." },
  ["murkbrine shorerunner"] = { 2, "Veiled Market dungeon", "Murkbrine Shorerunners are murlocs located in Stormheim during the Tazavesh, the Veiled Market dungeon." },
  ["murkbrine wavejumper"] = { 2, "Veiled Market dungeon", "Murkbrine Wavejumpers are murlocs located in Stormheim during the Tazavesh, the Veiled Market dungeon." },
  ["murkdeep"] = { 2, "murloc", "Murkdeep is a murloc who spawned on the coast south of Auberdine in Darkshore. Sentinel Glynda Nal'Shea would reward any Alliance who killed Murkdeep." },
  ["murkdeep (azmerloth)"] = { 2, "murloc located in Azmerloth", "Murkdeep is a murloc located in Azmerloth." },
  ["murkgill coldbringer"] = { 2, "', "Murkgill Coldbringers are located at the Kal'ai Ruins in Northern Stranglethorn." },
  ["murkgill forager"] = { 2, "', "Murkgill Foragers are located at the Kal'ai Ruins in Northern Stranglethorn." },
  ["murkgill hunter"] = { 2, "', "Murkgill Hunter are murlocs located at the Kal'ai Ruins in Northern Stranglethorn." },
  ["murkgill oracle"] = { 2, "', "Murkgill Oracle are located at the Kal'ai Ruins in Northern Stranglethorn." },
  ["murkgill warrior"] = { 2, "', "Murkgill Warriors are located at the Kal'ai Ruins in Northern Stranglethorn." },
  ["murkidan"] = { 2, "Illidan Stormrage-themed murloc companion", "Murkidan is an Illidan Stormrage-themed murloc companion that was given out to attendees of BlizzCon 2015, and to those who bought a Virtual Ticket." },
  ["murkimus' little spear"] = { 2, "rare item", "Murkimus' Little Spear is a rare item that teaches you how to summon the companion Murkimus the Gladiator. Those who obtained this companion were awarded the achievement  [Murkimus the Gladiator]." },
  ["murkimus' tyrannical spear"] = { 2, "', "Murkimus' Tyrannical Spear teaches the companion Murkimus Tyrannicus. After its appearance in the game files, it was speculated by fans that this pet would be rewarded from the 2013 Arena Pass as a replacement for the previous years' reward, Murki..." },
  ["murkloc tadpole"] = { 2, "Clawdacity!", "Murkloc Tadpoles are juvenile murlocs of the Murkloc tribe found inside the Murkloc Cave in Highmountain after completing  [10-45] Oh, the Clawdacity!. They are the result of Murky recruiting a number of Swamprock Tadpoles to his cause." },
  ["murkwater myrmidon"] = { 2, "', "Murkwater Myrmidons are naga located in Kal'delar in Val'sharah." },
  ["murkwater oracle"] = { 2, "', "Murkwater Oracles are naga located in Kal'delar of Val'sharah." },
  ["murkwater slaver"] = { 2, "', "Murkwater Slavers are naga located in Kal'delar in Val'sharah. They drag Underlight Slaves." },
  ["murkwater warrior"] = { 2, "', "Murkwater Warriors are naga located in Kal'delar in Val'sharah." },
  ["murky"] = { 2, "', "'Mrgglglbrlg rmrmgllg mrggggm. Mrrglglgy, mgllglgl mgggrrmgl?" },
  ["murky (traveler)"] = { 2, "green murloc", "Murky is a green murloc who comes from a fishing village on the Forgotten Coast of Feralas, where he lived with his aunt and uncle. One day, he left to go fishing, but his return was delayed by getting tangled in his own fishing nets, and when he ..." },
  ["murky jr."] = { 2, "murloc located in Winterfin Retreat in the Borean Tundra", "Murky Jr. is a murloc located in Winterfin Retreat in the Borean Tundra." },
  ["murky's little soulstone"] = { 2, "fearsome-ish", "Murky's Little Soulstone teaches Murkablo, a companion that was given out to attendees of BlizzCon 2011, purchasers of the DirecTV pay-per-view of the event, and purchasers of the internet streamed video of the event. Murkablo is the fearsome-ish,..." },
  ["murloc (tiragarde sound)"] = { 2, "murloc located in Fogcliff Strand in Tiragarde Sound as p...", "Murloc is a murloc located in Fogcliff Strand in Tiragarde Sound as part of the Squirgle of the Depths fight." },
  ["murloc (un'goro crater)"] = { 2, "', "Murlocs are murlocs located in Un'Goro Crater." },
  ["murloc (mob)"] = { 2, "', "Murlocs are murlocs located at Crystal Lake in Elwynn Forest. They primarily stick to the islands in the middle of the lake, though a few can be found on the northern shore." },
  ["murloc ambusher"] = { 2, "murloc located in Thaldraszus during  [40-70] If We Could...", "Murloc Ambusher is a murloc located in Thaldraszus during  [40-70] If We Could Turn Back Time." },
  ["murloc coastrunner"] = { 2, "', "Murloc Coastrunners are murlocs located at the northern coast of Westfall." },
  ["murloc flesheater (underworld minions)"] = { 2, "', "Murloc Flesheaters are heavy-melee ground units of the murloc forces in the Warcraft III Demo campaign Exodus of the Horde." },
  ["murloc flesheater (warcraft iii)"] = { 2, "', "Murloc Flesheaters are murloc creeps that can be encountered in the Felwood tileset." },
  ["murloc flesheater (mob)"] = { 2, "', "Murloc Flesheaters are murlocs found to the waters east of Lakeshire in the Redridge Mountains." },
  ["murloc forager"] = { 2, "', "Murloc Foragers are murloc found on the southeastern shore of Stone Cairn Lake and on the small river island east of the Brackwell Pumpkin Patch in Elwynn Forest." },
  ["murloc guardian"] = { 2, "', "Murloc Guardians were part of the Murloc tribe of Underworld Minions.  They maintained a magic wall around Sen'jin and the Murloc High Sorcerer." },
  ["murloc high sorcerer"] = { 2, "high sorcerer deep sea murloc of the Underworld Minions", "The Murloc High Sorcerer is a high sorcerer deep sea murloc of the Underworld Minions. He is one of two hero units of the Underworld Minions in the campaign Exodus of the Horde." },
  ["murloc hunter"] = { 2, "', "Murloc Hunters hunt the shores of Westfall. Usually accompanied by a pet crab." },
  ["murloc huntsman"] = { 2, "', "Murloc Huntsmen are murloc huntsmen creeps that can be encountered in many tilesets." },
  ["murloc huntsman (underworld minions)"] = { 2, "', "Murloc Huntsmen are ranged ground units of the murloc forces in the Warcraft III Demo campaign called Exodus of the Horde. They are produced at the Murloc Hut." },
  ["murloc lurker"] = { 2, "', "Murloc Lurkers are murloc mobs that can be found in Elwynn Forest, on the southeastern shore of Stone Cairn Lake and on the small river island east of the Brackwell Pumpkin Patch." },
  ["murloc minor oracle"] = { 2, "', "Murloc Minor Oracles are murlocs located at the northern coast of Westfall. Some are found on the shipwrecks off shore." },
  ["murloc minor tidecaller"] = { 2, "', "Murloc Minor Tidecallers are murlocs found by the lake's edge near Lakeridge Highway in the Redridge Mountains." },
  ["murloc mutant"] = { 2, "', "Murloc Mutants are mutant murloc creeps that can be encountered in the Felwood tileset. The bonus orc campaign The Founding of Durotar features some special Murloc Mutants, which are level 9, immense and extremely strong, expert at spellcasting." },
  ["murloc netter"] = { 2, "', "Murloc Netters are murlocs located along the northwestern coast of Westfall." },
  ["murloc nightcrawler"] = { 2, "', "Murloc Nightcrawlers are murlocs located at Stonewatch Falls in the Redridge Mountains." },
  ["murloc nightcrawler (warcraft iii)"] = { 2, "', "Murloc Nightcrawlers are murloc nightcrawler creeps that can be encountered in many tilesets." },
  ["murloc oracle"] = { 2, "', "Murloc Oracles are murlocs located along the southwestern coast of Westfall." },
  ["murloc patron"] = { 2, "', "Murloc Patrons are murlocs located in Mrgl's Bar and Gill in Nazjatar." },
  ["murloc plaguebearer"] = { 2, "', "Murloc Plaguebearers are murloc creeps that can be encountered in the Felwood tileset." },
  ["murloc puddle lord"] = { 2, "murloc operating in Lordaeron", "The Murloc Puddle Lord was a murloc operating in Lordaeron. His envoy was once spotted in the Alterac Mountains." },
  ["murloc raider"] = { 2, "', "Murloc Raiders are murlocs located at the northern coast of Westfall." },
  ["murloc ritualist"] = { 2, "', "Murloc Ritualists are murlocs appearing in the Founding of Durotar campaign." },
  ["murloc scout"] = { 2, "', "Murloc Scouts are murlocs found to the waters east of Lakeshire in the Redridge Mountains." },
  ["murloc seacultist"] = { 2, "', "Murloc Seacultists were part of the Murloc tribe of the Underworld Minions. They are found in Countdown to Extinction from the Warcraft III Demo campaign." },
  ["murloc shorestriker"] = { 2, "', "Murloc Shorestrikers are murlocs found by the lake's edge near Lakeridge Highway in Redridge Mountains." },
  ["murloc spearhunter"] = { 2, "', "Murloc Spearhunters are murlocs located at the Murloc Hideaway in Exile's Reach." },
  ["murloc streamrunner"] = { 2, "', "Murloc Streamrunners are murlocs located at Crystal Lake in Elwynn Forest. They heavily patrol the outer shores of the lake." },
  ["murloc tidecaller"] = { 2, "', "Murloc Tidecallers are murlocs found by Lake Everstill in Redridge Mountains." },
  ["murloc tidehunter"] = { 2, "', "Murloc Tidehunters are murlocs located along the southwestern coast of Westfall." },
  ["murloc tidehunters (rumble)"] = { 2, "', "Murloc Tidehunters are a ranged ground unit of the Beast family in Warcraft Rumble. Each squad of tidehunters is made up of two members by default, or three members with the Morelocs talent." },
  ["murloc tiderunner"] = { 2, "', "Murloc Tiderunners are murloc tiderunner creeps that can be encountered in many tilesets. They are light melee units and the most basic unit of the murloc race." },
  ["murloc tiderunner (underworld minions)"] = { 2, "light melee ground unit of the murloc forces in the Warcr...", "The Murloc Tiderunner is a light melee ground unit of the murloc forces in the Warcraft III Demo campaign called Exodus of the Horde. It is produced at the Murloc Hut." },
  ["murloc tidestalker"] = { 2, "', "Murloc Tidestalkers are murlocs appearing in the Founding of Durotar campaign." },
  ["murloc warrior"] = { 2, "', "Murloc Warriors are murlocs located along the western coast of Westfall." },
  ["murloc watershaper"] = { 2, "', "Murloc Watershapers are murlocs located at the Murloc Hideaway in Exile's Reach." },
  ["murloco"] = { 2, "murloc located at Murloco's Hideaway in Nazjatar", "Murloco is a murloc located at Murloco's Hideaway in Nazjatar. He is initially trapped and must be freed by defeating waves of naga enemies." },
  ["murmuring peacekeeper"] = { 2, "', "Murmuring Peacekeepers are earthen located in Dornogal." },
  ["murne greenhoof"] = { 2, "tauren located at the Tannery in Frostwall", "Murne Greenhoof is a tauren located at the Tannery in Frostwall. He is in charge of the building and provides leatherworking services." },
  ["murokk"] = { 2, "tuskarr located in the Dragon's Hoard in Valdrakken", "Murokk is a tuskarr located in the Dragon's Hoard in Valdrakken." },
  ["murrgly"] = { 2, "murloc from a fishing village in the Forgotten Coast in F...", "Murrgly is a murloc from a fishing village in the Forgotten Coast in Feralas. He used to teach his nephew Murky to fish, but he knew that the youngling wasn't good at it." },
  ["murrl"] = { 2, "murloc from a fishing village in the Forgotten Coast in F...", "Murrl is a murloc from a fishing village in the Forgotten Coast in Feralas. She has a husband named Murrgly and a nephew Murky." },
  ["mus'ten"] = { 2, "nerubian found in the Warehouse of the Burrows in the Cit...", "Mus'ten is a nerubian found in the Warehouse of the Burrows in the City of Threads." },
  ["mushroom merchant"] = { 2, "drogbar fungus vendor located at the Lost Road in Nelthar...", "Mushroom Vendor is a drogbar fungus vendor located at the Lost Road in Neltharion's Lair, a dungeon in Highmountain. He is covered with  Mushrooms for Sale." },
  ["mushroom merchant (highmountain)"] = { 2, "drogbar located in Bitestone Enclave", "Mushroom Merchant is a drogbar located in Bitestone Enclave and Greystone Enclave in Highmountain." },
  ["mushu cloudmane"] = { 2, "tauren druid located in Warfang Hold in Stormsong Valley", "Mushu Cloudmane is a tauren druid located in Warfang Hold in Stormsong Valley." },
  ["musu gentlemoon"] = { 2, "tauren druid trainer at the Crossroads in the Northern Ba...", "Musu Gentlemoon is a tauren druid trainer at the Crossroads in the Northern Barrens. This section concerns content related to Legion." },
  ["mutanus the devourer"] = { 2, "last boss of the Wailing Caverns", "Mutanus the Devourer is the last boss of the Wailing Caverns. Players must return to the entrance to summon him and will appear at the end of the escort event with Naralex." },
  ["mutated venture co. drone"] = { 2, "', "Mutated Venture Co. Drones are undead found in the Northern Barrens." },
  ["muzzle (champion deck: hogger)"] = { 2, "card from the Champion Deck: Hogger set", "Muzzle is a card from the Champion Deck: Hogger set." },
  ["mylle"] = { 2, "nerubian blacksmithing trainer located in the Umbral Baza...", "Mylle is a nerubian blacksmithing trainer located in the Umbral Bazaar in the City of Threads in Azj-Kahet." },
  ["mylton fyreswyd"] = { 2, "Arathi located in Empire's Edge Tavern in Mereldar in Hal...", "Mylton Fyreswyd is an Arathi located in Empire's Edge Tavern in Mereldar in Hallowfall. When Beledar shifted, Mylton was caught out on the coast and would have been a meal for the kobyss if Faerin hadn't been on patrol." },
  ["mylton wyldbraun"] = { 2, "Arathi located at Morgaen's Tears in Hallowfall", "Mylton Wyldbraun is an Arathi located at Morgaen's Tears in Hallowfall." },
  ["myrine"] = { 2, "kyrian located at Ithys' Basin in Bastion", "Myrine is a kyrian located at Ithys' Basin in Bastion." },
  ["mysterious ogre ninja"] = { 2, "ogre located in Frostfire Ridge", "Mysterious Ogre Ninja was an ogre located in Frostfire Ridge. He found a huge supply cache, but was taken out by the followers sent from the garrisons." },
  ["mystic makittuq"] = { 2, "tuskarr poison", "Mystic Makittuq is a tuskarr poison and reagent vendor located at the Moa'ki Harbor in the Dragonblight." },
  ["mystic ssa'veh"] = { 2, "naga located in Eye of Azshara", "Mystic Ssa'veh is a naga located in Eye of Azshara." },
  ["mystic tomkin"] = { 2, "tuskarr mystic found in Unu'pe in the Borean Tundra", "Mystic Tomkin is a tuskarr mystic found in Unu'pe in the Borean Tundra. He tells his fellow tuskarr a story every now and then." },
  ["mythressa"] = { 2, "dracthyr located in the Sapphire Enclave in Valdrakken", "Mythressa is a dracthyr located in the Sapphire Enclave in Valdrakken and in Morqut Village in the Forbidden Reach. She sells goods in return for  [Elemental Overflow]." },
  ["n'zoth watcher"] = { 2, "Waking City", "N'Zoth Watchers are ethereals located throughout Ny'alotha, the Waking City." },
  ["na'nuu"] = { 2, "Broken located in Krokul Hovel of Krokuun", "Na'nuu is a Broken located in Krokul Hovel of Krokuun." },
  ["na'val"] = { 2, "ethereal located at Fracture of Laacuna on K'aresh", "Na'val is an ethereal located at Fracture of Laacuna on K'aresh, in Untethered Space." },
  ["naakroan dunebreaker"] = { 2, "', "Naakroan Dunebreakers are ethereals located in Naakroa on K'aresh." },
  ["naakroan duststalker"] = { 2, "', "Naakroan Duststalkers are ethereals located in Naakroa on K'aresh." },
  ["naakroan soulbinder"] = { 2, "', "Naakroan Soulbinders are ethereals located in Naakroa on K'aresh." },
  ["nabiru"] = { 2, "Broken located in Eredath", "Nabiru is a Broken located in Eredath." },
  ["nadir"] = { 2, "broker located just outside Pilgrim's Grace in Zereth Mortis", "Nadir is a broker located just outside Pilgrim's Grace in Zereth Mortis." },
  ["nadjia the mistblade"] = { 2, "venthyr", "Nadjia the Mistblade is a venthyr and part of the Soulbinding process. She is first encountered in a cage in the Endmire in Revendreth." },
  ["nafien"] = { 2, "furbolg quest giver located outside Timbermaw Hold in Fel...", "Nafien is a furbolg quest giver located outside Timbermaw Hold in Felwood. He is friendly to all players, unlike other members of Timbermaw Hold." },
  ["naga corpse"] = { 2, "', "Naga Corpses are slain Zin'jatar Raiders located at Legion's Fate in Kelp'thar Forest." },
  ["naga deepstalker"] = { 2, "naga", "Naga Deepstalker is a naga." },
  ["naga explorer"] = { 2, "', "Naga Explorers are naga found in Nek'mani Wellspring in the Cape of Stranglethorn." },
  ["naga hatchling"] = { 2, "', "Naga Hatchlings are young Vashj'elan Naga in the spawning pool east of Ruins of Vashj'elan. They are protected in groups of three by Vashj'elan Warriors and Vashj'elan Sirens." },
  ["naga invader"] = { 2, "', "Naga Invaders are ghostly naga seen in the spirit realm version of the Terrace of the Fang in Vol'dun during  [30-60] The Curse of Mepjila, fighting Temple Defenders." },
  ["naga merrow"] = { 2, "naga located in Nazjatar", "Naga Merrow is a naga located in Nazjatar." },
  ["naga myrmidon"] = { 2, "', "Naga Myrmidons are naga warriors with blue skin and armed with fearsome tridents. In The Frozen Throne, myrmidons emerge from the Spawning Grounds structure." },
  ["naga myrmidon (fel hammer)"] = { 2, "', "Naga Myrmidons are naga located in the Fel Hammer serving the Illidari." },
  ["naga myrmidons"] = { 2, "', "Naga Myrmidons are naga located in the Fel Hammer. They briefly appear once their recruitment is complete." },
  ["naga royal guard"] = { 2, "', "Naga Royal Guards, as their name implies, serve as protection for important individuals. They are believed to be a magically-enhanced strain of Myrmidons." },
  ["naga sea witch (warcraft iii)"] = { 2, "', "A mystical Hero, adept at ranged combat. These scaly denizens of the ocean have often been associated with the coming of prodigious storms, but few have actually seen them rise from the sea and lived to tell the tale." },
  ["naga siren (deeprun tram)"] = { 2, "naga located outside Deeprun Tram", "Naga Siren is a naga located outside Deeprun Tram." },
  ["naga siren (warcraft iii)"] = { 2, "', "Naga Sirens are naga spellcasters. In Warcraft III, sirens emerge from the Shrine of Azshara structure." },
  ["naga summoner"] = { 2, "', "Naga Summoners are naga who Illidan made ethereal to better protect them, when they were continuing the spell Illidan cast using the Eye of Sargeras to destroy the Frozen Throne. They were killed and the Eye was destroyed by the combined forces of..." },
  ["naga tidesiren"] = { 2, "naga located in Nazjatar", "Naga Tidesiren is a naga located in Nazjatar." },
  ["nagad"] = { 2, "earthen located in the Forgegrounds in Dornogal", "Nagad is an earthen located in the Forgegrounds in Dornogal." },
  ["nagar"] = { 2, "earthen located in the Forgegrounds in Dornogal", "Nagar is an earthen located in the Forgegrounds in Dornogal." },
  ["nagojut"] = { 2, "tuskarr vendor aboard the Walker of Waves", "Nagojut is a tuskarr vendor aboard the Walker of Waves, a giant turtle that swims between Moa'ki Harbor and Unu'pe. This section concerns content related to Dragonflight." },
  ["nahari cloudchaser"] = { 2, "tauren jewelcrafting trainer located in the Cloudchaser J...", "Nahari Cloudchaser is a tauren jewelcrafting trainer located in the Cloudchaser Jewelcrafting shop on the lower rise in Thunder Bluff. This section concerns content related to Legion." },
  ["nahuud"] = { 2, "Broken quest giver found inside the Slave Pens", "Nahuud is a Broken quest giver found inside the Slave Pens. He wants revenge against his brother, who sold their whole village for his own freedom." },
  ["naimo"] = { 2, "tortollan", "Naimo is a tortollan." },
  ["naj'tess"] = { 2, "consort to the Sea Witch Zar'jira", "Naj'tess thought to turn the Darkspear's most trusted allies against them, but in so doing, he underestimates more than just the trolls. Naj'tess is the consort to the Sea Witch Zar'jira." },
  ["nak"] = { 2, "quilboar with the Razormane tribe found in Blackthorn Rid...", "Nak is a quilboar with the Razormane tribe found in Blackthorn Ridge in the Barrens. He was killed years ago, and his skull given to Mangletooth." },
  ["nakeena"] = { 2, "centaur flight master located at Pinewood Post in the Ohn...", "Nakeena is a centaur flight master located at Pinewood Post in the Ohn'ahran Plains." },
  ["nakodu"] = { 2, "Broken Lower City faction vendor located at the Lower Cit...", "Nakodu is a Broken Lower City faction vendor located at the Lower City market in Shattrath City." },
  ["nakt"] = { 2, "nerubian located in Ara-Kara", "Nakt is a nerubian located in Ara-Kara, City of Echoes." },
  ["nal fizzletongue"] = { 2, "', "The sinstone of Nal Fizzletongue is found at the southwestern end of the Chalice District in Revendreth." },
  ["nal'lak the ripper"] = { 2, "rare mantid found flying around Stoneplow Fields in Valle...", "Nal'lak the Ripper is a rare mantid found flying around Stoneplow Fields in Valley of the Four Winds. Nal'lak the Ripper is a pandarian champion." },
  ["nalaa"] = { 2, "tuskarr located on the Lost Arvillo in the Waking Shores", "Nalaa is a tuskarr located on the Lost Arvillo in the Waking Shores." },
  ["naladu"] = { 2, "Broken quest giver located at Ruins of Sha'naar in Hellfi...", "Naladu is a Broken quest giver located at Ruins of Sha'naar in Hellfire Peninsula. It seems he is the betrayer that sold out his tribe to the Illidari, but now seeks to free the remainder of the tribe so he may die in peace." },
  ["nalenn heartreaver"] = { 2, "elf paladin of the Silver Hand located in Stratholme", "Nalenn Heartreaver is an elf paladin of the Silver Hand located in Stratholme. She can be chosen to accompany the Highlord throughout the scenario during   [45] Stirring in the Shadows." },
  ["nalina ironsong"] = { 2, "Arathi innkeeper located in the Empire's Edge Tavern in M...", "Nalina Ironsong is an Arathi innkeeper located in the Empire's Edge Tavern in Mereldar in Hallowfall." },
  ["nallu"] = { 2, "tuskarr located at the Food Court stall in the Artisan's ...", "Nallu is a tuskarr located at the Food Court stall in the Artisan's Market in Valdrakken." },
  ["naluki"] = { 2, "tuskarr located in the Filled Bowl", "Naluki is a tuskarr located in the Filled Bowl and later Grimtusk's Hideaway in the Azure Span." },
  ["nalya battlehorn"] = { 2, "tauren found in the Town Hall in Frostwall once the Garri...", "Nalya Battlehorn is a tauren found in the Town Hall in Frostwall once the Garrison is in Tier 3. She offers players a chance to purchase unlocked follower contracts that were not available as quest rewards due to divergent quest lines, or having a..." },
  ["nalyx"] = { 2, "dracthyr located on the Lost Arvillo in the Waking Shores", "Nalyx is a dracthyr located on the Lost Arvillo in the Waking Shores." },
  ["namdo bizzfizzle"] = { 2, "gnome engineering vendor located in the Train Depot just ...", "Namdo Bizzfizzle was a gnome engineering vendor located in the Train Depot just outside the Gnomeregan workshop entrance. Because of the trogg invasion, business wasn't going well for him." },
  ["nameless mystic"] = { 2, "broken located at the Broken Shore", "The Nameless Mystic is a broken located at the Broken Shore." },
  ["naminze boltfingers"] = { 2, "goblin located in Undermine", "Naminze Boltfingers is a goblin located in Undermine." },
  ["namuuntsetseg"] = { 2, "centaur located at Teerakai in the Ohn'ahran Plains", "Namuuntsetseg is a centaur located at Teerakai in the Ohn'ahran Plains." },
  ["nandor"] = { 2, "venthyr trainee", "Nandor is a venthyr trainee who appears during  [60] Training Our Forces,  [60] Training in Ardenweald,  [60] Training in Bastion, and  [60] Training in Maldraxxus. He'll follow you and assist in combat while in the correct zone for the current tr..." },
  ["nanook"] = { 2, "tuskarr", "Nanook is a tuskarr who has been captured by the Squigglefin tribe on Seabreak Isle in Azsuna." },
  ["nanosh the slicer"] = { 2, "satyr", "Nanosh the Slicer was a satyr who led the Black Rook Assassins into attacking Bradensbrook. He was killed by the Council of the Black Harvest." },
  ["nanthaz"] = { 2, "earthen located in Nibelgaz Mine in the Ringing Deeps", "Nanthaz is an earthen located in Nibelgaz Mine in the Ringing Deeps. He serves under Keldaz." },
  ["nar'jira"] = { 2, "', "Nar'jira was formerly a Naz'jar Battlemaiden, but upon completing defeating the Kvaldir armies, she was crowned Champion of Azshara.  Her storyline plays out through visions via use of the  [Blade of the Naz'jar Battlemaiden]." },
  ["naraat the earthspeaker"] = { 2, "elite Broken found at the Eastern Earthshrine in Stormwin...", "Naraat the Earthspeaker is an elite Broken found at the Eastern Earthshrine in Stormwind City." },
  ["narashi spitescale"] = { 2, "naga located in Hatecoil Warcamp in Azsuna", "Narashi Spitescale is a naga located in Hatecoil Warcamp in Azsuna." },
  ["narathe"] = { 2, "ethereal located in Castigaar in K'aresh", "Narathe (/næ.'ræ.θe/ nah-WRATH-ay) is an ethereal located in Castigaar in K'aresh." },
  ["nardstrum copperpinch"] = { 2, "goblin vendor located in the Trade Quarter in the Underci...", "Nardstrum Copperpinch is a goblin vendor located in the Trade Quarter in the Undercity during the Feast of Winter Veil event. He is affiliated with Smokywood Pastures, and sells lower value holiday related items." },
  ["narg the taskmaster"] = { 2, "rare kobold", "Narg the Taskmaster is a rare kobold who wanders just outside the Fargodeep Mine in Elwynn Forest. He has a respawn timer of 20–30 minutes." },
  ["nargle boomslang"] = { 2, "', "Nargle Boomslang is Marin Noggenfogger's assistant and can be found resting in a pile of gold at Deliverance Point on the Broken Shore." },
  ["narishi"] = { 2, "flight master for the Vulpera Hideaway in Vol'dun", "Narishi is the flight master for the Vulpera Hideaway in Vol'dun." },
  ["narj deepslice"] = { 2, "dwarf meat vendor located at Refuge Pointe in the Arathi ...", "Narj Deepslice is a dwarf meat vendor located at Refuge Pointe in the Arathi Highlands." },
  ["narn"] = { 2, "Rustpine furbolg located in the Azure Span", "Narn is a Rustpine furbolg located in the Azure Span." },
  ["nascent brawler"] = { 2, "', "Nascent Brawlers are ogres located in Nagrand." },
  ["nascent dreadflail"] = { 2, "', "Nascent Dreadflails are domanaar found in Nexus-Point Xenas." },
  ["nashal"] = { 2, "vrykul", "Nashal was a vrykul. A statue of him called Nashal the Watcher is situated at Nashal's Watch in Stormheim." },
  ["nassleax bigear"] = { 2, "goblin located at Warfang Hold in Stormsong Valley", "Nassleax Bigear is a goblin located at Warfang Hold in Stormsong Valley." },
  ["nata"] = { 2, "tortollan located in the Sand Bar in Zuldazar", "Nata is a tortollan located in the Sand Bar in Zuldazar." },
  ["nata dawnstrider"] = { 2, "tauren enchanting vendor located on the middle rise in Th...", "Nata Dawnstrider is a tauren enchanting vendor located on the middle rise in Thunder Bluff. This section concerns content related to Legion." },
  ["nataniel highdawn"] = { 2, "Arathi located at Wildcamp Ul'ar in Azj-Kahet", "Nataniel Highdawn is an Arathi located at Wildcamp Ul'ar in Azj-Kahet." },
  ["nathanos blightcaller (tactics)"] = { 2, "world boss encounter located at the Marris Stead in the E...", "Nathanos Blightcaller, alongside his pets Blight-Howl and Plaguefang, is a world boss encounter located at the Marris Stead in the Eastern Plaguelands during Death Rising. He is initially surrounded by Argent Paladins and Argent Priests." },
  ["nathden"] = { 2, "earthen located in Mythic Aspirations in Dornogal", "Nathden is an earthen located in Mythic Aspirations in Dornogal." },
  ["nathenaseth"] = { 2, "dracthyr walking with Zurenoth in the Valley of Strength ...", "Nathenaseth is a dracthyr walking with Zurenoth in the Valley of Strength in Orgrimmar. He is holding a map." },
  ["nathoka bloodfang"] = { 2, "orc pet trainer located in the Barracks in Orgrimmar", "Nathoka Bloodfang is an orc pet trainer located in the Barracks in Orgrimmar." },
  ["nathrian archivist"] = { 2, "', "Nathrian Archivists are venthyr located in the Spoils of Sin in Castle Nathria." },
