  ["nathrian registrar"] = { 2, "', "Nathrian Registrars are venthyr located in the Spoils of Sin in Castle Nathria." },
  ["nathrian singuard"] = { 2, "', "Nathrian Singuards are venthyr located in Castle Nathria." },
