  ["nathrian soldier"] = { 2, "', "Nathrian Soldiers are venthyr located in Castle Nathria." },
  ["nathrian tracker"] = { 2, "', "Nathrian Trackers are venthyr located at Houndkeeper's Alley in Castle Nathria." },
  ["nau"] = { 2, "tuskarr child located in the Azure Span", "Nau is a tuskarr child located in the Azure Span. She also attended the gathering in Amirdrassil when it bloomed on the Dragon Isles after Fyrakk's death." },
  ["navarrogg"] = { 2, "leader of the Stonedark clan", "Navarrogg is the leader of the Stonedark clan, a relatively peaceful tribe of drogbar who never joined the forces of Dargrul the Underking. After an adventurer saved him and his people from the Feltotem tribe, Navarrog pledged his forces to the Hi..." },
  ["navarros"] = { 2, "Ascended kyrian located at Hero's Rest in Bastion working...", "Navarros is an Ascended kyrian located at Hero's Rest in Bastion working as the Flight Master there. He was part of the grand reception the Archon arranged for a Maw Walker, who decided to join the Kyrian Covenant, in honor of their efforts agains..." },
  ["navigator anderlain"] = { 2, "human aboard the Skybreaker in Icecrown", "Navigator Anderlain is a human aboard the Skybreaker in Icecrown." },
  ["naz'jar frost witch"] = { 2, "', "Naz'jar Frost Witches spawn during the Lady Naz'jar boss fight in Throne of the Tides." },
  ["naz'jar honor guard"] = { 2, "', "Naz'jar Honor Guards spawn during the Lady Naz'jar boss fight in Throne of the Tides. They are also seen in Shimmering Expanse and Abyssal Depths." },
  ["naz'jar invader"] = { 2, "', "Naz'jar Invaders are naga located in Throne of the Tides." },
  ["naz'jar oracle"] = { 2, "', "Naz'jar Oracles are naga located in the Throne of the Tides." },
  ["naz'jar serpent guard"] = { 2, "', "Naz'jar Serpent Guards are naga who guard the Ruins of Vashj'ir. In the visions of the Battlemaiden, they are at the Nar'shola Terrace probably commanding the Azsh'ir Soldiers." },
  ["naz'jar soldier"] = { 2, "', "Naz'jar Soldiers are naga located in the Throne of the Tides. They are fighting against Elemental Guards." },
  ["naz'jar sorceress"] = { 2, "naga located in Shimmering Expanse", "Naz'jar Sorceress is a naga located in Shimmering Expanse." },
  ["naz'jar spiritmender"] = { 2, "', "Naz'jar Spiritmenders are naga located in the Throne of the Tides." },
  ["naz'jar spitfire"] = { 2, "', "Naz'jar Spitfires are naga located in Shimmering Expanse." },
  ["naz'jar tempest witch"] = { 2, "', "Naz'jar Tempest Witches are naga found in groups before reaching Lady Naz'jar in the Throne of the Tides." },
  ["nazaruul"] = { 2, "Scourge necromancer", "Nazaruul is a Scourge necromancer, his stronghold is in the Plaguelands. He is a troll who tried to engineer a new war between humanity and orcs by driving various orcs and humans so mad with hatred in hopes that the truce collapses." },
  ["nazeer bloodpike"] = { 2, "orc quest giver located in Brackenwall Village in Dustwal...", "Nazeer Bloodpike is an orc quest giver located in Brackenwall Village in Dustwallow Marsh. He is a spymaster of the Horde." },
  ["nazeshi brawler"] = { 2, "naga", "Nazeshi Brawler is a naga." },
  ["nazeshi overseer"] = { 2, "', "Nazeshi Overseers are naga located in the Dreadpearl Shallows and Covescale Rise in Zuldazar." },
  ["nazeshi tempest-wielder"] = { 2, "', "Nazeshi Tempest-Wielders are naga located in the Dreadpearl Shallows in Zuldazar." },
  ["nazeshi tidebreaker"] = { 2, "naga brute", "The Nazeshi Tidebreaker is a naga brute that accompanies Tidecaller Nezara in the Dreadpearl Shallows in Zuldazar during the vulpera recruitment questline. When Nisha and the Horde player attack Nezara during  [40-90] Taking Out the Tidecaller, Ni..." },
  ["nazjarine trapper"] = { 2, "naga", "Nazjarine Trapper is a naga." },
  ["nazjarine vanguard"] = { 2, "naga", "Nazjarine Vanguard is a naga." },
  ["nazjarine warcaster"] = { 2, "naga", "Nazjarine Warcaster is a naga." },
  ["nazurathar"] = { 2, "dracthyr located behind the Hero's Call Board in the Trad...", "Nazurathar is a dracthyr located behind the Hero's Call Board in the Trade District in Stormwind City." },
  ["nazzivus darkblade"] = { 2, "', "Nazzivus Darkblades are satyrs located in Nazzivian on Bloodmyst Isle before the Tishamaat." },
  ["nazzivus felcaller"] = { 2, "', "Nazzivus Felcallers are satyrs located in Nazzivian on Bloodmyst Isle before the Tishamaat." },
  ["nazzivus felsworn"] = { 2, "', "Nazzivus Felsworns are satyrs found in Bloodmyst Isle." },
  ["nazzivus rogue"] = { 2, "', "Nazzivus Rogues are satyrs found on Bloodmyst Isle." },
  ["nazzivus satyr"] = { 2, "', "Nazzivus Satyrs are satyrs found on Bloodmyst Isle." },
  ["nazzivus summoner"] = { 2, "', "Nazzivus Summoners are satyrs standing around the summoning circle in Nazzivian in Bloodmyst Isle. They summon Tzerak who immediately kills them with  [Hellfire]." },
  ["neal allen"] = { 2, "human engineering", "Neal Allen is a human engineering and general goods vendor located on the bridge to Menethil Harbor in the Wetlands." },
  ["nearly headless jacob"] = { 2, "master Pet Tamer located at the shore of the Mirror of Tw...", "Nearly Headless Jacob is a master Pet Tamer located at the shore of the Mirror of Twilight in Crystalsong Forest. He is surrounded by his three level 25 battle pets: Stitch, Mort, and Spooky Strangler." },
  ["nebb"] = { 2, "kobold grubtender located in the Chittering Den in the Ri...", "Nebb is a kobold grubtender located in the Chittering Den in the Ringing Deeps. Nebb and Snubjaw were tending to their grubs when invasive undercrawlers attacked them and poisoned Snubjaw." },
  ["necrodark defiler"] = { 2, "', "Necrodark Defilers are drogbar located in Snowblind Mesa and Highmountain Summit in Highmountain." },
  ["necrodark greysworn"] = { 2, "', "Necrodark Greysworns are drogbar located in Highmountain Summit in Highmountain." },
  ["necrogg the darkspeaker"] = { 2, "drogbar leader of the Necrodark servants of Uul'gyneth in...", "Necrogg the Darkspeaker is the drogbar leader of the Necrodark servants of Uul'gyneth in Snowmane Village in Highmountain. He was killed by Huln Highmountain." },
  ["necrolord amarion"] = { 2, "human necromancer located at the bottom of the Wintergard...", "Necrolord Amarion is a human necromancer located at the bottom of the Wintergarde Crypt in the Dragonblight, communing with the Shadow of Thel'zan the Duskbringer. The Flesh-bound Tome is lying next to him." },
  ["necrolord zian"] = { 2, "mogu located on the expedition isles", "Necrolord Zian is a mogu located on the expedition isles." },
  ["necromantic mystic"] = { 2, "', "Necromantic Mystics are vrykul located in Stormheim." },
  ["nedward flanderspark"] = { 2, "gnome", "Nedward Flanderspark is a gnome who has a Gyrocopter." },
  ["needlemane"] = { 2, "quilboar", "Needlemane is a quilboar who can be encountered on Island Expeditions." },
  ["needler zhesalla"] = { 2, "mantid located in the Vale of Eternal Blossoms", "Needler Zhesalla is a mantid located in the Vale of Eternal Blossoms." },
  ["neeka bloodscar"] = { 2, "orc quest giver located in the Horde watch tower at Splin...", "Neeka Bloodscar is an orc quest giver located in the Horde watch tower at Splinterspear Junction in Swamp of Sorrows. She is one of the Horde's best trackers, trained in the Badlands." },
  ["neelo"] = { 2, "tuskarr child located in the Azure Span", "Neelo is a tuskarr child located in the Azure Span. He also attended the gathering in Amirdrassil when it bloomed on the Dragon Isles after Fyrakk's death." },
  ["neena"] = { 2, "worgen soul located in Maldraxxus", "Neena is a worgen soul located in Maldraxxus that becomes a Maldraxxi construct in a shape of a dog." },
  ["nefarious collector"] = { 2, "', "Nefarious Collectors are venthyr located in Archivam in Revendreth." },
  ["nefarious thug"] = { 2, "', "Nefarious Thugs are venthyr located in Revendreth." },
  ["nefaru"] = { 2, "rare worgen found deep in Roland's Doom in Duskwood", "Nefaru is a rare worgen found deep in Roland's Doom in Duskwood. She is on a 5-8 hour respawn timer." },
  ["nehmeh"] = { 2, "centaur located at the Artisan's Market in Valdrakken", "Nehmeh is a centaur located at the Artisan's Market in Valdrakken." },
  ["neighborhood child"] = { 2, "', "Neighborhood Children are located at the in Founder's Point and in Razorwind Shores. Some are seen following Kota Kon around and even take turns getting a ride." },
  ["neller jelenus"] = { 2, "Arathi lamplighter found standing guard at the bridge out...", "Neller Jelenus is an Arathi lamplighter found standing guard at the bridge outside Sina's Yearning leading to Lorel's Crossing in Hallowfall." },
  ["nelno copperbeam"] = { 2, "dockmaster of Valiance Keep in the Borean Tundra", "Nelno Copperbeam is the dockmaster of Valiance Keep in the Borean Tundra." },
  ["nelvek the ashen"] = { 2, "vrykul located in Stormheim", "Nelvek the Ashen is a vrykul located in Stormheim." },
  ["nemea"] = { 2, "Ascended kyrian located in Nemea's Retreat in Bastion", "Nemea is an Ascended kyrian located in Nemea's Retreat in Bastion. She is a Larion Master and rival to Pelodis, a Phalynx Master, who is also her soulbind." },
  ["neptool"] = { 2, "ghostly murloc quest giver on the Red Reaches shores of t...", "Neptool is a ghostly murloc quest giver on the Red Reaches shores of the Blasted Lands. He was the chief of the Rockpool murlocs and requests the aid of heroes to help recovery his village from the attacking Bloodwash naga." },
  ["nerada"] = { 2, "earthen located in the Forgegrounds in Dornogal", "Nerada is an earthen located in the Forgegrounds in Dornogal." },
  ["neri"] = { 2, "vulpera quest giver found next to a wagon west of the Bri...", "Neri is a vulpera quest giver found next to a wagon west of the Brine Basin in Vol'dun, next to Mekaru." },
  ["nernabel"] = { 2, "earthen located inside the Jewelcrafting shop in the Forg...", "Nernabel is an earthen located inside the Jewelcrafting shop in the Forgegrounds in Dornogal. She had an order for magma cores from Deeps that never came, so she asked an adventurer to get one from the Forgegrounds furnace." },
  ["nerub'ar broodling"] = { 2, "', "Nerub'ar Broodlings are nerubians located in the gauntlet in the Frostwing Halls in Icecrown Citadel." },
  ["nerub-ar watcher"] = { 2, "', "Nerub-ar Watchers are ethereals located throughout Nerub-ar Palace." },
  ["nerubian ambusher"] = { 2, "', "Nerubian Ambushers are nerubians who appear when interacting with Disturbed Earths in Khaz Algar." },
  ["nerubian captain"] = { 2, "', "Nerubian Captains are nerubians located in several delves and their story variants." },
  ["nerubian frontliner"] = { 2, "', "Nerubian Frontliners are nerubians attacking Livia's Patience in Hallowfall." },
  ["nerubian kinslayer"] = { 2, "', "Nerubian Kinslayers are a pair of nerubians who accompany Boroughbreaker Stik'kar on the Isle of Dorn." },
  ["nerubian lord (warcraft iii)"] = { 2, "', "Nerubian Lords are nerubian guardians who guard the path to Azjol-Nerub as part of the Nerubian Guardians in The Return to Northrend." },
  ["nerubian marauder"] = { 2, "', "Nerubian Marauders are nerubians that ambush adventurers who step in webs. They show up in The Spiral Weave and any delve with  [Web Spreaders]/ [Web Spreaders]." },
  ["nerubian saboteur"] = { 2, "', "Nerubian Saboteurs are nerubians located at the Tranquil Strand on the Isle of Dorn." },
  ["nerubian seer"] = { 2, "', "Nerubian Seers are nerubian seer creeps that can be encountered in the Icecrown Glacier and Northrend tilesets." },
  ["nerubian skirmisher"] = { 2, "', "Nerubian Skirmishers are nerubians located in the Opalcreg on the Isle of Dorn." },
  ["nerubian skulker"] = { 2, "', "Nerubian Skulkers are nerubians who ambush adventurers who step in webs. They show up in the Spiral Weave and any delve with  [Web Spreaders]/ [Web Spreaders]." },
  ["nerubian slasher"] = { 2, "', "Nerubian Slashers are nerubians located in several delves and their story variants." },
  ["nerubian stalker"] = { 2, "', "Nerubian Stalkers are nerubians who ambush adventurers who step in webs. They show up in the Spiral Weave and any delve with  [Web Spreaders]/ [Web Spreaders]." },
  ["nerubian threadmancer"] = { 2, "', "Nerubian Threadmancers are nerubians located in several delves and their story variants." },
  ["nerubian venomspitter"] = { 2, "', "Nerubian Venomspitters are nerubians located in Dalaran. They can be seen abducting the citizens of the city." },
  ["nerubian war-weaver"] = { 2, "', "Nerubian War-Weavers are nerubians located in Dalaran. They can be seen abducting the citizens of the city." },
  ["nerubian warrior"] = { 2, "', "Nerubian Warriors are nerubian warrior creeps that can be encountered in the Icecrown Glacier and Northrend tilesets. Spawns two Spiderlings upon death." },
  ["nerubian webspinner"] = { 2, "', "Nerubian Webspinners are nerubian sages located in the Tranquil Strand and nerubians found in the Opalcreg on the Isle of Dorn." },
  ["nerubian webspinner (warcraft iii)"] = { 2, "', "Nerubian Webspinners are nerubian webspinner creeps that can be encountered in the Icecrown Glacier and Northrend tilesets." },
  ["nesingwary trapper"] = { 2, "', "Nesingwary Trappers are Broken, goblins, and Forsaken found in the Borean Tundra. They can be enticed to kill themselves by placing some fur from the  [Pile of Fake Furs] on a Caribou Trap." },
  ["nether-stalker"] = { 2, "', "Nether-Stalkers are ethereals located in the Netherstorm." },
  ["nether-stalker khay'ji"] = { 2, "ethereal quest giver located at Area 52 in the Netherstorm", "Nether-Stalker Khay'ji is an ethereal quest giver located at Area 52 in the Netherstorm." },
  ["nether-stalker mah'duun"] = { 2, "ethereal quest giver located in the eastern part of the L...", "Nether-Stalker Mah'duun is an ethereal quest giver located in the eastern part of the Lower City of Shattrath, near the inn. He stands next to Wind Trader Zhareem." },
  ["nether-stalker nauthis"] = { 2, "ethereal quest giver located at the Stormspire in the Net...", "Nether-Stalker Nauthis is an ethereal quest giver located at the Stormspire in the Netherstorm. He seems to be in charge of the defense of the Stormspire against the Burning Legion." },
  ["nether-stalker oazul"] = { 2, "ethereal quest giver located at Tuluman's Landing in the ...", "Nether-Stalker Oazul is an ethereal quest giver located at Tuluman's Landing in the Netherstorm." },
  ["netherologist coppernickels"] = { 2, "goblin quest giver located at the Gyro-Plank Bridge in th...", "Netherologist Coppernickles is a goblin quest giver located at the Gyro-Plank Bridge in the Netherstorm." },
  ["nethervine inciter"] = { 2, "', "Nethervine Inciters can be found in the Botanica." },
  ["nethervine reaper"] = { 2, "', "Nethervine Reapers can be found in the Botanica." },
  ["nethervine trickster"] = { 2, "', "Nethervine Tricksters are satyrs found in the Botanica." },
  ["nethos the blighted"] = { 2, "Darkfallen death knight located in Arathi Basin during Br...", "Nethos the Blighted is a Darkfallen death knight located in Arathi Basin during Brawl: Comp Stomp for Alliance players." },
  ["netty bronzebeard"] = { 2, "great-aunt of the three Bronzebeard brothers", "Netty Bronzebeard is a great-aunt of the three Bronzebeard brothers, Magni, Muradin, and Brann. They noted that she has a temper when someone moves her knitting." },
  ["neve axeblow"] = { 2, "dwarf paladin located at Lunarfall in Shadowmoon Valley", "Neve Axeblow is a dwarf paladin located at Lunarfall in Shadowmoon Valley. She can only be recruited using the Headhunter's Harvest from Lunarfall Inn." },
  ["nevil darkstride"] = { 2, "worgen located at the Lunarfall in Shadowmoon Valley", "Nevil Darkstride is a worgen located at the Lunarfall in Shadowmoon Valley. He can only be recruited using the Headhunter's Harvest from Lunarfall Inn." },
  ["nevroll's drogbar"] = { 2, "', "Nevroll's Drogbar are a pair of drogbar located near Nevroll in Loamm in Zaralek Cavern." },
  ["news hawker"] = { 2, "Veiled Market in K'aresh", "News Hawkers are brokers located in the Gilded Landing in Tazavesh, the Veiled Market in K'aresh." },
  ["nexus stalker"] = { 2, "', "Nexus Stalkers are ethereals found in the Mana-Tombs." },
  ["nexus-king salhadaar"] = { 2, "', "Nexus-King Salhadaar (/sæl.həˈdɑːɹ/ sal-hə-DAHR) was once the ruler of the people of K'aresh, until Dimensius the All-Devouring ravaged their homeworld and scattered them across the Twisting Nether. Salhadaar led the group that became the ethereal..." },
  ["nexus-king salhadaar (tactics)"] = { 2, "boss in Manaforge Omega", "Nexus-King Salhadaar is a boss in Manaforge Omega." },
  ["nexus-lord donjon rade"] = { 2, "NPC added as part of the Warlords of Draenor beta", "Nexus-Lord Donjon Rade is an NPC added as part of the Warlords of Draenor beta, serving to teleport players to the dungeons and raids currently available for testing. He can be found in capital cities, player garrisons and other zone-in areas." },
  ["nexus-lord donjon rade iii"] = { 2, "NPC added as part of the Battle for Azeroth alpha", "Nexus-Lord Donjon Rade III is an NPC added as part of the Battle for Azeroth alpha, serving to teleport players to the dungeons and raids currently available for testing. He can be found in capital cities." },
  ["nexus-lord donjon rade iv"] = { 2, "ethereal added as part of the World of Warcraft: Shadowla...", "Nexus-Lord Donjon Rade IV is an ethereal added as part of the World of Warcraft: Shadowlands beta, serving to teleport players to the dungeons and raids currently available for testing. He can be found in capital cities." },
  ["nexus-lord donjon rade jr."] = { 2, "ethereal found in major cities", "Nexus-Lord Donjon Rade Jr. is an ethereal found in major cities." },
  ["nexus-lord donjon rade sr."] = { 2, "NPC added as part of the Legion alpha", "Nexus-Lord Donjon Rade Sr. is an NPC added as part of the Legion alpha, serving to teleport players to the dungeons and raids currently available for testing." },
  ["nexus-lord donjon rade v"] = { 2, "ethereal added as part of the World of Warcraft: Dragonfl...", "Nexus-Lord Donjon Rade V is an ethereal added as part of the World of Warcraft: Dragonflight beta, serving to teleport players to the dungeons and raids currently available for testing. He can be found in capital cities." },
  ["nexus-lord donjon rade vi"] = { 2, "ethereal added as part of the World of Warcraft: The War ...", "Nexus-Lord Donjon Rade VI is an ethereal added as part of the World of Warcraft: The War Within beta, serving to teleport players to the dungeons and raids currently available for testing. He can be found in capital cities." },
  ["nexus-lord donjon rade vii"] = { 2, "ethereal serving to teleport players to the dungeons", "Nexus-Lord Donjon Rade VII is an ethereal serving to teleport players to the dungeons and raids currently available for testing." },
  ["nexus-lord donjon rade viii"] = { 2, "ethereal serving to teleport players to the dungeons", "Nexus-Lord Donjon Rade VIII is an ethereal serving to teleport players to the dungeons and raids currently available for testing." },
  ["nexus-prince bilaal"] = { 2, "ethereal of the Ethereum", "Nexus-Prince Bilaal was an ethereal of the Ethereum who sought to use the power of the Nexus to empower himself with the Void." },
  ["nexus-prince haramad"] = { 2, "leader of the Consortium in Outland", "Nexus-Prince Haramad is the leader of the Consortium in Outland and can be seen as a hologram in the upper Stormspire, Netherstorm, and outside the Mana-Tombs of Auchindoun. In his own words, Haramad has so many enemies that would like to see him ..." },
  ["nexus-prince ky'vor"] = { 2, "ethereal located in the Shadow Docks in the Manaforge Omega", "Nexus-Prince Ky'vor is an ethereal located in the Shadow Docks in the Manaforge Omega. He is one of shadowguards summoned by Nexus-King Salhadaar." },
  ["nexus-prince razaan"] = { 2, "ethereal at the head of the Razaani", "Nexus-Prince Razaan is an ethereal at the head of the Razaani, running an operation in the Blade's Edge Mountains involving the collection of souls. His death was requested by by Leoroxx or Toshley, in order to recover his  [Collection of Souls] a..." },
  ["nexus-prince shaffar"] = { 2, "ethereal", "Nexus-Prince Shaffar is an ethereal and second nexus-prince to rule in Outland (the others being Nexus-Prince Razaan in Blade's Edge Mountains and Nexus-Prince Haramad, leader of the Consortium). He leads another faction of ethereals in the Mana-T..." },
  ["nexus-prince xevvos"] = { 2, "ethereal located in the Shadow Docks in the Manaforge Omega", "Nexus-Prince Xevvos is an ethereal located in the Shadow Docks in the Manaforge Omega. He is one of shadowguard summoned by Nexus-King Salhadaar." },
  ["nexus-thief asar"] = { 2, "card from the Tomb of the Forgotten set", "Nexus-Thief Asar is a card from the Tomb of the Forgotten set." },
  ["ney'leia"] = { 2, "haranir located in Wildcamp Or'lay in Azj-Kahet", "Ney'leia is a haranir located in Wildcamp Or'lay in Azj-Kahet." },
  ["nez'ara"] = { 2, "captured naga being held in a cave by (presumably) the ne...", "Nez'ara is a captured naga being held in a cave by (presumably) the nearby Ashvane pirates. She can be attacked after all four stakes are released." },
  ["nick arse"] = { 2, "Forsaken vendor located in front of the Cauldron of Rock ...", "Nick Arse is a Forsaken vendor located in front of the Cauldron of Rock cave on the Darkmoon Island." },
  ["nick peneckost"] = { 2, "Forsaken warlock located at Deliverance Point in the Brok...", "Nick Peneckost is a Forsaken warlock located at Deliverance Point in the Broken Shore." },
  ["nicolas araujo"] = { 2, "human flight master located at Mariner's Row in Boralus", "Nicolas Araujo is a human flight master located at Mariner's Row in Boralus." },
  ["nicole harris"] = { 2, "worgen", "Nicole Harris is a worgen." },
  ["nielas aran"] = { 2, "court conjurer of Stormwind", "Nielas Aran was the court conjurer of Stormwind, advisor to the throne and father and teacher of the sorcerer Medivh. Of all the mages, wizards, conjurers, and sorcerers, he had the most potential to protect and strengthen Medivh." },
  ["niena bladeleaf"] = { 2, "Darkfallen death knight standing with Synthanos Winterson...", "Niena Bladeleaf is a Darkfallen death knight standing with Synthanos Wintersong on the eastern edge of Oribos." },
  ["niepha shelvan"] = { 2, "Arathi located in the Empire's Edge Tavern in Mereldar in...", "Niepha Shelvan is an Arathi located in the Empire's Edge Tavern in Mereldar in Hallowfall." },
  ["night lord"] = { 2, "', "Night Lords are male undead located in the Guest Chambers in Karazhan. They are disguised as humans, but at 50% health they reveal their true appearance, removing all debuffs in the process." },
  ["night mistress"] = { 2, "', "Night Mistresses are female undead located in the Guest Chambers in Karazhan. They are disguised as humans, but at 50% health they reveal their true appearance, removing all debuffs in the process." },
  ["nightbane dark runner"] = { 2, "', "Nightbane Dark Runners are worgen found in Duskwood." },
  ["nightbane shadow weaver"] = { 2, "', "Nightbane Shadow Weavers are worgen found in Duskwood." },
  ["nightbane stalker"] = { 2, "', "Nightbane Stalkers are worgen located at the Rotting Orchard in Duskwood." },
  ["nightbane tainted one"] = { 2, "', "Nightbane Tainted Ones are worgen found in Duskwood." },
  ["nightbane vile fang"] = { 2, "', "Nightbane Vile Fangs are worgen found in Duskwood." },
  ["nightbane worgen"] = { 2, "', "Nightbane Worgen can be found in Duskwood." },
  ["nightbane worgen (radiant echoes)"] = { 2, "', "Nightbane Worgen are worgen located in the Ruby Dragonshrine in the Dragonblight when the Radiant Echoes event is inactive." },
  ["nightcaller velys"] = { 2, "Arathi found in Priory of the Sacred Flame during  [80] A...", "Nightcaller Velys is an Arathi found in Priory of the Sacred Flame during  [80] A Light in the Dark." },
  ["nightcloak fencer"] = { 2, "', "Nightcloak Fencers are venthyr located in Revendreth." },
  ["nightfall commander"] = { 2, "', "Nightfall Commanders are Arathi located in The Dawnbreaker." },
  ["nightfall curseblade"] = { 2, "', "Nightfall Curseblades are Arathi located in The Dawnbreaker." },
