  ["nightfall darkcaster"] = { 2, "', "Nightfall Darkcasters are Arathi found in the Dawnbreaker." },
  ["nightfall executor"] = { 2, "', "Nightfall Executors are Arathi located in Nightfall Sanctum, Skittering Breach, and Spiral Weave." },
  ["nightfall hopestealer"] = { 2, "', "Nightfall Hopestealers are Arathi located in Nightfall Sanctum, Skittering Breach, and Spiral Weave." },
  ["nightfall initiate"] = { 2, "', "Nightfall Initiates are Arathi located in Nightfall Sanctum and Skittering Breach. Some of them give up and run away after being defeated." },
  ["nightfall inquisitor"] = { 2, "', "Nightfall Inquisitors are Arathi located in Nightfall Sanctum, Skittering Breach, and the Spiral Weave." },
  ["nightfall lookout"] = { 2, "', "Nightfall Lookouts are Arathi located in Nightfall Sanctum, Spiral Weave, and Skittering Breach." },
  ["nightfall ritualist"] = { 2, "', "Nightfall Ritualists are Arathi located in The Dawnbreaker." },
  ["nightfall shadeguard"] = { 2, "', "Nightfall Shadeguards are Arathi located in Nightfall Sanctum, Spiral Weave, and Skittering Breach." },
  ["nightfall shadowalker"] = { 2, "', "Nightfall Shadowalkers are Arathi located in Mereldar during The Dawnbreaker dungeon." },
  ["nightfall shadowmage"] = { 2, "', "Nightfall Shadowmages are Arathi located in The Dawnbreaker." },
  ["nightfall tactician"] = { 2, "', "Nightfall Tacticians are Arathi located in Mereldar during The Dawnbreaker dungeon." },
  ["nightmare rider"] = { 2, "', "Nightmare Riders are satyrs located in the Garden of the Moon in Val'sharah." },
  ["nightmare runner"] = { 2, "', "Nightmare Runners are worgen located in the Rotting Orchard within the Duskwood Nightmare Incursion, accessed through the Dream portal in the Twilight Grove." },
  ["nightmare watcher"] = { 2, "ethereal located in the Emerald Nightmare", "The Nightmare Watcher is an ethereal located in the Emerald Nightmare." },
  ["nightmare weaver"] = { 2, "', "Nightmare Weavers are worgen located in the Rotting Orchard within the Duskwood Nightmare Incursion, accessed through the Dream portal in the Twilight Grove." },
  ["nightshade abductor"] = { 2, "', "Nightshade Abductors are Arathi located in Rambleshire on Isle of Dorn." },
  ["nightshade ambusher"] = { 2, "', "Nightshade Ambushers are a pair of Arathi located in Freywold Village on the Isle of Dorn during  [70-73] The Pillage of Freywold Village." },
  ["nikamik"] = { 2, "tuskarr child found with Maru", "Nikamik is a tuskarr child found with Maru and Tuk at the pier of Unu'pe in the Borean Tundra during the Bronze Celebration." },
  ["nikara blackheart"] = { 2, "Forsworn kyrian located in Bastion", "Nikara Blackheart is a Forsworn kyrian located in Bastion. She is summoned during the Vesper Repair: Sophia's Aria event." },
  ["nikolon"] = { 2, "kyrian located in Bastion", "Nikolon, initially seen as Disciple Nikolon and then as Fallen Disciple Nikolon, is a kyrian located in Bastion. After being given a new physical form, Nikolon was a deeply empathic soul who found himself unable to let go of his emotions and chose..." },
  ["nikto"] = { 2, "tortollan located at the Dive Bar in Zuldazar", "Nikto is a tortollan located at the Dive Bar in Zuldazar." },
  ["niles brokenboot"] = { 2, "goblin located in Undermine", "Niles Brokenboot is a goblin located in Undermine." },
  ["nilika blastbeaker"] = { 2, "goblin poisons", "Nilika Blastbeaker is a goblin poisons, reagents, and alchemy vendor located at K3 in Storm Peaks." },
  ["nillen andemar"] = { 2, "dwarf mace vendor located on the Stonewrought Dam in Loch...", "Nillen Andemar is a dwarf mace vendor located on the Stonewrought Dam in Loch Modan." },
  ["nilsa"] = { 2, "vulpera quest giver located in the Valley of Honor in Org...", "Nilsa is a vulpera quest giver located in the Valley of Honor in Orgrimmar alongside Kiro, Meerah, and Nisha." },
  ["nimm codejack"] = { 2, "gnome member of the SI:7", "Nimm Codejack is a gnome member of the SI:7 who was tasked by King Varian Wrynn to find the White Pawn in Pandaria. She traveled on the Skyfire from Stormwind City and arrived in the Jade Forest." },
  ["ninil'ko the bloodcaller"] = { 2, "efficient mentor", "\"Battle is an efficient mentor.\" Ninil'ko the Bloodcaller was a Klaxxi paragon, a legend of the mantid who was chosen, as all paragons are, to be encased in amber and preserved for when his strength was needed. Many thousands of years ago, the Kla..." },
  ["nipper"] = { 2, "nerubian spiderling located in the Fissure in Dornogal ne...", "Nipper is a nerubian spiderling located in the Fissure in Dornogal next to the tunnel leading to the Weaver's Lair." },
  ["nipskee fizzwidget"] = { 2, "goblin", "Nipskee Fizzwidget is a goblin who works for the Gadgetzan Times. He interviewed Nuxt Sparklespring about the engineering required to blow stuff up, and Nuxt was more than happy to give a demonstration." },
  ["niqu"] = { 2, "tuskarr child located in Camp Antonidas", "Niqu is a tuskarr child located in Camp Antonidas and Iskaara in the Azure Span." },
  ["nirathan"] = { 2, "dracthyr located in the Canals in Stormwind City", "Nirathan is a dracthyr located in the Canals in Stormwind City. He can be found walking between the Trade District and Old Town, looking at a map." },
  ["nirazal"] = { 2, "dracthyr flight master located at the Vault of the Incarn...", "Nirazal is a dracthyr flight master located at the Vault of the Incarnates in Thaldraszus." },
  ["nirobin"] = { 2, "member of the Azerothian Archives", "Nirobin is a member of the Azerothian Archives and a codicological archeologist. He is a self-proclaimed genius in the field of arcane codicology which is done through fusing blue and bronze dragon magic." },
  ["nisa cindersteel"] = { 2, "Arathi found patroling Light's Blooming in Hallowfall", "Nisa Cindersteel is an Arathi found patroling Light's Blooming in Hallowfall. This section concerns content related to Midnight." },
  ["nisha"] = { 2, "reckless vulpera fighter", "Nisha is a reckless vulpera fighter that is encountered throughout Vol'dun and plays a leading role in the battles against the Faithless sethrak." },
  ["nitazemish"] = { 2, "dracthyr located on the second level of the building at O...", "Nitazemish is a dracthyr located on the second level of the building at Obsidian Rest in Zaralek Cavern." },
  ["nivvet channelock"] = { 2, "gnome quest giver in Thundermar in the Twilight Highlands", "Nivvet Channelock is a gnome quest giver in Thundermar in the Twilight Highlands. He knows how to weld." },
  ["njorndar spear-sister"] = { 2, "', "Njorndar Spear-Sisters are vrykul located in Jotunheim in Icecrown. This section concerns content related to Shadowlands." },
  ["noatak"] = { 2, "tuskarr fish", "Noatak is a tuskarr fish and fishing supplies vendor found in Kamagua in the Howling Fjord." },
  ["noble courtier"] = { 2, "', "Noble Courtiers are venthyr located in the Court of the Harvesters in Revendreth." },
  ["noble reveler"] = { 2, "', "Noble Revelers are venthyr located in the Eternal Terrace in Revendreth." },
  ["noble skirmisher"] = { 2, "', "Noble Skirmishers are venthyr located in Sanguine Depths." },
  ["nobu"] = { 2, "ankoan flight master located at the Tidal Conflux in Nazj...", "Nobu is an ankoan flight master located at the Tidal Conflux in Nazjatar." },
  ["nodd codejack"] = { 2, "gnome member of the SI:7", "Nodd Codejack is a gnome member of the SI:7 who was tasked by King Varian Wrynn to find the White Pawn in Pandaria. When the Skyfire arrived in the Jade Forest, he got sick and was briefly tended to by Mishka." },
  ["noggrin onetooth"] = { 2, "unique kobold to the north of Orgrimmar during the Foundi...", "Noggrin Onetooth was a unique kobold to the north of Orgrimmar during the Founding of Durotar. He was killed by Rexxar and Rokhan in To Tame a Land." },
  ["nokhud apprentice"] = { 2, "', "Nokhud Apprentices are centaur located at Nokhudon Hold in the Ohn'ahran Plains and in the Nokhud Offensive." },
  ["nokhud battleguard"] = { 2, "', "Nokhud Battleguards are centaur located at Nokhudon Hold in the Nokhud Offensive." },
  ["nokhud beastmaster"] = { 2, "', "Nokhud Beastmasters are centaur located at the Battle of Spears in the Nokhud Offensive." },
  ["nokhud betrayer"] = { 2, "', "Nokhud Betrayers are centaur located in Maruukai in the Ohn'ahran Plains." },
  ["nokhud brute"] = { 2, "', "Nokhud Huntmasters are centaur located at Nokhudon Hold and Maruukai in the Ohn'ahran Plains and in the Nokhud Offensive." },
