  ["nomurok"] = { 2, "dead tuskarr located in Brackenhide Brambles in the Azure...", "Nomurok is a dead tuskarr located in Brackenhide Brambles in the Azure Span. Being a young tuskarr, he went with his fellow tuskarr to his first hunt, but was killed by the Brackenhide gnolls." },
  ["norah"] = { 2, "vulpera quest giver located at Camp Lastwind in Vol'dun", "Norah is a vulpera quest giver located at Camp Lastwind in Vol'dun." },
  ["nordric albrite"] = { 2, "human located in the Arathi Highlands", "Nordric Albrite is a human located in the Arathi Highlands. He can be found in a small house, dancing with (presumed wife) Greta Albrite." },
  ["norgabbon of stonedark"] = { 2, "drogbar located in Highmountain during the Legion Assaults", "Norgabbon of Stonedark is a drogbar located in Highmountain during the Legion Assaults." },
  ["norgor"] = { 2, "ogre captain of the Bloodfist located on the Molten Cay", "Norgor is an ogre captain of the Bloodfist located on the Molten Cay." },
  ["nori blackfinger"] = { 2, "', "Nori Blackfinger was once a Master Weaponsmith living in the Searing Gorge, specifically at Thorium Point. His blades were some of the finest in the world, and adventurers far and wide traveled to Thorium Point to have a weapon made by him." },
  ["norlaxx"] = { 2, "rare mogu located just south of Kri'vess in the Townlong ...", "Norlaxx is a rare mogu located just south of Kri'vess in the Townlong Steppes.  Norlaxx is a pandarian champion." },
  ["norobi"] = { 2, "tortollan located at the Seekers' Vista in Stormsong Valley", "Norobi is a tortollan located at the Seekers' Vista in Stormsong Valley. He will appear to welcome the adventurer during the completion of  [30-60] Battle Victorious and  [50WQ] Turtle Tactics." },
  ["nort"] = { 2, "tortollan located at the Seekers' Vista in Stormsong Valley", "Nort is a tortollan located at the Seekers' Vista in Stormsong Valley. He will appear to welcome the adventurer during the completion of  [30-60] Battle Victorious and  [50WQ] Turtle Tactics." },
  ["norukk"] = { 2, "bespectacled tuskarr located in Iskaara in the Azure Span", "Norukk is a bespectacled tuskarr located in Iskaara in the Azure Span. After the tuskarr caravan was ambushed by the Shadepaw gnolls, Norukk and some others were taken prisoner." },
  ["norvin alderman"] = { 2, "human cloak vendor located at the Runeweaver Square in Da...", "Norvin Alderman is a human cloak vendor located at the Runeweaver Square in Dalaran. It is unknown if he survived the destruction of Dalaran." },
  ["notfar the unbearable"] = { 2, "furbolg located inside a cave at the southern shore of th...", "Notfar the Unbearable is a furbolg located inside a cave at the southern shore of the Azure Span." },
  ["nothazoral"] = { 2, "dracthyr located in the Valley of Honor in Orgrimmar", "Nothazoral is a dracthyr located in the Valley of Honor in Orgrimmar. He is found fishing besides Lumak." },
  ["novice acquirer"] = { 2, "Veiled Market", "Novice Acquirers are brokers located in Tazavesh, the Veiled Market." },
  ["novice plifa"] = { 2, "tuskarr located at Gelikyr Post in Thaldraszus", "Novice Plifa is a tuskarr located at Gelikyr Post in Thaldraszus. She is found with Miya and Shoo upstairs in the inn." },
  ["novice quilboar"] = { 2, "', "Novice Quilboar are quilboar located in Razorfen Kraul." },
  ["noxiia atoh"] = { 2, "draenei located at the Lunarfall in Shadowmoon Valley", "Noxiia Atoh is a draenei located at the Lunarfall in Shadowmoon Valley. She can only be recruited using the Headhunter's Harvest from Lunarfall Inn." },
  ["nozand"] = { 2, "vulpera of Keg Leg's Crew located in Brew Bay in the Arat...", "Nozand is a vulpera of Keg Leg's Crew located in Brew Bay in the Arathi Highlands during Plunderstorm. Nozand is chasing Pincushion." },
  ["nozwik charbroil"] = { 2, "goblin vendor located in the Rusty Cylinder in the Pinchw...", "Nozwik Charbroil is a goblin vendor located in the Rusty Cylinder in the Pinchwhistle Gearworks in the Spires of Arak." },
  ["nuana"] = { 2, "furbolg located on Longclaw Island in the Azure Span", "Nuana is a furbolg located on Longclaw Island in the Azure Span." },
  ["nub the torturer"] = { 2, "ogre located at the Stonefury Cliffs in Frostfire Ridge", "Nub the Torturer is an ogre located at the Stonefury Cliffs in Frostfire Ridge." },
  ["nudara the shaper"] = { 2, "ethereal located in the Maelstrom Mercantile at the Grand...", "Nudara the Shaper is an ethereal located in the Maelstrom Mercantile at the Grand Bazaar in Dazar'alor. This ethereal can reforge Azerite gear and select again Azerite traits." },
  ["nuggle coinbender"] = { 2, "final buoy with Nuggle's corpse beside it", "The corpse of Nuggle Coinbender is found at  floating in the Evanescent Sea, off the southeastern coast of Spires of Arak between Pinchwhistle Point and the Wreck of the Mother Lode. Off shore from Sporemist Shallows and Pinchwhistle Gearworks is ..." },
  ["nulia"] = { 2, "tuskarr flight master located at Apex Canopy in the Wakin...", "Nulia is a tuskarr flight master located at Apex Canopy in the Waking Shores." },
  ["null glimmer"] = { 2, "Shadowed Crucible", "Null Glimmers are dracthyr projections summoned by the Scalecommander Sarkareth in Aberrus, the Shadowed Crucible." },
  ["nullaeus"] = { 2, "domanaar playing the role as the delves nemesis during Mi...", "Nullaeus is a domanaar playing the role as the delves nemesis during Midnight Season 1." },
  ["nullifier darkoor"] = { 2, "ogre located at the Ring of Blood in Nagrand", "Nullifier Darkoor is an ogre located at the Ring of Blood in Nagrand." },
  ["numa cloudsister"] = { 2, "level 1 tauren shaman located just inside the Slave Pens ...", "Numa Cloudsister is a level 1 tauren shaman located just inside the Slave Pens of Coilfang Reservoir. She is part of the Midsummer Fire Festival storyline to interfere with Ahune's summoning." },
  ["nuna"] = { 2, "tuskarr child located in Iskaara in the Azure Span", "Nuna is a tuskarr child located in Iskaara in the Azure Span." },
  ["nunaha grasshoof"] = { 2, "tauren leatherworking supplier located at the Shrine of A...", "Nunaha Grasshoof is a tauren leatherworking supplier located at the Shrine of Aviana in Mount Hyjal." },
  ["nunvuq"] = { 2, "tuskarr fishing trainer located in Iskaara in the Azure Span", "Nunvuq is a tuskarr fishing trainer located in Iskaara in the Azure Span." },
  ["nuptuk"] = { 2, "tuskarr child located in the Azure Span", "Nuptuk is a tuskarr child located in the Azure Span." },
  ["nur'rek the good husband"] = { 2, "nerubian located in the City of Threads", "Nur'rek the Good Husband is a nerubian located in the City of Threads." },
  ["nurse dolores"] = { 2, "worgen nurse located in Greywatch in Stormheim", "Nurse Dolores is a worgen nurse located in Greywatch in Stormheim. She is first seen in Greywatch tending to a Greywatch Guard that is suffering from Blight infection, but after Genn Greymane battles Sylvanas Windrunner in the Vault of Eyir, she s..." },
  ["nutaaq"] = { 2, "tuskarr dockmaster located at Kamagua in the Howling Fjord", "Nutaaq is a tuskarr dockmaster located at Kamagua in the Howling Fjord." },
  ["nutraal"] = { 2, "dracthyr located in Aberrus", "Nutraal is a dracthyr located in Aberrus, the Shadowed Crucible." },
  ["nye'rangi"] = { 2, "haranir located in Harandar", "Nye'rangi is a haranir located in Harandar." },
  ["nynthia"] = { 2, "Arathi located with Geoffy in Mereldar in Hallowfall", "Nynthia is an Arathi located with Geoffy in Mereldar in Hallowfall." },
  ["nyx bloodrage"] = { 2, "orc located in Durotar", "Nyx Bloodrage is an orc located in Durotar." },
  ["nyz'raal the umbral blade"] = { 2, "ethereal", "Nyz'raal the Umbral Blade is an ethereal who attacks Locus-Walker and Alleria Windrunner in the P.O.S.T. in Tazavesh, the Veiled Market during  [80] The Darkness Among Us." },
  ["o'mogg blackheart"] = { 2, "member of the Shadow Council", "O'mogg Blackheart is a member of the Shadow Council and aided in stealing the Heart of Auchindoun. While the Auchindoun defenders were able to save the Heart's core, they were only able to retain one of its pieces." },
  ["oaken crusher"] = { 2, "', "Oaken Crushers are Drust located in the Oaken Assembly in Ardenweald." },
  ["oakenpaw"] = { 2, "furbolg", "Oakenpaw is a furbolg." },
  ["oakheart drust-taken"] = { 2, "', "Oakheart Drust-Taken are Drust located in the Oaken Assembly in Ardenweald." },
  ["oakheart soul-eater"] = { 2, "', "Oakheart Soul-Eaters are Drust located in the Oaken Assembly in Ardenweald." },
  ["oakpaw"] = { 2, "rare furbolg found roaming throughout Greenpaw Village in...", "Oakpaw is a rare furbolg found roaming throughout Greenpaw Village in Ashenvale. He's on a 10.5-16 hour respawn timer." },
  ["oasis guest"] = { 2, "Veiled Market", "Oasis Guests are brokers located at the patio of Myza's Oasis in Tazavesh, the Veiled Market." },
