  ["oasis server"] = { 2, "Veiled Market", "Oasis Servers are brokers located in Myza's Oasis in Tazavesh, the Veiled Market." },
  ["oathbound warder"] = { 2, "', "Oathbound Warders are earthen who have been summoned by the  [Horn of the Peaks] during  [25-30] The Earthen Oath and  [25-30] Loken's Lackeys. Summoning them will dismiss current warlock or hunter pets." },
  ["oathbreaker"] = { 2, "ankoan", "Oathbreaker was an ankoan who betrayed his clan out of fear and frailty. They lie buried at an Ankoan Burial Shrine north of Mezzamere in Nazjatar." },
  ["oathspeaker al'joul"] = { 2, "ethereal located at North Sufaad on K'aresh", "Oathspeaker Al'joul is an ethereal located at North Sufaad on K'aresh." },
  ["oathsworn administrator"] = { 2, "earthen ocated at the Forgegrounds in Dornogal", "Oathsworn Administrator is an earthen ocated at the Forgegrounds in Dornogal who can be seen speaking with a recently arrived goblin named Norb." },
  ["oathsworn citizen"] = { 2, "', "Oathsworn Citizens are earthen located throughout Dornogal." },
  ["oathsworn councilguard"] = { 2, "', "Oathsworn Councilguards are earthen located at the Councilward's Rise in Dornogal." },
  ["oathsworn dignitary"] = { 2, "', "Oathsworn Dignitaries are earthen located in the Foundation Hall in Dornogal." },
  ["oathsworn holdout"] = { 2, "', "Oathsworn Holdouts are earthen located at the Dock Lifts in the Rookery." },
  ["oathsworn peacekeeper"] = { 2, "', "Oathsworn Peacekeepers are earthen located throughout Dornogal." },
  ["oathsworn stormrider"] = { 2, "', "Oathsworn Stormriders are earthen accompanying Baelgrim in the Tranquil Strand on the Isle of Dorn." },
  ["oathsworn trader"] = { 2, "', "Oathsworn Traders are earthen located at the Crossroads Plaza on the Isle of Dorn." },
  ["oathsworn tunnelwatcher"] = { 2, "', "Oathsworn Tunnelwatchers are earthen who guard the tunnel leading from the Weaver's Lair in Azj-Kahet to Dornogal." },
  ["oathsworn worker"] = { 2, "', "Oathsworn Workers are earthen located in the Forgegrounds in Dornogal and at the Crossroads Plaza on the Isle of Dorn. Some are seen driving carts pulled by Cart Haulers." },
  ["obrul the thug"] = { 2, "drogbar", "Obrul the Thug is a drogbar and member of the Stonedark clan who appears in the Hall of Chieftains in Thunder Totem after completing  [10-45] Unexpected Allies." },
  ["obsidian guard"] = { 2, "Shadowed Crucible", "Obsidian Guards are djaradin located in Aberrus, the Shadowed Crucible." },
  ["obsidian magus"] = { 2, "Shadowed Crucible", "Obsidian Magi are dracthyr located in Aberrus, the Shadowed Crucible." },
  ["obsidian warder"] = { 2, "', "Obsidian Warders are dracthyr located in the War Creche in the Forbidden Reach. At the Old Weyrn Grounds, some of them are being healed by Talon Menders." },
  ["obsidian warder custodian"] = { 2, "', "Obsidian Warder Custodians are dracthyr located in the War Creche in the Forbidden Reach." },
  ["obstorn"] = { 2, "earthen located in Dornogal", "Obstorn is an earthen located in Dornogal." },
  ["odan battlebow"] = { 2, "dwarf flight master located at the Trueshot Lodge in High...", "Odan Battlebow is a dwarf flight master located at the Trueshot Lodge in Highmountain." },
  ["odarrok"] = { 2, "earthen located on the Isle of Dorn", "Odarrok is an earthen located on the Isle of Dorn." },
  ["odessa belford"] = { 2, "undead", "Odessa Belford is an undead who briefly appears at Raven Hill Cemetery in Duskwood. She is a member of the Cult of Forgotten Shadows, guards the body of Natalie Seline, and assists the High Priest of the Conclave in reviving her." },
  ["odo the blindwatcher (classic)"] = { 2, "boss in Shadowfang Keep", "Odo the Blindwatcher is a boss in Shadowfang Keep." },
  ["odrinn bronzekeel"] = { 2, "dwarf of Keg Leg's Crew located in Brew Bay in the Arathi...", "Odrinn Bronzekeel is a dwarf of Keg Leg's Crew located in Brew Bay in the Arathi Highlands during Plunderstorm. He can be found begging in front of a pile of treasure." },
  ["odrogg"] = { 2, "drogbar located in Highmountain", "Odrogg is a drogbar located in Highmountain." },
  ["odyn"] = { 2, "', "Odyn is one of the titanic Keepers and the ruler of the Valarjar in the Halls of Valor. Once the Prime Designate of Azeroth, he was betrayed by the corrupted Loken cursed by his surrogate daughter Helya to be trapped in the Halls of Valor along wi..." },
  ["off duty stalwart"] = { 2, "', "Off Duty Stalwarts are Arathi located at Flotsam Shoal and Ghoststone Diggings on the Siren Isle." },
  ["off-duty laborer (hallowfall)"] = { 2, "human located in Dunelle's Kindness in Hallowfall", "Off-Duty Laborer is a human located in Dunelle's Kindness in Hallowfall. During the Shadow Curfew, they are inside a building." },
  ["off-duty stormguard"] = { 2, "', "Off-Duty Stormguards are earthen located at the Keepers Terrace in Dornogal." },
  ["off-duty stormrider"] = { 2, "', "Off-Duty Stormriders are earthen located in Keepers Terrace in Dornogal." },
  ["officer areyn"] = { 2, "human accessories vendor located outside Champions' Hall ...", "Officer Areyn is a human accessories vendor located outside Champions' Hall in Old Town in Stormwind City." },
  ["ogarth axefall"] = { 2, "orc located in Stormsong Valley", "Ogarth Axefall is an orc located in Stormsong Valley." },
  ["ogdrul"] = { 2, "drogbar located at Den of the Seeker in Trueshot Lodge of...", "Ogdrul is a drogbar located at Den of the Seeker in Trueshot Lodge of Highmountain. He wields a bow that looks like  [Rhok'delar, Longbow of the Ancient Keepers]." },
  ["ogg'marr"] = { 2, "ogre meat", "Ogg'marr is an ogre meat and drink vendor located in Brackenwall Village in Dustwallow Marsh." },
  ["oggog magmafist"] = { 2, "ogre located in Island Expeditions", "Oggog Magmafist is an ogre located in Island Expeditions." },
  ["ogir"] = { 2, "Broken reagents & poison vendor located at Telaar in Nagrand", "Ogir is a Broken reagents & poison vendor located at Telaar in Nagrand." },
  ["ogmot the mad"] = { 2, "ogre located in the Twilight Outpost of the post-sword ve...", "Ogmot the Mad (also known as Ogmot the Steadfast) is an ogre located in the Twilight Outpost of the post-sword version of Silithus." },
  ["ognip blastbolt"] = { 2, "roadie for the Level 80 Elite Tauren Chieftains found in ...", "Ognip Blastbolt is a roadie for the Level 80 Elite Tauren Chieftains found in the Grim Guzzler in Blackrock Depths." },
  ["ograbisi"] = { 2, "ogre prisoner found inside the Halls of the Law of Blackr...", "Ograbisi is an ogre prisoner found inside the Halls of the Law of Blackrock Depths. He shares a cell with Jaz the orc." },
  ["ogre (warcraft ii)"] = { 2, "', "The Ogres are the monstrous two-headed allies of the Orcs that were brought through the Portal by the Warlock Gul'dan after the First War to act as enforcers in an effort to quell needless infighting between the Orc clans. Due to the constant bick..." },
  ["ogre (beta)"] = { 2, "unreleased ogre", "Ogre is an unreleased ogre." },
  ["ogre ambusher"] = { 2, "', "Ogre Ambushers are two ogres standing on a cliff in Gilneas. They hurled boulders at the Stagecoach Carriage causing it to crash." },
  ["ogre bodyguard"] = { 2, "', "Ogre Bodyguards are ogres found guarding the door leading to Glubtok's room in the Deadmines." },
  ["ogre bodyguard (deepholm)"] = { 2, "', "Ogre Bodyguards are ogres who can be found protecting Millhouse Manastorm at his camp at the Upper Silvermarsh in Deepholm." },
  ["ogre brute"] = { 2, "', "Ogre Brutes are ogre warriors serving under Mug'thol of the Stonemaul clan during The Dark Lady." },
  ["ogre brute (exile's reach)"] = { 2, "', "Ogre Brutes are ogres located at the Darkmaul Citadel on Exile's Reach. During  [7-10] Right Beneath Their Eyes, they're friendly toward the player." },
  ["ogre chef"] = { 2, "ogre located at the Darkmaul Citadel in Exile's Reach", "The Ogre Chef is an ogre located at the Darkmaul Citadel in Exile's Reach. He moves around his workspace—from the fire, to the slab of meat on the table, to the pot filled with humanoid-looking bones—busily preparing food." },
  ["ogre henchman"] = { 2, "', "Ogre Henchmen are ogres located within the first section of the Deadmines, sometimes using the candles atop Kobold Diggers' heads to light their cannons." },
  ["ogre high arcanist"] = { 2, "', "Ogre High Arcanists were ogres of the Twilight's Blade found just east of Kirthaven in the Twilight Highlands during  [10-80WQ] Don't Bring That Here." },
  ["ogre imperion"] = { 2, "ogre", "Ogre Imperion is an ogre." },
  ["ogre magi ritualist"] = { 2, "', "Ogre Magi Ritualists were ogres of the Twilight's Blade who spawn during the 'Slay the Ritualists' stage of a Twilight's Call in the Twilight Highlands." },
  ["ogre girl"] = { 2, "servant of King Gordok", "A small ogre girl belonged to the Dire Maul Gordunni clan and was a servant of King Gordok. He was constantly slapping her." },
  ["ogros blazeseer"] = { 2, "orc located in Arathi Basin during Brawl: Comp Stomp for ...", "Ogros Blazeseer is an orc located in Arathi Basin during Brawl: Comp Stomp for Alliance players." },
  ["ogtinc"] = { 2, "furbolg hunter located upon a cliff overlooking the Ruins...", "Ogtinc is a furbolg hunter located upon a cliff overlooking the Ruins of Eldarath southeast of Timbermaw Hold in Azshara. He left his tribe in order to aid the Cenarion Circle." },
  ["ogudei"] = { 2, "mogu ruler", "Ogudei was the mogu ruler that built an edifice within the mountains of Krasarang Wilds. The Reliquary has taken interest in him, though little is known about him." },
  ["ogudei darkweaver"] = { 2, "', "Ogudei Darkweavers are unreleased mogu." },
  ["ogudei guardian"] = { 2, "', "Ogudei Guardians are unreleased mogu." },
  ["ogudei tormenter"] = { 2, "', "Ogudei Tormenters are unreleased mogu." },
  ["ohlorn farstrider"] = { 2, "tauren found in Garadar at Nagrand", "Ohlorn Farstrider is a tauren found in Garadar at Nagrand. He and Steven Walker used to hunt with only his totem and skivvies." },
  ["ohn aghi"] = { 2, "centaur of Clan Ohn'ir located on a cliff northeast of th...", "Ohn Aghi is a centaur of Clan Ohn'ir located on a cliff northeast of the krutal in Maruukai in the Ohn'ahran Plains, where he sits hovering above the ground inside a whirlwind." },
  ["ohn arasara"] = { 2, "centaur sitting on the east side of the Ohn'ir pools in M...", "Ohn Arasara is a centaur sitting on the east side of the Ohn'ir pools in Maruukai in the Ohn'ahran Plains. Windsage Dawa wants her guidance in preparing a proposal for Hunter Narman." },
  ["ohn meluun"] = { 2, "centaur located in Ohn'iri Springs in the Ohn'ahran Plains", "Ohn Meluun is a centaur located in Ohn'iri Springs in the Ohn'ahran Plains." },
  ["ohn seshteng"] = { 2, "centaur of Clan Ohn'ir serving as the spiritual advisor t...", "Ohn Seshteng is a centaur of Clan Ohn'ir serving as the spiritual advisor to Clan Shikaar in the Ohn'ahran Plains. She is first seen at her tent north of Timberstep Outpost as adventurers are introducing themselves to Shikaar who'll be joining the..." },
  ["ohn'ir windsage"] = { 2, "', "Ohn'ir Windsages are centaur located in the Ohn'ahran Plains." },
  ["oisin cragshot"] = { 2, "dwarf located at Lunarfall in Shadowmoon Valley", "Oisin Cragshot is a dwarf located at Lunarfall in Shadowmoon Valley. He would accept the turn-in of various items in exchange for  [Garrison Resources]." },
  ["okada"] = { 2, "tortollan innkeeper located at the Seekers' Vista in Stor...", "Okada is a tortollan innkeeper located at the Seekers' Vista in Stormsong Valley." },
  ["okir"] = { 2, "centaur of Clan Shikaar", "Okir is a centaur of Clan Shikaar who serves as the deaf Sansok Khan's interpreter in the Ohn'ahran Plains. He is always by his khan's side, acting as her speaker for those not versed in her signs and translating others' speech into sign language ..." },
  ["okrek"] = { 2, "rare arakkoa found in Terokkar Forest", "Okrek is a rare arakkoa found in Terokkar Forest." },
  ["okuna longtusk"] = { 2, "tuskarr found in Azsuna", "Okuna Longtusk  is a tuskarr found in Azsuna." },
  ["okuno"] = { 2, "Broken of the Ashtongue Deathsworn", "Okuno is a Broken of the Ashtongue Deathsworn and their faction rewards vendor who can be found in the Black Temple. When the Burning Legion returned, Okuno was defeated by the Illidari in order to infiltrate the Black Temple." },
  ["ol' dunken"] = { 2, "individual of the Bloodsail Buccaneers sent by Fleet Mast...", "Ol' Dunken is an individual of the Bloodsail Buccaneers sent by Fleet Master Firallon to scout an area in the Cape of Stranglethorn and to wait for the signal to attack Booty Bay in year 25." },
  ["ol' gail"] = { 2, "Arathi located in Beledar's Bounty", "Ol' Gail is an Arathi located in Beledar's Bounty, and later Lothar's Landing, in Hallowfall." },
  ["ol' waxbeard"] = { 2, "boss in Darkflame Cleft", "Ol' Waxbeard is a boss in Darkflame Cleft." },
  ["olbarig"] = { 2, "member of the Stormriders", "Olbarig is a member of the Stormriders, currently serving as one of Stormward Lufsela's Stormguards. He originally held this position under Stormward Baelgrim but left the order after a disagreement with Baelgrim regarding the binding of the storm..." },
  ["old fillmaff"] = { 2, "undead located in the Hall of the Guardian", "Old Fillmaff is an undead located in the Hall of the Guardian. He served Dalaran for several decades until the death knight Arthas Menethil attacked the city during the Third War." },
  ["old gate defender"] = { 2, "', "Old Gate Defenders are venthyr located at the Old Gate in Revendreth." },
  ["old gate merchant"] = { 2, "', "Old Gate Merchants are venthyr located at the Old Gate in Revendreth." },
  ["old grimtusk"] = { 2, "tuskarr located in the Upper Frostlands in the Azure Span", "Old Grimtusk is a tuskarr located in the Upper Frostlands in the Azure Span. He is in charge of Grimtusk's Hideaway." },
  ["old grizzleback"] = { 2, "furbolg located in Grizzleweald in Val'sharah", "Old Grizzleback is a furbolg located in Grizzleweald in Val'sharah. When the grells attacked the village during te third invasion of the Burning Legion, he tasked adventurers with defeating them and their leader, Enderkind." },
  ["old grmgl"] = { 2, "murloc located on the expedition isles", "Old Grmgl is a murloc located on the expedition isles." },
  ["old icefin"] = { 2, "murloc located on the Chillmere Coast", "Old Icefin is a murloc located on the Chillmere Coast. His son, Rotgill, has been turned into a mur'ghoul and the elder murloc offers a quest to reclaim the son's trident." },
  ["old murk-eye"] = { 2, "murloc", "Old Murk-Eye is a murloc that patrols the shore of Westfall, near the old Westfall Lighthouse. Captain Grayson wants Murk-Eye killed." },
  ["old murk-eye (azmerloth)"] = { 2, "murloc located in Azmerloth", "Old Murk-Eye is a murloc located in Azmerloth." },
  ["old murk-eye (rumble)"] = { 2, "melee ground unit of the Beast family in Warcraft Rumble", "Old Murk-Eye is a melee ground unit of the Beast family in Warcraft Rumble. Old Murk-Eye is an extremely weak unit on his own, but his hero ability allows for the player to flood the board with Murloc Tidehunters." },
  ["old natuuri"] = { 2, "centaur of Clan Ohn'ir located in the Carving Winds in th...", "Old Natuuri is a centaur of Clan Ohn'ir located in the Carving Winds in the Ohn'ahran Plains. She is not present on days when  [10-70WQ] Wind Breaker is available." },
  ["old rotten gill"] = { 2, "murloc", "Old Rotten Gill is a murloc." },
  ["oldge bonecreaker"] = { 2, "goblin located in the spectator area at the Bilgewater Fl...", "Oldge Bonecreaker is a goblin located in the spectator area at the Bilgewater Flats in Undermine." },
  ["olem"] = { 2, "broker located just outside Pilgrim's Grace in Zereth Mortis", "Olem is a broker located just outside Pilgrim's Grace in Zereth Mortis. He is worried about the dried Wellspring of the First Ones and wishes to restore its source in Provis Esper." },
  ["olgraneer"] = { 2, "earthen located in the Great Forge in Ironforge", "Olgraneer is an earthen located in the Great Forge in Ironforge." },
  ["olive (vulpera)"] = { 2, "vulpera child sitting on a rock next to the waterfall in ...", "Olive is a vulpera child sitting on a rock next to the waterfall in the Valley of Honor in Orgrimmar." },
  ["oliver harris"] = { 2, "worgen quest giver located in Raven Hill in Duskwood", "Oliver Harris is a worgen quest giver located in Raven Hill in Duskwood. He is working to save the mindless worgen running rampant in the area." },
  ["oliver hopewell"] = { 2, "worgen located in Bashal'Aran in Darkshore", "Oliver Hopewell is a worgen located in Bashal'Aran in Darkshore." },
  ["olivia abbington"] = { 2, "human innkeeper located at the Fort Wrynn in Talador", "Olivia Abbington is a human innkeeper located at the Fort Wrynn in Talador." },
  ["olmin burningbeard"] = { 2, "dwarf hunter trainer located in the Hall of Arms in the M...", "Olmin Burningbeard is a dwarf hunter trainer located in the Hall of Arms in the Military Ward in Ironforge." },
  ["olmyr the enlightened"] = { 2, "vrykul located in the Halls of Valor", "Olmyr the Enlightened is a vrykul located in the Halls of Valor. He becomes a ghost." },
  ["olnayvi copperpinch"] = { 2, "goblin vendor located in Shattrath City during the Feast ...", "Olnayvi Copperpinch is a goblin vendor located in Shattrath City during the Feast of Winter Veil, on the Terrace of Light outside the Scryers Bank. He is affiliated with Smokywood Pastures and sells higher value holiday-related items." },
  ["oloraak"] = { 2, "arakkoa fish vendor located in the Lower City of Shattrat...", "Oloraak is an arakkoa fish vendor located in the Lower City of Shattrath City." },
  ["olrenan"] = { 2, "earthen located at the Valley of Wisdom in Orgrimmar", "Olrenan is an earthen located at the Valley of Wisdom in Orgrimmar." },
  ["olthran craghelm"] = { 2, "dwarf heavy armor vendor located at the Military Ward wit...", "Olthran Craghelm is a dwarf heavy armor vendor located at the Military Ward within Ironforge. He is one of the owners of Craghelm's Plate and Chain." },
  ["oltuk"] = { 2, "tuskarr vendor located in the Common in Razorwind Shores", "Oltuk is a tuskarr vendor located in the Common in Razorwind Shores and Town Center in Founder's Point when the Reaching Beyond the Possible endeavor is active." },
  ["oluf the violent"] = { 2, "vrykul gladiator in the Ring of Judgement in the Howling ...", "Oluf the Violent is a vrykul gladiator in the Ring of Judgement in the Howling Fjord. He needs to be slain during  [10-30] Stunning Defeat at the Ring." },
  ["olut alegut"] = { 2, "orc quest giver", "Olut Alegut is an orc quest giver and alcohol vendor located near the Grom'arsh Crash Site in Storm Peaks. He is notable for selling  [Iron Boot Flask], which is required for  [But I'm On Your Side]." },
  ["olyssion the reclaimer"] = { 2, "kyrian located in the Path of Wisdom in Bastion", "Olyssion the Reclaimer is a kyrian located in the Path of Wisdom in Bastion. When approached, he rungs a bell, and Horrible Recollections appear, upon which Olyssion dies, and the Abandoned Memory spawns." },
  ["om'dodaf"] = { 2, "broker flight master located in Hosaas' Rest in K'aresh", "Om'Dodaf is a broker flight master located in Hosaas' Rest in K'aresh." },
  ["om'khell"] = { 2, "broker located in the Oasis in K'aresh", "Om'Khell is a broker located in the Oasis in K'aresh." },
  ["om'aad"] = { 2, "broker vendor found near Eco-Dome: Primus in K'aresh", "Om'aad is a broker vendor found near Eco-Dome: Primus in K'aresh." },
  ["om'bera"] = { 2, "member of The Ravel", "Om'bera was a member of The Ravel and wielder of one of the Reshii Ribbons. After the destruction of K'aresh, she became a broker." },
  ["om'door"] = { 2, "broker", "Om'door is a broker who appears in Eco-Dome: Primus in K'aresh." },
  ["om'en"] = { 2, "broker located in Tazavesh", "Om'en is a broker located in Tazavesh, the Veiled Market in K'aresh." },
  ["om'kota"] = { 2, "broker", "Om'kota is a broker who appears in The Oasis in K'aresh." },
  ["om'milla"] = { 2, "ethereal located in the Gilded Landing in Tazavesh", "Om'milla is an ethereal located in the Gilded Landing in Tazavesh, the Veiled Market." },
  ["om'mit"] = { 2, "broker located in Tazavesh", "Om'mit is a broker located in Tazavesh, the Veiled Market in K'aresh." },
  ["om'myuz"] = { 2, "broker located in Tazavesh", "Om'myuz is a broker located in Tazavesh, the Veiled Market in K'aresh." },
  ["om'nittar"] = { 2, "broker", "Om'nittar is a broker who appears in Eco-Dome: Primus on K'aresh." },
  ["om'rajula"] = { 2, "broker", "Om'rajula is a broker that appears in Stormwind, Orgrimmar, and Dornogal after completing  [10-90] Lorewalking: The Brokers, part of the Lorewalking campaign. He starts  [10-90] Locus-Walker, Telogrus Ranger, continuing the campaign." },
  ["om'raulf"] = { 2, "broker vendor found in Hosaas' Rest in K'aresh", "Om'aad is a broker vendor found in Hosaas' Rest in K'aresh." },
  ["om'reka"] = { 2, "broker", "Om'reka is a broker who appears in The Oasis in K'aresh." },
  ["om'resh"] = { 2, "broker", "Om'resh is a broker who appears in Eco-Dome: Rhovan in K'aresh. Om'resh was working at the eco-dome with Om'bera as a team for thousands of years, when a meteor destroyed his home, so he and Om'bera tried to salvage what they could, including taki..." },
  ["om'sharik"] = { 2, "broker located at Overlook Zo'Shuul on K'aresh", "Om'sharik is a broker located at Overlook Zo'Shuul on K'aresh." },
  ["om'sirik"] = { 2, "broker located at the Tazavesh", "Om'sirik is a broker located at the Tazavesh, the Veiled Market in K'aresh. He is the renown quartermaster for the K'aresh Trust major faction." },
  ["om'taha"] = { 2, "broker located in the Naakroa in K'aresh", "Om'talad is a broker located in the Naakroa in K'aresh. Along with Om'musa and Om'baladh, she was sent by Cartel Om to install an echo machine in the ruins to study the long-dead flora of K'aresh." },
  ["om'talad"] = { 2, "broker located in the Oasis in K'aresh", "Om'talad is a broker located in the Oasis in K'aresh. Om'talad is one of the brokers to place bets on Slateback Alpha races with adventurers at The Oasis." },
  ["om'thenai"] = { 2, "broker located in the Gilded Landing in Tazavesh in K'aresh", "Om'thenai is a broker located in the Gilded Landing in Tazavesh in K'aresh." },
  ["om'torid"] = { 2, "broker located at the Oasis on K'aresh", "Om'torid is a broker located at the Oasis on K'aresh." },
  ["om'volt"] = { 2, "broker innkeeper located at the Oasis on K'aresh", "Om'volt is a broker innkeeper located at the Oasis on K'aresh." },
  ["omapurita"] = { 2, "tuskarr tailoring trainer located in Iskaara in the Azure...", "Omapurita is a tuskarr tailoring trainer located in Iskaara in the Azure Span. At Iskaara Tuskarr Renown 6, she sells cosmetic helms." },
  ["omar the test dragon"] = { 2, "character used several times throughout the various test ...", "Omar the Test Dragon is a character used several times throughout the various test phases. During the Wrath of the Lich King beta, he would send out mails including a version of the  [Carrot on a Stick] that would enchant mounts individually." },
  ["omasum blighthoof"] = { 2, "tauren death knight located in the Plaguewood of Eastern ...", "Omasum Blighthoof is a tauren death knight located in the Plaguewood of Eastern Plaguelands under the command of Aurius Rivendare. He and Karthis Darkrune are guarding the entrance to Stratholme." },
  ["omenai curate"] = { 2, "', "Omenai Curates are draenei and Broken located in the Ring of Observance in Terokkar Forest and in the Trader's Tier in the Exodar during the Tishamaat." },
  ["omi"] = { 2, "vulpera quest giver located on the western outskirts of t...", "Omi is a vulpera quest giver located on the western outskirts of the Court of Zak'rajan in Vol'dun alongside Kenzou and Tacha. She 'can't spit dust' when it comes to magic, but claims to be able to mix poisons and potions with the best of them." },
  ["ominura"] = { 2, "stasis-locked earthen located in the Ringing Deeps", "Ominura is a stasis-locked earthen located in the Ringing Deeps." },
  ["on'hiea"] = { 2, "haranir located in Wildcamp Or'lay in Azj-Kahet", "On'hiea (pronounced /ɒnˈhaɪə/) is a haranir located in Wildcamp Or'lay in Azj-Kahet." },
  ["onaaka"] = { 2, "young tuskarr fisher from Taruka's clan", "Onaaka is a young tuskarr fisher from Taruka's clan. He was born on the same day and under the same constellation as Taruka, but whereas she struggled to be seen at all, he was set on making a name for himself and always tried to belittle her." },
  ["ondani greatmill"] = { 2, "tauren cooking trainer during Pilgrim's Bounty in the Dra...", "Ondani Greatmill is a tauren cooking trainer during Pilgrim's Bounty in the Dranosh'ar Blockade in Durotar." },
  ["one tusk"] = { 2, "tuskarr member of the Algari Expedition located in Fungal...", "One Tusk is a tuskarr member of the Algari Expedition located in Fungal Folly." },
  ["one-eyed thak"] = { 2, "swolbold located in an otherwise abandoned tower on the I...", "One-Eyed Thak is a swolbold located in an otherwise abandoned tower on the Isle of Dorn." },
  ["ongrom black tooth"] = { 2, "orc vendor for the commissions collected in the Krasarang...", "Ongrom Black Tooth is an orc vendor for the commissions collected in the Krasarang Wilds for the Dominance Offensive." },
  ["onlooker"] = { 2, "', "Onlookers are untargetable NPCs of various covenant races that make up the majority of the crowd in the Crucible in Oribos during  [60] A Long Walk,  [60] The Fate of Sylvanas, and the start of  [60] Penance and Renewal. Their ranks consist of kyr..." },
  ["ono'me"] = { 2, "tuskarr found at Kamagua in Howling Fjord", "Ono'me is a tuskarr found at Kamagua in Howling Fjord." },
  ["oogrooq"] = { 2, "tuskarr poison", "Oogrooq is a tuskarr poison and reagent vendor found east of Unu'pe in the Borean Tundra." },
  ["oomailiq"] = { 2, "tuskarr", "Oomailiq is a tuskarr who steers the Green Island, a giant turtle, between Moa'ki Harbor and Kamagua." },
  ["oooki"] = { 2, "tortollan following the Trained Crab at the Seekers' Vist...", "Oooki is a tortollan following the Trained Crab at the Seekers' Vista in Stormsong Valley." },
  ["opalcreg worker"] = { 2, "', "Opalcreg Workers are earthen located in the Opalcreg on the Isle of Dorn. Some are found dead." },
  ["opalfang"] = { 2, "furbolg located in the Vault of the Incarnates as part of...", "Opalfang is a furbolg located in the Vault of the Incarnates as part of The Primal Council encounter." },
  ["opalin"] = { 2, "earthen located in Freywold Village on the Isle of Dorn", "Opalin is an earthen located in Freywold Village on the Isle of Dorn." },
  ["ophelia"] = { 2, "naga sea witch responsible for the destruction of several...", "Ophelia is a naga sea witch responsible for the destruction of several Alliance ships and the deaths of untold crew within the Obsidian Breakers in the Twilight Highlands. Her sweet music, coupled with her night elf illusion, proves too much for m..." },
  ["opulence ba'hare"] = { 2, "broker located in the Broker's Den in Oribos", "Opulence Ba'hare is a broker located in the Broker's Den in Oribos." },
  ["or'jan"] = { 2, "haranir located at the Twilight Shore in Darkshore lookin...", "Or'jan is a haranir located at the Twilight Shore in Darkshore looking at Teldrassil. Finding Or'jan is one of the criteria of the exploration achievement  [More Than Just Their Roots]." },
  ["orange murloc egg"] = { 2, "', "The Orange Murloc Egg will summon Murki the murloc." },
  ["orator kloe"] = { 2, "kyrian located in Aspirant's Crucible in Bastion", "Orator Kloe is a kyrian located in Aspirant's Crucible in Bastion." },
  ["order of night disciple"] = { 2, "', "Order of Night Disciples are Arathi located in Hallowfall." },
  ["oreg earthfury"] = { 2, "tauren shaman with the Earthen Ring", "Oreg Earthfury was a tauren shaman with the Earthen Ring that lived sometime after the era of the War of the Three Hammers. When Sorcerer-thane Thaurissan released Ragnaros and shattered the Redridge Mountains of the Eastern Kingdoms, the effects ..." },
  ["orfus of kamagua"] = { 2, "tuskarr at the top of Ancient Lift", "Orfus of Kamagua is a tuskarr at the top of Ancient Lift that takes one to Kamagua. Orfus is the partner of Lunk-tusk, and one of Kamagua's strongest warriors." },
  ["organizer xy'hal"] = { 2, "broker located in Tazavesh", "Organizer Xy'hal is a broker located in Tazavesh, the Veiled Market in K'aresh." },
  ["organizer xy'mern"] = { 2, "broker located in Tazavesh", "Organizer Xy'mern is a broker located in Tazavesh, the Veiled Market in K'aresh." },
  ["organizer xy'vim"] = { 2, "broker located in Tazavesh", "Organizer Xy'vim is a broker located in Tazavesh, the Veiled Market in K'aresh." },
  ["oric coe"] = { 2, "', "Oric Coe is Adam Eternum's gnomish sidekick found in the Lower City of Shattrath City. This section concerns content related to Battle for Azeroth." },
  ["oric the baleful"] = { 2, "vrykul hero of the Winterskorn clan found at Balejar Watc...", "Oric the Baleful is a vrykul hero of the Winterskorn clan found at Balejar Watch in Howling Fjord." },
  ["orida"] = { 2, "earthen caretaker found atop the mountainside southwest o...", "Orida is an earthen caretaker found atop the mountainside southwest of Dornogal where she can be seen taking care of the tribute stones and the shutdown earthen found in that place." },
  ["original harvester of wrath"] = { 2, "', "The original Harvester of Wrath is one of the original venthyr Harvesters who were created directly by Sire Denathrius. Long ago, her power was stripped from her and given to the Stonewright, who has held the title of Harvester of Wrath ever since." },
  ["orin grimblade"] = { 2, "Darkfallen death knight follower located at the Frostwall...", "Orin Grimblade is a Darkfallen death knight follower located at the Frostwall in Frostfire Ridge. He can only be recruited using the Headhunter's Harvest from Frostwall Tavern." },
  ["orinoko tuskbreaker"] = { 2, "tuskarr abandoned in his youth", "Orinoko Tuskbreaker is a tuskarr abandoned in his youth. He is the fourth boss in the Amphitheater of Anguish." },
  ["orise"] = { 2, "ankoan flight master located at Orise's Vigil in Nazjatar", "Orise is an ankoan flight master located at Orise's Vigil in Nazjatar." },
  ["orluna"] = { 2, "Ascended kyrian located at the Elysian Hold in Bastion", "Orluna is an Ascended kyrian located at the Elysian Hold in Bastion. She sells cloaks, and ensembles, wherein the cloaks are included after completing  [Disciple of Humility]." },
  ["ormagrogg"] = { 2, "drogbar located in a cave of Snowblind Mesa in Highmountain", "Ormagrogg is a drogbar located in a cave of Snowblind Mesa in Highmountain." },
  ["ormgul the pestilent"] = { 2, "leader of the drogbar attack on Earthmother's Bounty in H...", "Ormgul the Pestilent is the leader of the drogbar attack on Earthmother's Bounty in Highmountain." },
  ["ormhun stonehammer"] = { 2, "earthen located in Deepholm", "Ormhun Stonehammer is an earthen located in Deepholm." },
  ["ornekka"] = { 2, "arakkoa in Spires of Arak", "Ornekka is a arakkoa in Spires of Arak." },
  ["oronn many-tongues"] = { 2, "ogre located in Molten Cay during Island Expeditions", "Oronn Many-Tongues is an ogre located in Molten Cay during Island Expeditions." },
  ["oronu the elder"] = { 2, "Broken shaman found at the Ruins of Baa'ri in Shadowmoon ...", "Oronu the Elder is a Broken shaman found at the Ruins of Baa'ri in Shadowmoon Valley." },
  ["orox darkhorn"] = { 2, "ally card from the War of the Ancients set", "Orox Darkhorn is an ally card from the War of the Ancients set." },
  ["orphan matron battlewail"] = { 2, "orc quest giver located in The Drag in Orgrimmar", "Orphan Matron Battlewail is an orc quest giver located in The Drag in Orgrimmar. She lives and works at the city's orphanage with Tosamina." },
  ["orren masyn"] = { 2, "Arathi located at Beledar's Bounty in Hallowfall", "Orren Masyn is an Arathi located at Beledar's Bounty in Hallowfall." },
  ["orsenth"] = { 2, "earthen located in the Nibelgaz Mine in the Ringing Deeps", "Orsenth is an earthen located in the Nibelgaz Mine in the Ringing Deeps. When earth elementals overrun Mine, the refinery crew were trapped with them." },
  ["orthus cliffwalker"] = { 2, "son of High Chieftain Cliffwalker", "Orthus Cliffwalker was the son of High Chieftain Cliffwalker and Masha Cliffwalker. During the questline in Stonetalon Mountains, he along with his parents are trying to protect Thal'darah Grove from Overlord Krom'gar's and General Grebo's false a..." },
  ["ortor of murkblood"] = { 2, "Broken found in Nagrand", "Ortor of Murkblood is a Broken found in Nagrand. He is a notable leader in the Murkblood tribe, once a noble shaman and friend of Arechron, Ortor went evil and became a muck-addled yes-man of Swamplord Musel'ek." },
  ["orville manfred"] = { 2, "worgen found at the stable outside Hero's Rest Inn in Sto...", "Orville Manfred is a worgen found at the stable outside Hero's Rest Inn in Stormshield. He is also found in Shatterstone Harbor in Vol'dun." },
  ["orweyna"] = { 2, "leader of the group of haranir scouts in Azj-Kahet", "Orweyna is the leader of the group of haranir scouts in Azj-Kahet, where she works to protect the great roots by containing the spread of Black Blood. Fascinated by the mortal races, she shares their concerns about the threat posed by the Kaheti a..." },
  ["osidion"] = { 2, "earthen located in the Tradelounge in the Forgegrounds in...", "Osidion is an earthen located in the Tradelounge in the Forgegrounds in Dornogal." },
  ["oskaer daleclash"] = { 2, "dead Arathi located in Sunless Strand in Hallowfall", "Oskaer Daleclash is a dead Arathi located in Sunless Strand in Hallowfall, encountered during  [80] Those Who Fell.  [Oskaer Daleclash's Tinderbox] belonged to him." },
  ["oskaer fortfervor"] = { 2, "Arathi located in Wildcamp Or'lay in Azj-Kahet", "Oskaer Fortfervor is an Arathi located in Wildcamp Or'lay in Azj-Kahet." },
  ["ossik"] = { 2, "worgen located in the Roasted Ram in Valdrakken", "Ossik is a worgen located in the Roasted Ram in Valdrakken. He is reading a book." },
  ["ota wen"] = { 2, "furbolg held captive at Silverwind Refuge in Ashenvale Fo...", "Ota Wen is a furbolg held captive at Silverwind Refuge in Ashenvale Forest." },
  ["otonambusi"] = { 2, "Broken general goods vendor located at Azure Watch in Azu...", "Otonambusi is a Broken general goods vendor located at Azure Watch in Azuremyst Isle." },
  ["otonbu the sage"] = { 2, "Broken quest giver located at Telaar in Nagrand", "Otonbu the Sage is a Broken quest giver located at Telaar in Nagrand. Otonobu is concerned about the Murkblood tribe massacring the Mag'har Sunspring Post and dumping the bodies of their victims, the Sunspring Villagers, into the lake." },
  ["otto (tortollan)"] = { 2, "tortollan child", "Otto is a tortollan child." },
  ["ottukhandler rutanko"] = { 2, "tuskarr stable master located in Uktulut Backwater in the...", "Ottukhandler Rutanko is a tuskarr stable master located in Uktulut Backwater in the Waking Shores." },
  ["outcast darkscryer"] = { 2, "', "Outcast Darkscryers are two Arakkoa Outcasts involved in  [40 Daily] Assault on Skettis and  [40] Missive: Assault on Skettis.  They can only be seen while on the quests." },
  ["outcast darktalon"] = { 2, "', "Outcast Darktalons are arakkoa located in Talador at Veil Shadar." },
  ["outcast harbinger"] = { 2, "', "Outcast Harbingers are arakkoa found in the Dark Woods in Ashran." },
  ["outcast kasimir"] = { 2, "venthyr located in the Ember Ward in Revendreth", "Outcast Kasimir is a venthyr located in the Ember Ward in Revendreth. He and his lover, Outcast Mirceo, stand next to the Outcast's Makeshift Muckpool." },
  ["outcast mirceo"] = { 2, "venthyr located in the Ember Ward in Revendreth", "Outcast Mirceo is a venthyr located in the Ember Ward in Revendreth. He and his lover, Outcast Kasimir, stand next to the Outcast's Makeshift Muckpool." },
  ["outcast necromancer"] = { 2, "', "Outcast Necromancers are centaur located in the Valley of Bones in Desolace. They can summon Undead Ravagers in battle." },
  ["outcast shadeweaver"] = { 2, "', "Outcast Shadeweavers are arakkoa located at Veil Shadar in Talador." },
