  ["outfitter eric"] = { 2, "gnome speciality tailoring vendor located in the Great Fo...", "Outfitter Eric is a gnome speciality tailoring vendor located in the Great Forge in Ironforge." },
  ["outfitter reynolds"] = { 2, "worgen located at Trueshot Lodge in Highmountain", "Outfitter Reynolds is a worgen located at Trueshot Lodge in Highmountain." },
  ["outrider balul"] = { 2, "deceased orc located at Icewind Drifts in Frostfire Ridge", "Outrider Balul is a deceased orc located at Icewind Drifts in Frostfire Ridge." },
  ["over-indulged patron"] = { 2, "', "Over-Indulged Patrons are gnolls, goblins, humans, and trolls located in the Flaming Taps in Cinderbrew Meadery." },
  ["overlord agmar"] = { 2, "Kor'kron leader of Agmar's Hammer", "\"I am many things, death knight, but two things I am NOT are STUPID and ILL-INFORMED\" Overlord Agmar is the Kor'kron leader of Agmar's Hammer, a major Horde base in the Dragonblight. He seemed to be the one who made the taunka's acceptance into th..." },
  ["overlord agmar (tactics)"] = { 2, "primary objective for the Alliance", "Overlord Agmar, who established the Horde base of Agmar's Hammer in Dragonblight, now leads the Horde in the Isle of Conquest and is accompanied by four Kor'kron Guards.  Defeating him is the primary objective for the Alliance." },
  ["overlord barbarius"] = { 2, "orc found in one of the caves on Redridge Canyons in the ...", "Overlord Barbarius is an orc found in one of the caves on Redridge Canyons in the Redridge Mountains. He's holding Danforth chained from wall to wall and is preparing to sacrifice him." },
  ["overlord blackhammer"] = { 2, "', "Overlord Blackhammer heads the Iron Horde forces stationed at the Iron Siegeworks. SI:7 has placed a bounty on his head for unknown crimes." },
  ["overlord bor'gorok"] = { 2, "orc located at the Bor'gorok Outpost in the Borean Tundra", "Overlord Bor'gorok is an orc located at the Bor'gorok Outpost in the Borean Tundra. He refused to allow the shaman to heal Ortrosh in order to teach him a good lesson and to give him time to reflect upon his failure." },
  ["overlord gorefist"] = { 2, "ogre found at Ango'rosh Stronghold in Zangarmarsh", "Overlord Gorefist is an ogre found at Ango'rosh Stronghold in Zangarmarsh." },
  ["overlord mok'morokk"] = { 2, "ogre quest giver located in Brackenwall Village in Dustwa...", "Overlord Mok'Morokk is an ogre quest giver located in Brackenwall Village in Dustwallow Marsh." },
  ["overlord ramtusk"] = { 2, "quilboar mini-boss found in Razorfen Kraul", "Overlord Ramtusk is a quilboar mini-boss found in Razorfen Kraul." },
  ["overlord ror"] = { 2, "named black Deadwood furbolg found in Deadwood Village in...", "Overlord Ror is a named black Deadwood furbolg found in Deadwood Village in Felwood. Dreka'Sur wanted Ror's cold, dead claw." },
  ["overseer akrath"] = { 2, "Adherent of Rukhmar", "Overseer Akrath is an Adherent of Rukhmar and the leader of the Apexis Excavation that accidentally stumbled upon a large ruin filled with Apexis technology. He controls the Apexis turret, using it to carve away chunks of mountain, and to incinera..." },
  ["overseer ardgrin"] = { 2, "earthen located in the Hallowfall Gate in the Ringing Deeps", "Overseer Ardgrin is an earthen located in the Hallowfall Gate in the Ringing Deeps. He is a trade overseer, managing the shipping tracks and running his shipments from the Deeps to Dornogal." },
  ["overseer atticus"] = { 2, "Forsworn kyrian located at the Eternal Forge in Bastion", "Overseer Atticus is a Forsworn kyrian located at the Eternal Forge in Bastion." },
  ["overseer axefist"] = { 2, "orc located at the Vol'jin's Pride in Talador", "Overseer Axefist is an orc located at the Vol'jin's Pride in Talador." },
  ["overseer blingbang"] = { 2, "', "Overseer Blingbang is one of the men of Baron Revilgaz, who sent him to find an object that would keep the trolls out of Booty Bay." },
  ["overseer flamelicker"] = { 2, "kobold located in Skittering Hollow", "Overseer Flamelicker is a kobold located in Skittering Hollow." },
  ["overseer hajeer"] = { 2, "naga located at the Zanj'ir Terrace in Nazjatar", "Overseer Hajeer is a naga located at the Zanj'ir Terrace in Nazjatar." },
