  ["overseer hyggred"] = { 2, "earthen located outside the Council's Treasury in Dornogal", "Overseer Hyggred is an earthen located outside the Council's Treasury in Dornogal." },
  ["overseer krix"] = { 2, "kobold located in Galson's Lode in the Arathi Highlands", "Overseer Krix is a kobold located in Galson's Lode in the Arathi Highlands, and a priority target for the Horde and the Alliance during the Battle for Stromgarde. He eventually succumbed to his opponents." },
  ["overseer lahar"] = { 2, "djaradin located in the Smoldering Barracks in Neltharus", "Overseer Lahar is a djaradin located in the Smoldering Barracks in Neltharus." },
  ["overseer rat-tail"] = { 2, "kobold located on the expedition isles", "Overseer Rat-Tail is a kobold located on the expedition isles." },
  ["overseer roskarrag"] = { 2, "earthen character in 'Forget Me Not'", "Overseer Roskarrag is an earthen character in 'Forget Me Not', a play performed by the theater troupe at the Proscenium on the Isle of Dorn. She didn't approve of Brunelda and Clodgran's love as she believed it reduced their efficiency in their wo..." },
  ["overseer sakar'thiss"] = { 2, "naga", "Overseer Sakar'thiss is a naga." },
  ["overseer snorgle"] = { 2, "kobold located on the expedition isles", "Overseer Snorgle is a kobold located on the expedition isles." },
  ["overseer steelsnout"] = { 2, "kobold located on the expedition isles", "Overseer Steelsnout is a kobold located on the expedition isles." },
  ["overseer ta'readon"] = { 2, "broker located in the Hall of Curiosities in Oribos", "Overseer Ta'readon is a broker located in the Hall of Curiosities in Oribos. When Maw Walkers first arrive in the city, he introduces the Hall of Curiosities to them." },
  ["overseer zambul"] = { 2, "centaur of Clan Nokhud roaming the Eternal Kurgans in the...", "Overseer Zambul is a centaur of Clan Nokhud roaming the Eternal Kurgans in the Ohn'ahran Plains. He oversees the Nokhud's efforts to defile the burial ground alongside Clan Ukhel." },
  ["ovyd"] = { 2, "', "Ovyd is one of the few vrykul who is recounted in history as spurning the sword, opting instead to use the spoken word." },
  ["p. diddimus"] = { 2, "gnome intern working for the highly esteemed Gnomeregan G...", "P. Diddimus is the gnome intern working for the highly esteemed Gnomeregan Gnews Gnetwork. Diddimus was with Wendy Breezy interviewing Barley McFrothbeard, when asked to hold Barley's ale so that he could show off the flying mount, unfortunately D..." },
  ["paa"] = { 2, "tuskarr child located next to Skygazer Paatu in Iskaara i...", "Paa is a tuskarr child located next to Skygazer Paatu in Iskaara in the Azure Span." },
  ["paceran the virulent"] = { 2, "boss in the first encounter of the Theater of Pain", "Paceran the Virulent is a boss in the first encounter of the Theater of Pain." },
  ["packleader ivar bloodfang"] = { 2, "worgen", "Packleader Ivar Bloodfang is a worgen and the leader of the Bloodfang pack of Silverpine Forest. Although clever and willing to form alliances with others, he doesn't hesitate to use violence, brutality, and desperate measures to get what he wants." },
  ["pactsworn wildcaller"] = { 2, "', "Pactsworn Wildcallers are ethereals that appear in delves when the  [Nemesis Strongbox] buff is active." },
