  ["paymaster alstein"] = { 2, "banker located in the Bank of Dalaran in neutral Dalaran", "Paymaster Alstein is a banker located in the Bank of Dalaran in neutral Dalaran. She is affiliated with the Kirin Tor." },
  ["paymaster amadi"] = { 2, "human banker located at the Dalaran Merchant's Bank in Da...", "Paymaster Amadi is a human banker located at the Dalaran Merchant's Bank in Dalaran. When Dalaran moved above Karazhan, he mysteriously was uncontrollably floated about the vault by an orb of arcane energy." },
  ["peacekeeper administrator"] = { 2, "', "Peacekeeper Administrators are earthen located in the Stoneshaper's Atrium in Dornogal." },
