  ["peacekeeper barr"] = { 2, "earthen peacekeeper located in Stoneshaper's Atrium in Do...", "Peacekeeper Barr is an earthen peacekeeper located in Stoneshaper's Atrium in Dornogal. She and Peacekeeper Aidda are atop a tower waiting for her stormrook, Lahk, to stop messing around." },
