  ["pelagos"] = { 2, "Eternal One serving as the Arbiter", "Pelagos is an Eternal One serving as the Arbiter, the being who rules over the Eternal City of Oribos and is responsible for judging mortal souls in the Shadowlands and assigning them to appropriate afterlives. He was formerly a mere aspirant of t..." },
  ["peletort"] = { 2, "murloc encountered during raid testing on the PTR", "Peletort is a murloc encountered during raid testing on the PTR." },
  ["pella brassbrush"] = { 2, "goblin barber in charge of the Barbershop in Ironforge", "Pella Brassbrush is the goblin barber in charge of the Barbershop in Ironforge." },
  ["pelodis"] = { 2, "Ascended kyrian located in Forgefire Outpost in Bastion", "Pelodis is an Ascended kyrian located in Forgefire Outpost in Bastion. He is a Phalynx Master and rival to Nemea, a Larion Master, who is also his soulbind." },
