  ["penned murloc"] = { 2, "', "The Penned Murloc can be found in the Menagerie in the city of Suramar." },
  ["penney copperpinch"] = { 2, "vendor located in the Valley of Strength in the orcish ci...", "Penney Copperpinch is a vendor located in the Valley of Strength in the orcish city of Orgrimmar} during the Feast of Winter Veil event. She is affiliated with Smokywood Pastures, and primarily sells lower value holiday related items, although she..." },
  ["penny clobberbottom"] = { 2, "goblin quest giver located at the Beastwatch in Gorgrond", "Penny Clobberbottom is a goblin quest giver located at the Beastwatch in Gorgrond. Penny eventually becomes a follower in commander's Garrison." },
  ["penny flay"] = { 2, "daughter of Robby Flay", "Penny Flay is the daughter of Robby Flay. She has a taste for pumpkin pancakes and her father does his best to provide them for her." },
  ["pensive aspirant"] = { 2, "', "Pensive Aspirants are kyrian located at Everdawn Commons in Bastion." },
  ["peon bolgar"] = { 2, "orc trade goods vendor located at Spinebreaker Post in th...", "Peon Bolgar is an orc trade goods vendor located at Spinebreaker Post in the Hellfire Peninsula." },
  ["permelia"] = { 2, "worgen located at the Lunarfall in Shadowmoon Valley", "Permelia is a worgen located at the Lunarfall in Shadowmoon Valley. She can only be recruited using the Headhunter's Harvest from Lunarfall Inn." },
  ["perobas the bloodthirster"] = { 2, "worgen found in the Howling Fjord", "Perobas the Bloodthirster is a worgen found in the Howling Fjord." },
  ["peroth'arn"] = { 2, "first boss to appear in the Well of Eternity instance", "Peroth'arn is the first boss to appear in the Well of Eternity instance." },
  ["perrexx"] = { 2, "satyr located in Moonclaw Vale in Val'sharah", "Perrexx is a satyr located in Moonclaw Vale in Val'sharah, accompanied by their felstalker named Razzok. In front of him are three dead Moonclaw Druids." },
  ["pet pal"] = { 2, "', "Pet Pals are located outside the Caverns of Time in Tanaris during the Bronze Celebration." },
  ["petra cogwenne"] = { 2, "gnome located in Mechagon City", "Petra Cogwenne is a gnome located in Mechagon City. During mechagnome recruitment, she is seen in Rustbolt on Mechagon Island." },
