  ["phaedra (kyrian)"] = { 2, "Forsworn kyrian encountered at the Temple of Loyalty in B...", "Phaedra is a Forsworn kyrian encountered at the Temple of Loyalty in Bastion during  [60] The Greater Good." },
  ["phantasmal murloc"] = { 2, "', "Phantasmal Murlocs can be found in the Oculus." },
