  ["phillios"] = { 2, "kyrian located in Bastion", "Phillios is a kyrian located in Bastion. When a Maw Walker arrived in Bastion seeking an audience with the Archon, they encountered Phillios in conversation with Tymon at the Aspirant's Crucible." },
  ["phillip"] = { 2, "boy", "Phillip was a boy who lived with his parents in a town in Lordaeron which was under the protection of the Silver Hand knight Thomas Thomson at the start of the Scourging. He informed Thomas that Baron Rivendare had sent a food supply to the starvi..." },
  ["phillip taversil"] = { 2, "Arathi located in Mereldar in Hallowfall", "Phillip Taversil is an Arathi located in Mereldar in Hallowfall." },
