  ["phyo'rne"] = { 2, "nerubian skinning trainer located in the Umbral Bazaar in...", "Phyo'rne is a nerubian skinning trainer located in the Umbral Bazaar in the City of Threads in City of Threads." },
  ["pick butterworth"] = { 2, "gnome located in the Stormwind side of the Deeprun Tram", "Pick Butterworth is a gnome located in the Stormwind side of the Deeprun Tram. He directs players to the Brawler's Guild downstairs in Bizmo's Brawlpub." },
  ["picky stefan"] = { 2, "venthyr located in Sinfall in Revendreth", "Picky Stefan is a venthyr located in Sinfall in Revendreth. He helps and participates in the Ember Court." },
  ["piercer gigra"] = { 2, "djaradin located at the Burning Ascent in the Waking Shores", "Piercer Gigra is a djaradin located at the Burning Ascent in the Waking Shores." },
