  ["pilgrim (isle of dorn)"] = { 2, "', "Pilgrims are earthen located in Dhar Oztan on the Isle of Dorn." },
  ["pilot bellowfiz"] = { 2, "dwarf quest giver located in Steelgrill's Depot in Dun Mo...", "Pilot Bellowfiz, nicknamed Fizzer, is a dwarf quest giver located in Steelgrill's Depot in Dun Morogh. He's a pilot of the Ironforge Siege Brigade." },
  ["pilot marsha"] = { 2, "Forsaken engineering vendor located at the Nesingwary Saf...", "Pilot Marsha is a Forsaken engineering vendor located at the Nesingwary Safari in Nagrand. She is standing by her crashed aircraft." },
  ["pink murloc egg"] = { 2, "pink baby murloc Companion", "The Pink Murlog Egg item teaches you to summon Gurky, a pink baby murloc Companion that follows you around." },
  ["pip"] = { 2, "tuskarr child located in the Filled Bowl in the Azure Span", "Pip is a tuskarr child located in the Filled Bowl in the Azure Span." },
  ["pirate party crasher"] = { 2, "', "Pirate Party Crashers are pirates affiliated with the Southsea Freebooters that are intent on disrupting the party going on at the KTC Headquarters pool in Kezan. They were hired by Trade Prince Gallywix." },
  ["pirdan the blinder"] = { 2, "djaradin located in the Waking Shores", "Pirdan The Blinder is a djaradin located in the Waking Shores." },
  ["pit boss buxdoggle"] = { 2, "goblin located in Brawl'gar Arena", "Pit Boss Buxdoggle is a goblin located in Brawl'gar Arena. You can speak with him at the start of every brawl and bet on who will win to win additional Brawler's Golds." },
  ["plague farmer (rumble)"] = { 2, "ranged ground unit of the Undead family in Warcraft Rumble", "The Plague Farmer is a ranged ground unit of the Undead family in Warcraft Rumble." },
  ["plaguebinder"] = { 2, "', "Plaguebinders are undead located in Plaguefall." },
  ["plagued dragonflayer handler"] = { 2, "', "Plagued Dragonflayer Handlers are vrykul located in Halgrind in the Howling Fjord." },
