  ["plainsmender darragh"] = { 2, "tauren fighting Iron Horde Grunts alongside many others a...", "Plainsmender Darragh is a tauren fighting Iron Horde Grunts alongside many others at the Dark Portal in the Blasted Lands and Tanaan Jungle. He died after the portal was destroyed." },
  ["plank-master bluebelly"] = { 2, "vulpera located in Stormtide Dregs on the Siren Isle", "Plank-Master Bluebelly is a vulpera located in Stormtide Dregs on the Siren Isle." },
