  ["pleeqi"] = { 2, "tuskarr located in Iskaara in the Azure Span", "Pleeqi is a tuskarr located in Iskaara in the Azure Span. This section concerns content related to Dragonflight." },
  ["pliar nose andy"] = { 2, "human located in Deadwash in Stormsong Valley", "Pliar Nose Andy is a human located in Deadwash in Stormsong Valley." },
