  ["plundered ambershaper's egg"] = { 2, "Island Expedition reward", "The Plundered Ambershaper's Egg is an Island Expedition reward. The item can also be contained in  [Snowblossom Salvage]." },
  ["plunderer jurval"] = { 2, "vrykul located in Stormheim", "Plunderer Jurval was a vrykul located in Stormheim. He was the leader of a group of Tideskorn who wielded crafted weapons made from  [Lumenstone]." },
  ["plunker"] = { 2, "murloc located at the Winterfin Retreat in the Borean Tundra", "Plunker is a murloc located at the Winterfin Retreat in the Borean Tundra." },
  ["pocimos"] = { 2, "kyrian located at Hero's Rest in Bastion where he sells c...", "Pocimos is a kyrian located at Hero's Rest in Bastion where he sells cooking supplies. He was present at the reception that the Archon arranged for a Maw Walker, who had decided to join the Kyrian Covenant, in honor of their efforts against the Ma..." },
  ["poisoncrafter kil'zit"] = { 2, "alchemy trainer found in Klaxxi'vess in the Dread Wastes", "Poisoncrafter Kil'zit is an alchemy trainer found in Klaxxi'vess in the Dread Wastes." },
  ["poisonmaster bortusk"] = { 2, "orc located at the Shattered Rise in the Spires of Arak", "Poisonmaster Bortusk is an orc located at the Shattered Rise in the Spires of Arak." },
  ["poko"] = { 2, "tuskarr child located in Kauriq Gleamlet in the Azure Span", "Poko is a tuskarr child located in Kauriq Gleamlet in the Azure Span. She can be found next to her master, Elder Nava." },
  ["pol amberstill"] = { 2, "', "Pol Amberstill can be found at the Brewfest camp just outside of Ironforge in Dun Morogh. In 2007, he wielded the  [Yellow Brewfest Stein]." },
  ["polar furbolg elder shaman"] = { 2, "', "Polar Furbolg Elder Shaman are polar furbolg shaman creeps that can be encountered in the Icecrown Glacier and Northrend tilesets." },
  ["polar furbolg shaman"] = { 2, "', "Polar Furbolg Shaman are polar furbolg shaman creeps that can be encountered in the Icecrown Glacier and Northrend tilesets." },
  ["polar furbolg tracker"] = { 2, "', "Polar Furbolg Trackers are polar furbolg creeps that can be encountered in the Icecrown Glacier and Northrend tilesets." },
  ["poli'lukluk the wiser"] = { 2, "Broken quest giver located at Telaar in Nagrand", "Poli'lukluk the Wiser is a Broken quest giver located at Telaar in Nagrand." },
  ["pon"] = { 2, "nerubian spiderling located in Umbral Bazaar in the City ...", "Pon is a nerubian spiderling located in Umbral Bazaar in the City of Threads." },
  ["ponoliak"] = { 2, "tuskarr chieftain of Iskaara", "Ponoliak was a tuskarr chieftain of Iskaara and the Iskaara Tuskarr in the Azure Span. He knew about Glimcoves, better known as ley lines and was a mentor to Brena." },
  ["popoak"] = { 2, "dead tuskarr located in Brackenhide Brambles in the Azure...", "Popoak is a dead tuskarr located in Brackenhide Brambles in the Azure Span. As a great hunter, he went with his fellow tuskarr to a hunt, but was killed by the Brackenhide gnolls." },
  ["porsha brassbearing"] = { 2, "goblin located between the Thistleshrub Valley", "Porsha Brassbearing is a goblin located between the Thistleshrub Valley and the road for Un'Goro Crater in Tanaris. She is sat under a tent, along with Lixi Greasenozzle and Lamba Ginwhistle." },
  ["portal authority tunnelmancer"] = { 2, "Veiled Market", "Portal Authority Tunnelmancers are brokers located by portals throughout Tazavesh, the Veiled Market." },
  ["portalmancer zo'dahh"] = { 2, "broker found in Tazavesh", "Portalmancer Zo'dahh is a broker found in Tazavesh, the Veiled Market." },
  ["portalmancer zo'honn"] = { 2, "broker found in Tazavesh", "Portalmancer Zo'honn is a broker found in Tazavesh, the Veiled Market." },
  ["portalmancer zo'nyy"] = { 2, "broker located at the Tazavesh Customs Enforcement in Taz...", "Portalmancer Zo'nyy is a broker located at the Tazavesh Customs Enforcement in Tazavesh, the Veiled Market." },
  ["possessed vrykul"] = { 2, "', "The Possessed Vrykul can be found in Azuregale Bay in Suramar." },
  ["post guard"] = { 2, "', "Post Guards are centaur located at Pinewood Post in the Ohn'ahran Plains." },
  ["prate cloudseer"] = { 2, "tauren found in Weathered Nook in the Thousand Needles", "Prate Cloudseer is a tauren found in Weathered Nook in the Thousand Needles." },
  ["preparing hopebreaker"] = { 2, "', "Preparing Hopebreakers are venthyr located at Wanecrypt Hill and Wanecrypt Hill Inn in Revendreth." },
  ["preservationist kathos"] = { 2, "dracthyr located in the Roasted Ram in Valdrakken", "Preservationist Kathos is a dracthyr located in the Roasted Ram in Valdrakken. She is the central character behind the Secrets of Azeroth event." },
  ["prideful hoplite"] = { 2, "', "Prideful Hoplites are Forsworn kyrian located at the Temple of Humility in Bastion." },
  ["priest maro'zik"] = { 2, "nerubian located in the Silken Ward in Azj-Kahet", "Priest Maro'zik is a nerubian located in the Silken Ward in Azj-Kahet." },
  ["priestess anetta"] = { 2, "human priest", "Priestess Anetta is a human priest and priest trainer located in Northshire Abbey in Elwynn Forest. She is a sacerdotal member of the Brotherhood of Northshire." },
  ["priestess asaani"] = { 2, "draenei located at the Teluuna Observatory in Shadowmoon ...", "Priestess Asaani is a draenei located at the Teluuna Observatory in Shadowmoon Valley." },
  ["priestess baerla"] = { 2, "dwarf priest trainer located in the town of Thelsamar in ...", "Priestess Baerla is a dwarf priest trainer located in the town of Thelsamar in Loch Modan." },
