  ["priestess of eyir"] = { 2, "', "Priestesses of Eyir are vrykul located in Stormheim." },
  ["primal squallcaller"] = { 2, "', "Primal Squallcallers are night elves and vulpera located in the Crystal Fields in Zaralek Cavern." },
  ["primalist arlin"] = { 2, "draenei located in the Waking Shores", "Primalist Arlin is a draenei located in the Waking Shores." },
  ["primalist earthshaker (emerald dream)"] = { 2, "', "Primalist Earthshakers are earth-infused furbolgs located at the Furnace Coil in the Emerald Dream. They are also found at the Field of Flames during the quest  [10-80] The Age of Mortals." },
  ["primalist galesinger"] = { 2, "', "Primalist Galesingers are vulpera located in the Halls of Infusion." },
  ["primalist instructor"] = { 2, "', "Primalist Instructors are night elves and vulpera located in the Ohn'ahran Plains." },
  ["primalist invader"] = { 2, "', "Primalist Invaders are night elves, tauren, vulpera, and jungle trolls located in the Ohn'ahran Plains." },
  ["primalist mur'og"] = { 2, "rare elite ogre", "Primalist Mur'og on the southern ridge high above the Daggermaw Ravine on Frostfire Ridge is a rare elite ogre. Look for an Ogre Wayguide at the trailhead, which states: Nothing At The Top Of This Mountain Turn Around Now Further up the trail is ..." },
  ["primalist storm-summoner"] = { 2, "', "Primalist Storm-Summoners are night elves and vulpera located in a cave at the Storm Scar in the Ohn'ahran Plains." },
  ["primalist stormsage"] = { 2, "', "Primalist Stormsages are night elves and vulpera located in the Shikaar Highlands in the Ohn'ahran Plains." },
  ["primalist stormslinger"] = { 2, "', "Primalist Stormslingers are vulpera that originally spawned at air invasions during the Tempest Unleashed pre-expansion event. They now appear on the Dragon Isles during Primal Storms." },
  ["primalist stormsurger"] = { 2, "', "Primalist Stormsurgers are night elves and vulpera located at the Storm Scar in the Ohn'ahran Plains." },
  ["primalist tempest"] = { 2, "', "Primalist Tempests are night elves and vulpera located at the Horn of Drusahl in the Ohn'ahran Plains." },
  ["primalist windweaver"] = { 2, "', "Primalist Windweavers are night elves and vulpera located in the Forbidden Reach." },
  ["primalsworn furbolg"] = { 2, "', "Primalsworn Furbolgs are furbolgs located in the Azure Span." },
  ["primrose crankshaft"] = { 2, "goblin located just outside the Incontinental Hotel in ce...", "Primrose Crankshaft is a goblin located just outside the Incontinental Hotel in central Undermine. During the fifth chapter of the Undermine(d) campaign, Primrose gives players the option to enter and exit the uprising phase against Jastor Gallywix." },
  ["prince atherann"] = { 2, "', "Prince Atherann was one of the San'layn who resurrected Archmage Arugal near Pyrewood Village in Silverpine Forest, as shown in a vision for the quest  [15-30] Out of Body Experience. His current whereabouts are unknown." },
  ["prince keleseth"] = { 2, "member of the San'layn", "Prince Keleseth (pronounced 'KEHL-eh-seth') was a member of the San'layn who served as the ruler of the southeastern reaches of Northrend — specifically as Scourge overlord of Howling Fjord — and as a representative to the vrykul." },
  ["prince keleseth (tactics)"] = { 2, "Darkfallen of the San'layn", "Prince Keleseth is a Darkfallen of the San'layn and the first boss of Utgarde Keep." },
  ["prince kellen"] = { 2, "rare satyr found in Desolace", "Prince Kellen is a rare satyr found in Desolace. He is known to be a very easy kill for a low level 30s person." },
  ["prince navarius"] = { 2, "Darkfallen of the San'layn", "Prince Navarius is a Darkfallen of the San'layn that can be found in Zul'Drak. He masterminded the creation of the massive flesh titan, Thrym and other flesh giants by using the corpses of local storm giants." },
  ["prince nazjak"] = { 2, "rare naga found roaming the Drowned Reef in the Arathi Hi...", "Prince Nazjak is a rare naga found roaming the Drowned Reef in the Arathi Highlands." },
  ["prince raze"] = { 2, "rare mob satyr found in Xavian in Ashenvale", "Prince Raze is a rare mob satyr found in Xavian in Ashenvale. He is on a 5-8 hour respawn timer." },
  ["prince renathal"] = { 2, "venthyr", "Prince Renathal is a venthyr who leads the rebellion from Sinfall in Revendreth against Sire Denathrius. Convinced that the Master is behind the anima drought, he rallied a formidable force to lead a rebellion to succeed Sire Denathrius and make t..." },
  ["prince sandoval"] = { 2, "Darkfallen of the San'layn", "Prince Sandoval is a Darkfallen of the San'layn who resides in Icecrown Citadel and challenges fighters to battle at Valhalas in Icecrown." },
  ["prince taldaram"] = { 2, "second boss in Ahn'kahet: The Old Kingdom", "Prince Taldaram, a Darkfallen of the San'layn, is the second boss in Ahn'kahet: The Old Kingdom. He has traveled to the nerubian city to siphon power and collect relics for the Scourge." },
  ["prince tenris mirkblood"] = { 2, "', "Prince Tenris Mirkblood was introduced on October 22, 2008 as a part of the Scourge Invasion world event — which was itself a precursor to the release of Wrath of the Lich King. He could be found in Karazhan secluded in the Guardhouse, behind a Bl..." },
  ["prince theraldis"] = { 2, "', "Prince Theraldis was one of the San'layn who resurrected Archmage Arugal near Pyrewood Village in Silverpine Forest, as shown in a vision for the quest  [15-30] Out of Body Experience. His current whereabouts are unknown." },
  ["prince valanar"] = { 2, "Darkfallen of the San'layn", "Prince Valanar was a Darkfallen of the San'layn and the Scourge overlord of the Borean Tundra. He ruled from Naxxanar, a Scourge necropolis above the Temple City of En'kilah in the northern edge of the Tundra." },
  ["prince xavalis"] = { 2, "satyr found in Shadow Hold in Felwood", "Prince Xavalis is a satyr found in Shadow Hold in Felwood. He is an ancient and powerful satyr that some believe to be a son of Xavius, blessed by Sargeras himself." },
  ["princess moira bronzebeard (tactics)"] = { 2, "level 58 elite located next to Dagran Thaurissan in the I...", "Princess Moira Bronzebeard was a level 58 elite located next to Dagran Thaurissan in the Imperial Seat in Blackrock Depths. She assisted Dagran during his encounter with players." },
  ["princess stillpine"] = { 2, "furbolg quest giver located at Bristlelimb Enclave in the...", "Princess Stillpine is a furbolg quest giver located at Bristlelimb Enclave in the draenei territory of Bloodmyst Isle. The Princess is one of the many who journey to Blood Watch to celebrate the hero of Bloodmyst and Azuremyst." },
  ["principle analyst hakone"] = { 2, "broker", "Principle Analyst Hakone is a broker. He is likely the owner of  [Hakone's Signet]." },
  ["prioress haelsey murrpray"] = { 2, "Arathi located in Hallowfall", "Prioress Haelsey Murrpray is an Arathi located in Hallowfall. As the Prioress of the Church of the Sacred Flame, she led the clergy of the Priory of the Sacred Flame as they contemplated of the mysteries of Beledar." },
  ["prioress murrpray"] = { 2, "boss in the Priory of the Sacred Flame", "Prioress Murrpray is a boss in the Priory of the Sacred Flame." },
  ["prison guard (alliance)"] = { 2, "worgen found guarding the Horde prisoners in Stormshield ...", "Prison Guard is a worgen found guarding the Horde prisoners in Stormshield Stronghold, Ashran." },
  ["private denning"] = { 2, "soldier of Honor Hold", "Private Denning was a soldier of Honor Hold who got killed by the Bleeding Hollow clan, his insignia now serving as a cursed talisman for them." },
  ["private draxlegauge"] = { 2, "gnome quest giver located in the Military Ward in Ironforge", "Private Draxlegauge was a gnome quest giver located in the Military Ward in Ironforge." },
  ["private robert anthony"] = { 2, "human located at Lion's Watch in Tanaan Jungle", "Private Robert Anthony is a human located at Lion's Watch in Tanaan Jungle. He is a soldier in the Alliance military and is part of the force that is engaged against Gul'dan's Iron Horde in Tanaan." },
  ["privileged contributor"] = { 2, "', "Privileged Contributors are venthyr located at the Caretaker's Manor in Revendreth." },
  ["profane invoker"] = { 2, "', "Profane Invokers are venthyr located in the Menagerie of the Master in Revendreth. They are draining anima from Repentant Souls." },
  ["professor dabiri"] = { 2, "ethereal quest giver located at the Protectorate Watch Po...", "Professor Dabiri is an ethereal quest giver located at the Protectorate Watch Post in the Netherstorm. He coordinates the fight against Dimensius." },
  ["professor lancissa"] = { 2, "dracthyr located in Algeth'ar Academy in Thaldraszus", "Professor Lancissa is a dracthyr located in Algeth'ar Academy in Thaldraszus." },
  ["professor putricide"] = { 2, "boss in the Plagueworks wing of the Icecrown Citadel raid", "Professor Putricide is a boss in the Plagueworks wing of the Icecrown Citadel raid." },
  ["professor saphigozi"] = { 2, "dracthyr located at Algeth'ar Academy in Thaldraszus", "Professor Saphigozi is a dracthyr located at Algeth'ar Academy in Thaldraszus." },
  ["professor slate"] = { 2, "mad scientist found in the Viewing Room in the Scholomance", "Professor Slate is a mad scientist found in the Viewing Room in the Scholomance. During the fight, he changes form." },
  ["professor vatlinteth"] = { 2, "dracthyr located at Algeth'ar Academy in Thaldraszus", "Professor Vatlinteth is a dracthyr located at Algeth'ar Academy in Thaldraszus." },
  ["profiteerist kej'takaz"] = { 2, "nerubian depicted by a statue in the Skeins in the City o...", "Profiteerist Kej'takaz is a nerubian depicted by a statue in the Skeins in the City of Threads, on the northern side of the Royal Preservatorium. The statue's plaque can only be understood while under the effects of  [Potion of Polymorphic Transla..." },
  ["prospector anvilward"] = { 2, "dwarf found at the North Sanctum in Eversong Woods", "Prospector Anvilward is a dwarf found at the North Sanctum in Eversong Woods, but will become hostile to Horde adventurers during the quest  [1-30] The Dwarven Spy. He spied on the activities of the blood elves in Quel'Thalas in order to help the ..." },
  ["prospector balmoral"] = { 2, "', "Prospector Balmoral could be found in Terokkar Forest during the beta." },
  ["prospector belvar"] = { 2, "dwarf located at Fort Wildervar in the Howling Fjord", "Prospector Belvar is a dwarf located at Fort Wildervar in the Howling Fjord." },
  ["prospector conall"] = { 2, "dwarf quest giver located at Telredor in Zangarmarsh", "Prospector Conall is a dwarf quest giver located at Telredor in Zangarmarsh." },
  ["prospera cogwail"] = { 2, "goblin quest giver located in Opportunity Point in the Ri...", "Prospera Cogwail is a goblin quest giver located in Opportunity Point in the Ringing Deeps. She also makes an appearance in the Darkfuse Disruption story in the Dread Pit and Waterworks delves." },
  ["protector alkaan"] = { 2, "draenei located at Karabor in Shadowmoon Valley", "Protector Alkaan is a draenei located at Karabor in Shadowmoon Valley." },
  ["protector andaal"] = { 2, "draenei located at Karabor in Shadowmoon Valley", "Protector Andaal is a draenei located at Karabor in Shadowmoon Valley." },
