  ["provisioner meriwether"] = { 2, "offensive spells vendor of Brew Bay in Plunderstorm", "Provisioner Meriwether is the offensive spells vendor of Brew Bay in Plunderstorm. White in the waiting room lobby before a match starts, or in the untimed practice mode, Meriwether will hand over all offensive spells so players with them can prac..." },
  ["provisioner ojito"] = { 2, "vulpera located in the Waking Shores", "Provisioner Ojito is a vulpera located in the Waking Shores." },
