  ["provisioner tsaalt"] = { 2, "Broken general goods", "Provisioner Tsaalt is a Broken general goods, reagent, food and drink vendor located at the entrance to the Shadow Labyrinth in Terokkar Forest." },
  ["provisioner zara"] = { 2, "centaur located atop the Shikaar rise in Maruukai in the ...", "Provisioner Zara is a centaur located atop the Shikaar rise in Maruukai in the Ohn'ahran Plains. She is the mother of Hunter Narman, and adventurers bring her sweets as part of preparing Windsage Dawa's proposal to Narman." },
  ["provoked watcher"] = { 2, "', "Provoked Watchers are Mawsworn kyrian located in the Maw." },
  ["prustaga"] = { 2, "vrykul guide located at Shield's Rest in Stormheim", "Prustaga is a vrykul guide located at Shield's Rest in Stormheim, having met both Brann Bronzebeard and Grif Wildheart." },
  ["puggi blasthops"] = { 2, "goblin located in Tiragarde Sound", "Puggi Blasthops is a goblin located in Tiragarde Sound." },
