  ["qannik"] = { 2, "tuskarr fishmonger in Moa'ki Harbor in the Dragonblight", "Qannik is a tuskarr fishmonger in Moa'ki Harbor in the Dragonblight." },
  ["qariin dotur"] = { 2, "centaur quest giver of Clan Teerai located in the cooking...", "Qariin Dotur is a centaur quest giver of Clan Teerai located in the cooking area of Maruukai in the Ohn'ahran Plains. As indicated by 'Dotur', she is one of Khanam Matra Sarest's daughters." },
  ["qatiichii"] = { 2, "tuskarr vendor aboard the Green Island", "Qatiichii is a tuskarr vendor aboard the Green Island, a giant turtle that swims between Moa'ki Harbor and Kamagua." },
  ["qi'nor"] = { 2, "mogu located in Lightning Vein Mine in Isle of Thunder", "Qi'nor is a mogu located in Lightning Vein Mine in Isle of Thunder." },
  ["qi'tar the deathcaller"] = { 2, "mantid located at Kypari Vor", "Qi'tar the Deathcaller is a mantid located at Kypari Vor. He is a Klaxxi Paragon corrupted by the power of the Sha of Fear." },
  ["qiang the merciless"] = { 2, "emperor of the mogu empire", "Qiang the Merciless, the Warlord King, was an emperor of the mogu empire. He was a great conqueror who ruled his vassals with an iron fist." },
  ["qin"] = { 2, "tuskarr child located in Mulsted's Marquee in the Azure Span", "Qin is a tuskarr child located in Mulsted's Marquee in the Azure Span." },
  ["qin-xi"] = { 2, "mogu located in the Mogu'shan Vaults as part of the Will ...", "Qin-xi is a mogu located in the Mogu'shan Vaults as part of the Will of the Emperor encounter." },
  ["qinsu the granite fist"] = { 2, "mogu", "Qinsu the Granite Fist is a mogu who can be encountered during Island Expeditions." },
  ["qu'nas"] = { 2, "rare mogu found in the Krasari Ruins in the Krasarang Wilds", "Qu'nas is a rare mogu found in the Krasari Ruins in the Krasarang Wilds. He is a pandarian champion." },
  ["qu'ruk the time-lost"] = { 2, "quilboar brute located at the Temporal Conflux in Thaldra...", "Qu'ruk the Time-Lost is a quilboar brute located at the Temporal Conflux in Thaldraszus." },
  ["quark bellow"] = { 2, "goblin located at Slam Central Station in the Undermine", "Quark Bellow is a goblin located at Slam Central Station in the Undermine." },
  ["quarry slave"] = { 2, "', "Quarry Slaves are gnolls, orcs, and dwarves located in the Grinding Quarry in Blackrock Mountain." },
  ["quarrychef higinnd"] = { 2, "earthen located in the Proscenium on the Isle of Dorn", "Quarrychef Higinnd is an earthen located in the Proscenium on the Isle of Dorn." },
  ["quartermaster alcorn"] = { 2, "human located in Arom's Stand in Drustvar", "Quartermaster Alcorn is a human located in Arom's Stand in Drustvar." },
  ["quartermaster alfin"] = { 2, "human located in Shatterstone Harbor in Vol'dun", "Quartermaster Alfin is a human located in Shatterstone Harbor in Vol'dun. He is angry at the Thieving Snappers that are stealing the supplies." },
  ["quartermaster apone"] = { 2, "human general goods vendor located at the Alliance camp n...", "Quartermaster Apone is a human general goods vendor located at the Alliance camp near the Dark Portal in Blasted Lands. This section concerns content related to Warlords of Draenor." },
  ["quartermaster ashu"] = { 2, "centaur of Clan Teerai located at the base of the krutal ...", "Quartermaster Ashu is a centaur of Clan Teerai located at the base of the krutal in Maruukai in the Ohn'ahran Plains." },
  ["quartermaster brevin"] = { 2, "quest giver located in front of the statue at Westguard K...", "Quartermaster Brevin is a quest giver located in front of the statue at Westguard Keep in Howling Fjord." },
  ["quartermaster durnolf"] = { 2, "vrykul located in Skyhold", "Quartermaster Durnolf is a vrykul located in Skyhold." },
  ["quartermaster gensai"] = { 2, "centaur located in a tent next to the river in northeaste...", "Quartermaster Gensai is a centaur located in a tent next to the river in northeastern Teerakai in the Ohn'ahran Plains. He is assisted by his daughter, Assistant Subame." },
  ["quartermaster huseng"] = { 2, "centaur renown quartermaster located in Maruukai in the O...", "Quartermaster Huseng is a centaur renown quartermaster located in Maruukai in the Ohn'ahran Plains." },
  ["quartermaster koratite"] = { 2, "skardyn earthen located at the Rookery Landing in the Roo...", "Quartermaster Koratite is a skardyn earthen located at the Rookery Landing in the Rookery." },
  ["quartermaster lungren"] = { 2, "Forsaken located in the Valley of Strength in Orgrimmar d...", "Quartermaster Lungren is a Forsaken located in the Valley of Strength in Orgrimmar during Death Rising." },
  ["quartermaster miranda breechlock"] = { 2, "dwarf Argent Crusade reputation goods vendor (only with F...", "Quartermaster Miranda Breechlock is a dwarf Argent Crusade reputation goods vendor (only with Friendly and above), located at Light's Hope Chapel in the Eastern Plaguelands. At some point, after World of Warcraft and before Cataclysm, she lost her..." },
  ["quartermaster taelica"] = { 2, "Forsworn kyrian located at Kalliope's Rest in Bastion", "Quartermaster Taelica is a Forsworn kyrian located at Kalliope's Rest in Bastion." },
  ["queen angerboda"] = { 2, "wife to King Ymiron", "Queen Angerboda can be found at Winter's Terrace in the Howling Fjord. She was the wife to King Ymiron, and was supervising his reawakening through a ritual done by the Scourge." },
  ["queen anub'izek"] = { 2, "founder of Azj-Kahet", "Queen Anub'izek was the founder of Azj-Kahet, and the first queen of the 'true nerubians'. According to the histories of Azj-Kahet, Anub'izek was a unique creature with the power of a lord and the memory of a sage, created by the 'dark ones' to co..." },
  ["queen azshara (eternal palace tactics)"] = { 2, "last boss of the Eternal Palace raid", "Queen Azshara is the last boss of the Eternal Palace raid. She is found outside the palace in a titan dome known as the Last Prison." },
  ["queen bretta"] = { 2, "vrykul queen of Stormheim", "Queen Bretta was the vrykul queen of Stormheim." },
  ["queen's court"] = { 2, "sixth boss of the Eternal Palace raid", "The Queen's Court is the sixth boss of the Eternal Palace raid. It consists of Silivaz the Zealous and Pashmar the Fanatical." },
  ["quell (nerubian)"] = { 2, "nerubian located in the City of Threads", "Quell is a nerubian located in the City of Threads." },
  ["questing knight"] = { 2, "', "Questing Knights are dead kobolds located in the cave under Campalot in the Ringing Deeps. They were killed by the Lady of the Lake." },
  ["questionable trader"] = { 2, "broker located just past Tazavesh Customs Enforcement in ...", "The Questionable Trader is a broker located just past Tazavesh Customs Enforcement in Tazavesh, the Veiled Market.  [Expedition Report A37J - Part 2] is found right behind him." },
  ["quicksmack magk"] = { 2, "drogbar located in Zaralek Cavern", "Quicksmack Magk is a drogbar located in Zaralek Cavern." },
  ["quilboar (rumble)"] = { 2, "', "Quilboar are a melee unit of the Beast family in Warcraft Rumble. Relatively cheap, this unit is decently tanky and can be placed anywhere on the map." },
  ["quilboar broodmentor"] = { 2, "', "Quilboar Broodmentors are quilboar located in Razorfen Kraul." },
  ["quilboar geomancer"] = { 2, "', "Quilboar Geomancers are quilboar located at the Quilboar Briarpatch in Exile's Reach. They serve under Geolord Grek'og and are in league with the Darkmaul ogres." },
  ["quilboar mealtender"] = { 2, "', "Quilboar Mealtenders are quilboar located in Razorfen Kraul." },
  ["quilboar pebble-watcher"] = { 2, "', "Quilboar Pebble-Watchers are quilboar located in Razorfen Kraul." },
  ["quilboar swinewatcher"] = { 2, "', "Quilboar Swinewatchers are quilboar located in Razorfen Kraul." },
  ["quilboar warrior"] = { 2, "', "Quilboar Warriors are quilboar located at the Quilboar Briarpatch in Exile's Reach. They serve under Geolord Grek'og and are in league with the Darkmaul ogres." },
  ["quilguard champion"] = { 2, "', "Quilguard Champions are quilboar found in Razorfen Kraul." },
  ["quillboar (warcraft iii)"] = { 2, "', "Quillboars are quilboar creeps that can be encountered in the Barrens tileset." },
  ["quillboar brute"] = { 2, "', "Quillboar Brutes are quilboar brutes appearing in the Founding of Durotar campaign." },
