  ["quillboar ranger"] = { 2, "', "Quillboar Rangers are quilboar rangers appearing in the Founding of Durotar campaign." },
  ["quillboar spirit caller"] = { 2, "', "Quillboar Spirit Callers are quilboar appearing in the Founding of Durotar campaign." },
  ["quillboar wild one"] = { 2, "', "Quillboar Wild Ones are quilboar appearing in the Founding of Durotar campaign." },
  ["quizla blastcaps"] = { 2, "goblin engineer", "Quizla Blastcaps is a goblin engineer who likes explosions and assisted the Horde during the Fourth War, the Dragonscale Expedition during the war against the Primalists, and Gazlowe's Greasemonkeys on the Siren Isle. She has a sister named Shuga." },
  ["qului the anxious"] = { 2, "centaur standing by a small duck pond northeast of Teerak...", "Qului the Anxious is a centaur standing by a small duck pond northeast of Teerakai in the Ohn'ahran Plains." },
  ["qwilla bloodedge"] = { 2, "orc follower located at Frostwall in Frostfire Ridge", "Qwilla Bloodedge is an orc follower located at Frostwall in Frostfire Ridge. She can only be recruited using the Headhunter's Harvest from Frostwall Tavern." },
  ["ra'ka bloodspear"] = { 2, "orc located at Darktide Roost in Shadowmoon Valley", "Ra'ka Bloodspear is an orc located at Darktide Roost in Shadowmoon Valley." },
  ["raaka the scalemonger"] = { 2, "tortollan located at Scaletrader Post in Zuldazar", "Raaka the Scalemonger is a tortollan located at Scaletrader Post in Zuldazar." },
  ["rabaan"] = { 2, "earthen theater troupe member located in the Proscenium i...", "Rabaan is an earthen theater troupe member located in the Proscenium in the Isle of Dorn. He plays General Ottomar in 'The Rivals' play and serves as a narrator in the 'Forget Me Not' and 'The Thraegar's Descent' plays." },
  ["rabid shadowhide gnoll"] = { 2, "', "Rabid Shadowhide Gnolls are gnolls found in the Redridge Mountains." },
  ["rabul"] = { 2, "vulpera located at the Artisan's Market in Valdrakken", "Rabul is a vulpera located at the Artisan's Market in Valdrakken." },
  ["rabxach"] = { 2, "satyr located at", "Rabxach is a satyr located at Andu'talah in Val'sharah." },
  ["racha"] = { 2, "tortollan", "Racha is a tortollan." },
  ["rachelle black"] = { 2, "worgen blacksmith vendor at the Lunarfall Excavation entr...", "Rachelle Black is a worgen blacksmith vendor at the Lunarfall Excavation entrance." },
  ["racing enthusiast"] = { 2, "', "Racing Enthusiasts are found in the following locations:" },
  ["racquili"] = { 2, "tuskarr located in Camp Antonidas in the Azure Span", "Racquili is a tuskarr located in Camp Antonidas in the Azure Span." },
  ["radd coppergear"] = { 2, "goblin vendor located in Undermine", "Radd Coppergear is a goblin vendor located in Undermine." },
  ["radiant supernova"] = { 2, "', "Radiant Supernovas are high arakkoa located in Skyreach." },
  ["radza thunderclaw"] = { 2, "furbolg located in Rustpine Den in the Azure Span", "Radza Thunderclaw is a furbolg located in Rustpine Den in the Azure Span. He also attended the gathering at Amirdrassil when it bloomed on the Dragon Isles after Fyrakk's death." },
  ["raegar breakbrow"] = { 2, "dwarf quest giver located in Prospector's Point in the Gr...", "Raegar Breakbrow is a dwarf quest giver located in Prospector's Point in the Grizzly Hills." },
  ["raen dawncavalyr"] = { 2, "head armorer of the Hallowfall Arathi", "Raen Dawncavalyr is the head armorer of the Hallowfall Arathi, located in the armory in Mereldar in Hallowfall. She can also appear in the Sinkhole delve." },
  ["raenie fizzlebog"] = { 2, "gnome found outside the Caverns of Time in Tanaris during...", "Raenie Fizzlebog is a gnome found outside the Caverns of Time in Tanaris during the Bronze Celebration, watching the Mount Mania." },
  ["raevyn sorrowblade"] = { 2, "Darkfallen death knight located at the Lunarfall in Shado...", "Raevyn Sorrowblade is a Darkfallen death knight located at the Lunarfall in Shadowmoon Valley. She can only be recruited using the Headhunter's Harvest from Lunarfall Inn." },
  ["rafaam"] = { 2, "main antagonist of the League of Explorers adventure in H...", "Rafaam is the main antagonist of the League of Explorers adventure in Hearthstone, serving as the third and fourth boss encounters in the Hall of Explorers, the fourth and final wing of the adventure. He is an ethereal thief who travels to differe..." },
  ["rafiq"] = { 2, "broker located at Pilgrim's Grace in Zereth Mortis", "Rafiq is a broker located at Pilgrim's Grace in Zereth Mortis." },
  ["ragash bloodwish"] = { 2, "orc located at the Mist's Edge in Darkshore during the Wa...", "Ragash Bloodwish is an orc located at the Mist's Edge in Darkshore during the War of the Thorns." },
  ["ragepaw"] = { 2, "rare Deadwood furbolg found in Deadwood Village of Felwood", "Ragepaw is a rare Deadwood furbolg found in Deadwood Village of Felwood. Slaying him is worth 100 Reputation with Timbermaw Hold." },
  ["ragged traveler"] = { 2, "undead found alongside the Rugged Traveler in a secret ro...", "The Ragged Traveler is an undead found alongside the Rugged Traveler in a secret room below Shadowforge City in Blackrock Depths. She and her companion were sought after by Anvilrage patrols." },
  ["ragglesnout"] = { 2, "rare elite quilboar found in the Razorfen Downs instance", "Ragglesnout is a rare elite quilboar found in the Razorfen Downs instance. If he appears, he can be found in the Spiral of Thorns just after Glutton." },
  ["raging rot hide"] = { 2, "', "Raging Rot Hides are gnolls found in Fenris Keep in Silverpine Forest." },
  ["raging stormrider"] = { 2, "', "Raging Stormriders are dead vrykul located at the Temple of Storms in the Storm Peaks during   [50] The Huntsman's Creed. Their mounts were Thunderous Proto-Drakes." },
  ["ragnok bloodreaver"] = { 2, "', "Ragnok Bloodreaver was one of the original death knights of the Horde, created by Gul'dan from the corpses of Stormwind knights and the spirits of the slain Shadow Council." },
  ["ragnvald drakeborn"] = { 2, "vrykul chosen by Odyn", "Ragnvald Drakeborn is a vrykul chosen by Odyn." },
  ["ragvar the plunderer"] = { 2, "vrykul located in Inkbinders Rise in Stormheim", "Ragvar the Plunderer is a vrykul located in Inkbinders Rise in Stormheim." },
  ["ragzy cashgrab"] = { 2, "goblin located on the roof of the Scrapshop in the Undermine", "Ragzy Cashgrab is a goblin located on the roof of the Scrapshop in the Undermine." },
  ["rahel"] = { 2, "venthyr located in Revendreth", "Rahel is a venthyr located in Revendreth and Sinfall. She discovered the three dead villagers in the Darkhaven Crypt in the aftermath of the stand off." },
  ["raider bork"] = { 2, "orc PvP mount vendor located right before the Hall of Leg...", "Raider Bork is an orc PvP mount vendor located right before the Hall of Legends in the orcish city of Orgrimmar. Curiously, he is not flagged for PvP and therefore unkillable, unlike his Alliance counterpart, Lieutenant Karter." },
  ["raj naz'jan"] = { 2, "naga emperor of Riplash when Leviroth was imprisoned", "Raj Naz'jan was the naga emperor of Riplash when Leviroth was imprisoned. Queen Azshara herself blessed his trident so it would slay the beast should it ever escape." },
  ["rajah haghazed"] = { 2, "naga", "Rajah Haghazed is a naga and leader of the Darkcrest tribe found in Darkcrest Enclave in Zangarmarsh. He was a fearless warrior and one of the Cenarion Expedition's most feared adversaries until Warden Hamoot sent adventurers to kill him." },
  ["rajah kaz'sith"] = { 2, "naga located in Zangarmarsh", "Rajah Kaz'sith is a naga located in Zangarmarsh." },
  ["rajani honor-guard"] = { 2, "', "Rajani Honor-Guards are mogu who stand guard in and around the Silent Sanctuary in the Vale of Eternal Blossoms." },
  ["rajani sparkcallers"] = { 2, "', "Rajani Sparkcallers are mogu War Campaign troop units, unlocked by  [Troop Requisition: Rajani Sparkcaller]." },
  ["rajani stormseer"] = { 2, "', "Rajani Stormseers are mogu located at the Gate of the August Celestials in Kun-Lai Summit." },
  ["rajani warrior"] = { 2, "', "Rajani Warriors are mogu mainly found outside the Silent Sanctuary in the Vale of Eternal Blossoms." },
  ["rajis fyashe"] = { 2, "naga", "Rajis Fyashe is a naga and leader of the Bloodscale tribe found in Bloodscale Grounds in Zangarmarsh. She summons Bloodscale Elementals." },
  ["rak'gor bloodrazor"] = { 2, "elite orc", "Rak'gor Bloodrazor is an elite orc who accompanied Garrosh Hellscream to Pandaria as his bodyguard. Garrosh then ordered Rak'gor to go with Vol'jin to investigate the saurok rookery in the Dagger in the Dark scenario." },
  ["rak'sha the swift"] = { 2, "naga located in the Eternal Palace", "Rak'sha the Swift is a naga located in the Eternal Palace." },
  ["rak'tul, vessel of souls"] = { 2, "boss in the Maisara Caverns", "Rak'tul, Vessel of Souls is a boss in the Maisara Caverns." },
  ["raka"] = { 2, "vulpera Trade Goods vendor located at the Vulpera Hideawa...", "Raka is a vulpera Trade Goods vendor located at the Vulpera Hideaway in Vol'dun." },
  ["rakha"] = { 2, "tortollan located at Scaletrader Post in Zuldazar", "Rakha is a tortollan located at Scaletrader Post in Zuldazar." },
  ["rakva"] = { 2, "nerubian located in the Umbral Bazaar in the City of Threads", "Rakva is a nerubian located in the Umbral Bazaar in the City of Threads. She considers Arax'ne and her family as traditionalists." },
  ["ralaar fangfire"] = { 2, "first worgen", "Ralaar Fangfire, also known as Alpha Prime, was the first worgen. A talented night elf druid who was able to surpass others in practicing the art of the pack form, he founded a group known as the Druids of the Pack and became their leader." },
  ["ralara"] = { 2, "Highborne mage", "Ralara is a Highborne mage. Originally a night elf, she perished and was raised as a Darkfallen during the Fourth War." },
  ["rally bigbombs"] = { 2, "goblin located in R&D in the Motherlode", "Rally Bigbombs is a goblin located in R&D in the Motherlode. He used to be Jastor Gallywix's chief weapons researcher before he took a huge payday to work for the Venture Company." },
  ["rally blastfoot"] = { 2, "goblin located in the VIP area of Corby's Cabana Bar", "Rally Blastfoot is a goblin located in the VIP area of Corby's Cabana Bar and Grill in Grudge Grotto in Azj-Kahet." },
  ["ramble rider enkor"] = { 2, "earthen located on the Isle of Dorn", "Ramble Rider Enkor is an earthen located on the Isle of Dorn." },
  ["ramdah"] = { 2, "earthen located in the Forgegrounds in Dornogal", "Ramdah is an earthen located in the Forgegrounds in Dornogal." },
  ["rampaging furbolg"] = { 2, "', "Rampaging Furbolgs are furbolgs of the Foulweald tribe found wrecking havoc at Silverwind Refuge in Ashenvale." },
  ["rampaging worgen"] = { 2, "', "Rampaging Worgen are worgen rampaging the Merchant Square in Gilneas City, chasing Frightened Citizens." },
  ["ramut the black"] = { 2, "mogu located in Island Expeditions", "Ramut the Black is a mogu located in Island Expeditions." },
  ["ran bloodtooth"] = { 2, "furbolg found in Bloodtooth Camp in Ashenvale", "Ran Bloodtooth is a furbolg found in Bloodtooth Camp in Ashenvale. He is the king of all furbolg in Ashenvale." },
  ["ran'hune"] = { 2, "haranir located in Harandar", "Ran'hune is a haranir located in Harandar." },
  ["rana"] = { 2, "broker located in Haven in Zereth Mortis", "Rana, previously Al'rana, is a broker located in Haven in Zereth Mortis. She goes with Al'dalil to Slumbering Vault to ensure it is safe from Cartel Xy." },
  ["rana bubblefizz"] = { 2, "gnome located in Brewnall Village", "Blixxrak is a gnome located in Brewnall Village. She is a member of the Short & Stout Brewing Co." },
  ["ranah"] = { 2, "vulpera repair", "Ranah is a vulpera repair and blacksmithing vendor and quest giver located at the Withering Gulch in Vol'dun. She is apparently trying to restore the gulch's ruined fields by repairing the nearby fountains." },
  ["ranald flamehair"] = { 2, "vrykul located in Beryl Meadow in Stormsong Valley", "Ranald Flamehair is a vrykul located in Beryl Meadow in Stormsong Valley, having been killed by Severus the Outcast." },
