  ["rangari arepheon"] = { 2, "draenei located in the Blademoon Bloom in Shadowmoon Valley", "Rangari Arepheon is a draenei located in the Blademoon Bloom in Shadowmoon Valley." },
  ["rangari borikar"] = { 2, "draenei located at the Embaari Village in Shadowmoon Valley", "Rangari Borikar is a draenei located at the Embaari Village in Shadowmoon Valley. He is training a pair of Embaari Peacekeepers." },
  ["rangari chel"] = { 2, "draenei Marksmanship hunter from Elodor", "Rangari Chel  is a draenei Marksmanship hunter from Elodor who joined the Alliance champion as a follower after the defeat of Socrethar at Exarch's Rise." },
  ["rangari d'kaan"] = { 2, "draenei sent on a mission in Gorgrond", "Rangari D'kaan is a draenei sent on a mission in Gorgrond. He travels through Naielle's Watch into the Highpass." },
