  ["ranger arepheon"] = { 2, "draenei located at Lunarfall in Shadowmoon Valley", "Ranger Arepheon is a draenei located at Lunarfall in Shadowmoon Valley. This section concerns content related to Legion." },
  ["ranger bodine"] = { 2, "dwarven hunter trainer located at the Greyfang Enclave in...", "Ranger Bodine is a dwarven hunter trainer located at the Greyfang Enclave in Dalaran. It is currently unknown if he survived Dalaran's destruction." },
  ["ranger bolor"] = { 2, "centaur roaming the southern outskirts of Timberstep Outp...", "Ranger Bolor is a centaur roaming the southern outskirts of Timberstep Outpost in the Ohn'ahran Plains. Her bakar, Batu, was killed by the Mudfin tribe." },
  ["ranger captain areiel"] = { 2, "Darkfallen dark ranger of high elf origin serving the For...", "Ranger Captain Areiel was a Darkfallen dark ranger of high elf origin serving the Forsaken." },
  ["ranger darksong"] = { 2, "Darkfallen", "Ranger Darksong is a Darkfallen." },
  ["ranger jargal"] = { 2, "centaur located in Cloverwood Hollow in the Ohn'ahran Plains", "Ranger Jargal is a centaur located in Cloverwood Hollow in the Ohn'ahran Plains." },
  ["ranger otyuk"] = { 2, "centaur located on the river shore just south of Timberst...", "Ranger Otyuk is a centaur located on the river shore just south of Timberstep Outpost in the Ohn'ahran Plains. His bakar, Pesca, has been dognapped by the Mudfin tribe, but returns to Otyuk's side after  [20-70] Return to Roscha." },
  ["ranjit"] = { 2, "first boss of Skyreach in Spires of Arak", "Ranjit is the first boss of Skyreach in Spires of Arak." },
  ["rank overseer"] = { 2, "', "Rank Overseers are swolbolds located in Darkflame Cleft." },
  ["ranni flagdabble"] = { 2, "gnome located at Lunarfall in Shadowmoon Valley", "Ranni Flagdabble is a gnome located at Lunarfall in Shadowmoon Valley. He can only be recruited using the Headhunter's Harvest from Lunarfall Inn." },
  ["rannida"] = { 2, "earthen located at the Keepers Terrace near the stairs le...", "Rannida is an earthen located at the Keepers Terrace near the stairs leading up to the Foundation Hall in Dornogal. She is friends with Bondaz." },
  ["ranpiata"] = { 2, "tuskarr located with Hudson at Hudson's Rock in the Azure...", "Ranpiata is a tuskarr located with Hudson at Hudson's Rock in the Azure Span." },
  ["raq"] = { 2, "tuskarr child located in the Filled Bowl in the Azure Span", "Raq is a tuskarr child located in the Filled Bowl in the Azure Span. He plays the nearby drum by dancing on it, and often breaks it as a result." },
  ["rasha'nan"] = { 2, "boss in Nerub-ar Palace", "Rasha'nan is a boss in Nerub-ar Palace. As adventurers battle Ulgrax the Devourer, she destroys the webs holding up the Grand Rampart." },
  ["rasha'nan (the dawnbreaker tactics)"] = { 2, "boss in the Dawnbreaker", "Rasha'nan is a boss in the Dawnbreaker." },
  ["rashok, the elder"] = { 2, "boss in Aberrus", "Rashok, the Elder is a boss in Aberrus, the Shadowed Crucible." },
  ["rasnar the war ender"] = { 2, "djaradin located in the underground portion of the Obsidi...", "Rasnar the War Ender is a djaradin located in the underground portion of the Obsidian Throne at the Obsidian Citadel in Waking Shores." },
  ["rasvan"] = { 2, "venthyr located in Revendreth", "Rasvan is a venthyr located in Revendreth." },
  ["raszel ander"] = { 2, "human warlock", "Raszel Ander is a human warlock who appears as a Mysterious Traveler at Demon Fall Ridge in Ashenvale after completing the ritual from the Dark Ritual Stone. He is a friend of Doan Karhan and remains by his side in the Barrens after completing the..." },
  ["rathamaresh"] = { 2, "dracthyr located on the Defiant Dragonscale in Durotar", "Rathamaresh is a dracthyr located on the Defiant Dragonscale in Durotar." },
