  ["rattleskew"] = { 2, "human ghost located at the Barnacle on the Timeless Isle", "Rattleskew is a human ghost located at the Barnacle on the Timeless Isle. He spawns as the third wave of the Battle of the Barnacle." },
  ["ratts"] = { 2, "vulpera located outside the Caverns of Time in Tanaris", "Ratts is a vulpera located outside the Caverns of Time in Tanaris. After speaking with her in  [10-90] Tat Big Meanie for Guest Relations, Ratts leaves the celebration grounds." },
  ["rau cliffrunner"] = { 2, "tauren quest giver located under Freewind Post in Thousan...", "Rau Cliffrunner is a tauren quest giver located under Freewind Post in Thousand Needles. Before the Cataclysm, he was located in the Post." },
  ["raul the tenacious"] = { 2, "worgen located at Boralus Harbor in Boralus", "Raul the Tenacious is a worgen located at Boralus Harbor in Boralus." },
  ["rauloo the hardened"] = { 2, "tortollan located in Zuldazar", "Rauloo the Hardened is a tortollan located in Zuldazar. At first he is found in a Nazeshi Cage in the Dreadpearl Shallows." },
