  ["ravenspeaker statue"] = { 2, "', "Ravenspeaker Statues are arakkoa located in Spires of Arak. They have been petrified by the breath of Stonescale." },
  ["ravenspeaker thelnaas"] = { 2, "arakkoa located at Lion's Watch", "Ravenspeaker Thelnaas is an arakkoa located at Lion's Watch and Vol'mar in Tanaan Jungle. Thelnaas is a member of the Order of the Awakened and has accompanied Dawn-Seeker Krisek to Tanaan Jungle to enlist the help of Alliance and Horde heroes." },
  ["ray tamer enaka"] = { 2, "ankoan located in Mezzamere in Nazjatar", "Ray Tamer Enaka is an ankoan located in Mezzamere in Nazjatar." },
  ["raz l. dazzle"] = { 2, "gnome located in Mechagon City", "Raz L. Dazzle is a gnome located in Mechagon City. During mechagnome recruitment, he is seen in Rustbolt on Mechagon Island." },
