  ["razik chumpchanger"] = { 2, "goblin general goods vendor summoned by the  [Goblin Town...", "Razik Chumpchanger is a goblin general goods vendor summoned by the  [Goblin Town-in-a-Box] along with a box of fireworks behind him. He has the  Toy Stability buff which lasts for 20 minutes, afterwards he'll despawn." },
