  ["razzi the shaper"] = { 2, "ethereal located at Tradewinds Market in Boralus", "Razzi the Shaper is an ethereal located at Tradewinds Market in Boralus. He can reforge Azerite gear, allowing you to choice the Azerite powers you want on that piece of gear again." },
  ["razzie coalwrench"] = { 2, "goblin vendor located in the Shrine of Two Moons in the V...", "Razzie Coalwrench  is a goblin vendor located in the Shrine of Two Moons in the Vale of Eternal Blossoms." },
  ["razzil naypolm"] = { 2, "goblin located in the Steamwheedle Laboratories in the Un...", "Lab Assistant Laszly is a goblin located in the Steamwheedle Laboratories in the Undermine." },
