  ["rebel drogbar"] = { 2, "', "Rebel Drogbar are drogbar located in Highmountain. They are visions of the past, seen assisting Huln Highmountain defeat the Deathwing in Neltharion's Vault." },
  ["recalled orinoko tuskbreaker"] = { 2, "tuskarr projection located in the Bronze Dragonshrine in ...", "Recalled Orinoko Tuskbreaker is a tuskarr projection located in the Bronze Dragonshrine in the Dragonblight during the Radiant Echoes event. He is the memory of Orinoko Tuskbreaker." },
  ["recalled silverbrook lumberjack"] = { 2, "', "Recalled Silverbrook Lumberjacks are worgen located in the Ruby Dragonshrine and the Dragon Wastes in the Dragonblight during the Radiant Echoes event." },
  ["recalled silverbrook villager"] = { 2, "', "Recalled Silverbrook Villagers are worgen located in the Ruby Dragonshrine and the Dragon Wastes in the Dragonblight during the Radiant Echoes event." },
  ["recalled vladof the butcher"] = { 2, "vrykul projection located in the Bronze Dragonshrine in t...", "Recalled Vladof the Butcher is a vrykul projection located in the Bronze Dragonshrine in the Dragonblight during the Radiant Echoes event. He rides Recalled Enormos and is the memory of Vladof the Butcher." },
  ["recalled winterfin rider"] = { 2, "', "Recalled Winterfin Riders are murloc projections located in the Dragon Wastes in the Dragonblight during the Radiant Echoes event. When the event is inactive, they appear in the Ruby Dragonshrine." },
  ["recalled winterfin shorestriker"] = { 2, "', "Recalled Winterfin Shorestrikers are murloc projections located in the Dragon Wastes in the Dragonblight during the Radiant Echoes event. Some are seen aboard the Recalled Shorestriker Canoes." },
  ["recalled winterfin tadpole"] = { 2, "', "Recalled Winterfin Tadpoles are murloc projections located in the Dragon Wastes in the Dragonblight during the Radiant Echoes event. Some are trapped in Cages." },
  ["recalled winterfin warrior"] = { 2, "', "Recalled Winterfin Warriors are murloc projections located in the Ruby Dragonshrine and the Dragon Wastes in the Dragonblight during the Radiant Echoes event." },
  ["reclaimer a'zak"] = { 2, "nerubian quest giver located in Azjol-Nerub", "Reclaimer A'zak is a nerubian quest giver located in Azjol-Nerub. They are initially found just inside the dungeon entrance, in the tunnel leading to the Gilded Gate, alongside some Azjol-anak Warriors and a Nerubian Flyer." },
  ["reclaimer makko"] = { 2, "dracthyr located in the Ohn'ahran Plains", "Reclaimer Makko is a dracthyr located in the Ohn'ahran Plains." },
  ["reclaimer zuan"] = { 2, "mogu loacted at Seeker's Point in Kun-Lai Summit", "Reclaimer Zuan is a mogu loacted at Seeker's Point in Kun-Lai Summit. He came to attack Lorewalker Cho." },
  ["reclusive fisher"] = { 2, "tuskarr located on Dragonskull Island in the Forbidden Reach", "Reclusive Fisher is a tuskarr located on Dragonskull Island in the Forbidden Reach." },
  ["recovering aeroknight"] = { 2, "', "Recovering Aeroknights are Arathi located in Wildcamp Or'lay in Azj-Kahet." },
  ["recovering resistance fighter"] = { 2, "', "Recovering Resistance Fighters are located at the Temporal Conflux in the Primalist Future. They are being healed by Resistance Medics." },
  ["recruiter barker"] = { 2, "worgen found in Stormwind Harbor", "Recruiter Barker is a worgen found in Stormwind Harbor, handling the Alliance Recruits preparing for the assault on the Broken Shore. Compared to the other recruiters, he doesn't seem very good at his job, being slow and prone to losing his papers." },
  ["redelav attendant"] = { 2, "', "Redelav Attendants are venthyr located at the Old Gate and the Eternal Terrace in Revendreth. When disguised as a Dredger Servant during  [60WQ] Secret Service, they are friendly." },
  ["redelav courier"] = { 2, "venthyr running around the Old Gate in Revendreth", "Redelav Courier is a venthyr running around the Old Gate in Revendreth." },
  ["redelav fencer"] = { 2, "', "Redelav Fencers are venthyr located at the Night Market in Revendreth. Here they wait in line to order goods from Ta'rmoro." },
  ["redelav footman"] = { 2, "', "Redelav Footmen are venthyr located at the Old Gate in Revendreth." },
  ["redelav groundskeeper"] = { 2, "', "Redelav Groundskeepers are venthyr located at the Redelav District in Revendreth." },
  ["redelav merchant"] = { 2, "', "Redelav Merchants are venthyr located at the Old Gate in Revendreth." },
  ["redelav steward"] = { 2, "', "Redelav Stewards are venthyr patroling Redelav District and the Old Gate in Revendreth. They are accompanied by Tamed Gargon." },
  ["redelav towerguard"] = { 2, "', "Redelav Towerguards are venthyr located in Redelav Tower in Revendreth." },
  ["redfang elder"] = { 2, "', "Redfang Elders are furbolgs found in Grizzly Hills." },
  ["redfang hunter"] = { 2, "', "Redfang Hunters are furbolgs found in Heart's Blood Shrine in Grizzly Hills." },
