  ["redpine looter"] = { 2, "', "Redpine Looter are gnolls located at Taelan's Tower in Western Plaguelands." },
  ["redpine necromancer"] = { 2, "', "Redpine Necromancers are gnoll necromancers located in Hearthglen Pass in the Western Plaguelands." },
  ["redpine shaman"] = { 2, "', "Redpine Shaman are gnolls located at Redpine Dell in the Western Plaguelands." },
  ["redridge alpha"] = { 2, "', "Redridge Alphas are Redridge gnolls located in Redridge Canyons in the Redridge Mountains." },
  ["redridge basher"] = { 2, "', "Redridge Bashers are Redridge gnolls located in Redridge Canyons in the Redridge Mountains." },
  ["redridge brute"] = { 2, "', "Redridge Brutes are Redridge gnolls located in Three Corners in the Redridge Mountains." },
  ["redridge drudger"] = { 2, "', "Redridge Drudgers are gnolls found in Redridge Mountains." },
  ["redridge mongrel"] = { 2, "', "Redridge Mongrels are gnolls located in southwestern Redridge Mountains." },
  ["redridge mystic"] = { 2, "', "Redridge Mystics are Redridge gnolls located in Redridge Canyons in Redridge Mountains." },
  ["redridge poacher"] = { 2, "', "Redridge Poachers are gnolls found in the Redridge Mountains." },
  ["redridge thrasher"] = { 2, "', "Redridge Thrashers are Redridge gnolls located in Three Corners in the Redridge Mountains." },
  ["reef lord raj'his"] = { 2, "naga found in Azuregale Bay in Suramar", "Reef Lord Raj'his is a naga found in Azuregale Bay in Suramar. He is accompanied by a Sashj'tar Tidecaller and a Sashj'tar Scaleguard." },
  ["reefstalker inaku"] = { 2, "ankoan of the Waveblade clan", "Reefstalker Inaku was an ankoan of the Waveblade clan. She hunted the naga and struck fear into their hearts." },
  ["reena cogscrap"] = { 2, "goblin archaeology trainer found in Warspear's Microshop ...", "Reena Cogscrap is a goblin archaeology trainer found in Warspear's Microshop of Ashran." },
  ["reformed bachelor"] = { 2, "', "Reformed Bachelors are satyr disguised as male humans in the Guest Chambers in the Return to Karazhan. When they are hurt enough, they reveal their true form." },
  ["refreshment vendor (npc)"] = { 2, "tuskarr food vendor during Hearthstone's 10th Anniversary", "Refreshment Vendor is a tuskarr food vendor during Hearthstone's 10th Anniversary." },
  ["refuge watcher"] = { 2, "', "Refuge Watchers are arakkoa located in Terokkar Refuge in Talador." },
  ["regal mistdancer"] = { 2, "', "Regal Mistdancers are venthyr located in the Sanguine Depths." },
  ["regald hornfyre"] = { 2, "Arathi lamplighter of the Hallowfall Arathi", "Regald Hornfyre is an Arathi lamplighter of the Hallowfall Arathi." },
  ["regla brighthorn"] = { 2, "tauren auctioneer found in Warspear's Auction House in As...", "Regla Brighthorn is a tauren auctioneer found in Warspear's Auction House in Ashran." },
  ["rei"] = { 2, "dracthyr located in Valdrakken", "Rei is a dracthyr located in Valdrakken." },
  ["reingard"] = { 2, "earthen located with Konraada", "Reingard is an earthen located with Konraada and Matthilde who is resting a book against his back at the Stoneshaper's Atrium in Dornogal." },
  ["rejold barleybrew"] = { 2, "dwarf quest giver located in Kharanos in Dun Morogh", "Rejold Barleybrew is a dwarf quest giver located in Kharanos in Dun Morogh. Before the Cataclysm, he was located in Brewnall Village instead." },
  ["rejuvenated defender"] = { 2, "', "Rejuvenated Defenders are rejuvenated Fallen Earthen Defenders that have been healed by a  [Telluric Poultice], this turns them into a guardian to the player. They will help attack Stormforged Raider and Stormforged Reaver for the  [25-30] Fightin..." },
  ["rel"] = { 2, "dracthyr located in Valdrakken", "Rel is a dracthyr located in Valdrakken." },
  ["relaxed patron"] = { 2, "Veiled Market", "Relaxed Patrons are brokers located in Tazavesh, the Veiled Market." },
  ["relaxing earthen"] = { 2, "', "Relaxing Earthen are earthen located in Boulder Springs on the Isle of Dorn." },
  ["relaxing patron"] = { 2, "', "Relaxing Patrons are centaur, dracthyr, and tuskarr guests of Khalla and Tuktu's grill on the northern coast of the Ohn'ahran Plains. There are ten of them around the area: A female dracthyr in visage form standing next to the Relaxing Mallard an..." },
  ["relaxing resident"] = { 2, "', "Relaxing Residents are earthen located in Keepers Terrace, Steam Vent, and Stoneshaper's Atrium in Dornogal." },
  ["relentless party person"] = { 2, "', "Relentless Party People are located at the Blackwater Marina in the Undermine." },
  ["relic breaker krelva"] = { 2, "Mawsworn kyrian located on one of the floating islands we...", "Relic Breaker Krelva is a Mawsworn kyrian located on one of the floating islands west of the Korthia mainland. To reach this  [Conquering Korthia]-required vignette, players must complete  [60] Bone Tools, part of the Chains of Domination campaign..." },
  ["rellen, the learned"] = { 2, "early hero of the Maruuk centaur", "Rellen, The Learned was an early hero of the Maruuk centaur. He established the centaur's footing in the Ohn'ahran Plains by showing them methods with which they should fight the land's apex predators: the spiders, slyverns, and thunder lizards." },
  ["relley cogwhacker"] = { 2, "gnome located in Delver's Headquarters in the Bazaar in S...", "Relley Cogwhacker is a gnome located in Delver's Headquarters in the Bazaar in Silvermoon City. She is an expert on the qiraji." },
  ["relothina"] = { 2, "centaur located in Nokhudon Hold in the Ohn'ahran Plains", "Relothina is a centaur located in Nokhudon Hold in the Ohn'ahran Plains." },
  ["remembered brute"] = { 2, "', "Remembered Brutes are quilboar projections located in the Quagmire in Dustwallow Marsh during the Radiant Echoes event. When the event is inactive, they are found south of Brackenwall Village." },
  ["remembered charlga razorflank"] = { 2, "quilboar projection located in Dustwallow Marsh during th...", "Remembered Charlga Razorflank is a quilboar projection located in Dustwallow Marsh during the Radiant Echoes event. She is the memory of Charlga Razorflank." },
  ["remembered hogger"] = { 2, "gnoll projection located east of Pyrox Flats in the Seari...", "Remembered Hogger is a gnoll projection located east of Pyrox Flats in the Searing Gorge. He is the memory of Hogger during the Radiant Echoes event." },
  ["remembered kobold"] = { 2, "', "Remembered Kobolds are kobold projections located east of Pyrox Flats in the Searing Gorge with Remembered Hogger during the Radiant Echoes event. When the event is inactive, they are found in the Cauldron." },
  ["remembered lich king"] = { 2, "Radiant Echoes boss located in the Path of the Titans in ...", "Remembered Lich King is the Radiant Echoes boss located in the Path of the Titans in the Dragonblight. During the fight, he also summons Skeletal Horrors." },
  ["remembered quilboar"] = { 2, "', "Remembered Quilboar are quilboar projections located in the Quagmire in Dustwallow Marsh during the Radiant Echoes event. When the event is inactive, they are found south of Brackenwall Village." },
  ["remembered riverpaw"] = { 2, "gnoll companion", "Remembered Riverpaw is a gnoll companion. It can be bought from Remembrancer Amuul in Dalaran and the Memory of a Duke in the Searing Gorge for 10,000 ." },
  ["remembered thornweaver"] = { 2, "', "Remembered Thornweavers are quilboar projections located in the Quagmire in Dustwallow Marsh during the Radiant Echoes event. When the event is inactive, they are found south of Brackenwall Village." },
  ["remembered zenn foulhoof"] = { 2, "satyr projection located in the Dragonmurk in Dustwallow ...", "Remembered Zenn Foulhoof is a satyr projection located in the Dragonmurk in Dustwallow Marsh during Radiant Echoes. He is the memory of Zenn Foulhoof." },
  ["remus"] = { 2, "deceased venthyr located in the Ashen Traverse in Revendreth", "Remus is a deceased venthyr located in the Ashen Traverse in Revendreth. He was one of Sabina's companions." },
  ["renavyth"] = { 2, "venthyr located in Torghast", "Renavyth is a venthyr located in Torghast, Tower of the Damned." },
  ["rend blackhand (rumble)"] = { 2, "unit of the Blackrock family in Warcraft Rumble", "Rend Blackhand is a unit of the Blackrock family in Warcraft Rumble. While mounted, he is a flying unit; upon dismounting, he becomes a melee ground unit." },
  ["rend blackhand (tactics)"] = { 2, "Warchief of the Dark Horde", "Rend Blackhand was the Warchief of the Dark Horde and the third boss in Upper Blackrock Spire. He was removed with the instance revamp in patch 6.0.2." },
  ["rendvith"] = { 2, "dracthyr located in the Azure Span", "Rendvith is a dracthyr located in the Azure Span." },
  ["renka"] = { 2, "vulpera located at the Artisan's Market in Valdrakken", "Renka is a vulpera located at the Artisan's Market in Valdrakken." },
  ["renpiaq"] = { 2, "tuskarr flight master of Morqut Village in the Forbidden ...", "Renpiaq is the tuskarr flight master of Morqut Village in the Forbidden Reach. He has connections to Wingrest Embassy in the Waking Shores and Veiled Ossuary in Thaldraszus." },
  ["renstadt gore"] = { 2, "worgen", "Renstadt Gore is a worgen that accompanied Commander Rell Nightwind and his team to an uncharted island to rescue the White Pawn but seemingly perished when they approached the Jade Forest and were ambushed by the Horde." },
  ["renthal bloodfang"] = { 2, "worgen located at the Lunarfall in Shadowmoon Valley", "Renthal Bloodfang is a worgen located at the Lunarfall in Shadowmoon Valley. He can only be recruited using the Headhunter's Harvest from Lunarfall Inn." },
  ["renthel"] = { 2, "worgen pack leader mentioned by Gaedrin Moonfang in his  ...", "Renthel was a worgen pack leader mentioned by Gaedrin Moonfang in his  [Faded Journal]." },
  ["renzi boltcutter"] = { 2, "goblin located under the stairs on the ground floor of th...", "Renzi Boltcutter is a goblin located under the stairs on the ground floor of the Incontinental Hotel in the Undermine." },
  ["rerjik mashnose"] = { 2, "gnoll barbarian", "Rerjik Mashnose is a gnoll barbarian and shaman. He wears a loincloth and several leather straps crossing his mangy pelt." },
  ["rescued consortium dealer"] = { 2, "ethereal", "The Rescued Consortium Dealer is an ethereal that can be set free from an Ethereum Prison in the Netherstorm. They grants 500 Consortium reputation to their rescuer." },
  ["rescued kid"] = { 2, "', "Rescued Kids are vulpera children who appear in Vorrik's Sanctum in Vol'dun after completion of  [30-60] The Little Ones." },
  ["rescued lower city brute"] = { 2, "Broken", "The Rescued Lower City Brute is a Broken that can be set free from an Ethereum Prison. Rescued Lower City Brute grants 500 reputation toward the Lower City to his or her rescuer." },
  ["rescued slave (vol'dun)"] = { 2, "', "Rescued Slaves are vulpera located in Vorrik's Sanctum in Vol'dun." },
  ["rescued tortollan"] = { 2, "tortollan located in Redfield's Watch in Nazmir", "Rescued Tortollan is a tortollan located in Redfield's Watch in Nazmir." },
  ["rescued tuskarr"] = { 2, "', "Rescued Tuskarr are tuskarr located outside Kargpaw's Den in the Azure Span after being rescued." },
  ["research scribe"] = { 2, "', "Research Scribe are venthyr located in Sanguine Depths." },
  ["researcher aderan"] = { 2, "Alliance quest giver situated at Fort Wildervar in Howlin...", "Researcher Aderan is an Alliance quest giver situated at Fort Wildervar in Howling Fjord. He is researching the movement of the giants at Giants' Run and their connection with the Iron Dwarves." },
  ["researcher au'daluk"] = { 2, "broker located in the near all the other secondary profes...", "Researcher Au'daluk is a broker located in the near all the other secondary profession trainers in the Hall of Shapes in Oribos." },
  ["researcher baneflare"] = { 2, "dracthyr item upgrader at Morqut Village in the Forbidden...", "Researcher Baneflare is a dracthyr item upgrader at Morqut Village in the Forbidden Reach. He exchanges one  [Untapped Forbidden Knowledge] to upgrade Primal Infused gear from item level 385 to 395." },
  ["researcher cornelius"] = { 2, "draenei quest giver located at Amberweb Pass in Bloodmyst...", "Researcher Cornelius is a draenei quest giver located at Amberweb Pass in Bloodmyst Isle, just north of the pass entrance. He is part of a group of researchers." },
  ["researcher imareth"] = { 2, "dracthyr at Morqut Village in the Forbidden Reach", "Researcher Imareth is a dracthyr at Morqut Village in the Forbidden Reach. He ends  [70] The Forgotten Ring and starts and ends  [70] Primordial Embellishment, part of the Zskera Vaults storyline." },
  ["researcher navuud"] = { 2, "ethereal quest giver located at the Protectorate Watch Po...", "Researcher Navuud is an ethereal quest giver located at the Protectorate Watch Post in the Netherstorm." },
  ["researcher sneakwing"] = { 2, "dracthyr located in a cave in Emerald Gardens in the Ohn'...", "Researcher Sneakwing is a dracthyr located in a cave in Emerald Gardens in the Ohn'ahran Plains. He is seen observing an animal leg bone." },
  ["resentful spa patron"] = { 2, "', "Resentful Spa Patrons are located at the Serene Dreams Spa in Thaldraszus." },
  ["reshad"] = { 2, "arakkoa of the Arakkoa Outcasts", "Reshad is an arakkoa of the Arakkoa Outcasts, described as an old storyteller. He is fascinated with the history of Terokk, the great ancient king of the arakkoa people." },
  ["resistance medic"] = { 2, "', "Resistance Medics are located at the Temporal Conflux in the Primalist Future. They are found healing Recovering Resistance Fighters." },
  ["resonating augari novitiate"] = { 2, "', "Resonating Augari Novitiates are eredar ghosts located in Eredath." },
  ["resonating augari summoner"] = { 2, "', "Resonating Augari Summoners are eredar ghosts located in Eredath." },
  ["resting windsage"] = { 2, "', "Resting Windsages are centaur located at Forkriver Crossing in the Ohn'ahran Plains." },
  ["restless denizen"] = { 2, "', "Restless Denizens are eredar located in Eredath. Unlike most of the eredar echoes, they are hostile." },
  ["restless explorer"] = { 2, "', "Restless Explorers are members of the Dragonscale Expedition located in Orgrimmar, climbing on Handholds, in the Dranosh'ar Blockade in Durotar, in Stormwind Harbor in Stormwind City, and in the Waking Shores." },
  ["restless guardian"] = { 2, "', "Restless Guardians are night elf, tauren, jungle trolls, and worgen located in the Dreamgrove. They can also be seen on the Vindicaar." },
  ["retained lookout"] = { 2, "', "Retained Lookouts are venthyr located at Death's End in Revendreth." },
  ["retained supplier"] = { 2, "', "Retained Suppliers are venthyr located in Death's End in Revendreth." },
  ["retained trafficker"] = { 2, "', "Retained Traffickers are venthyr located at Death's End in Revendreth." },
  ["retained venthyr"] = { 2, "', "Retained Venthyr are venthyr located at Death's End in Revendreth." },
  ["rethaela laskar"] = { 2, "Arathi located in the Fjord Tavern in Lorel's Crossing in...", "Rethaela Laskar is an Arathi located in the Fjord Tavern in Lorel's Crossing in Hallowfall." },
  ["rethazar the fallen"] = { 2, "satyr located in Ashenvale", "Rethazar the Fallen was a satyr located in Ashenvale. He was taken out by the druid champions sent from the Dreamgrove." },
  ["rethenash"] = { 2, "dead dracthyr found in the Support Creche in the Forbidde...", "Rethenash is a dead dracthyr found in the Support Creche in the Forbidden Reach." },
  ["rethilgore (classic)"] = { 2, "boss in Shadowfang Keep", "Rethilgore is a boss in Shadowfang Keep." },
  ["retired void storage agent"] = { 2, "ethereal located in Tazavesh", "Retired Void Storage Agent is an ethereal located in Tazavesh, the Veiled Market." },
  ["retriever au'prin"] = { 2, "broker located in the Hall of Shapes in Oribos", "Retriever Au'prin is a broker located in the Hall of Shapes in Oribos. He teaches Maw Walkers about Shadowlands Fishing techniques." },
  ["rett blasterhose"] = { 2, "goblin blacksmith located Vol'mar", "Provisioner Zukama is a goblin blacksmith located Vol'mar, the main Horde base in Tanaan Jungle." },
  ["returned ascended"] = { 2, "', "Returned Ascended are Forsworn kyrian located in the Seat of the Archon during  [60] The New Path." },
  ["returned aspirant"] = { 2, "', "Returned Aspirants are Forsworn kyrian located in the Seat of the Archon during  [60] The New Path." },
  ["revenant chieftain"] = { 2, "', "Revenant Chieftains are undead Highmountain tauren located at the Highmountain Burial Ground in Highmountain. Occasionally, they walk up toward a Legion structure and are sucked by it." },
  ["revenant of the wasteland"] = { 2, "broker located at the Ruins of Yaathron in K'aresh in Unt...", "Revenant of the Wasteland is a broker located at the Ruins of Yaathron in K'aresh in Untethered Space." },
  ["revered regular"] = { 2, "Veiled Market", "Revered Regulars are brokers located in Tazarest in Tazavesh, the Veiled Market." },
  ["reynah firecaster"] = { 2, "blood elf mage", "Reynah Firecaster was a blood elf mage who, with Barnabas Grell attempted to avenge their loved ones who were killed by the Scarlet Crusade." },
  ["rezrik"] = { 2, "earthen located at the bottom of the Coreway in Dornogal", "Rezrik is an earthen located at the bottom of the Coreway in Dornogal." },
  ["rhak'ik"] = { 2, "nerubian", "Rhak'ik is a nerubian that patrols the Silken Path in Azj-Kahet alongside Khak'ik." },
  ["rhean"] = { 2, "Ascended kyrian located in Bastion", "Rhean is an Ascended kyrian located in Bastion. She was part of the grand reception in the Seat of Eternal Hymns that the Archon arranged for a Maw Walker, who decided to join the Kyrian Covenant, in honor of their efforts against the Maldraxxus i..." },
  ["rheus"] = { 2, "kyrian located at the Aspirant's Rest in Bastion working ...", "Rheus is a kyrian located at the Aspirant's Rest in Bastion working as the Flight Master there. She was part of the grand reception the Archon arranged for a Maw Walker, who decided to join the Kyrian Covenant, in honor of their efforts against th..." },
  ["rhoho"] = { 2, "centaur located at the Gelkis Village in Desolace", "Rhoho is a centaur located at the Gelkis Village in Desolace." },
  ["riala the hearthwatcher"] = { 2, "vrykul innkeeper found at Valdisdall located in Stormheim", "Riala the Hearthwatcher  is a vrykul innkeeper found at Valdisdall located in Stormheim." },
  ["ribchaser"] = { 2, "rare mob gnoll found patrolling the gnoll camps by the La...", "Ribchaser is a rare mob gnoll found patrolling the gnoll camps by the Lakeridge Highway and the Three Corners in Redridge Mountains. He has a 2-3 hour respawn timer." },
  ["ric catstalker"] = { 2, "tauren located in the Drag in Orgrimmar", "Ric Catstalker is a tauren located in the Drag in Orgrimmar. He laughs as Max and Luke are running in front of him." },
  ["richard hatstock"] = { 2, "worgen located at the Threads of Fate in Dalaran", "Richard Hatstock is a worgen located at the Threads of Fate in Dalaran. This section concerns content related to The War Within." },
  ["ricky bozwallop"] = { 2, "goblin found behind Warspear's Gallywix's Garage on Ashran", "Ricky Bozwallop is a goblin found behind Warspear's Gallywix's Garage on Ashran." },
  ["rico bugsnapper"] = { 2, "gnome located on Mechagon Island", "Rico Bugsnapper is a gnome located on Mechagon Island." },
  ["ricter"] = { 2, "Forsaken", "Ricter was a Forsaken. Magus Wordeen Voidglare wanted the Bloodstone Marble that Ricter had stolen as part of his attempt to defect from his people." },
  ["rifleman brownbeard"] = { 2, "dwarf located in the Hall of Blades in the Shattered Halls", "Rifleman Brownbeard is a dwarf located in the Hall of Blades in the Shattered Halls. He is held captive by the Shattered Hand Executioner." },
  ["rigg bilgecrank"] = { 2, "consumable item vendor of Brew Bay in Plunderstorm", "Rigg Bilgecrank is the consumable item vendor of Brew Bay in Plunderstorm. White in the waiting room lobby before a match starts, or in the untimed practice mode, Rigg will hand over all consumable items so players with them can practice in a low-..." },
  ["riggle bassbait"] = { 2, "goblin", "Riggle Bassbait is the goblin who organizes the Stranglethorn Fishing Extravaganza, together with his mechanical help Fishbot 5000 and his assistant Jang in Booty Bay. Riggle is situated outside on a dock, so Bloodsail Buccaneers with flying mount..." },
  ["rik'kal the dissector"] = { 2, "mantid located at Klaxxi'vess", "Rik'kal the Dissector is a mantid located at Klaxxi'vess. His name comes from his talent of using his knowledge of physiology to better kill his enemies." },
  ["rikal"] = { 2, "tortollan located at Fort Daelin in Stormsong Valley", "Rikal is a tortollan located at Fort Daelin in Stormsong Valley." },
  ["rikati"] = { 2, "vulpera quest giver", "Rikati is a vulpera quest giver and wasp farmer located at the Four Stingers in Vol'dun. He specializes in extracting the bilewing wasps' 'honey' (in other words, venom) from their stingers and selling it." },
  ["rilak the redeemed"] = { 2, "arakkoa quest giver located in the Lower City in Shattrat...", "Rilak the Redeemed is an arakkoa quest giver located in the Lower City in Shattrath City. He can be found just north of the lower-level exit of the Aldor bank." },
  ["riley iceclaw"] = { 2, "worgen located in Arathi Basin during Brawl: Comp Stomp f...", "Riley Iceclaw is a worgen located in Arathi Basin during Brawl: Comp Stomp for Horde players." },
