  ["rokar bladeshadow"] = { 2, "aged orc farmer living just east of Razorwind Canyon", "Rokar Bladeshadow is an aged orc farmer living just east of Razorwind Canyon, northeast the town of Razor Hill in Durotar. He has a house and a small patch of crops." },
  ["rokgah bloodgrip"] = { 2, "orc quest giver located at Thunderlord Stronghold in the ...", "Rokgah Bloodgrip is an orc quest giver located at Thunderlord Stronghold in the Blade's Edge Mountains." },
