  ["rokor"] = { 2, "tortollan located at Atal'Gral in Zuldazar", "Rokor is a tortollan located at Atal'Gral in Zuldazar." },
  ["roland abernathy"] = { 2, "undead companion of Aelthalyste", "Roland Abernathy is the undead companion of Aelthalyste. The two were venturing in Highmountain until they came across a tauren camp that had been wiped out by a demonic contagion, Roland fell to the same contagion and Aelthalyste called for help ..." },
  ["roldira"] = { 2, "earthen located in the Crafter's Enclave in Dornogal", "Roldira is an earthen located in the Crafter's Enclave in Dornogal." },
