  ["rona greenteeth"] = { 2, "Forsaken food vendor found in the woods of Darkmoon Island", "Rona Greenteeth is a Forsaken food vendor found in the woods of Darkmoon Island, just west of the Darkmoon Faire. Rona serves food that she caught and prepared herself, though it's questionable what the food is made of." },
  ["ronald anderson"] = { 2, "human stable master located at Valiance Keep in the Borea...", "Ronald Anderson is a human stable master located at Valiance Keep in the Borean Tundra." },
