  ["roogug (classic)"] = { 2, "quilboar found in Razorfen Kraul", "Roogug is a quilboar found in Razorfen Kraul. To find Roogug in the instance, take the first left and follow the path." },
  ["rookery stormrider"] = { 2, "', "Rookery Stormriders are earthen located in pairs at both sides of the portal instance portal of the Rookery at the Keepers Terrace in Dornogal." },
