  ["rowa bloodstrike"] = { 2, "orc located in the Underhold during  [60] Stay of Execution", "Rowa Bloodstrike is an orc located in the Underhold during  [60] Stay of Execution. While guarding the imprisoned Baine Bloodhoof, Rowa was confronted by Thrall, Varok Saurfang, Jaina Proudmoore, Mathias Shaw, and an adventurer, who had united to..." },
  ["rowie"] = { 2, "tuskarr child found in Iskaara in the Azure Span", "Rowie is a tuskarr child found in Iskaara in the Azure Span. He also appears out in the world, as a messenger who offers Renown-related quests for the Iskaara Tuskarr." },
  ["royal advisor"] = { 2, "', "Royal Advisors are venthyr found in Torghast, Tower of the Damned. They were originally only found in the Upper Reaches wing." },
  ["royal arcanist"] = { 2, "', "Royal Arcanists are venthyr located in the Court of the Harvesters in Revendreth." },
  ["royal historian archesonus"] = { 2, "dwarf located in the High Seat in Ironforge", "Royal Historian Archesonus is a dwarf located in the High Seat in Ironforge. She wrote  [The Fall of Lordaeron and the Scouring of the Eastweald] and  [On Plagues, Curses, and Blights]." },
  ["royal nightcloak"] = { 2, "', "Royal Nightcloaks are venthyr located in Revendreth." },
  ["royal weaver"] = { 2, "', "Royal Weavers are nerubians located in the Terrace of Majesty in Nerub-ar Palace." },
  ["royal wicklighter"] = { 2, "', "Royal Wicklighters are kobolds located in Darkflame Cleft." },
  ["royce bigbeard"] = { 2, "dwarf found at the blacksmithing workshop just outside Br...", "Royce Bigbeard is a dwarf found at the blacksmithing workshop just outside Bronzebeard's Vault in Stormshield." },
  ["ru'murh"] = { 2, "nerubian spiderling located throughout Azj-Kahet", "Ru'murh is a nerubian spiderling located throughout Azj-Kahet and City of Threads. They offer rumors that can be investigated for the Severed Threads weekly quest." },
  ["rua"] = { 2, "tuskarr child found fishing in Kauriq Gleamlet in the Azu...", "Rua is a tuskarr child found fishing in Kauriq Gleamlet in the Azure Span." },
  ["rubaen hillhelm"] = { 2, "Arathi located in Hillhelm Stead in Hallowfall", "Rubaen Hillhelm is an Arathi located in Hillhelm Stead in Hallowfall." },
  ["rubbel"] = { 2, "vulpera located upstairs in the Incontinental Hotel durin...", "Rubbel is a vulpera located upstairs in the Incontinental Hotel during Liberation of Undermine. He serves as a crafting supplies vendor." },
  ["rudo"] = { 2, "vulpera child found sitting atop a boulder in the Vulpera...", "Rudo is a vulpera child found sitting atop a boulder in the Vulpera Hideaway in Vol'dun after completion of  [30-60] The Fall of Emperor Korthek." },
  ["rudra amberstill"] = { 2, "dwarf quest giver located at Amberstill Ranch in Dun Morogh", "Rudra Amberstill is a dwarf quest giver located at Amberstill Ranch in Dun Morogh. This section concerns content related to Legion." },
