  ["ruffious"] = { 2, "earthen located next to the Peacekeeper Captain at the Co...", "Ruffious is an earthen located next to the Peacekeeper Captain at the Contender's Gate in Dornogal." },
  ["rufus claybourne"] = { 2, "worgen druid located in the Circle of Spirits in the Drea...", "Rufus Claybourne is a worgen druid located in the Circle of Spirits in the Dreamgrove during   [10-45] Ascending The Circle." },
  ["rugnug"] = { 2, "earthen located in Dornogal", "Rugnug is an earthen located in Dornogal." },
  ["rui of the sharpened blade"] = { 2, "mogu located in Kun-Lai Summit", "Rui of the Sharpened Blade is a mogu located in Kun-Lai Summit." },
  ["ruklar the trapper"] = { 2, "kobold found outside the Jasperlode Mine in Elwynn Forest", "Ruklar the Trapper is a kobold found outside the Jasperlode Mine in Elwynn Forest. Despite being named, he has no special loot and is not associated with any quests." },
  ["rulkros"] = { 2, "Mawsworn kyrian located in Cocyrus in the Maw during  [60...", "Rulkros is a Mawsworn kyrian located in Cocyrus in the Maw during  [60] Tracking a Wild God." },
  ["rumble gamer"] = { 2, "', "A Rumble Gamer is standing next to the Warcraft Rumble Machine on the second floor of the Roasted Ram in Valdrakken. They were also found in the Valley of Strength in Orgrimmar and in Stormwind Harbor of Stormwind City." },
  ["rumelda bloodslur"] = { 2, "orc follower located at Frostwall in Frostfire Ridge", "Rumelda Bloodslur is an orc follower located at Frostwall in Frostfire Ridge. She can only be recruited using the Headhunter's Harvest from Frostwall Tavern." },
  ["rundalf moonstalker"] = { 2, "worgen", "Rundalf Moonstalker is a worgen." },
  ["rune extractor"] = { 2, "', "Rune Extractors are Mawsworn kyrian located in the Maw." },
  ["runeaxe initiate"] = { 2, "', "Runeaxe Initiates are vrykul located in Inkbinders Rise in Stormheim." },
  ["runecarver slave"] = { 2, "', "Runecarver Slaves are vrykul located in the Helmouth Cliffs in the Maw of Souls." },
  ["runelord ragnar"] = { 2, "vrykul located in Hrydshal in Stormheim", "Runelord Ragnar is a vrykul located in Hrydshal in Stormheim. Ragnar is one of three rune bearers which is used to imprison Malace Shade, the others being the Runesage Floki and the Runeskeld Rollo." },
  ["runemaster skomjorn"] = { 2, "Felskorn vrykul runemaster", "Runemaster Skomjorn is a Felskorn vrykul runemaster. He attacked the Valkyra but was, in turn, taken out by the champions of the Valarjar." },
  ["runesage floki"] = { 2, "vrykul located in Stormheim", "Runesage Floki is a vrykul located in Stormheim. Floki is one of three rune bearers which is used to imprison Malace Shade, the others being the Runelord Ragnar and the Runeskeld Rollo." },
  ["runeseer faljar"] = { 2, "vrykul located in Stormheim", "Runeseer Faljar is a vrykul located in Stormheim who leads the Bonespeakers. Along with Jarl Velbrand and Torvald, he could challenge Sigryn's claim to the throne of the Tideskorn." },
  ["runeskeld rollo"] = { 2, "vrykul located in Stormheim", "Runeskeld Rollo is a vrykul located in Stormheim. Rollo is one of three rune bearers which is used to imprison Malace Shade, the others being the Runesage Floki and the Runelord Ragnar." },
  ["runesmith balehammer"] = { 2, "dwarf vendor found in the Shadow Vault in Icecrown", "Runesmith Balehammer is a dwarf vendor found in the Shadow Vault in Icecrown." },
  ["runesworn customer"] = { 2, "', "Runesworn Customers are located at Transfer Station Ta in Bastion." },
  ["runethief xy'lora"] = { 2, "broker located in Pilgrim's Grace in Zereth Mortis", "Runethief Xy'lora is a broker located in Pilgrim's Grace in Zereth Mortis." },
  ["runeweaver gedolax"] = { 2, "earthen located in the Pools of Vision in Thunder Bluff", "Runeweaver Gedolax is an earthen located in the Pools of Vision in Thunder Bluff." },
  ["ruriq"] = { 2, "member of the Kauriq tribe found in Kauriq Gleamlet in th...", "Ruriq is a member of the Kauriq tribe found in Kauriq Gleamlet in the Azure Span. He is the brother of the chieftain of the tribe, Kauj." },
  ["rusthide"] = { 2, "gnoll located in the Azure Span", "Rusthide was a gnoll located in the Azure Span." },
  ["rustler burnhoof"] = { 2, "tauren located at Kor'kron Vanguard in the Dragonblight", "Rustler Burnhoof is a tauren located at Kor'kron Vanguard in the Dragonblight." },
  ["ruuan the seer"] = { 2, "arakkoa vendor located at the Veil Terokk in the Spires o...", "Kuro'ak is an arakkoa vendor located at the Veil Terokk in the Spires of Arak." },
  ["ruuan'ok cloudgazer"] = { 2, "', "Ruuan'ok Cloudgazers are arakkoa found within Veil Ruuan in the Blade's Edge Mountains." },
  ["ruuan'ok matriarch"] = { 2, "', "Ruuan'ok Matriarchs are arakkoa found within Veil Ruuan in Blade's Edge Mountains." },
