  ["ruul eagletalon"] = { 2, "tauren quest giver located at Bloodhoof Village in Mulgore", "Ruul Eagletalon is a tauren quest giver located at Bloodhoof Village in Mulgore." },
  ["ruuzel"] = { 2, "naga found on Ruuzel's Isle in Ashenvale", "Ruuzel is a naga found on Ruuzel's Isle in Ashenvale. Talen wants the ring Ruuzel possesses." },
  ["ruvan hornsby"] = { 2, "worgen located at Lunarfall in Shadowmoon Valley", "Ruvan Hornsby is a worgen located at Lunarfall in Shadowmoon Valley. He can only be recruited using the Headhunter's Harvest from Lunarfall Inn." },
  ["ruwi"] = { 2, "haranir located in the Den in Harandar", "Ruwi is a haranir located in the Den in Harandar." },
  ["ryaand"] = { 2, "earthen located at the Stoneshaper's Atrium in Dornogal", "Ryaand is an earthen located at the Stoneshaper's Atrium in Dornogal." },
  ["rybrad coldbank"] = { 2, "dwarf weapon vendor located in Anvilmar in Dun Morogh", "Rybrad Coldbank is a dwarf weapon vendor located in Anvilmar in Dun Morogh." },
  ["rydyr"] = { 2, "vrykul located in Stormheim", "Rydyr is a vrykul located in Stormheim." },
  ["ryfus sacredpyr"] = { 2, "Arathi located inside the Church of the Sacred Flame in M...", "Ryfus Sacredpyr (referred to as the Arathi Loremaster by the map marker) is an Arathi located inside the Church of the Sacred Flame in Mereldar, Hallowfall. He offers players a quiz of six questions about Arathi culture." },
  ["rynaam"] = { 2, "centaur flight master located at Forkriver Crossing in th...", "Rynaam is a centaur flight master located at Forkriver Crossing in the Ohn'ahran Plains." },
  ["rynox"] = { 2, "drogbar stonecarver or 'stoneshaper'", "Chief Rynox was a drogbar stonecarver or 'stoneshaper' and the second-strongest drogbar of his time, responsible for creating the statue of the legendary weightlifting champion Liftbrul in the Stonedark Grotto." },
  ["ryona blondbeard"] = { 2, "dwarf member of the Explorers' League", "Ryona Blondbeard is a dwarf member of the Explorers' League. Despite his limited field experience, Ryona has distinguished himself as one of the most talented and useful of the Guild's staff at the Ironforge Guildhall." },
  ["rysa hjafmir"] = { 2, "vrykul", "Rysa Hjafmir is a vrykul who recorded a chapter in The Legend of Odyn." },
  ["ryton blackholme"] = { 2, "', "Ryton Blackholme was Hallowfall's finest blacksmith. He trained Raen Dawncavalyr and Lars Bronsmaelt from back when they were but 'cubs'." },
  ["rytr paller"] = { 2, "Arathi child located in Hallowfall", "Rytr Paller is an Arathi child located in Hallowfall." },
  ["ryuxi"] = { 2, "cloud serpent master of the Rajani mogu", "Ryuxi is the cloud serpent master of the Rajani mogu, located outside the Silent Sanctuary in the Vale of Eternal Blossoms." },
  ["sabersnout"] = { 2, "quilboar champion of the Bristleback tribe found in the S...", "Sabersnout is a quilboar champion of the Bristleback tribe found in the Southern Barrens." },
  ["sabina"] = { 2, "venthyr located in Revendreth", "Sabina is a venthyr located in Revendreth. She had three companions, Miron, Lenusa, and Remus, but captors found her and shackled her to a post with a chain,  while being exposed to the light at the Desiccation." },
  ["sabina pilgrim"] = { 2, "worgen quest ender at Thunder Peak in Ashenvale", "Sabina Pilgrim is a worgen quest ender at Thunder Peak in Ashenvale. She has come to Thunder Peak to assist the shaman of the Earthen Ring with the volcano, and the elementals around her are now her allies." },
  ["saboteur kip'tilak"] = { 2, "first boss of Gate of the Setting Sun", "Saboteur Kip'tilak is the first boss of Gate of the Setting Sun." },
  ["sacred alchemist"] = { 2, "', "Sacred Alchemists are Arathi located in Arathi's End in Azj-Kahet." },
  ["sacred flame vintner"] = { 2, "', "Sacred Flame Vintners are Arathi located at the Sanctified Grounds in the Priory of the Sacred Flame." },
  ["sacredite savant"] = { 2, "', "Sacredite Savants are Arathi located in Ghoststone Diggings on the Siren Isle. They can be seen speaking with the expedition members of observing the crystal there." },
  ["sadana bloodfury"] = { 2, "orc shaman of the Shadowmoon clan", "Sadana Bloodfury is an orc shaman of the Shadowmoon clan and the first boss in the Shadowmoon Burial Grounds dungeon. She is first seen in conversation with Arnokk the Burner at Shaz'gul, discussing supplies headed for Tanaan Jungle." },
  ["sadaqat"] = { 2, "ethereal alchemy vendor located at the Stormspire in the ...", "Dealer Sadaqat is an ethereal alchemy vendor located at the Stormspire in the Netherstorm during the invasion of Outland. This section concerns content related to The War Within." },
  ["sage behofomat"] = { 2, "draenei enchanting vendor located at the Shattrath City C...", "Sage Behofomat is a draenei enchanting vendor located at the Shattrath City Center in Talador. Once Shattrath City becomes occupied, his whereabouts are unknown." },
  ["sagepaw"] = { 2, "rare gnoll located west of Thelsamar", "Sagepaw is a rare gnoll located west of Thelsamar. He is the leader of the Mosshide gnolls." },
  ["sagorne creststrider"] = { 2, "tauren shaman trainer located in the Valley of Wisdom in ...", "Sagorne Creststrider is a tauren shaman trainer located in the Valley of Wisdom in Orgrimmar. Before the Shattering, he was located in Grommash Hold." },
  ["sahaak"] = { 2, "arakkoa vendor located in a building on the island in Bla...", "Sahaak is an arakkoa vendor located in a building on the island in Blackwind Lake in Terokkar Forest. To be able to buy and trade with Sahaak, one needs to have  [Shabby Arakkoa Disguise]." },
  ["sahi cloudsinger"] = { 2, "elder tauren shaman trainer located in the Valley of Wisd...", "Sahi Cloudsinger is an elder tauren shaman trainer located in the Valley of Wisdom in Orgrimmar. This section concerns content related to Legion." },
  ["sai'kkal the elder"] = { 2, "arakkoa priest found at the Vortex Pinnacle in the Blade'...", "Sai'kkal the Elder is an arakkoa priest found at the Vortex Pinnacle in the Blade's Edge Mountains. Together with the Ancient Raven-Priest, they are part of a cult that worships the raven god Anzu." },
  ["sailor oldenhook"] = { 2, "tuskarr located on the Old Belfyr in the Azure Span", "Sailor Oldenhook is a tuskarr located on the Old Belfyr in the Azure Span." },
  ["sailor strongline"] = { 2, "tuskarr located on the Old Belfyr in the Azure Span", "Sailor Strongline is a tuskarr located on the Old Belfyr in the Azure Span." },
  ["sairuk"] = { 2, "tuskarr Kalu'ak faction quartermaster found at Moa'ki Har...", "Sairuk is a tuskarr Kalu'ak faction quartermaster found at Moa'ki Harbor in the Dragonblight. He is found southeast of the inn." },
  ["sak'ja"] = { 2, "naga located in the Eternal Palace", "Sak'ja is a naga located in the Eternal Palace." },
  ["sakrul the brewbrul"] = { 2, "drogbar beverage or 'drog' vendor", "Sakrul the Brewbrul is a drogbar beverage or 'drog' vendor who appears on the upper level of Thunder Totem in Highmountain after completing  [10-45] Unexpected Allies. He is standing at a bar labeled 'The Drog Bar'." },
  ["sal"] = { 2, "tuskarr located in Gral's Grotto in Zuldazar", "Sal is a tuskarr located in Gral's Grotto in Zuldazar." },
  ["salavass"] = { 2, "leader of the Skalaxi order", "Sorcerer-Lord Salavass was the leader of the Skalaxi order, a faction of the Apexis arakkoa, during the final years of the civilization's existence around 1,200 years before the opening of the Dark Portal." },
  ["salfa"] = { 2, "furbolg quest giver located by the entrance to Timbermaw ...", "Salfa is a furbolg quest giver located by the entrance to Timbermaw Hold in Winterspring." },
  ["sally boltwrench"] = { 2, "goblin vendor located at Krazzlefrazz Outpost in Drustvar", "Sally Boltwrench is a goblin vendor located at Krazzlefrazz Outpost in Drustvar. This section concerns content related to The War Within." },
  ["sally boom"] = { 2, "goblin located at the Shimmering Deep in Thousand Needles", "Sally Boom is a goblin located at the Shimmering Deep in Thousand Needles." },
