  ["salon patron"] = { 2, "', "Salon Patrons are located in the Victorious Visage in Valdrakken. They can be found talking to Alruathis and Panodormu." },
  ["salt-flop"] = { 2, "murloc quest giver located on the cliff above the souther...", "Salt-Flop is a murloc quest giver located on the cliff above the southern edge of the Shattershore of the Blasted Lands. He is a member of the Rockpool tribe." },
