  ["salty el"] = { 2, "gnome with the Anglers located throughout Pandaria", "Salty El is a gnome with the Anglers located throughout Pandaria. Her location changes daily with the location of special fishing pools noted by Ben of the Booming Voice." },
  ["salukan"] = { 2, "centaur flight master located atop the Shikaar rise in Ma...", "Salukan is a centaur flight master located atop the Shikaar rise in Maruukai in the Ohn'ahran Plains and the Nokhud Offensive." },
  ["salvator copperhand"] = { 2, "goblin vendor located at the Hovel Hill in the Undermine", "Salvator Copperhand is a goblin vendor located at the Hovel Hill in the Undermine." },
