  ["sami cogbreaker"] = { 2, "gnome located at Proudmoore Keep in Boralus", "Sami Cogbreaker is a gnome located at Proudmoore Keep in Boralus." },
  ["samu"] = { 2, "venthyr located in the Sinposium in Revendreth", "Samu is a venthyr located in the Sinposium in Revendreth. He works as a scribe and can be seen as a busy man." },
  ["samuel"] = { 2, "worgen", "Samuel is a worgen who was murdered by the Watchers. His companion Eadrik warned him not to take this situation lightly." },
