  ["sanguine cadet"] = { 2, "', "Sanguine Cadets are venthyr located in the Sanguine Depths." },
  ["sanitation facilitator"] = { 2, "', "Sanitation Facilitators are brokers located throughout Oribos." },
  ["sanngror the torturer"] = { 2, "Mawsworn kyrian located in the Torturer's Hovel of the Be...", "Sanngror the Torturer is a Mawsworn kyrian located in the Torturer's Hovel of the Beastwarrens in the Maw. Players will come across Sanngror and two Mawsworn Ritualists using what's left of a Diminshed Essence for some ritual." },
  ["sanoru"] = { 2, "Broken quest giver located in the Warden's Cage in Shadow...", "Sanoru is a Broken quest giver located in the Warden's Cage in Shadowmoon Valley." },
  ["sansok khan"] = { 2, "khan of the Shikaar centaur in the Ohn'ahran Plains", "Sansok Khan is the khan of the Shikaar centaur in the Ohn'ahran Plains. She is deaf and communicates through sign language." },
  ["sapp veirhann"] = { 2, "Arathi located in Dunelle's Kindness in Hallowfall", "Sapp Veirhann is an Arathi located in Dunelle's Kindness in Hallowfall." },
  ["sapper odette"] = { 2, "worgen located in Nazj'vel in Darkshore when the Horde co...", "Sapper Odette is a worgen located in Nazj'vel in Darkshore when the Horde controls the zone." },
  ["sapph"] = { 2, "Darkfallen death knight found in Malykriss: The Vile Hold", "Sapph is a Darkfallen death knight found in Malykriss: The Vile Hold. Vereth the Cunning wants her killed for the quest  [25-30G5] The Rider of Frost." },
  ["sapphronetta flivvers"] = { 2, "gnome mineralogist", "Sapphronetta 'Saffy' Flivvers is a gnome mineralogist who worked for the Explorer's League and was sent to study Azerite in Silithus shortly after the Argus Campaign until she was kidnapped when Horde forces attacked her camp. Before coming to Sil..." },
  ["sar browneye"] = { 2, "tauren located in northern Winterspring", "Sar Browneye is a tauren located in northern Winterspring." },
  ["sar'this"] = { 2, "arakkoa found at Lake Jorune in Terokkar Forest", "Sar'this is an arakkoa found at Lake Jorune in Terokkar Forest. He is found here with the Evoker of Sar'this, the Disciple of Sar'this, as well as several Minions of Sar'this." },
  ["sara"] = { 2, "vrykul avatar of Yogg-Saron", "Sara is the vrykul avatar of Yogg-Saron who assists players during phase one of his encounter. After revealing her true form, she transforms into a Val'kyr, becoming hostile and attacking players for the remainder of the fight." },
  ["sara balloo"] = { 2, "dwarf quest giver located in the Military Ward in Ironforge", "Sara Balloo is a dwarf quest giver located in the Military Ward in Ironforge." },
  ["sara finkleswitch"] = { 2, "gnome Battle Pet Trainer located at the Shrine of Seven S...", "Sara Finkleswitch is a gnome Battle Pet Trainer located at the Shrine of Seven Stars in the Vale of Eternal Blossoms." },
