  ["sarah schnau"] = { 2, "worgen located at the Lunarfall in Shadowmoon Valley", "Sarah Schnau is a worgen located at the Lunarfall in Shadowmoon Valley. She can only be recruited using the Headhunter's Harvest from Lunarfall Inn." },
  ["saralara fizzlesprang"] = { 2, "gnome located in Bizmo's Brawlpub in Deeprun Tram", "Saralara Fizzlesprang is a gnome located in Bizmo's Brawlpub in Deeprun Tram." },
