  ["sathilga"] = { 2, "stasis-locked earthen located in Taelloch in the Ringing ...", "Sathilga is a stasis-locked earthen located in Taelloch in the Ringing Deeps. Next to her is her plaque." },
  ["satyr (warcraft iii)"] = { 2, "', "Satyrs are satyr creeps that can be encountered in the Ashenvale and Felwood tilesets. In the single-player campaigns, they appear as members of the Corrupted Ancients and as Illidan's Servitors." },
  ["satyr gimp"] = { 2, "satyr used in the Warcraft III: The Frozen Throne officia...", "The Satyr Gimp is a satyr used in the Warcraft III: The Frozen Throne official scenario map 'Monolith'. Because of the power of the Monolith which has been attracting wildlife with its mysterious energies, it allows a Satyr Gimp to gather gold and..." },
  ["satyr hellcaller"] = { 2, "', "Satyr Hellcallers are satyr hellcaller creeps that can be encountered in the Ashenvale and Felwood tilesets. They are strong melee units with deadly spells and they are the strongest members of the satyr creep family." },
  ["satyr incinerator"] = { 2, "only 'hero type' unit for the race", "The Satyr Incinerator only appears in the Warcraft III: The Frozen Throne official scenario map 'Monolith' and is seen as the hero for this race. It attacks land and air units, and because it is the only 'hero type' unit for the race, it comes fre..." },
  ["satyr pyromancer"] = { 2, "satyr pyromancer", "The Satyr Pyromancer is a satyr pyromancer that appears in The Hunter of Shadows." },
  ["satyr shadowdancer"] = { 2, "', "Satyr Shadowdancers are satyr shadowdancer creeps that can be encountered in the Ashenvale and Felwood tilesets. In the single-player campaigns, they appear as members of the Corrupted Ancients and as Illidan's Servitors." },
  ["satyr soulstealer"] = { 2, "', "Satyr Soulstealers are satyr creeps that can be encountered in the Ashenvale and Felwood tilesets. In the single-player campaigns, they appear as members of the Corrupted Ancients and as Illidan's Servitors." },
  ["satyr trickster"] = { 2, "', "Satyr Tricksters are satyr trickster creeps that can be encountered in the Ashenvale and Felwood tilesets. They are light-ranged units that attack land and air units." },
