  ["sayge"] = { 2, "talented gnoll mystic employed as a fortune-teller at the...", "Sayge is a talented gnoll mystic employed as a fortune-teller at the Darkmoon Faire. He provides free buffs during the event in the form of Sayge's Fortunes and is also a quest giver for several monthly tasks." },
  ["saza"] = { 2, "Winterpelt Furbolg located in the Azure Span", "Saza is a Winterpelt Furbolg located in the Azure Span." },
