  ["scalecommander azurathel"] = { 2, "leader of the Obsidian Warders", "Scalecommander Azurathel is the leader of the Obsidian Warders, the dracthyr of the Alliance." },
  ["scalecommander cindrethresh"] = { 2, "leader of the Dark Talons", "Scalecommander Cindrethresh is the leader of the Dark Talons, the dracthyr of the Horde." },
  ["scalecommander emberthal"] = { 2, "', "Scalecommander Emberthal is one of the five Scalecommanders of the dracthyr. She led the Adamant Vigil and serves as the main neutral dracthyr that players interact with." },
  ["scalecommander sarkareth"] = { 2, "warlike faction composed of dracthyr", "Scalecommander Sarkareth was one of the five Scalecommanders of the dracthyr. He originally led the Ebon Scales but eventually led the Sundered Flame, a warlike faction composed of dracthyr and lesser dragonkin who rebelled against the five dragon..." },
  ["scalecommander sarkareth (tactics)"] = { 2, "boss in Aberrus", "Scalecommander Sarkareth is a boss in Aberrus, the Shadowed Crucible." },
  ["scalecommander viridia"] = { 2, "healers of the dracthyr", "Scalecommander Viridia is one of the five Scalecommanders of the dracthyr. She leads the Healing Wings, the healers of the dracthyr." },
  ["scaleguard commander"] = { 2, "naga", "Scaleguard Commander is a naga who was encountered by Alliance and Horde champions in Nazjatar." },
  ["scalemelter dorbane"] = { 2, "djaradin located in the Waking Shores", "Scalemelter Dorbane is a djaradin located in the Waking Shores. He is part of a Qalashi war party seemingly heading for the Ruby Life Pools." },
  ["scalepiercer"] = { 2, "djaradin located in Dragonbane Keep in the The Waking Shores", "Scalepiercer was a djaradin located in Dragonbane Keep in the The Waking Shores. Serving as a lieutenant, they were killed during the Siege on Dragonbane Keep in order to distabilize the other djaradin." },
  ["scales"] = { 2, "murloc located at the Winterfin Retreat in the Borean Tundra", "Scales is a murloc located at the Winterfin Retreat in the Borean Tundra." },
  ["scaleseeker mezeri"] = { 2, "corrupted dracthyr located in the Ancient Bough in the Oh...", "Scaleseeker Mezeri is a corrupted dracthyr located in the Ancient Bough in the Ohn'ahran Plains. He is revealed by Dawnbell." },
  ["scalewhisker cavalry"] = { 2, "', "Scalewhisker Cavalry are kobolds located in Highmountain." },
  ["scaps"] = { 2, "gnoll kid located in the Azure Span", "Scaps is a gnoll kid located in the Azure Span. He was injured and found by the tuskarr kids Neelo and Nau." },
  ["scarab lord ahzesh"] = { 2, "orc or gnome (depending on the race of the player) warlock", "Scarab Lord Ahzesh is an orc or gnome (depending on the race of the player) warlock that is a part of the Uber Town group. He can be briefly seen during the flashback of the confrontation with Illidan Stormrage atop the Black Temple as well as dur..." },
  ["scaravelle"] = { 2, "dracthyr located at the Artisan's Market in Valdrakken", "Scaravelle is a dracthyr located at the Artisan's Market in Valdrakken." },
  ["scargil"] = { 2, "rare mob murloc found on the Western Strand in Hillsbrad ...", "Scargil is a rare mob murloc found on the Western Strand in Hillsbrad Foothills. It is on a 5-8 hour respawn timer." },
  ["scarlet archmage"] = { 2, "', "Scarlet Archmagi are undead mages of the Scarlet Crusade located in Tyr's Hand in Eastern Plaguelands. Before the Cataclysm, they and the rest of the city's population were living humans." },
  ["scarlet cleric"] = { 2, "', "Scarlet Clerics are undead clerics — members of the Scarlet Crusade raised into undeath — found at Tyr's Hand in the Eastern Plaguelands." },
  ["scarlet commander marjhan"] = { 2, "undead found at Tyr's Hand in the Eastern Plaguelands", "Scarlet Commander Marjhan is an undead found at Tyr's Hand in the Eastern Plaguelands. She was formerly located at Light's Hope Chapel." },
  ["scarlet curate"] = { 2, "', "Scarlet Curates are undead of the Scarlet Crusade located in Tyr's Hand in the Eastern Plaguelands. Before the Cataclysm they were humans." },
  ["scarlet enchanter"] = { 2, "', "Scarlet Enchanters are undead of the Scarlet Crusade located in Tyr's Hand in Eastern Plaguelands. Before the Cataclysm they were humans." },
  ["scarlet praetorian"] = { 2, "', "Scarlet Praetorians are undead located in Tyr's Hand in Eastern Plaguelands. Before the Cataclysm, they and the rest of the city's population were living humans." },
  ["scarlet warder"] = { 2, "', "Scarlet Warders are undead paladins of the Scarlet Crusade located in Tyr's Hand in the Eastern Plaguelands." },
  ["scarscale"] = { 2, "murloc located in Whispering Reef during Island Expeditions", "Scarscale is a murloc located in Whispering Reef during Island Expeditions." },
  ["scav notail"] = { 2, "gnoll located in the Ohn'ahran Plains", "Scav Notail is a gnoll located in the Ohn'ahran Plains." },
  ["schmurky"] = { 2, "murloc located at the Winterfin Retreat in the Borean Tundra", "Schmurky is a murloc located at the Winterfin Retreat in the Borean Tundra." },
  ["scilla murkshadow"] = { 2, "naga sea witch", "Scilla Murkshadow was a naga sea witch who guarded Lady Darkscale. She was killed by Jaina, Rokhan, Chen Stormstout, and Rexxar after they had received news from Jaina that she was not commanding the humans to attack the Horde." },
  ["scion of fire"] = { 2, "', "The Scion of Fire is one of three Ethereum ethereals keeping Azuregos captive at the Axis of Alignment in the Beyond during   [10-45] The Nexus Vault /   [10-45] The Nexus Vault." },
  ["scion of ice"] = { 2, "', "The Scion of Ice is one of three Ethereum ethereals keeping Azuregos captive at the Axis of Alignment in the Beyond during   [10-45] The Nexus Vault /   [10-45] The Nexus Vault." },
  ["scion of magic"] = { 2, "', "The Scion of Magic is one of three Ethereum ethereals keeping Azuregos captive at the Axis of Alignment in the Beyond during   [10-45] The Nexus Vault /   [10-45] The Nexus Vault." },
  ["scorched bandit"] = { 2, "', "Scorched Bandits are venthyr located in the Ember Ward in Revendreth." },
