  ["scourged footman"] = { 2, "', "Scourged Footmen are former Alliance soldiers stationed in and around the Farshire Mine in the Borean Tundra who have fallen victim to the Scourge. Although adventurers aren't sent to kill them in any quest, Alliance players will inevitably encoun..." },
  ["scout bloodfist"] = { 2, "orc quest giver located at Cenarion Hold in Silithus", "Scout Bloodfist is an orc quest giver located at Cenarion Hold in Silithus. This section concerns content related to Legion." },
  ["scout boldbrew"] = { 2, "dwarf located at the Shimmer Ridge in Dun Morogh during t...", "Scout Boldbrew is a dwarf located at the Shimmer Ridge in Dun Morogh during the Blood in the Snow scenario. She was captured by the Frostmane." },
  ["scout brax"] = { 2, "orc found on the Lost Isles", "Scout Brax is an orc found on the Lost Isles. He was sent by Kilag Gorefang to observe the Alliance Beachhead and sends goblin adventurers to rescue the Horde's precious cargo." },
  ["scout chelse"] = { 2, "draenei located at Elodor in Shadowmoon Valley", "Scout Chelse is a draenei located at Elodor in Shadowmoon Valley." },
  ["scout khenyug"] = { 2, "centaur located in a watch tower at the southwestern entr...", "Scout Khenyug is a centaur located in a watch tower at the southwestern entrance to Teerakai in the Ohn'ahran Plains. As part of Khansguard Jebotai's war orders, he tells Khenyug to be on the lookout for Nokhud incursions." },
  ["scout maevest"] = { 2, "dead Arathi located in Shadowmire in Hallowfall", "Scout Maevest is a dead Arathi located in Shadowmire in Hallowfall. She was part of Wayshelm's unit, and  [Maevest's Compass] belonged to her." },
  ["scout santuun"] = { 2, "centaur located in Emerald Gardens", "Scout Santuun is a centaur located in Emerald Gardens and the Mane Squeeze in the Ohn'ahran Plains. She wants to get to know the local dryads." },
  ["scout tomul"] = { 2, "centaur of Clan Shikaar encountered as a quest giver thro...", "Scout Tomul is a centaur of Clan Shikaar encountered as a quest giver throughout the Ohn'ahran Plains. Although a good hunter, Tomul's most notable trait is her keen eyesight, which makes her an excellent scout for Sansok Khan." },
  ["scout watu"] = { 2, "centaur located in Pinewood Post in the Ohn'ahran Plains", "Scout Watu is a centaur located in Pinewood Post in the Ohn'ahran Plains." },
  ["scout wayshelm"] = { 2, "Arathi located in Hallowfall", "Scout Wayshelm is an Arathi located in Hallowfall. When Hallowfall once again came under threat by the Sureki and the army was stretched thin, a call to arms was issued to those with the strength to wield a weapon." },
  ["scrapsy fibblepop"] = { 2, "gnome located at Lunarfall in Shadowmoon Valley", "Scrapsy Fibblepop is a gnome located at Lunarfall in Shadowmoon Valley. She can only be recruited using the Headhunter's Harvest from Lunarfall Inn." },
  ["scribe au'tehshi"] = { 2, "broker located in the Hall of Shapes in Oribos", "Scribe Au'tehshi is a broker located in the Hall of Shapes in Oribos. He teaches Maw Walkers about Shadowlands Inscription techniques." },
  ["scrit"] = { 2, "kobold located in the Chittering Den in the Ringing Deeps", "Scrit is a kobold located in the Chittering Den in the Ringing Deeps." },
  ["scritchscratch"] = { 2, "kobold located in Gundargaz in the Ringing Deeps", "Scritchscratch is a kobold located in Gundargaz in the Ringing Deeps." },
  ["scrivener lenua"] = { 2, "venthyr", "Scrivener Lenua is a venthyr who sometimes appears high above the Forbidden Library in Revendreth. When she spawns, Forbidden Tomes are scattered throughout the area and must be returned to the library." },
  ["scrollmaster fon"] = { 2, "mogu", "Scrollmaster Fon is a mogu." },
  ["scrollmaster uro"] = { 2, "tortollan located at Boralus Harbor in Boralus", "Scrollmaster Uro is a tortollan located at Boralus Harbor in Boralus. He runs the Almost Ancient Tomes shop." },
  ["scrollsage goji"] = { 2, "tortollan located in Seekers' Expedition in Zuldazar", "Scrollsage Goji is a tortollan located in Seekers' Expedition in Zuldazar." },
  ["scrollsage gora"] = { 2, "tortollan", "Scrollsage Gora is a tortollan." },
  ["scrollsage nola"] = { 2, "tortollan of the Tortollan Seekers", "Scrollsage Nola was a tortollan of the Tortollan Seekers who appeared on Kul Tiras and Zandalar." },
  ["scrollsage rooka"] = { 2, "tortollan located in Little Tortolla in Dazar'alor", "Scrollsage Rooka is a tortollan located in Little Tortolla in Dazar'alor." },
  ["scuttlefin scavenger"] = { 2, "murloc", "Scuttlefin Scavenger is a murloc." },
  ["scuttlefin spearhunter"] = { 2, "murloc", "Scuttlefin Spearhunter is a murloc." },
  ["scythe (undead)"] = { 2, "undead located in the Hall of Shadows", "Scythe is an undead located in the Hall of Shadows." },
  ["sea witch (warcraft iii)"] = { 2, "leader of the Underworld Minions in the campaign Exodus o...", "The Sea Witch is the leader of the Underworld Minions in the campaign Exodus of the Horde." },
  ["seam reaper zhir'ix"] = { 2, "nerubian located in Rak-Ahat in Azj-Kahet", "Seam Reaper Zhir'ix is a nerubian located in Rak-Ahat in Azj-Kahet." },
  ["sean catchpole"] = { 2, "gnome engineering vendor found at the Engineering Works i...", "Sean Catchpole is a gnome engineering vendor found at the Engineering Works in Stormshield." },
