  ["seaspray murloc"] = { 2, "', "Seaspray Murlocs are murlocs located at the Western Spray on Mechagon Island." },
  ["seaspray oracle"] = { 2, "', "Seaspray Oracles are murlocs located at the Western Spray on Mechagon Island." },
  ["sebastian jurgens"] = { 2, "mad scientist found on an oil rig between the South Seas ...", "Sebastian Jurgens is a mad scientist found on an oil rig between the South Seas islands off the coast of Tanaris in the Great Sea." },
  ["secretive researcher"] = { 2, "Veiled Market", "Secretive Researchers are ethereals located in the Gilded Landing in Tazavesh, the Veiled Market." },
  ["security chief bilgewhizzle"] = { 2, "goblin quest giver located at Steamwheedle Port in Tanaris", "Security Chief Bilgewhizzle of the Gadgetzan Water Company security, was a goblin quest giver located at Steamwheedle Port in Tanaris. This section concerns content related to Cataclysm." },
  ["security specialist"] = { 2, "', "Security Specialists are brokers guarding the entrances to the Broker's Den in Oribos. During  [60] Report to Oribos, they helped guard other key points of the city." },
  ["security trainee"] = { 2, "', "Security Trainees are brokers encountered by adventure companions in Tazavesh." },
  ["seed-keeper ungan"] = { 2, "furbolg located in the Verdant Wilds in Island Expeditions", "Seed-Keeper Ungan is a furbolg located in the Verdant Wilds in Island Expeditions." },
  ["seeker anagi"] = { 2, "ankoan located in the Hanging Reef in Nazjatar", "Seeker Anagi is an ankoan located in the Hanging Reef in Nazjatar." },
  ["seeker anewa"] = { 2, "ankoan of the Waveblade clan", "Seeker Anewa was an ankoan of the Waveblade clan who 'sought answers to questions not yet asked' and 'slew the unknown with the blade of wisdom'. They lie buried at an Ankoan Burial Shrine in the Ashen Strand of Nazjatar." },
  ["seeker hilda"] = { 2, "venthyr found in the Endmire in Revendreth", "Seeker Hilda is a venthyr found in the Endmire in Revendreth. Talking to her will summon a wave of devourers, followed by Famu the Infinite." },
  ["seeker ke'rath"] = { 2, "ethereal vendor located in the Drag in Orgrimmar", "Seeker Ke'rath is an ethereal vendor located in the Drag in Orgrimmar." },
  ["seeker najed"] = { 2, "ethereal vendor located in the Three Winds in Stormwind City", "Seeker Najed is an ethereal vendor located in the Three Winds in Stormwind City." },
  ["seer akalu"] = { 2, "broken located on the bottom floor of the Fel Hammer in M...", "Seer Akalu is a broken located on the bottom floor of the Fel Hammer in Mardum. He resets your artifact skill points." },
  ["seer aleis"] = { 2, "Broken located in the Fel Hammer after researching Focuse...", "Seer Aleis is a Broken located in the Fel Hammer after researching Focused War Effort." },
  ["seer alsoomse"] = { 2, "tauren priest trainer located in Bloodhoof Village in Mul...", "Seer Alsoomse is a tauren priest trainer located in Bloodhoof Village in Mulgore." },
  ["seer bahura"] = { 2, "tauren of the Earthen Ring", "Seer Bahura was a tauren of the Earthen Ring. She would have appeared during the Elemental Unrest event but was replaced by Earthmender Norsala." },
  ["seer beryl"] = { 2, "tauren priest trainer on the Elder Rise in Thunder Bluff", "Seer Beryl is a tauren priest trainer on the Elder Rise in Thunder Bluff." },
  ["seer brighthorn"] = { 2, "tauren priest standing next to Malakai Cross in the Pools...", "Seer Brighthorn is a tauren priest standing next to Malakai Cross in the Pools of Vision in Thunder Bluff." },
  ["seer graytongue"] = { 2, "tauren quest giver found in Red Cloud Mesa in Mulgore", "Seer Graytongue was a tauren quest giver found in Red Cloud Mesa in Mulgore. Following the Cataclysm, Graytongue is nowhere to be found." },
  ["seer jovar"] = { 2, "Broken quest giver located in Telaar in Nagrand", "Seer Jovar is a Broken quest giver located in Telaar in Nagrand." },
  ["seer kormo"] = { 2, "Broken shaman quest giver of the Earthen Ring located in ...", "Seer Kormo is a Broken shaman quest giver of the Earthen Ring located in the Temple of Earth in Deepholm." },
  ["seer olum"] = { 2, "Broken located in Serpentshrine Cavern", "Seer Olum is a Broken located in Serpentshrine Cavern, located in the room with Fathom-Lord Karathress. He is a member of the Ashtongue Deathsworn and was one of the closest allies of Akama." },
  ["seer skaltesh"] = { 2, "Broken located at the Crystal Hall in the Exodar", "Seer Skaltesh is a Broken located at the Crystal Hall in the Exodar. He offers a potion that allows one to see hidden elemental spirits throughout the Crystal Hall for a short time." },
  ["seera flametamed"] = { 2, "djaradin located in Scalecracker Keep in the Waking Shores", "Seera Flametamed is a djaradin located in Scalecracker Keep in the Waking Shores." },
  ["seersa copperpinch"] = { 2, "goblin vendor located on the lower rise in the tauren cit...", "Seersa Copperpinch is a goblin vendor located on the lower rise in the tauren city of Thunder Bluff during the Feast of Winter Veil event. She is affiliated with Smokywood Pastures, and sells lower value holiday related items." },
  ["seerspine apprentice"] = { 2, "', "Seerspine Apprentices are murlocs located at the Murloc Shoals in Suramar." },
  ["seerspine chieftain"] = { 2, "murloc located at the Murloc Shoals in Suramar", "The Seerspine Chieftain was a murloc located at the Murloc Shoals in Suramar." },
  ["seerspine summoner"] = { 2, "', "Seerspine Summoners were murlocs located at the Murloc Shoals in Suramar." },
  ["seerspine warrior"] = { 2, "', "Seerspine Warriors were murlocs located at the Murloc Shoals in Suramar." },
  ["sef iwen"] = { 2, "Drust ghost located in Drustvar", "Sef Iwen is a Drust ghost located in Drustvar. She was once a druid member of the Thornspeakers." },
  ["sefin"] = { 2, "murloc found in Azmerloth", "Sefin is a murloc found in Azmerloth." },
  ["segallia"] = { 2, "dracthyr located in the Caldera of the Menders in the For...", "Segallia is a dracthyr located in the Caldera of the Menders in the Forbidden Reach, tending to a Soar Enhancer. She later appears at the Bluefeather Cliffs in Thaldraszus, where she tried to introduce herself to the Screechflight harpies and was ..." },
  ["seirdr"] = { 2, "vrykul found at Grey Shoals in Azsuna", "Seirdr  is a vrykul found at Grey Shoals in Azsuna." },
  ["seka"] = { 2, "tortollan located at Heyman's Hideaway in Vol'dun", "Seka is a tortollan located at Heyman's Hideaway in Vol'dun." },
  ["selas"] = { 2, "worgen found on Bloodmoon Isle in Grizzly Hills", "Selas is a worgen found on Bloodmoon Isle in Grizzly Hills. While the adventurers attacked the tower and managed to kill Arugal, his death was ordered by Sasha who accompanied them." },
  ["selector au'mar"] = { 2, "broker located in the Hall of Shapes in Oribos", "Selector Au'mar is a broker located in the Hall of Shapes in Oribos. He teaches Maw Walkers about Shadowlands Herbalism techniques." },
  ["selene"] = { 2, "vulpera", "Selene is a vulpera." },
  ["selenis"] = { 2, "elf", "Selenis was an elf that was training to become a demon hunter. While he survived the first part of the ritual, he was driven mad, attacked his fellow trainees and died while fighting them." },
  ["selina dourman"] = { 2, "Forsaken greeter located in the Darkmoon Faire on Darkmoo...", "Selina Dourman is a Forsaken greeter located in the Darkmoon Faire on Darkmoon Island, which is only available during the monthly Darkmoon Faire event. She gives out information about the faire to curious adventurers." },
  ["seline keihl"] = { 2, "worgen located at the Lunarfall in Shadowmoon Valley", "Seline Keihl is a worgen located at the Lunarfall in Shadowmoon Valley. She can only be recruited using the Headhunter's Harvest from Lunarfall Inn." },
  ["sellyna"] = { 2, "ethereal flight master located in Shan'dorah in K'aresh", "Sellyna is an ethereal flight master located in Shan'dorah in K'aresh." },
  ["selyria groenveld"] = { 2, "worgen agent of the Cenarion Circle seeking to cleanse th...", "Selyria Groenveld is a worgen agent of the Cenarion Circle seeking to cleanse the Plaguelands. She was one of the druids who re-cultivated Dalson's Farm." },
  ["seniku"] = { 2, "vulpera located at the Bloom in Razorwind Shores", "Itsero is a vulpera located at the Bloom in Razorwind Shores. She is sitting around a campfire with Itsero, Akuta, and Taiyata." },
  ["senior slimediver boxenkle"] = { 2, "Steamwheedle Cartel goblin located at the Vatworks in the...", "Senior Slimediver Boxenkle is a Steamwheedle Cartel goblin located at the Vatworks in the Undermine. He works as a senior slimediver." },
  ["sensabash"] = { 2, "dracthyr located at Forkriver Crossing in the Ohn'ahran P...", "Sensabash is a dracthyr located at Forkriver Crossing in the Ohn'ahran Plains." },
  ["sentinel abakh"] = { 2, "centaur patrolling the road on the north side of Timberst...", "Sentinel Abakh is a centaur patrolling the road on the north side of Timberstep Outpost in the Ohn'ahran Plains. His bakar, Elaichi, has been dognapped by the Mudfin tribe, but returns to Abakh's side after  [20-70] Return to Roscha." },
  ["sentinel kaliun"] = { 2, "centaur located in Cloverwood Hollow in the Ohn'ahran Plains", "Sentinel Kaliun is a centaur located in Cloverwood Hollow in the Ohn'ahran Plains." },
  ["sentinel olekk"] = { 2, "centaur located at Pinewood Post in the Ohn'ahran Plains", "Sentinel Olekk is a centaur located at Pinewood Post in the Ohn'ahran Plains." },
  ["sentinel osar"] = { 2, "centaur located in a watch tower on the west side of Timb...", "Sentinel Osar is a centaur located in a watch tower on the west side of Timberstep Outpost in the Ohn'ahran Plains. His bakar, Tseg, has been dognapped by the Mudfin tribe, but returns to Osar's side after  [20-70] Return to Roscha." },
  ["sentinel of winter"] = { 2, "boss in the Den of Nalorakk", "Sentinel of Winter is a boss in the Den of Nalorakk." },
  ["sentiu"] = { 2, "tuskarr located in Iskaara in the Azure Span", "Sentiu is a tuskarr located in Iskaara in the Azure Span, tending to the wounds of Japukitat. She also appears in Brackenhide Hollow." },
  ["sentry onatu"] = { 2, "ankoan of the Waveblade clan 'whose watchful gaze remaine...", "Sentry Onatu was an ankoan of the Waveblade clan 'whose watchful gaze remained vigilant until the end.' His final warning saved the ankoan. They lie buried at an Ankoan Burial Shrine in Nar'anan in Nazjatar." },
  ["seraphine seedheart"] = { 2, "Arathi child located in the Fungal Fields in Hallowfall", "Seraphine Seedheart is an Arathi child located in the Fungal Fields in Hallowfall." },
  ["seraphine of the winter"] = { 2, "worgen quest giver for Operation: Shieldwall", "Seraphine of the Winter is a worgen quest giver for Operation: Shieldwall, located on the Skyfire in Krasarang Wilds after completing  [15-35] Lion's Landing. She is focused on reducing the deforestation caused by Horde goblins." },
  ["serena arclight"] = { 2, "gnome engineering vendor located at Fort Triumph in the S...", "Serena Arclight is a gnome engineering vendor located at Fort Triumph in the Southern Barrens. Her status after the fall of Fort Triumph just prior to the destruction of Theramore Isle is unknown." },
  ["serena everwind"] = { 2, "night elf priestess", "Serena Everwind was a night elf priestess who fought for the Kaldorei Resistance during the War of the Ancients. During one battle, she witnessed Dath'Remar Sunstrider wielding Felo'melorn against the Burning Legion, and the description of the bat..." },
  ["serena scarscale"] = { 2, "naga sea witch", "Serena Scarscale is a naga sea witch who served Illidan Stormrage and Queen Azshara." },
  ["serevex"] = { 2, "mantid located at Sik'vess in Townlong Steppes", "Serevex is a mantid located at Sik'vess in Townlong Steppes." },
  ["sergeant altumus"] = { 2, "human quest giver located at East Supply Caravan in the H...", "Sergeant Altumus is a human quest giver located at East Supply Caravan in the Hellfire Peninsula." },
  ["sergeant amelyn"] = { 2, "human quest giver located on Theramore Isle in Dustwallow...", "Sergeant Amelyn is a human quest giver located on Theramore Isle in Dustwallow Marsh. She is in front of the defunct fountain near the docks." },
  ["sergeant ba'sha"] = { 2, "PvP accessories vendor located in the Valley of Strength ...", "Sergeant Ba'sha was a PvP accessories vendor located in the Valley of Strength in the orcish city of Orgrimmar. She sold items that were associated with  [Honor] ranking." },
  ["sergeant bahrum"] = { 2, "dwarf", "Sergeant Bahrum is a dwarf and the leader of Bahrum's Post in Dun Morogh. He sends Alliance adventurers to free Frozen Mountaineers, directs them to attack Dark Iron Spies (not knowing that they are allied with the Twilight's Hammer cult), and to ..." },
  ["sergeant bonesnap"] = { 2, "orc sergeant located in Bonesnap's Camp in the territory ...", "Sergeant Bonesnap is an orc sergeant located in Bonesnap's Camp in the territory of Grizzly Hills. He is in charge of the Horde's Conquest Hold assault on Silverbrook, and is considered one of Krenna's best sergeants." },
  ["sergeant brashclaw"] = { 2, "rare gnoll found in a gnoll camp in Westfall", "Sergeant Brashclaw is a rare gnoll found in a gnoll camp in Westfall. He is on a 2-3 hour respawn timer." },
  ["sergeant brond"] = { 2, "orc located on Theramore Isle during the Theramore's Fall...", "Sergeant Brond is an orc located on Theramore Isle during the Theramore's Fall scenario." },
  ["sergeant copperbolt"] = { 2, "gnome sergeant under the command of High Tinker Gelbin Me...", "Sergeant Copperbolt is a gnome sergeant under the command of High Tinker Gelbin Mekkatorque. He was a part of a group that had been sent to reconnoiter Sector 17 in Gnomeregan, the location of the High Tinker's quarters." },
  ["sergeant growlblade"] = { 2, "worgen located at the Southport‎ in Spires of Arak", "Sergeant Growlblade is a worgen located at the Southport‎ in Spires of Arak." },
  ["sergeant major clate"] = { 2, "dwarf PvP armor vendor located in the Champions' Hall in ...", "Sergeant Major Clate is a dwarf PvP armor vendor located in the Champions' Hall in Stormwind City." },
  ["sergeant shaynemail"] = { 2, "Arathi located at Sanctified Grounds in the Priory of the...", "Sergeant Shaynemail is an Arathi located at Sanctified Grounds in the Priory of the Sacred Flame." },
  ["sergeant yazra bloodsnarl"] = { 2, "Frostwolf orc found in Frostwolf Village in Alterac Valley", "Sergeant Yazra Bloodsnarl is a Frostwolf orc found in Frostwolf Village in Alterac Valley. This section concerns content related to Dragonflight." },
  ["servant of skovald"] = { 2, "', "Servants of Skovald are vrykul located in Stormheim." },
  ["set'thik fanatic"] = { 2, "', "Set'thik Fanatics are mantid located in the Heart of Fear." },
