  ["set'thik swiftblade"] = { 2, "', "Set'thik Swiftblades are mantid located in the Heart of Fear." },
  ["set'thik tempest"] = { 2, "', "Set'thik Tempests are mantid located in the Heart of Fear." },
  ["set'thik wind wielder"] = { 2, "', "Set'thik Wind Wielders are mantid in the Spoils of Pandaria encounter in Siege of Orgrimmar." },
  ["set'thik windblade"] = { 2, "', "Set'thik Windblades are mantid located in the Heart of Fear." },
  ["set'thik zephyrian"] = { 2, "', "Set'thik Zephyrians are mantid located in the Heart of Fear." },
  ["setaal darkmender"] = { 2, "draenei death knight found at Death's Rise in Icecrown", "Setaal Darkmender is a draenei death knight found at Death's Rise in Icecrown. She has two Darkmender's Ghouls on the end of a chain." },
  ["setara blazestrike"] = { 2, "dwarf located in Arathi Basin during Brawl: Comp Stomp fo...", "Setara Blazestrike is a dwarf located in Arathi Basin during Brawl: Comp Stomp for Horde players." },
  ["sethekk chosen"] = { 2, "', "Sethekk Chosen are arakkoa located in the Sethekk Hollow in the Spires of Arak." },
  ["sethekk dreadclaw"] = { 2, "', "Sethekk Dreadclaws are arakkoa located in the Ruins of Kra'nak in Tanaan Jungle." },
  ["sethekk guard"] = { 2, "', "Sethekk Guard are arakkoa found in the Sethekk Halls. They give 10 Lower City reputation when killed on Normal Mode and 15 on Heroic Mode." },
  ["sethekk harbinger"] = { 2, "', "Sethekk Harbingers are arakkoa located in Sethekk Hollow in the Spires of Arak." },
  ["sethekk initiate"] = { 2, "', "Sethekk Initiates are arakkoa found in the Sethekk Halls. They are often followed by Avian Darkhawks." },
  ["sethekk initiate (spires of arak)"] = { 2, "', "Sethekk Initiates are arakkoa located in the Spires of Arak." },
  ["sethekk invoker"] = { 2, "', "Sethekk Invokers are arakkoa located in Tanaan Jungle." },
  ["sethekk neophyte"] = { 2, "', "Sethekk Neophytes are arakkoa located in the Ruins of Kra'nak in Tanaan Jungle. Some are performing rituals at Ritual Circles and Felflame Orbs under the tutelage of Felborn Instructors." },
  ["sethekk oracle"] = { 2, "', "Sethekk Oracles are arakkoa found in the Sethekk Halls. They gives 9 Lower City reputation when killed on Normal Mode and 15 on Heroic Mode." },
  ["sethekk oracle (spires of arak)"] = { 2, "', "Sethekk Oracles are arakkoa located in Sethekk Hollow in the Spires of Arak." },
  ["sethekk oracle (tanaan jungle)"] = { 2, "', "Sethekk Oracles are arakkoa located in Tanaan Jungle." },
  ["sethekk prophet"] = { 2, "', "Sethekk Prophet are found in Sethekk Halls. They are vulnerable to all forms of Crowd Control." },
  ["sethekk prophet (spires of arak)"] = { 2, "', "Sethekk Prophets are arakkoa located in the Sethekk Hollow in the Spires of Arak." },
  ["sethekk ravenguard"] = { 2, "', "Sethekk Ravenguards are arakkoa located in Sethekk Halls." },
  ["sethekk serpent tender"] = { 2, "', "Sethekk Serpent Tenders are arakkoa located in Spires of Arak at Sethekk Hollow." },
  ["sethekk shaman"] = { 2, "', "Sethekk Shaman are arakkoa found in Sethekk Halls. They give 9 Lower City reputation when killed." },
  ["sethekk talon lord"] = { 2, "', "Sethekk Talon Lords are arakkoa located in Sethekk Halls." },
  ["sethir the ancient"] = { 2, "satyr located on a branch of the new world tree Teldrassil", "Sethir the Ancient was a satyr located on a branch of the new world tree Teldrassil, north of the Oracle Glade. Sethir was one of the few satyr who is considered to be humanoid." },
  ["shaarubo"] = { 2, "Broken meat", "Shaarubo is a Broken meat and drink vendor located in World's End Tavern in Shattrath City." },
  ["shackled servitor"] = { 2, "', "Shackled Servitors are vrykul located on the Naglfar in the Maw of Souls." },
  ["shackled vulpera"] = { 2, "', "Shackled Vulpera are captured vulpera located in Vol'dun during the Faction Assaults." },
  ["shad'anis"] = { 2, "ethereal located at Overlook Zo'Shuul on K'aresh", "Shad'anis is an ethereal located at Overlook Zo'Shuul on K'aresh. She serves as the Phase Diving coordinator and vendor." },
  ["shade of akama"] = { 2, "dark portion of Akama's soul", "The Shade of Akama is the dark portion of Akama's soul that binds Akama to Illidan's service. The shade was a reflection of all of the wickedness and evil that resided within Akama's soul: his egoism, vanity, and the lust and greed for power and g..." },
  ["shade of akama (tactics)"] = { 2, "boss in the Black Temple", "The Shade of Akama is a boss in the Black Temple. This is probably the easiest boss in the whole of Black Temple and normally killed third." },
  ["shade of xavius"] = { 2, "shade of Xavius", "Shade of Xavius is a shade of Xavius, the Nightmare Lord, and is the final boss located at the Heart of Dread in Darkheart Thicket. As Lea Stonepaw was conducting a cleansing ritual for the Spirit of Ursoc in his lair, the Shade of Xavius appeared..." },
  ["shadebough attacker"] = { 2, "', "Shadebough Attackers are djaradin located in Skystone Falls in the Emerald Dream." },
  ["shadeguard speaker"] = { 2, "', "Shadeguard Speakers are Arathi located in Nightfall Sanctum." },
  ["shadepaw bandit"] = { 2, "', "Shadepaw Bandits are gnolls located in Kargpaw's Den in the Azure Span." },
  ["shadepaw bruiser"] = { 2, "', "Shadepaw Bruisers are gnolls located in Kargpaw's Den in the Azure Span." },
  ["shadepaw hunter"] = { 2, "', "Shadepaw Hunters are gnolls located in Kargpaw's Den in the Azure Span." },
  ["shadepaw skulker"] = { 2, "', "Shadepaw Skulkers are gnolls located in Kargpaw's Den in the Azure Span." },
  ["shadepaw trainer"] = { 2, "', "Shadepaw Trainers are gnolls located in Kargpaw's Den in the Azure Span." },
  ["shado 'fitz' farstrider"] = { 2, "tauren quest giver located at the Nesingwary Safari in Na...", "Shado 'Fitz' Farstrider is a tauren quest giver located at the Nesingwary Safari in Nagrand." },
  ["shadow lord xiraxis"] = { 2, "final encounter of  [66D] Someone Else's Hard Work Pays Off", "Shadow Lord Xiraxis is the final encounter of  [66D] Someone Else's Hard Work Pays Off. His fight is similar to Nexus-Prince Shaffar without his Sparks." },
  ["shadow pillager"] = { 2, "', "Shadow Pillagers are orcs and Forsaken found in Karazhan with their homunculi minions. This section concerns content related to Legion." },
  ["shadow priest (npc)"] = { 2, "', "Shadow Priests are Forsaken, Dark Iron dwarven, jungle troll, and gnome priests located in Netherlight Temple, on the Broken Shore, and aboard the Vindicaar on Argus." },
  ["shadow priest (troll)"] = { 2, "troll", "Shadow Priest is a troll." },
  ["shadow priest (undead)"] = { 2, "Forsaken", "Shadow Priest is a Forsaken." },
  ["shadow priest anund"] = { 2, "dwarf priest", "Shadow Priest Anund was a dwarf priest who participated in the battle with the dread wyrm, Kaldrigos. He died due to standing in the dragon's arcane breath." },
  ["shadow vanguard magus"] = { 2, "', "Shadow Vanguard Magi are nerubians located near Rambleshire on the Isle of Dorn." },
  ["shadow vanguard soldier"] = { 2, "', "Shadow Vanguard Soldiers are nerubians located near Rambleshire on the Isle of Dorn." },
  ["shadow vault assaulter"] = { 2, "', "Shadow Vault Assaulters are vrykul death knights attacking the Shadow Vault in Icecrown." },
  ["shadow-captain lakheesh"] = { 2, "ethereal", "Shadow-Captain Lakheesh is an ethereal who ledresides in the Serrated Peaks in K'aresh." },
  ["shadow-sage brakoss"] = { 2, "arakkoa found in the Town Hall in Stormshield", "Shadow-Sage Brakoss is an arakkoa found in the Town Hall in Stormshield." },
  ["shadow-sage iskar"] = { 2, "arakkoa formerly cursed by Sethe to be broken", "Shadow-Sage Iskar is an arakkoa formerly cursed by Sethe to be broken and flightless. He led his fellow Arakkoa Outcasts in the battle against Rukhmar and her Adherents." },
  ["shadow-touched krokul"] = { 2, "', "Shadow-Touched Krokuls are Broken located at the Ruins of Oronaar in Eredath." },
  ["shadowbinder athissa"] = { 2, "naga located at Zin-Azshari in Nazjatar", "Shadowbinder Athissa is a naga located at Zin-Azshari in Nazjatar." },
  ["shadowcaster voruun"] = { 2, "Broken located in the Ruins of Oronaar in Eredath", "Shadowcaster Voruun is a Broken located in the Ruins of Oronaar in Eredath." },
  ["shadowfang bloodhowler"] = { 2, "worgen", "Shadowfang Bloodhowler is a worgen." },
  ["shadowfang darksoul"] = { 2, "', "Shadowfang Darksoul are worgen found in Shadowfang Keep." },
  ["shadowfang glutton"] = { 2, "', "Shadowfang Glutton were worgen you will first encounter in Shadowfang Keep." },
  ["shadowfang keep guard"] = { 2, "', "Shadowfang Keep Guards are Forsaken located at Shadowfang Keep and Pyrewood Village in Silverpine Forest." },
  ["shadowfang moonwalker"] = { 2, "', "Shadowfang Moonwalkers were worgen encountered in Shadowfang Keep." },
  ["shadowfang ragetooth"] = { 2, "', "Shadowfang Ragetooth were worgen encountered in Shadowfang Keep." },
  ["shadowfang whitescalp"] = { 2, "', "Shadowfang Whitescalps were worgen encountered in Shadowfang Keep." },
  ["shadowfang wolfguard"] = { 2, "', "Shadowfang Wolfguard were worgen located in Shadowfang Keep. They summoned Wolfguard Worgs to aid them." },
