  ["shadowguard darkweaver"] = { 2, "', "Shadowguard Darkweavers are ethereals attacking Tazavesh in K'aresh." },
  ["shadowguard duskwalker"] = { 2, "', "Shadowguard Duskwalkers are ethereals attacking Tazavesh in K'aresh." },
  ["shadowguard forgecaster"] = { 2, "', "Shadowguard Forgecasters are ethereals located in Shadow Point: Darkmend in K'aresh." },
  ["shadowguard infiltrator"] = { 2, "Veiled Market during  [80] The Darkness Among Us", "Shadowguard Infiltrators are ethereals attacking Alleria Windrunner and Locus-Walker in the P.O.S.T. in Tazavesh, the Veiled Market during  [80] The Darkness Among Us." },
  ["shadowguard lookout"] = { 2, "', "Shadowguard Lookouts are ethereals located in Shadow Point and Tempest Tract in K'aresh." },
