  ["shadowguard waywatch"] = { 2, "Ethereum Overcroft", "Shadowguard Waywatches are ethereals located in the Voidstorm. They fly crafts back and forth between Shadowguard Point, the Ethereum Overcroft, and the Ethereum Refinery." },
