  ["shadowlord al'zar"] = { 2, "ethereal", "Shadowlord Al'zar is an ethereal who led the Shadowguard's assault on Tazavesh." },
  ["shadowmaster aameen"] = { 2, "human located in Bizmo's Brawlpub in Deeprun Tram", "Shadowmaster Aameen is a human located in Bizmo's Brawlpub in Deeprun Tram and in Brawl'gar Arena. He is the third encounter of rank 3." },
  ["shadowmaster sydow"] = { 2, "mogu located at Mistfall Village of Vale of Eternal Blossoms", "Shadowmaster Sydow is a mogu located at Mistfall Village of Vale of Eternal Blossoms." },
  ["shadowrider neralva"] = { 2, "venthyr stable master located in Darkhaven in Revendreth", "Shadowrider Neralva is a venthyr stable master located in Darkhaven in Revendreth." },
  ["shadowspinner azarak"] = { 2, "nerubian located with Shipwright Isaebela in the Silkwood...", "Shadowspinner Azarak is a nerubian located with Shipwright Isaebela in the Silkwood Grotto on the Isle of Dorn. In Nightshade Hideout, he caught Lamplighter Kaerter and his adventuring companion in webs before leaving the cave with Isabella." },
  ["shadowstalker ezrekius"] = { 2, "Nightmare-corrupted satyr located in Val'sharah", "Shadowstalker Ezrekius was a Nightmare-corrupted satyr located in Val'sharah. He was taken out by the champions of the class orders." },
  ["shadowsworn adept"] = { 2, "', "Shadowsworn Adepts are human and undead members of the Shadowsworn found in the Blasted Lands." },
  ["shadowsworn dreadweaver"] = { 2, "', "Shadowsworn Dreadweavers are orc and undead members of the Shadowsworn found at the Altar of Storms in the Blasted Lands." },
  ["shadowsworn occultist"] = { 2, "', "Shadowsworn Occultists are undead and humans located in the Blasted Lands." },
  ["shadowsworn warlock"] = { 2, "', "Shadowsworn Warlocks are human and undead warlocks of found at the Altar of Storms in the Blasted Lands." },
  ["shadowtide bulwark"] = { 2, "', "Shadowtide Bulwarks are Arathi located in the Bleak Shore in Hallowfall." },
  ["shadowtide disciple"] = { 2, "', "Shadowtide Disciples are Arathi located in the Bleak Shore in Hallowfall." },
  ["shadowy advisor"] = { 2, "', "The Shadowy Advisor is one of the three Shadow Council members at the Grangol'var Village in Terokkar Forest who need to be questioned for  [15-30] Who Are They?. They are found talking with Shadowmaster Grieve inside the barracks about how to hid..." },
  ["shadrek"] = { 2, "ethereal quest giver located at Aeris Landing in Nagrand", "Shadrek is an ethereal quest giver located at Aeris Landing in Nagrand. He is a merchant who is interested in the ivory from the tusks of the native elekk, and will continue to accept ivory until a player reaches Friendly reputation with the Conso..." },
  ["shady dealer"] = { 2, "Veiled Market", "Shady Dealers are brokers located in Tazavesh, the Veiled Market." },
  ["shady smuggler"] = { 2, "Veiled Market in K'aresh", "Shady Smugglers are brokers located in Tazavesh, the Veiled Market in K'aresh. After approaching them and the Illicit Importer, they promptly teleport away." },
  ["shady solicitor"] = { 2, "broker located near Au'manal in Myza's Oasis in Tazavesh", "The Shady Solicitor is a broker located near Au'manal in Myza's Oasis in Tazavesh, the Veiled Market." },
  ["shagra"] = { 2, "worgen", "Shagra was a worgen who, alongside Gorfang, attacked Revil Kost, Karlain and Ambrose at the entrance of Roland's Doom. Ambrose killed the two worgen very quickly." },
  ["shagtusk"] = { 2, "quilboar", "Shagtusk is a quilboar who betrayed the Razorfen tribe and now resides in Freewind Post alongside other quilboars and tauren. At some point in the past, Shagtusk traveled to Dire Maul where King Gordok paid Chugara to build him a dome of thorns." },
  ["shaka (tortollan)"] = { 2, "tortollan located in Bait & Baited in the Sliver in Dazar...", "Shaka is a tortollan located in Bait & Baited in the Sliver in Dazar'alor who sells fishing supplies and is able to repair gear and weapons." },
  ["shaka (tuskarr)"] = { 2, "tuskarr located in the Waking Shores", "Shaka is a tuskarr located in the Waking Shores." },
  ["shaka beaststalker"] = { 2, "orc located in Frostfire Ridge", "Shaka Beaststalker is an orc located in Frostfire Ridge." },
  ["shaken arathi"] = { 2, "Arathi located in Fjord Tavern in Hallowfall", "Shaken Arathi is an Arathi located in Fjord Tavern in Hallowfall." },
  ["shala"] = { 2, "tuskarr located in Khuri's Fishing Spot in the Azure Span", "Shala is a tuskarr located in Khuri's Fishing Spot in the Azure Span. She sends adventurers to kill Gorger and collect his horns in order to make supplies for expanding the outpost." },
  ["shalassi oracle"] = { 2, "', "Shalassi Oracles are arakkoa found at Veil Shalas in Terokkar Forest." },
  ["shalassi sentry"] = { 2, "', "Shalassi Sentries could be found in Veil Shalas, Terokkar Forest." },
  ["shalassi talonguard"] = { 2, "', "Shalassi Talonguards are arakkoa found at Veil Shalas in Terokkar Forest." },
  ["shalba"] = { 2, "nerubian found in the Scents & Oils in the City of Threads", "Shalba is a nerubian found in the Scents & Oils in the City of Threads." },
  ["shale drilldeep"] = { 2, "earthen reagents", "Shale Drilldeep is an earthen reagents and poison vendor in Deepholm." },
  ["shalkeel"] = { 2, "centaur", "Shalkeel is a centaur who is in the Ohn'ahran Plains until he is killed by Fyrakk, leaving behind only ash." },
  ["shalo"] = { 2, "tortollan located in Little Tortolla in Dazar'alor", "Shalo is a tortollan located in Little Tortolla in Dazar'alor." },
  ["shan bu"] = { 2, "leader of the Shan'ze clan of Mogu", "Shan Bu was the leader of the Shan'ze clan of Mogu. Master of brutal lightning magic and powerful cloud serpents, Shan Bu's power matched even that of Niuzao." },
  ["shan jitong"] = { 2, "leader of the mogu spiritclaws at the Terrace of Ten Thun...", "Shan Jitong is the leader of the mogu spiritclaws at the Terrace of Ten Thunders who attempt to summon spirits to embody the ancient mogu statues of the site. Their rituals were stopped by the spirit of Pei-Zhi and adventurers." },
  ["shan kien"] = { 2, "very old mogu", "Shan Kien is a very old mogu that has been around since the Divine Bell was hidden away. He is also the sole person to know of its hidden location." },
  ["shan'ze animator"] = { 2, "', "Shan'ze Animators are mogu located in Diremoor on the Isle of Thunder. They are seen animating Animated Warriors." },
  ["shan'ze battlemaster"] = { 2, "', "Shan'ze Battlemasters are mogu located on the Isle of Thunder appearing during  [32-35] The Fall of Shan Bu." },
  ["shan'ze beastmaster"] = { 2, "', "Shan'ze Beastmasters are mogu beastmasters of the Shan'ze clan, found in Shan'ze Dao. They each lead a pack of 5 Bronze Quilen and can summon Quilen Stonemaws." },
  ["shan'ze bloodseeker"] = { 2, "', "Shan'ze Bloodseekers are mogu located in Diremoor on the Isle of Thunder." },
  ["shan'ze brutalizer"] = { 2, "', "There are two types of Shan'ze Brutalizers. One set is at Niuzao Temple during the Shado-Pan capstone quest  [25-35] Surprise Attack!" },
  ["shan'ze celestial shaper"] = { 2, "', "Shan'ze Celestial Shapers, also known as the Hands of Shan Bu, are four mobs in the Throne of Thunder. Similar to how Shan Bu attempted to bend Niuzao to his will, these Mogu sorcerers appear to be attempting to shape the power of the August Celes..." },
  ["shan'ze deathspeaker"] = { 2, "mogu necromancer located on the isle of Shan'ze Dao in To...", "Shan'ze Deathspeaker is a mogu necromancer located on the isle of Shan'ze Dao in Townlong Steppes." },
  ["shan'ze electrocutioner"] = { 2, "mogu located on the Isle of Thunder", "Shan'ze Electrocutioner is a mogu located on the Isle of Thunder." },
  ["shan'ze gravekeeper"] = { 2, "', "Shan'ze Gravekeepers are mogu of the Shan'ze clan located in the Court of Bones on the Isle of Thunder. Grand Magister Rommath of the Horde and Narasi Snowdawn of the Alliance want them eliminated in order for their respective factions to gain foo..." },
  ["shan'ze illusionist"] = { 2, "', "Shan'ze Illusionists are mogu found at Shan'ze Dao in Townlong Steppes." },
  ["shan'ze infiltrator"] = { 2, "', "Shan'ze Infiltrators are mogu located at the Underbough in the Townlong Steppes." },
  ["shan'ze invader"] = { 2, "', "Shan'ze Invaders are mogu found storming the bridge between the Shado-Pan Garrison and Niuzao Temple in the Townlong Steppes with air support from Shan'ze Cloudriders." },
  ["shan'ze obliterator"] = { 2, "', "Shan'ze Obliterators are mogu located in a camp by the northern tip of the Serpent's Spine in Townlong Steppes." },
  ["shan'ze pyromancer"] = { 2, "', "Shan'ze Pyromancer are mogu located on the Isle of Thunder." },
  ["shan'ze serpentbinder"] = { 2, "', "Shan'ze Serpentbinders are mogu located at Shan'ze Dao in the Townlong Steppes. They are seen corrupting Wild Cloudrunners into Shan'ze Cloudrunners." },
  ["shan'ze shadowcaster"] = { 2, "', "Shan'ze Shadowcasters are mogu on the Isle of Thunder." },
  ["shan'ze slaver"] = { 2, "', "Shan'ze Slavers are mogu located in the Lightning Vein Mine on the Isle of Thunder. They are accompanied by Saurok Slaves." },
  ["shan'ze soulripper"] = { 2, "', "Shan'ze Soulrippers are mogu located at the Court of Bones on the Isle of Thunder." },
  ["shan'ze spiritbinder"] = { 2, "', "Shan'ze Spiritbinders are mogu located in the Terrace of Ten Thunders in the Jade Forest. They summon Shan'ze Spirit Apparitions." },
  ["shan'ze spiritclaw"] = { 2, "mogu are killed in an explosion", "Shan'ze Spiritclaws are mogu found at the Terrace of Ten Thunders in the Jade Forest. During  [10-35] To Bridge Earth and Sky, they attack Pei-Zhi but are killed once his spell with The Tan-Chao is completed, the mogu are killed in an explosion." },
  ["shan'ze spymaster"] = { 2, "mogu located in Townlong Steppes", "Shan'ze Spymaster is a mogu located in Townlong Steppes." },
  ["shan'ze stonebender"] = { 2, "', "Shan'ze Stonebenders are mogu located in the Underbough in Townlong Steppes." },
  ["shan'ze thundercaller"] = { 2, "', "Shan'ze Thundercallers are mogu located at the Court of Bones on the Isle of Thunder. They are seen raising Risen Ancestors." },
  ["shan'ze warrior"] = { 2, "', "Shan'ze Warriors are mogu located on the Isle of Thunder during  [32-35] The Fall of Shan Bu." },
  ["shane webbeard"] = { 2, "vrykul located in Stormheim", "Shane Webbeard is a vrykul located in Stormheim." },
