  ["shao-tien assassin"] = { 2, "', "Shao-Tien Assassins are mogu who appear at Mogu'shan Palace in the Vale of Eternal Blossoms during  [87] The Shrine of Two Moons and  [87] The Shrine of Seven Stars." },
