  ["shaper korin"] = { 2, "ankoan located in Maedin's Challenge in Nazjatar", "Shaper Korin is an ankoan located in Maedin's Challenge in Nazjatar." },
  ["sharax the defiler"] = { 2, "satyr found in Darkshore", "Sharax the Defiler is a satyr found in Darkshore. He managed to corrupt the Blackwood furbolgs and to set up Jadefire Braziers." },
  ["shardgar"] = { 2, "earthen located in Freywold Village on the Isle of Dorn", "Shardgar is an earthen located in Freywold Village on the Isle of Dorn." },
  ["shardmaster azurrogg"] = { 2, "drogbar located inside the Crystal Fissure in Highmountain", "Shardmaster Azurrogg is a drogbar located inside the Crystal Fissure in Highmountain. He summons Rogg Shards." },
  ["shardmaster ufrogg"] = { 2, "drogbar located at the Crystal Fissure entrance in Highmo...", "Shardmaster Ufrogg is a drogbar located at the Crystal Fissure entrance in Highmountain." },
  ["sharfadi, bulwark of the night"] = { 2, "ethereal", "Sharfadi, Bulwark of the Night was an ethereal who spawns during the final stage of a Twilight's Call at the Ruins of Drakgor in the Twilight Highlands." },
  ["sharon boomgetter"] = { 2, "goblin", "Sharon Boomgetter is a goblin who operates the Bogpaddle Bullet, which runs from the Burning Steppes to the Swamp of Sorrows." },
  ["sharpfang"] = { 2, "gnoll located in the Azure Span", "Sharpfang is a gnoll located in the Azure Span." },
  ["sharptalon outcast"] = { 2, "', "Sharptalon Outcasts are arakkoa found in the Dark Woods in Ashran." },
  ["shawna baskett"] = { 2, "Worgen found aboard the boat The Dimension north of Templ...", "Shawna Baskett is a Worgen found aboard the boat The Dimension north of Temple of Karabor in Shadowmoon Valley." },
  ["shek'zeer bladesworn"] = { 2, "', "Shek'zeer Bladesworn are mantid warriors of the Shek'zeer found at the Clutches of Shek'zeer in the Dread Wastes. They are sometimes seen patrolling on amber scorpids." },
  ["shek'zeer clutch-keeper"] = { 2, "', "Shek'zeer Clutch-Keepers are mantid located in the Clutches of Shek'zeer in the Dread Wastes." },
  ["shek'zeer manipulator"] = { 2, "', "Shek'zeer Manipulators are mantid located in the Dread Wastes." },
  ["shek'zeer needler"] = { 2, "', "Shek'zeer Needlers are mantid located in the Dread Wastes." },
  ["shek'zeer swarmborn"] = { 2, "', "Shek'zeer Swarmborn are the newly hatched of the mantid empire, found at the Clutches of Shek'zeer in the Dread Wastes, being tended to by the Shek'zeer Clutch-Keepers. Normally, they would begin devouring each other when born until only the stron..." },
  ["shek'zeer wingblade"] = { 2, "', "Shek'zeer Wingblades are mantid located in the Dread Wastes." },
  ["shellraiser mort"] = { 2, "tortollan located at Venturewood in the Undermine", "Shellraiser Mort is a tortollan located at Venturewood in the Undermine." },
  ["shelly (murloc)"] = { 2, "murloc located at the Winterfin Retreat in the Borean Tundra", "Shelly is a murloc located at the Winterfin Retreat in the Borean Tundra." },
  ["shepherd ekhna"] = { 2, "centaur located in the Mallakh in the Ohn'ahran Plains", "Shepherd Ekhna is a centaur located in the Mallakh in the Ohn'ahran Plains." },
  ["shepherd tevatei"] = { 2, "centaur located in the Mallakh in the Ohn'ahran Plains", "Shepherd Tevatei is a centaur located in the Mallakh in the Ohn'ahran Plains." },
  ["sherik"] = { 2, "centaur located at the Gelkis Village in Desolace", "Sherik is a centaur located at the Gelkis Village in Desolace." },
  ["shieldbearer anak"] = { 2, "tauren located in Tomb of Tyr in Tirisfal Glades", "Shieldbearer Anak is a tauren located in Tomb of Tyr in Tirisfal Glades. He assists the adventurer during   [10-45] The Silver Hand alongside Helda the Breaker, Lyanae, and Kelissa Stilwell against Mordoth the Hunter's minions." },
  ["shieldbreaker murdonn"] = { 2, "fel-crazed vrykul", "Shieldbreaker Murdonn was a fel-crazed vrykul who broke through the outer defenses of Dalaran, and made it all the way to Krasus' Landing. He was accompanied by a felbat named Fangs." },
  ["shieldmaiden (npc)"] = { 2, "', "Shieldmaidens are vrykul located in Skyhold." },
  ["shieldmaiden warband"] = { 2, "', "Shieldmaiden Warbands are vrykul located in Skyhold." },
  ["shieldmaster daeun"] = { 2, "draenei located at the Lunarfall in Shadowmoon Valley", "Shieldmaster Daeun is a draenei located at the Lunarfall in Shadowmoon Valley. He can only be recruited using the Headhunter's Harvest from Lunarfall Inn." },
  ["shieldwall defender"] = { 2, "', "Shieldwall Defenders are located at Lion's Landing in Krasarang Wilds." },
  ["shieldwall mender"] = { 2, "', "Shieldwall Menders are draenei, humans, dwarves, and worgen planned to appear in Krasarang Wilds." },
  ["shienor sorcerer"] = { 2, "', "Shienor Sorcerers are arakkoa found at Veil Reskk and Veil Shienor in Terokkar Forest." },
  ["shienor talonite"] = { 2, "', "Shienor Talonites are arakkoa found at Veil Reskk and Veil Shienor in Terokkar Forest." },
  ["shienor wing guard"] = { 2, "', "Shienor Wing Guards are arakkoa found at Veil Reskk and Veil Shienor in Terokkar Forest." },
  ["shikaar beastmaster"] = { 2, "', "Shikaar Beastmasters are centaur located in the Ohn'ahran Plains." },
  ["shikaar blacksmith"] = { 2, "', "Shikaar Blacksmiths are centaur located at Great Hunt camps on the Dragon Isles." },
  ["shikaar hunter"] = { 2, "', "Shikaar Hunters are centaur located in the Ohn'ahran Plains. They also participate in the Grand Hunts across the other regions of the Dragon Isles." },
  ["shikaar hunter (emerald dream)"] = { 2, "', "Shikaar Hunters are centaur located in the Field of Flames in the Emerald Dream during  [10-80] The Age of Mortals." },
  ["shikaar plains guide"] = { 2, "', "Shikaar Plains Guides are centaur located at Shoreline Roots in Amirdrassil." },
  ["shikaar preyseeker"] = { 2, "', "Shikaar Preyseekers are centaur located in the Ohn'ahran Plains." },
  ["shikaar ranger"] = { 2, "', "Shikaar Rangers are centaur located in the Ohn'ahran Plains and inside the Nokhud Offensive." },
  ["shikaar scout"] = { 2, "', "Shikaar Scouts are centaur located in the Ohn'ahran Plains and the Azure Span." },
  ["shikaar sentinel"] = { 2, "', "Shikaar Sentinels are centaur located at Broadhoof Outpost in the Ohn'ahran Plains." },
  ["shimmerspine harvester"] = { 2, "', "Shimmerspine Harvesters are murlocs located in Kelp'thar Forest." },
  ["shinda creedpike"] = { 2, "Arathi located in Church of the Sacred Flame in Hallowfall", "Shinda Creedpike is an Arathi located in Church of the Sacred Flame in Hallowfall. He used to fish with his mother at the local pond when he was a child." },
  ["shipping facilitator"] = { 2, "Veiled Market", "Shipping Facilitators are brokers located at Tazavesh, the Veiled Market." },
  ["shipwrecked captive"] = { 2, "', "Shipwrecked Captives are captured gnolls, vrykul, humans, goblins, and Zandalari trolls located in Azsuna." },
  ["shipwrecked captive (pet tamer)"] = { 2, "gnoll ghost located in Azsuna", "Shipwrecked Captive is a gnoll ghost located in Azsuna. He is summonable by  [Sternfathom's Pet Journal]." },
  ["shipwrecked sailor"] = { 2, "', "Shipwrecked Sailors are undead located at the Cape of Lost Hope on the Tol Barad Peninsula." },
  ["shipwright bodyguard"] = { 2, "', "Shipwright Bodyguards are a pair of Arathi located in Nightshade Holdout on the Isle of Dorn. They are the guards of Shipwright Isaebela." },
  ["shipwright isaebela"] = { 2, "Arathi located with Shadowspinner Azarak in the Silkwood ...", "Shipwright Isaebela is an Arathi located with Shadowspinner Azarak in the Silkwood Grotto on the Isle of Dorn. Among her people, she was known as a technical genius and one of the best shipwrights in Hallowfall." },
  ["shirakess apprentice"] = { 2, "', "Shirakess Apprentices are naga located in Nazjatar." },
  ["shirakess enthraller"] = { 2, "', "Shirakess Enthrallers are naga located in Nazjatar." },
  ["shirakess overseer"] = { 2, "', "Shirakess Overseers are naga located in Nazjatar." },
  ["shirakess shadowcaster"] = { 2, "naga located in the Eternal Palace", "Shirakess Shadowcaster is a naga located in the Eternal Palace." },
  ["shirakess speaker"] = { 2, "', "Shirakess Speakers are naga located in Nazjatar." },
  ["shirakess starseeker"] = { 2, "', "Shirakess Starseekers are naga located in Nazjatar." },
  ["shirakess subjugator"] = { 2, "', "Shirakess Subjugators are naga located in Nazjatar." },
  ["shirakess tidemistress"] = { 2, "naga", "Shirakess Tidemistress is a naga." },
  ["shirakess voidreaper"] = { 2, "', "Shirakess Voidreapers are naga located in the Eternal Palace." },
  ["shirakess voidreaver"] = { 2, "', "Shirakess Voidreavers are naga located in Nazjatar." },
  ["shirakess voidtwister"] = { 2, "', "Shirakess Voidtwisters are naga located in the Deepcoil Tunnels in Nazjatar. They can be found working on the Naga Void Experiments." },
  ["shirtsi clothpatch"] = { 2, "goblin located in Everlook in Winterspring", "Shirtsi Clothpatch is a goblin located in Everlook in Winterspring. She provides the  [Shirtsi's Cloth Shirt] for free." },
  ["shiv fizzlescheme"] = { 2, "gnome located at the Obsidian Bulwark & Obsidian Citadel ...", "Shiv Fizzlescheme is a gnome located at the Obsidian Bulwark & Obsidian Citadel in the Waking Shores. He is one of the seven gnomes following Becca Black." },
  ["shiverspine"] = { 2, "', "Template:Tomb of the Forgotten TCG" },
  ["shlur"] = { 2, "female murloc", "Shlur is a female murloc and the senior shaman of the White Shark tribe. She is an old and crafty ruler and can silence even the proudest tiderunner with a single flick of her head-fin." },
  ["shoak"] = { 2, "tortollan located at Gloom Hollow in Nazmir", "Shoak is a tortollan located at Gloom Hollow in Nazmir." },
  ["shoalbreach lance"] = { 2, "', "Shoalbreach Lances are naga-operated ballistae located at Fort Daelin in Stormsong Valley." },
  ["shoalfin elder"] = { 2, "', "Shoalfin Elders are murlocs located at the Timeworn Strand in Azsuna." },
  ["shoalfin slave"] = { 2, "', "Shoalfin Slaves are murlocs located in Timeworn Strand in Azsuna." },
  ["shoalfin tadpole"] = { 2, "', "Shoalfin Tadpoles are murlocs located in Azsuna." },
  ["shoalfin warrior"] = { 2, "', "Shoalfin Warriors are murlocs located in Timeworn Strand in Azsuna. They are equipped with a spear and shield on their back, and also wield a hatchet and another shield in their hands." },
  ["shogo"] = { 2, "tortollan worshipper of Torga located in the Hall of the ...", "Shogo is a tortollan worshipper of Torga located in the Hall of the Lesser Loa in Dazar'alor. During Talanji's coronation when riots erupted in the Terrace of the Chosen, he was seen in a defensive stance in a corner of the hall." },
  ["shomko"] = { 2, "great tuskarr explorer", "Shomko was a great tuskarr explorer who led expeditions to the furthest shores of Northrend, and he founded the village of Pal'ea in western Borean Tundra. He defended his people in many battles and was a skilled fighter." },
  ["shopkeeper"] = { 2, "broker located just past Tazavesh Customs Enforcement in ...", "The Shopkeeper is a broker located just past Tazavesh Customs Enforcement in Tazavesh, the Veiled Market." },
  ["shoreline tidespeaker"] = { 2, "', "Shoreline Tidespeakers are murlocs located in the Opera Hall in the Return to Karazhan as a part of the Opera Hall: Westfall Story encounter." },
  ["shox'tik"] = { 2, "mantid located outside the Heart of Fear in the Dread Wastes", "Shox'tik is a mantid located outside the Heart of Fear in the Dread Wastes." },
  ["shred (worgen)"] = { 2, "worgen located at The Hall of Shadows in Dalaran", "Shred  is a worgen located at The Hall of Shadows in Dalaran. He and Tear seem to guard Madam Gosu." },
  ["shredmaster blix"] = { 2, "goblin operaing a shredder located at Lor'danel Landing i...", "Shredmaster Blix is a goblin operaing a shredder located at Lor'danel Landing in Darkshore just before the Battle for Darkshore. During the battle, he is found in Cinderfall Grove for both factions." },
  ["shrinekeeper qanosh"] = { 2, "djaradin priest located in Zaqali Caldera in Zaralek Cavern", "Shrinekeeper Qanosh is a djaradin priest located in Zaqali Caldera in Zaralek Cavern. He is guarding the area with Earthrender Ku'siva, but is attacked by Sabellian, Ebyssian, and an adventurer." },
  ["shrouded arcanist"] = { 2, "', "Shrouded Arcanists are venthyr located in Revendreth." },
