  ["shu blindeye"] = { 2, "pandaren emperor of the Pandaren Empire", "Shu Blindeye was a pandaren emperor of the Pandaren Empire. The  [Pearl of Yu'lon] was carved during his reign in honor of the Jade Serpent." },
  ["shua amberplain"] = { 2, "tauren", "Shua Amberplain is a tauren." },
  ["shuga blastcaps"] = { 2, "goblin located in Searat's Volitile Valuables at the Terr...", "Shuga Blastcaps is a goblin located in Searat's Volitile Valuables at the Terrace of Crafters in Dazar'alor. She and Quizla grew up in Kezan." },
  ["shurom"] = { 2, "centaur leatherworking trainer located at Timberstep Outp...", "Shurom is a centaur leatherworking trainer located at Timberstep Outpost in the Ohn'ahran Plains." },
