  ["shy ino"] = { 2, "tuskarr located at Apex Canopy in the Waking Shores", "Shy Ino is a tuskarr located at Apex Canopy in the Waking Shores. He and Curious Lilu are found listening to the stories of Fisherman Pasqaa." },
  ["si'vash"] = { 2, "naga in Broken Shore", "Si'vash is a naga in Broken Shore. She is one of four Broken Shore world bosses that have a chance to become available to players while the Nether Disruptor building is active." },
  ["si'vashi honor guard"] = { 2, "', "Si'vashi Honor Guards are naga located Strand's End on the Broken Shore. They accompany Si'vash." },
  ["siaszerathel"] = { 2, "dracthyr located in the Caldera of the Menders in the For...", "Siaszerathel is a dracthyr located in the Caldera of the Menders in the Forbidden Reach, tending to a Soar Enhancer. She later appears in Thaldraszus as a member of the Timewalkers." },
  ["siben"] = { 2, "vulpera located at Artisan's Market in Valdrakken", "Siben is a vulpera located at Artisan's Market in Valdrakken. He provides the option to reset Dragon Isles Profession specialization." },
