  ["sickly tadpole"] = { 2, "', "Sickly Tadpoles are murlocs hatched from Incubated Eggs in the Tomb of Sargeras." },
  ["siegebrul olgrul"] = { 2, "master of worms for the Mightstone drogbar attacking Snow...", "Siegebrul Olgrul is the master of worms for the Mightstone drogbar attacking Snowblind Mesa in Highmountain. Navarrogg describes him as a sadistic brute who torments all who serve him, saying that 'There are evil drogbar, and there is this foul mo..." },
  ["siegecrafter blackfuse"] = { 2, "twelfth boss of Siege of Orgrimmar", "Siegecrafter Helix Blackfuse is the twelfth boss of Siege of Orgrimmar. In addition to his custom shredder, Blackfuse utilizes the weapons that come from the conveyor belts on the sides of the room to produce bombs, lasers, and other weapons to us..." },
  ["siegehold fortifier"] = { 2, "', "Siegehold Fortifiers are nerubians located at Siegehold in Azj-Kahet." },
  ["siegehold spinstitch"] = { 2, "', "Siegehold Spinstitches are nerubians located at Siegehold in Azj-Kahet." },
  ["siennagosa"] = { 2, "dracthyr located at Algeth'ar Academy in Thaldraszus", "Siennagosa is a dracthyr located at Algeth'ar Academy in Thaldraszus. Only scribes with 25 points in Dragon Isles inscription may interact with her to obtain the  [Counterfeit Darkmoon Deck]." },
  ["siflaed coldhammer"] = { 2, "dwarf engineering vendor located at the Refugee Caravan i...", "Ruogo is a dwarf engineering vendor located at the Refugee Caravan in Terokkar Forest." },
  ["sigryn"] = { 2, "God-Queen of the Tideskorn vrykul", "Sigryn is the God-Queen of the Tideskorn vrykul. She is the daughter of late God-King Skovald and the sister of Torvald." },
  ["sigurd the giantslayer"] = { 2, "vrykul warrior", "Sigurd the Giantslayer is a vrykul warrior and champion of his clan. He arrived at the Temple of the White Tiger in the Kun-Lai Summit during third invasion of the Burning Legion seeking  [The Fist of Ra-den] on behalf of his clan." },
  ["sik'thik amber-sapper"] = { 2, "mantid", "Sik'thik Amber-Sapper is a mantid. It was to carry an explosive." },
