  ["silvermoon resident"] = { 2, "', "Silvermoon Residents are located throughout Silvermoon City." },
  ["silvia"] = { 2, "worgen located in the Tower of Estulan in Feralas", "Silvia is a worgen located in the Tower of Estulan in Feralas. During the Cataclysm, she became a member of the Sentinels and Shandris personally taught her how to coordinate an attack." },
