  ["sinfall defender"] = { 2, "Ember Court", "Sinfall Defenders are venthyr located in multiple locations, including Revendreth, the Ember Court, Sanguine Depths, and later briefly in Ardenweald during  [60] The Battle of Ardenweald. They wield a variety of weapons, such as rapiers, daggers, ..." },
  ["sinfall greeter"] = { 2, "', "Sinfall Greeters are venthyr located in the Ember Court and in Sinfall in Revendreth." },
