  ["sinfall rebel"] = { 2, "', "Sinfall Rebels are venthyr located in Revendreth." },
  ["sinfall recruit"] = { 2, "', "Sinfall Recruits are venthyr located in Revendreth, Sinfall, and the Ember Court. Two can be seen holding a Portal to Oribos in Sinfall." },
  ["sinfall reveler"] = { 2, "', "Sinfall Revelers are venthyr who appear in Sinfall during the Feast of Winter Veil. They are waltzing with each other in midair in the open space of the tower." },
