  ["sinfall socialite"] = { 2, "', "Sinfall Socialites are venthyr located in Sinfall in Revendreth." },
  ["sinfall tutor"] = { 2, "', "Sinfall Tutors are venthyr located in Sinfall and the Maw." },
  ["sinfall volunteer"] = { 2, "', "Sinfall Volunteers are venthyr located in Sinfall in Revendreth." },
  ["sinister antiquarian"] = { 2, "', "Sinister Antiquarians are venthyr located in the Spoils of Sin in Castle Nathria." },
  ["sinkeeper mateo"] = { 2, "venthyr located in Revendreth", "Sinkeeper Mateo is a venthyr located in Revendreth." },
  ["sinkeeper mourana"] = { 2, "venthyr located at the Crypt of the Forgotten in Revendreth", "Sinkeeper Mourana is a venthyr located at the Crypt of the Forgotten in Revendreth. After Sinkeeper Mateo sided with Denathrius and was subsequently killed by the Maw Walker, the Curator appointed Mourana as Mateo's replacement." },
  ["sinreader nicola"] = { 2, "venthyr located in the Grove of Terror in Revendreth", "Sinreader Nicola is a venthyr located in the Grove of Terror in Revendreth." },
  ["sinruna"] = { 2, "earthen located west of Taelloch in the Ringing Deeps", "Sinruna is an earthen located west of Taelloch in the Ringing Deeps. She is found next to the Badly Behaved Bot." },
  ["siouxsie the banshee"] = { 2, "Darkfallen death knight found in Acherus: The Ebon Hold", "Siouxsie the Banshee is a Darkfallen death knight found in Acherus: The Ebon Hold." },
  ["sir alastair purefire"] = { 2, "Arathi located outside of the Priory of the Sacred Flame ...", "Sir Alastair Purefire is an Arathi located outside of the Priory of the Sacred Flame in Hallowfall." },
  ["sir andru"] = { 2, "venthyr located in the Primrose Residence in Revendreth", "Sir Andru is a venthyr located in the Primrose Residence in Revendreth." },
  ["sir ashrealm"] = { 2, "Arathi located at Arathi's End in Azj-Kahet", "Sir Ashrealm is an Arathi located at Arathi's End in Azj-Kahet. After being questioned by Faerin Lothar and Gazlowe about Ryton Blackholme, he succumbed to his wounds." },
  ["sir barton brigham"] = { 2, "worgen located in Island Expeditions", "Sir Barton Brigham is a worgen located in Island Expeditions. Despite being part of the Island pack, he seems to be fully in control of himself." },
  ["sir finley mrrgglton"] = { 2, "sophisticated murloc adventurer", "Sir Finley Mrrgglton is a sophisticated murloc adventurer and member of the Explorers' League." },
  ["sir finley mrrgglton (azmerloth)"] = { 2, "murloc located in Azmerloth", "Sir Finley Mrrgglton is a murloc located in Azmerloth." },
  ["sir finley mrrgglton (delves)"] = { 2, "murloc", "Sir Finley Mrrgglton is a murloc who has a chance to appear in Delves with Reno Jackson as a Strange Disturbance. The pair duels with Brann Bronzebeard and his companion." },
  ["sir geofri"] = { 2, "venthyr located in Revendreth", "Sir Geofri is a venthyr located in Revendreth." },
