  ["sir luca"] = { 2, "venthyr located in the Redelav District in Revendreth", "Sir Luca is a venthyr located in the Redelav District in Revendreth. He can be found talking with Duchess Ileana." },
  ["sir marius"] = { 2, "venthyr located in the Redelav Hall in Revendreth", "Sir Marius is a venthyr located in the Redelav Hall in Revendreth." },
  ["sir maximus adams"] = { 2, "Arathi Basin battlemaster located at Refuge Pointe in the...", "Sir Maximus Adams is a Arathi Basin battlemaster located at Refuge Pointe in the Arathi Highlands. He was removed in patch 3.0.2 and replaced with Radulf Leder." },
  ["sir murkeston"] = { 2, "murloc located in the Dalaran Pet Tournament in Dalaran", "Sir Murkeston is a murloc located in the Dalaran Pet Tournament in Dalaran." },
  ["sir nandru"] = { 2, "venthyr located behind the Sinfang Parlor in the Redelav ...", "Sir Nandru is a venthyr located behind the Sinfang Parlor in the Redelav District in Revendreth. He can be found absolving an Abject Soul of its past sins, occasionally spawning various memories." },
  ["sir theleon braunpyke"] = { 2, "Arathi located in Morgaen's Tears in Hallowfall", "Sir Theleon Braunpyke is an Arathi located in Morgaen's Tears in Hallowfall. After Aelric Leid's attack on the Veneration Grounds, Theleon and his brother Sybaestan worked to remove the lingering kobyss plaguing the area when they were joined by a..." },
  ["sir toma"] = { 2, "venthyr located in the Eternal Terrace in Revendreth", "Sir Toma is a venthyr located in the Eternal Terrace in Revendreth." },
  ["sir vali"] = { 2, "venthyr located in the Sourwine Estate in Revendreth", "Sir Vali is a venthyr located in the Sourwine Estate in Revendreth." },
  ["sir vilhelm"] = { 2, "venthyr located in the Redelav District in Revendreth", "Sir Vilhelm is a venthyr located in the Redelav District in Revendreth. He can be found talking to Duke Omor outside the Redelav Hall." },
  ["sir viorel"] = { 2, "venthyr located in the Redelav District in Revendreth", "Sir Viorel is a venthyr located in the Redelav District in Revendreth. He can be found, escorted by two Stone Legion Protectors, walking between the Briarbane Stables the and the stairs leading up to the Menagerie of the Master." },
  ["sira moonwarden"] = { 2, "Darkfallen night elf warden", "Sira Moonwarden is a Darkfallen night elf warden. When Maiev Shadowsong went missing during the third invasion of the Burning Legion, she became the interim leader of the Wardens." },
  ["sira'kess guardian"] = { 2, "', "Sira'kess Guardians are naga located in the Abyssal Depths, found protecting Sira'kess Tide Priestess. They also appear in Shimmering Expanse during  [30-35] By Her Lady's Word." },
  ["sira'kess sea witch"] = { 2, "', "Sira'kess Sea Witches are naga found in Abyssal Depths. They can also be found in the Shimmering Expanse as friendly allies during the naga flashback quests." },
  ["sira'kess tide priestess"] = { 2, "', "Sira'kess Tide Priestesses are naga found in the Abyssal Depths." },
  ["sira'kess zealot"] = { 2, "', "Sira'kess Zealots are naga located in Quel'Dormir Temple in Shimmering Expanse." },
  ["siren naz'jul"] = { 2, "naga located in Suramar", "Siren Naz'jul is a naga located in Suramar." },
  ["siren sathraviss"] = { 2, "naga of the Hatecoil", "Siren Sathraviss is a naga of the Hatecoil that was taken out by the class orders." },
  ["sirena the fangbreaker"] = { 2, "centaur located at the Horn of Drusahl in the Ohn'ahran P...", "Sirena the Fangbreaker is a centaur located at the Horn of Drusahl in the Ohn'ahran Plains." },
  ["sirja"] = { 2, "tuskarr located in Camp Nowhere in the Azure Span", "Sirja is a tuskarr located in Camp Nowhere in the Azure Span." },
  ["sissix"] = { 2, "naga located at Aalgen Point in the Broken Shore", "Sissix is a naga located at Aalgen Point in the Broken Shore." },
  ["sissy flamecuffs"] = { 2, "gnome mage part of the Hodir encounter in Ulduar", "Sissy Flamecuffs is a gnome mage part of the Hodir encounter in Ulduar. She, along with her excavation team are trapped inside icicle blocks and must be freed if the raid wants help against Hodir." },
  ["sister absinthe"] = { 2, "human located in Stormsong Valley", "Sister Absinthe is a human located in Stormsong Valley." },
  ["sister adrianna"] = { 2, "human located at Stormsong Monastery in Boralus", "Sister Adrianna is a human located at Stormsong Monastery in Boralus." },
  ["sister ali"] = { 2, "human in Stormwind City", "Sister Ali was a human in Stormwind City who handled teleports to areas being tested during the alpha and beta of Cataclysm." },
  ["sister alison"] = { 2, "human innkeeper", "Sister Alison is a human innkeeper and vendor located in Tidecross in Stormsong Valley." },
  ["sister almyra"] = { 2, "human priest trainer first seen in Gilneas City", "Sister Almyra is a human priest trainer first seen in Gilneas City and later moves with the other Gilnean citizens to Darnassus. She is a member of the clergy in the kingdom." },
  ["sister elsington"] = { 2, "worgen quest giver found at Raven Hill in Duskwood", "Sister Elsington is a worgen quest giver found at Raven Hill in Duskwood." },
  ["sivet"] = { 2, "gnoll of the Woodpaw clan", "Sivet is a gnoll of the Woodpaw clan and the daughter of the current clan's leader, Jaggal. Her father has recently proclaimed himself to decide for the Woodpaw, but he hopes that Sivet will become the new matriarch." },
  ["skalkaz"] = { 2, "earthen located at Pillarstone Spire in the Ringing Deeps", "Skalkaz is an earthen located at Pillarstone Spire in the Ringing Deeps." },
  ["skar'this"] = { 2, "naga", "Skar'this is a naga and a servant of Neptulon appearing in the Slave Pens. He usually appears as Skar'this the Heretic, a friendly naga quest giver." },
  ["skargh the elder"] = { 2, "furbolg", "Skargh the Elder is a furbolg." },
  ["skarukaru"] = { 2, "dracthyr located at the Dranosh'ar Blockade in Durotar", "Skarukaru is a dracthyr located at the Dranosh'ar Blockade in Durotar. She has information on when the Defiant Dragonscale will dock." },
  ["skarvald the constructor"] = { 2, "vrykul boss in the Utgarde Keep", "Skarvald the Constructor is a vrykul boss in the Utgarde Keep. It is likely he is the one building the tunnel to Gjalerbron." },
  ["skavis nightstalker"] = { 2, "worgen located in Island Expeditions", "Skavis Nightstalker is a worgen located in Island Expeditions." },
  ["skedgit cinderbangs"] = { 2, "goblin located in the Wormlands in Azj-Kahet", "Skedgit Cinderbangs is a goblin located in the Wormlands in Azj-Kahet and in Entrepreneur Inc. in the Undermine." },
  ["skeer the bloodseeker"] = { 2, "mantid located at Klaxxi'vess", "Skeer the Bloodseeker is a mantid located at Klaxxi'vess. Skeer is a barbarous warrior who drinks the blood of his enemies, claiming it grants him strength." },
  ["skeld drakeson"] = { 2, "vrykul leader in Ember Clutch in Howling Fjord", "Skeld Drakeson is the vrykul leader in Ember Clutch in Howling Fjord." },
  ["skeletal usher (return to karazhan)"] = { 2, "', "Skeletal Ushers are undead located in Opera Hall in the Return to Karazhan." },
  ["skettis assassin"] = { 2, "', "Skettis Assassins are arakkoa located at Blackwind Landing in Terokkar Forest. They appear upon the completion of  [15-30] World of Shadows with the goal of killing Sky Commander Adaris." },
  ["skettis eviscerator"] = { 2, "', "Skettis Eviscerators were arakkoa once found at Skettis in Terokkar Forest. They were removed in patch 2.1.0 when the Sha'tari Skyguard quests were added." },
  ["skettis outcast"] = { 2, "', "Skettis Outcasts are arakkoa located in the Lower City in Shattrath City." },
  ["skettis outrider"] = { 2, "', "Skettis Outriders are arakkoa." },
  ["skettis refugee"] = { 2, "', "Skettis Refugees are arakkoa found at the Refugee Caravan in southern Terokkar Forest." },
  ["skettis sentinel"] = { 2, "', "Skettis Sentinels were arakkoa once found at Skettis in Terokkar Forest. They were removed in patch 2.1.0 when the Sha'tari Skyguard quests were added." },
  ["skettis soulcaller"] = { 2, "', "Skettis Soulcallers are arakkoa found at Skettis in Terokkar Forest." },
  ["skettis talonite"] = { 2, "', "Skettis Talonites are arakkoa found at Skettis in Terokkar Forest." },
  ["skettis time-shifter"] = { 2, "', "Skettis Time-Shifters were arakkoa once found at Skettis in Terokkar Forest. They were removed in patch 2.1.0 when the Sha'tari Skyguard quests were added." },
  ["skettis windwalker"] = { 2, "', "Skettis Windwalkers are arakkoa found at Skettis in Terokkar Forest." },
  ["skettis wing guard"] = { 2, "', "Skettis Wing Guards are arakkoa found at Skettis in Terokkar Forest." },
  ["ski'thik"] = { 2, "rare mantid found on Kota Peak in Kun-Lai Summit", "Ski'thik is a rare mantid found on Kota Peak in Kun-Lai Summit. Ski'thik is a Pandarian champion." },
  ["skibbles"] = { 2, "kobold child summoned by the  [Khaz Algar Orphan Whistle]...", "Skibbles is a kobold child summoned by the  [Khaz Algar Orphan Whistle] while on  [10-90] Bold for a Kobold, part of the Children's Week questline in Dornogal." },
  ["skin-me-own-coat dibblefur"] = { 2, "vulpera found in a building in Booty Bay in the Cape of S...", "Skin-Me-Own-Coat Dibblefur is a vulpera found in a building in Booty Bay in the Cape of Stranglethorn after the end of the Free T-Shirt Day." },
  ["skinnard"] = { 2, "second mate of Keg Leg's Crew at Brew Bay in Plunderstorm", "Skinnard is the second mate of Keg Leg's Crew at Brew Bay in Plunderstorm." },
  ["skip burnbright"] = { 2, "gnome located at the Lunarfall in Shadowmoon Valley", "Skip Burnbright is a gnome located at the Lunarfall in Shadowmoon Valley. He can only be recruited using the Headhunter's Harvest from Lunarfall Inn." },
  ["skithian dreadhawk"] = { 2, "', "Skithian Dreadhawks are arakkoa found at Veil Skith in Terokkar Forest. They also occasionally spawn from the cocoons at Netherweb Ridge." },
  ["skithian windripper"] = { 2, "', "Skithian Windrippers are arakkoa found at Veil Skith in Terokkar Forest." },
  ["skitter"] = { 2, "kobold located in the Ringing Deeps", "Skitter is a kobold located in the Ringing Deeps. She is the leader of the Quickwick tribe of kobolds." },
  ["skizzik"] = { 2, "outcast arakkoa located in Spires of Arak", "Skizzik is an outcast arakkoa located in Spires of Arak." },
  ["skola greatsword"] = { 2, "vrykul captain of the Tideskorn clan", "Skola Greatsword is a vrykul captain of the Tideskorn clan and hand of Lady Keletress, located at Tian Monastery in the Jade Forest." },
  ["skorthuz"] = { 2, "earthen located in the Ringing Deeps", "Skorthuz is an earthen located in the Ringing Deeps. He has a basilisk pet named Lisky." },
  ["skraa"] = { 2, "arakkoa trade goods vendor located at the Refugee Caravan...", "Skraa is an arakkoa trade goods vendor located at the Refugee Caravan in Terokkar Forest." },
  ["skreah"] = { 2, "arakkoa alchemy vendor located in the Lower City of Shatt...", "Skreah is an arakkoa alchemy vendor located in the Lower City of Shattrath City." },
  ["skreek the wingless"] = { 2, "arakkoa", "Skreek the Wingless is an arakkoa that would be involved with Swiftshadow and Y'kish in Gorgrond. Skreek would die." },
  ["skul'vrax"] = { 2, "satyr located in Val'sharah", "Skul'vrax is a satyr located in Val'sharah. He killed Swiftflight." },
  ["skuld"] = { 2, "Mawsworn kyrian located in the Fracture Chambers in Torghast", "Skuld is a Mawsworn kyrian located in the Fracture Chambers in Torghast, Tower of the Damned. He was found draining anima from three Bound Souls before Shandris Feathermoon and the Maw Walker arrived at the scene." },
  ["skuld vit"] = { 2, "Drust located beneath Darkreach in Ardenweald", "Skuld Vit is a Drust located beneath Darkreach in Ardenweald." },
  ["skulking gutstabber"] = { 2, "', "Skulking Gutstabbers are gnolls located in Gutshot's Overlook in Brackenhide Hollow." },
  ["skull-splitter grun"] = { 2, "ogre", "Skull-Splitter Grun is an ogre." },
  ["skullhat"] = { 2, "kobold vignette", "Skullhat is a kobold vignette and the apparent leader of the Skywhisker, found inside a cave in the Haglands in Highmountain along with three Skywhisker Scrappers." },
  ["skurro"] = { 2, "kobold located in the Dread Pit", "Skurro is a kobold located in the Dread Pit. He and his friend Luch were captured by the nerubians in there." },
  ["skuttogg"] = { 2, "drogbar located in Zaralek Cavern", "Skuttogg is a drogbar located in Zaralek Cavern." },
  ["sky-captain 'dusty' blastnut"] = { 2, "goblin Sky-Captain of the Horde zeppelin The Zephyr", "Sky-Captain 'Dusty' Blastnut is the goblin Sky-Captain of the Horde zeppelin The Zephyr, which travels between the tauren capital of Thunder Bluff to the orc capital of Orgrimmar." },
  ["sky-captain aerthin"] = { 2, "captain of the Righteous Hammer", "Sky-Captain Aerthin is the captain of the Righteous Hammer, an airship that travels around the Priory of the Sacred Flame in Hallowfall. He is one of four sky-captains that need to be spoken to in order to unlock the Sunken Cache treasure containi..." },
  ["sky-captain bomblast"] = { 2, "zeppelin", "Sky-Captain Bomblast commands The Iron Eagle, the zeppelin that runs between Orgrimmar and Grom'gol Base Camp. He runs the tightest airship in all of Azeroth, which might explain only one female goblin aboard." },
  ["sky-captain cableclamp"] = { 2, "zeppelin", "Sky-Captain Cableclamp commanded The Purple Princess, the zeppelin that ran between Brill and Grom'gol Base Camp. A laid-back captain, she allowed most of her crew to relax whenever they could." },
  ["sky-captain clairmonte"] = { 2, "captain of the Embers", "Sky-Captain Clairmonte is the captain of the Embers, an airship that travels around Hallowfall. She is one of four sky-captains that need to be spoken to in order to unlock the Sunken Cache treasure containing the  [Silver Linin' Scepter]." },
  ["sky-captain cloudkicker"] = { 2, "zeppelin", "Sky-Captain Cloudkicker commands The Thundercaller, the zeppelin that runs between Orgrimmar and Brill. He never manages to get Chief Officer Coppernut's name or gender right." },
  ["sky-captain dornald"] = { 2, "captain of the Mighty Lynx", "Sky-Captain Dornald is the captain of the Mighty Lynx, an airship that travels around Hallowfall. His lynx Regeneald is sitting next to him." },
  ["sky-captain elaena lancekat"] = { 2, "Arathi sky-captain of the Dauntless", "Sky-Captain Elaena Lancekat is an Arathi sky-captain of the Dauntless and the Starchaser. She is known for her strategic thinking in combat..." },
  ["sky-captain estraella"] = { 2, "captain of the Empire's Reach II", "Sky-Captain Estraella is the captain of the Empire's Reach II, an airship that travels around Hallowfall." },
  ["sky-captain onaro"] = { 2, "captain of the Resolute Flame", "Sky-Captain Onaro is the captain of the Resolute Flame, an airship that travels around Hallowfall. She is one of four sky-captains that need to be spoken to in order to unlock the Sunken Cache treasure containing the  [Silver Linin' Scepter]." },
  ["skycaller vrakthris"] = { 2, "centaur found in Thousand Needles", "Skycaller Vrakthris is a centaur found in Thousand Needles." },
  ["skygazer paatu"] = { 2, "tuskarr flight master located in Iskaara in the Azure Span", "Skygazer Paatu is a tuskarr flight master located in Iskaara in the Azure Span. Paa is found next to her." },
  ["skyguard ace"] = { 2, "', "Skyguard Aces are humans, dwarves, Broken, and blood elves briefly appearing in Terokk's Rest in Terokkar Forest. They assisted the adventurers in defeating Terokk." },
  ["skyguard amelia"] = { 2, "human flight master located at Fort Wrynn in Talador", "Skyguard Amelia is a human flight master located at Fort Wrynn in Talador." },
  ["skyguard blann"] = { 2, "flight master located at The Iron Front in the Tanaan Jungle", "Skyguard Blann is the flight master located at The Iron Front in the Tanaan Jungle." },
  ["skyguard prisoner"] = { 2, "', "Skyguard Prisoners are Broken quest givers located in cages in the four veils of Skettis in Terokkar Forest." },
  ["skyguard scout"] = { 2, "', "Skyguard Scouts are scouts found patrolling the skies near Blackwind Landing in Terokkar Forest and Skyguard Outpost in Blade's Edge Mountains." },
  ["skyguard windcharger"] = { 2, "', "Skyguard Windchargers are guards located in Skyguard Outpost in Blade's Edge Mountains and in Terokkar Forest." },
  ["skyhunter pahra"] = { 2, "centaur tending to some Shikaar Ohuna on the Shikaar rise...", "Skyhunter Pahra is a centaur tending to some Shikaar Ohuna on the Shikaar rise in Maruukai in the Ohn'ahran Plains." },
  ["skylord braax"] = { 2, "', "Skylord Braax is one of the three Twilight's Hammer cultists that are responsible for the elementals that have overrun the destroyed town of Auberdine." },
  ["skyreach arcanologist"] = { 2, "high arakkoa located in the Grand Spire in Skyreach", "Skyreach Arcanologist is a high arakkoa located in the Grand Spire in Skyreach." },
  ["skyreach archaeologist"] = { 2, "', "Skyreach Archaeologists are two arakkoa found inside a cave at Lost Veil Anzu in the Spires of Arak. They will periodically extract energy from one of the Apexis Pylons in the room, after which they will use that energy to power up one of the near..." },
  ["skyreach dawnbreaker"] = { 2, "', "Skyreach Dawnbreakers are arakkoa found at Skettis in the Spires of Arak. Some of them have Solar Familiar companions." },
  ["skyreach dreadtalon"] = { 2, "', "Skyreach Dreadtalons are high arakkoa located in the Spires of Arak." },
  ["skyreach labormaster"] = { 2, "', "Skyreach Labormasters are arakkoa found at Skettis in the Spires of Arak." },
  ["skyreach overlord"] = { 2, "arakkoa found at the Lower Quarter in Skyreach", "The Skyreach Overlord is an arakkoa found at the Lower Quarter in Skyreach. It holds several Low-Born Arakkoa in chains." },
  ["skyreach raven whisperer"] = { 2, "high arakkoa located in Skyreach", "Skyreach Raven Whisperer is a high arakkoa located in Skyreach." },
  ["skyreach scytheclaw"] = { 2, "', "Skyreach Scytheclaws are high arakkoa located in the Spires of Arak." },
  ["skyreach stormcaller"] = { 2, "', "Skyreach Stormcallers are arakkoa located in Spires of Arak." },
  ["skyreach tempest-keeper"] = { 2, "', "Skyreach Tempest-Keepers are high arakkoa located in the Spires of Arak." },
  ["skyscribe stefen edgley"] = { 2, "worgen located in the Ohn'ahran Plains", "Skyscribe Stefen Edgley is a worgen located in the Ohn'ahran Plains." },
  ["skysea wanderer"] = { 2, "', "Skysea Wanderers are night elves, worgen, and tauren located in the Dreamgrove and on the Vindicaar." },
  ["skyseer ghrent"] = { 2, "vrykul located in the Skyhold", "Skyseer Ghrent is a vrykul located in the Skyhold." },
  ["skytalon inuz"] = { 2, "arakkoa flight master located in Talador", "Skytalon Inuz is an arakkoa flight master located in Talador." },
  ["skytalon karaz"] = { 2, "arakkoa flight master located at the Sethekk Hollow in Sp...", "Skytalon Karaz is an arakkoa flight master located at the Sethekk Hollow in Spires of Arak." },
  ["skytalon kariz"] = { 2, "arakkoa flight master located at the Aktar's Post‎ in Tan...", "Skytalon Kariz is an arakkoa flight master located at the Aktar's Post‎ in Tanaan Jungle." },
  ["skytalon kuris"] = { 2, "arakkoa flight master located at the Veil Akraz in the Sp...", "Skytalon Kuris is an arakkoa flight master located at the Veil Akraz in the Spires of Arak." },
  ["skytalon meshaal"] = { 2, "arakkoa flight master located at the Veil Terokk in Spire...", "Skytalon Meshaal is an arakkoa flight master located at the Veil Terokk in Spires of Arak." },
  ["skywhisker loyalist"] = { 2, "', "Skywhisker Loyalists are kobolds located in Highmountain." },
  ["skywhisker scrapper"] = { 2, "', "Skywhisker Scrappers are kobolds located in Highmountain." },
  ["skywing"] = { 2, "quest giver located on the eastern edge of the Bone Waste...", "Skywing is a quest giver located on the eastern edge of the Bone Wastes of Terokkar Forest. He is an arakkoa cursed into the form of a parrot by Luanga the Imprisoner." },
  ["slain blighted"] = { 2, "', "Slain Blighted are Drust located at the Glitterfall Heights in Ardenweald." },
  ["slain tualiq villager"] = { 2, "objective of the daily quest  [25-30 Daily] The Light's M...", "Slain Tualiq Villagers are tuskarr found slain everywhere on Hrothgar's Landing. Freeing their spirits with the  [Confessor's Prayer Book] is the objective of the daily quest  [25-30 Daily] The Light's Mercy." },
  ["slain tuskarr"] = { 2, "', "Slain Tuskarr are tuskarr located at Iskaal in the Howling Fjord." },
  ["slain vulpera"] = { 2, "', "Slain Vulpera are vulpera corpses strewn about Shatterstone Harbor in Vol'dun prior to the Alliance's takeover of the port. They can only be seen by Alliance players that have yet to complete  [35-60] Ooh Rah!." },
  ["slark"] = { 2, "rare mob murloc found patrolling the Longshore coast in W...", "Slark is a rare mob murloc found patrolling the Longshore coast in Westfall with his buddy Brack. Slark is very fast moving, and catching him without any of his comrades is very hard." },
  ["slash gutspill"] = { 2, "drogbar located in the Valley of the Sword in Stormheim", "Slash Gutspill is a drogbar located in the Valley of the Sword in Stormheim." },
  ["slate quicksand"] = { 2, "earthen quest giver found at the Quaking Fields in Deepholm", "Slate Quicksand is an earthen quest giver found at the Quaking Fields in Deepholm." },
  ["slatecrusher raider"] = { 2, "', "Slatecrusher Raiders ae drogbar who accompanied Drog Almighty and burrowed their way out of the hills of Suramar, causing structural instability to the buildings in the area. In response, they were taken out by class order champions." },
  ["slatewhisker schemer"] = { 2, "', "Slatewhisker Schemers are kobolds." },
  ["slatewhisker shoveler"] = { 2, "', "Slatewhisker Shovelers are kobolds." },
  ["slaughtered sea witch"] = { 2, "', "Slaughtered Sea Witches are naga located on Ranazjar Isle in Desolace." },
  ["slaughtered vulpera"] = { 2, "', "Slaughtered Vulpera are vulpera corpses located next to a pile of Freshly Dug Sand in the Port of Zem'lan as well as at Taz'raka the Traitor's ruins in Vol'dun." },
  ["slave hunter brol"] = { 2, "ogre located at Stonemaul Arena in Gorgrond", "Slave Hunter Brol is an ogre located at Stonemaul Arena in Gorgrond." },
  ["slave hunter krag"] = { 2, "ogre located in Stonemaul Arena in Gorgrond", "Slave Hunter Krag is an ogre located in Stonemaul Arena in Gorgrond." },
  ["slave hunter mol"] = { 2, "ogre located at Stonemaul Arena in Gorgrond", "Slave Hunter Mol is an ogre located at Stonemaul Arena in Gorgrond." },
  ["slave watcher crushto"] = { 2, "', "Slave Watcher Crushto is one of the first two bosses in Bloodmaul Slag Mines." },
  ["slave worker"] = { 2, "', "Slave Workers are slaves working for the Dark Iron dwarves within the Slag Pit of the Searing Gorge." },
  ["slavemaster shiaxu"] = { 2, "final boss of  [32-35] To the Skies! He is found at the s...", "Slavemaster Shiaxu is the final boss of  [32-35] To the Skies! He is found at the southern end of the Lightning Vein Mine." },
  ["sleeby"] = { 2, "kobold", "Sleeby is a kobold that could be found following the mountain giant Fozruk in the Arathi Highlands. As of Battle for Azeroth, he now follows Fozruk's son, also named Fozruk." },
  ["sleep-deprived student"] = { 2, "', "Sleep-Deprived Students are dracthyr located in the Late Night Lab in Thaldraszus. They are kept awake by the coffee provided by Bromithus." },
  ["sleeping guardian (emerald dream)"] = { 2, "', "Sleeping Guardians are druids located in the Barrows of Reverie in the Emerald Dream." },
  ["sleepy resident"] = { 2, "active endeavor", "Sleepy Residents are people of various races located in any neighborhood where Friend of the Grummles is the active endeavor. They appear in the Town Center in Founder's Point or in the Common in Razorwind Shores." },
  ["slickerfin chief"] = { 2, "murloc", "Slickerfin Chief is a murloc." },
  ["slipster"] = { 2, "baby naga located in the Eye of Azshara", "Slipster is a baby naga located in the Eye of Azshara. Initially captured by the Violetsails and held in a Pet Cage, it is rescued by an adventurer, after which it is seen near Zantini." },
  ["slitherblade azanz"] = { 2, "naga located at Ashen Strand in Nazjatar", "Slitherblade Azanz is a naga located at Ashen Strand in Nazjatar." },
  ["slitherblade invader"] = { 2, "', "Slitherblade Invaders are naga located in Slitherblade Shore in Desolace." },
  ["slitherblade myrmidon"] = { 2, "', "Slitherblade Myrmidons are naga located at Ethel Rethor, Sar'theris Strand, and Ranazjar Isle in Desolace." },
  ["slitherblade naga"] = { 2, "', "Slitherblade Naga are naga located in Desolace." },
  ["slitherblade oracle"] = { 2, "', "Slitherblade Oracles are naga found at the Slitherblade Shore in Desolace." },
  ["slitherblade razortail"] = { 2, "', "Slitherblade Razortails are naga located at Ethel Rethor and Sar'theris Strand in Desolace." },
  ["slitherblade sea witch"] = { 2, "', "Slitherblade Sea Witches are naga found in northwestern Desolace." },
  ["slitherblade siren"] = { 2, "', "Slitherblade Sirens are naga located in Slitherblade Shore in Desolace." },
  ["slitherblade sorceress"] = { 2, "', "Slitherblade Sorceresses are naga located in Desolace." },
  ["slitherblade tide priestess"] = { 2, "', "Slitherblade Tide Priestesses are naga found around Ethel Rethor and Ranazjar Isle in the Desolace." },
  ["slitherblade tidehunter"] = { 2, "', "Slitherblade Tidehunters are naga found in Desolace." },
  ["slitherblade warrior"] = { 2, "', "Slitherblade Warriors are naga located in Desolace." },
  ["slithering sliss"] = { 2, "naga located in Azsuna", "Slithering Sliss is a naga located in Azsuna. She was taken out by the class orders." },
  ["slixi boompowder"] = { 2, "goblin", "Slixi Boompowder is a goblin who invented tossaways, a means of protection from the Uninvited Guest, after her husband, the Steamwheedle trade prince Klaxz Boompowder, fell victim to the creature. She has green eyes and her hair is arranged in rat..." },
  ["slobbermouth"] = { 2, "gnoll located in the Grim Guzzler of Blackrock Depths gua...", "Slobbermouth was a gnoll located in the Grim Guzzler of Blackrock Depths guarding Griz Gutshank with  [Brutal Gladiator's Bonegrinder] alongside Snaggletooth." },
  ["slowly decaying mosshide mystic"] = { 2, "', "Slowly Decaying Mosshide Mystics are dead gnolls located near Slabchisel's Survey in the Wetlands." },
  ["slrglrglr 'stabby' glrslrslr"] = { 2, "murloc located at the Trueshot Lodge in Highmountain", "Slrglrglr 'Stabby' Glrslrslr is a murloc located at the Trueshot Lodge in Highmountain. He is sparring with Gharset the Aimtrue." },
  ["slumbering mjordin"] = { 2, "', "Slumbering Mjordins are vrykul located in the Halls of the Ancestors in Icecrown. This section concerns content related to Shadowlands." },
  ["small illusionary amber-weaver"] = { 2, "mantid found in the Proving Grounds", "Small Illusionary Amber-Weaver is a mantid found in the Proving Grounds." },
  ["small illusionary hive-singer"] = { 2, "mantid found in the Proving Grounds", "Small Illusionary Hive-Singer is a mantid found in the Proving Grounds." },
  ["small illusionary wind-guard"] = { 2, "mantid found in the Proving Grounds", "Small Illusionary Wind-Guard is a mantid found in the Proving Grounds." },
  ["smilin' slirk brassknob"] = { 2, "goblin innkeeper found at K3 in the Storm Peaks", "Smilin' Slirk Brassknob is a goblin innkeeper found at K3 in the Storm Peaks." },
  ["smitescale oracle"] = { 2, "murloc", "Smitescale Oracle is a murloc." },
  ["smitescale stabber"] = { 2, "murloc", "Smitescale Stabber is a murloc." },
  ["smitescale youngling"] = { 2, "murloc", "Smitescale Youngling is a murloc." },
  ["smith au'berk"] = { 2, "broker located in the Hall of Shapes in Oribos", "Smith Au'berk is a broker located in the Hall of Shapes in Oribos. He teaches Maw Walkers about Shadowlands Blacksmithing crafts." },
  ["smith bran'miir"] = { 2, "draenei blacksmithing supplies vendor located in the Sha'...", "Smith Bran'miir is a draenei blacksmithing supplies vendor located in the Sha'tari Market District in Talador." },
  ["smith brinmaar"] = { 2, "draenei vendor located in Wrynn Artillery Tower at Fort W...", "Smith Brinmaar is a draenei vendor located in Wrynn Artillery Tower at Fort Wrynn in Talador." },
  ["smith gaan"] = { 2, "centaur located in the Ohn'ahran Plains", "Smith Gaan is a centaur located in the Ohn'ahran Plains. He is one of the few surviving members of Clan Toghus, having been rescued from the village of Daruukhan after it was destroyed by Clan Nokhud." },
  ["smolderhide chanter"] = { 2, "', "Smolderhide Chanters are furbolgs found at the Smolderhide Thicket in Val'sharah." },
  ["smolderhide hunter"] = { 2, "', "Smolderhide Hunters are furbolgs found at the Smolderhide Thicket in Val'sharah. They have Stinger Wasp pets." },
  ["smolderhide warrior"] = { 2, "', "Smolderhide Warriors are furbolgs found at the Smolderhide Thicket in Val'sharah." },
  ["smoldering murloc egg"] = { 2, "companion", "Deathy is a companion that was given out to attendees of BlizzCon 2010, purchasers of the DirecTV pay-per-view of the event, and purchasers of the internet streamed video of the event. Deathy is a murloc companion decked out as Deathwing, doing hi..." },
  ["smug francise"] = { 2, "venthyr located in Revendreth", "Smug Francise is a venthyr located in Revendreth." },
  ["smuggler nightfang"] = { 2, "worgen located in Highmountain in a camp along with Wrathion", "Smuggler Nightfang was a worgen located in Highmountain in a camp along with Wrathion. He was replaced by Chofa Nighthoof." },
  ["snaggle"] = { 2, "kobold miner appearing in Series 8 of DC Direct's World o...", "Snaggle is a kobold miner appearing in Series 8 of DC Direct's World of Warcraft action figures. He was part of a two-pack, also featuring Brink Spannercrank." },
  ["snaggle (worldbreaker)"] = { 2, "card from the Crafting: Worldbreaker Block set", "Snaggle is a card from the Crafting: Worldbreaker Block set." },
  ["snagglespear"] = { 2, "rare gnoll found in the gnoll camps south of Bloodhoof Vi...", "Snagglespear is a rare gnoll found in the gnoll camps south of Bloodhoof Village in Mulgore. He may be the leader of the Palemane tribe." },
  ["snaggletooth"] = { 2, "gnoll located in the Grim Guzzler of Blackrock Depths gua...", "Snaggletooth was a gnoll located in the Grim Guzzler of Blackrock Depths guarding Griz Gutshank with  [Brutal Gladiator's Bonegrinder] alongside Slobbermouth." },
  ["snaps"] = { 2, "tortollan located at Gloom Hollow in Nazmir", "Snaps is a tortollan located at Gloom Hollow in Nazmir." },
  ["snarglebone"] = { 2, "gnoll located in the Azure Span", "Snarglebone is a gnoll located in the Azure Span." },
  ["snarlmane"] = { 2, "rare undead gnoll found in the basement of Fenris Keep in...", "Snarlmane is a rare undead gnoll found in the basement of Fenris Keep in Silverpine Forest, being scared of its new occupiers. He is on a 4-6 hour respawn timer." },
  ["snarlmane (warcraft iii)"] = { 2, "leader of a gnoll group in Tirisfal Glades", "Snarlmane was the leader of a gnoll group in Tirisfal Glades and was caught in between a conflict involving Varimathras and Sylvanas after the Third War. Sylvanas used one of her banshees to possess Snarlmane and used his gnolls against Varimathra..." },
  ["snarlmane the bloodgorger"] = { 2, "powerful gnoll", "Snarlmane Bloodgorger is a powerful gnoll who tried to stop Kael'thas from fixing the last Arcane Observatory. Kael'thas slew the gnoll and reclaimed the observatory." },
  ["snazzle shinyfinder"] = { 2, "Bluewax kobold found in Candle Rock in Highmountain durin...", "Snazzle Shinyfinder is a Bluewax kobold found in Candle Rock in Highmountain during  [10-45] Candle of Command and  [10-45] Burn the Candle at Both Ends. According to Intern Jackie, Snazzle is a good worker, and he appears to be skilled at finding..." },
  ["snicarus dungleflight"] = { 2, "gnome located in Azsuna", "Snicarus Dungleflight was a gnome located in Azsuna." },
  ["sniffy pete"] = { 2, "worgen found in Bizmo's Brawlpub underneath the Deeprun Tram", "Sniffy Pete is a worgen found in Bizmo's Brawlpub underneath the Deeprun Tram." },
  ["snitch eagersnipe"] = { 2, "gnome located at the Obsidian Bulwark", "Snitch Eagersnipe is a gnome located at the Obsidian Bulwark and Obsidian Citadel in the Waking Shores. He is one of the seven gnomes following Becca Black." },
  ["snokh blackspine"] = { 2, "quilboar fire mage", "Snokh Blackspine is a quilboar fire mage, and is part of Theldren's team of gladiators at the Blackrock Depths arena." },
  ["snoll the icebreaker"] = { 2, "gnoll located in Snowhide Camp in the Azure Span", "Snoll the Icebreaker is a gnoll located in Snowhide Camp in the Azure Span." },
  ["snoozy clickclock"] = { 2, "gnome located at the Obsidian Bulwark", "Snoozy Clickclock is a gnome located at the Obsidian Bulwark and Obsidian Citadel in the Waking Shores. She is one of the seven gnomes following Becca Black." },
  ["snowhide brute"] = { 2, "', "Snowhide Brutes are gnolls located in Snowhide Camp in the Azure Span." },
  ["snowhide shaman"] = { 2, "', "Snowhide Shaman are gnolls located in Snowhide Camp in the Azure Span." },
  ["snowhide yeti hunter"] = { 2, "', "Snowhide Yeti Hunters are gnolls located in Snowhide Camp in the Azure Span." },
  ["snowstone crusher"] = { 2, "', "Snowstone Crushers are furbolgs located in the Azure Span." },
  ["snubjaw"] = { 2, "kobold grubtender located in the Chittering Den in the Ri...", "Snubjaw is a kobold grubtender located in the Chittering Den in the Ringing Deeps. Snubjaw and Nebb were tending to their grubs when invasive undercrawlers attacked them and poisoned Snubjaw." },
  ["snurk bucksquick"] = { 2, "Steamwheedle goblin zeppelin master located on the northe...", "Snurk Bucksquick is a Steamwheedle goblin zeppelin master located on the northern zeppelin tower on the Orgrimmar Skyway, where she provides information about The Iron Eagle traveling to and from Grom'Gol Base Camp. Fellow zeppelin master Squibby ..." },
  ["so' cartel assassin"] = { 2, "Veiled Market", "So' Cartel Assassins are brokers located in Tazavesh, the Veiled Market." },
  ["so'azmi"] = { 2, "broker serving as the fifth boss of Tazavesh", "So'azmi is a broker serving as the fifth boss of Tazavesh, the Veiled Market. Cartel So's lethal assassin, So'azmi was always perfecting his technique." },
  ["so'danah"] = { 2, "broker located on the outer ring of Oribos to the north west", "So'danah is a broker located on the outer ring of Oribos to the north west. He drops the  [Cartel So Shipping Manifest], which is the objective of  [60] Things Best Kept Dark, part of the quest chain to unlock Tazavesh, the Veiled Market." },
  ["so'leah"] = { 2, "broker serving as the final boss of Tazavesh", "So'leah is a broker serving as the final boss of Tazavesh, the Veiled Market. She was the leader of Cartel So." },
  ["so'narynar"] = { 2, "broker located at the Challenger's Promenade in Maldraxxus", "So'narynar is a broker located at the Challenger's Promenade in Maldraxxus. He works for Au'narim, and helps with the various businesses that Au'narim has going on in the place." },
  ["so'turu"] = { 2, "broker vendor located in the Hall of Holding in Oribos", "So'turu is a broker vendor located in the Hall of Holding in Oribos. Next to him are Ko'ropo and Ta'choso." },
