  ["soaring chakram master"] = { 2, "', "Soaring Chakram Masters are arakkoa located in Skyreach." },
  ["sock brightbolt"] = { 2, "gnome engineering trainer", "Sock Brightbolt is a gnome engineering trainer. He is located to the left of the entrance to Valiance Keep in the Borean Tundra." },
  ["sofee batalsworn"] = { 2, "Arathi vendor located in Faerin's Advance in Azj-Kahet", "Sofee Batalsworn is an Arathi vendor located in Faerin's Advance in Azj-Kahet." },
