  ["sojourning aspirant"] = { 2, "', "Sojourning Aspirants are kyrian located at Hero's Rest in Bastion." },
  ["sol-shaper krashyx"] = { 2, "arakkoa found in the Apexis Excavation in the Spires of Arak", "Sol-Shaper Krashyx is an arakkoa found in the Apexis Excavation in the Spires of Arak." },
  ["sol-shaper krivin"] = { 2, "arakkoa found at 'shrine to the raven god' in the Lost Ve...", "Sol-Shaper Krivin is an arakkoa found at 'shrine to the raven god' in the Lost Veil Anzu of Spires of Arak. Krivin uses the gift of Rukhmar to transform into Aspect of Rukhmar." },
  ["sol-shaper valarik"] = { 2, "arakkoa located in the Apexis Chamber at the Bloodmane Va...", "Sol-Shaper Valarik is an arakkoa located in the Apexis Chamber at the Bloodmane Valley in Spires of Arak. He is the author of the Adherent Note." },
  ["sol-shaper veoryx"] = { 2, "arakkoa found in the Apexis Excavation in the Spires of Arak", "Sol-Shaper Veoryx is an arakkoa found in the Apexis Excavation in the Spires of Arak." },
  ["solar myrmidon"] = { 2, "naga located in Azsuna", "Solar Myrmidon is a naga located in Azsuna." },
  ["solar priest vayx"] = { 2, "arakkoa located at the Lunarfall in Shadowmoon Valley", "Solar Priest Vayx is an arakkoa located at the Lunarfall in Shadowmoon Valley and Frostwall in Frostfire Ridge. He can only be recruited with his contract which is purchased from Dawn-Seeker Krisek at Lion's Watch or Vol'mar." },
  ["solar zealot"] = { 2, "', "Solar Zealots are arakkoa that are periodically summoned by High Sage Viryx at the Grand Spire in Skyreach. They will pick up a player and try to drop them off the edge of the platform." },
  ["solden blitzfuse"] = { 2, "goblin located in Slam Central Station in Undermine", "Solden Blitzfuse is a goblin located in Slam Central Station in Undermine." },
  ["solivane"] = { 2, "venthyr located in Sinfall", "Solivane is a venthyr located in Sinfall." },
  ["solonga"] = { 2, "centaur enchanting trainer", "Solonga is a centaur enchanting trainer and vendor located in Ohn'iri Springs in the Ohn'ahran Plains." },
  ["solsten"] = { 2, "vrykul located in the Halls of Valor", "Solsten is a vrykul located in the Halls of Valor. He becomes a ghost." },
  ["solstice hunter"] = { 2, "', "Solstice Hunters are Wolfcult trappers located in Solstice Village in the Grizzly Hills. They transform into worgen when their health gets low." },
  ["solux"] = { 2, "mogu located in the Vale of Eternal Blossoms", "Solux is a mogu located in the Vale of Eternal Blossoms." },
  ["son of arugal"] = { 2, "', "Sons of Arugal are worgen found in both Shadowfang Keep and Silverpine Forest. They can be a frustrating surprise for low-level Horde in Silverpine Forest." },
  ["sondo"] = { 2, "centaur located at Pinewood Post in the Ohn'ahran Plains", "Sondo is a centaur located at Pinewood Post in the Ohn'ahran Plains." },
  ["songstress nahjeen"] = { 2, "naga siren vignette located at the eastern end of Darkwoo...", "Songstress Nahjeen is a naga siren vignette located at the eastern end of Darkwood Shoal in Vol'dun, entrancing a Tortaka Refugee." },
  ["songstress of the deep"] = { 2, "naga", "The Songstress of the Deep is a naga who can be encountered during Island Expeditions." },
  ["sonnebrid"] = { 2, "earthen character in 'The Thraegar's Descent'", "Sonnebrid is an earthen character in 'The Thraegar's Descent', a play performed by the theater troupe at the Proscenium on the Isle of Dorn. She was a thraegar, a revered hero in earthen society." },
  ["soola hardshell"] = { 2, "tortollan located at the Seekers' Vista in Stormsong Valley", "Soola Hardshell is a tortollan located at the Seekers' Vista in Stormsong Valley." },
  ["soolaveen"] = { 2, "Broken quest giver located at the Refugee Caravan in Tero...", "Soolaveen is a Broken quest giver located at the Refugee Caravan in Terokkar Forest." },
  ["soolie berryfizz"] = { 2, "gnome alchemy vendor located in the shop Berryfizz's Potions", "Soolie Berryfizz is a gnome alchemy vendor located in the shop Berryfizz's Potions and Mixed Drinks in Tinker Town in Ironforge." },
  ["soothsayer sargle"] = { 2, "gnoll located in Murder Row in Silvermoon City", "Soothsayer Sargle is a gnoll located in Murder Row in Silvermoon City." },
  ["sootsnout"] = { 2, "kobold located in the Hall of the Candle King in Darkflam...", "Sootsnout is a kobold located in the Hall of the Candle King in Darkflame Cleft. She summoned Wickbreaker during  [73-75] Retaking the Mines." },
  ["sophia (kyrian)"] = { 2, "Ascended kyrian located in Bastion", "Sophia is an Ascended kyrian located in Bastion. She can be encountered in Sophia's Aria and Sophia's Overture where Maw Walkers help her by holding off Forsworn agents while she repairs the vespers located there." },
  ["sophie aaren"] = { 2, "human florist located in the Aaren's Flowers flower shop ...", "Sophie Aaren is a human florist located in the Aaren's Flowers flower shop on Festival Lane in Old Stratholme." },
  ["sophietta lynflayme"] = { 2, "Arathi located in Lightspark in Hallowfall", "Sophietta Lynflayme is an Arathi located in Lightspark in Hallowfall. She and her cousin Barahl came to Hallowfall together as stalwarts." },
  ["soran vidala"] = { 2, "Arathi located in Mereldar in Hallowfall", "Soran Vidala is an Arathi located in Mereldar in Hallowfall. He can be found dancing with Blimore Vidala and appears to be  Drunk." },
  ["sorcerer zhang"] = { 2, "mogu located in Zuldazar", "Sorcerer Zhang is a mogu located in Zuldazar." },
  ["sorolis the ill-fated"] = { 2, "Ill-Fated is an eredar located at the rear of the Conserv...", "Sorolis the Ill-Fated is an eredar located at the rear of the Conservatory of the Arcane in Eredath." },
  ["sorotis"] = { 2, "dracthyr located in Valdrakken where she serves as the Ti...", "Sorotis is a dracthyr located in Valdrakken where she serves as the Titan Relic turn-in. She is later found at Tyrhold Reservoir in Thaldraszus as the vendor for Ulderoth items during Time Rifts." },
  ["soteria eldenwing"] = { 2, "Forsworn kyrian located in the Citadel of Loyalty in Bastion", "Soteria Eldenwing is a Forsworn kyrian located in the Citadel of Loyalty in Bastion." },
  ["soul infuser"] = { 2, "', "Soul Infusers are venthyr that spawn during the Sun King's Salvation fight in Pride's Prison in Castle Nathria." },
  ["soul-bringer togan"] = { 2, "mogu located in the Unknown Crypt during Island Expeditions", "Soul-Bringer Togan is a mogu located in the Unknown Crypt during Island Expeditions." },
  ["soul-scribe"] = { 2, "ethereal", "Soul-Scribe (sometimes referred to as the Soul-Scribe) was an ethereal and the leader of the Wastelanders on K'aresh. She was once a member and leader of the K'areshi Oracles." },
  ["soul-scribe (tactics)"] = { 2, "boss in Eco-Dome Al'dani", "Soul-Scribe is a boss in Eco-Dome Al'dani." },
  ["soulbinder aedraa"] = { 2, "draenei located at Telmor in Talador", "Soulbinder Aedraa is a draenei located at Telmor in Talador. She was killed by Vorpil Ribcleaver in order to obtain  [Auch'naaru] from her." },
  ["soulbinder kraj'tess"] = { 2, "naga located at Carver's Harbor in Drustvar", "Soulbinder Kraj'tess is a naga located at Carver's Harbor in Drustvar and in Nazmir." },
  ["soulbinder sabeel"] = { 2, "ethereal located in North Sufaad on K'aresh", "Soulbinder Sabeel is an ethereal located in North Sufaad on K'aresh." },
  ["soulbinder sej'tetha"] = { 2, "naga located in Stormsong Valley", "Soulbinder Sej'tetha is a naga located in Stormsong Valley." },
  ["soulguide daelia"] = { 2, "Ascended kyrian located in the Sanctum of Binding of Elys...", "Soulguide Daelia is an Ascended kyrian located in the Sanctum of Binding of Elysian Hold in Bastion. She is one of the most veteran watchers of the Ascended and was tasked with bringing souls to the Elysian Hold once more." },
  ["soulharvester duuren"] = { 2, "centaur located at the Eternal Kurgans in the Nokhud Offe...", "Soulharvester Duuren is a centaur located at the Eternal Kurgans in the Nokhud Offensive." },
  ["soulharvester galtmaa"] = { 2, "centaur located at the Eternal Kurgans in the Nokhud Offe...", "Soulharvester Galtmaa is a centaur located at the Eternal Kurgans in the Nokhud Offensive." },
