  ["soulkeeper saraa"] = { 2, "venthyr located in Revendreth", "Soulkeeper Saraa is a venthyr located in Revendreth." },
  ["soulpriest avelia"] = { 2, "draenei located at Light's Rest in Talador", "Soulpriest Avelia is a draenei located at Light's Rest in Talador. She is tending to several Injured Auchenai Defenders." },
  ["soulpriest daevos"] = { 2, "draenei located at the Spire of Light in Talador", "Soulpriest Daevos is a draenei located at the Spire of Light in Talador." },
