  ["soulspeaker niir"] = { 2, "Broken located in the Crystal Hall in the Exodar", "Soulspeaker Niir is a Broken located in the Crystal Hall in the Exodar. He attended the Tishamaat and could be seen speaking with Fel-Caller Guloto and a Krokul Ridgestalker." },
  ["soulstalker doina"] = { 2, "venthyr located in the Chalice District in Revendreth", "Soulstalker Doina is a venthyr located in the Chalice District in Revendreth. She is fought three times." },
  ["soultrapper mevra"] = { 2, "', "Soultrapper Mevra is part of The Soultakers, world bosses introduced in World of Warcraft: Legion. She is found inside the Shrine of the Truthguard in Shield's Rest, Stormheim." },
  ["soultrapper valistra"] = { 2, "venthyr innkeeper located at Wanecrypt Hill Inn in Revend...", "Soultrapper Valistra is a venthyr innkeeper located at Wanecrypt Hill Inn in Revendreth." },
  ["soultwister cero"] = { 2, "Drust located at Tirna Noch in Ardenweald", "Soultwister Cero is a Drust located at Tirna Noch in Ardenweald." },
  ["soulwatcher abel"] = { 2, "venthyr located in Revendreth", "Soulwatcher Abel is a venthyr located in Revendreth. He was killed by Packmother Soulfang who is found feasting on his remains." },
  ["southsea brigand"] = { 2, "', "Southsea Brigands are humans, jungle trolls, and gnolls found on the Merchant Coast in the Barrens." },
