  ["southsea sailor"] = { 2, "', "Southsea Sailors are humans, goblins, and gnolls located in the Southsea Holdfast in Thousand Needles." },
  ["southsea smuggler"] = { 2, "', "Southsea Smugglers are humans and gnolls located in Oceanus Cove in Azsuna. Under the command of Captain Blindside, they are fighting against Flog the Captain-Eater." },
  ["spa greeter"] = { 2, "', "Spa Greeters are located at the entrance to the Serene Dreams Spa in Thaldraszus. They will pelt you with flowers when approached, but can be convinced to stop." },
  ["spa guest"] = { 2, "', "Spa Guests are located in Serene Dreams Spa in Thaldraszus." },
  ["sparik"] = { 2, "Broken armor", "Sparik is a Broken armor and blacksmithing vendor located at Telaar in Nagrand." },
  ["sparkcaller min"] = { 2, "Rajani mogu located in the Silent Sanctuary in the Vale o...", "Sparkcaller Min is a Rajani mogu located in the Silent Sanctuary in the Vale of Eternal Blossoms, where he is seemingly trying to animate a row of mogu statues with lightning." },
  ["sparky (murloc)"] = { 2, "murloc located on the Calston Estate", "Sparky is a murloc located on the Calston Estate. He is one of the two murlocs that appears after  [1-30] Ever So Lonely." },
