  ["speaker brokk"] = { 2, "earthen located in the Singing Forge in the Stonevault", "Speaker Brokk is an earthen located in the Singing Forge in the Stonevault. He is part of the Master Machinists pair fought in that vault." },
  ["speaker davenruth"] = { 2, "Arathi located in Nightfall Sanctum", "Speaker Davenruth is an Arathi located in Nightfall Sanctum." },
  ["speaker dorlita"] = { 2, "earthen located in the Singing Forge in the Stonevault", "Speaker Dorlita is an earthen located in the Singing Forge in the Stonevault. She is part of the Master Machinists pair fought in that vault." },
  ["speaker halven"] = { 2, "Arathi located in the Nightfall Sanctum", "Speaker Halven is an Arathi located in the Nightfall Sanctum. She is one of the leaders of the Order Night and was overseeing dark rituals being conducted in the area when Brann Bronzebeard and adventurers went exploring the Nightfall Sanctum and ..." },
  ["speaker jurlax"] = { 2, "earthen located in Gundargaz in the Ringing Deeps", "Speaker Jurlax is an earthen located in Gundargaz in the Ringing Deeps." },
  ["speaker kuldas"] = { 2, "member of the Machine Speakers", "Speaker Kuldas is a member of the Machine Speakers. He is an Awakener--it's his duty to go into old places in the Ringing Deeps, or newly awakened ones, and make sure that everything is in working order." },
  ["speaker shadowcrown"] = { 2, "boss in the Dawnbreaker", "Speaker Shadowcrown is a boss in the Dawnbreaker." },
