  ["speckle"] = { 2, "murloc located on the Calston Estate", "Speckle is a murloc located on the Calston Estate. He is one of the two murlocs that appears after  [1-30] Ever So Lonely." },
  ["spectral betrayer"] = { 2, "', "Spectral Betrayers are undead ghosts fighting Spectral Defenders north of Crown Guard Tower in the Eastern Plaguelands. Before the Cataclysm, they were found in Blackwood Lake." },
  ["spectral marauder"] = { 2, "', "Spectral Marauders are undead ghosts located on the road southeast of Crown Guard Tower in the Eastern Plaguelands." },
