  ["spice trader au'saar"] = { 2, "broker located just past Tazavesh Customs Enforcement in ...", "Spice Trader Au'saar is a broker located just past Tazavesh Customs Enforcement in Tazavesh, the Veiled Market." },
  ["spiderling (warcraft iii)"] = { 2, "', "Spiderlings are nerubian spiderling creeps that can be encountered in the Icecrown Glacier and Northrend tilesets. Two Spiderlings are created upon the death of either a Nerubian Warrior or a Nerubian Spider Lord." },
  ["spike (murloc)"] = { 2, "murloc located at the Winterfin Retreat in the Borean Tundra", "Spike is a murloc located at the Winterfin Retreat in the Borean Tundra." },
  ["spike coilee"] = { 2, "herbalism vendor located in the neutral town of Bogpaddle...", "Spike Coilee is an herbalism vendor located in the neutral town of Bogpaddle in the Swamp of Sorrows. He shares a shop with Mitch Yostpaddle on the west side of town." },
  ["spiky collar"] = { 2, "worgen companion", "The Spiky Collar drops from the Big Bad Wolf in Karazhan. It summons Lil' Bad Wolf, a worgen companion." },
