  ["spineripper ku-kon"] = { 2, "mogu located in Island Expeditions", "Spineripper Ku-Kon is a mogu located in Island Expeditions." },
  ["spineskin fuselighter"] = { 2, "', "Spineskin Fuselighters are quilboar located on the Siren Isle while  [80EWQ] Tides of Greed is active." },
  ["spineskin horker"] = { 2, "', "Spineskin Horkers are quilboar located on the Siren Isle while  [80EWQ] Tides of Greed is active." },
