  ["spirit of olum"] = { 2, "ghost of Seer Olum", "The Spirit of Olum is located inside the Black Temple. He is the ghost of Seer Olum." },
  ["spirit of udalo"] = { 2, "Broken ghost found at the Sanctuary of Shadows in Black T...", "Spirit of Udalo is a Broken ghost found at the Sanctuary of Shadows in Black Temple.  He is affiliated with the Ashtongue Deathsworn." },
  ["spiritbinder taleti"] = { 2, "troll", "Spiritbinder Taleti is a troll." },
  ["spiritseer ikalyi"] = { 2, "arakkoa", "Spiritseer Ikalyi is an arakkoa that appears in Lunarfall in Shadowmoon Valley or Frostwall in Frostfire Ridge after using  [Seer's Invitation]. While he is present, Ghastly Guests will spawn throughout the garrison." },
  ["spiritwalker akule"] = { 2, "tauren located in Stonetalon Mountains", "Spiritwalker Akule is a tauren located in Stonetalon Mountains and Thunder Bluff as part of the Heritage of the Shu'halo." },
