  ["sprag buzzboom"] = { 2, "dead goblin warlock located near the Darkmaul Bridge on E...", "Sprag Buzzboom is a dead goblin warlock located near the Darkmaul Bridge on Exile's Reach. He opened a Void portal so he could attempt to bind a voidwalker to his will, but he failed and was killed." },
