  ["ssarbik"] = { 2, "arakkoa sorcerer of the Hidden", "Ssarbik is an arakkoa sorcerer of the Hidden and a companion of Malus and his team. He joined them on the search for Aramar Thorne and a compass across Feralas all in service of a master, the dreadlord Xaraax." },
  ["ssavra"] = { 2, "arakkoa member of the Hidden", "Ssavra is an arakkoa member of the Hidden. Ssarbik is her brother." },
  ["ssslith"] = { 2, "naga found in Zangarmarsh", "Ssslith is a naga found in Zangarmarsh. He spawns during  [10-30G] Fhwoor Smash!" },
  ["stable master hail"] = { 2, "venthyr located in Revendreth", "Stable Master Hail is a venthyr located in Revendreth." },
  ["stablehand ta'shno"] = { 2, "broker located in the Hall of Curiosities in Oribos", "Stablehand Ta'shno is a broker located in the Hall of Curiosities in Oribos. Together with Keeper Ta'saran they manage beasts being portaled in, stabling them in the Dimensional Storage Cube." },
  ["stage manager huberta"] = { 2, "stage manager of the theater troupe in the Proscenium in ...", "Stage Manager Huberta is the stage manager of the theater troupe in the Proscenium in the Isle of Dorn. She directs adventurers through the various tasks needed to prepare for the plays." },
  ["staggon"] = { 2, "centaur", "Staggon is a centaur." },
  ["stain"] = { 2, "tortollan", "Stain is a tortollan." },
  ["stalvan mistmantle"] = { 2, "undead human found at Manor Mistmantle in Duskwood", "Stalvan Mistmantle is an undead human found at Manor Mistmantle in Duskwood." },
  ["stalwart aeroknight"] = { 2, "', "Stalwart Aeroknights are Arathi located in Lightspark in Hallowfall and in Dornogal." },
  ["stalwart echo"] = { 2, "', "Stalwart Echoes are echoes of eredar soldiers located at Triumvirate's End in Eredath, forever remembering the day of the flight of the draenei. They defend their fellow Velen loyalists from the man'ari." },
  ["stalwart trueshot"] = { 2, "', "Stalwart Trueshots are Ascended kyrian located in Xandria's Vigil in Bastion. They can be seen fighting the invading Maldraxxi forces." },
  ["stalwart valiant"] = { 2, "', "Stalwart Valiants are Ascended kyrian located in Xandria's Vigil in Bastion. They can be seen fighting the invading Maldraxxi forces." },
  ["stalwart of the flame"] = { 2, "', "Stalwarts of the Flame are Arathi located in Mereldar in Hallowfall." },
  ["stancie bronplough"] = { 2, "Arathi located in Mereldar in Hallowfall", "Stancie Bronplough is an Arathi located in Mereldar in Hallowfall. Around her, a pair of Mischievous Lynxes and an Imperial Lynx are sitting in empty boxes." },
  ["star captain barabos"] = { 2, "draenei rogue trainer located at the Ring of Arms in the ...", "Star Captain Barabos is a draenei rogue trainer located at the Ring of Arms in the Trader's Tier in the Exodar. Next to him are three Star Sailors." },
  ["starcaller ellana"] = { 2, "worgen located on the expedition isles", "Starcaller Ellana is a worgen located on the expedition isles." },
  ["stargazer zenoth"] = { 2, "dracthyr located in Algeth'ar Academy in Thaldraszus", "Stargazer Zenoth is a dracthyr located in Algeth'ar Academy in Thaldraszus." },
  ["stasia fallshadow"] = { 2, "Forsaken mage", "Stasia Fallshadow is a Forsaken mage who had a special talent for translating ancient tomes. Around the time of Onyxia's death, she arrived to the Pools of Vision, where she used a scroll that she had received from an orc shaman a few months befor..." },
  ["stasis-locked obsidian warder"] = { 2, "', "Stasis-Locked Obsidian Warders are dracthyr located in the War Creche in the Forbidden Reach." },
  ["steam pump overseer"] = { 2, "', "Steam Pump Overseers are naga found in Zangarmarsh. They work for Warlord Kalithresh, guarding the Steam Pumps being used to drain the lakes of Zangarmarsh." },
  ["steamwarden hurlt"] = { 2, "earthen located in Gundargaz in the Ringing Deeps", "Steamwarden Hurlt is an earthen located in Gundargaz in the Ringing Deeps. He assisted with repairing the Steamworks, directing the adventurers." },
  ["steelvein trader"] = { 2, "', "Steelvein Traders are earthen located in the Fissure and Corridors in Dornogal and in Undermine." },
  ["stefan frostbeard"] = { 2, "vrykul found at Oceanus Cove in Azsuna when  [45WQ] Huge ...", "Stefan Frostbeard is a vrykul found at Oceanus Cove in Azsuna when  [45WQ] Huge Cursed Queenfish is active." },
  ["stella boomboom"] = { 2, "goblin stable master located at the Bilgewater Harbor in ...", "Stella Boomboom is a goblin stable master located at the Bilgewater Harbor in Azshara." },
  ["stella darkpaw"] = { 2, "worgen", "Stella Darkpaw is a worgen who can be encountered during Island Expeditions." },
  ["stellin verasa"] = { 2, "Arathi located in Mereldar in Hallowfall", "Stellin Verasa is an Arathi located in Mereldar in Hallowfall. She later traveled to the Siren Isle and can be seen in Flotsam Shoal." },
  ["steve"] = { 2, "murloc located at the Winterfin Retreat in the Borean Tundra", "Steve is a murloc located at the Winterfin Retreat in the Borean Tundra." },
  ["steven allen"] = { 2, "human found along the coast in the northern part of Storm...", "Steven Allen is a human found along the coast in the northern part of Stormwind Harbor." },
  ["stevold milani"] = { 2, "Arathi located in Mereldar in Hallowfall", "Stevold Milani is an Arathi located in Mereldar in Hallowfall." },
  ["steward dayton"] = { 2, "worgen innkeeper for Greywatch in Stormheim", "Steward Dayton is a worgen innkeeper for Greywatch in Stormheim. He manages the Greywatch Barracks, and has been instructed by Greymane to keep the Barracks open to any and all allies of Gilneas in Stormheim." },
  ["stezi'ce"] = { 2, "ethereal located in any neighborhood where Consortium Con...", "Stezi'ce is an ethereal located in any neighborhood where Consortium Consternation is the active endeavor. They appear in the Town Center in Founder's Point and the Common in Razorwind Shores." },
