  ["stillpine hunter"] = { 2, "', "Stillpine Hunters are furbolgs located at Stillpine Hold in Azuremyst Isle." },
  ["stillpine raider"] = { 2, "', "Stillpine Raiders are furbolgs located in Stillpine Hold on Azuremyst Isle." },
  ["stillpine the younger"] = { 2, "furbolg located at Stillpine Hold in Azuremyst Isle", "Stillpine the Younger is a furbolg located at Stillpine Hold in Azuremyst Isle. He is the son of High Chief Stillpine, and thus heir to the chieftaincy of the Stillpine tribe." },
