  ["stomper kreeg"] = { 2, "ogre boss found in the Gordok Commons of Dire Maul", "Stomper Kreeg is an ogre boss found in the Gordok Commons of Dire Maul. If he is still alive when King Gordok dies, he will sell drinks and offer a quest." },
