  ["stonearm"] = { 2, "rare centaur found roaming the Kolkar camps around the Fo...", "Stonearm is a rare centaur found roaming the Kolkar camps around the Forgotten Pools  ,   . He is on a 1.5-2.5 hour respawn timer." },
  ["stonebinder agrogg"] = { 2, "drogbar located in Bitestone Enclave in Highmountain", "Stonebinder Agrogg is a drogbar located in Bitestone Enclave in Highmountain." },
  ["stonebinder gorgrogg"] = { 2, "drogbar located in Bitestone Enclave in Highmountain", "Stonebinder Gorgrogg is a drogbar located in Bitestone Enclave in Highmountain. He summons Plaguecloud Idols." },
  ["stonebinder ssra'vess"] = { 2, "naga located in Ameth'Aran in Darkshore", "Stonebinder Ssra'vess is a naga located in Ameth'Aran in Darkshore." },
