  ["stonedark slave"] = { 2, "', "Stonedark Slaves are drogbar located in Neltharion's Lair." },
  ["stonefather oremantle"] = { 2, "elite earthen located throughout Deepholm", "Stonefather Oremantle is an elite earthen located throughout Deepholm. He is the leader of all earthen within Deepholm." },
