  ["stonefist brawler"] = { 2, "', "Stonefist Brawlers are drogbar located in the Darkbrul Arena in Highmountain." },
  ["stonefist pit guard"] = { 2, "drogbar located in Deep Roads in Highmountain", "Stonefist Pit Guard is a drogbar located in Deep Roads in Highmountain." },
  ["stonefist rejara"] = { 2, "djaradin located in the Waking Shores", "Stonefist Rejara is a djaradin located in the Waking Shores. She is part of a Qalashi war party seemingly heading for the Ruby Life Pools." },
  ["stoneguard benston"] = { 2, "earthen located in Fungal Folly", "Stoneguard Benston is an earthen located in Fungal Folly." },
  ["stoneguard clayhoof"] = { 2, "tauren located in the Valley of Spirits in Orgrimmar", "Stoneguard Clayhoof was a tauren located in the Valley of Spirits in Orgrimmar." },
  ["stoneheart"] = { 2, "furbolg located in the Lair of Stoneheart in the Azure Span", "Stoneheart is a furbolg located in the Lair of Stoneheart in the Azure Span. He is the chieftain of the Rustpine clan." },
  ["stonehearth defender"] = { 2, "', "Stonehearth Defenders are earthen warriors that try to fight off the Stone Trogg Ambushers within the Stonehearth in Deepholm. They need help for  [30-35] We're Surrounded." },
  ["stonehearth geomaster"] = { 2, "', "Stonehearth Geomasters are earthen located at the Fractured Front in Deepholm." },
  ["stonehearth prospector"] = { 2, "', "Stonehearth Prospectors are earthen located in the Crumbling Depths in Deepholm during   [10-45] The Hammer in the Deep. They originally came form Stonehearth." },
  ["stoneweaver mcconnell"] = { 2, "venthyr located in Sinfall", "Stoneweaver McConnell is a venthyr located in Sinfall." },
  ["stonewrecker tokara"] = { 2, "djaradin located in the Waking Shores", "Stonewrecker Tokara is a djaradin located in the Waking Shores." },
  ["stored projection"] = { 2, "arakkoa projection located in the Howling Crag in the Spi...", "Stored Projection is an arakkoa projection located in the Howling Crag in the Spires of Arak. Initially shielded, they can be made vulnerable through the use of  [Apexis Keystone]." },
  ["storm scryer"] = { 2, "', "Storm Scryers are night elves and vulpera located in the Azure Span." },
  ["stormbound conqueror"] = { 2, "', "Stormbound Conquerors are terracotta warriors located in Warport Rastari and an unnamed cave near Xibala in Zuldazar. The deceased ones appear as normal mogu." },
  ["stormbound sorcerer"] = { 2, "', "Stormbound Sorcerers are vulpera located in the Primalist Future." },
  ["stormbreaker reykir"] = { 2, "vrykul located at Hrydshal in Stormheim", "Stormbreaker Reykir is a vrykul located at Hrydshal in Stormheim." },
  ["stormcaller arynga"] = { 2, "centaur located at the Ohn'iri Springs in the Nokhud Offe...", "Stormcaller Arynga is a centaur located at the Ohn'iri Springs in the Nokhud Offensive." },
  ["stormcaller boroo"] = { 2, "centaur located at the Ohn'iri Springs in the Nokhud Offe...", "Stormcaller Boroo is a centaur located at the Ohn'iri Springs in the Nokhud Offensive." },
  ["stormcaller initiate"] = { 2, "', "Stormcaller Initiates are centaurs located in the Ohn'ahran Plains." },
  ["stormcaller narkena"] = { 2, "centaur located in the Ohn'ahran Plains", "Stormcaller Narkena is a centaur located in the Ohn'ahran Plains." },
  ["stormcaller solongo"] = { 2, "centaur located at the Ohn'iri Springs in the Nokhud Offe...", "Stormcaller Solongo is a centaur located at the Ohn'iri Springs in the Nokhud Offensive." },
  ["stormcaller zarii"] = { 2, "centaur located at the Ohn'iri Springs in the Nokhud Offe...", "Stormcaller Zarii is a centaur located at the Ohn'iri Springs in the Nokhud Offensive." },
  ["stormcaster throm"] = { 2, "vrykul located in Hrydshal in Stormheim", "Stormcaster Throm is a vrykul located in Hrydshal in Stormheim." },
  ["stormcoil commander"] = { 2, "naga", "The Stormcoil Commander is a naga who orchestrates the Stormcoil army during its invasion of the Shrouded Shore in Vol'dun during  [30-60] Wrath of the Tiger. He is never directly seen, and his only presence is in the form of his yelled commands." },
  ["stormcoil dragoon"] = { 2, "', "Stormcoil Dragoons are Stormcoil naga located in Darkwood Shoal in Vol'dun. During  [30-60] Wrath of the Tiger, many of them are part of the Stormcoil army that invade the Shrouded Shore." },
  ["stormcoil sorceress"] = { 2, "', "Stormcoil Sorceresses are Stormcoil naga located in Darkwood Shoal in Vol'dun." },
  ["stormcoil tide-hunter"] = { 2, "', "Stormcoil Tide-Hunters are Stormcoil naga that accompany the Stormcoil army in invading the Shrouded Shore in Vol'dun during  [30-60] Wrath of the Tiger." },
  ["stormcoil tidecaller"] = { 2, "', "Stormcoil Tidecallers are Stormcoil naga located in Darkwood Shoal in Vol'dun. They are accompanied by Bound Tide Elementals." },
  ["stormfang bonecaster"] = { 2, "', "Stormfang Bonecasters are gnolls located in the Azure Span." },
  ["stormfang dustcaller"] = { 2, "', "Stormfang Dustcallers are gnolls located in the Azure Span." },
  ["stormfang grunt"] = { 2, "', "Stormfang Grunts are gnolls located in the Azure Span." },
  ["stormfang hexspiter"] = { 2, "', "Stormfang Hexspiters are gnolls located in the Azure Span." },
  ["stormfang shaman"] = { 2, "', "Stormfang Shaman are gnolls located in the Azure Span." },
  ["stormforged shieldmaiden"] = { 2, "', "Stormforged Shieldmaidens are vrykul shieldmaidens of the Valarjar found in the Assault on Broken Shore scenario, at Deliverance Point, and aboard the Vindicaar." },
  ["stormlord kao'dar"] = { 2, "worldsoul memory of a mogu located in the Isle of Dorn du...", "Stormlord Kao'dar is the worldsoul memory of a mogu located in the Isle of Dorn during  [80] Worldsoul Memory: Ancient Explorers event." },
  ["stormranger"] = { 2, "', "Stormrangers are earthen located in Flotsam Shoal and Sacred Hollow on the Siren Isle during storms." },
  ["stormranger guide"] = { 2, "', "Stormranger Guides are earthen located in Foundation Hall in Dornogal and Flotsam Shoal on the Siren Isle." },
  ["stormrider bruelda"] = { 2, "earthen located at the Keepers Terrace in Dornogal", "Stormrider Bruelda is an earthen located at the Keepers Terrace in Dornogal. A Stormrook is behind her." },
  ["stormrider cadet"] = { 2, "', "Stormrider Cadets are earthen located at the Rookery Landing and Stormrider Barracks in the Rookery. Some have been slain by the skardyn that are attacking the place and by Stormguard Gorren in Crashing Storm Hall." },
  ["stormrider edeltrau"] = { 2, "member of the Stormriders", "Stormrider Edeltrau is a member of the Stormriders. She was wounded in a battle and can be found recovering in Dornogal." },
  ["stormrider hunfrid"] = { 2, "member of the Stormriders", "Stormrider Hunfrid is a member of the Stormriders. He was wounded in a battle and can be found recovering in Dornogal." },
  ["stormrider meirand"] = { 2, "member of the Stormriders", "Stormrider Meirand is a member of the Stormriders. She took part in the defense of Dornogal against the nerubian forces who were seeking to destroy the Coreway." },
  ["stormscale myrmidon"] = { 2, "', "Stormscale Myrmidons were naga located at Ruins of Mathystra in Darkshore prior to the Shattering." },
  ["stormspeaker qian"] = { 2, "apparent leader of the Rajani mogu", "Stormspeaker Qian is the apparent leader of the Rajani mogu, located in the Vale of Eternal Blossoms' Silent Sanctuary next to Ra-den's throne. He leads the defense of the Vale against the invading mantid, mogu, and forces of the Black Empire." },
  ["stormspire nexus-guard"] = { 2, "', "Stormspire Nexus Guards are ethereal guards located at the Stormspire in the Netherstorm." },
  ["storul heavystone"] = { 2, "drogbar located in Zaralek Cavern", "Storul Heavystone is a drogbar located in Zaralek Cavern." },
  ["storykeeper ashekh"] = { 2, "centaur renown envoy of the Maruuk Centaur in Morqut Vill...", "Storykeeper Ashekh is the centaur renown envoy of the Maruuk Centaur in Morqut Village of the Forbidden Reach." },
  ["storykeeper jaru"] = { 2, "centaur of Clan Teerai located in the center of Maruukai ...", "Storykeeper Jaru is a centaur of Clan Teerai located in the center of Maruukai in the Ohn'ahran Plains, where he offers to tell stories of the Maruuk's early history. Gathered in front of him is a small audience consisting of Fureng, an Ohn'ir Ini..." },
  ["storykeeper yul"] = { 2, "centaur located in southeastern Teerakai in the Ohn'ahran...", "Storykeeper Yul is a centaur located in southeastern Teerakai in the Ohn'ahran Plains." },
  ["strap bucklebolt"] = { 2, "', "Strap Bucklebolt can be found in the Circle of Wills in Dalaran. It is currently unknown if he survived Dalaran's destruction." },
  ["strategist ankor"] = { 2, "draenei located in Shattrath City in Talador", "Strategist Ankor is a draenei located in Shattrath City in Talador." },
  ["strategist palladia"] = { 2, "Forsworn kyrian located at the Court of Elation in Bastion", "Strategist Palladia is a Forsworn kyrian located at the Court of Elation in Bastion." },
  ["strategist ta'drom"] = { 2, "broker located at Transfer Station Ta in Bastion", "Strategist Ta'drom is a broker located at Transfer Station Ta in Bastion." },
  ["strategist zo'rak"] = { 2, "broker located in the Enclave in Oribos", "Strategist Zo'rak is a broker located in the Enclave in Oribos. Members of Cartel Zo have a keen interest in observing mortals in combat." },
  ["stratios"] = { 2, "kyrian located in western Bastion", "Stratios is a kyrian located in western Bastion. This section concerns content related to The War Within." },
  ["strider ahu"] = { 2, "ankoan of the Waveblade clan 'who braved the currents of ...", "Strider Ahu was an ankoan of the Waveblade clan 'who braved the currents of distant depths.' They lie buried at an Ankoan Burial Shrine in Thoras'tal Spire in Nazjatar." },
  ["strider cuyler"] = { 2, "vrykul located on the cliffs in southern Stormheim", "Strider Cuyler is a vrykul located on the cliffs in southern Stormheim." },
  ["striker ga'dok"] = { 2, "second boss of Gate of the Setting Sun", "Striker Ga'dok is the second boss of Gate of the Setting Sun." },
  ["stromgarde cavalryman"] = { 2, "', "Stromgarde Cavalrymen are the knights of Stromgarde." },
  ["stromgarde citizen (undead)"] = { 2, "', "Stromgarde Citizens are undead located in Stromgarde Keep in the Arathi Highlands during the   [10-45] The Ruined Kingdom questline. They are initially friendly to the player, but turn hostile after Galen Trollbane betrays the player following the..." },
  ["stromgarde defender"] = { 2, "', "Stromgarde Defenders are humans found in Stromgarde Keep in the Arathi Highlands. This section concerns content related to Legion." },
  ["stromgarde troll hunter"] = { 2, "', "Stromgarde Troll Hunters are humans found in Stromgarde Keep in the Arathi Highlands. They are carrying torches, likely because (magical) fire can prevent trolls from regenerating their wounds." },
  ["stronghoof gentlebend"] = { 2, "tauren Blacksmithing vendor located at the Cenarion Wildl...", "Stronghoof Gentlebend is a tauren Blacksmithing vendor located at the Cenarion Wildlands in Desolace." },
  ["stuart"] = { 2, "venthyr located in Darkhaven in Revendreth", "Stuart is a venthyr located in Darkhaven in Revendreth." },
  ["studious drakewatcher"] = { 2, "', "Studious Drakewatchers are dracthyr, orcs, night elves, dwarves, and tauren located in Valdrakken." },
  ["studious scholar"] = { 2, "', "Studious Scholars are dragons and dracthyr in visage form located at Algeth'ar Academy in Thaldraszus." },
  ["stuffy socialite"] = { 2, "Veiled Market in K'aresh", "Stuffy Socialites are brokers located in Tazavesh, the Veiled Market in K'aresh." },
  ["stygian abductor"] = { 2, "', "Stygian Abductors are Mawsworn kyrian located in the Maw. Players who have reached rank four of Eye of the Jailer will have these units spawn randomly, without warning." },
  ["stygian abductor (sanctum of domination)"] = { 2, "', "Stygian Abductors are Mawsworn kyrian located in the Sanctum of Domination during the fight against the Eye of the Jailer." },
  ["subdued kobold"] = { 2, "', "Subdued Kobolds are kobolds located at Stonetalon Mountains, they were formerly members of the Boulderslide group." },
  ["subjugator gormal"] = { 2, "Gormali mogu", "Subjugator Gormal is a Gormali mogu who subjugates the Captured Nectarbreeze Farmers. He's later slain during  [10-35] Maul Gormal with the assistance of Shao the Defiant along with the Nectarbreeze Militia by applying  Taunted to take 300% more d..." },
  ["subjugator zheng"] = { 2, "mogu located in Warport Rastari in Zuldazar", "Subjugator Zheng is a mogu located in Warport Rastari in Zuldazar. He is a depraved slaver." },
  ["suen"] = { 2, "mogu located in the Throne of Thunder", "Suen is a mogu located in the Throne of Thunder." },
  ["sufaadi bladetamer"] = { 2, "', "Sufaadi Bladetamers are ethereals located in North Sufaad on K'aresh." },
  ["sufaadi enforcer"] = { 2, "', "Sufaadi Enforcers are ethereals that wander North Sufaad on K'aresh. They can only be seen while Phase Diving." },
  ["sufaadi headhunter"] = { 2, "', "Sufaadi Headhunters are ethereals that wander North Sufaad on K'aresh. They can only be seen while Phase Diving." },
  ["sufaadi soulbinder"] = { 2, "', "Sufaadi Soulbinders are ethereals located in North Sufaad on K'aresh." },
