  ["sufran"] = { 2, "broker vendor found near Eco-Dome: Primus in K'aresh", "Sufran is a broker vendor found near Eco-Dome: Primus in K'aresh." },
  ["sulik'shor"] = { 2, "rare mogu found outside the entrance to the Cavern of End...", "Sulik'shor is a rare mogu found outside the entrance to the Cavern of Endless Echoes in Valley of the Four Winds. He is a pandarian champion." },
  ["sully balloo"] = { 2, "dwarven soldier with much faith in his missions", "Sully Balloo was a dwarven soldier with much faith in his missions, stationed in Dun Modr. He and his unit were dispatched to watch over the Thandol Span." },
  ["sum'latha"] = { 2, "nerubian found in the Silken Ward", "Sum'latha is a nerubian found in the Silken Ward." },
