  ["summoned cabal deathsworn"] = { 2, "', "Summoned Cabal Deathsworns are orcs and Broken located throughout Shadow Labyrinth." },
  ["summoner binsley"] = { 2, "goblin", "Summoner Binsley is a goblin." },
  ["summoner marcelis"] = { 2, "venthyr located in Cinderwall in Revendreth", "Summoner Marcelis is a venthyr located in Cinderwall in Revendreth." },
  ["summoner mepjila"] = { 2, "naga sea witch", "Summoner Mepjila was a naga sea witch, a champion of Queen Azshara, and the leader of an army of naga invaders that attacked the temple of the loa Eraka no Kimbul in Vol'dun centuries ago. Kimbul's followers fought bravely, but the loa arrived too..." },
  ["summoner siavass"] = { 2, "naga located in the Sundered Temple in Zuldazar", "Summoner Siavass is a naga located in the Sundered Temple in Zuldazar." },
  ["summoner ta'xach"] = { 2, "broker located at Transfer Station Ta in Bastion", "Summoner Ta'xach is a broker located at Transfer Station Ta in Bastion." },
  ["sun-sage chakkis"] = { 2, "arakkoa quest giver located at the Aktar's Post in Tanaan...", "Sun-Sage Chakkis is an arakkoa quest giver located at the Aktar's Post in Tanaan Jungle." },
  ["sun-sage kairyx"] = { 2, "arakkoa located in Aruuna in Talador", "Sun-Sage Kairyx is an arakkoa located in Aruuna in Talador." },
  ["sun-sage rathyx"] = { 2, "arakkoa in Skettis in the Spires of Arak", "Sun-Sage Rathyx is an arakkoa in Skettis in the Spires of Arak." },
  ["sun-talon oberyx"] = { 2, "arakkoa found within the Ravager Den in the Undergrowth o...", "Sun-Talon Oberyx is an arakkoa found within the Ravager Den in the Undergrowth of the Spires of Arak." },
  ["sundered ambusher"] = { 2, "', "Sundered Ambushers are dracthyr located at the Lost Atheneum in the Forbidden Reach. Many are found dead during  [70] Creche Fallen, making it obvious that the Scalecommander Emberthal's talons did not go down without a fight." },
  ["sundered defender"] = { 2, "', "Sundered Defenders are dracthyr located in Nal ks'kol and Sundered Flame Camp in Zaralek Cavern." },
  ["sundered despoiler"] = { 2, "', "Sundered Despoilers are dracthyr located at Talonlords' Perch in the Forbidden Reach." },
  ["sundered devastator"] = { 2, "Shadowed Crucible", "Sundered Devastators are dracthyr located at the Blazing Bulwark in Aberrus, the Shadowed Crucible." },
  ["sundered fanatic"] = { 2, "', "Sundered Fanatics are dracthyr located on Dragonskull Island in the Forbidden Reach. They are found kneeling before Scalecommander Sarkareth during  [70] A Creche Divided." },
  ["sundered mender"] = { 2, "', "Sundered Menders are dracthyr located in Sundered Flame Camp in Zaralek Cavern." },
  ["sundered pillager"] = { 2, "', "Sundered Pillagers are dracthyr located in the High Creche in the Forbidden Reach." },
