  ["sundered researcher"] = { 2, "', "Sundered Researchers are dracthyr located in Sundered Flame Camp in Zaralek Cavern." },
  ["sundered ruinstalker"] = { 2, "', "Sundered Ruinstalkers are dracthyr located in the High Creche in the Forbidden Reach." },
