  ["sundered shadetalon"] = { 2, "', "Sundered Shadetalons are dracthyr located in Dragonscale Basecamp in the Waking Shores and in Thaldraszus." },
  ["suniya greenhoof"] = { 2, "tauren", "Suniya Greenhoof is a tauren that sometimes visits and wanders in the Frostwall's garrison." },
  ["sunwalker atohmo"] = { 2, "tauren paladin trainer located in the Valley of Spirits i...", "Sunwalker Atohmo is a tauren paladin trainer located in the Valley of Spirits in Orgrimmar. He is an honored member of the Sunwalkers." },
  ["sunwalker chagon"] = { 2, "tauren commander of the Kor'kron during the Lion's Landin...", "Sunwalker Chagon is a tauren commander of the Kor'kron during the Lion's Landing scenario." },
  ["sunwalker cheeso"] = { 2, "tauren located at the Antonidas Memorial in Dalaran", "Sunwalker Cheeso is a tauren located at the Antonidas Memorial in Dalaran. It is currently unknown if he survived Dalaran's destruction." },
  ["sunwalker dara"] = { 2, "tauren", "Sunwalker Dara is a tauren." },
  ["sunwalker dezco"] = { 2, "prominent tauren Sunwalker", "Sunwalker Dezco is a prominent tauren Sunwalker and the chieftain of the Dawnchaser tribe. He was dispatched by Baine Bloodhoof to the myth-shrouded land of Pandaria." },
