  ["supply master broog"] = { 2, "orc general goods vendor located at the Stair of Destiny ...", "Supply Master Broog is an orc general goods vendor located at the Stair of Destiny in Hellfire Peninsula." },
  ["support officer"] = { 2, "Veiled Market", "Support Officers are brokers located in Tazavesh, the Veiled Market." },
  ["supreme general pa'valak"] = { 2, "alternate version of General Pa'valak from Azq'roth locat...", "Supreme General Pa'valak is an alternate version of General Pa'valak from Azq'roth located in Tyrhold Reservoir in Thaldraszus during Time Rifts." },
  ["sureki arbalest"] = { 2, "', "Sureki Arbalests are nerubians located in the Grand Rampart in Nerub-ar Palace." },
  ["sureki conscript"] = { 2, "', "Sureki Conscripts are nerubians located at the High Hollows in the City of Threads." },
  ["sureki harvest guard"] = { 2, "', "Sureki Harvest Guards are nerubians located in Untamed Valley in Azj-Kahet." },
