  ["sureki marauder"] = { 2, "', "Sureki Marauders are nerubians located in Mereldar in Hallowfall." },
  ["sureki militant"] = { 2, "', "Sureki Militants are nerubians located in Mereldar during The Dawnbreaker dungeon." },
  ["sureki silkbinder"] = { 2, "', "Sureki Silkbinders are nerubians located in the Umbral Bazaar in the City of Threads." },
