  ["suspicious citizen"] = { 2, "', "Suspicious Citizens were found in the Drag in Orgrimmar and in Old Town in Stormwind City during  [10-80] Avoiding Blame." },
  ["suspicious nesmin"] = { 2, "broker located in Haven in Zereth Mortis", "Suspicious Nesmin is a broker located in Haven in Zereth Mortis. After hanging around for a while, he will head north and despawn." },
  ["suspicious operative"] = { 2, "broker located in Perdition Hold in the Maw", "The Suspicious Operative is a broker located in Perdition Hold in the Maw. They draw their final breath as they tell the adventurer of the plans of Seeker Xeros." },
  ["suzie boltwrench"] = { 2, "goblin located in Krazzlefrazz Outpost in Drustvar", "Suzie Boltwrench is a goblin located in Krazzlefrazz Outpost in Drustvar. She placed bounties on local dangers threatening the goblin and Horde operations." },
  ["svala sorrowgrave"] = { 2, "vrykul", "Svala Sorrowgrave was a vrykul who had been turned into a Val'kyr by the Lich King. As uninvited guests entered her room, an image of the Lich King congratulated her for having done a great service, for she was the one who discovered the Alliance ..." },
  ["sveldrek berserker"] = { 2, "', "Sveldrek Berserkers are vrykul located in the Pit of Saron." },
  ["sveldrek tamer"] = { 2, "', "Sveldrek Tamers are vrykul located in the Pit of Saron." },
  ["svergan stormcloak"] = { 2, "vrykul warrior of the Valarjar", "Svergan Stormcloak is a vrykul warrior of the Valarjar." },
  ["swabbie ciro"] = { 2, "worgen of Keg Leg's Crew located in Brew Bay in the Arath...", "Swabbie Ciro is a worgen of Keg Leg's Crew located in Brew Bay in the Arathi Highlands during Plunderstorm. He is watching Salty Swabbies fight in the pit along with Monty the Plunderer, Botswain Ham Ton, and Swabbie Kavan." },
  ["swamp thug"] = { 2, "tortollan", "Swamp Thug is a tortollan." },
  ["swamplord musel'ek"] = { 2, "Broken hunter", "Swamplord Musel'ek is a Broken hunter, ruler of the Murkblood, and the third boss of the Underbog in Coilfang Reservoir.  He is accompanied by his pet, Claw, who is part of the quest  [10-30D] Lost in Action which can be obtained from Watcher Jhan..." },
  ["swarmguard kzaz"] = { 2, "mantid located at the Engine of Nalak'sha in Mogu'shan Va...", "Swarmguard Kzaz is a mantid located at the Engine of Nalak'sha in Mogu'shan Vaults." },
  ["swinegart spearhide"] = { 2, "rare quilboar located in Agama'gor in Southern Barrens", "Swinegart Spearhide is a rare quilboar located in Agama'gor in Southern Barrens." },
  ["syenite"] = { 2, "earthen located outside the Crafter's Enclave at the Forg...", "Syenite is an earthen located outside the Crafter's Enclave at the Forgegrounds in Dornogal." },
  ["sygfraed siegepyr"] = { 2, "Arathi located in Mereldar in Hallowfall", "Sygfraed Siegepyr is an Arathi located in Mereldar in Hallowfall. He runs the Mereldar orphanage." },
  ["sylalleas frostwind"] = { 2, "Darkfallen death knight located at the Lunarfall in Shado...", "Sylalleas Frostwind is a Darkfallen death knight located at the Lunarfall in Shadowmoon Valley." },
  ["sylla"] = { 2, "venthyr located at the Charred Ramparts in Revendreth", "Sylla is a venthyr located at the Charred Ramparts in Revendreth. She's surrounded by her three battle pets: Ash, Fang, and Swarm." },
  ["sylva darkhowl"] = { 2, "worgen located at Lunarfall in Shadowmoon Valley", "Sylva Darkhowl is a worgen located at Lunarfall in Shadowmoon Valley. She can only be recruited using the Headhunter's Harvest from Lunarfall Inn." },
  ["sylvie fallensong"] = { 2, "Darkfallen death knight follower located at the Frostwall...", "Sylvie Fallensong is a Darkfallen death knight follower located at the Frostwall in Frostfire Ridge. She can only be recruited using the Headhunter's Harvest from Frostwall Tavern." },
  ["symon corwin"] = { 2, "Arathi located in Mereldar in Hallowfall", "Symon Corwin is an Arathi located in Mereldar in Hallowfall." },
  ["synthanos wintersong"] = { 2, "Darkfallen death knight standing with Niena Bladeleaf on ...", "Synthanos Wintersong is a Darkfallen death knight standing with Niena Bladeleaf on the eastern edge of Oribos." },
  ["syreian the bonecarver"] = { 2, "rare elite vrykul wandering around eastern Grizzly Hills", "\"The Lich King promised that more prey would eventually make their way to Northrend. How lucky for me.\" Syreian the Bonecarver is a rare elite vrykul wandering around eastern Grizzly Hills." },
  ["syth"] = { 2, "arakkoa slain by the Adherents of Rukhmar", "Syth is an arakkoa slain by the Adherents of Rukhmar. He had located  [The Eye of Anzu] and hidden it away, and the  [The Saga of Terokk] is located in his bookcase." },
  ["syzslack"] = { 2, "tortollan located at Anchors Down in Stormsong Valley", "Syzslack is a tortollan located at Anchors Down in Stormsong Valley." },
  ["ta'choso"] = { 2, "broker located in the Hall of Holding in Oribos", "Ta'choso is a broker located in the Hall of Holding in Oribos. He sells Sanctum of Domination equipment in exachange for a  [Puzzling Cartel Dinar], an item that was only available during Shadowlands Season 4." },
  ["ta'dal"] = { 2, "broker vendor found in Overlook Zo'Shuul in K'aresh", "Ta'dal is a broker vendor found in Overlook Zo'Shuul in K'aresh." },
  ["ta'elfar"] = { 2, "broker located in the Enclave in Oribos near Bolvar Fordr...", "Ta'elfar is a broker located in the Enclave in Oribos near Bolvar Fordragon and Tal-Inara. He allows queuing for Shadowlands raids in Raid Finder difficulty." },
  ["ta'eran"] = { 2, "broker quest giver initially located just inside the sout...", "Ta'eran is a broker quest giver initially located just inside the southwestern entrance to the Sepulcher of Knowledge in Maldraxxus. He enlists adventurers to help him gain access to the Sepulcher, claiming that it is so he can safeguard the milit..." },
  ["ta'hsup"] = { 2, "broker located in the Hall of Holding in Oribos", "Ta'hsup is a broker located in the Hall of Holding in Oribos and at the end of each Mythic+ World of Warcraft: Shadowlands dungeons." },
  ["ta'ilh"] = { 2, "broker located in Mythic+ dungeons", "Ta'ilh is a broker located in Mythic+ dungeons." },
  ["ta'ka"] = { 2, "broker located in Tazavesh", "Ta'ka is a broker located in Tazavesh, the Veiled Market. He is a supplier of rare creatures destined to repopulate K'aresh." },
  ["ta'kil the resonator"] = { 2, "mantid", "Ta'kil the Resonator is a mantid that can be encountered during in Island Expeditions." },
  ["ta'lan the antiquary"] = { 2, "broker located in the Broker's Den in Oribos", "Ta'lan the Antiquary is a broker located in the Broker's Den in Oribos. He sends Maw Walkers on quests to collect various curious objects from around the Shadowlands." },
  ["ta'leesa"] = { 2, "broker located with Ta'speri on either side of a portal j...", "Ta'leesa is a broker located with Ta'speri on either side of a portal just past Tazavesh Customs Enforcement in Tazavesh, the Veiled Market." },
  ["ta'lora"] = { 2, "broker of Cartel Ta", "Ta'lora, formerly called Lora, is a broker of Cartel Ta and the in-universe author of the Grimoire of the Shadowlands and Beyond. After learning of Cartel Ve's expedition to the Maw and of how Ve'nari betrayed her fellows in order to monopolize co..." },
  ["ta'mari"] = { 2, "broker located in Oribos", "Ta'mari is a broker located in Oribos. She can be seen talking to various brokers around the city and seemingly acting as a liaison between members of Cartel Ta and members of Cartel Ba." },
  ["ta'meri"] = { 2, "broker located on the outer ring of Oribos to the south west", "Ta'meri is a broker located on the outer ring of Oribos to the south west. She will send players to Tazavesh, the Veiled Market after completing  [60] Coins for the Ferryman, part of the quest chain to unlock the dungeon." },
  ["ta'nasi"] = { 2, "broker located in the Keeper's Respite of Korthia", "Ta'nasi is a broker located in the Keeper's Respite of Korthia. Cartel Ta has quietly spread observational devices all across the realm for the purpose of collecting information." },
  ["ta'nla the identifier"] = { 2, "broker located at the Night Market in Revendreth", "Ta'nla the Identifier is a broker located at the Night Market in Revendreth. A group of Redelav Fencers is waiting in line to order equipment." },
  ["ta'piks"] = { 2, "broker located in Tazavesh", "Ta'piks is a broker located in Tazavesh, the Veiled Market. He was also found at the Ring of Transference in Oribos during Shadowlands Season 4, where he maintained portals to Gorgrond, Karazhan and Mechagon." },
  ["ta'rant"] = { 2, "broker innkeeper located at Overlook Zo'Shuul on K'aresh", "Ta'rant is a broker innkeeper located at Overlook Zo'Shuul on K'aresh." },
  ["ta'resarra"] = { 2, "broker flight master located at the docks of Tazavesh", "Ta'resarra is a broker flight master located at the docks of Tazavesh, the Veiled Market." },
  ["ta'rex"] = { 2, "broker located just past Tazavesh Customs Enforcement in ...", "Ta'rex is a broker located just past Tazavesh Customs Enforcement in Tazavesh, the Veiled Market." },
  ["ta'rmoro"] = { 2, "broker located at the Night Market in Revendreth", "Ta'rmoro is a broker located at the Night Market in Revendreth. A group of Redelav Fencers are waiting in line to order equipment." },
  ["ta'ruca"] = { 2, "broker located at the Night Market in Revendreth", "Ta'ruca is a broker located at the Night Market in Revendreth." },
  ["ta'sam"] = { 2, "broker located just past Tazavesh Customs Enforcement in ...", "Ta'sam is a broker located just past Tazavesh Customs Enforcement in Tazavesh, the Veiled Market. She keeps this same location after Tazavesh's relocation to K'aresh." },
  ["ta'speri"] = { 2, "broker located with Ta'leesa on either side of a portal j...", "Ta'speri is a broker located with Ta'leesa on either side of a portal just past Tazavesh Customs Enforcement in Tazavesh, the Veiled Market." },
  ["ta'switch"] = { 2, "broker located in Oribos on Tournament Realms", "Ta'switch is a broker located in Oribos on Tournament Realms. They help Characters to switch covenant." },
  ["ta'tru"] = { 2, "broker barterer located at the Night Market in Revendreth", "Ta'tru is a broker barterer located at the Night Market in Revendreth." },
  ["ta'ules"] = { 2, "broker located just past Tazavesh Customs Enforcement in ...", "Ta'ules is a broker located just past Tazavesh Customs Enforcement in Tazavesh, the Veiled Market." },
  ["ta'vini"] = { 2, "broker", "Ta'vini is a broker. Occasionally he'll appear through the portal in the Hall of Curiosities in Oribos." },
  ["ta'xera"] = { 2, "broker located at the Night Market in Revendreth", "Ta'xera is a broker located at the Night Market in Revendreth. She ran the Black Market Auction House in the Shadowlands during the war against the Jailer." },
  ["ta'xor"] = { 2, "broker located in Tazavesh's Bazaar of Tangible Delights ...", "Ta'xor is a broker located in Tazavesh's Bazaar of Tangible Delights on K'aresh. He disappears when the Shadowguard incursion on the city begins." },
  ["ta'ylor"] = { 2, "broker belonging to Cartel Ta", "Ta'ylor is a broker belonging to Cartel Ta. She is a legendary Myza's Oasis act." },
  ["taal blevaans"] = { 2, "draenei flight master located at the Iron Docks in Gorgrond", "Taal Blevaans is a draenei flight master located at the Iron Docks in Gorgrond." },
  ["tabaanu"] = { 2, "Broken located in the Trader's Tier in the Exodar during ...", "Tabaanu is a Broken located in the Trader's Tier in the Exodar during the draenei heritage questline. He brought with him several Tamed Marsuul." },
  ["tabelius"] = { 2, "elf", "Tabelius was an elf that was training to become a demon hunter. While he survived the first part of the ritual, he was driven mad and sliced throats of several of his fellow trainees as they slept." },
  ["tacha"] = { 2, "vulpera quest giver located on the western outskirts of t...", "Tacha is a vulpera quest giver located on the western outskirts of the Court of Zak'rajan in Vol'dun alongside Kenzou and Omi. She claims to have sacked countless ruins across Vol'dun, from saurolisk dens to the Port of Zem'lan, and has survived b..." },
  ["tactical mender"] = { 2, "', "Tactical Menders are dracthyr found in Stormsunder Crater outside the Siege Creche in the Forbidden Reach." },
  ["tactical officer ahbramis"] = { 2, "', "Tactical Officer Ahbramis can be found in Wintergrasp. He is riding a  [Blue Mechanostrider]." },
  ["tad deepforge"] = { 2, "dwarf located at the Alliance encampment at the outskirts...", "Tad Deepforge is a dwarf located at the Alliance encampment at the outskirts of the Ruins of Lordaeron during Battle for Lordaeron." },
  ["tadi embertotem"] = { 2, "tauren located in Stormsong Valley", "Tadi Embertotem is a tauren located in Stormsong Valley." },
  ["taellyn"] = { 2, "dracthyr found speaking with Claretta in the Victorious V...", "Taellyn is a dracthyr found speaking with Claretta in the Victorious Visage in Valdrakken during  [70] Who Are You?." },
  ["taenar strongoth"] = { 2, "Arathi located in Velhan's Claim in Hallowfall", "Taenar Strongoth is an Arathi located in Velhan's Claim in Hallowfall. In the past, he served on the Indomitable and Duke Velhan was his captain." },
  ["taener duelmal"] = { 2, "Arathi located at Sanctified Grounds in the Priory of the...", "Taener Duelmal is an Arathi located at Sanctified Grounds in the Priory of the Sacred Flame." },
  ["taerlina"] = { 2, "kyrian located at Hero's Rest in Bastion", "Taerlina is a kyrian located at Hero's Rest in Bastion who sells inscription supplies. She was part of the reception the Archon arranged for a Maw Walker, who decided to join the Kyrian Covenant, in honor of their efforts against the Maldraxxus in..." },
  ["taerry bilgestone"] = { 2, "human located in Stillstone Pond in Hallowfall", "Taerry Bilgestone is a human located in Stillstone Pond in Hallowfall." },
  ["tagar (warcraft iii)"] = { 2, "', "Tagar is Cairne Bloodhoof's second in command. He appears in the mission Old Hatreds." },
  ["tagar bloodhoof"] = { 2, "', "Tagar Bloodhoof served as Cairne Bloodhoof's faithful second in command and currently serves as the leader of the tauren within Toghusuq Village." },
  ["tahli"] = { 2, "broker located in Zereth Mortis", "Tahli is a broker located in Zereth Mortis." },
  ["taintheart befouler"] = { 2, "', "Taintheart Befoulers are satyrs located in the Clutch of Corruption in the Emerald Nightmare." },
  ["taintheart deadeye"] = { 2, "', "Taintheart Deadeyes are satyrs located in Darkheart Thicket." },
  ["taintheart stalker"] = { 2, "', "Taintheart Stalkers are satyrs located in Darkheart Thicket." },
  ["taintheart summoner"] = { 2, "', "Taintheart Summoners are satyrs located in Darkheart Thicket." },
