  ["taintheart trickster"] = { 2, "', "Taintheart Tricksters are satyrs located in the Clutch of Corruption in the Emerald Nightmare." },
  ["taiyata"] = { 2, "vulpera located at the Bloom in Razorwind Shores", "Taiyata is a vulpera located at the Bloom in Razorwind Shores. She is sitting around a campfire with Seniku, Akuta, and Itsero." },
  ["takata"] = { 2, "tortollan located at Scaletrader Post in Zuldazar", "Takata is a tortollan located at Scaletrader Post in Zuldazar." },
  ["taken drogbar"] = { 2, "', "Taken Drogbar are drogbar located in the Echoing Halls of Highmountain." },
  ["takubvik"] = { 2, "tuskarr general goods vendor located in the Moa'ki Harbor...", "Takubvik is a tuskarr general goods vendor located in the Moa'ki Harbor in the Dragonblight." },
  ["tal'ana"] = { 2, "tuskarr food vendor located in Boralus Harbor in Boralus", "Tal'ana is a tuskarr food vendor located in Boralus Harbor in Boralus." },
  ["talah blightspewer"] = { 2, "orc located in Arathi Basin during Brawl: Comp Stomp for ...", "Talah Blightspewer is an orc located in Arathi Basin during Brawl: Comp Stomp for Alliance players." },
  ["talanis nightsbane"] = { 2, "Darkfallen located in Twilight Watchtower in Amirdrassil", "Talanis Nightsbane is a Darkfallen located in Twilight Watchtower in Amirdrassil." },
  ["talia direhorn"] = { 2, "tauren PvP quartermaster in Windrunner's Sanctuary in Dal...", "Talia Direhorn is a tauren PvP quartermaster in Windrunner's Sanctuary in Dalaran who sells PvP items consumables. It is currently unknown if she survived Dalaran's destruction." },
  ["taljori"] = { 2, "tortollan vendor located in Flotsam Shoal on the Siren Isle", "Taljori is a tortollan vendor located in Flotsam Shoal on the Siren Isle." },
  ["tally berryfizz"] = { 2, "gnome alchemy trainer located in the shop Berryfizz's Pot...", "Tally Berryfizz is a gnome alchemy trainer located in the shop Berryfizz's Potions and Mixed Drinks in Tinker Town within Ironforge." },
  ["talon arrosh"] = { 2, "dracthyr located in the Forbidden Reach", "Talon Arrosh is a dracthyr located in the Forbidden Reach. He and his fellow scouts traveled from Morqut Village with Scalecommander Emberthal to the Lost Atheneum." },
  ["talon damos"] = { 2, "dracthyr located in the Forbidden Reach", "Talon Damos is a dracthyr located in the Forbidden Reach. He and his fellow scouts traveled from Morqut Village with Scalecommander Emberthal to the Lost Atheneum." },
  ["talon ekrati"] = { 2, "dracthyr located in the Forbidden Reach", "Talon Ekrati is a dracthyr located in the Forbidden Reach. She and her fellow scouts traveled from Morqut Village with Scalecommander Emberthal to the Lost Atheneum." },
  ["talon guard kurekk"] = { 2, "arakkoa", "Talon Guard Kurekk is an arakkoa. He can be recruited into garrison and become bodyguard." },
  ["talon guard teth"] = { 2, "arakkoa found in the Town Hall in Stormshield", "Talon Guard Teth is an arakkoa found in the Town Hall in Stormshield." },
  ["talon guard varook"] = { 2, "arakkoa found in the Town Hall in Stormshield", "Talon Guard Varook is an arakkoa found in the Town Hall in Stormshield." },
  ["talon hermin"] = { 2, "dracthyr located in the Forbidden Reach", "Talon Hermin is a dracthyr located in the Forbidden Reach. He and his fellow scouts traveled from Morqut Village with Scalecommander Emberthal to the Lost Atheneum." },
  ["talon kethahn"] = { 2, "dracthyr found dead in his bed in the War Creche on the F...", "Talon Kethahn is a dracthyr found dead in his bed in the War Creche on the Forbidden Reach." },
  ["talon king ikiss"] = { 2, "boss of Sethekk Halls in Auchindoun", "Talon King Ikiss (/ˈaɪ.kɪs/ EYE-kiss), the boss of Sethekk Halls in Auchindoun, is one of the leaders of the Sethekk, along with Darkweaver Syth. Together, they led the exodus of the Sethekk from Skettis to the ruins of Auchindoun." },
  ["talon king ikiss (alternate universe)"] = { 2, "leader of the Sethekk", "Ikiss is the leader of the Sethekk, a cult of arakkoa who worship the dead god Sethe, the very same being who cursed them into their broken, flightless state. Ikiss is obsessed with the ancient arakkoa king Terokk, and has gone as far as to give h..." },
  ["talon mender"] = { 2, "', "Talon Menders are dracthyr found at the Caldera of the Menders and the Old Weyrn Grounds on the Forbidden Reach." },
  ["talon rommen"] = { 2, "dracthyr located in Dragonscale Basecamp in the Waking Sh...", "Talon Rommen is a dracthyr located in Dragonscale Basecamp in the Waking Shores and in Weyrnrest in Valdrakken." },
  ["talon scaralesh"] = { 2, "dracthyr located at the Dragonscale Basecamp in the Wakin...", "Talon Scaralesh is a dracthyr located at the Dragonscale Basecamp in the Waking Shores. He and his brother, Rommen were trying to cook up some rations to eat, but everything was so different to them, and they found it hard to find the same ingredi..." },
  ["talon tetsos"] = { 2, "dracthyr located in the Forbidden Reach", "Talon Tetsos is a dracthyr located in the Forbidden Reach. He and his fellow scouts traveled from Morqut Village with Scalecommander Emberthal to the Lost Atheneum." },
  ["talonpriest ishaal (alternate universe)"] = { 2, "', "Talonpriest Ishaal can be found in Ishaal's Hut in Spires of Arak. After he assisted in bringing Terokk back, he joins the adventurers as their follower." },
  ["talonpriest vizrak"] = { 2, "arakkoa caged up at the Ironhold Harbor‎ in Tanaan Jungle", "Talonpriest Vizrak is an arakkoa caged up at the Ironhold Harbor‎ in Tanaan Jungle." },
  ["talonpriest zellek"] = { 2, "', "Talonpriest Zellek can be found at Skettis in Terokkar Forest in the west part of the Blackwind Lake at the highest top of the treehouse village. He can only be fought under the effects of  [Elixir of Shadows]." },
  ["talonpriest zellek (alternate universe)"] = { 2, "', "Talonpriest Zellek can be found in Zellek's Hut in the Spires of Arak." },
  ["talonpriest zorkra"] = { 2, "arakkoa located at Zorkra's Fall in Talador", "Talonpriest Zorkra is an arakkoa located at Zorkra's Fall in Talador. She was apparently killed by the orcs just as she and her followers made it into Talador." },
  ["talvash del kissel"] = { 2, "gnome quest giver located in the Mystic Ward in Ironforge", "Talvash del Kissel is a gnome quest giver located in the Mystic Ward in Ironforge. He was a jeweler in Gnomeregan, but after the city fell and some rumors started about him he fell into debt." },
  ["talvfrida"] = { 2, "earthen located in the Great Forge in Ironforge", "Talvfrida is an earthen located in the Great Forge in Ironforge." },
  ["tamelyn aldridge"] = { 2, "human vendor located in the Commons in Ironforge", "Tamelyn Aldridge is a human vendor located in the Commons in Ironforge." },
  ["tamer korgrul"] = { 2, "drogbar responsible for turning the fledgling rockcrawler...", "Tamer Korgrul is a drogbar responsible for turning the fledgling rockcrawlers of the Rockcrawler Chasm in Highmountain into the monstrous siege worms that the drogbar ride into battle. Oren Windstrider wants him killed." },
  ["tamer orami"] = { 2, "ankoan stable master located in Mezzamere in Nazjatar", "Tamer Orami is an ankoan stable master located in Mezzamere in Nazjatar." },
  ["tamesis"] = { 2, "kyrian aspirant located near the entrance to the Garden o...", "Tamesis is a kyrian aspirant located near the entrance to the Garden of Respite, in Bastion. Next to her are a Cloudrift Runner, River Terrapin, and Fluttering Glimmerfly." },
  ["tamra"] = { 2, "broker located in Haven in Zereth Mortis", "Tamra is a broker located in Haven in Zereth Mortis." },
  ["tana lentner"] = { 2, "worgen engineering trainer located in the Craftsmen's Ter...", "Tana Lentner is a worgen engineering trainer located in the Craftsmen's Terrace in Darnassus. She's most likely related to fellow engineering supplies vendor Hugo Lentner." },
  ["tanaika"] = { 2, "tuskarr Kalu'ak faction awards vendor found at Kamagua in...", "Tanaika is a tuskarr Kalu'ak faction awards vendor found at Kamagua in the Howling Fjord." },
  ["tanda freeseeker"] = { 2, "tauren sleeping next to Bax Freeseeker in a hut just east...", "Tanda Freeseeker is a tauren sleeping next to Bax Freeseeker in a hut just east of the upper level of Thunder Totem in Highmountain. Marcus the paladin can be found sleeping next to them, though upon approach he wakes up and walks out of the hut, ..." },
  ["taneqi"] = { 2, "tuskarr located at the Hissing Grotto in the Waking Shores", "Taneqi is a tuskarr located at the Hissing Grotto in the Waking Shores. She is sitting next to Meekoo." },
  ["tanner au'qil"] = { 2, "broker located in the Hall of Shapes in Oribos", "Tanner Au'qil is a broker located in the Hall of Shapes in Oribos. He teaches Maw Walkers about Shadowlands Leatherworking crafts." },
  ["tanqin"] = { 2, "tuskarr located in Camp Nowhere in the Azure Span", "Tanqin is a tuskarr located in Camp Nowhere in the Azure Span." },
  ["tanrir"] = { 2, "Timbermaw furbolg quest giver located next to Burndl just...", "Tanrir is a Timbermaw furbolg quest giver located next to Burndl just outside of Winterfall Village." },
  ["tara steelstrike"] = { 2, "Arathi located in Mereldar in Hallowfall", "Tara Steelstrike is an Arathi located in Mereldar in Hallowfall." },
  ["taranthiza"] = { 2, "dracthyr located in the Azure Span", "Taranthiza is a dracthyr located in the Azure Span." },
  ["tareh"] = { 2, "tortollan located in Gral's Grotto in Zuldazar", "Tareh is a tortollan located in Gral's Grotto in Zuldazar. She was present during the funeral of King Rastakhan in Dazar'alor." },
  ["tareqsen"] = { 2, "centaur walking around the cooking area of Maruukai in th...", "Tareqsen is a centaur walking around the cooking area of Maruukai in the Ohn'ahran Plains. He is a former member of Clan Toghus, now tagged as a member of Clan Teerai." },
  ["tarhu the ransacker"] = { 2, "ethereal located in the Magisters' Park on the Isle of Qu...", "Tarhu the Ransacker is an ethereal located in the Magisters' Park on the Isle of Quel'Danas." },
  ["tari cogg"] = { 2, "gnome mage of the Kirin Tor", "Tari Cogg was a gnome mage of the Kirin Tor. She was known as one of the foremost gnome magi in Dalaran." },
  ["tarib"] = { 2, "earthen mining trainer located in the Forgegrounds in Dor...", "Tarib is an earthen mining trainer located in the Forgegrounds in Dornogal." },
  ["tariesh"] = { 2, "Mawsworn kyrian located in Calcis during the Escape from ...", "Tariesh is a Mawsworn kyrian located in Calcis during the Escape from the Maw. When Jaina Proudmoore and Thrall are found in Calcis by an adventurer and the Knights of the Ebon Blade, he led a squad of Mawsworn harbingers into ambushing them." },
  ["tarig"] = { 2, "earthen located in the Forgegrounds in Dornogal", "Tarig is an earthen located in the Forgegrounds in Dornogal." },
  ["tarjin the blind"] = { 2, "djaradin located at the Outcast's Alcove in the Waking Sh...", "Tarjin the Blind is a djaradin located at the Outcast's Alcove in the Waking Shores." },
  ["tarl cloudsong"] = { 2, "tauren shaman trainer located at the Bloodhoof Village in...", "Tarl Cloudsong is a tauren shaman trainer located at the Bloodhoof Village in Mulgore." },
  ["tarolekk the stomper"] = { 2, "centaur located in the Ohn'ahran Plains", "Tarolekk, the Stomper is a centaur located in the Ohn'ahran Plains." },
  ["tarralikitak"] = { 2, "tuskarr trade goods vendor found within Unu'pe in the Bor...", "Tarralikitak is a tuskarr trade goods vendor found within Unu'pe in the Borean Tundra." },
  ["taru amberplain"] = { 2, "tauren", "Taru Amberplain is a tauren." },
  ["taruk (centaur)"] = { 2, "centaur located atop the Shikaar rise in Maruukai in the ...", "Taruk is a centaur located atop the Shikaar rise in Maruukai in the Ohn'ahran Plains, where he tends to the Shikaar Ohuna. In the Nokhud Offensive, he is found standing alone on the rise and asks players to bring him ohuna eggs, which on Mythic di..." },
  ["taruka beastkiller"] = { 2, "young tuskarr fisher", "Taruka, later called Taruka Beastkiller, is a young tuskarr fisher and the titular protagonist of the short story 'One Small Tuskarr'." },
  ["tashar"] = { 2, "ethereal located in Eco-Dome Farfield in the Netherstorm", "Tashar is an ethereal located in Eco-Dome Farfield in the Netherstorm." },
  ["taskmaster askari"] = { 2, "orc located in Lucky Strike Mines in the Motherlode", "Taskmaster Askari is an orc located in Lucky Strike Mines in the Motherlode." },
  ["taskmaster banegore"] = { 2, "orc located at the Writhing Mire in Spires of Arak", "Taskmaster Banegore is an orc located at the Writhing Mire in Spires of Arak." },
  ["taskmaster filthwhisker"] = { 2, "kobold located in Echoing Halls in Highmountain", "Taskmaster Filthwhisker is a kobold located in Echoing Halls in Highmountain." },
  ["taskmaster gavril"] = { 2, "venthyr located in the Sinposium in Revendreth", "Taskmaster Gavril is a venthyr located in the Sinposium in Revendreth." },
  ["taskmaster matyas"] = { 2, "venthyr located in Feeders' Thicket", "Taskmaster Matyas is a venthyr located in Feeders' Thicket and at Witherfall Ruin in Revendreth. He fancies himself quite the connoisseur." },
  ["taskmaster skraggletail"] = { 2, "kobold located in Echoing Halls in Highmountain", "Taskmaster Skraggletail is a kobold located in Echoing Halls in Highmountain." },
  ["taskmaster snivvle"] = { 2, "Whitewhisker Kobold champion", "Taskmaster Snivvle is a Whitewhisker Kobold champion who claims the Coldtooth Mine at the beginning of every Alterac Valley battleground. He must be killed in order to claim the mine for your faction." },
  ["taskmaster veshis"] = { 2, "dracthyr", "Taskmaster Veshis is a dracthyr." },
  ["taskmaster whipfang"] = { 2, "rare gnoll found in Windshear Crag in the Stonetalon Moun...", "Taskmaster Whipfang is a rare gnoll found in Windshear Crag in the Stonetalon Mountains." },
  ["taskmaster xuexing"] = { 2, "', "Taskmaster Xuexing was one of Warlord Gurthan's commanders and was in charge of the huatang. He was eventually tricked by his rival into using the weapon against the mantid earlier than intended and died in the battle that followed." },
  ["taskmaster xy'pro"] = { 2, "broker located in Ephemeral Plains in the Sepulcher of th...", "Taskmaster Xy'pro is a broker located in Ephemeral Plains in the Sepulcher of the First Ones. They will drop a  [Security Override Orb] if killed with three stacks of the Synergy buff." },
  ["tata"] = { 2, "tuskarr child located on a boat in Kauriq Gleamlet in the...", "Tata is a tuskarr child located on a boat in Kauriq Gleamlet in the Azure Span." },
  ["tatia brine"] = { 2, "worgen fishing vendor found on the Darkmoon Boardwalk of ...", "Tatia Brine is a worgen fishing vendor found on the Darkmoon Boardwalk of Darkmoon Island." },
  ["tattertail"] = { 2, "kobold located in Skittering Hollow", "Tattertail is a kobold located in Skittering Hollow." },
  ["tatto"] = { 2, "tuskarr stable master located in Iskaara in the Azure Span", "Tatto is a tuskarr stable master located in Iskaara in the Azure Span." },
  ["tattukiaka"] = { 2, "tuskarr ottuk mount vendor located in Iskaara in the Azur...", "Tattukiaka is a tuskarr ottuk mount vendor located in Iskaara in the Azure Span." },
  ["tavar"] = { 2, "young night elf rogue", "Tavar was a young night elf rogue who participated in the War of the Thorns. He could take lives, and had, and was highly skilled at disguising himself as other races and working with the shadows." },
  ["tavern enthusiast"] = { 2, "', "Tavern Enthusiasts are many drinkers that travel with Tipsi and Anebria around the world. They can be of many peculiar races and origins, including: Scarlet Crusade undead." },
  ["tavern patron"] = { 2, "', "Tavern Patrons are goblins, tortollans and Zandalari trolls located in Torga's Tavern in Nazmir." },
  ["tavian"] = { 2, "venthyr innkeeper located in Sinfall in Revendreth", "Tavian is a venthyr innkeeper located in Sinfall in Revendreth." },
  ["tavid blightsteel"] = { 2, "dwarf located at the Lunarfall in Shadowmoon Valley", "Tavid Blightsteel is a dwarf located at the Lunarfall in Shadowmoon Valley. He can only be recruited using the Headhunter's Harvest from Lunarfall Inn." },
  ["tavio"] = { 2, "tuskarr located in Iskaara in the Azure Span", "Tavio is a tuskarr located in Iskaara in the Azure Span. She can craft Tuskarr Fishing Gear." },
  ["tavru akua"] = { 2, "tuskarr featured in series 4 of DC Direct's line of World...", "Tavru Akua is a tuskarr featured in series 4 of DC Direct's line of World of Warcraft action figures. He has not appeared in any other media." },
  ["tawroa"] = { 2, "haranir located in the Den in Harandar", "Tawroa is a haranir located in the Den in Harandar." },
  ["tazavesh enforcer"] = { 2, "Veiled Market in K'aresh", "Tazavesh Enforcers are brokers located in Tazavesh, the Veiled Market in K'aresh." },
  ["tazavesh security"] = { 2, "Veiled Market in K'aresh", "Tazavesh Security are brokers located in Tazavesh, the Veiled Market in K'aresh." },
  ["tea tester"] = { 2, "', "Tea Testers are bronze dragons, green dragons, blue dragons, draenei, Forsaken, goblins, and vulpera located at Cascade's Edge in Valdrakken. They help Lord Sinensus with his tests." },
  ["teacher zas'rush"] = { 2, "nerubian located in the Silken Ward in Azj-Kahet", "Teacher Zas'rush is a nerubian located in the Silken Ward in Azj-Kahet." },
  ["tech scavenger"] = { 2, "', "Tech Scavengers are goblins, ogres, and gnolls located on Mechagon Island." },
  ["technician braggle"] = { 2, "gnome quest giver found near the decontamination area of ...", "Technician Braggle is a gnome quest giver found near the decontamination area of uninstanced Gnomeregan." },
  ["technician dyvuun"] = { 2, "draenei quest ender located at Azure Watch in Azuremyst Isle", "Technician Dyvuun is a draenei quest ender located at Azure Watch in Azuremyst Isle. His image appears in Ammen Vale after  [1-10] The Emitter." },
  ["technician om'latif"] = { 2, "broker located at the Atrium on K'aresh", "Technician Om'latif is a broker located at the Atrium on K'aresh." },
  ["teddo bridgeblaster"] = { 2, "goblin located in the Incontinental Hotel in the Undermine", "Teddo Bridgeblaster is a goblin located in the Incontinental Hotel in the Undermine." },
  ["teego"] = { 2, "vulpera stable master located at the Vulpera Hideaway in ...", "Teego is a vulpera stable master located at the Vulpera Hideaway in Vol'dun." },
  ["teekcha"] = { 2, "tortollan quest giver located outside the Temple of Kimbu...", "Teekcha is a tortollan quest giver located outside the Temple of Kimbul in Vol'dun, along with Tulu." },
  ["teerai battlemaster"] = { 2, "', "Teerai Battlemasters are centaur located in the Ohn'ahran Plains." },
  ["teerai chef"] = { 2, "centaur standing next to a campfire in northeastern Teera...", "The Teerai Chef is a centaur standing next to a campfire in northeastern Teerakai in the Ohn'ahran Plains, alongside Alli and two Iskaara Traders. He is locked in an argument with one of the Traders about the advantages (or disadvantages) of centa..." },
  ["teerai fisher"] = { 2, "centaur found at the river northeast of Teerakai in the O...", "The Teerai Fisher is a centaur found at the river northeast of Teerakai in the Ohn'ahran Plains. Oddly, another Teerai Fisher sometimes spawns in place of Fireheart in Teerakai proper." },
  ["teerai keeper"] = { 2, "', "Teerai Keepers are centaur located in various places in the Ohn'ahran Plains. Some can also be found in the Emerald Dream at the Ancient Bough." },
  ["teerai rescuer"] = { 2, "', "Teerai Rescuers are centaur located outside Daruukhan in the Ohn'ahran Plains." },
  ["teerai soldier"] = { 2, "', "Teerai Soldier are centaur located in the Ohn'ahran Plains." },
  ["teerai villager"] = { 2, "', "Teerai Villagers are dead centaur located at the Horn of Drusahl in the Ohn'ahran Plains." },
  ["teerai watcher"] = { 2, "', "Teerai Watchers are centaur located in Maruukai, Broadhoof Outpost, and Teerakai in the Ohn'ahran Plains. They also appear in the Nokhud Offensive." },
  ["tefferty ulreth"] = { 2, "Arathi located at Beledar's Bounty in Hallowfall", "Tefferty Ulreth is an Arathi located at Beledar's Bounty in Hallowfall. He once assisted Wenren Althal in his research in hopes of being reunited with his wife, who stayed back in their homeland, until he secretly joined the Order of Night and was..." },
  ["teg dawnstrider"] = { 2, "tauren enchanting trainer located on the middle rise in T...", "Teg Dawnstrider is a tauren enchanting trainer located on the middle rise in Thunder Bluff. This section concerns content related to Legion." },
  ["tehd shoemaker"] = { 2, "Forsaken warlock working alongside the demon hunter Mariu...", "Tehd Shoemaker is a Forsaken warlock working alongside the demon hunter Marius Felbane to track demons across Azeroth. The two have a professional relationship, hating each other and what the other stands for, but acknowledging that they need each..." },
  ["tekazza of the aimless few"] = { 2, "nerubian flight master located in the Burrows in Azj-Kahet", "Tekazza of the Aimless Few is a nerubian flight master located in the Burrows in Azj-Kahet." },
  ["telaari citizen"] = { 2, "', "Telaari Citizens are draenei and Broken located in Telaar in Nagrand." },
  ["telaari elekk rider"] = { 2, "', "Telaari Elekk Riders are Broken located in Telaar in Nagrand. They are mounted on elekks." },
  ["telaari jailor"] = { 2, "Broken located in Nagrand", "Telaari Jailor is a Broken located in Nagrand." },
  ["telaari watcher"] = { 2, "', "Telaari Watchers are Broken located in Nagrand." },
  ["telash greywing"] = { 2, "boss in the Azure Vault", "Telash Greywing is a boss in the Azure Vault. Telash initially appears as a quest giver in the Azure Span, accompanying Scalecommander Emberthal as they seek out Malygos' knowledge regarding the imprisonment of the dracthyr." },
  ["teleporter"] = { 2, "level 70 ethereal offering to teleport players directly t...", "The Teleporter is a level 70 ethereal offering to teleport players directly to other friendly races' starting areas. He exists in all starting areas." },
  ["teliah"] = { 2, "Ascended kyrian located in Torghast", "Teliah is an Ascended kyrian located in Torghast, Tower of the Damned." },
  ["telkar doomhammer"] = { 2, "father of Warchief Orgrim Doomhammer", "Telkar Doomhammer was the father of Warchief Orgrim Doomhammer, and one of the best warriors in the Blackrock clan. He wielded the mighty Doomhammer, considered by some to be a weapon of prophecy." },
  ["teller almeida"] = { 2, "human banker located at the Dalaran Merchant's Bank in Da...", "Teller Almeida  is a human banker located at the Dalaran Merchant's Bank in Dalaran. This section concerns content related to Legion." },
  ["temnaayu"] = { 2, "tuskarr located at the Artisan's Market in Valdrakken", "Temnaayu is a tuskarr located at the Artisan's Market in Valdrakken." },
  ["temporal defender"] = { 2, "', "Temporal Defenders are located at Eon's Fringe in Thaldraszus. They are often found accompanying Temporal Investigators." },
  ["tempted scholar"] = { 2, "', "Tempted Scholars are kyrian encountered by adventure companions in Bastion." },
  ["tempula"] = { 2, "Forsworn kyrian located at the Temple of Humility in Bastion", "Tempula was a Forsworn kyrian located at the Temple of Humility in Bastion." },
  ["temuejin"] = { 2, "khan of the Red Tribe of centaur", "Temuejin, the Second Khan, was a khan of the Red Tribe of centaur. He commanded from Spearhold in Desolace." },
  ["tenaval"] = { 2, "venthyr located in Sinfall in Revendreth", "Tenaval is a venthyr located in Sinfall in Revendreth." },
  ["tender aru"] = { 2, "tauren stable master", "Tender Aru is the tauren stable master that can be found at Silver Tide Hollow in the Shimmering Expanse." },
  ["tenezeth"] = { 2, "dead dracthyr found in the Support Creche in the Forbidde...", "Tenezeth is a dead dracthyr found in the Support Creche in the Forbidden Reach." },
  ["tepolar"] = { 2, "centaur", "Tepolar is a centaur." },
  ["ter'kova"] = { 2, "haranir located in Harandar", "Ter'kova is a haranir located in Harandar." },
  ["terestian illhoof"] = { 2, "satyr located in the Repository of Karazhan", "Terestian Illhoof is a satyr located in the Repository of Karazhan. He hides in a secret passage behind a bookshelf in the library." },
  ["terl arakor"] = { 2, "human standing next to a wagon on the road through Sundow...", "Terl Arakor is a human standing next to a wagon on the road through Sundown Marsh in the Wetlands. His dialogue provides hints on how to find some of the rare mobs of the Wetlands." },
  ["terminal attendant"] = { 2, "Veiled Market", "Terminal Attendants are brokers located in the Tazavesh Customs Enforcement in Tazavesh, the Veiled Market." },
  ["terokk"] = { 2, "greatest king of the arakkoa", "Terokk was the greatest king of the arakkoa. Terokk was associated with the goddess Rukhmar and believed to be her incarnation, though this was not actually the case." },
  ["terokk (alternate universe)"] = { 2, "greatest king of the arakkoa", "Talon King Terokk was the greatest king of the arakkoa, who once ruled from Skyreach before being cast into the Sethekk Hollow and suffering from the curse of Sethe. He now waits in a world of shadows to be called back into the physical world and ..." },
  ["terokkar talon guard"] = { 2, "', "Terokkar Talon Guards are arakkoa located in [[]] of Spires of Arak." },
  ["teron gorefiend"] = { 2, "', "Teron Gorefiend, born Teron'gor, was one of the first orcish warlocks taught by Gul'dan, and a founding member of the Shadow Council. In death, he became the first of the Horde's death knights—necromantic terrors created by Gul'dan from the souls ..." },
  ["teron gorefiend (warcraft ii)"] = { 2, "', "The ancient Orc spirit of Gorefiend writhes within the decaying body of this fallen Knight of Azeroth. Malicious and extremely cunning, Gorefiend desires to open his own Portal from Draenor and claim a world for his own." },
  ["teron gorefiend (tactics)"] = { 2, "', "This article is about the in-game raid boss. For character biography and other appearances, see Teron Gorefiend." },
  ["terrace attendant"] = { 2, "', "Terrace Attendants are earthen located in Thraegar Rest and Keepers Terrace in Dornogal. They are seen cleaning crystals." },
  ["terrence fallrook"] = { 2, "father of Cedrick", "Terrence Fallrook is the father of Cedrick and Erik and an owner of Fallrook Estate and its winery. He is described as a good and important man in Southshore and might have been a part in a tribunal of Erik's murder." },
  ["terrified broker"] = { 2, "', "Terrified Brokers are brokers located in Eco-Dome Al'dani." },
  ["terrified trader"] = { 2, "Veiled Market", "Terrified Traders are brokers located in Tazavesh, the Veiled Market." },
  ["terror"] = { 2, "voidscarred Broken located in the Forge of Aeons", "The Terror is a voidscarred Broken located in the Forge of Aeons." },
  ["terrorized spa guest"] = { 2, "', "Terrorized Spa Guests are located in Thaldraszus." },
  ["tes'ka"] = { 2, "nerubian located in the City of Threads", "Tes'ka is a nerubian located in the City of Threads." },
  ["tesska the broken"] = { 2, "only one alive in the camp", "Tesska the Broken can be found in one of the Arakkoa Outcasts camps. Tesska is the only one alive in the camp, and he appears to be casting some sinister spell on one of the corpses." },
  ["test resource distributor"] = { 2, "broker located in the four Covenant Sanctums", "The Test Resource Distributor is a broker located in the four Covenant Sanctums." },
  ["tester von testington"] = { 2, "furbolg involved with testing the functions of the Winter...", "Tester von Testington is a furbolg involved with testing the functions of the Winterpelt Furbolg language." },
  ["teth"] = { 2, "nerubian located in Rak-Ahat in Azj-Kahet", "Teth is a nerubian located in Rak-Ahat in Azj-Kahet." },
  ["tethalash"] = { 2, "dracthyr located in the War Creche in the Forbidden Reach", "Tethalash is a dracthyr located in the War Creche in the Forbidden Reach. He is also found at Weyrnrest in Valdrakken." },
  ["teve dawnchaser"] = { 2, "tauren stable master found at Thunder Cleft in Krasarang ...", "Teve Dawnchaser is a tauren stable master found at Thunder Cleft in Krasarang Wilds. He is a member of the Dawnchaser tribe, which traveled to Pandaria in search of a dreamed paradise." },
  ["teya dawnchaser"] = { 2, "tauren found at Halfhill Market in the Valley of the Four...", "Teya Dawnchaser is a tauren found at Halfhill Market in the Valley of the Four Winds. She is a member of the Dawnchaser tribe, which traveled to Pandaria in search of a dreamed paradise." },
  ["tezran"] = { 2, "ethereal located at Tradewinds Market in Boralus", "Tezran is an ethereal located at Tradewinds Market in Boralus. He is a Master of Fate, and will soon be able to provide players with a  [Seal of Wartorn Fate] in exchange for Gold,  [War Resources] or Marks of Honor." },
  ["thaed pyremaker"] = { 2, "Arathi located at Morgaen's Tears in Hallowfall", "Thaed Pyremaker is an Arathi located at Morgaen's Tears in Hallowfall. He leads the Flame's Radiance during the Nightfall scenario hourly at the top of the hour (at xx:00)." },
  ["thal'kiel"] = { 2, "', "Thal'kiel was one of the greatest eredar sorcerers of Argus many years before they entered the service of Sargeras. A sorcerer of unmatched talent, he led an order of eredar magi and conjurers known as the Wakeners." },
  ["thalanor"] = { 2, "high-ranking member of the Knights of the Ebon Blade loca...", "Dread Commander Thalanor is a high-ranking member of the Knights of the Ebon Blade located on Acherus: The Ebon Hold." },
  ["thalas vylethorn"] = { 2, "satyr located at the Emerald Dragonshrine in The Deaths o...", "Thalas Vylethorn is a satyr located at the Emerald Dragonshrine in The Deaths of Chromie scenario." },
  ["thalia amberhide"] = { 2, "tauren found under Freewind Post in Thousand Needles", "Thalia Amberhide is a tauren found under Freewind Post in Thousand Needles. She is a close friend of Lakota Windsong, the tauren who was kidnapped by Arnak Grimtotem." },
  ["thallya"] = { 2, "kyrian located at the Terrace of the Collectors in Bastion", "Thallya is a kyrian located at the Terrace of the Collectors in Bastion." },
  ["thane banahogg"] = { 2, "', "Thane Banahogg is one of the challenges in the combat ring of Valhalas in Icecrown." },
  ["thane illskar"] = { 2, "ruthless vrykul mage", "Thane Illskar is a ruthless vrykul mage that can be found in the Circle of Suffering in the Underhalls of Icecrown. He has two champions who faithfully serve him: Volgur, a warrior and Brita, a hunter." },
  ["thane irglov the merciless"] = { 2, "vrykul located in Hrydshal in Stormheim", "Thane Irglov the Merciless is a vrykul located in Hrydshal in Stormheim." },
  ["thane torvald eriksson"] = { 2, "vrykul found in Voldrune in the Grizzly Hills", "Thane Torvald Eriksson is a vrykul found in Voldrune in the Grizzly Hills." },
  ["thane ufrang the mighty"] = { 2, "', "Thane Ufrang the Mighty sits in Ufrang's Hall in Icecrown. The thane is patient, with a head for strategy and warfare." },
  ["thanikos"] = { 2, "Ascended kyrian", "Thanikos was an Ascended kyrian and the Hand of Courage serving under Xandria, the Paragon of Courage. When the House of Rituals and House of Constructs who had allied with the Forsworn assaulted the Temple of Courage, Thanikos organized the defen..." },
  ["tharalash"] = { 2, "dracthyr located in the Drag in Orgrimmar", "Tharalash is a dracthyr located in the Drag in Orgrimmar. She is reading a map." },
  ["tharek blackstone"] = { 2, "dwarf located in Kharanos in Dun Morogh", "Tharek Blackstone is a dwarf located in Kharanos in Dun Morogh. Tharek works as a toolsmith, and his biggest customer is Beldin Steelgrill, who owns Steelgrill's Depot, making poor Blackstone an overworked toolsmith." },
  ["thargas anvilmar"] = { 2, "Ironforge dwarf in service of king Magni Bronzebeard", "Thargas Anvilmar is an Ironforge dwarf in service of king Magni Bronzebeard who has fought alongside King Varian. He is currently the patriarch of the Anvilmars and the last direct descendant of Modimus Anvilmar, the last High King of all dwarves." },
  ["tharken bloodspike"] = { 2, "presumably orcish witness to the Cataclysm in the Souther...", "Tharken Bloodspike was a presumably orcish witness to the Cataclysm in the Southern Barrens that lost his brother during the chaos." },
  ["thaumaturge altha"] = { 2, "', "Thaumaturge Altha is one of a handful of ethereals that have set up shop in Orgrimmar. During   [35] A Hidden Message, he will charge 10,000 to charge the  [Cryptomancer's Decoder Ring] into a  [Charged Decoder Ring]." },
  ["thaumaturge anjool"] = { 2, "ethereal arcane reforger found in the Hall of Secrets in ...", "Thaumaturge Anjool was an ethereal arcane reforger found in the Hall of Secrets in the Shrine of Two Moons." },
  ["thaumaturge faraket"] = { 2, "ethereal arcane reforger found in the Shrine of Seven Stars", "Thaumaturge Faraket was an ethereal arcane reforger found in the Shrine of Seven Stars." },
  ["thaumaturge rafir"] = { 2, "ethereal located in the Canals of the city of Stormwind", "Thaumaturge Rafir is an ethereal located in the Canals of the city of Stormwind. He is one of a handful of ethereals that have set up the shop The Three Winds." },
  ["thaumaturge vashreen"] = { 2, "ethereal arcane reforger previously found at The Three Wi...", "Thaumaturge Vashreen was an ethereal arcane reforger previously found at The Three Winds in Stormwind City, alongside Vaultkeeper Razhid, Warpweaver Hashom, Voidbinder Sturzah and Thaumaturge Rafir. While physically removed from the game, he does ..." },
  ["thaumaturge zajir"] = { 2, "ethereal arcane reforger found a building in the Drag in ...", "Thaumaturge Zajir was an ethereal arcane reforger found a building in the Drag in Orgrimmar, alongside Vaultkeeper Jazra and Warpweaver Dushar." },
  ["thaza"] = { 2, "dracthyr located in the Trade District in Stormwind City", "Thaza is a dracthyr located in the Trade District in Stormwind City." },
  ["the accuser"] = { 2, "venthyr located in Sinfall in Revendreth", "The Accuser (real name Harriet of the Crimson Shade) is a venthyr located in Sinfall in Revendreth. She is the Harvester of Pride, bearer of the  [Medallion of Pride], which gives her control over the Ceremony Ward, thus has authority over the Hal..." },
  ["the anvil (djaradin)"] = { 2, "djaradin in the Emerald Dream first seen at Slagfell Hold", "The Anvil is a djaradin in the Emerald Dream first seen at Slagfell Hold. Later, she could be found at the Eye of Ysera during the quest  [10-80] Triple Threat." },
  ["the big bad wolf"] = { 2, "worgen boss in the Opera House in Karazhan", "The Big Bad Wolf is a worgen boss in the Opera House in Karazhan. He drops the rare pet  [Spiky Collar], part of  [Raiding with Leashes II: Attunement Edition]." },
  ["the black knight"] = { 2, "agent of the Lich King", "The Black Knight is an agent of the Lich King, sent to disrupt Tirion Fordring's Argent Tournament." },
  ["the black knight (tactics)"] = { 2, "final boss of the Trial of the Champion in the Crusaders'...", "The Black Knight is the final boss of the Trial of the Champion in the Crusaders' Coliseum. He is encountered by all players, after they have defeated three grand champions of the opposite faction, and Argent Confessor Paletress or Eadric the Pure." },
  ["the blade"] = { 2, "mogu assassin known for slathering his blade in a powerfu...", "The Blade is a mogu assassin known for slathering his blade in a powerful ointment that plays with the mind to slay his enemies. He apparently collects the armor of his enemies as trophies, as well." },
  ["the blubberwall"] = { 2, "chieftain of the Imbu tribe of tuskarr", "The Blubberwall is the chieftain of the Imbu tribe of tuskarr who make their home in Imbu in the Azure Span." },
  ["the bone witch"] = { 2, "vrykul possessed by Lady Nightswood", "The Bone Witch is a vrykul possessed by Lady Nightswood. She gives quests for the Knights of the Ebon Blade." },
  ["the bonebreaker"] = { 2, "nickname given to a female assassin", "The Bonebreaker was the nickname given to a female assassin who, after one of her victims came back from the dead, developed a habit of breaking their legs after killing them." },
  ["the butcher"] = { 2, "second boss of Highmaul in Nagrand", "The Butcher is the second boss of Highmaul in Nagrand." },
  ["the candle king"] = { 2, "tyrannical ruler of the kobolds of the Ringing Deeps", "The Candle King is the tyrannical ruler of the kobolds of the Ringing Deeps, fought as a boss in Darkflame Cleft." },
  ["the candleking"] = { 2, "ruler of the Bluewax kobolds of Candle Rock in Highmountain", "The Candleking is the ruler of the Bluewax kobolds of Candle Rock in Highmountain. He is wearing the stolen skull of a long-dead Highmountain tauren named Oenia Skyhorn, whose ghost asks adventurers to kill the Candleking and take back her skull s..." },
  ["the caretaker"] = { 2, "venthyr", "The Caretaker was a venthyr and the former Harvester of Envy. The predecessor to the Tithelord, they were the 274th Caretaker." },
  ["the countess"] = { 2, "venthyr", "The Countess is a venthyr who is the Harvester of Desire, bearer of the  [Medallion of Desire], and thus has authority over the Castle Ward and is in charge of the court, composed of all the noble houses of the venthyr. She resides in Redelav Towe..." },
  ["the cow king"] = { 2, "tauren mini-boss", "The Cow King is a tauren mini-boss that regularly spawns in the 'Secret Cow Level', a special phased version of the Yorgen Farmstead in Duskwood available during Diablo's 20th Anniversary." },
  ["the curator (venthyr)"] = { 2, "venthyr located in Sinfall in Revendreth", "The Curator is a venthyr located in Sinfall in Revendreth, and is the Harvester of Avarice. She is one of the first venthyr, willed into being by Denathrius, and was never mortal." },
  ["the deathbringer (statue)"] = { 2, "nerubian depicted by a statue in the Skeins in the City o...", "The Deathbringer is a nerubian depicted by a statue in the Skeins in the City of Threads, on the southwestern side of the Royal Preservatorium. The statue's plaque can only be understood while under the effects of  [Potion of Polymorphic Translati..." },
  ["the drifter"] = { 2, "tortollan vendor located in the Drifter's Dive in the Azu...", "The Drifter is a tortollan vendor located in the Drifter's Dive in the Azure Span." },
  ["the fearstalker"] = { 2, "venthyr located at Wanecrypt Hill in Revendreth", "The Fearstalker is a venthyr located at Wanecrypt Hill in Revendreth. She is the Harvester of Dread." },
  ["the forgotten (mob)"] = { 2, "undead located on a platform in the Emperor's Approach in...", "The Forgotten is an undead located on a platform in the Emperor's Approach in the Vale of Eternal Blossoms." },
  ["the grand collector"] = { 2, "', "The Grand Collector appears in Blade's Edge Mountains near the end of the Bash'ir Landing raid, serving as the event's 'final boss'." },
  ["the gravekeeper"] = { 2, "boss in the crypt area of the Karazhan Crypts", "The Gravekeeper is a boss in the crypt area of the Karazhan Crypts." },
  ["the great akazamzarak"] = { 2, "goblin magician normally found entertaining some Dalaran ...", "The Great Akazamzarak is a goblin magician normally found entertaining some Dalaran Citizens at the Eventide in Dalaran. He is an expert with portals and teleportation and is therefore recruited by the Tirisgarde in order to teleport its members i..." },
  ["the grey one"] = { 2, "large statue of a petrified drogbar found on an upper led...", "The Grey One was a large statue of a petrified drogbar found on an upper ledge in the northeastern part of Neltharion's Vault in Highmountain among piles of treasure." },
  ["the hoardmonger"] = { 2, "boss in the Den of Nalorakk", "The Hoardmonger is a boss in the Den of Nalorakk." },
  ["the jade warlord"] = { 2, "powerful mogu spellcaster", "The Jade Warlord was a powerful mogu spellcaster." },
  ["the last architect"] = { 2, "ethereal located in Founder's Point", "The Last Architect is an ethereal located in Founder's Point and Razorwind Shores." },
  ["the muscle"] = { 2, "ogre located in Azsuna", "The Muscle is an ogre located in Azsuna." },
  ["the nameless king"] = { 2, "rare mob vrykul located in the Field of Fallen Kings in S...", "The Nameless King is a rare mob vrykul located in the Field of Fallen Kings in Stormheim. He is actually the vrykul king, Torvald the Defiant." },
  ["the nameless prophet"] = { 2, "centaur located in the tunnels outside Maraudon in Desolace", "The Nameless Prophet is a centaur located in the tunnels outside Maraudon in Desolace. He can cause major issues for single characters moving through the pre-instance area." },
  ["the puppetmaster?"] = { 2, "encounter controlled by The Puppetmaster in the 'Strange ...", "The Puppetmaster? is an encounter controlled by The Puppetmaster in the 'Strange Disturbances' variant of the Spiral Weave, where several puppets make up the final boss." },
  ["the rat king"] = { 2, "undead located in the Arcway", "The Rat King is an undead located in the Arcway." },
  ["the stonewarmer"] = { 2, "djaradin walking around the Fields of Reverie in the Emer...", "The Stonewarmer is a djaradin walking around the Fields of Reverie in the Emerald Dream." },
  ["the stonewright"] = { 2, "venthyr", "The Stonewright is a venthyr, the Harvester of Wrath of the Court of Harvesters. She is a former Night Warrior, and the first venthyr created from a mortal soul, which was so long ago that Prince Renathal confused her with the original Harvester o..." },
  ["the taskmaker"] = { 2, "rare nerubian located at Tenir's Ascent in Hallowfall", "The Taskmaker is a rare nerubian located at Tenir's Ascent in Hallowfall." },
  ["the tithelord"] = { 2, "venthyr", "The Tithelord, also called the Caretaker, is a venthyr, and the Harvester of Envy. According to Prince Renathal, he was the 275th Harvester to rule the Village Ward." },
  ["the verdigrease knight"] = { 2, "kobold located in the Verdant Gutters outside Campalot in...", "The Verdigrease Knight is a kobold located in the Verdant Gutters outside Campalot in the Ringing Deeps." },
  ["theka the martyr"] = { 2, "elite undead sand troll mini-boss found in Zul'Farrak", "Theka the Martyr is an elite undead sand troll mini-boss found in Zul'Farrak. A historical figure in Sandfury society who sacrificed himself for the benefit of his people, those who persecuted him were forever cursed into the form of scarabs." },
  ["thela soulsipper"] = { 2, "venthyr located in Torghast", "Thela Soulsipper is a venthyr located in Torghast, Tower of the Damned." },
  ["theldren (dracthyr)"] = { 2, "dracthyr located in the Azure Archives Annex in Valdrakken", "Kemora is a dracthyr located in the Azure Archives Annex in Valdrakken." },
  ["thelett shaleheart"] = { 2, "', "Thelett Shaleheart redeems Tier 16 Flexible armor tokens for Alliance players in Shrine of Seven Stars." },
  ["thelonia the cruel"] = { 2, "Mawsworn kyrian located in Calcis in the Maw during the E...", "Thelonia the Cruel is a Mawsworn kyrian located in Calcis in the Maw during the Escape from the Maw." },
  ["thenia"] = { 2, "kyrian located in Bastion", "Thenia is a kyrian located in Bastion. She's surrounded by her three battle pets: A Sunset Glimmerfly, a Plains Peachick, and a Golden Grazer." },
  ["thenios"] = { 2, "', "Thenios is one of the Paragons of the Ascended kyrian. Thenios once questioned his fellow Paragon Devos why she was training the soul of Uther, as this was beneath her station." },
  ["theo'drosh blindseyed"] = { 2, "orc located at the Axefall‎ in Spires of Arak", "Theo'drosh Blindseyed is an orc located at the Axefall‎ in Spires of Arak. He can be recruited as a follower." },
  ["theotar"] = { 2, "venthyr", "Theotar, the Mad Duke, is a venthyr and one of the soulbinds for Venthyr Covenant members. He is located in Sinfall in Revendreth." },
  ["theresa barkskin"] = { 2, "elite worgen found in the Molten Front", "Theresa Barkskin is an elite worgen found in the Molten Front. When first discovered, she can be seen resting near the graveyard at Malfurion's Breach, but later gets into the action at Igneous Depths during  [32-35 Daily] Enduring the Heat." },
  ["therkan"] = { 2, "earthen located in Gundargaz in the Ringing Deeps", "Therkan is an earthen located in Gundargaz in the Ringing Deeps." },
  ["thermalseer arhdas"] = { 2, "earthen located in the Forgegrounds in Dornogal", "Thermalseer Arhdas is an earthen located in the Forgegrounds in Dornogal." },
  ["therum deepforge"] = { 2, "dwarf expert blacksmithing trainer located in the Dwarven...", "Therum Deepforge is a dwarf expert blacksmithing trainer located in the Dwarven District in Stormwind City. He is the royal armorer of the House of Wrynn." },
  ["theurgist nitara"] = { 2, "naga located in Nazjatar", "Theurgist Nitara is a naga located in Nazjatar." },
  ["thick-hide"] = { 2, "furbolg located in Verdant Wilds during Island Expedition", "Thick-Hide is a furbolg located in Verdant Wilds during Island Expedition." },
  ["thieving agent"] = { 2, "', "Thieving Agents are brokers located in the Sepulcher of the First Ones." },
  ["thildink flickercraft"] = { 2, "gnome located in the Blazing Strand in Darkshore", "Thildink Flickercraft is a gnome located in the Blazing Strand in Darkshore." },
  ["thimble"] = { 2, "nerubian spiderling located in Azj-Kahet", "Thimble is a nerubian spiderling located in Azj-Kahet. It was among the weave rats that feasted upon Meesk the Venomtongue." },
  ["thirsty aspirant"] = { 2, "kyrian located at Hero's Rest in Bastion", "The Thirsty Aspirant is a kyrian located at Hero's Rest in Bastion." },
  ["thistlefur avenger"] = { 2, "', "Thistlefur Avengers are furbolgs of the Thistlefur tribe. They can be found at Thistlefur Hold in Ashenvale." },
  ["thistlefur den watcher"] = { 2, "', "Thistlefur Den Watchers are furbolgs of the Thistlefur tribe found at Thistlefur Hold in Ashenvale." },
  ["thistlefur pathfinder"] = { 2, "', "Thistlefur Pathfinders are furbolgs of the Thistlefur tribe. They can be found at Thistlefur Hold in Ashenvale." },
  ["thistlefur shaman"] = { 2, "', "Thistlefur Shaman are furbolgs of the Thistlefur tribe found at Thistlefur Hold in Ashenvale." },
