  ["thoradin ix"] = { 2, "current ruler of the Arathi Empire", "Emperor Thoradin IX is the current ruler of the Arathi Empire. Like all Arathi emperors, he receives and interprets prophetic visions from the Sacred Flame and commands his subjects to either fulfill or forestall their prophesied events in order t..." },
  ["thorgrum borrelson"] = { 2, "dwarf gryphon flight master located on the hill above The...", "Thorgrum Borrelson is a dwarf gryphon flight master located on the hill above Thelsamar in Loch Modan." },
  ["thorn blingring"] = { 2, "goblin located at Slam Central Station in Undermine", "Thorn Blingring is a goblin located at Slam Central Station in Undermine. She is held up by a Hyena Handler and a Customs Agent as a Contraband Sniffer is examining her luggage." },
  ["thorngrin the tender"] = { 2, "third boss of the Botanica wing of the Tempest Keep insta...", "Thorngrin the Tender is the third boss of the Botanica wing of the Tempest Keep instance in Netherstorm." },
