  ["threadis"] = { 2, "nerubian child summoned by the  [Khaz Algar Orphan Whistl...", "Threadis  is a nerubian child summoned by the  [Khaz Algar Orphan Whistle] while on  [10-90] The Eager Engineer, part of the Children's Week questline in Dornogal." },
  ["three-tooth"] = { 2, "', "Three-Tooth is what the Bristleback quilboar call their matriarch. She's been twisting the thorns of this crazy jungle to her own ends, and it was her orders that Ambassador Gaines be 'torn apart and fed to the overgrowth.' Corporal Teegan orders ..." },
  ["threm blackscalp"] = { 2, "orc leatherworker vendor for the Dragonmaw Clan", "Threm Blackscalp is an orc leatherworker vendor for the Dragonmaw Clan. He is located at Dragonmaw Port in the Twilight Highlands." },
  ["thrifty fisher"] = { 2, "tuskarr located in Roaring Dragonsprings in the Ohn'ahran...", "Thrifty Fisher is a tuskarr located in Roaring Dragonsprings in the Ohn'ahran Plains. As she was looking for a good place to set up fishing nets around the area, she found a dense population of waddlers who were eating most of the juvenile fish." },
  ["thripps"] = { 2, "nerubian located in the City of Threads", "Thripps is a nerubian located in the City of Threads." },
  ["thulsketha the binder"] = { 2, "Drust located in Eventide Grove in Ardenweald", "Thulsketha the Binder is a Drust located in Eventide Grove in Ardenweald. He wanted to sacrifice Kivarr for a ritual but was stopped by the Maw Walker and Ara'lon." },
  ["thunder lord"] = { 2, "', "Thunder Lords are mogu located in the Throne of Thunder." },
  ["thunker axeljink"] = { 2, "member of the Council of Tirisfal", "Thunker Axeljink was a member of the Council of Tirisfal and the father of Krank Axeljink. He died while defending Gnomeregan against the invading troggs." },
  ["thurgrum deepforge"] = { 2, "dwarf blacksmithing vendor located in the Great Forge in ...", "Thurgrum Deepforge is a dwarf blacksmithing vendor located in the Great Forge in Ironforge. This section concerns content related to Legion." },
  ["tiang"] = { 2, "tortollan located in northern Exile's Reach", "Tiang is a tortollan located in northern Exile's Reach. He is found in a secret underwater cave under a waterfall." },
  ["tidebinder sarjezi"] = { 2, "naga located inside a cave at Dragon's Teeth Basin in Naz...", "Tidebinder Sarjezi is a naga located inside a cave at Dragon's Teeth Basin in Nazjatar. She's guarding the cage that holds Farseer Ori." },
  ["tidecaller izaka"] = { 2, "ankoan of the Waveblade clan 'who spoke with the voice of...", "Tidecaller Izaka was an ankoan of the Waveblade clan 'who spoke with the voice of Neptulon himself and whose words still echo within the depths.' He lies buried at an Ankoan Burial Shrine in Ashen Strand in Nazjatar." },
  ["tidecaller nezara"] = { 2, "leader of the Nazeshi naga in the Dreadpearl Shallows in ...", "Tidecaller Nezara is the leader of the Nazeshi naga in the Dreadpearl Shallows in Zuldazar during the vulpera recruitment questline. Accompanied by a Nazeshi Tidebreaker, she is initially protected by a magical barrier powered by powercells scatte..." },
  ["tidehunter mela'kar"] = { 2, "naga", "Tidehunter Mela'kar is a naga." },
  ["tidelord rrurgaz"] = { 2, "level 62 elite male naga found on Alcaz Island in Dustwal...", "Tidelord Rrurgaz was a level 62 elite male naga found on Alcaz Island in Dustwallow Marsh." },
  ["tidemistress ethendriss"] = { 2, "naga located at the Spears of Azshara in Nazjatar", "Tidemistress Ethendriss is a naga located at the Spears of Azshara in Nazjatar. She is sacrificing 7th Legion Captives and Honorbound Captives in order to summon forth Wekemara." },
  ["tidemistress leth'sindra"] = { 2, "naga located in Nazjatar", "Tidemistress Leth'sindra is a naga located in Nazjatar. Disturb five Undisturbed Specimen to summon this naga." },
  ["tidemistress najula"] = { 2, "naga", "Tidemistress Najula is a naga who can be encountered during Island Expeditions." },
  ["tidemistress nazesh"] = { 2, "Tidemistress of the Nazeshi naga", "Tidemistress Nazesh serves Queen Azshara and is the Tidemistress of the Nazeshi naga. At her queen's command, she leads a naga army to attack the coast of Zuldazar." },
  ["tidemistress nessa"] = { 2, "naga", "Tidemistress Nessa is a naga who can be encountered during Island Expeditions." },
  ["tidemistress sashj'tar"] = { 2, "naga located at various areas in Suramar", "Tidemistress Sashj'tar is a naga located at various areas in Suramar, such as Jandvik (disguised as Toryl), Azuregale Bay & Sashj'tar Ruins." },
  ["tidemistress shellbreaker"] = { 2, "naga located in Bizmo's Brawlpub", "Tidemistress Shellbreaker is a naga located in Bizmo's Brawlpub and Brawl'gar Arena." },
  ["tidemistress sser'ah"] = { 2, "naga", "Tidemistress Sser'ah is a naga who can be encountered during Island Expeditions. She is accompanied by Shadow Serpents." },
