  ["tigari khan"] = { 2, "khan of the Ohn'ir centaur in the Ohn'ahran Plains", "Tigari Khan is the khan of the Ohn'ir centaur in the Ohn'ahran Plains. She is always accompanied by her ohuna companion, Altan, and is well-versed in reading omens from Ohn'ahra." },
