  ["tihku fogcaller"] = { 2, "tauren drum maker in Bloodhoof Village in Mulgore", "Tihku Fogcaller is a tauren drum maker in Bloodhoof Village in Mulgore. Zekhan used to watch and enjoy his drummaking, especially the way he worked the sinew threads to pull the tanned heads taut over their frames." },
