  ["tiza battleforge"] = { 2, "dwarf of the Knights of the Silver Hand located in the Ha...", "Tiza Battleforge is a dwarf of the Knights of the Silver Hand located in the Hall of Mysteries in the Mystic Ward in Ironforge. She is one of the most respected paladins in the city and has been known to train aspiring paladins in the ways of the ..." },
  ["to'no"] = { 2, "tuskarr child located at various locations in the Forbidd...", "To'no is a tuskarr child located at various locations in the Forbidden Reach. Players who find him with the  [Tuskarr Dinner Bell] can acquire the  [Oddsight Focus] from him." },
  ["to'tik"] = { 2, "tuskarr located in the Lost Ruins in the Azure Span", "To'tik is a tuskarr located in the Lost Ruins in the Azure Span." },
  ["toaka the explorer"] = { 2, "worldsoul memory of a tortollan located in the Isle of Do...", "Toaka the Explorer is the worldsoul memory of a tortollan located in the Isle of Dorn during  [80] Worldsoul Memory: Ancient Explorers event." },
  ["toalu'u the mystic"] = { 2, "tuskarr located at Moa'ki Harbor in the Dragonblight", "Toalu'u the Mystic is a tuskarr located at Moa'ki Harbor in the Dragonblight." },
  ["tobias mistmantle"] = { 2, "worgen warrior", "Tobias Mistmantle is a worgen warrior who occasionally appears in Gilneas-related quests. He is one of Darius Crowley's men and was a rebel during the Gilneas civil war." },
  ["tobias the filth gorger"] = { 2, "Broken quest giver located in the Lower City in Shattrath...", "Tobias the Filth Gorger is a Broken quest giver located in the Lower City in Shattrath City. Tobias met with Borak, Son of Oronok who learned about him trading  [Bloodthistle] to blood elven thistleheads for rotten arakkoa eggs." },
  ["tocho cloudhide"] = { 2, "tauren located in the Pathfinder's Den in Orgrimmar", "Tocho Cloudhide is a tauren located in the Pathfinder's Den in Orgrimmar and at the Common on Razorwind Shores." },
  ["todd abel"] = { 2, "human monk trainer found in Gilneas City during the worge...", "Todd Abel is a human monk trainer found in Gilneas City during the worgen starting experience. He can be found back in the city after the Reclamation of Gilneas." },
  ["togglin"] = { 2, "tuskarr located at the Uktulut Pier in the Waking Shores", "Togglin is a tuskarr located at the Uktulut Pier in the Waking Shores. He provides the time of the Lost Arvillo." },
  ["tokag bonebreaker"] = { 2, "orc located at the Gala of Gifts in Durotar during Love i...", "Tokag Bonebreaker is an orc located at the Gala of Gifts in Durotar during Love is in the Air." },
  ["toki"] = { 2, "tortollan of the Tortollan Seekers found in various place...", "Toki is a tortollan of the Tortollan Seekers found in various places on Zandalar and Kul Tiras." },
  ["toklo"] = { 2, "tuskarr located at the Artisan's Market in Valdrakken", "Toklo is a tuskarr located at the Artisan's Market in Valdrakken." },
  ["toko"] = { 2, "tortollan located in the Zocalo in Dazar'alor", "Toko is a tortollan located in the Zocalo in Dazar'alor. When the traitorous prophet Zul and Mythrax attacked the city, Toko was cornered by the invading sethrak." },
  ["toldren deepiron"] = { 2, "dwarf priest trainer located in the Hall of Mysteries in ...", "Toldren Deepiron is a dwarf priest trainer located in the Hall of Mysteries in the Mystic Ward in Ironforge." },
  ["tolliver houndstooth"] = { 2, "Gilnean worgen druid", "Tolliver Houndstooth is a Gilnean worgen druid and quest giver found in Northwatch Hold in the Southern Barrens. He can be found healing various Wounded Defenders around him with his druidic magics." },
  ["tollkeeper varaboss"] = { 2, "venthyr located in a building in Pridefall Hamlet", "Tollkeeper Varaboss is a venthyr located in a building in Pridefall Hamlet, accessed from the Decimated Crossroad, in Revendreth." },
