  ["tombcaller arban"] = { 2, "centaur of Clan Ukhel located inside the main kurgan in t...", "Tombcaller Arban is a centaur of Clan Ukhel located inside the main kurgan in the southwestern part of the Eternal Kurgans in the Ohn'ahran Plains. He walks between the mound's different chambers, repeatedly casting 'Bind Spirit' to summon Bound S..." },
  ["tombcaller ganzaya"] = { 2, "centaur of Clan Ukhel pacing in front of the easternmost ...", "Tombcaller Ganzaya is a centaur of Clan Ukhel pacing in front of the easternmost kurgan in the Eternal Kurgans in the Ohn'ahran Plains. While out of combat, he repeatedly casts 'Bind Spirit' on the Exhumed Spear in an attempt to raise the spirit o..." },
  ["tomothy hillhelm"] = { 2, "Arathi located in Hillhelm Stead in Hallowfall", "Tomothy Hillhelm is an Arathi located in Hillhelm Stead in Hallowfall." },
  ["toni the conner"] = { 2, "vrykul located in Stormheim", "Toni the Conner is a vrykul located in Stormheim." },
  ["tonraq"] = { 2, "tuskarr spear crafter located in the Kalu'ak village Unu'...", "Tonraq is a tuskarr spear crafter located in the Kalu'ak village Unu'pe of the Borean Tundra." },
  ["tooka hardshell"] = { 2, "tortollan located at the Seekers' Vista in Stormsong Valley", "Tooka Hardshell is a tortollan located at the Seekers' Vista in Stormsong Valley." },
  ["toolk"] = { 2, "tuskarr child located in Khuri's Fishing Spot in the Azur...", "Toolk is a tuskarr child located in Khuri's Fishing Spot in the Azure Span." },
  ["topa"] = { 2, "tortollan located at Scaletrader Post in Zuldazar", "Topa is a tortollan located at Scaletrader Post in Zuldazar." },
  ["toraan the revered"] = { 2, "Broken", "Toraan the Revered is a Broken, formerly located aboard the Vindicaar, although he is nowhere to be seen after the Lightforged draenei won the Argus Campaign and pledged themselves to the Alliance." },
  ["toralamir"] = { 2, "dracthyr located in the Victorious Visage in Valdrakken", "Toralamir is a dracthyr located in the Victorious Visage in Valdrakken." },
  ["torchsnarl"] = { 2, "swolbold located in the Ringing Deeps", "Torchsnarl is a swolbold located in the Ringing Deeps. One of The Candle King's enforcers, Torchsnarl held sway over the Warrens and took vicious pleasure in oppressing dissent." },
  ["tordrin"] = { 2, "earthen located in Rambleshire on the Isle of Dorn", "Tordrin is an earthen located in Rambleshire on the Isle of Dorn." },
  ["toreth bluestar"] = { 2, "night elf 'Lorekeeper'", "Toreth Bluestar is a night elf 'Lorekeeper', meaning it is his duty to record the names and noteworthy deeds of his fellow kaldorei. He is small but handsome, with teal skin and a tangle of green hair." },
  ["torgando featherhoof"] = { 2, "tauren located at the Gala of Gifts in Durotar during Lov...", "Torgando Featherhoof is a tauren located at the Gala of Gifts in Durotar during Love is in the Air. Players who donate enough gold to him will earn the  [Support Your Local Artisans] achievement." },
  ["torgg thundertotem"] = { 2, "furbolg summoned in the Conquest Pit in Grizzly Hills", "Torgg Thundertotem is a furbolg summoned in the Conquest Pit in Grizzly Hills." },
  ["torgrul"] = { 2, "drogbar ghost", "Torgrul is a drogbar ghost that appeared in front of a adventuring leatherworker at the Lifespring Cavern in Highmountain." },
  ["torgus (vrykul)"] = { 2, "vrykul located in Stormheim", "Torgus is a vrykul located in Stormheim." },
  ["torik-ethis"] = { 2, "rare mantid found in the Forbidden Jungle in Krasarang Wilds", "Torik-Ethis is a rare mantid found in the Forbidden Jungle in Krasarang Wilds. Torik-Ethis is a pandarian champion." },
  ["torin coalheart"] = { 2, "dwarf located at the Lunarfall in Shadowmoon Valley", "Torin Coalheart is a dwarf located at the Lunarfall in Shadowmoon Valley. He can only be recruited using the Headhunter's Harvest from Lunarfall Inn." },
  ["torin'zel"] = { 2, "nerubian sage located in the City of Threads", "Torin'zel is a nerubian sage located in the City of Threads." },
  ["torka"] = { 2, "tortollan quest giver located at the Tortaka Refuge in Vo...", "Torka is a tortollan quest giver located at the Tortaka Refuge in Vol'dun." },
  ["tormented krokul"] = { 2, "', "Tormented Krokul are krokul located at the Pits of Punishment in Antoran Wastes." },
  ["tormented satyr"] = { 2, "satyr", "Tormented Satyr is a satyr." },
  ["tormus deepforge"] = { 2, "dwarf quest giver located in the Great Forge in Ironforge", "Tormus Deepforge is a dwarf quest giver located in the Great Forge in Ironforge." },
  ["torngasak"] = { 2, "tuskarr drink vendor located at the Argent Tournament Gro...", "Torngasak is a tuskarr drink vendor located at the Argent Tournament Grounds in Icecrown. This section concerns content related to Shadowlands." },
  ["torra"] = { 2, "vulpera child", "Torra is a vulpera child that follows Nala around the Vulpera Hideaway in Vol'dun." },
  ["torran dellain"] = { 2, "Arathi stable master located in Dunelle's Kindness in Hal...", "Torran Dellain is an Arathi stable master located in Dunelle's Kindness in Hallowfall." },
  ["torsheg"] = { 2, "mogu located at the Golden Stair in the Vale of Eternal B...", "Torsheg is a mogu located at the Golden Stair in the Vale of Eternal Blossoms." },
  ["tortaka hunter"] = { 2, "tortollan", "Tortaka Hunter is a tortollan." },
  ["tortaka refugee"] = { 2, "', "Tortaka Refugees are tortollans located in the Tortaka Refuge in Vol'dun. One can be seen at the eastern end of Darkwood Shoal, being entranced by Songstress Nahjeen with Nahj'een's Song." },
  ["tortaka soothsayer"] = { 2, "tortollan", "Tortaka Soothsayer is a tortollan." },
  ["tortaka spirit-walker"] = { 2, "tortollan", "Tortaka Spirit-Walker is a tortollan." },
  ["tortaka tribesman"] = { 2, "', "Tortaka Tribesmen are tortollans guarding the Tortaka Refuge in Vol'dun. Some unarmed tribesmen can be freed from Jungleweb Victim webs at the Terrace of the Fang." },
  ["tortaka worshiper"] = { 2, "', "Tortaka Worshipers are tortollans located in Dazar'alor if Loa Speaker Kur'taji is present." },
  ["torthen deepdig"] = { 2, "dwarf quest giver located in the Grizzly Hills", "Torthen Deepdig is a dwarf quest giver located in the Grizzly Hills." },
  ["tortollan captive"] = { 2, "', "Tortollan Captives are tortollans located in Nazmir." },
  ["tortollan caster"] = { 2, "tortollan", "Tortollan Caster is a tortollan." },
  ["tortollan hardshell"] = { 2, "', "Tortollan Hardshells are tortollans located in Dazar'alor and Zuldazar and at Seekers' Vista in Stormsong Valley." },
  ["tortollan hatchling"] = { 2, "baby tortollan", "Tortollan Hatchling is a baby tortollan." },
  ["tortollan mystic"] = { 2, "', "Tortollan Mystics are tortollans located in Nazmir." },
  ["tortollan pilgrim"] = { 2, "', "Tortollan Pilgrims are tortollans located in Nazmir and Zuldazar." },
  ["tortollan sacrifice"] = { 2, "', "Tortollan Sacrifices are deceased tortollans located in Nazmir." },
  ["tortollan scrollsage"] = { 2, "', "Tortollan Scrollsages are tortollans located in Zuldazar." },
  ["tortollan seeker"] = { 2, "', "Tortollan Seekers are tortollans found in Little Tortolla in Dazar'alor and in Zuldazar." },
  ["tortollan shellraiser"] = { 2, "tortollan", "The Tortollan Shellraiser is a tortollan who manages the Reinforced Warshell at Zanj'ir Terrace in Nazjatar." },
  ["tortollan slave"] = { 2, "tortollans will casually walk away to freedom", "Tortollan Slaves are tortollan pilgrims from Nazmir that have been captured by the Faithless sethrak and are seen being auctioned off by Faithless Dealers at two of the slave markets in the Slithering Gulch in Vol'dun.  If the corresponding Faithl..." },
  ["tortollan spellflinger"] = { 2, "tortollan located in Nazmir", "Tortollan Spellflinger is a tortollan located in Nazmir." },
  ["tortollan tamer"] = { 2, "', "Tortollan Tamers are tortollans located in the unnamed underwater ruins north of Kaja'Coast in Dazar'alor. One is found near the Hall of Beasts in Zuldazar, accompanied by a Loggerhead Snapjaw, Emerald Turtle, and Turquoise Turtle." },
  ["tortollan trader"] = { 2, "', "Tortollan Traders are tortollans located at Backwater Beach in Zuldazar." },
  ["tortollan trader (neighborhoods)"] = { 2, "', "Tortollan Traders are tortollans found in the underwater dive bars near Breakwater Bight in Founder's Point and the Hull in Razorwind Shores. The dive bar in Founder's Point has two Tortollan Traders—one who sells food and another who sells drinks..." },
  ["tortollan traveler"] = { 2, "', "Tortollan Travelers are tortollans located in Anyport in Drustvar and in underwater ruins in western Zuldazar." },
  ["tortollan villager"] = { 2, "', "Tortollan Villagers are dead tortollans located in Zuldazar and Nazmir." },
  ["tortollan visitor"] = { 2, "', "Tortollan Visitors are tortollans found in the underwater dive bars near Breakwater Bight in Founder's Point and the Hull in Razorwind Shores." },
  ["tortollan warrior"] = { 2, "', "Tortollan Warriors are tortollans located in Nazmir." },
  ["tortollan young"] = { 2, "baby tortollan", "Tortollan Young is a baby tortollan." },
  ["tortollan youngling"] = { 2, "', "Tortollan Younglings are tortollan children located in Zuldazar." },
  ["tortolleni"] = { 2, "tortollan", "Tortolleni is a tortollan." },
  ["tortured protectorate vanguard"] = { 2, "ethereal located at Protectorate Watch Post in Netherstorm", "Tortured Protectorate Vanguard is an ethereal located at Protectorate Watch Post in Netherstorm. Before succumbing to his wounds, he is found by Commander Ameer." },
  ["tortured slave"] = { 2, "', "Tortured Slaves are skeletons and undeads found in the Detention Block in Blackrock Depths." },
  ["tortured slave (krokuun)"] = { 2, "', "Tortured Slaves are dead Broken located in Krokuun." },
  ["torturer alphonse"] = { 2, "torturer of the Scarlet Onslaught found in the basement o...", "Torturer Alphonse is a torturer of the Scarlet Onslaught found in the basement of the barracks at New Hearthglen, in Dragonblight, working at what appears to be an Alchemy Lab. Despite his status as a vile torturer, he begs for his life when tortu..." },
  ["tortusk"] = { 2, "quilboar", "Tortusk is a quilboar and the leader of the Razormane tribe that resides around Thorn Hill. He travels and fights mounted on his raptor Fez." },
  ["torval"] = { 2, "venthyr located in Revendreth", "Torval is a venthyr located in Revendreth." },
  ["torvald"] = { 2, "vrykul located in the Outcast's Hovel in Vrekt in Stormheim", "Torvald is a vrykul located in the Outcast's Hovel in Vrekt in Stormheim. He is the son of God-King Skovald." },
  ["toryl"] = { 2, "vrykul located at Jandvik in Suramar", "Toryl is a vrykul located at Jandvik in Suramar. She was impersonated by Tidemistress Sashj'tar." },
  ["tottle"] = { 2, "baby tortollan companion", "Tottle is a baby tortollan companion. Obtaining this pet will reward the  [Collector's Edition: Tottle] feat of strength." },
  ["tournament groundskeeper"] = { 2, "', "Tournament Groundskeepers are eredar echoes tending to the Circle of Aspirants in Eredath, either fidgeting in the main circle or picking at flowers at the southern edge of the area." },
  ["tower inquisitor"] = { 2, "', "Tower Inquisitors are Mawsworn kyrian located in the Maw." },
  ["toy vendor"] = { 2, "broker located at the Gilded Landing in Tazavesh", "The Toy Vendor is a broker located at the Gilded Landing in Tazavesh, the Veiled Market." },
  ["tracker akatani"] = { 2, "ankoan located at the Ashen Strand in Nazjatar", "Tracker Akatani is an ankoan located at the Ashen Strand in Nazjatar." },
  ["tracker burke"] = { 2, "worgen located in the Nesingwary's Trek in Zuldazar", "Tracker Burke is a worgen located in the Nesingwary's Trek in Zuldazar." },
  ["tracker ikuto"] = { 2, "ankoan located in Nar'anan in Nazjatar", "Tracker Ikuto is an ankoan located in Nar'anan in Nazjatar." },
  ["tracker jack"] = { 2, "worgen located in Stormheim", "Tracker Jack is a worgen located in Stormheim." },
  ["tracker kenji"] = { 2, "ankoan located in Nazjatar overlooking the Deepcoil Tunnels", "Tracker Kenji is an ankoan located in Nazjatar overlooking the Deepcoil Tunnels." },
  ["tracker okaju"] = { 2, "ankoan located in Dragon's Teeth Basin in Nazjatar", "Tracker Okaju is an ankoan located in Dragon's Teeth Basin in Nazjatar." },
  ["tracker onu"] = { 2, "ankoan located at the Ashen Strand in Nazjatar", "Tracker Onu is an ankoan located at the Ashen Strand in Nazjatar. He is found next to two dead Snapshell Tortoises." },
  ["tracker otaru"] = { 2, "ankoan found looking down over the Abyssal Pool in Nazjatar", "Tracker Otaru is an ankoan found looking down over the Abyssal Pool in Nazjatar." },
  ["tracker zo'korss"] = { 2, "broker located at the bridge leading to the Grand Menager...", "Tracker Zo'korss is a broker located at the bridge leading to the Grand Menagerie in Tazavesh, the Veiled Market." },
  ["trade enforcer"] = { 2, "', "Trade Enforcers are brokers located at Transfer Station Ta in Bastion." },
  ["trade facilitator"] = { 2, "', "Trade Facilitators are brokers located at Transfer Station Ta in Bastion and in Oribos. Some are found walking between the Hall of Curiosities and the Hall of Shapes, others in the Idyllia." },
  ["trader araanda"] = { 2, "draenei located in the Lunarfall garrison town hall", "Trader Araanda is a draenei located in the Lunarfall garrison town hall. She sells various items for gold, including pets and mounts." },
  ["trader ba'gor"] = { 2, "broker located in the Idyllia in Oribos", "Trader Ba'gor is a broker located in the Idyllia in Oribos. He can be found talking to Trader Ba'telk." },
  ["trader ba'kril"] = { 2, "broker located in Tazavesh", "Trader Ba'kril is a broker located in Tazavesh, the Veiled Market." },
  ["trader ba'no"] = { 2, "broker", "Trader Ba'no is a broker that can be found standing next to Lady Darkglen at Shadow Point on K'aresh. He is her retainer." },
  ["trader ba'telk"] = { 2, "broker located in the Idyllia in Oribos", "Trader Ba'telk is a broker located in the Idyllia in Oribos. He can be found talking to Trader Ba'gor." },
  ["trader caelen"] = { 2, "dwarf located at the Forge of Fate in Dalaran", "Trader Caelen is a dwarf located at the Forge of Fate in Dalaran." },
  ["trader caerel"] = { 2, "draenei vendor found at the central square in Stormshield", "Trader Caerel is a draenei vendor found at the central square in Stormshield." },
  ["trader harthan"] = { 2, "earthen located at the Forgegrounds in Dornogal", "Trader Harthan is an earthen located at the Forgegrounds in Dornogal." },
  ["trader jargal"] = { 2, "centaur vendor located in Teerakai in the Ohn'ahran Plains", "Trader Jargal is a centaur vendor located in Teerakai in the Ohn'ahran Plains." },
  ["trader kro"] = { 2, "tortollan located at the Seekers' Expedition in Zuldazar", "Trader Kro is a tortollan located at the Seekers' Expedition in Zuldazar. He also appears in the Krasarang Wilds." },
  ["trader narasu"] = { 2, "Broken Kurenai faction rewards vendor located in Telaar i...", "Trader Narasu is a Broken Kurenai faction rewards vendor located in Telaar in Nagrand, to the left of the main entrance of the inn." },
  ["trader nog"] = { 2, "tortollan located in Little Tortolla in Dazar'alor", "Trader Nog is a tortollan located in Little Tortolla in Dazar'alor." },
  ["trader oru"] = { 2, "centaur located at Teerakai in the Ohn'ahran Plains", "Trader Oru is a centaur located at Teerakai in the Ohn'ahran Plains." },
  ["trader so'lek"] = { 2, "broker found with Trader So'ran in the Hall of Shapes in ...", "Trader So'lek is a broker found with Trader So'ran in the Hall of Shapes in Oribos." },
  ["trader so'ran"] = { 2, "broker found with Trader So'lek in the Hall of Shapes in ...", "Trader So'ran is a broker found with Trader So'lek in the Hall of Shapes in Oribos." },
  ["trader ta'bix"] = { 2, "broker located at Transfer Station Ta in Bastion", "Trader Ta'bix is a broker located at Transfer Station Ta in Bastion." },
  ["trader ta'kraz"] = { 2, "broker located at Transfer Station Ta in Bastion", "Trader Ta'kraz is a broker located at Transfer Station Ta in Bastion." },
  ["trader ta'rap"] = { 2, "broker located at Transfer Station Ta in Bastion", "Trader Ta'rap is a broker located at Transfer Station Ta in Bastion." },
  ["trader toffa"] = { 2, "earthen", "Trader Toffa is an earthen." },
  ["trader urtusk"] = { 2, "tuskarr located at Forkriver Crossing in the Ohn'ahran Pl...", "Trader Urtusk is a tuskarr located at Forkriver Crossing in the Ohn'ahran Plains." },
  ["trading post barker"] = { 2, "', "Trading Post Barkers are located in Valdrakken, in Wizard's Sanctum in Stormwind City, and in Gates of Orgrimmar in Orgrimmar. They come in all playable races." },
  ["trainer frodrum"] = { 2, "centaur", "Trainer Frodrum is a centaur who lets players customize the hunting companions used in Grand Hunts. His default location is on the Shikaar rise in Maruukai in the Ohn'ahran Plains, but he also accompanies the Hunts in the field and can be seen alo..." },
  ["trainer grrglin"] = { 2, "murloc pet tamer of the Glimmerfin tribe located in Ventu...", "Trainer Grrglin is a murloc pet tamer of the Glimmerfin tribe located in Venture Bay in the Grizzly Hills." },
  ["trainer ikaros"] = { 2, "kyrian located at the Vestibule of Eternity in Bastion", "Trainer Ikaros is a kyrian located at the Vestibule of Eternity in Bastion. He is training a regiment of Kyrian Aspirants." },
  ["trainer orlogg"] = { 2, "drogbar located in Glimmerogg in Zaralek Cavern", "Trainer Orlogg is a drogbar located in Glimmerogg in Zaralek Cavern." },
  ["traitor gluk"] = { 2, "master Pet Tamer located in front of Dire Maul in Feralas", "Traitor Gluk is a master Pet Tamer located in front of Dire Maul in Feralas. He is in a small camp with his level 13 battle pets: Rasp (Beast), Prancer (Critter), and Glimmer (Dragonkin)." },
  ["trangad"] = { 2, "earthen located in the Lapidarium in the Fissure in Dornogal", "Trangad is an earthen located in the Lapidarium in the Fissure in Dornogal. He is working on an Oathsworn Worker." },
  ["translocation agent"] = { 2, "broker located next to the Stormwind", "The Translocation Agent is a broker located next to the Stormwind and Orgrimmar portals in Oribos. They offer training for the mage spells  [Teleport: Oribos] and  [Portal: Oribos]." },
  ["trap-layer kerwal"] = { 2, "gnoll located in Big Tree Hills in the Azure Span", "Trap-Layer Kerwal is a gnoll located in Big Tree Hills in the Azure Span." },
  ["trapped caretaker"] = { 2, "', "Trapped Caretakers are kyrian located in the Firstborne's Bounty in Bastion." },
  ["trapped tortollan"] = { 2, "', "Trapped Tortollans are tortollans held captive by Zeth'jir Seashapers in Scavenger's Shore in Stormsong Valley." },
  ["trapper mau'i"] = { 2, "tuskarr of the Kalu'ak tribe located in Dragonblight", "Trapper Mau'i is a tuskarr of the Kalu'ak tribe located in Dragonblight. He can be found in the Moa'ki Harbor next to the inn entrance (across from the flight master)." },
  ["trapper saghani"] = { 2, "tuskarr stable master located in Unu'pe in the Dragonblight", "Trapper Saghani is a tuskarr stable master located in Unu'pe in the Dragonblight." },
  ["trapper shesh"] = { 2, "tuskarr stable master found in Kamagua in the Howling Fjord", "Trapper Shesh is a tuskarr stable master found in Kamagua in the Howling Fjord." },
  ["trapper tikaani"] = { 2, "tuskarr stable master located at Moa'ki Harbor in the Dra...", "Trapper Tikaani is a tuskarr stable master located at Moa'ki Harbor in the Dragonblight." },
  ["trauga bloodhelm"] = { 2, "orc located on the Defiant Dragonscale in Durotar", "Trauga Bloodhelm is an orc located on the Defiant Dragonscale in Durotar." },
  ["traveling snailsman"] = { 2, "', "Traveling Snailsmen are two drogbar from Glimmerogg that are visiting the City of Threads, standing near one of the Shadecasters in the Umbral Bazaar. They are attempting to peddle snails and snail products." },
  ["traveling warrior (silvermoon city)"] = { 2, "', "Traveling Warriors are located in Falconwing Square in Silvermoon City." },
  ["travelling ore trader"] = { 2, "earthen located in the Court of Blood in Silvermoon City", "Travelling Ore Trader is an earthen located in the Court of Blood in Silvermoon City." },
  ["trawler yotimo"] = { 2, "tuskarr found at Anglers Wharf in the Krasarang Wilds", "Trawler Yotimo is a tuskarr found at Anglers Wharf in the Krasarang Wilds. He is standing next to a basket of Pickled Herrings." },
  ["treagor"] = { 2, "earthen cooking trainer located in Freywold Village on th...", "Treagor is an earthen cooking trainer located in Freywold Village on the Isle of Dorn." },
  ["tree warden chawn"] = { 2, "tauren quest giver located at Evergrove in the Blade's Ed...", "Tree Warden Chawn is a tauren quest giver located at Evergrove in the Blade's Edge Mountains." },
  ["trem"] = { 2, "tortollan located in northern Exile's Reach", "Trem is a tortollan located in northern Exile's Reach. He is found in a secret underwater cave under a waterfall." },
  ["tremen winefang"] = { 2, "venthyr located in the Sinposium in Darkhaven in Revendreth", "Tremen Winefang is a venthyr located in the Sinposium in Darkhaven in Revendreth." },
  ["treni"] = { 2, "earthen located in Freywold Village on the Isle of Dorn", "Treni is an earthen located in Freywold Village on the Isle of Dorn." },
  ["trespassing fadeblade"] = { 2, "', "Trespassing Fadeblades are Drust located in the Ember Court." },
  ["trevor"] = { 2, "priest of the Holy Light", "In life, Trevor was a priest of the Holy Light and friend to Leonid Barthalomew. He died and was risen as an undead during the Third War but was freed from the mindless servitude of the Lich King by Sylvanas Windrunner." },
  ["trex'na"] = { 2, "nerubian located in the Umbral Bazaar in the City of Threads", "Trex'na is a nerubian located in the Umbral Bazaar in the City of Threads." },
  ["treysh"] = { 2, "dracthyr mount vendor located at the Old Weyrn Grounds in...", "Treysh is a dracthyr mount vendor located at the Old Weyrn Grounds in the Forbidden Reach. Behind her are a Crimson Vorquin and Sapphire Vorquin." },
  ["trickclaw mystic"] = { 2, "', "Trickclaw Mystics are gnolls located in the Azure Span." },
  ["trickclaw mystic (brackenhide hollow)"] = { 2, "', "Trickclaw Mystics are gnolls located in Brackenhide Hollow." },
  ["tricktotem"] = { 2, "gnoll located at Lost Kanniak in Brackenhide Hollow", "Tricktotem is a gnoll located at Lost Kanniak in Brackenhide Hollow." },
  ["trilling attendant"] = { 2, "', "Trilling Attendants are nerubians located in Ara-Kara, City of Echoes." },
  ["tristan lyte"] = { 2, "Arathi flight master located in Sanctified Grounds in Hal...", "Tristan Lyte is an Arathi flight master located in Sanctified Grounds in Hallowfall." },
  ["trixxie boltcrank"] = { 2, "goblin located at the Sanity's Rest in Ringing Deeps", "Trixxie Boltcrank is a goblin located at the Sanity's Rest in Ringing Deeps." },
  ["trizivast"] = { 2, "', "Trizivast is one of two possible bosses for the Opera of Malediction event in the Karazhan Crypts." },
  ["troll male winter reveler"] = { 2, "', "Troll Male Winter Revelers are trolls located in Frostwall." },
  ["trooper bybee"] = { 2, "gnome located on Mechagon Island", "Trooper Bybee is a gnome located on Mechagon Island." },
  ["trope the filth-belcher"] = { 2, "Broken quest giver located at the Dragonmaw Base Camp in ...", "Trope the Filth-Belcher is a Broken quest giver located at the Dragonmaw Base Camp in Shadowmoon Valley. He is friendly to players who have completed  [25-30] Blood Oath of the Netherwing." },
  ["truetusk clansman"] = { 2, "tuskarr", "Truetusk Clansman is a tuskarr." },
  ["truetusk elder"] = { 2, "tuskarr", "Truetusk Elder is a tuskarr." },
  ["truetusk fisherman"] = { 2, "tuskarr", "Truetusk Fisherman is a tuskarr." },
  ["truetusk harpooner"] = { 2, "tuskarr", "Truetusk Harpooner is a tuskarr." },
  ["truetusk idol-carver"] = { 2, "tuskarr", "Truetusk Idol-Carver is a tuskarr." },
  ["truetusk orca hunter"] = { 2, "tuskarr", "Truetusk Orca Hunter is a tuskarr." },
  ["truetusk sage-priest"] = { 2, "tuskarr", "Truetusk Sage-Priest is a tuskarr." },
  ["truetusk sea-caller"] = { 2, "tuskarr", "Truetusk Sea-caller is a tuskarr." },
  ["truetusk wayfinder"] = { 2, "tuskarr", "Truetusk Wayfinder is a tuskarr." },
  ["truetusk whaler"] = { 2, "tuskarr", "Truetusk Whaler is a tuskarr." },
  ["trytooth hardchisel"] = { 2, "Bluewax kobold found in Candle Rock in Highmountain durin...", "Trytooth Hardchisel is a Bluewax kobold found in Candle Rock in Highmountain during  [10-45] Candle of Command and  [10-45] Burn the Candle at Both Ends. According to Intern Jackie, Trytooth has a dull mind, but a sharp chisel." },
  ["tsah'tal"] = { 2, "mogu located in the Five Sisters in the Vale of Eternal B...", "Tsah'tal is a mogu located in the Five Sisters in the Vale of Eternal Blossoms." },
  ["tsegzaya"] = { 2, "first daughter of Teera", "Tsegzaya was the first daughter of Teera, the first matriarch of the Maruuk centaur. She stepped up to lead and revitalize the centaur after her mother's death, but faced many hardships." },
  ["tsogmaa"] = { 2, "centaur located in Valdrakken", "Tsogmaa is a centaur located in Valdrakken." },
  ["tsuo"] = { 2, "Rajani mogu warrior located on the Mogu'shan Terrace in K...", "Tsuo is a Rajani mogu warrior located on the Mogu'shan Terrace in Kun-Lai Summit, found mortally wounded by mantid invaders. With his dying breath, he asks Magni Bronzebeard and a champion of Azeroth to seek out his clan." },
  ["tu'kol"] = { 2, "broker vendor located in the Hall of Holding in Oribos", "Tu'kol is a broker vendor located in the Hall of Holding in Oribos." },
  ["tu-luak"] = { 2, "tuskarr located at the Mirage Abyss in Thousand Needles", "Tu-Luak is a tuskarr located at the Mirage Abyss in Thousand Needles." },
  ["tua'kea"] = { 2, "elderly tuskarr fisherman living in Moa'ki Harbor in the ...", "Tua'kea is an elderly tuskarr fisherman living in Moa'ki Harbor in the Dragonblight. He considers Tu'u'gwar to be their ancient aquan nemesis." },
  ["tuff gorehoof"] = { 2, "tauren located at the Circle of Wills in Underbelly", "Tuff Gorehoof is a tauren located at the Circle of Wills in Underbelly." },
  ["tuk"] = { 2, "tuskarr child found with Maru", "Tuk is a tuskarr child found with Maru and Nikamik at the pier of Unu'pe in the Borean Tundra during the Bronze Celebration." },
  ["tuka"] = { 2, "tortollan innkeeper located at the Tortaka Refuge in Vol'dun", "Tuka is a tortollan innkeeper located at the Tortaka Refuge in Vol'dun." },
  ["tukkaraq"] = { 2, "tuskarr chieftain of Morqut Village in the Forbidden Reach", "Tukkaraq is the tuskarr chieftain of Morqut Village in the Forbidden Reach. To protect his people, he asked adventurers to defeat the Farscale naga, kill their leader, and take their supplies." },
  ["tukkuttok"] = { 2, "tuskarr vendor found walking throughout central", "Tukkuttok is a tuskarr vendor found walking throughout central and southern Valdrakken." },
  ["tuklo"] = { 2, "tuskarr trade goods vendor found in Morqut Village in the...", "Tuklo is the tuskarr trade goods vendor found in Morqut Village in the Forbidden Reach." },
  ["tuktu"] = { 2, "tuskarr food", "Tuktu is a tuskarr food and drink vendor located on the northern coast of the Ohn'ahran Plains, where he runs a bar and grill with Khalla the centaur." },
  ["tukuku"] = { 2, "tortollan vendor located at the Tortaka Refuge in Vol'dun", "Kurtu is a tortollan vendor located at the Tortaka Refuge in Vol'dun." },
  ["tullek"] = { 2, "tuskarr located on Longclaw Island in the Azure Span", "Tullek is a tuskarr located on Longclaw Island in the Azure Span. He is teaching the art of Fishing to the Longclaw Fish Catcher." },
  ["tulu"] = { 2, "tortollan quest giver located outside the Temple of Kimbu...", "Tulu is a tortollan quest giver located outside the Temple of Kimbul in Vol'dun, along with Teekcha." },
  ["tuluun"] = { 2, "Broken shaman trainer located at Azure Watch in Azuremyst...", "Tuluun is a Broken shaman trainer located at Azure Watch in Azuremyst Isle. Occasionally, the Draenei Artificer right next to Tuluun will stop working, turn around to face him and verbally attack him, accusing him of spreading heresy." },
  ["tumat"] = { 2, "mogu of the Zian-Ti clan encountered in the Unknown Crypt...", "Tumat is a mogu of the Zian-Ti clan encountered in the Unknown Crypt during Island Expeditions." },
  ["tundra coldhoof"] = { 2, "gentle soul", "Tundra Coldhoof cuts an imposing figure, with her long horns, her carved halberd and a wolf at her side. Tundra is a gentle soul who welcomes travelers to Icemist Village as they arrived, making sure the wounded and weary receive whatever care is ..." },
  ["tunnel rat crew boss"] = { 2, "kobold located in Gundargaz in the Ringing Deeps", "Tunnel Rat Crew Boss is a kobold located in Gundargaz in the Ringing Deeps." },
  ["tunnel rat digger"] = { 2, "', "Tunnel Rat Diggers are kobolds found in Loch Modan." },
  ["tunnel rat forager"] = { 2, "', "Tunnel Rat Foragers are kobolds found in Loch Modan." },
  ["tunnel rat geomancer"] = { 2, "', "Tunnel Rat Geomancers are kobolds found at the Silver Stream Mine in Loch Modan. They are forcing troggs to dig for them." },
  ["tunnel rat kobold"] = { 2, "', "Tunnel Rat Kobolds are kobolds found in Loch Modan." },
  ["tunnel rat lackey"] = { 2, "Tunnel Rat kobold located in Loch Modan", "Tunnel Rat Lackey is a Tunnel Rat kobold located in Loch Modan. After Bluegill Representatives killed Mosshide Representative, the lackey escaped." },
  ["tunnel rat scout"] = { 2, "', "Tunnel Rat Scouts are kobolds found in Loch Modan." },
  ["tunnel rat surveyor"] = { 2, "', "Tunnel Rat Surveyors are kobolds located in Loch Modan." },
  ["tunnel rat vermin"] = { 2, "', "Tunnel Rat Vermin are kobolds located in Loch Modan." },
  ["tupit"] = { 2, "tuskarr fishing vendor located in the Kalu'ak village Unu...", "Tupit is a tuskarr fishing vendor located in the Kalu'ak village Unu'pe of the Borean Tundra." },
  ["tuppo"] = { 2, "tuskarr located in the Azure Span", "Tuppo is a tuskarr located in the Azure Span." },
  ["tur ragepaw"] = { 2, "furbolg", "Tur Ragepaw is a furbolg who can be found near Ursoc's Den. Some time in the past, Tur had visited Kodian, looking for information to help him cleanse Ursoc of the taint introduced by Vordrassil's sapling having been used to restore him to life." },
  ["tur'xoran"] = { 2, "satyr located at Shala'nir in Val'sharah", "Tur'xoran is a satyr located at Shala'nir in Val'sharah. He is summoned with the Tur'xoran's Summoning Stone." },
  ["turanis"] = { 2, "elf", "Turanis was an elf that was training to become a demon hunter. While he survived the first part of the ritual, he was driven mad, attacked his fellow trainees and died while fighting them." },
  ["turek the lucid"] = { 2, "voidscarred Broken located in Eredath", "Turek the Lucid is a voidscarred Broken located in Eredath." },
  ["turi flickerflame"] = { 2, "gnome located in Theramore Isle in Dustwallow Marsh", "Turi Flickerflame is a gnome located in Theramore Isle in Dustwallow Marsh. Turi is a former apprentice of the late Rhonin and the leader of the Sullied Banner, a rogue mage sect, that wanted to create mana bombs." },
  ["turida coldwind"] = { 2, "tauren flight master located at Warsong Hold in the Borea...", "Turida Coldwind is a tauren flight master located at Warsong Hold in the Borean Tundra. She can be found at the top of the Hold." },
  ["turik"] = { 2, "tuskarr renown envoy of Iskaara Tuskarr in Morqut Village...", "Turik is the tuskarr renown envoy of Iskaara Tuskarr in Morqut Village of the Forbidden Reach." },
  ["turkino melethril"] = { 2, "worgen", "Turkino Melethril is a worgen." },
  ["turuk amberstill"] = { 2, "dwarf weapon vendor located at Amberstill Ranch in Dun Mo...", "Turuk Amberstill is a dwarf weapon vendor located at Amberstill Ranch in Dun Morogh." },
  ["tuskarr (azure span)"] = { 2, "', "Tuskarr are dead tuskarr dragged by gnolls in Kargpaw's Den in the Azure Span." },
  ["tuskarr chieftain"] = { 2, "', "Tuskarr Chieftains are tuskarr creeps that can be encountered in the Icecrown Glacier tileset." },
  ["tuskarr child"] = { 2, "', "Tuskarr Children are tuskarr children located in Uktulut Backwater in the Waking Shores, at Khalla and Tuktu's grill in the Ohn'ahran Plains, and in Khuri's Fishing Spot and Camp Antonidas in the Azure Span." },
  ["tuskarr child (forbidden reach)"] = { 2, "', "Tuskarr Children are tuskarr children located on Morqut Islet in the Forbidden Reach. They are often seen with Ottuk Pups." },
  ["tuskarr elder"] = { 2, "tuskarr located in Rhonin's Shield in the Azure Span", "Tuskarr Elder is a tuskarr located in Rhonin's Shield in the Azure Span. Next to him are three Younglings." },
  ["tuskarr elder (forbidden reach)"] = { 2, "', "Tuskarr Elders are tuskarr located on Morqut Islet in the Forbidden Reach." },
  ["tuskarr fighter"] = { 2, "', "Tuskarr Fighters are tuskarr fighter creeps that can be encountered in the Icecrown Glacier tileset." },
  ["tuskarr fisher"] = { 2, "', "Tuskarr Fishers are tuskarr located in the Azure Span." },
  ["tuskarr guard"] = { 2, "', "Tuskarr Guards are tuskarr located on Morqut Islet and Tempest Coast in the Forbidden Reach. Some are patrolling their settlement on giant ottuks." },
  ["tuskarr healer"] = { 2, "', "Tuskarr Healers are tuskarr healer creeps that can be encountered in the Icecrown Glacier tileset." },
  ["tuskarr homesteader"] = { 2, "', "Tuskarr Homesteaders are tuskarr located on Morqut Islet in the Forbidden Reach." },
  ["tuskarr sailor"] = { 2, "', "Tuskarr Sailors are tuskarr located on the Tempest Coast in the Forbidden Reach." },
  ["tuskarr sorcerer"] = { 2, "', "Tuskarr Sorcerers are tuskarr sorcerer creeps that can be encountered in the Icecrown Glacier tileset." },
  ["tuskarr spearman"] = { 2, "', "Tuskarr Spearmen are tuskarr spearman creeps that can be encountered in the Icecrown Glacier tileset." },
  ["tuskarr trapper"] = { 2, "', "Tuskarr Trappers are tuskarr trapper creeps that can be encountered in the Icecrown Glacier tileset." },
  ["tuskarr traveler"] = { 2, "', "Tuskarr Travelers are tuskarr located in Iskaara and Camp Antonidas in the Azure Span." },
  ["tuskarr tribesman"] = { 2, "', "Tuskarr Tribesmen are tuskarr warriors from Kamagua that can be summoned by using the  [Horn of Kamagua]. They assist the adventurers in retaking the village of Iskaal from pirates." },
  ["tuskarr warrior"] = { 2, "', "Tuskarr Warriors are tuskarr warrior creeps that can be encountered in the Icecrown Glacier tileset." },
  ["tuskarr whaler"] = { 2, "', "Tuskarr Whalers are tuskarr located in Whaler's Nook in the Azure Span. They hunt Seafoam Scuttlers." },
  ["tuskarr worker"] = { 2, "', "Tuskarr Workers are tuskarr located at a trading outpost in the Azure Span." },
  ["tuskbreaker the scarred"] = { 2, "quilboar brute", "Tuskbreaker the Scarred is a quilboar brute who can be encountered on Island Expeditions." },
  ["tusklord hrak'kar"] = { 2, "racial leader of the tuskarr", "Tusklord Hrak'kar is the racial leader of the tuskarr. Little is known about him." },
  ["tutaqan"] = { 2, "chieftain", "Tutaqan is the chieftain and huntmaster of the Uktulut tribe of tuskarr found in the Waking Shores." },
  ["tuukanit"] = { 2, "tuskarr vendor located in Iskaara in the Azure Span", "Tuukanit is a tuskarr vendor located in Iskaara in the Azure Span." },
  ["tuul"] = { 2, "broker located in Haven in Zereth Mortis", "Tuul is a broker located in Haven in Zereth Mortis." },
  ["tuyuki"] = { 2, "dead tuskarr located in Brackenhide Brambles in the Azure...", "Tuyuki is a dead tuskarr located in Brackenhide Brambles in the Azure Span who planned to set sail to Northrend to reconnect with their kin. She went with her fellow tuskarr to a hunt, but was killed by the Brackenhide gnolls." },
  ["tweekette"] = { 2, "vulpera located in Tiragarde Sound", "Tweekette is a vulpera located in Tiragarde Sound. She is passed out under the wooden walkway behind the inn of Hatherford, in a pile of straw, surrounded by a hookah, take-out boxes, a musical instrument, and other things." },
  ["twilight abductor"] = { 2, "', "Twilight Abductors are members of the Twilight's Hammer located in Vermillion Redoubt in the Twilight Highlands, who are carrying off Vermillion Eggs." },
  ["twilight acolyte"] = { 2, "', "Twilight Acolytes are members of the Twilight's Hammer cult found in the Moonshrine Ruins in Blackfathom Deeps." },
  ["twilight adherent"] = { 2, "', "Twilight Adherents are humans and Forsaken of the Twilight's Hammer found at the Descent into Madness in Ulduar." },
  ["twilight ambusher"] = { 2, "', "Twilight Ambushers are orcs, jungle trolls, and Forsaken located in the Twilight Highlands." },
  ["twilight armsmaster"] = { 2, "', "Twilight Armsmasters are tauren and Forsaken found in Grim Batol." },
  ["twilight avenger"] = { 2, "', "Twilight Avengers are Twilight mobs located in Silithus. During the Call of the Scarab, they can drop pieces of the Twilight set, which are used during the event to summon bosses." },
  ["twilight binder"] = { 2, "', "Twilight Binders are blood elves, humans, Forsaken, and gnomes located in Avalanchion's Vault in Deepholm." },
  ["twilight blade (mob)"] = { 2, "', "Twilight Blades are located at the Sanctum of the Moon in Eversong Woods." },
  ["twilight captivator"] = { 2, "', "Twilight Captivators are dwarves, humans, orcs, and Forsaken located in the Ruins of Drakgor in the Twilight Highlands." },
  ["twilight champion"] = { 2, "', "Twilight Champions are humans, orcs, dwarves, and Forsaken located inside L'ghorek in Abyssal Depths." },
  ["twilight corrupter"] = { 2, "', "Twilight Corrupter is satyr boss and part of the Scepter of the Shifting Sands quest line. He will spawn next to the moonwell in the back corner of Twilight Grove in Duskwood." },
  ["twilight cryomagus"] = { 2, "', "Twilight Cryomagi are humans and Forsaken located in the Twilight Highlands." },
  ["twilight cryomancer"] = { 2, "', "Twilight Cryomancers are frost mages of various races located just southwest of the Stair of Destiny in Hellfire Peninsula during the Midsummer Fire Festival. They share spawn points with Twilight Frostblades." },
  ["twilight cryptomancer"] = { 2, "', "Twilight Cryptomancers are Twilight's Hammer fire mages located at the Masters' Gate in Deepholm." },
  ["twilight cultist (twilight highlands)"] = { 2, "', "Twilight Cultists are deceased orcs, humans, jungle trolls, and Forsaken located in the Twilight Highlands." },
  ["twilight darkcaster"] = { 2, "', "Twilight Darkcasters are found in Ahn'kahet: The Old Kingdom in Dragonblight." },
  ["twilight defiler"] = { 2, "', "Twilight Defilers are humans, Forsaken, jungle trolls, and orcs attacking the Temple of Earth in Deepholm." },
  ["twilight desecrator (deepholm)"] = { 2, "', "Twilight Desecrators are dwarves, humans, and Forsaken located in Deepholm." },
  ["twilight disciple (darkshore)"] = { 2, "', "Twilight Disciples are located at Master's Glaive in Darkshore prior to the Shattering." },
  ["twilight dragon hunter"] = { 2, "', "Twilight Dragon Hunters are humans and Forsaken located in Sable Ridge in Azshara." },
  ["twilight elementalist (blackfathom deeps)"] = { 2, "', "Twilight Elementalists are humanoids that are members of the Twilight's Hammer cult found in the Moonshrine Ruins and Moonshrine Sanctum of Blackfathom Deeps." },
  ["twilight elite dreadblade"] = { 2, "', "The Twilight Elite Dreadblades are vrykul who spawn in the first phase of the Warmaster Blackhorn encounter." },
  ["twilight elite slayer"] = { 2, "', "Twilight Elite Slayers are vrykul who spawn in the first phase of the Warmaster Blackhorn encounter." },
  ["twilight enforcer (darkshore)"] = { 2, "', "Twilight Enforcers are located in Darkshore." },
  ["twilight fire guard"] = { 2, "', "Twilight Fire Guards are night elves, humans, Forsaken, and dwarves found in Searing Gorge." },
  ["twilight flamequencher"] = { 2, "', "Twilight Flamequenchers are members of the Twilight's Hammer located in Vermillion Redoubt in the Twilight Highlands." },
  ["twilight footsoldier"] = { 2, "', "Twilight Footsoldiers were members of the Twilight's Blade found near Grim Batol in the Twilight Highlands." },
  ["twilight frost mage"] = { 2, "', "Twilight Frost Mages are frost mages of the Twilight's Hammer on the Descent into Madness in Ulduar." },
  ["twilight heretic"] = { 2, "', "Twilight Heretics are dwarves and Forsaken attacking the Temple of Earth in Deepholm." },
  ["twilight lord d'sak"] = { 2, "lord of the Twilight's Hammer", "Twilight Lord D'Sak is a lord of the Twilight's Hammer, and author of one of the True Believer articles sent to the cult's members in Silithus. He dictated that to ensure security of the texts, they should be distributed with an escort of armed cu..." },
  ["twilight loreseeker"] = { 2, "', "Twilight Loreseekers are members of the Twilight's Hammer cult found in the Moonshrine Ruins of Blackfathom Deeps." },
  ["twilight magus"] = { 2, "', "Twilight Magi are Forsaken, blood elves, humans, and gnomes located in the Twilight Bulwark in Thousand Needles." },
  ["twilight master"] = { 2, "', "Twilight Masters are Twilight mobs located at the Twilight Outpost in southwestern in Silithus. During the Call of the Scarab, they can drop pieces of the Twilight set, which are used during the event to summon bosses." },
  ["twilight orelifter"] = { 2, "', "Twilight Orelifters are drogbar located in the Deep Roads in Highmountain." },
  ["twilight overlord"] = { 2, "', "Twilight Overlords are Twilight mobs located at Staghelm Point and Twilight's Run in northeastern Silithus." },
  ["twilight reaver"] = { 2, "', "Twilight Reavers are members of the Twilight's Hammer cult found in the Moonshrine Ruins of Blackfathom Deeps." },
  ["twilight sadist"] = { 2, "', "Twilight Sadists are found in Blackrock Caverns." },
  ["twilight seeker"] = { 2, "', "Twilight Seekers were members of the Twilight's Hammer who attacked Courier Tormun and Durak Flamespeaker. They were accompanied by Watery Servants, Earthen Servants, and Blazing Servants." },
  ["twilight shadow"] = { 2, "', "Twilight Shadows are members of the Twilight's Hammer found in Blackfathom Deeps." },
  ["twilight shadowmage"] = { 2, "', "Twilight Shadowmages are Forsaken members of the Twilight's Hammer cult found in Moonshrine Ruins in the Blackfathom Deeps. They are accompanied by Voidwalker Minions." },
  ["twilight shadowshifter"] = { 2, "', "Twilight Shadowshifters are Forsaken, humans, orcs, and dwarves located in the Twilight Highlands." },
  ["twilight shaper"] = { 2, "', "Twilight Shapers are blood elves, Forsaken, gnomes, and humans located in Twilight Withering in Thousand Needles." },
  ["twilight shardkeeper"] = { 2, "', "Twilight Shardkeepers are drogbar located in Deep Roads in Highmountain." },
  ["twilight slayer"] = { 2, "', "Twilight Slayers are vrykul of the Twilight's Hammer in Ulduar." },
  ["twilight speaker viktor"] = { 2, "Forsaken located at Zoram Strand in Ashenvale", "Twilight Speaker Viktor is a Forsaken located at Zoram Strand in Ashenvale. He is a part of the Midsummer Fire Festival." },
  ["twilight stalker"] = { 2, "', "Twilight Stalkers are orcs and undead located in Twilight Highlands." },
  ["twilight subjugator"] = { 2, "', "Twilight Subjugators are humans, tauren, orcs, and trolls located at the Ascendant's Rise in Mount Hyjal." },
  ["twilight tormentor"] = { 2, "', "Twilight Tormentors are located at the Pool of Ask'ar in Blackfathom Deeps." },
  ["twilight tower huntress"] = { 2, "', "Twilight Tower Huntresses are Darkfallen patrolling the Viridescent Thicket in Amirdrassil." },
  ["twilight tower ranger"] = { 2, "', "Twilight Tower Rangers are Darkfallen found in Twilight Watchtower in Amirdrassil." },
  ["twilight vanquisher (mob)"] = { 2, "', "Twilight Vanquishers are Twilight's Hammer members found in Verdant Thicket in the highest, northern part of Mount Hyjal. They appear in 4 versions: human male, orc female, Grimtotem tauren male and troll male." },
  ["twilight volunteer"] = { 2, "', "Twilight Volunteers are found in Ahn'kahet: The Old Kingdom in Dragonblight. They appear after killing the Twilight Initiates during the Jedoga Shadowseeker boss fight, during the fight Jedoga will call one forth to be sacrificed." },
  ["twilight's blade acolyte"] = { 2, "', "Twilight's Blade Acolytes were members of the Twilight's Blade located in Dunwald Ruins in the Twilight Highlands. They are working on Nascent Portals or sparring." },
  ["twisted-branch gnarlclaw"] = { 2, "furbolg", "Twisted-Branch Gnarlclaw is a furbolg." },
  ["twisted-branch shaman"] = { 2, "furbolg", "Twisted-Branch Shaman is a furbolg." },
  ["twixnee boltgear"] = { 2, "goblin located at the Ruins of Na'gwa in Nagrand", "Twixnee Boltgear is a goblin located at the Ruins of Na'gwa in Nagrand, where she manages a holo-projector for Gazmolf Futzwangler." },
  ["twizix copperbomb"] = { 2, "goblin engineering vendor located at the Pinchwhistle Gea...", "Twizix Copperbomb is a goblin engineering vendor located at the Pinchwhistle Gearworks in the Spires of Arak." },
  ["twyla flickspring"] = { 2, "gnome located in Mechagon City", "Twyla Flickspring is a gnome located in Mechagon City. During mechagnome recruitment, she is seen in Rustbolt on Mechagon Island." },
  ["ty'thar"] = { 2, "', "Ty'thar is one of the special Rank 4 Challenge Card encounters in the Brawler's Guild. To fight him, players must use  [Challenge Card: Ty'thar], purchased from the card trader in the arena." },
  ["tymon"] = { 2, "kyrian located in Bastion in Elysian Hold", "Tymon is a kyrian located in Bastion in Elysian Hold. When a Maw Walker arrived in Bastion seeking an audience with the Archon, they encountered Tymon in conversation with Phillios at the Aspirant's Crucible." },
  ["typoe crunchmode"] = { 2, "goblin", "Typoe Crunchmode is a goblin who works for the Gadgetzan Times as Editor-in-chief." },
  ["tyre coppercog"] = { 2, "gnome located in Theron's Watch in the Azure Span", "Tyre Coppercog is a gnome located in Theron's Watch in the Azure Span." },
  ["tyrus blackhorn"] = { 2, "satyr", "Tyrus Blackhorn is a satyr who has been imprisoned at Blackhorn's Penance in Mount Hyjal since Archimonde's defeat at the Battle of Mount Hyjal. Matoclaw states that Blackhorn was once a night elf, but was tempted by the offers of power made by Ar..." },
  ["udalo"] = { 2, "broken seer", "Udalo is a broken seer who can be found in the Arcatraz. He was killed by the fel beings that roam around in the Arcatraz." },
  ["ug'thor bloodfrenzy"] = { 2, "orc son of Warden Nork Bloodfrenzy found outside Warsong ...", "Ug'thor Bloodfrenzy, called Ug by his father, is the orc son of Warden Nork Bloodfrenzy found outside Warsong Hold in the Borean Tundra. While looking at the Alliance Deserters his father asked him if he what they were." },
  ["ugrul skullcleaver"] = { 2, "Frostcrag drogbar found inside a cave at the Highmountain...", "Ugrul Skullcleaver is a Frostcrag drogbar found inside a cave at the Highmountain Summit in Highmountain." },
  ["uisgaz"] = { 2, "stasis-locked earthen located in the Lost Mines in the Ri...", "Uisgaz is a stasis-locked earthen located in the Lost Mines in the Ringing Deeps. Next to him is his plaque." },
  ["ujni"] = { 2, "tuskarr located at the Drifter's Dive in the Azure Span", "Ujni is a tuskarr located at the Drifter's Dive in the Azure Span. He guards Unjiup." },
  ["uka"] = { 2, "tuskarr child listening to Elder Poa's stories in the Fil...", "Uka is a tuskarr child listening to Elder Poa's stories in the Filled Bowl in the Azure Span." },
  ["ukhel beastcaller"] = { 2, "', "Ukhel Beastcallers are centaur located at the Eternal Kurgans in the Nokhud Offensive." },
  ["ukhel corruptor"] = { 2, "', "Ukhel Corruptor are centaur located at the Eternal Kurgans in the Nokhud Offensive." },
  ["ukhel deathspeaker"] = { 2, "', "Ukhel Deathspeakers are centaur located at the Eternal Kurgans in the Nokhud Offensive." },
  ["ukos bloodwhisper"] = { 2, "orc found in the Drag", "Ukos Bloodwhisper is an orc found in the Drag, just outside the Transmogrification station. It appears that he is rifling through the mail box, as if he is looking for something." },
  ["uktulut protector"] = { 2, "', "Uktulut Protectors are tuskarr located at Uktulut Backwater, Uktulut Pier, and Uktulut Outpost in the Waking Shores. Some are mounted on ottuk." },
  ["uktulut trainee"] = { 2, "', "Uktulut Trainees are tuskarr located at Uktulut Backwater in the Waking Shores. Some are seen training on Tuskarr Training Dummies, while others sparr with each other." },
  ["uktulut villager"] = { 2, "', "Uktulut Villagers are tuskarr located in Uktulut Backwater in the Waking Shores." },
  ["uktulut wanderer"] = { 2, "', "Uktulut Wanderers are tuskarr located at the Hissing Grotto in the Waking Shores. They can be seen jumping from the springboards and into the waters of the Bubble Bath below." },
  ["ulag the cleaver"] = { 2, "undead loyal to the Scourge", "Ulag the Cleaver is an undead loyal to the Scourge. He was subdued by the Deathguards of Brill and locked inside of the crypt of the town's cemetery in Tirisfal Glades." },
  ["ularogg cragshaper"] = { 2, "drogbar located in Neltharion's Lair", "Ularogg Cragshaper is a drogbar located in Neltharion's Lair. He was confronted by Navarrogg at the Lost Road." },
  ["uldir watcher"] = { 2, "ethereal located in Uldir", "The Uldir Watcher is an ethereal located in Uldir." },
  ["ulf the bloodletter"] = { 2, "vrykul hero of the Winterskorn clan found at Balejar Watc...", "Ulf the Bloodletter is a vrykul hero of the Winterskorn clan found at Balejar Watch in Howling Fjord." },
  ["ulfar"] = { 2, "last of the Drust druids", "Ulfar is the last of the Drust druids and the leader of the Thornspeakers, an order of Kul Tiran druids based in Ulfar's Den in Drustvar, who train in the old ways of the Drust from before the time of Gorak Tul. He is the last Drust of this organi..." },
  ["ullna"] = { 2, "earthen located in Dornogal", "Ullna is an earthen located in Dornogal. She begins the Children's Week questline for The War Within." },
  ["ultan blackgorge"] = { 2, "dwarf located at the Lunarfall in Shadowmoon Valley", "Ultan Blackgorge is a dwarf located at the Lunarfall in Shadowmoon Valley. He can only be recruited using the Headhunter's Harvest from Lunarfall Inn." },
  ["umai"] = { 2, "ankoan located in Nazjatar", "Umai is an ankoan located in Nazjatar." },
  ["umber goonrock"] = { 2, "tauren", "A tauren runemaster and felsworn, Umber Goonrock is Dak'mal's right-hand tauren. He is a tauren, but enormous and misshapen." },
  ["umbi"] = { 2, "tortollan child", "Umbi is a tortollan child who appears to follow the player in Seekers' Vista in Stormsong Valley during the completion of  [30-60] Battle Victorious and  [50WQ] Turtle Tactics." },
  ["umbraxis the cruel"] = { 2, "Cruel was a satyr located at Shala'nir in Val'sharah", "Umbraxis the Cruel was a satyr located at Shala'nir in Val'sharah. He was in charge of preparing Malfurion Stormrage to be corrupted by the power of the Emerald Nightmare." },
  ["un'glok blackfinger"] = { 2, "orc located in Shadowmoon Valley", "Un'glok Blackfinger is an orc located in Shadowmoon Valley." },
  ["unak"] = { 2, "earthen located in the Forgegrounds in Dornogal", "Unak is an earthen located in the Forgegrounds in Dornogal." },
  ["unakk"] = { 2, "tuskarr located in the Sand Bar in Zuldazar", "Unakk is a tuskarr located in the Sand Bar in Zuldazar. He is seen speaking with Shornai." },
  ["unbound bonemender"] = { 2, "', "Unbound Bonemenders appear in the Shrine of Lost Souls after defeating the Essence of Order in the Pursuing the Black Harvest scenario." },
  ["unbound corrupter"] = { 2, "', "Unbound Corrupters are crystal satyrs found in the Forlorn Woods in Crystalsong Forest." },
  ["unbound crafter"] = { 2, "', "Unbound Crafters are earthen located by the entrance to the Challenger's Rest in Dornogal. They are seen speaking with an Oathsworn Peacekeeper." },
  ["unbound earthen"] = { 2, "', "Unbound Earthen are earthen located in Freywold Village and Boulder Springs on the Isle of Dorn." },
  ["unbound ethereal"] = { 2, "', "Unbound Ethereals are ethereals located in the Blade's Edge Mountains." },
  ["unbound ethereal (eco-dome al'dani)"] = { 2, "', "Unbound Ethereals are ethereals located in the Al'dani Sands in Eco-Dome Al'dani." },
  ["unbound gardener"] = { 2, "', "Unbound Gardeners are earthen located in Freywold Village on the Isle of Dorn." },
  ["unbound meadworker"] = { 2, "', "Unbound Meadworkers are earthen located in Cinderbrew Meadery on the Isle of Dorn." },
  ["unbound protector"] = { 2, "', "Unbound Protectors are earthen located at the Crossroads Plaza, Rambleshire, and Freywold Village on the Isle of Dorn." },
  ["unbound rogue"] = { 2, "', "Unbound Rogues appear in the Den of Mortal Delights after defeating the Essence of Order in the Pursuing the Black Harvest scenario." },
  ["unbound seer"] = { 2, "', "Unbound Seers are crystal satyrs found in the Forlorn Woods in Crystalsong Forest." },
  ["unbound stoneshaper"] = { 2, "', "Unbound Stoneshaper are earthen located at the Contender's Gate in Dornogal. They keep Crystalmaw in check, allowing it to be used as a training dummy." },
  ["unbound trader"] = { 2, "', "Unbound Traders are earthen located in central Dornogal and at the Crossroads Plaza on the Isle of Dorn." },
  ["unbound trickster"] = { 2, "', "Unbound Tricksters are crystal satyrs found in the Forlorn Woods in Crystalsong Forest." },
  ["unbound worker"] = { 2, "', "Unbound Workers are earthen located in the Coreway on the Isle of Dorn." },
  ["uncle bedlam"] = { 2, "prominent member of the Bilgewater Battalion", "Uncle Bedlam is a prominent member of the Bilgewater Battalion who resides in Bilgewater Harbor of Azshara. He appears to be the Battalion’s mascot, promoter, or some other informal leader." },
  ["undalog"] = { 2, "drogbar leader", "Undalog was a drogbar leader who had been stealing eagle eggs in order to feed his worms. He was taken down in his cave by the Hidden Path in order to protect the eagles from extinction." },
  ["undana frostbarb"] = { 2, "naga located in Nazjatar", "Undana Frostbarb is a naga located in Nazjatar." },
  ["undead drust"] = { 2, "skeleton", "Undead Drust is a skeleton." },
  ["undead female winter reveler"] = { 2, "', "Undead Female Winter Revelers are forsaken located in Frostwall." },
  ["undead miner"] = { 2, "', "Undead Miners are undead located in the Hollowstone Mine in the Grizzly Hills. Former trappers, they were cursed to undeath by the Shade of Arugal for refusing to join the Wolfcult." },
  ["undead ravager"] = { 2, "', "Undead Ravagers are skeletons who roam the Valley of Bones in Desolace. They can also be summoned by Outcast Necromancers." },
  ["undead warlock"] = { 2, "action figure released by SOTA Toys", "The Undead Warlock was an action figure released by SOTA Toys, along with the Tauren Shaman and the Jungle Troll Voodoo Priest." },
  ["undermine watcher"] = { 2, "', "Undermine Watchers are ethereals located in the Liberation of Undermine." },
  ["underseer bloodmane"] = { 2, "orc of the Iron Horde", "Underseer Bloodmane is an orc of the Iron Horde. His prize talbuk, Prize, is with him inside the building on Engineer Trak's rise northeast of Mor'gran Logworks in northeastern Talador." },
  ["understone breacher"] = { 2, "', "Understone Breachers are drogbar located in Highmountain." },
  ["understone demolisher"] = { 2, "', "Understone Demolishers are drogbar located in the Dragon's Spine in Neltharion's Lair. They transform into Colossal Charskins." },
  ["understone drudge"] = { 2, "', "Understone Drudges are drogbar located on the Lost Road in Neltharion's Lair." },
  ["understone drummer"] = { 2, "', "Understone Drummers are drogbar located in Neltharion's Lair." },
  ["understone lasher"] = { 2, "', "Understone Lashers are drogbar located in Neltharion's Lair." },
  ["understone rocklord"] = { 2, "', "Understone Rocklords are drogbar located in Highmountain." },
  ["undying servant"] = { 2, "', "Undying Servants are undead located in the Return to Karazhan." },
  ["undying soulbinder"] = { 2, "Mawsworn kyrian located in the Maw", "The Undying Soulbinder is a Mawsworn kyrian located in the Maw." },
  ["unearthed paragon"] = { 2, "mantid located in the middle of the Five Sisters in the V...", "Unearthed Paragon is a mantid located in the middle of the Five Sisters in the Vale of Eternal Blossoms. They die when all nearby Klaxxi Wakeners have been killed." },
  ["ungarl"] = { 2, "furbolg Chieftain of the Blackmaw tribe", "Ungarl is the furbolg Chieftain of the Blackmaw tribe. The Alliance hoped to include them as an ally, but this was foiled by a Horde agent." },
  ["unidentified centaur"] = { 2, "dead Nokhud centaur lying on the road between Szar Skeleth", "The Unidentified Centaur is a dead Nokhud centaur lying on the road between Szar Skeleth and Ridgewater Retreat in the Ohn'ahran Plains during  [20-70] Mystic Mystery. He was one of the Nokhud who ambushed Initiate Boku, and managed to grab  [Boku..." },
  ["unity"] = { 2, "extremely powerful abomination made entirely of kyrian flesh", "The Soulfused Construct, later known as Unity, is an extremely powerful abomination made entirely of kyrian flesh, created by First Apprentice Malkrex and Sharrex the Fleshcrafter in the Flesh Stitchery in Maldraxxus. The construct is the culminat..." },
  ["unjiup"] = { 2, "tuskarr located at the Drifter's Dive in the Azure Span", "Unjiup is a tuskarr located at the Drifter's Dive in the Azure Span. He guards The Drifter and is in turn guarded by Ujni." },
  ["unka"] = { 2, "younger sister of the tuskarr Taruka", "Unka is the younger sister of the tuskarr Taruka. She is an energetic child who was desperate to repair and fly Taruka's old kite, and Taruka hoped to earn enough knots to buy kite silk for her from the hoarder Warrak." },
  ["unkimi"] = { 2, "tuskarr located in the Azure Span", "Unkimi is a tuskarr located in the Azure Span." },
  ["unlucky gnoll"] = { 2, "', "Unlucky Gnolls are gnolls located just south of Gadgetzan in Tanaris. Partially Teleported Gnolls are also roaming the area." },
  ["unlucky kobold"] = { 2, "', "Unlucky Kobolds are kobolds located just south of Gadgetzan in Tanaris. Partially Teleported Kobolds are also roaming the area." },
  ["unnamed khanam dochra"] = { 2, "', "The Unnamed Khanam Dochra, or 'Favoured Daughter', was heir to the Khanam in a time of strife between dragons. She led a caravan on a diplomatic endeavor to Iskaara territory near Traitor's Rest at the behest of tuskarr leaders." },
  ["unng ak"] = { 2, "spokesman for all the furbolg packs gathered by Krasus", "Unng Ak was the spokesman for all the furbolg packs gathered by Krasus and Rhonin to help the night elves in their fight against the Burning Legion. He was of the Blackmaw tribe." },
  ["unpiat"] = { 2, "tuskarr located in Iskaara in the Azure Span", "Unpiat is a tuskarr located in Iskaara in the Azure Span." },
  ["unpukiat"] = { 2, "tuskarr innkeeper of Morqut Village in the Forbidden Reach", "Unpukiat is the tuskarr innkeeper of Morqut Village in the Forbidden Reach." },
  ["unraveled energy broker"] = { 2, "', "Unraveled Energy Brokers are brokers located on K'aresh. They can only be seen while Phase Diving." },
  ["unrepentant conjuror"] = { 2, "', "Unrepentant Conjurors are undead found in the Season of Discovery Karazhan Crypts dungeon." },
  ["unrepentant criminal"] = { 2, "', "Unrepentant Criminals are undead found in the Season of Discovery Karazhan Crypts dungeon." },
  ["unruly patron"] = { 2, "Veiled Market", "Unruly Patrons are brokers located in Tazavesh, the Veiled Market." },
  ["unseen marksman"] = { 2, "', "Unseen Marksmen are orcs, and night elves, dwarves, and Forsaken located in Trueshot Lodge." },
  ["unseen path ranger"] = { 2, "', "Unseen Path Rangers are located in Deliverance Point on the Broken Shore." },
  ["unstable fragment"] = { 2, "tortollan", "Unstable Fragment is a tortollan." },
  ["untethered lasher"] = { 2, "', "Untethered Lashers are ethereals located around North Sufaad on K'aresh. They can only be seen while Phase Diving." },
  ["untethered spellweaver"] = { 2, "', "Untethered Spellweavers are ethereals located around North Sufaad on K'aresh. They can only be seen while Phase Diving." },
  ["unthen"] = { 2, "earthen located in Rambleshire on the Isle of Dorn", "Unthen is an earthen located in Rambleshire on the Isle of Dorn." },
  ["untiq"] = { 2, "tuskarr located in Mulsted's Marquee in the Azure Span", "Untiq is a tuskarr located in Mulsted's Marquee in the Azure Span. She is holding a child." },
  ["unu'pe spearman"] = { 2, "', "Unu'pe Spearman are tuskarr guards that patrol the village of Unu'pe in the Borean Tundra." },
  ["unu'pe turtle rider"] = { 2, "', "Unu'pe Turtle Riders are tuskarr guards that patrol the village of Unu'pe in the Borean Tundra." },
  ["unu'pe villager"] = { 2, "', "Unu'pe Villagers are tuskarr villagers found in Unu'pe in the Borean Tundra. One is found chopping up a Dead Caribou." },
  ["unworthy initiate"] = { 2, "', "Unworthy Initiates are locked up in Acherus: The Ebon Hold to Acherus Soul Prisons." },
  ["upio"] = { 2, "tuskarr sleighing on a small isle west of the Azure Archi...", "Upio is a tuskarr sleighing on a small isle west of the Azure Archives in the Azure Span." },
  ["urazeras"] = { 2, "dracthyr located in the inn at Emberwatch in the Ohn'ahra...", "Urazeras is a dracthyr located in the inn at Emberwatch in the Ohn'ahran Plains." },
  ["urdak"] = { 2, "arakkoa found in Terokkar Forest", "Urdak is an arakkoa found in Terokkar Forest." },
  ["urel stoneheart"] = { 2, "first earthen king", "Urel Stoneheart was the first earthen king. He received  [Val'anyr, Hammer of Ancient Kings] from the titans themselves." },
  ["urela bloodrock"] = { 2, "orc banker in Warspear Hold in Warspear on Ashran", "Urela Bloodrock is an orc banker in Warspear Hold in Warspear on Ashran." },
  ["urgev the flayer"] = { 2, "vrykul located in Akstad in Stormheim", "Urgev the Flayer is a vrykul located in Akstad in Stormheim. He can be found practicing on a Training Block." },
  ["urglan"] = { 2, "centaur located in Nokhudon Hold in the Ohn'ahran Plains", "Urglan is a centaur located in Nokhudon Hold in the Ohn'ahran Plains." },
  ["urgolax"] = { 2, "mogu found on the Golden Stair in the Vale of Eternal Blo...", "Urgolax is a mogu found on the Golden Stair in the Vale of Eternal Blossoms. He is a pandarian champion." },
  ["urheld darkstone"] = { 2, "', "Urheld Darkstone, despite being an alchemist of great skill, was thought insane by his contemporaries and, hence, did not share his research. Instead, he etched it onto tablets." },
  ["urluk cloud-killer"] = { 2, "warlock of the Stormreaver clan", "Urluk Cloud-killer is a warlock of the Stormreaver clan who followed Gul'dan into the Tomb of Sargeras. He was frightened by the guardians of the tomb, and so Gul'dan slapped him across the face." },
  ["urok doomhowl"] = { 2, "ogre mini-boss summoned in Hordemar City in Lower Blackro...", "Urok Doomhowl is an ogre mini-boss summoned in Hordemar City in Lower Blackrock Spire. Urok cursed Warosh and stole his mojo." },
  ["ursal the mauler"] = { 2, "furbolg found in Gnarlpine Hold in Teldrassil", "Ursal the Mauler is a furbolg found in Gnarlpine Hold in Teldrassil." },
  ["ursila hudsen"] = { 2, "worgen located at the Lunarfall in Shadowmoon Valley", "Ursila Hudsen is a worgen located at the Lunarfall in Shadowmoon Valley. She can only be recruited using the Headhunter's Harvest from Lunarfall Inn." },
  ["urtago"] = { 2, "earthen located at the Crossroads Plaza", "Urtago is an earthen located at the Crossroads Plaza and in Fallside Outpost on the Isle of Dorn. She is the caretaker of Mourning Rise." },
  ["uruson"] = { 2, "rare furbolg", "Uruson is a rare furbolg who patrols the road in Starbreeze Village in Teldrassil. He is on a 1-2 hour respawn timer." },
  ["uskogg"] = { 2, "drogbar stable master located in Zaralek Cavern", "Uskogg is a drogbar stable master located in Zaralek Cavern." },
  ["usuri brightcoin"] = { 2, "goblin found in the Underbelly beneath Dalaran next to th...", "Usuri Brightcoin is a goblin found in the Underbelly beneath Dalaran next to the banker, Binzik Goldbook. During the purge of Dalaran, she was in a defensive pose." },
  ["usurper simona"] = { 2, "venthyr located at Darkwall Tower in Revendreth", "Usurper Simona is a venthyr located at Darkwall Tower in Revendreth. She was appointed to rule over Darkwall Tower after Prince Renathal was deposed by Denathrius." },
  ["utaik"] = { 2, "tuskarr standing next to Ataika on the western end of the...", "Utaik is a tuskarr standing next to Ataika on the western end of the besieged Kaskala in the Borean Tundra." },
  ["utama"] = { 2, "ankoan warrior", "Utama was an ankoan warrior who lies buried at Utama's Stand in Nazjatar. Utama attempted to hide from the naga in Kal'methir but discovered it was overrun with makrura and died in battle after being surrounded by the Kil'karrok makrura." },
  ["uthaga"] = { 2, "earthen located in the Forgegrounds in Dornogal", "Uthaga is an earthen located in the Forgegrounds in Dornogal." },
  ["uthek the wise"] = { 2, "centaur quest giver located in Gelkis Village in Desolace", "Uthek the Wise is a centaur quest giver located in Gelkis Village in Desolace. She was the shaman of the Gelkis clan and was initially neutral to players." },
  ["uukkarnit"] = { 2, "tuskarr trade goods vendor found in Kamagua in the Howlin...", "Uukkarnit is a tuskarr trade goods vendor found in Kamagua in the Howling Fjord." },
  ["uungbrul"] = { 2, "drogbar Trade Goods vendor", "Uungbrul is a drogbar Trade Goods vendor and member of the Stonedark clan who appears in the Hall of Chieftains in Thunder Totem after completing  [10-45] Unexpected Allies." },
  ["uvuld the forseer"] = { 2, "vrykul", "Uvuld the Forseer is a vrykul that can be encountered during Island Expeditions." },
  ["uylaru"] = { 2, "Broken located at the Fel Pits in Shadowmoon Valley", "Uylaru is a Broken located at the Fel Pits in Shadowmoon Valley. He holds a medallion fragment." },
  ["uzgarogg the seer"] = { 2, "drogbar located in the Deep Roads in Highmountain", "Uzgarogg the Seer is a drogbar located in the Deep Roads in Highmountain." },
  ["vadne bleakheart"] = { 2, "draenei of the Primalists located in a cave in the Serene...", "Vadne Bleakheart is a draenei of the Primalists located in a cave in the Serene Dreams Spa in Thaldraszus. She leads the Primalist force and summons elementals to disrupt the spa, and Quilius asks to kill her." },
  ["vadrak"] = { 2, "vrykul located in Stormheim", "Vadrak is a vrykul located in Stormheim." },
  ["vaedra strayfend"] = { 2, "Arathi stable master located in Mereldar in Hallowfall", "Vaedra Strayfend is an Arathi stable master located in Mereldar in Hallowfall." },
  ["vagnhild"] = { 2, "vrykul located in Stormheim", "Vagnhild is a vrykul located in Stormheim." },
  ["vahi bonesplitter"] = { 2, "orc located at Razor Hill in Durotar", "Vahi Bonesplitter is an orc located at Razor Hill in Durotar. She will trade  [Monster Hunter's First Rune Fragment],  [Monster Hunter's Second Rune Fragment], and  [Monster Hunter's Third Rune Fragment] to warriors in exchange for  [Severed Quilb..." },
  ["vahu the weathered"] = { 2, "Broken located on the bottom floor of the Fel Hammer in M...", "Vahu the Weathered is a Broken located on the bottom floor of the Fel Hammer in Mardum. As a researcher of the Illidari, he wrote the Tome of Fel Secrets." },
  ["vakan"] = { 2, "master of shadowflame", "Vakan is one of the Zaqali Elders, he is a master of shadowflame and is locked in constant conflict with his fellow elder, Gholna, over who is stronger. Through devastation and chaos, each elder attempts to outdo the other until one of them is cro..." },
  ["vakora of the flock"] = { 2, "arakkoa located at Ravenskar in the Spires of Arak", "Vakora of the Flock is an arakkoa located at Ravenskar in the Spires of Arak." },
  ["vakril"] = { 2, "tuskarr located in the Azure Span", "Vakril is a tuskarr located in the Azure Span." },
  ["val (broker)"] = { 2, "broker located at Pilgrim's Grace in Zereth Mortis", "Val is a broker located at Pilgrim's Grace in Zereth Mortis." },
  ["val thalvassa"] = { 2, "Arathi Lamplighter", "Val Thalvassa is an Arathi Lamplighter who appears outside the Council's Treasury in central Dornogal at level 80 to offer  [80] A Concerned Friend, an optional breadcrumb to the 'Rest at Last' questline in Hallowfall. Upon accepting the quest, sh..." },
  ["valarjar aspirant"] = { 2, "', "Valarjar Aspirants are vrykul located in the Halls of Valor and in Skyhold." },
  ["valarjar aspirants"] = { 2, "', "Valarjar Aspirants are vrykul located in Skyhold." },
  ["valarjar champion"] = { 2, "', "Valarjar Champions are vrykul found at various locations in the Broken Isles including Halls of Valor, Trial of Valor and the Broken Shore." },
  ["valarjar falconer"] = { 2, "', "Valarjar Falconers are vrykul located in Halls of Valor. Friendly versions appear during the Fields of the Eternal Hunt scenario." },
  ["valarjar marksman"] = { 2, "', "Valarjar Marksmen are vrykul found at the Fields of the Eternal Hunt in the Halls of Valor dungeon. Friendly versions appear during the Trial of Valor." },
  ["valarjar mystic"] = { 2, "', "Valarjar Mystics are vrykul found in the Halls of Valor dungeon. Friendly versions appear during the Trial of Valor and the Fields of the Eternal Hunt scenario." },
  ["valarjar purifier"] = { 2, "', "Valarjar Purifiers are vrykul found in the Halls of Valor dungeon. Friendly versions appear during the Fields of the Eternal Hunt scenario." },
  ["valarjar runebearer"] = { 2, "', "Valarjar Runebearers are vrykul summoned by Odyn at the Hall of Glory in the Trial of Valor raid. They are each branded with a specific rune." },
  ["valarjar runecarver"] = { 2, "', "Valarjar Runecarvers are vrykul found at various locations in the Broken Isles including Halls of Valor, Trial of Valor, and the Broken Shore." },
  ["valarjar shieldmaiden"] = { 2, "Fields of the Eternal Hunt scenario", "Valarjar Shieldmaidens are vrykul located in the Halls of Valor, as well as in Niskara, the Fields of the Eternal Hunt scenario, and on the Broken Shore." },
  ["valarjar spear-sister"] = { 2, "', "Valarjar Spear-Sisters are female vrykul members of the Valarjar faction, who used their expertise as warriors in battle during the third invasion of the Burning Legion. They principally answer to Odyn, and the Battlelord of the Valarjar." },
  ["valarjar stormrider"] = { 2, "', "Valarjar Stormriders are vrykul found riding Storm Drakes at the High Gate in the Halls of Valor dungeon. While alive, they are untargetable, but their corpses are seen after killing the Storm Drakes." },
  ["valarjar thundercaller"] = { 2, "', "Valarjar Thundercallers are vrykul located in the Halls of Valor." },
  ["valarjar trapper"] = { 2, "', "Valarjar Trappers are vrykul found at the Fields of the Eternal Hunt in the Halls of Valor dungeon. Friendly versions appear during the Fields of the Eternal Hunt scenario." },
  ["valarjar warsinger"] = { 2, "', "Valarjar Warsingers are vrykul located in Deliverance Point on the Broken Shore. They inform the Battlelord that Odyn requests an audience in Skyhold." },
  ["valdemar stormseeker"] = { 2, "vrykul emissary", "Valdemar Stormseeker is a vrykul emissary and Valarjar's quartermaster found at Valdisdall in Stormheim." },
  ["vale hunter (dracthyr)"] = { 2, "', "Vale Hunters are dracthyr." },
  ["valenta thuridale"] = { 2, "Arathi airship engineer located in Mereldar in Hallowfall", "Valenta Thuridale is an Arathi airship engineer located in Mereldar in Hallowfall and later Dornogal on the Isle of Dorn. She has been designing airships for more than fifty years and was the architect of the Starchaser." },
  ["valfir the unrelenting"] = { 2, "Drust blighted brute located in Mistveil Tangle in Ardenw...", "Valfir the Unrelenting is a Drust blighted brute located in Mistveil Tangle in Ardenweald. To attack the Drust, one player needs to pick up Sparkling Animaseed and use its extra action button on Valfir." },
  ["valgrexx"] = { 2, "nerubian located in the Maddening Deep in Azj-Kahet", "Valgrexx is a nerubian located in the Maddening Deep in Azj-Kahet. He is involved in the World Quest  [80WQ] Documenting Discordance." },
  ["valiant protector"] = { 2, "', "Valiant Protectors are kyrian located in Maldraxxus and the Maw." },
  ["valiant trainee"] = { 2, "', "Valiant Trainees are aspirant kyrian located in Xandria's Vigil in Bastion. Many of them are found dead, scattered around the Temple of Courage, killed by the Maldraxxi invaders." },
  ["validated doomsayer"] = { 2, "', "Validated Doomsayers are doomsayers whose doomsday preachings were finally proven right after the appearance of Argus in the skies of Azeroth." },
  ["valkyra aspirant"] = { 2, "', "Valkyra Aspirants are vrykul located in Stormheim." },
  ["valkyra guardian"] = { 2, "', "Valkyra Guardians are vrykul located in the Field of Fallen Kings in Stormheim and in Helheim accompanying Ashildir. They are also present during the Legion Assaults." },
  ["valkyra shieldmaiden"] = { 2, "', "Valkyra Shieldmaidens are vrykul located in Stormheim and in Skyhold." },
  ["valkyra shieldmaidens"] = { 2, "', "Valkyra Shieldmaidens are vrykul who briefly appear in Skyhold after recruiting them as Class Hall followers (warrior only)." },
  ["valrin paller"] = { 2, "Arathi located in Dunelle's Rest inn", "Valrin Paller is an Arathi located in Dunelle's Rest inn, in Dunelle's Kindness in Hallowfall. When fungarians in the Mycomancer Caverns started raiding spice crates bound for Lorel's Crossing, Valrin called on adventurers to go into those caverns..." },
  ["valued diner"] = { 2, "', "Valued Diners are located at the Vatworks in the Undermine." },
  ["valwar"] = { 2, "son of Warrith", "Valwar is the son of Warrith and the leader of a Broken tribe in Hellfire Peninsula. He disagrees with many of his father's decisions to trust outsiders." },
  ["valxx cracklequil"] = { 2, "goblin found in Everlook in Winterspring", "Valxx Cracklequil is a goblin found in Everlook in Winterspring." },
  ["vana gillscorhe"] = { 2, "Arathi located in Mereldar in Hallowfall", "Vana Gillscorhe is an Arathi located in Mereldar in Hallowfall." },
  ["vandellor"] = { 2, "high elf priest", "High Priest Vandellor was a high elf priest and a close friend of Grand Magister Belo'vir, and of Liadrin's family. After the parents of the future Blood Knight Matriarch died, Vandellor adopted the girl." },
  ["vanessa fairgraves"] = { 2, "undead death knight of the Knights of the Ebon Blade foun...", "Vanessa Fairgraves is an undead death knight of the Knights of the Ebon Blade found on Darkstone Isle off the Broken Shore. During   [10-45] The Dead and the Damned, she salutes the death knight adventurer and informs them that Baron Sliver has al..." },
  ["vanthryn the merciless"] = { 2, "Darkfallen of the San'layn", "Vanthryn the Merciless is a Darkfallen of the San'layn. He's one of Prince Valanar's personal retainers in Naxxanar in the Borean Tundra, along with Luthion the Vile." },
  ["vara balnir"] = { 2, "wife of Jorum Balnir", "Vara Balnir was the wife of Jorum Balnir and mother of Jarim. Her pride and joy was the snapdragon flowers that grew on the Balnir Farmstead." },
  ["varas (domanaar)"] = { 2, "domanaar", "Varas was a domanaar who built and commanded the Obscurion Citadel. His greatest delight was martial prowess and he donned a set of impenetrable armor known as the Lorica Umbra in battle." },
  ["varden claridge"] = { 2, "worgen found with Netheril Swiftstream at the Artisan's M...", "Varden Claridge is a worgen found with Netheril Swiftstream at the Artisan's Market in Valdrakken during  [70] Who Are You?." },
  ["vark battlescar"] = { 2, "tauren quest giver located in Shadowprey Village in Desolace", "Vark Battlescar is a tauren quest giver located in Shadowprey Village in Desolace. He is to be found on the second story of the building at 23,70, upstairs from the skinning trainer." },
  ["varlasen"] = { 2, "venthyr located in Revendreth", "Varlasen is a venthyr located in Revendreth." },
  ["varoun"] = { 2, "broker located in Haven in Zereth Mortis", "Varoun is a broker located in Haven in Zereth Mortis." },
  ["varrik"] = { 2, "venthyr located in Torghast", "Varrik is a venthyr located in Torghast, Tower of the Damned." },
  ["varyx the damned"] = { 2, "arakkoa located at the Ruins of Kra'nak", "Varyx the Damned is an arakkoa located at the Ruins of Kra'nak, one of the many rare mobs of Tanaan Jungle which could be found by the  [Hunter's Seeking Crystal] and  [Master Hunter's Seeking Crystal]. He was originally designed to be 'activated'..." },
  ["vashaar"] = { 2, "arakkoa", "Vashaar is an arakkoa." },
  ["vasilica"] = { 2, "venthyr stable master located at the Absolution Crypt in ...", "Vasilica is a venthyr stable master located at the Absolution Crypt in Revendreth. She is also present in Sinfall." },
  ["vaskarn"] = { 2, "dracthyr", "Vaskarn is a dracthyr that provides crest exchanges, found at key locations during a given season. She provides downgrades and upgrades for the crests as long as the character meets the criteria for them." },
  ["vault statue"] = { 2, "', "Vault Statues are mogu." },
  ["vault watcher"] = { 2, "', "Vault Watchers are ethereals located throughout the Vault of the Incarnates." },
  ["vaultkeeper aleer"] = { 2, "ethereal void storager located in Valdrakken", "Vaultkeeper Aleer is an ethereal void storager located in Valdrakken." },
  ["vaultkeeper edouin"] = { 2, "ethereal void banker found in the Ethereal Corridor in th...", "Vaultkeeper Edouin is an ethereal void banker found in the Ethereal Corridor in the Shrine of Seven Stars." },
  ["vaultkeeper fizznoggin"] = { 2, "gnome banker located in the Celestial Vault in the Shrine...", "Vaultkeeper Fizznoggin is a gnome banker located in the Celestial Vault in the Shrine of Seven Stars. This section concerns content related to Battle for Azeroth." },
  ["vaultkeeper jazra"] = { 2, "ethereal void banker found in Orgrimmar", "Vaultkeeper Jazra is an ethereal void banker found in Orgrimmar, alongside Warpweaver Dushar and Thaumaturge Zajir." },
  ["vaultkeeper maeelthas"] = { 2, "ethereal void storager located in the Frostwall's Storehouse", "Vaultkeeper Maeelthas is an ethereal void storager located in the Frostwall's Storehouse." },
  ["vaultkeeper meelad"] = { 2, "ethereal void banker found in the Hall of Secrets in the ...", "Vaultkeeper Meelad is an ethereal void banker found in the Hall of Secrets in the Shrine of Two Moons." },
  ["vaultkeeper nizsham"] = { 2, "ethereal void storager", "Vaultkeeper Nizsham is an ethereal void storager who can be found in Andromath's Rise in Stormshield." },
  ["vaultkeeper razhid"] = { 2, "ethereal void banker found in the Three Winds shop in the...", "Vaultkeeper Razhid is an ethereal void banker found in the Three Winds shop in the Canals of Stormwind City." },
  ["vaultkeeper sarniv"] = { 2, "ethereal void storager located at Lunarfall's Storehouse ...", "Vaultkeeper Sarniv is a ethereal void storager located at Lunarfall's Storehouse in Shadowmoon Valley. He is also located in Dalaran Merchant's Bank in Dalaran." },
  ["vaultkeeper ta'khis"] = { 2, "broker located in the Hall of Curiosities in Oribos", "Vaultkeeper Ta'khis is a broker located in the Hall of Curiosities in Oribos." },
  ["vaultkeeper vohra"] = { 2, "ethereal found in Warspear's Tower of Elements in Ashran", "Vaultkeeper Vohra is an ethereal found in Warspear's Tower of Elements in Ashran." },
  ["vaultkeeper xir"] = { 2, "ethereal located in the Ether House in the Fissure in Dor...", "Vaultkeeper Xir is an ethereal located in the Ether House in the Fissure in Dornogal." },
  ["vaultkeeper xy'vez"] = { 2, "broker located in Astral Getaways in Tazavesh", "Vaultkeeper Xy'vez is a broker located in Astral Getaways in Tazavesh, the Veiled Market." },
  ["ve'brax"] = { 2, "broker associated with Cartel Ve found in Desmotaeron in ...", "Ve'brax is a broker associated with Cartel Ve found in Desmotaeron in the Maw. He has been captured by the Mawsworn and claims to be next in line to be drained of anima by Runemaster Mavrok." },
  ["ve'lor the messenger"] = { 2, "broker located in Torghast", "Ve'lor the Messenger is a broker located in Torghast, Tower of the Damned. He starts the bonus objective  [60B] Ve'lor's Lost Parcel." },
  ["ve'nari"] = { 2, "broker", "Ve'nari (/vɛˈnɑːri/ veh-NAH-ree), originally named just Nari, is a broker who seeks to restore K'aresh. Once a K'areshi member of the Ravel, she served as an agent of then High Priest Salhadaar." },
  ["ve'nish"] = { 2, "broker located in Torghast", "Ve'nish is a broker located in Torghast, Tower of the Damned. He starts  [60] The Box of Many Things, which unlocks the new form of meta-progression in Torghast." },
  ["ve'nyo"] = { 2, "broker located at the Ring of Fates in Oribos", "Ve'nyo is a broker located at the Ring of Fates in Oribos." },
  ["ve'rayn"] = { 2, "broker", "Ve'rayn is a broker who briefly appears at the Ring of Transference in Oribos after players accept  [60] Explore Torghast, where she starts  [60] Trust Issues as part of the Torghast storyline. In patch 9.1, she appears in Korthia as part of the P..." },
  ["vear darksnout"] = { 2, "furbolg located at Thistlefur Hold in Ashenvale", "Vear Darksnout is a furbolg located at Thistlefur Hold in Ashenvale." },
  ["veeno"] = { 2, "vulpera located at Wingrest Embassy in the Waking Shores", "Veeno is a vulpera located at Wingrest Embassy in the Waking Shores." },
  ["vekax"] = { 2, "arakkoa quest giver located in the Lower City of Shattrat...", "Vekax is an arakkoa quest giver located in the Lower City of Shattrath City." },
  ["vekh"] = { 2, "arakkoa found in Trogma's Claim in the Blade's Edge Mount...", "Vekh is an arakkoa found in Trogma's Claim in the Blade's Edge Mountains. He is the leader of the Vekh'nir arakkoa which have enslaved all the ogres of the area." },
  ["vekh'nir dreadhawk"] = { 2, "', "Vekh'nir Dreadhawks are arakkoa found in the Blade's Edge Mountains." },
  ["vekh'nir keeneye"] = { 2, "', "Vekh'nir Keeneyes are arakkoa found in the Blade's Edge Mountains." },
  ["vekh'nir matriarch"] = { 2, "', "Vekh'nir Matriarchs are arakkoa found in the Blade's Edge Mountains." },
  ["vekh'nir stormcaller"] = { 2, "', "Vekh'nir Stormcallers are arakkoa found in the Blade's Edge Mountains." },
  ["vekkalis"] = { 2, "dracthyr located in the Valdrakken Treasury Hoard in Vald...", "Vekkalis is a dracthyr located in the Valdrakken Treasury Hoard in Valdrakken serving as a banker alongside Aeoreon and Numernormi." },
  ["velhan's claim defender"] = { 2, "', "Velhan's Claim Defenders are humans located in Velhan's Claim and Velhan's Hall in Hallowfall." },
  ["velhanite child"] = { 2, "', "Velhanite Children are Arathi children located in Velhan's Hall in Hallowfall." },
  ["velhanite citizen"] = { 2, "', "Velhanite Citizens are Arathi located in Velhan's Hall in Hallowfall." },
  ["velkar the thief"] = { 2, "satyr located at", "Velkar the Thief was a satyr located at Andu'talah in Val'sharah. He was instructed by Xavius to protect a  [Arcane Vessel Fragment] while gather the rest to complete the vessel." },
  ["vellas tearen"] = { 2, "Arathi flight master located at Aegis Wall in Hallowfall", "Vellas Tearen is an Arathi flight master located at Aegis Wall in Hallowfall." },
  ["vellcinda benton"] = { 2, "wife of Wyll Benton", "Vellcinda 'Elsie' Benton was the wife of Wyll Benton and former Prime Governor of the Desolate Council which she founded to take care of the city in Sylvanas' absence. She was once a servant in a kitchen." },
  ["velthreek"] = { 2, "leader of the Anhari order", "Priest-Lord Velthreek was the leader of the Anhari order, a faction of the Apexis arakkoa, during the final years of the civilization's existence around 1,200 years before the opening of the Dark Portal." },
  ["velyria the scholarly"] = { 2, "kyrian located in the Eonian Archives in Bastion after ch...", "Velyria the Scholarly is a kyrian located in the Eonian Archives in Bastion after channeling the Anima Conductor level 3 to the area." },
  ["venderthvan"] = { 2, "dracthyr located in the Azure Span", "Venderthvan is a dracthyr located in the Azure Span." },
  ["venerable denizen"] = { 2, "', "Venerable Denizens are venthyr located at the Grand Palisade in Revendreth." },
  ["veng"] = { 2, "undead centaur found in Maraudon", "Veng was an undead centaur found in Maraudon. In life he was the fifth alleged offspring of Zaetar and Theradras, and also the first Khan of the Galak clan." },
  ["vengeful bones"] = { 2, "', "Vengeful Bones are Drust skeletons located at Gol Koval in Drustvar." },
  ["venna seastorm"] = { 2, "naga located in the Eternal Palace", "Venna Seastorm is a naga located in the Eternal Palace." },
  ["venrie flitter"] = { 2, "Arathi lamplighter located in Dunelle's Kindness in Hallo...", "Venrie Flitter is an Arathi lamplighter located in Dunelle's Kindness in Hallowfall. She provides adventurers with a skiff in order for them to battle against shadow creatures in the air." },
  ["venthyr aristocrat"] = { 2, "', "Venthyr Aristocrats are venthyr wandering the halls of Oribos, often stopping by their covenant's section in the Enclave. They were also gathered in the Ring of Fates during  [60] Prisoner of Interest." },
  ["venthyr duelist"] = { 2, "', "Venthyr Duelists are venthyr." },
  ["venthyr guard"] = { 2, "', "Venthyr Guards are venthyr located in the Enclave in Oribos." },
  ["venthyr nightblade"] = { 2, "venthyr", "Venthyr Nightblade is a venthyr." },
  ["venthyr noble"] = { 2, "', "Venthyr Nobles are venthyr located in Oribos." },
  ["venthyr patron"] = { 2, "', "Venthyr Patrons are venthyr located at Transfer Station Ta in Bastion." },
  ["venthyr soulcaster"] = { 2, "', "Venthyr Soulcasters are venthyr who helps with adventures." },
  ["venthyr trader"] = { 2, "', "Venthyr Traders are venthyr wandering the halls of Oribos." },
  ["venture co. builder"] = { 2, "', "Venture Co. Builders are goblins, humans, gnolls, and Dark Iron dwarves located in the Stonetalon Mountains." },
  ["venture co. deforester"] = { 2, "', "Venture Co. Deforesters are found in the Stonetalon Mountains." },
  ["venture co. drone"] = { 2, "', "Venture Co. Drones are undead located at the Sludge Fen in the Northern Barrens." },
  ["venture co. drudger"] = { 2, "', "Venture Co. Drudgers are members of the Venture Co." },
  ["venture co. evacuee"] = { 2, "', "Venture Co. Evacuees can be on the neutral ship between the Alliance and Horde ships in Venture Bay of Grizzly Hills." },
  ["venture co. firestarter"] = { 2, "', "Venture Co. Firestarters are Dark Iron dwarves, jungle trolls, goblins, ogres, and gnolls located in Stormsong Valley." },
  ["venture co. hireling"] = { 2, "', "Venture Co. Hirelings are Venture Company members located at the Winterhoof Water Well in Mulgore." },
  ["venture co. honey harvester"] = { 2, "', "Venture Co. Honey Harvesters are gnolls located in the Buzz Barns in Cinderbrew Meadery." },
  ["venture co. laborer"] = { 2, "', "Venture Co. Laborers are members of the Venture Company that can be found wandering the Ravaged Caravan in Mulgore." },
  ["venture co. laborer (cape of stranglethorn)"] = { 2, "', "Venture Co. Laborers are goblins, gnolls, and Dark Iron dwarves located at the Crystal Shore in the Cape of Stranglethorn." },
  ["venture co. logger"] = { 2, "', "Venture Co. Loggers are found in the Stonetalon Mountains." },
  ["venture co. muscle"] = { 2, "', "Venture Co. Muscles are located at the Jeweled Coast in Stormsong Valley." },
  ["venture co. patron"] = { 2, "', "Venture Co. Patron are gnolls, goblins, humans, and trolls located in the Flaming Taps in Cinderbrew Meadery." },
  ["venture co. peon"] = { 2, "', "Venture Co. Peons are found in the Northern Barrens." },
  ["venture co. saboteur"] = { 2, "', "Venture Co. Saboteurs are goblins and gnolls found at Geezle's Camp in Azuremyst Isle." },
  ["venture co. straggler"] = { 2, "', "Venture Co. Stragglers can be found on-shore in Venture Bay in the three buildings." },
  ["venture co. taskmaster"] = { 2, "', "Venture Co. Taskmasters are members of the Venture Company located at the Ravaged Caravan in Mulgore." },
  ["venture co. worker"] = { 2, "', "Venture Co. Workers are members of the Venture Company found in the Venture Co." },
  ["verad"] = { 2, "Broken innkeeper located at the Harborage in the Swamp of...", "Verad is a Broken innkeeper located at the Harborage in the Swamp of Sorrows." },
  ["verana"] = { 2, "', "Verana, formerly a high elf ranger of the Farstriders, is now a Darkfallen void elf found in Telogrus Rift." },
  ["verdrak"] = { 2, "', "Verdrak was one of the perfect ones serving in Aratas' centaur army. He was considered one of the centaur's strongest fighters." },
  ["vereesa windrunner (time rifts)"] = { 2, "Darkfallen", "Vereesa Windrunner is a Darkfallen, an alternate version of Vereesa Windrunner, from Azmourne located in Tyrhold Reservoir in Thaldraszus during Time Rifts." },
  ["vereth the cunning"] = { 2, "', "Vereth the Cunning can be found in Icecrown." },
  ["verethian"] = { 2, "venthyr located in the Broker's Den in Oribos", "Verethian is a venthyr located in the Broker's Den in Oribos." },
  ["vermin trapper"] = { 2, "', "Vermin Trappers are vulpera located in Freehold. They are riding ratstallions." },
  ["vernon roberts"] = { 2, "worgen", "Vernon Roberts is a worgen." },
  ["verog the dervish"] = { 2, "centaur found near the Stagnant Oasis in the Northern Bar...", "Verog the Dervish is a centaur found near the Stagnant Oasis in the Northern Barrens. He answers directly to the Kolkar chief." },
  ["veron amberstill"] = { 2, "dwarf ram vendor located at Amberstill Ranch in Dun Morogh", "Veron Amberstill is a dwarf ram vendor located at Amberstill Ranch in Dun Morogh. This section concerns content related to Legion." },
  ["veronika"] = { 2, "venthyr located in Darkhaven in Revendreth", "Veronika is a venthyr located in Darkhaven in Revendreth. She is found talking to a Darkhaven Villager." },
  ["verroak greenheart"] = { 2, "worgen located at the Lunarfall in Shadowmoon Valley", "Verroak Greenheart is a worgen located at the Lunarfall in Shadowmoon Valley. He can only be recruited using the Headhunter's Harvest from Lunarfall Inn." },
  ["versya the damned"] = { 2, "Forsworn kyrian serving as a boss of a Tormentors of Torg...", "Versya the Damned is a Forsworn kyrian serving as a boss of a Tormentors of Torghast event in the Maw. She can drop  [Versya's Stygian Longbow]." },
  ["veruca"] = { 2, "tortollan located at Anchors Down in Stormsong Valley", "Veruca is a tortollan located at Anchors Down in Stormsong Valley." },
  ["vesharr"] = { 2, "arakkoa pet tamer located at Veil Terokk‎ in Spires of Arak", "Vesharr is an arakkoa pet tamer located at Veil Terokk‎ in Spires of Arak." },
  ["vesiphone"] = { 2, "Paragon of the kyrian Ascended in the realm of Bastion", "Vesiphone is a Paragon of the kyrian Ascended in the realm of Bastion. She represents the virtue of purity, in particular confronting one's emotions and past in order to move on and eventually ascend." },
  ["vesper churnmoat"] = { 2, "corrupted armor rummager of the Flame's Radiance", "Vesper Churnmoat is the corrupted armor rummager of the Flame's Radiance, located at Morgaen's Tears in Hallowfall as part of the Flame's Radiance and the Nightfall scenario. He sells Champion 1 weapons and accessories with the Nightfall purple ti..." },
  ["vesper stormiron"] = { 2, "Arathi located in Torchlight Mine in Hallowfall", "Vesper Stormiron is an Arathi located in Torchlight Mine in Hallowfall." },
  ["vess-guard na'kal"] = { 2, "mantid found at the Clutches of Shek'zeer in the Dread Wa...", "Vess-Guard Na'kal is a mantid found at the Clutches of Shek'zeer in the Dread Wastes. He is a champion of the mantid loyal to the empress, but his strength comes not from talent or experience, but rather genetic modifications, an honor normally re..." },
  ["vess-guard vik'az"] = { 2, "mantid found at Zan'vess in the Dread Wastes", "Vess-Guard Vik'az is a mantid found at Zan'vess in the Dread Wastes. He co-ordinates the defenses at Zan'vess, and is said to be worth ten mantid in battle, inspiring his fellow soldiers." },
  ["veteran dark ranger"] = { 2, "', "Veteran Dark Rangers are Darkfallen dark rangers of the Forsaken found at Woods' End Cabin in Gilneas. They are tasked with locating (and safeguarding) the coveted Scythe of Elune." },
  ["veteran sparkcaster"] = { 2, "Veiled Market", "Veteran Sparkcasters are brokers located in Tazavesh, the Veiled Market." },
  ["vi'azl"] = { 2, "nerubian located in the Burrows in the City of Threads", "Vi'azl is a nerubian located in the Burrows in the City of Threads. He acquired a deep fear of creatures with fewer limbs after his boss became an ascended and began to abuse him." },
  ["vian the volatile"] = { 2, "mogu serving as a Challenge Card encounter in the Brawler...", "Vian the Volatile is a mogu serving as a Challenge Card encounter in the Brawler's Guild during The War Within. To fight Vian, purchase  [Challenge Card: Vian] after reaching Rank 8 with the guild." },
  ["vicar eliza"] = { 2, "Forsaken priest located in the Hall of Balance in the Net...", "Vicar Eliza is a Forsaken priest located in the Hall of Balance in the Netherlight Temple. Eliza will recruit the greater Band of Zealots -- or Dark Zealots if the advancement upgrade Shadow Heresy is chosen." },
  ["vice president rax blastem"] = { 2, "shredder", "Vice President Rax Blastem is a shredder." },
  ["vicebound peltast"] = { 2, "', "Vicebound Peltasts are Forsworn kyrian located at the Temple of Humility in Bastion." },
  ["vicktor ebonfall"] = { 2, "worgen druid located in First to Your Aid in Dalaran", "Vicktor Ebonfall is a worgen druid located in First to Your Aid in Dalaran who can't shapeshift out of  [Aquatic Form]. It is currently unknown if he survived Dalaran's destruction." },
  ["victim of the inquisition"] = { 2, "', "Victims of the Inquisition are tortured victims located in Niskara." },
  ["vidious"] = { 2, "domanaar located in Slayer's Rise", "Vidious is a domanaar located in Slayer's Rise." },
  ["vigdis the war maiden"] = { 2, "War Maiden is a rare elite vrykul found in the Howling Fjord", "Vigdis the War Maiden is a rare elite vrykul found in the Howling Fjord." },
  ["vigilant dreadtalon"] = { 2, "', "Vigilant Dreadtalons are arakkoa found inside and in front of a cave at Lost Veil Anzu in the Spires of Arak." },
  ["vigilant quoram"] = { 2, "eredar vigilant on Argus", "Vigilant Quoram is an eredar vigilant on Argus and the gatekeeper of the Conservatory of the Arcane. Later, he can be found aboard the Vindicaar after the Lightforged draenei join the Alliance." },
  ["vigori"] = { 2, "constantly stuttering vulpera located at Camp Lastwind in...", "Vigori is a constantly stuttering vulpera located at Camp Lastwind in Vol'dun." },
  ["vik mournblade"] = { 2, "Darkfallen death knight seen speaking with Kaln Vilehoof ...", "Vik Mournblade is a Darkfallen death knight seen speaking with Kaln Vilehoof in Warfang Hold in Stormsong Valley." },
  ["vil'thik amber-mender"] = { 2, "', "Vil'thik Amber-Menders are mantid located in the Vale of Eternal Blossoms." },
  ["vil'thik amber-shaper"] = { 2, "', "Vil'thik Amber-Shapers are mantid located in the Vale of Eternal Blossoms." },
  ["vil'thik ambersinger"] = { 2, "', "Vil'thik Ambersingers are mantid located in the Vale of Eternal Blossoms. They appear when defending Chin and Tohi from mantid." },
  ["vil'thik drone"] = { 2, "', "Vil'thik Drones are mantid located in the Vale of Eternal Blossoms." },
  ["vil'thik harrier"] = { 2, "', "Vil'thik Harriers are mantid located in the Vale of Eternal Blossoms." },
  ["vil'thik quickblade"] = { 2, "', "Vil'thik Quickblades are mantid located in the Vale of Eternal Blossoms and Kun-Lai Summit." },
  ["vil'thik shrieker"] = { 2, "mantid", "Vil'thik Shrieker is a mantid that would appear in the Vale of Eternal Blossoms." },
  ["vil'thik swarmborn"] = { 2, "', "Vil'thik Swarmborn are mantid located in the Vale of Eternal Blossoms." },
  ["vil'thik swarmkeeper"] = { 2, "', "Vil'thik Swarmkeepers are mantid located in the Vale of Eternal Blossoms." },
  ["vil'thik warrior"] = { 2, "', "Vil'thik Warriors are mantid located in the Vale of Eternal Blossoms." },
  ["vil'thik warsinger"] = { 2, "mantid", "Vil'thik Warsinger is a mantid." },
  ["vile corruptor"] = { 2, "', "Vile Corruptors are satyrs found at the Cliffspring Hollow in Darkshore." },
  ["vile occultist"] = { 2, "', "Vile Occultists are venthyr located in Pride's Prison in Castle Nathria as part of the Sun King's Salvation encounter. They are channeling anima from Sinstone Markers." },
  ["vilo"] = { 2, "broker located in Haven in Zereth Mortis", "Vilo is a broker located in Haven in Zereth Mortis." },
  ["vincent huber"] = { 2, "Forsaken reagent vendor found at Light's Breach in Zul'Drak", "Vincent Huber is a Forsaken reagent vendor found at Light's Breach in Zul'Drak." },
  ["vindicator aalesia"] = { 2, "draenei quest giver located at Blood Watch in the draenei...", "Vindicator Aalesia is a draenei quest giver located at Blood Watch in the draenei territory of Bloodmyst Isle." },
  ["vindicator aesom"] = { 2, "draenei vindicator", "Vindicator Aesom is a draenei vindicator and a member of the Triumvirate of the Hand, the leaders of the Hand of Argus. He is initially found as a paladin trainer at Blood Watch on Bloodmyst Isle and acts as a member of the Order of the Silver Han..." },
  ["vindicator aeus"] = { 2, "draenei quest giver located in the Aldor Bank in Shattrat...", "Vindicator Aeus is a draenei quest giver located in the Aldor Bank in Shattrath City." },
  ["vindicator aldar"] = { 2, "draenei quest giver located at the Crash Site in Azuremys...", "Vindicator Aldar is a draenei quest giver located at the Crash Site in Azuremyst Isle." },
  ["vindicator aluumen"] = { 2, "draenei located at the Altar of Sha'tar in Shadowmoon Valley", "Vindicator Aluumen is a draenei located at the Altar of Sha'tar in Shadowmoon Valley. He asked adventurers to kill members of the Ashtongue tribe in the Ruins of Baa'ri and the fel orcs of the Shadowmoon clan in the Ata'mal Terrace." },
  ["vindicator arlaam"] = { 2, "draenei vindicator located in Auchenai Precipice in Talador", "Vindicator Arlaam is a draenei vindicator located in Auchenai Precipice in Talador." },
  ["vindicator banra"] = { 2, "draenei located at Newstead in the Arathi Highlands durin...", "Vindicator Banra is a draenei located at Newstead in the Arathi Highlands during the Battle for Stromgarde. He allows the requisition of War Elekks." },
  ["vindicator caelus"] = { 2, "draenei located at Auchindoun in Talador", "Vindicator Caelus is a draenei located at Auchindoun in Talador. He is seen teaching Auchenai Defenders." },
  ["vindicator corin"] = { 2, "draenei quest giver located at Vindicator's Rest on Blood...", "Vindicator Corin is a draenei quest giver located at Vindicator's Rest on Bloodmyst Isle. When the draenei launched a counterattack on the Sunhawk blood elves of Vector Coil, she was given a task to soften up their defenses." },
  ["vindicator doruu"] = { 2, "draenei leading the vindicators sent by Exarch Maladaar t...", "Vindicator Doruu is a draenei leading the vindicators sent by Exarch Maladaar to deal with arcane energy flooding Jorune Mine in Talador and the side effects of it. He is being assisted by  Archmage Elandra/ Manduil Skycaller." },
  ["vindicator dran'aan"] = { 2, "draenei paladin of the Silver Hand located in Stratholme", "Vindicator Dran'aan is a draenei paladin of the Silver Hand located in Stratholme. He can be chosen to accompany the Highlord throughout the scenario during   [45] Stirring in the Shadows." },
  ["vinemaster guff"] = { 2, "quilboar located near Burton Farmstead in Stormsong Valley", "Vinemaster Guff is a quilboar located near Burton Farmstead in Stormsong Valley." },
  ["vinemaster orgsteen"] = { 2, "quilboar located near Burton Farmstead in Stormsong Valley", "Vinemaster Orgsteen is a quilboar located near Burton Farmstead in Stormsong Valley." },
  ["vinemaster smagh"] = { 2, "quilboar located in the Collapsed Fields in Stormsong Valley", "Vinemaster Smagh is a quilboar located in the Collapsed Fields in Stormsong Valley." },
  ["vinespeaker ratha"] = { 2, "quilboar located in a cave at the Amber Waves in Stormson...", "Vinespeaker Ratha is a quilboar located in a cave at the Amber Waves in Stormsong Valley." },
  ["vinyeti"] = { 2, "', "Vinyetis (a pun on 'vignette' and 'yeti') are used as placeholders for vignettes during alpha and beta stages. They most commonly use yeti models, but some also appear as satyrs." },
  ["vir'aani arcanist"] = { 2, "', "Vir'aani Arcanists are ethereals found in the Spirit Fields in Nagrand." },
  ["vir'aani raider"] = { 2, "', "Vir'aani Raiders are ethereals found in the Spirit Fields in Nagrand." },
  ["virtuous gentleman"] = { 2, "', "Virtuous Gentlemen are undead disguised as male humans in the Guest Chambers in the Return to Karazhan." },
  ["virtuous lady"] = { 2, "', "Virtuous Ladies are undead located in the Guest Chambers in the Return to Karazhan. They are disguised as humans, but their real appearance is revealed when they are hurt enough." },
  ["virulax blightweaver"] = { 2, "mad scientist located in Plaguefall", "Virulax Blightweaver is a mad scientist located in Plaguefall." },
  ["viscount nicolae"] = { 2, "venthyr located in the Old Gate in Revendreth", "Viscount Nicolae is a venthyr located in the Old Gate in Revendreth. He is the new owner of Thornhill Manor, and Bogdan sent the Maw Walker to kill him." },
  ["visiting ascended"] = { 2, "', "Visiting Ascended are Ascended kyrian located at Hero's Rest in Bastion. They descend from above and proceed to walk around for a while before taking off again." },
  ["visiting warlock"] = { 2, "', "Visiting Warlocks are warlocks of various races found near Wilfred Fizzlebang outside the entrance to the Trial of the Crusader in Icecrown. Some are accompanied by felhounds or felguards." },
  ["visiting warpweaver"] = { 2, "', "Visiting Warpweavers are ethereals located outside the Caverns of Time during the Bronze Celebration in Tanaris. They are present during the Fashion Frenzy event." },
  ["visrynn"] = { 2, "kaldorei Darkfallen dark ranger", "Visrynn is a kaldorei Darkfallen dark ranger who remained loyal to Sylvanas Windrunner after the Fourth War and accompanied Nathanos Blightcaller and Sira Moonwarden on their mission to kill the loa Bwonsamdi. Visrynn has dark hair." },
  ["visser the scalekeeper"] = { 2, "vrykul flight master located at Valdisdall in Stormheim", "Visser the Scalekeeper is a vrykul flight master located at Valdisdall in Stormheim." },
  ["vitner monk"] = { 2, "', "Vitner Monks are Arathi located in the Priory of the Sacred Flame in Hallowfall." },
  ["vivi"] = { 2, "vulpera initially encountered alongside Coda at the north...", "Vivi is a vulpera initially encountered alongside Coda at the northern edge of the Prickly Grove in Vol'dun. Vivi found and nursed Coda back to health after he was stung by one of the wasps in the grove, but many of his fellow ferrets are still mi..." },
  ["vix chromeblaster"] = { 2, "goblin found in Warsong Hold in the Borean Tundra", "Vix Chromeblaster was a goblin found in Warsong Hold in the Borean Tundra." },
  ["vizier cromaug"] = { 2, "ogre located at Gordal Fortress in Talador", "Vizier Cromaug is an ogre located at Gordal Fortress in Talador." },
  ["vizier dar'gud"] = { 2, "ogre located at the Broken Precipice in Nagrand", "Vizier Dar'gud is an ogre located at the Broken Precipice in Nagrand." },
  ["vizier jin'bak"] = { 2, "first boss of Siege of Niuzao Temple", "Vizier Jin'bak is the first boss of Siege of Niuzao Temple." },
  ["vizna bangwrench"] = { 2, "goblin located at Orgrimmar Rocketway Exchange in Azshara", "Vizna Bangwrench is a goblin located at Orgrimmar Rocketway Exchange in Azshara. She used to be an engineering supplies vendor at Goblin Slums of Orgrimmar and then at Engineering Works after the construction of Orgrimmar Embassy." },
  ["vladof the butcher"] = { 2, "vrykul champion from the steppes of Icecrown", "Vladof the Butcher is a vrykul champion from the steppes of Icecrown, riding on the back of his mammoth Enormos. He is the sixth and final boss of the Amphitheater of Anguish." },
  ["void priest"] = { 2, "', "Void Priests are Forsaken and Dark Iron dwarven priests located in Netherlight Temple. They also appear in Deliverance Point on the Broken Shore." },
