  ["voidbinder sturzah"] = { 2, "ethereal item upgrader located in the Three Winds shop in...", "Voidbinder Sturzah is an ethereal item upgrader located in the Three Winds shop in the canal area of Stormwind City, alongside his fellow ethereals Warpweaver Hashom, Vaultkeeper Razhid, and Thaumaturge Rafir. This section concerns content relat..." },
  ["voidbinder tarazuuk"] = { 2, "ethereal item upgrader found in the", "Voidbinder Tarazuuk is an ethereal item upgrader found in the Andromath's Rise in Stormshield." },
  ["voidbinder zorlan"] = { 2, "ethereal item upgrader found in the Drag of Orgrimmar", "Voidbinder Zorlan is an ethereal item upgrader found in the Drag of Orgrimmar. This section concerns content related to Battle for Azeroth." },
  ["voidblade kassar"] = { 2, "naga located in Nazjatar", "Voidblade Kassar is a naga located in Nazjatar." },
  ["voidpriest sekkta"] = { 2, "', "Voidpriest Sekkta is found at his hut on the northwestern trail from Talador in the northwestern corner of Spires of Arak." },
  ["voidrider challnax"] = { 2, "twilight drake located in the Archival Assault delve", "Voidrider Challnax is a twilight drake located in the Archival Assault delve. Voidripper is her mount." },
  ["voidscarred krokul"] = { 2, "', "Voidscarred Krokuls are voidscarred Broken located at the Oronaar Collapse in Eredath." },
