  ["voidtouched channeler"] = { 2, "', "Voidtouched Channelers are ethereals of the Ethereum found in Coldarra in the Borean Tundra and the Beyond during the  [Aluneth] and  [Light's Wrath] questlines." },
  ["voidtouched nexus-stalker"] = { 2, "', "Voidtouched Nexus-Stalkers are ethereal nexus-stalkers of the Ethereum found in Coldarra in the Borean Tundra and the Beyond during the  [Aluneth] and  [Light's Wrath] questlines." },
  ["voitha"] = { 2, "kyrian located in the Temple of Humility in Bastion", "Voitha is a kyrian located in the Temple of Humility in Bastion. She is the Hand of Humility and serves Chyrus, the Paragon of Humility." },
  ["vok blacktongue"] = { 2, "orc located at the Pillars of Fate in Spires of Arak", "Vok Blacktongue is an orc located at the Pillars of Fate in Spires of Arak. He was a high ritualist of Shadowmoon, and a master runecarver." },
