  ["volida"] = { 2, "Forsaken frost mage", "Volida is a Forsaken frost mage, and is part of Theldren's team of gladiators at the Blackrock Depths arena." },
  ["vor'athil"] = { 2, "high elf ranger of the Farstriders", "Vor'athil was a high elf ranger of the Farstriders, originally serving under Ranger-General Lireesa Windrunner. He was muscular and had his long blue-black hair swept back in a ponytail, tanned skin, pointed ears, and eyes blue as summer skies." },
  ["vor'thik dreadsworn"] = { 2, "', "Vor'thik Dreadsworn are mantid located at Kypari Vor in the Dread Wastes." },
  ["vor'thik eggs"] = { 2, "', "Vor'thik Eggs are looted from Vor'thik Eggs in the Dread Wastes." },
  ["vor'thik fear-shaper"] = { 2, "', "Vor'thik Fear-Shapers are mantid located at Kypari Vor in the Dread Wastes." },
  ["vor'thik swarmborn"] = { 2, "', "Vor'thik Swarmborn are mantid located in the Dread Wastes." },
  ["voracious collector"] = { 2, "', "Voracious Collectors are venthyr encountered by adventure companions in Revendreth." },
  ["vorath"] = { 2, "Darkfallen of the San'layn located in Deatholme in the Gh...", "Vorath is a Darkfallen of the San'layn located in Deatholme in the Ghostlands." },
  ["vorlus vilehoof"] = { 2, "satyr", "Vorlus Vilehoof is a satyr who can be found standing in a moonwell in Teldrassil, defiling its pure waters, for which Elanaria wanted him dead. Before Cataclysm, he used to be involved in the quest   [10] Vorlus Vilehoof, but as of now he serves n..." },
  ["voru'kar nerubian"] = { 2, "', "Voru'kar Nerubians are nerubians located on the expedition isles." },
