  ["voru'kar venomancer"] = { 2, "', "Voru'kar Venomancers are nerubian venomancers located on the expedition isles." },
  ["voryis soulbreaker"] = { 2, "venthyr located in Dominance Keep in Revendreth", "Voryis Soulbreaker is a venthyr located in Dominance Keep in Revendreth." },
  ["vosur brakthel"] = { 2, "dwarf located in the shop Berryfizz's Potions", "Vosur Brakthel is a dwarf located in the shop Berryfizz's Potions and Mixed Drinks in Tinker Town in Ironforge." },
  ["vrglrok saurfin"] = { 2, "murloc found in Azmerloth", "Vrglrok Saurfin is a murloc found in Azmerloth. He is an alternate version of Varok Saurfang." },
