  ["vrykul shepherd"] = { 2, "vrykul found at Vrekt in Stormheim along with some Domest...", "The Vrykul Shepherd is a vrykul found at Vrekt in Stormheim along with some Domesticated Goats. He drops no loot." },
  ["vrykul soul"] = { 2, "', "Vrykul Souls are shades found in Gjalerbron in the Howling Fjord." },
  ["vula'jin the void"] = { 2, "troll blessed by the loa", "Vula'jin the Void was a troll blessed by the loa. A tale speaks of how he regrew almost his entire body after standing in a pool of shadowflame." },
  ["vulca"] = { 2, "venthyr located in Revendreth", "Vulca is a venthyr located in Revendreth." },
  ["vulnerable aspirant"] = { 2, "', "Vulnerable Aspirants are kyrian located in Bastion. They are depressed about failing the rites of Purity." },
  ["vulpera captive"] = { 2, "Ashvane forces simply send in another captive from one of...", "Vulpera Captives are vulpera found lying dead in Faithless cages at the Abandoned Burrows and enslaved by the Ashvane Trading Company in the Redrock Mines in Vol'dun. The ones in the Redrock Mines are forced to constantly mine Azerite, and when on..." },
  ["vulpera firefox"] = { 2, "', "Vulpera Firefoxes are vulpera pirates found at Daelin's Gate in Tiragarde Sound." },
  ["vulpera guardian"] = { 2, "', "Vulpera Guardians are vulpera guards mounted on hyenas that protect Vulpera Hideaway in Vol'dun." },
  ["vulpera gunner"] = { 2, "', "Vulpera Gunners are vulpera located in Krakenbane Cove in Tiragarde Sound." },
  ["vulpera kid"] = { 2, "', "Vulpera Kids are vulpera children cowering in front of Appraiser Versik in the Crater of Conquerors in Vol'dun. During  [30-60] The Little Ones, they are rescued by the Horde adventurer and later appear in Vorrik's Sanctum as Rescued Kids." },
  ["vulpera mixologist"] = { 2, "', "Vulpera Mixologists are vulpera located in Freehold in Tiragarde Sound." },
  ["vulpera padfoot"] = { 2, "', "Vulpera Padfoots are vulpera located at Daelin's Gate and Freehold in Tiragarde Sound." },
  ["vulpera poacher"] = { 2, "dead vulpera hunter located at the Wild Preserve in the W...", "Vulpera Poacher is a dead vulpera hunter located at the Wild Preserve in the Waking Shores. He is found clutching the  [Poacher's Pack] treasure." },
  ["vulpera prisoner"] = { 2, "', "Vulpera Prisoners are captured vulpera found strung up on a wall on Shath'kar's ledge in the Slithering Gulch in Vol'dun." },
  ["vulpera sharpshooters"] = { 2, "', "Vulpera Sharpshooters are vulpera troops that participate in various War Campaign missions." },
  ["vulpera slave"] = { 2, "', "Vulpera Slaves are vulpera that have been enslaved by Faithless sethrak in various locations throughout Vol'dun. Many are found in the Crater of Conquerors and need to be armed for  [30-60] Ready to Riot." },
  ["vulpera tidewatcher"] = { 2, "vulpera", "Vulpera Tidewatcher is a vulpera." },
  ["vulpera toe-slasher"] = { 2, "', "Vulpera Toe-Slashers are vulpera located on the Siren Isle while  [80EWQ] Tides of Greed is active." },
  ["vulpera trader"] = { 2, "', "Vulpera Traders are vulpera located at Backwater Beach in Zuldazar." },
  ["vulric fangborne"] = { 2, "Worgen located at Lunarfall in Shadowmoon Valley", "Vulric Fangborne is a Worgen located at Lunarfall in Shadowmoon Valley. He can only be recruited using the Headhunter's Harvest from Lunarfall Inn." },
  ["vurtok axebreaker"] = { 2, "orc quest giver located in Thrallmar in the Hellfire Peni...", "Vurtok Axebreaker is an orc quest giver located in Thrallmar in the Hellfire Peninsula. Vurtok has an extreme hatred against fel orcs to the point that his blood boils at the sight of them." },
  ["vydhar"] = { 2, "vrykul turned into a tree located in the Runewood in Stor...", "Vydhar was a vrykul turned into a tree located in the Runewood in Stormheim. He was transformed with the help of the Highmountain tauren many ages ago, his wisdom made eternal." },
  ["vyraxxis"] = { 2, "mantid located in the Gate of the Setting Sun in the Vale...", "Vyraxxis is a mantid located in the Gate of the Setting Sun in the Vale of Eternal Blossoms." },
  ["wagga snarltusk"] = { 2, "quilboar located in Thornheart in Stormsong Valley", "Wagga Snarltusk is a quilboar located in Thornheart in Stormsong Valley." },
  ["wahla"] = { 2, "tortollan located in Little Tortolla in Dazar'alor", "Wahla is a tortollan located in Little Tortolla in Dazar'alor. He was present during the funeral of King Rastakhan." },
  ["wailing mary smitts"] = { 2, "level 35 worgen found aboard the The Riptide in the Cape ...", "Wailing Mary Smitts is a level 35 worgen found aboard the The Riptide in the Cape of Stranglethorn." },
  ["waiter (broker)"] = { 2, "Veiled Market", "Waiters are brokers located at the Lap of Luxury in Tazavesh, the Veiled Market." },
  ["walkmay"] = { 2, "kobold located in Campalot in the Ringing Deeps", "Walkmay is a kobold located in Campalot in the Ringing Deeps." },
  ["wally"] = { 2, "tuskarr found with  Tic Tak <The Carpenter> on a small is...", "Wally is a tuskarr found with  Tic Tak <The Carpenter> on a small island at the center of the north shore of Kun-Lai Summit." },
  ["waltor of pal'ea"] = { 2, "tuskarr quest giver found in the Borean Tundra", "Waltor of Pal'ea is a tuskarr quest giver found in the Borean Tundra. He is one of the few survivors from Pal'ea." },
  ["wanderer ida"] = { 2, "earthen character in 'The Wanderer'", "Wanderer Ida is an earthen character in 'The Wanderer', a play performed by the theater troupe at the Proscenium on the Isle of Dorn. She was an adventurous and ambitious character who longed to explore lands beyond her homeland of Khaz Algar." },
  ["wandering reflection"] = { 2, "', "Wandering Reflections are kyrian memories located on the roads of Bastion during  [60 Daily] A Somber Melody." },
  ["warcaster bargol"] = { 2, "orc located north of the Dark Portal in Blasted Lands", "Warcaster Bargol is an orc located north of the Dark Portal in Blasted Lands." },
  ["warchanter ronvath"] = { 2, "djaradin located in Elders' Gift in Zaralek Cavern", "Warchanter Ronvath is a djaradin located in Elders' Gift in Zaralek Cavern. Fueled by hatred, Ronvath leads the djaradin effort to liberate the elders from Aberrus." },
  ["warchief blackhand"] = { 2, "orc chess piece in Karazhan's Chess Event", "Warchief Blackhand is an orc chess piece in Karazhan's Chess Event." },
  ["warcraft wiki:sandbox/5"] = { 2, "', "Razorfen Battleguards are quilboar found outside the Razorfen Downs in Thousand Needles." },
  ["warcraft wiki:sandbox/7"] = { 2, "', "Razorfen Battleguards are quilboar found outside the Razorfen Downs in Thousand Needles." },
  ["warcraft wiki:sandbox/8"] = { 2, "', "Razorfen Battleguards are quilboar found outside the Razorfen Downs in Thousand Needles." },
  ["ward guardian"] = { 2, "', "Ward Guardians are quilboar located in Razorfen Kraul." },
  ["warden alturas"] = { 2, "human located in front of the Violet Hold in Dalaran", "Warden Alturas is a human located in front of the Violet Hold in Dalaran. He seems to be the man in control of the prison." },
  ["warden amical"] = { 2, "human located in Tol Dagor during the extraction of Prisc...", "Warden Amical is a human located in Tol Dagor during the extraction of Priscilla Ashvane." },
  ["warden azjakir"] = { 2, "leader of the naga forces in the Clutch of Kelp'thar Forest", "Warden Azjakir is the leader of the naga forces in the Clutch of Kelp'thar Forest, keeping watch over Alliance and Horde prisoners. Erunak Stonespeaker wants him dead." },
  ["warden dialash"] = { 2, "dracthyr flight master located at the Temporal Conflux in...", "Warden Dialash is a dracthyr flight master located at the Temporal Conflux in Thaldraszus. He is found dead in the Primalist Future." },
  ["warden icoshock"] = { 2, "ethereal in charge of the prison cells at the Ethereum St...", "Warden Icoshock is the ethereal in charge of the prison cells at the Ethereum Staging Grounds located in Netherstorm." },
  ["warden moi'bff jill"] = { 2, "Broken quest giver located in Telaar in Nagrand", "Warden Moi'bff Jill is a Broken quest giver located in Telaar in Nagrand." },
  ["warden nork bloodfrenzy"] = { 2, "orc", "Warden Nork Bloodfrenzy is an orc and the father of Ug'thor Bloodfrenzy found outside of Warsong Hold in the Borean Tundra. While looking at the Alliance Deserters he asks his son if he knows what they are." },
  ["warkeeper gresh"] = { 2, "worgen located in the Gladiator's Refuge in Valdrakken", "Warkeeper Gresh is a worgen located in the Gladiator's Refuge in Valdrakken. He sells his goods in return for  [Bloody Tokens]." },
  ["warlord bloodhilt"] = { 2, "orc commander trusted by Warchief Garrosh Hellscream to e...", "Warlord Bloodhilt was an orc commander trusted by Warchief Garrosh Hellscream to ensure the operations of the Horde in the Southern Barrens and Krasarang Wilds." },
  ["warlord bult"] = { 2, "overseer of the Bladespire clan operations at the Circle ...", "Warlord Bult is the overseer of the Bladespire clan operations at the Circle of Blood within Frostfire Ridge. Igrimar the Resolute seeks his death, along with the rest of the ogre leadership at the Circle of Blood." },
  ["warlord darjah"] = { 2, "naga located in the Abyssal Approach of the Tomb of Sargeras", "Warlord Darjah is a naga located in the Abyssal Approach of the Tomb of Sargeras." },
  ["warlord kagni"] = { 2, "djaradin warlord", "Warlord Kagni was a djaradin warlord who led a Zaqali warband into launching an all-out assault against Aberrus, the Shadowed Crucible in search of their missing Elder, Rashok. He was also presumably the leader of the Zaqali tribe before the awake..." },
  ["warlord kalithresh"] = { 2, "third", "Warlord Kalitresh is the third and final boss of the Steamvault in Coilfang Reservoir." },
  ["warlord kao"] = { 2, "favored general of the Thunder King", "Warlord Kao was the favored general of the Thunder King, resurrected by the Zandalari trolls to help his master reclaim his hold on Pandaria. During the Fourth War, he sought to fulfill the pact the Zandalari had made with the mogu long ago, but w..." },
  ["warlord kara-na"] = { 2, "mogu located in Dazar'alor during  [30-60] Zandalar Forever!", "Warlord Kara-na is a mogu located in Dazar'alor during  [30-60] Zandalar Forever!." },
  ["warlord kaz'jatar"] = { 2, "naga located at the Felrage Strand in the Broken Shore", "Warlord Kaz'jatar is a naga located at the Felrage Strand in the Broken Shore." },
  ["warlord kolbine"] = { 2, "ogre barbarian", "Warlord Kolbine is an ogre barbarian and the ruler of the Deadwind ogres of the Deadwind Ogre Mounds in Deadwind Pass." },
  ["warlord kolkanis"] = { 2, "rare mob centaur found outside one of the huts in Kolkar ...", "Warlord Kolkanis was a rare mob centaur found outside one of the huts in Kolkar Crag in Durotar." },
  ["warlord krellian"] = { 2, "naga residing in the Temple of Zin-Malor in Azshara", "Warlord Krellian is a naga residing in the Temple of Zin-Malor in Azshara and he is the cruel royal leader of the Spitelash Naga. With Arkkoroc dealt with, the naga took the upper hand and marched on the new arrivals, the Bilgewater Cartel goblins." },
  ["warlord krom'zar"] = { 2, "elite Kolkar centaur", "Warlord Krom'zar is an elite Kolkar centaur who leads the attack on Regthar Deathgate's burrow in the Northern Barrens during  [5-30G] Counterattack!. Regthar wants  [Piece of Krom'zar's Banner], which can be looted from Krom'zar's Banner once the..." },
  ["warlord mo'gosh"] = { 2, "ogre located in Molten Cay during Island Expeditions", "Warlord Mo'gosh is an ogre located in Molten Cay during Island Expeditions." },
  ["warlord parjesh"] = { 2, "naga boss located at the Hatecoil Encampment in Eye of Az...", "Warlord Parjesh is a naga boss located at the Hatecoil Encampment in Eye of Azshara. After the shards of the  [Tidestone of Golganneth] were collected by a brave hero, Parjesh and Athissa stole it and tried to bring it to Queen Azshara." },
  ["warlord ramtusk"] = { 2, "quilboar in Razorfen Kraul", "Warlord Ramtusk is a quilboar in Razorfen Kraul." },
  ["warlord salaris"] = { 2, "naga warrior", "Warlord Salaris is one of the 8 different NPCs that can be with Priestess Delrissa, the third boss in Magisters' Terrace. He is a naga warrior." },
  ["warlord sargha"] = { 2, "boss in Neltharus", "Warlord Sargha is a boss in Neltharus." },
  ["warlord sriss'tiz"] = { 2, "naga located in Tides' Hollow on Azuremyst Isle", "Warlord Sriss'tiz is a naga located in Tides' Hollow on Azuremyst Isle. He is in command of the Wrathscale naga." },
  ["warlord volund"] = { 2, "vrykul located at the Tomb of the Old Kings in Stormheim", "Warlord Volund is a vrykul located at the Tomb of the Old Kings in Stormheim." },
  ["warlord xiar"] = { 2, "mogu located on the Isle of Fangs in Zuldazar", "Warlord Xiar is a mogu located on the Isle of Fangs in Zuldazar." },
  ["warmage adami"] = { 2, "human flight master located at Transitus Shield in the Bo...", "Warmage Adami is a human flight master located at Transitus Shield in the Borean Tundra. She is mounted on a red drake and is one of the Kirin Tor warmages deployed to fight against the Blue dragonflight." },
  ["warmage anzim"] = { 2, "human at the Amber Ledge in the Borean Tundra", "Warmage Anzim is a human at the Amber Ledge in the Borean Tundra, where he handles the red drakes allied to the Kirin Tor warmages deployed to fight against the Blue dragonflight." },
  ["warmage archus"] = { 2, "human located at the Amber Ledge in the Borean Tundra", "Warmage Archus is a human located at the Amber Ledge in the Borean Tundra. He is mounted on a red drake and is one of the Kirin Tor warmages deployed to fight against the Blue dragonflight." },
  ["warmaster blackhorn"] = { 2, "sixth boss to appear in the Dragon Soul raid", "Warmaster Blackhorn is the sixth boss to appear in the Dragon Soul raid." },
  ["warmaster blugthol"] = { 2, "ogre located at the Mar'gok's Overwatch in Nagrand", "Warmaster Blugthol is an ogre located at the Mar'gok's Overwatch in Nagrand." },
  ["warmaster suttai"] = { 2, "centaur located at Broadhoof Outpost in the Ohn'ahran Plains", "Warmaster Suttai is a centaur located at Broadhoof Outpost in the Ohn'ahran Plains." },
  ["warmaul champion"] = { 2, "warrior", "The Warmaul Champion is a warrior that appears during the Ring of Blood event in Nagrand." },
  ["warmaul chef bufferlo"] = { 2, "ogre located at the Warmaul Hill in Nagrand", "Warmaul Chef Bufferlo is an ogre located at the Warmaul Hill in Nagrand." },
  ["warmonger kharad"] = { 2, "elite centaur of Clan Nokhud guarding the path leading up...", "Warmonger Kharad is an elite centaur of Clan Nokhud guarding the path leading up to the Horn of Drusahl in the Ohn'ahran Plains." },
  ["warp-raider nesaad"] = { 2, "ethereal", "Warp-Raider Nesaad is an ethereal and the leader of the Zaxxis in the Netherstorm. After the Zaxxis cut their relationship with the Consortium and the Sunfury blood elves, Nexus-Prince Haramad tasked Nether-Stalker Khay'ji to deal with the rogue g..." },
  ["warpweaver dayelis"] = { 2, "ethereal located in the Bronze Enclave in Valdrakken", "Warpweaver Dayelis is an ethereal located in the Bronze Enclave in Valdrakken." },
  ["warpweaver dezeeran"] = { 2, "ethereal located in the Ether House in the Fissure in Dor...", "Warpweaver Dezeeran is an ethereal located in the Ether House in the Fissure in Dornogal." },
  ["warpweaver diveera"] = { 2, "ethereal located in Silvermoon City", "Warpweaver Diveera is an ethereal located in Silvermoon City." },
  ["warpweaver dushar"] = { 2, "ethereal transmogrifier found in the Drag in Orgrimmar", "Warpweaver Dushar is an ethereal transmogrifier found in the Drag in Orgrimmar. This section concerns content related to Battle for Azeroth." },
  ["warpweaver ezil"] = { 2, "ethereal transmogrifier located at the Tradewinds Market ...", "Warpweaver Ezil is an ethereal transmogrifier located at the Tradewinds Market in Boralus. He resides in the same shop as Azerite Reforger Razzi the Shaper and Master of Fate Tezran." },
  ["warpweaver farshlah"] = { 2, "ethereal transmogrifier located in the Frostwall's Storeh...", "Warpweaver Farshlah is an ethereal transmogrifier located in the Frostwall's Storehouse." },
  ["warpweaver hashom"] = { 2, "ethereal transmogrifier located in the Three Winds shop i...", "Warpweaver Hashom is an ethereal transmogrifier located in the Three Winds shop in the Canals of Stormwind City." },
  ["warpweaver hayri"] = { 2, "ethereal located in the Maelstrom Mercantile at the Grand...", "Warpweaver Hayri is an ethereal located in the Maelstrom Mercantile at the Grand Bazaar in Dazar'alor." },
  ["warpweaver ja'dun"] = { 2, "broker located in Tazarest in Tazavesh", "Warpweaver Ja'dun is a broker located in Tazarest in Tazavesh, the Veiled Market in K'aresh." },
  ["warpweaver jasor"] = { 2, "ethereal found in Warspear's Tower of Elements in Ashran", "Warpweaver Jasor is an ethereal found in Warspear's Tower of Elements in Ashran." },
  ["warpweaver ramahesh"] = { 2, "ethereal transmogrifier found in the Ethereal Corridor in...", "Warpweaver Ramahesh is an ethereal transmogrifier found in the Ethereal Corridor in the Shrine of Seven Stars." },
  ["warpweaver razeem"] = { 2, "ethereal transmogrifier located in any neighborhood where...", "Warpweaver Razeem is an ethereal transmogrifier located in any neighborhood where Consortium Consternation is the active endeavor. He appears in the Town Center in Founder's Point or the Common in Razorwind Shores." },
  ["warpweaver shafiee"] = { 2, "ethereal transmogrifier found in the Hall of Secrets in t...", "Warpweaver Shafiee is an ethereal transmogrifier found in the Hall of Secrets in the Shrine of Two Moons." },
  ["warpweaver shal"] = { 2, "ethereal transmogrifier found in", "Warpweaver Shal is an ethereal transmogrifier found in Andromath's Rise in Stormshield." },
  ["warpweaver sle'shal"] = { 2, "ethereal located at the Assembly Chamber inside the Magis...", "Warpweaver Sle'shal is an ethereal located at the Assembly Chamber inside the Magisters' Terrace during the Trial of Style. He handles token exchange." },
  ["warpweaver sondari"] = { 2, "ethereal located at the Assembly Chamber inside the Magis...", "Warpweaver Sondari is an ethereal located at the Assembly Chamber inside the Magisters' Terrace during the Trial of Style. His transmogrifying services are free during the event." },
  ["warpweaver swaggiss"] = { 2, "ethereal located outside the Magical Menagerie in Dalaran", "Warpweaver Swaggiss is an ethereal located outside the Magical Menagerie in Dalaran." },
  ["warpweaver ta'oren"] = { 2, "broker located in the Hall of Curiosities in Oribos", "Warpweaver Ta'oren is a broker located in the Hall of Curiosities in Oribos. They will occasionally comment on the work of their associates handling the beasts being portaled in." },
  ["warpweaver taxoss"] = { 2, "ethereal transmogrifier located at T&W Trading Post in th...", "Warpweaver Taxoss is an ethereal transmogrifier located at T&W Trading Post in the Canals in Stormwind City." },
  ["warpweaver torell"] = { 2, "ethereal located at the Assembly Chamber inside the Magis...", "Warpweaver Torell is an ethereal located at the Assembly Chamber inside the Magisters' Terrace during the Trial of Style. His transmogrifying services are free during the event." },
  ["warpweaver tuviss"] = { 2, "ethereal transmogrifier located at Lunarfall's Storehouse...", "Warpweaver Tuviss is an ethereal transmogrifier located at Lunarfall's Storehouse in Shadowmoon Valley, as well as in the Simply Enchanting shop in Dalaran over the Broken Isles. This section concerns content related to The War Within." },
  ["warpweaver voxin"] = { 2, "ethereal located in the Forgegrounds in Dornogal", "Warpweaver Voxin is an ethereal located in the Forgegrounds in Dornogal." },
  ["warpweaver zumzi"] = { 2, "ethereal transmogrifier located at Zen'shiri Trading Post...", "Warpweaver Zumzi is an ethereal transmogrifier located at Zen'shiri Trading Post in the Valley of Strength in Orgrimmar." },
  ["warrak"] = { 2, "old tuskarr hoarder from Taruka's clan", "Warrak is an old tuskarr hoarder from Taruka's clan. Taruka hoped to earn five knots so she could buy a bolt of kite silk for her sister Unka from Warrak." },
  ["warrith"] = { 2, "Broken leader", "Warrith was a Broken leader. He and his tribe were often hunted by the nether drakes Valoku and Zzeraku." },
  ["warug"] = { 2, "centaur quest giver located in Magram Village in Desolace", "Warug is a centaur quest giver located in Magram Village in Desolace. He was a leader of the Magram, and acted as the spokesman for the clan in dealing with Horde or Alliance aid against their enemy clans." },
  ["warug's bodyguard"] = { 2, "', "Warug's Bodyguards are two centaur who protect Warug at his camp north of Magram Village in Desolace." },
  ["washengtu"] = { 2, "centaur flight master located at Broadhoof Outpost in the...", "Washengtu is a centaur flight master located at Broadhoof Outpost in the Ohn'ahran Plains and in the Nokhud Offensive (in which Broadhoof Outpost is considered part of the Nokhud Approach). They appear as female in the Ohn'ahran Plains, but male i..." },
  ["wastelander farstalker (eco-dome al'dani)"] = { 2, "', "Wastelander Farstalkers are ethereals located in Eco-Dome Al'dani." },
  ["wastelander pactspeaker"] = { 2, "', "Wastelander Pactspeakers are ethereals located in the Al'dani Sands in Eco-Dome Al'dani." },
  ["wastelander phaseblade"] = { 2, "', "Wastelander Phaseblades are ethereals located in Eco-Dome Al'dani." },
  ["wastelander ritualist"] = { 2, "', "Wastelander Ritualists are ethereals located in Eco-Dome Al'dani." },
  ["wastelander soulbinder"] = { 2, "', "Wastelander Soulbinders are ethereals located at Castigaar on K'aresh." },
  ["wastewalker slave"] = { 2, "', "Wastewalker Slaves are Broken located in the Slave Pens." },
  ["wastewalker worker"] = { 2, "', "Wastewalker Workers are Broken who assist Coilfang Slavehandlers in combat in the Slave Pens." },
  ["watcher elaira"] = { 2, "tauren druid found above Forge Camp Hate in Nagrand", "Watcher Elaira is a tauren druid found above Forge Camp Hate in Nagrand. She was once part of the druid  [Swift Flight Form] quest line." },
  ["watcher emil"] = { 2, "venthyr located in the Crypt of the Forgotten in Revendreth", "Watcher Emil is a venthyr located in the Crypt of the Forgotten in Revendreth. He had been put in charge of the Catacombs of Regret by the Curator, who sent the Maw Walker to find Emil." },
  ["watcher eva"] = { 2, "rare undead", "Watcher Eva is a rare undead and former member of the Night Watch found wandering around southeastern Duskwood. He wanders around the Tranquil Gardens Cemetery, kneels at a grave, then goes to stand inside Blind Mary's house." },
  ["watcher havros"] = { 2, "kyrian located at Perdition Hold in the Maw", "Watcher Havros is a kyrian located at Perdition Hold in the Maw. Attempting to free him will send his soul into the Soulkeeper Crystal." },
  ["watcher jacintha"] = { 2, "kyrian located in the Temple of Humility in Bastion durin...", "Watcher Jacintha is a kyrian located in the Temple of Humility in Bastion during  [60WQ] Limbo." },
  ["watcher toki"] = { 2, "earthen located in Gundargaz in the Ringing Deeps where s...", "Watcher Toki is an earthen located in Gundargaz in the Ringing Deeps where she asks adventurers to kill The Ringing Death. Later she traveled to Ironforge alongside Vokmar and other earthen after High Speaker Brinthe asked her to serve as an ambas..." },
  ["watchman darkfury"] = { 2, "worgen located at Lion's Watch in Tanaan Jungle", "Watchman Darkfury is a worgen located at Lion's Watch in Tanaan Jungle. She is involved in the Alliance offensive against Gul'dan's Iron Horde in Tanaan." },
  ["watchmaster leonar"] = { 2, "Ascended kyrian located in Bastion", "Watchmaster Leonar is an Ascended kyrian located in Bastion. He was part of the grand reception the Archon arranged for a Maw Walker, who decided to join the Kyrian Covenant, in honor of their efforts against the Maldraxxus incursion in Bastion." },
  ["watergliding instructor"] = { 2, "', "Watergliding Instructors are tuskarr located at Eclipse Lake in Thaldraszus." },
  ["watersmith aiga"] = { 2, "ankoan of the Waveblade clan 'whose weapons always struck...", "Watersmith Aiga was an ankoan of the Waveblade clan 'whose weapons always struck true and carry on her legacy with every strike.' She lies buried at an Ankoan Burial Shrine in Gorgonian Overlook in Nazjatar." },
  ["waterworks gem-thief"] = { 2, "', "Waterworks Gem-Thieves are kobolds located in the Waterworks in the Ringing Deeps." },
  ["wavecrasher jurvak"] = { 2, "worldsoul memory of a vrykul located in the Isle of Dorn ...", "Wavecrasher Jurvak is the worldsoul memory of a vrykul located in the Isle of Dorn during  [80] Worldsoul Memory: Ancient Explorers event." },
  ["wavemistress s'revess"] = { 2, "naga of Zithreenai‎", "Wavemistress S'revess is a naga of Zithreenai‎ that was taken out by the Valarjar at the sunken ship Vaesska in Vashj'ir." },
  ["wax miner"] = { 2, "', "Wax Miners are kobolds located in Highmountain." },
  ["waxface"] = { 2, "swolbold located in the Waterworks", "Waxface is a swolbold located in the Waterworks." },
  ["waxle bangsaw"] = { 2, "goblin located at Venturewood in the Undermine", "Waxle Bangsaw is a goblin located at Venturewood in the Undermine." },
  ["waxmonger quiwik"] = { 2, "kobold located in Foundation Hall in Dornogal", "Waxmonger Quiwik is a kobold located in Foundation Hall in Dornogal. He gives the same quests as Waxmonger Squick in the Ringing Deeps for reaching certain Renown levels." },
  ["waxmonger squick"] = { 2, "kobold located in Gundargaz in the Ringing Deeps", "Waxmonger Squick is a kobold located in Gundargaz in the Ringing Deeps." },
  ["wayfinder ros"] = { 2, "broker flight master", "Wayfinder Ros is a broker flight master. While his whereabouts are unknown, a Bundle of Writings left by him, are found near the Ancient Translocator in Haven." },
  ["wayne the ancestral"] = { 2, "', "Wayne the Ancestral is located in the Lost Estate in Stormsong Valley." },
  ["wayneth antonius"] = { 2, "human", "Wayneth Antonius is a human. He was originally a reference to game designer Luis Barriga." },
  ["wayun"] = { 2, "tuskarr located in Whaler's Nook in the Azure Span", "Wayun is a tuskarr located in Whaler's Nook in the Azure Span." },
  ["wealthy patron"] = { 2, "Veiled Market", "Wealthy Patrons are brokers located at the Lap of Luxury in Tazavesh, the Veiled Market." },
  ["weaponmaster aloom"] = { 2, "centaur located in Maruukai in the Ohn'ahran Plains", "Weaponmaster Aloom is a centaur located in Maruukai in the Ohn'ahran Plains." },
  ["weaver aoa"] = { 2, "draenei tailoring trainer", "Weaver Aoa is a draenei tailoring trainer and vendor located on Aldor Rise in Shattrath City." },
  ["weaver daavu"] = { 2, "centaur located in the Ohn'ahran Plains", "Weaver Daavu is a centaur located in the Ohn'ahran Plains. He is one of the few surviving members of Clan Toghus, having been rescued from the village of Daruukhan after it was destroyed by Clan Nokhud." },
  ["weaver oesson"] = { 2, "ethereal located in any neighborhood where Consortium Con...", "Weaver Oesson is an ethereal located in any neighborhood where Consortium Consternation is the active endeavor. She appears in the Town Center in Founder's Point and the Common in Razorwind Shores." },
  ["weaver opali"] = { 2, "centaur located Teerakai in the Ohn'ahran Plains", "Weaver Opali is a centaur located Teerakai in the Ohn'ahran Plains." },
  ["weaver sagaa"] = { 2, "centaur located in the Ohn'ahran Plains", "Weaver Sagaa is a centaur located in the Ohn'ahran Plains. She is one of the few surviving members of Clan Toghus, having been rescued from the village of Daruukhan after it was destroyed by Clan Nokhud." },
  ["weaver torei"] = { 2, "centaur tailoring trainer", "Weaver Torei is a centaur tailoring trainer and vendor located in Maruukai in the Ohn'ahran Plains." },
  ["weaver yulutai"] = { 2, "centaur tailoring trainer located in southern Teerakai in...", "Weaver Yulutai is a centaur tailoring trainer located in southern Teerakai in the Ohn'ahran Plains, talking to an Iskaara Trader." },
  ["webbed lamplighter"] = { 2, "', "Webbed Lamplighters are Arathi captured by the nerubians in the Earthcrawl Mines." },
  ["webster"] = { 2, "nerubian spiderling located in the Fissure in Dornogal", "Webster is a nerubian spiderling located in the Fissure in Dornogal and in the Weaver's Lair in Azj-Kahet." },
  ["webwarper tath'rhiz"] = { 2, "nerubian located in Rak-Ahat in Azj-Kahet", "Webwarper Tath'rhiz is a nerubian located in Rak-Ahat in Azj-Kahet." },
  ["weed reaper basir"] = { 2, "Arathi located in Hallowfall", "Weed Reaper Basir is an Arathi located in Hallowfall. When Hallowfall once again came under threat by the Sureki and the army was stretched thin, a call to arms was issued to those with the strength to wield a weapon." },
  ["weeder greenthumb"] = { 2, "tauren found in the Slave Pens", "Weeder Greenthumb is a tauren found in the Slave Pens. To find him, you must first kill Mennu the Betrayer." },
  ["weegli blastfuse"] = { 2, "elite goblin found in Zul'Farrak", "Weegli Blastfuse is an elite goblin found in Zul'Farrak. Weegli is friendly and assists during the Pyramid battle." },
  ["weeping necrolith"] = { 2, "', "Weeping Necroliths are undead night elves located in Highmountain. They are stationary so long as you face them, but they move towards you at an incredibly high speed if you look away." },
  ["weisheng"] = { 2, "mogu found in the Hall of Kings in the Throne of Thunder", "Weisheng is a mogu found in the Hall of Kings in the Throne of Thunder." },
  ["welbiz cheerwhistle"] = { 2, "', "Welbiz Cheerwhistle redeems Tier 16 Raid Finder armor tokens for Alliance players in Shrine of Seven Stars." },
  ["well-informed trader"] = { 2, "Veiled Market", "Well-informed Traders are brokers located in Tazavesh, the Veiled Market." },
  ["wendy breezy"] = { 2, "gnome reporter of the highly esteemed Gnomeregan Gnews Gn...", "Wendy Breezy is the gnome reporter of the highly esteemed Gnomeregan Gnews Gnetwork." },
  ["wenha"] = { 2, "vulpera sitting next to Evie", "Wenha is a vulpera sitting next to Evie and watching the two Playful Prowlers outside the Orgrimmar Embassy in Orgrimmar." },
  ["wenikee boltbucket"] = { 2, "goblin quest giver located just southeast of the Mor'shan...", "Wenikee Boltbucket is a goblin quest giver located just southeast of the Mor'shan Base Camp in the Northern Barrens. This section concerns content related to Legion." },
  ["wenren althal"] = { 2, "Arathi quest giver located at Beledar's Bounty in Hallowfall", "Wenren Althal was an Arathi quest giver located at Beledar's Bounty in Hallowfall. The last surviving mage of the Hallowfall Arathi, he was working on a way to open a portal back to the Arathi Empire, and eventually asked adventurers to assist him..." },
  ["werlot"] = { 2, "Arathi located in the Dayspring Fields in Hallowfall", "Werlot is an Arathi located in the Dayspring Fields in Hallowfall." },
  ["whaldak darbenk"] = { 2, "dwarf", "Whaldak Darbenk was a dwarf who was found in Loch Modan during the original beta." },
  ["whale's belly patron"] = { 2, "', "Whale's Belly Patrons are located in the Whale's Belly in Tiragarde Sound." },
  ["wheat"] = { 2, "kobold stable master located in Camp Murroch in the Ringi...", "Wheat is a kobold stable master located in Camp Murroch in the Ringing Deeps. He is in a bathtub, and Charmed Glowmites, a Palelight Hopper, and a Seafoam Hopper are near him." },
  ["whelptamer akumi"] = { 2, "Blackrock clan orc found at the Valley of Ashes in the Bu...", "Whelptamer Akumi is a Blackrock clan orc found at the Valley of Ashes in the Burning Steppes. She is a hunter-type that uses either a bow or melee attacks." },
  ["whimsy cogtattler"] = { 2, "gnome located at the Obsidian Bulwark in the Waking Shores", "Whimsy Cogtattler is a gnome located at the Obsidian Bulwark in the Waking Shores. She is one of the seven gnomes following Becca Black." },
  ["whirling dervish"] = { 2, "', "Whirling Dervishes are arakkoa located in Lower Quarter and Grand Spire in Skyreach." },
  ["whisperer batalsworn"] = { 2, "Arathi located in Hallowfall", "Whisperer Batalsworn is an Arathi located in Hallowfall." },
  ["whisperer bravefort"] = { 2, "Arathi located in Hallowfall", "Whisperer Bravefort is an Arathi located in Hallowfall." },
  ["whisperer hillhelm"] = { 2, "Arathi located in Azj-Kahet", "Whisperer Hillhelm is an Arathi located in Azj-Kahet." },
  ["whisperer siegesage"] = { 2, "Arathi located in Hallowfall", "Whisperer Siegesage is an Arathi located in Hallowfall. He's summoned by interacting with a Suspicious Document lying on the ground." },
  ["whisperer warhavuk"] = { 2, "Arathi located in Azj-Kahet", "Whisperer Warhavuk is an Arathi located in Azj-Kahet." },
  ["whisperer warsididel"] = { 2, "Arathi located in Azj-Kahet", "Whisperer Warsididel is an Arathi located in Azj-Kahet." },
  ["whispering lurker"] = { 2, "', "Whispering Lurkers are troll aberrations located in the Passage of Time in Thaldraszus." },
  ["whisperwind healer"] = { 2, "', "Whisperwind Healers are secretly satyr disguised as tauren and night elves located at Jadefire Run in Felwood." },
  ["whistler"] = { 2, "quilboar", "Whistler is a quilboar." },
  ["whitewhisker digger"] = { 2, "', "Whitewhisker Diggers are kobolds found in the Coldtooth Mine in Alterac Valley when neither side has control." },
  ["whitewhisker geomancer"] = { 2, "', "Whitewhisker Geomancers are kobolds found in the Coldtooth Mine in Alterac Valley when neither side has control." },
  ["whitewhisker overseer"] = { 2, "', "Whitewhisker Overseers are kobolds found in the Coldtooth Mine in Alterac Valley when neither side has control." },
  ["whitewhisker tunnel rat"] = { 2, "kobold located in Alterac Valley", "Whitewhisker Tunnel Rat was a kobold located in Alterac Valley." },
  ["whitewhisker vermin"] = { 2, "', "Whitewhisker Vermin are kobolds found in the Coldtooth Mine in Alterac Valley when neither side has control." },
  ["whulwert copperpinch"] = { 2, "vendor located on the lower rise in the tauren city of Th...", "Whulwert Copperpinch is a vendor located on the lower rise in the tauren city of Thunder Bluff during the Feast of Winter Veil event. He is affiliated with Smokywood Pastures, and sells higher value holiday related items." },
  ["wicked oppressor"] = { 2, "', "Wicked Oppressors are venthyr located in Sanguine Depths." },
  ["widow arak'nai"] = { 2, "other two being Anub'azal (the General)", "Widow Arak'nai, codenamed the Weaver, is one of the three leaders of the Severed Threads conspiracy, the other two being Anub'azal (the General) and Executor Nizrek (the Vizier). She leads a titular subfaction, the Weaver, and is found dangling fr..." },
  ["wildlands furbolg"] = { 2, "', "Wildlands Furbolgs are furbolgs located on the expedition isles." },
  ["wildlands shaman"] = { 2, "', "Wildlands Shaman are furbolgs located on the expedition isles." },
  ["wildlands totemic"] = { 2, "', "Wildlands Totemics are furbolgs located on the expedition isles." },
  ["wildlands tracker"] = { 2, "', "Wildlands Trackers are furbolgs located on the expedition isles." },
  ["wildlands ursa"] = { 2, "', "Wildlands Ursas are furbolgs located on the expedition isles." },
  ["wildlands warrior"] = { 2, "', "Wildlands Warriors are furbolgs located on the expedition isles." },
  ["wildpaw alpha"] = { 2, "', "Wildpaw Alphas are gnolls of the Wildpaw tribe found in Alterac Valley." },
  ["wildpaw brute"] = { 2, "', "Wildpaw Brutes are gnolls of the Wildpaw tribe found in Alterac Valley." },
  ["wildpaw gnoll"] = { 2, "', "Wildpaw Gnolls are gnolls located in Alterac Valley. Killing a Wildpaw Gnoll will result in +1 reputation with either the Stormpike Guard or the Frostwolf Clan." },
  ["wildpaw mystic"] = { 2, "', "Wildpaw Mystics are gnolls of the Wildpaw tribe found in Alterac Valley." },
  ["wildpaw shaman"] = { 2, "', "Wildpaw Shaman are gnolls of the Wildpaw tribe found in Alterac Valley." },
  ["wildspawn betrayer"] = { 2, "', "Wildspawn Betrayers are satyrs located in the eastern part of Dire Maul." },
  ["wildspawn felsworn"] = { 2, "', "Wildspawn Felsworns are satyrs located in the eastern part of Dire Maul." },
  ["wildspawn hellcaller"] = { 2, "', "Wildspawn Hellcallers are satyrs found in Dire Maul." },
  ["wildspawn rogue"] = { 2, "', "Wildspawn Rogues are satyrs located in the eastern part of Dire Maul." },
  ["wildspawn satyr"] = { 2, "', "Wildspawn Satyr are satyrs located in Dire Maul. Their attacks are standard warrior abilities." },
  ["wildspawn shadowstalker"] = { 2, "', "Wildspawn Shadowstalkers are satyrs located in the eastern part of Dire Maul." },
  ["wildspawn trickster"] = { 2, "', "Wildspawn Tricksters are satyrs found in Dire Maul." },
  ["wiley"] = { 2, "vulpera carrying a rocket", "Wiley is a vulpera carrying a rocket that constantly runs in a large circuit around western Vol'dun at very high speeds, pursuing the Ridge Runner." },
  ["wiley jaki"] = { 2, "vulpera located in Tiragarde Sound", "Wiley Jaki is a vulpera located in Tiragarde Sound." },
  ["wilfred fizzlebang"] = { 2, "gnome warlock located on the Argent Tournament Grounds in...", "Wilfred Fizzlebang is a gnome warlock located on the Argent Tournament Grounds in Icecrown, where he is surrounded by Visiting Warlocks. He later appears in the Crusaders' Coliseum, where he attempts to summon a doomguard for the next challenge." },
  ["will larsons"] = { 2, "worgen battle pet trainer located near the center of Lor'...", "Will Larsons is a worgen battle pet trainer located near the center of Lor'danel in Darkshore. He is accompanied by his level 5 pet Gilnean Raven, Poe." },
  ["willard blauvelt"] = { 2, "orc located at the Circle of Wills in Underbelly", "Willard Blauvelt is an orc located at the Circle of Wills in Underbelly." },
  ["willard harrington"] = { 2, "worgen blacksmithing supplies vendor located at the Talon...", "Willard Harrington is a worgen blacksmithing supplies vendor located at the Talonbranch Glade in Felwood. He can be found within the tree, working with the anvil and forge nearby him." },
  ["willey hopebreaker"] = { 2, "undead of the Risen in Stratholme", "Willey Hopebreaker, previously known as a scarlet crusader Cannon Master Willey, is an undead of the Risen in Stratholme." },
  ["william allerton"] = { 2, "friend of Thassarian", "William Allerton was a friend of Thassarian, his body is found at the Farshire Mine in the Borean Tundra." },
  ["william edwards"] = { 2, "worgen", "William Edwards is a worgen." },
  ["willow"] = { 2, "Forsaken located at Kormek's Hut in Desolace", "Willow is a Forsaken located at Kormek's Hut in Desolace. Although she claims to adventurers to be a researcher working for the sake of science, she is actually an agent of Twilight's Hammer." },
  ["wilton hillhelm"] = { 2, "Arathi located at Hillhelm Stead in Hallowfall", "Wilton Hillhelm is an Arathi located at Hillhelm Stead in Hallowfall." },
  ["wind lord mel'jarak"] = { 2, "fourth boss in Heart of Fear", "Wind Lord Mel'jarak is the fourth boss in Heart of Fear. After his Set'thik soldiers and Garalon fail to stop the invading enemy, he makes his stand at the door to the Heart of Fear's inner sanctum with his swarm of Kor'thik warriors, Zar'thik hea..." },
  ["wind trader lathrai"] = { 2, "engineering vendor located in the Lower City of the neutr...", "Wind Trader Lathrai is a engineering vendor located in the Lower City of the neutral Shattrath City. He deals in exotic goods from other dimensions." },
  ["wind trader marid"] = { 2, "ethereal quest giver located at the Protectorate Watch Po...", "Wind Trader Marid is an ethereal quest giver located at the Protectorate Watch Post in the Netherstorm. Working for Prince Kael'thas Sunstrider and the Sunfury, Marid was killed by the adventurer when he tried to kill them after they chose to work..." },
  ["wind trader mu'fah"] = { 2, "ambassador to the blue dragonflight sent by the Ethereum", "Wind Trader Mu'fah is the ambassador to the blue dragonflight sent by the Ethereum, who plans to align with them. He is found in Moonrest Gardens in the Dragonblight." },
  ["wind trader tuluman"] = { 2, "ethereal weapon vendor located at Tuluman's Landing in Ne...", "Wind Trader Tuluman is an ethereal weapon vendor located at Tuluman's Landing in Netherstorm. In actuality, he is an agent that personally works for Nexus-Prince Haramad." },
  ["wind trader zhareem"] = { 2, "ethereal quest giver located in the Lower City of Shattrath", "Wind Trader Zhareem is an ethereal quest giver located in the Lower City of Shattrath. Zhareem can be found in the eastern part of Lower City, outside the World's End Tavern." },
  ["windborne primalist"] = { 2, "', "Windborne Primalists are night elves and vulpera located in the Wild Preserve in the Waking Shores." },
  ["windcaller blackhoof"] = { 2, "tauren quest giver located at Cenarion Refuge in Zangarmarsh", "Windcaller Blackhoof is a tauren quest giver located at Cenarion Refuge in Zangarmarsh." },
  ["windcaller claw"] = { 2, "tauren found in the Underbog", "Windcaller Claw is a tauren found in the Underbog. He also appears in the Steamvault." },
  ["windkeeper koreyx"] = { 2, "Adherent of Rukhmar", "Windkeeper Koreyx is an Adherent of Rukhmar that oversees Windswept Terrace. He does battle with Arakkoa Outcasts that were carried to his terrace by Ka'alu." },
  ["windreader argoram"] = { 2, "Thunderlord orc located at the Magnarok in Frostfire Ridge", "Windreader Argoram is a Thunderlord orc located at the Magnarok in Frostfire Ridge." },
  ["windreaver tar'rath"] = { 2, "mantid located in Rough-Hewn Passage in front of the Cham...", "Windreaver Tar'rath is a mantid located in Rough-Hewn Passage in front of the Chamber of the Paragons in the Siege of Orgrimmar." },
  ["windsage asuta"] = { 2, "centaur located at Forkriver Crossing in the Ohn'ahran Pl...", "Windsage Asuta is a centaur located at Forkriver Crossing in the Ohn'ahran Plains." },
  ["windsage contan"] = { 2, "centaur located at the Ohn'ir pools in Maruukai in the Oh...", "Windsage Contan is a centaur located at the Ohn'ir pools in Maruukai in the Ohn'ahran Plains, where she is performing a ritual with her sisters Windsage Kestan and Windsage Narran. All three were born of Clan Shikaar, but joined Clan Ohn'ir and we..." },
  ["windsage dawa"] = { 2, "centaur quest giver located at the Ohn'ir pools in Maruuk...", "Windsage Dawa is a centaur quest giver located at the Ohn'ir pools in Maruukai in the Ohn'ahran Plains. He asks adventurers to help him prepare a proposal to the love of his life, Hunter Narman, but frets about making the gesture great enough to m..." },
  ["windsage duusalkhi"] = { 2, "centaur located outside Daruukhan in the Ohn'ahran Plains", "Windsage Duusalkhi is a centaur located outside Daruukhan in the Ohn'ahran Plains." },
  ["windsage garuman"] = { 2, "centaur of Clan Ohn'ir", "Windsage Garuman is a centaur of Clan Ohn'ir, assigned to serve as advisor to Clan Nokhud, who appears in the Nokhud encampment in Maruukai in the Ohn'ahran Plains during  [20-70] Unwelcome Outsider. He accuses the Nokhud leader Balakar Khan of be..." },
  ["windsage kestan"] = { 2, "centaur located at the Ohn'ir pools in Maruukai in the Oh...", "Windsage Kestan is a centaur located at the Ohn'ir pools in Maruukai in the Ohn'ahran Plains, where she is performing a ritual with her sisters Windsage Contan and Windsage Narran." },
  ["windsage kven"] = { 2, "centaur talisman vendor", "Windsage Kven is a centaur talisman vendor and quest giver located at the Ohn'ir pools in Maruukai in the Ohn'ahran Plains." },
  ["windsage narran"] = { 2, "centaur located at the Ohn'ir pools in Maruukai in the Oh...", "Windsage Narran is a centaur located at the Ohn'ir pools in Maruukai in the Ohn'ahran Plains, where she is performing a ritual with her sisters Windsage Contan and Windsage Kestan. All three were born of Clan Shikaar, but joined Clan Ohn'ir and we..." },
  ["windsage oohr"] = { 2, "centaur cooking vendor located in Maruukai in the Ohn'ahr...", "Windsage Oohr is a centaur cooking vendor located in Maruukai in the Ohn'ahran Plains." },
  ["windsage ordven"] = { 2, "centaur located in Maruukai in the Ohn'ahran Plains", "Windsage Ordven is a centaur located in Maruukai in the Ohn'ahran Plains." },
  ["windsage qulisek"] = { 2, "centaur alchemy trainer", "Windsage Qulisek is a centaur alchemy trainer and vendor located in Maruukai in the Ohn'ahran Plains." },
  ["windsage selen"] = { 2, "centaur located at Broadhoof Outpost in the Ohn'ahran Plains", "Windsage Selen is a centaur located at Broadhoof Outpost in the Ohn'ahran Plains." },
  ["windsage togotseng"] = { 2, "centaur located in Ohn'iri Springs in the Ohn'ahran Plains", "Windsage Togotseng is a centaur located in Ohn'iri Springs in the Ohn'ahran Plains." },
  ["windsage tohr"] = { 2, "centaur located at the Ohn'ir pools in Maruukai in the Oh...", "Windsage Tohr is a centaur located at the Ohn'ir pools in Maruukai in the Ohn'ahran Plains. She is maintaining an orb of wind magic that she moves back and forth over the ground while Initiate Okan trains at hitting it with bolts of his own magic." },
  ["windseeker avash"] = { 2, "centaur located in the Ohn'ahran Plains", "Windseeker Avash is a centaur located in the Ohn'ahran Plains." },
  ["windseer grayhorn"] = { 2, "tauren quest giver located at Conquest Hold in the Grizzl...", "Windseer Grayhorn is a tauren quest giver located at Conquest Hold in the Grizzly Hills." },
  ["windshear digger"] = { 2, "', "Windshear Diggers were kobolds located in Stonetalon Mountains." },
  ["windshear geomancer"] = { 2, "', "Windshear Geomancers were kobolds found in Stonetalon Mountains." },
  ["windshear overlord"] = { 2, "', "Windshear Overlords were kobolds overseeing the miners in Windshear Crag in the Stonetalon Mountains." },
  ["windshear stonecutter"] = { 2, "', "Windshear Stonecutters were kobolds found in Stonetalon Mountains." },
  ["windshear tunnel rat"] = { 2, "', "Windshear Tunnel Rats were kobolds located in Stonetalon Mountains." },
  ["windshear vermin"] = { 2, "', "Windshear Vermin were kobolds located in the Stonetalon Mountains." },
  ["windstalker ifram"] = { 2, "ethereal rogue trainer located at the Terrace of Light in...", "Windstalker Ifram is an ethereal rogue trainer located at the Terrace of Light in Shattrath City." },
  ["wing commander brack"] = { 2, "orc located at Reaver's Fall in Hellfire Peninsula", "Wing Commander Brack is an orc located at Reaver's Fall in Hellfire Peninsula. He is involved with providing wyverns for bombing of the Burning Legion." },
  ["wing leader ner'onok"] = { 2, "mantid", "Wing Leader Ner'onok is a mantid and the last boss encounter of Siege of Niuzao Temple. Ner'onok was known as a master tactician." },
  ["wing-guard kuuan"] = { 2, "arakkoa wing-guard", "Wing-Guard Kuuan is a arakkoa wing-guard that serves the Adherents of Rukhmar at Veil Shadar in Talador. Kura the Blind was once a comrade of his, but when Kura abandoned his post, Kuuan informed their superior and had him cast down." },
  ["winged champion"] = { 2, "', "Winged Champions are kyrian located in the Necrotic Wake and the Spires of Ascension. The ones in the Necrotic Wake appear at the Fall of Courage after players defeat Amarth." },
  ["wingleader srak'ik"] = { 2, "mantid", "Wingleader Srak'ik is a mantid that can be encountered during Island Expeditions." },
  ["winglord dezran"] = { 2, "dracthyr", "Winglord Dezran is a dracthyr, second in command of the Ebon Scales. Dezran accompanied Scalecommander Sarkareth back to the Forbidden Reach after Raszageth's death and spied on the Primal Incarnates when they obtained a device containing the loca..." },
  ["winglord iyazael"] = { 2, "dracthyr located in High Creche in the Forbidden Reach", "Winglord Iyazael is a dracthyr located in High Creche in the Forbidden Reach." },
  ["winglord saistrasz"] = { 2, "dracthyr located in the Roasted Ram in Valdrakken", "Winglord Saistrasz is a dracthyr located in the Roasted Ram in Valdrakken." },
  ["wings of the widow"] = { 2, "nerubian flight master located in the Weaver's Lair in Az...", "Wings of the Widow is a nerubian flight master located in the Weaver's Lair in Azj-Kahet." },
  ["winna hazzard"] = { 2, "Forsaken found at Bloodvenom Post in Felwood", "Winna Hazzard is a Forsaken found at Bloodvenom Post in Felwood. She was accompanied by her kitten and had a penchant for laughing maniacally." },
  ["winterfall ambusher"] = { 2, "', "Winterfall Ambushers are furbolgs found in Winterspring." },
  ["winterfall den watcher"] = { 2, "', "Winterfall Den Watchers are Winterfall furbolg found in Winterfall Village and Timbermaw Post in Winterspring. Killing one awards +20 reputation with Timbermaw Hold until Revered." },
  ["winterfall lookout"] = { 2, "furbolg", "Winterfall Lookout is a furbolg." },
  ["winterfall pathfinder"] = { 2, "', "Winterfall Pathfinders are furbolgs found in Timbermaw Post in Winterspring. Killing one results in +10 reputation with Timbermaw Hold." },
  ["winterfall runner"] = { 2, "', "Winterfall Runners are furbolgs found in Felwood and Winterspring. Killing a Winterfall Runner grants +20 reputation with Timbermaw Hold." },
  ["winterfall shaman"] = { 2, "', "Winterfall Shaman are furbolgs found in Winterfall Village in Winterspring. Killing Winterfall Shaman will result in +10 reputation with Timbermaw Hold." },
  ["winterfall totemic"] = { 2, "', "Winterfall Totemics are furbolgs found in Timbermaw Post in Winterspring. Killing one results in +20 reputation with Timbermaw Hold." },
  ["winterfall ursa"] = { 2, "', "Winterfall Ursas are furbolgs of the Winterfall found in Winterfall Village, to the east of Everlook in Winterspring. The Ursa tend to be near the back of the village." },
  ["winterpelt defender"] = { 2, "', "Winterpelt Defenders are Winterpelt furbolgs located at Winterpelt Hollow in the Azure Span. Two of them are located near Sonova Snowden and can be interacted with." },
  ["winterpelt prisoner"] = { 2, "', "Winterpelt Prisoners are furbolgs located in a cave in Winterpelt Hollow in the Azure Span." },
  ["winterskorn berserker"] = { 2, "', "Winterskorn Berserkers are vrykul found at Skorn in Howling Fjord." },
  ["winterskorn bonegrinder"] = { 2, "', "Winterskorn Bonegrinders are vrykul found at Baleheim in Howling Fjord." },
  ["winterskorn defender"] = { 2, "', "Winterskorn Defenders are vrykul located in Baleheim in the Howling Fjord." },
  ["winterskorn elder"] = { 2, "', "Winterskorn Elders are vrykul located at Skorn in the Howling Fjord." },
  ["winterskorn guard"] = { 2, "', "Winterskorn Guards are vrykul located at Vengeance Landing in Howling Fjord. They guard Prince Keleseth." },
  ["winterskorn hunter"] = { 2, "', "Winterskorn Hunters are vrykul found in Howling Fjord." },
  ["winterskorn oracle"] = { 2, "', "Winterskorn Oracles are vrykul located at Skorn in the Howling Fjord. Others can be released from Riven Widow Cocoons at Rivenwood." },
  ["winterskorn raider"] = { 2, "', "Winterskorn Raiders are vrykul found at Skorn in Howling Fjord." },
  ["winterskorn rune-caster"] = { 2, "', "Winterskorn Rune-Casters are vrykul found at Skorn in the Howling Fjord." },
  ["winterskorn rune-seer"] = { 2, "', "Winterskorn Rune-Seers are vrykul found at Skorn in Howling Fjord." },
  ["winterskorn scout"] = { 2, "', "Winterskorn Scout are vrykul located in the Howling Fjord. They protect the Dragonskin Scroll needed for  [10-30] Sniff Out the Enemy." },
  ["winterskorn shield-maiden"] = { 2, "', "Winterskorn Shield-Maidens are vrykul found in Skorn in Howling Fjord. They are accompanied by Winterskorn Worgs." },
  ["winterskorn skald"] = { 2, "', "Winterskorn Skalds are vrykul found at Baleheim in Howling Fjord." },
  ["winterskorn spearman"] = { 2, "', "Winterskorn Spearmen are vrykul found at Baleheim in Howling Fjord." },
  ["winterskorn tribesman"] = { 2, "', "Winterskorn Tribesmen are vrykul found at Skorn in Howling Fjord." },
  ["winterskorn warrior"] = { 2, "', "Winterskorn Warriors are vrykul found at Skorn in Howling Fjord." },
  ["winterskorn woodsman"] = { 2, "', "Winterskorn Woodsmen are vrykul found at Skorn in Howling Fjord." },
  ["wireweaver grelka"] = { 2, "earthen located in the Lapidarium in the Fissure in Dornogal", "Wireweaver Grelka is an earthen located in the Lapidarium in the Fissure in Dornogal." },
  ["witch lord morkurk"] = { 2, "ogre found at the Throne of the Witch Lord in Talador", "Witch Lord Morkurk is an ogre found at the Throne of the Witch Lord in Talador." },
  ["withered quilguard"] = { 2, "', "Withered Quilguards are quilboar found in Razorfen Downs and are very similar to the Withered Warriors." },
  ["withered reaver"] = { 2, "', "Withered Reavers are quilboar located in Razorfen Downs. They are slightly more powerful versions of the Withered Warriors." },
  ["withered spearhide"] = { 2, "', "Withered Spearhides are nasty, rotting withered quilboar who are some of the first you find in Razorfen Downs. They have quite a few tricks up their sleeves." },
  ["withered warrior"] = { 2, "', "Withered Warriors are quilboar found early on in the Razorfen Downs." },
  ["witherscorn annihilator"] = { 2, "', "Witherscorn Annihilators are Drust located in Ardenweald." },
  ["witherscorn vanguard"] = { 2, "', "Witherscorn Vanguards are Drust located in Ardenweald." },
  ["wizak blastbait"] = { 2, "goblin located at the Krasari Falls in Krasarang Wilds", "Wizak Blastbait is a goblin located at the Krasari Falls in Krasarang Wilds. Ben of the Booming Voice considers him his archenemy." },
  ["wizbang booms"] = { 2, "gnome Holiday Fireworks Vendor", "Wizbang Booms is a gnome Holiday Fireworks Vendor. He sells fireworks during the Midsummer Fire Festival or Peon Day seasonal events (see Notes section.) He can be found on the plateau just outside of the Ironforge gate Ironforge." },
  ["wizbang cranktoggle"] = { 2, "gnome quest giver located in Lor'danel in the night elven...", "Wizbang Cranktoggle is a gnome quest giver located in Lor'danel in the night elven zone of Darkshore. He works with buzzboxes, securing long-distance communication within Darkshore." },
  ["wizlo bearingshiner"] = { 2, "goblin quest giver located in Whitereach Post in Thousand...", "Wizlo Bearingshiner is a goblin quest giver located in Whitereach Post in Thousand Needles. He has been missing since the Cataclysm, presumably having been killed in the Thousand Needles disaster." },
  ["wizzle brassbolts"] = { 2, "gnome located at the Southsea Holdfast in the Thousand Ne...", "Wizzle Brassbolts is a gnome located at the Southsea Holdfast in the Thousand Needles. Pilot Longbeard is a friend of the Brassbolts." },
  ["woeblade"] = { 2, "kyrian abomination located at the southwestern end of the...", "Woeblade is a kyrian abomination located at the southwestern end of the Hall of Chains in Maldraxxus during the Kyrian and Necrolords Campaigns. It is an amalgamation of kyrian disciples captured from Bastion's Temple of Courage; Xandria calls it ..." },
  ["woldkeeper freydrin"] = { 2, "leader of the Woldguard", "Woldkeeper Freydrin was the leader of the Woldguard. Boskroot Basin was her home, it was her charge to tend to it, so given by Keeper Freya." },
  ["woldtender igris"] = { 2, "earthen woldtender located in Boskroot Basin on the Isle ...", "Woldtender Igris is an earthen woldtender located in Boskroot Basin on the Isle of Dorn." },
  ["wolf master nandos (classic)"] = { 2, "boss in Shadowfang Keep", "Wolf Master Nandos is a boss in Shadowfang Keep." },
  ["wolfgrimm blackmantle"] = { 2, "worgen located at the Lunarfall in Shadowmoon Valley", "Wolfgrimm Blackmantle is a worgen located at the Lunarfall in Shadowmoon Valley. He can only be recruited using the Headhunter's Harvest from Lunarfall Inn." },
  ["wolfhandler ang'cha"] = { 2, "orc stable master located at Wor'gol in Frostfire Ridge", "Wolfhandler Ang'cha is an orc stable master located at Wor'gol in Frostfire Ridge." },
  ["woodpaw alpha"] = { 2, "', "Woodpaw Alphas are gnoll leaders of the Woodpaw tribe found at the Woodpaw Den in Feralas." },
  ["woodpaw brute"] = { 2, "', "Woodpaw Brutes are gnolls located in Feralas." },
  ["woodpaw mongrel"] = { 2, "', "Woodpaw Mongrels are gnolls located in Feralas." },
  ["woodpaw mystic"] = { 2, "', "Woodpaw Mystics are gnolls located in Feralas." },
  ["woodpaw reaver"] = { 2, "', "Woodpaw Reavers are gnolls located in Feralas." },
  ["woodpaw trapper"] = { 2, "', "Woodpaw Trappers are gnolls located in Feralas." },
  ["worker yareh'losh"] = { 2, "nerubian located in the Silken Ward in Azj-Kahet", "Worker Yareh'losh is a nerubian located in the Silken Ward in Azj-Kahet." },
  ["workmaster earwax"] = { 2, "kobold located in Mourning Rise on the Isle of Dorn", "Workmaster Earwax is a kobold located in Mourning Rise on the Isle of Dorn." },
  ["workmaster nast"] = { 2, "kobold located in Mourning Rise on the Isle of Dorn", "Workmaster Nast is a kobold located in Mourning Rise on the Isle of Dorn." },
  ["wormcaller iz'tikrine"] = { 2, "nerubian located at the bottom of a cave (entrance at ) i...", "Wormcaller Iz'tikrine is a nerubian located at the bottom of a cave (entrance at ) in the Wormlands in Azj-Kahet, where he is channeling on an Ancient Resonance Pylon. He is a great admirer of jawcrawlers, having authored a three-volume essay on t..." },
  ["wormspeaker devout"] = { 2, "', "Wormspeaker Devouts are drogbar located in Neltharion's Lair, being eaten by Naraxas." },
  ["worthy vrykul"] = { 2, "', "Worthy Vrykul are vrykul found behind the instance portals of the Halls of Valor and Trial of Valor instances at the Gates of Valor in Stormheim. They move towards the middle of the rooms, where they kneel and then ascend to the Halls of Valor." },
  ["wotan"] = { 2, "great hunter of the Winterskorn clan", "Wotan was a great hunter of the Winterskorn clan. Byakko was his companion." },
  ["wounded aeroknight"] = { 2, "', "Wounded Aeroknights are Arathi located in Azj-Kahet." },
  ["wounded defender (bastion)"] = { 2, "', "Wounded Defenders are Ascended kyrian located at Agthia's Repose in Bastion. They can be infused with anima in order to heal them up." },
  ["wounded guardian"] = { 2, "', "Wounded Guardians are centaur located in Suffusion Camp: Cinderwind in the Ohn'ahran Plains during Fyrakk Assaults." },
  ["wounded horde soldier"] = { 2, "', "Wounded Horde Soldiers are wounded orcs, jungle trolls, and Darkfallen located in the Ruins of Lordaeron during the Battle for Lordaeron. Following the battle, they are located on the Gates of Orgrimmar in Orgrimmar being treated by Orgrimmar Medics." },
  ["wounded initiate"] = { 2, "centaur of Clan Ohn'ir located with Tigari Khan", "The Wounded Initiate is a centaur of Clan Ohn'ir located with Tigari Khan and the Badly Wounded Mystics on the road north of Ridgewater Retreat in the Ohn'ahran Plains during  [20-70] Mystic Mystery,  [20-70] Toting Totems, and  [20-70] Taken By S..." },
  ["wounded kyrian"] = { 2, "', "Wounded Kyrian are Ascended kyrian located in Bastion." },
  ["wounded slave"] = { 2, "injured vulpera slave kneeling in the eastern part of the...", "The Wounded Slave is an injured vulpera slave kneeling in the eastern part of the Thundering Terrace in Vol'dun, where he is being constantly beaten by a Skycaller Apprentice and a Faithless Champion." },
  ["wounded soldier (hallowfall)"] = { 2, "', "Wounded Soldiers are Arathi located in Lothar's Landing in Hallowfall. They are being healed by Valrin Paller, Claryssa Paller, Marja Lenglow, and Gundargaz Caretakers." },
  ["wounded tuskarr"] = { 2, "', "Wounded Tuskarr are tuskarr located in Suffusion Camp: Frostburn in the Azure Span." },
  ["wounded valiant"] = { 2, "', "Wounded Valiants are wounded Alliance and Horde defenders located at the Argent Tournament Grounds in Icecrown." },
  ["wrangler kravos"] = { 2, "Broken located in Azurelight Square in Eredath", "Wrangler Kravos is a Broken located in Azurelight Square in Eredath. He has a steed and is likely a former member of Jerek's Wranglers." },
  ["wrath corruptor"] = { 2, "', "Wrath Corruptors are orc and undead warlocks patrolling Vortex Summit in the Blade's Edge Mountains." },
  ["wrekt seer"] = { 2, "', "Wrekt Seers are Broken found in Tuurem in Terokkar Forest." },
  ["wrekt slave"] = { 2, "', "Wrekt Slaves are Broken found at the Bloodscale Enclave and Bloodscale Grounds in Zangarmarsh. Upon aggroing nearby Bloodscale Overseers or Bloodscale Slavedrivers, these Broken will be called upon to assist." },
  ["wrekt theurgist"] = { 2, "Broken", "Wrekt Theurgist is a Broken." },
  ["wrekt warrior"] = { 2, "', "Wrekt Warriors are Broken located at Tuurem in Terokkar Forest." },
  ["wren darkspring"] = { 2, "gnome warlock located in Anvilmar in Dun Morogh", "Wren Darkspring is a gnome warlock located in Anvilmar in Dun Morogh." },
  ["wrench blackboot"] = { 2, "great dwarven tinker", "Wrench Blackboot is a great dwarven tinker. Before he went deaf, he was hailed for his study of sound and creation of devices to capture and imitate sounds." },
  ["wulferd fizzbracket"] = { 2, "gnome located in Fizzsprings Resort in Tiragarde Sound", "Wulferd Fizzbracket is a gnome located in Fizzsprings Resort in Tiragarde Sound. This section concerns content related to Dragonflight." },
  ["wulfred harrys"] = { 2, "worgen quest giver located at Fort Livingston in Northern...", "Wulfred Harrys is a worgen quest giver located at Fort Livingston in Northern Stranglethorn. He has been allowed into the Explorers' League, despite being a worgen." },
  ["wuls"] = { 2, "vulpera located in the Bloom in Razorwind Shores", "Wuls is a vulpera located in the Bloom in Razorwind Shores." },
  ["wunna darkmane"] = { 2, "tauren trade goods vendor located in Bloodhoof Village in...", "Wunna Darkmane is a tauren trade goods vendor located in Bloodhoof Village in Mulgore. She is the only known vendor of  [Recipe: Roasted Kodo Meat]." },
  ["wuul breezerider"] = { 2, "tauren", "Wuul Breezerider is a tauren who comes from Mulgore. His wife died approximately 10 years before the Cataclysm." },
  ["wyll benton"] = { 2, "elderly servant of", "Wyll Benton was an elderly servant of Anduin Wrynn. He had been taking care of Anduin since the king was little and refusing his service would offend him." },
  ["wyneth"] = { 2, "centaur found near the Stagnant Oasis in the Barrens", "Wyneth is a centaur found near the Stagnant Oasis in the Barrens, who needs to be killed in  [5-30] Verog the Dervish to lure out her mate Verog." },
  ["wyrmcult acolyte"] = { 2, "', "Wyrmcult Acolytes can be found in Blade's Edge Mountains. They become friendly when wearing the  [Overseer Disguise]." },
  ["wyrmcult hewer"] = { 2, "', "Wyrmcult Hewers can be found in Blade's Edge Mountains." },
  ["wyrmcult zealot"] = { 2, "wyrmcult member", "The Wyrmcult Zealot is a wyrmcult member, who, when low on health, transforms in a dragonkin called Wyrmcult Blessed. They become friendly when wearing the  [Overseer Disguise]." },
  ["wyrmeater"] = { 2, "djaradin located in Dragonbane Keep in the Waking Shores", "Wyrmeater was a djaradin located in Dragonbane Keep in the Waking Shores. Serving as a lieutenant, she was killed during the Siege on Dragonbane Keep in order to destabilize the other djaradin." },
  ["wyrmslayer angvardi"] = { 2, "rare elite vrykul found atop the Froststone Peak tower in...", "Wyrmslayer Angvardi is a rare elite vrykul found atop the Froststone Peak tower in north-central Forbidden Reach alongside his companion Nidharr. He guards the  [Words of the Wyrmslayer] book on some crates nearby." },
  ["xabraxxis"] = { 2, "satyr summoned in Darkshore during  [18] The Blackwood Co...", "Xabraxxis is a satyr summoned in Darkshore during  [18] The Blackwood Corrupted. He is responsible for the corruption of the Blackwood furbolg." },
  ["xaevian the watchful"] = { 2, "kyrian located in the Eonian Archives in Bastion after ch...", "Xaevian the Watchful is a kyrian located in the Eonian Archives in Bastion after channeling the Anima Conductor level 3 to the area." },
  ["xal'in"] = { 2, "nerubian located in Klaskin's Hollow in the City of Threads", "Xal'in is a nerubian located in Klaskin's Hollow in the City of Threads." },
  ["xalan the feared"] = { 2, "most successful general of the satyrs in Xavian during th...", "Xalan the Feared was the most successful general of the satyrs in Xavian during the War of the Satyr. A small party of night elves led a covert assault on Xavian and successfully assassinated him." },
  ["xalethar"] = { 2, "satyr located at Xalethar's Lair in Val'sharah", "Xalethar was a satyr located at Xalethar's Lair in Val'sharah." },
  ["xandivious"] = { 2, "', "Xandivious can be found in Winterspring. He drops Xandivious' Demon Bag when killed." },
  ["xandria"] = { 2, "', "Xandria is one of the five Paragons of the kyrian Ascended in Bastion, embodying the virtue of courage. She is one of the more martial of Bastion's Paragons, and is unafraid to pursue enemies of the kyrian even beyond her own realm." },
  ["xandris the dishonored"] = { 2, "Dishonored is a satyr located at Moonclaw Vale in Val'sharah", "Xandris the Dishonored is a satyr located at Moonclaw Vale in Val'sharah. He was among the first to betray his brethren and accept what later came to be referred to as the 'curse of Xavius'." },
  ["xanis flameweaver"] = { 2, "tauren shaman located on the Spirit Rise in Thunder Bluff", "Xanis Flameweaver is a tauren shaman located on the Spirit Rise in Thunder Bluff." },
  ["xannifrax the terror"] = { 2, "satyr", "Xannifrax the Terror is a satyr that attacked Val'sharah's Temple of Elune but was taken out by the druidic class order." },
  ["xaravan"] = { 2, "leader of the Emerald Circle", "Archdruid Navarax was the leader of the Emerald Circle, situated in Whisperwind Grove. In reality, however, he was the satyr Xaravan who had infiltrated the organization." },
  ["xaril the poisoned mind"] = { 2, "expert alchemist", "Xaril the Poisoned Mind was one of the Klaxxi paragons. He was an expert alchemist who specialized in using poisons and explosive compounds." },
  ["xark bolthammer"] = { 2, "goblin blacksmithing", "Xark Bolthammer is a goblin blacksmithing and engineering vendor located at K3 in the Storm Peaks." },
  ["xarran the binder"] = { 2, "ethereal located at Lunnall River in K'aresh", "Xarran the Binder is an ethereal located at Lunnall River in K'aresh." },
  ["xavaric"] = { 2, "level 55 satyr found at Jadefire Run in northwestern Felwood", "Xavaric is a level 55 satyr found at Jadefire Run in northwestern Felwood. He is the leader of the Jadefire Satyrs and his minions feed from the fel corruption of the local creatures." },
  ["xavathras"] = { 2, "named satyr located at the Ruins of Constellas in Felwood", "Xavathras is a named satyr located at the Ruins of Constellas in Felwood. He is the cruel leader of a group of Jadefire satyrs, who have made their home in tents amongst the Ruins of Constellas." },
  ["xavian betrayer"] = { 2, "', "Xavian Betrayers are satyrs found in Xavian in Ashenvale." },
  ["xavian felsworn"] = { 2, "', "Xavian Felsworns are satyrs found in Xavian in Ashenvale." },
  ["xavian hellcaller"] = { 2, "', "Xavian Hellcallers are satyrs found in Xavian in Ashenvale." },
  ["xavian rogue"] = { 2, "', "Xavian Rogues are satyrs found in Xavian in Ashenvale." },
  ["xavinox"] = { 2, "satyr located at the Stormrage Barrow Dens in Moonglade", "Xavinox is a satyr located at the Stormrage Barrow Dens in Moonglade. He can only be fought after Clookle has been cured." },
  ["xavius"] = { 2, "great Sargeras", "'You killed me and condemned me to a worse fate! I had failed the exalted one, the great Sargeras...and as was his right as a god, he punished me most severely." },
  ["xavius (tactics)"] = { 2, "final boss of the Emerald Nightmare", "Xavius is the final boss of the Emerald Nightmare." },
  ["xem'altan"] = { 2, "broker planned to appear in Maldraxxus", "Xem'altan is a broker planned to appear in Maldraxxus." },
  ["xevex"] = { 2, "nerubian depicted by a statue in the Skeins in the City o...", "Xevex is a nerubian depicted by a statue in the Skeins in the City of Threads, southeast of the Royal Preservatorium. The statue's plaque can only be understood while under the effects of  [Potion of Polymorphic Translation: Nerubian]." },
  ["xevozz"] = { 2, "ethereal boss of Violet Hold", "Xevozz is an ethereal boss of Violet Hold, an instance in Dalaran." },
  ["xevveth"] = { 2, "dead Enlightened broker lying on the road through the Gre...", "Xevveth is a dead Enlightened broker lying on the road through the Great Veldt in Zereth Mortis during  [60] Finding Firim. He believed it might have been a mistake of the Enlightened to exile Firim and went to find him, but were killed by Xy'teth..." },
  ["xiang-lin"] = { 2, "mogu in the Spoils of Pandaria encounter in Siege of Orgr...", "Xiang-Lin is a mogu in the Spoils of Pandaria encounter in Siege of Orgrimmar." },
  ["xigan"] = { 2, "mogu located in the Vale of Eternal Blossoms", "Xigan is a mogu located in the Vale of Eternal Blossoms." },
  ["xil'azan"] = { 2, "broker", "Xil'azan is a broker." },
  ["xil'rafell"] = { 2, "nerubian located in the City of Threads", "Xil'rafell is a nerubian located in the City of Threads." },
  ["xiln the mountain"] = { 2, "mogu located in the Vale of Eternal Blossoms", "Xiln the Mountain is a mogu located in the Vale of Eternal Blossoms." },
  ["xin the weaponmaster"] = { 2, "King of the mogu clans", "Xin the Weaponmaster is the King of the mogu clans and the last boss of Mogu'shan Palace. After the death of Zhao-Jin the Bloodletter, Xin rallied mogu clans under his banner and penetrated into the heart of the Mogu'shan Palace." },
  ["xinthoss the spear"] = { 2, "satyr located in Highmountain", "Xinthoss the Spear was a satyr located in Highmountain. He attacked the tauren living in Sylvan Falls and was, in turn, killed by the druid champions sent from the Dreamgrove." },
  ["xlox'zillswan"] = { 2, "nerubian located in the City of Threads", "Xlox'zillswan is a nerubian located in the City of Threads." },
  ["xorothian satyr"] = { 2, "', "Xorothian Satyrs emerge from portals in Mazthoril in Winterspring, coming most likely from Xoroth." },
  ["xorvasc"] = { 2, "satyr located in Val'sharah", "Xorvasc is a satyr located in Val'sharah. This section concerns content related to The War Within." },
  ["xur'ios"] = { 2, "ethereal vendor", "Xur'ios is an ethereal vendor that can be found at the Antonidas Memorial in the Broken Isles version of Dalaran. It is currently unknown if he survived Dalaran's destruction." },
  ["xy acolyte"] = { 2, "', "Xy Acolytes are brokers located in Sepulcher of the First Ones." },
  ["xy imports associate"] = { 2, "Veiled Market in K'aresh", "Xy Imports Associates are brokers located in Tazavesh, the Veiled Market in K'aresh." },
  ["xy imports organizer"] = { 2, "Veiled Market in K'aresh", "Xy Imports Organizers are brokers located in Tazavesh, the Veiled Market in K'aresh." },
  ["xy relic dealer"] = { 2, "broker located in Shadowlands dungeons during Shadowlands...", "Xy Relic Dealer was a broker located in Shadowlands dungeons during Shadowlands Season 3." },
  ["xy spellslinger"] = { 2, "', "Xy Spellslingers are brokers located in the Sepulcher of the First Ones." },
  ["xy'sous"] = { 2, "broker located in Tazavesh", "Xy'Sous is a broker located in Tazavesh, the Veiled Market in K'aresh." },
  ["xy'anath"] = { 2, "', "Xy'anath is one of the broker assassins sent by Cartel Xy to kill Firim in Zereth Mortis, seen during  [60] Unseen Agents. They are located in the northernmost part of the Great Veldt, near the border with the Terrace of Formation." },
  ["xy'aqida"] = { 2, "broker located at the Bazaar of Tangible Delights in Taza...", "Xy'aqida is a broker located at the Bazaar of Tangible Delights in Tazavesh, the Veiled Market." },
  ["xy'aro"] = { 2, "broker located at the Bazaar of Tangible Delights in Taza...", "Xy'aro is a broker located at the Bazaar of Tangible Delights in Tazavesh, the Veiled Market." },
  ["xy'azam"] = { 2, "broker located at the Circle of Thought in Zereth Mortis", "Xy'azam is a broker located at the Circle of Thought in Zereth Mortis. Together with Xy'kina, he is working on a Corrupted Architect." },
  ["xy'bin"] = { 2, "broker located in Tazavesh", "Xy'bin is a broker located in Tazavesh, the Veiled Market." },
  ["xy'bok"] = { 2, "', "Xy'bok is one of the broker assassins sent by Cartel Xy to kill Firim in Zereth Mortis, seen during  [60] Unseen Agents. They are roaming an oblong area in the northeastern part of the Great Veldt." },
  ["xy'darid"] = { 2, "broker located at the Bazaar of Tangible Delights in Taza...", "Xy'darid is a broker located at the Bazaar of Tangible Delights in Tazavesh, the Veiled Market. His wares must be traded to other brokers in the area to obtain the password needed for entry to Myza's Oasis and the boss fight against Zo'gron." },
  ["xy'ghana"] = { 2, "broker located at the Bazaar of Tangible Delights in Taza...", "Xy'ghana is a broker located at the Bazaar of Tangible Delights in Tazavesh, the Veiled Market." },
  ["xy'gin"] = { 2, "broker located in Tazavesh's Bazaar of Tangible Delights ...", "Xy'gin is a broker located in Tazavesh's Bazaar of Tangible Delights on K'aresh. He disappears when the Shadowguard incursion on the city begins, and afterwards the sale of inscription goods is taken up by Xy'lus." },
  ["xy'har"] = { 2, "broker located at the Bazaar of Tangible Delights in Taza...", "Xy'har is a broker located at the Bazaar of Tangible Delights in Tazavesh, the Veiled Market." },
  ["xy'jahid"] = { 2, "broker located at the Bazaar of Tangible Delights in Taza...", "Xy'jahid is a broker located at the Bazaar of Tangible Delights in Tazavesh, the Veiled Market." },
  ["xy'kaz"] = { 2, "broker located in the Slumbering Vault in Zereth Mortis", "Xy'kaz is a broker located in the Slumbering Vault in Zereth Mortis." },
  ["xy'kina"] = { 2, "broker located at the Circle of Thought in Zereth Mortis", "Xy'kina is a broker located at the Circle of Thought in Zereth Mortis. Together with Xy'azam, he is working on a Corrupted Architect." },
  ["xy'kitaab"] = { 2, "broker located at the Bazaar of Tangible Delights in Taza...", "Xy'kitaab is a broker located at the Bazaar of Tangible Delights in Tazavesh, the Veiled Market." },
  ["xy'lonu"] = { 2, "broker located in the Keeper's Respite of Korthia", "Xy'lonu is a broker located in the Keeper's Respite of Korthia. She sends Maw Walkers in quests to collect boxes with various items acquired by her associates in Korthia." },
  ["xy'low"] = { 2, "broker located in Tazavesh", "Xy'low is a broker located in Tazavesh, the Veiled Market in K'aresh." },
  ["xy'lus"] = { 2, "broker located near the Xy Imports Offices of Tazavesh", "Xy'lus is a broker located near the Xy Imports Offices of Tazavesh, the Veiled Market in K'aresh." },
  ["xy'mal"] = { 2, "broker located at the Bazaar of Tangible Delights in Taza...", "Xy'mal is a broker located at the Bazaar of Tangible Delights in Tazavesh, the Veiled Market." },
  ["xy'nam"] = { 2, "broker located in the Grand Menagerie in Tazavesh", "Xy'nam is a broker located in the Grand Menagerie in Tazavesh, the Veiled Market. He is one of the auctioneers, alongside Xy'noc, who run the place." },
  ["xy'nara"] = { 2, "broker located at the Bazaar of Tangible Delights in Taza...", "Xy'nara is a broker located at the Bazaar of Tangible Delights in Tazavesh, the Veiled Market." },
  ["xy'nell"] = { 2, "broker located in Tazavesh", "Associate Xy'nell is a broker located in Tazavesh, the Veiled Market in K'aresh. After the events of the 'On a Technicality' optional chapter of the Ghosts of K'aresh campaign, Xy'nell is promoted to Interim Coordinator Xy'nell." },
  ["xy'noc"] = { 2, "broker located in the Grand Menagerie in Tazavesh", "Xy'noc is a broker located in the Grand Menagerie in Tazavesh, the Veiled Market. She is one of the auctioneers, alongside Xy'nam, who run the place." },
  ["xy'rah"] = { 2, "broker located outside of Myza's Oasis in Tazavesh on K'a...", "Xy'rah is a broker located outside of Myza's Oasis in Tazavesh on K'aresh, where he appears to have succeeded Zo'gron in handling admission to the building. He disappears from his post after  [80] The Darkness Among Us when the Shadowguard invasio..." },
  ["xy'rath the covetous"] = { 2, "broker located next to three Misfortunate Pilgrims at the...", "Xy'rath the Covetous is a broker located next to three Misfortunate Pilgrims at the Ageless Shards in Zereth Mortis." },
  ["xy'rihn the keen"] = { 2, "broker located just past Tazavesh Customs Enforcement in ...", "Xy'rihn the Keen is a broker located just past Tazavesh Customs Enforcement in Tazavesh, the Veiled Market." },
  ["xy'tadir"] = { 2, "broker located at the Bazaar of Tangible Delights in Taza...", "Xy'tadir is a broker located at the Bazaar of Tangible Delights in Tazavesh, the Veiled Market." },
  ["xy'teth"] = { 2, "', "Xy'teth is one of the broker assassins sent by Cartel Xy to kill Firim in Zereth Mortis, seen during  [60] Finding Firim. They are first seen on the road through the Great Veldt, having just killed Xevveth, but run away and disappear in a flash of..." },
  ["xy'varek"] = { 2, "', "Xy'varek is one of the broker assassins sent by Cartel Xy to kill Firim in Zereth Mortis, seen during  [60] Unseen Agents. They are located in the Great Veldt, interfering with one of Firim's Triggered Traps." },
  ["xy'zaro"] = { 2, "broker located at the Bazaar of Tangible Delights in Taza...", "Xy'zaro is a broker located at the Bazaar of Tangible Delights in Tazavesh, the Veiled Market." },
  ["y'kish"] = { 2, "arakkoa in Gorgrond", "Y'kish is an arakkoa in Gorgrond." },
  ["y'lliya xennin"] = { 2, "satyr antagonist of the first chapter of the Guest Relati...", "Y'lliya Xennin is the satyr antagonist of the first chapter of the Guest Relations storyline. Players end up confronting him during  [30-90] Spot the Difference northeast of the Gaping Chasm in southeastern Tanaris." },
  ["y'tekhi"] = { 2, "quartermaster for the Severed Threads", "Y'tekhi is the quartermaster for the Severed Threads, located in the Weaver's Lair in Azj-Kahet." },
  ["ya'vik the imperial blade"] = { 2, "mantid located on the expedition islands", "Ya'vik the Imperial Blade is a mantid located on the expedition islands." },
  ["yaila"] = { 2, "haranir tailoring vendor located in the Den in Harandar", "Yaila is a haranir tailoring vendor located in the Den in Harandar." },
  ["yamas the provider"] = { 2, "nerubian found in the Weaver's Lair in Azj-Kahet", "Yamas the Provider is a nerubian found in the Weaver's Lair in Azj-Kahet." },
  ["yana bloodspear"] = { 2, "', "Yana Bloodspear has a large statue erected in her honor in the the Hall of Champions, located in the Scarlet Monastery in the Tirisfal Glades. She was born in Dalaran." },
  ["yanis the mystic"] = { 2, "Mystic is a vrykul located in Wyrmskull Village in Howlin...", "Yanis the Mystic is a vrykul located in Wyrmskull Village in Howling Fjord." },
  ["yano barkhoof"] = { 2, "Horde druid leader of Ashran", "Yano Barkhoof is the Horde druid leader of Ashran, found in Warspear Outpost. Yano is located on the right-hand side just inside the entrance to the base and can be found talking to Alascene." },
  ["yao firmpaw"] = { 2, "pandaren physician", "Yao Firmpaw was a pandaren physician whose career was so spectacular, his name is still associated with health and wellness in the Valley of the Four Winds. He never married; his heart was forever broken when his love, a young lorewalker named Lin..." },
  ["yargra blackscar"] = { 2, "orc quest giver located at the Firelands Forgeworks in Mo...", "Yargra Blackscar is an orc quest giver located at the Firelands Forgeworks in Mount Hyjal. She instructs adventurers to eliminate the Dark Iron dwarves laborers in Hyjal." },
  ["yarlyn amberstill"] = { 2, "dwarf child rabbit vendor located at Amberstill Ranch in ...", "Yarlyn Amberstill is a dwarf child rabbit vendor located at Amberstill Ranch in Dun Morogh. She runs very quickly near the entrance to the ram pen as she tries to catch her pet rabbit, Fluffy." },
  ["yarrog baneshadow"] = { 2, "orc found in the Burning Blade Coven in the Valley of Trials", "Yarrog Baneshadow is an orc found in the Burning Blade Coven in the Valley of Trials. Yarrog is a member of the Burning Blade." },
  ["yash"] = { 2, "tortollan located at Gloom Hollow in Nazmir", "Yash is a tortollan located at Gloom Hollow in Nazmir." },
  ["yaz blastromo"] = { 2, "goblin located in Warfang Hold in Stormsong Valley", "Yaz Blastromo is a goblin located in Warfang Hold in Stormsong Valley." },
  ["yazzai"] = { 2, "ethereal frost mage", "Yazzai is one of the 8 different NPCs that can be with Priestess Delrissa, the third boss in Magisters' Terrace. He is an ethereal frost mage." },
  ["yellowflame candlekeeper"] = { 2, "kobold", "Yellowflame Candlekeeper is a kobold." },
  ["yelnagi blackarm"] = { 2, "orc located in Razor Hill in Durotar", "Yelnagi Blackarm is an orc located in Razor Hill in Durotar. This section concerns content related to Mists of Pandaria." },
  ["yennu"] = { 2, "tuskarr child located on the Dragon Isles", "Yennu is a tuskarr child located on the Dragon Isles." },
  ["yinaa"] = { 2, "haranir innkeeper", "Yinaa is a haranir innkeeper and vendor located in a building in the upper part of the Den in Harandar." },
  ["ymirjar graveblade"] = { 2, "', "Ymirjar Graveblades are vrykul found in the Pit of Saron. They can see through stealth." },
  ["ymirjar necromancer"] = { 2, "', "Ymirjar Necromancers are vrykul necromancers found in Utgarde Pinnacle." },
  ["ymiron, the fallen king"] = { 2, "first boss in Maw of Souls", "Ymiron, the Fallen King is the first boss in Maw of Souls." },
  ["yngvild the watcher"] = { 2, "vrykul located in Jandvik in Suramar", "Yngvild the Watcher is a vrykul located in Jandvik in Suramar." },
  ["yolan hidor"] = { 2, "dracthyr located in the Common in Razorwind Shores", "Yolan Hidor is a dracthyr located in the Common in Razorwind Shores and Town Center in Founder's Point when the Reaching Beyond the Possible endeavor is active." },
  ["yolanda akithmael"] = { 2, "Arathi located in Mereldar in Hallowfall", "Yolanda Akithmael is an Arathi located in Mereldar in Hallowfall. She appears to be holding a lecture for an assortment of Arathi Stalwarts, Mereldar Artillerists and Mereldar Sentries." },
  ["yonaa"] = { 2, "haranir innkeeper", "Yonaa is a haranir innkeeper and vendor located in the Den in Harandar." },
  ["yonn deepcut"] = { 2, "tauren skinning trainer located in Bloodhoof Village in M...", "Yonn Deepcut is a tauren skinning trainer located in Bloodhoof Village in Mulgore." },
  ["yonpak ambercrest"] = { 2, "tauren located at the Central Encampment in the Emerald D...", "Yonpak Ambercrest is a tauren located at the Central Encampment in the Emerald Dream." },
  ["yonzi"] = { 2, "leader of the Skalaxi arakkoa", "Yonzi was the leader of the Skalaxi arakkoa, a remnant of the fallen Apexis civilization, around 1,000 years before the opening of the Dark Portal." },
  ["yori crackhelm"] = { 2, "dwarf found in Thunderbrew Distillery in Dun Morogh", "Yori Crackhelm is a dwarf found in Thunderbrew Distillery in Dun Morogh." },
  ["yorus barleybrew"] = { 2, "dwarf located inside the Lakeshire Inn in the Redridge Mo...", "Yorus Barleybrew is a dwarf located inside the Lakeshire Inn in the Redridge Mountains. He is a member of the Barleybrew family." },
  ["yorus the flesh harvester"] = { 2, "vrykul gladiator in the Ring of Judgement in the Howling ...", "Yorus the Flesh Harvester is a vrykul gladiator in the Ring of Judgement in the Howling Fjord. He needs to be slain during  [10-30] Stunning Defeat at the Ring." },
  ["yorvas flintstrike"] = { 2, "Arathi located in the Whirring Field in Hallowfall", "Yorvas Flintstrike is an Arathi located in the Whirring Field in Hallowfall. He and several fresh recruits were on patrol in the area when their torches went out, leaving them lost and disoriented." },
  ["young furbolg shaman"] = { 2, "', "The Young Furbolg Shaman is one of several young Stillpine shaman who stumbled across Bristlelimb Enclave and were slaughtered. Jol wants to resurrect one Young Furbolg Shaman in    [12] Redemption with the help of a  [Symbol of Life]." },
  ["young quickhands"] = { 2, "tuskarr fishing trainer located in Grimtusk's Hideaway in...", "Young Quickhands is a tuskarr fishing trainer located in Grimtusk's Hideaway in the Azure Span." },
  ["youthful vestige"] = { 2, "', "Youthful Vestiges are eredar children located in Eredath." },
  ["yowler"] = { 2, "gnoll found in the Redridge Mountains", "Yowler is a gnoll found in the Redridge Mountains. Magistrate Solomon wants Yowler's cold, dead paw." },
  ["yrvar isilmar"] = { 2, "vrykul", "Yrvar Isilmar is a vrykul who recorded a chapter in The Legend of Odyn." },
  ["ysabel gleamgaard"] = { 2, "Arathi located in Wildcamp Or'lay in Azj-Kahet", "Ysabel Gleamgaard is an Arathi located in Wildcamp Or'lay in Azj-Kahet. She was worried about her injured sister and was hesitant about the camp's haranir and did not want to offend them." },
  ["ythyar"] = { 2, "ethereal found in Karazhan", "Ythyar is an ethereal found in Karazhan, right before the Chess Event." },
  ["yu fei"] = { 2, "pandaren mage", "Yu Fei is a pandaren mage who was opening portals for everyone who needed them during the trial of Garrosh Hellscream. She was also magically unlocking and locking Garrosh's cell when necessary." },
  ["yzinia"] = { 2, "dracthyr located at Weyrnrest in Valdrakken", "Yzinia is a dracthyr located at Weyrnrest in Valdrakken." },
  ["z'tenga the walker"] = { 2, "troll", "Z'tenga the Walker is a troll and the quartermaster for the Saberstalkers. He is located at the Saberstalkers' camp north of Fang'rila." },
  ["zabta"] = { 2, "ethereal located in Castigaar in K'aresh", "Zabta is an ethereal located in Castigaar in K'aresh. Xal'atath sent a stalker to her in order to gain Soul-Scribe's trust." },
  ["zafod boombox"] = { 2, "goblin located on the Skybreaker or Orgrim's Hammer in Ic...", "Zafod Boombox is a goblin located on the Skybreaker or Orgrim's Hammer in Icecrown Citadel. He is part of the Gunship Battle." },
  ["zah'ran"] = { 2, "ethereal found where the treasure spawned after completin...", "Zah'ran is an ethereal found where the treasure spawned after completing delves. He'll start appearing at Tier 6 or higher after reaching Rank 5 in the  [Delver's Journey] during Midnight Season 1." },
  ["zak callabang"] = { 2, "goblin located at Fuselight-by-the-Sea in the Badlands", "Zak Callabang is a goblin located at Fuselight-by-the-Sea in the Badlands." },
  ["zalius"] = { 2, "satyr located in Satyrnaar in Ashenvale during Nightmare ...", "Zalius is a satyr located in Satyrnaar in Ashenvale during Nightmare Incursions." },
  ["zalnax"] = { 2, "nerubian located in Klaskin's Hollow in the City of Threads", "Zalnax is a nerubian located in Klaskin's Hollow in the City of Threads." },
  ["zamicilath"] = { 2, "dracthyr located in Thaldraszus", "Zamicilath is a dracthyr located in Thaldraszus." },
  ["zan'thik ambermancer"] = { 2, "', "Zan'thik Ambermancers are mantid found during the Assault on Zan'vess." },
  ["zan'thik drone"] = { 2, "', "Zan'thik Drones are mantid found flying around in large numbers during the Assault on Zan'vess." },
  ["zan'thik guardian"] = { 2, "', "Zan'thik Guardians are mantid located at the Whispering Stones in the Assault on Zan'vess. They are seen protecting the nearby Sonic Control Towers." },
  ["zan'thik impaler"] = { 2, "', "Zan'thik Impalers are mantid found at Zan'vess in the Dread Wastes." },
  ["zan'thik manipulator"] = { 2, "', "Zan'thik Manipulators are mantid found at Zan'vess in the Dread Wastes." },
  ["zan'thik resonator"] = { 2, "', "Zan'thik Resonators are mantid found at Zan'vess in the Dread Wastes." },
  ["zan'thik slasher"] = { 2, "', "Zan'thik Slashers are mantid found during the Assault on Zan'vess." },
  ["zan'thik slaver"] = { 2, "', "Zan'thik Slavers are mantid located in the Kyparite Quarry in the Assault on Zan'vess. They are seen fighting Yaungol Brutes." },
  ["zan'thik subjugate"] = { 2, "', "Zan'thik Subjugates are mantid found at Zan'vess in the Dread Wastes." },
  ["zan'thik swarmer"] = { 2, "', "Zan'thik Swarmers are mantid found during the Assault on Zan'vess." },
  ["zan-tien caller"] = { 2, "', "Zan-Tien Callers are mogu located in the Vale of Eternal Blossoms." },
  ["zan-tien conjurer"] = { 2, "', "Zan-Tien Conjurers are mogu located in Kun-Lai Summit." },
  ["zan-tien pikeman"] = { 2, "', "Zan-Tien Pikemen are mogu located in Kun-Lai Summit." },
  ["zan-tien raider"] = { 2, "', "Zan-Tien Raiders are mogu located in the Vale of Eternal Blossoms." },
  ["zan-tien scout"] = { 2, "', "Zan-Tien Scouts are mogu located in the Vale of Eternal Blossoms." },
  ["zan-tien subjugator"] = { 2, "', "Zan-Tien Subjugators are mogu located in the Vale of Eternal Blossoms." },
  ["zandalari infiltrator"] = { 2, "', "Zandalari Infiltrators are trolls found in Mogu'shan Vaults." },
  ["zandle"] = { 2, "tortollan", "Zandle is a tortollan that briefly appears in Seekers' Vista in Stormsong Valley during the completion of  [30-60] Battle Victorious and  [50WQ] Turtle Tactics." },
  ["zandras"] = { 2, "satyr found at the Warden's Cage in Shadowmoon Valley", "Zandras is a satyr found at the Warden's Cage in Shadowmoon Valley." },
