  ["zarvik blastwix"] = { 2, "goblin located in Zoram'gar in Ashenvale", "Zarvik Blastwix is a goblin located in Zoram'gar in Ashenvale and later in Blackwood Den in Darkshore during the War of the Thorns. He provided Goblin Hellions to the Horde adventurer." },
  ["zaxifran the defiler"] = { 2, "satyr located in Suramar", "Zaxifran the Defiler is a satyr located in Suramar." },
