  ["zazzix boomride"] = { 2, "goblin flight master located on Fizzle", "Zazzix Boomride is a goblin flight master located on Fizzle and Pozzik's Speedbarge in Thousand Needles. Tilly Topspin is his Alliance counterpart." },
  ["zealous consort"] = { 2, "', "Zealous Consorts are satyrs located in the Guest Chambers in Karazhan. They are disguised as humans, but at 50% health they reveal their true appearance, removing all debuffs in the process." },
