  ["zeggon botsnap"] = { 2, "goblin Arena battlemaster located in the Hall of the Brav...", "Zeggon Botsnap is a goblin Arena battlemaster located in the Hall of the Brave in Orgrimmar." },
  ["zeke bootscuff"] = { 2, "goblin quest giver found at Bootlegger Outpost in central...", "Zeke Bootscuff is a goblin quest giver found at Bootlegger Outpost in central Tanaris. Having been sent to the Gaping Chasm by Marin Noggenfogger to either wipe out the silithid or turn them into a profit, he and his team weren't very successful f..." },
  ["zeke the zerker"] = { 2, "vrykul located in Stormheim", "Zeke the Zerker is a vrykul located in Stormheim." },
  ["zektar"] = { 2, "arakkoa reagent vendor located at the Nest of the Ravensp...", "Zektar is an arakkoa reagent vendor located at the Nest of the Ravenspeakers in the Spires of Arak." },
  ["zeldis"] = { 2, "Darkfallen located at the Serene Dreams Spa in Thaldraszus", "Zeldis is a Darkfallen located at the Serene Dreams Spa in Thaldraszus. He is followed around by his Enamored Fans, known as The Zeldis Entourage." },
