  ["zenn foulhoof"] = { 2, "satyr located east of Dolanaar in Teldrassil", "Zenn Foulhoof is a satyr located east of Dolanaar in Teldrassil. He also appears hostile in Darkshore." },
  ["zephyrion"] = { 2, "ethereal quest giver located at the Stormspire in the Net...", "Zephyrion is an ethereal quest giver located at the Stormspire in the Netherstorm. He is interested in excavating the Ruins of Farahlon for its artifacts." },
  ["zer'ik"] = { 2, "mantid located at the Klaxxi'vess in the Dread Wastes", "Zer'ik is a mantid located at the Klaxxi'vess in the Dread Wastes. He took the succession of Kor'ik after his death." },
  ["zerid"] = { 2, "ethereal quest giver located at Aeris Landing in Nagrand", "Zerid is an ethereal quest giver located at Aeris Landing in Nagrand. He is the head of security at the encampment, and is concerned about the proximity of Aeris Landing to Oshu'gun because of the voidspawn and rogue ethereals in the area." },
  ["zerpy clampshock"] = { 2, "goblin vendor located at the Shattered Landing in Blasted...", "Zerpy Clampshock is a goblin vendor located at the Shattered Landing in Blasted Lands. She is a general goods vendor and also sells armor from the Iron Horde Incursion." },
  ["zevrax"] = { 2, "satyr found at Axxarien on Bloodmyst Isle", "Zevrax is a satyr found at Axxarien on Bloodmyst Isle, leading the Axxarien satyrs." },
  ["zevrim thornhoof"] = { 2, "satyr located in the Warpwood Quarter of Dire Maul", "Zevrim Thornhoof is a satyr located in the Warpwood Quarter of Dire Maul. He sacrifices people on the altar next to him." },
  ["zhahara darksquall"] = { 2, "naga assigned by her superiors to find the lost continent...", "Zhahara Darksquall was a naga assigned by her superiors to find the lost continent of Pandaria. However, Zhahara herself was obsessed with finding the Wandering Isle and the Pearl of Pandaria." },
  ["zhakir"] = { 2, "haranir located at Shaladrassil in Val'sharah", "Zhakir is a haranir located at Shaladrassil in Val'sharah. Finding Zhakir is one of the criteria of the exploration achievement  [More Than Just Their Roots]." },
  ["zhakloskar"] = { 2, "dracthyr located atop a wall in the Trade District in Sto...", "Zhakloskar is a dracthyr located atop a wall in the Trade District in Stormwind City." },
