  ["zhao-jin the bloodletter"] = { 2, "leader of the Shao-Tien mogu invading the Vale of Eternal...", "Zhao-Jin the Bloodletter was the leader of the Shao-Tien mogu invading the Vale of Eternal Blossoms. He was first encountered in the Hall of the Serpent of the Guo-Lai Halls, where he sent Dagou after the adventurers." },
  ["zhu of the eternal stone"] = { 2, "mogu located in the Guo-Lai Vault in Vale of Eternal Blos...", "Zhu of the Eternal Stone is a mogu located in the Guo-Lai Vault in Vale of Eternal Blossoms." },
  ["zhul'dar"] = { 2, "troll working with Havoc the Heartless", "Zhul'dar was a troll working with Havoc the Heartless and killed by Nori Blackfinger." },
