  ["zindaralash"] = { 2, "dracthyr located in the Valley of Honor in Orgrimmar", "Zindaralash is a dracthyr located in the Valley of Honor in Orgrimmar. She is speaking with a pair of Orgrimmar Grunts." },
  ["zink"] = { 2, "tortollan located in northern Exile's Reach", "Zink is a tortollan located in northern Exile's Reach. He is found in a secret underwater cave under a waterfall." },
  ["zinnin smythe"] = { 2, "powerful worgen warlock member of the Council of the Blac...", "Zinnin Smythe is a powerful worgen warlock member of the Council of the Black Harvest. He was present at the Maelstrom and was made mute from the trauma of watching Deathwing being unmade." },
