  ["zippy breathington"] = { 2, "Bilgewater Cartel goblin located in the Sinkhole", "Zippy Breathington is a Bilgewater Cartel goblin located in the Sinkhole and Tak-Rethan Abyss where she sells adventurers a device allowing underwater breathing." },
  ["zirixi swarmclaw"] = { 2, "', "Zirixi Swarmclaws are nerubians serving Queensguard Zirix on the Isle of Dorn." },
