  ["znort"] = { 2, "kobold", "Znort was a kobold that could be found following the mountain giant Fozruk in the Arathi Highlands. As of Battle for Azeroth, he now follows his son, also named Fozruk." },
  ["zo'fyne"] = { 2, "broker located in Tazavesh", "Zo'Fyne is a broker located in Tazavesh, the Veiled Market in K'aresh." },
  ["zo'gron"] = { 2, "broker serving as the fourth boss of Tazavesh", "Zo'gron is a broker serving as the fourth boss of Tazavesh, the Veiled Market. He serves as the bouncer for Myza's Oasis and to get past him, the password must first be obtained." },
