  ["zo'kita"] = { 2, "broker located in Tazavesh", "Zo'kita is a broker located in Tazavesh, the Veiled Market in K'aresh. He grows fruits named after himself in secret in Eco-Dome: Primus." },
  ["zo'lariya"] = { 2, "broker seen hammering on an anvil in Astral Getaways in T...", "Zo'lariya is a broker seen hammering on an anvil in Astral Getaways in Tazavesh, the Veiled Market." },
  ["zo'mezal"] = { 2, "broker located at the southern dock entrance to Tazavesh", "Zo'mezal is a broker located at the southern dock entrance to Tazavesh, the Veiled Market. During Al'dalil's quest to stop So'leah in Tazavesh, he is the one initially seen guarding the entrance to the Tazavesh Customs Enforcement and tells Al'dal..." },
  ["zo'pare"] = { 2, "broker located in Tazavesh Customs Enforcement in Tazavesh", "Zo'pare is a broker located in Tazavesh Customs Enforcement in Tazavesh, the Veiled Market in the Shadowlands. He also reappeared when the city moved to K'aresh and is present in Astral Getaways." },
  ["zo'phar"] = { 2, "broker located in Tazavesh", "Zo'phar is a broker located in Tazavesh, the Veiled Market in K'aresh." },
  ["zo'phex"] = { 2, "first boss of Tazavesh", "Zo'phex is the first boss of Tazavesh, the Veiled Market." },
  ["zo'ropo"] = { 2, "broker located in Shadow Point in K'aresh", "Zo'ropo is a broker located in Shadow Point in K'aresh." },
  ["zo'sorg"] = { 2, "broker located in the Enclave in Oribos", "Zo'sorg is a broker located in the Enclave in Oribos. He sells certain conduits, as well as ensembles and arsenals to unlock the appearances of Shadowlands PvP equipment." },
  ["zo'taur"] = { 2, "broker located at the Ring of Fates in Oribos", "Zo'taur is a broker located at the Ring of Fates in Oribos." },
  ["zo'turu"] = { 2, "broker located at Shadow Point on K'aresh", "Zo'turu is a broker located at Shadow Point on K'aresh. He is the renown quartermaster for the Manaforge Vandals major faction." },
  ["zo'umlo"] = { 2, "broker located at the Challenger's Promenade in Maldraxxus", "Zo'umlo is a broker located at the Challenger's Promenade in Maldraxxus. He seems to work for Au'narim in the promenade and part of his job includes capturing or containing beasts that are to be sold to the Maldraxxi so they can be used in the The..." },
  ["zoeh milani"] = { 2, "Arathi located in Mereldar in Hallowfall", "Zoeh Milani is an Arathi located in Mereldar in Hallowfall." },
  ["zoltanian cultist"] = { 2, "', "Zoltanian Cultists are found in Jaedenar, listening to Zoltan preach about the return of Sargeras. Some are seen with a rare undead blood elf skin with night elf voice." },
  ["zom bocom"] = { 2, "goblin PvP rewards vendor", "Zom Bocom is a goblin PvP rewards vendor.  He can be found in the Underbelly of Dalaran and is usable by both Horde and Alliance." },
  ["zooka"] = { 2, "tortollan located at the Seekers' Vista in Stormsong Valley", "Zooka is a tortollan located at the Seekers' Vista in Stormsong Valley." },
  ["zooti fizzlefury"] = { 2, "gnome of the Kirin Tor located at Khadgar's Tower in Talador", "Zooti Fizzlefury is a gnome of the Kirin Tor located at Khadgar's Tower in Talador. He researches time." },
  ["zosime"] = { 2, "kyrian", "Zosime is a kyrian who can be found in the Garden of Respite, in Bastion, alongside her larion companion Kala. As part of her trials as an aspirant, maintaining the garden was her first posting." },
  ["zovex"] = { 2, "ethereal located in Tranquil Strand on the Isle of Dorn b...", "Zovex is an ethereal located in Tranquil Strand on the Isle of Dorn but will not be in phase until completion of  [68-70] Secure the Beach from the Isle of Dorn storyline. Before Dalaran's destruction, Zovex was a prisoner of the Violet Hold and s..." },
  ["zu'shin the infused"] = { 2, "mogu located in Verdant Slope in Zuldazar", "Zu'shin the Infused is a mogu located in Verdant Slope in Zuldazar." },
